INSERT INTO "reviews" VALUES('6a2fd609ad8e5638f5ddc45e',26,26,'我说白了，谁敢说这个老师一点毛病我直接和你爆了，夯爆了，讲的又好，上课氛围很活跃，平时分高，只要4个条件满足一个直接拿满，也不咋点名，还请全班喝奶茶发糖，作业可以补交，有问题也会回答，期末最后的课还可以不去，小测管的不严，属于是想学习可以学好，想玩也可以玩好，说真的遇到她你就爽一年吧',5,5,5,15,0,0);
