INSERT INTO "reviews" VALUES('6a2ac53467a8944c51f2ee4a',43,43,'特别好，今天模电实验考试，我那个台子上一个人打开了反相。但是我没注意到，做出来波形是错的，老师给我看了之后给我改过来，就给我扣了3分让我重新记录波形，简直完美，特别温柔',5,5,5,15,0,0);
