INSERT INTO "reviews" VALUES('6a290fb9ad8e5638f5bcfcfc',46,4,'特别贱的一个老师，1分都不配，还教的特别烂每次动作讲解的表述能力都堪比一只成年的脚趾感，然后还在那里说女生不会听，你自己就是教得屎一样。，打分也是疯狂压你的分，好吗？完全是歧视女生来着，全家飞了，我要给他配冥婚。。。他们每次名字是必点的，可以让你请假，但是一请假分是必须扣的。',1,1,1,3,0,0);
