INSERT INTO "reviews" VALUES('6a277c4c67a8944c51e1648f',54,54,'讲解是稀烂的，人是躲办公室玩儿的，验收是要请神出来的，验收过程是要骂人的，打分是最低的。本人在他的实验里验收没有问题，他也欣欣然地盖了章，什么刺也没挑，到头来却打了个最低分，神了',1,1,1,3,0,0);
