INSERT INTO "reviews" VALUES('6a2767b176c5b81b4bf45a32',58,55,'上课水的一b，学了一个学期感觉啥也没学……不知道在干什么。上课自己就拿个手机跑一边去玩去了，或者跟其他老师聊天去了，考试全班一个样，练的好坏一样，认认真真上课的跟旷课的分数都一样，还考试干什么，直接打分不就行了。有毛病！不知道想干什么，想旷课的的，想水的，都来吧',1,1,1,3,0,0);
