INSERT INTO "reviews" VALUES('6a255f7667a8944c51d811e6',65,65,'给分低，教不会还点名点了一排人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a254a753923da236b3e652e',66,66,'本科遇到的最好的老师之一。是大三体育健康课程奥运裁判的老师，授课都是由体育学院的研究生助教来上，第一节课会把话说的有点重把一些人吓跑，但是实则刀子嘴豆腐心，非常为学生着想，给分相当高，有同学过不了或者有情况考不了试，也会温柔耐心的回答和商量解决。对比大一大二时候的羽毛球py简直一个天上一个地下。不过貌似要退休了，可惜',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a237f8276c5b81b4be173ac',67,67,'林川老师的工程电磁场氛围轻松，讲课很好，偶尔讲一些其他东西帮助你理解，上课跟着走期末不会有什么困难，作业少，很喜欢的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a2273ec76c5b81b4bdc5bcb',68,68,'事情多，给分低，各种提问，答不上还阴阳你，一分都不想给，遇到过的最神的老师，选上她基本上不好过了，重要的事说三遍，跑跑跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a22699d76c5b81b4bdc1876',58,55,'夯爆了，可惜后来选不上泽哥的课了，******简直一个天使（沈老师）一个恶魔',5,5,5,15,0,0);
