INSERT INTO "reviews" VALUES('6a2175f73923da236b2af0e4',6,6,'一大坨，大作业之前说只需要小组展示就行，临了最后两周了告诉我个人也要展示，个人展示就算了，还要我配图片，配调研过程。信誓旦旦告诉我们之前两节课就说明了个人也要展示，结果全班没一个人知道，现在所有个人选手都要着急忙慌赶个ppt去演讲，不讲就30分扣完。三节课连堂只是最基础的，要不是选课卡******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a213e86d2a61074f21ea113',73,73,'老师人十分和蔼，讲课也非常专业',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('6a213da0d2a61074f21e9940',74,74,'我就简短一些说吧，选了他你之后会很难受，不要选。就这么简短，但是越简短说明越要避雷。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a213cf7422e811e07d9d50b',75,75,'张娟老师人特别好，讲课也认真负责，讲得很好，然后平时对待同学也十分和蔼可亲，会耐心解答同学问题，而且会给你讲的很清楚。期末也不会为难同学，不会卡成绩。大家放心选张娟老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a213bbcad8e5638f594a0be',76,76,'这货平时你找他他是对你爱搭不理的，课上讲的是不行的，表面看着和善，实际上表里完全不一，选了他必定后悔，一句话总结：人品不行。',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('6a213a61422e811e07d9ba3f',77,24,'平时上课可能比较严，尤其是考勤方面，之前早八我是八点到的，但他要求提前十分钟就得进教室，所以就记旷课。但平时讲课倒还好，然后给分也不低，至少不会卡人。是否选择他就全凭自己取舍吧',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('6a2138cc422e811e07d9aec5',78,78,'经常把自己从美国回来的事挂在嘴边，感觉自己要上天了？平时讲课就让同学上去讲PPT，你知道是怎样吗？是让人自己下去看PPT，然后课上来讲，念完PPT后还要指指点点。然后每堂课还要留所谓的小测，下课前必须交，大半节课自己就坐在讲台上啥都不干。只能说能避开他就千万不要选。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a2137be76c5b81b4bd618a8',79,2,'上过这个人的专业课，只能说是个表里不一的人，表面笑嘻嘻，其实就是个笑面虎，平时作业难度高，期末布置的任务也极其繁重，能避开他就赶紧避开',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('6a21368d422e811e07d99c9d',80,80,'表里不一，要小心这样的',3,2,2,7,0,0);
