INSERT INTO "reviews" VALUES('6a20d092422e811e07d70ab8',87,87,'和学生打成一片，考试要求给分要求每次都会提醒，期末考试难度也是一降再降。课堂氛围也轻松自由，无论想踢球还是想休息老师都不会过多干预，冲就完了。',5,5,5,15,0,0);
