INSERT INTO "reviews" VALUES('6a1d0688ad8e5638f57f141b',103,6,'戏耍同学，情商低下，自以为是。平时分设计得让人拿不到一点，做第一排要跑得快才能抢到，我离得远怎么办，难道我不积极吗？问题问一两个，答不到他想的那个点上，答再好也没用。忽悠人说后面可以可以离开，同学们刚走他就点名。同学上去做汇报，一个劲的在旁边bb，同学只想顺利完成一下成绩任务，他在那儿说这不行那不好，最后把同学撵下去，说你的汇报不如b站up主的解说视频。无大语，没见过这么恶心这么垃圾的老师，简直是神人堆里的',1,1,1,3,0,0);
