INSERT INTO "reviews" VALUES('6a17cb38ad8e5638f56485b9',121,121,'信她给分高不如信我是秦始皇，一开始确实没啥问题，最后成绩登完就说平均分太高了，然后每个人都扣了5分，没见过这么逆天的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a17abf53923da236bf5b157',122,122,'我有一个小问题，为什么在2026年，五月24日，会同时有这么多学长学姐给老师好评，有的学长学姐都已经毕业三年了，是因为校庆，之前的学长学姐回来了跟老师叙旧了吗？我只是有个疑问，并没有说老师不好，老是确实是个跟认真专业的老师',4,4,3,11,1,0);
