INSERT INTO "reviews" VALUES('6a158008ad8e5638f5598a4c',130,54,'神人一个，实验选到他有福了，三个小时的实验课，他讲课讲一个半小时，一点重点都没有，结果到最后还是什么都不会。声音跟蚊子叫一样，听课的全围在前面都谁都听不清。还不准在他讲课的时候拿出来手机（拍照也不行），最后实验报告还乱七八糟一堆事儿，给分是别想高的，拉完了。',3,1,2,6,0,0);
