INSERT INTO "reviews" VALUES('6a156ff676c5b81b4b9ad6e9',132,132,'没吃过。的可以来选了，还不跑等什么呢？天天教你怎么用ai，不用ai你就要挨批，用错了也要挨批，做什么都要挨批，总之就是要把生活上（例如淘宝退货）受的气发泄在你身上。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a1547693923da236bea2440',133,133,'纯纯活在自己世界的玩意，上课没听你讲就是对不起国家父母，大家不重视这门课就调到大三设置期末考和实验恶心所有人，就为了你那一点可怜的存在感？你这种人说白了就是天天自尊心作祟的巨婴，三观都没成也配指指点点别人',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6a1419b63923da236be49cc8',99,99,'全宇宙倒数第一赤诚、善良、热忱、纯粹、温柔、谦和、治愈、明媚的老师；全宇宙倒数第一为学生着想的老师；全宇宙倒数第一不麻烦学生的老师；全宇宙倒数第一有审美的老师；全宇宙签到次数最多的老师；全宇宙事最多的老师；最宇宙最崇拜ai生成的老师；全宇宙开展课堂汇报次数最多的老师；全宇宙唯一课堂汇报随机抽小组成员上去讲的老师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a141303d2a61074f2dc882c',23,23,'神中神，讲课充满激情，通俗易懂，认真负责，真是关心呵护每一位学生的感受，大学遇到的最好的老师',5,5,5,15,0,0);
