INSERT INTO "reviews" VALUES('6a12fb2ed2a61074f2d766c5',139,139,'说实话我没懂这个课意义是啥……一百号人在一个大教室，插座就十几个，还必须带电脑。叫编程但是让我们做一些完全不相干的作业，又要花钱买一堆电子元件，花钱下一堆不会用的软件，作业也不知道怎么做，最后还是外包做，这种课赶紧取消吧',1,1,1,3,0,0);
