INSERT INTO "reviews" VALUES('6a115da267a8944c517354b8',143,143,'老师人很好 很有趣友善，讲的很生动，我跟老师课下聊天，老师没有任何架子，好感动，人真的很不错，建议选老师，好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a11587067a8944c51732e7a',122,122,'老师讲课还是蛮好的，讲课思路很清晰，课程内容虽然有些乏味，但是老师讲的还是很生动形象的，需要记忆的比较多，知识点比较杂，所以课堂笔记，课后作业也是必要的，课堂纪律也是提高课堂效果的一部分，点赞',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('6a1142f03923da236bd6433e',122,145,'赵老师专业水平优秀，课堂生动有趣，引人入胜，待人和蔼可亲，经常笑咪咪看着大家，很有亲和力，除了考试比较难以外，找不出任何缺点，强烈推荐！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a11287a76c5b81b4b84d09a',122,145,'讲课内容详细,讲课有条理，擅长结合实例讲解知识；课堂要求比较严，有作业、会点名和抽问；期中是开卷，期末是闭卷，会画重点；作为专业课，给分宽松，会捞。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6a111b48422e811e078871dd',122,145,'赵老师工作兢兢业业，教学方法灵活多样，善于调动学习积极性，待人真诚友善，用心呵护学生成长，值得由衷敬佩。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a111addd2a61074f2cd799b',122,122,'课程内容充实、条理清晰。善于将铸造、锻压、焊接等抽象工艺与生产实例结合，化繁为简。授课幽默风趣，PPT与板书并用，重点突出。耐心解答疑问，并带领我们动手实操。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a111a533923da236bd532a0',122,149,'赵老师上课认真负责，对待学生有一定要求，目的是督促学生认真学习。工作兢兢业业，教学方法灵活多样，善于调动学习积极性，待人真诚友善，用心呵护学生成长。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a111a3867a8944c51717a2b',122,145,'老师讲课条理分明，成形技术相关知识讲解细致。常结合实操案例辅助讲解，晦涩原理变得容易理解。课堂氛围良好，对待问题耐心解答，让大家稳步掌握专业知识。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a111a0a76c5b81b4b846b95',122,122,'老师授课通俗易懂，成型原理与工艺知识讲解详实。善于结合实际生产案例剖析知识点，课堂讲解深入浅出，悉心解答疑问，有效帮助我们吃透专业知识。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a1119d7422e811e07886759',122,152,'老师讲课逻辑严谨，将材料理论知识拆解讲解，重难点剖析到位。善于结合专业案例辅助理解，课堂节奏适中，答疑认真细致，助力我们扎实掌握学科核心内容。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a1119a0d2a61074f2cd6ea7',122,149,'老师授课条理清晰，模具设计知识点讲解透彻，材料相关内容结合实例易懂实用。课堂氛围轻松，耐心答疑解惑，能切实帮助我们夯实专业基础，收获良多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a11165fd2a61074f2cd4f3e',122,122,'老师相对来说是那种比较严谨的老师，课后也可以随意问问题，比较认真负责，是能在课程上学到东西的。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('6a11147876c5b81b4b843b4d',122,145,'这门课专业知识偏难懂，老师讲课功底特别扎实，上课节奏把握得刚刚好。讲课的时候还会结合实际例子来讲，原本晦涩的知识点一下子就好理解多了。
INSERT INTO "reviews" VALUES('6a106d0467a8944c516f2404',156,156,'拉完了，娘娘腔，规矩多的要死，贼喜欢压力人。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6a1051d0d2a61074f2ca77c3',157,157,'我真c**了，给我们考个太极扣的巨**严，别的班一点不练都过的，到你这没踮脚都过不去我真祝你早点*吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a1040f367a8944c516e1f0f',158,158,'💩中💩，点名对着人头数个数，巨严，天天上课压力人 不让玩手机，正是考公考研找工作最麻烦的时候天天搞个逼考勤，课程设计也有挺多的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a1020913923da236bd09e3f',159,159,'老师真的太好了，其他课程没名额了，我就报篮球了，基本上啥也不会，但是老师考核很松，还一直鼓励。这学期考太极，老师考前三个星期带着我们每节课练两遍太极。然后跳绳我从小也不太好，一直没敢去找老师计数，等到下课了才一个人去，老师也是一直鼓励我，并且他会给每个人多算几秒，最后我自己数的140个，老师给我数了155个，太感动了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a0ffbf43923da236bcf841c',68,68,'上课十几个周了连班里多少人都不知道🤣乐。说是让一个小组坐一起，每次都坐最后一排的，突发奇想来句你坐最后一排是来诚心上课的吗。 ？？？这种玩意你就选吧🤣🤣',1,1,1,3,0,0);
