INSERT INTO "reviews" VALUES('6a0c168076c5b81b4b6c1fad',182,2,'毕业设计选的这老师的，只能说糟了八辈子血霉，这样说吧，根据规范设计的数据，不对；拿去年他亲自带的学生优秀论文的数据，也不对；你设计的数据不是要合乎规范，也不是要合乎软件设计规范，而是要让他觉得规范，然后这老师很双标，不同人的同一个东西，他能表现截然不同的态度，而且你解释了他就说你学习态度不端正，不用心，根本沟通不了，对待他喜欢的学生就啥啥都可以',1,1,1,3,0,0);
