INSERT INTO "reviews" VALUES('6a014cc3d2a61074f27afe90',23,23,'老师真的既做到教好书，也在育好人，简直是我生命中遇到的最棒的教师之一，她简直是教师的典范，她积极的生活态度一直鼓舞着我，她不只是一门课的老师，更是人生的导师，感谢遇到刘霓老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a014c6967a8944c5121a1a6',214,36,'事情多，喜欢形式',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6a0091b176c5b81b4b301648',11,11,'拉完了，布置的作业起堆堆，p事贼多，莫名奇妙来一个小组任务。六级还每个周固定做，然后每页写名字学号拍照上传，神人来的。上课还特别爱抽问，嗯对，还检查你u校园作业时长点评两句。其实还会看这个活水，然后阴阳两句来着。咋就这么事多，英语谁不知道四六级重要，想学的人自己会学，不想学的人你管这么多干啥，每次就强迫干关于四六级的东西，真的恶心',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6a008dd03923da236b821061',42,42,'还是那句话，对我有意见的直接到六教找我，不要在某个小程序里撒泼打滚。别来沾边  死的很快',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a006ddb76c5b81b4b2f3cab',217,217,'挺好的老师，上课讲得条理清晰，人不齐的时候会点名，可以学到真东西，不过有时候会抽查实验完成情况，问相关问题，但是认真做了实验就没有问题，还会为学生着想，五一假期特地把实验截止日期延后了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6a006d5967a8944c511caeb1',101,114,'非常好！！！！期末考试的时候还会提醒你！！🥺哪个老师会这样啊',5,5,5,15,0,0);
