INSERT INTO "reviews" VALUES('6a00524a67a8944c511bf9a8',220,220,'真的狗屎，平时分给的好低，明明每个任务都是认真仔细地做而且质量不错也要扣20%，了解到同班的很多同学也是这个情况(除了期末考考得很高的同学)。期中考考得不差最后平时分83你搞笑呢，想要平时分高分别来。。。讲得我觉得也是不清不楚，避雷吧',1,1,1,3,0,0);
