INSERT INTO "reviews" VALUES('69fd58bf422e811e07210651',228,228,'依托石，上课爱刁难人，随时点人答不上来拎到第一排，扯自家女儿扯东扯西，刻板印象，公开发表学科歧视言论称降分的高考分时低一些的素质有差距，厌女，自以为是说教，做分内的事情还在那里强调自己多良心多辛苦，教的就那样照本宣科，主要是脑残爱发表奇怪观点，说两句话听的人都要气笑了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69fd435ed2a61074f2659bc5',229,229,'遇到她，你就爽吧!不点名，平时分直接拉满，大一遇到最好的老师，嘻嘻嘻。除了麦有点炸，但你自学玩手机也完全不管。考试前的检测也很简单，期末还会总结可能考什么，反正特别爽的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69fc3376d2a61074f2604fd6',230,230,'形策课自以为水课很重要，这不让干那不让干，声音还超级无敌大，特别吵，活水什么时候出个零分，正适合他',1,1,1,3,0,0);
