INSERT INTO "reviews" VALUES('69e9b3b43923da236b0e1edb',56,56,'专门注册来评论，老师贼好哈哈哈哈哈，二次签到因为有事情忘记签了，说明情况老师就给签到了。而且特温和，有些人你跑了，逃课了，当然不签了，我专门让我的助教学姐跟老师说，老师知道了就签到了，我们苦哈哈的练，你跑走了不签合理的！',5,5,5,15,0,0);
