INSERT INTO "reviews" VALUES('69e734c867a8944c519befdd',293,293,'首先，有两个雷鸣，女的不清楚，男的教心理健康，人挺好，前半学期会纸质点名，后半不咋管，给分高，记得在学习通回答问题就行',5,5,5,15,0,0);
