INSERT INTO "reviews" VALUES('69e6ef9d39adc64cd0a8b567',242,295,'上课讲的快，到后期基本听了和没听一样，而且其实表述也不清楚，坐后排更是有福等着睡着。作业基本让同学帮批所以基本写了就是高分，大图认真画画的过得去80分左右还是有的',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('69e6dd8a2ff161641c8a854a',296,296,'个人主观来看上课不咋样，而且声音比较糊，上学期后半节进度莫名的快，导致作业略多，但是上学期除了期中考以外，其他30分平时分都给满了🤔从第一学期观察来看是这么个情况',3,3,4,10,0,0);
