INSERT INTO "reviews" VALUES('69e5c30a8527b5029edd8933',96,96,'外面大太阳30多度，教室里面永远窗帘拉到最下面，空调没有来过一次，到了教室就想晕倒。老师更绝，超级爱大声尖叫，学生问问题反正就是阴阳怪气，差评走你',1,1,1,3,0,0);
