INSERT INTO "reviews" VALUES('69dc6adb39adc64cd071d89f',298,85,'有点聪明脑子是吗？全放你学生身上了，质疑精神吗？还是全搁你学生身上了，说什么都要质疑，我上的这是专业课吗？我在想我的专业课老师都没这么强大的质疑能力吧，一说就是不信，再说就是不管，整天就知道阴阳怪气学生😄😄，说什么自己上课累得很，我寻思你也没有自己做动作来教学生啊，这不是找的学生来教我们吗，真累啊。什么都可以和学生杠起来，你是和学生有仇吗？我就不懂了，作为老师什么一直要和学生过意不去？上课又不自己来指导学生动作又怪学生不自己练？大家选吧，选吧，就去感受他高尚的品德和个性吧，去感受他质疑的思维吧。想水水体育课的就别选了',1,1,1,3,0,0);
