INSERT INTO "reviews" VALUES('69d5d2f2f971c56b79e9a39f',359,228,'我都不知道前面给好评的是不是这老师自己找人刷的。上课无限点人起来回答问题，要不就是叫你起来读PPT，每周都得布置抄写作业，甚至还有经典背诵环节，每周发一段文章让你下课到她面前背诵。直接梦回高中。讲课更是一坨，觉得自己怀念高中生活的可以选她重新体验一下。而且节节课点名',1,1,1,3,1,0);
