INSERT INTO "reviews" VALUES('69d47dccb7e0dd42b26f7ee2',364,364,'固废来的，神人老师，上课不让干别的事情，做作业也要管，大三管的比我高中还严格。上课也上的结结巴巴的没有意思。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69d47da4807d4d3fd73c435d',365,365,'说话含糊，听不清楚，照着ppt念；上课是随堂要收小测试的，收的时候还要捏张数，为难人干什么；上课玩手机是要被盯着🐴的；是倡导自学的，但是上课不听是要挨骂的😁，老师你挺牛福啊',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('69d47905b7e0dd42b26f5fa3',365,365,'从未见过事如此多的老师，去上课要阴阳你不如不去上课的，讲课水平不详，动不动占学生时间讲课，如果你的教学水平真有你吹的那么高那你就应该能够知道要讲多久而不是胡乱占用时间。占时间只是一部分，你能讲清楚再说，看书能看懂的东西听了完全不懂，真是很有水平的老师。一分是活水的下限，不是这老师的下限。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69d4778fb7e0dd42b26f537c',246,228,'纯神人，大点名➕小点名，上课不让用手机，忘带书就让“滚出去”，作业甚至不发群里，逮着机会就要狠狠刁难同学，上课不知所云，口音还不清',1,1,1,3,0,0);
