INSERT INTO "reviews" VALUES('69cfd87b6a394b5e5c47ff13',293,375,'评论区的是同一个人吗？雷鸣不是女老师吗？温柔在何处？居然有四分？搞笑呢？咋评价呢，挺难评的，幸福心理学我推荐李玉梅，这是真的好老师。雷鸣老师过了更年期再选吧',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('69cfb6bf8591971b54408012',30,376,'放假前一天最后一节课点名，实习放到周末说自己周内没时间，学生们周末就有时间了？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69cf739b2a96a0191ad7ae42',377,377,'谁选谁可以不读书了，专心去上他的狗屁近代史。点个名换着花样点，不带教材还扣你期末总分，生怕你考高分。这种老师不知道哪来的，最水的课，最多的屁事，感觉自己老厉害了，觉得自己拿捏了学生。不让坐后面，还点人回答问题，点人就算了，回答不出来还会扣你期末总分，巴不得所有人认真听他讲完两个半小时。建议绝对别选这个傻福，作业也多，线上线下作业一起来。不带教材还扣分，说什么这次几分下次翻倍，无上限地扣。能不去就别去了，要保研的也别选，除非你认认真真啥也不干听他在上面叽里咕噜地说一堆，不然保研也别想了。选了的能逃就逃吧，外面的世界很精彩，看看花欣赏一下校园，自己认真学学准备考试也行，别去那里浪费时间还不讨好。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69cf62378591971b543e331e',378,378,'每节课一堆作业，上课点名不是让学生讲就是让学生上黑板讲，我真是哇塞了，动不动还要骂学生几句没思想没脑子没声音，讲课水平也很一般，控制不好上课时长',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69cf3d3c2a96a0191ad668e5',293,301,'完全一坨，喜欢放假前点名。人非常凶，可能在更年期，啥都不好，懒得说了。没有别的老师可以选所以大家也没办法。就一坨 没啥好说的 各方面都不咋行的老师一枚 ',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('69cf31be6a394b5e5c43c97a',380,380,'何老师人很好，特别负责，期末也会捞人，课下问问题解答很详细很认真，上课几乎不怎么点名，除非人少了很多，前一节课讲的内容不会下节课他又给我们所有人讲了一遍，而且课上写题他会认真看把你的问题指出来，让做完也会讲。上课有时候突然把自己讲笑了，新时代冷脸萌老师🌚真的推荐。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69cf2fc4b7e0dd42b253db96',103,6,'完全傻福。双标，提前不说要求做完了又让人改，第一节点完名走了一部分人，又说欺负他，毫无征兆再点一遍，关键是明明他自己说的点完了随便走😓莫名其妙，绝非水课😂自行揣摩吧孩子们',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('69cf1c216a394b5e5c431192',382,296,'大力！',5,5,5,15,0,0);
