INSERT INTO "reviews" VALUES('69ce35676a394b5e5c39548a',384,51,'老师好的很，分很高，总共点三次名，漏点名也有好的方法，第一次点名一定要去哈！不然不知道这个好方法。满昏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69ce34abb7e0dd42b24dee9b',385,27,'老师很好，即使平时不回答问题，请假不超过两次，只要好好写作业，平时分都会给满，本来开学还比较不安看评价。专业水平老师的也挺好，口语也好，顶多是上课有点无聊，a班嘛作业也确实多，每周都有。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69cdf03fb7e0dd42b24bedd5',122,122,'妥妥的关系户，没有一点学术水平，且喜欢装13觉得自己很有水平，平时分也是乱扣',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69cde6feb7e0dd42b24bba94',228,228,'平时分96，每个同学至少回答一次问题（4分回答问题分），多回答一次问题+0.5分，不挨个点名但是会点名提问（可以用来当作4分提问分），回答过问题一般就不会点你了，半期分数给的很高。唯一缺点是期末要查一次作业，作业每章都有，如果堆到最后写还是很多的，而且不能糊弄，但是这个作业相当于变相划重点了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69cde629b7e0dd42b24bb566',260,96,'绝世好老师，上课认真讲的好，严格但是事少，点名会在群里提前说',5,5,5,15,0,0);
