INSERT INTO "reviews" VALUES('69ca72e12a96a0191aaf29bb',85,407,'从来没上过这种新奇且干货充足的课程。本学期课程包含百分之四十的理论部分与百分之六十的实践部分（老师会在学期开始时调整比例），实践部分包含外出调研和骑行。老师的骑行经验相当丰富，专业知识也特别扎实，其本人更是德艺双馨，宛若温暖的太阳照亮全世界',5,5,5,15,0,0);
