INSERT INTO "reviews" VALUES('69c7814eb7e0dd42b22b332b',416,34,'讲课绝了，非常非常好，不是那种照着PPT念的，有自己的思路，讲的很清晰，很好很好很好很好很好，抢到他的课真是赚了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69c5fed92a96a0191a98e2e6',417,417,'强烈推荐徐图老师的课，因为每节课后都有我们最喜欢的测问环节，占总成绩五分，最后得分为：抢答问题次数/全班回答问题最高次数 *5分。喜欢测问抢答、卷死其他同学的快来！！！徐图老师在调动同学们上课积极性、利用人性博弈提升课堂参与度这块太权威了，非常推荐！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69c5f9e5b7e0dd42b2234ca8',418,418,'这个臭福老师天天上个课连时间都控制不了，上的数理统计一共两节课，下节课都上了还没下课，还说不让我们急，作业量巨多无比，每个一天根本洗不完，避雷避雷',1,1,1,3,0,0);
