INSERT INTO "reviews" VALUES('69c0fca72a96a0191a80008a',457,457,'抽人你举手也不抽你，扯一嗓子奇怪的语调，反正我忍不了',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('69c0e2e2f971c56b79742b21',359,228,'老师有点古板，规则比较多，事多有点麻烦，但是老师比较负责，只要不是不按她要求的话不会乱扣分。回答问题和坐前排得平时分，每周有小作业。上课水平还可以，不算很好也不差，会有一些思辨的问题让学生思考，总体来说想水的话就不要来，但是完成她的要求和作业平时分也会很高',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('69c0cf33b7e0dd42b2093ae9',459,68,'上课很水，人很好。甚至你不去她都不怎么管，只要你作业写了，小测去了就行，平时分给的很高。',5,5,5,15,0,0);
