INSERT INTO "reviews" VALUES('69bcf7272a96a0191a6c0bf4',44,316,'上课的时间弄错了，当天想去问下午可不可以补，直接说不合规矩，我最后都上完实验了，还是不给我签字，说直接0分没得商量，自己悟吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69bcf051f971c56b795fd5b8',467,22,'平时分拉满，人特亲和，就是带个小蜜蜂催眠，不过我不去上他的课，适合翘课，签到就是点一下就行，人很好，PPT啥都有，自学也方便',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69bceff2807d4d3fd7c021b5',278,228,'适合乐于回答问题，胆子大的同学，平时分折合49.8，什么含金量不多说，但是不好意思回答问题别选，笔记分不高还麻烦，问题简单的要死，当场豆包搜都行，好老师不多说，胆子小别选哈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69bcef8b8591971b54d6dbd7',430,194,'平时分拉满，除了不能玩爱机，老师认真的很好，有口音，不过我不爱听课纯自学，很有意思的老师，',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69bccba66a394b5e5ce16d26',465,465,'拉完了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69bcc83c6a394b5e5ce15832',103,6,'纯恶心人这老师，三节课我第二节听完早退了，结果第三节开始就开始点名了，之前言之凿凿说点名前会通知，比如第一节看人少，所以第二节开始后才点名。对力兹学院的就说第二节起码听完10分钟再走吧，还双标他大坝呢，早退一次直接总成绩扣20分，没错是总成绩，纯纯扫码了',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('69bb587e8591971b54cdb4b6',430,194,'吐字不清，有口音，仔细听也听不出来在说什么。会收手机，随机点名，作业特别多。到底是谁在刷好评？',4,1,2,7,0,0);
INSERT INTO "reviews" VALUES('69bb56606a394b5e5cd91bcf',40,40,'老师已经改邪归正了，平时分给的很高，基本90多以上，上课会叫人起来回答问题，但是答不出来也没事。其中老师不收手机',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69bab162f971c56b79539498',229,229,'虽然教室全是回音 麦不行 但是老师人很好，平时分给的也高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69ba99d92a96a0191a601899',475,475,'好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69ba716e807d4d3fd7b33d24',476,476,'他真的好强，第一节课不开灯，第二节课倒没出啥幺蛾子， 第三节课就开始了，玩游戏的他不管，我们在那正常讨论他还就请你出去了。其他老师还巴不得你在那讨论呢。他就喜欢死气沉沉的，活该收获那么多的差评。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('69ba69a8f971c56b7951d4d6',476,476,'神经病，第一节课不开灯，第二节课倒没出啥幺蛾子，第三节课觉得锁定名单了，开始发神经了，没见过哪个老师会管讨论的，他一上来就说不要交头接耳，玩游戏的他不管，就盯着一个人看。最主要的是还把我给连带了，还让我们出去，神人。离谱，撒比老师，一天的好心情都没了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69ba5bddf971c56b79515cf3',478,478,'人不错，就是很笨',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('69ba4da9807d4d3fd7b22d5b',479,93,'在活水给的第一个评价，人如其名，翔。一个七周的水课极尽可能地为难学生，上课分组坐，节节课点名，上课要回答大量问题，长的也丑，上这节课见这个人要做好心理准备。精神物理双重攻击！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69ba4c67b7e0dd42b2e89002',480,92,'就这么说吧，全校估计唯一允许旷课迟到，作业也是管得不严。总之，轶文轶文我爱你',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69ba4add807d4d3fd7b21abb',479,93,'恶心的要死，强制分组坐还安排座位。上课必须讨论，还一个组一个组来回答。就他屁事最多，还一堆任务，还要在QQ群上传课堂互动和课后作业。什么玩意儿，真的恶心，遇到他简直享福。一个水课管的真宽',1,1,1,3,1,0);
