INSERT INTO "reviews" VALUES('69b79d5e8591971b54ba1fc5',54,54,'第一节课就遇到这神人，说全班都不该来上课也是没谁了，上课讲答辩啥也说不清楚就让你做实验，做完还说啥螺丝没拧紧要扣分？？？对实验数据挑挑拣拣说对不上让你重做，下课了还剩一半的人没过关，遇上这神金有你好受的，0分都是抬举这玩意了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69b79b0c6a394b5e5cc6eae3',54,54,'拉完了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69b78a02807d4d3fd7a44786',334,175,'作业巨多无比，完全是浪费时间的那种，其他制图老师基本都是选几页勾几道题，他直接让你把那几页全部做完，还让你猜他下次收哪一页。上课枯燥无味。',3,3,1,7,1,0);
