INSERT INTO "reviews" VALUES('69b6bc686a394b5e5cc3623b',496,496,'非常接地气的一位老师。很少点名，上完一章会有一个布置作业，一个星期完成。平时慕课挂起走，作业正常交，一般给分都非常高。老师还会在群里和学生互动，分享和学科有关的新闻和趣事。总的来说选他就对了😋',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b6ad8fb7e0dd42b2d74028',429,33,'妈妈',5,5,5,15,0,0);
