INSERT INTO "reviews" VALUES('69b63289b7e0dd42b2d44e81',334,242,'平时分给的低，不过上课不点名。上课进度把控不好，CAD那一块直接没时间上，说那部分成绩算到平时作业里',1,3,1,5,0,0);
