INSERT INTO "reviews" VALUES('69b3bdc7807d4d3fd79183fa',429,33,'夯中夯，特别温柔的一个老师。也会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b3bd896a394b5e5cb360a5',504,5,'平时分给的特高，几乎无点名，偶尔会有随堂测交了就行，教学中规中矩略有些无聊，但人确实是很好。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('69b37d59f971c56b792de839',505,250,'好人，讲得挺清楚（略微有一丢丢快，但是可以接受），一般不抽问。忠告：好好写作业！不然你会后悔的',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('69b3795b2a96a0191a3cb2a8',264,230,'满昏！期末划重点，点名提前通知！不需要通过回答问题挣平时分！而且平时分库库高！幽默风趣，性格温和，知识渊博，还会讲很多有意思的事！唯一的遗憾就是只上一学期😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b378e1807d4d3fd78c6bc5',214,36,'一定要来，老师上课很👍，上课玩手机的寥寥无几，讲课效果太好了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b3789eb7e0dd42b2c3f167',346,56,'认真负责,和蔼可亲,平时分拉满👍🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b378768591971b54a312c9',509,96,'垃圾，讲得烂是原罪，只会念PPT，还讲不清楚，最关键的一点，上课随机抽问记平时分。辣鸡，别选',2,1,2,5,0,0);
INSERT INTO "reviews" VALUES('69b235cb807d4d3fd782891f',510,86,'真的很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b224d4b7e0dd42b2b8070e',237,237,'上了这个老师的课，我只能说哥们，这辈子你的高数有了。这个老师上课水的还是有说法的，如果你想听他的求学经历、旅游经历，那只能是欢迎。说话特别糊，还有超绝气泡音，几乎就是听不清了。还特别喜欢开不好笑的玩笑，如果对机器人女友有想法的，可以找他畅聊。课程内容，上课和不上几乎没有区别，坐在那里也是听宋浩。如果想听课的，就别选他了；如果想不上早八的，选他总没错，因为他从来不点名，除了最后几节课。',1,1,2,4,1,0);
INSERT INTO "reviews" VALUES('69b21f24f971c56b79218a38',162,36,'水课闹麻了，快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69b1b9a2b7e0dd42b2b6a2d3',513,66,'有九避九，选九重开。交大最尊重孔孟之道的老师，去了你就知道什么是尊师重道，什么是双重标准，群里面发消息是不可以的，私信问他事情也是不可以的，说好的加分是没有的，课上的比赛是一点都落不下的，连太极这种都能不让别人过，篮球好的没必要来他这里受气，篮球不好的等着挂科补考ptsd吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69b198cbf971c56b791ff213',433,433,'在A班里面算不错的，纸质作业不多，平常事儿也不算多，上课除了讨论只会在台上坐着，在底下干嘛都没人管你，任务只要你做了不管是不是刷的平时分给的都很不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b198b66a394b5e5ca2eb1b',515,118,'巨好无比的老师，快来！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b1977f6a394b5e5ca2e6af',516,516,'一个选修课，中医美容学给分巨低，到底要怎么样？课也去上了，也没书，考试就是纯开卷，还可以用手机搜，最后却给分巨低，这是想把我们骗进来杀吗？没招了߹ ߹',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('69b18b99f971c56b791fc653',517,517,'老师非常好！给分也可以！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b17e126a394b5e5ca28301',346,56,'爆好无比',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b15e2d2a96a0191a307460',237,237,'善于培养学生独立自主自学能力，上课风趣幽默，关心学生身体健康，每天都在说小心感冒.平时分能给多少给多少.除了上课梦游，绝对是一代天师.',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69b158d7b7e0dd42b2b4e969',86,86,'无敌无需多言 ',1,1,1,3,0,0);
