INSERT INTO "reviews" VALUES('69ad775f2a96a0191a18876b',23,23,'对教学充满热情、对学生充满爱心的好老师！被老师的激情教学深深感染，对编程从怕到喜欢，不仅高分通过，还收获很多做人的道理，感谢刘老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69ad39e96a394b5e5c83839e',551,551,'这个老师讲的很一般，但是我上课不听课所以没有影响。她是我在这个学校最喜欢的老师，人超级无敌好，她四周才布置一次作业，人来的太少了才会查人，是我上的最滋润的一门课程了，虽然我数据结构没学到什么东西。最后期末的时候还会单独给每个人发消息提醒我们复习。我最爱她了',5,5,5,15,0,0);
