INSERT INTO "reviews" VALUES('69a52b13f971c56b79cf3b15',587,587,'嵇昂老师非常认真负责，课堂也很有趣，平常非常松弛，给分也很高，跟自动控制原理的蔡亮成老师相比，我不敢相信他们是一个学校的老师。',5,5,5,15,0,0);
