INSERT INTO "reviews" VALUES('69a5271d6a394b5e5c591c00',573,573,'压平时分的神人',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('69a51b066a394b5e5c58dafa',591,242,'真的是很认真负责的一个老师，平时分给的挺高的，考前不断给我们讲重点，很耐心的解答问题，作业也改得很认真，只要你稍微认真学，工图拿个高分不是问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a51a2a2a96a0191ae33d3e',592,194,'平时分给的很宽松，老师人也很好，课堂氛围蛮轻松的。如果你有挂科的风险，老师会努力捞你的，除非你的分真的太低了，平时分拉满都救不回来',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a513edf971c56b79cec122',593,593,'可以',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a50d5e6a394b5e5c589440',515,118,'管的很松，但是对考试要求很高，上课的声音比较小，建议坐前排。总而言之，想考高分不建议，想水的话更不建议。',5,2,2,9,0,0);
