INSERT INTO "reviews" VALUES('69a504e1807d4d3fd7354753',430,194,'虎子神了，高数挂科了去补考，寒假一点没学，考前看了两眼，考完感觉废了，就这还给我能捞过了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a4f34b807d4d3fd734c007',85,597,'那还说啥了，你都给我发抱拳emoji了，这五分给你了呗',5,5,5,15,0,0);
