INSERT INTO "reviews" VALUES('69a4d87db7e0dd42b260eab5',261,600,'张口就说自己招研究生优先录用男的的来了🙄✌️',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69a46261b7e0dd42b25fec19',380,601,'挂科率40的工力都没挂但是额外复习了一倍时间的电路挂了，明白了没',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('69a4244e6a394b5e5c54e288',602,602,'上课有点枯燥，给分还不错，缺席了后果也不严重，中规中矩吧。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('69a423cf807d4d3fd731b421',603,603,'笑面虎，上课不教知识，念个PPT都念不好，你问他问题他叫你看书，布置个课设没人会做还不教，上课每节课数人，平时分40分期末卷面还没出就先扣你14分，完全不捞一下，选到他你就吃到大芬了。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('69a3eeb8b7e0dd42b25d38c0',604,229,'神中神！除了有点口音外都神！平时分给满了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a1d1be6a394b5e5c49e7d4',605,605,'老师讲课还行吧，除了经常喜欢写板书，稍微没听懂就真的听不懂了，给的ppt稍微有点乱，不过通信原理这门课本来就难，其他老师好像也没好到哪里去',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('69a1d0352a96a0191ad311d8',606,606,'从小韩毕业回来的老师，上课要求很多，要电脑录屏现场写代码，会来来回回走检查有没有人用手机，期末课设虽然有点繁杂，接近于要写一篇数学建模论文的形式，但是给了一个月时间，而且最后给分不算太低。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('69a1cf7b2a96a0191ad3100d',607,607,'老师人非常好，和蔼可亲，懂的知识很全面，实验给的分也很高，期末开卷会给考纲ppt，可打印，卷子里的内容几乎全都在ppt可照抄，虽然不知道为什么感觉全抄上了期末也只有八十多分，总评89，不过相较于另外两个限修，可以更轻松地拿到同样的分数。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a1971d807d4d3fd72574a3',607,607,'老师巨好，上课有问必答，平时事情也少，期末开卷考试，想要不复习都能期末高分选就完事了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69a190c3807d4d3fd725557f',609,535,'没什么好说的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('699ef16cb7e0dd42b2466223',610,610,'捞人这一块没的说，期末一道大题不会给我捞起来了',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('699db2aab7e0dd42b2411ed7',121,611,'说是上课水，而且分数不低，实则不然。因为班里有人平时什么都不干，平时分极低（30分左右大家自行想象，只有想不到的低，平时分30，期末需要90才能及格，但平时对自己就不上心到这种程度的人期末考90可以说是天方夜谭），为了不让他们挂科，提他们的分数，平均分高了，为了平衡把我们这些按时完成作业，上课全勤的人的分数调低。我这学期学习通上各项任务全部完成，上课全勤，每周的单词测试90往上，最后的成绩在教学班算不上前三也有前五，一定有90，最后得了78。既然一开始有说好评分规则，为什么要最后全部课程结束登分数时候临时调低？别的班实事求是，她美其名曰捞人，实则毫无规则意识和契约精神，调低分数后火速跑路解散群',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69956a268591971b5404fb49',612,612,'建议直接转去哔站深大，上课不怎么样，而且不让看手机，偶尔还会给后几排提问，很抽象。半期考试比较严但是可以偷偷用手机，期末考的难度中等，挂科率大概百分之二十，能选金秋延还是选金球延',4,2,2,8,0,0);
INSERT INTO "reviews" VALUES('699568f68591971b5404f896',613,613,'期末最后两节课讲完整个学期的内容，懂得都懂，但是期末给分有随便给的嫌疑，好好学和背题甚至基本没区别',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('699563d7807d4d3fd7f88889',614,614,'这学期第一次开FPGA这门课，上课体验感有些欠佳。感觉这门课适合数电学得很好，verilog基础很扎实的同学，像我这种数电差不多已经忘干净了的听这门真的很痛苦。要学的话可以去慕课或者哔站听听他讲的Soc什么的，期末考的还算比较基础，很少挂。另外最后一节课一定要去，会讲考点',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('699556aeb7e0dd42b22300c7',615,615,'感觉可能是电科专业大三上最好的老师。上课从来没点过名，但是课前要交作业就当考勤了。讲课非常好，板书都是手写，下课后还会发到群里，而且有些方法跟网课不太一样。期末考的也很简单，只给挂了四五个。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6994bcf0807d4d3fd7f72ed8',616,616,'这学期有幸选到吴老师的数集。本人上课没怎么听过，但是听认真听了的同学说讲课极水，多半时间在吹自己做的芯片，很少有讲正经内容。发给大家的PPT也是不知道怎么搞来的英文版，简陋到像是他自己做的。期中考试要排座位，还是比较严。期末考试往届都背的题，但是我们是出的新题，之后估计也不大可能考原题了。但是期末真的能捞，专业百来人没有挂的。感觉只求通过的uu跟春哥就行，想好好学的话还是建议转去听阳至瞻',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('698b22c9f971c56b79738dc4',617,617,'很随和的老师，点名会提前说，一学期大概七八次的样子，事少分高，无脑选就完了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('698ab2c42a96a0191a7c4845',618,457,'想拿高分快跑',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('69860ec8807d4d3fd7b8b8f3',6,619,'平时分只要不缺课，交了大作业给分还是挺乐观的的（今年我的分数是49分，满分50），但是但是但是！期末给分真的很低很低，认真学了挺久的，也挺有信心能考好的，期末分数一看直接炸了，班里同学也一大片一大片的六十几分，反观问了几个别的认识的同学（都是比较摆烂的那种），他们的老师最低也给打75+，80+的更是好几个。总之，你要是对自己的学习能力和考试能力很有信心，我建议你可以选他，其他的直接跑吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6984d03cb7e0dd42b2d64210',239,239,'很舒服的课，能在轻松愉快氛围中学到东西。老师人很好，爱说笑。据说去年保研有160多个学生填报他，全院最🔥导师了吧。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69848ca6b7e0dd42b2d51643',581,621,'大便，就他开这门课，想跑都跑不了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697e266e2a96a0191a461867',622,535,'讲的挺慢的，上课是挺水的，不怎么为难学生，中规中矩，期末会画重点，平时分也就是一个正常水准',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('697e2595b7e0dd42b2b872df',623,623,'电磁场，平时分给分很高，但真的听不懂，期末还是靠自己从头学吧。',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('697e24f02a96a0191a46117c',607,607,'三个限选，最推荐网络攻防，做实验有困难老师非常愿意提供帮助，平时上课也不用怎么听，期末考试开卷，跟着重点来完全没问题，无论想拿高分还是只想过，选就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697e23f8b7e0dd42b2b86d47',625,625,'老师讲的真的很好，上课多回答问题平时分基本都是满分，很为学生着想的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697def028591971b54a0ce1f',626,306,'千万别选 否则挂的风险非常大 给分巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697c1141da464b3c7da68d2e',627,627,'每节课固定嘲讽学生，给分难评',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697b4ed686897719aa3bd878',241,241,'完全神人，根本不捞人。我有门作业交到他邮箱甚至特地提醒了他要查收，他忘了看，给我平时分扣了五十来分，关键我期末考的高，最后总成绩定格在58分他都不愿意捞我。气死我了，永恨！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697b28b486897719aa3af23f',581,19,'交大什么时候开除这老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697b288251d91804b2d10d33',630,630,'给分高就行，起码不会莫名其妙挂人。上课能不能听懂一定是我能力问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697b284bda464b3c7da2f833',631,631,'狗屎老师，喜欢百分之五十的挂科率吗',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697b281fda464b3c7da2f745',357,357,'💩中💩，快跑，恶心的要命',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697b27debfa69d75a2359004',92,52,'很糟糕的老师，重修也不会捞，讲课水平差的要命',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697ad758ecda1f2ec3eb1108',80,80,'能过的分就是用平时成绩卡着你',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6979b7cdecda1f2ec3e62548',85,407,'神了 总评100分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6979aba18f092806556e81d0',636,636,'上课水 分不高 考勤都在 大作业水过去 平时分只有61',2,3,4,9,0,0);
INSERT INTO "reviews" VALUES('6978bb091c9d68479694ad88',637,211,'幽默捞石',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69788c5ac8f81e5498f624ff',638,638,'课堂规矩多，给分还巨低。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697884cdd4c46d3fcacadb34',221,36,'从来不讲一点书上的知识，规矩特别多，给分极其低，拉完了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6978846ac8f81e5498f5f791',640,229,'不点名，给分还行',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('6978830d7ec103259b12ed02',41,641,'给分非常高，很少点名',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69783c688f0928065567d62b',642,24,'不考勤不点名不捞人，选了就是挂科的命，认真学的也别选，给分非常低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69775f74fc754f151d5f167d',643,643,'上课纯吹牛b，给分低的要死，遇上倒大霉了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6976653c8f092806555f0488',636,636,'神！给我海底捞起来了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6976256e1c9d6847968825e8',527,527,'点名次数中等，作业只有一次是在学校里面拍花，平时课上会让你拍她考试的内容，然后期末可以打印出来开卷考（考的全是让你拍的），平时分给拉满了，期末也考90，而且老师有几节课会介绍一些植物包括学校里面有哪些果树可以吃，讲课的内容真的很精品很多对生活可能都有一些用，不过确实出现了一些人成绩低的情况，我朋友一起去的，他的分就最后只有70多，这种情况我猜可能是因为他的作业是ai+网图，然后期末考试之前没有浏览一遍那个打印的ppt一些知识点可能有点类似然后写错了也没有发现，每一个题的分值还是挺高的就被扣分了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69762370c8f81e5498eaf67b',164,164,'大四限选课真神，我上课这学期一次名没有点，一个翻译论文的大作业，期末直接给了99，夯爆了，考研考公的很适合选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69762284fc754f151d590048',647,647,'上的地下工程课设，半学期的课老师一半时间都在请假找其他老师代课，上的七零八乱的，回来之后就开始要收课设，没有任何实质性的讲解纯靠自己学软件，学各种内容，水的不行不行的，而且好像她要求的还比别的老师多，还要画图，听学长说他们之前随便做做别的老师都给80多，我自己做了虽然说也不可能完全对，但是只给了65分，可真是治学严谨呢，想课设得超绝低分然后再画图你就来吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6976211d7ec103259b064409',648,78,'那个说夯的不知道夯在哪里，大四经常点名，点名这么多次，平时分也可以这么低，课设给分也贼低，要不是别的班有重点，不知道咋过',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6975eb57fc754f151d57acee',649,36,'纯纯sb一个，平时分低的要是，闹麻了这玩意',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6975c55ffc754f151d56a6d5',650,650,'透露着成熟中年男人魅力的平时分满分王者唐主任你值得拥有',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69757f1a1c9d6847968407c0',650,650,'课程节奏稳定，讲解细致通透，典例通俗易懂。你可以不相信你自己，但一定相信你唐主任。伟大无需多言！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69745999d4c46d3fcab0e9f5',652,198,'虽然作业本成双、期中考试正规、每节课都有课堂练习是真的，不过老师上课讲得也还可以，不缺勤不迟交作业不缺交课堂练习的情况下平时分给得也还可以。活水评分比龙文杰的分还低有点太过分了，个人觉得应该跟白海峰差不多，3分左右。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('69743afe7ec103259bfbfba3',86,653,'要求特别严苛,不过最后的分还行就不给你打太差评了😡',3,3,2,8,1,0);
INSERT INTO "reviews" VALUES('69739d0cd4c46d3fcaae5cc8',245,654,'看不起人的样子，装...',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('69739cdb8f0928065551f40e',56,56,'好老师，专门注册来评价陈老师。神闷',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69739c98c8f81e5498df061d',55,55,'神！神仙老师，特好一老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69739657fc754f151d4cb62f',527,657,'神人老师，期末考试全用手机搜的只有20多，搞的我大四下还要选一门选修',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697395f91c9d6847967bce79',658,658,'👍🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69735af5fc754f151d4b5cdd',659,659,'上课只会念ppt ，没另外一个老师讲的好，期末口语考试给了题，结果上课时间不够全考完，于是临时换题让翻译，一部大部头谁能全认识，自己英语水平也不怎么样，dipole moment明明是偶极矩的意思非要说moment是时刻，moment是有时刻的意思，但是在这个词组里明显意思不一样啊，还非说我翻译错了，我也是无语了😓，自己也不去词典上搜，期末给的平时分也是个谜，平时每节课位置签到，人少也不说啥，期末了让助教查谁没去，于是出现了“匿名投票”让互相揭发…',2,3,3,8,0,0);
INSERT INTO "reviews" VALUES('69733c657ec103259bf7c754',660,636,'好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69733c641c9d68479679bad1',606,606,'😅😅刁难学生来的😅😅是不是有什么要求啊，不允许给学生高分的要求',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('69733c611c9d68479679bab8',606,606,'一分都多了，上课事特别多，还要录屏，上课写作业都要管，非要听他讲，给平时分也不高，很讨厌的老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69733bf81c9d68479679b84c',660,636,'好老师 给分高 亲近 讲课水平也很高 没有照本宣科 重点画的也很到位',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69733bb27ec103259bf7c316',664,664,'😅报告有一页下面空白比较多，直接给我了个C，神经😅😅😅',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('69733bafd4c46d3fcaac355d',664,664,'这个老师不负责，很水，问他个问题解决不了',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('69733b6cc8f81e5498dc514a',666,666,'老师挺有亲和力的，但是上课真的很无聊，幸亏这个课学的知识比较少了',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('69733b558f092806554fcb94',666,666,'邓涛老师人还可以，就是讲课很无聊，期末考试跟其他班不一样，要稍微难一点',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('69733b217ec103259bf7bf45',623,623,'老师人还可以，但是讲课超级无聊，而且真的听不明白，期末复习要死了，问他考啥重点根本不说',4,1,3,8,0,0);
INSERT INTO "reviews" VALUES('69733b191c9d68479679b2d5',623,623,'上的电磁场。马老师应该是学识渊博的，可惜马老师，完全看不见听不清啊😅😅😅😅',4,1,3,8,0,0);
INSERT INTO "reviews" VALUES('69733a9a1c9d68479679afc3',670,670,'全靠自学，上课在上面玩手机，我们在下面玩手机😅😅唯一好处就是没什么作业，平时分给的高吧但是期末复习都不知道怎么办😅😅😅ppt当个宝似的，要一百遍也不给发，从来不回学生qq，在群里都要跪下了也不给发，无语🙄不爱教课别来教',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('69733a19fc754f151d4a9e64',670,671,'讲的很一般，上课跟梦游一样，他讲两句话就在上面玩手机，根本讲不明白',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('697339d01c9d68479679ab2f',622,535,'上课前是不是从来不备课啊😅。上课感觉浪费时间。。',2,3,4,9,0,0);
INSERT INTO "reviews" VALUES('697339c41c9d68479679aae2',622,535,'不备课这个老师，讲的确实一般，平时分给的还可以，但是学不会',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('69733991fc754f151d4a9b26',674,179,'一般吧只能说，课设也很麻烦，现场验收，比其他老师事多',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6973398dc8f81e5498dc461b',674,179,'平时分也不高，课设也麻烦，与其他老师相比，无语了。。。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('697337eafc754f151d4a9137',676,676,'讲课一般，但是作业少事少，平时分满分，期中考试大家都满分',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('69733766d4c46d3fcaac1a07',625,625,'老师十分有亲和力，讲课很有条理，也不为难学生',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('69733648d4c46d3fcaac1313',383,678,'讲的十分垃圾，完全没有参考价值，期末也不画重点，全靠猜，没讲过还硬说讲过，完全没有章法',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697336397ec103259bf79e19',383,679,'大家快跑，不知道前面的高分是咋刷出来的，1分是因为最低分只有1分！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697335dcd4c46d3fcaac1077',625,625,'王千里老师人超级好，平时分也给的很高，从不为难学生，讲课是我见过最好的老师之一！！！每次课前都会帮我们回顾前面的知识，真的超级超级好！水平超高，思想很前进，很懂学生！！！！选到他的课就是赚到！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697331b81c9d6847967975a4',92,92,'不捞人，平时分多打5分就能过的、反正不捞',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('69732b62c8f81e5498dbd8d0',605,605,'只能说还行吧，但教这门课的老师就那几个，搜搜其他的也大差不差',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('69732a27d4c46d3fcaabb755',683,683,'听说下一届这课变成保研限选课了，要选也行，但建议换班',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('697326537ec103259bf72189',684,684,'极品好老师，刀子嘴豆腐心，好好听课可以学到真东西，非常乐意回答学生们提的问题，帮你建立系统性知识库。平时要求比较严格，嘴上说着不捞不捞，但期末还是会疯狂海底捞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6973257a8f092806554f20f0',685,685,'上的他的大物BⅡ，上课完全不管，为数不多的点名也比较随意，适合喜欢水的同学，期末也会划重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697324ded4c46d3fcaab93a6',686,686,'对于想水的学生来说是极品好老师🥹，只要不干扰正常授课几乎不会管你，期末也是尽力海底捞，对于好好听课的同学也能学到东西，给分也不低',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697324bbd4c46d3fcaab92c9',609,535,'每次上课前记得预习一下哈，不然讲都讲不明白，还要搞得很无辜',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69731e668f092806554eeecc',293,375,'雷老师的大学生心理健康给分是真的高，很多次上课没去总评还有94，平时上课也挺有意思，无脑选雷老师是对的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69731d1cc8f81e5498db7370',7,7,'看打分就行，不必多说！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6972f7018f092806554e012f',684,684,'老师专业性很强，即使期中没考好也没事，在期末的时候还会把平时的额外加分成绩添加到期中成绩上，总而言之老师很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6972e80cc8f81e5498da21ec',691,228,'神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6972e8077ec103259bf5b15e',692,174,'感觉老师有点“两极分化”，期末是真捞，给分很心慈手软了，平时分也将近拉满了。但是平时事真不算少，半期考会排座位出卷子（卷子上的题挺多的）闭卷考，基本每节课都有点名，期末划重点也感觉划了一本书。
INSERT INTO "reviews" VALUES('6972b9b7d4c46d3fcaa8a48e',693,693,'屎',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69724cc5d4c46d3fcaa7d5c0',637,694,'好老师',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('697231561c9d68479675637e',691,228,'平时分高 也不管玩手机的事（基本不管） 人还不错就是有课堂测试啥的也计分 ',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69721c3bfc754f151d45da27',696,696,'逆大天，上课云里雾里只会念ppt，ppt还是十年前上古时代的宝贝。巨喜欢随机点名抽问题，重点画的稀烂，平时分给不了一点，上他的课纯遭老罪',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69721ab5d4c46d3fcaa6c971',696,696,'邱小平又发力了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69721a887ec103259bf2f772',696,698,'智慧物流真是烂完了，上个智慧物流在这里讲什么强化学习大语言模型，我去，这些和这门课有什么关系，重点是不划的，全部都是重点，分是给的低的，无敌了！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69721574c8f81e5498d5659d',699,2,'好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69721458c8f81e5498d56060',5,5,'代老师是神，虽然没怎么听过课，唯一一次点名还不在，平时分依然给了90+，人很和蔼，作业一个月留一次，习题册十几二十页',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('6971f4ccc8f81e5498d4b224',637,694,'老师的人很不错，授课很专业，也很有人格魅力。作业量相对比较多，给分的话可以接受但是不算高。一学期下来收获很大，但是可能需要花些时间。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6971f0ed7ec103259bf21dda',702,702,'崩溃，平时分倒是跟另一个班差不多，期末卷面分别班几乎都是八十多，崔老师这个班基本都是六十，，那天晚上背到两点半早上又起来背，而且考完自我感觉也还算可以，结果这么低我真服了。。。。。。。跟另一个班的分相差这么大存心就是不想让我们过个好年吧。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6971b095d4c46d3fcaa45907',703,228,'感觉神中神。需要课堂汇报，但有就行，无期中，有几次简单课堂小测，可能需要回答问题和课下思考题，但可以第二节课上写，上课极其轻松。给分相对很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6971aeb28f09280655485001',704,704,'郭老师永远滴神，讲课很有责任很有激情，是真的能学到东西，平时分给的也不赖，总评97在此真的感谢郭老师（电分BII）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6971a6e67ec103259bf04a11',705,705,'平时分只扣了1分，上课有点阴，但是平时分给的还行，每节课正常去',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6971a02bc8f81e5498d2c1ec',706,706,'没吃过是可以试试，老师根本不管你学习态度认真不认真，每次都是认真回答问题，也坐前排，根本不认真看作业，屁事贼多，别的班期末都给重点，就他不给重点，傲慢自大，想保研或者那些正常想通过的人，你可以试一试选他的课怎么样？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69719f6c7ec103259bf026e3',304,707,'非常不推荐！
INSERT INTO "reviews" VALUES('69719f55fc754f151d43030a',708,708,'很用心的老师，可能平时分判得比较严，但是亲和力直接拉满，有不会的题目能给你讲很长时间',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69719960fc754f151d42d58b',709,709,'老师教得很好，课上讲的例子生动，贴近实事，真的是平时听课就知道是很认真备课的老师。划重点：很帅！非常有耐心，知识量很丰富，特别好的一个老师。给我们讲解的课程内容也很深入，给老师打call！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697198448f0928065547d09c',709,81,'我觉得老师上课很风趣幽默啊，很温柔，内容讲得又好又清晰。关键是我们都觉得老师好帅（绝对真实），大家快去选这门课程，有实力又有颜值的老师，抢到的有福了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6971942ac8f81e5498d262ed',322,322,'上的是她的职业生涯规划，给分巨低，每节课都点名，每节课都会布置作业，没旷过课，作业次次都交，最后平时分和期末只有七十多分，不知道怎么得罪她了，可能因为我教评打的低吧。。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697193dec8f81e5498d260af',712,712,'老师很亲和，课堂很水，不布置作业，但是给分不会很高',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('697192f7fc754f151d42a26e',709,709,'    老师又帅又有型，站讲台自带气场，听他讲课完全不会觉得枯燥。
INSERT INTO "reviews" VALUES('697191f3d4c46d3fcaa3a0bb',709,81,'    王老师人帅有型，站在讲台上就是行走的“思政男神”，而且讲课特别接地气。
INSERT INTO "reviews" VALUES('69718ffefc754f151d428b2a',715,394,'平时分很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69718f3c1c9d68479671a563',716,716,'虽然老师很喜欢吓唬人，但机考CAD很松，作业助教人也很好，平时分几乎拉满',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('69718e3efc754f151d427c26',78,78,'没有考勤没有作业，平时成绩给六十多，去上课等于白去，完全没有区分度',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('697188097ec103259bef811c',718,718,'平时分拉满！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69718710fc754f151d424f0c',304,707,'离散数学没有只能跑到这里来评价了，上课是纯读ppt，遇到题了还得自己思考一下才能讲出来，跟没备课一样，一学期只有一节课没去课堂表现只给了75分，折算下来扣了2.5分。',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('697168b7d4c46d3fcaa2ae46',720,720,'龙姐姐捞人真得好好啊😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970f7cf7ec103259bedbd23',721,721,'背刺这一块',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6970f1048f0928065545db67',722,722,'交通运输安全工程来的
INSERT INTO "reviews" VALUES('6970f0e01c9d6847966ff19f',723,723,'好老师啊
INSERT INTO "reviews" VALUES('6970e8b88f0928065545b81d',724,631,'毛老师很友善，为了让同学们安心备考，编程作业直到考完几天后才收，平时分给的也很高。除此之外毛老师是一位原则性很强的老师，对于旷课被抓找借口这类事情深恶痛绝，平常还是老实到课比较好😂。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6970e2708f09280655459ec0',725,40,'老师人很好，事情少，给分很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970e23f8f09280655459dfd',726,726,'嗯……作业难度超级大',5,3,1,9,0,0);
INSERT INTO "reviews" VALUES('6970e20f7ec103259bed6e70',727,727,'平时分给满，老师人超级好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970e1d51c9d6847966fb527',728,728,'老师讲的很专业，对作业要求不严格，可以补交，半期考试可以查书，平时成绩基本给满了，超级好的老师！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970dc68d4c46d3fcaa12bf5',716,729,'平时分比我期末低好多 助教很好 不晓得哪一步出了问题
INSERT INTO "reviews" VALUES('6970c06ac8f81e5498cf8c20',730,143,'我素未谋面的讲师(⸝⸝⸝ᵒ̴̶̷̥́ ⌑ ᵒ̴̶̷̣̥̀⸝⸝⸝)，听着他的网课考试的，如果不是听他的网课期末必低分。春哥我倒不怪他，他平时分拉满了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970c001fc754f151d3fd5c6',373,619,'平时分拉满了，我还能说什么？这可是保研课呀。老师我爱你(ღ˘⌣˘ღ)，79分期末分给我拉到90分，你不是五星上将谁是？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970beb7fc754f151d3fcdae',732,156,'跟机械设计张静做一桌的水平，我看专业课老师就2点，要么你会教书，知识点能讲明白，要么你平时分高点，摆烂划水不上课还想当严师的我通通给一分，平时上个课，半节课唠嗑，半节课看书，半节课讲课还天天点人划水，最后水到还剩半节课就让大家写练习（不讲评纯自习的那种），你怎么不去教思政课去？接着就是给分低期中考考的难的要死全班最高分才85分，真勾巴低分，最后给总分还是抹0不进一的那种………唉真服了，下学期选课直接换人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6970bccbc8f81e5498cf78c5',733,335,'反驳一下之前的观点，线下的学习才是重点中的重点，反而线上那些知识点有点食之无味弃之可惜，作为一学期每周抽出3节课来看MOOC的我来说，如果要重修这门课我觉对不会再看一次MOOC，一点用没有，多找学长学姐要一下往年考试题目和线下仔细听老师讲练习题才是最重要的，知识点系统性的学几天就能学完，平时作业认真做考个90作用不难，这个老师讲课其实很不错，平时分给的也很不错，尤其是阶段考，我根据答案估分估出来以为都是60多，结果一个80多，一个93，OMG这绝对是他心慈手软才能给出的分数，最后总评89，这个老师是真好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970bb5ed4c46d3fcaa06775',563,228,'中规中矩，请假如果不是病假扣1分，回答问题+1分，作为全班回答问题相对比较多的同学，拿了94分的平时分，前三周是一个平时分97的女老师给我们上课，然后突然就换成她了。说实话，不是很高也不是很低，但怎么说呢，唉。不说了，老师人还不错，平时分也没多低，只是我其他课考的不怎么样，作为最后一门出成绩的科目也没给我很多惊喜，有时候也在思考为什么要花快2天的时间准备马原这门课而不是专业课。这门课复习感觉一点性价比都没有，期末考了个75分，不高也不低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6970a5041c9d6847966e5da5',630,735,'拉完了，建议等成绩出来给他打分，（ps补考故意卡你不给你过）',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6970a06c7ec103259bebed5b',736,736,'老师特别负责！作业每次交上去都批改，平时分只要平时按要求完成作业和代码练习都不低。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69709ff28f0928065544234a',737,737,'给分原则：You make me happy ,I make you happy!
INSERT INTO "reviews" VALUES('697099e2d4c46d3fca9fbb21',738,706,'整个学院唯一一个不用期末考试，只用交论文就结束的老师！这一点帮期末节约了不少精力，其他老师都是一本书没划重点直接考试，很爽。
INSERT INTO "reviews" VALUES('697099928f0928065543ffc4',605,605,'讲课水平一流，内容清晰，课下问问题也很乐意解答，每节课都会签到，不建议逃课或者代签。
INSERT INTO "reviews" VALUES('697097ff7ec103259bebb575',740,740,'从交通运输规划原理过来的，必须给这个老师好评！！很有思考，深入讲解知识，鼓励交通算法编程。引导我们看电影《美丽心灵》，思考博弈论在交通中的引用，让我们阅读前沿期刊。课堂内容也不局限于课本，让我们自由选择，可以讲他自己的研究、交通运输相关期刊分类等等感兴趣的话题，好老师啊！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697096ddfc754f151d3ef78e',741,741,'很难评价的一位老师。
INSERT INTO "reviews" VALUES('697092e21c9d6847966df564',193,193,'给两分同情分都没戏，无敌了，讲的啥啊？照ppt念就完了？补考还不加平时分，不像是一个人类',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('69708c6dd4c46d3fca9f6994',743,743,'老师蛮热情的，但是建议生工不要选这门，制药无所谓。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69708ab67ec103259beb6581',706,706,'选到就是赚到',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69708a61d4c46d3fca9f55e4',703,228,'半期测试和课堂小测竟然采用在群里抢答的方式，我从未见过这种考试方式，而且她明知道很多人根本不看题，abcd的选项都是蒙的，依然坚持按照这个标准来给分，导致我的不定期考试跟随堂测验拿了很低的分，因为在群里抢答根本抢不上，',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6970883b7ec103259beb4fac',532,141,'一坨，选到了赶紧跑，毫无人情味可言，就是故意恶心你。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69707a908f09280655432666',221,36,'懒得喷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69706bd5fc754f151d3dd86f',748,392,'看到好多人给王瑞老师的评价都不是很好，我也偏个人角度的评价一下。
INSERT INTO "reviews" VALUES('69706937fc754f151d3dcb63',181,749,'虽然是双语教学，但是感谢大史不挂之恩，他是真的会捞啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697054a88f092806554259c9',750,73,'钢结构最好的老师，平时分拉满，不点名，和蔼可亲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('697046401c9d6847966c19c8',751,573,'数物不清楚 工力还不错',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('69704403fc754f151d3cf639',54,54,'神人走出来，严以待人 宽以律己，会挨个检查实验结果和数据能不能对上，稍有差错就要等着他检查完一轮之后的第二轮检查。但是呢这位老师喜欢在验收实验的孔隙见缝插针地躲到办公室窝着玩手机，需要你去三请四请请神才请得出来，态度恶劣没耐心，虽然最后你给了我比较高的分但是大概率是我遇上了心软的助教或者你摸到了虎符咒分裂出了善良人格。遇上这个老师我做的恶从此一笔勾销',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69703e127ec103259be98ff4',188,188,'从想要在这个课水一点的视角来看这个课其实还不错，虽然上课要回答问题才能要一个不错的平时分，但是大部分问题都比较简单，翻书或搜一下很容易找到。一学期回答7 8次，没有缺勤，平时分差不多就满了。偶尔上课上着上着会突然走下来巡逻，这个其实还好，只要不在这个时候当着她面玩手机写作业她就不会发难，但其实就算被抓住了也就简单说一两句。然后点名比较勤，，连着好几周点名是常有的事',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('69703ca31c9d6847966bcc04',637,694,'讲的很好很细致，会讲各个公式的原理和推导，能把不同部分的知识点完全串联起来，很好理解，ppt和作业以及作业答案也发的很及时，只要按时出勤交作业平时分都给的挺高。就是上课比较喜欢互动，还会提醒一下不听课的人，而且期末出题太难了😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69703c937ec103259be973d7',755,142,'西南交大绝顶好老师之一，除了材力的作业系统屎中屎。但是龚晖老师的网课还是非常不错的，有知识点有例题，干货满满，看完了就能做题的那种。在群里回答大家的问题非常之积极，几乎全天在线。为学生着想，能从学生的视角出发看问题。不过建议网课不要水，至少把例题全部看完。这边给到夯',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69703b4b7ec103259be96b27',756,22,'老师人很不错，上课不管玩手机（就算做第一排，玩一整节课手机也不管），平时分比较好拿，都出勤了作业都交了就能拿满分，作业正确率不影响。而且老师似乎有个隐藏好处就是不会让你的总评低于期末考试成绩，我平时分比期末考试成绩低一些，老师算总评的时候直接给我取的期末成绩把我抬进了4.0绩点🌹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69703a19fc754f151d3c9ecf',309,309,'崔老师是个非常有亲和力的老师，给我的感觉像邻居的阿姨，上课时会告诉我们哪些不用听，哪些重点听，一学期布置三次作业。稍微有些不足的地方就是上课由于在一些地方讲得很细还有比较多的拓展导致进度追不上安排，可能会安排周末补一两次课，还有就是由于作业确实比较少所以对于计算题的练习可能不够，主要是混凝土计算题需要自己下来多花点功夫多找点题做。总之崔老师人好，为学生着想，非常棒的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6970339c7ec103259be932bb',758,676,'上课喜欢说很多废话，思想陈旧爱说教，但是平时分拉满了，能忍的可以选',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('69702d3b8f0928065541453e',759,759,'
INSERT INTO "reviews" VALUES('696ff10e7ec103259be83966',760,760,'绝对好老师，平时看起来要求多，经常说要扣平时分，但其实最后给分很高。本来考完期末感觉又过不了要三战重修了，结果最后直接给了我70多分，缺了几次签到和小测也都没怎么扣平时分❤️',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696faeb27ec103259be7cb22',761,761,'只能说，伟大无需多言！你就选吧，一选一个95+分数',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696fae5ffc754f151d3b10c9',762,762,'一般，真的是不好不差.....为啥期末考了快满分，平时分能给的比期末低不少呢，明明上课无缺勤，平时大报告全部认真完成与提交了',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('696fac608f09280655401c8a',763,763,'上了他的选修课科幻社会学，每节课都去，作业全交期末报告认真完成，给我70多分，拉低综测好几分，差评！当然如果不注重综测只想混学分，那可以选这个选修课.........',1,1,2,4,0,0);
