INSERT INTO "reviews" VALUES('696f93661c9d68479669b467',141,765,'大作业要求巨多，平时分特别低，期末总评还没卷面分高，避雷，选到就赶紧逃吧',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('696f92eec8f81e5498ca3566',582,442,'讲的不知道咋滴，但确实捞人。平时分只要线上作业分刷够就行了。这学期我最后成绩刚好60捞的水平不多说',5,5,5,15,0,0);
