INSERT INTO "reviews" VALUES('696f21db1c9d684796670cc6',232,24,'超级好的老师！！讲课也讲得很清晰很好，会强调重点，板书工整清晰；期末的平时分给满了！！！（期中考试的卷子老师让我们自己批改，最后给的都是满分）🥹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696f1edbc8f81e5498c7b9df',175,774,'杨老师虽然平时对我们严格，但是给分真的很高呜呜🥹平时分和期末成绩都是远超预期，给的特别高！！🥹最开始因为老师平时很严格，还担心自己能不能通过，结果一点开成绩特别惊喜！最好的大水果老师！！！大水果yyds！！！',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('696f1d9dd4c46d3fca98bbad',476,779,'老徐醒悟了？之前学长学姐反映的什么崇洋言论。diss学生我这届都没遇到，相反问问题会耐心解答，平时分基本拉满，非实习课被发现不去也没什么。作业是有点多但能做到期末原题。测量要求也不远。挺好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696f1b0d8f092806553cf602',780,81,'逆天，18周周一考试，现在是20周的周二，别的班成绩都出完了现在成绩还没出，好难猜啊(估计是平时分给太低，现在考完了登完让同学去补)',1,1,1,3,0,0);
