INSERT INTO "reviews" VALUES('696e24e98f09280655387612',798,228,'如果只是作为一门水课不怎么听，老师平时分给的一般，上课会用学习通随机抽同学回答问题，签到也是学习通定位，作业相比我室友的另一位老师确实算少，这学期只有两次，一个规定的大作业，一个是按照自己喜欢的形式表达对马克思的想法之类的。但正如我前面说的，毕竟对大部分人来说这只是一门水课，给分很一般',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('696e247d7ec103259be15105',799,799,'纯纯垃圾，每节课点名，讲课水平跟死了妈一样，平时分是乱给的，期末是不划重点的，问他平时分为什么不给满说每个同学的基准分都是80，别的班的老师都给满了，傻逼一个司马东西狠狠避雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696e1eddfc754f151d34695a',25,26,'我是线代的，首先老师讲课清晰，简单易懂，小测只要对大多数题就给满分，期末老师还会给往年期末卷，而且这个老师给平时分是有依据的，只要把老师留的作业按时完成，不要缺勤，平时分可以直接给满的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696e1dd38f09280655384f0e',5,114,'讲课不知所云像没睡醒在梦游 平时分给的奇低无比 没见过比他平时分给的更低的了 想拿高分的避雷',1,1,3,5,0,0);
