INSERT INTO "reviews" VALUES('696df999d4c46d3fca9255e4',807,807,'感觉这个老师属于刀子嘴豆腐心那种，平时上课吓唬你，说什么补考非常难，让同学们期末好好复习一把过。但实际上期末试卷出的很简单，只要掌握他说的重点就行了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696df9221c9d68479662630d',808,140,'夯！！！人很好，平时分几乎拉满，不需要说你回答问题才能有满分。亲和力也很不错，感觉这种思政课就选这个老师就很好了！！！！',5,5,5,15,0,0);
