INSERT INTO "reviews" VALUES('696ce0aefc754f151d2d7285',823,793,'超级 超级 超级 好的老师！课堂很有趣，只要上课跟着老师的思路走，这门课很好上90+，每次咨询问题都会很耐心地回复我，然然妈妈是最好的！！！可惜下学期没有老师的课了，感恩遇见如此好的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696cdfae1c9d6847965be387',480,92,'大物2选上了王老师，就这么说吧，大物这门课别的老师要求的10次作业，老王这学期只收了3次，平时分除了半期都给满，可以旷课，只要不打扰课堂就可以，老师讲的也很容易让学生理解，ppt很好，很有侧重点，最后一节课会给复习重点的好老师，大物总评100在此感谢老王！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696cd874fc754f151d2d2f14',232,24,'明禄哥我的一辈子',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696cce181c9d6847965b7f97',826,114,'个人觉得很不错的老师，只要你问她都会给你答复，虽然是高数老师，但课本之外的知识提问以及线代问题她看到了都会答复，而且给分很高，虽然有口音，但后面可以慢慢适应。总之是一个很棒的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696cc7038f0928065530c8d8',827,827,'陈老师讲课yyds，认真负责，期末会给你以往的试卷然后带着你过一遍，对同学很亲切，给分很高，半期错了三个题只扣了两分可想而知，但是期末会严格改。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696cc6ac7ec103259bd9a4e2',828,828,'虽然考的难，但是给分是闭着眼睛给的，按照pde的步骤写方程类型不要弄错，最后结果不对扣不了很多分，期末有填空写了就有分。不过不要妄想通过他讲的理解pde，只能通过后续自己去看自学，要结合他的讲义去听(虽然讲义编的一言难尽)。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696cc1be8f0928065530a1d7',780,81,'平时分是从0开始一分一分给的(每节课最多+3，满分20)，讲课是纯念ppt和放视频的，上课是要提问的，实践作业是比其他班多一个的。一讲课，第一节pre，第二节放视频，第三节提问，不如让我去当老师算了😓😓😓',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696cade08f0928065530348a',462,462,'专门注册的活水，上课全勤，作业一次没缺全按时交的，实验系统也是满分，期中虽然考的不咋样但好歹也及格了，最后给我70多分的平时分!第一次遇到平时分比期末成绩都低的情况',3,2,2,7,0,0);
