INSERT INTO "reviews" VALUES('696c534f1c9d684796589c9d',837,837,'你就选吧 上课不能玩手机 不能吃早餐 不能干自己的事 还会被收手机 被嘲讽 期末重点录音也是被狠狠教育 别的班是放ppt的 你多鱼就是要锻炼学生的听写速记能力 迟到一分钟是要被锁到门外的 最后几节课迟到是要被记缺勤的 缺勤是要被记俩次缺勤的 你就选吧 选上了乐呵去吧',1,1,1,3,1,0);
