INSERT INTO "reviews" VALUES('696baca3d4c46d3fca850e7a',842,370,'她的流体力学和环境工程我都上了，除了上课有点啰嗦之外，作业和其他班差不多。但是他的平时分是真的高。，环境工程平时成绩给了满分，流体力学接近满分，39点几，还是推荐上。',5,5,5,15,0,0);
