INSERT INTO "reviews" VALUES('696a67d98f0928065525d883',869,869,'评有限元：******十五周就给他交过一次大作业，纸质版电子版都交了，纸质版还彩印了七十多页。结果期末考完试又重新收了一遍电子版，因为学委发他的过！期！了！也就是半个月根本没点开过文件！考完试第二天有的同学都回家了，******让重新按他的标准交报告，纸质版也要重新交，也就是说这半个月不光没看电子版，连纸质版也没看！还说不在乎成绩的同学可以不重新交，什么叫不在乎成绩？拿挂科威胁我们？现在又要重新写文档，又要重新彩印！这课教不明白别交，写信辞职！把学生当人看吗？******',2,1,1,4,0,0);
