INSERT INTO "reviews" VALUES('69699c3d8f0928065520d106',214,36,'上课基本上是瞎扯，关于学科知识的部分就是偶尔把每段第一句话读一遍。每学期要发一次言，还要拍一个视频，都算平时分。拍视频要求也不说明确，一开始以为关于思政方面任意一个角度拍个视频就行，后来又说要是情景剧，要露脸。到打分的时候一个组每个人对着摄像头读一段知识点，他又说他喜欢这个，打高分。神经。',1,1,1,3,0,0);
