INSERT INTO "reviews" VALUES('696910a07ec103259bc833ee',925,925,'刚开始讲课会找人上去讲，期中考完就一直都自己讲了。前面几节课会更难听懂，如果分离变量和特征展开能听课后自己自学学会做题，后面就会发现他讲的其实还行。他上课是直接就着题讲的，我觉得会比仔细推导好，就是应试，听了懂做题但原理可能不知道。上课做好笔记总结一些固定模板。平时分很高，很少点名，作业非常少只交了一次，期末会捞。',3,4,5,12,0,0);
