INSERT INTO "reviews" VALUES('6968a3bfc8f81e5498a8983d',873,228,'不行，平时分给的真不行，小组作业用心做的才给75分，期末也不会画重点，只会让看课本，废寝忘食的看课本最后期末只考了66😭😭😭',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('69689776c8f81e5498a831a7',885,790,'分给的太低了吧，期中管的比期末还严，平时没缺过课分也给的低，不建议选',1,1,1,3,0,0);
