INSERT INTO "reviews" VALUES('696887f47ec103259bc4d5a0',965,965,'生物生最温柔的母亲，给宇宙不解释。期末划重点清晰明了，手把手告诉你哪些例题习题要看。期末基本都是原题，卷子还会给公式。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69688735c8f81e5498a7b9fc',359,228,'神人一个，每周都要写几百字的作业，背诵的时候交上去没什么问题，最后一周统一交上去说要重新写，b5纸张太小了🙄给分特别低，期末班级平均分是60，自己还在群里阴阳。平时上课全勤作业都交了才八十多平均分...逆天神人',1,1,1,3,0,0);
