INSERT INTO "reviews" VALUES('69685280c8f81e5498a66ac6',975,975,'平时成绩除了半期全给满了，作业有时会在作业系统上面布置，但是拿到80分左右就给满而且还可以多刷，选这老师就完了。',5,5,5,15,0,0);
