INSERT INTO "reviews" VALUES('6968399f7ec103259bc2d714',819,228,'上课点名，事情贼多，别的老师期中考都给满，就她非要搞什么考试；每个人还必须主动举手发言课堂表现才给满分；从来没见过这么乱给平时分的老师，上大学以来给分最低的老师，谁选到她谁倒霉。',1,1,1,3,0,0);
