INSERT INTO "reviews" VALUES('696791cad4c46d3fca6fd40d',984,850,'老师人很好，半期是开卷考（可能每一届情况会不一样），事不多仿真作业只用做一次，平时点名次数也不多，语速态度都比较温和。平时分给的挺高的，作业课堂表现类的都是给满。',5,5,5,15,0,0);
