INSERT INTO "reviews" VALUES('6967715ad4c46d3fca6f15eb',953,953,'老师人很好，平时分给满了，考卷给分也很高，老师备课很充分，讲课也很积极，上课也可以写作业，超级棒',5,5,5,15,0,0);
