INSERT INTO "reviews" VALUES('6967687c8f09280655158b03',26,26,'我靠。平时分拉满了！！！！特别好的老师。而且我个人感觉讲课讲的挺不错的 有评论说讲的一般我感觉有待商讨。以及老师真的长得很温柔漂亮。',5,5,5,15,1,0);
