INSERT INTO "reviews" VALUES('6967673afc754f151d128691',748,392,'王瑞老师真的很好，10节课有五六节课回答了问题平时分就拉满了，期末改的也不严，上课的问题也不难回答，回答完就可以玩手机，期末总分一般都九十加，真的很好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6967663bfc754f151d12813c',748,392,'来给老师正个名 一学期我能回答六七次简单问题（不是过于专业的问题）平时分给满了 判卷也超级好',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('696760a6fc754f151d125fe8',281,281,'讲课很好，每次课结束前15分钟会点3至5个左右同学(一般是同班连号)上台解答问题(问题基本上是上次课后作业知识)，回答不上有概率扣平时分。(本人没被抽过，平时分给满了)
INSERT INTO "reviews" VALUES('69675f748f09280655155702',260,96,'虽然老师平时上课看起来严肃一点，但他是真心为你好。到了期末就会变得很温柔，随堂测试只要及格就给满分，会捞人，平时分给满，超级好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69675e8cd4c46d3fca6ea90f',769,769,'妈妈级的存在，特别温柔，讲课清晰明了，给分高，会捞人(如果平时分给满都捞不起来只能怪自己)，绝对好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696758158f092806551521b4',1001,1001,'上他的课真的有福了，来与不来随便你。本来课就难，上课对着pad写全英文板书，没有讲义，不按课本讲，不布置作业也从不讲习题，不给复习方向。喜欢吹牛，上课需要你特别尊重他。越讲到后面越抽象，讲课缺少逻辑，声音时大时小，很多学生听不懂是学生的问题。老师一学期能缺七次课，也不需要改作业，上课真轻松。水平很高，建议研究生可以考虑这位。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696757f5c8f81e5498a2934d',475,1002,'无语，慕课战神也是无敌了',1,2,1,4,0,0);
