INSERT INTO "reviews" VALUES('6967437d1c9d6847963f20b8',475,946,'。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696741387ec103259bbed5cc',564,26,'老师仁义啊，会捞学生，给分大方，上课认真和蔼会开玩笑，不骂人，作业会讲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696740dbc8f81e5498a1e996',8,1010,'看似给分较真，但是最后除了考试分不动，其它分全部给满了，上课会点名按名单顺序回答问题（翻译个句子），本来我还想吐槽他U校园时长要求80个小时，但是他没看那个直接给满分了，真不错啊，而且老师巨巨巨佛系，周末从来不催U校园完成情况，一整个学期才有几次提醒四级词汇要按时交',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('69673f498f0928065514664d',6,1011,'人给分巨大方，五十分的平时分全班都是48-50（抛开逃课的不提，逃课一次扣五分），上课就只点个名，不提问我们不用回答问题，不用看智慧树，玩手机只有第一节课他骂人了，后面的全班大片玩手机，他就只是暗戳戳说玩手机的没出息，也没直接发火骂人，期末给了大题重点，背三五个小时就能过那种',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696731258f092806551408b9',867,27,'事少，不积极回答问题的话分也不高，中规中矩吧',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('696730b97ec103259bbe6929',849,619,'一学期下来基本没什么事情，大作业用ai也不影响，点名次数比较少，提问什么的也不是很多，考前会给大家发习题文档，平时分比较混的也能得80多，总的来说还不错，可选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696726ee7ec103259bbe3720',741,741,'虽然大家评价都不好，但是我被捞了所以给个好评，老师燃尽了😋',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69671e268f0928065513a458',883,1015,'选到依然赚到',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69671b047ec103259bbdf8d3',229,229,'太牛逼了，人很亚撒西，上课从来不点名，而且平时分给满了，上课可能会觉得有点快但是要考的内容是会反复慢慢讲的，没听懂的内容不会考',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696719b2d4c46d3fca6cd357',1017,1017,'人帅心善，风趣幽默，安全工程的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6967197f8f09280655138cb5',229,229,'给我平时分都要捞满了🥰',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('69671769d4c46d3fca6cc806',648,78,'大四这个课又期中考又课设期末又闭卷，然后这个老师期中是闭卷，平时课上不管你做什么，但是经常点名，几乎节节课都点了，还说希望我们考研考公的听课，万一以后干土木，其实底下全是跨考的（无语……），偶尔课上有小测，作业也留了几次，课设有一个贼复杂的评分体系，还得写一个课设心得，这本书500多页编的又乱又没有逻辑，没有重点期末得背整本书，然后她的重点给的很模糊，听了和没听差不多，期中考试和期末考试都是靠别的班老师的重点，最后期末考了98，平时分只有80，节节课都去了，课堂小测，作业都交了，最后课堂表现只有60多，是我大学最低的一课堂分，课设给的也不高就70多，总之大四千万别选，大三慎选',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('696711898f09280655135a2f',1020,1020,'老师人看起来憨憨的，但是人很好特别负责，就是感觉口齿有一点不清晰，我没什么存在感，他平时分还是给了100，上课可以玩手机，想水的无脑冲。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696710fcc8f81e5498a0cd63',1021,228,'老师教的挺好的，有一两节课我认真听了（资本主义那一章）感觉讲的比较通俗易懂。缺点就是上课不让你玩手机不能睡觉，还对回答问题有要求，对于社恐人士不太友好，期中出的题很多也不能用科技。我整个学期只被她点名回答了一次问题，期中是随便写的应该没考太好，但是最后平时分拿了94，所以老师属于刀子嘴豆腐心。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('69670c2ec8f81e5498a0ab7d',954,52,'神中神，基本不点名，人也很亲和',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6966ff301c9d6847963d6e8c',1023,188,'平时分拉满，大作业鼓励学生，好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6966fe98fc754f151d0fc631',1024,1024,'老师人特别好特别好，知识丰富，视角切入独特，知识也很成体系',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6966fd15fc754f151d0fbbe7',1025,850,'想挂科的尽管来选，绝不捞人，期中别的都是开卷就他闭卷，平时分死低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6966fcec8f0928065512d065',730,143,'杨老师人很慈祥，特别好！上课写板书清晰易懂，平时分也是拉满！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6966fcb2d4c46d3fca6c17e1',475,1003,'别整你那幽默慕课了，好好提升一下上课水平不好吗？😂给后面来的同学们一点小小建议哈，不是说这位老师特别不堪，只是她一般和大雷许老师绑定在一起，谁知道这个课他们两个要怎么给分，而且别的班可选的老师都是不错的😘',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('6966fc877ec103259bbd344a',1028,588,'曾老师给分特别高！人很慈祥，选他准没错！！',5,5,5,15,0,0);
