INSERT INTO "reviews" VALUES('69665c361c9d6847963b55b8',257,26,'平时分完全不会捞人啊，用老师原话说，他只捞考了59的，把你捞成60，你考了55 54根本别想。上课很亲和，基本上不怎么点名，也不会强制要求坐在前排。但是平时分给的非常一板一眼，该给多少就给多少。最后总平时成绩只有46分，难评，，，',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('69665a148f09280655108cfb',504,5,'期末给了满分 好老师',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6966578ffc754f151d0d43a4',890,619,'交大毛概的神—知性有内涵，上课有内容，任务轻松，期末夯爆了，无脑冲就完了孩子们',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69665752c8f81e54989e4ef7',730,143,'神中神，给分高，讲题仔细，上课从不用ppt只手写板书，平时分给的高，期末很好过！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6966516afc754f151d0d1f61',587,587,'怎么说，这个课，两个老师来上，上的时候你感觉是个水课可以随便逃，老师也不管，期末全是知识点，一看ppt，做的一坨，谁见过ppt里原则这两个咋标红，其他全黑，完全不知道重点是什么，考纲给了，但是给的和目录差不了多少，我服了，老师人还挺好的，但是我不知道这个课意义是什么，水课就水，不水的话老师就别这么摆烂可以吗',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('69664d3dd4c46d3fca69e0b6',103,6,'老师人还挺好的，主要是得按他说的做，给满不含糊。他平时比较认真。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69664a4cc8f81e54989e0d7f',1042,462,'雷 各种不收作业 做实验迟到一会儿就不收。收了还以各种理由扣分。一次扣两分，答疑是完全没有的 ppt是照课本念的。语录是你最好记住课后的参考表 完全不考的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696643e81c9d6847963ad56d',389,389,'讲课认真负责，虽然会点名回答问题，但是很多都是按学号的，自己可推测什么时候该去，尤其海底捞，我孙哥必须神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696643a71c9d6847963ad440',389,389,'男神不解释。。。讲课很耐心很仔细，人也没有架子，微微东北腔听得人很亲切，考试评分比较宽松，平时分也没话说，总之男神不解释。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696640717ec103259bbac846',870,296,'刚被老师捞到60分特来感谢，老师讲课很好，认真学的同学会有收获，想混及格老师也会捞，上课偶尔两次签到，有两次随堂测验，人很亲和',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69663d917ec103259bbab906',886,1046,'专业水平我听不出来我只知道勤勤恳恳听课了把给的重点背得滚瓜烂熟了期末考了60。听评论说别的班重点划很好 只能说对转专业过来的人很不友好了。。',3,1,3,7,0,0);
INSERT INTO "reviews" VALUES('69663a387ec103259bbaa67b',118,118,'上课💦一般 平时小测突击安排 期末考试大打出手',1,1,1,3,0,0);
