INSERT INTO "reviews" VALUES('69661f958f092806550f57ec',1052,1052,'形势与政策3
INSERT INTO "reviews" VALUES('696615fd8f092806550f1e35',1053,118,'太好了😄范老师，平时分基本满了，讲课虽然有吹嘘的风格，但是人还是很好的！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696615527ec103259bb9e0f0',792,792,'敬波老师的课必须给到夯！！！！
INSERT INTO "reviews" VALUES('69660dac1c9d684796399dce',1055,1046,'学术品行有待考究',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69660d6dc8f81e54989cbd54',886,1046,'难评😁，给的什么玩意儿的重点，且不说别的班直接把答案给了，平时分也低的离谱，这门课就是个草台班子，真不知道在这种极端不公平的条件下有什么开的必要',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696607bafc754f151d0b7b9a',976,5,'吴老师真的很温柔，说话非常清晰。讲课很有逻辑，比较难理解的知识点她会停下来给我们举例子，作业不多不少但都是考点，只要上课认真跟着她课下自己再复习一下就能考很高。小测随便坐基本不管你，当然除了半期考试平时分最后都会差不多给你拉满的😭。真心是个好老师🥳🥳🥳',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6966037f8f092806550ea152',1058,985,'真神yyds！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('696600f97ec103259bb955c1',883,1059,'课很水，全程念PPT，每次都是下课点名，并且点名看人，给分一般，作业很多，想水课的不建议',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6965fe2b8f092806550e7b69',233,773,'人美心善，人民的好教师。但是给分会卡90，89.4分其他老师都是进1，她竟然是舍去卡成89，好难受',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6965fbe8c8f81e54989c34a0',103,6,'想了很久还是决定写一条评价，本来选了崔老师的课，突然被换加上活水评价并不高，最开始确实没啥好印象，但是一学期上下来实话说体验感还行，只点过一次名（因为一半人都没来），平时分需要坐第一排或回答问题挣，不想做这些就要做一个汇报，大作业只要不是ai痕迹很明显会直接给满分，上课可以写其他科作业，划的重点确实有用。
INSERT INTO "reviews" VALUES('6965fb028f092806550e61cc',1062,352,'老师人还行，负责是负责，但给分真不行，基本上平时分就25左右，平时分满分是30，成绩出来差点挂了',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6965f9e2fc754f151d0b13a1',1063,143,'除了不会教书没有缺点啊，宝子们，平时分给我满了扣1分（包含实验加期中考），期末最后一周点睛之笔的讲课，虽然很多废话但是是真的有在透题（不明显，但会点到的那种），想学真知识可以听杨岗的课，但是杨岗会讲很多补充知识（期末不考的那种）看学弟学妹们怎么选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6965f8e51c9d684796390092',1023,188,'上的李茂老师的毛概，平时分特别容易拿满，上大学以来第一次50分满分的平时分。上课也很水，大作业的汇报也很松。好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6965f77a8f092806550e477b',1065,1065,'人美心善，蔡晴姐姐简直了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6965f7377ec103259bb90d94',1066,1066,'别的不想评价，但就给分这一块你真是人才，nnnd作业平时分最后占比跟期末考一样，ntmd那考勤就不占分了是吧，选他课的直接准备期末考期末考和平时作业抄抄就行了，上课不用去反正也不占分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6965f62ec8f81e54989c0bf4',896,896,'周涛老师讲得very good，每次上课大家都听的非常认真，平常作业也都讲的很详细，考试的时候为了让大家更好发挥出水平试卷出的质量非常高，复习到100分的水平甚至写完卷子都以为自己100分了最后也只能考到80多分，让我知不足而后进，非常感谢周涛老师，下辈子还要选周涛老师的课',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6965f2cf1c9d68479638d30a',890,619,'富有学识且十分知性。胶大毛概的神，无脑冲！',5,5,5,15,0,0);
