INSERT INTO "reviews" VALUES('6965eebfd4c46d3fca67a3d4',1062,352,'线性代数 平时分给的还挺高的，九十多  然后我个人感觉讲的也很好，但是你一定要提前预习，不然会听不懂',5,5,5,15,0,0);
