INSERT INTO "reviews" VALUES('6965d4b51c9d6847963819e0',882,882,'虽然老师的大作业有点麻烦，但是期末卷子出的很简单，基本一点没学也能包过，平时分也给的很大方',5,5,5,15,0,0);
