INSERT INTO "reviews" VALUES('696517847ec103259bb55eaa',828,1073,'真神，没咋去上过课期末考的好直接平时分给拉满了，选到是赚到。只要期末考的好，过关没烦恼，真的好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69650d917ec103259bb53803',499,194,'期中95期末100加上平时分没85不必多言',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69650b368f092806550a6289',1093,1093,'平时分给的很高，应该是老师在慢慢点改变，虽然有些东西讲的不是很深，但是一般来说会讲明白的到最后。平时和老师学，一般来说是没有什么大问题的。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6965076dc8f81e5498981d7b',886,886,'能不选尽量别选，水平低，讲的烂，而且还喜欢对学生莫名其妙发火，期末不给重点，群消息不看，事多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6965072e1c9d684796350d7b',1095,1095,'讲课不知所云，梦到哪里讲哪里，一直让做一些和教学内容无关的事，布置的作业也难蚌，会让你把代码手写下来，特别恶心人的一个老师。快跑吧孩子们。',1,1,1,3,0,0);
