INSERT INTO "reviews" VALUES('6964e583d4c46d3fca6339d4',393,96,'教学负责，每节课都要带着复习前面内容。给分高，平时分除了半期考试全部给满(不旷课交作业前提)，随堂测试错过了甚至可以补交。亲和力好，有问题会耐心回答，上课干自己的事也不会管你。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6964def5d4c46d3fca6310d6',978,5,'复变函数与积分变换，平时分拉满了，给个好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6964c4d4c8f81e54989667a7',915,250,'丽丽姐你就是天使！平时上课很温柔很细致，期末还会海底捞呜呜呜',5,5,5,15,0,0);
