INSERT INTO "reviews" VALUES('6964bc537ec103259bb32781',173,28,'当时开学看活水对这个老师评价不怎么样还惴惴不安，但是实际上下来没那么糟糕，给的平时分有理有据，口语考试5分不会给低于4分，u校园和词汇认真做就行，我觉得不算严也不太松吧，会布置让做真题，也起到了督促作用。接触下来其实是个挺可爱的老师，我挺喜欢的',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('6964b55cd4c46d3fca6193f7',1105,1105,'神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6964b520d4c46d3fca61927c',1106,1106,'如果有0分，我肯定打0分，说的是下节是答疑课想来就来，结果到了答疑课，开始点名，从来没见过这样的老师，期末重点不画，复习毫无头绪。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6964ac8dc8f81e549895ba49',886,1046,'一坨大便，这人也是神了，平时也没期末，做了作业，考勤也没有缺，直接给不到八十的平时分，答辩答辩，理论课这样恶心，赶紧跑吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6964a4bafc754f151d043c5c',1108,188,'可以选了，这几个学期老师已经改正了，上课没主动发过言，平时成绩给了100啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6964a445c8f81e54989571e6',1108,188,'讲课要求清晰，划分知识点的时候能明确到行数，平时成绩更是只要完成作业不缺课就绝对不会辜负你，谁敢忤逆我女神。黑子再叫呢？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696499a7448e7823619c6e82',103,6,'特别好，上课坐5次第一排就能拿满平时分100，期末还捞人，上课虽然说不让玩手机但是你只要不打游戏都不管',5,5,5,15,1,0);
