INSERT INTO "reviews" VALUES('6964817a20c1620e1f390d19',334,175,'海涛不错 只要作业都交了画的还行给分挺高的
INSERT INTO "reviews" VALUES('696477a3daee5f72f279b2ee',250,250,'666',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6964768120c1620e1f38c68d',886,1046,'这老师咋那么神呢，在自己的权利范围内使劲刁难学生，其他老师给的重点都直戳要害，证明给重点起码度是很大的，但是这个老师就觉得你这门课就得考低就得低一点突出老师的专业（实际上专业水平难评），因此重点就给你一个大目录。而且平时讲的课考到20分吗我敢问5个运输方式的重点能考到哪个，建议别选，没办法选上了也尽量别听，期末重点拿别人班的就行了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69646f19448e7823619b5751',334,334,'平时分纯瞎乱给，太低了',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('6963aced448e78236198a22c',727,727,'平时分给满',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6963a98420c1620e1f345325',724,631,'专业能力一般但期末大神特神',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('696395c8448e78236197f6f9',43,43,'******男女区别对待态度不一样，啥也不懂要求还多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69638f89daee5f72f275c7c4',95,95,'喜欢无视你😡',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696384baaf4f482042e1fef8',446,241,'上课水，但给分巨低，很少点名，点了次次签到，结果期末平时分给的巨低，无语死了',1,1,1,3,0,0);
