INSERT INTO "reviews" VALUES('69636bb705564e31269f7dbd',1063,143,'烂透了 只能说这老师遇见都赶快跑 开学第一周先给你吹自己的功绩 吹嘘自己的学生 上课还会PUA 说不好好听都是来浪费父母钱的 ',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69636b62448e7823619701e1',730,1124,'神 控制工程跟着他学就是了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69636896af4f482042e15cc8',200,200,'为什么同样评级的作业别人比我多5分平时分，凭什么缺了一次课平时分直接扣一半考勤，没重点，没范围就算了，最后一次课讲了一大堆题说要考，就考了一道题，你在跟我开玩笑吗，啥阴间啊',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6963648720c1620e1f32d2aa',264,230,'学识渊博、为人和蔼、良师益友',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69635ea5daee5f72f274a999',1127,1127,'出勤点名6次缺勤4次平时成绩90那还说啥了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696355d2448e7823619675c9',1128,40,'每节课都点我回答问题，逮着羊毛使劲薅是吧，最后给我70不到的平时分，都给我选。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('696354a720c1620e1f326621',360,1129,'客观评价一下黄老师吧，黄老师的算法课和图形学课是我拿过专业课平时分比较高的课了，他的课有非常非常严格的标准，但是是有标准的，有规则和章法，只要能按要求一点点做平时拿个比别的专业课高很多的平时成绩没啥问题。不像很多专业课老师一声不吭作业按时做按要求做课设最后期末拿个80+的平时成绩。课程内容很多都是要自学，有些要求也近乎严苛，但如果为了分数而来，和黄老师的要求斗智斗勇，最后的期末成绩也很理想。但一切都是你自己极致的努力，课程内容和老师的授课都是困难制造器。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('69634f47daee5f72f27441cc',1130,1130,'今时不同往日了孩子们',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('696342ff05564e31269e6a4d',1131,1131,'课堂方面，根据我室友的说法，应该是讲的不错。我本人是比较摆烂的，上课是扫码签到，最后期末分很低也给我捞过了不至于挂科',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69632c84daee5f72f273718d',1132,631,'好老师这种就是好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69632c2406646d6d76dfdae7',535,535,'上课完全听不懂在讲什么，说话含糊不清，我的大脑光是分析他在说什么就已经精疲力竭了，更何况讲的还烂，根本就不知道他在说什么，整个课程纯靠自己B站自学。还不捞人，期末前就出平时分，给的还一般。上课还要随机抽人回答问题，简直了。',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('69632033af4f482042df9da9',102,66,'问他问题也不回答，臭架子摆起，还说你能不能问点有用的？我要是知道还问你吗我请问?站第一排靠边都听不清他说什么，蚊子一样大的声音就离谱，没听清问他就一副拽拽的样子不搭理你，期末看个成绩还故意把记分表背过去不让你看。区别对待男女生，我不多说，就看投篮标准就行了，不想多做评价。如果选上了您就偷着乐吧。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69631b65af4f482042df8579',803,1135,'郭姐神中神，上大学以来遇到的最好的老师没有之一',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696300f7448e782361946c1b',886,1046,'重点直接给目录 近一千多页ppt爽翻了好嘛',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69630084448e7823619469e6',1137,1137,'随便选择的选修课 没想到老师这么好 平时按时上课人到了就行 期末很水的一个报告 分特别高😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696257cd06646d6d76db19aa',271,271,'丁简直就是天使，太赞了兄弟们',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('696248b420c1620e1f2c638b',1139,1139,'享福了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696236d020c1620e1f2bf888',1140,80,'每节课啥也不带，对着ppt读，平时和和气气，期末平时成绩巨低，作业二三十页交了都不给满分，课设成绩也难评。',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('696231f920c1620e1f2bdac7',1082,40,'完全是💩 奇葩的提问，自己几乎不怎么讲，提问学生起来总结段落总结全文，上课很水，事还多，essay第一次交说我字少，改了之后又说字太多，内容也不差吧，满分十分给六分，期末考了八十多，平时分70都不到，硬是把我总成绩拉到七十多，我也是醉了，大学里面最低的一门英语课，别班的同学平时分都八九十。一学期提问回答问题十次以上表现才给满，除去考试和改essay以及最后一周不上课，几乎就是要每节课回答问题，听说通用学术英语本来应该是分最高的一门英语了。呵呵。',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('69622e63af4f482042dbb2d8',724,631,'毛老师神了，虽然看的是慕课里面游为老师的网课，但是期末是真的夯，分数拉满',2,4,4,10,1,0);
INSERT INTO "reviews" VALUES('6962134e448e78236190a3fa',886,1143,'他眼眸中隐约的是孤寂，期末画重点跟学生博弈',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696211ea06646d6d76d9597e',491,23,'刘老师自己真的超级好啊，平时分几乎全部拉满，而且很负责很有耐心，问她问题都温柔地解答。就算作业没及时交，最后还会给补交的机会。课程结束之后有考计算机二级之类的问题问刘老师她也会耐心解答，亲妈级别的存在。简直是我的恩师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6962113e06646d6d76d95572',886,1046,'他眼眸中隐约的是孤寂，期末画重点跟学生博弈',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6961ef5906646d6d76d862b7',505,250,'这个老师挺好，从最基础的三视图原理，到复杂零件的尺寸标注、剖视图绘制，每一个知识点都讲得特别细致，每次作业都会耐心批改',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6961ef4b448e7823618f9e5f',915,250,'夯爆了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961e811daee5f72f26d6a64',103,6,'我之前评价过了，再补评一句，加分机制比较复杂繁多，但是只要按要求做到了，就是满分，相反如果没按要求或者距离要求特别遥远，分数会比较低甚至很低。我猜测应该是教务有班级平均分要求，所以就导致两极分化比较严重，无法实现分数共同富裕。当然如果有企业家（zbj）精神，可以来，你可以先富起来，但是无法带动后富。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961df07af4f482042d9b619',1103,1103,'毛概平时成绩真的很高！！上课也很轻松！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961d8b105564e3126978d4f',1103,1103,'不多说什么，完全是捡了一个大漏来的，老师态度特别好，平时作业也就是那个大作业其他的根本就没有什么作业，我上课没有回答过一次问题，就是全勤+基本大作业平时分给了我惊人的98，上课也就是自己玩手机，还有老师平时上课中途会让我们勾几句话重点，期末也在群里发了大题考试范围',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961b499daee5f72f26c400d',56,56,'好老师，我的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961b42806646d6d76d6ff37',55,55,'神！难得的真的为学生考虑老师，高考压力太大，胖了40斤，现在很胖，老师从开始就跟我说需要降体重，不然身体受不了，然后教给我怎么练习，学期末减重15斤！天气冷，老师就带我们到有阳光的地方晒晒太阳，特好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961b236daee5f72f26c2d59',1030,5,'林老师真的是超级无敌好老师好嘛！给分好讲课好专业能力过硬人也温柔回答问题耐心！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961b1dc05564e312696a3e5',1154,1154,'老师讲课非常用心，讲课也非常好，电路分析平时分本来就比较固定改不了，老师也会捞人，个人感觉不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961b19d06646d6d76d6ec40',832,40,'六级加分是不算在平时分里的，上课回答也是不算在平时分里的，给分超级低，没见过这么神的老师，避雷！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6961b13a05564e3126969fb2',281,1156,'老师给分非常高，很宽松，但每节课会抽人上去写题目，考勤偏严格，而且专业水平一般，蛋给分非常高能接受',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6961b04adaee5f72f26c1de6',1157,52,'陈老师真的超级无敌好老师，讲课好，我这种物理很差的都能听懂，很有耐心人也温柔，给分也高，平时分都给我拉满了，还会带你考前复习！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961af9005564e3126968ed2',1158,26,'小娟老师数院的神，人美心善讲课好，温柔细致有耐心！给分也超级超级超级高！海底捞！！！都去选啊啊啊啊啊！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961ae34af4f482042d88c4c',1159,241,'老师人很温柔，讲课也挺好的，虽然我也没听。给分还挺高的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961ad82daee5f72f26c0ba2',11,11,'作业多但是可以抄，完成就行。我们班平时分平均44。b班会压分，a班任务完成就有分，扣的只是课程考试。而且老师很和蔼，上课玩手机也不管',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6961ac48af4f482042d87f4c',1158,26,'小娟老师我爱你！！人美心善，超级温柔讲得又好。数院唯一真神。给分还超高，已经不只是海底捞了，简直是陆上挖掘机！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6961425daf4f482042d78109',1162,114,'潘师，遇到事是真上啊，给力，平时上课比较严肃，关心学生，希望学生好好学习。平时分给很高，老师大义！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69613cf1daee5f72f26af14c',543,543,'一节课你能学到经济，中医养生，流体力学三种知识。有时候讲着流体力学，中间会引入中医的知识，用实例告诉你们很多东西都是有规律性的。另外，老师讲经济和中医的时候，可以能听出来在这方面是有很深的理解的，听着真的很有意思。总的来说，选王老师的课，不光能学到流体力学，还能帮你更清晰地认识经济社会的规律，形成正确的财富观念。如果想提升自己思想见识，选就对了。
INSERT INTO "reviews" VALUES('69612c27daee5f72f26abf6d',958,23,'一节课能翻几十页ppt，听不懂也不管你死活，天天纸质签到',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69612b3420c1620e1f272ddc',626,306,'考勤和作业一样没落，最后给六十几的平时分，难绷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69612ad1daee5f72f26abbc1',1103,1103,'还行吧，回答了两次问题，大作业拍的视频，平时分给的挺高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69612a4920c1620e1f272af3',233,773,'平时分就两次作业构成，平时没缺勤没缺作业，每次建模作业都是认真写的，但是只得到一次75分和一次80各占25%的平时分🥹',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6960f6d7af4f482042d62d2e',1168,228,'我是跟东哥混的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960d602daee5f72f26912bc',1169,1169,'崔老师，无可挑剔！上哪找这么敬业耐心讲课好认真负责给分高的好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960d58baf4f482042d571d3',542,1170,'胡老师讲的很好啊，虽然是照着课件讲，但课件上确实都是知识点啊，每节课之前都会回顾之前的内容，期末还出了两节网课给同学们梳理知识点和答疑，平时分给了满分，喜欢🥹🫶',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960cf3e20c1620e1f253034',1171,27,'一节课没缺勤，一次作业没少交，平时分给50分。上课上开心了侮辱你两句，不开心了骂你两句。牛逼吗？',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6960ca4206646d6d76d38dd3',26,26,'我不准任何人说张老师的坏话，人太好了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960c4f120c1620e1f24e7b0',1173,1173,'这么好的老师为什么没人评论呢，上的魅力器乐选修课，事巨少，平常就ppt介绍乐器，放演奏视频，自己做自己的事情完全不管，有时候还会请音乐系的专业学生来课堂展示，很棒！期中期末都是写点认知和心得之类的，很简单，偶尔点名，总评给出了100分的震撼满分！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960c35906646d6d76d35f91',1174,114,'期末是真的海底捞 按时上课按时交作业 平时成绩给满了 期末拉卷子上都能过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960b2a7448e7823618a37c7',1175,68,'上的陈晓红老师的通用学术英语，上课是真交你怎么写论文的，大论文的要求是非常明确的，只要按要求来写，分是超级高的(我拿AI的按要求稍微改了一下，95的论文分)。老师是那种特别潮流爱美的人，没事的时候喜欢在教室放歌。不安排具体座位，一学期只有三次学习通定位签。总之人美心善给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6960a8f205564e3126923c84',246,228,'上课：“我觉得同学对我的评价有失偏颇” 
INSERT INTO "reviews" VALUES('6960a78b448e78236189ea34',535,535,'平时分是上了大学所有科目里最低的（全勤加作业全部认真完成的情况下平时分都很低），而且上课他说的一句也听不清，一直就很简单很简单，讲的也不好，纯自学。期中高的原因是全专业期中都是那样算成绩的10×根号下（分数），又不是他自己一个人这样算，总之，拉完了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('696092dfaf4f482042d3ab65',1055,1046,'很值得信任的划重点',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('69608aed448e782361894748',1179,1179,'上课很欢乐，老师很和蔼，会细心给每个同学纠正动作，考试也不是很严格。平常就压压柔韧练练腿法，可能稍微有点累但是想摸鱼也是很容易摸的，老师也不卡请假，基本说了就会给通过。唯一的缺点是上完课之后脚底和身上都会被教室地垫染成蓝色，可以无脑冲！楷楷我们喜欢你🥰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69608ace448e78236189467f',1180,1180,'讲课思路不清晰，无用信息太多，PPT冗杂，复习内容有一大堆一笔带过，滥竽充数的文字和知识点。虽然划重点，但是由于每个重点一大堆无用信息，所以基本等于1000页PPT变成500页。',3,2,4,9,0,0);
INSERT INTO "reviews" VALUES('69607f4e20c1620e1f233ee7',385,28,'作业的确相比于其他老师来说可能多一点（u校园）。课程方面只有前几次上课点名，座位是固定的，上课不让看手机都可以理解。情绪价值给的很足，回答问题不管怎么样都会夸你。平时分估计大部分人都给的很高吧，而且有许多加分的机会，毕竟给我的满分🥲。批卷子给的也比较宽松，除非你不写不然都是往高给的。总体来讲只要你对英语认真，那陈老师相当不错。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69607a5706646d6d76d19985',1182,241,'随机无规律点名，逮到没来奖励平时分60',3,3,1,7,1,0);
