INSERT INTO "reviews" VALUES('695fda51af4f482042d0e6dd',246,228,'谁选谁知道',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695fc6c005564e31268ec460',121,1185,'信她给分高，还是信我是秦始皇
INSERT INTO "reviews" VALUES('695fc570af4f482042d091d7',1186,40,'神！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695fc08c448e7823618645b7',246,228,'这个老师就是纯纯恶心人，平时分给的出其的低，你敢信我37的平时分班上还有七十个人比我还低，这不就是明显的说明这个老师很有问题嘛。。。上课还一堆要求，不准玩手机，最后三排不坐人，但是说实话你听了他的课也没有什么用，因为他讲课讲的很一般。。。期中考试给分特别低，班上就十几个人上60。。。所以总的来说能转就转吧，我当时是没得选了才选他的。。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695fbe5faf4f482042d06c7d',246,228,'事儿贼多，平时分也挺低的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695fbb2605564e31268e823f',1189,605,'期末突击的玩家准备补考吧',1,1,1,3,0,0);
