INSERT INTO "reviews" VALUES('695fabc4daee5f72f263adc7',1191,1191,'神！真的会捞人啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f9b09af4f482042cfad30',1192,27,'大一两个学期都是陈老师的课，真是好老师！课后也很耐心解答我的一些问题，老师专门研究考试的，周末甚至专门抽时间帮我解答了雅思gre的一些疑问。真的特别好，上课也很负责。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f90c6448e782361854167',1193,28,'上课自由，平时分给的高，人美心善，说话温柔，没咋学也过了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f7aa120c1620e1f1f0676',1189,605,'非常差头一次见这么差的人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695f772ddaee5f72f26269e5',1195,1195,'神人老师，平时上课不考勤，期末看你眼不眼熟给你打出勤分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695f70e8448e7823618479f4',1196,1196,'老师人挺好的，态度很和蔼，但是上课很喜欢互动，会点人起来抽查知识点，不过答不上来也没事，不会说你啥的。微机原理这门课本来就比较枯燥，除了照着书和ppt念也没什么方法，所以我对这方面意见不大。就是期末半开卷的资料不允打印只能手抄有点麻烦。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('695f6fc5daee5f72f2623aaa',1197,496,'感谢老师给的重点✋🏻😭✋🏻，课堂也讲得不错，人美心善😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f6eee05564e31268cd264',1198,1198,'上课是用老师自己编写的教材，通过看书跟进度毫无压力，态度很好，不咋管课堂，提问都会回答。期末考试出卷也不难，部分题目可以找规律或者看前后呼应。就是实验部分有点麻烦，临近期末甩来一百多页的实验指导书，实验报告和大作业有点费时间，其他都挺好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f6db520c1620e1f1eb110',1199,223,'事多，特别喜欢点名，说话怪里怪气，喜欢收作业，喜欢搞不同形式麻烦的作业。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695f4ef920c1620e1f1dd2a5',438,28,'比较水，打分不高，只是保证你不挂，平时分给70左右，上课刷手机戴耳机会说，用ai会说',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('695f484bdaee5f72f2612696',1201,1201,'这个老师超级可爱/:,@-D也很认真负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f479620c1620e1f1da34e',385,28,'老师很好，平时分给的很高。作业确实多了点，但是都是对期末和四级有用的，用心做一下期末完全可以拿高分！课不水，但是也不用紧张',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('695f3f4620c1620e1f1d7976',1203,1203,'老师教得好，有耐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f38b405564e31268b6831',89,33,'期末平时分会拉人，好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f3408daee5f72f260bf13',598,28,'挺牛逼的，期末口语拉满（依据个人水平有零点几分的差距且一般不会超过零点五），我U校园一半多没写，作文也是补交，平时分除了客观的几乎拉满了，就是她说英语的时候口音有点怪还上课会点一下人，其他挺好的',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('695f2bcfdaee5f72f2609649',1189,605,'没其他老师选，迫不得已吃下最难吃的史，很烂的老师，很烂的人，像阿诺一样的脑缺，优越感十足',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695f2ab506646d6d76cb782c',411,36,'虽然老师有口音，平时要签到，但平时分给的相当慷慨',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695f266f06646d6d76cb5f45',250,250,'一坨，选到他这辈子就有了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695f260adaee5f72f260742f',336,336,'Σ玩意儿',4,1,1,6,0,0);
INSERT INTO "reviews" VALUES('695f217b06646d6d76cb4097',1210,1210,'这是傅志坚老师的计算机模拟评论：老师人很好，上课很认真，基本不点名；没有期中考试，只有一个大作业（很好完成）；期末考试划重点特别详细',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695ef8a320c1620e1f1bce32',56,56,'老师人很好，对学生负责，上课认真，期末也会捞，但想水的同学建议选其他的哦',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('695ead4b06646d6d76c89ca3',1212,837,'海底捞，不多说了，感谢恩师。虽然每节课都会用系统点名回答问题很讨厌…但没想到是真会捞。总之就是平时煎熬考试轻松吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695eacd705564e3126894673',976,5,'特别特别温柔的老师，唯一的缺点就是讲课有时候有点小声。认真听绝对能学会，很负责的老师，会演示解题过程并且讲的很详细。有课堂小测但是可以悄悄用手机查，给分也很高的，问问题都会回答',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695e9539448e78236180b558',102,66,'上课声音很小，听不清楚，慕课啥的也不给我们讲清楚，到了期末都要学生求着老师改分，还怪你自己平时不认真听🙄而且根本不是篮球老师，从来不会拿球示范，全是要求同学示范
INSERT INTO "reviews" VALUES('695e7761daee5f72f25e27ed',762,565,'这老师人品不行',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695e75edaf4f482042ca5f7b',762,1216,'我只能说想选他的课的，先听一句：“这老师的师德实在太差了，这老师的人品有问题”
INSERT INTO "reviews" VALUES('695e6d3105564e3126887b5f',762,1216,'妈的说实话，纯他妈傻逼老师一个，全家都他妈死光了一个狗日的，mlgb，上课tmd一天到晚点名起来回答问题，屁事还多，狗日的隔三差五点人起来回答问题，回答不上来，还要让人尴尬着。讲课讲那个狗逼熊样，tmd别人下课问问题他又不管了，纯傻逼一个，全家都死光了，死一户口本的人。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695e6a0206646d6d76c7c9e7',138,1218,'卷子乱出，一模一样的课出的卷子难度比其他班高一大截，考一堆见都没见过的，往年从来没考过的阴间知识点，孩子们快跑啊！快跑！！！',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('695e3969af4f482042c8e348',1203,1203,'老师专业水平非常高，上课节奏很好，照顾每个学生的感受，经常挨着问所有同学实验会不会做，选他的实验爽得不要不要的。性格张扬，有的时候喜欢挨个点寝室长的名',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('695e370aa54da130bed2eb61',411,36,'听不懂，事还多，分还低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695e2d5b06646d6d76c64ac5',233,773,'神中神不用多说 但作业每次截止的时间像是看心情随便点了，允许迟交但是要扣一点点平时分吧！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695e2706a54da130bed28fdc',886,1046,'给的重点非常非常多，足足有七张图片，还分为贴心地分为需要了解的，重点掌握的。勤勤恳恳背了那么多概念，特点，优点，可能就考了几分吧。。。五种运输方式讲了五个星期也就考了几分。。。(大题考的基本都是综合运输部分的内容)十多个ppt扔给你，你就背吧，背完考试啥也不会。呵呵',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('695e203b448e7823617e1a4e',411,36,'直接平时分拉满！
INSERT INTO "reviews" VALUES('695e1e8b448e7823617e0ca3',886,1046,'神人老师一个，重点不画，画了假的重点，累死累活背了一个晚上一百多个重点，几百页ppt，你给的重点考到的5个都没考到，隔壁张光y给的24个重点全都考到了你给的一个都没考到，我估计分数比别的老师的至少20分，大作业你也是神人，说别的学校发在期刊上的论文权威性不够那不权威发什么期刊，说为什么不用我们学校的，我们学校没有这方面的我们怎么使用，神人一个，手搓的辛辛苦苦的一个论文被他骂的一无是处，手写代码在你那就是重罪，罪不可赦，讲课枯燥乏味，刻板僵硬，总结
INSERT INTO "reviews" VALUES('695dfff3a54da130bed17001',1225,1225,'**********平时分给我四十',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('695df2c706646d6d76c49af7',910,1226,'平时签到是放个签到表在最前面自己去了签，那这懂得都懂，课前签完到想润就能润了，甚至能给上一节课没来的偷偷补签。期末就是交个一千字论文，随便AI一下九十加到手。但是期中的时候可能会有个小组作业，还是得稍微做一下。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695df0f4daee5f72f25acbe1',780,81,'******本来抢到了郜老师的习概 结果第五周给我换了一个这个老师 无语😓 简单说说吧 是一个年轻的女老师 但是上课事情很多 在统一的大作业之外还要布置一个小的pre或辩论（二选一）并且将它纳入平时分 每节课就有课代表来点名 如果你上课不主动回答问题那么你的平时分就会很低 因为她的平时分里有很大一部分占比是上课发言 反正就是高中老师喜欢的做法 别选就对了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695deed9a54da130bed105e4',1228,1228,'老师很好 上课不会管你干啥 事情少 不点名 课设有点麻烦但是是统一要求的 问他问题也会耐心给你解答 夯爆了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695deb30448e7823617ca8dc',915,250,'非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695de76205564e312685129a',1230,51,'期末给分高 点名少',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('695de2bd05564e312684fb72',1231,39,'老师超好！有什么问题问了都会回的，期末考试还是要努力一点分会更高！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695de20706646d6d76c43930',200,200,'上课就对着ppt讲 完全不管下面人有没有问题 期末考试完全不给资料，期末复习课讲的题说期末要考但最后一道都没出现 平时分给的还巨底并且不捞人 ',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695de1be448e7823617c793e',385,27,'比较像高中老师，上课比较无聊。不过老师是比较负责任的类型，问问题都会回。期末小测我没及格老师平时分直接给我打满了。。。。（感动）不过我平时作业都做了，上课也没有迟到什么的，大概老师只是比较看重学习态度',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('695dc86ddaee5f72f259bef4',168,168,'上了他的选修。一开始平时分给分很低，后来调整了一下也还行。给分在选修里说不上特别高，但是中规中矩吧。平常就是讲现代诗歌，会偶尔抽人回答问题，答不上来也没关系。运气好的像我这种一个学期也没背抽到过）期末考试是写卷子。卷子里的内容都是上课讲过的，尤其注意听考试前的一两节课。老师很有思想，讲的也很好，就是给分比较严格。但是比起来某些交通美学给分已经不错了。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('695dc759daee5f72f259b705',1235,1235,'超级无敌好人，上课很轻松幽默，结课就是一个ppt展示，给分很高！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695d40d906646d6d76c1ef48',55,55,'期末85的人来实事求是评价一哈，个人感觉老师是很负责的，是能看得到哪些同学有在认真学习，有些同学是在混的，也会体现在打分上。这一点对于想评奖评优的同学们很友好啊，认真对待就能够拉出来分差。当然我没打算评哈哈哈
INSERT INTO "reviews" VALUES('695d385006646d6d76c1d5dd',233,773,'神临了！三维设计平时分超高！脾气很好不会生气，对大家作业不满意也只是提醒，虽然每周的deadline有点紧但是只要认真做了期末考试分也不低，并且会有模拟考，会告诉期末分值分配，考试都会提醒大家要先完成什么好拿分的，好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695d363e448e78236179c2e9',233,306,'神
INSERT INTO "reviews" VALUES('695d1bcb448e782361794dc1',748,392,'不划重点,不回答问题平时分为零（最后总评有30分的平时分,自己看看不回答问题挂科风险有多大）,不允许后2排坐人,不推荐',1,2,2,5,1,0);
INSERT INTO "reviews" VALUES('695d110d05564e312681cd13',188,188,'根本不捞',1,1,1,3,0,0);
