INSERT INTO "reviews" VALUES('695cefc4af4f482042c2ad9d',200,200,'拉完了，拉完了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695cdfad06646d6d76bfe3f0',1243,1243,'没话说，对学生着想这一块。请假，补签，海底捞这一块',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695cde1506646d6d76bfdc6b',278,228,'“对抗”，是刘老师课堂的代名词。从课堂规则到考试规范，从学生守则到老师底线，她对期末的每一分都做了精准严厉的分配，宛如葛朗台一样一毛不拔。从她的言行中可以轻易感受到她对自己用十几年教学实践打磨出来的评分细则非常自豪。学生与她好像是两个天然对抗的阶层，钳制、打压是课堂的底色，而不是鼓励与引导。我至今不能理解为什么刘老师面带微笑却说出了暗藏“敌意”的话语，就像她似乎不能理解教育的初衷应当是灵魂的唤醒与点燃，而非一场关于权力和分数的零和博弈。',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('695cdd72a54da130becbdb7e',1225,40,'付老师给人一种很有亲和力的感觉，而且很有趣，上课认真听还是能学到不少东西的，课下去问老师问题也会很耐心的解答，认真完成作业平时分其实还不错。但也是因为学校的关系吧，给分得按照评分标准来的话，没有很多空间，平时分给的话看你上课积极程度，上课发言的话还是能加不少分的，纯摸鱼分一般不高，期末老师也还是会尽力多给你点分，不说了，付门永存',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695cd67aa54da130becbaeda',1243,1246,'常老师人真好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695cd61e06646d6d76bfa9fb',1243,1247,'伟大无需多言，是谁在诽谤我的义母？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695cd18506646d6d76bf8c73',200,200,'上课是念ppt的，考试是考容量滞后的，重点是没有的，期末是占六十五的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695cb4cddaee5f72f254b88b',209,209,'到底谁在黑，虽然不怎么爱搭理人，但是给分真的高的很，无敌',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695caead05564e31267f29c8',1250,696,'上课确实纯念ppt但也不管你，期末会给重点，很适合那种不爱听课的同学选，老师人也很好说话，可以说除了讲课不太行其他方面都挺好',1,4,5,10,0,0);
INSERT INTO "reviews" VALUES('695c8147a54da130bec96d3c',18,18,'没有任何扣分的理由 神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695c811906646d6d76bd69ff',1252,1252,'交大神中神，永远可以相信钒钒的实力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695c80b8daee5f72f253626d',1252,1252,'神中神 无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bf33005564e31267c29bf',799,799,'好老师，人挺好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bed10a54da130bec76a19',56,56,'闭眼冲就完了，人好事少，没有任何“爹味”，经常笑着跟学生沟通，很尊重学生的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bec0aa54da130bec767ce',55,55,'真的爱死了！由于个人一些问题，健身跑少跑了一次，导致健身跑没分数，陈老师期末专门打电话问我，给我时间让我解释，然后又给我机会，让我重新跑了一次，给我加满了，然后又提醒我下学期要注意。这种老师，还有谁？？？后面两年锁死陈曦老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bc23b05564e31267b5ca9',1128,40,'我每节课都去，学习通都写了，还上课回答问题 平时分就给40，最后一节课还舔着脸跟学生要好评， 上课真是水的一批，跟学生一起玩手机 屁事不管',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695bbaffa54da130bec676c6',1058,985,'讲课细心，平时成绩基本给满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bb346af4f482042bca969',83,83,'最好的高数老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bb2f1daee5f72f250341e',257,5,'6',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('695baf71a54da130bec63303',296,296,'老师挺认真的，PPT都是自己写的。人比较好也不管你上课玩手机。点名意外的准。',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('695baee5a54da130bec6307d',640,229,'从来不点名这一点很好。人还是比较负责的会发往年卷子。作业很少，提交照片即可从来不收。课我没咋听过。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('695bae6a448e78236171fcb9',233,773,'作业是截图提交的，平时分是高高给的，人是非常好的，上课建得快的有平时分加分，建的慢也不妨碍平时分高，神中神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695bae43af4f482042bc8bea',416,1264,'很好的老师!从来没点过名，上课不管你在干什么。OJ布置了很多题但是最后期末算分的时候，是尽力给满分的。讲课很有激情，很有趣的老师，还想上他的课，不知道能不能选上了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695ba950daee5f72f2500456',1265,1265,'老师非常负责，作业要求给的很详细，只要去上课了作业按要求了平时成绩能拿到85%-90%',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695ba6c8daee5f72f24ff63c',643,643,'快逃',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695b9dce06646d6d76b9db9b',1267,1267,'超级好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695b7693af4f482042bb44e6',643,643,'一学期下来没有讲过一句课内内容，有的只是对自己的吹嘘和对当代年轻人的不满，我不能想象一位老师是怎样将两节半课的时间全拿来问“这个PPT讲了什么”，名单上一个一个点名，一直到第三节课下课。我真的很想给你打五分好评但是分10000期来打，只不过最低只能给你打一分。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('695b6e1aa54da130bec4978d',643,643,'神人，第一次课发一个学期的大作业，之后每次课就只开作业进度检查大会（真的不讲课！）。每周备课一页ppt（对考试完全无帮助），没事还喜欢点名提问。课本从来没讲过，重点没划过，期末让你背课本。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695b6c39448e782361703833',517,517,'老师人很好啊，人文关怀强，每节课都有点名环节。平常有点不舒服和老师说，那节课就是在旁边休息看着。平时的上课活动内容蛮丰富的，期末也是能捞就捞
INSERT INTO "reviews" VALUES('695b698f06646d6d76b88539',643,643,'这老师只能说无语，上课一学期没见过他讲课，一天天事多，天天上课就是说  ：e我有想起来什么什么了，感觉什么比较好，看那个专家的视频了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695b4d3eaf4f482042ba1c8b',271,5,'不点名',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695b4b6ea54da130bec3af68',1273,157,'烂，跑，上个体育课不知道哪来这么多事，专业课都没她严，课越水老师越神',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695b34c4af4f482042b9961b',1274,426,'不划重点！上课叽里咕噜不知道在说啥！！快跑！！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695b321e05564e312677d839',9,157,'老师人真的特别特别好，会提前很久和你核对成绩，分给的很高，如果期末考试能满分的话，总体95➕没什么问题，反正就是非常无敌好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695b273a06646d6d76b6ecc3',226,1276,'上的手绘青花瓷，很水，只要期末考试能交上东西就可以。不过最后得分大多数集中在85-90之间，可以接受还是可以冲的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695a87b9448e7823616caace',369,66,'体育50几分给你挂科神人，以为自己网红就了不起一副高高在上的样子',1,1,3,5,0,0);
