INSERT INTO "reviews" VALUES('695a6c99448e7823616c1918',971,24,'人非常好，一学期只点三次名，一次没来他不会计较的。上课你随便玩手机，平时问问题，他总会很耐心的解答，教的也不错，至于作业，允许补交，而且很愿意捞人（前提他对你的印象不是很坏的话，比如经常不来上课）',5,5,5,15,0,0);
