INSERT INTO "reviews" VALUES('695a57b7a54da130bebfdcfb',89,33,'非常好老师，大学英语想学还是看自己，但黄老师事少温柔而且从不为难学生，给分如果你好好复习还是非常有性价比的，平时分45+没问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695a5169daee5f72f2499ff4',294,294,'别选她的任何课，恶心人，pua，复述她的废话，同一个人两节课能被点起来3次，全班起码覆盖一次，',1,2,1,4,0,0);
