INSERT INTO "reviews" VALUES('695a0c2905564e3126728eeb',1291,92,'说话模糊不清，但是认真学的话还是能学会的，平时分靠自己争取打了95.8分',4,1,1,6,0,0);
INSERT INTO "reviews" VALUES('695a0a26af4f482042b4240c',1292,1292,'何老师没毛病，可选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695a0179daee5f72f24778eb',1293,1007,'文丽老师特好一人，我之前平时没咋好好学，期末啥都不会，但老师硬是给我捞及格了，平时分直接拉满，老师上课也很有趣，一般会点3到4次名，平时作业也不是很多，不会故意为难哪个学生，总之蛮好的一个老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959f33906646d6d76b05195',517,517,'老师人很好，善待每一个学生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959e65806646d6d76b00e26',385,28,'上课有种高中的感觉，对玩手机、迟到要求很严格，对学生知识上的不足很包容，遵守规则平时分会很不错',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6959df4aa54da130bebcfbb9',888,779,'很有激情，讲得挺好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959dea405564e3126719e80',385,28,'啊啊啊我去感谢陈老师平时分打满了😭,当然想打满一定要踏实,学习态度要好。真的没有评论区的一些人说的不堪。当然你如果把英语当做一门水课想混过去那分肯定不高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6959d286daee5f72f2467818',173,28,'老师不捞人平时分严格按照该有的给，要混个脸熟的话会给点奖励，作业反正比我b班的室友少，我自己拖延症太严重了每次都拖到截止前才开始写都能觉得一点不用着急，上课真学不进去了稍微划几分钟水也没事，而且复习资料很足完全是要了就会给，我至今不理解为啥要骂。省流就是想学的来纯划水的可以润了，因为老师不捞人说几分就是几分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959cab206646d6d76af526e',11,11,'上课很水，基本不点名，只要认真完成u校园的作业平时分不会低',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959ca89a54da130bebc698f',649,36,'老师真的有点东西，上课很有意思',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6959c9e6daee5f72f2463bc4',969,23,'老师很和蔼，讲的也很好，选到一定不会后悔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959c999af4f482042b2baf5',26,26,'老师很温柔，平时讲的时候也会怕你听不懂再重复讲重复讲，作业布置的也不多，小测也比较睡，给到一个夯爆了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959c8b2daee5f72f2463456',1062,352,'你就跟着鲁老师学吧，一学一个不吱声，半期期末嘎嘎乱杀',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959c82206646d6d76af4252',11,11,'老师人很好，平时分也很高',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('6959c80205564e3126710104',11,11,'任老师人真的挺好，除了平常作业有点多，平时分没有给的那么低，还会在英语群里跟你聊天',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959b40ea54da130bebbe20a',11,11,'老师老师 我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6959510e06646d6d76ae1146',1307,1307,'很不错的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69594f8f06646d6d76ae0ec0',1308,1308,'老翟没毛病，是真正说出就业形势的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69593c0105564e31266fa30b',11,11,'老师平时分给的真的很高，只要认真完成优校园就行。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69593b66af4f482042af8a5d',558,792,'不说没用的，25年春季学期向老师的四学分模电挂科率不到百分之十，上课虽然比较喜欢管纪律，但是期末是真给捞啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695916bfdaee5f72f2441cdd',572,572,'史上最离谱老师没有之一，想被逼疯的可以来选一点没有夸张，甚至于在这里写下对他的避雷我都犯恶心。细数2025栗怀广老师预制装配式限选课9-16周作为：第一周，老师没来，教室里的四十多名同学等待无果相继离开。第二、三周，上课讲的狗屁不通，不知所云，没有备课痕迹，没有ppt没有书籍，拿着粉笔就在那乱讲，想营造一种侃侃而谈的感觉实则没那水平。作业和他教授内容无丝毫关系，此外每节课上课迟到，有一次进来之后说：“我都不想给你们上这课”态度恶劣。字数限制长话短说。答辩的时候也会挑刺，很神经，知道的是上一学分的限选课不知道的以为是硕士论文答辩，会把小组作业全盘否定，全看他心情，没过的原计划再答，结果老师又没来',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6959132bdaee5f72f2440bf5',728,1312,'拉完了，讲是不讲的，考是都要考的。上机课一个学期以来是一句话都没有说的，期中期末是都要考的，自己算个交互分配都算不明白！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6958ec4005564e31266e03d0',121,541,'出了分就比别的班低5 6分，简直拉完了
INSERT INTO "reviews" VALUES('6958e169448e78236164c05c',618,457,'66的平时分，狠狠避雷了！避雷！',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('6958d960daee5f72f242c5a4',334,175,'感谢老师，谁说平时分给的低的，这么好的老师居然还有人黑，那些骂的人你真的学了吗',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6958cbdbaf4f482042acf77c',618,457,'先说一下优点是会划重点，我讨厌的点是课前汇报和读后感的作业都好好做了，才给我80多的平时分，凭啥？🙂而且经常点名，看到课上你在干别的事，不管是在做作业还是在玩，会直接阴阳，不管你是想水还是想拿高分，都快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6958c8e5af4f482042ace5cd',209,209,'谁在黑🌚成绩出来了，90+97+95+97+95+95+95+97+92+85+91+94+95+95+94+94=1501，1501÷16=93.8125，谁在黑！给劳资吓死了🌚',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6958b621a54da130beb7ecc1',1318,301,'我也曾见过这位“名师”，大抵是有些异于常人的怪癖的：铃声不响，他便如木偶；铃声一震，他倒显出“大无畏”的气概来，非要在这残存的时间里，倾倒些陈年的渣滓不可。
INSERT INTO "reviews" VALUES('6958b452a54da130beb7e1e4',1318,301,'************************************************************************************************************************************************************************************：）',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6958a76eaf4f482042ac22ec',1320,40,'老师挺好的，很正能量，就是有点话唠。平时小测也不严，要求很清晰，事情很少，也不喜欢为难学生。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69589ec8daee5f72f2416dcd',141,65,'给到夯，思敏姐姐巨温柔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69587b23a54da130beb6ac1f',1282,1322,'事情多（要自己编排舞蹈），但就算编排了得到表扬，最终的给分也不会高到哪里',1,3,1,5,0,0);
INSERT INTO "reviews" VALUES('6958676eaf4f482042aad600',1273,157,'煞笔一个，选吧，你们就选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69586716a54da130beb63f07',56,56,'老师中的神，人好也很有耐心，上课不死板，鼓励大家动起来，老师做动作贼帅！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695866a1a54da130beb63a89',55,55,'好老师，无需多讲，闷头冲就行，老师真的很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695864eaaf4f482042aac8bd',56,56,'大学以来最拿学生当人的老师，特别好，认真负责有耐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69586481af4f482042aac753',55,55,'神中神，陈老师捞了我，快哭了，因为有体质测试，成绩差的一批，老师反复让我们确认成绩，跟我们强调了各项成绩的由来，捞了我捞了我，老师人太好，跟你当朋友处，负责又有爱',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69583819448e7823616149aa',1286,1286,'这课差点给我人上没了你知道吗，大学四年上的课就焊接科学与工程和CAD最顶尖，刚好都是刘老师的课，最想拼刺刀的一次',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6957d7df448e7823615dc39d',867,28,'麻麻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6957cbcc448e7823615d0bea',1330,1330,'感觉自己都不是很搞得清上课的内容，讲的也完全听不懂',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6957869605564e312666666c',298,85,'一定别选，上了一个学期他的游泳，和没学没区别，上课水的能打王者，就因为没加慕课堂，导致慕课分直接计零了，一个绩点就没了，毫无师德可言，给学生使绊子的第一次见，西南交大有他，这辈子有了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695785e606646d6d76a4422f',1332,81,'复习习概中跑来给你打个差评。孩子们这就是你标哥，上了一学期不知所云，除了中美就是中日关系，和课本内容可以说是毫无关系。你哪怕念PPT，让我勾画两笔，我现在也不至于这么痛苦，快跑孩子们，快跑！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6957849c05564e3126665aee',1333,27,'好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6957825105564e3126664c27',1130,1130,'纯垃圾，缺一次扣3分（总分），作业留的多，不管写成啥样都一个分；实验报告说的时候要求严，结果出来宿舍里兢兢业业的熬夜写报告哥和随便AI哥等4个人分一模一样。治学严格就是表面严格对吧😅🖕今年考试前还说出难题，把挂科率提到30%🤣我看谁敢选他😂',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69578207daee5f72f23d22cf',172,39,'纯傻逼我都不想说迟到一次直接扣老多分快滚吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6957814405564e31266645d0',517,517,'人文关怀无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6957791206646d6d76a3e589',389,389,'必须给我哥拉满，很难想象大学里还有讲课这么吸引人的老师，选就完了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695770f705564e312665c77f',35,35,'不水，事稍微有点多，前几周课还能做自己事情，后面就要排练唱歌，不想唱歌的话可以做导赏表演ai作曲之类的，但都不轻松。接近期末抽了一晚上去排练，期末音乐会要借服装。我是唱歌组的，虽然听别人说这课打分接近满分，但给了我95，比预期的要低一点吧，想拿高分的可以左转去选心理课，事少分更高。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('69576fe405564e312665c12c',751,573,'没有标准，全凭自己主观臆断，扫码了18分的题因为我把标注划在给的图里就全扣完，说真的没人在乎你在曼彻斯特留学和北大读研，山西口音巨重，讲东西支支吾吾的，你说你上学时候喜欢争第一，考试要拿满分，你讲课怎么不争第一呢？一下课就去抽烟🚬，愧为人师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69576f50daee5f72f23c7a9b',385,27,'挺负责的老师,梦回高中。想要平时分一定要把握每次机会,积极主动回答问题,因为她问问题的次数挺少的。作业也是真的多',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('695742c3a54da130beae784a',1341,114,'下课问问题敷衍得要死',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695740afdaee5f72f23b8b7f',23,23,'巨好的老师，强力推荐！上课有激情，对学生爱心满满，处处为学生着想，有问必答......真正体会到什么是教书育人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69573e83a54da130beae6438',210,28,'神中神，老师人超级好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69572a1ca54da130beadd9c1',315,40,'非常认真负责，是那种伸手不打笑脸人',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('69567adedaee5f72f238dc08',588,588,'糟糕，爹味非常重，很看不起学生，问题也不给讲，不耐烦几句话就把你打发走。脸臭到不行，又拽又傲，对学生很不友好。他讲也讲不清楚似的，有些易错点要自己下来学才知道，上课又不给你讲，就念PPT。可能以为自己应该在清北教书吧，得教放下PPT就懂的学生。期中考试出的题更是莫名其妙，对ppt上只出现了一句话的点考了一个大题，拉普拉斯逆变换？这是我们这门课的内容吗？然后又考一个巨难无比的力学系统让你写状态方程，考完都在骂，除了科技，0个人能写出来。同时担心期末又出些什么烂题。毕竟在课堂上就对学生非常不满并放出狠话说要考的比期中还难，还开嘲讽说担心大部分都通不过。作业，下课不顺手收了还让学生个个跑七教。绝绝绝',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('695666b0daee5f72f238613b',51,1346,'想拿高分的可以选，有一次小组汇报，每节课下课前都要点名，除此之外无事一身轻，给分98，老师我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6956593adaee5f72f2381d9c',1231,136,'老师人超级好，只要你勤奋练习，分都挺高的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69564ef3a54da130beaae1a6',9,157,'老师人很好。亲和力强，认真负责。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6956356d06646d6d769d299a',257,5,'是人我吃',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69563504a54da130beaa399e',1350,5,'拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69562ab2448e782361547780',1,1351,'给分很低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69561cb8af4f4820429fa2fc',22,22,'神中神，非常之好，虽然不知道为什么这学期节节课点名，但我觉得问题也不大。平时分好多人都给了100，作业忘交了还专门重新给我开了一次让我补，也没扣分。真的很好，讲课也清晰！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69561c53af4f4820429fa08b',1353,1353,'给分中规中矩吧八十多九十，上课很认真，准备的内容也很充分，连着两学期都上他的同一门课，但课堂内容、PPT完全不一样，能感觉到老师认真准备了。点名很少，不知道为啥选这个老师的人那么少',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('69561bc305564e31265ffede',832,40,'老师挺好的，课堂内容干货多，但确实每节课都抽人回答问题，不过答不上来也没啥事也不会骂你。我个人感觉给分挺高的，只有最后的final essay是认真查文献认真写的，前面都是水过去的，给了我45/50。。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69560d6d06646d6d769c3176',832,40,'给分特别低，别选就完了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6955f6b7a54da130bea8c823',832,40,'老师给分还是挺大方的，人美心善，课不水，但确实能学到东西。上课基本都会抽人回答问题，作业也是要下去花心思认真做的，想水的建议换老师',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6955f57bdaee5f72f235c757',48,48,'如果你羽毛球打得特别好可以来 注意是特别好 其他都不推荐 给分巨恶心 动不动就扣分 大学了还要被体育老师骂得狗血淋头 迟到一分钟也要扣分 然而你和她很熟给她说一声就行 迟到十分钟都不扣分 事情特别多 做什么都不提前给学生说 唯一一点好就是下课不点名 课中可以溜 对了 她脚受过伤好像 学生理解老师 没办法亲身示范得很好 老师不领情没办法 巨恶心快跑',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('6955f57705564e31265f2cc1',832,1358,'给分低的且擅长恶心人，这个人根本不加分而且屁事多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6955f3da06646d6d769bb26a',832,40,'专业水平很好但是我不理解 作业都是做了的 没有逃课过 签到全在 作业认真写的最后 50 平时分只有 39 还要算上六级加分 想要高分的可以出门左转了',5,5,2,12,0,0);
INSERT INTO "reviews" VALUES('6955e96205564e31265eeb5c',121,611,'上的通用学术英语，也是孙老师第一次上这门课
INSERT INTO "reviews" VALUES('6955e6d805564e31265ede1d',1093,1093,'本人常微分课，张春梅老师是我上大学以来觉得最喜欢的老师，治学严谨、认真负责、耐心细致，不知道楼上楼下恶评怎么来的。总之一句话，你认真学，她认真教，会学到真东西的同时、分咔咔高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6955c4d5a54da130bea7b1b1',1001,1001,'讲课声音是真的小，而且非得装杯用英文写板书，试卷也是英语，卑劣中的卑劣',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6955c3f1448e782361522548',1001,1001,'上他的课真的有福了，来与不来随便你。本来课就难，上课对着pad写全英文板书，没有讲义，不按课本讲，不布置作业也从不讲习题，不给复习方向。喜欢吹牛，上课需要你特别尊重他。越讲到后面越抽象，讲课缺少逻辑，声音时大时小，很多学生听不懂是学生的问题。老师一学期能缺七次课，也不需要改作业，上课真轻松。水平很高，建议研究生可以考虑这位。',4,1,2,7,0,0);
INSERT INTO "reviews" VALUES('69556885daee5f72f233fd09',121,121,'如果只是想水，但是不想要高分的不要选
INSERT INTO "reviews" VALUES('69555ca7af4f4820429ce1c2',89,33,'绝世好老师，温柔体贴，给分高，上课也想干嘛干嘛，点名次数少，而且还会提前几天提醒这周要点名，作业也给补交机会，必须满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695479deaf4f48204295d3cb',5,114,'讲的没有很好，但人特别好，上课可以随便看手机，小测也很水，课堂氛围很轻松，去问问题也会认真给你解答，萌萌守信',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('695478a505564e312654cce9',25,26,'我是他线性代数的学生，讲的很好，平时分也挺高的，但有可能会借晚自习小测（就一次），课后答疑也很负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6954727ea54da130be9c8fab',247,28,'老师真的好温柔，讲话非常客气，讲课也很尽心，虽然每节都点名，也会提问，但是如果你回答不上的话也是没关系的、根本不会说你，还会耐心的讲，非常负责。老师还会编教材呢！我平时没有缺勤过课程考试才考了74，她把我平时分直接拉满了，况且事多是全年级统一的作业多，又不是老师的问题，只要学习态度好，上课别迟到别缺勤老师就会很喜欢你的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69546a47a54da130be9c6b44',103,6,'果然，看大部分人对他的评分给的这么低不是没有原因的。感觉他的存在除了恶心学生就一无是处了。也不知道他祖上到底修了多少福才让他吃尽时代红利******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69541489a54da130be9bdaf3',1370,136,'我上的他的乒乓球，人很好，属于快乐教育，如果不是缺特别多人也不点名。对于那些努力但没有成效的人来说就是活爹，只要你努力，就算没达到要求，他也包给你过的。毕竟体育这门课你不追求高分的话选他是最优解，轻松快乐的同时也能顺利通过。班级群里赞声一片的好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695412cfa54da130be9bd887',1274,36,'水课但老师不水，要考试但不总结重点，点名常有，管理比较严格。总之不推荐但是能忍受，能换走最好，不能换也能凑合',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('695411bda54da130be9bd719',1372,23,'如果你专心听讲或者理解能力强能跟上，这老师虽然有时念ppt但是总体讲的算好的，也会经常提醒学生要跟上节奏。不建议注意力不集中的和想水的人来，打分很现实，不捞人也是真的。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('69541108a54da130be9bd5d3',870,296,'个人感觉张老师讲课挺好，逻辑性还是挺强的，但是非常建议课前预习后使用，因为很多同学反应上课听不懂；老师特别亲切，上课会反复强调没听懂去问她，没跟上去问她，她会帮你补起来；除了课程前期抽过一两次人回答问题之外，之后就是自愿的；平时分打分就是按每个部分打分，两次课堂小测（8道题里对5道满分，每题20分，满分100，每道题都有步骤分，对的，特别注意这一点，否则会扣满或者给5分）本质上挺严，不能用手机，但实际看情况；作业量适中，偶尔几次课会多一点；点名有过几次，但偶尔两次缺勤之后跟老师说明情况不会扣考勤分。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6954102ba54da130be9bd483',604,5,'如果你是理工科较好专业（交运电气计算机之类），万老师是个不错的选择。虽然有四川口音但能听懂，讲课答疑很细致也有思路，全程板书无PPT。而且这次他留出了期中成绩暂时不登方便捞人也很人性化，只要你不是节节课耍手机多少听一点就能过。
INSERT INTO "reviews" VALUES('6954100fa54da130be9bd461',307,307,'请输入文本',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69540fe405564e312653e5c7',100,100,'神中神，除开每次上课考勤这一点外无敌，事少分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69540d46daee5f72f22a9e52',1377,194,'人还可以比较好交流，就是喜欢念PPT，作业量一般往上，优点是除了隔三差五签到管的不严，缺点就是比较水，选到以后要有上哔哩哔哩宋浩课的准备',2,3,4,9,0,0);
INSERT INTO "reviews" VALUES('69540cefa54da130be9bd02e',87,87,'马朗老师神中神，直接冲就完事了。给分高，专业性强，是国家级裁判，好说话，名副其实刀子嘴豆腐心，专门注册账号来评论。我的朋友，你值得拥有！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69540b9baf4f48204294d5f9',1379,346,'上过这人的太极超市，点个名就她搞特殊要面对面扫码，麻烦的一批，签了几个就开始玩失踪，她没给你签那恭喜你这次白来了。态度也不好，建议太极超市避雷这位',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69540a2405564e312653dc9b',451,36,'先说优点，老师给分可以，上课也很水。
INSERT INTO "reviews" VALUES('695408aea54da130be9bc84f',1381,517,'这是选了个体育老师？选了个爹吧！选吧，都来选，上课当狗溜',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6954084005564e312653d92c',58,55,'垃圾，认真学习跟那些不认真学习的分数一样？？？大家都一样，上什么课？？你直接给分好了，水的不能再水了，学的那动作跟网上的都不一样',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69540811daee5f72f22a92ec',101,114,'怎么会有这么好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6954071906646d6d7690968c',55,55,'老师人好，有耐心，事情说的很细致，给分高，爱死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695406bf448e7823614afbed',56,56,'老师很和蔼，有问必有回应，我舍友的老师啥也不回，问了也没信儿，有的还让我问陈老师。老师很好，很负责，给分也很好啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6954064ddaee5f72f22a8f92',1386,1386,'老师前期很不错，但是一到做实验，事情贼多。所有要求都是临时起意，非要等我们作业和任务完成才说要求，这是最不能忍的，每次都等做完了才提她的其他要求，修改完了又有新的要求。唯一优点亲和力拉满，缺点是事情贼多',2,1,4,7,0,0);
INSERT INTO "reviews" VALUES('6954045806646d6d76908ffd',758,676,'跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('695403af06646d6d76908e6e',27,27,'很不错的一个老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6954032005564e312653cd68',232,24,'无敌，神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6953ffb8daee5f72f22a7eac',1390,28,'老师很好，在教务处要求下给分挺高了，人也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6953fb21a54da130be9b9192',1391,24,'老师很有耐心，几乎不点名，不管半期考多少，平时分基本给满。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6953faa606646d6d76906582',1391,24,'非常好的老师，值得选择',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6953fa05448e7823614ac5b8',173,28,'别去，开学卷子水一点，谁去谁后悔，作业多的要死，u校园还要查时长。',1,2,2,5,0,0);
INSERT INTO "reviews" VALUES('69533fc6af4f4820429017b7',1394,230,'每节课都要定为签，但怎么说呢，不会太为难你，结课后还会给你发一篇作文，蛮用心的老师',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('69533ce806646d6d768badf8',932,1395,'袁老师人还是蛮好的，作业没交直接跟他说就好了，不会对你太严，有很大容错空间，也不会故意刁难你，人还是很和蔼的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69533c32448e782361462083',1106,1106,'这老师简直神了，自己对课程时间的安排都不清楚，答疑时间都能记错，17周要上课，然后让考试周去答疑，这老师也是真性情中人，上课说话被他看见扣你几十分，天天上课阴阳怪气，你们反正就选吧，有你们好受的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69533be905564e31264f145c',9,157,'请假一次不扣分，上课能摸鱼，老师是真好，错就错在排球这门太折磨了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695337b5daee5f72f2258dcb',909,1398,'6',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6953288f06646d6d768b16d8',162,426,'最擅长把ppt内容换一种说法输出，但毕竟是门水课',2,5,3,10,0,0);
INSERT INTO "reviews" VALUES('695327c406646d6d768b11f1',649,36,'韩大律师你就选吧 平时分拉满 平时课上不能用平板但可以玩手机 回答问题加分 有几次小组作业 人少会选择性点名。我每节课就只是到了教室，一学期就回答了一次问题，小组作业课上案例讨论直接ai，课程组布置的小组作业也是马马虎虎做了，最后满平时分（不过他也没有细分各个分数，就一个“其他：100”）。人也挺幽默的，上课边玩手机边听几耳朵也挺有意思',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6952e12fa54da130be957cc6',1401,1401,'老师神中神！多开一些选修课呀！不想去也没关系，去了看电影之类的也很有意思！其实一学期只去一次期末也没关系懂吧。手写3k左右论文，抄就完了，没难度。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6952e02ddaee5f72f2246546',16,68,'老师人超级无敌巨好！！平时上课会慕课签到，但我感觉大岁数英语老师上课都要管考勤。回答问题加平时分，像站起来朗读一个自然段、上黑板写一个词语这种水活动，可以看出老师想尽办法为我们加分👍职场英语是四人小组做作业，90%的作业课堂就能做完👍努力一学期，平时分好像是94👍',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6952df26af4f4820428ea841',385,28,'是被分配到这个老师A班的，大家英语都太厉害了，所以我在班里的水平处于下游。怎么说呢。。很后悔大一下没有换老师，两学期，平时参加各种英语沙龙活动、英语比赛、志愿者、早读，就是为了弥补我的英语水平。结果到最后发现同一个班，中期考试成绩一样U课堂成绩比我低，人家啥也不干的平时分都比我高很多很多。不说了，英语水平一般的遇到就快跑。。。Btw，两学期在很认真的情况下平时分都没上85，后来换了个老师直接90+，快跑！！！',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('6952dd99448e78236144595e',1404,1404,'老师人很好，这门课程不仅有趣而且实用性很强，选上就偷着乐吧👍',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('69526ffa06646d6d7687ba93',230,230,'给分巨低，快跑。平时分都是80。快跑。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69526ef5daee5f72f21fb45f',1406,241,'有脾气 会提醒作业',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('695260ea448e7823613c4fd0',502,1407,'人如其名 大学四年上过最让人无语的老师 劣迹说不尽 言语很难表达 反正学弟学妹别选他作小组老师就好了 但是逃不过 因为他是主讲老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69525c68daee5f72f21f3e87',433,28,'逆天就对了，上课啥也教不了，作业屁事还一堆，问问题不理，给分还低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69525bdea54da130be8d5fa3',1409,1409,'闹麻了，这哥们天天一副蔑视的样子，别人问个事也不理，啥也不通知，还特喜欢阴阳怪气',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('695258ef06646d6d76873545',1410,1410,'无人想理，自以为很幽默',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6952556caf4f48204281dab0',111,1411,'必须给到一万分，平时分捞满，半期开卷，期末划重点还发糖给我们，一直夸我们🥹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69524973a54da130be8cf464',517,517,'很有原则也很体贴',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695244b005564e31264805c2',640,229,'赶紧跑，讲课照着PPT念，事特别多，还要写学习报告，除了她没听说哪个老师要求写的，特别麻烦',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6952440edaee5f72f21eacb3',1414,1414,'老师讲课风趣幽默，温柔和蔼，结合实际，思想前卫，谁敢忤逆',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6952427006646d6d7686aa1e',1415,1415,'胡老师太好了！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69523f53a54da130be8cb750',7,7,'太强了胡老师，教的超级好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69523f1d448e7823613b8104',499,194,'老师人超级超级好，教的非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69523ee106646d6d76869167',1418,39,'王老师人好，贼幽默有趣，对网球要求比较高，打得好给满分，愿意练态度好也会加分，大一下单打比赛最低90，对网球感兴趣的超级推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69522c8ddaee5f72f21df192',1419,1419,'高高在上，冷漠无情。。。慕课是不提醒的，平台问题提前截止考试，是怪学生不早完成的，考勤分是给不满的。从来没有为学生分数着想过🙄想要评奖评优的赶紧跑，在其他体育班从来没拿过这么低的分数',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('695229fca54da130be8c144e',1273,157,'没有排球水平的同学真心不建议选这门课，老师上课讲的东西是不错的，但是期末考试太过严苛。大一上对垫球五十个或者对墙垫一百个，大一下是发五颗球，大二上是扣五颗球。别的老师都是多次考试机会，董老师只有两次机会，一次看个数，一次看绩评，如果考试没考好，大概率就是六十分左右了，并且老师还要你感谢她捞你。就是没有排球基础的话，这门课不是那种你努力就能拿高分的课。',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('695228b1a54da130be8c0ae6',44,204,'纯cs 事特别多 给分纯随机',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6952255faf4f482042808e94',359,228,'老师很温柔，平时只需要回答几次问题坐下前两排就能拿满平时分，考勤的话一般是最后一节抽点一些人，偶尔全点。这学期平时不缺勤不缺作业，半期考试20分算10分的话的话平时分就已经有80分了。
INSERT INTO "reviews" VALUES('695223c305564e3126471633',799,799,'特别好啊因为是新老师，所以最开始没注意 其实他特别好啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69522092448e7823613a978c',281,281,'老师我爱你，作业没交过，课从没去上过，期中考的还不错，平时分竟然给满了！？虽然我没听过课不管了好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69521504af4f482042801e8e',883,1015,'到底是哪里给分高，谜一样的评分，作业都认真写的每次都及时交给的60分，期中成绩也是不公开，最后才知道，不知道哪里错的谜一样的评分，喜欢拆盲盒的有福',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('69520320a54da130be8b1db0',360,360,'可能是上辈子毁灭了银河系，我遇到了小黄鱼两次，算法课的时候专业课太多了没换掉。小黄鱼还是蛮可爱的，最喜欢他的一句话就是“讲了你又不听，做也不会做”，感觉像是无能狂怒，又感觉像是对命运的叹息，很搞笑好吧。他的PPT是用了几百年的且做的像shit，看他PPT不如看教材。讲课讲着讲着他自己都不知道自己在讲啥，讲了半节课了发现自己讲错了又从头讲。计图是真逃不掉，就他一个人教。算法课还有助教帮我们蒸，计图课小黄鱼直接压力助教了，有次作业都改完了分都发出来给我们看了，然后又重改，给我美美暴扣20分。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6952012d06646d6d7684de26',83,83,'大学的第一堂课就是何莎老师的高数，让我误以为大学老师都是这样负责又有水平的。选到何老师就是赚到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6951ffe0448e78236139d6b3',360,1129,'课是讲不明白的，作业是做不完的，学生是要压力的，实验报告的要求是海量的。每周都有一个实验一个作业，每个实验堪比一次课程设计，一门课花的时间比其他所有课花的时间都多。选到就是赚到。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6951f5a006646d6d7684993a',87,1183,'极好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6951f497448e7823613992d6',1430,1430,'上课就搁哪放疫情时期的视频，及其水',2,1,2,5,1,0);
INSERT INTO "reviews" VALUES('6951f204af4f4820427f412f',429,33,'挺好的一个老师，有真才实学，也和学生挺亲近的，期末也会捞人，会提醒你，挺不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6951f140af4f4820427f3be3',31,1169,'跟着秦老师学高数就是捡到宝了，课堂内容讲的清晰明了，专业水平高，时不时还会开些数学历史的玩笑，上课也有趣。而且课下问老师问题老师也很用心的回复。之前QQ上问的，秦老师回了我好几条五十多秒的语音给我解答。超级超级好的老师啊🥹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6951eec0a54da130be8a99ae',1433,1433,'上这课的只能自认倒霉了，奈何会计系只有她一个老师，没得挑。慕课多到爆，加起来我觉得能做十几个小时，每一章有习题还有期末测试，你觉得很辛苦了吧，按照成绩分配一算这些只占总分6分。没错，就是6分。课讲的是莫名其妙的，纯念ppt，关键是ppt还有错。书是自己编的，所以也是看不明白的。最后和你说大家做习题，期末选择题30分来自习题。习题一打出来，足足有60页，你不如让我把整本书背一遍算了。期末占总成绩的70%，考不好了年也别过了，等着回来补考吧。纯纯逆天，事已至此，我只能祈祷期末不要给我下死手🙏',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6951edb5af4f4820427f1a8a',247,28,'虽然上课学不到什么东西是照着ppt念，也会抽人（但是内容都能提前找到答案，而且就算答不出来老师也不会说你啥的，就让你坐下），而且老师人特别特别温柔，上课睡觉（如果不是太显眼的话）根本不会管。期末查平时成绩的时候，课程考试没及格还会笑着鼓励你要加油，平时的综合成绩也会整体捞的。反正综合下来还是特别好的（对于上课想水的人来说）。特别真诚温柔的老师。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6951ea88448e782361394d78',1435,457,'水课就选谢老师，上课几乎不点名，上课怎么玩都不管你，知道有同学翘课还会叮嘱让同学把重要消息带回去',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6951de0205564e312645502a',315,40,'天天讲哲学，讲不到重点，要求特多，考试考美音，他要求学英音',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6951dce4448e78236138e494',11,11,'作业暴多，笑面虎，讲课枯燥',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6951d90005564e3126452d3a',220,101,'老师高数讲的特别好 有重点 人还很亲和 上课偶尔点名 发信息也都会及时回复 平时分给挺高 非常棒',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('695185c9af4f4820427db519',237,237,'课是比浦西的水还多的，平时分是几乎没有的，考试是肯定不捞的，开玩笑是肯定带上你的，你学高数是只能靠PPT的。并且别指望他教的水就能捞你，他批完的成绩直接上传教务网，想在西南交大好好完成自己的高数生涯就别选他。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6950c6a0171b217b0e864160',39,39,'快跑，不要选，不要选，看不起学生，',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6950b390171b217b0e85deea',1441,228,'无敌的存在，平时分全员几乎不低于85，做次前排或者回答问题直接90以上，认真完成作业听讲全勤，平时分应该是全年级最高。老师讲课很有意思，听课像听书一样，能真正学到很多知识，神中神，无脑冲',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6950b23daf4f482042795cff',1058,985,'非常负责任的老师，朴实严谨，从来不拒绝同学的问题，有的时候，晚上十一点了，还在给同学解答问题，非常非常good',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6950ae54daee5f72f2168f23',221,36,'史中史，打一分的原因是因为不能打零分。byd一个小组作业问东问西的，之前也没说要做PPT，好不容易赶完又要说还要调查数据，你自己又不说，又耽误一些时间，最后有一个组没有汇报到又说是他们的问题，你是脑子抽吗？上课作业也不让写，讲的话也听不懂，就真的是纯坐牢不多做评价。哦，对了还有一次分组，在知到群里问小组把报告主题发出来，分了小组吗就发，到第二天早上有在冒火，说我们班怎么就是做不好呢？后面才有人说还没分组，“我没分组吗？”真的是脑子抽了想得出这种话来，老子还被分到前面。。。。。不多说',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6950a773af4f482042792616',1274,36,'上刘老师的德法课，老师讲的挺有意思，是个比较认真的老师了',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6950a51b05564e31263fc216',604,5,'老师教的很认真，小测也比较轻松',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('69508b9f448e78236132c87a',704,704,'好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69500f8605564e31263dade9',1193,28,'下课玩手机扣分，上课更别说了，讲课内容完全没用，让你们上课做题的话老师会直接失踪，拉完了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694f67e8448e7823612cda7f',505,250,'老师很认真，作业都会自己认真批，所以可能也会有平时分比较低的情况，当然如果认真好好学习的人可以选，无论线上线下，你有问题都可以问张老师，有问必答，一点架子也没有，作业没做完也可以补交，老师也不会说什么',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694f5f82a54da130be7e5a07',1289,1449,'全交大最懂信息论的老师，全交大人最好的老师之一拉满！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694f542ea54da130be7e1747',1450,1450,'最会阴阳的老师，快跑，事情巨多，▼・ᴥ・▼',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694edacea54da130be7c12bc',55,55,'谁选谁知道！全班没有一个上90的！到底是我们水平不行？还是缺课缺到来得还没有帮她代课那个老师多的她教学有问题？我只能说谁选谁倒霉',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('694ec135448e7823612a365a',1452,623,'无敌了这个老师，只能说快跑。
INSERT INTO "reviews" VALUES('694ec0fe171b217b0e7d1450',1453,114,'很有意思，我太喜欢这个川普了',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('694eb7c5daee5f72f20da307',1454,23,'老师讲的真挺好的人也很亲和，实验课还会跟你先讲一下难的点怎么做之类的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694eb64d05564e31263746f4',1455,136,'强哥手下拿过体育100分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694eb35fdaee5f72f20d93b8',415,415,'大物实验 遇到欧凯自动扣20分哦 原理是不想讲的 结果是要强制验收的 数据是不能改的 报告是要打低分的😋',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694e06d3448e782361261fe6',389,389,'一人血书请奇哥教材科基2，无脑奇哥，如果有排名，奇哥绝对算是前十，我一直是窥屏仔，为了奇哥来专门注册评价，我恨啊我恨，上过奇哥我就再也看不上其他老师的课了，就是朋友，没有架子，说话温柔，下课很多人去问问题，这个含金量不用多说了吧，我恨啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694e0255171b217b0e78e6f6',1458,676,'唐小虎期末答辩一人杀翻全场',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('694dfc84a54da130be7701a6',1386,1386,'看着很好说话，但是总感觉在某些地方让人很难受。期中考试考完了非要让没有及格的重新改一遍卷子，到期末了说我们作业完成情况不好要所有人重新打印出来改正了交给她。最恼火的是她带通信电路实验，总是喜欢中途提要求，也许她什么时候真的偷偷提过但是大部分人都不知道。所有实验都做完了才说要原始数据记录表原稿还要助教签字，所有报告都装订好了才说所有报告要订在一起，总感觉被她戏弄了。不过最后交报告时她也没要求那么严，这点还不错。',3,2,4,9,0,0);
INSERT INTO "reviews" VALUES('694dfb17daee5f72f2093955',676,676,'直接给我选，人超级好，上课态度也认真，就是讲课有点墨迹，期中考试可以抄，课堂作业少还能晚交，给假条就行，给分还高给我选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694dfa9905564e3126328335',1386,1386,'前期感觉还行，越讲越烂，ppt 很乱，上课听不懂，下课看ppt 看不懂，作业答案不给课上讲习题讲的一坨（网上搜不到），还让自己总结答案，实验课每周都有累死我',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('694df857448e78236125a1c8',411,36,'作业非常多，有课上回答问题（小于等于5）的kpi，捞不捞人不清楚，不建议选',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('694df825daee5f72f2092316',888,779,'老师对于教学认真严谨，可能有点口音，有时候发火是因为答题正确率不高，平时挺温和的，作业正常',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('694df704af4f4820426bd933',1082,40,'上课很水，喜欢分享澳大利亚生活，平时在后面玩手机也没人管。
INSERT INTO "reviews" VALUES('694df63adaee5f72f209108a',86,653,'😅😅😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694df5b4af4f4820426bd0d7',1450,1450,'别选，水课次次打卡，两次小组作业一个手写千字大作业。公共艺术课还是选魅力器乐',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('694df44505564e31263253d0',221,36,'纯纯神入来的，上课要分组，要喊“老师好”，带耳机玩手机写作业会被说，甚至会记名字扣分，上课不能喝牛奶吃面包，期末小组作业纯纯找茬，不想让人过就直说。平时分给的贼低，遇上他就享福去吧哈哈哈哈',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694df3ba171b217b0e78558c',221,36,'神入',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694def29a54da130be76360f',246,228,'没啥好说的纯纯打撒币',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('694dede4448e7823612549c5',819,228,'她让我感受到了马原的温度。她的课的基调是爱国，色彩是希望，目的是教会我们用马克思主义辩证原理来分析世间种种最后一节课的最后五分钟，她说:“我有三个期望，第一，希望大家都能通过马原课，希望要保研的同学取得满意的成绩，第二，希望大家失意不要忘记希望，得意时不要忘记失意，第三，希望大家能用马克思主义辩证法开拓眼界，提升个人综合素质，为中华民族伟大复兴奋斗”最后，只要认真听的话，老师给分很高的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694dec2d171b217b0e78196f',1212,1471,'很好的一位老师，本身是博导，上课也会拓展更深层的知识，幽默风趣，考前划重点。但是上课喜欢点名，虽然答不出来也不会为难。而且小组作业比较多，期末还有一次大作业。看个人喜爱吧，反正我为耿维老师扛大旗！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694dea6905564e312631f9b3',396,241,'一个学期只有一次作业，上课基本不点名，考前划重点。詹老师和蔼幽默，选到他就偷着乐吧！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694de5db05564e312631da8b',296,296,'课程比较乏味，讲得很快，选到的尽量认真听，如果没跟上就看网课，翘了课也无可厚非，签到比较少，除非来的人很少，回答问题很少',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('694dd2bbaf4f4820426ae2fd',1474,1474,'赵老师为人特别的亲和，像一个家长一样，平时分回答问题三次，有一个10分的就可以全拿到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694dbe7aaf4f4820426aaa59',1453,26,'上课说川普，口音重',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('694dbdee171b217b0e774237',23,23,'刘霓老师 对她绝对是好评啊，讲课有激情，内容重点突出，超有亲和力，人特好，很热心，问她问题总是挨个耐心解答，而且教出来的基本都是高分啊！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694d62fddaee5f72f206be8a',228,228,'教的形策，挺好的，没点过名，期末考试提前告知，基本上都带了两个设备来也不管。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694ca059af4f48204265552a',1450,1450,'快跑，事多，交大最会阴阳的老师，千万不要选童，当然最好也不要选交美这门课，跑！！！！！！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('694c9e99a54da130be6f9a7a',157,157,'期末很严，根本不捞你，期末有好几个人挂，千万不要选这个，纯垃圾
INSERT INTO "reviews" VALUES('694c9e79171b217b0e71d702',1480,194,'我爱余老师我爱余老师我爱余老师，真的认真负责，课讲的特别好！平时分全班基本都是满分，下辈子我还给你拷课件🥹🫶🫶🫶',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('694c9db1af4f482042653fbb',1481,1481,'支持',5,5,5,15,0,0);
