INSERT INTO "reviews" VALUES('694c9cafa54da130be6f885e',1481,1483,'最喜欢的专业课老师，特别特别好的老师，很温柔，考试也会提前告诉题型',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c9b89af4f4820426530d4',1485,1481,'很专业。。。进来就骂人。作业多，考试难，期末给分还可以',5,3,1,9,0,0);
INSERT INTO "reviews" VALUES('694c9b3905564e31262ba5b9',1486,1486,'上的专业课。完全不会中文的英国佬，要求很高，管的很严，上课不能玩手机会被赶出去。。。考试给分不也不高。。。除了专业毫无缺点',5,2,1,8,0,0);
INSERT INTO "reviews" VALUES('694c98f6af4f482042651ac2',1487,1487,'超级ex，一个水课事情巨多，上课不让坐后面，屁事贼多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694c988505564e31262b8c2b',247,28,'老师说话温柔，上课喜欢抽人回答问题，回答不了也没什么，给分公正透明',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('694c91af171b217b0e716464',1489,850,'课讲的超级好。回答问题超级耐心。听他的课都不用预习。每节课会用雨课堂点名。老师长的很像高启强，脾气很好的一个中年大叔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c8efd448e7823611e8ecc',769,1490,'非常好的老师，期末慕课会发题来拉你的平时成绩，期末也会捞人，上课生动有趣，讲的非常清楚，遇到就是赚到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c8af405564e31262b2987',221,36,'人品堪忧，别人把精心准备的ppt拿上去分享，你一个劲地打断别个，因为自己留的时间不够就帮他推进度，时间限制是临时定了，ppt是早就做好了的，别人糊里糊涂地讲完你还一个劲地问刻薄的问题，你阴阳怪气别人?谁想上你课，谁想给你发言，谁想做你的汇报作业，能跑快跑吧。补充一点：你在前排做作业会被记学号，在后排玩手机的倒不管（当然走下来的时候还是要装个样子的）',1,1,1,3,0,0);
