INSERT INTO "reviews" VALUES('694c7f72448e7823611e2b57',1501,1501,'给分高，老师好，期末有复习',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c216bdaee5f72f20024c5',25,25,'不懂为什么都说好，名气大于实力。很怀疑每天搞这种数学建模的人是怎么博士毕业的，太差了，上起课来给我的感觉像个骗子，从来没有结论，不知道这课的逻辑是啥
INSERT INTO "reviews" VALUES('694c1d8ea54da130be6daba5',1503,1450,'傻逼老师，比我见过有几个行政的还差，不知道是不是关系户。如果你网上看到那种评论大学老师有多逆天，她就是那种聚合体。一门选修课给她上出必修的优越感了，一开始颐指气使地嘲讽理科生衣服穿搭，又说我的时间比你们的珍贵多了，又说是给学校面子才屈尊上课。貌似做点生意，有点业务，吹嘘自己去过哪些地方，见过什么厉害的人，完全一副市侩模样，小人得志，居然网上称之为艺术家，却未见发表什么大作，简直是厚颜无耻。前几天看她在食堂，恨不得上去扇她两巴掌。一门逼选修摆的谱比我必修课还大，讲的内容不成体系，要不是学校要求这个课能开得起来吗？上课还不给看手机写作业，给的作业分数也是十分幽默。这种老师赶紧扫进垃圾堆吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694c1ca1af4f48204263b1d1',442,573,'骂他的说的都对',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694c1c25af4f48204263b05e',1082,40,'还是很不错的老师，可以选，上课会开火车回答问题，但都很简单，事也少',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c1b34448e7823611d704e',1506,1506,'无脑冲',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('694c1b2aaf4f48204263ad53',46,4,'平常不教啥，期末考试死命往下压，要求贼多，选他课没基础就别想拿满分。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694c1a84daee5f72f200137c',264,230,'超级好的老师！平时分给满！虽然上课的时候可能有时候声音会大了一点，但是平时分给满这真的无敌了，然后有时候会点名，期末也会划重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c19f705564e31262a2a5c',1406,241,'超级好的老师！平时分给满！有时候会点名，有两三次叫人起来回答，但是他很温柔，你可以现用手机搜，回答不上来也没啥，然后还会提醒我们四级啥的，上课不听也没啥，期末会划重点！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c1956448e7823611d6a6f',948,92,'讲真，我感觉她讲的挺好的，我不咋听，会把每堂课要记得公式写在黑板上，然后也会告诉重点，我印象中没有点过名，然后老师很温柔，也很水，你听不听她不管你，平时分也还不错，只会扣期中考试的分，总的来说很不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c1869a54da130be6d9e70',891,114,'我真是数学不好，还好他捞我了，平时基本不会点名，只有看学生来的太少的时候才会点名，老师很温柔，不会和我们发脾气，虽然讲课稍微有点慢。但是老师很认真负责，平时分80多，没有特别高，但是我期中考的也不高，所以总体来说很不错了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c1827171b217b0e7037fb',369,66,'邹伟豪老师是非常非常好的老师，期末没有考好，也会捞你，是我最喜欢的体育老师，没有之一',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694c17aa05564e31262a24f5',1513,1513,'感觉还好，没有考试，就是交论文，平时会点几次名，然后听不听无所谓，最后90',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('694c174eaf4f48204263a337',311,1514,'平时每堂课会采用传纸条签到的方式，有的时候上课会按顺序让同学们读PPT，平时会有一些写的东西然后交上去，类似于测试自己的体质什么的，然后就是期末要考试，但是会给复习资料，只要好好写主观题就可以，然后好像还要拍两张照片啥的，总的来说挺简单的，然后最后94分，感觉还不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694b3a47af4f4820425d5721',459,68,'唯一优点就是不怎么考勤了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('694ad834a54da130be671f3d',913,913,'菲菲特别好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694ad7fdaf4f4820425c8e7d',348,348,'每天火气好大 说话听不清',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('694ad584448e78236116f838',605,605,'不许忤逆刘林老师！老师讲课真的讲的很好！建议想要好好学的来，想摸鱼的不建议来，因为老师每节课都有扫码签到，经常课堂小测加上作业多，但是老师真的教得好所以我还是支持她！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694ad453171b217b0e69cfad',607,1519,'好老师，特别水，上课一直问我们有没有听懂，听说我们课设多还帮我们把课设截止日期后延了www',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694ad347448e78236116f52f',540,1520,'满分满分讲的好人又体贴',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694ad30f05564e3126231d82',592,1073,'我爱钟华老师！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694ad2b905564e3126231cf5',1341,114,'小测不及格抄试卷。。。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('694acf7905564e3126231713',1523,114,'神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694acdb9af4f4820425c7e91',572,572,'该教师同时教授预制化概论，现对其25年9-16周授课内容进行记录。首周教师缺席，补课通知渠道不当致多数学生未收到。次周教师仓促要求学生讨论毫无知识背景的预制化设计，仅临时讲解便布置无法完成的作业。第三周教师迟到，学生因作业无解陷入僵局，教师方补充讲解。第四周教师突然以经费不足为由全盘推翻前期内容，转而要求学生基于陌生图纸进行施工方案设计，而该内容学生并未系统学习。后续课程缺乏实质教学，仅进行无效小组讨论，甚至出现由研究生“看场子”的非正常代课。期末汇报时，以不合要求为理由枪毙小组成果。
INSERT INTO "reviews" VALUES('694ac896a54da130be670181',915,250,'人美心善，是真的很会教书的老师，讲课思路很清晰而且通俗易懂，也会很有耐心地解决同学问题，从来不点名，只要作业交了就行。但凡稍微愿意学的应该就都不愿意错过她的课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694a016e171b217b0e64fba6',1526,1526,'超级NPD，非常以自我为中心，狂妄自大不能反驳，无法听取任何学生的意见，总是想一出是一出，说话又臭又长，一句话解决的事能掰扯半小时',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6949e782daee5f72f2f37c4d',1499,1499,'近代史，大部分时间还好，会莫名其妙抓着一个人一直说。。。期末会给重点',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('6949e5ffdaee5f72f2f3750b',564,26,'但老师，绝对的好老师，认真负责，只要你不犯事就不会对你平时分怎么样，上课很耐心，会一遍一遍给你讲不懂的，作业稍微有点多，不过也都是习题册上到哪写到哪。亲和力很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69491810af4f482042542ab7',23,1529,'特别好特别好，最后给我们发的邮件看得我眼睛袅袅了都，有耐心又负责，对她很愧疚我太笨了考试考不好，但她真的教得特别特别好，写到这里有点想她😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69490ba705564e31261a4349',604,229,'作为外地人，听老万上课的口音完全能听懂，而且带上口音非常诙谐幽默，很有记忆点，学线代更有意思了，写题目时脑中自动播放他做题的口音，爽！！！上课完全不念PPT，还有小故事环节，yyds！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69490aa9448e7823610df431',1531,641,'这个老师真的超级好，尤其富有耐心。在课堂上，如果你真的想通过听课学东西，是可以学得到的，而如果实在不想上课，你在课上不管是玩还是写作业她都不会管。虽然平时作业量大一些是不可避免的，毕竟课程比较重要，但做不完的时候她会经常给予容错机会，甚至有一次很多人还没写的编程作业，她把截止日期先推了两天，之后又往后推了两天。最值得一提的是她的学生一直以来的挂科率是0，也就是说基本上不管怎么样都会把你捞上来，真是五星好老师，多么希望每一科老师都能像她这样！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6949083ddaee5f72f2f02b2c',545,33,'分到他可以回去复读了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6949053e448e7823610dcde3',6,6,'想平时分高一点的，可以冲 
INSERT INTO "reviews" VALUES('6948ffd3448e7823610da4cd',6,6,'选到这个老师的课，这辈子有了。每节上课都要说自己上了一天的课，谁不是上了一天的课。最后三节课让我们发言，不想发言的，点名让你上去发言，期末还不画重点，只能说选课慎重。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6948ef7a171b217b0e603d25',1535,1535,'老师人很好，上课基本不点名，只有第一节课和人实在少得太多了才会让签到，上课很有趣，会讲自己的经历，专业知识很渊博，讲课会从多方面讲，期末考试是闭卷考，老师人真的很好，只可惜我认为是水课，没认真听，上课一般不允许做后三排，也不准玩手机，但你偷偷玩还是不会管你的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6948ed1405564e312618f897',1536,1536,'选他的有福了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6948eccf448e7823610caefa',1537,526,'现在站在你面前的是，带竞赛的，带的队伍必得国奖的伟大老师香香姐，香香姐上课教的很严，不准玩手机睡觉，但是，人超级超级好，教的很透彻，不懂的随便问，还会开线下答疑，这科想得高分，香香姐是必选项！强推',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6948ba5f448e7823610b957f',1538,1073,'小熊熊超级风趣幽默，讲课也讲的好，作业也不多，私下问问题也很仔细，分给得也很好，会捞人。小熊熊我们喜欢你。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6948b9f7448e7823610b932a',380,601,'讲得很清晰很仔细，还会在课上亲自下来仔细给你讲，作业也不多，除了口音有点迷迷，容易打瞌睡，无脑冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('69481c7c171b217b0e5cf415',1332,81,'三观有问题，证明“种花民族是最勤劳的民族”的论据竟然是鼓吹996，单休，全年无休。一节课平均三分钟就要提到“美国”“日本”，看来真是虐恋美日两国啊！极度的自卑让人变得无理很能在老师身上体现。。爱国比的是谁最爱祖国最爱国人，而不是谁最恨外国（按照这个逻辑，lyb你爱的到底是zg还是你超在意的美日🤣👈）',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6947b99c171b217b0e5ad5ea',792,792,'首先这位老师人其实很亲和，对学生也挺好的，不会很苛责学生。对于考勤和学生位置以及作业，大作业的要求都不是很高，所以我觉得这方面他挺好的。
INSERT INTO "reviews" VALUES('6946e7addaee5f72f2e4e64f',1542,1542,'上过最逆天的老师，幽默贾佳，从做人到教书，没一项行。快跑，快跑，快跑！要想大学生活过不好，贾佳的课少不了。快跑，快跑，尖酸刻薄这两个词是为她而生的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69465e27daee5f72f2e1ec6a',230,230,'打分巨低，一点不捞人，感觉就跟全班人有仇似的，上课戴个耳机都被针对点名，选他真算你有福了',1,1,1,3,0,0);
