INSERT INTO "reviews" VALUES('6944fea8171b217b0e4acbcc',1175,68,'通用学术英语来的。可补交作业，会捞捞学生，很有责任心的老师，为同学考虑。目前分数还没出。',5,5,5,15,0,0);
