INSERT INTO "reviews" VALUES('6944d01105564e3126fabb7e',788,1551,'想逃？在独断万古的娟天帝面前，一切评分都失去了意义。交通工程最有含金量的课程，享福吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6944ba53af4f48204239c035',573,573,'味大，无需多盐',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6944b34c171b217b0e48c86c',95,522,'专业能力可能是还尚存有一点，情商完全为零，背后说其他老师坏话，觉得自己高人一等，说自己就像邓小平这种总设计师，所有人都得哄着他，******材料实验所有的老师都特别特别和善除了他，还喜欢给别人单独开小灶，给别人穿小鞋。
INSERT INTO "reviews" VALUES('69449d62f05e621fb1e460da',1554,1554,'很好的一个吉祥爷',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694409d9a54da130be406d4e',1555,1555,'老师人超好，平时分几乎是拉满的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6943e1fda54da130be3f6c52',704,704,'神😤',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6943bc90f05e621fb1e0edc7',1557,1557,'老师讲的非常好，更难得的是PPT做的非常适合自学，就算上课摆烂也不用担心学不明白',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('694389ca05564e3126f3e3ea',228,228,'22道大题作业你就写吧，写错了还要打回来重新写，上课时不让上厕所的，去了还要阴阳你，来晚了要坐第一排，回答问题错了要坐第一排，写别的科目作业还说蠢的不知道听课，受虐倾向请选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6943882ddaee5f72f2cfe660',228,228,'期末交课后作业，所有人排着队一个一个检查，我全抄我哥们的，我哥们就排我后面，检查的时候她直接说我这道题不对那道题不对，反正没过，反手给我哥们全对，直接过了。咋了我哥们字小了点你没眼睛看了？还有分小组的讲ppt，自己没把握好时间导致最后三个小组直接不用讲了，你让其他上去讲的小组准备这么久，我们心里会有多不平衡？不多说了，1分直接打上位列拉班。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69437974af4f48204233773d',9,9,'神中神 休息时间多 人也很好 强度不高 期末老师给分也高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694371ebdaee5f72f2cf570c',314,664,'这真的是人类吗，每次实验挑毛病水平一流，甩脸色有一手。实验前不告诉你仪器有问题，做到下课来告诉你这仪器是坏的（何意味）😡😡😡😡。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6943701005564e3126f3386a',211,240,'没有半期考试，没有网上刷课，平时分98，让我这种笨学生也能开心的学习',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6942bf58af4f482042307c72',1282,1322,'老师人还可以，但不要选运动舞蹈，想要跳广场舞自己编排动作的可以来，想跳拉丁的可以来，别的躲得远远的...把体育课上成了拉丁舞专业课，拜托我们不是舞蹈生不要对我们要求这么高好吗',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6942b567daee5f72f2cc6255',89,33,'黄老师简直是我女神！！！！！词汇测试忘做了她会帮忙打回来重新提交，u校园有些单元忘做了她也会帮忙登记。平时大事小事都会在群里通知，流感来了还提醒我们注意防护！而且基本不点名，一学期就签到过一次！！真的很好的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6942b4ada54da130be388037',1565,1565,'喜欢背PPT和抄PPT的可以选，分也不高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6942ae55f05e621fb1dba9c2',221,36,'非常好的老师，认真负责，普通话非常标准，上水课的时候甚至可以做高数',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6942ab9df05e621fb1db9972',1567,1567,'评城市美学
INSERT INTO "reviews" VALUES('6942aa81171b217b0e3efa35',1568,1568,'还行，上太极基本不会自己教都是助教教，事儿比较少，而且你只要动作不出大错分都打的很高，上起来还是比较轻松的',5,3,5,13,1,0);
INSERT INTO "reviews" VALUES('6942aa1edaee5f72f2cc174d',1394,230,'讲课非常有趣，跟讲相声一样，如果不想听的话，在课上玩手机也没有什么大问题，想学习的人可以去找他深入探讨问题，不想学习的只想及格的也能随便过，总之就是非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6942a8b7a54da130be3833e2',1570,394,'讲的很好，案例很多，有时会点玩手机的学生回答问题，但主要是提醒作用，作业几乎没有，偶尔会有一两个，给分也很大方，非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694297b3af4f4820422f9035',832,449,'睿门😋英语公共演讲真的能学到东西，并且一定程度上可以锻炼口语和胆量，外向爱交际喜欢挑战和表达的直接冲就是了，课上有很多幽默外向的同学（实际体验是这节课真的有很多我刚刚提到的可以直接冲的特点的同学，周围几乎都是e人，交流起来0障碍，i人同学慎选不过也很推荐来锻炼下胆量，老师很温柔包容完全没有问题的😋）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694295bfa54da130be37d01c',103,6,'樊老师的分数要求很严格，思政课应该引导学生，而不是要求学生，过度用“加分”搞一些看似增加积极性的方法，实际上对于学生是否能学明白这门课程并没有太大益处，甚至这种变相的硬性要求可能会让思政教育适得其反，容易激发人们的叛逆心理。
INSERT INTO "reviews" VALUES('694294ca05564e3126ef2236',1573,1573,'怎么没有人给我女神打分，都来选我女神的课好吗好的，大学三年遇见过的最好的老师没有之一😋老师甚至还能眼熟同学，上次教学楼下碰见还主动笑着跟我打招呼😋😋而且老师带的专业课的实验课也超级体贴，会亲自帮忙调试并且分析原因给出修改建议而且还很有耐心像大姐姐😋（相比之下之前的实验课老师都是什么神人算了不提也罢）是本学期最难的一门实验课但是对老师本人毫无怨言甚至对实验课都有点爱屋及乌😋（）理论课也讲得超级好，每节课都会快速复习一下上节课内容，效率很高讲得又快又好😋对同学们的课下提问也都是有问必答😋总之都来选我女神（好奇怪怎么代代相传的口碑在活水上竟然没有，好老师也只在小圈子里流通吗（））',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('694291b0f05e621fb1dafdbf',640,229,'捞不了学生，上课念清朝老PPT，建议配合网课，但是问她问题她会耐心讲给你',2,2,5,9,0,0);
INSERT INTO "reviews" VALUES('6942912a05564e3126ef0da5',517,517,'高大威猛，给分高，就是游泳馆没修好，下学期请让我一头蒙进水里🥺',5,5,5,15,0,0);
