INSERT INTO "reviews" VALUES('694261f6f05e621fb1d9c16d',314,664,'据野史记载，寸曾一度陨落，在复活赛赛场上依靠平时在实验室用学生练习的寸劲、寸拳，战胜了牢大、佐巴扬、烈海王等一众强者，从阎王殿寸到奈落地狱，从塔尔塔罗斯寸到海姆冥界，最终于实验室重生。在这之后她更加努力的在实验室锻炼自己寸的能力，立志于让每一届学生都能体会到寸的强劲与伟大',1,1,1,3,0,0);
