INSERT INTO "reviews" VALUES('693b9955af4f482042044eb0',228,228,'有受虐倾向的必选，作业让你抄整整22道题，两万多字，手不停写，至少五个小时（亲测），考试是不画重点的，开卷是绝对不可能的，小组作业是一定要锐评的，打回作业之后是一定要讽刺挖苦的，上课必点名，回答不上来上第一排亲密交流，随堂考试不开卷，期末不开卷，重点也不画，上课讲的屁用没有，经典名句（我从来不让我孩子玩游戏）******',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('693b8a46f05e621fb1b17fe7',1612,619,'我是选的他的习思想，一次课都没缺，仅仅因为没回答问题只给了80的平时分☺️☺️☺️（没有事先说必须要回答问题，只说了会有加分）我能接受扣一点但是只给80是不是有点太过分？上课就是看视频然后提一些问题（类似谈美国问题之类的），回答问题还要打等级……更别提全是那种批判类的问题，第一次打低分，过了一学期了还是觉得很无语。。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('693b828c05564e3126c688a7',1286,1286,'除了吹牛，觉得自己教的很厉害以外，其实啥也没教，给你个PPT喊你自己做，上个大四的水课还要高要求，自己也没有高水平，纯纯西南交大学术妲己，拉完了，话倒是挺多，所以表达能力满分。',1,5,1,7,0,0);
