INSERT INTO "reviews" VALUES('693432d1a54da130bee58f3d',171,1646,'特别恶心的发言，感觉是cjb类型，天天上课就是对男的女的意淫，我天天骂美国的老舅都没他恶心，至少老舅不会意淫现在的女生不学设计就是花男人钱。朋友圈全是ai美女泳装照和一些莫名其妙的以为自己是哲学巨著的nc言论，分打的巨低，要求贼多还爱显摆自己的书法拉一踩一其实是屎。给我一种小时候被妈妈伤害了导致特别厌女的感觉。。要点名。还要认人脸。',1,1,1,3,0,0);
