INSERT INTO "reviews" VALUES('692d0180f05e621fb15f38d2',1419,48,'给分又又严，上面两个好评骂低分的估计被照顾过。一个大众课凭什么用这么严格的要求对普通学生，谁管你国不国家队，来交大当老师我又上你的课我就只认你老师的身份。给分就是低，不愿意给普通学生活路',1,1,1,3,0,0);
