INSERT INTO "reviews" VALUES('69290e0eaf4f4820429be34f',1318,301,'因为害怕，所以选择转专业',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69287747a54da130be9e77a2',1318,301,'这是啥必上的课？我没有因为：作业是书上每一章后面近乎所有大题，周二布置周五交上课😷😷💩💩🐒🐒🤮🤮，每节课必拖堂，5-7min不等而破防。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('692874c9f05e621fb1461b24',1675,1675,'选这门课的这辈子有了，明明是限选，几乎每节课都要拖堂。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69280c56171b217b0ea853ee',314,664,'设备没几个好的，电脑里全是病毒，你们学校真就不把学生的诉求和财产当回事吗？怪不得人才流失哈哈这种玩意儿越多，流失越严重',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6927c25a171b217b0ea5e43c',1677,1677,'老师人很好 冲吧家人们 偶尔点名然后作业不多 期中考试是发给你电子版自己做 上课有意思 如果想学到知识很不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6927c1f5af4f482042949f28',1021,228,'事多的要死 期中考试排座位 上课最后一排坐到第一排…期中别的班都用科技她一直转悠 出的五道简答题，还有单选多选 别的班甚至只有选择，上课还不让玩手机不让看课外书 点人 快跑壁垒',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('6927a933daee5f72f2335c90',415,415,'别来大物实验恶心人了，揣着架子，问你个问题都要嘲讽几句，没见过这么当老师的，生活不顺把气都撒在学生身上？那你挺活该了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6926d456171b217b0ea1ae4d',280,280,'上瑜伽课都在地上瑜伽垫活动，她要是讲话非要你站起来听，你要是不站起来就是对她不尊重，她自己坐着讲话，高贵什么？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6926b85edaee5f72f22f31e2',1681,1681,'AI的奴仆，感觉讲的很有道理，但细细回想一下就啥也不是，天天说一些假大空的妄论，我老舅喝多了在酒桌上跟他讲的差不多，每天就灵机一动的想一个主题让我们开始做，啥也不教，认为ai是神，鼓吹2035年后什么都有，最爱空想科技，认为我们做设计的应该深耕科研，我没搞懂他的想法。就课程内容来看，一无是处，浪费时间。就课程严厉程度来看，非常好，能睡饱三小时。就课程成绩来看，生死大权掌握在同学手里，他把自己撇干净了。反正几周下来我是什么也没学到，上课算是一种煎熬。',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('6926b181af4f4820428f2896',314,664,'纯纯生活不如意，前来压力你，实验验收甩你冯脸色，有一点点不对就炸，遇到她也是享福了，啥呗',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6926a26bf05e621fb13bbd38',359,228,'一分不是因为能得一分，而是因为最低一分，打不了零分。事情多的要命，哪有老师迟到还扣分的，而且就晚到个几分钟。专业课老师都没这么多事吧。还要写作业，背诵一些毫无意义的东西，强制回答问题，讲的无聊死了，点人回答答不上来就开始长篇大论讲大道理，无敌抽象，快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('692558e3af4f4820428803a1',1282,1282,'好',4,5,5,14,0,0);
