INSERT INTO "reviews" VALUES('6923bad005564e312640dd5a',24,1695,'拖堂大王',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('69217cefa54da130be793b1a',1095,1095,'******布置的作业跟课堂上一点关系都没有，能跑的赶紧跑，学长给你们的忠告，讲课梦到哪儿想哪，完全就没有一个体系，自己布置的作业自己都没有看过，上课不知道从哪找的网站上面的文件，和课本上的代码完全不是一个量级，对你的考试一点都没有帮助，如果你想要拿高分，甚至是拿及格就一句话跑就完事了。本来是开卷的考试，自己弄成闭卷，交作业不让压缩',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('692178bddaee5f72f2132fe4',1697,1697,'老师讲得可以，感觉他水平很高，看起来有点社恐，基本不抽人，也不点名，玩手机也不会管，只是期末考试好像不怎么捞。不过和李星比起来，还是棒棒哒',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6921786805564e312636f3b1',1697,1697,'宇宁老师太好了，讲课一定会让你明白原理是什么，非常的温柔。',5,5,5,15,0,0);
