INSERT INTO "reviews" VALUES('69201631a54da130be71b62a',1702,1702,'我也配评价他？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691f2222af4f48204269017b',1537,526,'表达能力讲课水准这些我不评价了，我也没报到她的课程，但是带土木工程制图实训的时候在那讲报告怎么写，没讲两个字就因为自己没开投影仪把自己气个半死然后就撂挑子开摆了不讲了，之前说要在群里发模版也不发了，让我们自己看着写有问题就直接给0分，无言了😅',1,1,1,3,0,0);
