INSERT INTO "reviews" VALUES('691dd455daee5f72f200bdaf',23,23,'特别特别好的老师，不但讲得好，还一直鼓励我们，从我怕这门课到想拿高分，是我目前最喜欢的老师，没有之一',5,5,5,15,0,0);
