INSERT INTO "reviews" VALUES('691d5fb905564e312620fc24',307,307,'讲得差，讲课没有什么重点，感觉他讲课就是沉浸在自己的魔法电路世界里面。快跑快跑，纯一坨。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691d2a4cf05e621fb107787f',724,631,'讲课把自己讲迷糊了，可见其平差功底，建议小登避雷',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('691c82b3171b217b0e6a89b9',1668,573,'很不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691c6c1c171b217b0e6a039b',1600,96,'教学很专业，深入浅出，课堂内容很充实，很有逻辑性，老师从不为难学生，不点到但是大家都主动的认真在听足以说明课堂能留住人。老师也是一个很善良的人！（今天和他坐同一个电梯下楼，中途有一个坐轮椅的学生要上电梯，大家都在给同学腾位置，然后马老师主动说他下电梯！老师真的很好！课上课下都堪称为人师表，我很受触动，所以来五星支持了！希望老师也看活水！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691c3a23a54da130be59f2e4',1454,23,'挺和蔼的，但我是傻子。。听不懂',3,2,5,10,0,0);
INSERT INTO "reviews" VALUES('691be620f05e621fb10032eb',55,55,'幸好选了陈老师的课🙊🙊🙊人太好了吧，大家都别选，就我自己选就好了🐒陈老师跟其他老师不一样，从不说教，负责！又教东西！巴巴适适的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691be574af4f482042556e8a',56,56,'听了学长学姐安利，选的陈老师的课，老师人真的很好，也很有耐心，什么事情说的都很清楚，也会给学生机会（我因为个人身体原因少跑了一次健身跑，老师后面允许我自己补了跑步，然后说会把分数加上）。安利给大家，无脑选就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691be111f05e621fb10009e6',56,56,'陈老师无敌负责，人也很好，上课都会带着跟着我们一起锻炼，上课氛围也很好，不懂差评哪里来的🤐🤐🤐可能我自己不喜欢水课吧，觉得来都来了，还是要锻炼要学一些东西吧，身体是自己的啊，想摆脱“脆皮大学生”。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691be01d171b217b0e661a1e',55,55,'爱死陈老师，老师人好，负责任，基本问问题有问必答，不会像一些老师，理都不理，石沉大海一样。上课真的在教，带学生锻炼身体，不是放养，态度端正，认真练习，不可能低于80的！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('691bd6a2171b217b0e65beab',1381,517,'别来，心情不好惹到她就准备被体罚吧宝贝🤭',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691bcdb0f05e621fb1ff24be',48,48,'石中石，万泉部诗人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691af7b705564e3126133589',1273,157,'太逆天了，超市迟到几分钟不让进，给出各种理由让我走，怎么求她都没有用，我已经解释过很多次了，从来没有这么绝望过被一个老师逼哭了，都这样了她的课还能多好，看到跑路就行了！！无语无语无大语！从来没有这么烦过，不想说脏话就这样……',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691af6deaf4f482042509082',1727,1727,'懒得喷，跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691af3cb171b217b0e617ac6',1728,1728,'旷课一次老师就像你鲨了她全+一样，各种刁难踢皮球，快跑吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691ac05605564e31261186a4',1274,419,'嗓门大，爹味浓，口音重，爱情境表演，每节课叽里咕噜不知道在叫啥',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691abfa993ab0a070f28731f',1274,426,'不知道学校从哪个街边烧烤摊淘来的稀罕货，每节课必以哪有你们这个条件开头，以后能敬孝你们父母吗过渡，不懂社会险恶收束，佐以惟妙惟肖的变声表演仅限老登油腻风范',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('691aa3ace71ecb2c8004e809',1182,1731,'这b课就一个原则，上课时随便玩，作业考试都抄ai就行，别想着自己写，自己写的作业没有别人用ai写的分高，纯纯无脑',1,1,1,3,0,0);
