INSERT INTO "reviews" VALUES('691a806aeb5f221d6f8a3498',1733,1733,'发哥！这学期同学反应作业多也有改留少一些，期中考试也很简单，人也挺好说话的，而且从来不点名😢',4,5,5,14,0,0);
