INSERT INTO "reviews" VALUES('69155e2f1c203d5a41516769',1742,1742,'理论力学给我直接上成了水课 作业留了是从来不判不发不讲的，误人子弟，压根不会讲课，浪费时间，听他课真的没有收获，不负责任，敷衍了事，专业能力一般',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('69154ac9eb5f221d6f762e55',1743,1743,'教的一般般，爱讲废话，讲内容不着边际，还爱挑三拣四嫌弃你们班不如某某班，你一个本硕博都是西南交通大学就别嫌弃别人这的那的吧………',1,1,1,3,0,0);
