INSERT INTO "reviews" VALUES('6914a399e338d34df4556c58',1021,228,'事非常多，事一堆，讲的还算可以，但是会随机抽人回答问题，莫名其妙的问题也是随机抽人回答，挺无语的，会划重点，会徘徊禁止玩手机，上课还不让用电脑和平板',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('6914a1a0e338d34df4556626',136,1747,'非常传统式的教育方法，要是你热爱传统武术传统跆拳道的教学方法（诸如不能搞小动作不能讲悄悄话进道馆敬礼被点到要敬礼讲话要敬礼见到老师要敬礼之类）那选她没错，要是受不了管教的话选她的课等于再上三年军训',5,3,1,9,0,0);
INSERT INTO "reviews" VALUES('691495b9096517792f93a83e',1748,1007,'英语授课666',1,1,1,3,0,0);
