INSERT INTO "reviews" VALUES('691409fa1c203d5a414bed95',6,6,'沙兰子😓',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6914086d096517792f90ab62',6,6,'🍬🍬🍬讲课是灌水的，讲话是低音炮的，是喜欢无痛呻吟的，自从发现可以点学生上去回答翻转课堂以后，再也没有上过课，就开始装腔作势评价',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6914017e096517792f9088f6',6,6,'前几节课全程坐着念经，气质像少林寺里跑出来被榨干的假和尚，并且每节课要强调一番自己课很多很累。中后期直接让学生上台分享与课程考核完全无关的内容，还要卖弄自己的各种人生阅历。喜欢赤石的放心选。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6913f801a2e7070c57e6d23b',1753,1753,'不知道打高分的怎么想的，事情一大堆',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6913f428a2e7070c57e6b936',6,619,'上课讲东星斑和澳洲大龙虾多少钱一斤，在韩国和重要领导人一起吃饭。自从前几节课上完现在一开始上课就开启翻转课堂让学生发言，要求屁事贼多，又是个人体会，又是要结合家乡特色事例，要求不满足还不咋给分，真是纯作孽',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6913c863096517792f8f48cd',1755,1755,'半个学期的课程，第10周才上第一次课，刚来就要求交手机， 完了最后10分钟给你整俩课堂作业，我可以说认真听课也不一定写得出多少(如果有做笔记那当我没说)，这谁受得了😅',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('691360b321dce511395bca57',1756,52,'虽然上课照着PPT念学不到什么东西，但是你张姐捞人是真捞啊，给我一个期末考29分的人都捞及格了那还说啥了，给姐磕两个',5,5,5,15,0,0);
