INSERT INTO "reviews" VALUES('69127c0bd9e1c5394e5b16a6',1762,415,'主要是半导体这门课有点太难了，邱老师人还是很好的，有一次周内有事给我们把课调到周末还在课上给我们发糖吃。平时作业每个章节就布置两三道题，考勤也不算太多。期中考试是写一份论文，期末考试会考一大堆概念题，而且卷面分就算只有三四十也会给捞，平时分也是基本给满的',5,5,5,15,0,0);
