INSERT INTO "reviews" VALUES('69114b5421dce511395252ab',202,82,'好老师！上课枯燥无味，对着PPT念，有时候还自己不知道念到哪里去了，实习课说又不说清楚要求，搞得我们半节课调不出来仪器，然后调不出来仪器，又把我们打回去重做，真的是人才老师，非常非常好！选到的有福了！',2,1,1,4,0,0);
