INSERT INTO "reviews" VALUES('69114493096517792f8446f7',1768,92,'钟晓春的大物选上就偷着乐吧，PPT都是老师自己做的，就算上课没听下课自己看课本和PPT也能看懂。老师上课很负责任，期末考试范围以外的东西也会给你拓展，而且讲得很好很清楚（虽然纪律有点严，上课不让玩手机）。考试基本都是考作业题，期末复习多看看作业题就行，给分也很高，平时分都是拉满的',5,5,5,15,1,0);
