INSERT INTO "reviews" VALUES('690d988ac29a3849f8a3cc90',282,1771,'supertiger神中神，绝世好老师，儒雅随和，验实验的时候很亲和，不会很压力，而且发现ai写代码，只要你能解释清楚，也会放你过去，期末给分更是十分大方，我考试考的分不高，全靠supertiger平时分实验分给高捞起来了',5,5,5,15,0,0);
