INSERT INTO "reviews" VALUES('690d7dcde338d34df436760a',1773,1773,'老师人特别好啊，考试想着我们不会做，允许我们开卷考，还特意在试卷上出了四十分的概念题，只用在书上照着抄就行。老师上课的时候会听取我们的意见，讲慢一点或者再讲一遍，很有耐心。下课遇到时还会主动和我们打招呼。（其实我上的课程是建筑力学，但是不知道为什么没有这个课程选项）',5,5,5,15,0,0);
