INSERT INTO "reviews" VALUES('690c3b1aeb5f221d6f517e96',1633,81,'******课上得稀烂没半点干货，还整天装得人五人六的，态度差到爆！脾气暴躁得跟吃了枪药似的，一点就炸，还极端偏激。咱班同学要做手术请假，医院证明都交了，他死活不批，还阴阳怪气地膈应人，说些难听的风凉话，缺德到家了！一点同理心都没有，纯属没师德的玩意儿，拿着这点破权力刁难学生，恶心人第一名！真见过最垃圾的老师，没有之一，看着就烦，晦气！',1,1,1,3,0,0);
