INSERT INTO "reviews" VALUES('68cb8f84a2e7070c57d7a6bc',1991,1065,'撤吧撤吧，你们就撤吧。把学生喜闻乐见、思想开放、讲的明白马列毛的老师都撤了，撤的“文件汇编”之风大行其道，撤的把学生们都教成死背课本思想防线一触即溃的接班人，这笔账迟早要还。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('68cb6dda03c88b65d74669eb',2017,762,'真没见过专业水平这么低的老师，讲课拖拉，喜欢东扯西扯，扯也扯不好，一直整烂活，简单的能给你讲半天，真懒得听这课，还天天卖她那网课，也是够了这个老师。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('68ca5612eb5f221d6f637240',2018,2018,'绝对好老师，课程原因听起来会很无聊，不过老师绝对负责，课上也不会管你，期中课堂考试老师直接在前面玩手机不管你，快考完的时候还开玩笑问我们“都抄完了吧”。期末前把资料都给整理出来，甚至还把期末一道20分大题偷偷塞到资料里，工程材料请认准付正鸿',5,4,5,14,1,0);
