INSERT INTO "reviews" VALUES('68c4cdc621dce5113944dadc',124,124,'别选别选，我学的她的创新创业，超级烦，周末大早上来上课，还要两个班打乱随机分组讨论尴尬的要死，我服了，i人别选，和陌生人半句话憋不出来，还要汇报，我的周末都被她毁了，事巨多，超级烦！',1,1,1,3,0,0);
