INSERT INTO "reviews" VALUES('68c3804b03c88b65d72e4887',582,442,'平时分巨低，明明是线下教学，非得搞线上作业，那个学生系统还贼难用',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68c37ff6e338d34df42dad57',785,114,'最开始上阳老师的课的时候可能不太习惯，非常明显的一点就是他确实说话不太能听得清楚，对于想上课认真听讲的同学会有点难受，但是多听一段时间会习惯很多。但是优点也非常明显，阳老师本身是非常负责的，平时分会拉的非常高，几乎满分，然后很少点名。总体非常推荐！',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('68c37db721dce5113940ea49',2058,230,'非常温柔的老师，平时分给的也高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68c3703dd9e1c5394e408d3f',571,81,'老师人很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68c3687aa2e7070c57bdedfd',1291,92,'真的听不清在说啥，课后事也比较多，别的老师都是一节一张卷子，他是一节一张纸质卷子一张学习通卷子，而且还经常迟发搞得来不及。。但是最后捞捞我了，给分也不是很低，对于只是想及格的人来说还不错',4,2,4,10,0,0);
INSERT INTO "reviews" VALUES('68c30438e338d34df42cbdb6',1157,52,'要定位签到收作业，不过做了就会给满对应平时成绩，作业会批但是写错几题不扣平时分。讲得挺仔细认真的，尤其是考前复习千万要听，毕竟半期和期末老师捞不了。超声探伤实验课也是他上的，我做的时候教材上没有这个实验，但是老师解释得非常仔细，录音录像之后只要智力水平达到高中一边听回放一边做一定能轻松做出来。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68c2526c21dce511393d57f1',442,442,'作业漏过一次，实验全做，没缺过课，平时分给70，创造了我本科所有学科最低分，上课还诋毁人，乱点人还嘲讽，你是这个👎',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68c242ac49adb47c4185655f',2063,301,'平时分给的超级多，课后可以跟老师多交流也会积极回应，课程难度大不代表老师讲的不好对课程有兴趣的可以冲。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68c241bb49adb47c418561b3',157,157,'如果以前学过排球，选这位老师我觉得是没什么问题的 ´ᯅ`我之前没有接触过，老师隔几节刚上课会讲一点，之后就自己练习，感觉不是很友好，我也没有和他学的动力。偶尔他会带出差，来代课的老师感觉很好，我和搭子垫球的动作都是他纠正的，后来是组队的同学教我的。给分还可以吧，第一个学期垫球我也没到线也勉强过了，之后逐渐学了一点最后分数也能到八十。',3,1,1,5,0,0);
