INSERT INTO "reviews" VALUES('68c0eaf1d9e1c5394e3709ff',476,779,'徐老师是目前我接触到的所有老师里面最亲和的，只要你愿意学，他都会耐心给你解答，QQ消息是都会回的，实验课我也真的有收获，我喜欢向老师提问，又想混又想得高分的不宜来，但上徐老师的课绝对会有收获，不论是在应试还是实操，只要多问，收获满满，而且徐老师不考勤，小测不在也会给分，还要怎么样',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('68c0e6129d67ec36894ed653',1273,157,'我想换课😭😭😭😭谁来救救我，老师教的还行，如果你也喜欢排球并且抗压能力不错就来选吧😭我受不了了🤦上课喜欢说一大堆废话，并且很针对基础不好的同学，有自己的一套无用且严格的规则，很喜欢排球的我真的要被逼的讨厌排球了',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('68c0e4e19d67ec36894ed122',2078,23,'快跑。平时分由很多很多板块组成，每个板块都有很大几率扣分，如果喜欢挑战的可以试试。期末期中没有题库，得找其他班的要😌',2,2,1,5,0,0);
