INSERT INTO "reviews" VALUES('687c52be6c99203343ff94f3',1157,52,'非常好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('687b32e3005b61419ddc1eec',2157,2157,'我以前不懂为啥有人激情开喷老师 原来是我前三年运气好 遇到的老师很正常 本来准备考研人有点微死了 遇到这么个老师直接诈尸了 每天起来就想上网喷人 也算她功德一件 好老师总是能激发学生的自驱力 还有遇到神经小组成员更是心潮澎湃 啥也不做 老师骂完他顺着就骂你 顺嘴的事情 哈哈 还没说完 想到再发',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687b2fe7005b61419ddc12a4',2157,2158,'学院课程设置的极不合理 同一课程四个老师 老师之间评分标准实际上也不统一 教评更是如同虚设 后台都有学号 而且评了才能看成绩 大三课设 别的组甚至不去答辩的分基本就跟去了一样高 不同老师要求区别极大 老师也不在乎学生死活 高兴给几分给几分 辛苦做的其实不如问上届要的 上届要的不如抽个好老师 抽到这个老师就乐吧 咋做都会完蛋的 事情也是最多的 开组会 小组别的同学迟到直接连坐 我请问呢 我又不是他们亲妈 他们起不来我能怎么办 给分普遍偏低 一点小事揪着说 字大了字小了 你们老师之间能不能商量清楚了再说 我难道是凭空写出来报告 本来学到这个专业就完了 分的这个老师更是想死的心都有了 ',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687b2a0b6993d81fe6c316c2',2157,2159,'找不到课设的课程选项 太气人了 说话做事非常情绪化 工艺上的问题提不出来 心情好怎么都行 心情不好就大吼大叫 非常恐怖 认真做给分也就普通 主要还是要抗住骂 注意千万不要顶嘴 不用花太多心思 课设抽到她可以避雷了（估计也换不了哈哈）一款很经典的生院老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687b1e036993d81fe6c2e467',18,18,'牛逼，总评95你是我亲爹😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('687a4c30fbbb215be84027f7',2069,2161,'什么课设答疑把人难受死',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687a13289eeffb332a0e141e',2069,1743,'事还多，一个大作业，一个课程设计，巨麻烦，要求还多，复习也没重点，压不到题',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6879ebb19eeffb332a0d331f',478,478,'亲和力很好，平时分给的也高，不点名，不抽问(很多都是自问自答)就是讲课有些时候自己也卡顿',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('6879eae1d3496c42464fdeae',861,861,'特别幽默，特别好，就是说话有点漏风，有时候听不清，上课听讲的话会考很好的分数，不听的话靠自学有点子难。因为课上会讲一些区别于课本的更加简单的方法',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('68787b7c005b61419dd17279',1732,1732,'******要求还贼多',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('68787793005b61419dd16304',264,230,'伟大无需多言！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('687869639eeffb332a0757ea',2167,2167,'关于测量没有什么要求，就给你一个ppt，去问就笑眯眯的让你觉得很水，最后验收就告诉你很多问题，有点小题大做挑刺的感觉。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68785e5efbbb215be837c49b',2168,2168,'不是，毛老师，我真的好好复习了，你给的分素在？项目管理和采购两门课的给分都好离谱，虽然有部分原因是考试题目比较灵活，复习抓不到考点，但是不管怎么说，给分的确不太友好',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('68785b54d3496c4246496076',2169,2169,'选的物流设备，当时这门课还是开卷。与其说马啸来笑面虎，不如说她笑面虎，讲课是温柔的，沟通是和善的，作业是基本没有的，给分是吓人的。',4,5,1,10,0,0);
INSERT INTO "reviews" VALUES('68785a6e6c99203343efe179',2170,790,'上的系统工程课，可以说是物流最好的老师之一了，上课不会管手机，讲话也温柔，期末好好复习也能考高分',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('687859ccd3496c424649587f',563,228,'去年上的他的课，我宣布浦仕勋脱离“四大天王”称号，平时分很高，上课带我们出去晒太阳，期末重点很准，没什么可以挑的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6878584ae5ac4d514eebaf49',2172,2172,'我不知道为什么交运最低分的老师是崔异，在我心中毫无疑问是冯春，上课得很认真才能听懂他想讲什么，期末我们班就一个上80的，其他全是60和60以下，表达能力极差，喜欢说肉夹馍，喜欢扯哲学，喜欢抽名字长的少数民族，我们那一届期末没给重点也没给往年考题，挂了三分之一的人，助教也sb，问他“期末挂太多怎么办”，他说“不用管，你把卷子改出来就行了”，然后助教居然真的照做了，挂了人补考只过了4个，第二年又不开重修班，不批扩容，辅导员教务拿他没办法，电话打不通邮箱不看，唯一的优点据说他科研能力还不错，但是你讲不懂课弥补了这一点……期末复习可以看北交那个慕课，比他讲的好太多了。给分低没办法，物工逃不出他手掌心。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6878553abf6625518c66028c',2173,2173,'运筹学一和二都是选的她，我还算比较喜欢这个老师，比物工后面会遇到的一群牛马蛇神强多了，有时候上课会讲错东西，自己发现不了只有认真听的同学能纠正，但是认真听讲还是很容易听懂的。大四还有她选修，但我选上了牟能冶和郭波，还是把她退了吧',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('6874f178bf6625518c5659c2',344,793,'神中神，虽然现在只教茅班和智慧了。上课跟上巨轻松，考试难的题他自己会删，平时分不够他自己会给🥰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6874f056b9570274dfe6c1e1',209,209,'没有人类能忍受和谢美俊的长期交流。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6874f01ab9570274dfe6c05d',211,240,'qq答疑巨及时，五次考勤，说的也很好，平时分给的也巨高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6874ef86d3496c424639accd',177,177,'伟哥平时分不拖累总评，如果不够会提到和期末分差不多的不拉分。上课说的也很清楚作业也不多，认真听期末不用过多复习，该捞的也捞了，爱你伟哥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68746862b9570274dfe23188',2178,2178,'选了老师的土木工程地质，学期唯一一次点名是教务逼老师查课堂出勤被迫点的，作业少事少平时分给的很高，期末海底捞，听学长说去年他的班上只挂了一个没去期末考试的人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6873e6ceb9570274dfe027b0',2012,296,'大哥牛逼666',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6873e610d3496c4246331c12',2180,2180,'没去上课 给分不低',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6873e5b76993d81fe6a1d7a9',175,774,'看了别的同学的评价，我觉得还是来说一下这个学期我看到的杨老师。机器学习这块，平时上课基本没去，中间去一次还是让他把我拉到知到群里，最后平时分也是挺高的，没有那么多要求（作业都做了）。期末最后一次课我还是去了的，给画重点，该说的都说了，很多人没来老师也没说什么，课堂上和我不少眼神接触，可能确实希望和同学们有一些互动哈。不要看到历史低分就不选这个老师，老师也是有改变的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6873a53abf6625518c4e3027',211,240,'平时分乱打，每次坐第一排期末算平时分还是被判缺勤一下扣十几分，讲课还可以，不好沟通，建议选隔壁邱老师班',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('68736584fbbb215be81dddf4',2183,2183,'选的卫星导航定位原理，平时分由实验，作业，课堂表现三部分构成。上课会提问问题，回答不上来课堂表现会扣10分，作业全交了还是给了80，实验难度巨大。哪怕是做对了也才给了80多，期末给的重点跟考试基本关联不大，且重点巨多。PPT全英文，复习起来大。不理解之前的评分为何这么高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687327af6993d81fe69c7c0e',83,83,'特别特别好的老师！！上课很认真很好理解，ppt知识都很清晰也会提前放到智慧树上面，上课笔记没跟上可以在智慧树上看到ppt。课后作业是勾题做的，我觉得量不大，其他班基本上都是全部要完成的，作业就会很多很多。打分的时候也非常好，只要不是特别敷衍这门课，基本上莎莎老师一定会捞你，平时分都是满的😭😭😭特别好。课后有问题也可以问，老师会很耐心回答你。点名也不多，很偶尔吧会点名，但我感觉就算真的一两次点名时候不在最后莎莎老师也不会扣你的平时分。真的是我目前遇到的最好的老师😭😭😭太喜欢莎姐了😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68732542b9570274dfdabb6b',2136,313,'一学期四节课有两三节都找的代课 最后考试的时候不给看手机 认认真真写了很多期末打了60  平时分也很低 狠狠壁垒😅😅😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68730d68d3496c42462cc2d0',334,334,'差',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68730d1abf6625518c498abc',334,242,'💩',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687255e5b9570274dfd63ffa',2136,313,'平时分给的非常低，所以几个室友他们的平时分都很低，导致期末刚刚好擦线过，就令人非常的无语',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687234f0d3496c4246284b21',476,476,'老师人挺好。给分还可以，比上不足，比下有余，除非你上课听课或者他的问题能答上，能有很高很高的分。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6872348bbf6625518c452cba',2190,2190,'孩子们，快跑！这个理论课的实操作业比实验课的实操作业都多，又臭又长；期末考试与期中考试重合度高达90%，但是他考完期中后不发期中卷子，所以建议你在他期中开卷考试的时候，用手机把期中考试卷子题目都拍下来。然后你去考期末就背期中卷子，期末就能稳过且拿高分；你要是背他期末给你发的重点就会发现几乎不考他划的重点，不如复习期中卷子。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687232c4fbbb215be816c615',1606,1606,'快跑！
INSERT INTO "reviews" VALUES('6872151ac02b652dbc3a179d',209,209,'不多说',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6871fbcf6993d81fe694f5f7',1307,1307,'上课和实习过程都很公平，一碗水端平的那种。平时课堂和接触中觉得老师是很好相处的那种，但是定下来的规则又是严格执行的。这种有原则的老师真不多了···',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6871d9d5bf6625518c424e8a',1606,1606,'划假重点，我受伤了😭',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('6871d996bf6625518c424cec',2190,2190,'给分比较高，期末考试与期中课内课后作业重合度高，老师性格和善，也很专业，但是作业很多😵‍💫',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6871d984fbbb215be813ea04',1503,1450,'恶心，平时分算错了跟她讲直接不理自己就把分登了，那她给我们看平时分的意义是什么，真恶心啊这就是老师吗，事情又多真是',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6871d797bf6625518c423fa8',2197,876,'你亮哥绝对没得说 讲得好事还少 给分除了半期全部给满（当然作业和雨课堂要做） ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6871c132c02b652dbc378702',99,361,'交通美学来的，事情非常多，说话含糊不清，给分也不高，能跑就跑吧，别以为抢到了是好事，宁缺毋滥',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6871c077b9570274dfd19f38',373,230,'妈妈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6871be92c02b652dbc377124',2200,2200,'妈妈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6871be2cb9570274dfd18c9a',209,209,'给人的感觉就是蠢，不是坏',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6871bdf1bf6625518c415f95',2202,27,'必须满分，首先老师的授课能力很强，善于引导，亲和力强。其次，有英语汇报但可以接受，做了就有高分，不强制，想卷想躺都可以，上课多回答问题就能拉满平时分。最后，在结课的时候，如果你已有她的好友，她会给你发告别信，鼓励你在语言学习上更上一层楼，她真的，我哭死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6871b2256993d81fe692c265',1675,1675,'千万别选她的材料制备，总共才十个人，每节课都要点名，只要有一节课没去，平时分就给的很低只有七十几分。出完分真的有种被背刺的感觉，平常事还很多。',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('6871af2ed3496c42462412cd',2116,185,'带的电子电路绘图实训。表达能力尚可。首先是考勤，异常严格，没有任何回旋的余地，会用高高在上的眼神审视你，作业也非常严格。其次会管你课上玩手机，会下来走动，抓到玩手机玩游戏直接算缺勤。最后班上同学迟到班委要一起扣分连坐，能跑就跑',2,3,1,6,0,0);
INSERT INTO "reviews" VALUES('6871629fbf6625518c40308a',2205,2205,'纯逆天老师，行车组织课程设计给分极其恶心，别的老师看差不多的课设直接90+，93,98的在朋友圈刷到好几个，李力批课设能扣皆扣生怕给你给分给多了，平均分差距没有20也有十分，作为一个保研课何其逆天？大三下都在考研了为什么还要折磨学生？实习克扣经费，生均550怎么花的完全不透明，重庆实习和绵阳实习住宿就快让你住到村里去了，人均23块钱一晚上的酒店上课还有脸说经费不够，实习完就地解散回学校的钱都不报？你告诉我经费去哪里了？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687156b5b9570274dfd03ef3',756,22,'满分没的说',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68715644d3496c4246233098',953,953,'上课没回答过问题平时分94，感觉给分很高了，挺好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('687155e6bf6625518c401b69',533,101,'神中神讲课十分细致，在个人上大学两年以来遇到的老师里第一梯队的第一梯队',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68715529d3496c4246232eaf',932,762,'上课川普但也无所谓听多了自然就习惯了，平时分满分没的说，很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('687154d4bf6625518c4019ca',2210,114,'没话说，抛开口音不谈这是真好老师，神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68715495bf6625518c401977',2211,1241,'给分低，平时作业是机改经常还改错，期末考试考的跟复习的完全不搭边',2,4,4,10,0,0);
INSERT INTO "reviews" VALUES('687153d06993d81fe691cc08',1672,1672,'神中神，我遇到过老师中算是第一梯队',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68711d1bd3496c42462239d0',2213,2213,'总的来说，我对雷老师的评价雀氏有一点个人主观的因素，可能因为期末确实给自己的分比较满意，但这也证明了一个事实，只要认真看要求背的部分，老师肯定不会亏待你的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68710a6ab9570274dfce91fb',1243,1247,'不用说了简直是一坨 上课事逼 打分还低 个水课竟然是最低的一门',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6870e669c02b652dbc33753c',198,2155,'这个电子技术实习就已经很狗屎了，让画电路板，昨天刚画好，今天要求就变了。本来精心画好的电路板，都已经拿去打板了，结果说你这不行那不行，非要改成她想要的样子。原理图怎么画也不讲清楚，一看到那里不对，就让你回去改。她就是一句话的事，我回去改原理图，接线图怎么都要改10分钟。纯纯浪费学生热情，让我觉得我的努力毫无意义。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6870e20db9570274dfcd5eea',198,2155,'感觉没什么水平，只要板子画的不合她心意就必须给你挑错，指导出0点相关内容，另外对来询问的同学未免太过双标，不想指导就别来教。
INSERT INTO "reviews" VALUES('6870df89b9570274dfcd45b2',2136,313,'随机生成分数，草菅人命',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6870d863d3496c42461ff371',2136,313,'对学生从来不管，不负责，课后作业从不提醒，课经常缺，让其他老师代，期末考试才知道有这么个老师，平时分一律80以下（无理由），绩点给你卡的死死的，期末考试不让查手机，美其名曰诚信考试，其实就它不让查，成绩是最后登的，结课一个多月才登******上它的课不给差评是这个👍',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6870d81ec02b652dbc32e81c',1738,230,'******历史给我捞过了，我没意见.jpg',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6870d7c7b9570274dfccf9f5',2197,876,'老师人很好很和蔼，也不怎么管你上课干什么，有的时候会下来转一圈。作业给分挺高的，平时考勤不点名，分会按雨课堂的答题次数来算。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6870d6e8bf6625518c3cc796',209,209,'我上这实习课发烧贫血请一早上假去医院看病，把带学院公章和辅导员签名的假条和医院病例和医院给的假条拿给他的时候，他说没他签名不认，也不给我签名直接给我记个缺勤。
INSERT INTO "reviews" VALUES('6870d694bf6625518c3cc500',2222,2222,'讲课没有逻辑，念ppt大师且ppt做得一坨且不发ppt得主动要，天天绷着脸，给分倒是一点不放水，不捞人，期中考试考两遍也是个人才',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6870ca22b9570274dfcc76e3',416,63,'老师人很好，上的c语言和c++，认认真真跟的话平时分给的奇高无比。讲课也很风趣',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6870b86ac02b652dbc31c820',2183,2183,'上的卫星导航定位原理，平时分满分，考试也比自己想象中高很多，很满意😀就是老师平时上课ppt是几乎全英文的，复习有点痛苦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68708557b9570274dfca61b5',1095,1095,'诗人握持',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('687085516993d81fe68bfe6c',1095,1095,'史',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68707c72fbbb215be80b98cf',2227,1732,'王老师真的是圣人！上的计组跟离散。不点名，给重点，脾气也很好，问问题都很热情的回复',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6870048ffbbb215be809b799',1131,1131,'上课有重点，有互动，甚至会奖励同学小奖品。鼓励同学问问题，非常有耐心。会根据作业情况和同学反馈带我们着重复习知识点，是很认真负责的老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68700352d3496c42461b093e',2229,2229,'内容跨度大（从3d打印到激光切割到使用stm32开发板到焊接到pcb设计与制作），授课靠放B站视频和念PPT，任务很多，指导几乎没有，项目耗材自费。临近期末周还布置两个平时项目加一个期末项目。课程综评平时分占百分之百，老师给得很吝啬。作为计院大一必修课几乎是最折腾人的。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('687001c1b9570274dfc82a31',2230,2230,'上的是易老师的英语一二。老师对每个人很关注，会针对性地进行点拨。课上给人感觉可能有点严厉，但是其实老师非常好沟通而且很有耐心，甚至半夜回学生私信解答问题。非常荣幸能在大学最开始的一年接受易老师的教导。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686fc6c8d3496c424619e72e',2231,256,'无须多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686fc47bb9570274dfc6f2c2',74,74,'很好的老师，使我的成绩旋转',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686faa3f6993d81fe687d9bb',202,82,'上到他的工程测量实习你就有福了，七天实习能见到他两天、别的老师要求150个碎部点，社会你缸哥直接要求500个碎部点，美其名曰“最基本的工作量”。实习的要求是从来不讲完的，和助教两个人两套标准，疯狂左右脑互搏，让同学们的实习过程非常迷糊，非常痛苦。实习材料要求下午五点提交，你缸哥实习期间的第二次露面就是为了在下午四点的时候，将大家辛辛苦苦绘制的图判为不合格，留给大家1小时的宝贵改图时间。从来没讲过的地形图要求又突然强加到我们身上，这种不负责任、以折磨学生的老师活到现在算你运气好，教也教不明白，纯在折磨同学******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686fa85ed3496c4246190821',42,43,'构思一坨',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f9ec6c02b652dbc2ba831',74,74,'全人类最极致的cs，所有贬义词的集合，优选班能跑一个是一个，实在是令人作呕',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f9113b9570274dfc56ae6',75,2236,'和龚辉一样都是神，平时分除了期中全是自己挣得，期中最后登分的时候也很高，考四五十的能给你登到七八十，考八十多的能给你登到九十多，在群里问问题也很有耐心，神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686f903abf6625518c35327f',74,74,'天才老师，excel专家，也就会个表格了，水平是不高的，要求还多，实习废话一大堆耽误我们进度，实习要求是说不清楚的，截止的时候才说要交什么，天天讲一号线装逼，实则跟他没有一点关系。上课就爱念ppt，然后掏出他的陈年表格，选他的就是👉🏻🤡',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f8c77bf6625518c351451',408,2119,'感觉讲课不是很会抓重点，但不缺勤平时分高得一批（本人满分），而且现在没小测搞人心态了，思维导图AI一下就满了，期末给分出奇的高，总的来说已经很不错了！！！',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('686f8c45d3496c424618300f',74,74,'许愿别在假期实习被安排上他吧，不然宁愿挂了算了。操作异常繁复，要求前后不一，头回见以为难学生为乐的老师，问什么东西都是自己拿规范研究去，搞得我们像是做了八年工地的老师傅。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686f732eb9570274dfc455fa',202,82,'实习老师是他，纯恶心人来的，最后两小时才发实习报告',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f6cd4bf6625518c33eb7f',2241,2241,'这老师怎么说呢。每姆、扫码、侏儒、建议她找个黑人谈恋爱，好好被调教一下。乱给分，平时分40几乎没有33的，20多分一大堆。我缺1次课，得分和缺6、7次的一样。作业我每次都交，次次都是自己写的最后作业分56分，我问她怎么回事，她给我来个作业分按计算题的得分来算，反正怎么说她都有理。怎么你只按计算题来算分那你布置一大堆简答题干什么，老子写半天一分都不给。自己细品吧，这人应该是交大最cs最恶心的老师，啊不对，她是一条母狗',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f69bc6993d81fe6858bdb',2242,181,'当堂听懂，期末考课堂测验',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686f6980fbbb215be80587bf',888,779,'大二一年的工程测量都选高老师，两学期平时分都直接给了100。
INSERT INTO "reviews" VALUES('686f38f8bf6625518c327f51',351,1496,'给分高 性格好，期末会给提示，神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686f2da5d3496c4246153efd',178,178,'神好吧，无需多言，别看凶巴巴，其实老好了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686f2d15c02b652dbc2820e9',1503,1450,'这个老师千万别选，ldx因为前面没评价栽坑了，事情多的要死，一个选修课给分给的低的要死，除了考勤之外所有任务作业全部给你七八十分，老师上课还管你玩手机，ldx组长加上发言加了几分最后才八十多 班里大部分都是七八十，总之赶紧跑吧，选这个老师真是倒大霉了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f2b03bf6625518c32150b',178,178,'感觉是很严格的老师，但实际上最后还是会发力的，刀子嘴豆腐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686f25a96993d81fe683a876',74,74,'cs老师一个就知道折磨学生，疯狂折磨。上课手机是不能看的，任务是其他老师的几十倍。屎吃少了的可以去上一下他的课。教条极其迂腐，问他问题他能骂你10句。任务严重超标，要求极其变态，快跑，快跑！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686f2075fbbb215be8037427',1857,1857,'老师特别好 期末考试狠狠捞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686f12acfbbb215be802fb26',2250,2250,'选到他有福了',4,2,2,8,0,0);
INSERT INTO "reviews" VALUES('686f02bdbf6625518c30cfbe',2251,2251,'交运专业的 上了老师的线路基础与选项设计 其实老师人挺好的 上课很认真 课设也讲的很仔细 基本每天都有线下答疑 线上也随时秒回 可能因为学时的原因 对我们课设要求不算严格 更多是体验过程 期末还有提纲ppt 重点的计算题会反复讲 平时分也给的很高 总的来说交运的同学推荐选齐老师 不然做课设会很崩溃',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686efe74b9570274dfc0efd8',54,54,'有福了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686ea44ec02b652dbc25f788',2253,2253,'期末捞人，但是平时点名挺多的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686ea3cfb9570274dfbfe839',2254,2254,'期末不画重点，开卷考试的限修课就给40多分',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('686ea346d3496c424611d53c',2255,2254,'上课不能吃东西不能讲不能笑，讲课挺水的，但是给分不咋高',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('686ea2bdc02b652dbc25f37b',2256,364,'上课讲的特别好，还会捞人，老师也很和蔼',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686ea276fbbb215be801c255',1728,1728,'期末17周点名，上课不知所云，但是期末捞人，划重点不知道画的啥，讲话乱七八糟，还赶学生走',3,1,2,6,0,0);
INSERT INTO "reviews" VALUES('686e904bd3496c4246118779',2258,837,'666胡路，喜欢乱给分。你的意思是我认真学了一学期，被评了一学期的优秀作业，平时分还低于班级平均分？
INSERT INTO "reviews" VALUES('686e870cc02b652dbc257509',2259,2259,'老师人很好，平时作业和大作业认真完成，上课签到做题啥的都去，认真做，平时分给的挺高的。只要都尽力写了，卷子写满了，老师期末会捞你的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e77bb6993d81fe680e895',193,193,'抽象人干抽象事，跟我期末最后两周300页PPT说去吧😋😋😋',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686e7661fbbb215be800e3fa',74,74,'老师，你很好了，你上测量实习课一直在强调不要拍照，不要玩手机，真是印象深刻啊。实习的时候仪器给我调大了三倍误差就算了，实习的时候能不能把话说清楚啊，能不能简洁一点啊，站着听一小时真的很累啊。还有，你知道我测了那些点吗？你就说我无效点太多，谁能半天把碎部点测完，我请问呢？你真把我们当地质和测绘的在搞嘛？你又说我们测量精度不行，又要求我们精度要高，人其他带测量实习的老师都说了，非专业的搞清楚过程，绘制一个大概就行了，为啥偏偏你要求高啊？是，你自己对自己要求高也不能要求我们这么搞啊，七天实习，不待满几乎弄不完，真的是我们的问题吗？同样测量实习，工作量简直不要太爽，分到您是我们的荣幸啊！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686e76336993d81fe680dce9',74,74,'真的很想把所有脏话全部招呼到他身上，实习过程中三个班没有一个人不骂他。实习任务量是别班的数倍，任务繁琐且复杂，很多要求都没有任何意义感觉就是来专门ex学生。讲话絮絮叨叨半天讲不清楚，问他问题也是经常不过脑子回答，一会是这个要求一会又是那个要求，说话左右脑互搏。给学生校准仪器越校准误差越大结果还要反过来说教学生。这个人非常的古板僵化，不幸选到他带的实习就等着爽吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686e75eac02b652dbc25093f',74,74,'没吃过💩的可以试试，上大学后没遇到过这个类型的，天天左右脑互搏，要求居多，天天闲的要命，实习的时候到处晃，到处“教化育人”，真不把学生当学生，得了，没话说，挂光名不虚传，他带的那个实习成功让我感受到活着总会有人给你制造困难，遇到他开局智商减一半',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686e74c66993d81fe680cdb6',74,74,'这个老师太好了，课讲的细致，绝对不会粗略带过；就算我们不会他也会很细致地和你讲解，绝对不会含糊其辞前后不一致；课后想要研究他的PTT上也会非常详细的把难点写在上面让我们很好的课后理解，绝对不会出现不清晰的情况；给我们的测量要求也不会太高，绝对不会让我们测量任务是其他老师的几倍；在测量时遇到他他会非常耐心的和我们解答问题与纠正错误，绝对不会有任何的不耐和看不起，绝对不会在批评你一顿后不解决任何问题。
INSERT INTO "reviews" VALUES('686e6e04d3496c424610ad69',2151,1087,'讲课一般，期末不捞，天天签到，缺一两次勤少交一两次作业平时分就六七十了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686e48e6bf6625518c2dc879',77,24,'曾老师人超好啊，哥们就交过一次作业，实验数据都忘记上传了，平时只要不经常缺勤，平时分直接给满啊。虽说讲课确实有点影响，但分是拉满的，就怕你不过',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('686e4245b9570274dfbd8764',2267,177,'平时分拉满了，范文礼我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e41f4c02b652dbc2392d5',1074,2119,'满分，刘黎我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e3486b9570274dfbd04a7',209,209,'参与了谢老师的电子实习，本来看活水的评价大家对他的印象都很差，所以以为老师很凶很严厉，结果没想到他特别耐心负责。电路板有问题他不仅帮忙排查错误，还修改好，从晚上七点到九点多，一直默默地在帮我们修改，没有任何批评和指责，真的很感动，路转粉了家人们 有时候真的人不可貌相 面冷心善的一个老师 ',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('686e2ef1d3496c42460ecab0',2167,2270,'平时作业交了给分拉满',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('686e2ecfd3496c42460ec98c',67,2121,'不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e2e6cb9570274dfbcd125',582,442,'挺好的，中规中矩',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e2e30b9570274dfbccf40',121,611,'对的学生非常友好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e2d026993d81fe67ea5c0',2274,2274,'人很好，平时分太低，作业全交',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('686e2bd6b9570274dfbcb97c',976,2275,'好老师，不重要的概念不讲，而且三连堂不会说太多，会给我们留十几分钟到一节课的时间，还每次都提前下课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e2b61c02b652dbc22ca7a',903,2276,'好老师，认真负责，除了半期出题难没什么缺点，模电实验没上到的话会给你提前讲，和他说哪里不会也会教你，特别温柔！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e2adad3496c42460ea780',535,535,'老师挺好的，讲课确实挺好，偶尔听不懂是我走神，算是会捞吧',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('686e26856993d81fe67e68a1',2278,2278,'史。懒成苟。惹不起!',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('686e2492c02b652dbc228c7e',2015,2015,'教的一般，但是给分很高，助教改的大图分数很低，但是登成绩的时候不是按助教的登而是清一色给90，全靠上学期的底子考的80，上学期的老师教的好但是给分低，不过现在想想幸亏上学期教的好不然这学期分数要很低',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e245ffbbb215be8fe63ac',2280,2280,'期末过于离谱，当个老师重点也给不来。就是专门坑人的，简简单单多给点平时分，但是期末分严重缩水，呵呵了。',4,2,3,9,0,0);
INSERT INTO "reviews" VALUES('686e1df96993d81fe67e16bc',2281,2281,'重修过了来******
INSERT INTO "reviews" VALUES('686e16f0bf6625518c2c02e0',214,36,'简直就是**老师，只会想着怎么整学生，点名每次在，每次上课都去，课后作业也有在好好做，但总能无理由扣你的分，你选就选吧，一选一个总评70多分，区区水课，简直逆天，除非你能和他打好交道，不然赶紧跑，谁选谁倒了八辈子大霉!!!',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686e13c5b9570274dfbbe756',351,1496,'平时分巨低，。。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686e09fbc02b652dbc21238e',2284,2284,'亮亮我爱你 事少给分高，平时也不怎么点名，早八人很少也没点名，就最后几周点了几次。上课也不会管你干什么，想水的也可以选。作业都交了考勤都到了平时分拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e064cfbbb215be8fd5f05',2285,2285,'这个老师很年轻诶，和晏老师一起挂名但是只有他一个人上课，上课巨水，布置作业看见你现场用手机也是开玩笑的说说不太准，而且事情少，平时分巨高，卷面给分也很可以，也挺有意思的，好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e05f7c02b652dbc210937',2286,99,'地下铁道这门课不同老师事情不一样，周老师事情算比较多的，但是只要你完成了给分就很高，分数和完成率很大关联和质量不大，所以基本上拿到的平时分很高很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686e0594d3496c42460d67c4',2287,2287,'老师很和蔼，也很水，上课基本上不管，偶尔会有课堂作业充当考勤，平时分给的巨高，随随便便95/100的平时分，无脑冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686dfeafc02b652dbc20d884',888,779,'无敌 平时分100 总评99',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686dfbbad3496c42460d278b',545,33,'个人主义感极强的老师，思想迂腐却又“摩登”，大肆推扬那些自以为是的，偏激又有些执拗的论点。喜欢的是真喜欢，不听的是真不听。课上与其说是讲英语知识，不如说在满足他自己口头指点江山之快感，时事政治，古今世事统统涉猎。老师英语发音极其难绷，根本听不懂他文思泉涌时吐出来的那一连串的英文小句子。平时作业多如牛毛，根本做不完。课堂pre展示环节会直接根据他的想法打断你的讲演，直接指出你PPT以及语言错误。论优点，便是课堂的自由性，如果你坐在机房内侧，只要不是上课突然跳舞就不会管你。甚至分不清这到底是不是个好老师。
INSERT INTO "reviews" VALUES('686dfb36bf6625518c2b3478',411,36,'虽然上课听不懂他在说什么，但是全勤+次次回答问题+每次课堂作业超过200字+认真完成小组大作业≈平时成绩100。适合卷王来',5,1,5,11,1,0);
INSERT INTO "reviews" VALUES('686dee9a6993d81fe67cb22e',2250,2250,'上课就是疯狂念ppt，声音像蚊子一样，还经常言行不一',1,2,2,5,0,0);
INSERT INTO "reviews" VALUES('686ddb4bfbbb215be8fc3697',612,2292,'上课直接自学就行了，给分挺高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('686dd21fbf6625518c2a0ac5',25,26,'课讲的很好，但是严，人还不错',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('686dd1d1c02b652dbc1f7e6b',1291,92,'说话听不清，会取消考试资格！讲课水平实在难以恭维，但是会捞人，平时分给的很高，听他话再自学期末能过的',2,1,4,7,0,0);
INSERT INTO "reviews" VALUES('686dd150c02b652dbc1f746e',310,157,'b男一个，很爱装b，教学能力也一般，全靠自带基础或者天赋，最后给分也很低，体育差点挂科，换完老师期末分比他给的高20分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686dd0c36993d81fe67bb53d',1394,230,'上课略严，不能坐后两排，不能太猖狂玩手机，喜欢说教，但是人很好！平时分给的很高！对待学生很真诚！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686d6ee5bf6625518c2859bb',67,67,'身为副教授，个人认为他是交大现在为数不多的，还能保持对学生有极好的亲和力，极高质量的教学水平与极高的耐心的存在，并且给分相当的仁慈宽松。我只能说一句工程电磁场真神，上他的课只要课上好好听，不会的课后问他问题，期末考的满意完全没问题。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('686d07f6bf6625518c260872',2298,2298,'上课一句正经的话都不讲，一直在扯闲篇，给的重点和ppt和讲的东西完全没有一点关系，期末考试给分特别低，我都不知道为什么全是主观题还能给这么低的分的😅唯一一点好处是平时分高，不过都是期末成绩换的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686d0192fbbb215be8f7ac60',2299,760,'平时分给得超级高，属于是过了斩杀线就给捞的那种。上课基本不点名，有也是纸质签到（懂得都懂），有时候来的人较少，李老师也只是提醒大家尽量都来，能听一点是一点，从来不拿平时分逼大家；作业较少，而且一点不用那个远古学生系统！请假什么的不会多过问，只要提前告知，甚至不要假条。课堂上栩哥准备充分，讲解细致，还时不时停下来关心大家，怕我们没听懂。有问题QQ问他必回，还给你仔仔细细地讲，期末答疑安排了两次线下、三次线上。你只要别一次课不去，一次作业不交，考前一周的书都不看，说实话，不知道怎么挂。 最后还是希望大家都好好上课，尽量少缺勤，好好珍惜这样一位有实力还体贴学生的暖男！
INSERT INTO "reviews" VALUES('686cec55bf6625518c253fbf',1053,127,'各种吹牛，不捞人就算了，平时分乱给，一直缺勤的人直接给满，每次课都上了的人却给的特别低，吹牛大王果然恐怖如斯',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686ce3a4bf6625518c24f635',2301,2301,'平时分巨低，离谱',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686cd97cd3496c424605501c',2302,2302,'老师今天看到你给的数据分析的分我已经破防了
INSERT INTO "reviews" VALUES('686cd934bf6625518c249d88',2303,2303,'这里是23级的考试建议（仅根据自己的量子力学考试经历）：1.即使你整个学期没学，期末的时候也不用担心，把PPT看完(记住最好)就能得高分（甚至满分）。2.即使你整个学期都在学，也不要太安心，没看PPT照样得完蛋，因为考的是PPT上的，你自学/上网课学不到。最后，不要小看PPT那些犄角旮旯，它的分数可能很高，你没见过大概率就写不出来（即使你学过）。总之，我认为这种考试并不能正确反映学业水平，主要考察的是你看没看PPT。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('686cc80fb9570274dfb3aaa0',1743,1743,'会捞人，讲得不咋样',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('686cc749fbbb215be8f5c678',67,67,'林川老师人很好，讲课很认真，还会怕同学们听不懂，重点会强调，平时强调的重点期末考试全考了！期末对着作业认真复习，有错题不会的就问林老师，93分路过。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686cb460bf6625518c235c19',2306,2306,'找不到蔡创老师的评价只能在这下面发言了，拼尽全力艰难取胜，这门课大三下是真挂人，两个班平时分都是好的七八十，大多数就六十多，半期难出天际，半期开卷考试书和ppt翻烂依旧五十多且没写完，成型小伙立正了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686cb44dfbbb215be8f52f40',476,476,'我本是学生，今天来上课，区区一工测，大家都通过',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('686cb124c02b652dbc1784aa',185,185,'选aj 健步如飞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c99c0fbbb215be8f47a21',1600,96,'神中神 真的神中神 无敌好的概率论老师 成绩完美 讲课也好 坚持用自己的板书 不依赖ppt 上课讲课思路清晰 讲课风趣 我还想再学一次概率论马老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c996a6993d81fe673f528',564,26,'但哥啊 我的神 期末猛猛捞 平时分基本给满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c93c3b9570274dfb22af2',75,2236,'材料力学不唯一真神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c9366bf6625518c224e67',551,551,'看我的评分，这个老师唯一的优点就是亲和，你期中如果考的不怎么好，她会往上给你提分，然后平时分给的很高，但是讲课水平真的差是要死，如果你选了她的课，那你就赶紧找个网课上吧，讲课超级快，整个人神神癫癫的，总而言之，想水课的可以选，但如果想好好学的话就别选了。',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('686c92596993d81fe673bd41',704,704,'老师人非常好，讲得也是顶尖，非常负责任，只要是问她问题，她都会详细的解答，选她就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c91ead3496c4246031e83',1949,230,'这个老师给我的平时分是96，自己参考吧，然后就是期中前经常在知到上点名，可以让其他人帮你签，上课的话只要不是太过分，比如让你回答问题，你说你在写高数作业这种，她基本不会管你',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('686c9121d3496c42460318cd',541,1010,'不选就吃亏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c90f2c02b652dbc16a53a',26,26,'老师人挺好的，非常的平易近人，小测也非常非常的水，平时分给的很高，是满分。讲课也挺好，就是到每次课的最后时间可能累了，就是讲得比较快',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c8c1cfbbb215be8f40f24',1053,126,'他们说的完全没错，他确实啥也不是，上大学以来完全最有病的老师。平时分巨低，能换就换吧。快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686c8b88bf6625518c220dea',177,177,'志伟志伟 伟大无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c8ad6b9570274dfb1e3bb',179,179,'爹爹爹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c84326993d81fe6734249',2320,1353,'无脑冲 缺了好几次课 平时分都给满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c83956993d81fe6733d42',1330,1330,'测控最好的老师😋😋😋',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c835e6993d81fe6733aba',179,764,'数字电子技术，和模电一样期中各显神通，而且这门课本身就比模电简单的多。听课其实也可以听懂的，下来稍微复习一下就能考个不错的分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c8306b9570274dfb19efe',2323,22,'爱你东哥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c796cc02b652dbc15b8cb',2324,81,'这老师真是个人，太有人性了，是一点都不会捞人，平时分给的巨低，就60，明明再给6分平时分就过了就是不给，纯恶心人，纯在造福社会',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686c6682b9570274dfb098a0',2325,92,'李老师各个方面都很好，人美心善，唯一缺点就是出分实在是太晚',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686c0028b9570274dfaf9392',2299,760,'老师人很好，上课特别活泼，对学生很真诚，交作业也不会用那个很难用的系统，不怎么点名，偶尔点名也是让大家传纸签到。平时分拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686bfbd7bf6625518c1f3834',202,82,'一句话，60+％的挂科率，不怕挂你就选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686bfb83d3496c4246007f93',2281,2281,'社会你龙哥，人狠话不多，别的班平时分半期考试占3分，你龙哥20分，直接告诉你一句话期末考60就过（平时分最低24分，满分40分），第一次见不缺勤平时分给及格分的，课堂表现怎么都给不满，说教务不让给满，作业量多，不交扣一分，抄袭扣两分，抄袭之后不补交直接扣四分直至将你平时分全部拿下，下午两点的课直接一点上课，别相信22级那批34分都给捞起来的，你龙哥已经将小登们的40+狠狠拿下了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686bfb3dc02b652dbc14133b',2281,2329,'******无故加课作业量大期中占比高平时分低阅卷严格期末不捞，在这个班能总评70的放其他班能达到80，唯一优点是讲课详细问题会回但他又咬字不清听讲很难受，就这样吧想不出更多不带脏字能客观评价他的话了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686bfab1bf6625518c1f32e4',2281,2281,'讲课是一般的，作业是不允许补交的，平时分是很低的，阅卷是极严的，学生是命很苦的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686bf9bf6993d81fe6711e90',2281,2281,'平时分是不捞的，作业一共10分，几十次作业，缺一次就要扣2分，作业又多又难，下午两点的课，一点就要到教室，还点名 谁选谁就有福了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686bf28a6993d81fe671004b',2323,2332,'哥我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686bf081fbbb215be8f1741d',222,852,'自身实力强，还很谦逊，很完美的老师，太喜欢了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686befa2fbbb215be8f1701c',23,23,'白月光老师，原来上课可以这么好玩',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686bef3dfbbb215be8f16d8a',476,779,'上了徐老师两学期课，老师教的超好，个人收获很多，不考勤，实验比其他班轻松（以让每个人掌握为目的，无机械重复工作），作业量跟其他班差不多，平时分几乎满分。只要认真听讲，认真完成作业，期末拿高分没问题，徐老师yyds🌹🌹🌹🥰🥰🥰冲就对了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('686bed72bf6625518c1ef4a5',1053,127,'别选！！！！第一期中成绩不给看，期末考完了才知道，跟特么刮彩票一样，第二自己不组织随堂测试，算成绩的时候把随堂的15占比算到期中成绩，等于说期中占35，期末50，考勤作业15，一点不捞人。******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686be9366993d81fe670d2d1',2337,2337,'上实验课你可能觉得他不好，但他最后给分是真的高，有个实验没做好，最后也给了90',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('686be3866993d81fe670a4c6',39,39,'0分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686be210b9570274dfaf05f8',1053,127,'上课：吹牛逼
INSERT INTO "reviews" VALUES('686bde5afbbb215be8f0ea26',2340,2340,'老师很抽象，上课沉浸式念ppt（每节课都会叫多个人回答多个问题），这门课非常难，考试也很难，和作业的关系很有限。期末复习重点是没有的，许多个100来页的ppt你就看吧，布置的作业是没有答案从来不讲的，老师给分是很严格的，平时分是很低的，实验是很抽象的。避雷。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686bda4ffbbb215be8f0d322',36,36,'上课:念ppt，放视频，点名字回答问题，一节课三次讨论时间，下来挨个问问题，然后打钩，注意打上勾只能不扣分。偶尔大点名，定位签
INSERT INTO "reviews" VALUES('686bd9ae6993d81fe67064c4',74,74,'把专业课上成水课，选了不去其他班蹭资料蹭课等着挂吧。上课先讲一节课规矩，然后摆弄他的excel表，又不教怎么算，上课ppt也不给，下课给堆公式算例又不教怎么算，做些没讲过的作业，“我相信交大学生的自学能力”，每个人的数据还不一样，上课也是讲北京地铁多牛逼，成都以前那个设施施工我去过，实习也是工作量最多的，一个班73个人，要测73个点，而且实习前让你算点依据这个实习也没教，全班只有6个全对还是不讲，验收出来一个班就对七八个点。作业也不改，平时分也低，上课不准你拍PPT，问问题不能拿打印店资料，上完课还问你“我讲得精彩不精彩”，选了等挂吧，纯逆天老师。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686bd34ebf6625518c1e43d6',179,764,'还愿，期末44过了，神',5,5,5,15,0,0);
