INSERT INTO "reviews" VALUES('686bb009c02b652dbc120050',17,17,'嘴上说给分松最后给我期末66分，不懂什么意思哈，直接给我平均分拉低了整整一分，我期末纯自己写都没用过ai最后给我66分，笑死',2,2,2,6,0,0);
