INSERT INTO "reviews" VALUES('686ba3d7c02b652dbc11a6b6',1966,101,'很负责的一个老师，会安排习题课给大家讲题，基本不点名，习题课会提问。上课期间会有小测验，不过最后期末都给了满分，平时分也给拉满了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b9fc8b9570274dfad1fa5',2299,760,'认真负责 人民的好老师 👍🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b94d6fbbb215be8eec844',2354,792,'数电真神，给分爆高，上课通俗易懂，表面上严肃实则亲和力拉满而且非常幽默，问问题也会秒回，课设给分最高，数电无脑易安林就对了，这学期他的数电总评98轻轻松松。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('686b8d8bb9570274dfac83e8',322,322,'跑了头疼一秒，不跑头疼一学期',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686b8c516993d81fe66e0dff',322,322,'就是一坨，形策都能给人挂了，还天天点名，事多，照本宣科，冷酷无情。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686b8c28c02b652dbc10da5e',138,138,'不点名，拖堂就拖堂吧，平时分还给我96',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b881ab9570274dfac4376',2358,2358,'人很好哈，亲和力强，还给我推荐凡人修仙传来着，。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b87d1d3496c4246fd2cf6',2359,2358,'竟然没人评价吗，老师人很好，给分高，毕业设计也可以选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b8788c02b652dbc109374',1487,1487,'48人挂了14个，美醉了，不过补考也让我真正掌握了专业知识。感谢老师哈',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('686b8721fbbb215be8ee2ab9',1743,1743,'老师人很好哈，我们一个宿舍的摆子重修，都给过了60.61',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b860afbbb215be8ee1650',23,23,'人美心善，温柔耐心，讲课充满激情，跟着学易得高分，做人做事收获大，最喜欢的老师！yyds！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b84a7d3496c4246fced94',433,433,'事多分低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686b81eebf6625518c1b928a',704,704,'讲课好，会捞人，给分高，同时，霸气侧漏，幽默风趣',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b8139bf6625518c1b8cfc',1390,433,'平时分太高了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b80f6bf6625518c1b8ab1',1788,1093,'平时分太高了！(*¯︶¯*)',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b80c06993d81fe66d7573',2122,1796,'选就是了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b7814fbbb215be8ed95a1',2142,2119,'学弟学妹们冲啊！！吕晓琴老师yyds 人特别好 上课也很有耐心 作业量也不多 一周布置四道题左右 只要按质量交作业 慕课按时完成 课堂上签到 都能获得很高的平时分！！课堂上听不懂想自学也不会严格的约束你（还是好好听课比较好）而且老师讲的也很好 有什么不会的都可以问 期末也会带大家总复习',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b74ccc02b652dbc0fc65f',1949,230,'老师人很好，大家快去抱他的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686b71ebd3496c4246fc4288',648,889,'期末完全不捞人，平时作业多到没边，还要全手写，上课只管自己讲，没有重点，避雷了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686b6d3d6993d81fe66cb788',2371,80,'挺好，教课某些地方会稍快，作业好好做完，按时提交，最后平时分94，不踩雷，老师很随和',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('686b6c6ec02b652dbc0f8490',67,2121,'不多说，2次作业没交，平时分95，而且在q群有ppt,复习就是看ppt，期末95，老师人也挺好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b58e06993d81fe66c2781',2058,230,'女神级别，人美心善，特别温柔，平时分期末直接拉满了，而且也会说一些重点，本来是随便选的老师，没想到是个宝藏老师，无脑冲就对了。上课也不严，只有一个知到点名而已。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b493f6993d81fe66bbd3f',1087,1087,'讲课水平很高，平时分给的很高，讲的很清晰，人也很和善，课堂气氛也很好，很有热情的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b47bed3496c4246fb1047',1938,2375,'作为一门选修作业真的很多，要求很高不能缺勤，讲的可能还行吧…但真的不值得选，会在课上批评学生，缺交作业会取消平时分！',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('686b425afbbb215be8ebfdc9',1274,36,'老师上课喜欢用大道理评判学生，刚开始上课看到你玩手机会提醒你，后来就不管了。一学期只点了两次名，有一个小组作业和读书报告。平时分不像之前人说的那样给的低，小组作业读书报告稍微认真一点点就行，给了我45的平时分（满50），很高了。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('686b419db9570274dfaa1fc7',2377,230,'不多说什么了，虽然有的同学对老师评价不好，老师上课确实回来回转，但是止不住老师给的分高啊，只要上课点名都在，平时分直接拉满，我智慧树（知道）忘记做线上期末考试了，本来伤心了很久，总分要扣10分，结果老师都是直接给满分，平时分100，分奴速选！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b414cc02b652dbc0e5f10',467,22,'老师上课很无聊，可能需要自己课下学。点名会有学习通签到（不定位的那种）。平时分除了半期考试如实填之外给的特别高。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('686b409c6993d81fe66b7a85',334,175,'上的他的机械工程制图2，因为大部分人都跑了，教学班只有二十多个人，也从来没点过名，小测只有在期末考试前测过一次，还是画的之前大图画过的内容，小作业布置的有点多但是大部分都不收，要收的话会在课堂上说下节课收哪页（可以直接临时补）。大图和小作业画的别太差都交了平时成绩能有80，但是智慧树线上课程我都看完了只给了我70多分，最后平时成绩39（满50）。老师课下很冷漠，PPT和作业答案是没有的。',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('686b3d3ab9570274dfa9f7a2',1066,1066,'每次作业都是十几页往上，平时成绩还是看你作业完成正确率给分的，这不是要求你去抄答案吗？而且老师对学生不关心，上课迟到很正常，来了什么也不说就对着ppt照本宣科。不会划重点，一个五百多页的书要求你学完，并且考试难度一年高于一年，题目和高中有什么区别，第一次碰见这样的专业课，就算你每次按时交作业不缺勤也是八十多分，因为你作业正确率不够，老师也不会捞人，建议大家谨慎选择，这样冷淡的老师往往就是给分低的，你挂科与成绩高低，老师毫不在意。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686b37acc02b652dbc0e0f5b',2381,2381,'高代1，高代2都是期末突击的，都刚好卡线过，甚至最后都调了期中成绩比例，这就是罗神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686b1a37fbbb215be8eaba22',209,209,'课上的烂，分看心情给，人品低的无话可说，你看看你那个实习弄的什么东西？默认全校所有人都是电赛国一选手是吧，懒得教还是没本事教，惹公愤了多少次了？你的科研很强吗？真不知道你这种人是怎么在这个位置上光明正大得呆了这么多年的，晦气。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686b10f8bf6625518c1828a7',322,322,'老碧登',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686aad116993d81fe669213a',505,561,'老师人很好并且老师教的很好，但是就是给分死板，巨低，期末考试卷面成绩被平时分拉低了2分',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('686aacc26993d81fe6692067',598,27,'好老师，人美心善',5,5,5,15,0,0);
