INSERT INTO "reviews" VALUES('686aa6fbfbbb215be8e9840a',214,36,'老师讲课很有趣，专业度也不错，就是打分感觉全凭心情，不知道前面几位说平时分高的是不是故意害人的，注重平时分的同学能跑就跑，不然你会收到莫名其妙的低分，不要认为老师会给你讲道理',3,5,1,9,0,0);
INSERT INTO "reviews" VALUES('686aa574b9570274dfa79468',27,28,'温柔人美心善好老师！按老师要求把该做的都做了分数就会很高。好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686aa520bf6625518c172617',2390,186,'我们上的是孙老师的土木工程防震减灾导论，孙老师人美心善，老师会讲很多有趣的事情，每节课都很有意思，平时分给的也非常高，期末只要肯背就能得不低的成绩。总之就是非常喜欢孙老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686aa430b9570274dfa78b50',393,96,'只要不旷课，课堂练习都写了，平时分给满。好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686aa346d3496c4246f867ba',957,2392,'老师是经典理科战神皮肤，适合主观能动性强的同学。另外高数下册相对于上册难度上升不少，这是有血与泪的教训的（哭）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686aa1e9bf6625518c17180c',322,322,'不想说了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a98d9c02b652dbc0ba952',209,209,'老师我很喜欢你',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a93f6bf6625518c16af92',2395,2395,'选修课多彩巴蜀器乐，乱打分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a93aed3496c4246f7fc0e',582,442,'老师的传家宝ppt像是国家机密文件，不准你要，上课过的也很快，上她的课想要跟她的节奏很难，讲的也不清楚，经常留一节课啥也不干，也不讲课，期末前直接消失',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('686a85a1fbbb215be8e8ba39',776,2397,'老师能捞则捞，太好了感动[流泪]',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a8525b9570274dfa6cacf',776,24,'救我狗命于水火之中，老师太好了，能捞则捞，太感动了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a844f6993d81fe66832d3',2399,230,'平时分给的很高 只要慕课刷满就行 但是每节课都要点名 缺勤要扣分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a8319fbbb215be8e8a8c9',25,26,'讲的很好 重点突出 上课氛围比较轻松 虽然会吓唬人 但最后平时分还是给的很高 ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a82c26993d81fe66826dd',2058,230,'必须满分，签到前还提醒让同学叫没有来的人到教室，平时分拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a8290fbbb215be8e8a5c6',52,52,'上课水 平时分拉满 期末狠狠捞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a8228c02b652dbc0b201e',377,2403,'给分超级无敌低 没拿过这么低的分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a773bb9570274dfa66943',2058,230,'人美心善，平时分拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a7508d3496c4246f73f47',264,230,'大一目前遇到过最好的老师😭，课是可以不用去的，不去可以在寝室爽完，但如果你去了你也不后悔，会幽默风趣地讲近代史以及自己的生活经历，你如果认真跟他一起学会发现他讲的真的十分通透😭😭，幽默的风格真的让我认真学了不少😭，上课的抬头率比某些专业课都多😭，可惜我是他最后一届了😭，祝他后续工作顺利，潮平两岸阔，风正一帆悬🔥🔥🔥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a51c6bf6625518c150410',209,209,'好评',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a4587c02b652dbc097a39',221,36,'虽然说上课点名回答问题，但是回答不出来也没事，只是上课点名多，不要翘课，早退，手机电充满玩就好了，任务完成就给分，考试靠自己政治素养了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a3b26c02b652dbc09269a',2408,1732,'点名频率极高，平时分极低，作业多，讲课讲一半自己不会了，速跑',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('686a3b1ebf6625518c145724',373,230,'平时分给的非常高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a3ac8c02b652dbc0923ee',2210,114,'有责任心',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('686a3a2ffbbb215be8e6b62c',234,234,'非常有责任心，非常有亲和力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a39d7b9570274dfa4c55a',1972,1972,'要求巨多，不准看手机，不准说话，小组作业要求严，要求多就算了，水平很一般，上课就是念PPT，作业还一堆要求，老老实实交一个学期作业，最后作业平时分给50，期末给分也低，能上他的课有福了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('686a34e8bf6625518c142469',2413,71,'满分，签到一次没去，平时分给了90，期末还捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a322dd3496c4246f571da',1938,2414,'很差，给分很低，事情很多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a3210fbbb215be8e672e7',1938,364,'很差，事情很多，给分巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a1ea7bf6625518c137829',604,96,'siuuuuuuuuu',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a1e38d3496c4246f4dbd5',25,26,'线性代数来的，作业又要写练习册又要写雨课堂，事儿多分少态度恶劣，自己讲的题自己都讲不对，塘完了说是。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a1cb2bf6625518c136b4b',209,209,'lz真的不理解你那个实习搞的是什么东西。。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a1a1cb9570274dfa3ce23',612,2138,'狗篮子最后一天还穿个皇马队服来监考，平时上课就是一坨浓蟹特',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686a0804fbbb215be8e53fb8',359,228,'老师人很好，按照给的要求来做平时分低不了，上课坐前两排抽到了会有加分。每次上课会准备问题，一般提前一节课公布题目，下一节课让同学来回答，回答3-4次这个项目分数就满了。老师还会对回答的内容进行评价，引导同学们思考，回答的时候会专注地看着你，课上也讲解得很清晰。每堂课最后会有两道题作业，但是下课前就能完成，一道题总结一些重要知识点（书上两三行内容），一个是抄写给的名著片段（100-200字），每个人会要背一次名著片段。最后平时分给了满分，很好的老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686a00376993d81fe6649219',264,230,'伟大 无须多言
INSERT INTO "reviews" VALUES('6869faa6d3496c4246f3e349',264,230,'老师讲课生动，幽默，知识渊博，人也特别好，从来不会卡你平时分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6869f96bd3496c4246f3dbfd',334,562,'尹老师人特别好，平时分和期末分给的很高，强烈建议大家去选尹老师的课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6869f38bb9570274dfa2cba9',2424,2178,'特别好的老师……总是笑眯眯的，很和蔼，很亲近的长辈的感觉，不点名，上课会重点强调需要记住的点，课上作业测验什么的都按时交，平时分就高，总之选到他就是赚到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6869ee736993d81fe6641677',1554,1554,'吉祥爷真的和之前不一样，作业少，讲评很认真，非常幽默，画完大图会一个一个指出问题再交，只要按时交作业考勤，平时分给的很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6869e97dd3496c4246f36e30',264,230,'伟大无需多言，课是可以不听的，平时分是会给满的，重点是会划的。',5,5,5,15,0,0);
