INSERT INTO "reviews" VALUES('6869e8816993d81fe663e997',264,230,'拉满了，真的拉满了，平时分100分，上课比较水，讲的也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6869e782b9570274dfa27334',2429,2178,'平时看着有点凶，忍忍也就过去了，期末给分是真高啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6869dee6bf6625518c11bf0e',2399,230,'平时分拉满了，50分全给，真神',5,5,5,15,0,0);
