INSERT INTO "reviews" VALUES('68691c80fbbb215be8e0f8bd',2063,301,'ppt女王张雪梅老师，故意二次点名的张雪梅老师，讲话声音听不清一点的张雪梅老师，每次上课都把花名册上的名字点个遍的张雪梅老师，特别爱抽人回答问题的张雪梅老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68691bcbfbbb215be8e0f48c',349,194,'好老师，讲课讲得特别好，自己做的文档思路清晰有例题，人也很和蔼，迟到一会儿也没关系，吃早餐也不管。高数上下册90+都靠徐昌贵老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68691a82d3496c4246effb35',141,65,'我们高老师根本没有改邪归正。见过平时分比期末考试分还低的老师吗。作业不布置清楚，同学质疑还卖惨卖可怜，说自己分已经给得很松了。上课语速特别快，讲一堆物理史和根本听不懂的推导过程，让人昏昏欲睡，根本没办法认真听课，还喜欢抽人回答问题，讲的也不是很好。有抖m倾向的可以选这个老师。',1,1,1,3,0,0);
