INSERT INTO "reviews" VALUES('6869117afbbb215be8e0ae34',957,194,'老师讲课中规中矩，他确实是天赋型选手，一些东西课上听他讲理解不了，需要课下用功。随堂测验很难，不过他在台上不管。总体还可以，事情少给分高，老师人也不错，努力了几天总评八十多过了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68690d92c02b652dbc02faeb',887,23,'女神级别，老师只是看起来严肃，但是实际上温柔又耐心讲得也好。本人属于不擅长计算机的那种，复习了很久也是一上机脑袋一片空白，考完担心挂不挂，但最后总评八十多。老师的功劳🥰🥰🥰🥰🥰',5,5,5,15,0,0);
