INSERT INTO "reviews" VALUES('6868ceb6c02b652dbc00fa40',954,52,'这个学期上的是王老师的A1，小老头很和善，一次都没点过名，上课的话只要你不走神就是可以听懂的。我期中期末都考的不怎么样，王老师直接把平时分拉满救我小命。这个小老头真的很好呀😭😭😭（谁懂好几次早上起来下着大雨接过在群里看到老师说不用去上课有多开心🤓🤓🤓ps:老师让我们不去教室是因为新课已经上完了或者有什么演示实验哦）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868ce0cc02b652dbc00f55b',532,141,'好老师，就是上课质量不太好，适合自学能力强的学生，没点过名，考试以外的平时分都满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868cd28bf6625518c0c0332',211,240,'非常好超级无敌好 答疑一定要去！！！！智慧树超时忘记做了然后还帮你延期，讲的也很好幽默风趣！！永远的神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868b9356993d81fe65d7626',2469,2469,'无脑冲孩子们，老师教学细致热情，划分知识点很清晰，真正会站到学生的立场考虑的好老师。考试前划重点划的比我散粉都细，喜欢和学生交流，很认真负责。哎呀有点太多了说不完了，选就完事！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868b76fd3496c4246ecfd4f',2017,762,'真是很好的老师，讲课清晰易懂，而且人美心善，当时半期生病没考，老师还帮我想办法补救，太感谢她了🥰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868ab5fb9570274df9ba9b8',232,24,'爹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868a99cfbbb215be8dd9afd',627,627,'太棒了，平时点名记的一塌糊涂，太细致了。平时上课骂骂人，嘲讽一下，侃大山，太幽默风趣了。期末画重点太全面了，都是补考的重点啊，学弟们不用担心考试，因为他也不知道考啥。sml
INSERT INTO "reviews" VALUES('6868a8d9c02b652dbc000d30',776,24,'乐源老师太好了，米米嘟，上课讲的非常细致，课后找老师私聊问题也是秒回，平时作业可能稍微有点多。但是期末复习的时候真的，特别有用，助教老师也会把每次的作业答案发在群里，平时不上课期末听个网课做做平时作业，突击一周也能过，感谢乐老师，必须五星好评',5,5,5,15,0,0);
