INSERT INTO "reviews" VALUES('6868a294bf6625518c0af535',592,1073,'老师非常非常好，平时分给满了，上课讲课也非常有意思，考试前还会有习题课，从不点名',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68689f44c02b652dbcffce8d',2050,2477,'笑面虎。虽然平时分给的低，但是期末考改得严呀XD',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('686899b16993d81fe65c9d4f',2478,2478,'神中神，老师讲课很好，经常用通俗易懂的例子解释课本中的难点，人也很亲和，平时分给得很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868944fd3496c4246ec1157',211,240,'神中神！讲课讲得好就算了，还幽默和蔼，一点都不为难学生，只要按时上课交作业，期末平时分随便拉满，选到王老师的同学真的请认真对待电机学，以前还听说电机学是四大天书，跟着王老师学虽然也觉得确实抽象，但也没想的那么难了，最后成功拿到了很好的成绩！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6868854b6993d81fe65becda',228,228,'要想高分可以选马晓燕，我平时分得了接近满分，事情可能有点多但是我觉得还行，首先是一单元学完会有课后作业，然后最后会检查批改，但是只要你改了就是满分，其次是上课会提问，但是只要你主动回答问题就不会提问你，主动回答问题加分，上面会画√，她不点名，主要靠提问看人来了没有，然后就是实践作业，她确实要求比较高，给分中规中矩，我就得了八十吧，但是主动回答问题我加了2.5分，全抵消了，期中靠手机和书可以考九十来分，小测都是老师提前强调在书上画过的重点，也是满分，总而言之，如果你只是想摆，那可能事情有点多，但是你是保研佬的话我推荐你选她',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68685e61bf6625518c091036',430,194,'课程是很专业的，老师是很幽默的，课堂气氛是很不错的，看爱机是不可以的',5,5,5,15,0,0);
