INSERT INTO "reviews" VALUES('6867fb37bf6625518c0819e3',177,177,'额，有人说老师声音小的那位你是一边戴着耳机一边听的吧，但凡你认真听也不会说老师声音小，我一学期都是坐的最后一排听的，我个人觉得老师教得挺好的，平时分给得也高，神中神，老师期末会把能捞的都捞了，选到就是赚到。当然，你想自学也没问题，老师上课从不签到（就是最后面有一次说要系统记录一下才有了mooc的一次签到）',5,5,5,15,0,0);
