INSERT INTO "reviews" VALUES('6867205fb9570274df926293',393,2513,'平时分全给满 每节课都会回顾上节课的内容 会让你理解概率论为什么按这个顺序上课 底层逻辑是什么 讲的也很不错
INSERT INTO "reviews" VALUES('6866fd90fbbb215be8d3d02b',2514,2514,'上课讲的很快很水，而且给分真的巨低无比，作业严格的要死。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6866dfd3fbbb215be8d39a9a',99,361,'交通美学事巨多，给分也贼低，一选修课一个学期四次大作业，还天天考勤，最后给七十来分，恶不恶心😅😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6866d568c02b652dbcf605db',953,953,'没怎么点过名，上课很水，没作业。平时分给满，谁敢忤逆。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6866d52c6993d81fe652f36d',2517,1241,'么么哒，平时分给满，上课不管玩手机',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6866c819c02b652dbcf5f45a',64,64,'这老师全价四万了，哈哈哈，懂得都懂，楚生中的楚生',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6866c4fefbbb215be8d37656',103,6,'看这大部分人的评价都是这样，我也是安心了，明白第一次教书能有这种评分的含金量吗。至于给他差评，这老师还会在群里连发多条消息辩解，一眼丁真，鉴定为反驳性人格。想想某人假惺惺的说自己很开明，我当时居然还真信了，哎。至于这门课是不是水课呢，他的原话是绝非水课，由此可知，拿高分得经受多少考验。看到我的这条评论，希望给后来的懵懂无知的新生一点帮助吧，你如果一学期做不到回答十次问题的话，千万别选，不然平时分低于八十不是梦哦',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6866b48fb9570274df913c01',228,228,'快跑吧，上课一股子慵懒的高傲劲头，看不起这个看不起那个，讲课也是毫无水平的照本宣科，超级多的手写作业是要布置的，改是不能收上来占用其他时间的，只能在课间大排长龙。pre是要处处刁难甚至重做的，考勤是每天课前随机点到的，平时分是低低的。还经常有把学生当老公的迷惑性发言“你们不想再见到老师了吗”，出平时分和期末成绩也是要在群里表演的，谁选谁倒霉。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6866b227c02b652dbcf5bd74',198,198,'神，平时分几乎给满，一学期就写四五次作业，课设随便糊弄糊弄都能拿高分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6866abd5bf6625518c0058a5',887,23,'满分无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6866aac6c02b652dbcf59ecb',971,24,'老师上课很负责，有板书不是单纯ppt，一学期点三次名，只要平时作业都交，上课都去，平时分拉满，最后也是被狠狠捞了🤓🤓🤓🤓',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68665b6cc02b652dbcf353a2',756,22,'必须满分💯',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68665b2eb9570274df8ed2b7',2525,2525,'这不满分？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68665ad1bf6625518cfe0d59',526,1554,'兼职部的首席诗人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68665ab5fbbb215be8d0dc3d',526,1651,'诗人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68665aa8c02b652dbcf34e32',526,716,'诗人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68665a42c02b652dbcf34bd5',526,526,'平时分给多点要si吗？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68665a1cfbbb215be8d0d895',450,450,'开学只是吓唬你罢了实际真的刀子嘴豆腐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686650d16993d81fe64fb7de',1390,28,'老师很热情，很负责任，就是上课有时候喜欢点人回答问题，不过考试基本能捞的都会捞（除非实在考太差）',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6866501bfbbb215be8d09083',1377,194,'中规中矩吧，讲课还行，作业不算少，平时分也还过得去但不算很高，不过老师挺负责任的',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('68664fc86993d81fe64fb0bd',242,242,'讲课一般般，看速成课过的考试，平时作业会有点多，虽然老师看着很和蔼但是平时分给得很抠门。。。。。。就算平时作业都好好完成了平时分相比其他老师还是会比较低',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('68664eee6993d81fe64fa944',540,2534,'神中神，讲课能听懂，作业和平时考试好好完成平时分就有90！而且老师超级温柔…恩施我要追随您一辈子……',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68664d1cc02b652dbcf2dcb6',2535,2535,'机原老师，一学期点三次名，作业也有点多，但是期末特别能捞，谢谢老师我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68663c8a6993d81fe64f0f4f',430,194,'60分过了：“爱死你了，虎哥”
INSERT INTO "reviews" VALUES('68662b3bfbbb215be8cf5ac4',372,5,'感觉她的课算是我遇到的大学数学老师里面讲得最通透的，基本上课认真听基本能掌握80%',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686628cfc02b652dbcf1b181',311,1514,'这课都是第二节课传纸条式的签到，平时没什么事。给分比较正常化，反正我93总评，不知道算不算高',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('68662647fbbb215be8cf2e8c',727,727,'点名不多，一学期完整点名三次左右，缺勤也能后期坐前排加回来，基本上平时分都是满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686625acbf6625518cfc4be2',666,666,'老师人很随和，平常作业也很少，课程任务也很好完成，给分很高，不过课堂可能有点枯燥（我觉得更多是课程原因哈哈）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68661c6ad3496c4246ddce22',2541,92,'上课讲得好，说话好听，作业比较少，就考了两次勤，平时分给的高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68660ad1c02b652dbcf0b59b',311,51,'好人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68660a80bf6625518cfb6644',65,65,'不负责任，喜欢让学生帮她代课，出了问题还算我们头上。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686608d2c02b652dbcf0a3f9',1157,52,'平时分作业交齐，签到都签了，基本就给满。期末还有很多复习资料，重点也勾的很完善',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68660820bf6625518cfb5320',170,233,'无敌了，课没缺过，作业没少交过，上课的测试也是认真做的，结果80平时分，比期末考试分还低，跟之前评论一模一样，这下真是选择大于努力了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68660667c02b652dbcf093ac',1290,27,'老师给分很严谨，不会捞人，平时分都是记录在案的，有很多作业，都和平时分有关，一点要做，特别是u校园，占大头',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6866060d6993d81fe64d4eb2',953,953,'无脑选，一学期没咋去上课，上课也没回答问题，大作业也是随便搞了，平时分直接给满分。期末只考20分以上就能及格，无脑选好吧。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6866040bc02b652dbcf08329',360,360,'傻鸟玩意',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6865fee56993d81fe64d1f95',1500,1500,'神中神，上课挺好玩的，平时分是巨高的，为了捞大家会把平时分占到60%，上他的课算是物理系大一小东西的新手保护期了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865fd7cfbbb215be8cdf394',540,540,'伟大无需多言QAQ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865fc40c02b652dbcf043dd',1788,1093,'赵哥神中神，一节课没去过平时分100',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865fc19bf6625518cfb0243',540,1897,'神仙老师，你只管考40，剩下交给老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865f9a8d3496c4246dcf437',2458,23,'这个老师人不错，每节课上课都有纸质签到，还有一个非常尽职尽责（但也比较烦人）的助教，会一一统计你的平时作业并且非常详细的打分（导致作业平时分不高），整体来说可以来，但是来了就别想摆烂了',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('6865f7eabf6625518cfadd2d',1290,27,'小老头其实人挺好，但平时分实在给的少而且作业很多，平时上课会从一些生活中的事情开始讲，但感觉像是在上水课，学不到啥东西，不推荐',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6865f6febf6625518cfad52f',1066,1066,'平时作业是助教改的，给分挺低（有次抱着答案抄只得了88分，实在难绷），老师确实很有水平，上课能手推满黑板的公式出来，但是讲课水平实在一般，整体中规中矩吧，不推荐也不避雷',5,2,3,10,0,0);
INSERT INTO "reviews" VALUES('6865f5ed6993d81fe64cd831',1453,114,'神中神，非常好的老师，最后悔的事情就是下学期调课没选宝哥的高数，平时分除了期中是直接拉满的（据说你天天翘课也是一样）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865f389d3496c4246dcbfed',450,450,'有一说一，黄银是真的刀子嘴豆腐心，平时上课凶巴巴的但是给分一点都不低，而且有东西他真教啊，考试应该是赋分制度，我期中虽然没有满分但是平时分还是100（虽然可能和我帮他批过一次作业有关系，但他没问我的学号姓名（当时说要请我喝茶）），总评拿下96，想拿高分的同学努力冲就完事了，但是他挂人也是真挂',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865ecc7d3496c4246dc7619',491,1529,'倩倩老师人真的很好很负责，我觉得交大能有倩倩老师真的是荣幸，刘老师上课讲的细致耐心，下来问她问题她也会耐心回复，不会不管不顾，而且平时分基本上拉满了，简直是我的女神！！！❤❤😘😘',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6865e433b9570274df8afd12',2559,2559,'特别特别特别好啊，作业少，讲的也清晰，分也高，就是想水的人可能比较难受，他上课会喜欢抽后排和玩手机的回答问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865d1fc6993d81fe64b9d50',23,23,'最温暖体贴有爱心的老师，讲课生动有激情，容易听进去，只要认真跟着学，高分到手~不过抢课太难，要看运气，哈哈，我运气超好，祝君也好运~',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865ca39d3496c4246db6583',491,23,'神中神！老师很负责任，讲课讲的很好，对学生很好，很有耐心，基本上问问题都是秒回，给分也很高，你按她要求完成基本是满的除了期中给的资料也很多，是一位在大学难得见到的好老师，我专门开个账号来夸她！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865afc5b9570274df89cbc4',788,449,'中规中矩的老师吧。
INSERT INTO "reviews" VALUES('6865ad3ebf6625518cf8f057',965,1241,'真是我亲妈啊，神中神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865a7a5d3496c4246dae5da',960,228,'老师人很好啊，别的专业都是期中考试啥的，我们都没有，给分也巨高，事情很少人也好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865a5606993d81fe64ae5ed',1705,1170,'超级好的老师，化工原理和无机化学都是他带的，考什么说的很清楚，作业少，讲课也很清楚，good！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865a474b9570274df89a151',877,2566,'很好的老师呀，给分满了，讲课也很清晰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68659a39c02b652dbcee039c',2567,803,'很有个人魅力，可惜退休咯！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68659a1bb9570274df898cbb',803,1111,'极有亲和力的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686599996993d81fe64acaf5',1320,40,'良师益友，不只是上英语课，更是一节有着很多人文关怀的课程，琳姐虽然会扯一些其他内容，比如最近的新闻，日常生活的事情，但是还是比较有价值，真正让人思考除了得高分以外的事情。感觉真的是回归了“教育”的本质，引领大家在大学里面养成健全的人格，而不是一个偏激极端的后现代个人。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6865988bd3496c4246dac65c',2570,2570,'水课也懒得说太多了。。。但是期末不给考试范围就差别人一大截，我还是弟兄发给我考试范围才背完了考试重点',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('68659768fbbb215be8cb9cca',12,4,'老朱真的不仅仅是一名体育老师，更是支持大家的兄弟，经验老道的教练，富有魅力的男人，更是交大的骄傲（带队在贡嘎杯总是能有好成绩）。平时的体育课会和大家互动很多，也见得到他高超的水平，和大家开开玩笑或是说自己以前做运动员和警察时的有趣故事，深受大家的爱戴。并且很打动我的一点就是他很尊重班上很少数的女生！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68658950c02b652dbcedf063',55,55,'很负责的老师！！认真上课的话，分给得超高。我学舞蹈所以动作学得比较快，也认真上课了，体育课大一和大二没有低过95分。老师人也特别好。
INSERT INTO "reviews" VALUES('68658752b9570274df897605',2573,2190,'老师很好，中间有一次还会奖励作业得分高的同学，平时分基本90+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686586d8d3496c4246dab386',2574,1767,'上课不管我们干什么 ，也不提问， 非常适合水 ，而且只要点名到+完成作业平时分基本拉满满的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686578e7b9570274df8963a2',751,573,'人才老师感觉给分就很随意感觉就是看心情，上课讲话是不清楚的，经常讲着讲着就开始吹牛了，平时分瞎给 ，捞人是不可能的，这课你就上吧一上一个不吱声',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68656c69bf6625518cf82fc6',119,26,'除了板书有点看不清，其他都很好',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('686569b5bf6625518cf8290d',7,7,'你胡哥真是唯一真神 平时分除了期中全部拉满 手写板书讲的也清楚明白 真能学到东西 而且考试整个班整体成绩都很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686569996993d81fe64a8168',909,909,'老师讲的不错，就是声音有点小，还有口音偏四川话。但是课特别水，不点名，有的时候是传一张表签到。期中期末作业都是交一篇论文，给分不错',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6865690dbf6625518cf82589',2579,2579,'老师讲得很有意思，上课还会放视频，期末考试交论文，给分也高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6865644fc02b652dbceda3bd',2197,876,'其他的活水评价有些年头了，我来说说吧，现在平时成绩竟然有雨课堂的回答问题，没有提前说清楚 导致扣了一两分，其他的还行，上课会转悠，人很和善',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6865629a6993d81fe64a6cca',1175,68,'分确实低了，我坐前三排且回答问题的情况下分还是实打实给，固定排位置',3,4,4,11,0,0);
INSERT INTO "reviews" VALUES('68655b4afbbb215be8cb24b1',2582,790,'物流工程不得不选的老师，大二下开始每学期都有他的课，期末重点画得很多背的东西也很多，但是给分还可以，不算物流工程里特别差的老师',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('68655a69c02b652dbced7f29',1975,619,'给分还不错，但是平时事情比较多，有两次小组大作业，不让坐最后三排而且不定时点名（很严格的那种）
INSERT INTO "reviews" VALUES('68655965c02b652dbced794f',2584,40,'老师人非常非常好，给分也高，这两学期平时分总分50基本上水水考试都能有四十七八，不要犹豫冲冲冲：）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('68648f12b9570274df82bc25',271,2499,'成绩出来了，你就知道我为什么称丁浩老师是神了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686489036993d81fe643ca36',2586,2586,'快跑吧 平时分才七十多 我c++都没考这么低 期末完了找她根本找不到 肇事逃逸 好友不通过邮箱不看',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68647aa3d3496c4246d33c60',271,2499,'老师人超级好，平时分和期末期中考试分都给的很高，虽然上课挺难的，但是给分超高啊！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68647793b9570274df81eaa0',870,296,'刚被捞起来的，特来感谢🙏，人很好，你想刷高分她上课勤勤恳恳，你想混及格她也捞你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686469cfd3496c4246d2f2c9',119,26,'神中神，老师在QQ是问问题有问必答，作业也很少',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6864677cbf6625518cf04d34',119,26,'不知道是不是我个人原因，感觉老师教学水平有些不足，有时候会讲错，不过人很好，说出来会纠正，很亲切，没架子，感觉是个新老师，可能还不太熟悉教学吧，不过课比较水，作业不多，平时分巨高，感谢满绩',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('68643819d3496c4246d29dda',2299,2236,'非常好的老师！不要听里面唯一的一个差评。李老师年轻有活力，对学生认真负责，而且非常温和，对同学们很宽容。期末答疑和平常的教导是交大数一数二的细致。好好听他的课一定没差的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68642efbc02b652dbce55c29',85,1614,'非常友好，温柔的老师。老师是真的希望我们能掌握体育技能，教学很负责。期末考试老师一般给分很宽松，而且卡在89点几 79点几这种分数 老师会主动帮你凑整！！选到就是赚到！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6864274fd3496c4246d281c2',1538,1073,'手写板书，讲的细致，平时分给的高，会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68641cabd3496c4246d269fd',2594,2,'快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68640e61bf6625518cefaa0d',2507,81,'徐娅楠老师万岁，徐娅楠老师万岁！给了我满分的平时成绩！老师人很热情，会在课堂中加入一些实际问题、网络热梗来让大家辩论，可有意思了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('68640e37c02b652dbce50b8e',2596,1409,'💩',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('68640ddd6993d81fe6423d23',755,760,'真神！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68640d9bc02b652dbce5090d',2598,2598,'一个没有水平的老师，上课读ppt，要看着ppt才会讲例题，而且听课的话不如自己学来的快',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68640d44b9570274df80fc25',1175,68,'平时分给的巨低，上课很水，',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68639819ce7fc86faf9145af',870,296,'非常非常棒，期末会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686397b4c02b652dbce14383',119,26,'年轻漂亮又温柔的老师，只要你好好学平时分就会很高，老师会在课堂上放慢讲课速度来保证学生听得懂，而且会认真回答QQ上的每一个问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68639677bf6625518cebf4d3',2602,653,'少找他点评就是了 别跟她杠 她让你改方案也别改越改她越不满意',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('686395ead3496c4246ce8e9f',2603,653,'对任务布置和上课比较有逻辑 平时作业也会提出一定不错的建议 每周会布置钢笔画 在建筑学院大一老师里算不错了',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('68639551b9570274df7d3899',119,26,'老师上课内容很细致啊 很可爱很漂亮的老师😍课后qq上回复很及时 会安排作业讲评课 上课也不枯燥讲的很细致 平时作业也不会特别多会挑着做 只要每次作业都交小测都测了平时分拉满 ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68638d87b9570274df7cf192',2507,81,'平时分100，事少',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686386edc02b652dbce0b626',56,56,'陈曦老师是我遇到的最负责的老师，超级喜欢',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686381eebf6625518ceb478f',2607,2607,'这学期选了老师的管理经济学的选修课，事少分高，点了大概三次名，都是把自己学号写到纸上，期末作业是一篇论文，字数不限。老师上课就自己讲自己的，没人理她也无所谓，讲完课就放点视频',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686379dcce7fc86faf904a35',1108,188,'之前春玲姐可能确实做的不好，但是最近已经改了许多了！会提前几分钟下课，上课在智慧树上布置刷题训练（送分的），下课登记就能加分，平时上课也很温柔，虽然对迟到问题还是比较严肃的，但是整体真的非常非常好！！！只要每节课都来，不逃课不翘课不旷课，平时分打满！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68637879b9570274df7c4d7a',1108,1065,'平时分拉满了，春玲爹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68636b86c02b652dbcdfed4b',2603,653,'带的班作业量比别的班都大 但老师性格还行不会和某些人一样阴晴不定 属于制约性的存在 但平时好像提不出有用的改进方案 只会让你再好好想想然后陷入循环 给分也不是很高',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('68636362bf6625518cea72ef',732,156,'平时成绩给负分，七三开的学科期末考六十多过不了，怕你补考过还会改你平时成绩，出总成绩的时候平时分又给你减两分，没话说',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68635c46ce7fc86faf8f8f2e',2612,859,'交通设计课平时分特别低还占百分之五十，给分真的狠',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68635a8ec02b652dbcdf7d07',2613,2613,'平时签到就是签字，平时分拉满了40，好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686356bdc02b652dbcdf61f8',1523,26,'非常好的老师 平时分很高，除了半期改不了其他基本都拉满 ，一学期只点一两次名，发消息问题也基本秒回，人很好很有耐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686350e1d3496c4246cc83fa',2119,2119,'比较严，但是人很好。旷了三次课交了个检讨，最后平时分拉满了没扣一分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6863470d6993d81fe63c0eed',119,26,'老师很接地气，和蔼可亲，没有架子，在QQ上问问题必回你，然后平时成绩也是直接拉满了!!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686346706993d81fe63c013e',1955,194,'自打上大学后遇到的最负责的老师，很用心，考试前还会给你腾出好好分析你的错误，左老师我的神!!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68634013c02b652dbcde80fc',450,450,'以下评价为刚出分之后的个人评价：佛度有缘人，你懂得大学考试赋分的含金量吗？黄老师不会亏待每一个学了的人，想刷高分冲就完事了，缺点就是挂了的是真会挂。试卷相对难但它有赋分啊。上课要求回答问题，作业要求高是为了你学得更透彻，个人确认过眼神，他是真的希望你以后能拿诺奖。中间可能有比较多的作业，可能有千字论文的提交，这些行为却不妨碍他给你平时分拉满，也许你出分前骂过他无数次，最后你会承认他确实是个好老师。好好珍惜吧，要求严格又给分高的老师不多了。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6863400cce7fc86faf8e7668',592,1073,'钟华老师超级好，只要认真对待，完成她布置的任务，期末平时分拉满，讲课超级认真，而且会听同学的建议，超级好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68633e38ce7fc86faf8e659c',1287,68,'平时分太低了 比我期末考试成绩都低 上课水 但是作业依旧很多',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('68633df2b9570274df7a78b1',326,36,'事多分低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('68633d43d3496c4246cb9bc1',55,55,'很好的老师，上课挺严格的，但是非常认真负责，想水课的友友就不要来了，建议报其他老师哈，但凡认真的同学给分都高。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6863294ec02b652dbcdde1c1',1523,114,'非常好的老师 高数1 2都是上的她的课，不怎么点名 一学期可能就一两次，平时分给的非常高，除了半期没法改 其他分数几乎全部给满，老师人也非常好，平时发消息问题几乎秒回，神！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6863281fce7fc86faf8dd055',849,619,'彭老师是真的好，有原则讲道理，学术水平高，对学生亲和力也高，该加的分绝不少你的，只要你不旷课被点到，分数都不会低。最重要的是上他的课，你做什么事情他不管你啊，老师上课会有提问环节，回答几个问题基本上平时分就满了，更重要的是老师提问的一些内容都是期末简答题的重点，回答几个问题之后期末考试带着背一下就行了，这学期彭老师的毛概课最后成功总评90+。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6863246f6993d81fe63b040f',1401,1401,'我女神，神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862dd7bd3496c4246ca5c5e',430,194,'挺幽默的 平时分给的还可以吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862dd066993d81fe63a6d9d',2455,241,'五星好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862d993b9570274df7923b3',8,1010,'老师特别好，给分也很高，上课不怎么点名，也不管下面做什么，人也好，给分真的很高！基本没有作业！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862d512d3496c4246ca47a0',2629,920,'老师人特别好的，会捞人的老师，上课回答问题或者帮忙会给小零食，之前上一门他的选修还给发了奶酪棒，讲课也蛮有意思',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862d271b9570274df791909',1025,850,'松茸哥人很严，但是教的确实很好，我平时比较摆烂，到最后几周幡然醒悟了，坐前排改变上课态度，最后期末多亏狠拉了一把才没挂，可以说是救命恩人了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862d186bf6625518ce7cee9',2631,198,'好老师 可能因为研究方向不是数字方向所以数电讲的不是那么清楚 但是为人亲和，愿意给学生分享自己的经验 给分高，真的很不错！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862cbfac02b652dbcdd1640',1381,517,'辣鸡辣鸡，欢迎体验',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6862cb65bf6625518ce7c268',2633,26,'快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6862c821c02b652dbcdd0b6c',55,55,'超爱陈老师，陈曦老师太有魅力了🥰好喜欢。武术打的超帅，学识渊博，思想开阔，跟陈曦老师交谈每次总能让我豁然开朗。她对待体育课非常严格，但正因为这种“严格”，才让作为大学生的我在学校中真的进行了体育锻炼，对比其他“舒适”的老师，如果她也是这样，我想我应该也真的慢慢走向“垮掉的一代”吧～总之就是跟着陈曦老师这两年，是真的“学有所获”！身体是自己的，以后我才不要“拿钱换时间”！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6862c807bf6625518ce7b888',2635,2190,'地院最年轻，最美丽，脾气最好，最优秀，给分最高的老师，她简直是神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6862c75d6993d81fe63a40a0',56,56,'陈老师的课是真的可以学到东西，锻炼身体的，老师人也很好，很多课程的规则、上课的要求都说的很清楚，我舍友体育课都没咋说，回来都是问我😂不晓得下面同学区别对待何出此言，有一说一，我是班级中的隐形人，不会表现很好，也不会表现不好，陈老师一直很认真的讲解啊，也很耐心的解答，给分总的来说还是很宽松吧，除非真的都不会练才比较低，一般都是80分以上啊，90分以上也很多。武术动作可不就是多练嘛😅😅不练咋会，反正大三还是追随陈老师了',5,5,5,15,1,0);
