INSERT INTO "reviews" VALUES('6862c66ebf6625518ce7b075',119,26,'老师非常非常友好也很年轻 QQ也是有问必答 一学期几乎不点名 只要课后作业都交了（比别的班少）小测也来了平时分就是满分 神神神',5,5,5,15,0,0);
