INSERT INTO "reviews" VALUES('686219cece7fc86faf885c06',103,6,'只能坐在前五排，而且只有第一排可以加一分，你这让我前两节有课的怎么抢到第一排？！对比一下别人班的，不限制座位，前三排加分。并且如果不是周周都非常积极得去举手，加之非常幸运被点到，否则平时分不可能拿满。做个人吧。建议这个老师别玩王者了，去打瓦多找点妈妈，我怕你不够消耗的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68621835bf6625518ce2edef',2241,195,'逆天，乱给分，全班40分平时分没有超过33的，点名九次，八次到和一次到分是一样的；作业全交，两人写一模一样，一个作业分50一个作业分90；找他理论说什么都是他占理的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68621429b9570274df742d3c',1641,1641,'纯神经病贱，给分低的要死，纯折磨人的，不知道这种老师活着干嘛？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6862130e6993d81fe6355d42',2586,2586,'毫无能力，讲课梦话，出尔反尔，能跑就跑！态度极差，爱翻白眼，要求刁钻，喜欢大吵！',2,3,2,7,0,0);
INSERT INTO "reviews" VALUES('68621038d3496c4246c53306',2028,2651,'信息学院乃至是整个学校最差劲的老师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68620e2b6993d81fe6353c7e',297,194,'帮胜哥你真是帮胜啊！！！！！！！！作业补交的，点名漏到一次，而且一学期就点了两次名还是导员找他要考勤他才点名的，期中点了一次期末最后一节点了一次，平时分拉满了我爱死你了我靠，主要是不仅人好，讲的也好，逻辑巨清晰比b站很多热门老师讲的都好！！！！！！（但讲的快）',5,5,5,15,0,0);
