INSERT INTO "reviews" VALUES('686203f46993d81fe634f19c',1048,26,'完全不捞人，差评，就差一点都不捞',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686203a3bf6625518ce259b1',2241,2241,'平时分给60分的神人，逆天了，纯沙币老师，作业又多，b事还多，选了的人有福了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6862006bb9570274df739c43',2661,2661,'上课就是念ppt  念的也不好  ',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6861f69ed3496c4246c4657f',209,209,'老师其实还是很好的，上课也讲的很好，上过他两学期的实验课了，之前还觉得他不太好接触，这学期最后一次实验我因为U盘坏了，实验数据没了，没有在课堂验收实验，没想到老师很理解我，专门在中午等我一个人给我验收，我很感动',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('6861f661bf6625518ce1ed5c',297,194,'讲课逻辑很清楚 人也随和脾气超级无敌好 平时分超高不点名 爱死了😍😍😍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6861f5e06993d81fe6347e1e',54,54,'吗的这种楚圣就该发配印度 拿给印度小哥发泄 本小女子一节课被他骂了三次 真特么楚圣',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6861f445c02b652dbcd7157d',1095,1095,'c无泪s',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6861f408c02b652dbcd713d2',25,26,'老师上课讲的很清楚，PPT最后面会有总结部分，复习什么的看PPT就够了。
INSERT INTO "reviews" VALUES('6861f386b9570274df732837',1095,1095,'垃圾老师千万别选，上课水还严的不行，不带电脑也扣分。上机课啥也不讲，问他啥都让我们自己问AI，那我问你你是干什么的，考试考手写Python 代码。结果上课从来不讲，赶快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6861d0c0bf6625518ce0de46',1390,433,'其他都还好，就是请假会扣分(拿了有学院批的并且盖了章的假条)，我外出打比赛被扣了2分，还说是学院规定，那一起去打比赛的十几个同学的老师怎么都没扣？还说怎么别人都不请假就你请，，，，，，，，，，，',5,4,2,11,0,0);
INSERT INTO "reviews" VALUES('6861ce66b9570274df722a15',1333,28,'老师很耐心，讲的很好，人也好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68619aa3b9570274df71bd18',229,229,'有口音，讲的不十分清楚，但是人很温柔',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('68619a16b9570274df71bc91',452,2671,'认真负责，讲的挺好的，其他不想说',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('68619988ce7fc86faf85c480',1333,28,'美丽温柔，幽默fashion',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68619924bf6625518ce065bc',334,175,'建议线下追着老师问，非常有耐心，线上他说话有点听不懂',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('68619791ce7fc86faf85c23e',2674,2674,'上课不算严格，对女生尤其包容，但是微信信息确实基本不回',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('68619576bf6625518ce0615a',499,194,'会回QQ，讲的很好',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('68618689bf6625518ce04c19',23,23,'唯一真神，伟大，无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6861860f6993d81fe632cc33',345,2677,'许老师其实很好，小测感觉就像是摆设，只要你期末的分能让她给你救回来，她是真的会救你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686182d7b9570274df7197a6',1267,2678,'上的大学生心理健康。老师讲课挺好的，上课很有意思，讲的内容很丰富，但是期末给分不高。上课就一次不去但是每次都坐前面互动，回答问题，作业也都写了，期末和平时分都很低',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68617d7ece7fc86faf85996e',788,40,'纯纯逆天，一点不水，平时测验要收手机，少一台都不开考，作业给分也不高，还查你ai率',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68617d41ce7fc86faf859905',2500,228,'平时分给满的神中神，很懂学生，会跟学生一起打球，上课也不是照本宣科，总会找一些学生感兴趣的课题，一学期从没点过名。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686178a0d3496c4246c2a6a9',974,2681,'半个学期没上课平时分还是98，有多好不必多说，点名少，最后两节课会点名，其中有一节还是考试。期末考试一篇八百字大作文可以提前写好过去抄。上课经常放电影，选到就是赚到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68616a8ec02b652dbcd52fdc',954,52,'这学期上的大学物理AI，老师很亲切，私信回的很快，没点过到，作业全交平时分直接拉满，没有口音，楼上说教学水平一般，我对这个看法最多赞成25%，老师上课确实极少情况会有出错的地方，但他也及时发现改正了，总之就是一个很好的老师。ps，不知道其他物理老师教的怎么样，但至少我对他的教学还是挺满意的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6861696dce7fc86faf856232',348,348,'神人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686168b8b9570274df715430',209,209,'伟大，无需多言',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('686167d46993d81fe63277c7',870,296,'被老师捞及格了，来打个好评',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('686166c06993d81fe632741a',27,27,'王蕾老师超级好，人很温柔，给分很大方，为学生着想。上课讲的内容很充实，语速适中，声音也很好听，如果不是因为英语在早八兴许肯定不会犯困',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6861664abf6625518cdff6bb',870,296,'张老师很好，上课偶尔点名，讲课速度或许会有点快，但是课上看网课也不会太管。老师看着比较严肃，但是人很好。平时分给的很大方，随堂测验可能会比较严（也可能看助教的情况），期末会捞人，大大滴好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686093946993d81fe62c50b7',2688,2688,'最好的老师，无脑选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6860937fc02b652dbccf2fb0',433,28,'每节课需要手机上签到，但是上课非常水，基本都是玩手机的，课堂讨论ai一下就出来了。给分不好说，我的线上作业缺的非常多，但是最后总成绩也有八十多分。想水的其实可以选，而且我觉得她人也还好，课后问她什么也会回。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('686091d0b9570274df6b3fb0',527,527,'平时分给的高，但是期末考试成绩非常低只有七十多分。而且我把每次课的笔记都整理好了，自认为卷子上几乎所有题都是对的不知道为什么成绩这么低。慎选，需要你自己每节课记笔记。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('68607d79d3496c4246bbe78a',2202,27,'真的特别好的老师，上课讲的特别好，平时分也给的很透明，很公正，而且很高，无脑冲就完了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68607d68d3496c4246bbe765',877,877,'神中神无脑选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6860350cd3496c4246bb6080',1,1351,'依托答辩',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('686034a4ce7fc86faf7e6bc0',617,2694,'无需多言，只要人到了，作业提交了，不管你魂到不到，都是平时分满分。作业就一个大作业，允许ai，不像别的老师，全是习题。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686033f16993d81fe62b547c',362,28,'顶级老师，人超好，除了每天点名外，其余没坏处
INSERT INTO "reviews" VALUES('686022e2b9570274df6a1899',767,694,'真是海底捞的呀，太感谢老师了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68601f94d3496c4246bb29cd',1290,28,'欧老师超级超级好，能给的平时分都拉满了，平时u校园没在规定时间做完的话，还会延长时间，剩下差的分就是课程考试和期末考试',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68601d10b9570274df6a0319',103,6,'客观评价一下，老师是个好老师，喜欢和学生打交道，很有亲和力，人品没问题，老师是真的想教会我们东西，变着花样上课，但是你能不能把你那破加分机制改革一下，现有的加分机制是：主动举手回答问题+2，被抽点起来回答+1，坐第一排+1，偶尔碰上出勤加分。你班上那么多人，还有很多上课不爱举手的，哪有那么多机会让全班同学都把要得的平时分挣满啊，更离谱的是有个男生天天迟到，上课还不听讲，樊老师就老抽他起来回答问题（强调一下被抽起来回答也要加分），让该同学平时分加满了，而且有些同学的分都加的溢出来了，有些同学的分数还很低，到快期末的时候又顾不上那么多人举手，太不公平了。希望老师改革一下，表现好的象征性加一点就行了',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('68601c9bb9570274df6a0172',2699,2699,'天使降临人间',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68601ba3ce7fc86faf7e28dc',685,685,'同学们如果被他的大物实验报告打了0分 不要慌张赶快去找辅导员开证明重新选一个老师再做一次实验覆盖掉原来的分就可以了',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('68601a336993d81fe62b0a60',2701,2701,'老师都很好，上课既能听音乐放松也能学到知识，课程有个实践作业是和其他人组队上台唱歌或者其他音乐相关的表演，很有趣，平时签到表填完就有出勤分，但我认为这门课值得听值得学，期末给分有90以上',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686013febf6625518cd85964',103,6,'那些觉得分给的高的，我也懒得查成分。没逃过一次课，也有过回答问题的时候，结果平时分比考的还低，试问哪个老师在这样的情况下平时不会打九十分？！还有所谓的知识点，这里没有，如果想考好，去找其他的朋友要，大部分老师都是会发的。只能说选上了就受着，之后就会有好运了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6860131cd3496c4246baf9a3',828,828,'期末给分挺高的，刀子嘴豆腐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68601303d3496c4246baf92e',828,828,'小测去了就有十八九分平时分了，只要按时交作业不逃课，期末40都能过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('686012b3bf6625518cd84d1c',2699,2699,'老师超级无敌有趣😎 上课能学到很多知识
INSERT INTO "reviews" VALUES('6860122fbf6625518cd84ae5',2699,2699,'特别好的老师 上课风趣幽默 很负责任 感谢',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685f3a3db9570274df63c3b3',385,27,'虽然陈老师课上的作业会比较多，PPT多，座位还是固定的，上课激情是不那么丰富的，课程考试是不能作弊的，但是只要你都认真做了陈老师直接送分给你（很多东西都是看态度不会看分数）（两个学期都是46.5以上），你去问相关的问题陈老师都会耐心及时回答',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('685f387a6993d81fe624de43',1538,1073,'上课用手写板书不用PPT，条理清晰逻辑严密，循循善诱，和蔼可亲。作业不多但很有效，小测这些也富有针对性。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685f2074c02b652dbcc74fea',298,85,'课上是啥也不交的 课间是只找女同学说话的 恶心至极',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685ef5e5d3496c4246b43936',264,230,'神中神中神啊，遇到你就选，选了绝对不后悔，不管你是想听课学知识还是想水都选，老师的课真的很有意思，而且知道很多，也很友好，总之是神，选就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ef568bf6625518cd18601',264,230,'神中神中神！讲课会讲各种历史故事 特别有意思 完全不是死念ppt 让我一个讨厌历史的人都忍不住听 上课干别的也不会管你 平时分更是拉满…每次点名都会提前通知 考试划重点特别准确 简直是学生心中的大好老师👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ee88eb9570274df61bad3',2229,2229,'很宽松很亲和的老师 ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ee816bf6625518cd17496',2713,2713,'神中神 讲课讲的很好 人也亲和 爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ee7d56993d81fe6242c6b',360,360,'上课不懂在说些什么 这学期没急着润下学期的人机交互直接仅他一位老师可选 没力气了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685ed84f6993d81fe6240840',2227,1732,'老师人很好！！基本不点名 很认真负责 也不管你在干嘛 选她',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ed2fac02b652dbcc6cd4c',1,1351,'一楼陈继兰老师上大号说话。事情特别多，特别喜欢轴测图，要求巨高给分巨低，我通宵画的一张A3才六十分。图纸平均给分六七十。。。我看到都两眼一黑。总之赶紧跑赶紧跑赶紧跑。重要的事情说三遍。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685ed2c6bf6625518cd1429d',2258,837,'每节课签到，隔壁寇伟华运筹学课和实验课都没作业，就葫芦🐸每周都有作业，甚至放假前几节课还要可汗大点兵，抽同学回答问题，检查你是不是在认真听课。
INSERT INTO "reviews" VALUES('685ed258b9570274df6188a0',1955,194,'老师很好，讲的很好很负责，刀子嘴豆腐心。平时会说扣平时分什么的结果期末还是拉满，比如那个作业我缺交了四次老师在群里提醒我们好几次补交，我还是没交结果给了我95分！！！可惜就是苦了我室友抄了一晚上全部抄完了交上去结果跟我分数一样🤓。最爱左老师小傲娇了！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ed0c8b9570274df618487',2719,2719,'选修了尹老师的线路工程BIM技术，事少，分还可以，适合考研党选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ed090d3496c4246b3f03a',297,194,'非常好的老师，教学水平很高，上课认真负责，期末带学生复习很认真，是真的用心想把学生教好，平时不点名，哪怕学生来的很少也只是和辅导员提醒一下，不会扣平时分，期末会捞人，回消息也比较及时，ppt都会在课前发出来，问问题他也会非常耐心的解答，真的是对每一个学生都认真负责，目前遇到最好的老师，非常伟大！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685ec9656993d81fe623d83c',413,27,'老师人还是可以，就是老教师有点古板，上课感觉有点无聊。但我们班U校园普遍做的不好，老师重新开放了一次让我们补做，感觉为了不让太多人挂还是有努力的，平时分就实事求是，你都做了就高分，自己水就不高',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('685ec4abc02b652dbcc69212',2722,2722,'特别特别好的老师，年龄很大了，好像明年就要退休了，u型理论这个课也很好玩，也没有考试，就期中写一篇不限字数的总结，期末写一篇三千字总结就行了。从中学到了很多东西，非常好，最后给了95分，特别特别好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d810dc02b652dbcbf7c6e',433,28,'大一英语一和二都是她带的，平常感觉事有点多（比如英语二，一开始让小组轮流做ppt上来讲，不过搞了两次之后就没有了）但是其实感觉平时分大家给的都挺高的，基本上都是满的。上课每节课会手势签到，也会偶尔提问，不过提问即使没人回答也没事，她会自己接着回答，上课也不会巡视，坐着玩手机也不会管，课堂氛围很轻松。讲课感觉她蛮认真的，认真听的话是可以学到东西的。总而言之感觉还行',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('685d7f35c02b652dbcbf77fa',52,2724,'这门课好几个老师一起上的，当时我上的第一次课就是马老师的，内容很有意思。最后期末论文应该也是马老师给的分，这学期最后成绩有99分，感动',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d7ebc6993d81fe61c6441',1538,1073,'真的是妥妥的交大宋浩，咱们小老头的科手写板书超级无敌爽，超级可爱的一个老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d7e72b9570274df5a1811',2726,2726,'你敦哥虽然口音重，有时候听不懂他说啥，但是给分是真高，考啥给啥重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d7d29c02b652dbcbf7342',2455,241,'老师人巨好，上课温柔，反正别管了，选就完事了。（爱你丹姐)
INSERT INTO "reviews" VALUES('685d7ccbb9570274df5a1412',2455,241,'丹姐我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d7c11c02b652dbcbf7084',2729,2729,'很差劲的一个老师，不适合教本科学生',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685d7983bf6625518cc9cd91',99,99,'事情真够多了 上个选修课给自己当皇帝了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685d77f9c02b652dbcbf63c3',785,26,'阳神！！！无需多言！！！期末考的好，平时分直接拉满。ppt很有条理（但是讲课听不太懂，得完全专注），ppt真的很好！！！(很多知识点的总结和例题真的非常典型',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d7732bf6625518cc9c6e6',918,918,'无需多言，推。唯一缺点就是表达不太好，上课不太能听明白。但是平时分给满了，只要作业交了，半期也不严，当做测试，平时也不会定名，只是为了完成点名而在几个周点名，上次偶尔会让练手。值得推荐，老师也特别和蔼。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d739ad3496c4246ac4b6b',2157,2733,'上课基本不管，但期末考贼严，闭卷，四个监考老师围着你转，真想喝酒只有16周一节课是实践品酒，其他纯知识点',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685d7373b9570274df59f303',385,27,'不水，老师其实人很好，按要求就行了，事多？但我两学期平时分都是满的反正满足了',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('685d7233ce7fc86faf6f7757',1048,2735,'怎么说呢？这个老师，超级好啊，上课从来不点名，平时测试也不严格，给你当做出勤率，超级好，推荐啊。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685d707cbf6625518cc9a7d7',11,11,'老师人挺好的很和善，给分合情合理吧不算低，还是不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685cc100bf6625518cc4ad3b',2737,761,'事情多，给分不高，一堆破事，点名机制更是牛逼，一分钟以内签到',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685cbcdb6993d81fe61703c5',1332,81,'神中神，平时整狠活，期末直接让你抄手机，活爹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685cbbd6c02b652dbcba155b',2739,2739,'他的数据结构简直了，，很抽象听不懂一点然后感觉专业水平很low',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685cbb8b6993d81fe616f857',2740,1753,'老头神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685cb3f4ce7fc86faf6a11ea',417,417,'给分太低，期末改卷苛刻，考勤只要请了假不管什么原因直接扣两分。没见过这种老师，遇到就有福了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685cb3f1b9570274df54883e',417,417,'课非常无聊，作业非常非常多，PPT内容非常非常多，期末不划重点，说全面复习。改卷非常非常严格，非常非常糟糕的一门课',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685c9c256993d81fe615ef77',540,1897,'老师真的超级有耐心，讲课也很细，非常非常负责任',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685c626d6993d81fe61520eb',685,685,'不清楚必修情况，但老师人上选修课真的很好，讲的很清楚，分数也很高，选修的话不用担心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685bfabdc02b652dbcb6a1d7',2745,2745,'wcnm',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685bf962ce7fc86faf66e1fb',2229,2229,'一学期做了六七个课设，还全都是没接触过的，给分也不咋地，选了它就有福了，整天要么花钱找代做要么焦头烂额学吧，还不定时签到',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('685bf917b9570274df514f16',359,228,'讲真，但凡用点心，平时成绩会很好看的。相比于一些误人子弟，表达能力存疑的马原老师，这位还是很推荐的。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('685bf8756993d81fe613984d',2745,2748,'每节课点名，一学期做了三个课设，期中还要上去汇报，说下学期的课设做整个交大的可视化地图，数据集都找不到一点，考试重点也没有，上课全部放脑瘫英文视频，还爱说教',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('685bf2a3d3496c4246a37b2f',22,92,'无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685bf0d6ce7fc86faf66a7ad',563,228,'先说，浦老师真的挺好。被优先到刘丽娜班上，换课只能选到他了，看风评不是很好，战战兢兢去上了几节课，一开始会抽人回答问题，会在课上讲自己的求学之路云云，但是并没有很过分……第三周往后就是稳稳的幸福☺️在msj和lln疯狂布置作业、强制记笔记的对比之下，浦老师没有给一点课余的压力！期中考试都明确说明可以使用手机，课堂回答问题和大作业展示都是自愿（课堂加分就是站起来读一段ppt上的字）而且每次自愿行为不论难易浦老师都会给予很大的肯定，认真对待你的展示，会对每个自愿的学生说谢谢你……你要是以为我是那种积极性很强的人那就大错特错，在我狗了一学期没有一次发言的情况下，平时分90！！和蔼又认真工作的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685bbea5b9570274df4f8d94',2157,2733,'上大学最低的一科选修 作为选修课能比正课事多，而且竟然还有期末考试 一点不水的那种期末，正课考试 期末和平时成绩五五开 逆天 不知道这个课为什么这么多人抢着选，对那个平均分保持怀疑态度。上课墨迹，每节课都有各种任务。点名签到扫码签到都有。期中课堂展示，点评的时候很凶而且把每个人都骂一遍，我们组很认真在做，结果她还是鸡蛋里挑骨头，把专业问题刨根问底。然后很高傲地给了个60分，注意这个组评是给小组内每个人的。最后的期末更是逆天，给一千多道题，安排考场，抽考其中一百道，内容涵盖地区时间品种等，难道我一科选修课还要抽出来提前一周时间备考呗😆😆😆据说班里还有挂科的，不是天天不来上课，就是单纯各种扣',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('685bbdc6d3496c4246a1ea13',586,24,'李老师真的讲的很好，每周都有作业，还会批改，特别有助于学习，讲课也很幽默',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('685b8bc9b9570274df4dd3ba',1065,1065,'感谢蔡老师送来的满分小组作业，蔡老师马院第一好～～～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('685b76ebc02b652dbcb2aad8',359,228,'纯纯出生，平时各种找事情，作业也留一堆，逼事多的要死，平时分还低的要命，只能祝4000+😄',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685b6405bf6625518cbcb2c0',385,27,'平时分需要上课回答问题才会给满，上课一般，学不到什么东西。会抽人回答问题和读课文，事比较多',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('685b5f8f6993d81fe60ed94d',188,188,'老师给分完全按照给分标准来，课堂能积极发言，一学期回答六次以上的问题且无旷课记录其他正常就基本满分，可惜我只有三十多分，怒而给出111的差评😡😡😡',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685b5233ce7fc86faf61d6e1',2119,2119,'五分只是活水的极限，但不是邱老师的极限',5,5,5,15,0,0);
