INSERT INTO "reviews" VALUES('685ada79c02b652dbcafc956',2582,790,'除了必须选他的课之外，每门可以选的课都选了老马，中规中矩的评价是上课讲的还算不错，喜欢吹牛，认真听还是有收获，有作业、课堂抽问也就算了，要命的是期末复习，勾一堆不考的迷惑人，太难背了，每次考试只有一半多一点是背过的',3,4,2,9,0,0);
