INSERT INTO "reviews" VALUES('68594b8abf6625518cb1a2d5',2582,790,'说实话，老马算好的老师，你认真听课还是能听到点知识的，期末画的重点多是事实，但平时分给的还算可以了，期末好好背拿的分也不会少',5,5,5,15,0,0);
