INSERT INTO "reviews" VALUES('68580725d3496c42468cab44',2299,2236,'温和，宽容且负责。显得的同你交一帮除了装蒜和使绊子之外啥本事没有的老登格格不入',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68580161bf6625518caa1a58',2172,2172,'考试不画重点你让我复习牛魔呢，满大篇的内容无从下手，内容又多又杂，是我是教授还是你是教授。牛魔的快玉玉了，每天啥都不干就瞎bb给你复习去了，避雷，狠狠避雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6857fef96993d81fe6fc4aa0',2172,2172,'期末考试给我哥们复习玉玉了，下次别划重点了',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6857c9e6d3496c42468afe07',2603,653,'正常老师，不说很好，但是相比某些老师绝对算是差中最优解了',3,3,3,9,0,0);
