INSERT INTO "reviews" VALUES('6857c9006993d81fe6facd33',86,86,'建筑各班一起评图评分 我们班老师都没说什么 直接给我们班低分斩杀 曹老头真有你的👍',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6857abf1bf6625518ca78feb',280,280,'老师特别好！！！带的我们瑜伽，因为前一个老师要退休了。平时课上会做些让我们放松的简单瑜伽，期末考试是小组编排表演一个瑜伽舞蹈，老师给分很高。上个学期的瑜伽老师给分特别低，特别无语。但王老师给分特别高，从来没想到能拿这么高的总评！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('685799c96993d81fe6f954ec',427,427,'离人很近，离神很远了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685797f36993d81fe6f94827',86,86,'跟孙笑川坐一桌去吧',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('68578c96d3496c4246894229',2172,2172,'主播主播，物流专业有没有特别逆天的老师？有点兄弟有的，冯春，与李国旗并称“龙虎双边的男人”。上课讲风水，给你从九里讲到峨眉。点名频率很高。随机抽人回答问题，抽到了就逮着你一直追问。你看他上课笑嘻嘻，期末你就老实了，没有重点，全英文课本五百多页全考，期末卷子也是全英文，还有高贵的斩杀线，不给你说平时分，看你不爽直接平时分就没了或者很低，卡着线让你挂。很难想象这是个人，这门课还没有其他老师，根本跑不掉',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68578a03b9570274df366771',2298,2792,'来了来了，物流专业超级战神，我愿将其与冯春并称为“龙虎双边”，天天上课讲他那往昔峥嵘岁月，时不时就找个人起来聊天，改个作业就开始说ai了，说他是能战胜ai的男人，你用了ai做作业就是没战胜ai，那我直接顺从了。期末重点更是说得比马赛克都模糊，还跟PPT一点关系没有，真是神人',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6857885fce7fc86faf4c6a2c',2582,2793,'没开玩笑，物流专业看到老马不笑的都是神人了，每门课期末经典几百页PPT，每一章给你留一点点不勾，其余全勾，考的又偏。考前说一句“我不勾的不一定考，考的一定在勾的里面”那肯定啊，直接勾完了，不在里面就奇怪了',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('68578716bf6625518ca69564',2169,2780,'怎么给我改闭卷了，八百多页ppt最后一周发，一章九个大标题给你勾了七个，你就背吧，改卷还贼严。但是平时上课挺水的没得，有一两次作业',3,3,3,9,0,0);
