INSERT INTO "reviews" VALUES('6856f66dce7fc86faf4a038e',86,86,'最水的专业课，学不到任何东西，每天就是被cy进行打压和pua，老师最喜欢在qq群转发营销号说计算机行业不行的文章。。。。很多行为简直无厘头，除了折磨人想不出其他意义',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6856f59cd3496c424686af51',1377,26,'老师人很好，给补交作业，但是上课照念ppt，建议自学',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6856f581d3496c424686af21',86,653,'一个人就可以拍全家福的老师
INSERT INTO "reviews" VALUES('6856f524c02b652dbc99739c',86,653,'对人性和心境的考验',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6856e5f76993d81fe6f65444',19,2812,'平时分略低，有期中考试但是只占5分。另外，总是上课前不久才说是实验课要带电脑，还在上别的课下课又赶回去拿电脑。。。',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('6856d57bce7fc86faf499612',83,83,'遇到莎莎姐你就偷着乐吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6856c838ce7fc86faf495339',58,55,'我不认为老师上课任务多，虽然确实很少让一直休息，但是跑圈热身可以走，上课可以带耳机，只要明面上过得去跟着做一做动作，老师都不会管你，下课也还算早，起码周围一起上课的班里算早的。至于期末给分高低完全看认真程度，大一打太极，可能标准了才分高，一般的85，大二的内容基本上你能自己顺下来，动作没大错分就90了。如果觉得难，只能说武术都这样。这个课也经常让自己联系，期末前一节课自由复习，还给参考视频，抽出一节课时间好好顺一顺，也不至于过不去，毕竟一段操顶多四分钟',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6856b9fed3496c4246859878',2078,2815,'物流工程专业讲课最好的老师，没有之一',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6856b8036993d81fe6f5638d',2172,2172,'冫春',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6856b76f6993d81fe6f55fb0',2582,2817,'平时还好，期末特别恶心。重点多到爆炸，最喜欢划大范围重点，考偏的小点，你第一眼觉得是重点的，一定不会考。
INSERT INTO "reviews" VALUES('6856b1b7bf6625518ca2fe92',2172,2172,'你说的对，这就是冯春。课程是被垄断的，上课是讲风水吹牛逼的，考试是不给重点全考的，试卷是全英文的，期末是有斩杀线的，成绩是随心所欲的，上课每节课都要点名的，最后一看成绩。啊啊啊啊啊啊啊啊
INSERT INTO "reviews" VALUES('6856a7f6b9570274df327b5b',2819,28,'无须多言 ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68569ce0d3496c424684bea0',51,375,'我选的同一个老师的心理学与生活，每节课都点名，不过不太管你在课上干什么。要做ppt，认真做会给九十多分，不认真会让你重新做。期末考试按要求让老师看出来是自己写不是纯抄AI就可以了。总体来说比较宽松，稍微认真一点就行。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('68566399c02b652dbc95d5cc',2821,40,'想拿低分的可以选了，平时作业一大堆，给分还低，其他班老师几乎没啥任务，这个老师会让你们做各种讨论，还有各式各样的小组视频作业，中间有一周休息还能布置作业，作业几乎周周有，特别累，给分不如其他班全程摸鱼摆烂的同学高，别选别选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685658346993d81fe6f25d5f',118,118,'老师讲课水平很高，不过说话有点奇快，不坐前排可能听不明白，讲课没有PPT全是手写其实有利于跟上他的节奏，但是考试复习有点难受，期末会捞人，平时成绩也算是不错了',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('6856485b6993d81fe6f1e828',1128,611,'我上的是他的职场英语，老师很佛系，上课比较水念PPT，会点名和提问不过回答不上来没啥事情。课后作业不会通知和提醒需，要你自己注意。总体事情比较少，期中期末一共两次小组汇报+一个mooc学习，平时分给的也还可以。',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('68557e9eb9570274df2c3632',22,92,'我不允许任何人忤逆你。除了半期基本都给满。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68556c686993d81fe6edeec5',58,55,'教学耐心，课堂也比较轻松，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68556ad1d3496c42467e3818',976,281,'课堂轻松，通俗易懂，深入浅出，选到就偷着乐吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68556a2ebf6625518c9bf32f',903,2155,'上了这么多专业课才懂老师的含金量😭😭😭，教学水平没得说😭😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68556900bf6625518c9be384',383,138,'可以感受到老师很负责，但是作为一门专业课，老师的讲课水准真的不敢恭维，PPT也是完全毫无章法，不明白这个课存在的意义是什么，干脆让大家全都上网课最后去考试算了，不知所云',2,1,2,5,0,0);
INSERT INTO "reviews" VALUES('68553cb1bf6625518c9aa3fd',2829,2829,'老师很随和，总是笑眯眯的，不管画成什么样都会得到老师的夸夸，然后会温柔地指出你的不足，讨厌画画，但是喜欢周老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68553c17bf6625518c9a9fb0',86,86,'这是一场精神层面的打压，控制，侮辱',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68553acc6993d81fe6ec963f',1377,26,'老师喜欢签到和测试，课堂上偏严厉，但是人还是很好的，挺好说话的，好好上课至少会拿到一个不错的平时分的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68552b44bf6625518c9a21fd',103,6,'怎么说， 你要是每节课都不来的话就别选，只要有正确的态度平时分就是满的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6855286fc02b652dbc8ef6b0',214,36,'快跑，破事一大堆，上课还抽问，我见有个女生每节课都被点，就纯搞针对，无语',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685523f3d3496c42467c3ff4',177,177,'我是来蹭课的
INSERT INTO "reviews" VALUES('6854fb41c02b652dbc8d78c6',103,6,'别洗了，事实上就是很麻烦的一个课。作业不能用ai，每节课都到且回答问题才有可能平时分满分。装作很开明实际上只是表象罢了，小测的要求基本上就是要你完全认真听课，对于主课都不一定做得到。期末考试也不划重点，别人老师都给划，就给个视频自己看，我自己也会找',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6854ef53ce7fc86faf3d22d1',799,2836,'神中神！开学第一节课就说，考勤他抓得不严，自己去图书馆自习之类的也可以。平常完全不用去，学期内两次小作业，期末一个大作业，用ai半小时搞定的程度，绝对的好老师！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6854432ac02b652dbc8a1038',2507,81,'改好了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68542d60bf6625518c949875',2737,761,'破事多，真的破事多，作业也多，很烦',1,3,3,7,0,0);
INSERT INTO "reviews" VALUES('685425f5d3496c4246772b70',103,6,'老师很严谨，想平时分拿满分的同学可以考虑选，主动回答问题，坐第一排都有加分，全勤一定会吃到随机掉落加分。每周主动回答一次一定能拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6854243ec02b652dbc897c00',103,6,'认真负责的好老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('68541a36bf6625518c9420e5',1282,1322,'太累了，而且给分不高，吃不了苦的最好不要选这门，老师人还可以',3,4,4,11,0,0);
INSERT INTO "reviews" VALUES('685419c1ce7fc86faf393705',2842,2842,'难评，上课老是提问，不会就算没来，讲的中规中矩',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('68541442ce7fc86faf390b3d',2843,2843,'Lily老师是我遇到过的最恐怖但最负责的老师，我的英语水平是读写障碍级别的。pre非常多还要脱稿，她发现我有困难，允许我不脱稿，但相应的我的得分会减少，而不是直接零分。我的汇报两次就通过了，因为她不仅指出你的问题，还会告诉你应该怎么解决。Lily老师尊重每个人，不敢举手的，不经常举手的，尝试了她就会笑着鼓励，可能大家收获不同，但是她能保证在她的课上每个人都有收获。我看到有些不是专业课的同学评价，如果你想要上轻松的水课，那一定不要选她，但是如果你真的想学英语，她一定能给你带来收获。她给的每分都是你的努力。她不是一个委婉的人，但她能准确指出问题并告诉你怎么解决。这条留给我的后辈们，她是一位好老师。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('685407216993d81fe6e56c15',491,23,'神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6853f20e6993d81fe6e4e282',99,99,'交通美学屁事巨多，一堆小组作业，定位签，上课答题😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6853f0c1ce7fc86faf381f03',2121,2121,'两个学期上了他32个电工电子实验😃😃😃成型人的噩梦👍👍给分无情，不懂变通，为人冷漠😡',2,3,1,6,0,0);
INSERT INTO "reviews" VALUES('6853e171d3496c4246755772',103,6,'也不多说，自满到极致',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6853ddbbce7fc86faf379b1c',103,6,'作为一个年轻老师，老师对待教学的心思非常认真。在最后的一周本没必要上课，但还是考虑要名正言顺的捞一把平时分低的同学，增加一次小测，考的还是平时上课一再强调标准答案的问题。而且最后还提供给了同学们复习的资料。毛概本是让人接受先进思想，强化政治素养的必要课程，但是水的人多了反而认真对待的就成了异类。可哀可叹。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6853d9c7d3496c4246752088',99,361,'其实评价交通美学的同学是没有见过另一个讲交通美学的老师，跟那个一对比这个简直天堂，一共才四次作业，只要求小组汇报而不是以个人身份，最后还不用彩打，另一个老师要求打印一打作业，真的这个简直天堂，而且老师还很好说话',1,5,5,11,0,0);
INSERT INTO "reviews" VALUES('6853d89ebf6625518c925242',2574,2850,'老师超级超级好！上课即使我们在干别的事情也不会说，会画重点，非常和蔼可亲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6853d1e1c02b652dbc874832',2851,837,'严格按作业给分，给分低，出的试卷难，跟学生说话没耐心，高高在上，不点名',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6853bbf1d3496c424673f122',922,762,'十七周 在所有老师都停课的情况下还要求上课测验你就来吧一来一个不吱声。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6853b45abf6625518c9107d0',2631,198,'作为新来的老师在讲课方面有所欠缺，作业多，适合自学能力强的同学，但是老师人很好，平时分也给的很高，不刁难人，我平时分接近满分😤',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('685399c76993d81fe6e24430',546,880,'感觉这老师有点仇视学生，上课点名，讲课枯燥，还觉得自己掌握学生的分就因此高高在上的，小组作业各种找你毛病，平时测验内容是她上课说的话，查答案都查不到，反正就是狠狠地压平时分。讲课时还要下来到处像雄狮一样巡逻审视领地，想偷偷玩手机的同学要注意了哟',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685393ee6993d81fe6e21908',2637,1265,'小组作业的形式真的让人不得不吐槽，美其名曰一定要组和组之间分开差距，一定要给出得分差距，带来结果就是班级平时分很低
INSERT INTO "reviews" VALUES('685392966993d81fe6e211a7',1596,52,'遇到你就跑吧 没有一节课不拖堂 也就是照着ppt念 给分也低 三节连堂只下一次课 然后还能拖15分钟堂 饭都没得吃',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('68538addbf6625518c8ff3fb',349,194,'喜欢贵子',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6852f6bbbf6625518c8d741a',1377,26,'讲了如同没讲，离了PPT就废掉武功了，给分低，次次签到，爱测试',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('685290b5ce7fc86faf301758',499,194,'老师教学水平很高，讲课逻辑也特别清晰，而且每次上课都会把上次的内容复习一遍，每一大章讲完也会有专门的复习ppt(考前看完全够用)。不过点名次数比较多，建议不要逃课。
INSERT INTO "reviews" VALUES('68526f8ace7fc86faf2eeb2e',2860,2860,'nc一个，课水作业多还杂，每个星期都要交ppt，期末说是允许你补交作业，七十根本交不了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68523ff9d3496c42466b3dd6',2861,394,'交运少有的男屁事经',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68523fba6993d81fe6da53f2',2861,2862,'大四的限选课挂了四个人，说好可以交请假条交了又不认',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68523f36ce7fc86faf2d975f',2861,2205,'作业课设给分低，大四点名严格，差点因为他无法毕业',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68520a7ac02b652dbc7c0288',193,193,'啥掉一个 上课不让玩手机跟打游击战一样 一干点啥就用平时分压你 骚操作一堆 上课抽人课堂表演唱歌不唱就扣你平时分 期末也不画重点 上课照着ppt念讲句话还得寻思半天 没吃过的史的可以来上两节他的课哈老子一分也不想给',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685195e66993d81fe6d745a3',1503,1450,'他们说的是真的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685146986993d81fe6d51334',586,24,'振动力学A真神！无懈可击 ！上大学到现在少有的讲的清楚课的还幽默亲和力强的老师！
INSERT INTO "reviews" VALUES('68514336bf6625518c82fbb6',476,476,'讲课非常无聊，作业很多，然后喜欢点评任何他不喜欢的实物，有点重女轻男（态度完全不一样，女生问问题，同学还有不会的来嗷，男生问，你先下去……）',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('68513674d3496c4246657bfd',369,66,'最有病的体育老师哈，一个学期三分之一是代课老师，登成绩极其不负责任，线上也几乎联系不上，考试很严，均分至少比年纪大的老师低十分，谁因为流量选他这辈子有了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('685130ee6993d81fe6d4588a',353,2869,'划重点唯一真神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('685103d2bf6625518c80e53c',2775,2775,'神中神，老师甚至因为我们不听讲请我们吃饭😭，我有罪😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68510233ce7fc86faf2620e1',411,36,'事情挺多的，每节课都要签到，有很多小作业要水，期末和其他老师一样要写论文和小组作业，所以没什么指摘，不过他的川普我是真的听不懂。每次会有课堂发言 可以加平时分，平时稍微认真点给分就挺高的，我的平时分他给我给满了，100分。总结就是认真一点多举手发言，每次小作业正常写，得分不会太差',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('6851014eb9570274df0fcfbf',751,1652,'或许这就是聪明的具象化',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6850fbbe6993d81fe6d2c0e7',42,43,'名     胜     古     迹',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6850f10c6993d81fe6d27a3b',54,54,'认认真真做结果给了我很低的分',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6850f013bf6625518c806040',978,5,'个人意见，评高等数学。老师人很好，期中期末会带着复习，平时线上答疑也及时，能感觉老师很负责任。平时会布置线上预习，可以搜题直接水过，个人感觉作用不大。上课签到可以直接微信小程序进入，不一定非得扫码。每一单元都有课堂检测，取两次最高分。给分高是因为老师人好，但是平时上课都是自学的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6850ef2dbf6625518c8059f1',64,64,'没有主人的可以来',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6850e08ab9570274df0eebb9',209,209,'谢美俊nmsl吧，csb',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6850dc1dbf6625518c7fcffa',2878,28,'无敌',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68503ec2c02b652dbc725ab2',526,1554,'纯纯臭sb一个，劳资画了半天就没标剖面的方向得了个B，别人画都没画完都有A-你是人啊，我cnmlgb的王宁，你这种出生就不要来教这种科目行不行，本来就很费时间还遇到你这种出生，每次都要我画三四次，逗我很好玩是吧，为什么别的老师给的分高没人挂科作业又少呢？cnmlgb的王宁',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6850330f6993d81fe6ced96e',598,27,'干妈，平时分除了课程考试没法改，其他全部拉满，yyds😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684ff0cbb9570274df098489',64,64,'看到大家这么多差评，我很痛心，王璐明明特别好的一个老师呀，课堂上他讲课风趣生动，课后还会贴心的给我们布置很多作业，让我们练习，作业都特别有趣，每个周都会让我们小组的三个人聚在一起讨论非常有实用价值。而且学校的每个大赛他都会提醒我们关注，会让我们去参与，如果我们不参与的话，他还会积极的督促提醒，一定要让我们参与，而且这个是算在考试成绩里的，所以大家也都会呃非常积极的参与，然后认真作答，然后这样也能给大家带来很多奖项（参与奖），王璐真的是一个特别特别好的老师，你们一定要选他的课，你来交大不读王璐的课你就是白来了交大。上述都是我的肺腑之言，大家千万不要被那些打1分的给骗了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684fe7f2bf6625518c7a7f55',932,932,'一堂课总会像个NPC一样重复一句话:有些同学，来了不好好听讲，带个耳机看自己的巴拉巴拉一大堆。有说这话的时间不如好好练一下普通话，操一嘴极其抽象的川普，作为一个四川人都必须要非常集中注意力才能听懂他在说什么，川普说成这样谁听他的课呀，看网课还要被他蛐蛐。上到17周都结课了就他不结，一星好评了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684fd8aec02b652dbc6f19bf',1596,52,'认真写报告和报告上内容写对点是两回事，嘻嘻嘻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684fd6ab6993d81fe6cb7805',2500,228,'不多说，平时分满昏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684fd6896993d81fe6cb7717',2885,40,'不多说，平时分48.8',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('684fd1b0c02b652dbc6ed4b1',271,2499,'老师上课认真，基本上全是板书，但是鼠鼠水平低下，完全听不懂在讲什么，此处的懂不是指课程太难了而不懂，纯粹是对丁浩老师中文发音的叹为观止，吞字严重，关键词小声嘀咕，说给自己听，衔接词修饰词倒是重音强调，一瞬间梦回本鼠跟八十太姥的交流场景，期末考试重点等于没画，不考原题，选课的uu们做好自学的准备。',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('684fcfd1d3496c42465c7262',2596,1409,'老师严是挺严，但正常的话分数不会给低，至少不会故意恶心人',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('684fc99fbf6625518c7973cc',1095,1095,'司马的玩意，开学的时候说期末考试特别简单，闭着眼睛都能考九十多，结果学期过了一半了自己把开卷考试改成闭卷，还来压平时分，平时作业也不批，到学期末了要求学生把以前交的所有作业重新交一遍，那破东西谁能从三月留到六月啊，留着给你妈上坟吗，也太爱你妈了吧，妈了个逼的，明明自己批个作业就能解决的问题，上课的时候信誓旦旦说回去批结果又嫌累不批了，既然你不爱看那就把作业都烧给你妈，让你妈在阴间看看他阳间的儿子能干出多阴间的事，让你学学好早点去阴间陪你妈',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684fbb1dd3496c42465bc293',1481,2889,'非常非常非常非常非常好的一位老师！最好的霞霞姐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684faebbb9570274df074d2a',571,81,'就选它！老师超级好，期末划重点很仔细，平时分给的超高！很难不爱啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684ef57cbf6625518c74d60a',1941,86,'水中水，来了就是混日子，往那一坐就是玩手机，也是活明白了，给分也是随便给，所有人一个分，随便抽一个给高分，在打击积极性方面有着巨大贡献，本来就不多建筑的热情一干二净。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('684ef3f1d3496c424657b45b',245,245,'事多分低的代表。说话好似谜语，，听不懂；想法好似变脸，赶不及。经典建筑学艺术家们的风范，想学到什么是没有的，想发展什么是不可能的。只认大师和案例，排斥技术和工具。不要提什么从游戏中来的想法，只需谈及大师们的作品。建筑学院当下的缩影',3,3,1,7,1,0);
INSERT INTO "reviews" VALUES('684ed643d3496c424656eb51',12,4,'老师非常非常好，专业亲和，分数也高，闭眼选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684e718ed3496c4246540567',2241,2241,'上课感觉这个私人就很扫码，嘴臭事多天天说要挂人。还没给期末分，如果这条评论还在说明给分确实很低，那这条慕⭕就是扫上加扫',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684e523ac02b652dbc657449',2895,92,'纯傻篮子，自己弄掉学生的请假条反过来怪学生，头一天布置作业没说要收第二天又要交，上课事比高中老师还多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684e4ca9c02b652dbc65556e',1596,52,'不是哥们？大学物理实验你有认真给分吗？ 我上课几乎是前几个做完，数据你检查了还让我修改了，认认真真写完报告你给打55分？',1,1,1,3,0,0);
