INSERT INTO "reviews" VALUES('684d7a87c02b652dbc61b418',2843,2843,'lily，我想上早八',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('684d4d736993d81fe6bcefba',1282,1282,'老师真的超级温柔啊，上课特别有活力特别温暖🥹上一节课感觉活人味都上来了，我给亚亚老师爆灯！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684cd246c02b652dbc5cbbba',23,23,'天使老师！人美心善，处处为学生着想，不仅激情讲授C++，还教做人做事，跟着刘霓老师学，轻松高分，yyds！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684cd124d3496c42464a404b',214,36,'能run就run吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684bf82dc02b652dbc585af9',513,66,'脾气爆，比潘宏还会训狗。辅导员叫请假他都不干。冷不防考跳绳都不事先通知，拿学校的烂跳绳跳了一次就再也不补测了。每节课机械性地反复练习，动作姿势不到位也不提醒，练的时间比另外两个篮球班多多了。动不动就板着个脸，没事就吼，给分超级低，对分数有问题还不能问他。晚上九点后给他发消息不但不回你，下节上课还要骂你。啥事都交给队长，上课时自己就坐在那里混工资啥也不管。经典名言：“你每节课都来上了我凭什么要给你平时分满分”“就算是校长都没有权力因为搞活动把我的课请掉”。没当过狗的可以来体验下。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684bda16ce7fc86faf07a465',2058,230,'老师人超级好，只要偶尔定位签到，线上智慧树做了就好。最后一节课会画重点，还会想方设法为同学减轻负担，选到老师有福了!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684bd9986993d81fe6b3fd7d',54,54,'恭喜你成为我所有实验的最低分🥰🥰为表感谢给你也打一个最低分相互尊重吧',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('684bc537d3496c42464477b8',2281,2281,'别选，讲个课又木，发作业是不定时的，交作业还必须定时，作业的量完全随心情，又恶心又多，还不让补交，补了也扣分，就是想方设法把你平时分扣光，',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684ba452bf6625518c608031',162,419,'上课不让玩手机，一直抽人回答问题，期末不画重点，谁选谁有福，水课这样子，我专业课都没这么严',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684ba37ed3496c4246435b8e',2637,1265,'整个班平时分都六七十，上八十的不超过5个人，必须回答5次问题才能满分，别的班回答问题都是额外加分，选了她的课你就是次次出席也拿不了满分出勤',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('684b9e45c02b652dbc55b69e',2121,2121,'做过的都说好',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684b9a89bf6625518c6033c0',884,2911,'一坨，还自视清高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684b9a0fce7fc86faf05d34a',884,2911,'我没上过ct的课，但是一定不要选她的毕设，屁事多到想跳楼，答辩完半个月依然让改论文，还想着剽窃学生的成果，没有任何规定要提交源代码给指导老师，三番五次问我要源代码',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684b98d26993d81fe6b20a3c',725,40,'给分特别低，快跑！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684b9016c02b652dbc551f45',161,161,'避雷这个大冤种老师，上课几乎不讲课，平时作业就是做PPT，短视频，最好的大作业让做审单系统。最最最重要的是，他从不讲课，上课全让同学讲PPT，做展示汇报。期末不画重点，把没讲过的PPT都给你，让你自己复习。真是林子大了什么老师都有，奇葩一个。如果不是必修，马上逃离这个老师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684b0086c02b652dbc52adfa',2915,2915,'形策千万别选他，差得要死，天天换着法的点名，从没见过这么事多的形策老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684af6d2bf6625518c5cea9f',214,36,'拿着鸡毛当令箭，在自己的职权范围内尽最大可能为难学生，有种占尽时代红利高高在上的感觉。作业是布置不清楚的，通知是人看不懂的，提交的作业文档是不会打开的，对学生的专业是指指点点的，形策是认真监考的。
INSERT INTO "reviews" VALUES('684ae8eab9570274dfeb8278',2371,80,'没找到这老师的结构力学，想说这老师的结构力学讲的简直一坨，解释地不清不楚，ppt也写得特别不详细。作业也多',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('684adbf0bf6625518c5c3aa7',196,196,'伟大无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684aca00d3496c42463eb013',971,24,'上课主讲PPT 定理和例题都有黑板的推导 我认为这种基础学科要是老师纯照着PPT念就差太多了 但许老师带着推导的过程其实就很好 线下的答疑也是煞费苦心 线上习题去问也是手写一遍过程给你 只要不缺旷 作业不缺交平时分也毫不吝啬 是我遇到的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684ac990c02b652dbc512f8f',1341,114,'乐',1,2,1,4,0,0);
