INSERT INTO "reviews" VALUES('684aabc8d3496c42463daeb1',2058,230,'说话温柔，上课不像某些老师无自知之明恶心人，非常善解人意',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684aaa65b9570274dfe9868d',344,803,'很好的一个老师。作业不多，评分清晰。讲课认真，吐字清楚。上课非常舒服。',5,5,5,15,0,0);
