INSERT INTO "reviews" VALUES('684aa47cbf6625518c5a7327',2136,313,'精华二字，别选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684a5fa36993d81fe6aa3af1',802,706,'上课声音小，期末重点如划，qq群也不建一个ppt也不发，还有个50分斩杀线，期末低于50直接斩杀，能不选就别选吧',2,1,3,6,0,0);
INSERT INTO "reviews" VALUES('684a5847ce7fc86faffdf917',214,36,'上的形策课，考试不让用手机',2,3,1,6,0,0);
INSERT INTO "reviews" VALUES('684a52ddd3496c42463b0898',604,96,'上课认真跟着他走绝对不会挂，给分很不错，但是口音严重，冤枉学生上课玩手机',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('684a525cd3496c42463b0582',2937,2937,'最歹毒的老师没有之一，巴不得所有学生都挂科，上课讲的稀里糊涂，期中考试不通知开卷，要求还特别多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684a3bfe6993d81fe6a91ebe',785,114,'非常让我难忘的一位四川的老师！！大一高数上下都是阳老师带的，引领我们走进了数学的大门。他上课力求用自己的理解，讲每个公式背后的原理，推导的一清二楚，板书也很有特色，虽然谈不上漂亮，但是井井有条，逻辑清晰。他非常认真，希望我们都认真学高数。如果你一直在后面玩手机，他会亲自上前提醒。最后我们整个班数学竞赛省赛的成绩非常优秀！！离不开阳老师一年为我们打下的基础。最后一节课讲到罗素谈数学，那种严谨之美，讲的非常棒，阳老师的体悟很深！非常难忘的高数老师，冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684a39adb9570274dfe60174',491,23,'为什么都给刘霓打分，没人给我们刘倩打分！！现在我是大二下了，回首大一上教的计算机程序设计基础，特别感谢刘倩老师，人温和，ppt精美，上课认真负责，同学的问题qq及时回复。她上课之前会放一些歌曲，印象最深的是《篇章》这首歌，非常感动！后面打蓝桥杯的时候请教问题，她都及时回复！一个好的老师，领我走进了计算机的大门，让我们班同学对计算机感兴趣。直到今天，都非常怀念大一计算机刘倩老师和高数的阳锐顺老师，可惜回不去了！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('684a378b6993d81fe6a8f20a',2940,2940,'wxl就是神，其实不是，其实是，很牛！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684a35a3b9570274dfe5da75',1105,185,'严老师又帅，讲的又好，科研水平也很高，人非常和善，儒雅。你可以随时在qq上找他问问题，他没回一定是没看到。上课不光会把知识点讲的非常透彻，还会给你联系实际讲故事',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684a33f3b9570274dfe5cccf',1023,188,'老师讲课真的很好，完全可以一整个学期听她讲课而不感到枯燥，一学期下来也会有非常多收获',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6849a5acb9570274dfe36fe8',36,2943,'之前因为看到那个交大张VV的评论就对这个老师挺好奇的，还是比较喜欢这个老师。
INSERT INTO "reviews" VALUES('6849a304b9570274dfe360cd',24,24,'老师人好，非常讨厌同学上课玩手机，但是介于理论力学这门课程的特殊性，一定要理解老师这么做的行为。因为理论力学真的是相当难且落下一点儿就极容易跟不上的学科，再加上互联网上没有太优质的网课，也就证明对于大部分同学来说，最好最不容易挂科的选择就是每节课从头跟到尾，课下作业认认真真做，郑老师每节课都会有课前习题也会讲，提交上去的作业也都会认真批改，甚至很多细节上的东西都会给予指正。
INSERT INTO "reviews" VALUES('6849a180bf6625518c54c195',2197,876,'非常好老师，会用雨课堂，有ppt留存，讲课讲的清楚（不知道为什么神似我喜欢的一位高中物理老师），语气比较平缓，有时候会放一些有趣的物理现象科普小视频。我们这届使用的学习通留作业，作业答案的详细解析都会在群里面发，对于期中期末复习非常有用，我们这届期中考试甚至从中出的原题，感谢老师给的详细解析！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6849a023b9570274dfe35055',1454,23,'温柔爱笑好老师，上课给人的印象就是很开心，要求的全部做到平时分极高，线上线下问问题都会耐心解答，会开雨课堂，上课ppt全部都有记录，如果有哪些知识点没懂看看ppt、问问老师都容易搞懂。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68497ee2d3496c424636d944',2940,2940,'拉满了的含金量不必多说',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68497e62bf6625518c53da60',1641,1641,'传奇王阳，装货',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684976e5ce7fc86faff96e2e',1390,28,'超级好的老师，U校园每次截止前都会提醒！！口语之类的平时分都给的很好，这一年真的很高兴遇到这位老师！！我真的哭死！！至于前面说的请假扣分的事情我觉得纯自己的问题好嘛，一学期上课就不到十五六次自己请四五次的假还要怪老师？？？请假本身就是自己的问题啊？？很有理由嘛？？自己知道自己请假了就想办法加分啊，竞赛讲座什么的都可以加分，自己额外分什么都没有加就说老师随便扣自己的平时分，，，真的好无语这种没有能力还诋毁人。。总之遇到这个老师，跟着她好好完成任务绝对嘎嘎好的！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('684962adce7fc86faff8d5b3',2399,2950,'很多评论都是在说老师讲课很有趣生动，但老师优点不止这些。老师很责任的同时要求很低，老师主要严格的要求就是别缺课，每节课基本上都会点名。视频制作和课堂PPT展示只要不是很烂，都是90分往上，老师给分非常高，课堂PPT注意的就是PPT字少一点，讲的多一点，这样分更高。还有就是再次再次强调，不要缺课！老师算平时分的时候考勤不是按学校规定来的，缺一次平时分总分扣10分，相当于总评扣5分！千万别缺席。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68495ba6bf6625518c52d1b7',7,7,'神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684950946993d81fe6a4535b',23,23,'绝对好老师，认真负责，上课激情四射，容易调动大家的学习积极性，对待学生很真诚很有耐心，认真跟着学，轻松高分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684945a96993d81fe6a3e846',96,96,'非常喜欢文理歧视，上课不是在阴阳人就是在念PPT，讲的东西自己也不会捏。每周一篇作业，课上还有作业，课上作业还要让人带回去做完了交😃在听的一头雾水的情况下还要做巨量作业是认真的吗老师，教的东西和专业课毫无关系，以后就业和考公考研能用到0个，想问学校为什么要让我修这门课',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6849453bc02b652dbc4759c0',248,48,'挺和善一老头，平时分给得也不低，唯一的缺点是有些啰嗦，导致平时上课能自由打球的时间不多，有一定羽毛球基础的同学建议看看其他老师。（ps：含泪告诫各位千万千万别选彭艳的羽毛球！分低脾气也怪，天天点名，本人早退一次直接期末总分扣5分，说话跟谁亏她欠她一样，快跑😥）',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('68492e4cbf6625518c5145cc',2229,2229,'难绷哈，东西是一点学不到的，工程设计是张嘴就要的，这节课上学到的唯一东西就是复制粘贴。无论是在现实还是使用电子设备🤗',2,1,3,6,0,0);
INSERT INTO "reviews" VALUES('68492812d3496c4246341ee1',12,4,'很懂足球而且人很好的的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68492109bf6625518c50df58',99,361,'四次大作业电子版纸质版全要交，结课要手写一千字感想，每次上课都有定位签，还动不动弹一个限时小问题，想折磨自己你就来这门交通美学',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6849097cce7fc86faff5cb47',1390,28,'因为平均分高，就要扣请假同学分的老师！（假条交了，病历给力，就差手术单子没给她看了，结果因为班级平时分平均分高，就给请假两次以上的同学扣分，一下就扣掉我两分，请问我是故意要生病的嘛？我没事去医院挨刀子干嘛？）',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('6848dd1ab9570274dfdd13d0',1390,433,'说实话，这个老师上课是挺不错的，但是最让我受不了的是，明明已经请假了，假条给了，病历也给了，最后还是要扣我两分，那我开假条的意义是什么？让她拿着假条给我扣分嘛？',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6848dbdfce7fc86faff2fb18',2646,2960,'巨棒，选到就是赚到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6848ceaebf6625518c4e2c23',2961,761,'这学期坐了四个必做，一个选做，一个期末大作业，期末作业以微视频＋文字说明的形式做的，平时需要展示，会给你提出不足，可以学到东西，讲的就是如何利用图书馆或者网上的各种资源。期末不考试，点名偶尔',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6848cddbce7fc86faff29b48',51,1346,'比较水，老师也不太关心你在干啥，一学期一次演讲，一次开卷考试，但快下课时是会点名，而且每节课，偶尔一次缺勤不会计较，除了这个没缺点，讲话快算吗，要是不听课的话，好像不算唉',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6848cb7ec02b652dbc4362e0',5,2735,'狠狠捞人，但是，讲课比较天马行空，一不留神就找不到了，作业就是课后练习册，每隔一段时间需要上交',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684879c76993d81fe69f458f',884,884,'说话难听，学术水平极差，屁事多，有大bing。发消息不回，出尔反尔',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68487943b9570274dfdbd5ae',884,884,'太差了，太逆天了，简直折磨，从来没见过屁事这么多的老师。讲个课都能讲错，除了绘画列车运行图其他pi都不会。还阴阳怪气的说话，不断的贬低你，说你上了四年大学白上了。
INSERT INTO "reviews" VALUES('6848575ece7fc86faff15df1',360,360,'本次上机考试考验你读心术能力，未能成功读出老师心里所想者，总分扣3分！
INSERT INTO "reviews" VALUES('68484cd1b9570274dfdb2541',1401,2967,'还是可以选的，尤其如果其他好课没选上。课程更适合2000年初其实，那时“企业家精神”很流行，上课放《中国老总》纪录片，我觉得蛮好看（不过B站评分很低且评价真实到位）。但内容有点复读机，总在说“企业家精神是勇敢、目光长远、持续学习、身体棒……”，对冰箱、联想、360等企业家一直正面赞美.不过她人挺好，分数给力：无作业，平时发发言，期末3000字手写报告，认真写（搞好封面、字迹和引用格式）就能97、98，基本90+，任务也少。强烈推荐选《经典纪录片欣赏》！放《活着》《钢琴家》《本杰明·曼巴顿》等电影，太经典了，同样无作业，轻松。这门课感觉算选修里对学生好的了。如果能辩证、深入看待这些企业家就更好了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('684844abce7fc86faff0f380',2968,370,'别选交通美学！：
INSERT INTO "reviews" VALUES('68484258bf6625518c4c6b86',360,360,'我说怎么还有洗黄海于的，能用自己的神人阅读理解乱改编题当成上机考试期末，写的牛头不对马嘴的给ai都干投降了，全班零人做出来半期考试也是120人的班起码100人得20分，我说这人不配当老师你能反驳吗😊',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68481933bf6625518c4b3340',209,209,'相比起调不了课就建议你重修的H昊，小米椒宁愿弄几个班也不会让几个人少的班并在一起
INSERT INTO "reviews" VALUES('6848044abf6625518c4a98dd',2258,837,'我不许你们抨击葫芦，下一届的同学们也得有这个资源😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6847ff86ce7fc86fafeef620',1095,1095,'跑！！！！！！cs中的cs！！！！开卷变闭卷，真是小刀拉屁眼',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6847f68bc02b652dbc3f58e2',1641,1641,'课讲不清楚，完全没有逻辑，牛吹的到是挺高。开始几节课还以为是我能力不行，后来才发现他是真讲不明白',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6847e49cce7fc86fafee09aa',277,48,'给分很高！老师也非常和蔼，闭眼冲就完事了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6847e016b9570274dfd7d3f4',64,64,'纯头里面有点问题，最后汇总成绩以前说的所有的话，什么承诺啥的，异常情况处理啥的，全都不认，纯恶心人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6847dfc9c02b652dbc3e8cde',64,64,'别相信他说的异常处理，遇见王璐你这辈子就有了，是m属性的快点来，每周都有大论文，每周都有小签到，随时还要带电脑去定时练习。分是乱给的，人是微笑的，默认是所有同学都是爱因斯坦的，动不动是你的问题的，这老师真的应该去说相声而不是来教数学建模。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6847d752bf6625518c490b37',23,23,'很幸运上了刘霓老师的c++，人很好，认真负责，教的也好，认真听刘老师的话，期末轻松90+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6847d4efb9570274dfd77bf3',64,64,'纯SB，成功让数学建模成了我最讨厌的课，作业永远可以比你想的更过分，老师还自我感觉良好，上课讲些废话，问就是这门课是要自学的，SB，想受苦的可以赶紧来',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6847d231d3496c42462be9f8',40,40,'真的无语了这老师，过分超级扣，能跑的赶紧跑，这个老师还不如江楠，事情超级多，只要是能扣的分，绝对给你扣完了，平时分真的太低了，差评，避雷！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6847b063b9570274dfd689b8',563,228,'第三次选课期间有潜伏期 千万别以为从良了 快跑吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68479f2bc02b652dbc3ca754',46,4,'扫码了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684790d86993d81fe698dc97',271,5,'这么好的老师都给我选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('68478ed96993d81fe698c700',2983,294,'感觉和很多评论不符。平时会抽问或者轮流回答问题，回答不出来也没事，但是一学期就点一次名，迟到不管翘课也不太管吧。脾气挺好，可能人看着比较古板。我这种英语菜鸟平时也翘课作业也有晚交但是平时分也不错。本来是因为没选上课才选的这个老师，上完后感觉挺不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6846d4d9c02b652dbc38cc20',2984,361,'事多，考勤多，一个学期三个大作业，买书考试，一点都不水，想水的千万别来。狠狠避雷避雷避雷避雷避雷避。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6846c1a5d3496c424625df5d',85,85,'老师真的太好了😭😭😭给分特别高 即使不擅长运动最后得分也不低 老师人也特别特别好 对同学特别和善 有事情找他也会耐心解决不会糊弄 体育一定要选他',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6846ba5bbf6625518c42f03c',411,36,'魔音贯耳，听完一学期可以去申请工伤，签到是要拖到上课最后一秒的，把人往死饿',2,1,2,5,0,0);
INSERT INTO "reviews" VALUES('6846b2f2b9570274dfd1136c',1095,1095,'他跟乌鲁鲁坐一桌，你都分不清谁才是cs',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('684695e3c02b652dbc36d16a',2674,2988,'出生',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68468aa0ce7fc86fafe5b4b6',1095,1095,'烂老师，上课讲的听不清，脱离课本，作业全让AI做，问问题也解答不出让问ai，每堂课都让背电脑去然后也用不着，一直不让同学看手机（******你倒是好好讲啊，听了也不知所云）作业还经常让手写，本来开卷的考试还特意改成了闭卷，真是浪费大家的时间，无敌了这老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6846814ab9570274dfcf7164',2258,837,'懒得喷，讲课跟蚊子一样照着PPT念，时不时抽个幸运儿上去讲评作业，他的运筹学实验也是一坨，网课达人，AI达人',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('68467f10bf6625518c4106c8',903,179,'PPT防自学，如果想学好这门课的人，上课得一直听讲才行，下来需要及时做好笔记',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('684658ffce7fc86fafe4568b',2992,2815,'对比其他老师，真的很好了，期中直接给你了，这还有啥要的？！',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('684658ecbf6625518c400af5',2992,2815,'除了说话听不清以外，暂时没发现其他缺点。超水，没作业。很好的老师啊。对比某胡姓男子，只能说差距巨大了😁😁😁😁',4,2,5,11,0,0);
INSERT INTO "reviews" VALUES('68465837b9570274dfce596d',1273,157,'别选，气死我了，一学期辛辛苦苦给的分还巨低，我每周下课还练球够认真了吧，没用。。。。。气死我了。。。每次都比选其他课的分低好多。。。老师还说是自己最认真，广受好评，谁在好评。。我上两年真的上哭了，把我从多年热爱排球到讨厌排球课也是特别厉害了',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('684654e5ce7fc86fafe437eb',450,450,'不如去做小动物医疗的神人',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('68464fc5bf6625518c3fc2b8',2968,370,'交通美学来的。。。可能是这门课设计的原因，别选这门烂课。。。老师事也多，水课不水作业多的一比，神金。。。要不是为了美育课程学时谁选这门破课，之前也没有交通美学的评价纯纯小白鼠，快逃！！！烂课烂到根的烂课老师也烂课程也烂毫无意义浪费生命的破课！！！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('68464a96d3496c4246224194',2843,2843,'逆天东西',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6845518bce7fc86fafdebce9',103,6,'戏耍学生来满足自己的存在感',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684536466993d81fe68b5647',99,99,'快跑！！！！快跑！！！！！千万别来交通美学！！！特别爱从前到后从后到前晃，每节课都要签到还时不时微助教上弹个问题让你答，算在考勤里，一节课弹五六次！！！事还贼多，快跑！！！！！！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('68451731b9570274dfc71f05',664,664,'预习报告只看字体，不看内容，字写的不好看就是b，字写的好看了随便抄抄就是a，控分没跑哈',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('68445136ce7fc86fafd9bf23',264,230,'选就对了，上课认真听能学爽，放肆玩也没事，很照顾学生，知识渊博，非常有气质',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6844482ad3496c42461822c2',209,209,'石',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6843a051b9570274dfbeaae4',131,3003,'要毕业了还是想注册一个账号说一下。怎么会有一门选修课，你所有课都去，所有作业都交，作业也花了时间，给打60多分。太逆天了，选修课强度这么高吗 快跑 快跑 快跑 快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684301ffd3496c4246113d61',1641,1641,'做他的大物实验算是摊上大的了，一学期七个实验，其他都是85+，就这个给个60分，实验随便讲完人就不见了，上课挎着个脸，像学生欠他好多钱似的似的，数据随便看一眼说你是错的，给你画个叉就了事，真只有自认倒霉',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6842cc5ace7fc86fafd108ba',380,1897,'满昏！满昏！这学期数电由于半期班上考试的成绩都不是很理想，何老发试卷下来让我们改正，并且说根据改的情况重新半期打分，人民的好老师！爱死圣仲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6842c117b9570274dfba8ac6',383,678,'25年的评价，该老师上课自顾自讲，选她的课还不如自己看PPT，思考题从来不讲答案，只让自己下去自己想。教学能力堪忧，讲课水平糟糕，特别沉浸在自我良好的世界。助教的知识水平比该老师好太多，建议学校让助教授课。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('68428ed3b9570274dfb8bcf0',209,209,'不敢相信本班学生进去坐满了不让我做实验，然后有同学做完最后剩下半小时进去，刚连完线还没调整，就喊我们收拾走，给我打零分。平时也是十分拽，演示围成一团根本没打算让大家都看清楚，分也给的低。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('684288a7c02b652dbc1f3bc8',209,209,'真私募了纯tm出生给一分都是高的了，仪器有问题叫过来看都不看就说我电路接错了，结果他自己接法和我一模一样也做不出来，然后就气急败坏算我这次实验不过，选课的时候不管让选超，然后做实验的时候实验室坐不下就不让人家做，这不是纯他🐎出生吗',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6842821fc02b652dbc1f1116',209,209,'讲话声音小，讲得不明不白，对学生态度不好像谁欠他钱一样。我做个实验还低声下气的。做完实验啥也不会，说实话也不知道开这个课有啥用，一学期这么多节还占一点分。顺便一提还是地中海➕娘炮说话',2,1,1,4,0,0);
