INSERT INTO "reviews" VALUES('6838197bc02b652dbce07691',1350,5,'胡丽娜老师超好，上课负责讲解，管的也不是很严，想课上做作业或者干点其他啥事也是ok的，只要不太过分。最重要的是，课外你在网上问她问题，她会认真解答，无论是难的或者是那种可能就我一个人不能理解的简单问题，不像某些老师，可能就不回复那种简单问题了。',5,5,5,15,0,0);
