INSERT INTO "reviews" VALUES('68351432bf6625518cd94fa0',1250,696,'纯念ppt，一字不差哈。',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('68341488bf6625518cd3fc0f',2674,2674,'整天上个课P事贼多，根本没时间自由活动，考试要求自己不说清楚，后面去问就说第一节课就见讲过了。每天带着个墨镜垮这个脸，就和我欠了他钱一样，考试巨难，给分巨低，考试还几乎没有补测机会。差评差评差评，千万别选他的课!!!',1,1,1,3,1,0);
