INSERT INTO "reviews" VALUES('6833eb026993d81fe6249565',592,1073,'伟大无需多言，一伯昏！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6833d03dd3496c4246b45632',139,3075,'有毛病，东西都做好了我坐那画点画阴阳怪气的让我滚回寝室，玩手机的不管，逃课的也不管，老子忍着脾气上认真早八还要来说我，作业布置的和狗屎一样，明明知道我们不可能完成要靠外包还是要布置那么离谱的作业，真的恶心',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6833cfccb9570274df5f941d',142,760,'作业超多，还有那个无语的学习系统，纯恶心人，半小时的作业硬生生也一两个小时，上课还阴阳人，上个课受各种贬低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6833cfa2ce7fc86faf75df41',139,139,'莫名其妙的作业……莫名其妙太莫名其妙了，教个1+1喊我自己做高数，搞什么',3,1,1,5,0,0);
