INSERT INTO "reviews" VALUES('6831baf8ce7fc86faf6b70c8',2500,228,'袁神
INSERT INTO "reviews" VALUES('68302f37b9570274df4beaec',1641,1641,'上个课垮着个脸，和我欠了他很多钱一样，对学生要求异常苛刻，一言不合就拿挂科和扣分来吓唬人，一定是家庭不太和睦，人生不太如意，才会把怨气发泄到学生身上。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6830053bb9570274df4a9a4e',298,85,'不知道在装什么，一个体育还这么多事哈，平时上课摆烂，到了期末就开始严格要求，还怨我们下课不去练，在装什么，我只能说选了这辈子有了（文化课要是上课认真听期末不用学起码及格吧，不知道在说教什么），很未知的一个老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('682ff0786993d81fe60dfb46',1939,3082,'老师真的特别好，期末简单，可以无限刷分，也会尽力把其他分数往上提，老师也很有水平，能学到东西',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('682fc3866993d81fe60c779a',592,1073,'交大最好的高数老师，教学讲课水平很高，教学ppt也是非常的好，非常清晰。老师还超级超级负责任而且温柔，很乐意去答疑，而且不会因为问的问题不太聪明而批评人，只要问问题就很乐意。老师还非常关心学生的，我根本想不到老师认真到都能记住我的字迹。老师的价值观也非常正。真的是第一赞的完美老师，当时选钟华老师的课是我最正确的选择，以后见一个学弟，我吹一次钟老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('682f2045b9570274df4623fd',304,707,'这位老师是为什么可以上那些独属于他自己的课呢。ppt 照搬书，一字不落，甚至还有念 ppt 的时候把“逗号”都念的人。好多实验自己懂吗？问个问题一问三不知，说自己也不知道，那来要你干什么用呢？上课更是和催面没有任何区别，要声音没声音，要内容没内容，讲的都是 ppt 上的内容。就有的课还只能选他就很恶心。还呢选的赶快逃吧。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('682ea22fc02b652dbca8b62a',209,209,'您这位电子实验课的师尊可真是仙风道骨啊！三尺讲台硬是给您坐出了禅意打坐的境界，那气若游丝的讲解声，怕是用了失传已久的"传音入密"神功，得亏我们没生在武侠世界，不然都得自备助听器来朝圣。您那套"皇帝不急太监急"的教学法着实精妙——眼皮半阖着讲完公式定理，末了还附赠一句"这都不懂还学什么工科"，活脱脱把实验室改造成了《皇帝的新装》剧场版。
INSERT INTO "reviews" VALUES('682e9f006993d81fe6061f96',103,6,'老师一言难尽，选了就享福吧嘻嘻',1,1,1,3,0,0);
