INSERT INTO "reviews" VALUES('68220a4abf6625518c69892f',3114,3114,'事多分少，自己不上课，上课完全没有一点体验感笑死了，课程上下来根本没听老师讲过东西哈，倒是在慕课上认了个老师，原来钱这么好赚吗，没良心来钱就是快是吧骆小翀。最后说要写课程总结，怎么还想看我们夸你吗哈哈哈，要点脸吧。最后憋出来个课程总结，总结什么，谢谢你选的慕课吗，某人放话不写直接重修蛤，最后还要侮辱我nm,作业也是多的要死每天都在做，每次给他看都是打回，这么会设计倒是教教学生啊，上嘴唇下嘴唇一碰一闭一股臭气，除此之外就是批评，有你我真的服气。我真希望你能好好看看我写的评价，像你这种人最好滚蛋，要这个材料要那个材料，结课了分不多，钱花了不少。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6822073eb9570274dff805f4',3114,3131,'专业水平一分，不上课就是放着慕课玩手机。表达能力一分，布置作业几句话，做完了又莫名多出来一堆要求呵呵，一直改一直改，看到我评论的别说什么“自己怎么不问清楚”能这么说的也是。。怎么就你最聪明么 你想到别人想不到？？ 这个老师左右脑互搏，自己推翻自己 上周说多角度照片就行  下周又要实物，一周2-4个构成，一直不收就攒着，总不能堆教室里吧 寝室四个人根本放不下只能扔一部分。没有实物熬夜重新做了 最后说打分只看最后三个。。。有没有师德 你把学生当人么？你有尊重我们吗？想一出是一出自己开心就行了么 ，确实我们有什么办法呢呵呵，就活水给你打差评呗，反正我是希望以后的学弟学妹不要遇见这种逆天“老师” ',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6822041cce7fc86faf0d4ea4',685,685,'瞧一瞧看一看了哈！大物实验有点吃操作怎么办？没关系不用慌哈，这里只要十分一次付费咨询，赠送PUA礼包，还包售后🙂。喝喝我真氧化钙了🙂。。。去spa。。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6821f9546993d81fe6ba8f73',3133,496,'期末裸分过了，总分还能给你挂了，就因为课程设计写的不好😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6821dcd8cde6ea10ed5a173a',3114,3114,'神人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6821bfcc3f81e43d5f3c5f2b',1825,1825,'他的远动监控也别选。上课0板书。讲课让人云里雾里的，也不流畅。还喜欢点名和抽人回答问题，回答不上扣你平时分。人跟友好更是不沾边。选他的课就别抱着什么好的幻想了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6821b5993f81e43d5f3be4d3',3098,3136,'快跑吧 周末早八补课三个半小时 上课迟到罚站每节课点名 讲课一坨屎还自认为讲的很细',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6821ab5b117fb603c9b67642',1641,1641,'我是好学生，六十分',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('68216fe1117fb603c9b4bcba',3098,3098,'上课不讲书上的内容，不发ppt，据他所言："书上有的可以自己看，不讲。发了ppt你们就不听课了，不发。"。上课迟到1秒都要站后面。上课按学号坐位置，跟考试一样。在没有少上任何一节课的情况下周末补课，周六早上8点到11点半（纯纯因为自己上课乱讲乱吹讲不完）。上课偶尔拖堂，经常偶尔。每节课上课基本都要给你讲讲人生道理。什么吃饭不要玩手机，看到老师要问好，作业字要好好写，等等。口头禅："你这都不会，出去不要说是我的学生"。天天上课随机压力一名看不顺眼的学生。能选到这个老师肯定能得到多种纬度的全方位发展，包括大不限于：1.与其它班学生打好关系，因为你永远不会知道考点。2.自学能力大幅加强。。（上限了）',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6820abf42c0db64bfb153263',18,18,'我感觉什么都拉满了 讲课也听得懂只是有时候语速太快你说他一句老师也就反应过来了 平时分也可观 期末也捞 神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('682089813f81e43d5f354306',99,99,'事确实多，去年冬季学期从第4周开始翻转课堂然后他自己讲了两三周又开始让我们课程设计，还要求彩印，纯拿学生的钱不当钱',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('682088912c0db64bfb143fef',1503,2924,'纯💩，翻转课堂**',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('682071243f81e43d5f3494c0',10,10,'半期考试还在群里十分激情的喊麦，我真的哭死。她怎么能这么认真负责呐(˵¯͒〰¯͒˵)满昏必须满昏',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('681ed426f51acb77be7d5eeb',504,5,'高数12都是晓梅，和高中班主任一样，苦口婆心，非常认真负责的老师，经常给同学答疑。平时分拉满，一分都没扣。',5,5,5,15,0,0);
