INSERT INTO "reviews" VALUES('681e1749117fb603c9a15484',2637,1265,'太nt了，别人都是两次小组作业就她是三次，还必须要求视频，付出了很多却得不到更好的成绩，一定要避雷',4,2,1,7,0,0);
