INSERT INTO "reviews" VALUES('681df5bcf51acb77be78cb6f',3148,3148,'好！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('681df56e117fb603c9a07f47',96,96,'喜欢文理歧视，脾气不稳定，经常发货，从来不反思自己交的好不好，只知道责怪学生在下面不听指挥，而且作业任务多的没边，谁上谁倒霉，讲的课还差，无敌了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('681dae29685d2315e67d2175',54,54,'提问是不理的，设备有问题是不看的，答案是必须准确的，戾气是深重的，贬低人是有一手的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('681d7d30aeacc640aca6895f',1732,63,'讲得烂，事情多',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('681d77b5f51acb77be750de4',294,294,'跑，赶紧跑，上课把你当小学生教作业把你当博士生整。宛如暴力扭曲s般的课堂控制欲，要求全程跟读，随时抽问让你复述她的上句话即使是废话。小组作业通过率高达百分之五十，评判标准全凭个人喜好，重做可能是因为她没看懂你条分缕析的一段话，不重做可能是因为你的选题合她口味。另外，谁想知道你的出国经历和研究生博士生教学经历？who ask you？',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('681cb596aeacc640aca23bae',1503,2924,'纯哈气，交通美学课程内容，建筑学院九成学过，就不该选，速度润。什么大水课，还让你抬头听讲。一定要逮你耍手机，一定不能有自知之明。很好的诠释了某些大学老师的小资精致气。PPT一股子AI味道不说，琐事还多，经典翻转课堂。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('681c7cc4117fb603c9975939',314,314,'太抽象了，仿佛是更年期，学生都是得罪它的人，验收的时候没一个好脸子，好像这实验分不高就要完蛋一样。稍微一点小错误都要炸，脾气坏的没话说。说白了，有的人就是总想着在自己有限的权利范围内最大限度地刁难别人😄',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('681c57d3aeacc640ac9f715c',2843,2843,'一笑感觉乌云密布，太阴了。。。老是在课上阴阳怪气。。。',1,1,1,3,0,0);
