INSERT INTO "reviews" VALUES('67fe93b43f81e43d5f94f47d',226,226,'哈哈找不到形态创意，无所谓，反正我也很少见一个课需要全体都有花玛尼捧他凑脚哄他开心。男的会用建模软件好厉害口牙，男的做的雕塑好想收藏口牙，男的光是站着袅袅就好厉害了口牙。女生如果不心灵手巧就不行，女生不是准备不充分就是运气不好。原来都是因为我没有拿你最喜欢的石塑黏土搓个吊',1,1,1,3,0,0);
