INSERT INTO "reviews" VALUES('67f771fc685d2315e6cfa0cf',3253,3253,'线性优化非常推荐，主要是助教上课，背背答案就90+。其他课不好评价，高分基本上是助教给出来的，老师挺抽象的。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('67f5bdc43f81e43d5f6cd757',716,526,'💩中💩，天天上课阴阳人，作业一大堆给分还特别低，画图一堆要求还不在画图前说清楚，给完低分才告诉你他的要求，谁选谁挂科',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67f4ea7aa34a4b79fc9e4983',2640,217,'**玩意，没事就上课点名，做不了还要扣分，讲课又不清楚，平时要求还高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67f4d2f4b3002f28ab9fad12',3256,2432,'纯唐，每节课考勤不说了我确实该去，但他妈每周都来5分钟小测验，10道题给我五分钟还要我计算生怕耽搁你讲课了是吗？分算的死作业又多纯脑瘫',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67f472fafe6af4500b50e8ce',2774,573,'老师很负责，作业很多，上课逃不掉，每五分钟雨课堂一道题',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('67f3bbb2685d2315e6bebe27',3258,3258,'我选的她的大学生心理健康，老师人挺好的，也温柔，但是，课多想选个作业少不点名的课的同学千万别选，她点名每节课都点，定位签，然后基本每节课课堂上有小作业，课上得写，所以这种时候想写别的作业的同学就别想了，然后她课上还会有讨论，必须组队的，组队讨论完也要交作业，课下作业也挺麻烦，要拍视频，还要考试，反正建议课多的打算选个水课学点别的的同学不要选。最后声明老师人挺好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67f384d8a34a4b79fc97cada',1157,52,'作业的布置和收发非常非常人性化，讲课也很细致负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67f23a5f3f81e43d5f5d8c91',2582,2793,'******讲课水平见仁见智，但是我是听不懂，左一下右一下想到哪说到哪，非常喜欢抽问。和楼上的某条评论一样，考试给人一种是他努力你才拿到这么多分的感觉，重点期末能整理40页word，花在他的课时间最长给分最低，上了他两年的课总算是要结束了******',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('67f20ea03f81e43d5f5c85d1',64,64,'无语多言，多来几次你就懂了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67f0bae18f5c603fa61e1dbd',330,92,'我猜你买了个包，杀币小组作业狗屁不通给分还低，谁选老子笑谁，这些狗屎作业浪费每个人的时间，想红想疯了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67ef58d1685d2315e6abe38a',563,228,'老师没毛病，纯粹某些学生事太多了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67ed1648fe6af4500b32c6ce',1663,211,'我上的张老师的氢能科技选修课，张老师给了很多次提交中期和期末汇报的机会。上课也不严格，讲得也非常好，推荐推荐！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67ec9b8da2c0e443c8b96ed0',3265,3265,'物理专业的信号与系统的限选直接去选电讯或者信息学院的4学分的去课程替代吧。讲得一坨天天阴阳怪气，我认为花费过多的时间用来阴阳怪气那些本来就不学的人对真正想学习的人不公平吧',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('67ec981fb3002f28ab7c1986',563,228,'建议老师能换成定位签到，很多不来的也能二维码签到',5,5,5,15,1,0);
