INSERT INTO "reviews" VALUES('67ebcc51a2c0e443c8b6c977',48,48,'喜欢挂科的来它超市，包挂的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67ebb979685d2315e69c7596',54,54,'恶心人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67ebb072fe6af4500b2c8be0',1186,40,'我上的是交际与文化视听说，老师人非常随和，给人温文尔雅的感觉，课堂轻松，提问抽人偏随意，随便说说就行，平时作业也不多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67ebae1c685d2315e69c34ed',202,82,'南蚌，上课挺严的不允许用平板，耍手机，交谈，吃东西，上课开始时会点名而后进来算缺勤，讲内容多而杂，很难搞到重点，带严重口音，声音是混的，基本所有东西都在课上讲，群里啥也不会告知，千万别分心，实习的表格形式内容还有资料准备要求都很高，敷衍的话评级基本都是d,另外平时分给的是最低的，不会捞人（重点是上课水平一般，不布置作业，都得借同学作业来学重点写题目，一节课下来感觉老师讲了不少，但不知道学了啥）',4,1,1,6,1,0);
INSERT INTO "reviews" VALUES('67eb3e60a2c0e443c8b36e75',1171,27,'建议痛风早日战胜谭勇，遭尼🐴',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67eaa0d7fe6af4500b27f746',258,43,'不可否认你相比数电实验其他几个玩意像人多了，但是客观的说你讲的是真的不太好，而且非常应付差事，并且问你几个关于预习报告的问题就容易不耐烦。你的助教是真的很让人无语，说个啥完全不听，自己瞄一眼不等你把改了以后波调出来就说你是抄的，可给ta厉害的哦。个人认为quartus这个软件好好学一下，还是很有必要的，我自己肯定端正态度认真的学，但请你们老师助教有的时候也反思一下好吗？',1,1,2,4,1,0);
INSERT INTO "reviews" VALUES('67ea5d58685d2315e696798f',3275,3275,'很厉害的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67ea30098f5c603fa6021f33',411,36,'低分好吧，签个到他自己没听到学生回答自己没看到学生举手，下课找他他说不管了，没答到你就多说几遍啊，上课也不说下课不让签了，把上课的和不上课的一样对待，说话也听不清，都不知道你点了，有病吧，你不管公平吗，避雷避雷，真的有病，我真是觉得有病，教资怎么考的，教育行业要求公平，我要是点到，没理你但是你在上课，你大学的时候不也跟我一样，换位思考也没有，我真的觉得讨厌。。。。。千万避雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67e9f5e1117fb603c9b32336',2119,2119,'作业多，喜欢点人，甚至做的不好会叫你重做，简而言之抖M乐园了',3,3,1,7,0,0);
