INSERT INTO "reviews" VALUES('67e615ae117fb603c9a25965',3286,3286,'尼玛神经的没边了，天天想一出是一出，上一学期的课要用大学四年时间来治愈。事多的要死，比专业课都事多。一己之力干死我所有专业课，想读英语的来体验一下哈，上完这辈子都不想碰英语了',1,1,1,3,0,0);
