INSERT INTO "reviews" VALUES('67dd0b13685d2315e659bdbe',1825,1825,'二十年不变的教案给二十一世纪的学生洗脑，批量生产课堂废料的伪人，用最低能耗的表演式教学兑换体制内的生存安全感。
INSERT INTO "reviews" VALUES('67dcd2d7fe6af4500be7466e',748,392,'听她课是真累，一门水课比上正课都要累。上课不允许坐后三排，后面人一多就来一个乾坤大挪移后三排全坐到前三排来，说话总喜欢一踩一捧，语气也让人不舒服，提问贯穿整节课，不回答平时分就是死低，唯一能说不错的就是不怎么点名，不推荐。',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('67dcc76ea34a4b79fc32a4ab',221,36,'普通话亥等',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67dc5af8b3002f28ab33802c',3323,3323,'这个老师说话真的很好听 能感觉到文学工作者的独特魅力 据说还是西南第一个图书馆专业研究生 适合对语文有兴趣的宝宝们',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67dc5a48685d2315e6568fc0',1048,114,'没人觉得这个老师很像陈奕迅吗？？我不唱声嘶力竭的情歌～不代表没有心碎的时候oh～',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67dc59b031731c30f8c46cf2',12,3325,'老师我太爱你了…我是选修课唯一的女生 但老师也会教我一些我能练习的足球知识 并且允许我在足球场逛来逛去 有事晚点来 有事提前走老师都会同意 （可能我足球基础太弱了，自己也不愿意上场）还会主动关心我没参与集体活动会不会不开心…专业水平特别强 每次看他们训练都好厉害…老师你太好了…',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67dc58cfb3002f28ab337e0d',2005,1697,'感觉比高中老师吓人(´･_･`)人不错 你有问题她会很开心的解答 上次举手她以为我回答问题呢可开心了结果我说我要上厕所( ̀⌄ ́)',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('67dc58748f5c603fa6c18e1f',541,27,'人不错 话有点多 英语课感觉每个老师都差不多 认真负责',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('67dc40b2fe6af4500be5b150',1274,36,'上课乱说话，乱开同学玩笑,乱发表评论，不让玩手机，浮夸张扬的老头，避雷避雷！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67dbb587da7a556c03c81942',2377,322,'   分可能好拿，但是个人感觉老师的价值观与主流不符（不好赘述，不允许玩手机、写作业、听歌，上的很难受，像细嚼鱼腥草（品shi）。不建议任何人选，无论你是想水或是想学到东西...',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('67dbb32ab9b8310c49217ec9',102,66,'上课蚊子叫，遇事就骂，啥也不教，烂事挺多，故意卡人50过分挂科就好像有指标一样，把不得给0分，还不让换课，千万别来，跟乔丹一个货色',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67db787100f6a60dd66079d0',751,573,'谁是简中谁选，每节课必点名，作业写的乱就0分，讲课1/4时间在废话，想重上高中的可以来',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67dafdcc4a556c651f491c5f',3251,3332,'快跑，千万别上，上课纯浪费时间恶心人的，没重点爱乱扯，面向对象程序设计这么重要的一门课被当水课对待，一个半小时的晚课他要延长到三小时，多的时间全拿来扯，关键所谓的干货部分也就是对着书挑着念几段然后讲些稀里糊涂莫名其妙的例子，有些书上的重点被他直接略过，很多例子自以为很清晰明了其实完全是混淆理解 ',4,1,4,9,0,0);
