INSERT INTO "reviews" VALUES('67d9b496710cf7015be43156',24,24,'如果你听力好的话，就无脑冲（最好是那种四级听力能接近满分的），他上课语速非常快加上吐字十分不清晰，另外就是他声音又很小，但由于教室里有麦，就导致他说话还有回音（自带混响哈），让人真的难以理解在说什么，一节课听不懂你以后就别再想听懂他的课了。除此之外，并不是上课不点名而是每次上课都会通过小测来间接性点名（与个人来说，有点烦）',4,1,2,7,1,0);
INSERT INTO "reviews" VALUES('67d9b0f3da7a556c03c15c0d',1537,526,'她上课特别喜欢聊天，拿CAD这块讲她讲的根本不足以让你完成她的作业，手绘图难度是其他老师的好几倍，CAD也是，这么多好评让我一度以为全是代画给的，毕竟完成她的作业据我所知，大部分都是找别人画的（ps:踩我的有理由怀疑是代画哈）',2,2,2,6,1,0);
