INSERT INTO "reviews" VALUES('67d50c1fda7a556c03b0bbb8',237,237,'有一点好处 很好逃课 被点到回答问题直接说自己不会就好了 QQ上问他的东西他说下来看看 就看到学期结束了 老师超级能水。。。基本不讲课，千万别选，或者不行没能换，那就往后排坐自学吧，平时分给的也低；包括吹牛都只知道追忆大学...多半现在科研也没什么成果...反正除非你就是打算逃课，不然千万千万不要选他。',1,1,5,7,0,0);
