INSERT INTO "reviews" VALUES('67d3bc68b9b8310c4904f663',131,226,'真的服了 看到他就ex想吐。。天天找茬他是甲方吗毕业归来说我有四年工作经历不为过吧。。选到他就完了一股味学校能不能拿远点谁知道他怎么拿到教师资格证的C说话也很抽象表达能力更是像s一样哈直接降龙十八掌……补药选他啊。。',1,1,1,3,0,0);
