INSERT INTO "reviews" VALUES('67c64dda8b6f717a2b2a541a',1250,696,'我真服了，纯念PPT，而且念不全，将讲python一节课从赋值讲到if else语句，一节课把C＋＋一学期的内容讲完了😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67c5e7588b6f717a2b29bfa3',1381,517,'易大师，专业素养很高但要求比较严格，给分不错也确实刀子嘴豆腐心。建议会游泳的可以来水体育课学分，不会游泳的只能说快跑',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c5a76700f6a60dd613ae9b',99,361,'水课事情还多 点名 ppt汇报课上提问样样都有上课比专业课老师还要认真',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67c5a6dfbd4703056af02b2a',42,42,'学得很通透了',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('67c5671abd4703056aeefd66',1735,3456,'老师超级好，很温柔，作业也不多，还给减少了一点总是先夸你在说一下你的问题，超级好，给分也高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c54b63ed44882e4fcf4957',377,377,'第一次见被点起来答题，答错了直接在最终成绩扣两分的。come holder看了都说六',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67c52691da7a556c0377f369',1503,2924,'交通美学速润，孩子们。一门选修课，上来就问有多少是来水那两个学分的，问完了就说理科生也要增加文科素养之类的，要好好听课，桌面上不许有任何电子设备，只许抬头听课。讲课是念PPT的，作业是留一大堆的（有翻转课堂、小组汇报、线下作业等等），选修课舍不得给分那么死，那只要劝后人速润了。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('67c51eb34fe7e23200380bdd',3459,641,'老师特别温柔，为数不多会主动在课堂上问你哪里没听懂的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c51e3b00f6a60dd6113872',1850,34,'打分特别多，作业特别少，吐词很清楚，讲得也很慢很细腻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c51326da7a556c0377993d',3461,2678,'想问一下学长学姐，建筑学院的选修课学时要求6个，报了一个个性化选修，算那个毕业要求培养方案的选修板块吗',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('67c47f84da7a556c037678a6',55,55,'陈老师认真负责，讲解细致，示范标准；同学们有问题时会耐心解答，亲自示范，反复纠正直到掌握为止；课上严格要求，课下很亲切，不会忽视同学们的需求；课程安排很充实，强度不低，给分也蛮高，适合想学到真东西的同学，跟着练一定会有所收获，体能也会有所提高♡´･ᴗ･`♡',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67c47b77092cdc7cfa38107e',3463,3463,'老师我爱你',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c46f82bd4703056aec0724',776,2397,'乐老师必须打满好吧，上课又负责又认真，助教也很负责每次都改作业并且把答案发群里，只要认真听老师讲课期末高分根本不难啊，听不清楚就往前坐，平时给分也嘎嘎高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c46d25ed44882e4fcd0666',334,175,'冷酷无情，平时分巨巨巨低，上课总是带着浅浅的微笑，知道你听不懂的嘲笑…………',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('67c463758b6f717a2b249a5a',3466,3466,'只讲重点，脾气温柔，平时抓的比较紧但给分很阔绰。',5,5,5,15,0,0);
