INSERT INTO "reviews" VALUES('67c42ed7710cf7015b96e085',725,40,'老师挺好的，上课回答几次问题平时分也就还行，事少',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c41346b9b8310c49ccfff9',1538,1073,'非常好的老师，讲得好作业少，上课中会处理作业较难的部分，一学期基本只点一次名，平时分也给得高',5,5,5,15,0,0);
