INSERT INTO "reviews" VALUES('67c2def3da7a556c0370f593',3473,3473,'上课就是讲ppt和放视频，不怎么点人回答问题，期末交一个论文就好，想搞更高分再交一个ppt，给分特别高，适合水成绩',5,5,5,15,0,0);
