INSERT INTO "reviews" VALUES('67c204c4b9b8310c49c61665',1480,194,'怎么4.9了？是谁在诋毁我恒哥？我恒哥分高事少态度好，平易近人作业少，态度严谨跟高中老师差不多',5,5,5,15,0,0);
