INSERT INTO "reviews" VALUES('67c1312c8b6f717a2b18ec1b',214,36,'阴的没边了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67c1293fb9b8310c49c2b732',459,68,'上的是蒋老师的职场英语，上课会教你一些论文知识，也会带着你实践，基本不会讲课本，上课不点名，课后也基本没有作业。课下论文作文是由助教批改按照老师要求写基本就有13分(满分15分)。本人是蒋老师的课代表，课代表加分+竞赛+六级一共是加了9分(明确说了)，最后平时分是99分，所以基本你按照蒋老师要求来，平时分都不会低就是90分左右。作业的话我是课代表，我每周在上完课后都会找老师再问一下，最后会在班群里发布，每个作业的节点我也会在班群里提前说',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c126b94a556c651fedc568',3484,3484,'课设胡乱给分',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('67c125f900f6a60dd603e2ad',2346,762,'娟姐人很好，专业能力够，对概率论有自己的见解，平时分拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c125a78b6f717a2b18b167',849,619,'彭老师上课讲的比较无聊，会发ppt让你做笔记，后面做了笔记会根据你的笔记情况加分，基本上笔记做的好能够平时分拉满。在最后一节课会带你过课本，最后一节课划的重点基本都是考试题，虽然无聊但是还是要听一听',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c1251fbd4703056ade994d',10,10,'上的是吴老师的大物B，实在是大物课太无聊了，但是老师讲的很认真很仔细，平时分基本拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c124a500f6a60dd603dbd0',229,2381,'云丽老师讲的很详细，讲过的题基本都是考试题，不点名，平时分直接拉满。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c12430710cf7015b8bfdbc',3489,1001,'这门课的难度问题，不是杨老师的问题，最后考试考课后原题，这门课要想学好课下一定要看书，一定要复习',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('67c122f2bd4703056ade8d72',1419,48,'赶紧跑吧。爱摆架子 打分极低 为人刻薄 阴阳怪气大师  工作效率也很低。我认为没有哪个真真的大师会刁难学生。她这个人真的很没水平。',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('67c11866da7a556c036a20e6',194,194,'我说白了，豪哥的课你上不下去你就回家吧，你去spa',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('67c0c6a6da7a556c03695ba3',1372,348,'不屑于多讲，根本不管学生后续听不听得懂，前面没听懂后面不会就是活该。。没听懂也不敢多问，一脸不耐烦瞧不起人。。。作业和实验都好好做了，平时从没缺过课，期末给平时分巨tmd低，连80都没给，加上期末考试也不太会，美美50多挂科，一点点点都不捞，想都别想',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('67c0aea34a556c651fec9348',3493,3493,'老师很温柔，专业性强，画不好也鼓励我们，给分和善。属于是建筑课里最放松的课了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c0ae418b6f717a2b1787fb',1453,26,'伟大无需多言，说话很有趣的小老头，也会鼓励我们，成绩拉满。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c0ade08b6f717a2b1787a7',1186,40,'老师人很温柔，很好说话，给分可以，我一个学期没回答问题，每节课都在睡觉，最后平时成绩92🌚🌚😭，只要正常完成作业学习通，不缺勤，给分都低不到哪去。但是上课会固定座位，也会点很多人回答问题，不过你回答自己不会也没关系她都会给加平时分。（默默收回了三个月前给的三星评价）',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('67c0abbf092cdc7cfa2ad27e',380,601,'老师给分可以，签到一般是学习通定位签，作业可以补交，但是特催眠，上课听不太懂😭，线上问问题很热情解答。基本上一个学期没去上课，最后平时成绩跟期末卷面一样，不会特别低。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('67c0ab0f4a556c651fec90a8',346,56,'跟了老师两年，每个学期总评都是九十多😭😭老师人很热情温柔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67c09b054a556c651fec7d14',1768,92,'钟老师是我心目中的神！上课之前起来讲一两次上节课讲了什么之后你的平时分基本上就是满的了，但是别缺勤，说实话四学分的大物a都要缺勤的话平时分低一些也是情有可原了哈。平时看着比较严厉其实问题什么的都会给你解答，讲课速度比较快但是确实会比较耐心地带着大家解例题，期末复习也会带着大家一起过知识点，总之就是很不错的老师，优选班是她的冲就是了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67bff07dda7a556c0366683b',1386,1386,'平时分拉满',5,5,5,15,0,0);
