INSERT INTO "reviews" VALUES('67beda0c4fe7e232002320a2',3507,1732,'人工智能课。有点不好评价，这门课本身就是很烂，一个导论课水平（居然变成智能保研课了那你其他专业不是保研课的是不是分开比较好……），他让课前下软件跑程序我也勉强能忍受，上课讲得没东西也还好，就是不让玩手机貌似😂，好多事情包括课设检查应该是全部交给助教了，没作业签字来签到算是优点。',3,3,3,9,0,0);
