INSERT INTO "reviews" VALUES('67b6c8f6092cdc7cfa0a3157',202,82,'大学生要学会自己找材料，大学生要学会自己学习，大学生要学会自己解决问题，大学生要学会自己找复习资料，实习不会做怎么办？那就不做呗～幽默老式，兄弟萌一定要选他口牙！不选，那就少一段难忘的经历啊！',1,1,5,7,1,0);
