INSERT INTO "reviews" VALUES('67a434a34a556c651f8fff5c',705,705,'学弟学妹听劝赶紧跑，这老师纯傻逼，期中考试给20分，理由是试卷和一个人雷同，我tm根本都不认识，问了人家也不认识我，平时分拉的非常低硬挂你，就拿这门自控说，24-25第一学期补考名单，一共五个班挂了39个人，武越的一个班独占19，挂科率是lcw的6倍以上，上课也是纯水，给的作业屁也不是，不去做别的老师的题期末根本没戏，听人劝吃饱饭，快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('679cea32f2f9f935110dccc2',3552,535,'按心情点名，按心情给分，按心情上课，十一放完假连课都不记得上直接旷掉，叽哩哇啦乱讲一通期末还提前结课。上课讲的，作业写的和考试考的不能说完全不同，只能说毫无关系。不知道期末是您亲自操刀还是助教改，总之出的成绩让我相册改卷人。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6799dfef429bf7097718772d',1770,3109,'还记得老师请我们在犀浦春天吃饭，虽然教学要求严，但生活中对大家很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6798a096e340cc59b32cc138',715,394,'老师全中文授课，脾气很好，氛围轻松，一学期点名大概2-3次。有2次左右的课堂案例分析，期末有一个大作业。期末会给重点，简答题几乎全考到了。强烈推荐！但是给分没有想象中那么高，可能是学校统一了给分标准吧，86点几的平时分在几个老师中也不算低了。',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('6794b806429bf709770e8f35',581,581,'期末巨难，给的重点基本没用，选课的人都不到40个能挂14个',1,1,1,3,0,0);
