INSERT INTO "reviews" VALUES('678f6d09429bf70977feef45',3563,3563,'郭老师很好的一位女老师，上课讲的特别细！是我为数不多的不用额外听网课就能学明白的专业课，跟上她的节奏绝对能学的很好，课下QQ上问一些问题她回复的也很快，另外她还会专门抽出课来讲习题，平时分除了期中只要没缺勤作业交了就是满！吹爆郭老师！',5,5,5,15,0,0);
