INSERT INTO "reviews" VALUES('678b74306db11a18ac2180bb',250,250,'在他的课上，放心大胆的玩，不会错过知识点的，因为他不会讲知识点。经典语录是“有没有不懂的，有的话下来自己看”还特喜欢搞歧视（地域人种都有）',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('678b6e817aae956c174ff799',271,5,'丁浩老师上课讲的很难听懂（或者说因为地域的关系我听不懂丁老师说话），PPT的例题也没有答案，本人全靠自学。但是期末有一些老师可以控制的分数给的高，都是满分。',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('678b5c506db11a18ac20fed7',2559,2559,'上课要求注意力集中，但老师是真打算把俺们教会啊，很负责，教学方式还挺先进的。考试基本上就是上课提到的重要知识点，给分不错。',5,5,5,15,0,0);
