INSERT INTO "reviews" VALUES('678a63436db11a18ac1df8e4',1953,1596,'上课多回答问题就行，除了期中考试平时分都给满了，认真听能学到东西，就是平时课堂有点严格了，一直玩手机会被点',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('678a62048101ac2f444339de',1186,40,'给分很高，而且上课很轻松，95%的时间都在玩手机，虽然每节课都有布置作业但基本没检查过，唯一的缺点可能是固定座位吧',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('678a607d5d97b2416dd574b0',3370,228,'老师专业水平确实很高，如果认真学真的可以学到东西，光看平时分确实比不上一些几乎打满的老师，给分比较严，期中期末各一次随堂测，大作业也会看你有没有认真完成，但也不会特别低，总之还算推荐',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('678a4c8a7aae956c174c02dd',3599,3599,'虽然老师平时作业挺多 但是还是分给的挺高的',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('678a45468101ac2f4442be83',459,40,'蒋婧老师的课确实是很水的，同年级的几个人一起上课，他们经常趴着睡觉，蒋婧都不会管，我一般都是打游戏(不开声音就没事)，除了iwrite和学习通其他的作业也基本上没有，她即使说有什么什么作业其实也不会管你到底有没有做完，只要学习通作业都好好完成，学习通定位签都签了，平时分都不会低(PS：别拖作业，最后期末虽然会催你补作业但是我估计还是会对分数有影响)，基本上我和我室友们都是40+的平时分，45左右也是有的，总之横向对比身边其他人的平时分来说她打的分确实是性价比偏高的了，反正现在通用学术英语是五五开了，正常点的都大差不差，还有，说没有明细的，不知道之前是怎么了，反正我们上课的时候是给我看了明细的哈',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('678a44d05d97b2416dd4f546',1386,1386,'我给你讲，王老师是对的，不赖',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('678a33ef4a556c651f504ea6',1189,605,'给分巨低，平时分巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678a30c84a556c651f503f4f',2324,81,'平时成绩100，啥也不多说了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678a19fd429bf70977ec5039',3442,1500,'客观评价，老师人还可以，讲课稍有问题，部分重点讲不明白，适合自学，PPT战神也是事实，但是他期末是真的捞啊，平时分除了期中考试都打满了，属于那种帮不了你但是尽量不拖你后腿的那种，我看素有恶评，可能是近年来“改过自新”了吧。',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('678a0f025d97b2416dd3f4ab',2169,394,'老师人还行 平时分太低了特别是那个20分的大作业 期末闭卷考 幸好勾的重点还不错',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('678a0a24429bf70977ebfb05',141,141,'课讲得差，想考高分得找网课听。平时分很抠，大物DI的课堂表现5分只给了我3分，问她理由根本不带理你的。线上问她问题有一次给她问住了直接拒绝回复。大物想考高分的千万别选',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('678a09074a556c651f4f7062',281,1156,'口音浓厚，但是讲课可以，认真听还是听的懂的。平时分给满，但是期末考试不捞人。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6789fc4c8101ac2f44415132',1252,18,'作业少，而且线上提交，只要交了，作业分就是满的。老师人很好，不管是线上还是线下问老师问题，都能得到有效的解答。上课很少点名，印象中这学期一共点了两次，一次是随机抽了十个人，另一次是全点，但是第二次点名的前一次课老师就说下次课会点名。平时分拉满，绝对的好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6789fa5bf2f9f93511dd8918',2200,2387,'讲得非常好，条理清晰，重点突出，听完课把作业一写基本上知识点就都掌握了，完全不用再去找网课什么的。上课完全不点名，只会在下课时间让用慕课签个到。给分超级好，能给的基本都拉满了，期末也会捞，个人感觉王老师是高低分段的都捞，亲妈级别的好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6789f7b95d97b2416dd36ec0',1441,228,'平时分给的非常低。本来是邵春波的优选班，听说是天王就换到了郑瑶，现在肠子都悔青了。郑瑶平时分给的没我期末的卷面分高，什么实力不用多说。对比一下其他老师吧，这学期杨东平时分99，张素风平时分96，邵春波平时分94。选择郑瑶让你开局马原就比别人低十分。补充一下，郑瑶的班平时分没有过90的，平时分低绝对不是我个人上课不作为的问题，郑老师言辞凿凿说什么教务规定学生的平时成绩不能超过90，但是我了解到的没有任何一个同学说他们的马原老师提过该规定，合着是教务专门限制你郑老师的？而且上课管的比较严，基本两次课点一次名，半期闭卷考试，还说严格按照题目要点给分，期末重点画了相当于没画。总之，避雷这个垃圾老师！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6789e6168101ac2f4440ebde',1441,228,'平时分偏低 一个班平时分上90的寥寥无几 基本都是85左右',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6789bc778101ac2f444027d6',691,228,'必须要上课回答问题才有高分，平时回答问题5次，实践作业ppt做的认真一点，加上ppt汇报，平时分给了95，讲课水平不晓得没咋听，她到不管玩手机好像？可能我没被抓着过，不过她经常下来溜达，有的时候点人回答问题，经常点名，作业不多就一个小组作业，其他两次作业她上课给时间写上网抄抄就得了',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('6789bacc6db11a18ac1ad55d',3613,1849,'事多分少一点专业水平都没有，完全不给任何意见就会让你自己搜集资料自己找案例抄，脾气爆骂人难听动不动翻白眼，嘴贱还爱蛐蛐同事蛐蛐学生',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6789bab8429bf70977ea88da',1023,188,'平时分莫名其妙比朋友都少了两三分',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('6789ba595d97b2416dd25572',1904,1904,'爸爸',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6789b9d1429bf70977ea8415',3616,3616,'上课老爱扯些有的没的，我不是很想知道你当年在设计院的事哈，事多分少，考试画假重点才是最不能接受的哈',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6789b9037aae956c1749414c',1773,1773,'致敬传奇捞捞王hjw🫡讲课挺好的人也好他真的我哭死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6789ae054a556c651f4dcfbe',674,307,'本人23级发表于2025年1月17日，就以下几点：1.期中考试：她班是按照期末考试的形式来坐座位，最后登平时分成绩的时候会给你多加几分，别的老师呢？有线上考试，有期中考试水考（即一堆人坐一起）所以选了她的课能体验两次期末考试；2.点名：点名也是不知道哪节课会点名，不算多，那是因为随堂测验代替了点名；3.课设：她的课设难度绝对是最高的，别的老师要么自己选一道简单的给学生，要么给几十个自己选一个，她专门给了等级，难的满分100，简单的满分70；4.随堂测验：上课线上考试一共有三次，每次都要按照你考的分数折合到总评，我因为这个总评扣了1分。别的老师到底怎么样请仔细了解活水字数有限已经尽力挽救小登了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67894ba78101ac2f443f134c',1287,68,'课很水，但是给分特别低，平时分没我期末考的分高......',1,1,1,3,0,0);
