INSERT INTO "reviews" VALUES('6788e7cd6db11a18ac1883db',3519,457,'讲课讲的很好，但是分给的不算很高，作业也挺不水，但是是位好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6788e7885d97b2416dd00010',3628,3628,'期中成绩占总分40%，期末30%，我服了。期中考的很难，没有例题，作业也没有。期末很简单，可惜占比少。给分很严，完全不捞。很无语。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6788e1ed9d433b7c963538a7',100,100,'教的好，人美心善，还善于捞人，拿高分和捞过分都很推荐的一个老师（电分老师都是很好很好的爸爸妈妈😭😭😭👍🏻👍🏻👍🏻）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6788dc50f2f9f93511d9e57a',532,141,'纯纯**我只能说，给分巨低瞎**给分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6788dc22429bf70977e80004',703,228,'千万别选，事多，点名，无重点，根本不捞人，人不行',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6788cd226db11a18ac1802f5',740,740,'作业超级多，不建议选',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6788c7a47aae956c17464e5d',819,228,'选到她了，你就赶紧跑吧！平时分给的特别特别低！而且期末阅卷给的分数也很低。如果你想要拿高分，千万不要选！一节课没有缺，平时作业互动什么的都有认真做，最后全班最高分只有94，基本上就没有几个平时分上90的。别的班平均分，基本上都能够拉满。我会一辈子恨她的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6788c5267aae956c1746409a',3038,228,'老师还可以，平时分给了我97.5，平时做前四排会加分，还有每隔一节课都会有作业，抄得认真点就可以了。不过期末卷面分还是很低，总评下来卡绩点……',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('6788c1238101ac2f443cef8e',3038,228,'这学期给成绩不是特别慢了。',5,5,5,15,0,0);
