INSERT INTO "reviews" VALUES('6788bebcf2f9f93511d94a33',3038,228,'孩纸们，她变了！平时分给满了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6788bce79d433b7c9634735c',457,457,'平时分给的比考试还低，是这个👍，还不如隔壁张大律师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6788a9684a556c651f4a707f',357,357,'无话可说',1,1,1,3,0,0);
