INSERT INTO "reviews" VALUES('678890c39d433b7c96338c1a',3641,3641,'逆天，钢结构两个学分的课硬是给你整成5个学分的学习量。平时占30期末占70，老子结构力学四个学分都是46开。还有就是这b老师本来平时分就只有30，他硬是要给你找各种理由扣到只有25左右，期末还不捞人，我tm整张卷子全部写满了，你每个简答题多给我一分我不就可以过了？无语，水课配上垃圾老师，快跑吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67888f108101ac2f443be2ae',703,228,'老师和蔼可亲，平时分也很给力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678889b49d433b7c96336f54',703,228,'神中神，不像传闻中说的那样，应该是改变了，这学期上课我就玩手机，会考三次课程测试但是也不太管。一学期基本是水，除了大作业也没其他任务。混了一学期给我平时分94分。啥都不说了好吧神!!!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67887df45d97b2416dcde9a1',975,975,'老师很好，作业系统基本上有个八十分平时分就给满了，实验也很好拿满分，就是上课的深度不够，平时分除了半期考试都是满分，上课很自由，感觉是个好老师，很关心学生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67887b6ff2f9f93511d7fa6d',3645,3645,'神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67887ae89d433b7c96332557',703,228,'勺春波666 平时分给的没有比他还低滴 平时事还那么多 真是太死马了 想保研别选他',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67886ad1f2f9f93511d7a193',1042,462,'老王虽然看着很随意甚至敷衍，但是其实对学生也挺不错的，会捞人，给分也很不错',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('67886a4c429bf70977e57b18',3648,174,'为学生着想的老师，这学期上他的高电压感觉很不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678866144a556c651f492b28',703,228,'平时分满分啊满分！而且我没有主动举手回答问题，只是春波会有那种思考题，你主动做下节课主动教就行，上课坐前排一点玩手机小心点别一直玩，期末嘛今年是给了重点但是没有给内容，可以找别的班要，平时也不言老师挺温柔，但是会点名，不要逃课！',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('67885b52f2f9f93511d755e4',3650,325,'上课讲的比较一般啊，听的人很少，都是自学的，但是期末还行，看看往届题就差不太多了',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6787ee4f8101ac2f443a3089',53,53,'乱给分 上课讲的一坨屎 ppt更是一坨 还骄傲的吹嘘自己挂科率高达百分之40 光荣战绩有∶ 挂大四学生   平时分给0分 没错 就是0分 你没看错 就是0分! 平时在群里也是装死 不回消息 总之他的教学水平就是一坨屎 他也是一坨屎 可能他觉得去美国教过几年书他就很牛逼了吧 呵呵 懂得都懂  死老头子',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6787e88ff2f9f93511d6a3a3',903,307,'不许有任何人忤逆康妈😭😭😭，期末心软的神，ldx错了一堆题目最后给分给了我一个想都不敢想的高分😭，给分超级仁慈，期末真神啊😭😭，康老师平时讲课思路清晰逻辑连贯，大家都自觉坐前排的，都去上康妈的课，包你过的😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6787e8699d433b7c9631c9a6',903,179,'康萍你是一个妈妈😭😭😭真海底捞😭😭😭妈妈妈妈妈妈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6787c00e5d97b2416dcbfc79',975,975,'改邪归正了，平时分除了半期全满了。吹爆王老师🤩🤩🤩，老师上课确实不太好，适合我这种自学的人。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6787ac749d433b7c9630cc76',232,24,'平时分满分无需多言',5,5,5,15,0,0);
