INSERT INTO "reviews" VALUES('67878cf3429bf70977e2fe52',1453,114,'有一次点名我没去平时分也给满了，虽然上课效率不高，但人随和幽默，好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67878bf69d433b7c96303cf2',1675,1675,'人看起来很亲和，两次没交作业平时分给七十多火死了，上课坐前两排才能听清。',1,4,4,9,0,0);
INSERT INTO "reviews" VALUES('678789a75d97b2416dcaf992',141,765,'老师上课很有活力，平时分也是按规矩来，该捞也会捞，很亲人的实话说。真心推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678789409d433b7c96302e3a',1906,15,'测绘工程专业外语，老婆子严的很，给分还低，平时分上90的人不多，期末上90的就更不多了',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('678788c9429bf70977e2eb10',18,18,'讲课很有活力，改卷很松，基本上听了课就不会有问题，无脑冲就好了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678787e3f2f9f93511d50651',1675,3663,'我来说说她的力学吧，一分都嫌多。课是PPT战神的，平时分是给不高的，人是不捞的，声音是极小的，重点是不明的，复习资料是不给的，大一应物力学统一分配，分到她班只能自认倒霉。（仅代表大部分人看法，且本人力学不算平时分还说的过去，并非因挂科而产生的消极评价，若部分自学成才的天才觉得上得好我也无话可说）',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6787868a8101ac2f44387c76',489,3664,'平时分给的低，老师一点都不捞人，平常没几个学生听课一点都不管，布置作业超级多，线上线下都有作业，讲课也水',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('678783005d97b2416dcad9ea',637,694,'从来没见过这么低的平时分！期末和总评差不多一个分了，作业留的多又难，ppt全英文，那个半期简直就是随便给分，要是想总评高一点的话，能选其他老师还是选一下其他老师吧',2,2,4,8,0,0);
INSERT INTO "reviews" VALUES('6787679f8101ac2f4437d4ed',1565,1631,'平时分很低，上课无聊',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('678767254a556c651f45fc53',193,193,'平时分真的是按心情在给，一学期没缺勤，作业按时交，、平时分比不上隔壁班天天缺课不交作业的同学。上课就是念ppt，根本听不懂，只能靠期末考前看黑马程序员突击',3,1,2,6,0,0);
INSERT INTO "reviews" VALUES('678765c3f2f9f93511d44c48',1675,1675,'上的是刘老师的力学课。
INSERT INTO "reviews" VALUES('67876568f2f9f93511d44a82',3669,3669,'真挺屎的，别认真准备了认真准备绩点给的也很低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67875b4a7aae956c1740d624',3670,3670,'除了不讲课都还行',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('67875b2d4a556c651f45be1a',3671,3671,'很顶级',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67875a57429bf70977e1eb92',81,81,'平时要求多得不行，上课也喜欢抽查回答问题，然后哪怕你回答了问题，节节课去上课，平时分也特别特别低，你能想象在其他老师给满分平时分的情况下只给你七十来分吗，我只能说，你要是选了这个老师不跑你是这个👍🏻',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678759d08101ac2f443789b1',1025,850,'非常严格和专业的老师，知识渊博什么都懂，问的问题都能回答，不知道评论区在黑这个老师的人都是什么成分，要点名，作业多，水课和分奴勿选',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6787581f9d433b7c962f1330',81,81,'避大雷，没见过哪个老师把全班的大作业全部打回重做的，花了6周搞大作业，课都讲不完，给分巨低，比别的班光平时分就要低十几分，事很多🤮期末重点画一本书等于没有重点，无语',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('67873a0e8101ac2f4437071d',81,81,'思想不正，破事极多，自以为是，随意给分，贾兆帅我＊你先人',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('678732737aae956c1740275f',348,348,'不会的题全靠拍，上课也讲不清楚，莫名其妙发脾气，平时分低的离谱',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6787304d5d97b2416dc93599',1964,1964,'难评',1,4,1,6,0,0);
INSERT INTO "reviews" VALUES('67872e9b7aae956c1740168a',826,114,'老师知识点讲的很清楚，就是有点口音，听多了倒也还好，平时分给的比较高，很喜欢的一个老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67872d455d97b2416dc927b4',2078,23,'老师讲课很清楚，知识点讲得很详细，点名比较多，适合想认真学的同学听',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67871733f2f9f93511d2d88c',3680,80,'老师讲课很清晰，会结合板书和PPT进行授课，课下作业不多，按时完成作业一般平时作业都是满分，线上问老师问题能及时回复。还有就是一般课堂前会有上一节课的内容回顾，会找同学起来回答问题(基本每个混凝土老师都会这样)，能说上来一点就可以了，一点都不说可能会扣一点分。总之，跟着黄老师是能学到很多东西的，给分也不低，几乎都是给满了的。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('6786c418429bf70977dfefe1',3472,1731,'没见过这么会给分的，你就选吧🥰什么事都干了还敢给你个平时分70分，习概能差点挂了我是没想到的，有这种硅谷都够成都市动物园多开几个园区的。这么Na2Co3的老师真得给个好评如潮👍',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6786c3c87aae956c173ec957',3472,3682,'这位更是Na2CO3，没见过这么会给分的，你就选吧，什么事都干了还敢给你个平时分70分，习概能差点挂了我是没想到的，有这种硅谷都够成都市动物园多开几个园区的。这么爱惜家人的老师真得给个好评如潮👍🫶',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678696eef2f9f93511d1de88',1675,1675,'懒得喷，期中占平时成绩50%，真的6，所有作业都交了，期末90+，平时成绩59，全给我干废了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67868e008101ac2f443544b0',18,18,'这第150个评价，再次宣告交大活水霸榜人赵春明',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('678682d44a556c651f4358f5',2125,3685,'混凝土的，巨离谱这老师，别的老师统一课设，就他不同，要做他自己定的课设，还比别的班难好多，平时分也低，不会捞人，唯一的优点就是不点名',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('678678da7aae956c173e357e',1452,623,'跑，讲的一坨，给分很低，恶意挂人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67867731f2f9f93511d17157',431,80,'老师上课水平很高，平时上课不怎么点名，但是偶尔有课堂小测，期中考试成绩按照期末考试成绩赋分，给分挺不错的，建议大家上！！！！',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('678676e37aae956c173e2cf0',3472,81,'就算你没缺课，你必须得多回答问题，才可能平时分超过80分，但是给分真的太低了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67866474f2f9f93511d11ae6',1732,3689,'讲课讲的特别烂，特别不清楚。光靠上课根本学不到东西，都得找网课补课。而且平时分给的特别特别低，服了',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('678662de9d433b7c962bf399',6,619,'遇到李子重真是大大滴“福气”，期末考完觉得90稳了的卷子给了70分，行，真行。😅一个班的人普遍觉得分给得过于低，低得都在问怎么复议成绩',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67865bacf2f9f93511d0f00c',3691,3691,'畜牲，千万不能选这个人，期末95+，平时分给80，神人。上课还要被他骂',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67864ef69d433b7c962b9711',1063,143,'这三年遇到最逆天的老师了，绪论上三周，上课拖沓，上到最后一周才把新课上完。一讲课就是自己多牛自己的研究生多牛，动不动就pua底下的学生。不重视本科教学，上几周课就让另一个老师上，然后最后又自己上。有人说他是科研大牛，你拿怕是院士，不重视本科教学就别来给本科生上课。期末问考试范围是啥，问就是不知道，题型也不说。结果一出出四十分的概念。给分也是乱给，全交作业的人没有缺交作业的人平时分高，大物实验给分都没这么逆天。哥们三年挂了不少科，没抱怨过任何老师，都是从自己身上找原因。第一次遇到这么逆天的老师，不求你捞，给分都不能公平给。期末考的越低，给平时分越低。摆明了就是恶心你。选到他的赶紧跑吧',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('678647a8f2f9f93511d0992c',6,619,'上课纯翻转课堂，不勾重点，上课偶尔管玩手机，偶尔点名，不过只要按要求发言了，平时分给分还是非常高的（49/50）',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('67864362429bf70977de63f6',867,27,'我考的低是我的问题，不是您的问题，满分献上',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678642395d97b2416dc66a4a',2078,1529,'抽象，枯燥，不如崔波一根',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('6786370d5d97b2416dc63a16',141,65,'老师特别负责，讲课条理清晰，只要搞懂她给的题目，期末完全没问题。平时分给的也挺高的，一些不好的评价应该是之前的吧，现在真的挑不出毛病，结课甚至有种舍不得的感觉，都放心选高老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678632757aae956c173cdc1b',762,762,'虽然上课风格真的一点都不喜欢，但还是给我过了，就放你一马',4,3,1,8,0,0);
INSERT INTO "reviews" VALUES('678630534a556c651f41f5ab',3253,3698,'上的机器学习，虽然上课讲得不怎么样，期末题也难，还不画重点只有ppt上的题（考试之前我连题型都不知道😅），平时分给的也不高，但是期末考试是真捞啊😭😭😭我好几道题不怎么会总评80多，我承认之前是我说话太大声了😭',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('6786304e9d433b7c962b08f6',2017,762,'刘老师又漂亮又温柔，打分也高(^.^)就是有时候讲得太深了，我听不懂(͡° ͜ʖ ͡°)但真的很会鼓励学生，让我充满动力～',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67862f8a429bf70977de0d47',775,24,'超级超级好的老师！！！！！他的课我旷了很多次，被记下三次缺课，期中我没考及格，但是最后总评只扣了我平时分3.6分（实际上我期中就应该扣总评五六分了），真的超级好的老师，上课一般点名是让写纸条交上去就可以了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67862f5af2f9f93511d03133',1452,623,'讲课水平一坨，喜欢扯些没用的，不如直接看网课用的PPT甚至和网上华科讲的视频一样，给分也是巨低，第一次遇到作业按时按质提交作业分不给满的，真是倒了八辈子霉选他的课，当初看活水评分这人挺高，现在我只能说赶紧跑，平时分还没期末分多，我真是****',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('678620ec8101ac2f4433640b',3479,526,'作为一个老师，把学生踢出群后一直不加，怎么申请都不加，你要干嘛，我还做集贸作业，我这课挂了你负全责，看着人畜无害的小胖子，没想到内心如此阴暗，也没看到你在群里提醒修改名字啊，有问题第一时间不解决，解决有问题的人是吧，你真的配做一个老师吗，你扪心自问你配吗？跟你说话，你那个阵仗哦，啧啧啧，生怕别人不知道，哥们，这么多戏，你咋不去演戏啊，表演型人格，茶得受不了，你这种人，我一辈子忘不了，我会给我身边的朋友一一陈述你的光辉事迹的😁，加油，你是最配做老师的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67861d338101ac2f44334f1f',532,141,'劳资tm今天就跟你爆了，就是点C你，一句话戳中你G点，你是个边是个蛋啊，其他老师的课我也上过，群我也加过，只能说人与人之间亦有差距，装你牛魔酬宾啊，是不是脸给多了？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67861cf09d433b7c962aa319',869,3704,'一学期见不到几次面，不是在出差就是在出差，讲课水平不怎么样，规矩还多，好在上课基本是让另一个老师上，线上补课也是让自己的博士生讲。同样是一次作业，就要比别的班多要求写几道题（关键写起来巨麻烦），同样是期中考试，别的班开卷他的班要求闭卷。平时分一般水平，期末就靠临时记忆背重点，一学期下来啥也没学到。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6786158ff2f9f93511cfa4b4',3472,81,'这位更是Na2CO3，没见过这么会给分的，你就选吧，什么事都干了还敢给你个平时分70分，习概能差点挂了我是没想到的，有时候真想不明白这到底是学校还是scp基金会，有这种硅谷都够成都市动物园多开几个园区的。这么爱惜家人的老师真得给个好评如潮👍🫶',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678614ce9d433b7c962a78b9',3472,81,'这位更是Na₂CO₃，没见过这么给分的，你就选吧，什么事都干了还敢给你个平时分70分，习概能差点挂了我是没想到的，有时候真想不明白这到底是学校还是SCP基金会，有这种👻5都够成都市动物园多开几个园区的👍🏿👍🏿',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67860bd2f2f9f93511cf7392',3707,741,'老师人特别好，根据我们的课表改了上课时间，让我们本来有课的周五可以放假了。
INSERT INTO "reviews" VALUES('67860aff429bf70977dd4708',1210,1210,'好老师！！人特别随和，给分很高，半期开卷，期末会划重点。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67860a7cf2f9f93511cf6d12',1228,1228,'老师人很好，只是这课太难听下去了Orz
