INSERT INTO "reviews" VALUES('6785ffdb6db11a18ac0d2bad',691,228,'本来选这个老师很忐忑，但是平时分出来的时候惊到我了，居然有99分。平时有课堂任务，作业测试什么的都会打分，上课回答问题有加分。老师今年的平时分给的比往年都高，可能赶上好时候了。在马原卷面成绩很难高分的时候，平时分真的救命啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785f347f2f9f93511cf0453',3712,92,'老师脾气巨好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785f2c4429bf70977dcd919',849,619,'跟前面的说的不一样，我缺勤一次，没交笔记，平时分给了90，上课可以随便玩',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785f25b9d433b7c962961be',18,18,'无需多言',5,5,5,15,0,0);
