INSERT INTO "reviews" VALUES('6785ea7f6db11a18ac0cd3a3',2646,2960,'太好了，平时分给的满满的，上课也不会点名，期末还会狠狠得捞，实在是不可多得的中华好老师！（除了会突击期中考试 ，其他都很好）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785dfe3f2f9f93511ceb1dd',705,705,'cnmdSB一个，平时分给这么jb低，你要jb干啥啊。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6785db055d97b2416dc47130',3718,1796,'给分很高 而且上课特别水 老师人很好 期末成绩95+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785daab429bf70977dc6c65',3719,230,'上课找理由说有人听课不让你坐后排 讲课也没什么水平 期末划重点实际上是把一整本书的内容划了一遍 而且不会捞',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('6785b0404a556c651f3f8215',24,24,'真神不解释！选到小武就偷着乐吧！老师巨负责，作业都是自己批改，qq群里资料也特别多，复习都省得去打印店买题，答疑什么都很尽心尽力，讲得也蛮好。期末考试应捞尽捞，平时分我漏交了好几次作业也拉满了。（虽然小武上课不让玩手机，不听课的同学可能会觉得在坐牢，但是在小武的优点面前这点小问题无伤大雅🥹）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67853b9d8101ac2f44304233',24,24,'我爱蜡笔小武！！！
INSERT INTO "reviews" VALUES('678539a4429bf70977d9e09e',819,228,'上课内容还算丰富，但是给分超低，平时分全班几乎没有90以上的（无论有无回答问题），其他老师基本平时分在九十分以上，所以很亏。且期末改卷非常严格（统改，期末卷面分70+都算不错的了）',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('678537ae4a556c651f3ec70d',2210,3723,'老师口音太重了我听不太清，板书也有亿点乱，但平时分给的特别高，基本都拉满了，人也很和善',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('678533c2429bf70977d9cbd6',3724,3724,'垃圾老师（要求多，平时分低）期末重点不画，考试都是冷门的，批卷子贼严，整张卷子写满了不到30分👍，我寻思最后两个那种开放题都有快20分了吧，结果毛分不给
INSERT INTO "reviews" VALUES('67852b5b4a556c651f3e9fb6',776,24,'乐源老师我哭死，说捞真的捞了，平时分直接干到99了，明明期中考那么差呜呜。大学以来最感动和最对不起的就是乐老师，感觉上课不认真不努力，没有考出理想的成绩来配上老师的认真负责和人情关怀……',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67852b225d97b2416dc2b487',849,619,'交笔记，平时分90+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678525528101ac2f442ff2ae',3727,1904,'选了shl你就偷着乐去吧 三生有幸啊哈哈哈哈哈哈哈哈哈哈哈😄😄😄😄',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6785218a4a556c651f3e6b40',1095,1095,'会讲课，但是只会讲一点点；会捞人，但是只能捞一点点；平时作业抽象且量大，上课待人友好，有问必答（虽然不一定能给你解释清楚，基本上就是有问“必答”），上课多数时候让用chatgpt生成（期末会考代码，三道大题占共计40分），通过率应该不差，据说同一科目的其他老师给分很高，想卷成绩的建议快跑。',2,1,3,6,0,0);
INSERT INTO "reviews" VALUES('678518f07aae956c17390e96',1095,1095,'真的遇见什么老师啊，一门自己都不知道在讲什么的课，其他教学班的人平均分90，他班级平均分70多，这老师早点下岗吧，真的无语死了，真的tmd sb',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678515c07aae956c17390007',1095,1095,'后来的学弟学妹们，人工智能千万不要选他，给分太低了，我想骂人了，他到底啥意思，想干啥，服了。这评分没有负的真是对不起他。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67851377f2f9f93511cc5a44',370,370,'这老师讲课很好，每节课都有作业，平时分有多少给多少，想好好学可以选这个，想水的赶紧跑',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67851143429bf70977d925b3',1095,1095,'作业是一堆作业堆到一起布置的，每次是只会用ai写的。考前能说开卷考试只准带书的，考后批改巨慢，给分巨低的。最后机械专业是学成计算机了的',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('678510f65d97b2416dc23136',1095,1095,'老师挺亲和的，就是实在不理解老师的教学方式😓（个人认为给分也不高',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('678503e17aae956c1738af72',691,228,'我承认是我平时说话太大声了，霞姐平时分给满了😭老铁双击666（上课会点名，经常逃课的别选）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('678503b9429bf70977d8ebfe',756,22,'交了作业没有缺勤的话平时分基本是给满的，可选，建议不要缺勤有可能触及逆鳞。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678503624a556c651f3dcf5f',1493,3736,'老师挺好的，但是最后给分实在难以恭维，没有缺勤，报告交了（助教说没问题），最后分数比缺勤平时分70几的分数还低，去反映却回答无误，也只能算认栽，怀疑是为可选项的汇报没有做导致的分数偏低（我的问题）。所以建议想拿高分的同学一定要找人一起汇报分会很高，除此外的事情很少。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('6785030d429bf70977d8e94d',1791,774,'不知道平时分咋给的，但挺高，上课挺轻松，除了偶尔抽人回答问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678502cf4a556c651f3dcd1e',480,92,'神中神，玩了一学期，平时分除了半期直接拉满，上课只要不说话就行，也不点名，只要交作业就行',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785023d6db11a18ac0a0b13',1287,40,'课很水，睡觉也不管，最后平时分还没我考得高。。。。折算下来只有38服了，想水的来',1,5,5,11,0,0);
INSERT INTO "reviews" VALUES('6785022a5d97b2416dc1dcbf',2169,3740,'人还行，真性情，但是给平时分容易低，上课讲的东西感兴趣就听，不感兴趣就没必要听，最后根据她画的重点去复习书上内容，是可以写的七七八八的，祝各位都能拿到好成绩🌹',3,4,4,11,0,0);
INSERT INTO "reviews" VALUES('678501c4429bf70977d8e432',505,175,'平时分不高，全看作业',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('6785019a429bf70977d8e377',716,716,'平时分45能给个43，喜欢吓唬人说挂科，但是挂科可能性不大，想考高分的建议私下自学，不然期末还是有一定可能崩，',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('6785015d7aae956c17386c9d',3727,1904,'上课不用听，背题库就行，签到群里说，无需交假条，平时分除了实验都给满了，也没布置过课后作业，课堂作业就两次直接拍照搜答案，错了也没关系，迟到和说话会被口头批评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6785009f7aae956c1738690f',359,228,'总的来说这位老师只能算是中规中矩，会明确评分标准，要求你回答问题，回答质量并没有要求特别严，拿满平时分肯定比其他有些老师难但不是没有可能。她上课质量不是特别高，差不多会有10周作业布置，每个人都会有一次背诵但是段落不长背完问题不大，回答3次问题可以满这一部分，回答5次问题估计能达到满分标准（因为半期拿满可能性为0得需要一定加分），如果有机会可以换别的更好的老师建议换，但是能做到上面这几点的留在这里也不会太吃亏，就这样，仁者见仁智者见智。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('6784f4da7aae956c17382f20',176,176,'飞神我的超人，课讲的好给分超级高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784f2fef2f9f93511cbc521',716,716,'李松老师啊
INSERT INTO "reviews" VALUES('6784edce4a556c651f3d6f5f',3747,80,'平时不用去，有作业但我没交过，而且期中老师会发教务网邮箱通知，记得把课设找个好模板，期末再考个45斩杀线以上，老师狠狠捞过😲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784ed4d9d433b7c962612a0',1542,1796,'老师很偏执，假装自己和圣母一样，对和自己关系好的同学就很好，对于不太熟的同学就很emmmm，反正快跑吧，老师有自己坚持的一点正义吧',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6784ec954a556c651f3d6aa6',99,361,'屁事贼多，每节课点名，上课还得时不时的在那个卡得像屎的微助教上答题，平时分给的莫名其妙，辛辛苦苦一个小组ppt汇报，一个调研报告，一个地铁文化墙设计最后只给了89分，三个工作还都认真做了，一个选修课的报告写了40页都打动不了这b老师的心，还有他这个考试，期末周让你去考一个半小时题量的选修这你受得了吗，比专业课上的事都多，老师更是毫无亲和力可言，问个啥都得凶你一顿，想要高分水课的不建议。最后冲着对轨道热爱想来的同学建议别选，他会给你讲一堆的文化漫谈，你想听的都没有，你跟他说轨道反而是你跑题了😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6784ebe2429bf70977d87e9a',1274,36,'刀子嘴豆腐心，平时分给我的挺高',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('6784e9159d433b7c9625ffd8',233,306,'太✅8️⃣好了平时分狠狠的拉满助我度过大一简直是再生父母',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784e2f8429bf70977d85439',702,702,'期末一万字重点，结果试卷上的题基本都在最后两三千字，请问是想干嘛呢？而且改的又严，就是存心不让过',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('6784d0b8429bf70977d7ebbc',178,946,'千万别选，事居多，五分的东西想让人做100分的事，纯奋，谁选谁后悔，还能选她是这个👍',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6784c4c48101ac2f442e0ffa',3754,156,'流体力学B，选就是了，平时很松，上课只需要定位签个到，不点名，课堂两次小测一共10分，半期10分，管得松，期末考试前老师会带着讲题，会发重点，也会答疑一学期没听课，照着老师的重点和速成课，总评82，感谢老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784bcd96db11a18ac08ab7c',3755,80,'点名少，事情不多但是麻烦，上课念PPT，给分一般',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784b529f2f9f93511ca9086',755,3756,'无脑选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784ac4e4a556c651f3bfc6e',526,1651,'讲的不好，且作业多，且给分低，平时分也低，大图作业给分也低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6784a9e76db11a18ac0846c4',3727,1904,'迟到或者上课老讲话会被老师说，其他的倒是不怎么会管你，要请假的话在群里说一声就行，不需要假条，这个学期只签过一两次到。看好多同学说给分问题，不过这个学期我的平时分给满了哎。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6784a2f37aae956c173694d2',1157,52,'特别好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784a2986db11a18ac082600',592,194,'重修的，虽然只去上过一次课但还是过了，这个老师真的好好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6784813f9d433b7c9623c554',3727,712,'平时分给满了，满昏',5,5,5,15,0,0);
