INSERT INTO "reviews" VALUES('6784570e9d433b7c962300ed',242,242,'赫赫 真是一点也不捞 平时分低的很 讲的也很快 亲和力高 因为看着笑嘻嘻的 但是分低。。',1,1,3,5,0,0);
