INSERT INTO "reviews" VALUES('6783cd1f6db11a18ac059881',393,96,'挺好的 虽然老师上课我听不太进去。。这是我自己的问题哈哈哈 上课认真听期末会很轻松的 概率论需要理解',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6783cc8f5d97b2416dbd544d',129,129,'上的管理学原理 感觉平时分不高。。期末考了88老师也没有捞一下 总评还是88。。不过平时没什么事 上课还挺有意思的 期末重点也给的挺全',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6783b237f2f9f93511c70af1',202,82,'首先，第一点，这老师讲的不怎么好，甚至还会漏讲，期末还要你自己去学没讲过的。不会发实验表格。
INSERT INTO "reviews" VALUES('6783a9127aae956c17335894',526,1651,'教的还是挺好的，但是作业太多，别的班一学期两个大图她有四个而且还是一个图里好几个小图，除了这个每周固定还有很多道习题册作业，最后几周还要刷cad课程纯靠自己下来学习研究然后上机考。平时分给的特别细，具体到每一张大图，半期考也很正式，会利用你的周末时间，总之很不轻松，想得高分要保证每一项都认真完成，她给分很严格。',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('6783a621429bf70977d39929',334,334,'海涛哥一次不点名 真给你捞人👍👍👍👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67839c257aae956c173327ad',385,28,'这里正名一下，陈越老师作业确实是真的多，人也是真的严，但认真上课平时分拉满。为人相对公平公正，比较喜欢口语好的学生。不满者勿喷，千人千面。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('678398917aae956c17331514',1453,26,'王中宝老师上课氛围轻松，授课很幽默，作业正常量。平时课上完后会留出一点时间自习，这个时候你可以问问题，他都会认真解答。临考试会再专门开习题课答疑解惑，认真负责。平时分除了期中的都会拉满！！！为人没有架子，会和我们分享他的求学经历，寓教于乐。不想负担太重又想得个高分的冲！！！',5,5,5,15,0,0);
