INSERT INTO "reviews" VALUES('67836820f2f9f93511c59a88',1320,40,'难评，天天拖堂，讲课节奏很有问题。虽然人看着挺温柔的，但给的平时分比别的班低很多。而且也没学个什么东西。',3,4,3,10,0,0);
INSERT INTO "reviews" VALUES('678366df4a556c651f376a25',1596,1596,'老师超级温柔！教的很详细，可以选择性地听，也会很耐心地给学生讲解问题！ppt做的很好，期末救星。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('67835c387aae956c1731dca5',1377,194,'平时分给的不高，课堂签到，按时完成作业就占10分，剩下90分全是考试的，没有捞的余地，趁早跑',2,2,2,6,0,0);
