INSERT INTO "reviews" VALUES('678337ab6db11a18ac02e447',18,18,'老师巨好!!!!讲课特别有趣而且通俗易懂，概率论最好的老师没有之一🥺🥺👊🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6783324d5d97b2416dba3cf9',2015,2015,'给分高，期末捞人，一学期就点一次名，也不为难人，属于是有求必应，虽然科目有点难，但是老师超级好',5,5,5,15,0,0);
