INSERT INTO "reviews" VALUES('6782f3e75d97b2416db958f8',720,720,'重修生选了龙老师，平时在准备考研没听过课，期中考了55，龙老师最后登成绩给了95，平时分90.3，期末考了60+，突击两天总评73，龙老师好说话，作业给分高，不点名，课设要好好做，不懂的来问龙姐姐，谢谢龙老师祝我顺利毕业读研',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6782a4fa8101ac2f4426de15',1157,52,'上课有意思 期末会给复习的资料 很全 而且会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67828b404a556c651f3514a1',480,92,'人很好，重修的同学可以选，要求比较宽松，给分很大方，期末会发重点，帮助很大，好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678282dcf2f9f93511c2e051',925,3793,'讲课一坨，讲课给自己听，如果你是学过一遍穿越回来可以听，否则建议自学为主',1,2,2,5,0,0);
INSERT INTO "reviews" VALUES('678279f14a556c651f34d43b',18,18,'无敌好老师！',5,5,5,15,0,0);
