INSERT INTO "reviews" VALUES('6782750c6db11a18ac00f45e',961,762,'拉满了，有两次大测验，但是可以搜题，偶尔签到，但是分拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67826c114a556c651f349094',142,75,'平时分给的很严，作业布置的特别多，选课的同学慎重哈，喜欢写作业的可以来，喜欢认真学习的可以来，每节课还要签到',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67826644f2f9f93511c264b9',2128,3798,'讲课一般，比较和蔼，期末改得严，但是平时分给满',4,4,5,13,0,0);
