INSERT INTO "reviews" VALUES('678259db8101ac2f4425b8ea',18,18,'上课很有意思，为人和善，平时分很好赚。作业多但基本不检查，期末会捞人，太爱赵老师了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678259957aae956c172ed834',18,18,'赵春明老师神中神！上课幽默风趣讲的清晰明了，作业也少，平时分更是拉满！！毫无缺点！！！！春明哥yyds！！！选到的同学有福了！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6782597ef2f9f93511c225b5',604,96,'无敌',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678259398101ac2f4425b6aa',18,18,'神中神，不选春明后悔一生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678259057aae956c172ed639',18,18,'伟大，无需多言，赵春明，我的超人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6782583d4a556c651f3434c7',271,5,'一般',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('678257a4f2f9f93511c21f11',23,23,'刘老师人美心善，上课充满活力，答疑非常耐心，跟着学轻松高分，做人做事方面也收获很大，很真诚的老师，大爱！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678253866db11a18ac006069',430,194,'选虎子，就对了！气氛是随和的，管理是很松的，分数是给的高的，只是速度是很快的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678252d88101ac2f44259c5d',1547,26,'只要不缺课，交作业，上课也不见得要回答问题，课堂测试也不见得要做全对，平时分也是会拉满的（我就是这样的），同学们整体考差了，还是会先反思自己的原因，有时也许会讲不清楚，但总体上挺好一老师（其实猛子挺阳光的，不像刚见到似的那么冷）。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67823c797aae956c172e5d2a',3814,3814,'上课有一半的时间都在闲聊，专业性听不出有什么，只是知道他过去的经历很丰富。可能有一点自己的想法，不愿意随便给学生打分，但是他的评判标准实在叫人迷惑，感觉有点自相矛盾，又有点自以为是。喜欢说不以成绩论英雄，结果还是照挂不误。尤其是课程报告交了9次，也没啥大错，不知道为什么平时分只给了60。失望。感觉更像个经验丰富的江湖骗子。',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('6782377e8101ac2f44252383',1058,26,'很认真很亲切的老师，不定期考试打分比较高（不缺席的情况下）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678232f7429bf70977ce6a80',986,3816,'叼毛老师，跟吃了大便一样，虽然大四水课，你妈的就给80分，那我平时每次都去上课让你恶心我算是白去了，上个水课要求叽叽歪歪的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6782209f6db11a18acff6c2e',3568,462,'这个老师特别好，真的，儿豁嘛，虽然普通话不太标准，但不影响我对他的喜欢。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67821be55d97b2416db6b425',3755,80,'老师积极回答学生提问，乐于解决学生问题，是交大不可多得的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6782117e8101ac2f44244be2',785,114,'很认真很负责的老师，平时分除了期中考试全部拉满了，作业也挺少的，讲题很清楚。
INSERT INTO "reviews" VALUES('67820e764a556c651f32bd3e',1441,228,'课讲的还可以，但是平时分低，才80多，别的班都九十多，需要高分的速跑',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6781fb0f6db11a18acfeb3e1',3821,3821,'通用学术英语英语平时分47/50，老师人很好，很温柔，期末为了捞人平时分甚至会布置别的类型的作业让同学完成来进行打分，pre的作业要求也很松，稍微认真准备就是满分，不会pua学生，即使有人没来也不会点名，有重要的考试之类的会提前通知同学们到教室，很不错的一个老师。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6781f3d1f2f9f93511c02a59',2885,3822,'垃圾',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6781f02b5d97b2416db5d01a',309,309,'老师上课的时候就把重点划完了，期末复习出的几乎都是讲过的题。一学期就三次作业，没写完还可以推迟一周交，而且助教给分都特别高，选到就是赚！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6781e6674a556c651f320f24',294,294,'你见过上课不带书、上课玩手机、甚至不做笔记都要扣平时分的吗？你见过问啥都不告诉你的吗？但这些她都能干得出来！快跑，选了这个大傻*的课就是自讨苦吃。',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('6781e49af2f9f93511bfe837',281,281,'上课思路清晰，平时分基本上能给的都给满了，期末也划了重点，除了有点口音有时候听不太清楚外都很好。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6781e47b6db11a18acfe51cf',1768,22,'虽然专业能力不算特别强，但至少期末会捞人，选她的课基本不会挂科。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6781e4359d433b7c961a8415',228,228,'纯傻狗，期末给分巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6781e3b84a556c651f3201a3',1108,188,'点名开教务网投影学生信息大头照点名，上课一直读PPT自说自话，没什么作业但是给了60的平时分，问老师说是因为缺了两次课，大家自己看情况选吧',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6781e1ce429bf70977ccdcae',788,1551,'课设一定要提前写，如果是交通工程专业并且课程大纲和我这一届差不多。那么期末你面临的会是15天内完成4个课设，并且要复习期末内容。道路工程课设内容非常多，并且她上课没教过怎么做，她也不会讲，要你自己问。我认识的每一个人都是熬夜四五天做课设，她课设的设计图打印下来甚至长2.7m，宽0.88m（宽度甚至是截了一半的，因为打印店没有这么大的纸）。课设如果有点小问题是有一定几率得0分的，包括比如笔误（自己设计的半径600写成6000），或者一些未知原因。所以做出来不管多忐忑，一定要先给她检查一下，免得最后交了出分喜提0分。',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('6781e0579d433b7c961a6f33',788,788,'计算题一道56分，名词解释8个一个3分共24分，简答题4个一个5分共20分。给的重点不是考试的重点，而是参杂了大量假重点的版本，加大复习背诵的痛苦。最后的计算大题甚至考了一个她从来没有讲过计算公式的C形曲线，根本不知道怎么写。这里对娟天帝本人不做评价，只为了学弟学妹不用遭罪讲讲她的课应该做什么。课上：娟天帝只会读PPT，但是会可汗大点兵疯狂挨个抽问，你可以不会但是你不能不在。作业：一定要自己做不管多么恶心，最好在期中之前完成，因为期中就是一道100分的计算大题，遇到超高平曲线竖曲线结合的时候，先算平曲线，因为平曲线的缓和曲线长要用来当超高缓和段，再算超高，因为超高高度最后要和修正值一起加在高程',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('6781d781429bf70977cca612',3650,325,'草泥马的反转了',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('6781d2cd4a556c651f31ac0e',1025,850,'讲课很好 就是作业多分低 想好好学电力电子的可以听听 想拿高分的不太建议选',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6781d1a44a556c651f31a686',1699,211,'上的他的单片机，豪老师👍事儿少分高，不过之后好像没有单片机了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6781c5aa5d97b2416db4fa7d',359,228,'果然是米麻薯，事巨多，一次没缺勤分还低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67817e22429bf70977cbd35e',958,23,'特别爱怼人，每节课的基础环节，没有计算机基础的听他讲课很吃力，爱花式点名，课间不下课。作业题讲题不仔细，只是两三句话概括，期末重点画满了一张A4纸还不如不画，相比别的班学生期末还有老师自己整理的复习资料……',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('67817a235d97b2416db4766d',1128,40,'上课纯念ppt，每节课基本都是抽人提问填满的，有个随堂测验占了平时分一半，布置作业从来不在群里通知，甚至iwrite作业开启提交也不通知，等到下次上课才说然后已经截止了……平时分只给了42/50，一般别人班都是45+，听别人推荐选的，体验感很一般，只能说想要高分的别选',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('678176bdf2f9f93511bebecc',2642,2642,'闭眼冲!平时分基本给满了，平时也只有两个大作业，比较费时间，但期限长，讲课也讲的很清楚明了，会划重点，课前随机点名，自己主动回答问题会有加分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678174f75d97b2416db47260',19,2812,'讲课水平一般，基本是快速念ppt，好在课程比较简单看看书也就会了。上课不抽人提问。老师人很好，回答问题很耐心，作业量很合适，不会花费大量时间，给的提交时间也比较长，半期闭卷考试，但只占总分的5％。平时按时提交作业不旷课的情况下平时分给了46/50。个人感觉相比隔壁班不足就是讲课水平一般和期中不水，好处就是作业比较简单',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('6781520cf2f9f93511be90a9',131,3418,'选修全勤，作业认真交了，给了85（特么的*纯***',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67814a89429bf70977cb8e05',3650,325,'我不多说无敌',4,5,5,14,0,1);
INSERT INTO "reviews" VALUES('67814a318101ac2f4421d6fc',334,175,'上课自顾自地讲，从来不管学生听懂没有，问个问题高冷得不得了，让你自己去看书，平时分给得也非常低，每次作业都认真完成了，考勤一次不缺，结果平时分总评扣我4分，大一上学期所有老师就他平时分给得最低，一定是人生太不如意了，才会损人不利己。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('678141bb4a556c651f30668c',188,188,'给分巨低 上课不回答问题就70多分 而且期末一点不捞😅',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('678137d85d97b2416db3dff3',1197,496,'sb一个',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678133766db11a18acfc9789',3650,325,'新老师，平时比较喜欢板书，ppt不太有，后面忘了，但是平时分拉满，期末就算叫你弟过来给你每题写点abc，每题给两分也能过，给跪了，神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67812d8c7aae956c172a994b',118,3845,'肖老师太nb了，期中才七十多，期末稍微考好点，总评就帮我拉到90了(ღ˘⌣˘ღ)',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67812ab69d433b7c961879ac',2058,230,'人美心善',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678129ff9d433b7c961876a6',2058,230,'平时分拉满了 点赞点赞 只要上课到了就没事了 人美心善',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678125888101ac2f44213529',348,348,'这老师就是一坨，讲的也狗屁不是，一天天就知道压力学生，生怕学生不知道他是个超雄。实验也不看你写的程序帮你改，就用自己背的那点玩意写，你跟他不一样跑出来也不行。喜欢猎奇的学生真是有福了。但是我还得表扬他一下只要有57.58分的学生一点也不捞。真是公平公正，上课就是用他那娘娘腔口音来说话。说他讲的好的估计也是找的水军，真是没谁了，没见过这样的老师，世界之大无奇不有。我真是了解了物种多样性',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678122419d433b7c96184f9a',3849,80,'老师真的很好！平时分给的很高 不点名 期中开卷 讲的也很好 家人们冲冲冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67810df2429bf70977ca78bc',788,1551,'下面向你走来的是道路工程唯一牢大，交通工程专业淘汰王，期末考试计算题56分开创者，课程设计A0大图主宰者，三连讲课堂手机制裁者，课堂可汗大点兵，打分铁血无私青天大牢爷，交通学子的噩梦--娟天帝',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('67810ce98101ac2f4420bee8',7,7,'胡老师我有罪 一点没学大物上下都给我捞60分过了😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678107eaf2f9f93511bd54fb',19,2812,'讲的课差 平时分给的很低 期中考试特别严格 及格的都很少 我身边很多人所有作业都交了但是作业分也只有80 这种作业不缺交但是还扣好多分的dddd 赶紧避雷吧 杨骏真的水很多分数 也会高点 ',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('6780f3f78101ac2f442048c2',565,3853,'平时管的比较松，一学期大概点了三四次名。课后作业比较少，事情也不多。给分挺高的，好说话。上课可能有点跟不上，但是可以看ppt学。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6780f23f4a556c651f2efcca',58,55,'老师很帅，给分也高，体育分在同班同学里算很高的了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6780f1935d97b2416db29697',121,1010,'给分很好，庆幸在什么也不懂的大一遇上这样的优选课老师🥹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6780f1394a556c651f2ef85f',2885,40,'平时分有47+（满分50），平时事少，给分不错。人很温柔，比较负责，作业和其他的通知都会在群里进行强调。我觉着只要能尽一个学生的本分，不缺勤，不忘交作业选她错不了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6780ef96f2f9f93511bce3f1',1032,736,'老师人超级好，课虽然比较难，但是讲得很细致很清晰，一点不水，期末给分也高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6780ec739d433b7c9617519e',42,43,'要不是最低分是1分，我一分都不想给。就最后一道十分的题没做，前面的验收波形什么的都没问题，最后成绩给50，不想多说了，，，',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6780b9cb429bf70977c8cd7e',19,2812,'平时分有点低，作业都认真做了',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6780b0928101ac2f441ee50a',1531,34,'杨老师人超级好，考试前都会给范围给题型（这是能说的吗。。）好好做作业平时成绩全都打满。唯一的不足之处就是发QQ问问题基本不会回复，这个得找助教。不过课程的助教也是很好的。
INSERT INTO "reviews" VALUES('6780a48b5d97b2416db10909',270,270,'思想封建给分低，课上说中国女生要学习日韩女生，不能让自己的丈夫看到自己的素颜，要等丈夫睡着之后再去卸掉。这还是人话吗！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6780a1734a556c651f2d61b0',18,18,'伟大无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6780a0fb429bf70977c85f60',373,3863,'平时分拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67809f664a556c651f2d5a24',2012,296,'平时摆烂期末恶补，符伟爹直接给我60分过了，谁敢说符伟不好我第一个和他急',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67809c5c4a556c651f2d4bf8',372,5,'笑里藏刀，人面兽心',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67809c344a556c651f2d4b58',515,118,'逻辑不对，被扣了35分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67809c076db11a18acf9ba3e',58,55,'人超好，我因为要刷绩点但是有腰病，有很多动作受限，但是老师还是尽可能给了高分，人很帅，后来我去实习请假也很容易，像一束光，温暖了我苦难的刷绩点之路',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67809aef7aae956c17279cc9',3868,3868,'上课稍严一点，但给分很高，我两门都是九十加',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67809a8e429bf70977c84185',1252,18,'人超好给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67809a295d97b2416db0dc6e',359,228,'本来平时成绩是满分的，最后一节课还去找她确定了一下，班上好多同学都是，结果莫名其妙的最后平时成绩都变成85，有的人只有75，在群里好多人质疑，结果她还说我们自己不行别找老师。呵呵，三分人样还没学会，七分官威栩栩如生',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678099185d97b2416db0d540',1174,3871,'别选纯**',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678098f0429bf70977c8390a',1174,3872,'呵呵别选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678096b67aae956c172788e4',870,296,'压分 具体表现在课程报告上 平时分分类很多其他基本实事求是 ',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('67809609f2f9f93511bb2abe',385,28,'除了课程考试的平时分都打满了被老师捞到90 平时分努力可以拿满分 老师很认真负责 比较像高中学习',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678095916db11a18acf99ba8',788,1551,'学交通不得不品的一门，最后没挂有种死里逃生的感觉。老师呢确实有一定水平，但是对学生要求太高了。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('67809282f2f9f93511bb1882',476,779,'上课确实不点名，作业手抄量大，特别恨国，特别喜欢贬低学生，表达也不清楚，我祝你成功哈哈',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678090fb5d97b2416db0ab15',359,228,'无疑是一位负责的马原老师，但很遗憾，她站在了马克思主义的正面，却站在了学生的反面。（说明：此处并不是代表学生也在马克思主义的反面，我相信我们都有社会主义远大理想，仅指米老师没有抓住师生关系的主要矛盾）',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('6780901c7aae956c17276688',564,26,'好啊，平时成绩拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67808f564a556c651f2d0a5b',359,228,'事多给分少强行要求回答问题，不回答平时分极少',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('67808e7a4a556c651f2d05f5',2507,81,'我不知道为什么评论区那么多人给娅楠姐那么多差评，好像差评都是21级，不知道亚楠姐以前怎么样。但我是22级的，就我今年的情况来看，亚楠姐似乎改变了很多！平时人很好，很体贴学生，有点刀子嘴豆腐心的感觉，心真的很软。到期末了还会给各种加平时分的小理由，比如签到加分，交笔记加分等等。最后给分也很高，几乎拉满。总之我为娅楠姐正名！现在的她跟评论区其他人说的完全不一样，判若两人，可以放心选。说假话我期末考9门全挂',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67808df3429bf70977c7feeb',2507,81,'老师超好的👍讲课内容生动丰富，结合实事讲课，上课放的视频都比较有意思。在下面做自己的事情不会管，回答问题会有加分，点名次数不多，还会有一次签到加分。老师说最后一节课前交学习笔记可以弥补平时分，但平时分给的很高感觉交不交就是满分和9590分左右的区别。老师是一个很人性化的老师👍',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('67807eaf429bf70977c7aa7f',1169,1169,'作业看都不看，全部拉满。讲课认真，很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67807ae09d433b7c961514e3',1350,5,'胡老师 我的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678075428101ac2f441db742',170,233,'傻比东西，重修平时分给15分，平时分没期末考的高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67805c494a556c651f2c2b0f',491,23,'刘老师真的很负责，跟着她好好学肯定高分，最后悔的就是没有认真学辜负了她吧，但是期末还是过了，感谢感谢',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('678059cb5d97b2416dafbed5',3886,3886,'老师人很好，这门课也非常水，上课只有几个讨论作业，有两次小组汇报，期末没考试，只要交报告就行，但是我总评并不是很高
INSERT INTO "reviews" VALUES('678019d1429bf70977c6e398',3755,80,'选了她的课，你将会遇上世界上最差最烂的老师，不用我多说了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('678012897aae956c17255fca',3755,3888,'诗人沃迟',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6780124d7aae956c17255f94',3755,80,'真的是个cs啊我服了，大半夜发消息说课程设计不合要求，要明天上班时间内交过去，不然直接挂我，明天还有期末考试，我只能说求本事没有的木够就是这样的想，自己来了交大十几年还是个讲师，没有任何研究成果，只能通过卡学生来找存在感是吧，全班平时分七十多，本来这科就，存心不想让人过呗，4m婉仪，这种就应该被尼哥狠狠地进入捏',1,1,1,3,0,0);
