INSERT INTO "reviews" VALUES('677ff7e39d433b7c9613b207',170,170,'哇塞，我是上课打他了吗？课堂表现平时分给我32分，平时作业一次没少交过，作业平时分68，哇塞，七十的平时分是人能给出来的？平时上课声音巨小，跟蚊子一样，课也讲的一般，平时分还低，真的，能跑就跑，选了他真是倒霉死了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677ff5c2429bf70977c69e06',1762,415,'中规中矩吧，当时的Matlab上机实验是他带的，挺水的',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('677ff0ba4a556c651f2b8e08',1600,96,'完全没得说，上课真的通俗易懂，作业少，每周不超过六题，困难的地方会详细板书，每节课开头会先复习下防止脱节。而且会提前复习，带你写往年的卷子。而且小测只要交了就是满分，包选的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677fefd18101ac2f441cbe36',3821,3821,'钟老师已经很棒了说实话，我上的她的通用学术英语，中间还翘了几节课，最后给了46.9。说白了大学英语最主要的就是平时分，事少分高，最后的口语考试都是直接让我们上去说几句卡壳少的就给5分满分了，水课混分必选啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677feeac7aae956c17250645',3895,3895,'老师人超级无敌巨好！！！不点名，上课讲的也好，期末会带着复习一丢丢，然后给划重点，而且给分很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677fedf66db11a18acf7f11f',3896,6,'老师偶尔查考勤，没有在课堂上回答过问题的期末平时分也有九十几',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677fd7345d97b2416daec4c3',922,762,'非常好老师，给我平时分拉满了。上课字不是很清晰，但是资料和ppt都会发群里，有问题会解答。很少点名，也不怎么管你上课干嘛。会有三次随堂测试。',5,5,5,15,0,0);
