INSERT INTO "reviews" VALUES('677fd2aa7aae956c17248e21',3133,496,'缺了一次课，作业全交了，期末63，综评59，无敌了🤣上了五学期，几十门课第一次遇到期末裸分过了总分没过的课，不想说多了，想挂科的来👐',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677fcde89d433b7c9612fa32',2078,1529,'感谢老师不挂科之恩',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677fc9947aae956c17245b7a',170,170,'每节课都去了，课堂表现只给80。所有作业全交了，而且助教改的基本都是90分以上，最后课后作业82？？？我想知道他的给分标准在哪里？看心情吗？他上课从来不叫人回答问题，我怎么表现？我还能怎么表现？我要怎么表现才能100分？给他塞红包吗？',1,2,1,4,0,0);
