INSERT INTO "reviews" VALUES('677fb919429bf70977c586c8',2642,2642,'老师上课会提问 我回答了几次 总平时分给了将近满分 人很温柔 讲课也是合格的 也能为学生解答清楚疑问 点名也只有几次',5,5,5,15,0,0);
