INSERT INTO "reviews" VALUES('677fb0e18101ac2f441b8e35',1699,211,'儒雅随和的老师，平时分给的很不错，每次课要签到，单片机实验可能要麻烦一点点～',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('677fa8a19d433b7c9612428c',3911,3911,'期末考试占总评70%，给分很一般，期末不划重点，上课喜欢跟你探讨交通各方面内容，探讨到期中都没开始讲正课，ppt第一页放了一个月才切换到“目录”，期末汇报喷学生做的不好，没事喜欢找别的老师专家来客串，还让去参观公交公司',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('677fa3568101ac2f441b51d7',170,233,'哈哈……哈哈哈……老师太棒了，第一次见这样的平时分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677fa30d4a556c651f2a1dbd',1762,415,'为什么没有0分',1,1,1,3,0,0);
