INSERT INTO "reviews" VALUES('677e89be8101ac2f4417454a',175,773,'上的是这个老师的人工智能课 没缺勤没迟到 作业没漏交没迟交 上课也回答问题 平时分奇低无比 期末成绩都比平时成绩高 鬼知道怎么评的 上课不来的平时分能有90 气的爆炸 问他成绩还不耐烦 一问就说让我复议 早知道这样还不如翘课 真是没话可说 ',1,1,1,3,0,0);
