INSERT INTO "reviews" VALUES('677e704af2f9f93511b2de50',819,228,'这个老师千万千万不要选，真的，平时不缺勤，作业按时交，小组作业也汇报了，结果平时成绩就8十几，其他有的班能拉到均分95，罗敏的班最高分都没有90',1,1,1,3,0,0);
