INSERT INTO "reviews" VALUES('677e66236db11a18acf1eb19',2631,198,'作业多的不行，他自己的数电也是现学的，能对着根本不考的一章讲整整三周也是给我气哈气了☺️但是人还是很友善的，半期考试强行往上拉分',1,3,5,9,1,0);
INSERT INTO "reviews" VALUES('677e58675d97b2416da8cca6',788,40,'开学选课的时候老师没有评分，战战兢兢盲选了，上课管很松，连座位都没固定，学期里面点了几次名，最后平时成绩拉满i了，老师讲的也好但是英语课嘛（',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677e4d3a8101ac2f44161660',348,348,'请苍天，变忠奸，老凯是真的会捞',5,4,5,14,0,0);
