INSERT INTO "reviews" VALUES('677e435d9d433b7c960cbbb3',194,194,'超级无敌好。讲的好，性格好，给分好！！闭眼冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677e4228f2f9f93511b1fe89',194,194,'康康老师呜呜呜呜呜呜，又温柔讲课又好，画重点很到位，简直我的神，遇上他你们就偷着乐吧呜呜呜呜呜呜，平时分打的懂的都懂呜呜呜呜呜',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('677e3c4f9d433b7c960c8934',831,762,'上课不咋听得懂，但有一说一平时分还是给的挺大方',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('677e34c3f2f9f93511b1a5c7',626,306,'虽然上课不点名，但是喜欢叫人上去画图，平时分特别低，照着参考答案画的图都才给七八十分，我见过平时分给的最低的一个老师，没有之一',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677e1f5ff2f9f93511b10b8a',38,223,'恶心死了，给分巨低，一个选修课，事多就算了，我能忍受。小组作业给你认真完成了，期末作业认真完成了，上课我都出勤了，还坐的前排，问题也积极回答过。结果平时分就给个80，好声好气询问一下平时分给分的标准，不正面回答就算了，反而还觉得给80分还给高了，像赏赐一样。拽的跟个二五八万似的，身为教师一点人文关怀都没有，语气里满满的傲慢。本来觉得上课的时候，老师讲挺好，认真积极配合了，结果分打太低了，真的太失望了。能避雷尽量避雷吧，特别是对绩点有要求的同学。真的没见过这样乱打分的。上大学以来最ex的老师',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('677e020bf2f9f93511b08578',2469,67,'电工电子无脑选，期末前还画重点，考的低给你海底捞。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677dfa3c5d97b2416da6b919',3964,80,'想过离远点，鲨滩脑戴不知道想的什么，诚心不让你过的，跟入机一样',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677df89f8101ac2f44144423',3964,80,'想要上课的，选他，课讲得好；想要高分的，选他，只要肯露脸，平时分不会低；想要不上课的，选他，根本不会点名；想要不挂科的，选他，他一定会捞你的。
