INSERT INTO "reviews" VALUES('677d4f48429bf70977bc48c2',3968,3968,'其实是日语Ⅰ，但是活水上只有2就写在这了。老师很温柔，给分也高🥰上课会写比较多练习题，回答问题朗读也是挨个挨个来，想学日语的快来👍🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677d41e49d433b7c96091788',788,40,'平常没事但是给分巨底',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('677d416b429bf70977bc179d',543,543,'王老师讲得特别好，是大学里为数不多的讲课让我能听懂的老师。一个学期就点过两次名，而且布置作业也会及时发答案给我们学习，选了她你流体力学必过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677d36c85d97b2416da48060',3971,3971,'你真是活全家了，41和42分有什么区别吗我想问问你，多给一分就过了你偏要恶心一下人？上课从头到尾就知道吹牛逼，吹自己多牛逼多牛逼，重点是不画的作业是没用的上课是吹牛逼的考试是要挂人的一节课从头上到结束不知道你这节课说了什么，我想问问你啊你是不是觉得自己可有学术水平了啊，觉得自己是个人物了啊，就你也配当老师啊吹吹牛，读读PPT也能混工资的话我感觉我也可以当老师啊',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677d2f555d97b2416da455ce',109,109,'他确实上课有点无聊，平时要求有点高甚至奇怪，但他是真的刀子嘴，豆腐心，想过真的什么也不会都行，实验一对一考察你什么都说不出来，他就耐心给你讲，最后实验这一栏什么不会也96，期末只要劝他他就同意开卷，加上平时分总分真的不低',5,5,4,14,0,0);
