INSERT INTO "reviews" VALUES('677d1f99f2f9f93511adae64',592,194,'老师她真的好好呜呜呜呜呜呜，讲的很清楚，课堂氛围也很轻松，平时分给的巨巨巨巨高，基本上都是满的呜呜呜呜呜，神仙老师！！！',5,5,5,15,0,0);
