INSERT INTO "reviews" VALUES('677ce94cf2f9f93511aca15f',626,175,'一点不捞人啊57分就这么水灵灵的挂了快跑',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('677ce05e9d433b7c96072ddc',42,43,'对不起🐉哥，抱怨了一学期结果最后平时分给我58分（满分60），我预习报告有好几次B，还有一次二验，但最后貌似没扣多少分。不过🐉验收实验确实比助教严格，会很恼火（）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677ccbeb6956c579b9c89d20',178,946,'期末透题的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677cbbbb463f2652395670d6',68,40,'这些年改善了，平时分拉的满满的，前面说是举手才有加分，我一学期都划水，最后给的满满的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677cbae7463f2652395667ac',1901,250,'真的被他无语死了，平时分给的巨低，就百分之16的平时分他要扣我两分，真的无语死了，关键我是全勤加作业全交，只是个别时候做的作业有点难会有点差，但是没放空过任何题，主要我是认真写的这样错了才能反映自己真实情况，真是那群全抄答案的给满，认真写的给低是吧，要不是考试占比高，指不定要被这个老师拖累多少分。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677cb6847d0bf93db8e48420',299,5,'很好的老师，待人热情和善，教学很认真，美中不足就是上课带了口音，只能说是我和杨老师缘分未到',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('677cae4db954b334c1d19147',3568,462,'可爱的卷卷老师认真负责，知识点都会讲到，虽然有一丢丢福建口音，但还是抵挡不住我的喜欢！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677cad1359bcea15154acc91',2151,1087,'言而无信，平时说的好，说会给加平时分，比如补课的时候去了加2分，结果不加，平时分是按期末考试给的，考的低就给的低，考的高就平时分高，不存在捞人（给低了补考还难受）作业一学期两次，不过一次就是一堆，总结，平时分给的不高（对于想低分过的）选其他老师吧',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('677caca5463f265239561515',3990,294,'听的是Liya的通用学术英语，但是活水上找不到Liya的通用学术英语呜呜呜，就只能来这个下面评价了。Liya老师上课讲的非常好，很有系统，很有逻辑且言之有物，真的会很有收获。而且Liya会在第一堂课就明确整个学期的学习进度，并且会手把手指导我们完成作业。比如像那个pre，Liya直接把PPT模板发给我们。分数是公平客观的，态度认真平时分是正常的。期末考试是看个人与老师无关。我爱Liya！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677ca4686956c579b9c7a409',785,114,'我太爱他了，平时成绩拉满了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677c9ecdb954b334c1d12a8c',610,610,'半期30 期末31 给我捞上去了😭👍🏻',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('677c9db859bcea15154a686b',3993,241,'老师人美心善，期末给分巨高，大家都快来选！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677c8e1859bcea151549f878',1130,1130,'神人，一个线上预习作业占总成绩10分，稍微一点不对就给你算错，莫名其妙拿了67分线上成绩',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('677c8c106956c579b9c6ea4c',1021,228,'回答问题答得多就可能把平时分拿满 上课不能玩手机 会一直强调玩手机的问题 不太适合想水课的同学',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('677c8ad692a52c17d7b954d3',852,760,'禹爹下午靠你了',5,5,5,15,0,0);
