INSERT INTO "reviews" VALUES('677c740c59bcea151549403c',23,23,'激情四射，幽默风趣，能够激发同学们的学习热情，回答问题极具耐心，神中神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677c1ac159bcea15154893d6',96,96,'（不过审，脏话）人麻了，阿米诺斯',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677c0e717d0bf93db8e13dd9',1103,1103,'为什么没有0分',1,1,1,3,0,0);
