INSERT INTO "reviews" VALUES('677bfee159bcea1515483ce4',1130,1130,'给分苛刻，事情多，和英语课有的一比',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677bf319463f2652395358f5',4003,4003,'蔡老师捞我了，无需多言，神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677bea75b954b334c1ce1296',21,40,'作业太多了人也非常严肃 没有学到什么东西 完全打消英语热情（本人极度热爱英语高考142）上课特别喜欢抽人回答巨多问题 比大部分班作业多得多 平时分不高（我的u校园是自己做的分数不高 是分数实打实的换算 所以我平时分很低 但很多班是看完成度）但因为背考四级每周做一套真题外加我自己喜欢英语所以自己练口语刷题背单词还有巩固花的时间也很多 我觉得做的有用的事情其实对我的平时分没有帮助 只是期末考试比较高 但平时分扣十几分的话总分也不算高 可能只是太严格了然后我也没有特别努力吧 感觉真的挺打消英语热情的 有点遗憾..',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('677be7266956c579b9c4c5ea',831,762,'不理解为什么评分这么低。首先，老师点名和签到很少，签到定位，但是整个犀浦都能签上😂其次，课堂测验和小测都是在学习通完成，她不会盯着你做，允许你翻书或者搜题，因为她觉得这些只是为了让你掌握知识。作业就是好好做练习册，时间给的很宽泛，没交的还可以补交。两次小测有很多人因为各种原因没有提交成功，在我看来那真的是自己的问题，但是老师给了机会重新交。并且小测取得是两次的最高分。平时分的作业部分是按照作业平均分给的，平时好好做就会很高，一般都九十➕。其他的能操作的分数全部拉满。可能讲课逻辑有点欠缺，但人很好，问问题都会回，专业知识也很扎实，更新一下版本啦uu们！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('677be5b57d0bf93db8e07d34',264,230,'学识渊博，要求松，点名还会预告。对历史有兴趣的能学到课本以外的东西，纯划水老师也不太管，不过智慧树之类的得做。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677be4c36956c579b9c4b700',3463,3463,'老师很和蔼，课上会说评分标准，也会叮嘱学生记得做慕课的任务（不是刷过课就行了，要按老师要求提问）。总分由几部分构成，超市、考勤、体测之类的自己拿多少就是多少，但是慕课按要求完成之后给分超高，达到气排球考试要求之后给分也超高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677be4b1463f265239529699',278,228,'挺好的，不知道以前咋样，反正现在还不错，应该是改邪归正了吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677be2d6b954b334c1cddcda',958,23,'点名和作业要求多，给分公开透明（即不捞人但不压分），时不时怼人，如果不自学上课可能听不懂。不过会答疑。',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('677bdfb56956c579b9c49283',598,28,'反正我重修，总评六十分👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677bdeac59bcea15154781e5',360,1648,'大赞计算机图形学理论课，狠狠地捞了我一把',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('677bdb017d0bf93db8e0336e',1065,1065,'平时分五十分拉满了..只要回答满五次问题（回答问题是马院的规定，老师基本都要求）任何人想回答问题她都会给机会，把所有要回答的人点完。老师人美美美美心善善善，上课也只点过几次名，反正下辈子还跟她！😭😭我的完美老师😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677bcc9392a52c17d7b68975',626,175,'我恨你',1,1,5,7,0,0);
