INSERT INTO "reviews" VALUES('677b923559bcea1515458ed8',2525,296,'像高中老师，讲解耐心透彻，认真听肯定有高分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b91c57d0bf93db8de5c1a',2484,92,'全世界最好的老师😋给分高 上课讲的不错 不听也不管你 基本不点名 考试前会带着复习',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b88b26956c579b9c258cb',96,96,'作业交满了不管等级是什么都是满分，签到是手机签到就算你不去上课只要在手机上签了到也是平时分拉满，点名会通知，雪梅公主傲娇点怎么了，爱死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b7b1b7d0bf93db8dd5fbe',278,228,'不知道老师以前是不是很逆天，但现在绝对改过自新了。上课口头说不让玩手机，但实际上你偷偷玩也不会刻意管，期中考试课堂测给分都很高，小组作业和笔记做了分数就不低，而且点名比较少，唯一要注意一下的就是不要迟到（这是刘老师特别反感的），一学期下来总分47/50很简单，平时分低的同学稍微反思一下自己该做的有没有都做。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('677b77c07d0bf93db8dd4378',769,833,'姐很好，分很高，但是期末复习还是看作业题吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b65017d0bf93db8dcd39f',2012,296,'期末平时分拉满 讲的细心 符老师你是这个👍👍👍👍👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b644bb954b334c1ca8081',1169,1169,'西交自己的大力王',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b61ac92a52c17d7b398df',40,40,'改邪归正，三次旷课平时分90折算45',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677b5a156956c579b9c11e46',40,40,'上课整排整列抽人回答问题，但是期末平时分给的奇高，我旷了一次课还能95的平时分，上课也够水，虽然感觉水平不太高',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('677b4cc8463f2652394eaa65',2584,40,'神中神
INSERT INTO "reviews" VALUES('677b38a4463f2652394e0df3',515,118,'晟哥YYDS！美国回来的，基本功扎实！上课会拓展很多东西，对想好好学习的学生是真的无敌！找他问问题，他也会特别特别耐心的回答！期末划重点也特别详细！下面那个差评我不同意，绝对是他没有好好学！唯一的不足，就是经常半夜发作业，吓死个人！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('677b30346956c579b9bff1a6',1243,4033,'伟大无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677ab2c1463f2652394c9fdc',25,26,'你要是他的高等数学，建议抢着当他的高数小助理，能给除考试以外平时分拉满',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('677ab1a9463f2652394c9bef',450,450,'属于纯纯的刀子嘴豆腐心，平时分除了期中期末考试能给就给，主要是这门课实在是有点难度，而且他不怎么给你大题过程分，上课很凶，刚柔并济吧',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('677aa56fb954b334c1c76380',76,76,'平时分随便给的，期末考试都是作业原题，神中神无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a714892a52c17d7ad3b63',255,223,'课很好，那我只能说22电气那个哥们选修课只给了60分，自己是真的不行哈',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('677a6a8659bcea15153d32ed',1082,40,'基本上不点名不签到，但是会叫人回答问题，回答问题加分，老师人很好，作业基本没有，课堂互动性很强，适合积极进取对自己要求高的学生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a68a6b954b334c1c307d5',278,228,'非常好的老师，不知道为啥这么多差评，老师看着严肃其实挺有亲和力的，要求也不高，就做过一个ppt演示，平时分给的挺高的，基本上不点名不签到，主动回答问题加分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a4f3a92a52c17d7ac5d35',1158,5,'人美心善幽默脾气好，再蠢的问题都会认真解答，给分也是无敌慷慨，泥胶线代活菩萨',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a4ed26956c579b9b945bc',588,588,'讲课烂人还凶，恶趣味极大复习课讲完题目转头出卷避开考点，专门出偏门的。上大学以来碰到过恶心人的一个，上他的课这辈子有了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677a4c31463f265239480f46',3446,2119,'从小到大没见过这么好的老师，极大的提高了我的自学能力',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677a44076956c579b9b8f96e',353,859,'老师人真是谦和极了，那个平时分也高，期末考试分也感觉溢出的高。我敢说你报他的课99.99％不会挂科',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a429b59bcea15153c248d',4044,737,'平常上课真的真的提问多，有作业，作业平时分还不高，选课的同学真的要三思。',4,5,1,10,0,0);
INSERT INTO "reviews" VALUES('677a3b1592a52c17d7abce93',334,175,'涛哥真的很好，讲课很清晰，下来问他问题回答得特别认真，从来不会敷衍，作业稍稍有点多，但给分和其他老师持平。而且基本上不点名，逃课他也是睁一只眼闭一只眼（我们班当时只有4个女生，他都叫得出名字，每次没来私下都要问，但从来没扣分，我们都旷了很多课）。涛哥绝对是被黑了！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a399859bcea15153be227',99,361,'照着PPT念，一次小组报告两各论文，每天上课都要签到，还有数不清的测试题。17周开卷考试还不能用手机',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('677a38ca7d0bf93db8d505c6',4047,4047,'平时分乱给',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677a36a86956c579b9b88ed3',85,85,'想你了陈老师😭😭😭要不是大三没有您的课，直接跟您走完大学了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a2a1992a52c17d7ab4636',3911,3537,'不建议，无重点',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677a29c8b954b334c1c14692',2765,2765,'神中神，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677a289a59bcea15153b62ba',3755,80,'私似沐表字减重愁亩✓，跟个沙鲁安一样听不懂人话的闹腾东西，糙疼吗，院长天天厚乳她表示亩琴几回才有机会让这✓重来这学校教书的？💩💩💩💩😡😡😡',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6779fa9292a52c17d7aa07d2',2461,2461,'交运的这门课原来是两个课，铁路的和列控，并到一起后变成了一门课。我是上学期上的，忘了评，今天注册了顺带提一嘴，能避雷就避雷，讲的800年前的东西，PPT用的04年的，比我都大。期末考试拿书画重点，卷子不是她出，她也不管考啥，考的甚至都不是书上的，气笑了属于是。给分也不是很可观，祝选到的人好运。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6779f9c27d0bf93db8d35312',706,706,'第一次用活水就是为了给胡老师打分，去年吕苗苗的信号没来得及喷，先喷胡老师。不得不说，胡老师可能是一个经济学专家，或许他讲经济更有权威性，上课不怎么点名2-3次，他也不太会管你的干什么，所以上课还是挺好的。我们今年一共两次平时作业，一次论文一次文献综述，期中考试五道开卷论述题，平时分占的30%，你会难以想象主观性的东西他会给多低的分，我自认为自己花了不少功夫，没有用gpt，全部自己打出来的，可能离标准还是不够。期末考试没有重点，一句话不提，给了一个PPT，拿到卷子单选 多选 填空 判断改错 简答 计算 论述 所有恶心的都考 有10分是书和PPT都没有的，卷子胡老师出的。㊗️胡老师越来越好！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677982556956c579b9b54191',1906,1990,'大学四年遇到不好的老师屈指可数，但是钟萍绝对是数一数二，考试不及格点名道姓艾特，上课点名又多，课程设计不说要求交上了之后打低分然后才说要做100页以上。平时分巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67793f79b954b334c1bc8f09',1127,4055,'伟神伟大，无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67793b7559bcea1515364cd5',1906,1990,'快跑快跑快跑快跑……大学四年见过最抽象的老师没有之一。三连讲一个课间都没有还能每次稳定拖堂二十分钟＋，最后一次课讲了一节课课设排版然后拖堂一小时莫名其妙为了你们好划重点，问题是其他班老师直接给提纲都没上课啊。作业要求多，每节课按时到作业自己做最后期末考试分还没平时分高。还在群里＠所有人说课设明明要求了一百页，最后75页的课设给不到七十分。哈哈哈哈哈给爷气笑了（土经管）真的布施仁',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67793abb6956c579b9b412fa',1906,4057,'没有土经管就写这儿了，希望能被更多人看见。大四了都，第一节课说大家可以自习只要不玩手机大声说话就好，然后点名是节节课点名的，明明说了可以自己干自己的事，也没影响她上课，站在台上就开始阴阳全班同学。9.45-12.15的课没有课间！还要拖堂！注意是没有课间还要拖堂，节节如此！期末考前人家班给个考纲，先说四十分钟废话然后开始划书拖堂到一点。期末给分还特别低，不让提前交卷要摁等剩半小时才行！不考的内容还要布置平时作业，一有什么小问题（例如没有按她要求用A4纸）绝对不会留情，当着全班的面阴阳你，群里经常点名批评一些同学，补交的作业还要降分处理（她原话是c级70-75分）。总之就是快点避雷吧，一分都多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67793a816956c579b9b41191',1906,1990,'没有土经管就写这儿了，希望能被更多人看见。大四了都，第一节课说大家可以自习只要不玩手机大声说话就好，然后点名是节节课点名的，明明说了可以自己干自己的事，也没影响她上课，站在台上就开始阴阳全班同学。9.45-12.15的课没有课间！还要拖堂！注意是没有课间还要拖堂，节节如此！期末考前人家班给个考纲，先说四十分钟废话然后开始划书拖堂到一点。期末给分还特别低，不让提前交卷要摁等剩半小时才行！不考的内容还要布置平时作业，一有什么小问题（例如没有按她要求用A4纸）绝对不会留情，当着全班的面阴阳你，群里经常点名批评一些同学，补交的作业还要降分处理（她原话是c级70-75分）。总之就是快点避雷吧，一分都多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67791dfc92a52c17d7a6713c',411,36,'缺点:有川普(问题不大），课后会有小作业和签到。
INSERT INTO "reviews" VALUES('67790f807d0bf93db8ceb78d',1021,228,'给了我平时满分100的顶级老师，就是上课不让玩手机不让写作业（虽然他会说你，但是你仍然可以偷偷玩偷偷写），期末给你划重点，超级爽啊，上课回答问题有加分（特别简单的选择题，随便答疯狂加，我加了4分）想要高分的你就狠狠的给我冲，虽然上课苦，最后给你分，让你直接起飞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6778ec30463f26523940df7f',214,36,'平时喜欢喷洋文。上课讲个文言文，被学生指出错误，还整上一个故意说错，期末不划重点，避雷，太扫码了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6778eb5292a52c17d7a50683',4044,737,'上课不点名，但是经常抽问以此代替点名。
INSERT INTO "reviews" VALUES('6778ea6792a52c17d7a4ffcb',2765,2765,'不知道给差评的人是怎么上的课。史老师上课很水，不会管你在做什么。整个学期一次作业和一个期中测试，作业很水交了就是90+，期中测试做了就是满分。期末报告也很简单，80+随便拿，总评要上90应该说是非常轻松的。
INSERT INTO "reviews" VALUES('6778d96f59bcea1515339bcd',2432,2432,'很顶级，除了期中都是满分，就算旷课考勤也给满，要是期末很低，还会捞你给你加点期中分，神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6778d913b954b334c1b9bd41',76,76,'神中神，上课不点名，期末只要看会平时留的作业，随便拿捏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6778d08d463f2652394002cf',4066,24,'平时分给到98（好几个同学给到99
INSERT INTO "reviews" VALUES('6778c1b46956c579b9b0c491',529,529,'偶遇极品老师强如怪物，不教东西不讲道理，拼尽全力无法战胜。上课是对着照片自己画的，东西不知道教哪了，作业是要多到占用你所有时间的。学院是没安排考试的，自己是非要当土皇帝安排的，占用考试周复习时间填他的天坑，还硬要说其他学院统一安排的考试不算考试。学生放寒假人都走了他突然出现，作业是要当天收齐的，管你这那那这交不上是吧那就全不及格。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6778c017463f2652393f945d',529,529,'发信息是全平台不回，交作业你要随时待命，留作业不给要求，交作业时不满意你就重画去吧，要不然就是挂科吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6778becdb954b334c1b8fc75',588,588,'讲课讲的依托，听两节课听不懂，还对学生人身攻击，果断退课，但一想没选这个限修课大四还要多学一门别的限修课就不爽，果断回来给你一个一分。这节课和通讯原理我是真想不懂为啥培养计划有这玩意',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6778b0866956c579b9b03284',529,529,'作业暴多 想一出是一出',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6778a87092a52c17d7a31645',3911,3911,'上课总是不来，期末没重点，上课一坨💩，期末考试又难',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677814bc6956c579b9adef2e',4072,126,'实变函数，真别太认真了，哥们期末快满分，平时分你给我80多，每次作业都是认真写的，给分只看你批改的十几次作业中的两次，那我还不如就只写两次作业呢，我们认真写作业还有必要吗？真的越想越气，逆天！千万别选！！！',1,1,1,3,0,0);
