INSERT INTO "reviews" VALUES('6777efd9b954b334c1b5ac1a',788,788,'李娟你码什么时候私啊',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6777b9c7463f2652393aee3b',626,175,'开门见山，给的分数非常低，上课还会抽人上去回答问题，在黑板上画图，而且平时分非常非常低，平时作业多少分就多少分，但批的很严，而且制图答案难找，千万别选！！！',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6777b79792a52c17d79f05cb',499,194,'在这里给差评是希望重修的同学看到。千万不要选，除非你能严格要求自己按照老师的要求来。起码对于我来说，李老师的成绩都是如实给的，不存在拉高平时分的情况，半期我没有参加，也不能申请期末成绩替换，最后的平时分是29/100；期末要考90分才能过。希望重修的同学能慎重选择，不要以为平时做了一点老师最后就会拉满平时分，拉满的也许都是那些本来就能拿80%的同学。',1,1,1,3,0,0);
