INSERT INTO "reviews" VALUES('6777aba459bcea15152dd199',588,588,'快跑吧，上课讲的听不懂，迟到了或者坐后面或者低头就会提问你，回答不出来就扣平时分。毫无重点，一学期每节课都听讲，课后习题也认真学了，期末考试出的题目还是不会。。。',3,2,2,7,0,0);
