INSERT INTO "reviews" VALUES('677752c8463f26523938142b',442,442,'老师真的会捞人，泪目了，感谢老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6776cd3c92a52c17d79a50d7',142,760,'作业超级多，作业系统和雨课堂作业混着来，而且每节课都签到，雨课堂回答问题，平时分给的很严，59的平时分是人能给出来的？',2,2,2,6,0,0);
