INSERT INTO "reviews" VALUES('6776c420463f265239363c53',1273,157,'喜欢被pua，被阴阳怪气，被打低分的可以来；校园生活太如意想给自己找点挑战的可以来哈🥰',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6776bcfd59bcea15152959dd',3507,1732,'人工智能课程找不到他。虽然这个课程所有老师都要避雷。一学期你可以不浪费我们时间的，每节课都在讲大道理，我为啥要听你一个理工科的讲道理呢？最后一周想听你划重点，你又来和我们说“别局限于课内啊”。上课内容一点不讲，但我要考试嘞，大二这门人工智能课其实还是导论课，作为一个学生，放大一上或者把这门课取消了，包括大一上上的人工智能导论课，两个都是一坨。',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('6776b87159bcea15152943bc',860,860,'讲课一般，但是考试两个半划重点不一样，避雷，而且基本每节课都点名',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6776ab407d0bf93db8c298aa',2631,198,'课是讲不清楚的，作业是留的最多的，学生的建议是不听，半期是必须在教室考的，勾重点是全目录的，嘴上是最甜的，干事是出生的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677698657d0bf93db8c21b7d',3691,3691,'电气不应该有这门课，ppt十几年没改过，复习提纲甚至最早从17年就开始一模一样的发到现在，以至于你根本不知道期末会考那些东西，甚至题型都不说，垃圾课程垃圾老师，建议网课',2,3,2,7,0,0);
INSERT INTO "reviews" VALUES('6776985559bcea1515288a0a',1024,1024,'上过邓老师的必修和选修。邓老师是全世界最好的老师，人很温柔很有趣，每节课都有精心备过课，而且内容很新颖。如果喜欢文学一定不要错过邓老师的课，她的课绝对不会让大家失望的！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677675c77d0bf93db8c11b64',2765,2765,'给分绝啦，交运的都去选吧，期末随便给分，早八天天点名',1,1,2,4,0,0);
INSERT INTO "reviews" VALUES('67766a1459bcea15152734b1',442,4101,'差差差！！跑！！！纯有兵，上课是讲不清楚的，说话是难听的，平时分是低到一定境界的。到底谁在给好评？？？别选他，这人真的就是以挂学生为目的来教书的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677659d6b954b334c1acd488',832,449,'给平时分巨恶心',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677657d6463f2652393394c8',588,588,'喜欢人身攻击，喜欢监考的时候嘲讽不会做的同学，喜欢跟一起监考的老师聊天，喜欢嘲讽除了电气的其他学院看不起其他学院的学生。。。因为一个老师讨厌一个学院还是第一次。。。',1,1,1,3,1,0);
