INSERT INTO "reviews" VALUES('67764d6bb954b334c1ac6d5c',3407,762,'微积分期末考含金量无需多言啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677642a46956c579b9a3246e',359,228,'平时成绩出来就无语了 别的班事情比它少分数比它高 平时这也要算分那也要算分 期末了自己加个平时分都加不清楚 统计了的平时加分没加上 你去找它它和你说不予理会 讲课不知道啥样 没听过 反正没了屁屁踢不能讲的那种 小组作业做了就做了吧 还要班上展示之后抽人点评 是不是自己不会上课所以要搞这些过场混时长啊 它算得上是上大学以来印象最最最差的一个老师了 遇见它真的倒八辈子的霉 想发掘它这样一个宝藏老师的可以来试试',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('67763c9859bcea151525d3a3',505,561,'超好，只要认真做作业平时分95+，一般来说90+也没问题，如果作业提交出问题也会解决，不会扣分，讲的很好，超级清晰，有时确实会有点快，但是一直跟着走没问题。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67761e7e463f26523931eb16',515,118,'神中神，上课不点名，作业约等于没有，课讲得也好，平时分拉满，考前划重点。想混的能轻松过，想认真学的也真能学到东西',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67760c98463f265239316671',560,560,'很莫名其妙的一个人，给分看心情，在莫名其妙的地方卡你',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('677607ca59bcea151524527d',230,230,'真的，遇到这样的老师是真的逆天，去听课他要骂你，那我还不如不去听课，平时分也不给满，期末考试这么多东西这么背？我是学历史的吗？那些给好评的，祝你们一辈子都是这样的的老师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677566f192a52c17d792eb84',4112,114,'难评！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677552fd92a52c17d7928a5a',2500,228,'神！神中神！古希腊掌管期末考试分数的神！上过袁老师课的都说好，他真的我哭死🥹',5,5,5,15,0,0);
