INSERT INTO "reviews" VALUES('6774eca2b954b334c1a50219',101,114,'期末考试监考的时候还会提示你，什么含金量我不多说。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6774eb87463f2652392b9a21',640,229,'老师人还是挺好的，问她问题也会细心解答，就是上课有点过于传统了，下来认真复习基本问题不大',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('6774e125463f2652392b517f',4119,4119,'分低，全勤+期末认真做就八十多，和其他选修比起来真的很烂，不推荐',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('6774dfcd463f2652392b47d9',799,799,'沙比老师，电力系统对计算步骤要求这么高的课，上课讲题不讲过程只会照ppt念，他亲手打出的QQ群消息发作业答案结果变脸，所有作业题不发答案让我们照着好的同学的写，期末没有重点没有ppt，只有他一厢情愿的“考试提示”（QQ里发几段文字就完了，简答题的提示是多看PPT），节节课点名，最可恨的是同学要拍他的期末ppt他还摆出一副嘴脸，说这是上课不认真的表现，摊上这样的老师建议马上选其他老师，不要到期末连作业都搞不明白，就连自己说过的话都做不到，纯纯的懒猪',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677395ea53e867372c08f376',4121,4121,'给分真的很随意，也没有告诉大家具体的标准，期末直接就是一个小组展示，根本不看别的，喷泉上平均分挺高的，但是有可能你就是那个分母😑',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('677375ad8c07e50a483c34b4',2584,40,'水但分低的要死',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('67735e3853e867372c075c30',1904,1904,'教我们材料力学性能，上课的人知道他的含金量，牛，老师人巨好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6773599953e867372c074397',1705,1241,'我最爱的老师👍👍👍👍',5,5,5,15,0,0);
