INSERT INTO "reviews" VALUES('6772bca48c07e50a483a3747',1850,34,'作业多得批爆',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6772aa92ab7cdd52d31b15dc',807,862,'神中神！考试题出的贼简单！说简单就简单，一点不骗人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6772aa8b8c07e50a4839ec65',4081,841,'软件分析来的，期末都给65，会做过程也正确，组里就两人还这么低。真的是搞不懂，平时分那次上课正好是保研填报志愿时候请假了，该扣还是扣。
INSERT INTO "reviews" VALUES('6772a5548d47a742dd62cb79',2028,2651,'一份是活水的底线，不是他的底线',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6772971ffe905f512d53ca07',373,619,'上的习概，刚考完就过来评价了。在所有的班级都只给提纲之下，我问遍了其他班级都不划重点，而就在考前一两天她在微信群里偷偷给我们发重点，这个重点全是试卷上的问的问题（包括选择和大题），考完后我只能说就差直接把试卷给你了，作为一门保研课陈洁就是我的神！都给我去选她。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('677296f0048ba05bd57b8e0f',373,619,'无敌好吧，五星上将，无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67727a648c07e50a4838f3f3',4132,4132,'差极了。上课格调拿得高的就看不起你那个范儿，提的问题不知道在讲些什么，老爱叫人回答问题，又不说正确答案，一通胡然就过去了，期末压分严重。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6772779e8c07e50a4838e569',31,31,'听秦老的课，只要认真听，跟上节奏，压根就不用去看宋浩老师的网课也能考高分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6772605e048ba05bd57a4bd4',1287,1287,'平时分也太他奶奶的低了吧😤',3,4,3,10,0,0);
INSERT INTO "reviews" VALUES('6772539b631e1b04a02e7219',515,118,'很好的老师，上课不点名，讲课很有意思，老师很有耐心很尽责，能上晟哥的课是我的荣幸',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6772533a631e1b04a02e6f94',193,193,'上课照本宣科，硬读ppt，不准玩手机，剂量堪比安眠药，直接睡晕。作业课堂一般能完成，缺少期末复习资料与习题，期末只能看网课女娲补天。但课堂答疑环节有求必应，耐心尽责，专业水平过硬，但是我个人来说学不到一点，上课真的巨巨巨巨无聊。是一个很耐心很尽责的老师但是对不起🧎这样上课我真的一点都学不会，第一堂课感觉毫无切入点，就放了一大段代码，我那时候真的是一个字都看不明白',4,2,5,11,1,0);
INSERT INTO "reviews" VALUES('677245c2631e1b04a02e18d4',2168,2779,'老师人挺好的，平时分给的比较高，但是采购这门课期末考试挺难的，可能是我复习的不是很好吧，最后分数并不高，还是选高级编程语言吧，起码没期末考试',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('677243f5fe905f512d51feac',4138,4138,'我男神，平时和期末都是100分如何呢，刀子嘴豆腐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6772087fab7cdd52d317d36c',832,40,'相当恶心，故意卡你平时分，给得巨低，而且绝不会捞人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6772026453e867372c01edc3',12,4,'朱曦老师你是我的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67716b5600e84069cca2d826',725,40,'帮老师就打分这块澄清一下。老师人很好，给分很宽松。但班平要在一个区间，是整个年级规定的，老师会尽最大可能把分给到最高的，除了课堂测试这是谁也没法变的，其他部分老师都给分很高，最后我的平时分90+',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('67716340631e1b04a02b417d',1542,1542,'跑跑跑快跑 期末她自己忘了评优免考的期限 其他班都已经出了免考名额了  就她不出 考前去问她她说全部都得考不评优了 服了辛辛苦苦做的大作业完全没用 ',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('67714ed3fe905f512d4eb462',89,33,'分配黄老师你就有福了，从未点名，u校园四级忘记写了还能平时分45，我爷爷级别的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67714d558c07e50a48346123',658,658,'烂，期中试卷出的比其他班难的多，平时讲课也很拉，期末考试的前一周还在留作业，考试重点也没有，问问题也解答的不好，回答之前先拷问一下',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('67714cf600e84069cca23acb',68,40,'史，乱给平时分，赶快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67713ba58c07e50a48340a94',2469,2469,'究极无敌好老师！选到就是赚到，每节课按时下课，绝不拖堂，上课很仔细，重点都手写在黑板上，最后一节课最后十分钟他都说是垃圾时间，直接就下课，考前有画重点，太贴心了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67713755ab7cdd52d3154a90',373,230,'好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677110a7fe905f512d4d7d96',3814,3814,'cs',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67710a7a53e867372cfe6a53',4149,1073,'马老师真的是神啊，平时基本都没怎么学，老师平时分酷酷地给，期末考试没及格，马老师直接修改平时成绩给我捞起来了，老师真的太好了，必需好评，最好的高数老师。给分高，事少，可以水过，爱了爱了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677108fe8c07e50a48330aba',1128,40,'别选，别选，千万不要选！那些好评都是刷的，不知道怎么来的，这学期被好评骗进去，选了一学期他的课。上课体验感巨差，经常强制点名抽人起来回答问题，问题很多，一节课大概要问10多个问题。平时分给的也是同类老师里最低的，满分50的平时分，只给30多分，身边的其他同学选的其他老师给的都是45往上，就离谱，课后基本不管，什么作业和通知都是最后才发或者直接不发，主打一个什么都不说，上课只念PPT，如果有人没吃过史可以体验一学期',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('677107fd631e1b04a02967be',264,230,'神中神，完全不点名，看人少了只是叹气，期末平时分给满！上课幽默风趣，想认真学习的同学也不会吃亏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677107f3ab7cdd52d3144c9a',281,281,'神中神，所有人的平时分全给100，神中神，每堂课都写满板书，真的很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6771079153e867372cfe541a',281,281,'课讲的不错，略有口语，每节课点人上去做题但是不为难你，期末平时分给满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('677106cc048ba05bd574f5f5',465,4154,'冯振勇，真神，实验报告随便写就行了，大家都给85，写的多写的少都无所谓，实验也不要求验收，可以n个人一组，真的爽',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6771065bfe905f512d4d41ae',1441,228,'就感觉很一般啊，给分很严，没有想象中那么好，平时分100算上加分也就85的均分，感觉和别的老师也就大差不差',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6771014a048ba05bd574d5d9',19,2812,'快跑吧兄弟姐妹们',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('677101228c07e50a4832d926',3930,3930,'这老师是我遇到最奇葩的老师🌚🌚',2,2,2,6,0,0);
