INSERT INTO "reviews" VALUES('6770db8c53e867372cfd60ef',1495,1495,'期中不考试直接算满分，平时分拉满，期末只要考20就过了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6770c1dd8d47a742dd5a3f92',278,228,'总结下：
INSERT INTO "reviews" VALUES('67700bc000e84069cc9d5499',11,11,'**老师
INSERT INTO "reviews" VALUES('676fff228d47a742dd57b838',48,48,'抽象无需多言。男生女生放一起打比赛排名算成绩。我笑死了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676ff6e4fe905f512d498c30',705,4163,'一点不会讲课，自控PPT最差劲的一个，和别的老师比起来真的是差了不知道一点半点，课件也自带防自学功能，特别敷衍，而且很不详细，很多题型都没有，需要自己课下去看别人班的PPT来弥补知识，想学好的去wyz和lcw，别来武越，否则课下白费功夫',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676fe9348d47a742dd573b32',1095,1095,'吴磊老师是cs中的顶级cs，是手枪局输了全甲鸟狙的诱饵蛋队友，是安禄山进长安的糖丸了，鼻孔塞花椒',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('676fdea8ab7cdd52d310034b',986,3816,'老师经常超雄，平时生气了点名不在就扣5分，还把来了的人的照片发群里说拿回去一个一个对照看谁没来，汇报批评用AI写的，说不好好弄就给挂，期末仿真要求极其严格，说抄的直接完蛋，没有仿真文件的扣40，是电气学子的最后一道坎',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('676f69f2048ba05bd56e2ec7',1554,1554,'看似严格，实际净整些闷骚的',3,3,3,9,0,0);
