INSERT INTO "reviews" VALUES('676ed1ae048ba05bd56ba3ac',2323,22,'我只能说是神，这辈子见过最好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676ec65a00e84069cc983a89',2074,40,'好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676ec305fe905f512d44cd60',4138,4170,'特别特别好啊 期末100分什么含金量 事也不多就只有一个大作业',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676e9bd1048ba05bd56a85e1',1523,26,'平时分拉满了',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('676e99bf631e1b04a01fd0e7',1095,1095,'上课讲的就是*，考试虽然不知道要考什么，但他拓展的git一定不会考，上完一学期是不知道有什么收获的，唯一教会的是怎么用文心一言',1,1,5,7,1,0);
INSERT INTO "reviews" VALUES('676e999bfe905f512d43d76a',1095,1095,'老人孩子先走！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676e985c631e1b04a01fc9ee',1095,1095,'他妈的，长话短说，我专门注册个这个账号来给他打低分，纯傻逼，我操，选到他这辈子有了，等考完期末再细说',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676e9590ab7cdd52d30abee5',1095,1095,'不好好教，都别选他。别的班老师不会让你用AI做题的',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('676e8b36631e1b04a01f830a',1500,1500,'赵可老师教学经验很丰富，重点突出。上课注重引导，有时候会把PPT改成英文的活跃气氛，寓教于乐。课后会认真批改作业，指出问题所在重点是考前会划重点！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('676e892b8c07e50a4828da8d',867,28,'活佛级别的，对学生特别客气，客气到🐭🐭坐立不安；也特别温柔，很好说话，平时分超级高，作业都是按统一标准留的，没有一点附加。🐭🐭平时分直接拉到95，下学期继续选😋👍🤤🤤🤤🤤🤤🤤🤤',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676e67e88d47a742dd50cab2',23,23,'刘霓，一个点满幸运值才能在大学生活中碰到的真诚的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676e5736048ba05bd5690ae2',1849,4179,'说好的开卷呢，期末最后一周17周你突然说个闭卷，而且重点勾了等于没勾，讲的全考，上课前布置作业下课马上就要收，谁听的了课，这谁受的了1星好评',1,1,2,4,1,0);
