INSERT INTO "reviews" VALUES('676e1e83ab7cdd52d3083459',3925,3925,'黄老师教学十分负责，要求严格却也十分和蔼，讲课经验丰富，知识通俗易懂，并会结合许多案例理解加深印象，并会补充一些十分有用的知识点，同时黄老师十分注重实践，上了他的回归分析之后能够较熟练使用R语言编程分析实际问题，老师上课的也经常提出一些思考题让同学们在教材的基础上进一步探究学习，同时也老师在指导科研项目方面也十分耐心和负责，能够学习到很多知识，是一位真正的即讲课讲得好，有科研水平突出的好老师!',5,5,5,15,0,0);
