INSERT INTO "reviews" VALUES('676d5f978d47a742dd4cd472',4195,457,'非常和蔼的老师，能把课上得有滋有味，在QQ上咨询课程作业也是有问必答，耐心提供建议',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676d580900e84069cc92164c',543,543,'老师挺好，一学期就俩次点名，其中一次用半期考试代替，平时上课会分享一些补肾知识，推荐一些中药啥的，最后几周上课拖堂就是因为前面推荐各种补肾药耽误了一点点课程，挺有意思的，作业也是交了就行就给分，而且作业可以无限延迟交，还会发作业答案，只需要在期末考试前交即可，选她就对咯',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676d5434631e1b04a01aa52f',102,66,'全是60出头 懒得喷。。又枯燥又严又分低，事还多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676d4edf8d47a742dd4c741b',1849,4198,'住区规划没有tag，所以在这里评价。该老师的优点是会帮忙亲手改CAD图，引得部分学生对其高度称赞。实际上却是一个废话连篇，自己认死理，和交流学生抬杠的老古板，凭借自己老师的身份，以甲方的姿态压服学生，强迫学生同意其观点。该老师评图和交流见人下菜，以自己的喜好不露声色的偏向自己中意的同学。',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('676d48ad00e84069cc91c88f',1848,1848,'老师我爱你TT特别细心温柔的老师，会很好很细致的帮你改方案，人美心善TT在建院最喜欢的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676d442aab7cdd52d3054c98',832,449,'对于敢表达的同学一定认准张老师，不怎么水但是真的能学到东西，不是照本宣科，不一定和别的班讲的一样但会教你很有用的知识（比如如何合理使用ai），超级温柔，即使回答错问题或者口语表达不好也会很包容引导你~',5,5,5,15,0,0);
