INSERT INTO "reviews" VALUES('676d2b6bfe905f512d3dcaa0',260,96,'水平不知道咋样，反正你问啥也不告诉。一天天就知道扣分。别的老师都是想让学生过，他倒好，能少给一分算一分。还不要脸的说自己给分多公正，其实就是个傻*。千万不要选他的课，赶紧跑。',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('676d17236a0b72000625c8b6',3821,4204,'我是通用学术英语的，想从英语课学的很多东西的别来，除此之外老师温柔亲切，给分超水，很好说话，不会点名，这么高的平时分你值得拥有',5,5,5,15,0,0);
