INSERT INTO "reviews" VALUES('676bbafc3fd6846b0b198f47',88,88,'孩子们快跑，相信我这条评论就行了，绝对不是恶意评论，虽然这门课实用性很强而且很新颖吸引人但这个老师给分巨抽象，在大三，别的网球班期末给95+，他平均成绩在60-75左右，考试一锤定音，压根不管你平时上课表现，成绩自己登错了还不承认，一直搞学生心态，我大学第一次遇到体育给50-60-70居多的老师，快跑吧孩子们，选了这个这比选了土木还要完蛋。',1,1,1,3,1,0);
