INSERT INTO "reviews" VALUES('676b8aa177124e2a6c7c03b3',2878,28,'给分特别高，能记住同学的名字，还很温柔讲课也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676b843ee1ddfb3297a99f20',2202,28,'目前遇到最具人文关怀的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676b72be3c83f17f55c07a5c',3628,3628,'实验课男女打分差异极大，女生没有低于90的男生最高没有过90的，看看你打的那点分，男生一个错号就打到75了，反正就是这不合适那不合适😆慎选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676b68e86a0b7200061da173',457,457,'不划重点😭',3,5,1,9,0,0);
INSERT INTO "reviews" VALUES('676b68943c83f17f55c03794',48,48,'不推荐抢这个老师的羽毛球，除非你对体育的课程分数没要求。首先每堂课都要签到，就算迟到一分钟也要扣你分。而且平时分给的巨低，一学期只迟到了一次，考勤分只有60，迟到还有连坐机制其他同学她也要扣分。而且没练过有点底子的话大概率你期末成绩也不会超过75。上课会对你的着装严格要求，必须穿运动鞋，没穿被她发现了就扣你分。还有一定要刷慕课，不刷少十分。',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('676b611f8097b23c9acf19e7',954,52,'耐心负责，点名巨少，和同学关系也很好，属于是那种比较幽默风趣的类型',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('676b5539e1ddfb3297a899c9',3502,217,'他的地图制图上课水的不行，照着ppt念，每次实验做完之后上课会抽人起来点评，期末平时分百分之30，不捞人，不给复习大纲，选到他你就乐吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676b54708097b23c9aced7e7',545,33,'很好的一位老师，上课内容丰富，从古代到近现代中外历史政治经济文化形式无所不讲，并且经常会发表自己的一些独到见解，是一位很不错的英……英语老师？！那没事了，我以为是马院的老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676ae7a73fd6846b0b169c60',140,368,'猫孝子，朋友圈给胖猫哭丧，莮拳师难蚌。为防止后来人不知道胖猫事件是什么，科普一下：体重200斤电竞男胖猫不把钱给老赖家庭都给女友了，后自愿跳河紫砂，网上cgg网暴女的捞女。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676addff77124e2a6c791382',385,28,'懒得喷',3,3,1,7,0,0);
