INSERT INTO "reviews" VALUES('676abf9e0b1efa78204cca15',4247,395,'其实他分不高…尤其是期末考，他批得很严很严，分不高，期末考上90几乎没有？不过他倒不卡绩点哈哈。还有，上课抽电子烟',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('676abeefe1ddfb3297a73ec2',725,40,'老师人很好，没作业，而且事少。但是给分真的低…我们班平均分上90的可能就一两？她还说我们班平均分太高了，所以课堂表现分的5分都没加（1分都没有）而且她说她还要再调低…',3,3,3,9,0,0);
