INSERT INTO "reviews" VALUES('676925d6618f2516fa4b7265',2646,2960,'老师期末前的最后一堂课给我一种他会狠狠捞我的感觉，讲完课之后还提前放我们走了，太爱了（虽然期中考是真的零帧起手哈，但是事后也捞了一把没及格的同学哈）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676925863fd6846b0b0ee22b',3467,3467,'上的是中国人文地理选修课，这门课很水，期中是交一个报告，期末开卷考试可以搜答案，但是有几次点名。如果真对人文地理感兴趣感觉没必要选，因为老师口音很重听不懂他在说什么。而且期末考试安排在17周，在期末复习的时候还要浪费时间来考试😅，如果有更好水的课还是选别的吧，但是如果没有什么好课选这个也行。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('67691e928097b23c9ac64bb6',588,588,'智障',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676917b33c83f17f55b6e9da',831,762,'上课一点思路都没有，讲课完全听不懂还喜欢用“难吗？不难”来阴阳怪气学生，ppt混乱，挤压学生课余时间用来小测，非要等到下课了以后才签到，而且以手机没信号为由拖堂，还振振有词说“你们要走的走没签到那也没办法”，期末十六周一下子布置12-17章的作业（截止时间到1.5号....那时候期末考试都要考完了。）17周不答疑，叫到班上进行小测一点复习时间都不给留。。。。真是腊鸡',1,1,1,3,0,0);
