INSERT INTO "reviews" VALUES('6768caea3fd6846b0b0ccdfb',2654,40,'给分巨低。。。。。感觉被骗过来了，避雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6768c9833c83f17f55b5223a',2878,28,'老师好好啊，太爱你了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6768c683e1ddfb32979defa9',362,28,'不是 谁说这王老师不好 这王老师必须满分啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6768c36b0b1efa7820436f6c',2885,40,'我只能说是神！首先是平时分，除了测验，作文，quiz其他给满。期末的presentation要求三分钟不用脱稿，对着念只需目光与老师对视三次，也不用做PPT，其他班好像都有要求，我们班应该大部分同学都是5分拿满。课堂更是水的没边，11点准时不讲了让我们自习，提前五分钟下课，而且课堂上讲的东西基本上没啥，有时候上课过去就是帮你看一下你写的稿子然后其余时间自己自习。再是课堂表现分，除了上课回答问题加一分，每次课后会在群里发问题让在课堂上没发言的同学录语音条，也加一分，所以我们班基本每个人都是5分满分的课堂表现，这对社恐同学不用我多说了！这么好的老师竟然没人抢，当时第二次选课还有那么多空余。快选快选',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6768bdf73fd6846b0b0c828c',1333,28,'老师菜菜捞捞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6768b62d6a0b7200061224b0',709,949,'莮拳师，上课叫女学生早点生孩子，不生就是没履行对国家的义务',1,1,5,7,0,0);
