INSERT INTO "reviews" VALUES('6768b37e6a0b72000612184f',1966,101,'老师真的非常负责任，还会额外给大家一周上一节习题课，平时点名很勤。想要好好学就选他就好了，但是对不想好好学的同学来说就是地狱了。',4,5,5,14,0,0);
