INSERT INTO "reviews" VALUES('6768512377124e2a6c6e286c',1953,1596,'朱老师，很抱歉我要在这里diss你了：这几分你不想给就不给吧，不就是几分吗，我不要我也能在这个专业奋斗着生存下去。',2,2,2,6,0,0);
