INSERT INTO "reviews" VALUES('6768181a77124e2a6c6d4af8',2821,11,'老师人超级好 讲课简单易懂 上课幽默风趣 而且回答问题是在手机上用qq回答 回答对了还有加分 而且十分有耐心 无脑选！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6768138b618f2516fa4742a9',4305,4305,'点名非常多，作业量很大',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('6767e912618f2516fa4658c7',4306,517,'洪老师必须满昏！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6767c3a36a0b7200060eda91',315,40,'1.虽然要求手机必须关机，但是你偷着看也没事。2.讲课永远在站在靠门口的那一排过道上，你只需抢靠窗的座位即可享有自由权。3.想要平时分的需要多完成她的任务，比如讲一段课文，用英音读一段文章等，这个确实不算水，需要自己努力。4.虽然评论区都在说要背诵课文，但其实很水的，她坐在你站着，直接照着读就OK了。5.随堂测试会下来巡视，小心被抓。6.讲课全是哲学，虽然学不到啥但挺有意思的，不过你真的要或多或少懂一点哲学，不然作文分很低。',5,3,2,10,0,0);
INSERT INTO "reviews" VALUES('6766e3198097b23c9abcbcff',2646,1170,'这个老师蛮好的，尽管上课可能有点水（很少管人），但是教的很好，能看的出来他非常有专业功底，点名很少，我可以说是非常好的一名老师了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6766e19e618f2516fa42330d',592,194,'上课认真负责，交流通情达理，给分中分段小放水，高分段不设障——能抢快抢。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6766b1af8097b23c9abbbe5d',228,228,'bookbook，外向的能回答问题的来吧，我这种比较蔫的，自愿回答问题抢不到，老师临近期末开始点没自愿回答过问题的同学起来回答，一共点了我三次并且最后只算作回答了一次😅，我请问呢？速run',4,4,1,9,4,0);
INSERT INTO "reviews" VALUES('6766b0b177124e2a6c6673f6',4311,4311,'该老师说话说不清楚，表达能力差，一句完整的话里要穿插好多个“那么”。该老师很怕麻烦，学生如果有什么事情没做好给他添乱了，比如实验器材没收拾好等，他会直接发火。如果平时有什么事情找他更是直接踢皮球。要是有同学想找他做项目是非常非常不推荐',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('67669a4b8097b23c9abb4c93',187,1973,'引人入胜：时不时鼓励你
INSERT INTO "reviews" VALUES('67667a34e1ddfb329794fbfc',2448,157,'老师人很好，很亲和，期末会适当捞，还是需要平时功夫到位，上课很轻松。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6766788477124e2a6c654136',582,442,'温柔的好老师，教学上可能照比那些教授差了一点点，但是教学和回答问题是真的很耐心，平时分也会尽力拉你，选了绝对不亏',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('67666ff43c83f17f55abfdbd',769,1490,'yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67666fc58097b23c9aba5015',1391,24,'老师的课程讲的也还算清楚，但是作业挺多的。不过鲁老师给分确实也是会尽力给的，只要平时作业大部分都交，不要经常旷课，老师绝对是会捞你的。本人期末43分，老师直接平时分打满狠狠捞了一把
INSERT INTO "reviews" VALUES('67666ef70b1efa78203a6604',3821,3821,'老师上课很水，基本上是不点名的，有重要的事情也会在群里说，给分挺不错，虽然不会特别高但也不至于阴间分数，想水课的同学我感觉钟老师是再合适不过了。',3,5,5,13,0,0);
INSERT INTO "reviews" VALUES('67666e45618f2516fa3fb4e8',257,4318,'陈老师讲课是听不懂的，但是只要按要求交作业，不缺课，平时分是很高的。而且平时很少点名，一个学期就点了两次。',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('676659236a0b72000608ba0e',43,43,'也配当老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676621916a0b720006077f10',176,176,'老师人特别好，除了期中考试的平时分都是会给满分，除非你课全旷，作业全部交，他甚至说你们要是不想上课，上的很累可以跟他请假不来，他都能理解，就是讲课方面有点口齿不清，但是ppt巨详细，都是自己每年新做的，期中期末还会偷偷发往年试题给我们看，平时作业也不是很多',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('6764d1f877124e2a6c5de93c',513,66,'脾气差，没抢到想要的课就来了这个老师的课，第一节课就莫名其妙大发脾气，原因是学生说了句脏话，本来觉得没什么。后来发现他就是纯脾气差然后没耐心，反正只能顺从',1,2,1,4,1,0);
INSERT INTO "reviews" VALUES('6764cd21618f2516fa3867ff',43,43,'只能说抱歉，牢🐲比他都能说是天堂，这老师经常莫名其妙找问题，考试验收前面几个交他可以花十几二十分钟看一个人只为了找一个错，要求上写的误差不高于多少满分他说我光标没对齐扣两分😅，问题是他对齐了也在误差内啊😅😅😅，后面牢🐲过来帮验，有位同学波形数据都是错的人家只扣了一分😅😅😅，上他的实验课真有种感觉，认真接线真不如天天混',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6764c1273c83f17f55a46194',42,43,'懒得喷',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6764b8033c83f17f55a436bc',294,294,'纯纯恶心人，专业水平好不好表的能力强不强不知道，反正恶心人是有一套的。上课每次迟到一分钟都要给你扣0.5分，还笑着阴阳你，上课就是念PPT，对着PPT让我们跟她一起念，谁没念，叫谁站起来。什么作文的要求带着我们看一遍就好了，TM偏偏让我们跟他读几遍，又不是小学生，真服了。还有每次上课都讲你们怎么办呀，上课不认真听，影响期末成绩呀，给我整笑了，你还以为你教挺好是吧，学个蛋',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('6764b7a2e1ddfb32978ce577',99,361,'要求多，没有亲和力，事情特别特别多',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6764b47fe1ddfb32978cd962',8,1010,'上课雀食要抽人回答问题，但是没回答上来也没让你罚站（不知道扣没扣分），在名单前面的话被抽到的次数会多一点。U校园布置得特别多，每一节都要学，每本书的学习时长要求拉到最满，快做吐了，有时候截止时间还弄错了（感觉他不太会操作）。随堂测试特别水，在下面直接，，，都行。口语考试更水，直接照着他给的示例读就行，一分钟不到啊，口语满分。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('676450ff8097b23c9ab1e503',1452,623,'老师人很好，给分据说不低，能力也很强，但是授课水平……如果能接受自学邓老师也不妨是一个不错的选择。',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('676450fe6a0b7200060092c7',1377,101,'拿个话筒在上面讲，完全听不懂，全靠B站大学。作业还一抹多，还特别喜欢上课签到。问他点多西就喜欢搞点高深的东西，测试还贼多，而且还特别喜欢占用周末时间，这点是最烦的。总之就是很不好。',3,1,2,6,0,0);
INSERT INTO "reviews" VALUES('67644fa377124e2a6c5c9cf2',2646,1170,'人强但太自信了，不按课本讲，不布置作业，但凡落一节课就跟不上来了。期中考试也不提前通知一下，就说“下节课如果看到我抱着卷子过来了，就说明这节课考试”，真的很烦，大部分人都没复习，考出来的分也普遍的低。不过人挺好的，坐最后几排玩手机、补制图作业他都不说你的，最多调侃一下。总之，想摆的选他的课准没错，但想学好可能就不太推荐了。',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('67644f173fd6846b0bfad5d0',2210,4330,'学长都说好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67644cd13c83f17f55a38c1d',346,346,'樊老师认真负责，很体贴，上樊老师的课挺轻松的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67644b186a0b7200060086e8',526,716,'你我本无缘全都怪网卡',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6764488177124e2a6c5c8ccd',976,5,'唯一真神😭😭😭老师你好温柔好伟大',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('676446663fd6846b0bfabdd4',955,955,'平时分低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676445e8e1ddfb32978c1cb4',255,223,'一个选修缺勤一次总分扣21分。有一个研讨会说去了加分，结果没去是在平时分里扣了10分（平时分占总分70分）。期末作业是交简历，自己亲手写的给了65，别人直接粘贴复制的群里她发的模范作业给了85，问就是简历内容太少了，自己心里有数别找她问分的事。我要是内容多我用你教写简历吗姐姐。一个选修给60 70分整个西南交大是闻所未闻，综测直接给你拉个大的。
