INSERT INTO "reviews" VALUES('676269f93c83f17f559abe4a',2596,1409,'我是女生，也挺喜欢打篮球的，考试的时候女生的标准更松一点，老师超级好对比我舍友选的另外一个篮球班老师，侯老师简直太好了!',5,5,5,15,0,0);
