INSERT INTO "reviews" VALUES('676262ca0b1efa782027bf01',1826,87,'大三一生的健康锻炼给分较低，班里同学期末总评基本都是七十多甚至六十多，上课发现玩手机就扣分，每节课都点名，别选！',2,2,2,6,0,0);
