INSERT INTO "reviews" VALUES('6762440a3fd6846b0bf11780',6,619,'byd上课自己不讲全让同学讲，自己搁那打电话，装作很忙的样子，你在装什么😡😡，天天臭着张脸，谁欠你了？讲少了要批评，别人讲多了2分钟给人打断赶下去，想让别人尊重你的前提是尊重别人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676243ad77124e2a6c52dd22',961,762,'讲的一坨还喜欢在课上强迫别人听课，每节课都要做它布置的垃圾题，期末喜欢强迫去上课幸运儿上去讲题',1,1,1,3,0,0);
