INSERT INTO "reviews" VALUES('676239c477124e2a6c52a0cf',121,541,'虽然老师脸臭臭的也不爱笑，但是人真的很好，口语考试的时候一直支支吾吾，最后只说出来三句话😭老师还是给的“良”级的分，看着老师用一个臭臭的表情给我打标准分感觉好对不起老师哈哈哈哈哈哈',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('676237e38097b23c9aa74cf4',7,7,'上课认真而且容易学懂，签到少，平时分基本都能给满，考前带着复习划重点，老师超级棒！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67623550618f2516fa2cfcf6',1994,38,'阴阳nm的中外合办呢，我们就是有钱上学这么你了？还搞起阶级分化了纯属是有病，一开课就说什么中外合办的学生学习能力低人一等。满口粉红言论ex的要死',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('676232e36a0b720006f61094',1273,157,'很好的老师。首先，摆烂的不建议来，要求比较严格，但努力努力都可以达到。其次，对学生上课时的安全很关心，会时常要求你热身一定要充分，也会时常强调安全注意事项。然后，人比较亲切，如果技术动作有什么问题都可以去清教，老师看出问题也会主动指出来。最后，虽然期末测试的要求比较高，但老师放的比较宽，多加练习就可以拿到不错的成绩。如果真的想学学排球的话十分推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67622a0c6a0b720006f5d2fd',4369,1857,'讲课很温柔，听得很明白，你听不懂他会再讲一遍，大胆一点问就好，平时分给的也很高，会容许补交作业的机会，讲得好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67620ae93c83f17f5598b6a2',1058,5,'老师人超级好，超级负责，和高中老师差不多，能在大学碰见这么负责人的老师真是太少见了，她的课只要愿意学就一定能学懂，老师还炒鸡又耐心，作业批改十分认真负责班里同学出现的问题会一一发到群里，进行解答和示范呢，总之真的超级超级负责，而且人还很和蔼，能上她的课包是最幸福的人！
INSERT INTO "reviews" VALUES('6761185e8097b23c9aa29b20',4345,4345,'上课一直不高兴，不让提问',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6761178c77124e2a6c4dbdb4',1231,39,'很好，从大一开始选的，零基础的，老师很有耐心，而且给分挺多，签退直到下周上课',5,5,5,15,0,0);
