INSERT INTO "reviews" VALUES('6760cba98097b23c9aa0caed',68,40,'这老师纯神经病啊意味不明变化莫测的心情，所有同学给她演示都被她说“浪费我的时间”，那不知道为啥她要当老师浪费时间，习惯性随口攻击学生都是习惯性的了。',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('676055cd8097b23c9a9ffb22',891,114,'平时分拉满，人很亲和，课在交大讲的算极好的啦！真的很爱',5,5,5,15,0,0);
