INSERT INTO "reviews" VALUES('675fb6e40b1efa78201ba01f',961,762,'快跑吧，上课暗中针对同学，强迫同学上去讲题，期中前一节课搞小测验还考期中不考的内容。小测验是不打印出来的，看不清的同学是不允许拍照的，自己讲的差是不允许同学上课看网课的，看到同学上课做作业是要阴阳的，平时分是练习题做错了也要扣的，问她题是不给你讲还要让你下节课在班上讲的。。。',1,1,1,3,0,0);
