INSERT INTO "reviews" VALUES('675f89e277124e2a6c469470',4352,4352,'学长们说的很对啊，不仅拿不到80分，70分都拿不到。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('675f89b78097b23c9a9b66ac',4352,4352,'对这个老师真的无语，对女生不咋地，对男的超级不咋地，根本就拿不到70分。千万别觉得他是瑜伽，觉得他是水就来报。相信楼上们学长说的。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675f84756a0b720006ea2cdd',1994,241,'选了你就偷着乐吧，他精通如何最可恶地PUA你，会采用报数点名法，会自以为很有水平地教育你，总结:根本不是人。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675f0e658097b23c9a9a47cb',270,4406,'老师人真的很好，是需要动起来的课，平常没有作业也没有期中考试，期末只交一篇论文。而且活动内容其实挺简单的，就是很基础的芭蕾知识，还有一些力量训练(其实你水，老师也不会说你)。课前会点名，但是有事可以跟班长请假， 然后平常大家有事请假有时候都不会要求交假条 老师人也很和蔼 课上还会给大家聊天 开玩笑什么的 总之真的体验感很棒。(ps：非常推荐想练柔韧性的宝子)',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675eff2e3fd6846b0be395f9',4407,4407,'可爱捏，上课有时会用中文讲就是口音离谱听不懂。期末考试会透题，很照顾学生。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('675efe173fd6846b0be3912f',1127,4055,'如果这周有其他的考试老师会很贴心的将考试的时间延后，防止学生过劳。真的是很好的很亚撒西的人啊就是我太菜了线代学不会😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675eaeb091944c6b55b40b94',230,230,'对于喜欢历史的同学来说，上谢老师的课就是一种享受！谢老师讲课有激情，平时作业我们这班是写了一篇论文，虽然和水课的属性有些格格不入，但喜欢历史真的要听听谢老师的课，能有很大收获。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675e6456e1ddfb3297714edc',1596,1596,'密码的大物实验只给60分我测密码，做密码的实验呢，还不如崔雅静给的65分，测',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675e582e8097b23c9a967b16',4411,521,'你能想象一个选修课，一个班38个人，有7个挂科，5、6个60多，80分以上的不到一半吗？每节课必点名，MOOC上还有主观题作业',2,4,4,10,1,0);
INSERT INTO "reviews" VALUES('675e551fe1ddfb32977103b8',359,228,'【省流】：考勤严，事情多，讲课差，互动僵，想水的别来，想分高的慎重考虑
INSERT INTO "reviews" VALUES('675e4e343fd6846b0bdfbeb5',4413,68,'上的她的通用学术英语，上课还算水，讲课是照着ppt念，有课堂问答环节，【没人主动起来回答就抽人回答】，平时成绩构成较为复杂，【会压分】，总之一句话：【事多分少，想水的别来，想要高分的也不推荐】',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675e4b673c83f17f5588bfa3',526,1651,'作业爆多，讲课都不管你听懂没',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675e4b596a0b720006e53ac3',2229,2229,'上课啥也讲不明白，期中期末直接做大项目，而且他不会帮你，就全程自己做，避大雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675e438d0b1efa7820155811',1157,52,'实验给分低……错一个地方直接扣5分，半期辛辛苦苦复习，结果被实验成绩拉下去，很无语',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('675e3de83c83f17f55886d66',65,65,'给分低，上课讲的不清不楚，还不允许问她问题，简直sb一个',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675e343f77124e2a6c40dc70',1770,3109,'认真负责的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675d732891944c6b55aeeb1b',3186,3186,'很好，很认真的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675d723a77124e2a6c3e95a5',4352,4352,'课一节不落的上，慕课一节一节的看完了，考试不说动作标准但也是认真在做，考试前还复习了动作。最后只给个60多分，给分太拉垮了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675d37bc3c83f17f5584b42a',2230,4399,'最最最神的老师 真的非常非常喜欢 特别特别负责人 虽然快退休了以后的xdx可能就享受不到了 只能说你的英语他能给你起死回生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675d1d1e3fd6846b0bdb06c2',4407,4407,'真的捞人！考试给分也很高！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675d1cec0b1efa782010b8a6',4423,4423,'外教讲得挺好，唯一不好的一点是只讲跟设计相关的东西，和cad关系不大',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('675d06fd77124e2a6c3c2dd0',704,704,'就讲课来讲，老师讲得很好，就解题思路给你捋得很明白很清楚，而不像有些老师照PPT念，签到是mooc签到，一学期没签到小于等于3次课堂表现分就给满分，至于mooc那些测试自己搜一搜也能拉满，半期也是在mooc上考，搜题也能拉满，这么一看你平时分基本是满的，总的来说，老师神中神，电分里教的最好的老师了，如果你想自学，那你就自己看看咯，反正我是觉得这个老师非常好😘',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675c759577124e2a6c3a8eea',2299,2236,'很好的一个老师',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('675c7515e1ddfb329769d497',74,74,'快逃，别犹豫',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('675c6ae891944c6b55aad038',1694,4427,'杨老师的教学方法并非适用于每个人。如果你是热爱设计真心想学设计的话，选杨老师的课程肯定不会出错。如果你是想要不用多么努力就得到一个还不错的分数亦或者求一个水课老师，那么杨老师的课程不适合你。对于老师本身，仁者见仁，智者见智，但是杨老师对于教学的态度绝对是严谨认真的，专业能力方面绝对是顶尖的，只要你想学，他就会将他的知识倾囊相助。而且在与学生的交流过程中杨老师一直是一个平等随和的态度，我没有见过杨老师骂一次人，所以我不太明白上面几个评论说杨老师骂人、恶心等诸如此类话语，是不是能力与态度实在差的离谱被分数整破防来这找存在感，还有顶着力航专业的小号（ID：激光雨玩）来血口喷人，这个更是阴的没边。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('675b8efc77124e2a6c35c63d',1289,1449,'没什么好说的，神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b8a4e8097b23c9a892609',260,96,'拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b89b96a0b720006d98944',250,250,'上课就是一坨屎，两节课3分之一时间在讲东讲西，还有3分之一时间在贬低同学，最后课讲不完了还要拖堂。每次课不讲清楚，作业一大堆，平时分是不给的，期末是不捞的，逼话是要讲的。张口闭口就是美国人纯纯汉奸',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675b882877124e2a6c35a150',4431,87,'拉满了 老师心善人美 多得不说',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b7f7877124e2a6c357775',1175,28,'平时事情多上课还要抽人回答问题我忍了，江怎么做presentation的时候她说这对男同学更重要，不然怎么晋升怎么当领导？这什么逆天言论，身为一个老师，却在课上乱讲，ex！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675b42f1e1ddfb3297647874',1042,462,'平时分不高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675b327791944c6b55a55bd7',3370,228,'老师实力很强，专业水平max，上课也会结合时事热点讲一些有趣的话题，会点名，但是课上也能真的学到东西，选到不亏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b1bd13fd6846b0bd35d4d',4435,4435,'选了老师的法医选修，讲课很有意思，点名比较少，平时没有作业，给分蛮高的！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b162391944c6b55a52e91',345,2677,'难评，平时分说根据期末考试和期中考试来定，进步二十分才给一门平时分满分，三十分两门，四十分三门，那我平时做的作业听的讲都被她吃了吗？上课翻ppt巨快，根本没看完就翻过去了，自己讲完了不管我们死活',2,1,2,5,0,0);
INSERT INTO "reviews" VALUES('675b0f148097b23c9a883e03',362,28,'作业量真的多，给分完全按标准，中规中矩吧',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('675b0eb80b1efa782008c744',4438,22,'上课水，作业不少，按时完成的话平时分很高，不会压分，但考试的话更多靠自己复习了',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('675b0de30b1efa782008c50f',44,316,'大物实验M，带了一个学年实验，总体感觉还是很好的，总之实验M不存在离谱的情况',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('675b0d2f3c83f17f557b2116',974,51,'不点名，作业基本没有，期末均分99，选到就是赚到，如果真的想学也能学到东西，好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b0be3e1ddfb3297641d91',891,114,'老师真的负责，脾气也好，讲的很细。很少考勤。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675b0a2877124e2a6c34a709',803,1135,'认真听讲，神中神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675a5fbb77124e2a6c30ce03',3926,2035,'快跑啊孩子们！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('675a5a1891944c6b55a1439f',890,619,'于老师真的超级好。平时分50分只要你按要求来就可以全部给你，上课内容也讲得特别好，她学哲学的，她的课堂更多的是在教大家人生道理，很多能用在大家以后生活中的知识，教学内容也会讲。我觉得更有价值的是她教给我们能用到以后的那些东西。然后最后也会给化范围。真的超级好，非常温柔，选到就是赚到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675a40053c83f17f5576940c',2299,760,'平时分给的还行。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('675a32d30b1efa782003d1d1',1370,1183,'对自己的体育能力不自信，或者想水课的，最好报张老师的乒乓球。平时点名看人头，人少才会点。上课你甚至可以一直站着玩手机，老师也不会管。考试有点麻烦，但是只要你交了视频，老师肯定会保你及格。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6759bd0191944c6b559ef9e3',1826,87,'这老师真是太棒了，都来都来，必须都来，完全跟换了个人一样，和以前的评价完全不同。看学生的眼神像欠了他八百万一样，感觉下一秒他就能提着刀砍人。而且教的也不咋地。。。踢个毽子谁不会，不会的他也不教，课上的太极拳教的还是盗版的，一年能学两套不同版本太极拳你就偷着乐吧。',1,4,1,6,0,0);
INSERT INTO "reviews" VALUES('6759bab56a0b720006d2cc22',418,418,'上的是她的高数  讲课一坨  平时分低  听她不如听宋浩  除了作业多，每天还要在群里发题目让人做  唯一好处算是不怎么点名',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67595f518097b23c9a7faf92',43,43,'我只能说，这就是一个畜生老师，谁选周三周四，轮到他上课，谁就烷基八氮，懂了吗。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('67595ae80b1efa782000ed01',3098,3098,'感觉从22级之后就别选他了吧，很坑，21级的学姐说她们那时候，晓鹏还愿意发ppt建群，到了我们这届，一言难尽，坑人啊，第一次见额外补课的，课讲的还行，老师挺有水平的，但也不是额外补课的理由，还有这里没有linux内核分析，千万千万不要选linux内核分析，巨tmd坑，贼能拖堂，给哥们干心态爆炸了',5,3,2,10,0,0);
INSERT INTO "reviews" VALUES('6759591677124e2a6c2cc2ef',2072,22,'给分很高，老王看似点名其实没啥用，期中也可以水，我就记得我大物就交了一次作业，然后就再也没有去过了，然后平时分满昏，强无敌',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('675955b13c83f17f55735d7f',248,48,'给分很高，慕课不用看都是满分(不能细说了，万一被人注意到了)，羽毛球考试有点难度，但还好，基本你认真打了都会给你昏，还有体测也可以加很多很多分，各种地方加昏，除了上课有点水，其他都还好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67594ea077124e2a6c2c812b',954,52,'老师人超级好，偶尔签到，问问题很耐心，也很亲和，平时分真的是全部拉满除了期中。就是讲课比较差',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('675946456a0b720006d04c22',890,619,'神，只要一学期内，你所在的一个组一共回答五个问题，然后按要求完成实践作业，平时分50铁定拿到，这是给分上面的，其次是讲课，虽然我只听了一节课，但是她讲的是真的🐮，层次分明，罗辑清晰，选北溟老师的有福了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67594638e1ddfb32975acb46',885,790,'吾游历至此，发现此课，课名中散发着妖异光芒，吾言此课甚毒，定不堪入耳。吾自持大乘期修为兼具神农血脉，强行装逼，曰：“此书观其名便知乃毒物也！然，世人无人尝之，不知其性如何。吾乃神农后裔且修为顶天有何惧之！今日便效仿先祖之举一尝百草。”遂听起课来，可未曾料到只是刹那间吾友便发出惨叫，众人闻之惧惊！只见吾七孔流血面目狰狞，口中更是吐血不止，整个人瞬间变得枯黄瘦小。赶忙拿出仙丹妙药让其服下，可还没来得及搭救便已无力回天。吾弥留之际只留下一话：“此书比之世间毒物还毒百倍”便化作飞灰而去。恰逢吾秽土转生之际，特来敬告各位没有大罗金仙修为者切勿强行听课，否则只怕会被其毒顷刻炼化！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('67593b513c83f17f5572ab8f',1499,1499,'近代史，平时分直接给满
INSERT INTO "reviews" VALUES('67584f35e1ddfb3297552854',1826,87,'非常好，上课玩手机不管',5,5,5,15,0,0);
