INSERT INTO "reviews" VALUES('675825abe1ddfb32975321e6',3463,3463,'非常好的老师，期末只要是个人就能80分以上，平时也挺水的，完全可以课前签完道就溜，她发现少人也不会管。目前遇到过的最好的老师，神中神，冲就完事了
INSERT INTO "reviews" VALUES('675813cd3fd6846b0bc4d1ff',3407,5,'上的微积分 老师很好啊 很认真',5,5,5,15,0,0);
