INSERT INTO "reviews" VALUES('675806aae1ddfb329752771d',3463,3463,'上课强度很低，考核标准也很松，基本人人期末都是90+，爆推！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6757fe800b1efa7820f7c166',260,96,'老师真的非常好！上课认真负责，上课讲的很好，签到会提前说，超级负责，考前会讲习题，划重点，一点不学的同学老师会批评，而且老师本人清清爽爽干干净净的，超棒！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6757effb3c83f17f556bfcd6',2377,322,'上课老恶心，经典的水课，时不时恶心你这是你花钱买的课',2,1,5,8,0,0);
INSERT INTO "reviews" VALUES('6757e9bde1ddfb329751ac8e',2983,294,'考试是不提前通知的，作业是从不发在群里的，各种通知是没有的，上课是必须点名回答问题的',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6757dcaa77124e2a6c24cc46',1538,1073,'熊学老师我们喜欢你，我们我们，我们喜欢你🤓🤓🤓',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6757db298097b23c9a777fa3',1058,5,'非常负责，有点像高中老师，有时会拖堂，上课水平一般，有时候会把自己讲懵，作业比较多，小测成绩默认有50分，从不点名',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('6757da3f91944c6b5593e085',1453,114,'平时分拉满，上课比较快，课上经常跑题，有口音，基本不点名',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('6757d0ae8097b23c9a77490c',194,194,'上课讲的很详细，会划重点，人很好，作业一般可以补交，十五周有个课程报告(不过很水)，会在群里发课件，还会留时间复习，真的爱了😍😍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6757bcb06a0b720006c70991',1095,1095,'孩子们快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6757bb130b1efa7820f636fb',1095,1095,'从第一节课开始，话是说不清听不懂的，课是讲不明白的，课上是不让玩手机写作业的，每节课是要带电脑的，电脑没电了是要被说的(根本没插座但让带电脑电源)，老师课上写代码是要问文心一言的，作业是完全不会写(本人第一学年智育成绩专业第4)的，代码(问文心一言)是要求看懂的(从来没学过python)，课是每节都会拖到12.30的，饭是吃不上的，期末是不划重点的，内容是不按着书讲的(无法复习)，考试是完全不会的',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6757ae488097b23c9a767c8b',546,40,'上了那么多课，没见过那么多屁事的老师，这有要求那有要求，还是个笑面虎，看着嘻嘻哈哈的，平时分是要求巨严，只要你有点达不到要求，分绝对不给，作业迟交也没分，问问题说说过了，不会回答你 感觉心理有点BT，还说什么给你分低了别去骂她？？？还能说什么***',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('67579ecb6a0b720006c64494',230,230,'鸡冠老师，屁事多，不让坐最后一排，鸟脾气还差得很，排到他简直是倒了八辈子霉了',1,1,1,3,0,0);
