INSERT INTO "reviews" VALUES('67446db82096fe04ef2650e5',2157,4548,'水平没的说，讲课的知识都很专业而且很有用，能学到东西，但是老师讲课很无趣，连葡萄酒这么吸引人的内容也能讲的昏昏欲睡也是没谁了，对着ppt照本宣科也没有吸引人的图片，上课事剧多，想水课可以水，但是你会水的非常难受，每节课都有作业，而且最后的自由展示她搁那挑三拣四的，问的问题也刁钻，感觉不想让你好好上选修',5,3,1,9,0,0);
