INSERT INTO "reviews" VALUES('67400e2e2ab16711a40e8ef4',221,36,'希望他能看到这里对他的评价——这个课就是浪费他自己的人生浪费别人的人生。上课是言之无物的，作业是“拜托”但是威胁你一定要写的，上课答不出问题是记旷课的，普通话是**一样的，听不清普通话反问一句问的是什么是断定你答不出问题的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673f2717ac1fe61f24f24996',2299,2236,'老师对课程内容的掌握非常深入，讲解清晰易懂。”总能用生动的例子让我们理解复杂的概念。老师的教学方法非常有效，能够激发我们的学习兴趣，老师总是鼓励我们提问，课堂氛围非常活跃。
INSERT INTO "reviews" VALUES('673de440ee486145b762c6c4',2299,2236,'李老师上课尽职尽责，布置的作业量适中，只要布置的作业交了，基本平时分都是拉满的。在期末考试复习期间，老师也会不遗余力地帮助学生掌握关键知识点，如果平时有疑问，可以随时向他咨询。强烈推荐李老师，无论是追求高分的学生还是希望轻松学习的学生，都能从他的课程中获益，非常值得选择。
INSERT INTO "reviews" VALUES('673dafce82cc8f075d153e65',123,123,'唐人一个，懒得多说',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673d914a79aa410e8ed07b6c',4149,1073,'神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('673d5308a79a1012513fa072',246,228,'👿👿👿牛马无需多言，选课的时候忘了看活水了👿👿👿👿',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673d42b3a79a1012513f63f8',142,548,'纯纯思慕，合理怀疑给她打好评的是不是她自己买的，真是纯出生吧，给分又低，又天天上课红温，又天天布置巨多作业，每次去问问题先被骂一顿还解决不了疑惑，考试改卷多给你一分就像沙拉她的马一样。很难想象这种人怎么还能有3.5的分的',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('673cd5c52a7e1c27eed11880',588,588,'会对学生说出“我就看你不爽”类似的话，上课讲完ppt后马上要求做题不给消化时间，题目做不出来常常会嘲讽学生计算能力与解题能力差，作为限选课，非常不推荐选他。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673cd35dcb437809e210b41d',588,588,'爹味十足的老师，期中考试考完去问问题竟然会对学生说“期末前会讲，不希望跟每个学生都讲一遍”这种话。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673c81275eab5b193e9a04a4',56,56,'某思考部位发育不完全，不会依据客观现实，只凭自己主观臆断判别，谁碰见它这辈子就有了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673c7a305eab5b193e99eed3',1379,346,'**玩意，没见过这么恶心的老太',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('673c5623f7e7312d47631c6a',1600,96,'虽然但是其他都很好，就是板书不太行啊（叹气）',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('673c4b04012b52314f8f1c3a',39,39,'老师在遇到提问时态度较差，不耐心',4,3,1,8,0,0);
INSERT INTO "reviews" VALUES('673c22fa6794ce0e1025e13a',2259,1129,'给分高，管的松，老师人很温和，回答有耐心，我只能说神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('673c18c0530c77138dea01cf',2299,760,'老师非常负责，对学生也很好。课程平时成绩给的很高，作业也相对较少，基本全部都能顺利通过课程。在课堂上，老师讲解也很细致、条理清晰，学生的疑问总能第一时间得到耐心解答。尤其是在期末复习阶段，为了帮助学生更好地掌握重点知识，课后反复叮嘱大家，如果还有疑问，可以随时向他请教。他不仅在线下悉心辅导，还在班级群里主动答疑，确保学生能够顺利通过考试。这位老师强推，很适合大家选，不管是想考高分的，还是想水的，都非常适合，强烈推荐。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('673bff5250310c1f4ed10a78',2299,2236,'老师讲课生动有趣，知识点也讲得特别清晰，感觉是认真备课的，材料力学毕竟还是比较简单，学起来不是很难，每周都有作业，对作业的要求不高，基本只要交了就给分，平时成绩给很高，上课的时候老师也不怎么管，讲课的声音也可以，听的很清晰，可以坐后面听',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('673bfa806794ce0e102560c8',2299,2236,'老师课讲得很好，每周都有作业，不会用系统布置作业，只要作业交了，平时成绩就很高，应该会捞人，35分都能过',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('673bf4e9012b52314f8e06c7',2861,2205,'太牛了，你怎么不去亖啊，大四上限选课挂了十个人',1,1,1,3,0,0);
