INSERT INTO "reviews" VALUES('672d9cc16794ce0e10030c63',257,5,'老師水平很高，四川大學的bachelor，香港理工大學的master。印象最深的是第一节课不按常规，先讲初等变换，让我们后面学得很轻松，光是这一点足以证明他是理解了线性代数并且认真备课的。
INSERT INTO "reviews" VALUES('672ce7836794ce0e1001dbc6',31,31,'秦老师是我遇到的最好的老师，水平极高，极具人格魅力，超爱！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('672ce516cb437809e2ea48c9',44,204,'我要为樊代和老师正名！！!人真的很好，而且实验成绩每个班虽然有差异，但最后给分的时候，是让全年级的均分一样(这个老师给我们说过)。所以不存在给分低的问题。而且老师人也很好，也比较好说话，是我遇到的不错的老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('672ca15844f37b2dbd2e2c13',1733,1733,'完全不备课的老师，讲课很糟糕，会经常卡壳，ppt完全就是照着课本挪上去的，完全起不到很好的重点标识作用。关键这门课跟数理统计还很不一样，不容易找到自学网课。平时布置作业又多又难，完全找不到重点。作业也从来不讲，说是有个答疑课也完全起不到答疑作用，还必须去签到。考试也是一坨，不想说了，如果不是被迫要学随机过程，都别来沾边。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('672c96496d848d7e9aaffb79',2961,761,'做的ppt给她看了，说做的不好我们又重新做了一次，做的都要吐血了，交上去也没说什么，自我感觉良好，结果期末背刺我，太过分了，一个选修课给分这么低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('672c9526f7e7312d473ca9fa',1949,230,'专业水平和表达能力很好，点名也比较少，大作业只要认真完成就是满分，给分非常高',5,5,3,13,0,0);
