INSERT INTO "reviews" VALUES('672c940f6d848d7e9aaff40c',1032,736,'课程内容非常有意义，老师给分也很高，虽然课程比较难，但讲的非常好，五星好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('672c93c4af89092436afb037',344,601,'课讲的挺好的，但是爱讲人生哲理，不爱听，烦，制造焦虑第一人',5,4,1,10,0,0);
