INSERT INTO "reviews" VALUES('672b90265eab5b193e707865',1733,1733,'教材一言难尽，上课对着PPT把天书再念一遍，每周更是要求毫无作用的答疑课，书上习题是一个不落全部布置，但毫讲解的，没见过这样布置作业的。
INSERT INTO "reviews" VALUES('672b5ba04fac0c61c674fac7',1994,241,'sm玩意儿，tm的收手机，一个不到全寄，当自己高人一等。还说什么大学毕业之后只能各过各的阶层，还有什么“我是你见过最吊的人”吊你妈没了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('672b40d45eab5b193e6f954f',1749,1409,'本人只参与过他的体育超市，一直大吼大叫，感觉学生欠他多少似的，一点也不会好好说话。总共一个小时的超市做二十分钟的准备活动，我不认为走路是什么需要彻底锻炼开的运动。',2,1,1,4,0,0);
