INSERT INTO "reviews" VALUES('66dfb2c0c00adc547d08d386',1513,1513,'老师挺好的，给分虽然不是很高很高的那种（85+？）但课真的水，没事听听感觉也很受益，不太常点名，但主打随机，时间随机，次数随机，期中期末各千字论文一篇也还好。期中不知道有作业去找她她说都可以补，但消息很不流通，不建课程群，交流和布置/上交作业全靠教务网邮件，感觉不太方便，但老师是真的好老师，喜欢小动物的可以去听听，课程内容很受益',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66dfb0539fb072087b34a629',1419,48,'有点羽毛球基础的同学都能来水一下分数，评奖评优建议选一下其他的，我感觉王老师教学还行',4,2,3,9,0,0);
INSERT INTO "reviews" VALUES('66dfb04dd01e26201568321e',311,51,'之前选的心理电影赏析，是我给分最高的一节课😭97啊！老师很和蔼温温柔柔的，课上签到是到点传纸条写名（她别的是不是这样就不知道了），期中作业写几篇电影观后感交上去，期末开卷考试直接拿着期中作业去抄就行了，听我们说字太多了她甚至还现场说把限定字数改',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66dfb04acf05a13cc5544d2f',377,377,'很无语的老师，事情很多，再加上平时分要回答问题才能拉满，期末考试更是一坨，本人没缺过课，但是每节课都第三节点名也是神人了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66dfae73543f59210fee04c2',172,39,'羽毛球，上他课和军训一样，事巨多，小牌大耍，每天上课前先所有人站着听他宣讲；会拖课，但不能迟到，自己拖课，但对迟到的人说，告诉上一节课的老师要先走来上他的课；给分也很低，拼死拼活两学期才混个八十出头，室友学别的轻飘飘水一水就九十多；天天两手一背，喜欢使唤人，助教/比他年轻的老师/体委在他手里是呼来唤去的；微妙的感觉他很无视女生；签到不点名喊学号……这就奇葩一个，如果你觉得自己还挺喜欢羽毛球的，没事爱打打的，就不要来了，来了你会讨厌羽毛球',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('66dfad4d22c9c60150bb63eb',4905,4905,'老师讲的可以，给分很高，适合刷绩点，就是上课不让写作业',4,5,4,13,0,0);
