INSERT INTO "reviews" VALUES('66dea37d543f59210fea2b09',4195,457,'老师很温和，上课需要每个人都上台发言(不知道别的班什么样)，做完小组活动需要推选一人上台做报告，在平时分方面她分的还是很细致的，但是好好完成还是有90分的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66dea1c9543f59210fea2572',932,762,'老师会板书，讲的不错。有口音，但认真听几节就能听懂了。会评讲作业，不是交了就不管的。除了期中和期末考，没有打问题就全部打满。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66dea043154d657e59a8d8c7',24,24,'好老师，除了听他说话有点费劲之外哪里都好，认真负责，有答疑，作业有详细答案，还有给我们发历年真题的详解，平时分很高，真的会拉满',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('66de9f7195e0f363493b007e',887,23,'认真负责的好老师，课讲的也好，每次还指点我们报告怎么写，回答问题很耐心，很亲切，但是如果这门课你想水，那最好不要去，因为她次次课都网上签到。',5,4,5,14,0,0);
