INSERT INTO "reviews" VALUES('66dbca859fb072087b28b9f7',2433,142,'朱神yyds！材力补考总评62 感觉补考考的挺难的 以为自己过不了 没想到朱老师让我过了！朱老师上课幽默风趣 而且开学 过年过节还会在群里发红包 是一位非常负责尽责的老师 上课讲的也非常好 只是🐭🐭确实听不懂 只能尽力去听 总之是一位超好的老师 ！！！',5,5,5,15,1,0);
