INSERT INTO "reviews" VALUES('66d9df25be187967db31fb09',3925,3925,'严格但是挺好的，数理统计前面2章讲的比较详细。但后面讲的特别快，课堂上会强行叫人上去写题目加平时分，很负责的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66d9de1d22c9c60150a8ebe6',294,294,'一坨史，从来没见过迟到扣平时分的老师，别的老师顶多口嗨一下扣平时分，这老师有能扣的他是真扣啊',1,1,1,3,0,0);
