INSERT INTO "reviews" VALUES('66c7eea74095855b7c618860',5,114,'水是水，特别水，随堂测验不管做得怎样交了就行，但平时分不算太高，半期80平时分也才80+。。。评论那个半期44平时分捞到80多的是真实存在吗',5,5,5,15,0,0);
