INSERT INTO "reviews" VALUES('66baf74e4f448873f8b5cb3e',74,74,'他的工测实习累是累，而且时间跨度比其他老师的长，要求一堆，真的想骂人，实习完了出分也磨磨唧唧的，硬是半个多月快一个月了才出分，出分前很想喷他，但最后给了90分诶',3,3,3,9,0,0);
