INSERT INTO "reviews" VALUES('66972832df8aa45a55ec6d6c',74,74,'纯纯一大シャビ，上个工程测量实习Bたまで那么多任务，学工程测量只是个辅助，要求却那么严，说话发布任务不能一次说完，临时又改了好多任务，找他提交任务又不在，引起公愤了，为人教条有古板还巨会甩锅',1,1,1,3,0,0);
