INSERT INTO "reviews" VALUES('66964bdf2768d74884d5b641',74,74,'烂的一批，实习史一样，工作量大，要求高，但是讲评一点不清，要你早八晚六，不管你怎么测国标要求你，搞个碎部测量画图一点不说，交上去不对叫你回来重测，简直就是史，说什么标志啊，天井啊，开始装死，一点不说，学生自己悟？无法理解的老师，让我的暑假无限延期，千万避坑！！！！',1,1,1,3,0,0);
