INSERT INTO "reviews" VALUES('66962fb5aca6db51e35d4944',74,74,'从生下来没见过这么逆天的老师，实习刚开始的时候，25页PPT讲了三个多小时，还说什么不讲废话，全是废话，还说我们实习比别人轻松，我不说我们工作量是别人的3倍也得有2倍了，对数据要求也是极其苛刻，还得按国家标准来，就学校那破仪器，能测个大概就不错了，比别人先开始，走的比别人晚，遇上它你就算有福了🤡',1,1,1,3,0,0);
