INSERT INTO "reviews" VALUES('6694e830c668584cd9063ab5',3059,1241,'教的一般，平时分低。所有作业都按时交了，得分都是A或者A+，因为助教统计的问题，少打了一次作业，显示一次没交，作业分只有83。私聊发作业图片，他说可以改成92，结果根本没改，私信再问也是敷衍回答，说已经提交了，但教务网显示就是没改。',2,2,2,6,0,0);
