INSERT INTO "reviews" VALUES('66924d61c668584cd9fb2282',533,101,'线性代数之神！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66920cbc8c6e404f3d27eaf8',2190,2190,'非常棒的老师，亲切和蔼的老教授，期中开卷，基本考的要么是书上的要么是上课讲过的，期末与期中大部分重叠，就是前半期作业有一点点多，但也很容易完成，总体感觉不输教这门课的其他任何老师',5,5,5,15,0,0);
