INSERT INTO "reviews" VALUES('6691d3c88c6e404f3d26a23b',5073,38,'上课不停的抽人回答问题，平时分也不行，明明每次课都去了但是课堂表现分只有90😅把我恶心坏了',3,3,3,9,0,0);
