INSERT INTO "reviews" VALUES('669119ee556b231523e4940e',674,307,'呵呵，平时也是不缺勤，认真学的，牢叶讲的也可以。最后看到平时成绩也是认认真真地让我吃了一惊。活久见，能见到自己平时成绩比期末还低。牢叶您是真严啊！',5,3,1,9,0,0);
INSERT INTO "reviews" VALUES('669102932768d74884bd49c7',5077,3886,'你的平时分给的不高，但期末简单弥补了这一点',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6691012eaca6db51e34780f8',696,698,'一个小组同时教的课设，任务分配也没问题，组员最高100，我70，你真牛啊好牢石',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6690fc8221b811069344e6bc',674,307,'想水的哥们直接避雷，平时分给的很死板而且很低，折算下来我平时分比期末还低，能选其他老师就不要选',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6690efd62768d74884bcdda7',696,696,'id已然证明，邱小平在我心目中的地位之高。两年的课程，这是唯一一个让我如此破防的老师。上课基本是助教教的，少数的自己教的课程口齿不清，东扯西扯，胡诹一通，听的人云里雾里。上课形式是念ppt的，上课内容是不顾学生基础的，课后问题是得不到想要的答案的，课后作业是超纲且搜不到的，实验报告是让学生发挥想象力的，实验代码是网络抄来的，考试考纲是反向重点的；虽然老师上课能力让我怀疑其教书水平，但老师架子确实是数一数二，让学生提早到班，上课规矩重复不断，确让我感受到了小学老师的严厉教导。呜呼，积怨已久，罄竹难书；唯能感慨，遇人不淑。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6690c53d5245002aaa23f6d7',3369,5081,'抽象人',1,1,1,3,0,0);
