INSERT INTO "reviews" VALUES('668ff7f0aca6db51e342f6e2',1158,26,'只能说很负责，也很理解学生，上课讲的很清楚，平时会发PPT，只要稍加复习，期末80+很轻松',5,5,5,15,0,0);
