INSERT INTO "reviews" VALUES('668fdfb52768d74884b86f38',860,860,'上丁老师的课，你就得认真听，因为全是干货。老师人特别好，自身教学水平非常高，不会照本宣科读ppt，讲的全是非常有用的干货和很前沿的东西，认真听就能学到特别多。省流：神。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668fcdac21b81106933f9da3',1531,641,'除了作业都给满了
INSERT INTO "reviews" VALUES('668fcd5721b81106933f9c3a',480,92,'很水，平时分交几次作业直接给满',5,5,5,15,0,0);
