INSERT INTO "reviews" VALUES('668fb15e5245002aaa1f5ed3',365,81,'得回答问题分才高。不回答问题就80多分。作业是交纸质论文，给分还算正常，不高不低。检查周会不让做其他的。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('668fb008607130454ecbcd4e',5096,496,'网编。给分巨高，半期都能给你拉起来。作业很少。阅卷超松。人也挺好。讲课虽然有点乱，不过还要啥自行车呢。可谓:陈老师，你是我的神。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668fa67a8c6e404f3d1daecd',631,74,'1.上课中规中矩。2.每学期基本只有四次课后作业。3.节节课要求定位签到。但我为什么要给这么低的评分呢，这个b牢師是最垃圾的实习，别的班测三教之类的比较简单，高山让你们去测八教去测九教，而且实习有问题你去问，他能给自己整破防，全靠助教哥带他飞。',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('668f9f75aca6db51e34110a4',30,376,'老师给分高，体贴学生，讲课很清楚，期末会画重点。大家快去抢！',5,5,5,15,0,0);
