INSERT INTO "reviews" VALUES('668f9e3b8c6e404f3d1d7d26',631,74,'纯纯倚托 实习的时候一问三不知 验收数据的时候一堆不提前说的要求 连有什么限差都不知道 选最难的教学楼 上最严格的要求  且身上臭臭的 交数据的时候差点被熏死',1,1,1,3,0,0);
