INSERT INTO "reviews" VALUES('668f93b8aca6db51e340c88c',2151,841,'冷酷无情，成绩一出直接失联。上课经常巡视，检查做题情况。平时分很低，少交一次作业就扣四分，少去一次课就扣两分。快逃吧',1,1,1,3,0,0);
