INSERT INTO "reviews" VALUES('668f1358aca6db51e33e3058',2172,2172,'最逆天的一集，教材和试卷都是全英文，ppt像机密一样就是不发，上课瞎几把乱讲，作业没有答案，期末没有任何重点，给分特别低特别低，而且根本没有明确的给分标准，最后只有一个总评都不知道这成绩咋打出来的😅，在西南交大遇到的最ex的老师没有之一，抽象程度令物流工程专业其他老师黯然失色',1,1,1,3,0,0);
