INSERT INTO "reviews" VALUES('668ea6052768d74884b2ed18',604,2035,'可能是给线代概率论打的高所以评分高吧，反正他的应用统计打分超低，应用统计可以跑了，超级凶，要求比别的班老师多得多，作业打分压分，半期考试期末考试压分。',2,2,1,5,1,0);
INSERT INTO "reviews" VALUES('668e83fa556b231523d8cecb',3025,5119,'评价 1 分是因为没有 0 分可以评价，建议系统更进一下，这个老师的期末分给的很低，没有人情味，讲话还巨唐诗，建议遇到了就好好背期末的复习提纲，软件工程的同学们自求多福吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668e7934c668584cd9ea9a0d',5120,1196,'上的是现场总线，这门课也只有这一个老师，上课基本听不太懂。偶尔会有一次点名，平时分拉满，期末考试也有题库，但是这学期期末出了两道不是题库里面的题，根本就不会😢',4,3,5,12,0,0);
