INSERT INTO "reviews" VALUES('668e5602556b231523d7c081',297,194,'帮胜哥真的yyds! 我上大学来最喜欢的老师，帮胜哥讲课很有逻辑方法，下课回答问题也十分耐心细致，真的超喜欢！关键是帮胜哥平时分拉满，直接冲！',5,5,5,15,1,0);
