INSERT INTO "reviews" VALUES('668e093721b81106933734a1',1131,1131,'神中神👍
INSERT INTO "reviews" VALUES('668e0863df8aa45a55c36e5f',2172,2172,'纯逆天一个，教材是全英文考试也是全英文，讲课奇差无比，不知所云。ppt好像国家机密一样就是不发，作业没有答案，期末没有任何重点。给分也是奇低无比，而且连平时分占比多少都不说，最后直接给个总成绩，谁知道你是怎么打出来的？😅😅😅在西南交大见过最差最恶心的老师没有之一！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668e066caca6db51e3398dde',2172,2172,'生产计划这门课，你要是期末考不到50，那么平时成绩就只占20%，无论如何你也过不了，你考到了50，平时成绩占比会按比例提高，最高到50%，反正肯定能让你过，这门课很难，冯春讲的也烂， 建议提前找学长学姐要作业答案，越早越好',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('668e064a2768d74884af5403',1108,188,'上了一学期，感觉还不错，可能是知道自己原来太抽象，这学期挺好的，事情不算多，就一次课堂作业和两次不算难的小组作业，平时分给了95',5,5,4,14,0,0);
