INSERT INTO "reviews" VALUES('668e0146c668584cd9e7dc4a',2172,2172,'没有平时分，期末考多少就是多少。PPT课本全是英文，试卷也是英文，期末不画重点。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668dfd22df8aa45a55c3305c',3295,3295,'事多的一批，小组汇报纯纯表演，而且小组汇报的分数还跟你是第几组汇报有关系，主打一个先到先得，平时上课不知所云，英语发音难以评价，期中考试用AI出题，想要平时分拉满就得给他当牛马整理翻译英文书😓期末考试还行，会捞，但架不住平时很折磨，上课不怎么点名，偶尔会发位置签到',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('668df2d65245002aaa168c9a',728,4936,'讲话讲不清楚就算了，上课班上零抬头率。总之就是快跑，期末考得高的就压平时分，期末考得低的就猛给平时分，总之就是正态分布笑死',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668df019ae490e3ede8ec73e',2172,2172,'nc一个，没见过这么恶心的老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668dd8898c6e404f3d14bbf1',2116,177,'平时作业有时比较多，但是上课听了就很简单😋给分也不错，周姐人还是比较nice的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668dd7f821b8110693362508',2116,185,'有时会点名，上课有点小快，但是氛围很好。最后给分还不错😋',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668dd0efc668584cd9e6d554',5145,5145,'我是去年上的他的电机学，感觉课讲的很混乱，完全不知道在讲啥。导致全都要自学，但是这门课自学有难度',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('668dccd95245002aaa15da3a',696,723,'讲课差得不行完全是找着ppt念，平时作业破事一大堆，期末考试反向画重点，给30个重点就考4个😅😅😅😅，还不如不画，期末给分也是迷，简直是毫无任何优点的老师😅和隔壁生产计划的冯c堪称卧龙凤雏',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668dca06607130454ec274fc',408,2119,'那些给低分的只能说自己菜，自己不学怪老师给的低，平时分直接给满，不想多说，期末你自己没学懂换哪个老师都一样，电机考的又不是特难，感觉期末随便80多，葛老师出了期中直接拉满，综评轻松上90',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('668d69c2aca6db51e336ddaa',2005,1697,'快跑快跑，平时分低的一比，讲不明白还事多，夹着个嗓子，快run',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668d5c43df8aa45a55c152f6',268,181,'老师是湖南人，口音很重，我个人不太能听懂。上课感觉什么也学不到，全靠自学。不过电气这边的计算机网络期末考试很简单而且不是保研课，所以也无所谓了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668d5ae4c668584cd9e5333c',408,408,'怎么说呢，感觉这个老师确实厉害，但是每节课都要求我们做思维导图还会抽人上去讲。一学期要写4次报告，其中有两次需要制作ppt上台汇报。除了mooc和实验以外的成绩都拉满了。但是这门课他上课讲的比较粗略，期末复习基本只能自己翻书硬看。期末考试有10道选择 5道简答 2道20分的问答题，还有一道20分的计算，感觉扣分比较狠',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('668d58bfaca6db51e336a151',767,5151,'我这学期上的是电气测量技术，上学期也上了她的自动控制原理，都在这评价了。李老师上课讲的比较细致，按她的讲解讲义来的话，期末考试差不多复习一下感觉就没有问题了。不过电测和自控她都会安排一次闭卷的期中考试，感觉比期末稍难。但是，自控如果感觉期中考的不好的话可以交一篇论文加分，电测我报告没按时提交最后补交也没有影响。总之，李老师是电气真神👍👍👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668d55af2768d74884ad2ea3',252,978,'跑就对了，作业隔天早八上课前天晚上半夜才想起来要布置的，一口川普是听不懂的，上课是爱提问的，签到是经常有的，应试技巧是一点不教的，小测试是直接算成平时分的，小测试和大考一样正规的，小测试特别频繁的且不掺杂任何水分的，，群聊是禁言的（没有任何什么群聊特别活跃的说法）。。。。。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('668d548e8c6e404f3d137720',1966,101,'很好的老师，使我期末急补也及格',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668d4f98aca6db51e3367d37',720,720,'看到这老师离远一点，平时分打的不明不白，考试还给你往死了低压，90分的水平她那里只能考70',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668d46375245002aaa141ee6',696,698,'划30个重点，就考5个 nb',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668d439cc668584cd9e4c69b',696,723,'逆天老师…期末成绩考的高的压平时分，期末成绩考的低的猛猛给，不认真学的和认真学的没啥太大差别。辛辛苦苦熬夜复习做课设没**用，******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668d3f9dae490e3ede8c41aa',30,5157,'很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668d3e90df8aa45a55c0c950',304,304,'很难评，你说他讲课差吧下来人还是很和蔼友善、意识到自己的问题态度还很诚恳，你说他期末突然让补交所有实验报告吧结果最后报告写得再水分都很高。如果你能自学并忍受他的一些令人哭笑不得的操作的话，还是可以选的，给分是真的不含糊。',4,1,5,10,0,0);
INSERT INTO "reviews" VALUES('668d3b58df8aa45a55c0b870',5159,5159,'上课虽然一言难尽，但是给分是真给啊🤗🤗平时分直接给满，不带一点含糊的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668d3ae6556b231523d2bec8',5160,5160,'平时分给八十，总分给58，喜欢，不错，那两分说是给不了',5,5,5,15,0,0);
