INSERT INTO "reviews" VALUES('668d33c5607130454ebfe63f',1554,1554,'都说吉祥爷老了给发低，上过的才知道绝对比其他抽象老师给发高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668d333521b8110693341515',1949,230,'不许你们诋毁我们汪老师😭😭😭人家老师人又好上课激情飞扬很有感染力😡😡😡，为人亲切和蔼上课还从来不点名👍👍👍，关键是平时分给了我满分😍😍😍你们有没有这样的老师啊，真是老老又师师啊😎😎😎',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668d30782768d74884ac6d3a',408,2119,'讲课水平一般，但只要认真完成作业有额外加分',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('668d2e5c556b231523d28400',67,67,'林老师的电磁场，就是我的神，期末狠狠捞，给分很高很高',5,5,5,15,0,0);
