INSERT INTO "reviews" VALUES('668d2dd12768d74884ac5f16',696,723,'上的数据分析，物工的同学们，这个人反向画重点，平时上课上得稀烂，可以这么说，这是所有物工专业课老师里面上得最烂的也不为过，期末分数大家能写的就20分左右，这个人怕挂太多人，给到50几，但我们都知道空白的就有60几分，考完当天全班破防，平时分他给的70几，总分62～65，平时作业很多，实验也写不来，给的代码都没法运行，而且这门课我们这年只有他教，都没法换，碰到他你们就认命吧',2,1,3,6,0,0);
INSERT INTO "reviews" VALUES('668d2d9c8c6e404f3d12b96b',2119,2119,'总裁就是我的神，讲的超级好，给分超级高，人超级好，不过每节课提问15分钟+点名',5,5,5,15,0,0);
