INSERT INTO "reviews" VALUES('668d1e3b21b811069333aae1',5170,1241,'纯纯cs，平时分能给多低就多低，其他老师都是给满，就他破事多 作业要留档什么，必须发压缩包过去 还要检查笔记',1,1,1,3,0,0);
