INSERT INTO "reviews" VALUES('668d015e556b231523d1969c',182,183,'纯纯cs，司马老师，隔壁班平时分95+，你踏马70-，专业课压分脑子有大分，上课口齿不清，bb啥玩意听不到，节节课点名，尼玛全按你要求搞，最后期末给平时分还要拉坨大的，纯纯cs。',1,1,1,3,0,0);
