INSERT INTO "reviews" VALUES('668cff40c668584cd9e34243',706,706,'点评交通运输经济，只有一个期中作业报告，平时会点名，上课东拉西扯，期末没有重点，说会给PPT在教务网上也没看到，平时分给的很低，期末改卷子给分也低，不推荐',3,3,3,9,0,0);
