INSERT INTO "reviews" VALUES('668cb9d621b8110693319bcb',563,228,'我和室友期中考试答案一致，同为一个小组，小组作业一样，考勤比我多五分，结果平时分比我多了20分？更夸张的是这老师还在群里攻击学生，口口声声要客观证据，同学说什么都没用，只要他那所谓的客观证据（但上文已经表明给分非常的不客观）。给了一堆低分后还说自己为了捞人已经打破了原则。中途还因病缺席了四五周，课是不上的。期中考试许多人没交试卷问他群里装死，期末出平时分跟同学对线倒是秒回， 不懂。并未改良，避雷',1,1,1,3,0,0);
