INSERT INTO "reviews" VALUES('668c8da1aca6db51e3324d69',3641,3641,'不捞人，下午考完晚上就上平时成绩了，但是平时分基本都有九十多，基本没有作业，课设随便做做就好了。这个课有点抽象在的，虽然是一个开卷的课， 但翻书都翻不明白，喷泉上一查我们这一届平均分61, 但老师给九十多也不能说是老师的问题',5,5,5,15,0,0);
