INSERT INTO "reviews" VALUES('668c0ea18c6e404f3d0dac17',123,123,'这位老师可以称之为交运阎王爷，据我所知他的行车组织课是挂人挂的最多的，一点不捞人。他本人性格古怪，脾气暴躁，想必评论区的朋友们已经说得很清楚了。那么我补充一项他的事迹：某同学某节课没来下次课补了张假条，阎王爷打了无数个电话就是为了求证这张假条的合理性与真实性…
INSERT INTO "reviews" VALUES('668c09725245002aaa0f0a48',1105,185,'伟大无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668c07d7ae490e3ede8625ec',2446,2340,'课讲的一般，上课总扯没用的，极其不负责任，期末不划重点，就点过一次名，收一次作业，但最后平时分背刺你，上两年大学遇到的第一个不捞人的老师，纯纯cjb',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('668bf7c98c6e404f3d0d4949',708,708,'不捞人，平时上课事很多，想拿高分的可以选，只要求过的不建议去',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('668bf79f556b231523cdae9e',3036,3036,'期末90+平时分给80史中史不如选hhy，避雷，赶紧逃，助理自己看不懂别人的思路直接不给分，真厉害，专业知识不够乱给分，建议赶紧跑',1,1,1,3,0,0);
