INSERT INTO "reviews" VALUES('668be32d21b81106932e9115',1606,1606,'给分巨低，PPT是给神仙看的几乎全是英文，平时作业一点也不水，每节课都要点名抽人回答问题，回答不好平时分低，好吧回答好了平时分也可能还是很低hhh。。。总之快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668be25a5245002aaa0e5162',1606,1606,'想知道那位得到95平时分的同学是怎么学习的',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('668bdc645245002aaa0e36ee',5210,5210,'成绩出来了，发现直接被炸飞了😅平时讲课很一般很一般，反正我感觉是抓不住重点的，效果不如我按参考书自学好😅期末考试说好了大量送分题，结果整个不定向选择题，然后还有10分一个的幽默大题，反正有两个我是没本事从他的全英语ppt里面得到答案😅我兄弟选隔壁牵引电机的都接近满分😩21级电气选门课的有福了🤗🤗',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668bdc13556b231523cd1ebf',2582,790,'笑面虎，纯纯笑面虎！目前上了他的城市规划和综合运输，平时全是大作业，一学期他一个人，两门课，可以给你布置9个 个人大作业和3个小组大作业，哪怕平时分能有90左右，但是期末全是重点，PPT勾了好几百页的重点，尽管考的都在勾的里面，但是隔壁牟能冶勾得起码少一半，没有对比就没有伤害啊！最后给分，可能是我没怎么背吧，期末分数60分，我真的谢谢他不挂我啊，给我一种完全是他努力我才及格的错觉😅而且物工的同学们，从大二下开始，你每学期都要上他的课，每学期都要被恶心下，我真的服了，呵。
INSERT INTO "reviews" VALUES('668bdbce556b231523cd1c2d',2582,790,'虽然期末重点确实画了几百页，作业也不少，但是平时分和期末给分已经很不错了，城市规划和综合运输工程都是这样，老师现在还是挺好的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668bdb002768d74884a6a5cb',5213,5213,'结构设计和抗震设计都是林老师上的，都是开卷课，平时作业有点多但是给分很大方，两门都是96以上。老师是国家注册结构工程师，专业水平非常高，考试考的都是课本上的算例，老师上课讲得很细，期末稍微复习一下就喜提九十多😋',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668bd875607130454eb9c649',1547,26,'不得不给我猛子哥正名了，说是不回答问题分不高其实平时分偷偷拉满，不拖堂，只要认真点他人还是很好的，对于上课戴耳机的同学才会发脾气，跟得上他还是可以学明白的，不过数学系讲课确实比较复杂，感觉课后要花点时间。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668bc964c668584cd9de31b3',1394,230,'老师人太善良了，讲课很有意思，水平也高，没怎么回答问题平时分也是拉满了，和同学交流起来也很和蔼，结课的时候给每个学生写了一封信，我哭死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668bc2efc668584cd9de13ae',1052,1052,'毛概平时分挺低的，事还多，不建议选',2,2,1,5,0,0);
