INSERT INTO "reviews" VALUES('668bb4c2aca6db51e32f38e4',4974,678,'我也不说有多好，但看到这群人诋毁老师真的受不了，也不知道都是什么成份的人，平时分就是作业，期中，课堂表现，我都不知道老师能有啥操作空间，上课啥的都已经说的很详细了，还带着做过很多题了，说期末没复习提纲的，考前已经带着说了一遍重点了，大多数都考了，群里也发过练习题和简答题，考的题都有类似的，还说要自己去找题？非要直接把卷子给你看才满意是吧？一群什么人？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668bae4c2768d74884a5b5a5',5219,280,'确实这个课程组需要课后加练，但是其他方面老师还是很好的，表达也很清楚，非常有爱心',5,5,5,15,0,0);
