INSERT INTO "reviews" VALUES('668b983caca6db51e32e84f7',211,240,'期末海底捞，力挽狂澜，差点就被电机学斩杀了，还好有嵩哥，评价满分不是没有理由的，无脑选!!!讲课讲的好，期末海底捞，5星是活水的极限，不是嵩哥的极限，电机是真的难，但你永远可以相信嵩哥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668b96f321b81106932cc75a',986,986,'课程分比期末占百分百，没有平时分，成绩只看期末大论文，对格式要求很严，平时基本不点名，平时不去都行，但是我每一节都去了，难受',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('668b96d28c6e404f3d0b2937',177,177,'上课从不点名，从不提问，半期发群里让我们自己写，作业只要交了就给满，韩志伟先生真的拉满了，信号与系统的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668b95ea607130454eb83ebb',2354,792,'非常好的一个老师，刀子嘴豆腐心，前期课堂吓唬一下，后期狠狠给分，只要按要求完成平时的任务，平时分基本拉满，数电选安林哥就对了',5,5,5,15,0,0);
