INSERT INTO "reviews" VALUES('668b7422df8aa45a55b89678',888,779,'快跑吧，根本不捞的，上课口音也重，脾气暴的很，学到包挂的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668b63d4df8aa45a55b8296d',5210,5210,'给分抠搜的一比，上来说贼简单，平时分也不是给满的，不如润去别的限选，总评随便拉爆这课十几分。考试选择上来十道不定项，太有实力辣',2,2,2,6,0,0);
