INSERT INTO "reviews" VALUES('668b5ea3556b231523ca6fbf',5210,5210,'平时分30，三个大作业，课件全英文，上课讲得不好，全靠期末对着英文ppt自学，学了吧，期末出题还难，10道选择题，全是不定项选择，哈哈哈哈哈哈哈哈哈哈哈哈哈哈，21级电牵保研的不知道有多少人被他坑了。',2,2,1,5,0,0);
