INSERT INTO "reviews" VALUES('668b5c60607130454eb71b4d',2354,792,'神中神！课设前期吓唬一下我们😰，然后给分拉满😍我愿称之为给分小王子！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668b5c235245002aaa0b8a52',2354,792,'神中神，上课三节课时间安排合理，上课要求严格，但是给分非常高，基本不点名，作业很少，期中考试开卷。',5,5,5,15,0,0);
