INSERT INTO "reviews" VALUES('668b571a2768d74884a3e2dc',5210,5210,'别选别选别选别选别选别选别选！全英文课件，期末70%，考勤占0%，三次大作业占30%，我认识的电牵大佬很多都在这个班，结果分都不高，想高分选牵引电机，想水选故障检修，来自老东西的真诚建议！',1,1,1,3,0,0);
