INSERT INTO "reviews" VALUES('668aaa035245002aaa09a76b',2241,195,'上的她的建筑施工，这个牛马老师，我真是服了，上课只会叭叭叭，总会把你当傻呗对待，一副你啥也不懂啥也没学过的姿态居高临下学生。期末自动要求闭卷，我只能说真是***，一个规范的东西闭啥卷，嗯是的，考试之前给了个大纲，你把全课本都画成重点谁背的完啊，总之，建工方向，叫本科建工方向的建工老师，可以换下一批了！',1,1,1,3,0,0);
