INSERT INTO "reviews" VALUES('668a8ee321b811069328d301',4974,678,'机组A，上课无聊 讲的水
INSERT INTO "reviews" VALUES('668a69d1607130454eb4005b',2169,5249,'老师人真的挺好的，和蔼可亲，很随和，会和同学们交流。平时上课很轻松，听不听无所谓。期中和大作业和平时讲的关系也不是很大。但是平时分给得真的很低，每一项做得一般般的话只有75分，期末是开卷，给分还是会好一点，平时分总分75总评给我捞到80了。不过据说以后这门课会改成闭卷。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('668a5b9d556b231523c6d5ff',974,5250,'综合评分95，讲课还好玩有趣，选了不亏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668a54d78c6e404f3d0655f0',4793,2570,'纯纯废物一个，乱打分，很多人都是作业全交了最后来个你有次没交，自己不好好整理收上去的作业就乱打分，学弟学妹们快跑，听说黄景春老师很好',1,1,1,3,0,0);
