INSERT INTO "reviews" VALUES('668a270c8c6e404f3d056720',373,230,'分高来，点名大概五六次，一次没来但就扣了1分，喜欢前面点名，坐前排可加分',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('668a2651ae490e3ede7df6b1',3724,2178,'。。。随便挑几个人给平均我也是服了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668a2162c668584cd9d7144d',5257,2793,'话少作业不多，平时分直接40',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668a205caca6db51e328c2a6',123,123,'只有经历过他的课，才懂什么叫真正的抽象，还是那句话想重修就选，每节课必拖堂，专门挂学生，让学生重修，平时分50分，上30的没几个一般都是20多，期末🉐️考60到70还是那句话，有胆你就来，闫王点卯。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668a148a8c6e404f3d051c3b',1850,34,'平时作业挺多的，但是平时分给的是真的高，基本上是满的，半期很水，上课讲的挺好的，就是记不住，期末还是得靠自己学，基本上不会挂科。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('668a10f2ae490e3ede7d9ae6',5,2735,'啊啊啊啊啊，不知道他是怎么打的平时分，高数1的时候，半期60多，平时分给的还挺高，有80多，高数2，我半期都80多了，平时分就比上学期高1分？！属于是半期低，平时分才给的高吗？这样也不太公平吧？！',3,2,5,10,0,0);
INSERT INTO "reviews" VALUES('668a0427556b231523c52ebe',1547,26,'给分高，负责任，也可以宽容，虽然对课堂要求严，不会提前下课，但是到点必下课，小测比较多，还会签到',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6689fdb1ae490e3ede7d35ad',3399,3399,'就这门课而言，老师是还不错的。人看着也比较和蔼，两节课内容也不是很多，还用了很多时间介绍课外的东西（放视频）。没有半期，平时作业只有两个课程设计，是自学实现，但是难度也不是很大，也能学到东西。期末卷子也不是太难，比较难受的是ppt是英文的。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6689f5e621b811069325f2f5',3754,156,'老王是专业水平非常高的一个老师，为人儒雅随和，课程氛围很轻松，与学生没什么互动，有问题也会积极解答，由于流体力学和液压控制本身课程难度很大，所以要高分也要认真学习，老王的期中考试确实是单独出卷，但是派两个研究生来监考，也不管你用不用设备搜题，两个课程的半期都是这样，平时上课还有小测，期末还会带着大家复习（非常重要!）期末考试出卷难，是好几个老师统一卷，改卷相对严，课程又7/3开所以还是有比较多的人挂，总之考试不是水课，但上课像个水课',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('6689f1e9607130454eb1b4cb',1487,1487,'新生研讨课和大三专业课都是上的丁老师的课，老师是非常厉害的老师，讲课很生动，专业知识很丰富，有问题会热情解答，但是由于课程性质，他的课想要分高确实要认真学，他也不会出水卷来给咱特高的分，但是改卷比较宽松，上课之前会随机抽人提问上一讲的问题（专业课），如果没人答得上来还会发点小脾气，总之是个非常非常优秀的老师，想要学到城轨专业知识选他就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6689659c21b811069324c4d5',209,209,'电子工艺实习请个假咋那么麻烦呢',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66895e45607130454eb07d15',418,418,'讲课神叨叨的很墨迹，但平时分不低，不做小测，上课会抽人，不点名，不让玩手机，后四排不能坐人，期中考得不好就要去坐第一排',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('66895c7d8c6e404f3d02f023',5267,837,'会记住每一个同学按照表现打分，抽查点名，缺课多直接挂，上课经常抽人回答问题，上课不能上厕所，上课要听讲，教得没毛病，但课程比较难，作业三四次，有期中测试',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('66895aec2768d748849cf7ca',5073,1796,'这里没有膝盖，我就在这里评价了。平时分他真的扣，平时不发言他真的扣平时分😭😭上课也感觉很抽象，总之快跑😭😭',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668942d721b8110693242212',5269,5269,'最后改动平时分占比挂了一大堆人，我的建议是以后就叫他亮吧，因为没有马',1,1,1,3,0,0);
