INSERT INTO "reviews" VALUES('6689366f8c6e404f3d0220e7',3098,3098,'差评！差评！
INSERT INTO "reviews" VALUES('6689303adf8aa45a55b04966',118,126,'只能说内心阴暗这个人，平时不怎么点名，期末就给你南蛮入侵全部杀穿',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66892bee2768d748849c10f8',1186,40,'上的交际文化与视听说，屁事一堆，看学习通还要求做笔记，她还要收上去检查打分，平时还得多回答问题，一学期两个小组大作业（PPT+视频），和2个小组讨论，和两个录音作业，平时分也低，可能我差吧，反正基础不好的别选她',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('66892b56556b231523c29ff4',1991,1065,'很好，特别好，很有趣，可惜这学期上面有检查，小崔同志后面就安分了，前期很有趣，属于在底下玩都忍不住想听听的那种，真的很有趣，而且平时分给满100，期末画重点，谁来谁爽，更何况这是我们优选班，终究是体会到了出生就在罗马的感觉了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66892b545245002aaa0400e4',5021,5275,'每节课提问考勤，很严格但期末给分不错会捞，课间会放音乐',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('66892a56aca6db51e3257e4c',5276,3698,'讲课听不懂，因为我菜，但是能感觉到是物工比较好的老师了，哪怕说平时分是专家组给，但是最后好像所有人都是90，期末考不是他改，是经管学院的老师改，但是他出题还是尽可能出简单，后面的答案在前面的那种，大题也是直接把平时小组作业的那些东西当大题，给分还行吧，毕竟物工很多。 。的老师，陈宁真的算不错的了',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('668928fb5245002aaa03f3fd',5077,5277,'能去郭波班就去郭波班，张扬讲得一坨💩，最后期末全靠自学，郭波讲得可比张杨好多了，张扬平时成绩就是一个财务报表（总共15张左右），拢共平时成绩就40分，他这个大作业就占了100%，写得人想死，写得好可以得95，写得不好就很差了。郭波至少点名跟作业会占分，大作业占了20%好像，而且郭波教的很好啊。张扬讲得真的差，上课就吹牛，什么给内江烟草做项目，什么恒大破产，什么每个老交大老师应该在成都都有3套房等等，谁上他课谁知道',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('668916a2556b231523c23cbb',1391,24,'老师只是事多，但只要不是平时太离谱，有些可以没做好，分也是给满的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66891178c668584cd9d33968',2200,2387,'王老师真的超级超级好，平时分能拉满的都拉满了，我QQ会向王老师问问题，她也很耐心解答，回复也很快！刚刚QQ给王老师说，我很喜欢她，她也很亲近的回复我！选王老师不后悔！她是我上大学为数不多遇到的好老师，上课讲解知识点，通俗易懂，讲得都很有用，把她讲解的基础抓牢，期末90+不是梦！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66891033556b231523c21bca',222,852,'非常好的老师，使我的材力通过。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66890feb8c6e404f3d0169a8',478,2570,'老师很友好，上课时经常乐呵呵的。平时分能给满的基本给满了。不知道给差评的什么情况',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668908d22768d748849b64bb',1287,68,'很不错的老师，很温柔，课上很少管人，如果想平时分高建议多回答几次问题～',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('6689079a2768d748849b5ec5',2399,230,'平时分给分没隔壁那几位那么神能到95+ 但是作业按时交上课缺勤少平时分还是能到90+',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6689012f5245002aaa032b21',903,179,'好，太好了，最好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6688f4992768d748849aed1b',395,395,'神！没要求！但是自学更有用',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6688f174df8aa45a55ae967b',5073,313,'习概，正常上课签到作业，平时分就给85，真恶心人啊',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('6688edf4ae490e3ede78ed89',5287,322,'第一周没选她的课，她记我缺勤，平时分给40。第一周选了她课的人，平时分80，比其他形势政策老师低太多了。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6688d3a9aca6db51e323b120',4977,4977,'爱给平时分打低呗，笑里藏刀的老师',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6688c5be5245002aaa01fcf0',5289,198,'作业少，讲的还行，上课偶有点名，每章线上测验，半期严，分座位排学号，严格监考。平时作业和课堂测验得分不会给满，但课设宽松。期末不划重点，不捞人。',5,4,2,11,0,0);
INSERT INTO "reviews" VALUES('6688c14ddf8aa45a55ada1f0',5290,5116,'温水煮青蛙，平时上课云淡风轻，期末连题都读不明白',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6688be5bdf8aa45a55ad944f',264,230,'平时分拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6688ab3ec668584cd9d0ee9d',5292,1954,'一个男老师给分抠抠嗖嗖的',2,3,3,8,0,0);
INSERT INTO "reviews" VALUES('6688a614df8aa45a55ad0776',1023,188,'神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668896f2aca6db51e32272b6',888,779,'期末根本不捞，平时分感觉是乱给的，有的高的离谱，有的低的离谱，上课还有口音',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6688839fae490e3ede76bb5f',888,779,'不捞，会莫名其妙扣平时分，全勤扣了课堂表现，期末全看个人本人',3,5,1,9,0,0);
INSERT INTO "reviews" VALUES('6688828bae490e3ede76b93c',2507,81,'事多话多给分还不高，只能说符合我对年轻老师的刻板印象',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6688244b2768d7488497d260',380,380,'老师非常棒，每一个重难点知识都会在课堂上花时间做题训教并一对一的进行询问辅导，期末还会统一讲解作业，而且作业也会通过学习通发布答案和讲解视频，老师本身的讲课水平也很高，平时分给的也都是八九十分，只要认真把课后作业搞懂，也是很好过的！何老师的课只有早八，第一节课会花点时间复习上节课内容（会着重点名坐在最后一排的人回答问题）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66881f0121b81106931f11b0',1891,5298,'和蔼可亲，不过点名有点勤，且作业要求有点严格，是按点给分的，导致大家最后的平时分都有点低。优点是考试之前会画重点',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('6687ff9d8c6e404f3dfd740c',5299,5277,'上的是物流工程制图，物流大二下为数不多的好老师😭给分高平时上课和作业也轻松，上课很多时候都会提前下课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687fea9c668584cd9ceee90',5300,5300,'课课堂表现评分方法：每节点名，全勤仅得60分，在此基础上回答问题，每回答一个问题+8分，从未见过必须要回答5次问题才能拿满平时分的。至于什么改作业认真，考试简单，笑死助教的功劳直接搬过来给老师？考试统一出卷又是他的功劳了？口齿含糊从第四排开始几乎听不清说话内容，专业水平可以给4分，其余难绷。',4,1,1,6,0,0);
INSERT INTO "reviews" VALUES('6687fc0721b81106931e7935',5301,2287,'谁在黑魏星老师😡平时分全部拉满，作业很少，课设简单，还有复习课，不知道怎么输😋',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6687efdddf8aa45a55a9f5b7',888,779,'根本不捞啊😭',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6687ecb1c668584cd9ce93df',888,779,'给分高，没得说',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687eaa0556b231523bcfcc0',888,779,'不捞，下一个',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6687e6ebae490e3ede74b6be',564,26,'老师整体还是不错，给分也挺高的，就是小测分不见得能给满，整体来说还可以，事情不多，但是期末要写一个小论文，交了就给5分，挺好的。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6687e2aa607130454ea9d9f2',564,26,'虽然老师讲课有时讲着讲着就不会了，但是平时分拉满，有小测，但是小测基本上都可以用手机收到。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6687df72ae490e3ede7495ac',2507,81,'明明是水课还强制要求你回答问题，不然平时分就很难看，无法理解',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('6687df1aae490e3ede749447',330,92,'老师声音特别小，还断断续续，三排之外基本上听不见。屁事多，给分还低，速逃',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6687dd6daca6db51e31f96be',330,448,'老师很差劲，作业是扣分的，上课是听不清的，可能怕大点声把我吓坏吧，三排之后别想听课，根本听不到。事情很多，搞了个什么个性化作业，让大家小组合作，给一堆表格让你填，好像七八个吧，还老点名，上课不发PPT，期末画重点声音小的可怜。(而且个人觉得其实画出来的重点也没什么用，因为大概就是把整本书的重要的点提了一下，是真的只是提了一下，提定理名字这种。)中午12点多下课从不提前，甚至拖课。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6687db11aca6db51e31f8ddf',2,5310,'平时分给的高',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6687d8be8c6e404f3dfcae43',755,75,'龚总yyds，上网课，让我少了一节早八课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687d753556b231523bca2e5',5312,5312,'平时分拉满了，不出意外应该全都是满分，一学期一次课没点过名 给分高事情少，就是上课讲的不够细致，老师总觉得说个大概就可以了，学不到很难的东西，但还好期末考试很简单。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687d64e8c6e404f3dfca4cc',631,74,'高山纯纯大傻逼，优选班是他倒八辈子霉，别人工测实习测的是方正方正的教学楼，他倒好，tm给测一个八教和九教，控制点贼多，300—400个碎步点，工作量是其他老师的N倍，天才呀，真tm是个大天才。测的导线靠马路旁，车俩又多，真想把学生给创飞呗。群上传达的消息可以随机变化，主测旁边的教学楼一下子在群上发要测，一下子又发不要测，一下子又可测可不测，真牛逼🐮，工作要求能够随机应变的。一些没教的知识点，默认学生会呗，老师没教默认学生会，问就是看书，选了高山的工程测量实习就是选一节军训，狠狠训',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6687d5285245002aaafe28a2',776,24,'这是什么品种的傻逼，平时成绩给的巨低，正修都不让你过，重修的压根没有活路，我真的不知道怎么有这种死人老师',1,2,1,4,0,0);
INSERT INTO "reviews" VALUES('6687cc1e21b81106931d7887',380,793,'神中神，给分极高，很负责任的一位老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687c01f607130454ea91a6b',1332,81,'谁选刘玉标，我笑他两年半！',3,3,2,8,0,0);
