INSERT INTO "reviews" VALUES('6687bba3ac273541e2ebd9be',5318,5318,'上课听不懂学不会ppt也看不懂 但是川子他捞啊 猛猛捞 凭这点叫一句川神',2,2,5,9,0,0);
INSERT INTO "reviews" VALUES('6687abdb31e27e7bf61dd922',2507,81,'极品，遇到快跑，人是sjb的，给分是乞丐的，不向上取整的，总之是个✘✘',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6687aa8cec86885101666ba0',2739,2739,'它的数据结构与算法分析课简直依托，平时分隔壁班基本都拉满了，它给个90都难，上课抽象无比巨坑。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6687a7beeacc9e05f0e7af12',1554,1554,'捞个🥚捞捞捞，吉祥爷给你全部挂完😅😅😅，听我的，先换制图',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('6687a7781486d01f9713b172',948,92,'老师很温柔，很温柔，很温柔',5,4,5,14,0,0);
