INSERT INTO "reviews" VALUES('6687a1eb9c24444b445143ea',18,18,'神中神。伟大，无需多言，平时分直接拉满，期末周带着总复习',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687a1c2f504e025e7c68918',18,18,'作业不多，除了期中其余给满，事也很少。虽然说回答问题，五分课堂分给满，但是不回答也给满了，作业也不查，只要自己学会了(不管是课上学还是刷网课)，老师是不会为难的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687a1a29c24444b4451423c',373,230,'老师很好，期末会画重点，基本上每位同学平时分都90以上',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66879faaac273541e2eb39c8',18,18,'打5分是因为只有5分，满分好老师✌',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66879f9bf504e025e7c67cc3',18,18,'目前为止遇到最好的老师没有之一，上课风趣幽默，考前还会发给我们试题练习，平时分直接拉满，大爱赵老师！！！！！！？？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66879b34f504e025e7c66518',727,4601,'上的习概，从🌰重那里跑过来的，一次作业写好就拿了满分😋，其他同学基本都九十多，上课没有回答问题的要求，分高事少强推。听说原来优选的班上有六七十的，幸好润了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('668789f79c24444b4450c5c5',3599,5332,'作业超多然后分又给的很低，平时分也给的很低快逃',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66878971eacc9e05f0e70343',365,81,'大作业以论文形式，给分较为理想，但是要回答问题，回答了问题，平时分高达90分；不回答问题，平时分高达80分，望周知',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('66878754cfad27515b0da391',359,228,'如果你在犹豫小米两级分化严重，告诉你文科同学很喜欢因为他们会说话，工科同学很讨厌因为不说话不给发，事也很多，想水想跑快点跑',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('66878469eacc9e05f0e6ec39',2633,26,'本来是没有评论的，凭一己之力一学期3个好评',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6687844231e27e7bf61d00cb',2500,228,'寓教于乐，不是死读课本，真心希望学生学到东西的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687817518c83b50b9986a13',802,5337,'要是想自己班总评六七十分，另一个班八九十分的话就选他，水是真水，重点是真不好好画啊，全是重点',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('66877ed8f504e025e7c5d6b3',5077,5277,'平时分作业认真做的话给分还不错，期末重点比较简略，上课不点名很水，老师比较和蔼',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('66877e9a981d7d6feea86281',18,18,'选的随机过程，我不会说赵老师是神，但这就是事实',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66877dd9ec86885101656bac',18,18,'离了赵老师谁还把我们当小孩啊，赵老师真的是我在交大遇见的讲的最好的数学老师，选他选他选他选他！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66877c70eacc9e05f0e6cb74',294,294,'选别人没选上才选的她，上课真的和其他人评价里的一样。那我说说少有的优点吧，如果你想认真学英语而不是水可以选她，因为她讲的确实很认真。其次是要求虽然真的多，但是你按要求完成的话平时分是我几个英语老师里给的最高的',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('66877acfac273541e2ea8466',831,5342,'随机过程期中考试，当天同一时间考，她给她的班级在考前五分钟开卷，另一个授课老师毫不知情😅😅😅只能说难评',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('66877a331486d01f9712cbec',82,82,'珍姐无敌，从不点名上课也不巡视，问问题的时候很和蔼可亲，平时分给的巨高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668779f8cfad27515b0d6832',18,18,'老师讲课讲的非常细致，又快又好，课下问他问题也会非常耐心细致地解答，非常好的老师👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668777e7f504e025e7c5bae2',77,24,'曾老师是最近几年才来的老师，对考试和批卷情况不是特别了解。但是老师真的很温和，而且擅长鼓励式教育，一边讲一边夸😂事也很少，平时讲课非常认真的，也会强调一些答题规范，如果你想水或者及格万岁他也不会管你，我们上课后边很多一直玩手机的。最后平时分老师都给拉满了，也基本不点名，作业是一周交一次给课代表。特别喜欢曾老师的一点是回消息真的很快，私信问题或者要课件每次都会很快很认真的回，期末考前那天晚上问他题好晚了老师还是很快回了，很感动。总之还是很喜欢曾老师的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668772cd981d7d6feea821e8',77,24,'上完老师课说下感想
INSERT INTO "reviews" VALUES('66877253f504e025e7c5a1a6',2151,1087,'这么说吧，每节课都要考勤，缺一节课扣两分，作业一次不交扣四分，严格按照标准。上课管挺严，坐最后一排都要被问题怎么解。不想多说，期末成绩一发群马上解散直接失联',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('66876ee7f504e025e7c5938a',452,452,'很好的老师，教学水平高，平时分给满分，而且考试之前会有保命题，不过上课风格有点像高中老师那般严格，但是平时是很和蔼可亲的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66876e44cfad27515b0d3325',1191,5349,'无需多言，亲妈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66876e2dac273541e2ea4a33',194,194,'很好的老师，平时分除了期中考试直接拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668769769c24444b44501640',1883,24,'两个字，愉悦，四个字，非常愉悦！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687639acfad27515b0cede5',1372,23,'大一下上的他课，为什么会有人觉得他上课是在念ppt？，他上课具有条理性是我大一见过的老师里最好的，算法问题都是循循渐进的告诉你为什么会这么做，先告诉你原因再告诉你做法，没有所谓的死记硬背，接着就是问问题，至少我在机房做实验的时候他重来不会不耐烦或者是阴阳怪气，反而是十分有耐心的告诉我，哪里出错哪里需要修改，我QQ上问他问题，他也是打字最多的回复我，而且正是那道题考试的时候刚刚好考到，如果他没回我，这道题算法我就是不清楚。
INSERT INTO "reviews" VALUES('6687630c31e27e7bf61c51ab',5257,2793,'平时分给满分的好老师！不爱点名的好老师！没有课后作业的好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687600df504e025e7c533e7',811,762,'总评93分，期中95，期末92，平时分不回答问题统一扣一分（全班总共不到五人回答过问题，不是不想回答，1是频率少，二是难度不低 ），平时作业每次按时交了，评价起码b+以上（期间还有一次a+）就这样平时作业都扣我1分半（10分给了百分之85），这种平时分不应该全给满的吗？跟他讲了以后才改到百分之90，还是扣了一分，期中复习两天考的95搞得现在跟别人考85分的没什么两样，真无语',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668754b7f504e025e7c4f61a',457,457,'平时分非常一般，快逃',1,1,1,3,0,0);
