INSERT INTO "reviews" VALUES('66873c5c18c83b50b9970b2a',5357,5357,'期末做了不到90分的题，最后给了90多。神中神！😎😎',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66872eb61486d01f97114fe4',925,428,'上课时候总是喜欢下来看看你在做什么，还喜欢偶尔叫人上去讲课，期中直接给助教判的试卷，助教给分巨低，答案错全错，最后给每个人期中加十分，但感觉有点杯水车薪。期末不给画重点给分也一般。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66872c57ac273541e2e90865',142,5359,'作业多，给分低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('66872c12ac273541e2e907f0',23,23,'神中神，非优选，幸运进入刘老师的班，刘老师上课充满激情，让西加加容易理解，答疑耐心温柔，跟着刘老师学轻松得到90+，刘老师的正能量也深深影响着我，太爱了，yyds!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6687293aec8688510163cfbf',359,228,'真别选，平时分低，其他班90多，就她80多，还有发言的基础分15分，没发言就没这15分了，离谱，反正选了快跑，上课交的还不咋样，有时候都不知道自己说啥',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668726c4eacc9e05f0e536c7',5276,3698,'老师人挺好的，期末平时分不管报告做得怎么样都给90，重点画得比较宽泛，但是总得来说在物流大二的老师里面算很好的了',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6686c75831e27e7bf61a68b4',1023,188,'茂姐无敌😋😋😋虽然上课随机点名，但是只要你不缺勤或者平时表现好，平时分都会很高很高的哦',5,5,4,14,1,0);
