INSERT INTO "reviews" VALUES('6686c2fccfad27515b0aa707',1274,36,'真的无语了，上课不知道说些什么乱七八糟的话，让我怀疑他真的是大学老师吗？爹味很重，期末课堂表现全勤竟然还能扣我15分，遇到就跑1吧，真的是无语。跑跑跑',1,1,1,3,0,0);
