INSERT INTO "reviews" VALUES('668690e018c83b50b994ebcf',478,498,'唯一的好处是不点名😅😅上课水平不行，自学这门课也难，平时分给的又低，根本不知道平时分具体有哪些，全靠自己信息搜集能力。快逃😨',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('66868eddac273541e2e701a4',3036,3113,'选的算法分析的课，平时分很高，期末我一题没做出来，只填了几个空，最后还是捞上来了，他教的很好，是我没学好。总之，李晓航老师YYDS',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668685d4eacc9e05f0e32355',5376,5376,'听说其他班站场还要半期考试，殷勇班没有。不点名，没作业，平时分给的还不错，基本上都能过。想水的快来，推荐！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66867a1bf504e025e7c20033',2535,2535,'神中神，在这一年机械原理考试较难的情况下捞了许多人，很多觉得自己要挂的人都被捞起来了，平时在手机上点到，但是老师从来不看签到地点，上课也不抽人。',5,5,4,14,0,0);
