INSERT INTO "reviews" VALUES('66862ed8981d7d6feea1fc3d',1154,1154,'上课很亲切，表现力十足！与同学相处融洽！同学们都能积极的回答问题！说捞你的时候也会把平时分给你打满！选她就对啦！',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('66862996eacc9e05f0e140b0',5388,23,'老师很耐心，问什么问题都会给解决，期中期末都是机考不捞人，平时分会给很高，但是 c++ 学不会就是学不会，挂科率很高很高',5,5,5,15,0,0);
