INSERT INTO "reviews" VALUES('66860260ac273541e2e432dc',1743,1743,'虽然不怎么签到，但作业比其它老师多，每次上课必定跑题，讲得一般，做不出来题还会嫌你资质差，觉得期末突击是乱象吓唬学生不发PPT，平时分低，不怎么捞人，倒一挂科率，水至清则无鱼，人至察则无徒',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6685eb75ac273541e2e3cc94',5392,394,'老师专业能力很强，也很亲和，就是平时分给的太低了，平时分30分满分只给25的样子，作业还暴多，对一个工科生来说实在是有点难崩',5,4,4,13,0,0);
