INSERT INTO "reviews" VALUES('6685a658cfad27515b05a7e1',3212,5,'确实讲课快，适合自学，提前学了上她的课会很轻松，除了期中期末，剩下的成绩都是拉满的，基本不点名呦',5,4,5,14,0,0);
