INSERT INTO "reviews" VALUES('66855a0e18c83b50b990458b',1441,228,'本来不是想打1分的，心情挺复杂的，但是打一个中等的分又怕没人注意到。结论：老师很好，基本不点名教学质量也很高，少数思修课程中让我基本能听下去的。但是！想高分的话还是换个老师吧，起码今年是这样。
INSERT INTO "reviews" VALUES('668555c4cfad27515b04b9b4',211,240,'嵩哥yyds!',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6685549418c83b50b99027b6',3489,5391,'杨中维yyds 期中给了100分啊 期末考了54（水分贼大 几乎都是编着写的）但是最好还是70分🥺给分的神 上课的神 上课循序渐进 讲得很好（但是我不是听课的料）但是他讲的真的很好 而且老师很温柔 有一次我在教室门口遇见他正要进教室，他竟然给我让路 让我先走🥺特别特别特别好 选到他无脑冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66854a81981d7d6fee9ef2fe',3489,5391,'平时分一点不捞，节节课去课堂表现还要倒扣，没明白是有吃了他家大米吗',1,1,1,3,0,0);
