INSERT INTO "reviews" VALUES('6685205bec868851015b7bf4',5415,910,'每节课都去，平时分100但是期末分63，实在无语',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('66851c99eacc9e05f0dd71ce',2119,2119,'邱老师真的是太好啦，讲的很好很细致，给分也很高。大家都去选邱老师的电机😄',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66851c6f9c24444b4446b2a1',2119,2119,'你交电机之神，伟大无需多言，讲课条理清晰，重点分明，给分还高，平时分直接拉满了，只能说选择总裁选择成功，懂不懂国家精品课程含金量啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66851c06ac273541e2e0f186',2119,2119,'电机神中神，讲的好给分高，选他就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66851bf331e27e7bf612d75c',2119,2119,'神，有哥们36被捞上来了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66851bd518c83b50b98f19d6',2119,2119,'总裁！我的神！！讲课很有条理很清晰，特别强！人也很好很有趣。会经常强调重点知识加深大家的记忆和理解，给分也很好，除了考试全部拉满！！电机学这门课很难，但是有总裁真的会轻松很多！！虽然上课会提问，但是回答不出来也没关系，重点就是加深印象。大家都快去选他！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66851b5deacc9e05f0dd6bf9',2119,2119,'邱老师爱死你了，朋友们无脑入！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66850ffdec868851015b1671',540,1520,'神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66850f28cfad27515b034869',2535,2535,'上的谢老师的机械原理，谢老师人超级好，上课虽然要说我们，但是期末狠狠打捞了，整个寝室都过了',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('66850adfec868851015af9a0',3202,5424,'抽象就对了',3,2,5,10,0,0);
INSERT INTO "reviews" VALUES('6685098a31e27e7bf6126abc',52,52,'马老师上课不让玩手机，签到多，讲的比较快知识点密集比较难跟，但是会发ppt建议自学能力好的选。作业只要全部按时完成平时分给满，小组作业抽人展示有点难绷，但是群里和同学聊天挺好玩的',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6684f72431e27e7bf611ff10',2861,2862,'很好的老师，使我平时20毕业爆炸。凭什么只有听课的人才能有平时分？等我考试回来一大堆要做的东西不知道就截止了，然后平时给到补考80才能过，就您铁面无私我活该拼命补考是吧？',4,3,1,8,0,0);
INSERT INTO "reviews" VALUES('6684f2aceacc9e05f0dc87a6',5210,5210,'只能说快跑😭😭😭',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('6684ec4731e27e7bf611c592',2500,228,'袁神，启动！(✧◡✧)',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6684cb2ecfad27515b01ec31',882,2793,'课设要求简单给分还高，上课耐心温柔还会讲一些有趣案例，会提问但答不上也没事，一些重要章节会发作业一定要好好做，期末很有可能原题。人美声甜心善，汤汤老师一定不要错过( ﹡ˆoˆ﹡ )',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6684c8a2eacc9e05f0dbc72b',5430,5430,'每次都签到，只交了个作业，给了89，上课随便干什么，想水的强烈推荐',5,5,5,15,0,0);
