INSERT INTO "reviews" VALUES('6684c703ac273541e2df4839',315,40,'给分规则很多。如果认真完成的话，平时分还可以，但要求严格，真心不适合大多数人。如果摆的话，给分就比较一般。老师心底还是好的，但学生上课上得心累也是真的。',4,3,2,9,0,0);
