INSERT INTO "reviews" VALUES('668497caeacc9e05f0d941b3',1991,188,'崔神不必多说，评分可见一斑。只要不缺勤，平时分拉满，大作业统一给满分。期末划重点带复习，总分就看你期末考怎样了。神中神，能选必选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66848a69981d7d6fee9b4b0c',887,23,'很好的老师  很认真负责但是又不刁难学生  课程作业确实比较少  是我上大学来听得进去的唯一一门课  缺实验作业可以补交  雨课堂小测忘写了也可以给老师说  期末真的有很努力捞人  另外课程测验是可以通过联系系统补满分  选到的偷着乐',5,5,5,15,0,0);
