INSERT INTO "reviews" VALUES('6684121c31e27e7bf60f1f07',170,170,'若志一个 肾虚上课声音小 期末乱给平时分 每节课都去 作业按时交 得到了80的平时分😓😓😓学这门课基本没听他讲 纯自学 上课看你画图 画错了还会阴阳你😓😓😓😓赶紧跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66840ccb31e27e7bf60f04d2',170,170,'避雷，真的，三连堂每节课都去了，签到都签了，课堂练习都做了，正确率70%以上，课堂表现平时分就给66分，同班的同学旷课也没签到，课堂练习没做，给了80分课堂练习平时分，不知道是拿什么给的平时分。平时上课说话声音跟蚊子一样，虚的一，能跑就跑吧，平时分真没期末卷面高。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668404d5981d7d6fee9a18a7',68,68,'第一次选课没抢到后面才选了冯老师的课，当时看了一眼活水心都死了，但是上课之后我发现没有那么夸张，老师人很好，上课回答问题0.5分一次，基础分3.5，多的会+在其他项里。上课需要跟着老师思路走，我觉得老师讲课还是很有吸引力的，所以听她课并不会无聊，是能学到东西的。然后作业也不算多，能接受(但是她上课要是没人举手回答会随机抽人，没回答出来会被蛐蛐两句)。分给得蛮不错的，我最后56。但是老师会不定期点名，然后请病假需要医院证明，是适合上课比较活跃能听一下课的友友们的，不太适合摆哥',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('668404061486d01f97046c6d',3407,762,'。。。谁说他平时分拉满的，我两学期的课平时分都50不到，室友的也很低',2,2,1,5,0,0);
