INSERT INTO "reviews" VALUES('6683e716eacc9e05f0d751f7',428,4716,'老师挺好的，上的数学分析，教的真挺好，会课外扩展，可以帮助大家掌握好数分知识，数学分析作为数学专业最重要的课程，学好他是尤为这样的，确实是交大为数不多的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6683de4e1486d01f9703a522',828,828,'名师！有能！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6683d5f9cfad27515bfe86b4',2633,26,'首先 每节课都点名 三次不到直接取消考试资格 迟到五分钟就算不到 上课不允许看手机 看手机扣平时分 上课讲的支支吾吾 自己给自己讲 作业多的要命 要求特别高 考试一点不捞 考勤准时去 作业准时交 平时成绩都不给满 谁选他的课谁倒霉',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6683cd6feacc9e05f0d6bbe4',260,96,'亲爹！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6683ccc69c24444b44418422',5471,156,'ppt全都看过了理解了，自己找的网课也刷了，不让过可以早点说呗，考前发个自测题都做得能背下来的程度结果发个卷子做下来没有一道相似的，选填确实不咋会但是大题认真写了啊，你那个平均分二三十是（）打的出来的分？大三下本来就考研各种忙，期末也花了整整一周来学这个课。你考前模拟诈诈大伙也就算了，非得给全班挂一半多呗，感到恶心。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6683c9f9ac273541e2da25b6',24,24,'你很难再找到一个像郑小武老师一样的认真负责的严师了，上课会管学生玩手机 会点名 但平时分会拉满 你只要跟着老师走 就不怕分低 建议想考高分 想突击顶分的同学来 想水的别来',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6683c8c11486d01f97032672',491,1529,'毫不夸张的说包捞的呀，硬给我捞，刚好60！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6683c0f831e27e7bf60d7095',2633,26,'上课事情多的一比，只能听他讲，问题听不清楚他讲话，又克扣平时分，碰见了赶紧润，我概率论平时分94高数70，期末还没考就挂了7个人了，自己看吧，想挂就报',1,1,1,3,0,0);
