INSERT INTO "reviews" VALUES('6682e43d31e27e7bf60a61dd',252,114,'高数讲的一坨，平时分给的最低，没有之一。还喜欢进行随堂测验，一学期还来个三次，就等于你一学期要考五次高数，测验测什么，测你马。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6682e2e418c83b50b9857846',252,114,'nc一个，讲课一坨，平时分最低，一学期三次随堂考试不放任何水，走来走去，随堂考试题型变来变去，头一次见考数学来默写公式和表达式的，大一选到他你有福了，后悔没在这个学期高数课把他换掉',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6682ddd8f504e025e7b3e75c',828,1073,'神中神，无敌海底捞，认真交作业就会疯狂捞你，选到就是赚到，我为凡神疯狂打call',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6682d5bbf504e025e7b3cd15',546,880,'语言文化翻译，事情少基本不下来溜达，坐第一排也可以摆，作业认真写平时分就可以',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6682c125981d7d6fee951df4',5094,2570,'我不知道为什么次次作业都交了，基本上都是手写的，不敷衍，最后课后作业100只给我七十是什么意思，你给我平时成绩无缘无故打中低分，我也给你打低分..',4,2,2,8,1,0);
INSERT INTO "reviews" VALUES('6682aa459c24444b443cea24',373,619,'上的习概，老师不怎么点名，但是有平时作业，上课不是很水的那种（偶尔抽人，会提醒不许用电脑之类的），平时分接近满分。但是听说其他老师更水，没作业，并且平时分50/50。反正没必要非要抢这个老师吧，优选班是她没必要换，非优选班没必要一定要换成她的课。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6682a5901486d01f97fe6f09',831,5342,'无敌了，压分巨离谱，想拿高分速跑！！！',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('668293a29c24444b443c66d9',42,5127,'只有说声抱歉',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668292a131e27e7bf608f041',551,551,'平时成绩给满分必须给好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66829267ec8688510151738d',35,35,'老师人真的很好，讲课真的专业，对待课程很认真，所以想水课就不太容易，每节课点名，但是没什么作业，期末也就是表演，如果认真上课一定高分，90➕',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668291b4eacc9e05f0d1b959',177,177,'神中神，打算自学的选，不签到不点名，平时分只要交了qq群作业就给满，从来都不改的，期末透题，无敌好吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66828f22eacc9e05f0d1ade7',1103,1103,'平时分给的一般，讲课水平也一般般。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('66828c1bf504e025e7b2667a',1103,1103,'处中处，选就裂，快跑，无敌了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668286b3ac273541e2d51312',2017,762,'为什么表达能力高分啊，上课生动形象，不过基本都是切蛋糕，挖沙子，一整节课都在举例子学不到个啥。坐在后排会课前抽问，坐在前排听了个寂寞还饱受折磨，中途逃课可能会点名，选了她的课就是一种享受。课上不能看网课，会和你争辩网课和她自己的专业水平。会有一个其他班没有的课程报告，美其名曰GPS（get,problem,suggestions)，快跑孩子',2,3,3,8,0,0);
INSERT INTO "reviews" VALUES('668285d8ac273541e2d50c93',2017,762,'讲课一般，天天切蛋糕，挖沙子，平时给分就那样，就作业分是满的，还贼拉多，不讲题，自认为比网课老师好的多，建议不要听网课，因为她在质疑网上的全是错的，点名很花式，提问从后往前，总之，很一般，事还多，自以为是，体验感很差',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('668277df9c24444b443bd32c',3212,3212,'来交大这么多年，没见过这么抽象的老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668270d0981d7d6fee936e60',961,762,'复习周就上传了所有平时成绩，还给的巨低。期中和小测都丢给研究生改，结果改卷只看答案不看过程，一片人期中10分8分的。好多人期末要考70-80才能过，还有期末周小测这种逆天操作。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668270a531e27e7bf6084584',961,762,'给分巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('668269bdec86885101509ed4',546,880,'选的她的翻译，感觉不错，不用想其他英语课一样用英语发言，上课讨论就是在微助教上面打字讨论，平时的翻译作业，基本上用Gpt做，自己稍微改一改就可以，而且没有慕课和学习通，吧把小组作业认真完成，最后平时分也很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668268f2ac273541e2d47183',82,476,'老师人特别好，上课很轻松，老师非常有耐心，而且会发复习资料，平时分接近满分，给分很高真的是好老师！！',5,5,5,15,0,0);
