INSERT INTO "reviews" VALUES('668107d731e27e7bf602cba6',3253,5547,'上的线性优化，物流工程的同学们，如果你运筹学单纯形法学得还不错，那么这个限选课千万别错过，就是把单纯性法的表格法改成代数法罢了，作业也是好几届都不变，直接拿着上一届学长学姐的答案抄就行，平时成绩几乎给满，助教想方设法的给分，期末也全是课后原题，只是全英文的PPT而已，但是你运筹学单纯形法都学好了，这个PPT可看可不看了，还有个内点法，更简单，这么多年都考的那么一道题，直接背住就行。这课比马啸来那个城市规划好一万倍，马啸来那么多大作业，期末背那么多东西。这课就一共就10道题里面出5道还是4道，答案都给你了，轻轻松松95+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('668103f418c83b50b97d8bfc',1320,40,'老师人挺热情，每天说给我们各种加分，实际上平时成绩少的可怜，比其他班要少好几分，快跑',2,2,2,6,0,0);
