INSERT INTO "reviews" VALUES('667ffa1731e27e7bf6fec984',411,36,'说川普听不懂，还喜欢布置课堂作业，上课回答问题可以加分（但个人感觉没什么用 回答问题平时分还是不高）期末又要做小组作业又要做个人作业，别的班同学都只有小组作业',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('667fee23ac273541e2cab5ec',411,36,'不缺勤，上课回答问题，大作业个人作业完成，课堂作业完成，平时分70+',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667fec6cec8688510145e55d',433,433,'田田老师人真的巨好啊 只有亲身体验过她上课的才知道她人真的不像活水上说的那样！uu大一一整年都上的她的课 平时作业真的很少很少几乎全都是u校园上的作业 偶尔几篇作文提交在u校园上想ai直接就可以复制粘贴 她的课每节都会有u校园的手势密码签到所以建议不要逃课 偶尔会抽人起来回答很简单的问题（读单词和翻译什么的）除了这些以外真的没什么了！她从来不下来巡堂（小测偶尔会）你上课小测想在下面玩手机真的没人管你 pre一个学期算上最后比较有创意性的口语考试一共会有2-4次 而且她给分真的挺高的 uu这学期u校园时长差了四个小时好多都忘记做了还有好几次请假和迟到最后平时分都有90+ 大家真的理性看待评论！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667fc06deacc9e05f0c692d4',823,793,'集所有优点于一身',5,5,5,15,0,0);
