INSERT INTO "reviews" VALUES('667ef54eec868851014193b1',2078,23,'老师人性格比较好，但是上课真的无语。人是一直照PPT念，还会抽人回答问题，点名要点两次，作业量也是真的多啊，期末重点划了等于没划。赶紧跑路吧。',1,2,3,6,0,0);
INSERT INTO "reviews" VALUES('667eec8ceacc9e05f0c3bdaf',828,828,'凡哥，永远滴神。人也耿直，找他写推荐信，二话不说，非常好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667eec7cac273541e2c6f8d5',294,294,'这学期实在没课选了，不想去翻译，最后选了杨老师，怎么说呢，其实评论区说的情况都很属实，上课确实比较像高中，而且会让同学们读ppt和她发的消息，最令人头痛的是她会抓迟到扣分，下面是给分，一个学期有两次小组作业，一次ppt，一个视频，感觉事情不是很多，就说得按照她的要求来，最后在鼠鼠没有任何加分以及六级没过的情况下，杨老师给了56/60，感觉已经很高了，如果小伙伴们也没得选了的话且有冲击高分的想法，杨老师还是可以选的，给分确实不错。',2,4,5,11,0,0);
INSERT INTO "reviews" VALUES('667ee173f504e025e7a4585c',349,194,'非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667ebc37cfad27515bea224b',123,123,'点名每节课都有，而且往往点上节课没来的。他的课如果没去，别在后面课上补假条，补了=你没去=扣分。平时分拿多少就是多少，一点不捞。上课喜欢吹牛逼，时不时在黑板上写他认识的人的名字。这门课期末不划重点，想拿高分的，第一个是别选他，第二个是没事就做做这门课的习题集吧(网上能搜到，一般也会发)',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667eb315ac273541e2c61075',250,250,'快跑！！！！！！！！！！',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('667eb26031e27e7bf6f9b8b8',250,561,'就是一坨勾史，能从工图起源给你讲到宇宙起源，再从美国骂到教室里的每个同学，无差别地图炮，而且口音奇特，不知道哪来的外星人，反正上他的课无缘无故就被内涵',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667eb23df504e025e7a38342',250,250,'非常好的老师，选到就是赚到。
INSERT INTO "reviews" VALUES('667e844f18c83b50b973f469',409,1622,'她的物理实验课真是没得说，给分巨低，总的来说就是个笑面虎，表面上和蔼其实比谁都不讲人情，对学生根本没有互相的尊重，选到她的课就赶紧逃吧！！！',1,1,1,3,0,0);
