INSERT INTO "reviews" VALUES('667e1226ac273541e2c301f6',978,352,'参加了三次数模比赛拿了三次奖，平时分给了100总评98，虽然他上课讲的内容感觉对我并没有什么帮助，但是人还是比较和善的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667dad6c18c83b50b9703d26',5105,5606,'虽然听着有点无聊，但是老师确实讲得很认真，有时候说话有点小刻薄。把作业题都搞会考试就没问题，偶尔点名。总的来说还是挺推荐的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667da2e718c83b50b9702f0a',1672,1672,'是在是没有见过比王老师更好的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('667da21feacc9e05f0be7e8e',248,48,'史中史，羽毛球班，大一下学期打了几乎一整个学期的太极。一口一个天人合一，一口一个本我超我。给分纯看心情，跳绳成绩也睁眼说瞎话。也就是我有羽毛球基础不然高低得挂科。',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('667d9f00f504e025e79f45c7',1991,188,'崔晓东yyds，冲就完了！在别的班都没划重点的情况下考前划重点，平时分几乎拉满。老师上课风趣幽默，像脱口秀，敢讲真话，不屑于拍某些领导的马屁。真的很害怕这么好的老师被背刺！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667d9de71486d01f97e93ecb',2582,790,'一样的课，他划的重点是别的班的五倍，问就是PPT基本全是重点，几百页的PPT真的背不完，给分特别低，笑面虎',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667d9d9b981d7d6fee8044e9',1193,27,'不点名，一学期一次不去，作业一次不交，平时分拉满，妥妥的好老师，冲就对了，上课打瞌睡的话会给你批假让你回宿舍睡，很关心学生的身体健康，不让你做在课堂上受罪，很贴心，没点过名，冲就对了，等你选了以后你就知道你选的对不对了，嘿嘿嘿，包不后悔的，老弟🤠🤠🤠，冲吧，孩子',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('667d9d3acfad27515be56840',696,723,'考前一天晚上发了几十个重点，考试几乎没考，好一个反方向的重点！讲课是讲不清楚的，问他问题是不会回答的，要么是助教回答，要么是其他同学回答。真啥比',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667d9c9bac273541e2c22d97',3886,5613,'牟老师人超级好，城市规划原理平时作业不多，就是上课不让玩手机。不过最最重要的是有重点他是真勾啊，划的重点考试全考到了，另一个班勾的重点几乎是他的三倍。',5,5,5,15,0,0);
