INSERT INTO "reviews" VALUES('667cd7909c24444b4425cb85',1480,127,'很好的老师，讲课讲的很有意思，跟着他真能学到东西。管的比较严，不过给分很高。想学东西的速选，想划水的谨慎。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667cd59331e27e7bf6f1b139',2878,27,'选到黄老师的课无脑冲就完事儿了，特别温柔，讲课也认真，会记住每个学生的名字，期末还会捞人，真的特别好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667ccd6131e27e7bf6f18900',984,850,'上的城轨供电和监控，我看看谁还不选王老师，期末开卷一门，另一门给了PPT背了就有90分，全是原题，上课不怎么管你，点名迟到了也没事，平时作业基本没有，但是上课讲的很细（所有她上的课）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667cc9c7ac273541e2be6ef6',2637,40,'平时分56/60',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667cb74eeacc9e05f0ba51e4',85,597,'老师神中神，给分巨高，上课挺有意思的，主要是会给你加分！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667cb66a18c83b50b96bc967',867,27,'上课比较水，平时起来水几次问题平时分还是很高的，老师人也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667ca9eb9c24444b4424e37c',6,619,'后几排是不让座的，手机是不让玩的，上课是要点评女生坐姿身材和穿搭的，是要吹牛说自己主动放弃了北京户口多么牛逼的，给分是很低的，逼事是超级多的，课是不下的，笑死我了从来没见过这么令人无语的老师，他在课上直接立规矩被他抓到玩手机还有点名没来的这学期就给你挂科，真的是好大的官威《我直接给你挂科我说到做到》，快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667c760d31e27e7bf6f02498',123,123,'快跑 快跑 快跑 不要不信邪 这是真的大坑 快跑！！！！！！！！！如果想试试补考可以选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667c598b1486d01f97e3f600',1727,5629,'评奥运裁判带你鉴赏赛事（大三体育课）：长话短说就是压根不鉴赏，天天让你在操场锻炼。。一学期十七周就鉴赏一两次。。期末考试考跳绳或者是体测内容 快跑吧千万别选这个课（他本人不上课都是助教上课。。）',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('667c545831e27e7bf6f0018c',233,306,'好喜欢你～😊😊😊
INSERT INTO "reviews" VALUES('667c53df981d7d6fee7b3d02',173,28,'我推冰冰老师，平时分直接拉满，老师人很好，很和蔼可亲，大爱',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667c53439c24444b44240c64',1727,87,'打满一百个记评也只有70+分
INSERT INTO "reviews" VALUES('667c4c2c981d7d6fee7b2f7c',173,28,'刚开始看到分到这个老师，感觉天都塌了其实没有评论区那么夸张，也可能是老师有听取大家的意见改善了很多，个人感觉平时分给分不算很低，在不参加任何二课/志愿者/背书的基础上，（平时分60分满分）拿55及以上也都还是比较轻松的（甚至可以抛弃掉部分作业，她作业相对于其他班确实算比较多的）（因为四六级考试还有竞赛什么的有加分），老师很温柔，笑起来很可爱，助教人也很好，非常好说话，总之还是非常推荐的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667c49bc31e27e7bf6eff007',1265,1265,'平时事略有点多，上课会点人回答问题，但最后平时分给了57',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667c4436ac273541e2bcb6bc',5635,5635,'确实几乎节节课点名，随机抽人回答问题，两个作业，一个2000字的手写的桥梁赏析，随便抄抄都90，一个打印的6到7页PPT，找个模板往里加点稍微和她课沾边的评价桥梁的东西轻松95；我每节课点到的时候都在，有幸被叫到回答问题一次，但离太远她没听清然后课堂表现分也给满了；两个作业和课堂表现都占20%，最后的课程设计打印点儿思路，随便画上一张结构简图都给了92分，这个课程设计占40%，没有期末考试😄，总成绩只有平时分，上课随便干啥都不管，课前交作业和课程设计的时候会顺便签到，交作业的时候签完到就能溜了，她不会再点名，小概率会抽你回答问题，总体来说还是很水的，选修最后给94分应该不低吧🤓',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667c42c49c24444b4423ec8a',315,40,'每节课课前都会点名。作业少，只有U 校园，课本练习（一个学期四个单元），作文（一个学期四次还是五次），口语（上课会抽）。加分机会贼多。不摸鱼的话，平时分应该有45分及以上（我一个英语废渣，期末不挂，全靠将近50分的平时分）。喜欢讲哲学，哲学讲的挺好，喜欢听她讲这些',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667c4285cfad27515bdffa33',961,762,'夸杨宝英好的那个学生是不是吃了shit了
INSERT INTO "reviews" VALUES('667c41bbeacc9e05f0b85eb0',1032,736,'老师人非常好，这门课本身又难教又难学，老师能那么耐心的解答每位同学的问题，难能可贵！老师还会为每位同学的分数着想，尽量给每位同学高分。平时作业也不多，这门课我们专业第一次开，感谢能遇上这么好的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667c410931e27e7bf6efd97b',1032,736,'课讲的可能有点模糊，毕竟也是真难，但老师很好，特别为学生',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('667c40baac273541e2bcacf1',123,123,'差评如潮！必须差评如潮！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667c3fab9c24444b4423e351',961,762,'给分太低了，其他班同一张卷子能高三四十分，不知道是什么心理，挂人压分好玩吗😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667c3c6c981d7d6fee7b0721',123,123,'重量级人物不知道这位是怎么混到现在的，上他的课和赤石没有什么区别，纯浪费生命。上他的课是这样的，你只需要担心自己能不能过就行了，而闫海峰老师要拉低你的成绩考虑的事情可就多了。辛辛苦苦考了67十分搞不好还是挂，没见过全班大部分人的平时成绩只有60分左右的老师吧，更别提因为别的班的老师画了重点就连夜改期末试卷。想跑？不好意思你会发现他一个人开了一堆班，没一个报满的，你换课只能是换个刑场，不知道他在恶心谁呢。配套的课程设计也是抽象，不光要求你交个成品，还要看你画的草图也要交上去。真是搞不懂他那花生米大的脑仁里面装的都是什么，在现代还能存在这种专门为了让学生挂科而压分的老师，等哪天逼疯几个学生就老实了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667be60c18c83b50b968cb38',1273,157,'请假麻烦。下雨也得拉过去溜溜，讲几句再走。我自己能及格全靠平时分和平时上课没有摸鱼划水，老师硬捞，但如果是其他体育课，基本你上课认真的话，自己考个及格是不成问题的。
INSERT INTO "reviews" VALUES('667be198cfad27515bde2e5a',541,28,'无论出于什么样的学习态度，能来就算是福气了，u校园该搞就搞搞，分就不可能低，老师比你还担心你的成绩。总之神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667bdea7981d7d6fee795261',408,2119,'类似于龙文杰那种，做学术很厉害，但是讲课一坨的，就看电机学的几个老师班上的人数就知道，别的老师都是爆满的，就这个老师一个班30多人
INSERT INTO "reviews" VALUES('667bdd5cf504e025e79872f3',2200,177,'老师神中神，但是这次没画重点，谁能想到前面几章的分值那么低，最后以为不是重点的两章分值那么高',5,5,5,15,0,0);
