INSERT INTO "reviews" VALUES('667bdb0f9c24444b44221777',1103,1103,'拉中拉，随机考勤，平时分要回答问题，讲课很无聊，全是读ppt，但是最关键的是画重点
INSERT INTO "reviews" VALUES('667bd8159c24444b442203f6',4081,2598,'平时分不怎么样，慕课，课堂测验，期末考试什么的都很严格。平时认认真真写了作业上了课结果比别的班平时分少了三到四分',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('667bd67e18c83b50b9687a2a',246,228,'喜欢针对人 上课喜欢抓迟到 喜欢蛐蛐人 快跑吧 千万别选他 平时分给的也低 太痛苦了',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('667bd13c9c24444b4421e0e3',2637,1265,'简直就是神！！！分数高低完全看自己，回答问题+作业做的好分就高，给了我59/60，第一次这么高的英语平时分！说给分低的都是自己没认真做吧，怪不得老师！都来选她！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667bce2eeacc9e05f0b62009',228,228,'每章都会布置几道课后题，有点多，小组作业要求略高，不满意的会让你修改。但是老师划的重点完全贴合考试内容，基本上猜得出材料题考什么，极大地减轻了背诵的负担，而且平时分给分都是90+。挺好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667bcb56eacc9e05f0b60efe',31,5035,'上到秦老师的课就偷着乐吧',5,5,5,15,0,0);
