INSERT INTO "reviews" VALUES('667bbcbeec8688510134cb24',4115,4115,'煤油钼，早点退休伊特谢特吧😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667bb088ec86885101348b8f',961,762,'期末周小测，改卷逆天，碰到她算我倒了霉了，能跑赶紧跑吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667bae141486d01f97e0ea17',1853,670,'上大学以来，上过的最垃圾的老师和课程。前半学期讲课没有任何重点一会儿想前面一会儿讲后面速度快的飞起。讲的比隔壁班能快一两章，简直离谱。然后说动手才能加深印象，花了一个多月的时间让我们自己做一个课程项目。结果导致后半部分时间不够，又讲课快的飞起。更要命的是期末考前划重点。画的重点跟期末考的卷子没有什么鸟关系。还不如不画重点，那样至少自学的时候不会学漏。更要命的是你找她要ppt，她一直说以后会发以后会发，结果到了期末考试都没发。就算一开学把ppt全发了，然后一学期啥都不干啥都不讲，我期末都能考得比现在好。听她讲课，干扰我自学进度。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667ba842981d7d6fee7831b9',449,40,'老师很温柔，大二上学期通用学术英语，大二下学期限选英语公共演讲都上的任老师的课。平时分50+，作业超过截止日期也可以找助教补交。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('667b9886cfad27515bdcc12e',1168,228,'伟大无需多言',5,5,5,15,0,0);
