INSERT INTO "reviews" VALUES('667b8084ac273541e2b91e53',2444,2444,'很有活力，讲的很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667b7d91cfad27515bdc3987',1955,194,'左东老师yydd！！上过老师的线性代数，后面的概率论就选了他的，因为在活水上找不到他的这两个课，所以就来高数这评价了。老师不管什么课教学风格都是一样的，课件都做的很好，讲的也很好，资料整理发的很多很有用，其他班的小伙伴都来要。而且如果不是教学评估，老师从来不点名，并且只要按时交作业，平时分都是拉满的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667b37dbec8688510132a8fe',631,631,'好你个丽丽****，就爱59挂人，49我都不说话了，59挂一堆人***',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667afdb0cfad27515bdb0726',11,11,'跑，当年不小心给分到a班，平时一堆事，天天要搞小组ppt平时给的还贼低，期末考试考70分都给我挂了。',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('667af6ca18c83b50b96546c3',87,136,'马朗yyds，大一的时候因为网卡了进去只有足球了，之前完全没接触过，马老师人很好，给我们充足的时间踢比赛和练习，会亲自给你教动作，而且给分这些的十分人性化，本人的水平有这么高的分简直不敢相信。总之，yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667af3fc31e27e7bf6e9fd7f',1175,68,'神中神，从来没回答问题，平时作业，小组作业正常做，55.6',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667ae95a18c83b50b9651c7a',4510,5559,'当我选课前看到活水上对杨老师的评价时，我的内心是忐忑的：我担心“哲学的智慧”这门课干货少、老师喜欢随便怼人...但是我还是坚持了自己的初心。
INSERT INTO "reviews" VALUES('667ae40ccfad27515bdabb23',16,68,'课很水，老师亲和力也很强，就是平时分给的不高',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('667ae1a8981d7d6fee757bb2',788,449,'只能说无敌老师，在这门课花的时间比身边谁都少，拿的分比周边谁都多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667ade5b9c24444b441ec8b7',513,66,'别选，快跑，去什么都别去这个，问问题就是“关我什么事”，什么都不管，还甩脸子',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667adc0fec86885101320247',5674,5674,'我为唐老师打榜！一个学期体验下来，就是开学就会把课程要求和给分要求说的很清晰，整个学期只是最后一节课点名作为出勤考察，而且还会提前一周在群里说，期中是小组展示，期末就一个论文（要查重但是不难），想水课混学分的话可以选择。而且上课我觉得真的很专业，至少我这个对美术作品很感兴趣的人来说真的很喜欢，老师人美心善，如果你也感兴趣请记得多和老师互动！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667ac578ac273541e2b6a4f5',1606,1606,'期末复习给假资料，被误导完了，强调的东西一个不考',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667ac3dc981d7d6fee74eda5',5676,279,'快跑，快跑！！！！！快跑我说真的没开玩笑！！！！上课非常随心所欲（贬义）完全就是凭心情上课，朝令夕改不是一天两天了，经常在作业上放学生鸽子，作业跳着看，你的名字他不眼熟就根本不看你的作业。一个PPT反反复复用，重复的东西反反复复讲。自己不懂的东西，非说这是学生自己拟造的词汇。大清早就亡了，这么喜欢的连坐的老师21世纪了还能在你交看见，点两个人答不上来就一口气给全部人加作业，无视其他人的努力。看到另一个评论说很大男子主义的时候我当时还没觉得，现在上了两个学期他的课我只劝各位快逃……感觉根本就是在拿学生找乐子……',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('667ac0a41486d01f97ddee9e',696,723,'如果不能说脏话我就没什么可说的了，反向划重点真🐮b👍👍👍',1,1,1,3,0,0);
