INSERT INTO "reviews" VALUES('667a7b1f31e27e7bf6e7c4ca',1193,27,'很不错的老师，之前看到老师的评分还有点害怕，经过两学期之后，发现老师其实非常和善，而且平时给分也很高，第一期答题四级参加英语沙龙55+，第二期课堂不活跃没有参加沙龙也有50+。平时上课除了不带手机和安排固定位置之外几乎没什么比较不适应的地方，每节课都有固定的课文背诵可以加分，而且都是英语沙龙要求的，相当于加两次分，作业也不是很多，除了要考4级和6级的时候会安排一些真题之外，平时就几乎只有u校园的作业。补充，会点名(根据固定座位一眼就看出来了)，上课可能比较枯燥。总的说来是一位不错的老师。(个人意见仅供参考)',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('667a7855ac273541e2b50767',373,230,'老师讲课很有激情、考试重点及其确切，推荐！',5,5,5,15,0,0);
