INSERT INTO "reviews" VALUES('667a776e981d7d6fee737a48',2202,27,'就是说谁家大学老师期末会给学生发巧克力 结课之后也有一年来的感谢信息 真的人文关系拉满 而且是真的费劲了心思想让我们学好英语 上课真的非常引人入胜 分到金老师的班长你就透着乐吧',5,5,5,15,0,0);
