INSERT INTO "reviews" VALUES('667a428d31e27e7bf6e6bf61',1128,40,'职场英语，给分挺高，上课念ppt，会提问！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('667a3f299c24444b441ba860',87,136,'马老师真的很认真，人也非常好，与同学们能打成一片，给分也很高，即使你的慕课没有看完，也会给你尽量给高，很幸运能遇到这样的体育老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667a295c9c24444b441b34cc',11,11,'上完一年的感受：本人大一新生所以进去完全不知道u校园还要算时长平时分特别低，第二学期懂了分就上去了，老师可能也知道我们什么鸟样，平时分给的很高。。。对老师第一印象不是很好但是上到后面觉得他教我们也很无奈哈哈😂老师人还是很不错的，不会问题也不会被骂，作业没做也不会口头骂你直接扣分（额）而且本人上学期逃了两节课完全没被抓，爽',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('667a280aec868851012e852b',5703,5703,'给亲爱的郭老师一个大大的好评😘老师很负责，上下课都会很认真地监督学习，但是不会特别严厉，跟着老师走总评85以上肯定没问题的，努把力就能上90，欢迎来养老！不过逃课就算了，老师都记得我们的脸哈哈，谁没来会直接认出来的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667a0da4eacc9e05f0ae392d',1128,40,'神，平时分55/60是常态',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6679a2d31486d01f97d9c144',2202,27,'全胶带最好的英语老师！只要认真完成作业上课回答几次问题！除了随堂测试平时分几乎是满的！上课气氛活跃，口语听起来非常舒服！都给我报！',5,4,5,14,0,0);
