INSERT INTO "reviews" VALUES('66798b18ac273541e2b1c6f6',1955,194,'伟大，无需多言。唯一缺点就是有一点点口音，不过问题不大，适合想好好学且想得高分的同学',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66798a8eec868851012cd7e8',5709,5709,'好老师，沟通友善，上课风趣幽默，期末划重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66798a45981d7d6fee703fe5',5002,3026,'淼子哥是有实力的，手推公式刷刷刷就来。但是这门课基本上就是全推公式了......',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('667989ab31e27e7bf6e3dff7',896,896,'涛神水平确实高，老师是个好老师，上课基本上就是念跟教材一样的PPT，会稍微解释一下。就是这门课本身有点抽象，涛神经常会用看弱智的眼光看你',5,2,1,8,0,0);
INSERT INTO "reviews" VALUES('667986cb981d7d6fee70329b',483,5712,'听得进去一分钟就是神人了。每个班准备ppt负责讲一节课，最后加分还得根据准备ppt的人数平分，期末三千字报告，自己没东西讲只会点人回答问题，要不给讲课的同学发点工资？',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6679839331e27e7bf6e3c5c2',867,28,'职场英语平时分给了58.2 太感动了呜呜呜 回答三次问题课堂表现分就是五分满分(一次一分) 多回答的会加在其他项里面 而且老师真的很美很温柔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66795b899c24444b4417a539',846,27,'李老师会在能力范围内给高分，真神！人美心善！',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('66795278ac273541e2b0b22a',1058,5,'很好的老师，把你当成小朋友教你，有点像回到高中，想水的别选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66794e68eacc9e05f0abb496',1193,27,'上课是挺水的，但是平时分给的我很满意，两次都是54.5/60，事也不多，都是教学规定的任务，人很温和，喜欢。总是提醒我们要去英语沙龙背书，挣点平时分。课上没人举手时偶尔一两次会挑人回答，回答不好也没关系。课上不让看手机。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6679446a9c24444b44172ff9',264,230,'神，神中神，做自己的事情完全无所谓，要中途翘掉也不管，讲课非常激情且幽默风趣，认真听的话一定会有收获',5,5,5,15,0,0);
