INSERT INTO "reviews" VALUES('66785307ac273541e2ad088d',457,457,'上课抽人回答问题都是小意思啦！！！第十六周的时候说 十七周上课讲关于期末考试的注意事项以及回答有些同学问划不划重点的问题……第十七周的课上，他的回答是：不划～',4,2,3,9,1,0);
INSERT INTO "reviews" VALUES('6678510a1486d01f97d41c15',140,368,'老师很有梗，超级幽默的，偶尔提问，帅气',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6678509f31e27e7bf6deea6a',2377,322,'上课不让玩手机，不许坐后排，第一排不坐满就不上课，其他正常水平，讲课没趣味',5,4,1,10,0,0);
INSERT INTO "reviews" VALUES('6678500731e27e7bf6dee8c8',1212,1471,'给分很高，会划重点，上课水，会点人回答问题，每节课都签到，期末要做小组汇报，考试开卷',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66784d6631e27e7bf6dee136',870,296,'会点人回答问题，回答不来扣平时分，偶尔点名，讲的很普通，但不会管你在课上看网课，作业太多，每页练习题都要交，小测不少还压分',3,4,3,10,1,0);
INSERT INTO "reviews" VALUES('66784c1818c83b50b95a8ca3',395,1007,'会捞人但给分不高，平时分实事求是，有小测但会提前预告，不点名不留作业',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('66784ba7ec868851012792d1',5739,5739,'给分超高，超级水，也不留作业不用教材，平时不点名，期末交论文替平时分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66784b2918c83b50b95a89eb',27,27,'平时分给的比较严格，很努力的情况下才能拿到 50+（60分满），讲课特别好很仔细很好的老师，真的能学到东西，作业不少',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('667802def504e025e78926bb',121,1010,'炒鸡好，温柔大方，给分高，人到就行了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677f9f79c24444b4411bbae',3925,3925,'选的是数理统计，老师教的很耐心，喜欢把过程都说一遍，本人概率论csj教的，基础不怎么样，但是依旧能听懂，主要就是上课要跟着思路走，上课会让人回答问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677f91b981d7d6fee686a9a',2346,2346,'本评价针对数学专业概率论这门课，讲的稀烂，自己完全不懂，PPT也不是自己的也不给你，工科的课不知道，但是这样一个专业水平的人来教数学系简直太难以接受，大大磨灭数学系对统计方向的学习兴趣，而且很影响下学期数理统计的学习，关键讲的烂自己不懂不说，而且给分很低，期中期末全都要挂掉了，数学系千万不要选，建议隔壁统计的老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6677f7dd1486d01f97d29b49',925,4716,'可能他是第一次讲复变函数，建议选复变函数的不要选，其他的我不知道，他的复变函数自己教不懂，然后给分又是乱给的，不是给分低，是全凭运气给分，自己讲的复变函数是混乱的，自己都搞不明白来教学生，最主要的是他连作业是哪儿都是混乱的，就是哪一节该做什么作业他都是混乱的，当然至于其他的课我就不知道了。',1,2,3,6,0,0);
INSERT INTO "reviews" VALUES('6677eac931e27e7bf6dd2ca0',210,28,'上课有时候点名，只要不缺勤u校园写了，就算你口语考试说中文，他平时分也能给你90+，神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677eaae9c24444b4411718a',210,27,'我罗希姐，教的又好，给分又高，人美心善，上课也轻松，给分又高，我爱我罗希姐🥰🥰🥰🥰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677de2a981d7d6fee67d5e5',385,27,'除了作业比较多以外，其他还可以。课上原则上要关掉，会点人回答问题，大部分是课前完成的作业和小部分翻译之类的，个人感觉还能接受。布置的四六级作业很大程度上帮我备考。平时分给的还不错。',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('6677d6a118c83b50b958618d',1292,1292,'期末复习周要求做课设，都不知道怎么做',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6677cb7e18c83b50b95825c5',5318,5318,'有的人可能就不适合教学，科研能力很强，但是教学水平。。。。。。。。。。但是老师人很好',3,1,5,9,0,0);
INSERT INTO "reviews" VALUES('6677cadd981d7d6fee676ea4',385,27,'这作业你就写吧，一写一个不吱声。考核项目非常多，上课很累事很多，但其实也学不到什么东西。老师挺亲和的，卷王可以选。',2,3,5,10,0,0);
INSERT INTO "reviews" VALUES('6677ca3f981d7d6fee676bc9',2688,2688,'非常好的老师，很推荐选。期末论文交了直接95',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677ca0e1486d01f97d1a6a2',1513,1513,'不挂人，但给分也不算很高。胜在事少，课程听着轻松还不用考试。',3,5,5,13,0,0);
INSERT INTO "reviews" VALUES('6677c9aacfad27515bcc629e',409,1622,'诸君可得过40分的大物实验？',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6677c3e318c83b50b957feea',1850,34,'学生全都花钱买的课设，还以为自己很会教，年年桃李满天下',1,1,2,4,1,0);
INSERT INTO "reviews" VALUES('6677c3bcf504e025e787e3ba',185,185,'一般',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6677bd68f504e025e787c128',4438,22,'PPT的朗读者，只会读ppt，问个问题都答不上来，讲的也听不太懂',1,3,3,7,0,0);
INSERT INTO "reviews" VALUES('6677bb6dac273541e2aa36d4',89,33,'非常好的老师，给分高，上课不下来转，课程内容丰富',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677aa43f504e025e7876cdd',1600,96,'马老师真的人很好，上课不会点名，讲的很好，用板书，很少用PPT，人也很亲和幽默，我真的爱死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677a70ff504e025e78760ad',344,803,'和蔼可亲，对每位同学都非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677a6ebcfad27515bcbb344',344,5760,'超级好的老师，上课很好，特别为学生着想',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677a50bcfad27515bcbabf2',725,40,'上的翻译，真的水，平时作业就是翻译一句话还不是每周都有。小组作业喷不了，都是学校规定的，但是老师要求很低，视频做得水也没关系。平时分还可以吧，啥也没干都50+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677a4cc9c24444b441018a3',362,28,'老师挺好的，平时要求比较高，管的严，平时分每项都按规定给的，得多少就是多少',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677a4a39c24444b44101817',68,68,'给分上限很高，其他老师一般56,57算高的，冯老师可以给到58,59.平时上课比较无聊，不听在下面干自己的事也没什么，老师偶尔抽人回答问题，不知道问题或回答不上可能会被说但也没什么。老师讲课认真，作业什么的一般拿课堂时间完成，负担还是比较小的。职场英语这门课有慕课要注意作业截止时间，另外老师课堂回答问题一次0.5，超出课堂表现算在加分里面可以说性价比极高了',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('66779a4918c83b50b957314f',210,28,'👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677895deacc9e05f0a3dc7f',1547,26,'只会给你讲概念，不会给你讲方法，新老师对于考试内容一无所知，上课抓不住考试重点，然后又比较死板，听不进学生的话。',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('6677831931e27e7bf6db09f0',459,68,'本人水平四级未过，课上摆哥，课后也是摆哥（没有任何加分）测试50多分（测试搞个备用手机可以操作），最后平时分49感觉也可以了，毕竟课上不点名，作业只用做全年级都有的，上课玩手机打游戏就行😋，感觉还是蒋的课不错的适合摆哥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667782beac273541e2a92db1',16,5767,'king！平时分57分爱她！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6677800a31e27e7bf6dafae1',610,610,'我觉得讲的挺好的，平时分给满。助教超级超级好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66777f59ec8688510123cc0a',7,7,'首先，课讲的非常好，而且老师对物理是有情怀在身上的，每次讲到重点或者讲一点物理史的时候感觉眼睛都在放光。ppt做的简洁明了，平时作业没带可以回去拍照发送，平时分除了期中全部拉满。人也非常亲和。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66777e9aeacc9e05f0a3a3d9',2012,296,'符老师真的超级好！选到他就偷着乐吧！上课不念ppt，板书纯手写。讲课特别清晰明了，还会举很多例子，作业布置合理。平易近人，QQ上问他问题看到就会很耐心回复。只要平时别逃课，作业好好交，平时分除了期中都给你拉满。反正就是特别特别好，强推！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66771159eacc9e05f0a2d3d7',2157,2733,'人好分高活不多，期中小组ppt期末水考试，点名不用去教室可以扫码签，还给发酒喝',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66770cbe1486d01f97cf65d6',459,68,'平时分巨低，别选，前面之前打高分的对得起自己的良心吗？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6676fe5931e27e7bf6d9eb68',1474,1474,'特别特别好的老师，讲课非常细致，认真负责，经常与同学们沟通，邀请大家报考他的研究生。上品行端正的老师的课，有如沐春风的感觉（平时分给我的满分😚',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6676fd0aac273541e2a7f7a4',3921,2598,'一学期没听懂几次话，口音重得根本听不清',4,1,3,8,0,0);
INSERT INTO "reviews" VALUES('6676fac6ac273541e2a7f0e8',4991,226,'有病 留的作业纯恶心人 不说解决方案，只会说她在日本留学老师是不会讲的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667674a0cfad27515bc753cb',5776,5776,'限修课三次不去就不给过，比较忙没时间去的，大三大四可以多犹豫一下',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('667673e51486d01f97cca015',1748,395,'很严格的老师，限修课上课不准玩手机，缺勤缺多了会吓别人期末没成绩别来了，学生请假必须要提前一天请，提前五分钟请会不通过请假。总的来说是个守死规矩的很严格的老师，想水的话最好绕过她',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('667670c41486d01f97cc906f',2584,40,'57.2/60',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66766ee8ec868851011ffe01',314,314,'在交大见过最差的人就是她了，说再多也没用，因为咱们没得选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6676692118c83b50b952a6e7',1489,850,'陆老师真神，管的少又松，无论给分还是作业都松，点名基本雨课堂，考前画考点，算是比较水的。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('667660bbec868851011fbd96',1372,348,'大一上上的刘老师的课，对于我来说绝对是满分，阴阳怪气可能有人会这么觉得，但是老师说叫你多看书有什么问题么，不是也一样给你回答了吗又不是叫你看书就不给你回答了。我印象最深有一次凌晨问老师问题老师马上就回了。念ppt是确实，不过预习了能听懂，不预习的话课后再补可能会比较难受。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66765c4d1486d01f97cc31f7',210,28,'超级棒！最大的特点就是非常好说话！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66764ad4ac273541e2a4b0d2',101,114,'不给 3 个 5 分说不过去了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667645499c24444b440abd76',315,40,'对于认真搞平时分的会很友好，但如果她要求的没准备扣分也扣的挺厉害的。我英语能力挺烂的所以她要求的尽量做到。每节课点名，作业每次也查，有时候会布置新概念英语的背诵和朗读，只要有准备就不可能扣分甚至加分。还总会让人讲解课文段落，好的加分不好也不扣。期末平时分也会捞人。按正常来算我平时分应该是51硬给我提到了58。课上的有些无聊，但还是爱她😢',3,4,5,12,1,0);
INSERT INTO "reviews" VALUES('667644b7cfad27515bc66568',123,123,'全交大最恶心的老师没有之一，活该交运这烂专业越来越差，把6个课设安排在大三下，不想让学生考研，卷子改的巨几8严格纯纯➗声，选到他的课的人就享清福吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66764277ac273541e2a4857f',2012,1753,'符伟大，无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66763a49981d7d6fee613224',172,39,'分少，室友其他课基本上80/90+，这个老师压分事还多，太极别的班一个不挂，他带的羽毛球班一挂挂七八个。天天在课上摆架子，教得不咋地，架子先摆出来，搞不好以为他是奥运冠军。上课快无聊死，把全班聚在一起絮絮叨叨絮絮叨叨，技术动作就教了一学期几节课，第二学期全面散养，搞双打比赛，什么也不教了，上课掐个小烟过来，搞得跟领导开会一样说几句，羽毛球嘎嘎好的来，否则别碰。',3,5,1,9,0,0);
INSERT INTO "reviews" VALUES('667632279c24444b440a5b9f',2012,1753,'我为符老师举大旗！！！符老师yyds！！！',5,5,5,15,0,0);
