INSERT INTO "reviews" VALUES('6675aa62ac273541e2a30945',5,2735,'讲课很有意思，当听戏一样听听课下来再自己看看会轻松很多，真的会捞，随堂测验也说交了就80，期中44能给捞到80，但是作业基本不布置，期末考试自己得上点心。',5,5,4,14,0,0);
