INSERT INTO "reviews" VALUES('66747e45981d7d6fee5ad217',5803,619,'不理解你是来干什么的，关灯放视频然后感觉就没然后了，但是平时分确实给了我80多',1,2,3,6,0,0);
INSERT INTO "reviews" VALUES('6674757f18c83b50b94a9cc7',545,433,'莫老师讲课几乎没有英文，古今中外啥都说，非常严肃爹味十足。因为在A班，不知道为啥课程考试的分数就是那么低（全班普遍都低，班上还是有不少英语高手的，结果都六七十，我考了60多），因为这个原因，这学期我拼命搞平时分加分特别努力（加满了）结果平时分总分还是只有53分。这门课大一学生是退不了的，而且刚进大一的学生也不太可能关注活水这个平台。所以学弟学妹如果来到了他的班，那些U校园啥的最好全找代刷，想尽办法把课程考以外的平时分多得一点（毕竟课程考你的分不会太高），然后适应他东拉西扯的讲课的方式就OK了。',3,5,1,9,0,0);
INSERT INTO "reviews" VALUES('66746ac21486d01f97c4cc06',385,27,'作业确实多，但给分也很不错，适合喜欢卷的同学，老师很负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667460d418c83b50b94a7a84',3707,741,'给分高，选！',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('66745c251486d01f97c4b09e',5635,5635,'手写2000字课程作业，画设计图，做ppt，上课点名就算了，点人回答问题，拜托通识课哎😑',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('667459aceacc9e05f09833da',5808,2205,'选就完事了',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('66745979f504e025e779f983',1332,81,'难评',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('6674588ceacc9e05f0983035',2633,26,'这老师严的一笔，每节课必点名，三次不去必取消考试资格',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('6674585ff504e025e779f59c',2819,28,'我本身英语很好，老师对我就较轻松，给分也很高，虽然有时比较严厉，但确实是一位好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667456fb981d7d6fee5a8c7f',221,36,'张大律师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667455f2eacc9e05f0982946',1033,736,'只针对这门课而言，统计不想认真学又想拿高分的，建议选同时期的市调，不然后悔死😢',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6673a992ac273541e29a20cc',545,433,'A班事情是很多的，但是莫老师这个人吧，就是严格按要求办事，严格按要求给分。好好干分很高（我平时分57），不好好干分就低。每次上课都点名的，总体来说不水但是肯肝分就高。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('6673a95b9c24444b44ff2ea0',1538,1073,'熊老师真的超好！！！讲得仔细，人也超温柔，超可爱！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6673a7e8cfad27515bbb3698',83,83,'无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6673a15731e27e7bf6cb9655',123,4552,'每一次都会点名。给他一次点名的机会，他恨不得全班都挂科。一分是交大活水平分的极限，但绝非学生对他印象的下限，每一节课必点名。课程设计别的老师审核一下就完事，本来不需要草图，他非要去每个学生弄一个草图，平白无故增加工作量，纯属恶心。每一节课必须拖堂（除了自己有事情之外），而且拖堂根本不讲课，从来都是念叨他曾经带过的学生和北京交通大学他所认识的人。考试根本不可能给你重点，不但不会给你重点，别的班老师一旦给了重点让他知道，他还会把卷子改掉，出的异常的难。计算题大题10分的大题从第1步开始错，几乎往后就没有分。无任何人身攻击，所说的一切，都是学长经历的事实。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('667398c51486d01f97c107e5',499,194,'神中神，平时分直接拉满！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66738f09981d7d6fee56a703',459,68,'本人是22级的，英语本身基础不是特别好，当时是看着评分很高来选的，但是不知道为什么就是选完之后评分突然降下去，最后在给平时分的时候知道的原因，为人特别懒，并且都不过问你的成绩，总的来说吧，就是英语这些公共课的话评分都不是特别的标准，有些老师评分不好，但是给分却很高，有些老师却又评分很高，但是又不怎么样，主要是还是得问具体的学长们，但是她平时确实很水，没有什么平时作业缺点就是给分确实不是特别好，对于基础不是特别好的学生来说就是灾难（平时作业就是一个PPT和一个视频）',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('6673882318c83b50b9464a06',83,83,'特别好的老师TTT 平时分会给满，讲的又好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667375d1ac273541e2991b04',2674,2674,'快run!',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6673754bf504e025e7759284',23,23,'最喜欢的老师，温柔耐心，讲课超有激情，让C++不枯燥，跟着学易得高分，QQ问问题秒回，处处为学生着想，无脑冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6673730f31e27e7bf6ca4f08',1538,1073,'讲的很好，冲啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6673209c31e27e7bf6c9aac5',5824,4047,'我上的是交通基础设施防灾减灾导论，老师讲的很好，上课氛围很轻松，不点到，大部分时候会有培养能力的探究性作业',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('66732020ac273541e2983946',2819,28,'认真负责，但是作业真的多',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('66731fe8f504e025e7745b06',257,5,'讲的很有活力，可惜我听不懂',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('66731facac273541e29838c6',349,194,'真的好老师，不仅讲的好，并且对待差生还有特别帮扶',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667319eeac273541e2983056',5828,5828,'真的学到了很多，更自律和自洽了，不仅是学习能力变强了，心态也积极了很多，李老师教给我们很多有用的小技巧，超级超级喜欢李老师啊，他情绪很稳定，给分也高，还很细心。总之想水也可以水，他会尽量捞你的，可是认真听你收获会更多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667309af981d7d6fee5564d5',2151,1087,'平时分低，但是考前会给两套真题卷',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('6672e4171486d01f97be08ab',913,611,'人不错，是个好人',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6672c7e81486d01f97bd7dc1',1186,40,'不是哥们，90.5 的平时分可不是在开玩笑[嘘]。这意味着期末我考十五分我都可以过[吃瓜]',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6672c20feacc9e05f0911ec7',513,66,'都怪我大一选课时没有看活水😭两学期差点体育挂科，班里基本比其他体育班低十分',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6672be33cfad27515bb6615a',1379,346,'1️⃣第一次上，前五次体育课没有出现什么问题，考试成绩也中规中矩，从不缺勤，作业按时按量完成。为了准备期末考试甚至课下专门练过考试要求功法动作。2️⃣因为本人经常健身体质不错，体测数据还可以。
INSERT INTO "reviews" VALUES('6672ba12f504e025e772bc59',1186,40,'说给分低的可能是以前的情况吧，这学期我加分只有1分，平时作业也都是糊弄的，最后平时分还有54。而且老师人很温柔，课上也很水，事情跟大一的老师比也不算多了，平时也没做很多事。如果选不到大热门的老师选胡老师也不错。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6672a8c99c24444b44fb7052',3990,294,'巨巨巨好的一位老师，平时分只要不缺勤都挺好，的，我和我朋友都50+，回答问题还有笔记都会加分，想要平时分，上课回答还有笔记分都很好拿。而且作业布置的也没有很多，和其他视听说班基本一样的，而且老师讲课方式，口语还有老师本人都巨巨巨巨好！之前盲选的老师，超爱Liya老师！',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('6672a6b431e27e7bf6c7a652',887,23,'必须满分，讲的太好了，神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6672a63618c83b50b942bf1a',377,377,'水课老师自己心里没点b数，熊天帝，上课不让玩手机还一直点别人回答问题，回答不出来还他妈扣分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6672a5d2981d7d6fee539cab',344,803,'耐心细致，愿意认识每一个人，讲的特别好，但是上课要求高，不让玩手机，依旧满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6672a58eeacc9e05f09097b5',1538,1073,'这个年头一笔一划在黑板上写的好老师还有多少啊😭不念PPT讲的非常好，人很和蔼，一个学期点一次名左右，必须满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6672a33a9c24444b44fb53eb',268,181,'垃圾，史',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66729ed818c83b50b94297f0',1568,4347,'贼垃圾，事多还容易挂',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66729dcc9c24444b44fb38ca',101,114,'偶尔要点名，必交作业，分高，教的好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66729dcaac273541e29600df',83,83,'神中神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66729d421486d01f97bcaee3',2210,114,'老师人挺好的，问他问题都会耐心解答，期末还会给复习资料，就是表达能力稍微欠缺，可以冲，当然首选何莎。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('667295a918c83b50b9426001',344,1111,'很好的老师，选到就是赚到，真的能学到东西，很有亲和力的一位老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66729532cfad27515bb5888f',1503,2924,'如果你想被收手机并且强制上一个毫无美学意义的课，并且想自掏腰包去打印几十页的PPT（必须彩印！！！），这会是一个不错的选择',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66729468f504e025e771f174',2674,2674,'孩子们，快跑……会变不幸',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6672917d9c24444b44faf30e',1021,228,'每节课点名，上课不让看手机',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('66728633f504e025e771a0e6',162,419,'挺恶心的，喜欢折磨人',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667285ea31e27e7bf6c6df1c',1171,5850,'依托答辩我只能说，挺恶心的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667285bbcfad27515bb52f9a',100,833,'非常有耐心，非常温柔，教的也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667285371486d01f97bc1f5f',876,52,'比较好的老师，但是建议自学',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66727cb99c24444b44fa7f90',2169,5249,'老师虽然人很好，但是给分是真的低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('667275d5ec868851010f59c7',5392,5854,'老师特别特别好，上课不死板，平时分给分很高，很愿意帮助同学，找他当指导老师也很负责，很好很好很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667267e1eacc9e05f08f4f01',890,619,'好好好巨好，之前优选班搜的时候发现没人给她评价还很害怕，上完课才发现，嘻嘻平时分拉满，上课很好水，只用组个小组，每组每人回答一次问题就OK了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66723e5bf504e025e7703407',315,40,'老师英语水平没的说，但是上课会掺杂哲学，也会锻炼口语，对于应试英语基本没帮助，适合想接触哲学的，听说期末回捞，不过好像她本来给分就低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6672393aec868851010dfd14',3038,228,'最后一节课还要上课，每节上课都要写题，半期考试全是简答题还只给一节课写，期末提纲发两个也不说考哪个，你藏着掖着是怕大家考得太好是吧？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66718c2affead844f1b821d0',3370,228,'人好很温和，水平也很高，讲课不死板，不是全念ppt，就是平时测试有点多，虽然是开卷，给分还可以，不会特别低，具体也要自己挣，偶尔点名，而且是随机点几个',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66718a43907b106e1ea15ecd',953,953,'课上的要求不算太过分，平时分给的真的很高，我都没举手回答过，期末平时分给了96',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6671880a907b106e1ea15281',540,540,'神中神，讲课仔细回答问题耐心，分数还给的高，所有老师中最强的那一个没有之一',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('667175c5b32fe80e3f7c1aff',986,986,'老师人超好，我哭死，真的，特别温柔，你就选吧，绝对不后悔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66716d84ffead844f1b78f7f',362,27,'给分低，作业多，点名',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66716d02ffead844f1b78d82',362,28,'巨烂无比，上课点名，事儿巨多，讲的还烂，作业还多',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66716c11b32fe80e3f7beeaf',23,23,'老师真的很好😘老师人美心善，讲课生动，不愧为交大最好的老师之一🥰好喜欢好喜欢！有急事请假页完全没有问题，超级贴心的一个老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66715fcc4c228f277cfed57e',221,36,'我是史学家，我只能说这旧世史，上课回答问题说不出来就算上次旷课，天天说为我们的分数担心，说我们考不好他也很焦虑，就这样子怎么能够让我们考好',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66714eb4b32fe80e3f7b506f',1381,517,'大三了，选游泳想体验一下或者学会游泳。结果大三上就上了四节室外游泳池，冷的要死，啥也没学会。大三下恒温游泳池开了之后，又得从头开始学。我的感觉是，根本没怎么教，老师专业素养很高，但是不适合怕水的人选课。怕水的人千万别选，千万！！！期末不放水，水性不好的坐等挂科。大学三年最尽力的一门课，自费游了五六次也没学会，只能说自己太菜了。😭😭',2,4,1,7,0,0);
INSERT INTO "reviews" VALUES('66714deab32fe80e3f7b4c64',247,28,'事多分少，五星分期给',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667137af6d0641565bf753ac',2525,565,'事情特别多 平时还什么不让玩手机 不准手机出现在桌面上 不然就没收 建模课期末还要答辩 答辩的时候一点计划都没有在浪费时间  她还咄咄逼人问个不停  问一些莫名其妙的问题',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6671367eb32fe80e3f7ac899',2525,565,'超级差评，事特别多，期末还要答辩，明明没教到什么，但是自我感觉良好，觉得我们应该全部都会了，都避雷吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66711d16ac7d473fc9c6ce77',40,40,'平时分太低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('6670f4c11c60eb3de8ce4ed5',1273,157,'真的有点难绷，平时事比谁都多，最后给分比谁都低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66703b844c228f277cfa79f4',961,762,'答疑周还要给你整一次考试，其他班老师都说了回归分析不考还硬出题让你来练，期中是不捞的，作业是非常多的，分数是极低的，希望后来人别选她了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6670377f907b106e1e9c3c76',23,23,'老师很认真，耐心，对学生细致入微的关心， 是我最喜欢的老师！！yyds！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66703682bd8b97410c97a387',252,114,'快run！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('667009b7ac7d473fc9c240c6',314,314,'畜生
INSERT INTO "reviews" VALUES('667004c94c228f277cf96625',887,23,'老师专业能力强 讲解耐心 跟着就能学得很好 给分也很高  期末还会给机会补作业 选吧 一选一个满意',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('666fd7bc6d0641565bf08994',3550,1551,'杀迪奥一个',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('666fa7d1ac7d473fc9c03033',5662,5662,'评分代表态度',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('666f9e135cf7132b0003e4c3',252,114,'教学水平不行 上课是川普 普通话考试都没过怎么当的大学老师 每学期课堂上弄小测 给的分很少 平时分给的很低 很拉绩点 保研的慎选 等着被捞的也慎选 因为这个老头很古板 作业布置的也不合理 经常前一天晚上通知第二天收作业 很离谱 避雷吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('666f222c83045102809f145c',1058,26,'老师很有耐心，平时分给得很高，上课认真负责，为人也很和蔼，从上小学以来见过的所有老师里面能排的上号的好老师',5,5,5,15,0,0);
