INSERT INTO "reviews" VALUES('666825795cf7132b00e2b3a7',6,619,'来更新一下李老师的最新评价，先说重点平时分49/50。李老师以前的话可能确实比较严厉什么的，但是他可能自己也意识到了自己的问题有改进。平时分由三个部分组成:考勤、大作业、发言。考勤考了3次只要来了这一部分满分。大作业满分20分，李老师特别好他说他给的99%分数都是在15+，我本人用gpt加自己润色，19/20。发言很简单，联系教材内容和热点上台讲4分钟左右(念一下稿子)即可，只需要发言一次，这一块满分，且李老师会在学期末专门给3节整课给大家发言，所以不用焦虑。综上只要你完成最基本的要求你这门课在李老师这里就可以拿满。大家冲冲冲！',5,5,5,15,0,0);
