INSERT INTO "reviews" VALUES('6659685d907b106e1e350caf',1554,1554,'依托√10，我就这么说吧，你就算闭着眼睛选一个都比这货好，能跑赶紧跑，过来人的经验，千万别不信邪或者有侥幸心理，我只能说这么多了',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('6659385d5cf7132b009de6d9',1066,1066,'这届开始不定期点名+半期考试 试卷全是助教改的 给分巨低 作业特别特别特别多，一次十页写死你的那种 周末还开习题课也是助教讲 啥也不会还讲 选另一个老师吧求求你们了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('665933565cf7132b009dc598',48,48,'赶紧逃！想要高分的逃！喜欢正常老师的逃！不想被骂的逃！课程难度大，除非是打羽毛球打的很好的大佬，你来她的班你可能能拿个80+。其他一般的人来分很低，她要求多，事多，态度差。妥妥一个更年期莫名其妙的妇女，上课迟到一分钟扣分，请事假扣分，干啥都扣分，说“女生夏天穿的太清凉会影响男生打球，所以不能穿”媚男怪。教学能力没有，态度差，自己说线上不回答问题，线下你去问她她又很凶会很大声地吼你，且不会解决你的问题。大一太极她不会打，大二跳绳她不教，两年羽毛球她正视授课时间不超过半小时，一般都是让你的小组长教你，分组也全是随机，你的组长是认真负责还是水货全看命。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('6659323a4c228f277c8f56e8',3370,228,'今天老师课上说会看活水🤣🤣🤣其实挺不错的捏，给个好评',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66585c8e4c228f277c8c1d6d',209,209,'厌男，媚女，顶级双标怪，娘了巴🐔的二逼，就该被 5，6 个体育生狠狠的鞭挞，秃头 顶级的油腻大叔标准，出生行为不断，我真想知道谁他妈把它研究出来的，能不能给他爆破了，喜欢赶人，就该像秦始皇墓，找一些当代小仙女，他赶进实验室 活埋地下，就永远的呆在那儿，真希望有一天实验室爆炸，让它真正成为实验室的光',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('665859828304510280328784',572,572,'上课来了先看五分钟电脑，然后挨个收作业点评，ppt可读性做的不好就关灯，完全不考虑你要看书，上课也不讲教材内容，经常跑题开始吹水，因为选的人少经常下来拷打。课设做的很早，多次检查修改。作业挺多，而且要求讲的很不清楚，快期末考了发一个全英文英制单位设计书让你看着建模，人都麻了
INSERT INTO "reviews" VALUES('665855515cf7132b009a98c2',209,209,'sg',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('66585473907b106e1e2ff6e8',209,209,'真的这家伙真人事一点不干，故意刁难人不说，动不动就说这个时间不验收了给你赶走，你倒是安静了，多少人等了两个多小时，你的时间是时间，学生的时间就不是时间了？',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('665850484c228f277c8bd467',2005,1697,'不想说什么了，高中没选化学，有机化学将成为我大学成绩中永远的污点，可能是我自己的问题吧🫶🏻',3,3,3,9,0,0);
