INSERT INTO "reviews" VALUES('6657986b83045102802f197c',5977,143,'这位老师说句难听话有点德不配位，自己班的学生怎样都好，其他班学生全是问题。三伏天不允许穿短裤，不知道是我个人接受能力差还是这位真的离谱，只能说仁者见仁吧，总之本科经历最后悔的就是选了这位老师的课，如果各位想要体验下夏季汗流浃背的话可以选这位的课',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6657968a5cf7132b00972bd6',1273,157,'离谱中的离谱，就没见过这么离谱的老师，千万别选，本人大学期间最后悔的一门体育课没有之一',3,4,2,9,0,0);
INSERT INTO "reviews" VALUES('6656a73fb32fe80e3f0519f5',5979,4427,'喜欢周末和同学们在8号教学楼研学😍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('66568ded6d0641565b7e2155',1273,157,'真抽象啊，第二次了，下雨非要喊去集合一下然后说句下周跳绳考试就解散，不会打字？',3,1,1,5,0,0);
