INSERT INTO "reviews" VALUES('665526afffead844f1378a2e',87,87,'真的是非常非常好的老师，有自己独特的教育理念，希望你通过踢足球来增强体魄，玩得开心。很有人情味（经常嘴硬心软哈哈哈）总之就是喜欢足球的报马老师的课绝对不亏，对足球不那么感兴趣也能轻松愉快',5,5,5,15,0,0);
