INSERT INTO "reviews" VALUES('6653f83b4c228f277c7a18a9',1330,1330,'上课讲个东西讲着讲着就说她不知道，她没接触过，就只会念ppt，考试也不考课内的。',1,2,2,5,1,0);
INSERT INTO "reviews" VALUES('66503dc2907b106e1e0d38b0',3479,526,'必须锐评一下，确实还行，课上经常讲笑话，这节课点不点名会在群里提前通知，但不知道是不是老师安排问题，作业时间很，非常，十分紧张，基本一周一交，cad就算了，能copy一下，手工大图不管什么样的，都是一周一交，有些班其实不到一周，他要求六天就交，学委还提前一天收，其实五天左右就交了，后边还不允许补交，同样的大图别的老师给两三周都行，要是一周交了就加分，他要是补交直接零分，必须一周交，碰见课多的学期，调休多的学期，以及考试的周末，天天熬夜画，还得写别的科作业，还得复习，你就完了，知道吗，牢底！！！！！',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('664f5ec86d0641565b62471d',1536,1536,'快跑！讲课水平一般还特别自以为是，非常小心眼',2,2,1,5,1,0);
