INSERT INTO "reviews" VALUES('664ed5721c60eb3de8380d34',209,209,'我超市你的吗。老字又不是学电气的，讲一大堆没什么用的东西，还要搞得人模沟阳的。忙了半天什么也没学好，跟猴子摘桃一样。软件培训PPT也不给，上课一副表情也是很复杂，态度恶劣，给分还低，没把自己定位搞清楚。',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('664e899cac7d473fc92aad60',476,779,'本来以为他是歧视女生，因为diss人的时候会强调“我一个女学生”，后面发现他是歧视所有人🤣，默认土木都是男的不强调罢了，同事也diss，上课先拉踩其他老师，感觉全交大除了他没好老师。实测是要自己画表格的，作业是六面A4纸抄题的，基本不点名你上课可以不来但是不能出声',2,3,2,7,0,0);
