INSERT INTO "reviews" VALUES('664da3748304510280052f1e',2895,92,'普通话是不会说的 断句是一字一字的 专业水平是没有的 折磨学生是有一套的 选到他的课是倒霉的 听他讲话是到胃口的 本来挺难的一门课 偏偏碰到这么个倒胃口的老师 谁选到谁知道',1,1,1,3,0,0);
