INSERT INTO "reviews" VALUES('664a99446e387f08d7436826',6006,2570,'表达能力极差，上课“呃、啊、内个”极其多，照着PPT念，一点互动交流没有，至于专业水平，感觉他像意识流讲法，想到哪讲到哪，不知所云，总之极其差！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('664a1e7a0b74d82a76b90f01',819,228,'布置读书笔记快要交了才发模板？早干嘛去了？模板上还追加一堆要求。竞标不能恶意低价，她却就可以追加要求。又半期考试又大作业又读书笔记的，没见过那个政治课老师这么多P事。上课还不让看手机了（说是教学检查周），我™能去就已经给足你面子了。唯一真史',1,1,1,3,0,0);
