INSERT INTO "reviews" VALUES('66485ac2ae533a7a60560c72',1685,6012,'期末总成绩出问题沟通完全无效，只讲TA认为正确的；上课一边强调时间紧任务重一边滔滔不绝占用练习时间；对待助教老师态度差；管的比我中学班主任还多。',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6646ca950b74d82a76ab330f',1274,36,'很一般，根本不下课，还老是互动，说自己的事，也不是不点名，来人少了就点，还威胁说点到没到的绝对成绩60多',3,3,3,9,0,0);
