INSERT INTO "reviews" VALUES('6646c20bdcb6297b73235592',869,3704,'25的选汽车的小登，我知道你们想找什么，老卢是这样的，人其实挺幽默的，但爱狗叫，这课其实很水，只要你期末看了三天，八十不是问题，会给重点，信我这课你只需要知道集成刚度和钢架桁架，但上课基本可以等于不听（byd什么d算子之类的根本听不懂），但是大作业一定要写尤其是仿真，不然纯粹是找削，第一次作业让你手写16*16矩阵那是真绷不住，但我还是要说，老卢其实并不是很抽象，他只是单纯的幽默过头了，给分其实真不低，期中都是送分的，当作业布置的',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6645f8744abe701c1c9d8e98',4510,5559,'就了解一点哲学的人来讲，这个老师水平是可以的，她有科哲背景。作为哲学的通识课，不是哲学史的通识课，它更讲求思辨性，所以小组汇报必然要求是严苛的，逻辑的，论证的，有主见的，哪怕是辩证的亦或者是形而上的诡辩的，而非形式的宣讲哲学史教材，哲学史的知识都是无用的知识，剩下的东西——进行哲学的精神活动和独立思考以及批判性思维的能力，才是有用的。',5,4,1,10,0,0);
INSERT INTO "reviews" VALUES('6645afc6e2d3272cc905bffe',230,230,'大傻逼，避雷。行策下课时间问题做作业怎么你了，跑过来说我不尊重他，上课没拿出来做还不够尊重你？',1,1,1,3,0,0);
