INSERT INTO "reviews" VALUES('663af0c02f558907a158326d',427,427,'专业能力肯定有，但平常p事多，又让人摸不着头脑；上课讲的很乱，没得章法，只让你去读专著，PPT还行；三个班的课，半个班的人，大水课。行事风格真的像个艺术家，不适合当老师。',4,1,2,7,0,0);
