INSERT INTO "reviews" VALUES('663ac375ae533a7a60180aa4',696,723,'我想打零分的，第一条评价说的没错“一生致力于恶心学生”，上课吐字不清楚，全程糊一嘴，上课屁事一堆，一点小事能给你掰扯十分钟，点个名也要整很长时间。向他提问，他要我们发群里，然后全是助教来回答，我严重怀疑他啥也不会，这种人是怎么招进来的？',1,1,1,3,0,0);
