INSERT INTO "reviews" VALUES('662f4aea4828413557ff9bd7',3628,3628,'大一就碰到的普通生物学顶级老师！超级和蔼啦，对每个同学都很好，而且很有耐心，问了一些很蠢的问题也不会被冷嘲热讽><很喜欢上罗老师的实验课，不会有很大压力，操作有失误也不会批评，做不好的话老师会来帮忙，还直接上手帮同学拍过鱼hhh。课也很好很专业！给分挺不错的，上课就是扫码签到也不会点人回答问题，还是比较舒服的。大一最喜欢的老师！',5,5,5,15,0,0);
