INSERT INTO "reviews" VALUES('6628bc7edcb6297b73a261cc',6087,6087,'选通信原理是我大二最荒唐的决定，如果自学能力强的当我没说，老师不会讲课，声音小跟念经似的让人昏昏欲睡，念个ppt都不念不明白，要是指望课上听懂她讲的，我承认他理解能力远超于常人。真搞不懂一个交通工程学这种学科，要想学还得需要复变函数知识，往前没基础，往后用不到，真搞不懂为啥找这种老师上这种抽象的课。确实是开卷，开心吧，书上没有，ppt上有，开心吧，不给你，乐子学科，除非你真感兴趣，不然还是跑到工程地质吧（想保研的慎选通信原理，给分巨低）',1,1,1,3,0,0);
