INSERT INTO "reviews" VALUES('66263240e2a31527b7d1ef01',2169,3740,'老师上课英文PPT，讲话逻辑不清，胡说八道，想好好听你都没办法，水平真的差。完全可以都不去，课件看见你走了都不管，期末重点一大堆，全背了也就80多分，真的无语😓',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('6625d4f5e5e5a426f7fbf5ef',344,344,'英雷为什么是神！讲的很好，深入透彻详细，课堂挺有趣的，也很乐意跟学生交流，但上课不能玩手机，老师很认真负责，不是水课别想着水，英雷哥哥整活还是有一手的😋',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6625c3dbe2a31527b7ceaf3e',1171,27,'我真服了，讨大吃货，每天上课隔那pua，什么你baba，mama（重庆话就这个发音）从村里把你供出来不容易，你不好好学，不是你怎么知道我们家就是农村的，上个课还搞个农村的喝稀饭，喝不上燕麦粥，城市的才喝粥，怎么这都21世纪了你是穿越了？，大男子主义的要死，你baba是城里人，你mama是村里出来的，你就又知道了？还我妈不舍得穿好吃好，嫁给我爸才过上好生活，在家没有话语权，你咋又知道了？咋的，我看你家就是这样吧，才这么想所有人，上次上个课拿书打人，这次上课把你那个爪子按人头上拧人脑袋，抽烟抽的我离你两米都能闻见，搁楼道吐痰，咋的骂我们不尊重你你就尊重人家保洁了？',1,1,1,3,0,0);
