INSERT INTO "reviews" VALUES('65f1097ba668a42bc81c3b3a',604,2035,'老师对于教学特别认真，对于签到点名极其严格，近乎于不近人情，不接受纸条式的请假，必须办齐请假手续，否则就记旷课，似乎没有迟到和早退，全算旷课。教学很多搬运视频不过讲课认真，稍有口音。上课手机需要上交，不能玩手机抓到就寄。绝对不算水课，信我，其他评论全有问题→_→',5,4,2,11,5,9);
