INSERT INTO "reviews" VALUES('65e146d2fb1b6b6192828bbb',489,3664,'讲课表达能力一般，但是人还是很好的，热情接待问问题的同学，课下去和她讨论问题可以解释很清楚。平时分按照要求做的话，会给的很高，也有写笔记的加分项目，加分甚至可以把平时分拉满。之前看到那么多差评，还有点害怕，不过上了她一学期的课，感觉整体还是OK的。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('65e145b4436cc7685bbf6d28',2169,394,'上课不知所云，你想好好听，都听不下去。课间休息可以随便走，看见也不会管，期末重点特别多，背完了也给分贼低。',3,3,3,9,1,0);
