INSERT INTO "reviews" VALUES('65dd6118436cc7685ba585ef',4482,157,'******上课和播放器一样，多说一句都累着他。上课啥都不教，要求还很高。宽于律己，严以待人。给分超级低！而且还有暴力倾向，选他的课要注意安全',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('65dd54facaa7af401d0b40fb',2413,6356,'不点名，作业少且简单，上课基本不抽人。老师是属于中规中矩的类型，老师授课细致而富有逻辑，但是课堂并不生动，容易走神，适合上课喜欢摸鱼的同学选课。',4,4,4,12,0,1);
INSERT INTO "reviews" VALUES('65dd5320436cc7685ba52d19',733,335,'很不错的老师，但是诟病于这门课的繁琐程度，机械设计是真真正正需要看mooc才能拿高分的学科，老师每节课上课会有小测也是为了督促线上学习，线下课程仅仅只是起一个复习作用，如果线下才开学，就有点颠倒重要性了。老师的线下课程讲的还是比较细致，重点都有给出，也不局限于应试教育，会讲很多教学外的内容。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('65dd50e60b680859640af0ba',3754,156,'上过老师的课后，发现并没有其他平台上说的那么不堪，授课中规中矩，教学逻辑比较清晰，教学中会给出题型具体分析，考点也划分得很具体，但是平时成绩给的不高。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('65dd4e45436cc7685ba4c66d',730,143,'非常非常优秀的老师，无论是表达能力，还是教学逻辑都可圈可点，老师授课擅长化繁为简，并且是大学教师中为数不多用板书授课的老师，教学水平很高，很有人格魅力。',5,5,5,15,0,0);
