INSERT INTO "reviews" VALUES('65dcd5ed3bac4307f75829d8',6363,80,'快跑快跑，这老师给分超级低******，认认真真学一学期，平时分就给70，*******赶紧润',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65dca92f436cc7685ba112b0',2654,40,'之前听说给分高选的，但是好像课程改革了以后所有这个课的课程作业和评分标准都统一了，严格按照作业质量打分，而且平时作业是助教打分，不会随便就得高分了。抛开分数老师人很好，讲课也很好。',4,4,4,12,2,0);
