INSERT INTO "reviews" VALUES('65dc7468df6fff7d5ef1e0cb',1128,611,'五次缺勤平时分五十八🥰🥰🥰🥵🥵🥵想嗦嗦锐锐的大光头🥵🥵到底是谁再给我的小锐锐差评了😡😡😡纯纯尬黑✊😡👊',5,4,5,14,10,1);
INSERT INTO "reviews" VALUES('65dc327b53ec9335b7ae4e33',788,40,'******快跑别选，平时分给的超低，补考英语一共13个人，李娟班上的占一半，其他老师的平均只有两个人。',1,1,1,3,0,0);
