INSERT INTO "reviews" VALUES('65dbff087d5eb67d3b4b7789',2923,6371,'感觉是自己懂得很多但是表达不出来，讲课能力不行但十分友善，问问题都会解答而且给分完全不用担心。',4,4,5,13,0,0);
