INSERT INTO "reviews" VALUES('65dbfd37caa7af401d02971e',551,551,'有0分给0分了。讲课讲的稀里糊涂，ppt也做得晦涩难懂。考试不用年级上的题自己出题，出得来题目都读不懂我感觉是我语文有问题。给分奇低，期末考完试两天就改出来分数然后立马解散qq群。就没见过这么不负责任的老师。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65dbee29fb1b6b61925f1426',3727,1904,'老师很好，挺好讲话，但不适合完全的摆哥。期末基本都考题库里面的题，选择题复习两天就能拿下，大题只要你答到几个关键点就能给不少分，因为我如果按标准给分我估分只有六七十，但期末88属实爽到考前突击的我了😋😋。语言表达有点含糊随意确实难受，但就如前面所说这并不影响你背题库，平时分除了工材实验平时20分确实不知道按什么标准给，其他的就两三次作业+两三次课堂练习+我们这届有一个类似调查任意一种工程材料的报告交满，我是基本给满了，看以前学长评的很低的就不清楚什么原因了',5,4,5,14,1,1);
