INSERT INTO "reviews" VALUES('65b3d17cabbc4a43a3de536c',532,141,'怎么说呢，这很难评价，慎重考虑，非常喜欢阴阳学生，打压学生，找存在感，自以为是，感觉自己高人一等，实际上什么水平都没有，讲课稀烂，建议能跑就跑，已经不是课的问题，而是人品问题了，总而言之，无德无才之人。ps：熟悉此人的同学都知道其内心险恶，心胸狭窄，远超龙哥，毕竟龙哥还是有水平的。',1,1,1,3,6,0);
