INSERT INTO "reviews" VALUES('65addbca80417d46953a3c3f',888,779,'别选，其他班都没有期中考只有他非要喊我们来考，上课口齿不清啥也听不见，像是嘴巴里含了什么东西一样。做实验也是，什么都不讲就喊你做，做不出来还要骂你。最后就是期末绝对不捞人，不知道******，遇到赶快跑吧',1,1,1,3,8,6);
