INSERT INTO "reviews" VALUES('65ad191feaa8971035e326b6',4695,2812,'很幽默的老师，每学期只有第一周点一次名（来不来都无所谓），后面人再少都不会点名。老师的课（尤其是数据结构）是真难听懂，作业难度不低基本靠自学，不过老师会发模范作业可以照猫画虎，只要完成了他的作业，无论质量如何（但最好别直接copy），都不会挂人。另外，老师的平时分是按作业平均分给的，大都在A等（85），完成质量高可得A+（95）',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('65acfbe4eaa8971035e1bbb0',948,22,'神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65acd915eaa8971035e05956',4247,1007,'总体老师很有意思，上课比较轻松压力不大，期中只用写一篇期中论文，平均分都是92。三连讲提前下课，会在考试前提示重点，好好好！但为了应付考试自己还是要多刷网课和题',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('65aca1a5eaa8971035dd05c1',5739,5739,'市场营销课，钟老师上课非常有趣，很多例子，旁征博引。没有作业，期末五百字总结。划重点，平时分拉满，卷面捞人。有钟老师的课必选！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65abbb1080417d4695232061',393,96,'不说啥了，选彭皓就完了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65abbaa7eaa8971035d56595',1441,228,'老师挺好的，只要你节节课不缺席平时分肯定不会差的，而且免考名额给的很多，想要的可以冲（反正我没冲）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65abba0459abf37a4dcb2930',652,198,'没啥好说的，******平时分给的低，上课经常小测，总摆出自己很牛的样子。顺便吐槽一下，计院为啥要开这门**课程',1,1,1,3,0,0);
