INSERT INTO "reviews" VALUES('65ab200459abf37a4dc237ef',861,861,'******两个班期中出的卷子不一样，一个班超纲题多助教说不用做，结果******直接算你没写扣分，一个班题贼简单随便写写就得分，赶在最后一天出成绩，别人问就装死',1,1,4,6,3,0);
INSERT INTO "reviews" VALUES('65ab153e011c097af259744a',1801,543,'老师课讲的不错，平时分正常，不高不低，偶尔有一点点毒舌。总体来说还是可以的',5,5,5,15,0,1);
