INSERT INTO "reviews" VALUES('65aac8b580417d469518db42',6131,3563,'道理是讲不完的；
INSERT INTO "reviews" VALUES('65aac65080417d469518d30b',489,3664,'老师还是不错的 平时分还是比较高的（你按照她的要求来 作业不抄[得太离谱] 也有加分项目 按时到）真心不错 不知道为什么评分低
INSERT INTO "reviews" VALUES('65aab4548b113c0cc6120012',3038,228,'建议Run，不到教务网关闭的时候不出成绩，会比其他正常的马原老师晚出3到4天成绩，除了免考的平时分会到90，不免考的平时分就88左右，平时上课有五次小测，还有期中，写的挺多，其他马原老师都告诉只考第一个提纲，第二个提纲是补考的范围，她发两个提纲还要让我们都要看，迷惑同学。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65aab1ba8b113c0cc611f37f',6419,6419,'上课五分钟，吹牛皮两小时。半期考试发群里自己课后做，课设改改颜色排序交了就是满分，期末还会给你讲考点，期末考试给分也很宽松，没啥压力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65aab10959abf37a4dbf7cf9',6420,80,'平时分留着过年是吧给七十几分😅一口一个我给分不会低结果一寝室七十几 本来课就难天天搁这点名课堂测验是怕我们过吗🤣只能说除非你有足够自信可以把混凝土学好，否则尽量别选这个老师，不然大抵是过不了一个好年的',1,1,4,6,2,0);
INSERT INTO "reviews" VALUES('65aab00680417d4695188094',855,140,'刀子嘴豆腐心，蔡哥平时可能烦了点，期末给分是一点不吝啬',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65aaae549e94c36bb302d418',6420,80,'这种又难******的课再遇到这种老师压力挺大的。跟个老仙女一样，喜欢刁难学生，一学期不知道重申了多少回她不会捞人。讲过的东西不会再讲你QQ上问她也是不会鸟你的。对男生要求很严格，抽问问的问题很难回答而且不给你几秒钟思考时间。平时作业稍微有点错都是B。课设别个班都是打印电子报告她要让手写。感觉不太想让学生过这门课。不过好歹课件做的不错，平时分不算低，期末成绩也没有为难我，就不打差评了',4,4,1,9,0,0);
INSERT INTO "reviews" VALUES('65aaaaa7eaa8971035ca08f1',1919,543,'讲课挺好，作业挺多，半期挺难，平时分挺满，期末没压力',5,5,5,15,0,0);
