INSERT INTO "reviews" VALUES('65aaa4678b113c0cc6119af8',2598,2598,'神中神 平时直接拉满',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65aa9c9880417d469517dccf',7,7,'我大物ΙΙ选的他，冲就完了！平时分拉满（ps大物ΙΙ满分）',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('65aa9a4759abf37a4dbebedc',3038,228,'跑！首先期末出分巨慢！得拖一个多星期才出成绩。其次平时分巨低！几乎不可能上90。四次随堂测试，我坐了两次前面（前面有加分），PPT做的也还行，平时分都才88。除了免考的基本平时分上不了90。',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('65aa6b438b113c0cc60eae3d',775,1017,'正常请假的打低分，逃课没被他发现的正常打高分，说话像吃了黏黏胶一样，科研水平也极差******',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('65aa449e59abf37a4dbb186b',703,228,'老师，以前听其他人的点评对你没有好感是我的错，98的平时分你是我心中的神，室友也是98，绝对是所有马克思老师里给得最高的，无脑冲(*´I`*)   （附:本人上课仅回答过一次问题，课上也很摆）',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('65aa17e2eaa8971035c38e54',1005,73,'平时分低，上个课时不时就发电捏😅',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('65aa0ccb80417d469511933a',450,450,'胃达，无需多盐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65aa090259abf37a4db88caf',6434,73,'朝令夕改，提前半个小时跟你说之前从未提过的作业要截止。上课随意东拉西扯，不会跟你完整系统地讲课，也不会告诉你考试考什么，也不会给你系统复习，自己说过什么完全不记得，明明13 14周就讲完了课还是要另找时间补课，这也就算了，补课第一次迟到半个小时，第二次找理由取消，第三次直接不找理由就不来了，而且很喜欢讲笑话，说他自己和斯坦福哈佛的教授水平都是差不多的，这估计是我这辈子听过最好笑的笑话了，你真那么牛逼你在这当讲师？先混个教授吧。总之谁选谁倒霉',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65aa07e480417d469511129e',6131,3563,'不予评价',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('65a9f6669e94c36bb3fb207a',1983,1983,'抽人回答问题然后无端把别人骂一顿或者直接赶出教室，恐吓同学说要给他退课或者不准参加考试😅这学期被抽过的同学态度都是端正的，至少都回答出了内容，他反正都要骂，合着别人只是撞上你心情不好的时候了😅上他的课梦回1864年上早朝的时光，稍有不对就是杀头
INSERT INTO "reviews" VALUES('65a9e902eaa8971035c1b240',3552,535,'你这考试给分是真低啊',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('65a9e1b080417d46950f6543',2984,361,'期末考也去了，点到只有一次没去，总评给20分，刷新交大下限了吧😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a9cd4d8b113c0cc607d7eb',56,56,'无误，上他的体育感觉是种折磨',1,1,1,3,2,3);
INSERT INTO "reviews" VALUES('65a9cc6a9e94c36bb3f90d55',849,619,'上课的时候可以写作业也可以看课件做笔记，期末会检查笔记，笔记全程做完平时分不会低，我平时有99，如果写了笔记分还低可能就是半期大作业写的太糟糕或者笔记不是按老师课件写的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a9bc54eaa8971035bee3c2',2078,2815,'很负责的老师，教的很好，就算你是个摆子也能学到东西。就是作业有点偏多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a959ec9e94c36bb3f553ee',1087,1087,'选就对了。绝对实力担当，讲课逻辑清晰，行云流水！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('65a93e3780417d46950915b5',1513,1513,'期末论文只要不是自己写 直接认定你大篇幅Ai给分巨低 真的逆天老师 还以为这课给分多高',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65a92f7b011c097af247ead4',271,5,'平时分拉满，讲得特别特别特别特别特别好，也会捞人',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a91506eaa8971035b96cdc',849,619,'你的专业水平我是认可的，或者说我感觉思政课老师上课水平都不差，但是你这给分也太牛马了，写了那么多笔记，最后平时分和其他老师比起来算低，那你这写笔记的意义是啥，然后想查下期末卷子的大题情况，为何要反问我怎么去查，我要是有这能力的话我犯得着去低下头去求你？',5,2,1,8,0,0);
INSERT INTO "reviews" VALUES('65a9068d80417d469505cb38',6446,496,'会在群里提前一天提醒交作业，签到挺多的，用慕课签。课程设计有两个报告（这个老师），还有慕课测验（所有班一样），这个事情挺多的。半期考试发下来做，占5分。有期末复习课。讲课的话也还行，声音算清楚，但是讲课思路不太清楚。给分一般，怎么课堂表现都不给满呢（全勤）……期末考试比想象中难一些，题型跟平时不太一样。',3,4,4,11,0,0);
INSERT INTO "reviews" VALUES('65a9021d59abf37a4dae2b42',34,34,'上的数据结构和实验。教学水平一般，只会念PPT，曾经有一次用Word写了下代码给我笑死。每节课都要雨课堂扫码签到，作业是清览，挺多，而且清览属实阴间。然后实验的任务要求没有任何规范，作业交了不管就算了，期末跟你说助教给高了，至于啥问题咱也不知道，你就压呗。不过客观来说别人不知道我给的都还是90以上的，期中考成绩好像都加了分，实验课的成绩全部扣5分，反正是挺阴间的。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65a8dc6e80417d469503ad8a',489,573,'讲课生动 有激情 平时分只要你按要求做了 给的是真的高（本人平时分满分）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a8d70580417d4695035ecb',3582,3582,'大一上个导论课，最后答辩的时候根本不耐烦你在讲什么，我最后花了很久准备，只给了个72分，无语了，真牛。',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('65a8d3cd59abf37a4dabced4',452,965,'郝静老师上课确实有点阴阳，但是在她的课上是真的可以学到很多东西，而且平时除了期中都给满了，期末考试给了大题的原题和类似的题目，前面选择也有几道原题',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('65a8c8518b113c0cc6fd488f',176,176,'哲学博士交复变，强中强啊，强中强啊
INSERT INTO "reviews" VALUES('65a89b03eaa8971035b35562',53,53,'乱给分，真是无语，感觉白学了他的非参....从来没给老师差评过，他是第一个。给学生极大的学习挫败感，不适合教这门课...',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('65a8936ad3a3253d03ceeb3c',1168,228,'老师太好了😭平时分给得很高，作业也非常轻松好水，期中考试开卷，交了就满分，平时上课讲得东西听一听也挺有意思的，马原最好的老师了👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a891e5d3a3253d03cedc92',706,706,'给分低（这课三七开平时分他也能给你打的低的离谱） 不划重点（人家说从来没有划重点的习惯。。） 老师人很傲慢总会居高临下 并且像初高中时期很烦人的班主任一样总会因为一些小事絮絮叨叨个没完…
INSERT INTO "reviews" VALUES('65a890ec731a1f600548cf2b',571,6,'我说厕所怎么这么堵，原来是被拉满了',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('65a890b4d3a3253d03ce9512',258,43,'人美心善',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a88f48731a1f600548bdcc',307,307,'平时分巨低',2,1,2,5,3,0);
INSERT INTO "reviews" VALUES('65a88ef990f1e64a727771c6',34,34,'事儿多，分低，教的差',1,1,2,4,2,0);
INSERT INTO "reviews" VALUES('65a88b712543857e58ec295e',960,228,'呃，没回答问题或者缺过勤 平时分就不可能高了。会划重点',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('65a8882f731a1f6005480b73',34,34,'上的是他的数据结构，******就不说了，PPT上把STL写成了ATL也照着念更是世纪名画。下面复制一段群聊原话：“ 因助教给你们打的实验成绩普遍偏高，我看了一下相关的报告，还存在不少的问题，因此所有报告都给减了5分。”。so？有问题不说，一直憋到出成绩的时候莫名奇妙给你扣5分？？还一视同仁扣五分？？认真写的和随便抄的都扣5分？？？？？',1,1,2,4,4,0);
INSERT INTO "reviews" VALUES('65a881967c6c3940169e87a6',100,100,'拉满，人美心善',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a880fb90f1e64a7275f532',278,228,'可冲',5,5,3,13,0,1);
INSERT INTO "reviews" VALUES('65a8137f731a1f6005439600',1753,2735,'何其有幸上过丁老师的高数课，外表英俊帅气，讲课非常易懂，板书非常漂亮，给分很高，会叫学生“小朋友”，结课了会深情地跟大家说“江湖再见”，赞同另一位朋友说的“理科人士独有的浪漫”，非常charming！！！
INSERT INTO "reviews" VALUES('65a812a1731a1f6005439328',1756,52,'人美声甜给分高，回复消息及时，亲和力强，普通话非常标准，听她讲课是一种享受
INSERT INTO "reviews" VALUES('65a811b190f1e64a72737f80',831,762,'认真听还是可以的 平时分给满 点名较多
INSERT INTO "reviews" VALUES('65a8113809df0b3e0f2ef67d',769,1490,'全方位优秀的好老师，给分高，专业能力强，教学不像大学大部分老师的点到为止，会配合习题，深入浅出，行云流水，为人非常和蔼，妈妈型的老师，永远爱利姐！！！电分老师是她你就等着享福吧！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a810542543857e58e7d4a6',176,176,'1.课程轻松，除了半期平时分给满，上课从不点名，作业交到一定次数就是满分，且可以反复不限次数补交；
INSERT INTO "reviews" VALUES('65a8067709df0b3e0f2eafd6',10,10,'选就对了，一学期点名3次左右，其余全部学习通签到，还是不带定位不带拍照的。平时分直接拉满，人美心善，我感觉真的很漂亮，很有气质的一个老师，真的强推！！！！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a7f989731a1f600542bd43',176,176,'吹爆小张老师，他真的超级超级超级好 ！！！！可以说是最好的老师了，上课从来不点名，就算教室里一半的人都到齐都没点过名。 我一半点的课都翘了没去过，除去半期成绩 ，平时成绩只要交了作业全部拉满，而且可以期末无限补交作业，期末还捞人。我真的哭死，交大最爱的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a7f3f5d3a3253d03c8030b',1452,623,'******赶紧跑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65a7efb62543857e58e6b3de',706,706,'上课水，给分一般，不划重点，会挂人',3,3,2,8,1,0);
INSERT INTO "reviews" VALUES('65a7ef81d3a3253d03c7d451',706,706,'能看出来老师学识不错，但是平时分一年比一年低，真的很离谱，作业报告都交了也写了，水也没有特别水，最后平时分只有七十几，说经济统一不画重点，也不给拷ppt，真服了。。作业也比其他班多，讲课慢，其他班只有一个期中报告，他除了期中报告还有额外的课程报告，可能厉害的同学平时分得分高吧。普通同学不建议选，自己斟酌吧，专业课平时分低的老师都不推荐，哪怕是三七开也很离谱🤧他的班平时分是最低的',3,3,1,7,2,0);
INSERT INTO "reviews" VALUES('65a7ec4c7c6c39401699bddf',720,720,'混凝土您捞我一手，你就是我救命恩人呐，重修被迫选过来还被活水评价吓了一手',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a7e977731a1f60054219a0',176,176,'神中神，无敌好老师，上课不要求出勤，只要作业交够平时分全拉满，每次课后都有相应PPT总结，最后还会告诉考试重点，在群里会反复细心的提醒同学，私信问老师题也会耐心解答，总之无脑选，张老师我真的爱死你了！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a7e56d90f1e64a7271e500',705,705,'上课不讲一句废话，全程高能，PPT也做得很好很有体系，讲的分析方法也很好，这学期认真听课感觉收货挺大的
INSERT INTO "reviews" VALUES('65a7ca8309df0b3e0f2c0357',708,708,'老马真的好啊😭我哭死😭我的老马',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a7c6d090f1e64a72705fd3',975,975,'平时分拉满了，真爽，但是讲的不好，声音很小，槽点比优点多，不过适合我这种自学的人',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('65a7c63290f1e64a727059a5',6403,535,'假做阳间人，净做阴间事',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a7c58d7c6c39401697dff8',708,708,'马老师真挺好',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('65a7c525d3a3253d03c5d9a5',56,56,'对待自己喜欢和不喜欢的学生两幅嘴脸，大一大二非常后悔选了他的体育，被折磨了两年，每次上体育课前都很难受，让本来快乐的体育课变成了大一大二最恶心的课，别的班体育课都是快快乐乐的就结束了，上他的课要非常认真，比上专业课还累，最后武术总评给你来个动作不规范，最虽然大二学习狠狠努力了一年，但是因为体育，大二的奖学金也没评上，真的感谢有你，温暖了四季！😊',4,1,1,6,1,4);
INSERT INTO "reviews" VALUES('65a7b686d3a3253d03c532f7',691,228,'特别喜欢点名问问题，时不时就下来转两圈，还喜欢在最后下课前签到。课全勤，作业都做了还回答过问题平时分都只有80多',3,3,2,8,1,0);
INSERT INTO "reviews" VALUES('65a7b34f90f1e64a726f877e',1663,693,'电气学院最爱老师，一学期下来能记得班上人的名字，讲的特别好特别详细，人也非常温柔，我的神！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a7820cd3a3253d03c2aeb1',691,228,'老师课不水，但认真上课平时分不会低。没有期中考也没有小测，只有3次作业，2次纸质作业1次实践作业，纸质作业字写的多点、网上搜点基本满分。点名这学期一共点了3次。如果每节课都到，三次作业认真做不应付，上课回答几次问题平时分肯定不低。总结就是想水的快逃，想卷的就选。',5,5,5,15,3,5);
INSERT INTO "reviews" VALUES('65a77ae3731a1f60053c96fe',5808,2205,'给分高 不爱点名 作业少 半期考试开卷 唯一的不好就是期末重点不太详细
INSERT INTO "reviews" VALUES('65a774d2d3a3253d03c20ad9',637,694,'作业多，平时分巨少，自控里面给分最少的吧，选吧，一选一个不吱声',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a767c1731a1f60053bc570',2173,2173,'呃怎么说呢，运筹学平常不学最后抱佛脚的不要选，她要求期末要过50，否则平时分就会给你卡到最后折算为59，要求挺多的，听隔壁同学王坤就没这要求，那考个三四十分就能过',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('65a7661c09df0b3e0f26be43',691,228,'******马原平时分给我不及格，真有你的，还挂我马原，116人，3.6%的挂科率，谁马原老师还挂人？😓😓😓',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('65a75d8c2543857e58df9783',6488,2,'保证期末卷面考80＋的无脑冲！平时分不能保证卷面60的好兄弟能顺利通过考试。水课一门，本人每节课都到，作业按时交，平时分58。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a750fc2543857e58df0541',3680,80,'给人一种挂了学生更能体现他治学严谨，教学有方的感觉。',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('65a74e5309df0b3e0f258eb3',2170,6490,'人特别好，平时分给的也高，期末考试给分也高。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('65a74c422543857e58dece43',637,694,'只能说是非常好的老师。可能是我太菜了。平时分给80多分，什么意思啊？课堂表现给这么低。去别的老师那里不来上课都不止这个分，考90多，你他妈最后卡我绩点给89，我只能说人才老师好吧',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('65a74bad731a1f60053a7c92',2491,6492,'讲课没啥吸引力，期末不划重点，期末复习莫名其妙的，最后改的分还低。平时分给的还行',1,2,5,8,0,0);
INSERT INTO "reviews" VALUES('65a748407c6c394016920222',691,228,'基本每节课点名，上课随机抽人回答问题，敢一次不去真给你挂，马原老师中平时分最低之一，我的评价******',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('65a744ec731a1f60053a2ba6',6494,6494,'课上随便干什么。然后经常让你讨论，然后举手起来回答问题可以加分。分给比较一般。不能跟很多其他的老师比，他是真的要回答问题和课程论文要让助教评分，所以自然不可能给满。不能比不能比……',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('65a7442f7c6c39401691cf34',6495,322,'还可以，随便在课上做什么。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('65a737c47c6c3940169136d9',221,36,'老师没有人情味，扣分多，有口音，听不懂思密达。',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('65a6aa0509df0b3e0f20a771',6497,723,'没有作业不爱点名有课设给分一般',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('65a6a9d47c6c3940168dab6a',1252,18,'伟大，无需多言',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a6a78a731a1f6005358944',6499,1555,'平时分扣饱饱😋',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a6a48c7c6c3940168d785b',751,573,'老师很有个性，爱国，会给同学分享他的经历，课堂氛围好，给分也高，作业分abc三档但是拿c就算90分，而且大概率会给满，老师希望同学能从他那学到东西，也尽量不让这门课成为同学的负担，课下也认真负责，有问题都可以问，可以交流，非常推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a6a155d3a3253d03bb6b9f',1025,850,'老师比较严，也不太好说话，别的班期中开卷他不开，仿真作业会让你带电脑过来检查，他的要求你要是都做到平时分还行，想水课不建议选',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('65a69f5e2543857e58d9cb73',1105,1981,'五星的含金量，无需多言',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a696982543857e58d96037',1005,73,'更年期老师',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('65a694a92543857e58d949a5',1949,230,'给分低低低低低低低低',2,2,2,6,0,1);
INSERT INTO "reviews" VALUES('65a688ca7c6c3940168c1978',2173,3740,'供应链虽然平时分挺高的，但是期末给分不知道是什么标准，我重点差不多全背下来了，期末考试也都写满了，最后期末只有75，总评82，不理解',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('65a688937c6c3940168c16e0',527,2049,'伟大无需多言
INSERT INTO "reviews" VALUES('65a685e609df0b3e0f1eec9f',4687,4687,'课，是不当回事的，考试周提前两周不上课，除了第一节课不点名。
INSERT INTO "reviews" VALUES('65a683a609df0b3e0f1ecc70',932,6388,'夸他的说的都是真话，口音不会听不懂的，不是四川话，只是夹杂着四川口音的普通话。有些老师普通话倒是标准，上课跟个念PPT的AI一样才叫无语。上课和讲练习都很认真的给你一步步计算。你还有机会看到世界名画：《写的满满当当的四面黑板》^_^',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('65a681cf90f1e64a72642a22',307,307,'登录活水，点击榜单，点击院系选择计算机，点击差评榜，你就可以看到这位差评榜榜二的传奇了。课堂分怎么给，根据考试给，考试怎么考，学习通考，考完后题目不能看不能复习，也不讲解，做题只是为了让他有扣你分的理由。期中考试也是学习通考试，写一题交一题，这题不写完不能看下一题， “这题我给你你写20分钟，你十分钟写完了，那你就干等着，下一题20分钟你又没写完了，那你这题就零分” 。如此惊世骇俗的考试设计真是第一次见。上课的声音像羊伟一样，坐第三排都听不清。我都不想说什么了-_-',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('65a67f6190f1e64a72640ace',6510,773,'好！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a67f42d3a3253d03b9a22f',77,24,'最烂的老师，没有之一。早八的课让学生七点半过去找他改卷，结果自己迟到害我们所有人在教室里干等。******，作业一次课一留，批的极其不认真，鸡蛋里挑骨头，打分完全看心情。有的时候随便挑一道题让助教讲，助教******。期末考试的时候发了二十多道题，以为良心发现，结果******不给答案，自己做一遍才发现还把期中考试的题给整进去了，敷衍至极。选到的兄弟们赶紧跑吧，跑不了的兄弟们如果不在意重修的话就直接别去上课了******',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65a67e9a2543857e58d82307',984,850,'电力电子的神好吧，不过实验老师是真垃圾，害我总分没100',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a67dc1d3a3253d03b98e37',751,573,'认真学了，平时分基本都是满的。不过不画重点是真的顶啊。这次期末就考了70多分，太jb难受了，难度偏高是一方面，感觉主要还是老师出差和假期冲掉了一些课，导致大部分学生最后一章没学好（我自学也学的一般，最后一章30分）。老师还是可以的，别听那些鬼乱说，自己是废物就别怪老师，工程力学一直是有难度的，但这老师教你基本不用课后去自学啥，都能做出来所有题目，讲课能力非常好，在我所有老师中都可以排上前面。平时有问题QQ上基本老师都会回你，而且答疑也很细致，老师比较负责。最主要是老师很看重学生，你不学他会督促一下你。最后没上90主要是我的问题，不是老师的。',5,5,5,15,4,3);
INSERT INTO "reviews" VALUES('65a67d712543857e58d81222',2984,6514,'两次大作业，第一次作业介绍家乡地铁，还要求打印报告，交了又不看不给分，最后打分只看第二次文化墙设计。期末开卷考试，要准备他的那本教材。每节课点到。内容还将就，如果真的喜欢地铁文化还是可以选，如果只是混换一个吧。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a66b3e7c6c3940168a77ba',76,76,'唉',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a6670b7c6c3940168a3af5',751,573,'好！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a664d62543857e58d6be9a',175,175,'期末考得低老师会捞，考得一般就平时分就别想高了，一次没交就扣大分，无语-_-||，上课无聊，不布置作业又要交作业，作业都要写完贼多，服了',2,4,2,8,0,0);
INSERT INTO "reviews" VALUES('65a664bd7c6c3940168a1d6b',1401,1401,'分巨高，神！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a66173731a1f600531e9ad',462,462,'老师真的人超好，非常亲和，年轻且知识渊博，会给回答问题的同学奖励，平时分很高，认真听能学到很多东西，期末基本没什么问题，强烈推荐!!',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a660a309df0b3e0f1cd768',142,75,'yyds，正常听课写作业不复习轻松90+，温柔体贴细致，体验相当好。',5,5,5,15,0,4);
INSERT INTO "reviews" VALUES('65a66097731a1f600531ded7',462,462,'无脑选就对了 老师特别好 上课更不用说好吧',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a65bf309df0b3e0f1c9935',2984,361,'放假回家了登了平时成绩，平时没逃过一次课，请假也是开了假条交上去，在线学习也完成了，结果不知道为什么平时成绩60多分，质疑成绩给老师发信息，也不回，也不处理这件事。真的很烦这种对学生成绩不负责任的',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65a644a8731a1f600530636d',393,96,'好，讲的好，给分高，考的好，事也少，平时作业忘了交，隔了一个星期再补上都行，两个小测试就一道题，还让你用手机，最后无论对错都是直接给满分，平时分就期中成绩没有办法改，其他都是拉满100，期末是自己考，反正跟着他平时认真学，期末复习个一两天，考个90+都很简单',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a643e509df0b3e0f1b4cd0',2170,6490,'就复习了3个小时吧，考试考了半个小时就交卷了，真的不会写，感觉我交的是白卷，但是老师没让我挂，捞了我，平时分给的很大方，是我太烂了，能及格已经是她最大的仁慈了',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('65a643437c6c394016884653',17,17,'给分90+，每节课都点名，事很少，就期末有个论文（全部gpt写就行），期中没有作业。平时讲课会讲40分钟，课还挺有趣 ，不听也没关系，就是会点一两个一直玩手机的人起来回答问题，不会也没关系，就说不会就行，然后就坐下了。大部分情况是点上节课不在的人，我反正没被点起来过，接着就放视频，最后下课前15分钟助教点名，点完就可以走。或者他不想讲课的话就是一直放视频。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('65a6416409df0b3e0f1b23a3',2491,2491,'上的软件工程，期末没有重点，反正我裸考，给我踩线过了，平时分90+，期末总评刚刚60，应该是捞的我。课很水，作业也水，反正我课没听，考试没准备，给我过了，他就是一个好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a63568d3a3253d03b59ca5',886,1046,'专门为这个老师注册的活水，给分巨低，期末不给重点，只有900页PPT，避坑',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('65a635507c6c394016878d94',960,228,'每次都去上课了，没回答问题平时分就很低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('65a6244090f1e64a725f4c9a',741,741,'神！课上认真负责很有节奏，课后作业量适中，期末给分慷慨',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65a62239731a1f60052ebc55',3410,4761,'上课水的要死，什么都不教……审美答辩，打分死低，避大雷',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('65a613b509df0b3e0f1942d1',1062,352,'负责用心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a6016909df0b3e0f189fab',3978,6532,'课讲得还是挺有意思，考试也划了重点，但是给分跟蒋玉石相比差得不是一星半点',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('65a5ff3e731a1f60052d7c55',2688,2688,'期末交了论文，平时去的时候都没签过到，没去的时候都签了到，最后老师说我五次没到总评给了我0分',1,1,1,3,0,2);
INSERT INTO "reviews" VALUES('65a5fd5809df0b3e0f187bd4',52,52,'讲的好，上课板书也很好，会告诉你什么是重点，而且期末还有各种复习资料。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65a5fcf890f1e64a725deb63',2346,2346,'满分，讲得好！人更好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a5fc94731a1f60052d6442',2821,3822,'老师好，作业稍微有点多。不过给分很好，讲课也是。多回答问题有加分。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a5f60390f1e64a725da80b',546,40,'还好，平时分挺好的。没有老同学说的那么不堪，可能老师态度逐渐转变了。现在给分很温柔',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65a5d45309df0b3e0f172179',6538,80,'😍😍真是混凝土的神啊，当时选课的时候基本没什么人选。说是提问回答不出来要扣平时分结果一点没扣，平时作业和课堂表现都是满的，课设给了96，还专门拿了一节课让助教教我们做课设，时间也很宽松给了我们一个多月，平时作业很少，上课很轻松，期中考了59最后给了85，舍友还被捞了一把到60，我哭死',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a5d405d3a3253d03b21a1b',4885,3563,'老师认真负责，还会给我们推荐其他网课，会鼓励我们，答疑及时，捞人',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a5b9bd2543857e58d0365d',24,1695,'这么说吧期末卷面过42就能过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a5b841d3a3253d03b1a2a6',170,233,'第一次遇到平时分给的比我期末卷面都低的老师，先说本人情况一次没旷过课，作业确实只少交过两次，但是最后平时分70多我是没想到的，上课也比较无聊，作业多的一批一周留了一堆CAD',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65a5743cd3a3253d03b11d0f',10,10,'特别好的老师！给分很高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a573427c6c394016831880',886,1046,'分数给的低，期末不给划重点，平均分比别的班能低8分，而且还会挂人',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('65a54e3f90f1e64a725a9f3d',392,392,'合着这门课没有平时分啊，堂堂抽人回答问题，又是随堂测试又是小组作业汇报的，不给PPT不给划重点不建课程群，改卷一点不水题一点不送分，严得很高中政治课一样',5,4,1,10,1,0);
INSERT INTO "reviews" VALUES('65a54d5f731a1f60052a26c6',3517,3517,'说话听不清，靠自学吧，大题范围基本上都圈到了，就是平时分给得很低。。。',2,1,1,4,2,2);
INSERT INTO "reviews" VALUES('65a54cedd3a3253d03b020fa',2491,6492,'上的软件工程，老师人很和蔼，给分还可以吧，不算特别高',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('65a53b337c6c394016817830',505,561,'算你幸运，等挂吧',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('65a539c509df0b3e0f1462fc',592,194,'老师人真的很好 教的也好。平时分狠狠捞，课后作业也是挑的题做，还有考前课堂习题讲解。赞',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a536db2543857e58cdc0dc',242,242,'笑面虎 脸上笑嘻嘻 给分低 改卷严',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('65a5205b731a1f6005284c0c',3334,3334,'“没有人能挂在我这，除了不写。”包die如是说到。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('65a5160109df0b3e0f12cc6f',3712,92,'神中神，不多说',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a5051bd3a3253d03ad13f8',198,179,'平时分几乎拉满了，期末给分也很高，神中神！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a4fd8d7c6c3940167eb44a',330,22,'上的大物BII,老师上课很认真负责，讲课也很容易理解，期中期末找老师问问题老师也都耐心解答了，认真上课写作业平时分基本就给满（不包括期中），期末期中考试给分算公正，不宽松也不苛刻，推荐。还有老师上课考勤很频繁的，千万不要逃课。',5,5,5,15,0,7);
INSERT INTO "reviews" VALUES('65a4f8c209df0b3e0f1164c3',532,141,'上课不要交头接耳，不缺勤，作业交齐了，就算课堂从来不回答问题，平时分都是满分，能给满的都给满了',5,4,3,12,1,2);
INSERT INTO "reviews" VALUES('65a4f814d3a3253d03ac5d2b',3727,712,'讲课水平一般，但是工程材料主要还是靠自己看书背书，一学期作业只有一个400字的小作文，期中老师直接把卷子发下来让我们自己回去做，当然期中占分也很少，平时上课不来的直接请假老师不会多说，期末评分也很宽松，我觉得比我预估的要高很多，还是很不错的。',4,3,5,12,0,1);
INSERT INTO "reviews" VALUES('65a4f67f90f1e64a7256a388',1391,24,'选到就是赚到，老师上课认真负责，作业也有系统的习题方便期末复习，这点真的很好，因为理力很难找到系统的复习资料。给分方面，只要认真上课做作业平时分就拉满，慕课智慧树这些老师也不会计较，当然自己想做也是很不错的学习资源。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65a4f10e731a1f600525fb13',3334,573,'包爹的伟大无需多言，上课认真负责，期末认真带学生们复习，最后成绩海底捞，永远的神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a4e89a09df0b3e0f107e75',24,1695,'给我听湿了，快点去选！😋😋',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a4e51ad3a3253d03ab51c6',4668,946,'平时分是实打实给的，如果你是想水就别选他的课，分会很难看。课程讲的一般。总得来说中规中矩。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('65a4dc41278a914754109361',2299,760,'基本上节节课都要点名签到，讲课的话声音比较小，坐后面很容易听不清，不过能听清楚的情况下确实能把知识讲的还算是明白。作业量还可以，只要都交了作业是可以满分的，但是没有反过作业。给分的话就是基本按照标准给，不会恶心人，除了那个实验系统抽疯。几次交了实验报告给我显示缺交导致实验方面平时分极低，但是反映完之后也正常给我上了分。总而言之想水可以选，毕竟发现你上课玩手机也不会有什么极端措施，想学东西的话还是可以靠龚老师的网课，而且这个老师留作业不用那个逆天系统。',4,4,4,12,5,1);
INSERT INTO "reviews" VALUES('65a4d0a9278a9147540ffa82',532,141,'比较难评，我每次点名都去了，但是他还是每次都要点我。平时成绩也都拉满了还算可以吧，就这个点名我不理解，甚至有几次一次点名点我两次....',4,4,4,12,3,0);
INSERT INTO "reviews" VALUES('65a4cd376329884b8137f87b',604,96,'凯皇yyds! 总评98，这辈子第一次这么高!',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('65a4cce8983c234771da0b3f',2500,228,'袁老师yyds, 平时分只要你想加，肯定会很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a4c97e6329884b8137cd41',198,179,'香香妈妈神中神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a4c8ab6329884b8137c420',190,5,'老师人很好，很有亲和力，也很专业，平时分给满，平时经常在群里给同学们答疑，期末给同学们手写一大堆提纲，重点也划得很准。除了表达没什么可挑的。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('65a4c49a983c234771d9af99',198,179,'无敌 爷',5,5,5,15,0,0);
