INSERT INTO "reviews" VALUES('65a4c3ec278a9147540f648c',190,5,'很认真的老师，听他讲话会觉得不清楚，他打字和提纲写的清晰。
INSERT INTO "reviews" VALUES('65a4b888983c234771d90dfd',260,96,'有啥说的，平时分除了半期都拉满。而且半期的内容有一大部分高中都接触过，半期考试考好点，期末考30就能过。我给李老师打5分是因为活水最高只能打5分！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a4b7bc0fc8007a64576b42',4515,773,'老师人很好，期末捞人，作业也不多，上机测试也很水',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('65a4b6046329884b8136dc10',563,228,'平时成绩给了95，折算下来是47.5，人我觉得还不错，这学期一共签了四五次到，如果你没来，可以让同学给你发签到码，中间有一次天气挺好，还带着我们绕着学校转了一圈，半期考试就一道大题，挺水的，还有实践作业一定要记得交。总之还挺不错的。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('65a4b2c4983c234771d8ca28',228,228,'平时分不高不低，平均在90左右除非回答特别多问题参加免考，只能说一般般',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('65a4b14d983c234771d8bb1b',867,27,'平时分卡的是真的死，我英语六级加分之后还只有刚60出头的平时分，平时还一直强调给我们的活有多轻，实际上都差不多
INSERT INTO "reviews" VALUES('65a4b0446329884b81369cd3',345,96,'最逆天的老师，其他就不说了，看其他同学评论也能知道，但是她整个人就没有人性。
INSERT INTO "reviews" VALUES('65a4afbb278a9147540e6bcf',228,228,'这老师我是真的服啊，给的平时分真的低，我回答问题虽然不算多，但是也好得回答了4个，隔壁班4个问题都能给平时分96分，我才91分，狠狠地踩到雷区了，听说四大天王给的分都比这个高******',4,3,1,8,1,1);
