INSERT INTO "reviews" VALUES('65a3b4a6983c234771d0a42d',6600,6600,'作业全交了，点名也全到，半期考试一个题未错，机考也没问题，平时分只有八十多一点，同学58都不捞一下的，大过年的搞的真挺恶心的',1,1,1,3,2,0);
