INSERT INTO "reviews" VALUES('65a3a8cd0fc8007a644e9cf0',558,623,'给分高，嘎嘎刷好评',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('65a3a73d66bfda4ea7b11130',360,1648,'让我能怒评几次的也就这课了。不知道花了多少时间在这没用的东西上面。其实给分也挺随意的，不知道按啥标准。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('65a3a144278a91475405973e',1252,18,'老师人真的很好，很年轻很帅，感觉他和学生交流没什么代沟。讲课很细致，会认真推导一些公式来帮助学生辅助记忆，作业题量很少但是质量很高。期末考前还会带着全班认真梳理每个知识点，针对性的讲解一些练习册上的题目。总之，我很幸运能遇见他，让我很享受的去学习概率论这门课。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a3a0980fc8007a644e44cc',3065,140,'******作业多的想死，考完了才知道别的班都划重点就你不划，给分给的死低死低的******想到考试周还担心毛概会不会挂科吗？想的话就来选它！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a391cd6329884b812d1ba9',932,932,'神，除了期中和期末考，其它分数全部打满。作业交了就行，如果忘交了，可以上课的时候跟他说，他就会允许你补交。讲课也很牛逼，考啥讲啥，讲得清晰透彻，会板书，只要去听课了就能学会，甚至不用预习不用看网课。至于口音什么的，听一两节课就习惯了，我都不知道一个口音有什么好喷的，又不是听不懂。作业就练习册的题，不多，最主要是他会评讲作业，不是交了就不管的。期末他还会把去年的期末卷拿出来讲一下。真的是强大认真负责，选他的课你认真听一定能学好的。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('65a38f77278a91475404dd67',307,307,'差评榜第二是有原因的。上个课，说话又小声又催眠，不坐前排听不清。至于教学，前面部分感觉学过离散所以没啥难度没感觉，但是到了后面，我不知道他是赶进度还是啥，讲得贼快，很多都没理解，还是课后看书自己慢慢学的。至于给分，那是真该喷了，课堂表现靠上课的随堂小测平均分，作业也会给你评分，期中考最恶心，学习通发题，每道题只能在规定时间做和提交，导致考得很差。所以整个给分就没有什么捞你的地方，题做不对就是分低。',2,1,2,5,1,0);
INSERT INTO "reviews" VALUES('65a38c8d278a91475404bb73',1453,26,'以后谁和我说王中宝上课给分不行，我和你们急。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a38bf60fc8007a644d693f',1130,1130,'非常好的老师，上课认真教学，教材是老师亲自编写，上面有实验视频，风格幽默但又细节严谨，要求较严但平时给分很高，听他的通信最后总分90多，电气的学弟们选到向老师的课冲就完了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a38b92278a91475404afc8',1453,26,'******你真是我亲爹，一学期没去上课没交过作业平时分给我干满，我爱你。么么么么么么么么么',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('65a388d06329884b812cbb5e',1453,26,'掌中宝我认🉑了，概率论除了期中其他全100分，人民好教师！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a37105983c234771cdbe73',2598,2598,'我女神，我女神啊啊啊啊啊。平时分都几乎给满，两学期考两次捞两次，我要爽飞了🥵教A1的时候翠娟经常提醒认真听讲，抽问是因为A1课程四学分确实很难，下学期上A2了从来不说你什么。神中神就完了🥰',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65a3700066bfda4ea7aeaf9b',6600,6600,'真有趣',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65a36e96278a914754036069',573,573,'非常好的课程，出卷和改卷能够让听课的人在及格线上挣扎。期末考试过后会给你们上压力，体现老师的人文关怀。平时上课会大量抽学生回答问题，浪费时间且没有意义，这就是工程力学给我带来的自信',2,1,1,4,2,0);
