INSERT INTO "reviews" VALUES('65a35ee0983c234771ccfdcb',24,1695,'神中神，我是重修报郑老师的课，最后一个月没去上过课，作业也没交，最后对完答案感觉又要g了，出成绩后老师狠狠的捞了我，真是太感谢老师了，作为全校属一属二的挂科课程，郑老师是指定神中神，第一次被捞，我现在好幸福！！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a348db66bfda4ea7ad22e0',4885,3563,'这门课比较难，加上课时给的少，所以你会感觉课程学习困难。李燕姐姐虽然上课讲的照本宣科，她而且进度缓慢，但期末给分真的宽松，请不要埋怨老师，李燕姐姐人真的特别好。',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('65a344be983c234771cc0452',260,96,'老师讲课挺好的，给分拉满，作业相比其他班还算少点，一个非常好的老师',5,5,5,15,0,0);
