INSERT INTO "reviews" VALUES('65a32231278a91475400c312',24,1695,'小武哥，神中神，非常的负责任，讲课也很好，遇上难点和不会的地方讲的很细很透彻，从课程中收获了很多，平时分拉满了，是我遇上最负责任的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a31fe5983c234771cb010b',2433,142,'神中神，老师上课讲的很好，知识点讲的也很透彻，课程中学到了很多东西',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a2db4866bfda4ea7ab3e38',100,100,'超级好的一个老师，人美心善，温柔如水，认真负责，和蔼可亲，真的超棒！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a2d84c0fc8007a6448af19',2433,142,'力航的学生，很喜欢朱老师。不只是因为老师讲课讲的是真的好，还因为老师很幽默风趣，他真的很体贴我们学生，将心比心，换谁来不会爱上他呢？这个学期我不太喜欢学习，这是个人原因，所以我大多数情况下都躲在后面玩手机，老师幽默的说：“手机玩多了让手机歇歇吧，别把它累着了”。可惜的是我确实荒废了学习，后面只考了65分，老师硬是给了90分的平时分（期中我也只有63）。挺可惜的，没能遇到一个好老师的时候发挥出自己的全部（心情真的很差，学不进去）
INSERT INTO "reviews" VALUES('65a2bc9c0fc8007a6447f759',2821,40,'给分是真不高，严格给的，要不是期末不差，就被狠狠背刺了',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('65a2bb636329884b81276bb6',2567,1111,'交大即将退休的老教师，可惜没有遇上马老师年轻的时候，感觉现在教的有些力不从心，不过还是学到了很多东西。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('65a2bacc6329884b81276554',674,6634,'虽然明年这门课程就没了，但是叶老师和丁老师教的这个班我觉得相当不错，两位老师都很认真地在教学，两位老师人都很和蔼，而且很仔细的回答大家的疑问，照顾到大部分的同学，那些黑老师的，我真的搞不懂☹️☹️',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a2ac850fc8007a644752b9',1291,22,'上课讲的话根本听不懂，声音忽大忽小，一到重点声音又小语速够快，哥们坐第一排都傻眼了，只能庆幸润的早，极其死板，净把没用的东西看那么严，作业卷子交了还要学习通再敲一遍，我舍友卷子全交了，期末还考满分，就因为两次忘记学习通提交总评直接只剩91，只能说真让人无语，选到他是真倒霉，纯属给自己找麻烦，速跑！！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65a2abf20fc8007a64474c33',1062,352,'平时分(除去期中)拉满，专业能力突出，每周有线下答疑时间',5,4,5,14,0,0);
