INSERT INTO "reviews" VALUES('65a2a8d30fc8007a64472d93',1252,18,'张老师讲课通俗易懂，治学严谨，作业不多，是他自己选的题，一次就那么几道，最重要的真的海底捞，很好的一位老师，真诚、仁慈且幽默',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65a2a8a10fc8007a64472a93',3868,762,'人很和蔼，不过讲课我听不太懂。至于平时分，半期93，一次作业迟交，最后94.5，供大家参考。不过老师人还是很和蔼的。',4,3,5,12,2,0);
