INSERT INTO "reviews" VALUES('65a2491f66bfda4ea7a5c8aa',831,762,'讲的******为了给你打差评我专门注册了活水账号。前面简单的单元讲半天，后面几个章节就硬拉进度，第十七周还在上新课。导致几乎所有这个班的人都是最后两天学三个章节的内容，今晚学完明天考试。讲课纯纯就是表演给自己看，没人听得懂。就像其他评价说的那样，一股莫名其妙的“拿鼻孔看人”的感觉。平时分给的不算差，签到，交作业齐了分就不低。但是讲课******我从第二章节就开始自学到期末考试，卧槽牛魔的，上她课真的是心理压力暴大',1,1,1,3,0,2);
