INSERT INTO "reviews" VALUES('65a2461f983c234771c4c18a',532,141,'老师讲课挺好的，而且在他专业范围之内会努力的给你拓展一些东西，点名也是在课堂最开始几分钟之内点，上课点名这件事情无可厚非吧，你一节课都不去还想要和别人每节课都去的一样的平时分未免也对别人太不公平了吧？就是回消息确实很不及时，而且出成绩也很慢。偶尔说话会有点儿呛，让人难以下台，但是想要好好学习靠自己拿分的确实可以冲一下',5,5,5,15,2,4);
