INSERT INTO "reviews" VALUES('65a20a0366bfda4ea7a32e52',450,450,'神人，点名超过三次没来就退课，一会说平时分60一会说平时分65******，能给就给，不能给一开始就别吹牛，又爱画饼又不爱付出******',1,1,1,3,0,0);
