INSERT INTO "reviews" VALUES('65a1f4a60fc8007a643fee24',751,573,'每次上他的课都很折磨，还会时不时过来看你有没有玩手机，一边不听还一边防止他过来看你，题型也不说，上了一个学期很折磨，人还好比较幽默',4,2,3,9,0,0);
INSERT INTO "reviews" VALUES('65a1ed606329884b811f3a15',141,765,'海底捞……！平时分获取很友好，别忘了上课前定位签到，然后正常交作业刷视频就能拿满。老师人很好，声音也好听，讲课也很有激情',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65a1eca06329884b811f34a2',307,307,'抛开说话自带很重的鼻腔音（你很难听清他在说什么），教学水平还是可以，期末也捞人，能润就润吧，不能润就坐前排吧，不然你听不清的',4,2,3,9,0,3);
INSERT INTO "reviews" VALUES('65a17d116329884b811d93fa',751,573,'三个真实事件，其余自己评判。1.期中考试结果对了图画错了扣了50分本以为是乱扣分用来鞭策学生，后面期末会加上去，结果您老真扣啊2.上课有奖竞猜，让学生猜谁上午给自己打电话，猜对了平时分加满，竞猜结果已有同学评论了3.ppt上的和自己布置的作业不一样，写了ppt上的题直接作业判0，两样作业都写了也是0',3,2,1,6,5,0);
INSERT INTO "reviews" VALUES('65a16f5b6329884b811d4183',751,573,'芝士是没有的，口齿是模糊不清的，儿子是比教学重要的，我胶也有属于自己的丁真',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('65a16d230fc8007a643d9992',751,573,'******上课让学生猜早上谁给他打电话，猜对了平时分直接给满。结果又是他的宝贝儿子，上课玩手机被班主任逮着了。猜到的人分数直接给拉满了（顶针），太幽默了。真正期中考试的时候给分就乱打，一步错就零分，不按他的想法来就零分，恶心至极。',1,1,1,3,8,0);
