INSERT INTO "reviews" VALUES('65a0fc2766bfda4ea79bb22c',459,40,'平时分真不高，而且还为了“保护隐私”什么方式都联系不上，教学群都不进，自己的问题还以一种很高的姿态来教育你，叭叭能说',5,1,1,7,3,0);
INSERT INTO "reviews" VALUES('65a0f9cf278a914754f04ad6',3754,156,'******期中考试当时他不管，但是我去迟了，只能坐第一排，然后他出了一道特别难的题，占35分，写不了一点 别人一下没看的那种人，随便抄抄手机，十分钟就抄到满分了，我复习了四五天，然后最后考了50分，最离谱的是期末我最后91，平时分他给我扣了20分，最后总评直接从93干到了88，申请这个账号就是过来骂他的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65a0f7ea278a914754f0374e',2602,653,'我跟你说吧，这个老师他就只会喜欢那种哗众取宠的设计。他只会喜欢那种很装逼的设计，专业能力极其低下，一点都不专业，经常讲很多错误的东西出来。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65a0f79766bfda4ea79b85e4',748,392,'平时成绩如果不回答问题就是零分，但是好像最后期末算总成绩的时候不算平时成绩，平时成绩好像占比为零',5,5,4,14,1,0);
