INSERT INTO "reviews" VALUES('65a0c8e52be3a26cec444304',5558,737,'户老师给分巨高，平时分直接给拉满了！！！讲课也特别幽默风趣，人也非常平易近人，请加和户老师说一声就行了，也不需要交请假条',5,5,5,15,0,1);
