INSERT INTO "reviews" VALUES('65a0c8022be3a26cec4439b7',3577,631,'游老师非常好，上课从不点名，但是这个课不认真听就是听不懂没办法，期末复习一下就会了，然后会有一个期末大作业，感觉有点难，平时分90还是很可以的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a0c7774f662037486db7fe',1108,188,'春玲已经做出了改变，上课会有一次期中作业课上写课上交，然后毛概大作业交了，全勤，上课不用回答问题，但是会点名，最后期末平时分94，已经很高了',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('65a0c7299c4d834feade38a0',1756,52,'人漂亮心善良，平时分拉满，讲的也不错，好老师！',5,5,5,15,1,0);
