INSERT INTO "reviews" VALUES('65a0c6323a094c20e12df30f',759,759,'给分无敌低，见过最高平时分就70哈哈，没见过这么低的，但是这个分在他这里可能已经算高了，期末也没重点😓😓',1,1,1,3,0,0);
