INSERT INTO "reviews" VALUES('65a0c0872be3a26cec43f38e',631,631,'老师很好，作业少，讲的比较深。但是确实讲什么就考什么，没有废话。只是课程设计需要自己一个人完成，并且有一定难度',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('65a0b4c22be3a26cec439863',5581,5581,'老师人很好，平时没怎么回答过问题，每节课都去最后92',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65a0b2992be3a26cec4385f2',846,28,'本来英语a班事情很多，但是老师人很好很温柔，小组作业口语考试只要有准备得分都很高，后几次作文是线上提交。平时成绩还是很高的！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('65a0b2919c4d834feadd8c27',1169,1169,'男神 除了期中考都给满 他也说过只要你期末考的高 你平时不交作业不来上课也会给满 还会发作业讲解视频 ',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a0b2802be3a26cec438576',953,953,'之前不评价，这学期平时分100，荣晋新神!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65a0b19f90d3d1241d2f0186',1169,1169,'崔老师很敬业，会发作业的讲解视频，半期和期末考前会及时发往年试卷的电子版。最关键是，平时分拉满了！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a0b0a63a094c20e12d3efa',252,114,'对比其他老师，给分是真低。一学期做了三次小测，占20分，考多少就给多少 也不让用手机搜，还说学校要求小测占20分及以上必须按正式考试要求，因为他没有所以我们要做三次小测，严重拉低了平时分。期末考前也不发往年期末考试卷，说学校不公开他就真不发。期末出成绩前平时分就登上了，捞不捞显而易见。',2,2,1,5,7,1);
INSERT INTO "reviews" VALUES('65a0b09c4f662037486cf419',767,694,'学自控没听说过李崇维，就像西方......李崇维老师幽默风趣，讲课逻辑清楚，授课技巧高，并且平时分给得满中满（半期考差了，期末给她交个小论文也起飞），期末捞人。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65a0adc090d3d1241d2ee1f8',2007,24,'老师很温柔，上课基本不会管你，平时分是拉满的，半期考试尽力给你分，作业也比较少，可能是课程难度原因，老师讲课很难听懂，我是自学的，而且老师从来没有点名过，我作业也有一次没交，半期考了80，平时分还给我拉满了，老师也和蔼可亲。好评，不过那种上课认真听老师讲，上课跟着老师学的不建议选',5,5,5,15,0,0);
