INSERT INTO "reviews" VALUES('659ff44f2be3a26cec3f5ec1',788,1551,'难度是起飞的，考试是爆炸的，重点是没有的，老师是逆天的。交通工程同学保研的拦路虎、评优的终结者、挂科的开拓者——李娟，在道路工程和它的课设迎接每一位同学~什么，想逃？不好意思，只有这一位老师哦🤗🤗🤗',1,1,1,3,7,0);
