INSERT INTO "reviews" VALUES('659fbf9a2be3a26cec3d1895',1379,346,'你很难想象，一个学生，体育课从不缺勤，健身跑从不缺席，期末考动作也及格了，最后居然因为慕课给挂了，别的班慕课成绩就算0分，跟老师求求情还是能过的，因为体育真没必要挂人，再说你从不缺勤态度已经很好了，主要是你这体育还能挂人的？******',1,1,1,3,5,0);
