INSERT INTO "reviews" VALUES('659faabe90d3d1241d27e230',6775,140,'课上鼓励学生回答问题，靠抢答，一般同学根本没办法挣平时分，一学期都回答不了几次。做了加分作业，最后平时分70多、老师人挺好就是给分最后居然比吴春玲的班还低。。。。。。。。。',2,2,3,7,0,0);
