INSERT INTO "reviews" VALUES('659f59af4f6620374862c02f',2642,2642,'期末低，平时也低，但老师会捞人，平时上课水偶尔点名，因为课程内容较难后期大部分人听不懂，考的不会太难，感觉可以不用听所以建议润另外的老师',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('659f58263a094c20e1230dfd',2541,22,'除了年级统一的半期考试，只要作业都交了就是满分，一学期只因为来的人太少点了两次名，讲课也很有激情不是光念ppt，大物也确实不难',5,5,5,15,0,0);
