INSERT INTO "reviews" VALUES('659eb66190d3d1241d21b022',876,876,'大物上下都是老郑带的，首先老郑教的好，但是我真的听不懂大物。其次，老郑给平时分到分了四个板块，一个是期中考试成绩；然后是20分的必给分（前提是点名你都在）；然后是10分的作业分（作业是老郑修改了的题，我的作业都是夸克搜的，所以我是拿满了的，要是全自己做的可能分就低了）。期中跟期末考试前一个月，老郑会发复习资料压缩包，里面有考试范围跟重点，还有PPT，反正我大物下是平时一点没学，就靠期末老郑发的压缩包，突击2个星期，考个80分还是没问题的。最后老郑平时说什么扣分扣分，但是最后都不会扣分的，甚至去年大物上他看我期末分太低，把期中分数也拉高了50，平时作业分也给满了，老郑捞人很大方的',5,5,5,15,2,0);
