INSERT INTO "reviews" VALUES('659eaa299c4d834feacfce3c',2424,2178,'赵老师也算是我在土木碰到最好的老师了，人非常亲和，土木工程地质这一门课只要上课做了小测验作业交了，基本上就是50平时分，平时上课划重点，之前因为生病回家做手术，赵老师会跟你说为你补课，当时真的很感动，期末背一背就能得很高的分，更重要的是他对很多事情有这自己见解，不仅得高分还能学到东西，真的很荣幸上过赵老师的课，真的是我在交大见过的最好的一位老师',5,5,5,15,2,0);
