INSERT INTO "reviews" VALUES('659e14c04f66203748599c6d',3577,631,'选到他你们就偷着乐吧！！！好到爆炸，知识点讲得很透彻，而且非常认真负责，讲得非常好！非常具有人格魅力，只要你每次作业按时完成按时提交平时分没有问题，鼓励学生线上问他问题，有问必答！！而且是心软的神，如果再给我一次机会我一定更认真的学习平差！！老师真的太好啦！！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659e14532be3a26cec303f7c',3577,631,'温温柔柔，有问必应，会捞人。很抱歉成绩太差把老师弄玉玉了。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('659e143f2be3a26cec303ee8',1063,143,'******折磨人，考试恶心人，他出卷子，40个填空题什么概念，纯纯想挂我们，真的，快跑',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('659e141890d3d1241d1ba296',1063,143,'上课课程内容外的话太多，进度很慢
INSERT INTO "reviews" VALUES('659e13d79c4d834feaca39e3',3925,3925,'黄老师人很好，上课认真严谨，老师水平也很高，在课程内容基础上也会补充一些更有深度更前沿的知识。数理统计和回归分析都是他上的，统计系宝藏老师，值得去上他的课！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659e13a63a094c20e119ee6e',3577,631,'老师真的讲的很好，非常负责，问问题都会回答。为了让我们过，除了半期成绩之外的平时分都拉满了。非常好的老师！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659e13442be3a26cec3035f2',751,1652,'老师其实挺不错了，虽然有点照本宣科的，但是可能是老师感觉太简单了，讲不出来，不过老师讲例题，答疑的时候挺细致负责的。期中考试的形式和给分真奇葩，也是无语了，这也是平时分不高的原因。不过期末考试老师是真的很细致地改了，能给的分都给了，过程也尽可能的给分了，不然我感觉我是过不了的。学啥还是要靠自己努力的了。',5,4,5,14,1,6);
INSERT INTO "reviews" VALUES('659e13449c4d834feaca32f7',3925,3925,'老师人超好！！！选就完事了！！！',5,5,4,14,0,0);
