INSERT INTO "reviews" VALUES('659e132c4f66203748598a54',3925,3925,'很好的课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659e128690d3d1241d1b94c9',3925,3925,'黄老师要求高，水平高，人很好。已经修了他的数理统计和回归分析，下学期时间序列还选他!统计专业提升自身素养的必选宝藏老师，希望平时分也能高一些哈哈',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659e12373a094c20e119e13d',3925,3925,'神中神，无论是教学能力还是对学生的人文关怀，各项水准都是非常顶级的老师，他的课程值得大家选择。',5,5,5,15,0,0);
