INSERT INTO "reviews" VALUES('659e06d13a094c20e1197332',751,1652,'我注册账号只为给差评',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('659e014c4f6620374858e166',751,1652,'我只能说，smx只折磨力院的人。课难，但是smx讲的更难。没那个自信还是别选他的数物吧',5,3,5,13,1,3);
INSERT INTO "reviews" VALUES('659dff2590d3d1241d1ad831',314,664,'也算电气名人之一了，小东西们等着她折磨你们做实验吧',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('659dfd7e90d3d1241d1ac3ed',6933,211,'重修跟的曾老师，感谢今年电力电子考得巨简单，事儿少平时分高那种',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659df7a22be3a26cec2f220d',751,1652,'******登活水就是给你打差评的。不会讲课，就不要讲。菜，就多练。你站讲台上支支吾吾的，憋了半天来一句“这没难度吧？”是几个意思？讲着讲着就开始吹牛皮，吹你那宝贝儿子数竞生做高考题不及格******看到我们听不懂就开始发电绕着教室挨个问会不会，都这样了还懒得再讲一遍把它讲明白。每次上课都是照着从书上抄下来的PPT念，夹杂那不知道哪里的北方口音，想把你的课听明白是难如登天的。平时分给得也是抽象至极，先不说半期占20分，你出三道大题一道十分就搞定了？我全写完了给了13分。还好意思说要当力航第一杀手，自己讲的差怪在学生头上了？看你工力好评那么多，赶紧回去讲你的工力吧，别祸害我们学数物的了。',1,1,1,3,19,0);
INSERT INTO "reviews" VALUES('659df1223a094c20e118a7d3',6935,6935,'贾老师给分很高，结果对了验收就给A，错了有时还能让你改了重验。做实验之前会先讲解内容，提醒一些容易错的地方。问问题也会耐心地回答，挺和蔼的，前几个实验也体谅大家不熟悉这些操作所以做得慢。期末考试开卷。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659decdf90d3d1241d1a3572',18,18,'全世界最好的概率老师！！！！我爱赵春明！！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659dd7404f66203748579a08',751,1652,'你就选吧，一选一个不吱声',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('659d987f4f6620374856e691',2433,142,'神中之神 材力没他真不知道咋办了，每节课上课时会把上节课的知识点主动梳理一边，平时上课幽默风趣，讲题会提供多种方法，思路清晰声音洪亮，知识点给我们一点就通。如果你材力挂科了，那我只能说多找找自身原因。可以说，选到就是赚到，还会给我们发红包，这样的老师可以说是打着灯都不好找了，武门🙏🏻',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('659d8c899c4d834feac75b64',751,1652,'我们力院也要有自己的🐉哥！******声音小的一批还不清楚，感觉嘴里就像含着东西一样👍。上课讲一半突然开始拷打我们，我寻思你讲完会似是吧😅？平时分少的一批，一共20分的半期他布置两道题，答案不对步骤分是一点不给，就算答案对了步骤不合他意也是0分******
INSERT INTO "reviews" VALUES('659d84a84f66203748569136',751,1652,'师明星，力航的🐲，上课对着ppt念，例题是没有的，平时分是随便给的，考试改卷是死板没有过程分的，100的试卷，他可以给你改4分，著名评论家，材料力学朱志武，评价到当我看到学生们发的表情包，我只能咧嘴一笑，上过他课的学生，只能说，我以为龙文杰只是个笑话，没想到他居然也能发生在我的身边，力航成功打破模电壁垒，拥有了自己的龙文杰',1,1,1,3,19,0);
INSERT INTO "reviews" VALUES('659d82593a094c20e116e124',6941,6941,'英概也干了',1,1,4,6,1,0);
INSERT INTO "reviews" VALUES('659d7f152be3a26cec2d0bf2',751,1652,'四大名补',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('659d7bae90d3d1241d18608c',198,179,'神中神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d7b212be3a26cec2cecb6',751,1652,'选了他你就有福享了',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('659d7a659c4d834feac6e202',751,1652,'上课是听不清的，PPT是简约抽象的，平时分是保守的，复习资料是不给的，期末卷面是钻牛角尖的😅😅😅',2,1,1,4,15,0);
INSERT INTO "reviews" VALUES('659d77173a094c20e11686be',751,1652,'很有幽默感的老师，给分幽默，改卷幽默，分也是一分不会少给.',5,5,5,15,1,6);
INSERT INTO "reviews" VALUES('659d76264f66203748561fe4',751,1652,'老师讲的太好了，PPT有很多页，这个平时分也是直接拉满了，批改卷子也是特别认真，一分都不会少给。老师也特别幽默，连期末卷子都要给学生露一眼。',5,5,5,15,0,7);
INSERT INTO "reviews" VALUES('659d760b3a094c20e1167c29',751,1652,'力航学院第一杀手，看他教的另一科好像评价还可以，我的建议是跑，此人绝非善人',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('659d74eb3a094c20e1166fd4',751,1652,'“多年以后，当面对教务网上的数物成绩，他将会想起为了马克思主义基本原理的老师将数物老师改回师明星的那个午后。”',1,1,1,3,32,0);
