INSERT INTO "reviews" VALUES('659d74954f66203748561296',751,1652,'老师太棒了 平时分给满呢 ',5,5,5,15,0,4);
INSERT INTO "reviews" VALUES('659d732e4f6620374856039d',751,1652,'******平时成绩40给20，一点不捞',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('659d71de2be3a26cec2c921e',751,1652,'谁来谁知道',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('659d6f789c4d834feac66fb6',185,185,'讲课太催眠了，一般人很难不睡着。ppt做的还可以，建议上课自学。给分相对其他工程电磁场老师偏低一点点，（因为实验要严格一点）',5,1,4,10,0,0);
INSERT INTO "reviews" VALUES('659d690f2be3a26cec2c37e7',359,228,'老师很好呢，好温柔，直接给满，上课积极发一下言，一学期发言5次就满昏了，讲话温温柔柔的，强推！',5,5,5,15,1,5);
INSERT INTO "reviews" VALUES('659d62104f66203748554adb',2323,92,'你只管考到40，剩下交给爹',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d4b892be3a26cec2aa170',909,6957,'生物技术制药这本书很好，因为我基因工程期中期末复习全靠它ʘᴗʘ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659d48cc90d3d1241d15ef52',1065,1065,'说真的，没想到在毛概这门课上能碰到这么好的老师。人美心善，上课风趣，期末还会划重点。最重要的是，平时分给的很足，只要你上课回答够问题了，平时分直接45+，我就直接拿到了50分满分。平时上课的时候，只需要稍微听一下，老师讲课非常易懂，就算是理科生也可以听得透透的。总之一句话，选晴晴，你选不了吃亏，选不了上当，如果你想在毛概这门课上大放异彩，现在就行动起来。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659d46044f6620374853c60f',1065,1065,'人美心善啊啊啊啊啊啊啊啊啊',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659d45c290d3d1241d15cb7f',452,965,'就是神',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('659d3ffa90d3d1241d158b0a',573,573,'老师平时分给的挺高的，平时分40分，能给个34分，已经很不错了，而且也够用了，这要是再考不过，那就真的是自己的问题了',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('659d3fa22be3a26cec2a192a',573,573,'老师认真负责，讲课有意思，而且平时分给到很高，我有两次缺勤，作业还没交，还给了我34分，无脑冲就完了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659d37df9c4d834feac3bf65',4669,1170,'上课只念ppt，考前没有提纲，好多章节就让你自己看，',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659d36f79c4d834feac3b4f0',1065,1065,'守护全世界最好的蔡蔡，平时分50分，直接给满！！！我室友一次问题没回答，也有45！（有5分的课堂表现分，你只要回答5次问题 一次一分，不会在意你回答问题的质量，只在乎你回答问题的行为！！！），期末会叮嘱各种注意事项，并且有同学询问，她基本上秒回！秒回！并且老师人巨漂亮！！！上课偶尔会考勤，但是会在点名前提前通知！所以选她选她，谁不选我蔡蔡我真的会伤心T_T！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d369e9c4d834feac3b078',449,3822,'满分',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('659d34d49c4d834feac398b8',1441,228,'给分没那么想象中的好，50给43的样子吧，但是人还可以，你是卷王当我没说',3,3,4,10,1,1);
INSERT INTO "reviews" VALUES('659d347d4f662037485303af',1065,1065,'蔡老师简直就是人美心善的代言词好吧，平时只要回答满五次问题就能拿满表现分，不考你回答的水平，回答了就行，期中大作业认真做一下就能满，全宿舍三个人平时分满分（另一个5次问题没答完扣了三分），上课也很轻松老师讲课也好，很多时候还会放视频水课，最后还画了重点两个大题就是，谁不选谁后悔好吧😥',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d31af3a094c20e113312a',1065,1065,'老师人美声甜，课上只要不缺勤、回答五次问题（还都是很简单的问题）就给了满的平时分，期末也划了重点，真的是特别特别好的老师😍晴晴😍',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d2bef4f66203748529c88',6277,6277,'老师很好，很和蔼，还捞我了就我一条狗命感谢老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659d241a3a094c20e1128c5f',346,56,'从小学到现在最好的体育老师，哭了，多幸运才能加入樊老师的课堂啊。抢到就是赚到！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659d208f3a094c20e11266fc',887,23,'强推啊，是那种特别负责任的老师，如果你想好好学习的话会学到特别多的东西，人特别好有亲和力，上课要去上但是不点名，无脑选，我中期考试就她这一门过及格线了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d11c190d3d1241d137ec7',4668,6972,'不知道这个老师是不是生活不如意，课都不来上，成绩不公布，平时分巨低，只知道让学生写论文，除了吹牛一无是处，太不敬业了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659d0ec94f662037485162be',891,114,'真正的“母亲”都是慈祥的！！！哪有“母亲见不得孩子好的！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d0df490d3d1241d13535e',989,989,'逆天老师，考前画的重点基本没用，教信院电力电子期末没有填空，就一道计算题，其它全是原理概念性的简答分析，平时就照PPT念',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('659d0dda4f662037485159c0',315,40,'总体来说，想平时分高一点就要上课讲内容，背她规定的内容，完成这些平时分就高，想混还是不要选为好',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('659d09c32be3a26cec27cd4c',1455,87,'我的神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659d08684f6620374851243c',315,40,'快跑，交大唯一神棍',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('659d00cd90d3d1241d12cbcf',504,5,'无脑冲 上的老师的高数1 人很好 讲课也挺好的 下课会在群里发PPT 周末会组织答疑 上课也不点名不怎么管 我坐中间前排玩手机都没事 课堂小测只有两三次 要么很简单要么就是练习册上的原题 最后平时分是真的拉满了 暖暖的很安心 我看期中成绩也是期末才传上去的 估计老师看情况还会改期中成绩再捞一把',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659cf0413a094c20e1108df9',2584,40,'吴老师人美心善事情少，但是没有回答问题给我平时分50不到',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('659cefe590d3d1241d122aea',359,228,'******作业都有完成，也没缺勤，平时分就给80分😅',2,2,2,6,4,0);
INSERT INTO "reviews" VALUES('659ceb8f2be3a26cec26ab05',176,176,'年轻老师嘛 虽然重点不突出 但是耐心推过程啊 刚开始没经验而已 普通话虽然广味有点重 那就看你们自己了 但他是真的懂大学生啊 不点名 作业随便交 给分还不清楚 强推！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659ce33a9c4d834feac04d64',5732,296,'感谢老师的矩阵分析期末课程🙏🙏',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659cde0a4f662037484f84b4',430,194,'上课幽默，不管迟到，偶尔点名，手机不是用来娱乐不管你。考试不怎么捞，但考得不是那种擦边或者不及格的话，平时分就给你几乎拉满',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('659cd16b4f662037484f097b',1307,1307,'刘哥人温柔又帅，上他的课很轻松，几乎不点名，实验和实习也非常人性化不会为难学生。平时分几乎给满，期末裸考都能随便过🥰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659cccea3a094c20e10f33f3',1287,40,'平时分91🥰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659cca232be3a26cec2559cb',2654,40,'平时分就50上下浮动，这门课其他老师平时分都在55左右，她给分偏低，给分很细，就按照表格来的，平时事不算多，上课会点人回答问题，答得多可能平时分会高点，或者组里面有人答的多也可以，第一周就会说，她平时分可能给不上50，最后还是给上了，反正平时成绩就是按时完成作业，六级测试考好，这些分她是实事求是的，能浮动的就平时课堂，也就占5分。但是她给分就是不高，室友是其他老师，平时分都是55、56这样',5,3,3,11,0,1);
INSERT INTO "reviews" VALUES('659cc8d73a094c20e10f0d9b',551,551,'3学分的计网硬是被你搞成4学分的感觉。人计算机专业的半期点到代替考试，你高低拖到14周专门出一套题考******也要自己单独出一套题，你平常口口不离的谭教授的题你嫩是一个不出******做个课设提前一天在群里催，期末考试提前15分钟在那里说交书包要发卷了，你急得很，让大家都寄得很。一口川普一秒几个字，一节课下来嘴停都不带停，不用喝水，不当rapper可惜了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659cc68a4f662037484ea22f',526,1651,'怎么说呢，平时分给分真的很严，大图有明显的错误都会扣分，但作业的平时分应该是认真做了就高分吧。在qq上面问问题也能及时回，而且挺耐心。
