INSERT INTO "reviews" VALUES('659b933b9c4d834feab6a86f',3484,3484,'主要问题是这个实验事情有点多，好在难度不是很高。代码基本上都是现成的，只需要去连线和自己敲。报告画流程图虽然有点麻烦，但比好多实验轻松多了吧。预习基本就是抄书上画书上的图。给分也挺宽容的，错了有改的机会。还有个补充实验要自己做，这个挺费时……期末考试也不算出得特别难吧，熟悉实验内容就差不多，能接受。',4,4,4,12,0,0);
