INSERT INTO "reviews" VALUES('659aaed29c4d834feab11426',170,233,'凭心而论，老师本身没有什么问题，这门课吃想象力，你想象力好一个学期啥也不学照样考80多，老师讲课很枯燥（本身课也没意思），作业挺多，平均一次作业自己做的话3小时打底，CAD靠自学，平时分助教给的，按点给分，导致大家分都不高，平均七八十，期末考基本都是做过的原题，这个老师不会捞人，只能说想摆的就快点润',3,3,1,7,1,1);
INSERT INTO "reviews" VALUES('659aa0d99c4d834feab072f2',2302,2302,'课不会上，分也不会打是吧
INSERT INTO "reviews" VALUES('659a97599c4d834feab00ed3',2432,2432,'老师人很温和，讲题目很细致，每节课PPT都会发在群里，只要期末考到他能捞的动，必定捞。强烈推荐',4,5,5,14,1,0);
