INSERT INTO "reviews" VALUES('659a8d123a094c20e1ff5c20',7062,779,'讲得不好，听不明白，声音又小，还喜欢抽问，实习的时候操作也不讲清楚，平时分还乱给，谁选谁倒霉',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659a88822be3a26cec1563d0',1537,1651,'大一一年的工图老师都是她，大学里面难得的对学生这么负责的老师了',5,5,5,15,0,0);
