INSERT INTO "reviews" VALUES('659a793090d3d1241d002e0c',398,85,'考试难过，给分贼低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659a77bd2be3a26cec14cb07',4510,1825,'第一次给她的评价口吐芬芳被删了，那就再来一次正好这学期上完了。首先，课堂表现也就是所谓的平时分，只有回答四次（小组两次，个人两次）以上才会给，只要没达到这个数量，给零分，即使你全勤加作业全交也是0分。然后大四的课程，每节课会写一次课堂测验，一共三次需要上去放ppt的汇报，******大四了谁给你与，整个班级民不聊生，怨念滔天。他还振振有词上了，属于是不得理不饶人。再说三次小组汇报，不论你做的什么样，他都是一顿乱喷，从头黑到尾，主打的就是一个你做的不行，改几次都是不行。我也上过一些大雷比如什么蒲世勋之类的，但是这个老师真的比他们离谱太多，上辈子杀人放火，这辈子她给你上必修。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('659a63cb4f662037483d8f61',78,78,'整本书都是重点 交大土木的未来！',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('659a62b99c4d834feaae180c',2726,7070,'非常好的老师，会划重点，会教我们很多知识，包括常识，还会捞人，讲什么重点就考什么，非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659a62594f662037483d81c5',168,168,'非常好的老师，讲课引人入胜',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659a5d8e4f662037483d480a',122,122,'感觉大多数金属老师都挺抽象的，赵君文算是头等恶心的那一类。上课口齿不清，还怪我们不认真听讲；要提问的时候，故意不把题目说清楚，而且只问一遍，就抽人回答，回答不上来可能还要扣分。如果他自己有时候错了，也不承认，直接糊弄过去，也不承认学生是对的。还有给分巨低，我们年级最后总分上80的半只手都数的过来。另外，它是看心情捞人，你学的好也大概率不给你高分，你学的烂它倒是可能会捞你，反正我觉得就挺离谱的。唯一的优点可能就是上课会带一些实际的铸造件什么的，你可以实际看到长什么样子。
INSERT INTO "reviews" VALUES('659a4f354f662037483cb373',6,619,'天天让学生发言,你是翻转课堂还是颠倒课堂？往那一坐什么都不干，课都让我们替你讲了，工资能不能分我一半？快期末了在那奖励发言一次算两次，以为自己很善解人意？那之前发言满三次的算什么？上课什么都不讲，期末考试不给划重点，期末自测复习资料题也不发，期末论文打分对比其他教学班也压分，老师你是有什么心事吗？',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('659a4a234f662037483c7ba6',345,96,'针对数据挖掘这门课，好评！一学期没去上课，考试前一天速通教材原题，平时成绩和期末成绩几乎拉满！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659a469b90d3d1241dfe1b16',532,141,'没上过你的大物课，就上一节你的大物实验课都要恶心我一次。抽回答个问题错了就一直嘲讽，打的分也是一学期所有老师里最低的。没事跟隔壁王续宇学学',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('659a31f69c4d834feaabf8e0',442,573,'2024年1月7日，结构设计优化出成绩的一天，居然被捞起来了，而且助教说了是老师本人改的。平时上课会点名啥的，大四的课准备考研会被说几句，脸皮厚点也都不算事，来了交了作业就行。我本来听了网上的这些传闻，一点期待没有，然后没想到过了。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6599fd842be3a26cec0fac11',1493,1493,'不知道为什么这学期给分给的比较严格，平时上课是抽四五个或者干脆不点名，有一个老师搞了一次手势签到。如果你写了论文，做了报告，刷了网课这一套全部下来才92，不如同一类别的大学生心理健康。建议出门左转选曾毅一学期都没啥事轻松98',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('6599ed3b4f6620374838cc54',42,43,'******给分确实还行，但是其他实验课老师给分也高，而且还不会恶心你',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6599dd693a094c20e1f8bed0',3473,3473,'有水平，有意义，给分合理。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6599dced3a094c20e1f8bcfb',1493,1493,'事多（一次报告、一篇论文、两门智慧树），分还低。',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('6599c1e890d3d1241dfa1159',459,40,'我真的，崩溃，那个平时分出来的一瞬间我整个人都是懵的。分数组成不细说，和学生不直接交流，自己上课在上面一坐就是讲，一扯能扯到课外半节课，最后平时成绩也给我们看，就给了几个名单说是谁谁谁的哪项没分。平时测试还有什么论文书写多少分也不说，纯纯自己在那里搞。本来觉着人看着是比较和善，结果给平时分你给的那么恶心？别贪她的课水，不检查作业，想拿高分去别的老师。',1,1,4,6,6,0);
INSERT INTO "reviews" VALUES('65999b4590d3d1241df99800',222,852,'真的超爱这个老师，讲的好还负责，半期期末还给你发往年卷子的图片和答案，不用去打印店买，不选就是错过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659988d42be3a26cec0dc107',5924,5924,'不水，平时模式基本是讲一周，讨论一周（需要交读后感提纲）。期中考试是presentaion。这门课很有意思，是我这学期最喜欢的课，了解了很多的书。老师还请其他老师讲了一周，还有一周去图书馆玩，馆长亲自讲解。但是现在在期末周中2000字且要查重的期末读后感搞得我心力交瘁了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659965294f6620374835b408',5581,5581,'老古董，死板，平时分就按照作业给分，不如纪录片那些，作业让你欣赏小提琴，要认真听分段落，上课要互动答题，一道题30s，还得好好听，太死板了',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('659956063a094c20e1f52501',5460,5460,'最好最好的小加州老师🥺课堂氛围好，老师价值观也非常正，特别特别温和可爱的california，请永远当我的老师吧！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659951c93a094c20e1f4f6ef',7086,7086,'喜欢我们快期末时把群里发的所有资料撤回的boren老师吗？******',2,1,1,4,3,0);
INSERT INTO "reviews" VALUES('65994f739c4d834feaa5385a',2302,2302,'快跑吧，上课给你做数学建模，课胡讲一通，极其不负责任。两节课吹牛一节半，剩下半节课胡讲。说平时分全部都给85，到最后只给80。无语了',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('65994f699c4d834feaa537f1',6941,6941,'****** 英国概况上的什么玩意，讲了又好像没讲，根本听不懂。考试更是恶心无比，平常按专题上课，考试按时间考😅，分给的奇低无比，让人挂科好像能显得他很有水平似的******。还让人给他上课提建议，但坚决不改，呵呵******',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('659949d82be3a26cec0ace88',5581,5581,'我作业什么按按时交了，课也去上了，最后平时分给了70我真的绷不住了，就一个选修课，我听那小提琴名字还挺优雅的******没有点小提琴的基础还不配拿高分不配选你这门课呗，每次上课晚上必拖到9点20******我寻思着一门选修课你要这么严格？我们大家都是来欣赏音乐的，还有，我们期末周，你挨个@群里面的同学批评他们的作业问题，你不知道我们都要复习都要考试的吗******',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('659947983a094c20e1f47f10',459,40,'平时分给的超级低，天天拿自己班和其他班比较，如果你在那个坏班，那么恭喜你平时分只有40出头，当然平时分总分60，哈哈哈。',1,2,1,4,4,0);
INSERT INTO "reviews" VALUES('659944ea2be3a26cec0a9737',68,40,'去年上的她的课，给其他老师打了好评，想起来她。非常窒息的课，我甚至很疑惑这是我交的老师？我交的课堂？尖酸刻薄的代表，特别爱恶心人……退一万步说，上她的课你别想提高任何英语水平。最后给我的成绩是48/60，中规中矩吧，但我的表现肯定是没有任何问题的，因突然手术请假两次，均给她发了qq我的一切证明，并在回校后第一时间交给她我的证明，她都没认，当众说我算旷课。噢噢还有，该老师明确说在下课后别烦她，虽然我也没事找她，找她也p用没有，但还是想说一句，这是你当老师的态度吗？',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65993e5d2be3a26cec0a4fed',1291,7092,'非常非常无语，2个学分的课，比6个学分的事还多！曾老师上课很用心，课后作业极多，课设非常繁复。表面很温和，笑面虎一枚……我就一节课没去，课堂表现70（我理解），课设70（非常不理解…）平时成绩极低。上曾老师的课，别的没什么，小心被背刺哈哈',2,1,1,4,4,0);
INSERT INTO "reviews" VALUES('65993ddc90d3d1241df5a08a',1291,6837,'没有缺勤也不打满平时分，课设要求巨多，而且课设没有模板，自己去查，然后阶段性发要求来折磨你，考试前两天还要求看课设然后有问题去修改，看起来很亲和，实际上偷偷给你打低分，是我目前见过最离谱的老师。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('65993a794f6620374833b7e5',2122,1542,'光哥yyds，最对我胃口的老师',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('6599371e3a094c20e1f3cf36',7095,7095,'有机会吗？有机不会？没关系，相信肖神，期末就差把原题告诉你了，要考什么说的明明白白，平时也是直接拉满了。
INSERT INTO "reviews" VALUES('659936099c4d834feaa41cf0',563,228,'这学期选了浦仕勋老师的课，不知道老师以前啥样，但是这学期的体验还是足够让我给老师一个五星好评的。作业就是正常的要求水平，一学期点名五次，不缺课的话一点问题没有（真不想去了也可以让同学给你发签到码），半期考试开卷一道大题，很水，期末给分也很高，中间还有一次因为天气太好了带同学们出去晒太阳，是我比较喜欢的老师了',5,5,5,15,7,2);
INSERT INTO "reviews" VALUES('659934c92be3a26cec09ea47',7095,7095,'考前把重点划的明明白白，平时分直接拉满，上课很偶尔点次名。肖神伟大，无须多言。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65992dd53a094c20e1f3672f',7098,123,'好老师，期末随便考就过了，上课温柔亲和',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6599126f4f66203748320c59',2302,2302,'胖胖的样子真可爱，大家猛猛冲，期末考看我考的低，专门调了占比，给我拉高了分数，上课不点名，平时没作业，猛猛冲就完事了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65990ff79c4d834feaa2741e',2302,2302,'是人我吃',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65990f3f2be3a26cec084bc4',563,228,'怎么说呢，最近马原进保研课程了，老师的教学方式可能也变了。给的平时分很高，总共才签到5次，我室友缺了一次也给90。而且老师也没有那么严，讲课的时候基本是按照自己的理解来讲，可能不看书听不懂他要讲的核心思路是啥。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('659902fb4f66203748317723',294,294,'人麻了，兄弟们自己体会，全勤，平时分给七十。 。。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6598f51f3a094c20e1f127ab',2047,28,'平时分除了随堂测试，其他全拉满，出乎意料，就靠平时分让我总分好看一点',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('6598f4bf2be3a26cec0749f5',170,170,'通宵画图使我的牛牛转不起来',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('6598f4983a094c20e1f12173',7105,760,'很好的老师，点名使我的牛牛旋转',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6598f4183a094c20e1f11b97',170,170,'快跑！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6598f2ea4f6620374830db45',7105,760,'好评，老师一学期就点一次名，作业全是在学生系统写，不需要动手',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6598cba53a094c20e1ef7461',2302,2302,'真跑，不开玩笑，平时分低，加上去的中期作业全体80分，最后全班的平时分都是82.5，期末考划重点也是奇葩（但不点名不挂人）想要冲高分的别来',1,5,5,11,2,1);
INSERT INTO "reviews" VALUES('6598c82190d3d1241df0c96f',459,40,'老师虽然上课水，可以做自己的事情，而且布置作业也少但是基本不检查。一学期学习通签到了三次。但是平时分不高，而且只在最后一节课上课给大家看一个看不懂的平时分，而且是没有算慕课的，所以我也不知道平时分都扣在哪了。',3,3,4,10,4,0);
INSERT INTO "reviews" VALUES('6598c58c2be3a26cec055a82',7110,7110,'平时分三项，①课堂表现去上课就是满分②学习通作业，都是选择题③期中作业，身边人几乎都90+
INSERT INTO "reviews" VALUES('6598ad0e4f662037482e08e0',2012,296,'叠',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6598a58c4f662037482dcdb0',7112,7112,'快跑！！！！！这门课不仅平时要做特别多的报告，期末还要考试。而且期末还要做额外汇报，完事还有个人报告。报告要求董铁军也不讲清楚，都考试了又临时改报告要求。你一个选修课整这么多事你配吗！！！！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('659834792be3a26cec028982',459,40,'就最后一节课给我们看了某些项的平时分，但是又不说是什么东西和总平时分的构成，想要找她看个平时分，需要通过课代表（因为她不进班级群），还要报名字学号才给看。哎，喷就喷在给分规则不详细，不公开有xlsx为什么不能发出来呢，那么多人有异议为什么不在群里解释呢，只能说高高在上不下基层。课上没怎么讲课文，就是讲如何写论文，拍ppt，很少下讲台，可以做自己的事，平时的作业有学习通慕课视频加quiz，iwrite上写introduction，outline，conclusion等论文部分，有小组视频作业，不能算事少，期末考六级卷靠自己。总结给分不透明，分少，想分高的慎来。',3,2,1,6,6,0);
INSERT INTO "reviews" VALUES('6598190690d3d1241dece320',2885,3822,'人很好，平时事也很少很少，给分还可以吧，有7分加分最后平时分56/60',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659818644f662037482b2d03',459,40,'看到平时分的时候直接原地暴毙而亡，为什么为什么为什么为什么平时分给得那么低啊，慕课和Iwrite那确实是自己拿分就算了但是为什么不给我们看看其他的平时分呢我们甚至不知道自己的期末论文写得咋样简直太神秘了',3,3,3,9,8,0);
INSERT INTO "reviews" VALUES('659814dd3a094c20e1eb354d',1379,346,'给老师磕一个，本人慕课报错一节没看******最后纯靠平时成绩和期末给我拉到八十了。神不多说，期末只要打完就有90+。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('659813bd3a094c20e1eb26bc',7112,7112,'按下面3个都可以得高分，但是我不想给，真的。一门选修，没完没了的PPT汇报，还有一份像样的期末论文，还要考试。考试的综合题叫我自己创造一个轨道交通模式，，，',2,2,2,6,3,0);
INSERT INTO "reviews" VALUES('6598128c90d3d1241dec9634',1175,433,'平时考试管的很松',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('659812743a094c20e1eb17b7',1001,2381,'上他的课有时候也是挺无助的
INSERT INTO "reviews" VALUES('659812582be3a26cec0151b3',7120,1267,'好混，每节课都会点名的，不过我只去了3次还是有80分',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6598123390d3d1241dec91ec',7112,7112,'一门选修课一个学期做四次小组汇报，讲完了还要答辩，最后一次答辩三个老师坐着听，完了期末闭卷考试，还要写期末报告，不是你事怎么这么多呢😅',1,1,2,4,2,0);
INSERT INTO "reviews" VALUES('6598122a3a094c20e1eb145e',2584,40,'其实按评分的3个标准都能5分，但是看了我的分数，我给不出高分。幸存者偏差，选风评好的老师也会有崩盘的风险。后两次作业格式规范了比前两次不规范格式的分数还低，自己写的。',2,2,2,6,4,1);
INSERT INTO "reviews" VALUES('65980a114f662037482a7d7c',459,68,'皇帝',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('659803304f662037482a2b95',4305,4305,'故意压分',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('6597fdda2be3a26cec005ad2',5581,5581,'非常恶心的一门课.....分数是上课每节课雨课堂回答上一讲课的问题，对一题0.5，就五道，全部答对再加0.5上限3分，******互动就占30分，我请问呢，每次回答30s，搜都搜不过来，难不成一门选修，我还给你复习😅😅😅。一次平时作业15分，写两次平时作业，累死累活的不说，叫你赏析音乐片段，一点基础没有的怎么赏析啊，作业内容叫你写各段落的起止时间和表达内容，只要写不对那次作业就50分以下了最后的期末报告写一万多个字，真的服了******',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('6597f3339c4d834fea99e5cb',1955,194,'你们甚至不愿意叫他一声左爷😎',5,5,5,15,10,0);
INSERT INTO "reviews" VALUES('6597f2352be3a26cecffd895',823,380,'如果教学也有战绩，我愿称昆姐为游龙🤗',5,5,5,15,10,0);
INSERT INTO "reviews" VALUES('6597f0119c4d834fea99c320',2885,40,'英语公共演讲，认真准备演讲，认真做作业，按要求完成课堂参与，平时分就会比较高，老师人也不错，留个好评',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6597e9aa9c4d834fea99786f',563,228,'很不粗，老师我觉得很不粗的，就是点名是个问题，不建议喜欢逃课的选，签到签了，实践作业交了，这学期因为一些事只有几个组汇报了，老师平时分给了97，课一节没听，还有次天气好，老师带着我们逛校园，和老师谈了一路我觉得老师人没问题，就是签到的时候要注意老师课上签到一直玩手机的话错过了签到可是要拿证据证明你去上课了的',5,5,5,15,5,3);
INSERT INTO "reviews" VALUES('6597e1f74f6620374828b37c',540,1897,'电分1和2都在刘老师这里，刘老师特别好，而且很温柔，没有大学老师那种严厉感，但是又有很高的教学能力，你问啥都会给你耐心解答，很好很好的老师，非常赞，总之特别的平易近人教学能力高，上课一听就懂，最爱的电气老师!',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('6597e0e43a094c20e1e8d694',459,40,'原先冲着这个老师人美心善来的 结果可能是风太大了 到现在都不知道平时分的构成，上课给我们看了一个慕课还没出的平时分表，老师也未解释每一栏的分数组成。。总共上课签了三次到，可能平时事是比较少，就几次iwrite和一次视频，但是最后分真的很低!！想得高分的同学速速run！！！别只图事少！！！！这个平时分我闻所未闻！！！低到离谱！！',3,2,5,10,9,0);
INSERT INTO "reviews" VALUES('6597d60e90d3d1241de9e09f',604,5,'老师yyds，只要作业每次都交，课堂测试（他甚至会讲然后让你边听他讲抄答案我哭死）交了就可以，平时分直接拉满，点名几乎没有',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('6597d3852be3a26cecfe8848',604,229,'伟大，无需多言/::+，之前发的时候手滑了没给小凯5.0，补一下😋',5,5,5,15,0,2);
