INSERT INTO "reviews" VALUES('6597c6ea3a094c20e1e7b046',1265,1265,'不错',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6597c40690d3d1241de9127b',1955,194,'这是一条非常客观的评价，先说结论，左董老师人非常好，很感谢他，老师很打动人的几个点：1.除了半期，平时分直接给满，注意是直接满分的那种 2.左东老师自己编制的练习题非常有用，做一遍对考试很有帮助，并且老师会自己做一遍，把详细答案过程发在群里 3.考前有专门的答疑时间和地点，课后或者平常问问题老师也都会解答 4.给作业补交的机会，真的会用心提醒大家 5.上课从不点名，就算想水课也完全可以选',5,5,5,15,6,0);
