INSERT INTO "reviews" VALUES('6596b7de3a094c20e1df5101',48,48,'凶，脾气不好，累死累活一学期最多给你八十几分。事多话多还怕麻烦，有问题永远让你自己解决别找她，平时分随心所欲地扣，没有下限，可能会倒扣课程分，羽毛球唯一真神。',1,1,1,3,4,0);
