INSERT INTO "reviews" VALUES('6596b38790d3d1241de09795',278,228,'早就对加拿大女王的名声有所耳闻哈哈，但一学期下来我觉得老师上课还是比较专业的，认真准备了PPT和视频，讲的也很好，上课还会划重点。就是态度确实像传言一样，老翻白眼，老抽问，想得点平时分太难了，上课还不让玩手机，不让带耳机，不能迟到......想认真学的uu推荐选她',4,4,2,10,3,3);
INSERT INTO "reviews" VALUES('6596b2592be3a26cecf5459d',2170,6490,'平时作业少，老师特别温柔，脾气很好。上她的专业课有一种在上水课的感觉，老师也不管上课听没听，也从不点名。只要按要求完成作业，平时分基本都是满分。就是老师讲课讲的一般般，感觉听不进去QAQ',5,5,4,14,4,0);
