INSERT INTO "reviews" VALUES('6594da994f662037480e27e3',7190,1910,'眉亩',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6594d99f90d3d1241dcff30a',3821,4204,'不知道下面在说些什么屁话，本来大学全靠自学，老师知识储备很足，上课风趣幽默跟你讲很多书本里没有的东西还不好吗？作业都是固定每节课下课后交待，你不影响上课想干什么干什么，平时分很高，英语水平差不多就能过。',5,5,5,15,4,1);
