INSERT INTO "reviews" VALUES('6594d7f44f662037480e0c8c',1441,228,'平时分拉满，期中考试错过还让补考，划重点直接一道大题，上课讲的也非常非常好，遇到的最好的老师没有之一，看到有她的课就赶紧抢，别犹豫！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6594d6d49c4d834fea7e829f',92,22,'马老师水平很高，而且特别和善，可以加好友，平时有问题直接问，没有一点架子超级友好，对学生很热心，期中考试你要是学会了考八九十没问题，讲问题也非常耐心，有问必答。',5,5,5,15,0,0);
