INSERT INTO "reviews" VALUES('65945ba12be3a26cece209b8',1108,1065,'我那年三生有幸被迫选了吴老师，一个班30+的人，估计她自己心里也有数为啥就这几个人，那一年完成了基本任务，多数考勤在的学生平时分都是满分。',1,1,5,7,2,1);
INSERT INTO "reviews" VALUES('659458e99c4d834fea7bf2bc',7197,80,'老师知识相当扎实，上课思路清晰，平时分也高。爱死了。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6594572d2be3a26cece1f83e',6434,73,'积了大德，祥瑞通天',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('659443604f662037480ad98a',176,176,'老师人很好，每次老师都会找往年的题，不考勤，作业没交也给很多机会补交，人很好很好很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65943eb93a094c20e1cb199c',604,96,'万佬我哭死，嘴上说着不爱我都是假的，上课提醒我们不要耍手机，不然很容易挂科，还揪出了几个上课玩手机的，然后期末发现平时分给满了',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65942b1c90d3d1241dcbbfa0',1320,40,'老师人很好，上课很认真，水平也很高，作业很少，但是给分一般偏低😅',4,4,4,12,0,0);
