INSERT INTO "reviews" VALUES('659421854f66203748096373',5674,5674,'还是很不错的，除了刚开始和期末，其他时间都不点名，算是美育里面事很少的了',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('659421314f66203748095ede',1287,40,'好好好，上课很水啊，不会管你干什么，一个学期签到了2次，作业除了都有的没有额外的。给分也很不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65941fde3a094c20e1c9b1ae',6420,80,'易老师人挺好，就是课堂上是不是测试太玩心跳。讲重点时带过太快，有时候一不留神就没听明白了。平时分肯定是比你实际上的得分高些，但是想水的同学就算了，她习题不发，只让你拍照，ppt很精练，上课不听也不咋看得懂。。。。',5,3,5,13,2,0);
INSERT INTO "reviews" VALUES('6593f3859c4d834fea776b7e',1106,1106,'专业性是有的，就是态度我不好说。上他的课从来不敢玩手机，有节课一同学玩手机被他骂了。“你们爱来不来，我无所谓的”“我跟你们说我是会挂学生的，有的学生毕业一年了还来参加我这门课的补考”。
INSERT INTO "reviews" VALUES('6593e8292be3a26cecdcfe40',6721,6721,'前两个人说的没啥问题，本来就不是很重要的课，大家都60左右不上不下的，然后突然就莫名其妙有几个59的，你要是40，50我感觉都正常，59我难以评价，不过你们这门课基本上也就他一个老师，他上课听了也没什么卵用，反正对着PPT念一个学期，我上我也行，平时念PPT，考试给你上国家消防工程师难度，还有的捞有的不捞，与其抱着侥幸心理让他捞你，不如多把书翻翻，他真就不捞人，听说有人就差一分真的就差一分他给挂了。真的逆天',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('6593e7269c4d834fea76dd18',2170,6490,'老师人很好，平时分给得也很高，讲课也可以，差评有点尬黑了😅',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('6593e6d39c4d834fea76d92b',1175,28,'上的通用学术英语。老师很好的，早八可以迟到。虽然上课抽人回答问题，但是每次都抽那几个组长，大多数人不会被抽到，提问回答不上也会给你台阶下，不会说你。作业下课后都会马上在群里通知，很清楚。而且作业挺少的，都是书上那种十分钟不到就能写完的题，她也不检查。
INSERT INTO "reviews" VALUES('6593e1644f66203748060a65',725,40,'别看恶评，老师挺好的，而且事情少，看了楼下说通知事情，这方面有时候群里通知确实较少，但是课上其实都会说，上课如果没人回答问题会抽问，回答不对也没什么关系，而且自己举手会加分，只要举手就加，真别看其他恶评😓',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('6593df2d9c4d834fea76852d',6721,6721,'******真把自己当什么了，给学生两分******，选到他就等着随机挂科吧😁',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('6593dcf83a094c20e1c6374f',867,28,'竞赛和六级额外加6.5分，没有回答过问题，线上作业差一次，最后54.4/60平时分，给分水平大家自己斟酌。但是课确实水，人也比较温油，习惯性给5分了（我是学术英语）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6593db889c4d834fea765c4d',6721,6721,'开卷是开卷，但是我就想问问你，就卡那一分有什么意思期末多一分及格，你偏得扣一分有意义吗。你要是真恶心都别捞呗，那么多60然后随机选个59是吧',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('6593d5f29c4d834fea76219f',11,11,'很水 上课不管 也不点名 就是网上的作业有点多 不过认真刷完平时分还可以',4,4,4,12,0,3);
INSERT INTO "reviews" VALUES('6593b7564f6620374804637a',1273,157,'想水的别来！想水的别来！想水的别来！期末考很严很难，上课会盯住人，给分也一般，热爱排球的可以选择，想水体育的别选！',4,5,2,11,2,0);
INSERT INTO "reviews" VALUES('6593b6bf3a094c20e1c4ba16',598,28,'老师人很棒！！上课管的很松，给分高，上课回答问题可以加平时分，答完问题随机抽查就不会点你名，随便水。fif口语没做完会再布置一次补交，也可以补交平时的作文等等，人美心善的好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6593a58c9c4d834fea743830',345,96,'两次随堂测试，要排座位，运气好稍微靠后一点就可以随便作弊，监考助教都在最前面。但我运气不好，次次第一排，我朋友在后面抄了接近满分，我自己硬做。
INSERT INTO "reviews" VALUES('65939c943a094c20e1c3b0ed',68,40,'老师教的课真的很好，考试也不下来看随便抄，最后只扣了我期末写作测试的三分，最后给了57。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659395a22be3a26cecd9ad3d',1087,1087,'真心好老师，上课认真负责，思路清晰，课后作业适中',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659381f39c4d834fea72addd',1128,40,'只念ppt，上课什么都不讲，平时测试考试也不通知，别来沾边',1,2,2,5,1,0);
INSERT INTO "reviews" VALUES('65937fd82be3a26cecd8bdca',11,11,'亲和力还是不错的 上课虽然点人但是你不会的话他会自己解答，就是平时分磕碜的可怜，别了吧',1,1,2,4,3,0);
INSERT INTO "reviews" VALUES('65937f5d3a094c20e1c26f53',353,859,'考试，我只能说，他有PPT诱导法与反向预测法，老师人还行',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('659313fa2be3a26cecd6ba9e',1063,143,'恶心死了',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('6592e1292be3a26cecd5911f',2635,2190,'女神，水，分高事少，上课是一点课都不讲，讲以后找工作哪儿工资高，以后读研怎么选导师……狠狠爱了😍😍😍😍😍😍😍😍😍😍',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6592df574f66203748fec6e9',1273,157,'大一时是卢立宝老师 好的不得了大二换她了。专业水平很高，表达也很清楚（要求比较多），亲和力没有，很严很严很严很严，要是排球打得不好或不认真可能有点危险，但会捞，挂科的人还是很少的，但要评先选优达到80以上很难很难很难，一个班基本没几个。',5,4,1,10,3,0);
INSERT INTO "reviews" VALUES('6592dd4a90d3d1241dc08d1e',68,40,'教的课还是可以的，就是那些主观的作业给分不太高，我本人自认为做的任何作业还是认真且不错的，但作业部分没到80%。课堂表现5分基准分3.5,回答一次问题＋0.5。本人最后平时分46分（10分课堂测试考了5分左右 可能有点低）原始成绩，无任何加分如晨读讲座四六级等。建议去选杨琼或者刘静都行',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('65929e2090d3d1241dbdc7ce',345,96,'赶紧跑路，宁愿下学期学也不选她。她的课不仅有限时练习，还有闭卷测验。******分开记分，还各记各的。我两回测验90分以上，给我扣了0.7分。课后作业评分还评分数，只要没全对，就扣分******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659299d44f66203748fbc938',413,27,'老师很好，无脑冲就对了',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65928a973a094c20e1bbbe83',2584,40,'吴山老师人很好，给分按规定给的，平时认真把作业写完，该有的分不会少。六级+晨读共计4.5的情况下，平时分56.5/60',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65927b929c4d834fea6b63ae',1175,433,'******纯纯被之前评价误导，怎么还有4.0的？给分低的离谱，作业一大堆，******懂不懂点名提问，快跑快跑!',1,5,1,7,0,0);
INSERT INTO "reviews" VALUES('659272c52be3a26cecd122e0',1770,3109,'严要求的好老师。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('659271ff4f66203748fa7629',294,294,'就这么说吧，评论里面评价这位老师的大部分是真的，关于点名，讲课风格。但是，在我有部分任务没有完成特别好的情况下，她平时分给了85，况且讲课不算差到离谱情况下，还是可以选的。',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('659271fc3a094c20e1bae195',7233,7233,'水，真的水，没见过这样上课的',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6592718390d3d1241dbc423d',1122,3041,'梁老师上课认真负责，对学生很不错。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('65926e9d90d3d1241dbc262a',1749,1409,'慕课不说清楚是哪些有几个，点名就算了，但考试给分有点太严格了，QQ消息也从来不回',3,3,2,8,0,1);
INSERT INTO "reviews" VALUES('65925e3f9c4d834fea6a55b3',808,140,'讲课温柔，分给的巨高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65925a534f66203748f995f3',1175,68,'通用学术英语，拍的视频分数全班倒数第一最后也有54.7  神',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6592571e90d3d1241dbb465d',2584,40,'57.3/60',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659243844f66203748f8974b',449,40,'慧慧老师真的好好，讲话温温柔柔的，给分也很大方，随便回答两个问题就50多，就算答错也不会说你，选就完了！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65922ffa2be3a26cecce7782',281,281,'真挺好的，平时分能给满的全都满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65922fd590d3d1241db9a952',281,281,'谢老师课讲的很好，作业留的也不是很多，只要你作业每次都交了，除了半期考试之外的平时分就是满分，能给的分全给了，冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65922f033a094c20e1b826db',42,42,'妈的模电实验最后本来是助教验的他还要来帮忙，只会说让你不要动他把所有的测量打乱了自己重新测，平常在群里也是谜语人一个',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65922e1c4f66203748f7c38e',228,228,'老师真挺好的，睡了一学期平时分还有42/50',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65922df09c4d834fea685a58',228,228,'老师人很好，上课时课堂氛围比较轻松，给分很高',5,5,4,14,0,2);
INSERT INTO "reviews" VALUES('65922dd32be3a26cecce6377',449,40,'任慧老师真的很好，课堂平时分满分5分不回答问题都有3.5，平常也管的松玩了一学期手机还拿了52分平时成绩，小测她也不会下来到处转',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65922cf12be3a26cecce5c99',449,40,'慧慧老师真的超好，声音好听，人也温柔，会冲你笑，鼓励你答题，基本不会强制挑人，答错也不会怪你，一般不会点名，给分也非常大方，我们宿舍3个人选的她的通用学术英语，平时分最低的也有50分，冲就对了',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6591d92e9c4d834fea66db99',1130,1130,'老师水平很高，但到这一届开始实验和考试要求都提高了，实验成绩给A的很少，还有随机的5次随堂测试',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('6591d7eb3a094c20e1b6a19a',571,6,'神，拿满平时分都不难，讲课各方面都很到位，为人和善，很难不成为大家喜爱的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6591d70f3a094c20e1b6a062',3446,4594,'因为是两分的课就给你讲的云里雾里的，发的ppt几百页，也是讲过的没讲过的都有。其他方面也突出一个随便。',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('6591c9064f66203748f628c4',1186,40,'平时也挺努力了 但是平时分给我好低啊😭',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('6591a2e52be3a26ceccc12db',2885,40,'四级582六级518雅思6.5（6）平时分56.2/60',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65919fb79c4d834fea65f07c',2584,40,'给分真一般真的，比其他班低，当然也比一部分高。给每个人的分都很平均，基本都一样的，如果实在没得选再选吧。但是上课确实很水，什么都不管',3,3,3,9,0,1);
INSERT INTO "reviews" VALUES('65919ba190d3d1241db71d27',2584,40,'******真服了，给分一点点，不公布成绩详细分数，平时分故意压分，适合摆烂的去，想高分赶紧跑。',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('65918f462be3a26ceccb74b5',1265,1265,'拉满了拉满了，余老师神中神，平时分60给了57，好好写作业，上课回答点问题，分就能很高，选她没问题',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659180403a094c20e1b4ab01',788,40,'上课水的不行，回答问题也不登记，上课喜欢发言和社恐的都一个课堂表现分，作业一个学期就只有4次作文，书上作业全都不用写，但是给分真一般',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('659170e32be3a26cecca3daa',725,40,'作为一个四级考了将近600分 六级550+的学生 而且上课经常回答问题 作业都完成的情况下 给了不到80的平时分',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('6591659090d3d1241db507f8',10,10,'想满分冲吴就对了！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659165079c4d834fea63c871',1441,228,'非常好，对学生很有耐心也很仁慈',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659164473a094c20e1b379ad',1157,52,'必须5分，神中神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('659163359c4d834fea63b690',1265,1265,'非常好，肯定不是他们说的那么差，只要多举手回答问题，好好做作业，平时分不会差。60的平时分拿了59，有史以来最高分就是余老师给的，yyds！谢谢余老师！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('65915ac12be3a26cecc959c7',7261,7261,'老师超好的，上课有趣轻松，给分高，选修课首选',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659159532be3a26cecc94983',7261,7261,'老师人超级好的！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('659150563a094c20e1b2a0a1',1058,26,'老师特别好，
INSERT INTO "reviews" VALUES('65914e1a4f66203748f24159',1225,40,'不怎么点名。一节课不翘，一节课不听，平常作业全靠gpt，期末论文直接抄，他坐讲台上一动不动头都不抬的。平时分给的比较公正，不低',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65913f2390d3d1241db36cdc',2197,876,'讲的很好，认真负责，什么时候问他问题他当天就会用语音给你讲解，特别好的一个老师给分还高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65913e9890d3d1241db368af',83,83,'莎莎老师好爱，哄着我们上课，讲课讲的特别清楚明白，还会时不时问我们跟没跟上，给分拉满，但是每节课都是定位签到',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('65913e153a094c20e1b1d96d',499,194,'给分拉满，讲课一般，自学佬可以选',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('65913da74f66203748f192c7',173,28,'事情多，给分严，加分还不能如实加，说英语竞赛最多只能加5分，不按照年级规定来，年级规定是竞赛不限',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('659131ca2be3a26cecc7aa54',96,96,'一p念到尾，不忘阴阳你几句。110个人的优选班只剩下十来个人，好好想想吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('659131489c4d834fea61a12a',1,1,'作业真的多，给分也不行，赶快润',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('65912a499c4d834fea615388',1225,40,'首先，我是个水哥，每节课都去，从来不听 上课也从不回答问题，也没有任何加分！！！去了就玩手机 期末论文都是提前打印直接抄，一有作业也都是直接百度翻译或者chatGPT，平时分53分，我并不觉得低，大家自行选择，反正我很满足',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6591290690d3d1241db28c73',1231,39,'太喜欢潘老师了 让我一个网球纯新手和菜鸟在一年多的时间里真的慢慢会打网球了 好开心🥳
INSERT INTO "reviews" VALUES('659128ee4f66203748f0be5e',430,194,'很好的老师 听不懂是我的原因',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659128b52be3a26cecc74750',7274,23,'比较水，想要学编程要自己努力，但是老师很好，喜欢雨课堂点名 但是老师真的很好',2,5,5,12,0,0);
INSERT INTO "reviews" VALUES('659128164f66203748f0b435',4149,1073,'很好的老师，真的很好 满分真的不过分',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('659127fe9c4d834fea613a85',1225,40,'为什么这么多低分的！平时分60给我56分\^O^/你就说好！不！好！ 讲课有很多拓展的内容 人也很有意思 总叫我们各位观众哈哈哈哈哈
INSERT INTO "reviews" VALUES('659127e44f66203748f0b25d',1727,87,'挺好的老师，就是期末考核对没有基础的太不友好了，对墙垫球60个才算及格，隔壁气排球25个就满分',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('6591276f9c4d834fea613420',1171,27,'******脏话连篇 整天没事找事，分给的还低，谁碰上倒了八辈子霉了',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('659109da9c4d834fea600097',360,1129,'没办法，自己好好学吧',3,1,2,6,1,0);
INSERT INTO "reviews" VALUES('659108204f66203748ef61f9',360,1129,'上课非常烂，枯燥无味PPT复读，关键是PPT也做的很烂，教材复读机，备课一点也不用心。考试非常难，给分非常低。突击考勤三次，缺一次直接少三分之一的分。不捞人，一声不吭把你挂了后面联系都联系不上（虽然挂的不是我）。实验要求又多又麻烦，花费大量时间，基本上全得靠自学解决。
