INSERT INTO "reviews" VALUES('65901a374f66203748e8792a',751,1652,'平时分真给的高吗？如高😅',3,1,1,5,10,0);
INSERT INTO "reviews" VALUES('659018484f66203748e8606d',345,96,'很烂很烂很烂很烂很烂，上课让助教放自己录的网课他人不来，让我们在教室看视频，作业交了之后不给答案，小测排座位，上课念PPT，巨快，不如自学，课堂练习没做对扣分扣扣扣扣扣',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65900fc73a094c20e1a840c3',345,96,'跑吧，课后作业不给满，课堂表现不给满，小测堪比期末期中考试，专业水平为0，就会看这ppt读，说话难听，最后快到期末考试了还小测，课堂练习都计入平时分，临近期末考试了不来，让助教在教室放视频，别选她的课，跑跑跑，大雷，威力加强版原子弹',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65900d8c4f66203748e7d7c4',345,96,'事多分少，一学期俩小测，冷酷无情，给分很低，快跑。',1,1,1,3,1,0);
