INSERT INTO "reviews" VALUES('658fc0de90d3d1241da695ac',7318,66,'我只能说不会打篮球的没有篮球基础的千万别来，来了就是纯纯坐牢。不知道哪里惹到他了就会体罚你，而且不允许在QQ上问他问题，线上请假从来不回你。',1,1,1,3,0,0);
