INSERT INTO "reviews" VALUES('658f76cc3a094c20e1a2bfbc',51,375,'很好的选修课，想水完全没问题，想听一些心理学案例她也讲的比较风趣就是声音小点。最后展示你只要ppt文案不错排版不错就98了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658ef5a62be3a26cecb7d638',703,228,'还好，作业略微多点，没有传的那么夸张，老师挺和蔼的，免考也挺容易的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658ef3d82be3a26cecb7c8ff',51,375,'曾老师的课真还有人那么低分啊，非常和蔼的考试，想要高分可以和她说明情况，只要你去上课，完成汇报，至少95',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658eb6cf90d3d1241da07088',209,209,'不多评，我是个有素质的人',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('658eb6b19c4d834fea4f204b',4482,157,'****** 没有师德，喜欢骂人，给分极低。排球打满50个给满分，他说扣点技术分。我打五十个最后只给了78，还一副施舍你的样子，牛逼。一学期被他骂好几次，包括但不限于打排球衣服穿太厚碍着他眼等。🙂🙂🙂大一大二我体育没下过90，遇到他80都没上，66666',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('658ea9973a094c20e19e474b',452,965,'每节课都有小测，小测按比例登，不管你期末考多少，平时分都按小测加，我期末考了81平时分只有78，对自己平时学习有信心的同学放心冲',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('658ea99690d3d1241d9fe47c',1812,7335,'法理学，啥都没干平时分100。老师讲的有意思',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658ea07e9c4d834fea4e349c',7336,7336,'什么都不用说，直接看数据，别的班均分80，他的班1/3挂科，剩下全是60分。想挂的选。学弟学妹们，感谢学长们帮你们趟雷吧。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('658e9ad03a094c20e19dbb5d',489,573,'个人感觉还好吧，作业量适中，写笔记给平时分奖励，有三次小组学习，不过小组学习要求也不严格。不过老师确实挺忙的，教学过程中常常会有工作的电话，表述也确实有些平淡。课程本身难度也不高，认真些能拿高分（本人就是高分）。
INSERT INTO "reviews" VALUES('658e995e4f66203748dd81d6',85,1614,'老师真的YYDS必选，老师慕课，期末考试，考勤都会给你加分',5,5,5,15,2,0);
