INSERT INTO "reviews" VALUES('658e827290d3d1241d9e6df0',22,22,'绝绝绝！教的真的巨好，上课思路清晰，还专门有录视频在学习通，平时分拉满，直接亲妈！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658e81e72be3a26cecb329d2',298,85,'非常好的老师，会认真教动作，让打球好的给基础差的多些指导，给分也很高，体育超市报了他的但没签上到后台帮忙给签上了。
INSERT INTO "reviews" VALUES('658e7db64f66203748dc7599',23,23,'老师超级好，上课互动非常多，而且单独找你分析你的情况，让你有学的信心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658e7d149c4d834fea4cdb5f',6420,80,'老师上课讲的很好很细，老师前半学期经常搞课堂测验目的是为了让大家都学会这门课，毕竟这门课50%的挂科率不是靠期末随便看看就能过的，但凡她布置的任务都独立完成了，你对这门课的学习还是多少掌握了知识的',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('658e7ca62be3a26cecb2eb09',614,4948,'老师的能力很强，虽然讲课一般',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658e7c6e90d3d1241d9e27c0',459,40,'老师专业基础扎实，给分不错，上课想听的可以学到东西，摸鱼的人她也不会管太多',5,5,5,15,0,7);
