INSERT INTO "reviews" VALUES('658e72df3a094c20e19c0478',398,48,'******Mook成绩有问题，反应直接摆烂不管，不要体育成绩的大胆选。交大这种老师能不能给开除啊',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('658e725c9c4d834fea4c4dfe',592,194,'老师非常非常好 从来不点名 年轻有活力很温柔 对学生超级好嗷  跟学生相处很和谐 作业老师都是帮你挑着题再写  （相比其他老师很少了）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658e6fc290d3d1241d9d7e46',1419,48,'王老师前国家队的，专业实力真没得说。关于打分问题我只能说高远球拉到位分都不会低于九十。我一个纯业余选手因为步伐和高远球还行都能期末拿100',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('658e69f090d3d1241d9d122e',5376,4552,'挺好的老师，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658e65d890d3d1241d9cc5bd',173,28,'人很好，和蔼负责，however作业巨多',3,3,4,10,0,1);
INSERT INTO "reviews" VALUES('658e57314f66203748d9e3e1',1132,631,'老师人非常好，平时分基本上给的都是满分，点赞点赞，强力推荐',5,5,5,15,0,0);
