INSERT INTO "reviews" VALUES('658e4ec14f66203748d95018',3517,3517,'虽然熊老师的课有时候听不进去，但是这是个很好的老师，会捞人，很具有亲和力。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658e4e1e4f66203748d94731',828,1073,'水平正常，不必避坑，正常水平。',4,3,3,10,0,0);
