INSERT INTO "reviews" VALUES('658e4d8290d3d1241d9b038b',1087,1087,'真的懂且能讲清楚的结构力学老师，ppt做的漂亮，上课不点名，作业可以缓交3次，注意有课堂测试',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('658e4cc090d3d1241d9af8d2',7369,73,'专业知识很一般，内容讲解不清晰，但是能扯能吹牛，就当听相声',1,2,3,6,2,0);
INSERT INTO "reviews" VALUES('658e45d53a094c20e198fa3e',1005,80,'老师比较严厉，高中老师风格，跟着她来就会发现其实性格也挺好，当然了发现你摆烂肯定会发脾气的，作业要求严格一些，要自己写，但只交过四次，平常也不点名。发脾气的事情肯定是有的，但要我评价她还是一位好老师，想跟着学的就选吧，平常想小摆一下就别选了，肯定是不好受的。',5,5,4,14,3,4);
