INSERT INTO "reviews" VALUES('658e37939c4d834fea48c3c4',142,760,'作业不算特别多，只是截止日期是每周一次，别的班截止日期比较长，但是作业量都是差不多的，教学也很负责。而且线上问问题回复特别快',4,4,5,13,0,3);
