INSERT INTO "reviews" VALUES('658e2dd690d3d1241d99c948',785,114,'人很好，很负责，我不是四川人，但上课能听懂，感觉方言没其他同学说的那么严重',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658e1c643a094c20e197950e',2885,3822,'老师人很好很温柔，上课也是比较水，很轻松，点名也很少，而且每次上课都会提前一会下课。平时作业也会在群里提醒。就是小组讨论有点多，社恐如果班里没有熟人的话会有点尴尬。期末给分也还可以，如果有加分就会好一些。如果选不上大热门的老师，刘静老师也是不错的选择。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('658e156c2be3a26cecadca80',1087,1087,'上了周老师结构力学的上和下，讲课很有条理很清晰，课堂氛围很轻松，课后偶尔还能跟周老师吃个饭，课件动画做得好。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('658e11ab4f66203748d73be7',1087,1087,'课件好，讲课逻辑清晰，真的懂结构力学。横向比较，平时分中上等',5,5,5,15,8,0);
INSERT INTO "reviews" VALUES('658e06db9c4d834fea477012',1273,157,'天天被压力快崩溃了😡慎选',3,1,1,5,4,0);
INSERT INTO "reviews" VALUES('658db81b4f66203748d66371',1127,4055,'老师讲课有点点困，但是期末的时候都会把大家的分数往上提一提，是个很好的老师，对数学的理解很深刻。很可惜下学期上不到陈老师的课了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658db72e90d3d1241d982641',409,1622,'老师是个严格的人，讲课和考试追求公平性和实力，因此，老师的给分也不会很高。但是她对同学的也很负责，才会出现下面同学一些说法，但其实也没那么严重。但大物的主要成绩不在于老师的平时分，主要在于期末。你如果能够耐心和老师交流，就会发现私底下是一个很随和耐心的人，老师心态很好总是抱着学习的心态，没有什么架子。她或许不是一个很好的选择，但也不差，如果有幸选到她的课又换不掉，耐心听她讲课与她交流也是个不错的选择。',4,4,5,13,1,9);
INSERT INTO "reviews" VALUES('658dab722be3a26cecacb5bf',1409,1409,'老师水平一般，期末主观给分，只看基本动作，动作不标准就分不高，对待没有专门学过的同学很不友好，再去刷分有可能还会比上回分数低，群里不回同学的问题和消息，每次在哪上课到了上课点才说，时不时还点名，有时候还说大家都是成年人，他也不想点名，真不知道怎么说的出口，只可惜体育课一选就是两年，真的恶心',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('658da29e2be3a26cecac8628',282,282,'人非常好，很和善，教得好，讲的好，分高，真的在教书育人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658da1252be3a26cecac7d4d',1273,157,'一分不想给，尖酸刻薄，别删我评论 骨子里都是坏的',1,1,1,3,4,0);
