INSERT INTO "reviews" VALUES('658da0002be3a26cecac76d8',1273,157,'严的要死一点不讲情面 生病了请假要求下课前必须把假条送到 不然就算补假条 “补的假条”一律不收直接给你记旷课 哪怕只是迟到都有可能被记个旷课 每节课都点名 期末考得贼严一点不放水 动不动就骂人上纲上线的 群里消息也不爱回 本来就倒霉想选的课没选上才来了排球班 遇上她真是倒了大霉 偏偏还要两年才能走 恶心死了（顺便蹲个朋友跟我换课 排球课超好玩的哦 23级周四上午三到五节）',1,3,1,5,4,0);
INSERT INTO "reviews" VALUES('658cef434f66203748cfe2ec',430,194,'我看谁给我们虎子哥打低分😡
INSERT INTO "reviews" VALUES('658ce71d3a094c20e18fb38a',85,407,'陈老师人很好，对自行车感兴趣都可以选，平常也是有问必答',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('658ce6c890d3d1241d91501d',546,40,'我现在已经大四了，想起吕曼曼还是咬牙切齿特地回来痛批。大学四年里******，当时的大作业她前前后后让我改了五次，问她哪里还有问题她指出让我改的地方？？？？？作业还巨多，她的套路就是如果哪一年选她的人少了就装模作样期末平时分给高点，然后借此让这批学生传开口碑迎接下一批待宰羔羊。全勤➕作业全完成平时分44你敢信？绩点直接爆炸，总之有受虐倾向我觉得她是你的不二之选。非常好的老师，使我的保研消失。',1,1,1,3,4,0);
