INSERT INTO "reviews" VALUES('658cd3eb9c4d834fea3f63cc',233,306,'上的老师的机械制图课，老师人很好，上课没有点过名（人很少也只是让课代表数人数但不会点名）平时作业正常量，大作业给分很高。好老师，选上就是赚到',5,5,5,15,0,0);
