INSERT INTO "reviews" VALUES('658c6a402be3a26ceca44a8c',523,377,'讲课非常有意思，还会给大家科普一些书上和影视作品上的片段！人超级超级好！并且请假只用提前说一声，不用特地打假条！点到次数也很少！',5,5,5,15,3,0);
