INSERT INTO "reviews" VALUES('658c5ac290d3d1241d8f34f3',7095,7095,'我只能说，找你肖哥学有机，只要不是特别摆烂，百分百不挂科，作业偏少，抽样点名，期末直接告诉你该复习啥，有这种宝藏老师还不赶紧选？',5,5,5,15,3,0);
