INSERT INTO "reviews" VALUES('658c59813a094c20e18d8bdb',2302,2302,'针对交通数据分析，只有他上这门课。上课只会敲代码，有时候自己还会忘记，老是报错。笑面虎一个，看着和蔼，平时表现只给80，而且所有人都很低。复习重点就是所有讲过的。按心情调平时和期末成绩占比（一般期末往上调，期末还考的贼难）。如果他教别的课，建议不要选他。
INSERT INTO "reviews" VALUES('658c550390d3d1241d8f1238',2230,2230,'老师人真的很好，很懂配合，谢谢易老师救我狗命',5,5,5,15,0,0);
