INSERT INTO "reviews" VALUES('658ba0489c4d834fea38432c',257,26,'平时不会管你，期末也不会管你',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('658b9fe890d3d1241d89a38f',1243,1246,'老师人挺好，也比较负责。至于老师教的生医专业课，按要求来可以学到很多东西，期末考试难度适中（可能有部分题比较难，但大多数题比较友好），然后就是给分比较合理，如果作业完成质量比较好，平时分也会比较高。总体来说还不错，留个好评。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658b9fc99c4d834fea384146',457,457,'谁选谁有福哈哈哈无重点还要搞汇报',2,2,2,6,0,1);
INSERT INTO "reviews" VALUES('658b8b9990d3d1241d892a82',2878,28,'选到就是赚到，黄朝华我的神，下辈子给她当牛做马',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('658b89e63a094c20e187778c',2878,28,'老师真的特别好，我遇到的最好最好的英语老师，虽然是A班但是平时分很高，很幸运遇到老师，会记得一辈子',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b85399c4d834fea37a5c4',1333,28,'😋',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b81449c4d834fea379109',4784,641,'课讲得是一点不行，从第一节课开始就没听懂，上完他的课，会的还是会，不会的还是不会。刚开始大家抢前排，后来大家抢后排。作业多的一批，还会阴阳怪气，一分否不想给，上他的课影响学习，选到他的课就等着自学吧，还有那什么第二次测验，也是难的一批，大把考三四十的，总之，快跑！！！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('658b7e299c4d834fea3782f2',430,194,'？？搞不懂为什么有人不给虎哥满分？',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658b7b642be3a26cec9db991',221,36,'上课不点名，但是给分贼低，事情贼多，反正赶紧跑赶紧跑',1,1,1,3,18,0);
INSERT INTO "reviews" VALUES('658b7b0f90d3d1241d88de1f',89,33,'如果你是想来水课的话是可以的
INSERT INTO "reviews" VALUES('658b1a6d4f66203748c669b1',24,1695,'神，我是转专业的学生，上的重修班，小武怕我们听不懂还另外给我们开小班教学。想学的同学无脑选，想水的别来，小武会介意你上课玩手机开小差，别给双方找不痛快。
INSERT INTO "reviews" VALUES('658b0d504f66203748c64a27',7428,7428,'阳阳老师课上得好，人也好！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b097c4f66203748c63e27',35,35,'如果你想来水这门课 那还是很痛苦的 别来
INSERT INTO "reviews" VALUES('658b08884f66203748c63adf',545,33,'上课很有趣，给分不低，老师上课总喜欢讲很多故事，文化，台风挺搞笑的，很轻松的氛围，平时分自己按部就班做好作业也不低，但是a班作业确实多一些。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658b07d93a094c20e1863e0b',1513,1513,'老师人很好，挺好水的，点名抽点，有一次会交课堂作业，但是最后平时成绩都是教务网上自己确实过没问题的，可以补交假条，期中期末都是论文，很有趣的课。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b060e90d3d1241d87e09c',684,684,'老师专业能力强，水平高，对学生十分负责，生化课程学习很枯燥，要记忆的很多，老师会分享自己的营养方案和自己对这些生化知识的运用，还是很有趣的。小组合作，作业都是小组完成，有固定座位，一学期都按固定座位坐，平时会有默写加分项。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b04e14f66203748c62bea',2654,40,'茜姐很好，人也很好说话，上课中规中矩，作业晚交也能好说话，可以补交，分数挺高的，想水想认真学的都可以，长得也好看，课很轻松，作业也少，十分推荐。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('658b041690d3d1241d87d876',1168,228,'老师神中神，人超级好，讲课很有趣，会讲故事，很有思想，认真听很有收获，期中相当于没有，给满差不多，一学期只点了一次名，视频作业和读书笔记，事情很少，想认真听和想谁都可以直接冲，但是没有免考名额，东哥这么好期末给重点还要什么免考名额啊？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b02ba4f66203748c622ca',7435,7435,'这门课如果你喜欢诗词，选吧没错的，哪有那么多为了修选修而修的课，这门课我觉得就是不水，或者不是那么水，有小作业，期末就是一篇800字鉴赏，但老师上课很认真，很有情怀，是真真切切传播文化，很有思想的一位老师。感恩相遇，感恩文学。冲着分来的没必要，打分不算高，但也还可以。有些课是为了分，有些课是为了内心。很幸运能遇见段老师，如果认真听的话，每一堂课都很有趣，带你走进诗词的世界，不过老师选择提前退休去追寻诗和远方了，已绝版。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658b01be2be3a26cec9cb109',52,52,'马老师神中神，科教的好人也好',5,4,5,14,0,1);
INSERT INTO "reviews" VALUES('658afcc79c4d834fea364e0d',271,5,'老师讲的很好，但喜欢突击小测，往往是在课程结束最后十多分钟，随机给道题做，然后上交。题的内容一般是刚讲完的新知识。但测的次数不是很多，也就两到三次。上课的uu要好好听讲呀！',4,4,3,11,2,0);
INSERT INTO "reviews" VALUES('658abf374f66203748c4420d',4352,4352,'选这课就别想上八十了，老师就直接是******',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('658abe972be3a26cec9acd1c',172,39,'很严……事多，谨慎，别，听劝，写给以后的各位同学，千万别来🙏，听过来人的劝',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('658aba8c4f66203748c426bc',89,33,'超级好的老师！！！A班的神！！！入学前听A班好多事管的也严要求又高觉得难受的想死 直到遇到黄老师的课！！！ 比B班还轻松！！老师心态年轻幽默哈哈哈哈哈爱了爱了',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('658aaedc3a094c20e183e77a',2005,1697,'刚开始感觉她嗲嗲的有点做作，但一段时间后感觉这个老师挺不错的。她讲课有点念PPT的感觉，但PPT可以拍照可以拷贝；课后作业很多始终很少都有可能；考试90%以上都是卷子或课后原题，可以说把卷子和平时作业都过一遍背住，90以上完全没问题，给分的宽松与否不定；有时候会点名；上课严禁玩手机，玩手机的话会被她说，喜欢上课摸鱼的不建议选她；在课上被抽问到很简单的问题没答出来，她会说“这么简单都不会”“你们怎么什么都不会啊”这类话；有时候讲到一些知识，她可能会拓展一点点；小测会有但不多，不过小测的分考太低的话被她看到了会被当堂说，不留颜面那种。总而言之，这个老师有优点也有缺点，更适合化学能力稍微强一些的学生',5,5,4,14,1,1);
INSERT INTO "reviews" VALUES('658aae249c4d834fea3423eb',604,229,'好好好',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('658aade84f66203748c3e005',2878,28,'老师人超好！教的也很好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658aacb62be3a26cec9a6617',25,352,'女生分多，懂得都懂。讲的西撇，还必须打比赛并且指导老师必须挂上他的大名，想认真学建模建议自学或者换老师。期末论文自己写的分数没人买的分高，有压分嫌疑，100多个人的论文交上去第二天就出成绩了，怎么打得分不敢恭维，只能说，一坨。上课还要做题，别想逃课了，16次课13次都要做题，做不对平时分就少。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('658aaa709c4d834fea3408f3',89,33,'很轻松，会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658aa8b12be3a26cec9a4d0d',2584,7446,'吴山老师真的真的特别好！人美心善，考试看得不严，平时课下作业有点点多，偶尔开火车读课文，其它的都很完美',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658aa8682be3a26cec9a4bae',7447,7447,'上的是高老师的互联网选修课，很亲和幽默的一位老师！对待同学很耐心，因为是选修，不怎么点名，也不要求大家满勤，真的很好的一位老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658aa80b4f66203748c3bd96',1848,1942,'濮老师天下第一好！人又漂亮会打扮，平时也很温柔，遇到划水的方案也都认真批改和讲解，真的很喜欢！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658aa7b69c4d834fea33fcb8',7449,7449,'很会勾重点，对不听课的学生来说很友好，期末考试有点水，平时不讲什么内容',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('658aa74e4f66203748c3b9ae',1590,1848,'很可怕的老师，想着建筑的同学避也是避不开的，不如劝一下别的专业不要选她的选修课吧，很会pua别人，能把一个好好的同学说得一无是处，从外貌批评到家庭环境，容易被洗脑。专业课没见教东西，反正自己意会吧',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('658aa2752be3a26cec9a2b5e',297,194,'yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658aa0ca9c4d834fea33d9d8',297,194,'神中神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658a91d390d3d1241d84e2ec',2323,92,'神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658a55902be3a26cec985989',7449,7449,'讲课念PPT就算了。构造课还让同学做PPT上台讲：建筑物理更是一绝，九里周末早八的讲座让你早上六七点坐地铁去上，不去还扣平时分，真的恶心！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('658a3b759c4d834fea31a633',978,5,'课前会在雨课堂布置预习作业一般是慕课视频和十几道题目，课后作业一般就是习题册挑部分题目做，作业量确实挺大。课堂会点名但临近期末的一个月没点过名，课上还会抽人回答问题确实惊心动魄，课内板书和PPT结合每个点怎么来的都会说的很清楚。临近期中期末他会发往年题目给你做并录制视频讲解（真的很好）。期末前还会讲解题目答疑。关于平时分我觉得给得挺多的只要认真完成预习课后作业就会高，还有两三次线上测试认真做分就会高。总之老师非常负责，有种高中老师的感觉，考试的每种题型给你讲的透透的，虽然作业多但老师也是为你好。如果想好好学习就选他分数肯定很高。',5,5,4,14,1,1);
INSERT INTO "reviews" VALUES('658a371090d3d1241d82fd0a',2878,27,'特别特别特别特别特别特别特别特别特别善良的小女孩且学且珍惜吧🫡',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658a35c43a094c20e18147c7',2878,27,'特别特别特别特别特别特别特别非常非常好的老师 特别特别体贴 就是平时可能会听写 遇到你就偷着乐吧😋
INSERT INTO "reviews" VALUES('6589c20f4f66203748c0459f',7458,7458,'巨恶心，上课爱说教，期末莫名其妙给低分',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('658989ba9c4d834fea2fc903',7459,426,'受不了一点，幸好下学期就说拜拜',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6589872490d3d1241d81288d',1694,1694,'超级恶心，不讲课还高调的一批，盗用学生作品，动不动就骂学生',3,1,1,5,1,1);
INSERT INTO "reviews" VALUES('658978d39c4d834fea2f65d3',7461,7461,'很可，给分很高，作业也很轻松！老师有真才实学，讲得有意思！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658977b14f66203748bf1be3',1273,157,'快跑！快跑！大二被迫上了排球课，给分非常低（比大一老师给分低至少七八分），比赛如果名次不好会扣很多分，并且老师带女排比赛缺席很多次课。给个人技术打分也很低，不明白她缺这么多次课，知道我是什么技术吗？',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('658931c19c4d834fea2df41f',684,684,'老师确实有丰富的知识并且非常愿意把它们教给我们，对学生也非常关心，还会和我们分享养生知识。会让我们分组然后布置小组作业，对我们建立知识体系确实很有帮助。但是讲课语速很快、内容很多，有种不顾我们死活把知识塞进我们脑子里的感觉，看似讲了很多，实则我们啥都没记住。如果不是PPT上写了重难点不然我真听不出有什么重点。三节课所有内容都是一样的平静的语气，困得人直接昏迷过去了。',5,3,4,12,1,0);
INSERT INTO "reviews" VALUES('65892ff190d3d1241d7f5a8e',398,48,'确实什么都不管，教完东西就润，班上大部分人大部分慕课分数全有问题甩手给******最后慕课全部上完狂砍50分，呵呵，如果你能接受这样的到时候你成绩有问题的别怪没提醒过你。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65892cb290d3d1241d7f4c38',385,28,'刚考完口语，真的很好，老师很负责任的，有什么问题你以任何态度提出来她都会改（见QQ群），当然我是摆子哥，或许不适合高分飘过的同学？？？',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65892c954f66203748bd9df2',385,28,'好好好！抛开u校园不谈，挺不错的，耐心，就是上课讲得画画画重点，然后自己背',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('658900983a094c20e17cecbc',7105,2236,'老师讲课有水平的，人也很好。这门课平时分不是由老师决定的，而是统一用软件答题，只要做很容易拿满分。老师甚至还会给你补交的机会。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6588f42f3a094c20e17cbc1b',96,96,'阴阳的神',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6588f16e9c4d834fea2ce962',2399,230,'这位神 讲形式与政策从不点到考试也水',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6588e13a2be3a26cec92ea42',89,33,'老师超级好，给分高，上课也轻松',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6588d80d3a094c20e17c550c',413,28,'水课的不二选择，平时分包你满意，口语考试只要能说话，你都能拿3分，唯一的毛病是要提前到15分钟到教室，但是这不重要，选择了陈华，你就选择了期末考个30、40分就能过',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('65885ed02be3a26cec91fdda',1171,27,'啥也不是，有本事你就选',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('65884b174f66203748bb3f1c',7473,7473,'神中神！选上岳丽全的课，随便学点就不挂科。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65884a5e90d3d1241d7cede1',532,141,'一次不去，终身点名。上了一个学期，我室友名字都快被喊烂了，没事他是真点名。',3,3,3,9,3,0);
INSERT INTO "reviews" VALUES('658831b79c4d834fea2b085e',532,141,'消息从来不回，讲课没啥重点，迟到一次以后就天天点你',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65882fc59c4d834fea2b00d8',1291,7092,'为什么给分低还这么多事呢？嘴上还说着跟同学关系好，我真吐了',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('658800983a094c20e17a14a4',1480,127,'超级无敌好，直接选，不要犹豫',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('6587c9232be3a26cec8fc179',349,194,'很激情，PPT提前发，内容提前说，作业答案具体步骤也会发，上课有例题，还有习题课，作业是他挑的题写，助教可以补交作业',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6587c88b9c4d834fea297228',542,1170,'个人觉得不是难以忍受，作业可以补交啥的，上课在后边玩手机也不管，就是有时候感觉像高中班主任一样，如果实在换不了别的课也不用担心，她不是一个好老师，但也不坏，就是一个精致的小老太太',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('6587c78e4f66203748b9429f',2819,28,'平时没啥雷点，会听写单词，但你可以下边操作一下，不严，然后每周一套真题，有点做题痕迹她就过了，几周写一次作文，我个人认为，最不水的就是期末口语考试，一个人一个人的考，试题是从fif里边抽，一共十套，每套都是长作文，一个人80s，我已经放弃这个分了',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6587c6f24f66203748b9405a',769,833,'太棒啦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6587c68e4f66203748b93eab',257,5,'脾气很好，但讲课听不清，不仅是音量小，发音也有问题，坐前两排得努力听，后边根本听不清一点，PPT会发，但是是这周他的所有课上完之后，如果没人要，他就不发了，题不是不讲，而是没时间讲，特别想说的是，他在讲作业或者例题，在黑板上写的时候，很乱，跟不上，如果自学的话，应该挂不了课，就看自律性和对数学的天赋了，每周有作业，有时候是下课就留，有时候是他这周课都没了留，每周收，可以网上当天补交，作业还会评级',1,1,5,7,1,0);
INSERT INTO "reviews" VALUES('6587c5343a094c20e1793259',6994,1651,'老师23年年底退休，他说我们是他在职最后一班，但他以后可能会帮别的老师代课，我认为他只是给分严格，但不会恶意扣分，讲课也很激情，助教平时作业给分特别特别高',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('6587b8592be3a26cec8f7e25',176,176,'老师是个好人，也很厉害，不要求出勤，但是，老师的学位是哲学博士就更厉害了',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('6587a8a79c4d834fea28e525',1350,5,'由于客观原因，老师讲课语速较快，但是该讲的全讲，讲得超好，节奏快但是能跟上。大力推荐😋（个人觉得提前预习的话，听了老师的课之后课下基本不用看宋浩🤗）',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('6587a15790d3d1241d7a2b80',176,176,'老师普通话没有很好，听着有些费劲。
INSERT INTO "reviews" VALUES('65872e503a094c20e177bf28',1749,1409,'考勤搞这么严感觉没必要',2,2,2,6,0,1);
INSERT INTO "reviews" VALUES('65872d569c4d834fea27eefe',532,141,'嘤嘤嘤 老师再找不到我的作业要破防了😰',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('65872cbb2be3a26cec8e3a0b',842,6644,'不是水课，很认真负责，老师很关心学生很有原则，只能说适合的很适合，不适合的会很难受',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65872c203a094c20e177bc6f',631,74,'大家好，我是西 南 交 通 大 学 高 山 老 师',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('65872bb63a094c20e177bbf6',1307,1307,'好老师，有石粒且没架子，冲就完了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65872ba03a094c20e177bbdc',631,74,'顶尖抗压吧吧主，感觉生活太如意？那就来上实习吧，🥵🥵让你感受生活的乐趣，🐭🐭我呀，阴暗冷漠扭曲的爬行了捏',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('65872b592be3a26cec8e37c9',631,74,'珍爱生命，远离',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('65872b1a90d3d1241d79577e',532,141,'小伙子年纪轻轻说话欠揍的一，交了作业没看到说没交，群里和邮箱消息从来不回，到处找不到人，不知道的以为似了😅',1,1,1,3,14,0);
INSERT INTO "reviews" VALUES('65872b0890d3d1241d795765',532,141,'寄很难评',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('65872abc3a094c20e177ba8c',532,141,'****** 找存在感',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('65872ab44f66203748b7bd4c',1307,1307,'非常非常好的一个老师，实习关心学生，批改试卷会为学生着想😊😊',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('65872a7c2be3a26cec8e369f',1307,1307,'老师太好了😭 ，好温柔',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6587290a3a094c20e177b5c1',1307,1307,'刘哥实习怕我们热着了，让我们在空调车上等着🥰🥰',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658709812be3a26cec8de6ac',82,82,'点名，但确实水',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('6586f7739c4d834fea2760cb',532,141,'下课根本找不到人，发消息从来不回，PPT也不发，每节课都点名',2,2,1,5,3,0);
INSERT INTO "reviews" VALUES('6586f2e63a094c20e1771afd',7502,7502,'中规中矩人很好，但期末看自己努力了',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6586c2913a094c20e17660e5',542,1170,'1.认真做的期中作业，一个字一个字码的，给了85。2.上课全勤，第16周还特地找老师核对出勤率，老师亲口给我说的全勤就是满分 结果现在今天出分给我扣了7分。老师的课确实是水，就一次拿签到表点名其余课手机签到就行，我从第一周到第16周每节课都是7点半准时出现在教室，结果他给我扣了分。那些晚上上课缩在寝室里面打游戏，那些在教室外面签了到就跑的人，平时分成绩给了满分。3.沟通每次都很不耐烦，我检查自己的考勤一学期至少有几次了，每次很不耐烦的跟你讲话，想体验被当狗可以试试4.见到这种选修课老师，如果你只是想满足学分预警和毕业要求，那你只需要用手机签个到论文随便水5.对想刷分的同学我的建议是快跑。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6586adde3a094c20e1762073',3719,230,'点名两次，缺勤一次在教务网上会给你登记为缺勤两次，且正常都不会登记在上面。期末不会捞人。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('658662522be3a26cec8ba334',264,230,'非常好，只不过他对我们不重视这门课表示遗憾，偶尔听听挺有意思的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658661f22be3a26cec8ba1d4',1065,1731,'美女老师，平时分回答五次问题就给满，基准分25，回答完问题就是30，防内卷。三连讲会提前一点结束',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658661262be3a26cec8b9fb1',1273,157,'不建议没有基础的同学选这么课，考试要求严格没有同情分，有点摸鱼的同学平时分给的很低。考勤每节课点名而且老师基本脸熟每一个同学。课堂中还有10min的素质强化，体能不行的别来。上学期发球没发好5过2，期末喜提70，慎选',4,4,2,10,9,0);
INSERT INTO "reviews" VALUES('658648399c4d834fea250f0d',168,168,'最喜欢的老师
INSERT INTO "reviews" VALUES('6585b7003a094c20e173e51f',6396,6396,'全靠自学，课是不上的，题是要做的，不过挺负责的，有问题你不明白会打电话告诉你',3,1,5,9,1,0);
INSERT INTO "reviews" VALUES('6585b65a90d3d1241d757a4a',5120,7510,'讲的捞，自己还理不明白，给分还行',5,5,5,15,2,0);
