INSERT INTO "reviews" VALUES('65854fa69c4d834fea235155',1132,7513,'专业水平超强，黑板上手推公式，亲切和蔼，给分超高，半期考试也是能给就给，上课会启发式地教学，不过一节课讲的算例稍多，速度稍快',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65854de12be3a26cec899d24',1994,241,'一个人没来全班扣分👍🏻',1,1,1,3,5,0);
