INSERT INTO "reviews" VALUES('6585498a2be3a26cec8996cf',573,573,'快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('658548009c4d834fea23440a',3502,7517,'我上是地图制图学基础，不过照样快跑。老师上课念ppt无聊的要死，到做实验的时候好像又什么都没讲。并且经常上课点名，差不多是节节点。
INSERT INTO "reviews" VALUES('658541352be3a26cec8987c1',627,271,'上课能不能别一直拿你那天才儿子拉踩学生贬低学生了，无语，布置的作业还死多',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('65853e8e3a094c20e17305c8',3821,3821,'上课侃起来其实还是蛮有趣的，专业内容也讲，给分也高，只要不影响上课也不管你，很像话很多的大姐姐（？）反正我挺喜欢',4,5,5,14,2,1);
INSERT INTO "reviews" VALUES('658529b03a094c20e172e58c',2005,1697,'虽然有机还没有期末考试，但课也算是都上完了。不知道大家认为一个不好的老师是什么样的，是作业多？给分低？课讲的不行？还是对学生不好？人品不行？两个学期她的课上下来，感觉其实她并没有以上的问题，而且期末考的基本都是原题，只要期末考的比期中高最后她也会把期中分数往上拉的。最后一节课她讲完了所有的课，和同学们聊天，那个时候我觉得她就像一个普通的、有点慈祥的长辈。总体来说她还是可以的，大家不要觉得选到她的课倒霉了。当然死亡点名还是令我们这些不好好学的同学颤抖的',4,5,4,13,5,0);
INSERT INTO "reviews" VALUES('6585277f4f66203748b2ed10',4001,7521,'很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658527429c4d834fea231128',4001,21,'很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658521b290d3d1241d747226',48,48,'再喜欢羽毛球也不要选，谁选谁知道，整一个超级无敌抽象姐。上课迟到一分钟也扣分，请事假交了假条直接体育成绩扣两分，要是缺一次勤直接体育成绩扣五分，要是成绩出了问题不会给你改分数，就算是她自己的问题也不改，打电话直接拉黑，qq发消息不回。羽毛球要是技术不好分也很低。另外每次上课一个半小时要讲半小时的废话，我们就站着听她讲。别选真别选不要来遭罪。',1,1,1,3,12,1);
INSERT INTO "reviews" VALUES('6585206690d3d1241d747032',1600,96,'特别特别好的老师。迄今为止遇见过的唯一一个不用ppt全程板书的老师，老师给我们说作业最多布置六道，每次的作业真的就不到六道题，上课基本上不点名，请假也很宽松，想起来了补交假条就好，只要作业都交了平时分给的也很高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658508a290d3d1241d744fa3',96,96,'快跑！！！如果真的想好好听课就别上她的课！！阴阳大师，很会骂人******😓',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6584f5a390d3d1241d743112',1675,1675,'声音小，照着ppt念，不捞人，只能说拉满了',1,4,1,6,2,0);
INSERT INTO "reviews" VALUES('6584e9679c4d834fea22ba8b',1939,1939,'人超级好，曾经的运动会冠军，分给的挺高的，期末考可以无限刷，主要是说话幽默，人真的很好！',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('65846bad4f66203748b22ef3',1869,1869,'美国博士后，专业水平高，上课逻辑清晰，容易听进去，缺点是平时较忙作业发的晚上课有时候会卡顿（毕竟是新老师）',5,3,5,13,1,0);
INSERT INTO "reviews" VALUES('658466083a094c20e17220bb',560,3214,'不选就亏了！老师给分很高，想方设法给你加分！一定要选！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658465d94f66203748b226ba',560,3214,'老师给分很高，就是考试会考软度，不过压压就行，我这种身体硬的不行+慕课只有六十多的人总评都有九十多，全勤也有加分，慕课也有加分，考试内容也简单，有什么理由不选！',5,5,2,12,0,0);
INSERT INTO "reviews" VALUES('6584646e3a094c20e1721ecf',1127,4055,'真的很好的老师。划考试重点 考试不难 就是上课一点点困 作业适中。
INSERT INTO "reviews" VALUES('6583e2da4f66203748b15446',1685,1685,'这个老师话很多而且态度很差，动不动就压力学生，根本不会说好话，上她的课心情很糟糕',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6583dd983a094c20e1714542',199,428,'讲的很细致，上课经常讲小故事，考试很多题都是课上讲的例题，潘潘我爱你',5,5,5,15,0,0);
