INSERT INTO "reviews" VALUES('6583b3084f66203748b10882',4,4,'人很好，上课经常对近期足球发表见解，对联赛欧冠进行，可惜准确率偏低，同时是siuuu的粉丝，考试比较松',5,5,5,15,0,1);
