INSERT INTO "reviews" VALUES('6583aa8d3a094c20e170f1d4',598,27,'任何一个人不上张维老师的课我都会难过！神中神老师，给分高人美心善，有一次我作文没交补交上去字很难看老师都看不懂我写的什么还问我，最后都打了11分，fif口语我没做过期了老师特地补开了一期给我们加分，遇到这样的老师真的幸运',5,5,5,15,1,0);
