INSERT INTO "reviews" VALUES('6583a93190d3d1241d727e5d',278,228,'今年选课的时候就已经看到评价老师已经变好了，上了半学期觉得她真的其实挺好的，客观评价，上课讲的还行，有时候也会给我们讲点好玩的，一般不考勤，但是随机点过两三次名，给分也很客观，我们班平时分平均有九十多，值得选。',4,5,5,14,1,2);
INSERT INTO "reviews" VALUES('6583a14390d3d1241d7270a6',48,48,'给分很低，搞连坐制度，莫名其妙地改考试给分，不打招呼就说哪次算补考，期末满分直接降30分，快跑，赶快跑，打车跑！！',3,2,1,6,2,0);
