INSERT INTO "reviews" VALUES('65838c532be3a26cec874414',674,307,'教的很好，特别是Verilog部分，认真听对数电实验很有帮助，但说实话因为她教学方法很严，所以选了她导致平时分比别人少了2-3分，期中闭卷难度拉满，小测10分钟让你做15题，课设难度很大。',5,5,5,15,0,0);
