INSERT INTO "reviews" VALUES('65838afc3a094c20e170bc62',42,43,'烂！******死板，只有自己的一套标准，波形截图留的空白多了都要扣分。实验前要求不说清楚，验收时只要有一点不对二话不说直接给二验。还喜欢嘲讽学生，男女区别对待。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('658388c42be3a26cec873fd5',2116,177,'神！很好的一位女老师。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('658386609c4d834fea20e7b5',7553,7553,'老师很搞笑，散发一种奇怪的气质，上课没听过，非常枯燥，但是人很好，不严格，不会抽人回答问题，平常很水，就日语考试很烦，想摆烂的同学学其他语种比较好。',4,4,4,12,0,0);
