INSERT INTO "reviews" VALUES('658242139c4d834fea1f16d3',1168,228,'马院遇到的最喜欢的老师了😭，上课讲的内容认真听还是很有意思的，感觉老师的水平还是非常高的。不想听也特别好水，上课不点名作业也非常轻松（相比于其他班记笔记拍视频），老师上课也说平时分会给的不低，真的太好了😭',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658240b22be3a26cec8571ae',373,230,'事少分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658240584f66203748aeedfc',452,452,'给原题，满分',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('65823a294f66203748aee502',674,6634,'平时分比其他老师低，讲课水平一般，但问问题会回复，就是回复可能晚一点',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('65823a134f66203748aee4ef',1243,7568,'上的医疗仪器与人类健康。挺水的，在下面玩手机写作业都没事。不点名但是偶尔会课堂上提问然后写纸上交，都很简单直接百度，大概三四次。会有两次实验课，就是去测血压、心电图，挺好玩的，然后发一张很简单的实验报告期末交了就行。有一个小组作业是构思一个医疗产品然后做海报，互评打分。老师还会把所有小组的海报打印出来贴教室里。没有期末考试，最后96分',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('658238ac2be3a26cec8565c8',2829,7569,'每节课都有作业，即交一幅画，挺费时间的。对绘画不是太感兴趣的不建议选',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('658235fb9c4d834fea1f059c',1197,496,'神中神，讲课很多地方会举例子，听不懂老师还会再讲一遍，作业交了就行，半期考试也宽松，课设提交时限也宽松。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6582351c2be3a26cec856120',1189,605,'不适合教书，说实话。老师可能自己懂，但不会讲，也不让问问题。每次上完课跟没上课一个感觉。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('658233a33a094c20e16ed491',1386,1386,'老师讲课讲的很好，实验也会陪着同学一起待到很晚，做事认真。实验比较难，但没有实验考试。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('658232404f66203748aedaa4',2567,7573,'平时分给的高，半期有时候都没有考试，写份总结就可以了，讲课纯板书，思路清晰，这样的老师不多了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('658232039c4d834fea1eff78',1727,7574,'选的奥运赛事鉴赏 每天没啥事 随便练练跑跑
INSERT INTO "reviews" VALUES('6581d42a9c4d834fea1eba21',48,48,'宝藏老师，希望有更多的人可以来受罪，自己说的体育课最后两次课考试，这学期因为流感，第一次考试的时候发高烧请假第二节课去考的试，结果只有第一次课考的人分数“正常”（但是还是比任何其他项目都低），第二次课考的就给你算补考最高70分了（没有提前通知过这件事）跟她理论她还说所有体育班都是这个要求，而且第一周考试有同学在课上要继续考试还让别人不考了，第二周再来，属于是悄悄赠送幸运观众一个美丽补考是吗😅经常像这种不提前告诉你要求，等你做完了才说。上课也从来不讲技术动作，只会给技术不好的同学说自己练，上课就在旁边聊天也不纠正同学的动作，然后考试基本都给那些同学超低分，上她的课纯纯坐牢捏😅',1,1,1,3,7,2);
INSERT INTO "reviews" VALUES('6581caa03a094c20e16e8364',89,33,'老师人非常非常好，平常会关心我们有没感冒什么的，而且给分很高。',5,5,5,15,1,0);
