INSERT INTO "reviews" VALUES('65810f313a094c20e16d275b',260,96,'李老师我的神，神中神，随堂测试有丶难，但是都能拉满，就算你没来随堂，他都按半期考试成绩作为参考，再做成绩上浮后计入，他真的，我哭死😭😭',5,5,5,15,0,0);
