INSERT INTO "reviews" VALUES('6580f9822be3a26cec839d3f',1749,1409,'迟到请假扣大分，几乎每节课都点名，一个破大三体育慕课还麻烦的要死，要评论区点赞十个才有分，还占慕课50%老师也只字未提，班里都是不及格 真服了',2,4,1,7,0,1);
