INSERT INTO "reviews" VALUES('657ff64990d3d1241d6d4662',572,572,'整天一副心高气傲的样子，不知道的还以为得了诺贝尔奖。作业是没有，但是要考公考研的都不建议选，因为有课设并且要经过多次检查和修改。要是想有一个繁忙充实，充满压力与焦虑的学期就来好好享受吧。',3,1,1,5,3,0);
