INSERT INTO "reviews" VALUES('657feb812be3a26cec8236f5',1105,1105,'讲得非常好，严老师特别帅，都冲都冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('657fe3059c4d834fea1bb520',23,23,'刘老师神中神，讲得好人也超好，耐心温柔超有爱心，高分过，最爱刘老师yyds！',5,5,5,15,16,0);
INSERT INTO "reviews" VALUES('657fda012be3a26cec821b66',24,24,'还没考期末就迫不及待来给小武哥打分了。小武哥真是我在大学遇到的最负责任的老师，每次答疑几乎都秒回也不厌其烦，而且他这学期居然没有找助教，所有作业都是他手批而且还会有批注。课前会有一道题作为课前测验，主要是方便他掌握大家的情况。教学方法灵活，会根据难度调整教学速度（前面有难度的地方讲的真的巨慢），但是上课不允许看手机，会经常提醒大家。作业量也还可以认真学并不难。总之，理论力学作为一个传说中挂科率很高的学科，如果你不想挂科，如果你想拿高分，如果你不想囫囵吞枣听完一节课啥也没学会还要靠b站大学，郑小武绝对是你的不二之选！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('657fd65c3a094c20e16b7b8b',876,876,'大家好我是可可，天杀的坏老头整天就知道说可可喜欢学习，我只是一条狗啊😭。不建议大家来选这个老头的课，因为重点到位课上全是干货，期末还狠狠捞人，这种好课就应该喜欢可可的人来选🥰',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('657fd22590d3d1241d6d0bce',35,106,'反正选了就准备唱歌吧，然后基本节节课点名。',2,2,2,6,0,0);
