INSERT INTO "reviews" VALUES('657fc1ca2be3a26cec81f1e7',1379,346,'上了两年多这课了，老师还是挺好的，给分也挺高，考试的时候只要动作会打都给了90。就是这课要记动作挺痛苦的，不过后面熟练了就好，也不用花太多时间，上课的时候认真点，要考试的时候再多练练就差不多。大一大二她考试要拍自己打的视频。每节课考勤。各种事情通知也比较及时（体测之类的），也比较负责。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('657fb08a90d3d1241d6cd25e',257,5,'人没得说，挺认真的，但是讲课真的听不懂还是得自学，要么说老师讲课经验不足讲不明白，要么就是我本人层次太低实在是听不明白他说的，考试都是靠自学',5,1,1,7,1,0);
