INSERT INTO "reviews" VALUES('657d3d3e90d3d1241d68a1d3',533,101,'芒姐我的神，讲课好给分高',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('657d3cff3a094c20e1670c3c',870,296,'感谢老师，很会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('657d3cb93a094c20e1670b70',307,307,'讲话听不清，测试特别多，学习通小能手，测试每道题都限时然后还不准看平时测验题目复习😍————爱来自数学的电🥰',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('657c82c24f66203748a5fd67',1291,22,'没上过课，但你大物实验讲了一个多小时只给几十分钟做实验，讲的还贼嘎啦听不清。这次实验是我这学期的第四次实验，结果在考试前两天才出，给了我70分，只能说你真牛逼。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('657c70c93a094c20e165b616',948,92,'优点：平时分高、很少点名。缺点：讲课不行，就照着PPT',2,3,5,10,1,0);
INSERT INTO "reviews" VALUES('657c705a2be3a26cec7c46e7',6277,6277,'优点：从不点名、平时分比较高。缺点：讲课水平一般',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('657c6fb92be3a26cec7c458d',958,23,'老师人很严肃，而且讲的确实快，而且偶尔拖堂。唯一的优点就是平时分给的高',4,3,2,9,1,0);
INSERT INTO "reviews" VALUES('657c6f044f66203748a5cb19',826,114,'口音很迷，而且讲的不是很好，前几节课听的课，后面是在听不了了去看宋浩了',3,2,3,8,2,0);
INSERT INTO "reviews" VALUES('657c4e5890d3d1241d66e40a',1590,1590,'很喜欢coco老师的上课风格，轻松加愉快，5％精力管理的理念真的很喜欢，在她的课上，可以随意发疯，可以畅所欲言，真的很爱，每到交作业比较忙的时候coco子还会自动给我们放假，这样的老师谁能不爱！真的很懂学生，很体贴学生的想法和情绪！太爱啦！快来选黄老师的课！',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('657c4c4f90d3d1241d66dde7',1590,7649,'喜欢coco.她让我开始认真对待设计。好可爱，好爱她',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('657c48c090d3d1241d66d423',1590,1848,'Coco老师真的很可爱，她的专业课和可持续都有上，上课很轻松氛围很好，就是Coco子废话多了一点。专业课一周看一次方案就行，而且提的意见不只是针对一个设计，对于以后做设计都很有用，适合积极上进想做好设计的人食用。而且Coco子每次打分都会给自己学生疯狂拉分，疯狂加分，狠狠爱了。可持续课也很有意思，每周发疯课，课上随便闹，随便玩，真的很解压，太喜欢Coco子啦！',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('657c41ce9c4d834fea154c82',1590,1590,'黄老师的选修课基本上不用做什么，十几周的课基本是上一节隔一周才上下一节的，期末周的时候还会避开交图考试高峰，上课还会带着我们做瑜伽，可以躺在瑜伽垫上睡觉，宽容性和丰富性很高的。黄老师专业课上对我们的指导可能不会像保姆啥的有求必应，你问问题就能得到一个让你满意的具体方法。但她会一针见血指出你的问题还有你设计的问题，同时给你指明学习方向或者设计方向（可能让其他人觉得讨厌和荒谬的就是这点吧），还会结合交图时间给你做出合理的规划建议。真的比那些只会找你设计的问题，还不告诉你解决方法，唯一解决方法法就是让你“去找案例”的花瓶老师好多了。觉得黄老师教的不好？找自己问题。',5,5,5,15,4,4);
INSERT INTO "reviews" VALUES('657c2c184f66203748a50405',913,611,'很好的老师，关心学生，迟到也不说你，上课不死板，上课氛围挺轻松的，上课做其他学科作业她也不会说你，上课经常讲别的故事，会跟你聊一些大学生应该有的思想',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('657bf4432be3a26cec7ac1a5',2500,228,'袁神，启动！',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('657bc8124f66203748a3c99e',294,294,'******实在是别的班选不下了，不然也没人来这个班',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('657bbcb92be3a26cec7a1a36',294,294,'******上课就会念ppt，一口东北腔，******在英国留学经历，实际就爱装，天天点名，不去上课，不管你生病不生病，直接给0分******她最好一辈子都别生病。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('657a772b3a094c20e1608f7a',405,7656,'这老师很不错。地下专业的学弟们我强烈推荐在大四上期选专业选修课的时候，选一门马龙祥老师的地下工程中的计算机方法这门课，这门课是教ansys的使用方法的，和地下专业课程设计简直绝配。这老师教的全是干货，想学ansys的大胆入。平时作业基本没有，而且没有期末考试。简直完美。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6579e2f23a094c20e15fba76',277,48,'上课多是自己练 也不盯梢 氛围轻松 老师人也非常和蔼 亲和力强 期末考试看得出来有在尽李捞了 打的比较差的都在八十多分 少数很会打的同学能给到九十分 可以选！',5,5,5,15,0,0);
