INSERT INTO "reviews" VALUES('65783fc24f662037489c6a3c',1419,48,'****** 自己天天窝在寝室打游戏导管搞的飞起都不愿花时间打打球。王老师国家级健将外面教球几百块一小时，学校里免费给你们这些饭桶教球还不乐意了，给分低就不要选，有的是人上。我当年被踢出校队半点话不敢说一句，只有对王老师的感激，让我意识到自己的不足，而不是像你们一样给分低就在这里叫。',5,5,5,15,5,9);
INSERT INTO "reviews" VALUES('65783ada2be3a26cec72d285',1418,1183,'非常棒，不是太过分的话基本不考勤，学到了很多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('65780d1a4f662037489c099b',172,39,'人说话捞又哆嗦，课讲的听不懂，完全不如助教，助教不在这老哥都不知道怎么组织，好要管班级纪律和集体意识？？',2,2,2,6,1,0);
