INSERT INTO "reviews" VALUES('6574a3603a094c20e15923ef',4695,7679,'老师人很好，确实是和蔼可亲，不是杨骏课听不懂，而是b站大学更有性价比（其实还是老师的课讲的不怎么好，不如直接听网课）。作业的话如果对编程感兴趣其实也还好，不至于像隔壁测编写起来痛苦，但作业的量确实有点大',3,4,5,12,1,0);
INSERT INTO "reviews" VALUES('6574a1909c4d834fea093914',630,630,'我不管他本身能力有多强，他作为一名教师，在他的课上我学不到任何东西，什么都还没讲明白就直接让学生做实习，差评',3,1,1,5,4,0);
