INSERT INTO "reviews" VALUES('6570803e9c4d834fea046195',5709,7694,'任平山老师 我的超人 上课从来不管你干什么但他自己讲的很尽兴 而且你认真听讲的话会发现他讲得非常好 ppt里很多都是他自己出国时拍的照片 而且他说“逃课没关系 我年轻的时候也逃课” 真的挺喜欢他的',5,5,5,15,1,0);
