INSERT INTO "reviews" VALUES('656f33b79c4d834fea027098',4352,4352,'这学期也不知道发什么癫，上课开始考勤直接上系统的那种，然后课一个学期比一个学期的水，给分的要求一个学期比一个学期的严。说什么慕课给我们分高，期末打分就要低，大家都六七十分，普遍比上个学期要少五分甚至五分还多。本来选他就是图个轻松分不低，真是脑瘫啊，辛辛苦苦奋斗一学期，体育连80都上不去，真是不知道该说点啥。想水课啥也不干的无脑选，但凡对分数有一点要求，快跑，头也别回，跑！！',1,1,1,3,3,0);
