INSERT INTO "reviews" VALUES('6565f4276aa58e39d92f9ead',2005,1697,'信我，想拿高分选她。我一点没学懂，把她平时小测题全背下来，考前复习了一天笔记，期末97，总评98。她上课问问题的时候最好应一下，没人给反应她会发火，尖尖的声音骂人确实有点受不了，但是平时她还是笑嘻嘻的。',5,5,5,15,1,1);
