INSERT INTO "reviews" VALUES('655ed8166aa58e39d918f443',1048,2735,'怎么说呢 这是唯一一个我上他课会觉得愧疚的老师 （因为我不怎么听也不怎么去）我上的是杨老师的线性代数 专业水平相当不错 老师本人平易近人认真负责 不点名 考勤分会拉满 讲课细致又有耐心 平时分给的超级高 会捞 非常适合自学的宝宝体质 快选杨老师！！！',5,5,5,15,2,0);
