INSERT INTO "reviews" VALUES('655ed4f36aa58e39d918ea69',1596,1596,'崔哥还是可以的，上课讲解很详细，线下作业批改很认真(所以想要划水赚分不太容易)，对能力提升很不错，上课不会一惊一乍的，自学和听课体验感都很不错。唯一缺点是说平时分给分比别的老师低，但是不得不说还是很可以的。澄清一下崔哥讲课零基础都能听。',5,5,4,14,2,0);
