INSERT INTO "reviews" VALUES('655cd98a6aa58e39d912da1d',7752,1154,'做个供变电课设课设要求贼多，总觉得哪里都有问题，要求每个小组的课设内容，公式，结果和选型都不一样，那干脆分小组干嘛，同样给的课设条件，公式和结果要求不同就呵呵了，而且不能分工合作，要不然就给分低，相当于六个人一起做，只给100分的六分之一即17分。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('655c5a27117ff355ed6870d6',3755,3888,'老师水平极其有限 不知道怎么来交大当老师的 来了十年多还是个讲师 没有任何研究成果 仅仅获得过三个奖 而且还都是指导老师 说白了跟她半毛钱关系都没有 上课只会念ppt 作业又多 课程设计还会卡人 动不动就说去副院长办公室 还说什么把你学习态度计入档案 她要这么牛怎么十多年还是个讲师',1,1,1,3,2,0);
