INSERT INTO "reviews" VALUES('655b3341117ff355ed64bd3a',307,307,'人比教材抽象😅，遇到他之后我觉得我的前半生很美妙😋。具体就是每节课用那个🪝学习通小测，每次限时，期中考也是，给分勾师一样，给他一点好评都是对其他老师的不尊重，请大家争取让他在活水成为三国杀一样的存在❤️。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('655b1717117ff355ed644f81',6377,7761,'上了他的《电子机械动起来》，一学期都在讲单片机构成和机理，期末就让做个有识别能力的车出来。啊？我学过吗？没学过啊！教给你的和你期末要用的完全是不搭边的，这课程对不起这选修的资格，自学内容非常多，PCB设计，c语言，软件使用全得你自己去学。',1,1,1,3,1,0);
