INSERT INTO "reviews" VALUES('654ef0fbc397986b141b4f14',1850,34,'肥肠优秀的老师，让我真正意义上感受到了大学与高中的区别，总得来说******，这么多年了都是这个作业量，我真的是服了，这么多年了有没有好好自学，这么多年都是这个作业量，有些时候找找自己的原因好不好******',1,1,1,3,1,0);
