INSERT INTO "reviews" VALUES('654de1fcc397986b1419b44c',264,230,'没什么好说的，神，神中神。选到他的课就是赚到。想听课的，绝对能学到知识；想水课的，从开学到期末，一节课不来大概率都能过。选就完事了',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('654d9d9b117ff355ed4a90e3',7801,7801,'项目找人是随机的，软件是不给的，进度是半年没有的，ansys是一个月要精通的，找茬是每次见面都有的，指导一点没有只会复读你说的话的，跟你说一套跟你队友说一套，专业水平堪忧，别跟他做项目别选他做导师，这会是你大学生活不幸的开始',1,2,2,5,0,0);
