INSERT INTO "reviews" VALUES('654b530a117ff355ed46f61a',7812,7812,'很温柔的一个老师，能给你的方案提出针对性的建议，尊重学生的想法，耐心倾听，不会把自己的想法强加给学生， 真的很用心，也很热爱教学！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('654b5264c4f6c57523fa8454',7813,20,'她真的是一个超级好的一个老师，能和学生感同身受，对学科教学有自己的想法，能上她的课三生有幸！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('654b5145c4f6c57523fa81ed',1773,1773,'他真的，我哭死，安排随堂半期考试，是8:30开始考，而不是8:00，太细心温柔了，感动！知道内容量太大，改开卷考试，期末会捞人。上课幽默风趣，会给编记忆的口诀，很有耐心，乐于帮助学生解决各种问题，治学严谨专业性很强，而且基本不点名，上课回答不出问题也会耐心再次讲解。总而言之是一个非常好的老师！',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('654b49d3c4f6c57523fa7574',442,573,'网上随便找个课都比你讲的好，天天惦记******雨课堂，变着法子扣学生的分，上课还经常卡壳******',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('654b305fc4f6c57523fa464d',373,230,'神中神，就选她，准没错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('654b08b7c4f6c57523fa0417',6377,7817,'学的他的《电子机械动起来》，单论讲课还行，但是他讲的跟我们要做的作业毫无关系，不知道听课拿来干嘛，完全就是自学。最后还要让你做一个机器人出来，上课内容跟课程大作业完全就是牛头不对马嘴。让你下载openmv，但关键是这软件他根本就没有讲过怎么用，只能网上查，那我还要你老师拿来干嘛，我自己自学不行吗。一坨苟史',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('654b0450c4f6c57523f9f702',785,114,'老师讲的很好，虽然普通话不是特别标准，但他已经努力的讲清了',5,5,5,15,0,0);
