INSERT INTO "reviews" VALUES('654aef82c4f6c57523f9d0a5',1955,194,'我是大一的，左东老师教我线代。先说缺点吧，作业很多，说话速度太快有时听不清，问题的时候会阴阳怪气（可能确实是我问的问题太低级？）。再说优点，很负责，会给你发很多练习题，往年卷子。我现在还没考期中，老师说期中没及格的，中午放学后必须补课。然后听老师自己的意思，再结合活水其他评价，平时分基本是给满的。总之是很负责的老师。',5,4,3,12,0,0);
