INSERT INTO "reviews" VALUES('653776b2c4f6c57523d80c29',741,741,'老师上课讲的贼快，经常抽学生回答问题，一讲课有7，8个同学被抽，而且把平时她口头上提的作业当做期中考试的一部分，突击检查收作业，同学们哀嚎一片。结论:跑，赶紧跑，别选这个老师',1,1,1,3,0,0);
