INSERT INTO "reviews" VALUES('65373815c4f6c57523d7a3b2',526,1651,'常言道“时间就是生命”。生命以年为单位计数，我的生活以分钟为单位计数，而画工程制图的时间以小时为单位计数，原来，生活与生存，中间只差一幅工程制图作业。谁懂啊，一幅大图，画了两遍，最后只有65分。为了作业能通过，我晚上熬夜画图，早上早起画图，努力规避上一幅图的错误，最后只能感叹“旧的问题解决了，只会产生新的问题”！是我手中的素描铅笔与A3图纸之间的距离太短了，我宝贵的时间，就这样在我的一笔一画中溜走了！我的作业分数，都藏在那些不为人知的小细节里了！一幅作品完成了，我两眼一花，还有好多页习题集作业等着我呢。课是好课，人是好人，作业不是人做的作业。手绘作业能不能赶紧滚出我的生活T_T',2,1,1,4,8,0);
INSERT INTO "reviews" VALUES('6537291b117ff355ed25b2af',7878,7878,'说话含含糊糊的根本听不清真的听不清楚，PPT战神，没讲几句就开始做题了，讲着讲着就跑题脱离了知识点碎碎念一些别的东西。',3,1,2,6,0,0);
INSERT INTO "reviews" VALUES('65370cef117ff355ed25854f',40,40,'老师很有实力，但问题实在是太多了，也不是嫌问题多，主要连气都不敢多喘，不知道啥时候就被叫起来了，真的让人很难受，分数也就那样，大家自己选择吧',3,4,3,10,0,0);
