INSERT INTO "reviews" VALUES('652f8766117ff355ed199a9a',6420,80,'想水课的千万别选，花样太多了。每节课都有花样提问，回答不上来还要扣分。提问还区别对待，有点ex，这个大家自己体会，对“部分学生”问“是不是”和“对不对”这种定性的问题，对“另一部分学生”问“为什么”和“是多少”这种问题。隔三差五还有课堂检测……',1,1,1,3,0,0);
