INSERT INTO "reviews" VALUES('6528a115117ff355ed0eefd9',1005,73,'老师好像很玻璃心，一边说着自己是40多岁了一边上课别人洗个鼻涕她都受不了骂课堂是菜市场，课上打了招呼去厕所都不够，还要继续揪着不放，群里面同学对她礼貌问候她也和同学急，真不知道是怎么当上大学老师的，天天说别人的时候也不看看自己啥样******',1,1,1,3,5,3);
