INSERT INTO "reviews" VALUES('6525e936c4f6c57523bc746f',1291,92,'其实除了说话不太清楚其他的都很好 毕竟老师本人知识储备很高 平时分给的也很高 也会捞人 特别爱点名，非优选班必点。之前听说这个老师怎么怎么不好 但是上完了感觉还挺好 没有想象的那么差 说话不清楚这个事 我感觉前排还是能听懂的 坐了一学期前排 感觉还挺好。',5,3,4,12,0,1);
