INSERT INTO "reviews" VALUES('6512cf7663372b4e217ecb73',1419,48,'******平时慕课太极拳健身跑全满分，最后两学期平均分还不到80，综合成绩专业前几也得不到一分钱奖学金，真有你的👍🏿👍🏿也就比艺术先强点，毕竟上课不想打球还能水一会😅',1,1,1,3,4,2);
INSERT INTO "reviews" VALUES('6512cb3e63372b4e217ec3b8',693,693,'******系统直接判重修算了，翻转课堂******，要是让同学讲能讲明白，******，发个课件，两次课件内容是重复的，顺序也不对，作业固定一周一交，没有答案，说是让同学评讲就算答案******',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('65129211156a2610d0c26b2b',1108,188,'看有评论说她不管玩手机和做其他事，我专门来说一嘴😅刚刚上课第一句话不准我们挂羊头卖狗肉，发现一次扣五分，第二次扣十分，第三次十五……我也不好说吧，不知道刚刚才说的是不是真的要搞，但是整得人挺烦的',2,3,2,7,0,0);
