INSERT INTO "reviews" VALUES('65024c9f63372b4e216397e0',2119,2119,'老师上课会一个一个点名，一节课前十几分钟都在抽人回答上节课的内容。讲课清晰易懂，人真的真的很好，给分巨高。要是自己学的话不建议。要是上课好好听，绝对能学的很好！邱忠才老师牛逼',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('65023c34156a2610d0a7dc52',1590,3369,'作业贼多，事不少，隔壁班只有个小组PPT，我们竟然除了PPT还有一张A1的大图，A1是什么概念，a1是8张A4的大小，还要求画满，最坑爹的是，这才只是开始，我们还只是场地分析场地调研，案例分析和自己的方案还没开始做啊！！！五星上将麦克阿瑟曾评价到:“如果我让我的士兵和黄媛学习建筑，他们一定会调转枪头打我的。”',1,2,1,4,5,2);
