INSERT INTO "reviews" VALUES('65019b0763372b4e21629bab',1193,27,'其实还行，虽然教的不好，但是除了上课不能玩手机之类的也没啥。课后基本没有作业，但是要记得刷u校园和视听说，平时作业就几篇作文。平时分都给到45左右了，课堂上发言积极的话（老师教的很简单，基本就是翻译句子）平时分也有50多。但是感觉教的不好，全靠自觉了',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('65017cc6156a2610d0a6bc4e',264,230,'一节课没听经常翘课平时分90+，期末纯裸考过了',5,5,5,15,0,0);
