INSERT INTO "reviews" VALUES('650178c063372b4e21625bf2',433,433,'说实话，课讲得不好，口语也不行，对待自己的ppt态度也不认真很多错的单词，作业也很多浪费时间的东西，她的课上学不来什么东西。但是英语课不能换，只能建议自己自学提高课程分，备考四六级了',1,1,1,3,1,0);
