INSERT INTO "reviews" VALUES('64feea1e63372b4e215e6a6d',2069,1743,'机械原理是一门偏难的课程，刘老师授课专业水平不容置疑，课堂氛围还好，上课也会给出历年例题来进行讲评，但是由于老师带着扩音器上课并且还有点口音，确实有时候听不太懂，还有就是老师会布置大作业，而其他老师听说是不会布置的，至于给分，我们届是直接给的总分，平时分不明确。',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('64fee413156a2610d0a2b96f',8086,8086,'张老师平时上课对细节把握得很好，语法点讲解到位。但要早读🥹，总体来说非常负责！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64fee300156a2610d0a2b7a4',449,449,'任慧老师其他课给分可能不高，但是演讲这门课给分是真的很大气，我属于稍微认真一点的，平时分直接给了99分⊙▽⊙，而且这门课任务真的很少，主要看有没有上台演讲的胆量',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('64fee13a156a2610d0a2b4fb',430,194,'虎虎yyds，上课很风趣，也挺水的，想学东西也能学到，给分很高，会尽力捞人',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64fedd29156a2610d0a2aa83',756,22,'金科老师真的特别好，期末该捞你他真捞你，60分险过，没有他我就挂科了，呜呜呜。金科老师上课很有趣会跟我们分享自己的想法看法还有一些哲学问题，讲题目也清楚（期末的时候还叫我们多看看哪些题目，结果真考到了）作业这周没做完可以允许补交，还不会扣你分，平时分直接拉满，我爱死金科老师了，一个长得帅且有人格魅力的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64fec38f156a2610d0a279b0',627,26,'很有学识在数学方面很专业，认真听的话会有收获，但老师嘴巴很毒，会打击学生自信心，只能说是个好的数学研究者，表达方式可能有些过于冷酷了',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('64feb6aa63372b4e215e071d',604,5,'讲得好，且认真负责，上课不用ppt,手写板书，平时分除了半期都是满的，凯皇yyds',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('64feb646156a2610d0a263dc',627,26,'讲得好，水平高，跟他学习知识的话没有任何问题。他比较喜欢骂人和嘲讽人，不过听他骂人是一种享受，哈哈哈，给分也是可以的，平时的作业交了就可以，平时分90左右吧',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('64feb4fc156a2610d0a2624d',1171,27,'每节课必点名，缺勤会扣分，上课比较有意思，也比较水，给分是按规矩给的，该多少就多少，不过那些平台作业只要你认真按时做了，分数绝对不低的，说分数低的都是自己的问题，而且课堂测试你可以在下面偷偷用手机。你上课就算一个问题都不回答课堂表现的5分都有3,4分。对于勤快一点的学生来说是非常不错的，平时分50+没有任何问题',4,4,4,12,0,19);
INSERT INTO "reviews" VALUES('64feac1663372b4e215df5fd',452,965,'******系统麻烦的要命，人还阴阳怪气，而且喜欢区别对待，你不在群里问她问题直接不鸟你******',1,5,1,7,0,0);
INSERT INTO "reviews" VALUES('64fe9cf6156a2610d0a23e2a',1171,27,'老师很有亲和力，比较接地气，负责任，给分较高，上课轻松，只要按要求完成平台作业，平时成绩不会低',5,4,5,14,0,18);
INSERT INTO "reviews" VALUES('64fe9818156a2610d0a23777',8096,23,'讲得非常的好，上课要认真听讲，这是我唯一一门从头到尾每节课都认真听的课，同样也是我唯一一门考到了90分以上的课，非常感谢冯老师。爱逃课的就不要选了，几乎每节课，除了课前签到外，都还要随机点名。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64fde10a156a2610d0a14c7e',1499,1499,'平时分给的很高（而且我大部分作业都没做）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64fdd5e0156a2610d0a13a2b',35,35,'老师特别好说话，讲话声音也很好听很温柔，平时上课有时候需要唱唱歌，期末是小组合唱汇报，打分超高接近满分！！！理论课的话有时候点名，实践课会学生自己在表上签到，还是很不错的，适合对水没要求但是需要高分的同学！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64fdcfa463372b4e215cd600',776,2397,'助教，老师都挺负责任的，每一次作业助教都会逐个批改，拿红笔圈出错的地方。但是老师声音确实很小，每节课后基本都有作业。老师也很想把班级带好，课后和他们联系他们也会给你解答。只能说想学肯定会有收获，但是有时候我确实听不清老师说的啥。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('64fd056c156a2610d09fe410',348,348,'转专业之前在凯老师这上的这个课，听说以前不是很好，但教我们这届的时候认真的挺好的，期末也捞人，解答问题也耐心，qq上找他问问题也回复的很快',5,5,5,15,2,9);
INSERT INTO "reviews" VALUES('64fc52df63372b4e215a86fc',1538,1073,'熊老师的高数课是交大最棒的！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('64fc29ad156a2610d09e9cac',5803,230,'说话口齿不清，根本听不懂，期末画重点根本画不到点子上，一个班最高分82，其他全是七十多八十 出头，平时分打的还挺高，但是期末都低得一。上课基本就是放放视频念念ppt。期末根本找不到复习点，属于是有力无处使',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('64fb6039156a2610d09d904d',8103,8103,'我只知道他的新生研讨课给分******',5,4,1,10,1,0);
INSERT INTO "reviews" VALUES('64fb5efd63372b4e21592d53',5732,5,'只要你会知识点，课都可以不去。平时成绩由期末成绩决定',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64fb5e7b156a2610d09d8e30',51,51,'除了要PPT演讲一次和点名外yyds。总评98，不多说了',5,5,5,15,1,0);
