INSERT INTO "reviews" VALUES('64f9c76e63372b4e21569730',3868,3868,'本来都没有注册过活水的，今天偶然搜了一下乔老师，原以为是5星好评没想到居然只有一星，我只能说乔老师学术水平相当可以，人也非常好相处，关键是给分高啊，不是你们怎么回事，又不想着认认真真学习，人乔老师还给你们这么高的分数你们怎么还在这不满意啊，各位，乔老师的课放心冲吧',5,5,5,15,5,1);
