INSERT INTO "reviews" VALUES('64f9186b63372b4e21556533',755,760,'唯一的缺点就是学生系统刚刚开始用会比较不适应，后面就好了，龚老师真的有那种成熟男人的魅力，讲课侃侃而谈，回答问题细心，选了不会后悔',5,5,5,15,1,0);
