INSERT INTO "reviews" VALUES('64f85b7963372b4e21544b1b',8128,8128,'属于上限高下限极低的专业了，拿高分不太容易。但是及个格稳的一批，考试七十分问答乱写都行，只要不留白绝对给你过。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('64f84f40156a2610d0988c83',3507,1732,'莫名其妙，千万别选。
INSERT INTO "reviews" VALUES('64f84f25156a2610d0988c70',3507,1732,'在这里有好评，我要认为是刷的了，他可能存在专业能力，但他的表达能力是足以让一个班的同学抢着换课的存在，一开课就让做一个叫Rodin的软件作业，这软件纯英文，网上也没教程，细说一下表达能力吧，每当我想尽量听懂他说的话，就有额，啊打断思路，一句话额，啊之类的词可能有3/4个，听下来完全不懂说了什么。所以22级他的班去的人很少，还得叫辅导员强制让我们去上课，想想吧',5,1,3,9,4,0);
INSERT INTO "reviews" VALUES('64f83c8c156a2610d0986c28',2433,760,'原神，启动！',5,5,5,15,3,0);
