INSERT INTO "reviews" VALUES('64f6f03c63372b4e21520981',8143,8143,'******装的一批，天天扯点有的没的，实际上只要你了解一点他说的东西就知道他纯不懂装懂，自己半瓶子晃荡，还天天装的大彻大悟，想着当人生导师',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('64f6ebd863372b4e21520106',5415,910,'平时挺水，期末给分不高',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('64f6d47f63372b4e2151d1a0',616,4776,'******会拿着嫖来的不知道哪里的讲义和答案照着念，自己啥都不演示，什么都不会教，只会说你自己不学。',1,1,1,3,3,0);
