INSERT INTO "reviews" VALUES('64f670b763372b4e21512e07',1291,22,'现在勇哥平时分给挺高的，不过课差不多得完全自学，说话依然听不清',5,1,5,11,2,0);
INSERT INTO "reviews" VALUES('64f5bd69156a2610d09489f1',2740,1753,'老师水平高教得好，上他的课不用带任何教材，不用看网课。而且人非常好，幽默风趣。还给分高海底捞！强推！！',5,5,5,15,1,0);
