INSERT INTO "reviews" VALUES('64f5465c156a2610d093b578',209,209,'懂得都懂，他在哪个时间段就赶紧跑吧，当然你要是精通模电的专业人士那当我没说',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64f545d363372b4e214f5c06',978,5,'这老师教的挺好的啊，尤其是他的复变函数，讲的清楚明白，只要平时好好听课，期末都不用复习的，百分百能过！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64f5452d156a2610d093b157',408,408,'可显着他牛逼了，上课搁那儿吹牛逼，被他给懂完了，平时成绩给的贼低，不知道给高分的人是什么成分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64f539e8156a2610d0939dd9',92,52,'平时去了，作业到最后交齐了，基本平时分就给满了，不过教的不行，得自学，除了给分高没啥其他的了',3,2,5,10,0,0);
INSERT INTO "reviews" VALUES('64f52904156a2610d093813b',5022,3641,'讲话声音又小，方言又听不懂，考试有考纲不给，平时分看期末成绩给，别说捞了…不踩你你一脚都算好的',1,1,1,3,0,0);
