INSERT INTO "reviews" VALUES('64f4789063372b4e214e3229',264,230,'老师期末划重点很准，平时分享的看法也很真诚。就是感觉这门课不太受重视，平时听的人不多，挺可惜的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64f415e0156a2610d091e38b',239,1854,'绝对是交大最好的老师！不仅是老师而且是朋友，人帅声甜，打球又厉害，很会和学生相处，完全感觉不到和老师相处的架子和紧张感，还经常带学生玩，真的爱死恒哥！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64f29a9463372b4e214b4cc9',6,619,'******平时上课手机管的贼严就算了，扣分也及其重。我按他的规矩有两个扣分项，平时分直接扣了40！光扣40就算了还莫名其妙多扣6分压到54！第一次期末总评57不捞，补考总评59？！！******就是故意挂人！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64f1a1bf156a2610d08e2835',14,51,'很好很好的老师，给分高，非常轻松，只有期末论文，没有要求字数，用心写加上自己的感悟即可高分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64f1931c63372b4e2149be69',8172,737,'Nice',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64eee47b156a2610d089ad74',709,949,'一句话“比******好多了”，专业能力过硬，素养很好，会提前给知识点，应该是会捞的，打分区间也很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64eee3e1156a2610d089ac0c',2213,2213,'说一个比较政治学，他压分，不明白能在大一学生上看到什么样出众且不同常人的科研色彩...',1,3,2,6,0,0);
