INSERT INTO "reviews" VALUES('64e0b52c180f890efe38266b',571,81,'只要不缺钱不迟到平时分就基本上拉满，就算扣了也能回答问题补回来。平时没有作业笔记pre等各种乱七八糟的事，上课认真负责，期末划重点巨认真。总之强推✋ ',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64def4890a07f07f3b436ab2',1770,3109,'可以选，好老师。',5,5,4,14,0,0);
