INSERT INTO "reviews" VALUES('64d832e90a07f07f3b36b55b',1122,3041,'梁老师非常认真负责，大一的好老师！读书的时候不明白。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64d4560c180f890efe228bae',83,83,'巨无霸好！！！选莎莎绝对赚',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64d1acac180f890efe1e05e4',8182,573,'好老师，可选。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64d03ece180f890efe1ba7b5',8183,2018,'水，不推荐！！！字多不一定描的好，字少肯定有道理。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64d03d0b0a07f07f3b29788d',3814,3814,'理论功底非常深厚的老师，也是为了同学们好的好老师，虽然有时候觉得老师愤世嫉俗，估计发自内心感觉恨铁不成钢。无可挑剔。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64d03c50180f890efe1ba404',1770,3109,'有原则的老师绝对是好老师，但不一定是招人喜欢的老师。感觉这是专业最为核心的课程之一，老师上课的时候给大家提供很多国内同一课程的在线视频作为课程补充资料，这样不懂的地方可以看，这一点比自己找好。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64d03a4b0a07f07f3b2974c8',389,389,'划重点，海底捞。结果你懂的。。。',3,3,3,9,0,3);
INSERT INTO "reviews" VALUES('64d0398d180f890efe1b9fd6',95,522,'普通话讲不好，不能否认是极其好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64cf15400a07f07f3b27aa0e',7473,181,'老师讲课挺好的，人也很温柔。可选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64cf14fa0a07f07f3b27a99d',6398,5151,'老师给分挺高。ppt做的挺好。就是上课感觉老师的表达能力一般，有时候有点把自己说急了的感觉。但是认真听课还可以。人也很好，问问题会很认真地回复你。可选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64cf13ed180f890efe19d425',674,307,'老师讲课挺好人也温柔。但是平时分确实给的低。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('64cf13730a07f07f3b27a6ab',5010,177,'很好的老师，讲课有条理突出重点，给分也高。而且很有气质很漂亮。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64cf12e7180f890efe19d298',2280,2280,'老师人好，给分超高，全部拉满，上课通俗易懂。推荐。企业专家授课的读后感好像是隔壁班老师有要求所以林老师才要求的。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('64cf12410a07f07f3b27a486',67,67,'林川老师的工程电磁场教的好，人也温柔，应该是胡建口音。这门课比较难懂，但老师讲完每个知识点都会问我们有没有听懂，我们很沉默的话他就会不厌其烦地一直重复讲哈哈哈哈哈生怕我们哪里没懂。给分也很高。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64ccd01e0a07f07f3b24198c',74,74,'你是懂出期末考试题的，王挂光。👍🏻',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('64c7bc77180f890efe0cedf5',1415,1415,'听力课作业有点多每节课会互动，给分不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64c7bbd80a07f07f3b1aa519',8196,4138,'给分嘎嘎好，95心满意足',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64bf2502fb52c431f74604c2',1419,48,'快逃！',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('64be462bfb52c431f744ce56',52,52,'马老师上课还是挺轻松的，虽然嘴上说不让玩手机，但是同学看网课还是没特别在意。讲课能讲清楚，但是容易偏题，提前预习了会好不少。期末会捞人，看情况高分也捞，不会卡绩点。',4,3,5,12,2,0);
INSERT INTO "reviews" VALUES('64bde4ed966d5d052c28bf2b',808,140,'感谢老师平时分给我拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64bde47f966d5d052c28be7a',8200,8200,'给分很高，老师上课也算佛系',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('64bca2a3966d5d052c26f511',7970,4198,'全能型老师。折磨人一流。',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('64bbaafefb52c431f7410cdd',876,365,'目前遇到的老师里做复习资料做得最认真的老师，一定要做完他的期末练习题，考试有奇效。一个挺有意思的小老头，他家泰迪狗很可爱，资料也很不错，期中考的太烂也没关系。总之上郑老头的课，只需要:不在课堂上睡觉，每次作业都交，复习题认真做完，考85+特别轻松，选他不怕踩雷',5,5,4,14,3,0);
INSERT INTO "reviews" VALUES('64b8fbeefb52c431f73cf8f8',1370,1183,'最讨厌，没有之一。成绩高的他会降你出勤分，成绩低的他会提你出勤分。好家伙，你给分是真灵活，合着就硬降低分差呗。想要高分的别来沾边，除非你的网球特别擅长，除非你是体委',1,1,1,3,1,2);
INSERT INTO "reviews" VALUES('64b4cf0ffb52c431f735b710',22,92,'选选选！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64b4ceddfb52c431f735b6c5',2139,2140,'我不好说',3,2,2,7,1,0);
INSERT INTO "reviews" VALUES('64b4b709966d5d052c1a2ca7',22,92,'黄老师神中神，讲课很清楚，学习通上会上传课件、往年试题和作业习题讲解',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64b2ce47fb52c431f732ccd5',1394,230,'谁能拒绝一个平时分给90+的老师！讲得非常好，上课不点名（下课要定位签到）人也非常真诚 期末甚至会给同学写信',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64b2ad56fb52c431f7329ac4',2424,2178,'学的土木工程地质，全班通过，平时分拉满，神中神',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64b14b8a966d5d052c152a43',1307,1307,'何刘老师人帅心善我超爱，不知道怎么挂🥰🥰',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64b14ae9fb52c431f7309020',1307,1307,'老师真的人超级好！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64b09e63966d5d052c13bf87',563,228,'改革了，上课没有回答过问题，平时没有作业（只有个大作业ppt），期中开卷，上课不为难，你该咋咋，两节课点次到，平时分挺高',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('64b0651f966d5d052c138015',1770,3109,'如果英语好，可以选双语刘老师的课，听说要求低一些。今年老师把前面几年的课程成绩数据发在群里，每年都是100多人的大课，还是666。。。',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('64af4103966d5d052c117fd0',1307,1307,'中肯评价，给分按照平时作业情况来的，老师人特别好，特别好说话，实习也不为难学生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64aeefeefb52c431f72c8e44',1093,1638,'不知道捞人为何物不知道好评是为什么 ：）
INSERT INTO "reviews" VALUES('64aeef10966d5d052c11218c',1653,198,'纯÷ 平时分巨低 选就裂',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64aed3bd966d5d052c110191',545,433,'平时分给得很低，上课讲得很散。',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('64aecf6a966d5d052c10fa98',18,18,'概帮帮主！',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('64ae8a36fb52c431f72bd378',5073,313,'好像期末是挺低的，但平时分给得还可以啊。倒是这个老师平时上课爱抽人，说话断断续续（有点像一口气上不来的感觉）比较让人介意。人还挺亲切的。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('64ae86ed966d5d052c106674',535,535,'讲的很好，平时分是跟着期末打，期末高，平时就很高。很好的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64ae32e3966d5d052c0fd61d',2745,2748,'课堂体验较差******每堂课都点名，缺勤就追着你点一学期。考试不画重点（一开始说给画的，后来反悔了😅）就给你几百张PPT看，考试出的填空题很偏，根本填不出几个，分数登了两个星期（😅)，还以为他在想办法给我们加分，最后平时分还都只给个七八十分。
INSERT INTO "reviews" VALUES('64ae0d39966d5d052c0f53a8',3489,4290,'虽然平常上的很难，但是期末比较简单，会说要考什么题，好老师',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('64ae0d1dfb52c431f72abadb',8222,8222,'分还给得挺高的……虽然行策学分太少没啥用，但事少分高没窒息操作还是挺难得的，五分送上。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64ae0b18fb52c431f72ab860',736,8223,'真的是个好老师。因为linux的东西全要自学，周老师实验出得都不是很难（对比其他班），符合大部分普通学生（比如我）的水平，验收也不是很严。分数也还可以。每次都会提醒大家走之前带好东西，挺细心的。课程设计也专门在群里提醒了注意事项。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64ae0979fb52c431f72ab5f3',736,3098,'不拖堂的周老师简直无敌了。讲课思路依旧很清晰 声音也一点不含糊，会评讲作业（而且作业也不多吧，就五次好像），半期考试很松（今年是直接发下来当作业做的）。在群里还会回复消息发表情包Σ(っ °Д °;)っ，怪搞笑的。点名都到了的话 课堂表现应该是拉满的。这课英文考试确实比较恼火，考完之后老师还在群里总结错的多的地方提醒大家。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64ad9cbafb52c431f72a474a',67,2121,'老师很温柔，上课氛围也比较轻松，讲课好给分高，偶尔上课还会聊一些老师自己总结的人生哲理',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('64ad9b7d966d5d052c0edece',2210,281,'卿老师对学生态度很好，会积极解答学生的问题，上课讲课很有逻辑感与启发性，会拓展一些课程外的知识点，有助于理解。考试前还会组织一次考前答疑，会讲一些考试的考点',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64ad99cf966d5d052c0edd35',674,2155,'叶老师讲的很好也很有逻辑，想期末拿高分只要上课认真听课就行，几乎不需要花费课下功夫，可以省下很多时间去学别的。平时分确实给的不算高，但也中规中矩，你要是平时什么都好好做了也不会和别的班差很多。总的来说叶老师适合想好好学的学生选，不太适合只想混个期末不挂科的，所以评价才这么两级分化',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64ad8cdffb52c431f72a3494',691,228,'22年上的，老师还不错，靠着每堂课回答一个问题成功拿到免考名额',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('64ad3937966d5d052c0e2b55',348,348,'我为凯老师举大旗！之前有听说凯老师不太好，但是上了他的课，他真的改变了许多。平时分给的很高，而且会捞人，真的太感动了。点名也不多，除非人少得明显，但是也能去找他补签。平时有什么问题，QQ上也基本是秒回，非常赞₍₍Ϡ(੭•̀ω•́)੭✧⃛',5,5,5,15,2,8);
INSERT INTO "reviews" VALUES('64ad3851fb52c431f7298d58',504,5,'上的她的高数。简单来说就是可以把89拉到90，但不能把87拉到88。虽然就一分，但是也不能一样的作业一个给100，一个给85吧',5,4,3,12,0,1);
INSERT INTO "reviews" VALUES('64ad3763fb52c431f7298bd2',5267,837,'老师人美，教的也很好，上课收获很多，但是对于上课纪律管得挺严，不能中途上厕所也不能逃课。给分挺高的，想认真学习的可以选她',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64ad3747966d5d052c0e2821',4784,2259,'见评分，形式主义',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64ad2531fb52c431f7296fb8',2745,2745,'不针对这个带队老师，只针对这个实习本身。
INSERT INTO "reviews" VALUES('64ad225f966d5d052c0e0511',3507,1732,'年少不知飞哥好，错把宏宇当成宝😭',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('64ad1eba966d5d052c0dff6f',27,27,'老师很温柔，给分高，很容易过',5,5,4,14,0,0);
