INSERT INTO "reviews" VALUES('64ac16c0fb52c431f727ac47',74,74,'烈日炎炎当牛马
INSERT INTO "reviews" VALUES('64ac1683fb52c431f727abf8',74,74,'可以说脏话吗？',1,1,1,3,12,0);
INSERT INTO "reviews" VALUES('64abcca8fb52c431f7272019',42,5127,'人美温柔心善 平时分拉满 推荐！',5,5,5,15,5,2);
INSERT INTO "reviews" VALUES('64abc870966d5d052c0bb57b',676,676,'老师人很好，事少分多，讲课也不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64ab81d3966d5d052c0b29b5',533,101,'很好的老师，讲课思路清晰而且有耐心，即使是课下去问问题也会耐心解答，很站在学生角度帮忙考虑。平时分直接拉满，期中和课堂小测我有蛮多没写出来的也给了90和95。芒姐我的神，好好学大胆冲！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64ab805afb52c431f72692a0',1770,3109,'其实还可以',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64aacec9966d5d052c0a19ff',2136,313,'平时分😅',3,3,1,7,1,0);
INSERT INTO "reviews" VALUES('64aa9333fb52c431f7251b28',3442,1500,'很无语，请假之后算我缺勤，后来说只是记录但不扣分，最后期末成绩出来又说忘记统计了，总分少了整整两分。而且半期考试的试卷拖到快期末的时候说开始批，期末也是考完一周才批出来。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64aa6ef9966d5d052c097636',3473,3473,'这门课平时很轻松就期末一个论文，而且论文只对格式有要求内容只要不抄的太离谱都给高分。愿意做PPT上去汇报甚至可以综评给100。老师非常和善友好，理解学生。想出国拉均分或者凑学分大胆冲。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64aa5836966d5d052c094e2c',452,452,'才来大学的时候听学长学姐们说郝老师阴阳怪气，其实现在已经改了，已经很有亲和力了，班上同学都开始喜欢她了，平时跟除了期中其他都是拉满了的，而且期末会画重点，让你期末考无压力。我们这届很幸运，刚好遇到改后的郝老师',4,4,5,13,3,1);
INSERT INTO "reviews" VALUES('64aa4ddf966d5d052c093e8d',1756,52,'给分还行，讲课讲不明白',3,1,4,8,1,0);
INSERT INTO "reviews" VALUES('64aa2ff9fb52c431f7248812',74,74,'平时的教学与期末考试无关，实习更是离谱，感觉像故意刁难学生一样。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('64aa1ae2966d5d052c08f5e8',311,1514,'很好呀，老师很和善，上课干啥都行，还能时不时学学养生方法啥的，期末考试的时候会给你们发一个知识点，可以打印开卷考试，考试的时候除了主观题全是那上面的，就是找不同就完事了。主观题多些点就没事，总评98，而且他上课还有加分项，如果你去做个课程汇报或者上跟着老师做个五禽戏，我盲猜给满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a9ec70fb52c431f7240e15',1770,3109,'可能觉得是对自己读研读博后最有用的一门课之一，读书的时候觉得老师要求严，不划重点，讲的多，作业多，每堂课小节，课程报告，平时分和期末分也高，等需要的时候才发现给自己打下非常好的基础。谢谢老师！！！',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('64a9a0f1fb52c431f723cb72',191,191,'平时分除开期中考都给满了，老师长得不漂亮但可爱，上课也挺有趣活泼的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a98e35fb52c431f723b7e7',74,74,'******优选班老师是他，上课换啦实习换不了，早上迟到半个小时还好意思说别人，实习内容比别的老师工作量大至少一倍，感觉就是心里有问题故意刁难学生，******反正见到他跑就对了',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('64a96a48966d5d052c07e415',4084,1702,'恶心人，明明是只用看慕课的水课，平常慕课作业超级多，认真做了慕课作业，结果大家都一起75分，期末考试没有通知，没点进去慕课看到考试就期末零分，40多个人的课，20多个零分，大三下修的课******',1,2,1,4,3,0);
INSERT INTO "reviews" VALUES('64a92bf6966d5d052c075f5d',8256,8256,'只会提要求不会教，自己很专业懒得带学生，给分很低',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('64a91a24fb52c431f722a3ba',1949,230,'平时分太低了！！！避雷避雷！',3,3,3,9,1,0);
