INSERT INTO "reviews" VALUES('64a907f6966d5d052c06d827',887,23,'金艳姐姐我唯一的神，期末总评94😉',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('64a903d0fb52c431f7224cc1',8147,26,'期末比室友高18分，最后总评还比室友低',1,2,1,4,0,0);
