INSERT INTO "reviews" VALUES('64a901f1fb52c431f7224a81',8264,96,'主打一个水，人好事儿少，几次签到没签上平时成绩也基本满分，考试前特别能划重点，杨老师我爱你',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a90049966d5d052c06ccb7',8265,26,'讲得一般',2,3,3,8,0,0);
INSERT INTO "reviews" VALUES('64a90025fb52c431f7224811',5549,8266,'您要求严格，教学严谨我觉得没问题，但是您给分赏罚不明我觉得有很大的问题，比如说课设画大图，淘宝上买图完全没自己画的同学最后的分数却能比完全自己手画的同学高很多。这样的迷惑评分标准以后谁还愿意选您的课呢，谁还愿意自己去手画大图呢，大家都去淘宝上买图得了。说严重一点，就是教学事故',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('64a8ff44fb52c431f72246b0',2447,23,'一般',1,1,1,3,2,6);
INSERT INTO "reviews" VALUES('64a8fe83966d5d052c06c991',2210,114,'跟着卿铭老师学，完全不必看网课了，讲得嘎嘎好，给分嘎嘎高！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a8fd7a966d5d052c06c795',716,729,'很好，平时分超高！',5,5,5,15,0,0);
