INSERT INTO "reviews" VALUES('64a8c6d1966d5d052c0671d6',648,889,'平时作业有点多（都是书上的题），定期提交。偶尔微助教签到。有一个课设，老师会给一个上届的模板（可作为参考）。平时讲课讲的很快，但是期末会给复习PPT照着那个复习过肯定没问题的。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('64a8c5f8fb52c431f721f039',8273,4961,'不点名，平时没作业，有一个课设（给分85左右），平时分还行，期末不怎么划重点（不知道其他老师划了没）。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('64a85740966d5d052c0604b6',1062,352,'上他的线性代数，口齿不是很清晰，有小测，每周都要交作业，平时分给的很低，我期中90+，平时经常回答问题，最后写建议，给了我80+的平时分，然后ppt做的也不是很好，看着费劲。好像研究方向是线性代数相关的，但是这点对我没啥帮助。平时挺负责的。',4,2,1,7,3,0);
INSERT INTO "reviews" VALUES('64a8458ffb52c431f7216f3b',2231,256,'会捞人，人很好，会划重点，会给复习提纲',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('64a844b6fb52c431f7216e38',4438,22,'老师人挺好，我物理不好所以觉得课还是干货满满。只要平时按要求完成任务，期末好好复习，分不会难看。平时分挺好挣的。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64a835a4966d5d052c05d980',1289,1449,'认真负责的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a8143dfb52c431f721107f',2280,2280,'本来平时期末37开改成46开，而且那四十分平时分只要期末有个五十几都拉满了，期末改的还非常松。分低或者挂了是这门课比较难，不是王老师的错，他已经尽力在送分了，不知道为什么评分这么低。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('64a8065bfb52c431f720fc83',2178,2178,'讲的不行，别的老师都是97，他给70.80，快跑，真是倒大霉遇到这老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64a7f2f8fb52c431f720dbcc',2429,2178,'听课时嘲笑巫锡勇，半期时诋毁巫锡勇，期末时理解巫锡勇，出分时感激巫锡勇。',5,4,3,12,0,0);
