INSERT INTO "reviews" VALUES('64a7ebcefb52c431f720d1a5',1033,736,'好老师，我上的数学系的数据库，老师平时分直接满分，好老师，好老师',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('64a7e52efb52c431f720c876',3202,551,'爹',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64a7e2c5966d5d052c0548c1',351,351,'下面那些我也不知道什么情况，反正我的平时分是拉满的，思维导图有让做，但是在平时作业完成的情况下做不做也没有什么影响',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a7e21f966d5d052c0545ae',1350,5405,'人美心善，给分高，线代平时成绩公布那会给我惊呆了，直接拉满，无脑冲',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('64a7e1eafb52c431f720c2f6',616,8286,'平时分给的贼低，期中考试一堆作弊的还占总分的百分之二十五。期末考划范围一直强调某个代码，结果考了另一个，就是想耍你，建议避雷。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('64a7dc62966d5d052c053e02',802,706,'李明老师神中神',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('64a7d923fb52c431f720b658',23,23,'神中神，超级负责的一位好老师',5,5,5,15,20,0);
