INSERT INTO "reviews" VALUES('64a7a924fb52c431f72060ad',631,74,'
INSERT INTO "reviews" VALUES('64a7a7e4fb52c431f7205ee1',631,74,'想体验工地生活吗？想体验穿上雨衣当晴天，打开灯光当白天的经历吗？那就来选高山的实习吧!从早上6点起床到晚上8点回寝，选最难测的八教，选要求最严格的老师，让你体验真正工地之美。想让高山教你测量中的问题？不存在的，一个合格的土木人就应该自己摸索，但是亲爱的高山总是能在你测绘到一半时指出问题，让你再体验一遍测量之美。总体而言，如果你想体验真正的工地生活，体验人生第一次睡着在路边的椅子上,睡在路沿石上，就选高山吧！抢晴天，抓阴天，牛毛细雨当好天，月亮底下当白天，晴天一天顶两天，小雨大干，大雨硬干，暴雨钻空干，没雨拼命干，干！干！干！',1,1,1,3,12,0);
INSERT INTO "reviews" VALUES('64a79a68966d5d052c04d018',631,631,'平时分给的还算高，但是千万千万不要靠近他的实习
INSERT INTO "reviews" VALUES('64a79819fb52c431f7204abc',8294,8294,'平时很好，冷不防一个背刺，平时成绩给这么低我真是绷不住了',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('64a795f3966d5d052c04ca6a',8295,2461,'李老师的专业性很强，并且知识点重点程度非常明了，考试前还会划重点，半期考试开卷，给分一般，就是平时作业和课设比较麻烦，容易重做重交。',5,4,2,11,0,0);
INSERT INTO "reviews" VALUES('64a794b3966d5d052c04c8a3',7062,779,'听他讲不如自学，但是给分确实可以，即便你半期考试啥都不会，期末平时分依旧给了九十多。',2,2,5,9,0,0);
INSERT INTO "reviews" VALUES('64a79435fb52c431f7204578',4250,2713,'去年上的她的数据库原理课，上课点人很厉害，纪律管的很厉害，平时作业要扣分。总之我上她课挺累的，喜欢自学的不要选她。',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('64a78859fb52c431f7202f60',631,74,'实习就是依托，不想搞就别搞，别恶心学生',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('64a7829dfb52c431f7202807',631,74,'说实话，赶紧跑，什么＊＊老师',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('64a78120966d5d052c04a895',5170,1241,'学他的物化，期末考的比平时分高，牛逼class',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a77f40966d5d052c04a644',631,74,'来过就知道，不来吓一跳，来过实习的才知道，高山有多棒👍🏻',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('64a77b07966d5d052c04a084',616,8286,'期中懂的都懂，大家都是顶级特工。主要是几百行的代码让你背，背了就有分，感觉还不如数电。老师讲课就吹牛，说出来就年薪xx，就搁这画饼。这门eda就当文科学就可以了。',3,2,3,8,5,0);
INSERT INTO "reviews" VALUES('64a76682966d5d052c04857a',4941,1353,'要学知识不如其他老师开的职业生涯大发展与规划，分数给得又不高（平时，期末），还有期末考试，因为选课人太少还喊大家去帮她宣传，蚌埠住了',1,3,1,5,0,0);
INSERT INTO "reviews" VALUES('64a75f04966d5d052c047b53',616,8286,'期中考试大家怎么做的老师心里自己不清楚吗？一个学期点了七八次名结果最后考勤不计入平时分。。。',3,3,3,9,4,0);
INSERT INTO "reviews" VALUES('64a7005dfb52c431f71f5d22',563,228,'个人认为老师没大家说的那么差。2023上学期老师就改变了自己的教学模式，没有让同学讲，每次老师讲课时能够明显感受到他有在认真备课，老师的知识储备量也非常丰富。平时作业开学的时候说了蛮多项，其实最后也只要求我们做实践作业，并且没有要求小组必须上去展示。平时成绩给分只要你上课坐前面一点，能否够和老师有点眼神交流，平时成绩能够拉满，而且老师上课也说过不会让认真的人得到不公平的分数（对于课代表能免考也能够理解，毕竟课代表帮着老师做了蛮多事情）。期末的时候老师会给重点的范围，选择题三分之二都是从公众号上面出。个人认为这位老师还是很推荐的，没大家说的那么恐怖。',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('64a6f834fb52c431f71f5554',2306,2306,'大三下59.95挂人 没什么好说的 当他的学生就是他的仇人',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('64a6e7c9fb52c431f71f450f',2267,177,'讲课不太行但给分高啊，想要自学的速来，人蛮好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a6ddee966d5d052c03b585',52,2724,'上课水但是给分低。。当时上的是好几个老师一起，各自分开板块讲，最后期末挑三个老师讲课内容交三个小作业再加一个期末大作业（？好像是）上课玩手机写作业啥的倒也不管，期末认真写了作业结果85都没有。。想水学分的可以，出国刷绩点不推荐',2,3,3,8,1,1);
INSERT INTO "reviews" VALUES('64a6c890966d5d052c0384a7',631,74,'无知时诋毁丽丽，成熟时理解丽丽。丽丽为什么平时分毫无水分，期末不捞人呢？是为了告诉你土木工程的路没有捷径和侥幸可言，今天的纵容是对你明天的损害。其次是典中典的实习。在七月的日晒与蚊虫下，丽丽选择最恶心的八教，是为了让你知道，平静的湖面练不出精悍的水手，你的土木人生会更加坎坷。丽丽对实习的一堆******，是为了让你清楚以后的领导不会对你和颜细语。丽丽给你过期五年的仪器，会让你晓得土木的工作不会事事如意。丽丽整个测量的五天只在群里发号施令几乎不来现场指导你，是为了养成你独立思考的能力。曾经我也和大家一样，说******。可是现在我悟了，******而是用他的码让我知道，土木的水很深，你把握不住',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('64a6b259966d5d052c036358',52,52,'满昏，平时分快到一百了，其他的在交大众多物理老师中已经算好的了，人也挺好的',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('64a6a9a5fb52c431f71ecc21',353,859,'说实话，别被一众好评骗了。上的城规，一学期下来，基本每节课有作业而且量大，有期中考试。老师无论是上课还是为人都很好，划重点更是一绝，精准简洁，除了选择你该知道的都知道了（懂得都懂），选择每个也指了方向。但给分实在不怎么样，有压分的嫌疑。头天晚上考试，第二天就出成绩，改卷质量实在不敢恭维。我把重点背了很多遍，考完试感觉也很好，结果就那点分我是不相信的，身边也有人有这种情况。相比之下，李明就很好，听说给分高改卷松，平时作业少没有期中。总结想得高分的选李明，期末来听王斌划重点。',3,3,5,11,4,2);
INSERT INTO "reviews" VALUES('64a6a79dfb52c431f71ec8e9',6396,6396,'专业性强，但上课老吹牛b，下课各种任务，后期就全是翻转课堂让你自己讲。但助教很好。',4,1,1,6,0,0);
INSERT INTO "reviews" VALUES('64a6a70bfb52c431f71ec815',2278,2278,'隔壁王德林平时分给满，陈不给满，复习也只是嘴上过一遍，重点什么都没有',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('64a6a50efb52c431f71ec53b',708,708,'放养式。   ！ PPT题没答案，作业题没答案，也没评讲，期末复习不说话，出的题还变幻莫测，🐴🐴啊',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('64a6a394fb52c431f71ec220',2280,2280,'老师人非常好，平时分直接拉满，上课画重点，期末改卷也松，也非常喜欢学生答疑。老师人实力也很强，本硕C9，真搞不懂评论区里的出生怎么评论的😅，自己菜逼怪老师是吧，活该挂科。反正老师人很好，比隔壁班陈明武好多了，冲就完事了',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('64a6a141fb52c431f71ebcc4',2278,2278,'隔壁班王老师平时分直接100，这边上课不回答问题直接80多。😢呵呵，输在起跑线。属鼠喜欢自学就要受到这样的惩罚吗',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('64a6a022fb52c431f71ebb1f',2136,313,'避雷，点名没缺，作业次次交，平时分只给七十，天天上课都要点名，还有提问，也会布置作业，讲的又没什么用',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('64a69b7f966d5d052c0339ae',2851,837,'作业量大，从不点名，课堂效果需要一定的自学能力，分数给的很宽松。整体比较推荐',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('64a69006966d5d052c032507',2302,2302,'这个课设立的初衷是好的，就是想让我们什么都学一点，可是老师可能是准备不充分的原因，教的东西自己都不会，上课不用PPT硬讲，表达能力也比较差，说话就像说给自己听一样，全程不看讲台下，期末的时候大多数人都是懵逼的，根本不知道考什么怎么考，参考教材看了也没用，但他期末还是捞了一手，不至于挂人，总结就是一个强行加到培养计划里的水课。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a684cdfb52c431f71e8b4e',2851,837,'上课不点名，作业按时交了，好好写写，都给不少的分，期末不给重点，上课讲课要靠自己悟，口头禅是不能再说了，你们自己想，老师的能力毋庸置疑，通过率也有9成左右，小东西们自己珍重',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('64a68369fb52c431f71e8971',2302,2302,'有点抽象说实话',4,1,1,6,1,0);
INSERT INTO "reviews" VALUES('64a68357fb52c431f71e895f',2302,2302,'神级好老师，讲课幽默风趣，分数给的很公平，在运输专业课老师中算最好的了，期末会捞，基本没有挂科',5,5,5,15,0,0);
