INSERT INTO "reviews" VALUES('64a66962fb52c431f71e5541',7336,8324,'上的瑶瑶老师的《机械制造技术基础》，上课什么都没听。瑶瑶老师水是真水，期末考42就过了，捞是真的狠捞啊。想水的同学可以选（期末也得看书），想认真学的请避坑。',5,5,5,15,0,3);
