INSERT INTO "reviews" VALUES('64a66807966d5d052c02daa1',3258,8327,'冲就完事儿！选的老师的大学生心理健康，讲得很好，很可惜有几节课为了补作业没有听,真的可以学到心理知识；而且老师很善良，签到不多，作业不多，考试开卷给分也不吝啬，最后总评96。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64a65a42966d5d052c02ba2f',8328,230,'呵呵，提前五天截止网课记分，没谁了吧。直接挂了一堆人',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a64f76fb52c431f71e1b8f',5002,3026,'******讲得差，一节课没几个人，一学期只有第一周布置过作业😅 后面纯摆烂，期末隔壁班写满都考六七十分，我们班二三十分一大堆，也不捞人。期中考试前一周还说不考试交报告，后一周马上改口了，期中考试还占30%，选到就是恶心到',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a63f51966d5d052c028d02',82,476,'超级温柔，给分很高！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a63500fb52c431f71de7a2',613,43,'数电实验净关注那波形图，图稍微差一点直接不看，浪费一次机会，三次全浪费机动周不能补验',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64a62e5e966d5d052c0269c8',741,2862,'这个老师上课和平时挺严厉的期末考试也出的很偏但都是上课讲过的，平时好好听吧，平时认真期末会狠狠捞的',3,4,2,9,0,0);
INSERT INTO "reviews" VALUES('64a62c2cfb52c431f71dd9bc',631,74,'我只能说兄弟们看见了这条评论快跑，这老师老古板文字题不会给同情分，并且最最最恶心的是他的实习，工作量是别人的6倍，而且要求很奇葩！快跑！！！',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('64a62c1ffb52c431f71dd9b5',4084,8140,'****老师，一个线上MOOC，期末考试MOOC上不签到就给0分，教务也不发邮件提醒，正常人谁会考完试还一直关注你MOOC消息啊，一个水课挂一堆人，而且都是大三下的，挂了直接延毕吧。',1,1,1,3,5,0);
