INSERT INTO "reviews" VALUES('64a59a66966d5d052c018ce6',1394,230,'老师讲课非常棒，但给分属实一般，作业按要求完成，没缺过课平时分虽然有90但相对其他老师95，98的确实会低一些，这学期最后一次作业截止时间居然在考试周不是很理解',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('64a599ed966d5d052c018c38',1499,1499,'近代史平时分直接100 神中神只能说',5,5,5,15,0,0);
