INSERT INTO "reviews" VALUES('64a5994bfb52c431f71cfcad',3036,3113,'说算法课。讲的细，ppt也做得很详细，作业每次会发答案，会讲解作业思路。也不严格。实验也比较松，报告只用交一次（不用预习报告），实验做完后也会发示例做参考。讲课也围绕考试讲，重视基础。实验考试还特地提醒大家先做简单的后面两个题，半期考试出题也有选择题。给分也还可以。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('64a59686fb52c431f71cf8bb',2739,2739,'快跑！Python的数据结构，隔壁班一堆98、99，教的东西一样，听课效率一样，这老师平时分给七十多直接跟隔壁拉开距离，平时分巨低，期末考试给分巨低，导致最后总评也巨低，跟隔壁班比不了一点。总之，想最后分数好看点，就别选他！不懂为什么这老师这么想让学生挂吗？',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('64a548f7fb52c431f71c55c7',5198,376,'******平时分是我见过给分最低的老师，没有之一，随随便便挂人，不知道五五开的比例是为了什么******',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('64a53f4bfb52c431f71bccd6',75,75,'很好的老师，平时作业过期了也能补做，平时分基本给满分，上课也很少点名',5,5,5,15,0,0);
