INSERT INTO "reviews" VALUES('64a53850fb52c431f71bbdb7',452,965,'老师比较严格，作业也很多，但是讲得确实比较好，如果想认真学习或者高中没有化学基础的可以考虑选她，但是如果想水课的还是不要选她了，平时分给的其实也还可以，有利有弊吧。',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('64a5383b966d5d052c004cc5',7758,313,'什么样的辅导员有什么样的下级，暂且不谈袁导本人有多故步自封斤斤计较，其下属年协就令人发指。
