INSERT INTO "reviews" VALUES('64a52ea3fb52c431f71bad2d',360,360,'这门课课程难度对于我这样整个大学没什么编程经验并且数理逻辑不好的混子来说难度挺大，理论课的考试可以通过背考前老师发的题库拿到前面选填的30分，不太会挂（老师还会挽救大家依托史的期中考试成绩）主要是实验课！！！因为有上机考试的存在，所以对于不怎么编程的同学有挑战。如果你和我一样，混过了前两年的话，建议在你看到这条评论的这一天起就养成写LeetCode的习惯！！！推荐按网站“代码随想录”中：回溯 贪心 动规三个板块的顺序去刷题，这三种算法也是考试的重点，掌握了的话通过课程完全没问题~
INSERT INTO "reviews" VALUES('64a52bf3966d5d052c0037bf',2713,2713,'非常负责的老师，讲课水平也很高。虽然每一章讲完都会有小测这一点平时很让人心烦，但到了期末才知道好（如果小测不是全抄的话',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a52b2f966d5d052c00366f',8371,3098,'事少作业少，但是讲课不太行，建议从一开始就做好自学的准备，期末考试题目也不算难',4,2,4,10,0,0);
INSERT INTO "reviews" VALUES('64a52a0afb52c431f71ba5aa',8372,3287,'找助教验得多，但找老师验得几次感觉也还好（本人每次都是抄的，验收得分均下来应该有B+，这门课验收就得会扯，哪怕全是抄的也得有底气。不过代码还是得看的，比如问得多的动态扫描或者分频，知道大概实现原理和在代码的那个位置最好）PS. 直接和老师说是抄的会给B-并且不问别的问题',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('64a5298ffb52c431f71ba4c7',18,18,'赵老师 神！！！！！！！！！！！！不多说了  神！！！',5,5,5,15,1,0);
