INSERT INTO "reviews" VALUES('64a5117afb52c431f71afa5a',1332,81,'真不知道思政老师为什么思想能够这么偏激，经常点名，要笔记，要回答问题，要有作业，不是加分项，是扣分项，平时分给分巨巨巨低，50基本分40，其他老师几乎都是无差别50，不知道倒什么霉，遇到他😭😭😭😭',1,1,1,3,0,0);
