INSERT INTO "reviews" VALUES('64a4db99fb52c431f71a99de',351,351,'虽然杜老师课讲得一般般，但谁又能拒绝平时分给满呢😋😋😋，考试什么的把作业搞懂轻轻松松90+',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a4d76f966d5d052cff2086',1105,185,'很好很温柔的老师 讲的好 很亲和 作业少 重点准',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4d668fb52c431f71a90b2',2119,3019,'邱老师太强了 我电气工程概论课平时认真表现好 最后mooc分不高 我和他说给我高一点 然后给我了95 讲课很有激情的老师电机A 实验最后给我98 很好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4d5e6966d5d052cff1e1d',1074,1074,'给分也高 虽然没给满  然后捞的真的狠 我期末最后98 你学的积极她也喜欢你 然后上课讲的非常卖力 很负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4d589fb52c431f71a8f5a',2354,792,'很友好的老师 作业给的不多 但是都是重点 然后数电课设给分也高 上课表达能力可能不完美 但是教的重点分明且清楚，很负责很友好 问啥都会尽量回复',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4d442fb52c431f71a8d7a',3053,1954,'好老师，人非常亲和，有耐心，讲课也很清楚',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a4d3dafb52c431f71a8d0b',1489,850,'老师无敌，讲的很清楚，期末划重点，考试前如果他看过卷子，你去答疑的话还会跟你提示一些重点，平时分给的也很高，不会为难学生，冲就完事了',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('64a4d3b5fb52c431f71a8cba',4510,5559,'平时事多，还要做小组报告，而且经常要回答问题，不然平时分很低，容易被怼，建议真正喜欢哲学的才来学这门课，否则学的很难受。期末考试题目要写很多字，但是期末给分还可以，反正最后能捞你一手。',3,3,2,8,1,4);
INSERT INTO "reviews" VALUES('64a4d350fb52c431f71a8be7',2242,181,'老师人挺好的，答疑也很细心，上课讲的很清楚，ppt做的很认真。就是平时分给的不是很高，实验和作业都认真做了还没拉满，平时成绩只有95，如果想认真听课的话可以选这个老师',3,5,5,13,1,0);
INSERT INTO "reviews" VALUES('64a4d23a966d5d052cff1875',2323,92,'芜～完美的海底捞🥳',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4d147fb52c431f71a88db',23,23,'神中神🥰',5,5,5,15,20,0);
INSERT INTO "reviews" VALUES('64a4d029fb52c431f71a8751',211,211,'讲的好，风趣幽默，一个有魅力的中年男人，讲课很好，没有期中考试，可能会因为报告扣一分左右，无脑冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4c791966d5d052cff06ff',430,194,'平时分拉满，人也很好，可冲',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a4c6ce966d5d052cff05ee',23,23,'刘霓老师神中神！无需多说，无脑选，选不上可蹭课，她对蹭课学生一样关爱，蹭课高分通过，感谢刘老师，yyds!',5,5,5,15,19,0);
INSERT INTO "reviews" VALUES('64a4bba9fb52c431f71a6b58',1600,96,'老师非常好 讲课轻松有趣 点名会提前一节课提醒 一个学期就点两次名 讲的非常好 我没学好真的对不起他 他好温柔 作业也不多 交了批改了平时分就给满 他真的我哭死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4bb7efb52c431f71a6b17',1600,96,'马骁老师yyds！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4b2b6966d5d052cfeebf3',1493,8413,'上课很轻松，给分也高，推荐👍🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a4a6bbfb52c431f71a519f',18,18,'赵老师yyds，无需多说，概率论无脑赵春明',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a49a69966d5d052cfed122',480,92,'老师超级好，平时上课特别轻松，只要不影响课堂干啥都行，平时分直接给满，在群里直接发习题答案和ppt，非常方便复习，讲课虽然有点念ppt，但是认真听讲得还是可以的（不过我都是课上看东大网课😂），本来以为期末只能考80多了，没想到考了95，特地来感谢一下王轶文老师🙏，大物2又选中王老师了👍🏻',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('64a49891fb52c431f71a443d',8341,1228,'绝世好老师！平时分给得超级高，期末考试全在重点里，把分直接喂进嘴里！平时上课作业很少，也不点名，人也非常和蔼，都给我选！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64a488aa966d5d052cfec15a',351,351,'长得太漂亮了，平时分高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a46b32fb52c431f71a1cd1',23,23,'刘老师讲课特别特别好，充满激情，风趣幽默，和蔼可亲，耐心认真，完美！最喜欢的老师，没有之一！',5,5,5,15,19,0);
INSERT INTO "reviews" VALUES('64a4631a966d5d052cfea15d',3370,228,'给分很低。不想多说',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('64a46084966d5d052cfe9ef5',831,5342,'一句话总结:教的一般，但是给分高，刷新一下版本了家人们',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('64a456dcfb52c431f71a0802',887,23,'刘金艳老师，优选班是她真的很幸运，虽然没有刘霓老师火，但是刘金艳老师讲的绝对行！遇到这样的老师，真的太幸运了，感恩珍惜！
INSERT INTO "reviews" VALUES('64a453d7966d5d052cfe8f63',393,96,'彭皓老师你就是我的神啊啊啊啊！想认真学习的选彭老师没错，老师每节课都会领着回顾上节课，讲课条理也很清晰，还会写板书，写过程，带大家算。人也蛮幽默的，随堂小测都说先自己做（实在做不上再动用科技你懂的）。平时也不签到不点名，就可能抽一个同学回答问题。期末考的不能再差了，平时分拉满，让我擦边过了啊啊啊啊！感恩彭老师！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a45298966d5d052cfe8e32',958,23,'冷酷无情，上课就为了完成任务，真建议刘倩
INSERT INTO "reviews" VALUES('64a45243fb52c431f71a0380',198,198,'我之前的评价有失偏颇，胡老师是我亲妈，神中神，作业少给分高，只要不逃课都给满。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('64a45030966d5d052cfe8be3',1066,1066,'能捞他是真能捞，上课水，没有半期考试，平时分就是作业分数，课上讲的东西挺有水平的，坚持听下来收获会很多，不过听着听着就走神了……',5,3,3,11,1,0);
INSERT INTO "reviews" VALUES('64a44eec966d5d052cfe8a74',3990,294,'张老师课讲的不错，但是要求很严格，作业巨多（小组作业、口语作业、视频作业、个人作业等等），给分实打实的靠自己，不捞人，水课摆烂会被同组同学举报上去，平时分直接判零',3,4,4,11,2,0);
INSERT INTO "reviews" VALUES('64a44edf966d5d052cfe8a50',349,194,'非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a44cd1966d5d052cfe885c',18,18,'学概率论不跟春明老师学，就像去西方没去耶路撒冷，春明老师不仅课讲的好，带同学们复习，而且有问必答，春明老师是西南交通大学概帮的少帮主，是二十世纪最伟大数学家的徒孙，是铁蛋概率论的创造者，是在西南交大穿川大短袖的电科学者，是我见过最好的数学老师没有之一。抛开玩笑话不谈，希望所有跟着赵老师，或者慕名而来的同学，真的能做到，为往圣继绝学，为万世开太平，当然要是你发现做题的时候概率大于一，记得找赵老师，他会夸你是个天才🤣👉🤡',5,5,5,15,14,0);
INSERT INTO "reviews" VALUES('64a44b5f966d5d052cfe86e7',18,18,'赵门🙏 🙏 🙏 霸榜实至名归',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a44b24966d5d052cfe86b2',491,23,'满分不解释，完美的老师',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('64a44786fb52c431f719f827',877,2566,'太爱了😍 😍 😍 范老师人好心善，会反复讲解你不懂的知识点，而且出题也很仁慈，QQ非常及时答疑相关知识问题。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a446a4966d5d052cfe81e9',430,194,'超爱虎虎捏，幽默风趣，讲课也很好，期末期中会发卷子给你画重点讲解',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a44654966d5d052cfe81bb',211,211,'优点：给分高（除了慕课之类的全给满）；讲的好，上课讲的全是重点，不是重点的基本不讲；风趣幽默，作业少，点名就靠当堂课用草稿纸做一道题收草稿纸。
INSERT INTO "reviews" VALUES('64a443db966d5d052cfe7f25',8341,1228,'上的葛老师的python数据结构与算法分析，平时根本不点名，一堆人逃课，上课大家也不听，平时作业也没有，就写一些感悟就行，全部chatgpt搞定，并且期末画重点，画啥考啥，考得还简单，根本挂不了科，几乎都是85分以上，一堆98、99的，葛老师yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a44325fb52c431f719f22b',978,978,'建模课，讲得烂，作业多，每节课签到，很多时候都是扫码签到，签到码是2s一换的，签个到搞那么麻烦，反正没几个人听，还要求我们参加比赛，即使我们小组自学得了二等奖也没办法上90，全组期末成绩卡到89，很无语',3,2,2,7,7,0);
INSERT INTO "reviews" VALUES('64a368e3fb52c431f7184046',2584,7446,'人美，事少，课水，可逃，给分一般，冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a35d68966d5d052cfcb680',961,762,'学的是数学系的数理统计，感觉老师挺好的，讲课确实不太行，但是课后答疑还挺好的，而且平时分给了我满分，挺不错的，没其他回答说的那么不堪',5,5,5,15,2,10);
INSERT INTO "reviews" VALUES('64a31684966d5d052cfc74d9',142,142,'不是我就想问她的好评是哪儿来的？奶奶滴被骗了，平时作业超级多，别的班一周三道题，我们班一周2-3次作业，一次至少八道题，平均13左右，雨课堂和烂学生系统混着来，手写二十分钟的题用那个破系统至少一个半小时，就这样平时分还给的巨低，谁抱谁知道，我真的服了，准备补考去了。考完试在群里说一句：私聊不回，有事群里说。我真服了。主要讲课讲的也不咋好啊🤔',1,1,1,3,8,0);
