INSERT INTO "reviews" VALUES('64a2f535fb52c431f717cc38',491,23,'刘老师教得非常非常非常非常好！！！！！！
INSERT INTO "reviews" VALUES('64a2f4d3966d5d052cfc4fc6',836,1529,'老师真的很负责，讲课也有意思',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a2f462966d5d052cfc4f32',1499,1499,'上课不准玩手机之类的，管得较宽，事不算太多，连智慧树都可以不做，但是她布置的作业（一些问答题）最好完成，上课该举手就举手，后来就直接平时分给满',5,5,2,12,0,0);
INSERT INTO "reviews" VALUES('64a2f436fb52c431f717caa4',8453,26,'袁老师退休愉快',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a299a0966d5d052cfba28c',373,230,'陈老师太好了，在考试成绩还没出来的时候平时分没给满，但是在我期末没有及格的情况下，她直接给了我平时分全部满分，作业也不多，很早以前就把选择题全部发智慧树里面，让我们做，第十五周才交，期末选择题都在里面，也发大题复习题，要考的都在里面，可惜我没背。平时上课也水，我们班好像没有点过名。反正近代史上陈老师的就对了！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64a2991efb52c431f7172293',1554,1554,'难评，反正分低，但是捞人',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('64a2945cfb52c431f7171aef',903,179,'康萍姐姐我滴神，巨能捞，42的期末都捞起来了，而且期末感觉给的也多了
INSERT INTO "reviews" VALUES('64a291c4fb52c431f71716f9',828,828,'不知道为啥评价这么低，我感觉王凡老师很好啊，上课的重点讲的很清晰，有很多对应的例题讲解能够更加清晰的弄懂知识点，说老师不好的应该是自己的问题吧。而且平时分也给的高，平时也不点名，课堂氛围也还蛮轻松的，专业水平很强。',5,5,5,15,1,5);
INSERT INTO "reviews" VALUES('64a287bdfb52c431f7170694',6705,1753,'从不点名，狠狠捞人，我的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a2860cfb52c431f71702c0',545,433,'上课没啥可听的，因为发散性思维，一会儿扯外国神话一会儿扯中国近代史，当然对这方面感兴趣的同学可以选，但是英语的知识学不到什么。给分还可以，认真学能上90。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('64a28520fb52c431f71700cf',8460,8460,'一个选修课，半期考试期末报告都交了，自己说半期考试就是看看教学情况，结果给分很低，3次作业就一次没写就给0分了，选修课也要硬给你挂了，建议别选',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a284f7fb52c431f717007c',584,584,'老师人很好，点名也是偶尔点，上课不会提问啥的，人长得就很和善，期末给分很高，而且期末考试之前会给发往年的试卷，一整个爱住！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a283abfb52c431f716fd14',1093,1638,'虽然要手写论文，平时点名不氵，但讲的不错，而且捞人的！老师人很好很负责任',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('64a283a8fb52c431f716fd11',264,230,'特别特别好的老师！学识渊博，幽默有趣，和同学就像朋友一样，特别轻松愉快。考前猛划重点，全是期末考点，外加平时成绩拉满，成绩简直无敌！可惜只上一个学期呜呜呜，我的磊哥啊！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64a28317fb52c431f716fbeb',2197,876,'超级棒！平时分拉满，上课不点名，讲的也很好，人很和蔼，没有架子，有次我出教室鞋带开了他还叫住我提醒我，总之选他没错！',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('64a2826a966d5d052cfb7b0c',584,8465,'超级好的老师，上课总是笑眯眯的很和蔼，考前会给前几年的考试卷还会划重点，平时分特别高，判卷子给分也很高，天使老师，选到就是赚到',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a27c93966d5d052cfb6d11',334,334,'给大家避个雷吧，这么说吧，在同样的出勤率和作业完成度的情况下，尹老师的平时分至少比其他老师少10分+，如果你不想努力画了一学期大图并且全勤上课最后平时分比考试分还低的话就别选尹老师的课。',3,3,1,7,3,0);
INSERT INTO "reviews" VALUES('64a27b4cfb52c431f716ea1d',1991,1065,'一般般吧，生病有一次没去交了，假条最后依然扣了10分，没有群联系不上老师，只能发邮件给他，最后回复我说我没交假条，........自己整丢了学生来负责。最后说一句习思想划的重点一般般',2,2,3,7,3,3);
INSERT INTO "reviews" VALUES('64a27a50fb52c431f716e89b',8468,8468,'能跑就跑，谁选谁傻掰，上课事无敌多，任务是别的班的三倍以上，每章都额外有无敌多的思维导图，不能自由组队，期末改卷她最严，从不捞人，没有重点，要不是看了别的班老师划的重点真得挂科',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64a278b0fb52c431f716e636',5388,23,'课堂上专业水平很高，条理清晰，给分清楚，老师唯一的缺点就是喜欢点名签到，上课时不准玩手机。',5,4,5,14,0,0);
