INSERT INTO "reviews" VALUES('64a22939966d5d052cfaded7',1906,1990,'专业水平不知道，教学水平一般，对待学生态度极其恶劣，上课能跟下面学生呛两句。实习时完全不管事，测完之后给仪器参数，群里问问题就装死。还公然在群里骂所有学生都是垃圾。我的评价是速润。',2,1,1,4,1,0);
