INSERT INTO "reviews" VALUES('64a1b2ac966d5d052cfa2280',23,23,'大学以来最好老师',5,5,4,14,20,0);
INSERT INTO "reviews" VALUES('64a1b224966d5d052cfa21fd',674,307,'适合去听她讲课，不适合作为给分的老师，同等水平下差不多会和其他班折合后平时分差七八分左右，总之慎重。而且其实最后期末复习还是大部分靠自己，也没什么必要就非她不可',5,2,2,9,1,1);
INSERT INTO "reviews" VALUES('64a1ad14966d5d052cfa1c9a',674,307,'优点:1.叶老师上课讲得非常好，知识点全在PPT上，只要不是特别犯困，每节课跟着老师思路认真听，就能掌握到八九不离十的程度，完全不需要课下补课。
INSERT INTO "reviews" VALUES('64a1aa72fb52c431f7159b10',1066,1066,'平时分就是作业成绩，上课很水不管也不点名，但是感觉挺有水平的，只是不适合教学',5,3,3,11,1,0);
INSERT INTO "reviews" VALUES('64a18913966d5d052cf9e2fb',674,307,'总要扣你一点分，讲课还行，但我推荐鹦鹉哥',4,4,4,12,0,1);
INSERT INTO "reviews" VALUES('64a18856fb52c431f71563ec',674,307,'乐，平时分比期末考试分还低。还自我感动，课设要求事情多分又低，别的班做简单课设随便就95以上，在叶文霞这里做简单的封顶70。期中考试又多又难，管得you严 还不捞你。平时作业也是事情多，还临时变卦，给你一个猝不及防。平时分我只能说自求多福，我只能说她教的好，但是分太低了。这门课很简单，我建议选其他老师要高平时分，期末自学，绝对能过。在叶这里，平时分低，就很难保证不挂科哈哈哈哈哈。活水上给她高分的，我都怀疑是反串，乐。我周围都是上她课的同学，我们都很清楚她的打分，值不值得活水的高分。',3,2,2,7,5,3);
INSERT INTO "reviews" VALUES('64a1843ffb52c431f7155ce2',351,1496,'******架子太大，为了自己的面子会多给你扣分',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a1827ffb52c431f715455f',8018,5620,'鲁大师不管是课程还是课设给分都很高，就是讲课讲的稀里糊涂的，也经常听不清楚他讲什么，不过你放心，上课听不听都无所谓，期末找其他班要李雪婷的重点（超级准），期末考试随便考 上课也挺水的 不会管你做任何事情 课设在上交之前还会检查',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a18005966d5d052cf9c309',674,307,'优点：讲课好，表达的很清楚，认真学可以学到很多东西，比其他班多得多，还会讲实验内容，真正消化了完全不用担心期末考试
INSERT INTO "reviews" VALUES('64a174df966d5d052cf9b219',42,42,'第二个实验我们班在他手上只过了五个左右，有一个同学示波器上已经正确显示波形并且在报告上已经画出了波形图，但就是因为横纵坐标标注成xy不符合他的要求直接一验打叉，后面那个同学要他二验，而他的反应永远都是那句话“回到你座位上去”然后并没有去给他二验直到下课，然后到时间直接说下次补验，到时间拉电闸了要，然后直接走人，导致我们班绝大部分人都是补验（助教验除外）。在另一个实验过程中，把正确的波形在示波器上调试出来了，然后图也画好了，然后把报告给他看的时候只给你说一个错误，也不告诉你怎么改，然后一验没了，然后二验也只说一个问题仍然不告诉你咋改，到了补验只看下你报告然后说了“收了吧”******',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('64a17466966d5d052cf9b150',3442,1500,'快跑，讲得一般，但是喜欢阴阳怪气',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('64a173dc966d5d052cf9b095',852,142,'跌跌跌跌跌跌跌跌跌跌！人水平高😎😎，讲的又好😋😋，事情又少🥰🥰，期末还狠狠捞🥵🥵。遇到他真的是我大学的荣幸🥳🥳。我看还有谁材料力学不选我江跌的？😤',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64a17363966d5d052cf9afee',351,1496,'快跑，一个学期累死累活4章思维导图+上台presentation+乱七八糟的调研+一大堆作业，平时分扣扣搜搜的，讲得很不好，老师事特别多，不愿意捞',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('64a170f9fb52c431f7152b96',23,23,'刘老师神中神！最温暖的老师！课讲的非常好，学起来轻松易懂不容易走神，90+通过，感恩刘老师！',5,5,5,15,20,0);
INSERT INTO "reviews" VALUES('64a16742966d5d052cf99de4',4482,157,'一：强烈推荐M倾向的参加，压力拉满，给你全方位调教。二：你最好真的会，不给分就真******不给分。运气不好你甚至没有补考的机会。三：你最好没有问题，因为你无法在任何交流平台和他取得任何联系。',5,1,1,7,9,0);
INSERT INTO "reviews" VALUES('64a15ad1fb52c431f714df35',351,1496,'******又是思维导图又是上台演讲，另一个贾老师的班只要认真写了作业了平时分98% 99%，你搁这给我们70%平时分666',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('64a15724fb52c431f714d5b2',87,87,'马教练神中神！！对女生特别特别好，成绩打得也超高，人和蔼可亲，神中神',5,5,5,15,1,0);
