INSERT INTO "reviews" VALUES('64a14aa9966d5d052cf95ef6',377,377,'******能跑就跑，上课会点人回答问题，虽然概率不高，但点到了回答不出来会扣分，点名不来可能会出大问题，半期作业就他最离谱，30分钟话剧不知道用什么脑子想出来的，完全不care学生死活。平时分也不高，有的人甚至很低。',1,1,1,3,4,0);
