INSERT INTO "reviews" VALUES('64a140b5966d5d052cf94d34',3091,2,'要评价的是地下铁道这门课，讲的一般，课程设计难，任务量大，要求独立完成，时间紧，最后登成绩的时候登错了，一问也不知道，狠狠避雷，谁选谁倒霉',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('64a13d3e966d5d052cf94800',836,23,'上课特别好，而且期末特别能捞人，泪目了家人们，感恩感恩',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('64a13c96966d5d052cf946f6',1480,194,'懂得都懂，一伯分',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64a13c56966d5d052cf9469b',1768,92,'无敌！只能说无敌！上课教的特别的好，而且关键是，期末特别能捞人，大物期末考试70%，我考了40分，觉得自己必寄了的时候，老师把我平时分给的几乎满了，99分，只为把我捞到及格，家人们谁懂啊，给老师磕一个，真是世界上最好的老师了，大爱',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64a13b2c966d5d052cf944ed',377,377,'神中神，上课只要不说话随便玩手机，期末平时分给了一百分',5,5,5,15,2,16);
INSERT INTO "reviews" VALUES('64a137bffb52c431f7149f7c',1768,92,'神中神，真的好老师，讲课很认真负责。平时分回答次问题就满了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a1343bfb52c431f71498fa',540,540,'刘老师教的电路分析，前四个学期以来遇到讲课最好的老师，上课有很多例题帮助学生理解知识，讲课也很细致，节奏不快不慢，好评！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a131c9966d5d052cf933cc',5486,535,'讲话极含糊，吐字听不清，讲课水平很一般，平时作业按质量和次数给分。',2,2,5,9,0,0);
INSERT INTO "reviews" VALUES('64a12fa2fb52c431f7148d88',2895,92,'老师专业水平很高，教学也很用心，只要不缺席作业全交平时分就拉满，总体还是很不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a12acffb52c431f714829e',7120,1267,'我上的是她的心理电影赏析课，水的老师上什么课都是一个风格的，老师人超级好，期中一次作业期末一次作业，就结束了，没有期末考试，如果要点到的话她会提前一周在教室说，而且每一节课都是看电影，她放完电影就自己坐在第一排了，每次点完到都有很多同学悄悄从后门溜出去，她都是睁一只眼闭一只眼的，要选水课的必选她，给分也超级高，只要认真写了两次论文不会低于95的，论文很简单的，就是写电影观后感什么的，随便裁裁就有了，总之这门课真的性价比很高的，我记得也没有多少人选冯老师的课，我当时是没有投权重就选上了。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64a129a2966d5d052cf922b5',315,40,'上课就是讲哲学，看似哲学实则是宗教，每节课都会点名，抽读新概念，容易扣分，但最后平时分会偷偷加点，能感觉到她是真的想教我们东西，虽然结果……
INSERT INTO "reviews" VALUES('64a128c0fb52c431f7147fab',237,5,'上课很水，就是在吹牛逼，全靠自学，他课上都是看网课的同学，没几个人听
INSERT INTO "reviews" VALUES('64a121f2fb52c431f71475e9',22,92,'全交大最认真负责的大物老师 平时分拉满 期末捞 上课认真细致系统性强 期末复习周在群里答疑 每个同学的问题都认真回复 学习通上上传所有章节的网课内容方便自学 还有历年考试真题和答案 不多说 亲妈！！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64a10f1b966d5d052cf8f92c',4119,4119,'老师上课还算可以，但因为我本身对京剧没有太大兴趣，所以主打陪伴。期末不考试，老师提前一周发，大家在一周之内做完就行，分很高90➕',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a1054dfb52c431f7144c0f',3925,3925,'数理统计期末出那么难，害怕大家都过了是吧',3,3,3,9,1,3);
INSERT INTO "reviews" VALUES('64a0f3d2966d5d052cf8d1da',2437,1954,'很好的老师，平时分能拉满的都拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a0f329fb52c431f7142fee',142,75,'******但是讲课还行。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('64a0f2bcfb52c431f7142f4c',74,74,'******平时分低事情还多的很，为人极其教条古板，能跑就跑。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('64a0f18bfb52c431f7142db9',23,23,'刘老师是我目前在本科学习期间遇到的最热心和负责的老师，狠狠赞了',5,5,5,15,20,0);
INSERT INTO "reviews" VALUES('64a0e730966d5d052cf8c117',233,306,'老师典型的刀子嘴豆腐心，平时要求严格一点，但是生怕我们挂科，真的很好了!张老师上课特别认真，讲得很细心，也不会觉得无聊，机械制图确实有点难，但这不是老师的问题，老师已经很完美了，平时分最大限度给了，我还以为我要挂科，结果成绩还将就，真的哭死了，在哪找这么好的老师!!!(真的心里话)',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64a0e3af966d5d052cf8bc17',351,351,'平时成绩拉满',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('64a0cf73966d5d052cf8a123',883,1015,'给分高可以报',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a0cd2e966d5d052cf89ebd',7098,8527,'真的服了这老师 大家别报 平时分给的真尼玛低 卡线过的给的高',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('64a0ccb6fb52c431f713fdd1',527,657,'给一个客观的评价吧，我这学期总评96，基本上出了前两周没去其他时候都去了（没选到和教室太小还没换），因为她会点几次名但是不知道什么时候点。半期有个作业，叫拍一些屋顶照片，但是这个后来说交了就给满；期末考试占70但是考的都是课上叫记的内容，在课上你可以做自己的，在她突然停下来的时候拍ppt就行其他时候她不管你。当然想听还是能听到好东西的，我记得我还听了一节关于灭点的构图，水也可以但别太水这真会挂人的。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('64a0c606fb52c431f713f5b0',2413,71,'看似水课，实际7：3超级挂科之课。材料学院最后的阻止转专业的屏障',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('64a0871cfb52c431f7137aac',808,140,'平时分直接拉满100分的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a0831a966d5d052cf8196a',751,1652,'看到这么多工程力学课程的好评，我只能猜测师老师可能是对工程力学掌握比数学物理方法好太多吧。数学物理方法上他的课真的是一种折磨，念PPT而且有时间讲着讲着自己也不会做了，这很难评。',3,3,3,9,9,0);
INSERT INTO "reviews" VALUES('64a07542fb52c431f7136b10',465,8532,'给分高，人也很耐心',5,5,5,15,0,0);
