INSERT INTO "reviews" VALUES('64a07494fb52c431f7136a8c',1596,52,'没遇到过这么差劲的老师，上课什么内容不讲还能拖堂，不知道上的是啥课',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64a07400966d5d052cf80d22',2122,1796,'光哥yyds，连续第二学期抢他的课了，上课讲的有意思给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64a073a7966d5d052cf80cc7',4820,241,'上课啥也不讲，点名迟到就算旷课，总感觉自己很了不起',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64a0732bfb52c431f713694d',101,114,'上课有自己的讲义，讲的十分细致，还会录屏下来发到群里，每次考试前都会复习重点，基本没有随堂测，平时分除了半期全给满',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64a0729dfb52c431f71368ea',1531,641,'人很好，上课虽然读PPT但是不点名，实验和作业有问题都会耐心解答，作业到截止日期忘做了还会给你延期。平时分全给满，期末也会狠狠捞人',5,5,5,15,3,0);
