INSERT INTO "reviews" VALUES('649f9b8cfb52c431f7121b23',3407,762,'选到就是上辈子修福了！！！亮哥yyds！！！平时分给满！注重学生意见，及时回答问题。完美的老师！无脑冲！！！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('649f9b09fb52c431f7121a6f',2447,23,'必须拉满！！！老师温柔漂亮，平时分直接给满！！！有不会的会耐心解答，讲课思路清晰。选到就是赚到！！冲！',5,5,5,15,2,0);
