INSERT INTO "reviews" VALUES('649f8ba5966d5d052cf6a8a8',23,23,'yyds！在交大遇到的最好的老师，上课超有激情，幽默风趣，课后QQ随时回复，经常鼓励重修的我，让我从开始害怕这门课到后来想考高分，最后90通过，感谢刘霓老师！yyds!',5,5,5,15,21,0);
