INSERT INTO "reviews" VALUES('649e327afb52c431f70f7f62',427,427,'老师平时不怎么检查作业，就是期末交图即可。不太摆的话老师给分也不错',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('649e3244966d5d052cf41cae',297,194,'大家注意，有一个22地学的小丑，故意拉低分，不知道是老师哪里得罪了他故意往下刷分，老师的策略是期中期末都九十分以上，所有的平时分拉满，而且就算不拉满给分也都是九十多，而且你如果期末考试比期中有进步，平时分几乎都是95+，神仙老师，讲课是PPT和板书结合，很多题目也会手算，神仙级别',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('649e14d1fb52c431f70f5758',271,271,'我错了😭 ，丁浩老师的拓扑学很好，是老师的起点太高我没跟上罢了，虽然讲的难，但是给分确实高，鼠鼠期末好多不会，结果还有97，太感动了，大家快选他👍 ',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('649de156966d5d052cf3c4ac',5803,619,'平时分95，很水的老师，上课他讲他的你做你的，课程就一个大作业。不过他每节课要点名。拉平时分我建议选他',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649dd023fb52c431f70f192a',5803,619,'上的是习概课，上课节节课点名，然后课堂质量不高，天天放视频，虽然不怎么管你，但是也挺恶心的，有两节课放的视频都一模一样，每节课都来然后作业认真做平时分会拉满的，期末重点画了和没有差不多，没有好老师了再建议来',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('649dc4fa966d5d052cf3abc8',2258,837,'节节课智慧树定位签到，几乎节节课布置作业，上课还会挑一个倒霉蛋的作业当众点评。平时分给分一般，不会拉满（这课半期+期末占70）。这里再说一下他的运筹学实验，抽象的一批，别人老师都没有期末考试他非要自己整一个期末考试，平时课堂作业考勤统统不算数，好像就按照最后这次期末考试他给分..',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('649dc38b966d5d052cf3aa99',2461,2461,'先说优点：不爱点名，没有作业，没有课设，据说处于及格边缘的会捞。缺点：平时分给分不咋地，不知道咋给出来的。',3,3,3,9,0,0);
