INSERT INTO "reviews" VALUES('649db947fb52c431f70f0176',751,573,'（老师你为什么要这么好，平时分本来我就是满的，结果期末上七十分平时直接拉满，我真的哭死。）咳咳，师老师真的很好，大学第一个除了选修课的平时分满分，爱死了',4,5,5,14,1,9);
