INSERT INTO "reviews" VALUES('649d3cd5fb52c431f70e233d',751,573,'在师老师这里重修，我只能说以前太年轻了跟了优选版成志强，那简直不是人过的生活，赶紧冲爆师老师，无敌，最好的力学老师了。（不来这也别去成志强那******）',5,5,5,15,1,9);
INSERT INTO "reviews" VALUES('649d35dd966d5d052cf2abdb',7435,7435,'那位00级武装部的评论真是想我所想了，十分赞同，就是现在助教不查重了基本上粘贴也可，她上课不要指望效果好，因为她大舌头，根本睡不清话 ，她自己抨击了一通高中机械的语文赏析，但是她讲的我听了两节跟高中没什么区别，就没听了，偶尔听一两句能气的要死，老是笑着讲一些并不好笑的笑话。总得来说想水的还是可以水的，，给分也还行，大概七八十分，毕竟这是助教给分，想充实自己的我感觉是没什么收获。',3,1,4,8,2,0);
INSERT INTO "reviews" VALUES('649d3078966d5d052cf2a432',2202,28,'老师很好，给分不错，不固定的平时分都给拉满的，U校园太低也会手动调高一点。氛围轻松，鼓励主动发言，很少直接点名学生。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649d29a0966d5d052cf29a84',349,194,'贵子yyds！高数二总评满分🥰😆🤤',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('649d1acefb52c431f70deb16',258,43,'给分不如龙文杰，脾气比龙文杰好。',4,4,3,11,2,1);
INSERT INTO "reviews" VALUES('649d1a0ffb52c431f70de9b1',3098,8223,'胡老师专业过硬，能力很强。但是脾气嘛，不好评价。属于那种非常愤青，然后比较喜欢压力和阴阳怪气的。对学生的要求很高，实验课最后一起验收的时候，如果你是抄的代码会比较麻烦，会各种连环追问，让人被问到心态崩溃。但是你问问题的话回答很认真，教学来说也很负责，总之看你能不能接受多元化性格的教师了。',5,5,1,11,2,0);
INSERT INTO "reviews" VALUES('649d19d6fb52c431f70de952',708,708,'期末倒是给个范围啊！老马呀！！老马啊！！！',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('649d183afb52c431f70de696',3036,3113,'算法与分析设计课程加实验。李老师挺好的，现在能选的就是李老师和黄海于老师。黄老师相比来说作业很多，脾气也比较差，李老师上课一般般，但是脾气非常好，很耐心也很热心。作业以及实验课验收等等方面要求也不高。推荐选他。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649d1767966d5d052cf27bd2',2885,40,'英语公共演讲，老师人不错，给分正常水平，你做了多少事就多少分，分数是好多好多个小项，比如作业演讲和小测加起来的分数。如果能选到别的课，还是选别的，公共演讲事情比较多。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('649d114bfb52c431f70ddbc4',5026,5026,'副院长上课有意思平时分给拉满作业一学期就交了两次 对不对不要紧交了就满分考前给画重点和考的一样',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649d113ffb52c431f70ddbb5',271,2499,'上课讲的有点穿越，大家其实都听不太懂，然后他发的PPT也只有各种定义定理的陈述，我想预习和复习根本没办法😣 ，期末出的也难，感觉不想捞人',2,2,2,6,0,1);
INSERT INTO "reviews" VALUES('649d007a966d5d052cf2583e',3479,526,'我的义父！！！学芳老师超级好！！！给分高而且作业少，期末会捞人！！！',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('649d0062966d5d052cf257ed',142,548,'想卷高分的可以来，作业刷到满分，每节课都去平时分可以给满。只是想过的建议别选，不花大量时间刷作业成绩平时分会很低。',4,4,4,12,2,4);
INSERT INTO "reviews" VALUES('649cf69d966d5d052cf24468',3407,5,'高数平时分100拉满，亮门',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('649cf067966d5d052cf23aeb',2485,26,'韩老师人真的很好 一学期基本不点名 平时分不用担心 期中期末考自己 体验很好',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('649ceb8e966d5d052cf2349f',3921,2598,'最后的平时分给的很高，老师讲课有口音坐后面会听不清楚，讲的前面会慢一些，后面讲的较快，每节课都要考勤',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('649ce611966d5d052cf22d70',2992,6194,'重点很详细，上课念PPT，口音听起来不太清晰，很水。想考高分建议选别人，求及格可以选他。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('649ce472966d5d052cf229cd',142,548,'每节课点两次名，作业多而且不捞人，忙活一学期下来平时分60，不说了我已经在研究补考的对手了😅',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('649ce2ebfb52c431f70d9256',3921,2598,'这学期平时分98.5',5,5,5,15,2,0);
