INSERT INTO "reviews" VALUES('649cde8b966d5d052cf221a5',7336,8324,'有幸上过他的机械制造，上课不知道在讲什么，要不要期中考试自己都不清楚。之前说期末是开卷考试，考试前一天通知闭卷。先不说课怎么样，感觉人不太靠谱😅',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('649cdaf4fb52c431f70d86cb',2525,1169,'老师讲的不错，人也不错，冲！',5,5,5,15,0,0);
