INSERT INTO "reviews" VALUES('649cd921fb52c431f70d8448',23,23,'刘老师巨好，讲课超有激情，人很温柔，有爱心，总之，哪哪都好，yyds！',5,5,5,15,22,0);
INSERT INTO "reviews" VALUES('649cd7b7966d5d052cf217a4',8645,8645,'期末考试开卷，半期提交大作业，平时有几次小作业，不怎么点名，上课不让玩手机（可以偷偷玩），给分一般。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('649cd74bfb52c431f70d81ee',142,760,'四大名捕，名不虚传。平时分一不留神只剩60分，而且绝不捞人，考试完加老师好友直接被老师拉黑。讲课也乱七八糟没有章法',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('649cd606966d5d052cf21546',1157,52,'脾气超级好，资料、考前重点、考前卷子都会发',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649ccca8966d5d052cf20861',3641,3641,'他真的超级好，超级温柔，课设乱做的平时分都给满了，为什么有人说他是雷？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649ccc5d966d5d052cf20808',491,23,'老师待人和蔼可亲，课讲得好，超级认真负责，好老师！',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('649c8174fb52c431f70cea74',6,619,'这老师我只能说你遇上了就是倒霉了，上课阴阳怪气学生，有次下课之后他说：有问题的同学可以留下来交流一下，因为没几个人留下来，他很大声的质问还在教室里没及时走出去的同学：你们都很睿智吗？永远板着一副脸，上他的课从来不让玩手机，有同学因为玩手机被记过学号。他私自把智慧树的分换成签到分，总共50分的平时分，签到就占30，少去一次扣十分，关键他没给我们说智慧树的成绩不计入，白白看了那么多，浪费时间。有人问他智慧树怎么搞，他就说了一句：我太不清楚智慧树。******还特别喜欢吹嘘他去过那些地方，经常说：知道这个地方吗？我去过。（别的班平时成绩大多数都是接近满的，这个老师给平时分大片七十几分）',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('649c74b5fb52c431f70cde53',785,229,'讲话断句很抽象，不坐前排听不清在说什么',5,1,2,8,0,0);
INSERT INTO "reviews" VALUES('649c63af966d5d052cf161e0',2829,7569,'老师说话声音很小，巨小，往后坐根本听不见，每节课都要交作业，每节课都要交作业，每节课都要交作业',3,4,3,10,0,0);
INSERT INTO "reviews" VALUES('649c6105fb52c431f70cc9cd',1332,81,'老师上课挺有意思的，但是不让你玩手机或者干别的事，一讲里差不多一节课让同学发言，期末的时候说发言累计三次且全勤就给满平时分，可以下课交小作文当发言，想混的话不能选这个老师，喜欢翘课或者社恐也别',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649c6080966d5d052cf15e85',1025,850,'懂不懂挂科率第二的含金量啊',1,1,1,3,2,0);
