INSERT INTO "reviews" VALUES('649c5e3bfb52c431f70cc637',250,250,'选到他真的是你们上辈子毁灭了银河系，上课基本上纯纯骂人，从中国骂到日本骂到美国，从浙江骂到山东骂到四川。众人皆醉他独醒，他称他的学生为半残废，总之，赶紧跑！！！',1,4,1,6,7,0);
