INSERT INTO "reviews" VALUES('649aa467966d5d052cee59d5',7,7,'人帅，给分高，上课逻辑很清楚而且ppt很简洁重点突出，认真听绝对能听懂，作业正常不多不少，考前还会梳理知识点直接选就完事了。',5,5,5,15,0,0);
