INSERT INTO "reviews" VALUES('649aa27b966d5d052cee5749',118,3845,'有能力，但是想讲的深又讲不到点上去，并且不用ppt所以如果你走神了就会恭喜你无法复习。。。建议真爱数学的选',3,4,3,10,0,0);
