INSERT INTO "reviews" VALUES('649aa071fb52c431f709c33e',2230,8703,'神中神😍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649a9b6e966d5d052cee4823',8704,8704,'这学期桥梁工程，从不点名，没有作业，平时分拉满，很难不过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649a9aee966d5d052cee46b5',373,619,'事情多，交课堂笔记和两万字手写自测题里二选一，但平时分拉满也不多说什么了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649a9996fb52c431f709b321',8706,336,'挺负责的，平时分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649a97a3966d5d052cee3e24',8707,8707,'老师人很好，但是准备好自学吧……',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('649a93ca966d5d052cee35a9',491,23,'绝对是我见过最认真的老师，能记住好多同学的名字和状态，人也和蔼可亲，平时分直接拉满，总之选她不会后悔',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('649a8545966d5d052cee1ff4',68,68,'真的人美心善！！！平时基本不会有额外的作业，小组作业都是年级组统一的那种，只要按照她的要求来，分数真的高！而且她要求也说的很明白，要求也不会高，只要态度认认真真真的就好！想要拿高分的可以冲。而且感觉大家对她评价有点不好，不太懂，但是没有什么人选的话就比较容易选上课哇！真的冲吧，大二的英语都是她，平时快拉满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649a7958966d5d052cee0cc7',27,27,'长得好看,声音好听,人特别温柔,讲的也很好,她的口头禅是"可以吗?""当然可以了~".选到她的课,我这一年还是很开心的.如果你和我一样,都喜欢专业实力很强,讲课非常好,老师念英语就是享受,冲就是了!',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('649a75f3fb52c431f70974f6',1940,653,'老师真的很好,真的很好.',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649a7186966d5d052cee0223',1171,27,'大男子主义的古板男，拓展的词汇有不少上不了台面的让人不舒服的，平时隔三差五会和同学起冲突，很固执。课的优点也不是没有，就是较水，作业也可以水。不会捞人但给分正常。还有就是四川口音严重，还会怪学生没有入乡随俗听不懂不赖他。🤗✋',3,2,1,6,15,0);
INSERT INTO "reviews" VALUES('649a654afb52c431f7095d29',5021,5275,'老师严格，别想水。上课喜欢点人起来回答问题，意思是别逃课，大部分人都被点到过。同学回答不上问题会一直抽……教的还是很好的
INSERT INTO "reviews" VALUES('649a6237966d5d052cedebc9',1192,27,'神中神老师，现在上课开始收手机了，看似严格但是老师很好的，讲课很好有条理，有时候会讲她在国外的趣事。偶尔抽人回答但是每次都抽跟她比较熟的几个学生。不点名。事情少，平时就做u校园，一学期写几次作文。书上的题会检查一次但是会提前告知要收。小组作业和pre基本没有，就有过一次上课讨论，然后交一张讨论结果表。期末口语考试交录音，适合社恐。
INSERT INTO "reviews" VALUES('649a5eec966d5d052cede736',7860,7860,'好像点过一两次名。平时上课自愿回答问题加平时分，想水的直接坐座位上玩不会管，不会抽人回答问题。拍视频全班有五个免考名额。期末考试会给提纲，照着上面的问题背就能拿到大题的分，选择题可以裸考
INSERT INTO "reviews" VALUES('649a573dfb52c431f7094470',5581,5581,'推荐！没怎么去上过课，作业都按要求交了，期末92，老师很好！！',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('649a5613966d5d052cedd0f4',5581,5581,'老师挺不错的，备课啥的比较认真，对学生也比较水，推荐',5,4,5,14,2,2);
INSERT INTO "reviews" VALUES('649a48a6fb52c431f7092d54',1538,1073,'熊老师上课讲得非常好！！而且全程手写板书，思路清晰，只要上课听讲完全不用再去另外听网课啦！！课后作业也不多，而且每章结束之后有复习课和对应习题，非常好！！快冲冲冲！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6499f806966d5d052ced1f90',1732,34,'大一上的喻老师的c语言，平时分直接拉满。老师人也很好',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6499dc77966d5d052ced07aa',246,228,'上课不让坐后三排，不让玩手机，第六感奇准，每次点名都能点出一大半没来的，期末平时分给的低，免考名额是考试前一天才发出来，浪费其他专业课的复习时间。还没出最后成绩******',1,2,2,5,1,0);
INSERT INTO "reviews" VALUES('6499d6c9966d5d052ced02da',5581,5581,'还可以，比较水了',5,4,4,13,3,2);
INSERT INTO "reviews" VALUES('6499ad62fb52c431f7083e61',11,11,'老师其实还是挺和蔼的。看到评分这么低，也是有点难过。老师比较认真，平时分给的不算高。',5,5,5,15,2,7);
INSERT INTO "reviews" VALUES('6499aa61966d5d052cecc338',11,11,'其实我觉得还好，老师虽然有时候看着挺凶，但是平时时候也挺和蔼的，给分比较严，但是平时只要正常完成任务分也挺高的，我平时作业得分不高，听写一塌糊涂，成绩也挺可以的',3,3,3,9,0,4);
INSERT INTO "reviews" VALUES('6499aa16fb52c431f7083829',1753,2735,'平时分拉满 教的特别棒 狠狠爱了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6499a944fb52c431f70836f1',1753,2735,'平时分绝对拉满，讲话又好听，人又帅，考试绝对过，五星上将麦克阿瑟曾说：高数不能没有丁修勇，就如同西方不能没有耶路撒冷。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('6499a830966d5d052cecbfc7',297,194,'这么说吧，期末平时分一点没有，考多少就是多少，大家注意一下，能转就尽量转走吧',1,1,1,3,2,24);
INSERT INTO "reviews" VALUES('6499a7fcfb52c431f70834a9',1753,2735,'老师巨好，教的特别棒，很有趣，教题的时候还会说小朋友，特别棒的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6499a763fb52c431f7083385',1753,565,'会叫大家小朋友，好有爱的老师！说不捞人，但是最后平时分还是基本上拉满了，嘴硬心软，英俊帅气可爱yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6499a612fb52c431f70830a1',1753,2735,'爱死真的爱死，平时分拉满，讲课超棒，讲话超级好玩，没人不爱！！！～',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64998fbffb52c431f7080104',5292,1954,'挺好的，哥们儿学三天总分87',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649985fafb52c431f707f2ef',2878,28,'谁不爱黄老师!!分给的巨高，上课也有趣，人超级好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64997818fb52c431f707db71',883,8732,'讲课基本照ppt念，ppt就是复制粘贴书本内容。吐字不清晰，想要学点东西的慎重。但是平时分给的很大方。',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('649977a9fb52c431f707dab2',8733,2124,'很有意思，作业和考试就是拍中药认中药。开卷，有组队讲ppt环节',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649977a2fb52c431f707daab',237,237,'平时分能拉满的都拉满了',5,4,5,14,0,2);
INSERT INTO "reviews" VALUES('6499775a966d5d052cec63dc',951,8735,'学的数据库基础，很不错，人很和善，随便问问题，平时分也给的很多。有时候会抽点前排的人回答问题',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64997702fb52c431f707d91e',722,8736,'不错，平时分给的很大方，会画重点。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649976bd966d5d052cec62dd',353,859,'画重点那都不叫画重点，太精确了。讲话带口音，不太能听清。不怎么点名，上课水平一般，但稳过。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6499764dfb52c431f707d7b4',8738,737,'全靠自学，ppt和上课讲的、考试考的都有出入，建议是别选。期末给分一般。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('649975dafb52c431f707d6bf',741,2862,'很一般，讲课和ppt根本没关系，问题是都不板书，随便讲的才是考试内容，ppt和考试内容毫无关系。不友好，勿选。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('649971b1fb52c431f707d048',373,619,'平时留题，并不是网站上答题，而是手写出来最后一起交，题量不小，手写的总字数在2万字左右。其他的很好，给分大方，上课也不管你。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('64997183966d5d052cec5a30',428,4716,'我的爹',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64996f33fb52c431f707ccc0',304,707,'平时实验检查非常仔细，但是你不懂的他根本不会给你讲，不懂的永远不懂，每次实验也是什么都没讲就让做。平时分六十多分百分之七十我自己的责任百分之三十他的责任不过分吧？',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('64996dee966d5d052cec5528',1065,1065,'没学毛概，学的习概，这位老师只要上课回答次数满，满勤，平时分就是满分。平时回答问题给的机会也很多，随便回答两句就行。总之，推荐！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64995788fb52c431f707a806',545,433,'上课讲男尊女卑并深以为然，还是在大学课堂上听到…甚是震撼。',3,3,3,9,1,2);
INSERT INTO "reviews" VALUES('64995512966d5d052cec2da5',250,250,'糟糕透顶的老师，能跑就跑。天天上课扯淡讲什么莓果，大图讲评的时候讲话巨难听，除非有被pua倾向或者心理素质很好不热别来，逮谁骂谁，不论画的好坏',2,1,1,4,2,0);
INSERT INTO "reviews" VALUES('649945c4fb52c431f70783c4',1493,1493,'老师超级好，讲课也很有趣，当然不想听也很好水',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64992e9a966d5d052cebdbcd',2579,8747,'老师很有经验，讲课清晰易懂。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649923c0966d5d052cebc8b7',4925,4925,'男老师女老师都很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64992167966d5d052cebc569',89,33,'一定要好评，水且高分，我的神',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('649920cefb52c431f7073d77',25,352,'我是他高数课的学生，讲的真的很好还会解答问题，选他！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64991d33fb52c431f7073783',491,23,'好老师！认真负责🥺班里近100人她能记住一半多，了解每个人的学习情况。实验报告交晚了可以补，只要跟着走，平时分会很高。初学c加加，知识点又多又杂，听课有时也会觉得无聊🥱但刘老师会总结知识点，每章编程练习，还会录重难点编程题的视频。跟着走成绩不会差！',5,5,5,15,8,0);
INSERT INTO "reviews" VALUES('64991b92966d5d052cebbc56',36,36,'老师可以的。去年给我们平时分给满的。上课课间还经常跑下来和我们键政。交大张维为，上课读ppt总是一脸难蚌的表情，很有意思的一个老师。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('64991ae6fb52c431f7073421',1538,1073,'熊老师😭我哭死😭讲课好，知识点全面，举例多，平时分除半期考试拉满，期末海底捞，每章都有习题课，期中期末还有复习课。就是讲课有点快，提前复习一下效果更佳。带点川普～',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('649919b9fb52c431f7073269',819,228,'还可以。平时分给了46左右。大家基本都在44这样。就是上课比较折磨，不能横屏打游戏不然会下来抓，以及上课经常会有一些逆天发言。不过总体来说老师也比较温柔，负责好说话，给分也不错。',3,5,5,13,1,0);
INSERT INTO "reviews" VALUES('64991616966d5d052cebb3c7',2485,26,'上课讲的好，只要你课后可以花一小些时间复习她的课就可以跟上，也会获益良多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649912effb52c431f70727df',2210,114,'救命，高数平时期末五五开，平时分老师直接给满，这谁不爱啊',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('64991228fb52c431f70726cb',353,859,'期末画的重点就是考题，神中神😍',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('649911b8fb52c431f70725e4',214,36,'******
INSERT INTO "reviews" VALUES('64990f1d966d5d052ceba9d6',1753,2735,'都给我选Mr.Ding！丁叔叔会叫你小朋友，人特别温柔特别好，平时成绩除了半期考试全部拉满，拉满的含金量懂不懂啊。期末捞人也是特别猛，有同学平时拉满也没过，直接把他半期考试改高了，都给我冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649900a1966d5d052ceb7ab1',373,230,'上课不点名，事也少，写一个科学家报告和选择题库就行，期末平时分直接拉满，就是上课声音很大干不了别的事（不过因为某些原因还是认真学近代史吧）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6498ffaefb52c431f706eb05',373,230,'平时分直接拉满，不多bb了，选就完事了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6498f8eb966d5d052ceb3b57',1538,1073,'熊老师人真的很好，非常有亲和力，很喜欢笑，有时候还很可爱，平时分随便九十好几',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6498834efb52c431f70638a9',278,228,'从今年开始马原课整体有所调整，刘老师可能自己也有所改变。这一学期课程里，她的上课节奏是：放ppt划重点，问答环节采取抢答（很少点名回答），只有一次作业，缺点是说话模糊。本人缺勤一次，期中、随堂糊弄写的，平时成绩为44/50，很满意了。相比于同学选的其他老师——必须参加辩论赛、必须回答问题否则扣4分平时分、两周一次作业……平时成绩才40……很知足。另外，想获得免考的报她相对轻松很多，也可能是这回选她课的都比较摆',4,4,5,13,1,4);
INSERT INTO "reviews" VALUES('649857aefb52c431f7060025',8764,8764,'人看起来蛮亲和，说话有点含糊，加上是早八，基本没清醒听完，听懂过。有课堂小测，但给分应该不严格。说是上课上去回答问题加分，但是好像并不会太影响（可能会看期末分数）。后半期作业挺少，有上机作业五次，做得差不多的话，评分都比较高的。一个蛮好的地方是期末复习指导，会有一些必考题的暗示（需要用心领悟）。计组a毕竟只有一个专业开，也没得选咯。ppt还是蛮详尽 自学还是可以。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('6498556a966d5d052cea7f23',1538,1073,'谢谢熊老师！！！就凭上课写的基本上都是板书这一点就可以薄纱全国99%的大学老师了！！！不仅给分高还会主动捞捞！！！请大家玩了命的选他！！！',5,4,5,14,5,0);
INSERT INTO "reviews" VALUES('649854c8fb52c431f705fbbf',96,96,'还行。非常严谨，不该给的分一分也不会多。',4,3,3,10,1,1);
INSERT INTO "reviews" VALUES('64985485fb52c431f705fb70',2230,2230,'很难得的好老师，能做易老师的学生三生有幸',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64985443fb52c431f705fb28',1538,1073,'老师大好人，教得好，心肠软，凭他会写满满黑板，秒杀好多老师。活菩萨，感谢老师再造之恩！圆满结束前来还愿。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('649843dd966d5d052cea5aad',459,40,'老师很好，对待课堂非常认真。有时候教室里摸鱼严重，老师会语气严肃一点，谈一些与个人发展相关的问题，但能听出来她是真心地为学生考虑！给分很松也会捞人！',5,5,5,15,1,6);
INSERT INTO "reviews" VALUES('649842f7fb52c431f705d55e',2229,2229,'老师很有亲和力。但从代码到实物这门课的教学安排完全是依托史，课堂非常水，很难学到知识。给分也很严，一门限选课居然只给60分，wtf！！！',1,5,5,11,2,0);
INSERT INTO "reviews" VALUES('649841f8966d5d052cea571c',8764,8764,'老师人很好，非常有亲和力，给分也不严，作业不多。但还是建议自学，因为不太能听明白讲课。。。。（大概率是我的问题）',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('649825befb52c431f705a86e',2437,1954,'一学期下来除了知道他有个在美国非常优秀的儿子之外啥也没学会，不过这是我的问题不是他的问题。老师很牛逼很有钱，虽然经常锐评我们但是其实讲的话都是非常真实的。不好也不差，希望他平时分可以多给点。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('6497f58e966d5d052ce9dc2c',5021,5275,'老师有点离谱，不让看手机，但也可以看，上课老是会点人回答问题，还要看学生表现确定之后是否会画重点，只能说有点严格和恶心。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('6497f505966d5d052ce9daca',8774,8774,'只能说，老师人很好，但是讲的课确实不容易进脑子，不听课也能考高分，适合摆烂学习',5,4,5,14,3,0);
INSERT INTO "reviews" VALUES('6497f3bd966d5d052ce9d53c',27,28,'老师人真的很好，对所有事情都面面俱到，平时分只要认真学习，绝对不低，就是作业有一丢丢多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6497e33d966d5d052ce9bdb7',2713,2713,'首先这个课相对来说不难，花点功夫学就行。老师上课非常认真，讲课条理清晰，声音流畅自然。给分也比较仁慈，一个学期点了三次名吧。美中不足是每章都有小测，但是也不算太难吧。很负责任，翘课没小测的还给补考机会，作业也能补交。实验课她还考虑到大家事情多，推迟了交报告。whatever反正这门课也没得选，有个好老师是福气。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6497e2ee966d5d052ce9bd3c',5581,5581,'比较水，就是作业要写的有点多',4,4,4,12,6,3);
INSERT INTO "reviews" VALUES('6497bab7c0092f540a19d6a2',1734,38,'教的中医药，平时分巨低，选到她算你倒霉，平时上课让用雨课堂做题，给的时间巨短，没做完就说你打字慢能怪谁',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6497b2fb2b817039064177fd',733,8266,'你说你开机电综合设计这门课干嘛，不让自由组队，让几个不熟且开摆的人******谈团队精神呢？',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6496b61ac0092f540a181d93',191,8780,'平时成绩4.6开，光期中考试就占总分的20%平时分给的低，慎选',1,1,4,6,0,0);
INSERT INTO "reviews" VALUES('6496b575c0092f540a181cb2',1108,1065,'老师人还可以，比较爱点名，总共点了有5次，还有两次小作业，全勤且作业认真写都交了就给满平时分，总的来说还可以，不喜欢坐牢的慎选。
INSERT INTO "reviews" VALUES('6496a9b22b817039063f71c4',5581,5581,'可以，比较水',5,5,3,13,5,4);
INSERT INTO "reviews" VALUES('6496a6db2b817039063f6a2c',5581,5581,'还行，平时较水，但要写的东西有点多',5,4,5,14,4,1);
INSERT INTO "reviews" VALUES('6496a5ac2b817039063f65c3',5581,5581,'老师很专业，不过前期对非专业的学生有点吃力（上课要答题啥的，作业略多，三次作业，都要写东西，基本上得写个几千字才行，不过上课还是比较轻松的，建议感兴趣的选',5,5,4,14,4,1);
INSERT INTO "reviews" VALUES('64969b10c0092f540a17a56e',7062,779,'工程测量里最差的，慎选 ',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('64968fa62b817039063f37ca',823,380,'看我表情行事：😍😍😍😍😍🥰🥰🥰🥰😘😘😘',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649668a82b817039063ef7b6',2437,1954,'非常亲切，不懂的问题他反复讲解，直到大部分同学听懂为止。很理解我们考研的学生，会提前通知下节课是否点名。
INSERT INTO "reviews" VALUES('649667a82b817039063ef656',7473,181,'老师人很亲切，回答问题很耐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6495ab32c0092f540a165313',278,228,'老师挺好的，今年平时分最后都给挺高的，课正常去，大作业认真做，分数都可以的，除了期中之外，课堂小测也是只有选择，能给你加的分都会给你的，感觉老师变好了呢。',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('64959fdbc0092f540a162dc4',8371,3098,'Freedom trumps all else. By the way, you''d better to be prepared to learn by yourself.',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('6495708cc0092f540a15d5f1',2015,2015,'非常非常好滴老师，很亲切，太幸运能够在大一上遇到他😁',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6495674f2b817039063d6f1d',297,194,'放在大学老师里属于是会讲课的了，平时分给满了，很有逻辑，但是作业很多',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('649567402b817039063d6ef1',297,194,'讲的不错，平时给分不高不低，期末会认真的让大家复习。',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('649566f2c0092f540a15c48c',1062,352,'上他的线性代数，他表达能力堪忧，但是很认真负责，就是不会讲课，把握不住重点，听他的课也有点费劲，平时分也不是全给满',2,1,4,7,3,0);
INSERT INTO "reviews" VALUES('649566c9c0092f540a15c453',948,92,'平时分占30%且给的高，基本满分。点名只有临近期末点了三次。但是讲课讲的是真烂，就自顾自的讲，她也知道自己讲的不咋样所以允许学生在课上自己听网课。',1,2,5,8,1,1);
INSERT INTO "reviews" VALUES('6495658d2b817039063d6c7d',948,92,'完全不会讲课，纯念PPT，就是你讲课得把基本公式的原理给一步步的推导讲懂了吧，讲的飞快，关键的步骤完全跳过，她给你讲的都是很浅层次流于表面的东西，公式都没讲懂就直接讲题，随便b站哪个老师都比何讲的好一百倍，自己还讲的挺高兴，课上基本没人来，第一节课大教室坐满了，到中期不够30人，这也能说明什么问题了吧',1,1,5,7,1,2);
INSERT INTO "reviews" VALUES('64955375c0092f540a15a232',68,8797,'虽然上课啥也没干，拍视频也摸鱼了。况且作业完成的也不是很好，上课也没怎么听。但是平时分给了51。作为一个学生这个老师真的是最善良的老师。在别人英语分只有45.46的普遍情况下。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('64951d31c0092f540a1543d5',8147,26,'徐老师退休了，作为最后一届感谢栽培',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('649482132b817039063bf1e7',239,239,'恒哥的评价竟然这么少？这么人见人爱的神仙老师，课讲得好，人幽默，又帅，人又耐斯，跟学生打成一片。爱他！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6494609fc0092f540a13d0bf',2005,1170,'绷😅',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('6494602d2b817039063b7cc9',11,11,'😅',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('64945fef2b817039063b7c78',11,11,'上最水的课，布置最多的作业，给最低的分
INSERT INTO "reviews" VALUES('64945f29c0092f540a13ce67',11,11,'凭一己之力让整个班平均分低其他班十分',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('64945e332b817039063b7961',535,535,'来自挂科人士，47分以下不捞人，期末头天改第二天就出成绩，鼠鼠我呀，要准备补考啦',3,2,3,8,2,0);
INSERT INTO "reviews" VALUES('649457642b817039063b6ec9',8805,304,'大爱晏子',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64945711c0092f540a13c1e0',304,304,'唉😮‍💨，还差的远呐',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('649453582b817039063b5531',5581,5581,'老师是好老师，但是没必要真没必要，我选个美育课我那是为了提高审美修养吗，我那是为了美育学分。为了这两破学分我每周四晚上兢兢业业守着手机答题选东西，期间还得交两次课堂作业要你欣赏乐曲，我个人能力不行也没这兴趣也没这心思去欣赏那个乐曲，我正课事情都忙不过来还有闲心思忙你这个？到头来时间也花了分也不高，我就是想水两个学分我容易吗，折磨了一个学期了，只建议热爱小提琴音乐的有时间的人来选，其他人就算了，放过自己吧',3,3,3,9,12,0);
INSERT INTO "reviews" VALUES('649433c5c0092f540a137937',978,978,'纯纯逆天，被折磨了一学期',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('649431ebc0092f540a1376f7',1108,1065,'修的习概 特意来给老师好评 首先不要求笔记  虽然她中途想变卦 但最终没有要求笔记 交作业签到这些规矩她都讲的很清楚  经常签到 人也很温和 很负责！！发了自己做的word和word简化版！！只要你按照她的要求来 平时分满分！看见50满分激情好评！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6493ee93c0092f540a130ef3',2229,2229,'从代码到实物没有期末考试，成绩全看期末项目（平时的东西不做都没关系。事情多又做项目又做海报又报告，全自学器件自费）。下什么软件从来是头天晚上才通知。这门课基本就是什么都没教让你做项目（要做两个），课程安排混乱。工训中心又远，设备质量也不行。感觉他上课不太上心，挺不负责的，除了人还比较随和，没啥优点。雷中雷。',1,1,3,5,5,1);
INSERT INTO "reviews" VALUES('6493e70c2b817039063aacf2',978,978,'上课事多，节节课要求扫码签到（那个啥比码怎么扫也扫不上😅），平时讲课口齿不清啥也听不懂，脾气还不好。作业要求还一大堆，要么一下留十多道作业题，要么当天晚上就是ddl😅😅😅，每次上课都想似🙏。课上有时候还用慕课堂随机抽人回答问题，心脏不好的能直接过去😅。平时分和期末大报告给分都不高，狠狠拉低均分绩点。这都是我高考分低调剂到物流这个啥比专业应得的🙏🙏（仅评价数学建模b这门课）',1,1,1,3,14,1);
INSERT INTO "reviews" VALUES('6493e0bbc0092f540a12fa17',230,230,'避雷',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('6493e0172b817039063aa328',8813,1482,'非常好',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('64931cf3c0092f540a120222',8814,8814,'老师人很幽默，讲课也挺有意思，能让人听得懂，给分也高，半期考试会提前划题目，期末最后几节课特地空出时间来画重点讲题目，真的好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6492feeac0092f540a11bfaf',179,179,'omg太适合追求自学 平时分高的了！！！我滴神 可惜数电没抢到😭',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('64928b62c0092f540a10ff39',3895,3895,'不点名，水，给分还行，这门课的实验老师实验分给的比较低',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('64928a8bc0092f540a10fdf6',5567,1904,'上课收手机，上课很无聊，期末会捞人',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('649288a9c0092f540a10fb79',4016,910,'电影很好看很经典，期末水观后感，偶尔点人点评电影，分很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649287f82b8170390638a6ef',1186,40,'老师比较温柔，给分一般，上课会提问，视听说事和小组作业很多',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('649282012b81703906389f53',2202,27,'老师超好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64927c452b817039063897e7',1108,188,'看了以前活水的评论，选到春玲老师的课后疯狂祈祷。第一节课见到老师后还和同学说，她说话好温柔。点名也就正常频率还不搞花式点名！也不多事儿，就两次简单的课堂作业，而且她说只要不敷衍都给满分！最后平时成绩拉满了😭 😭 真的很惊喜！',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('649276edc0092f540a10e440',1108,188,'不准你们说我春玲爹的坏话😭平时分一百分谁懂啊，那些上课不来的平时分当然没有了，习概第一次开，没有平时作业，两次随堂测验只要交了就全满分，最后平时成绩100，所有人交了作业和签到都来了都是100，不准你们说我春玲姐的坏话',5,5,5,15,2,6);
INSERT INTO "reviews" VALUES('64927176c0092f540a10b7aa',5803,8823,'一个选修课采用两级制给分******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6491ddd02b81703906379e51',2637,40,'上了她的语言文化翻译课，避雷，平时分给的低的要命，作业课程一次不落，但是上课不回答问题就分很低！讲课语速非常快像个小钢炮一样哒哒哒哒！话太密，建议神经衰弱的同学不要选！',2,3,3,8,2,0);
INSERT INTO "reviews" VALUES('6491cec52b81703906378b8e',7120,1267,'老师很温柔，课也很轻松，但是期末给分不会无脑高分，想刷绩点的还是要注意一下',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('6491babbc0092f540a0fb438',5581,5581,'老师还会发红包！！！好就一个字！！！',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('6491b812c0092f540a0fafff',709,949,'怎么没有人评价，很会捞，爱来自瓷器🙏🏻如若此后百年千年，来人漫步于西史身侧，人们便要呼他的名🙏🏻',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64919b302b81703906371c42',5581,5581,'首先，这个老师对这个选修课非常认真，每次都认真备课，上课的时候还会拉一会儿小提琴，能学到很多专业知识，如果愿意听一听也很陶冶情操。其次，这个课程相对比较水，经常只有一半的人来上课，但是老师也不怎么说，可以在小程序里直接上课，不过我觉得还是在教室上课效果比较好。最后，这个老师的作业有三次，除了一次期末大作业还有两次平时作业，如果上课听了的话可以直接写，没听的话建议抄课件或者适当百度，因为老师每个人的不一样作业都会看。总之，个人认为这门课很不错。',5,5,5,15,3,3);
INSERT INTO "reviews" VALUES('64919917c0092f540a0f6973',5581,5581,'超级推荐这个课！老师人很好，每节课上课都会拉小提琴。有两次作业，可以直接看雨课堂的课件写，期末总结写个几千字分也挺高的。课程也挺水的，一大半人不来上课老师也不说什么。',5,5,5,15,7,5);
INSERT INTO "reviews" VALUES('64919862c0092f540a0f683e',5581,5581,'只要上课听了就行作业基本上都会做，上课也不一定要去教室，这老师是雨课堂上课，基本上第一次去了之后，以后上课直接从雨课堂进去就行了。期末交总结，写个三千字差不多给的分就挺高了，字数低一点应该也没关系吧不清楚。反正力推这个课！！！',5,5,5,15,7,5);
INSERT INTO "reviews" VALUES('649197dd2b81703906371689',173,28,'作业多的一匹',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('6491977a2b817039063715db',131,3003,'课程不严，但需要自己做东西，很多人根本没去上课老师也没管',3,5,5,13,0,5);
INSERT INTO "reviews" VALUES('64917bfa2b8170390636e294',2210,281,'神，期末硬生生把我从40多拉到60',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64917b8c2b8170390636e19b',68,40,'这学期这个老师有所改善，',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('64916c19c0092f540a0f14d9',5581,5581,'我是一点都不想给好评，没打零分算好的了，上课的同学一般都没什么基础，每节课都提问算分，你就一节选修课我还要认真复习你上课内容吗，什么玩意啊。三次大作业也是恶心的要死，不懂古典乐的根本分不了段落，竟然作业分能给到不及格一下，我真的不理解，而且还鼓励大家作业不停内卷，一个选修课感悟要给你卷到几万字才值得表扬******',1,1,1,3,12,5);
INSERT INTO "reviews" VALUES('64915e36c0092f540a0ef9dd',807,862,'这门课我们有两个老师上（姚志洪老师、刘海旭老师），有半期考试，开卷，期末考试也是开卷。考试内容大部分书上都能找到，给分高，可以冲。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('649126a92b81703906364e5f',510,653,'赵老师！狠狠赞了！太好一老师了！超耐心，给的意见很具体，而且会找出每个设计的亮点！我哭死！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64912582c0092f540a0e9dcc',545,433,'莫老师！超级好！刀子嘴豆腐心！给分很高！',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('64911c18c0092f540a0e8747',4066,24,'我是傻逼',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6490fbf72b81703906360805',725,40,'上的翻译。优点：作业较少，事情不多。缺点：给分不高甚至有点低，上课要抽很多人回答问题，几乎不在群里通知大家事情，总是口头说一下。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('64906fd32b81703906356a8d',5190,5190,'曹老师人很温柔，讲课也很清楚，特别喜欢和我们交流哈哈哈哈哈哈，有点可爱',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64905eee2b81703906353b0a',545,433,'特别好的老师啊！刀子嘴豆腐心No.1有被生活打压后的美，嘴很毒但平时分给的很多形成鲜明对比。从英语这门学科来说对基础不太好的同学不太友好更多需要学生花更多时间自行学习英语，课下事情其实很少打听一圈后了解到莫老师的课程课下作业都是该课程要求的基本量没有单独的加量安排；上半学期对课本关注不多课上农门阵非常好玩在英语课上什么都能学除了英语；下半学期更关注于书本上内容龙门阵含量极速下降，两学期你可能经历黑转粉转路人转黑转粉持续循环',5,5,4,14,3,0);
INSERT INTO "reviews" VALUES('64903c6dc0092f540a0d4737',1267,5618,'谁选谁总评90+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648fdc67c0092f540a0ca473',1186,40,'老师人很好，但是每节课都去，每次作业都认真完成，上课也举手回答过问题，就是分很低，大概就是80左右，想拿高分的快跑',3,5,5,13,0,0);
INSERT INTO "reviews" VALUES('648fcc15c0092f540a0c8509',1390,433,'超级无敌好的老师！！非常认真负责，非常真诚，可以记住全班人的名字，会提醒大家交作业，每次作业截止时间前还会截图提醒，上课很热情很有耐心，课下还提醒大家的身体健康，很亲和有趣，课前课后还会放一些视频活跃气氛，大学遇到陈老师真的很幸运，平时分也给的很高！非常认真负责的老师，选她没戳滴！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('648f2d11c0092f540a0bd182',1454,23,'有口音听不太清 一点不捞🥹 但是事少不怎么点名 有一点歧视非理工科生（从qq动态看出）',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('648f238f2b81703906337574',68,40,'很多人觉得她不好 会骂人。其实只要按照她的要求来就不会。她上课讲的很清楚了 而且课上给你做作业。不占用另外的时间。我觉得按她的说法去做真的很简单 另外上课多发下言 平时分挺高的。她给我学术英语59.8 职场英语60满的平时分。我真的没见过那么好的老师😭。而且学术英语和职称英语去年都存在压分的情况 她给我那么高❤️',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('648f066b2b81703906333213',40,40,'******上课点名几乎每节课都点，全班都能点一遍。给分特别抠，最后平时分都四十多一丁点。给分太低******',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('648eeaddc0092f540a0b5348',2637,40,'事比较多，作业给分抠，上课不回答问题分很低，社恐就别来了',1,1,3,5,3,0);
INSERT INTO "reviews" VALUES('648edf11c0092f540a0b4364',1128,40,'老师挺水的，想学东西的别来，想摆烂的非常可以，分比较高，事很少',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('648edba52b8170390632f2a1',2983,294,'这个老师，英语专业能力还是可以的。但是给分确实有点低。这个课本来细碎的小分就多，她分拿捏又得很死。最后平时分普遍都比较低。另外， 她处理工作感觉不是很及时',3,3,2,8,0,1);
INSERT INTO "reviews" VALUES('648ecf3fc0092f540a0af380',1600,96,'好好好，必须满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648ebda72b8170390632bfcd',604,96,'******凯皇yyds',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('648e812dc0092f540a0a765a',1265,1265,'非常好，英语平时分最高分都是这个老师给的。只要作业认真完成，给分都不低。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('648e7541c0092f540a0a668d',68,40,'是上学期选的冯老师的课，之前看了活水的评价还挺担心的，但抢不到其他老师就选了冯老师。体验下来，我觉得冯老师真的没有说得那么吓人，她性格比较直爽，所以可能批评人的时候有点不留情面。课程方面，以每个人都要做完的大作业举例，刚开始的时候她会布置小组作业，给出框架，慢慢地让大家了解学术英语的写作，会将一篇最终要提交的论文拆分成几个部分，一步一步带着大家完成。讲参考文献的格式的时候也很认真细致。跟着她学确实能学到很多东西。当然班上确实有挨她骂的人，说真的，都告诉你要怎么写了还乱写一通，那不骂你骂谁。而大二下，出于兴趣选择了另外一门课程，没有选择她的职场英语，但周围选了她课的同学评价都很高。入股不亏！',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('648e65b4c0092f540a0a4e13',255,223,'绝了，杨姐的职规课特别好，给分也高，课上也可以学到很多，她让我对职业这方面有了很新的认识，绝不是那种很死板的课，上职规课就选杨姐的！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('648e64f9c0092f540a0a4c1c',35,106,'第15周有课堂音乐会，是每个学生都要表演，无聊且费时费力；期末大作业是公众号推文，但要求在第十周之前完成；每节课是一个一个的点名才能走；一节课没逃过，还帮她审核作业，公众号推文也上她的公众号了，结果平时成绩连90都没上，拜托这是选修课，对这老师真无语',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('648dd497c0092f540a09acd1',1320,3017,'给分低，兢兢业业给这么低，每次课都拖堂，',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('648db0282b8170390631453b',8024,8024,'总成绩二级制。所有人一个分，不管付出多少。',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('648dad6fc0092f540a095c78',2821,11,'神中神，按时完成老师的要求平时分就不会低，平时上课回答问题可以用手机在群里发言。',5,5,5,15,0,0);
