INSERT INTO "reviews" VALUES('648d9440c0092f540a0936c6',725,40,'基本每节课都会把所有人叫起来一遍回答问题，平时分给的一般，作业给的很低，上课听着想睡觉。',2,2,3,7,0,1);
INSERT INTO "reviews" VALUES('648d9086c0092f540a0931ce',5460,8864,'平易近人有梗还容易被怼的姚老师一枚啊~',5,5,5,15,0,0);
