INSERT INTO "reviews" VALUES('648d8e8dc0092f540a092f45',51,51,'虽然老师恐性/别少数群体，但事少给分高就对了🤗（每节课都要点名哦～）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648d57c1c0092f540a087bc8',546,40,'这老师还好，课后事情不算多，平时分50左右也不难，但是每节课得到',4,5,5,14,0,3);
INSERT INTO "reviews" VALUES('648d30392b817039063051eb',3479,526,'义夫！学芳的好，上过课的人才知道！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648d0fa72b8170390630229e',546,40,'本人上的语言文化与翻译，曼曼平时上课还好，不经常抽人，进度比其他班快，作业认真一点都完成给分还算可以，课堂表现和小组作业我都能有80+。对比来说没有像学术英语那样很多人说的给分低',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('648c984a2b817039062faea0',1493,1493,'需要留学刷分的可以找他，期末额外做一个报告就94份左右',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648c88fe2b817039062f9d92',1186,40,'人还是很不错的，事也不多，但给分相对低',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('648c88512b817039062f9b71',489,573,'刘娟老师人美心善哦，长得漂亮就像18岁的清纯少女，上课氛围也十分好呢，每节上课从来都不迟到，作业量很贴切大家的接受能力，而且老师会很耐心的教你如何学习这门课，上课呢不需要做笔记，只需要跟着老师就好了，平时也不会点名，上课也不会布置习题让大家在雨课堂上提交哦，平时分超高的呢，老师期末还会捞你，班级平均分都在80左右啊，这样好的老师你还不心动吗，快快抢走老师吧',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('648c87cec0092f540a06fd17',42,43,'听说龙哥通过率特别高，很多还是满分。我已经满分过了，我觉得这个龙哥还是很不错的，好拿高分。现在很多别的什么老师给分可不高，看到很多师兄抱怨龙哥怎么严厉怎么样的，我就想这点苦都受不了，干别的肯定也不行。',5,5,5,15,17,43);
INSERT INTO "reviews" VALUES('648c72752b817039062f74c3',1493,1493,'老师很温柔，给分还不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648c3dfe2b817039062ede51',1372,23,'不是很懂为啥老师评价这么低，大一下上的这门课，念ppt这个倒是，不过也能听得懂，上午上完课下午做实验，当时疫情是在寝室做的，有不懂的地方直接私聊也会回答，连续问好几个也没啥问题，还愿意帮看整段代码，上课还鼓励同学有不懂的地方可以直接带电脑过去帮忙看看，最后平时分拿了一百分，当时期末是笔试，没有这平时分就寄了',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('648c19f5c0092f540a05fe53',1186,40,'老师人好，平时上课很水，但是课后事比较多，平时分给的比较低',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('648c1269c0092f540a05e928',2005,1697,'快跑，上课嗓音尖锐，一直考考考，均分压的很低。当然如果你是门捷列夫当我没说。还很喜欢揪着学生说不记笔记，ppt翻那么快还不准拍照！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('648c06b1c0092f540a05da0d',3719,230,'分没出不知道，不过没点过名，后期去的人不到一半也装没看出来，有次叫班长收作业，班长没来也没追究',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('648bee5b2b817039062e5ab6',954,52,'老师人特别好，上课很水，基本不点名，期末作业交齐使劲捞',4,4,5,13,2,0);
INSERT INTO "reviews" VALUES('648bd9942b817039062e3961',546,40,'事多点，没那么不堪，稍微水点平时分也能50左右',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('648b42372b817039062d92d0',2230,8881,'老师真的特别特别特别特别好，真的没有想过在大学能遇到这么负责的老师。真的真的很幸运能够遇到易老师🌹🌹🌹🌹🌹',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648b3e71c0092f540a04e627',5300,5300,'yyds。人很好，和善、耐心，讲课还行，作业不多。数据库实验课程要求也比别的老师少。数据库这个课不难。一定要避雷朱焱老师，舍友被折磨的欲仙欲死。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648b3de12b817039062d8e3e',8883,8883,'讲课还行，人很好，很和蔼，有问题都会耐心解答。作业不多。计组这课有点难，要多花点功夫的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('648b3d052b817039062d8d63',42,43,'电子龙yyds，脾气不太好，喜欢阴阳怪气，但是期末平时分给分很高的，交大名师。当然数电实验是给你分配的老师，你也不知道是谁。如果分配到龙哥，可以锻炼大家以后上职场曲意逢迎、笑里藏刀的能力，平时分也不错，推荐。',5,1,1,7,2,0);
INSERT INTO "reviews" VALUES('648b2efbc0092f540a04cba7',8885,361,'上课情况：主要是读ppt和课本上的内容，但是老师表达能力和亲和力都不错，不会感到枯燥。老师管得松，不想听可以在下面明着玩手机用电脑、做自己的事，相当于换个地方自习；
INSERT INTO "reviews" VALUES('648b2d8b2b817039062d72fa',674,307,'超好的老师',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('648b2d71c0092f540a04c956',8887,8887,'很暴躁，对学生不好，体育因为参赛考试请假了，结果回来不让补考',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('648b2d172b817039062d725d',1186,40,'很好的老师，给分高，对学生也很好!特地登这个号给老师评价',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('648b1ad2c0092f540a04acad',8885,361,'是中国人就别选！！！每节课点名，一篇大论文，一篇设计，还有考试，一个选修课还搞考试！！考试开卷不能用手机，没有课本等于寄，等于变相让你掏钱买书。虽然还没最终给分，但体验感已经是足以给到全1分的程度！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('648b19a92b817039062d4b9a',1480,127,'yyds',5,5,5,15,1,0);
