INSERT INTO "reviews" VALUES('648b02d32b817039062d1b78',100,478,'给了押题的卷子，命中率很高好老师
INSERT INTO "reviews" VALUES('648b029bc0092f540a047291',2885,40,'平时分55不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('648a92efc0092f540a03affc',1441,228,'郑瑶老师上课和蔼可亲，讲的也好（如果想学到东西认真听的话）。多坐第一排可以加平时成绩也会让老师认识你，获得免考资格。郑瑶老师的免考资格是真的多！！！我们班大概10个同学。yyds!!',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('648a75ffc0092f540a0376cc',1458,1449,'屁事一堆，讲课逻辑混乱，到学期末搞个大作业也没有搞懂这个学期学了什么玩意。建议不会教可以退休',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('648a71932b817039062c23d4',8814,8814,'老师人很好，很幽默，讲课也讲挺好，后半学期根本没听过课，老师最后4次课带着复习了一遍基本上都会了，平时分也给的高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6489ceb42b817039062b64f4',1441,228,'平时分给的高，无脑冲',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('6489c7472b817039062b468a',808,140,'老师人又可爱又好 最后一节课还写了稿子跟我们告别hhhhhh 还有几天考试 先来打个好评 希望平时分给得也不会低',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('6489c3492b817039062b405c',360,360,'海哥是一名充满热情和智慧的老师。他总是能够把枯燥的知识点变成有趣而易懂的内容。他非常细心，总是在课堂上鼓励我们提出问题和讨论，帮助我们更好地理解所学内容。虽然他对我们要求很高，但他总是能够耐心地解答我们的疑问，不厌其烦地帮助我们掌握知识。他经常用自己的故事和经验来启发我们，让我们不仅在知识上得到提高，也在人生经验上受益匪浅。我感激海哥对我们的一切支持和鼓励，他的教导让我感到自己变得更自信、更有动力，也更加热爱学习。',1,4,5,10,1,11);
INSERT INTO "reviews" VALUES('6489c2272b817039062b3e66',360,360,'黄老师为人和蔼可亲，上课认真，专业能力强，能从他课堂上学到很多东西。',5,5,5,15,5,18);
INSERT INTO "reviews" VALUES('6489829a2b817039062ad9af',4413,68,'给分很低，而且亲自告诉我们她会压分（也确实压分了！！！！警告)，事情还很多，除了英语相关的内容啥都做过，主打一个教书没水平事儿多还浪费学生课下时间来做一堆事情（而且必须是小组作业，一个组内打同分）
INSERT INTO "reviews" VALUES('64898050c0092f540a022936',389,389,'呜呜呜呜，没有对比就没有伤害，老师讲的真的很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64896a3c2b817039062aad89',23,23,'yyds！必冲！',5,5,5,15,23,0);
