INSERT INTO "reviews" VALUES('64893782c0092f540a01a1b3',294,294,'不咋地，别选别选',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('648922acc0092f540a0182cd',7045,28,'在其他同学每周一个pre或ppt的时候，杨老师班上风平浪静没啥作业，而且课上不要求回答问题。给分也挺合理的，神中神！',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('6489215ec0092f540a0180d2',2202,28,'Iris老师yyds！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6489190dc0092f540a017334',876,685,'节节课要点名，郑老师个人性格很有意思，真的喜欢天文学的话可以来，但如果只是想混个学分还是不建议来。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('648917c8c0092f540a017159',2230,2230,'个人水平很高，治学相对严谨，经典刀子嘴豆腐心。上课狠话放的多但实际上给分非常高。总的来说是一位难得的好老师👍',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64890e1e2b817039062a193d',2878,27,'黄老师神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6488f9b4c0092f540a014a8b',1042,462,'我的神！很好相处的老师！有作业但是是能够完成的量，讲课声音洪亮，专业能力够，想学肯定是可以学到东西的，也可以摸鱼。而且真的很为学生着想，是年轻老师~谢谢王老师的平时分把我的工力成绩捞到了一个新的阶段😭😭',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('648895dfc0092f540a00ef6d',142,142,'作业特别多，雨课堂和学生系统混着的，稍不留神就平时分丢完了',1,1,2,4,5,0);
INSERT INTO "reviews" VALUES('648893be2b81703906299feb',8914,8914,'事情一堆，毫无重点',1,1,1,3,0,0);
