INSERT INTO "reviews" VALUES('6461dc53d79b4a6c7fd2ceda',1065,1065,'说真的 上了三年大课 终于给我们优选班分配了一位巨巨巨巨好的老师 一学期回答五次问题平时分直接拉满 社恐人可以选择不回答问题也可以拿到45分 而且每次回答问题老师都会让全部想回答问题的人回答 缺点就是有时候举手很久都没有被请到 不过最后肯定还是会起来回答的 老师还问我们想不想做大作业 结果就是一个学期也没有大作业也没有实践 上课气氛也很轻松 只要不交头接耳老师都不会管 全班点名前一天老师还会在群里提前告知 last but not least， 老师超级超级超级漂亮！！是气质美女！！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('6460ece2c48240148930ffda',823,1897,'这还用说，讲课讲得好，又好说话还幽默的然然妈妈难道不值得拥有吗？给我无脑冲！！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64605234d79b4a6c7fd09287',5219,280,'别来，快跑求求了，完全不顾学生自顾自的一个课程组，我是说不仅别报这个老师也别报这个运动舞蹈!因为它不顾你的意愿还会那你调剂!希望让选他们的人足够少让这个该死的课程组倒闭! 乐，舞蹈比赛占期末50%，还有另外的期末考试，谁教你的两个期末？为了上台要课外加练，上课说让我们最好再晚一个多小时走理直气壮？尼玛的谁造成的一个0.5学分45分钟的课费这么老大牛鼻子劲？',1,1,1,3,3,0);
