INSERT INTO "reviews" VALUES('6448d0b315730471b5e95ae2',637,694,'给分高，给了我39.6分 平时作业有点多，认真做期末考试很简单。半期考会排座位但是很简单 认真学总评95+不是问题',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('64489fbb7cd5773a6d50b944',246,228,'自己讲得不好也就算了，也不能做别的事情，如同坐牢，念的全是书上的，那我为什么不自己看书，感觉简直浪费生命。说好了考试结果来了不考，熬夜复习的算什么啊，这是干嘛，骗学生上课吗？还不如想办法把课讲好点…还有自己说第一周说了要中期考，可是拜托还有二三次选课啊，后面来的人根本都不知道，还是有人在群里问了是不是要考试才知道…真无语啊啊啊啊',3,3,2,8,3,0);
