INSERT INTO "reviews" VALUES('6445dcf215730471b5e5257f',6087,6117,'喜欢我期中闭卷吗？喜欢我天天司马脸吗？喜欢我上课念ppt吗？哼，想逃？这门课就姐一个人上！通讯原理这一块姐就是王！什么？你的期中结束了？说过多少遍了！你的期中由我拉斯特巧来无限复活！如果你能像我一样教学严格、永远不笑的话，那真是泰裤辣！😝（纯发电，只能说这门课适合认真学的人，不适合我这种摆烂哥😭）',1,1,1,3,4,0);
