INSERT INTO "reviews" VALUES('64369b349502220dcbd7a2b8',6,619,'给分低，只扣分，不加分。不给看手机，不给用电脑，上个课：“你看手机干什么“，“现在的年轻人都这么喜欢看手机了”，凭情绪扣分，“这是我的权利”，突发性点名，期末压分严重。前几周选课未结束时会伪装成“正常人”，后面直接本性显露无疑，是个喜欢利用职能之便折磨他人的衣冠“人士”。满嘴民主、正义之词，极尽独裁、冷漠之事。不要犹豫，快跑。',1,1,1,3,22,0);
