INSERT INTO "reviews" VALUES('64327ae01abe031ff72a0a17',258,43,'呃……她平时确实挺松的，包括她带的助教也是不知道要验什么的样子，演示一下就过了，也不会问问题。给分的话也不错，平时一验加上报告所有部分写好能给满。只是期末考试的时候她这个摇摆不定的考试标准，明明说了仿真做出来了画图才有效，结果她又允许直接画图也给分了(在她检查了我的之后……)只要装着差一点就弄好仿真了，时间到了她也会等你然后去先检查别人的。是，可能是挺好的挺松的，但这是不是有点……',3,3,4,10,0,1);
