INSERT INTO "reviews" VALUES('64284f761abe031ff71d2bf1',1042,462,'刚留学回来的老师，真的很在乎学生；讲课逻辑清晰声音洪亮，有时候会抽一两个人回答问题，不难答不上也没什么；作业基本每周都有但是都是书上习题，不算难；后面全班期末考试考了32分以上的都平时分拉慢了，因为期末32平时慢刚刚及格，真的很好的老师',5,5,5,15,3,1);
