INSERT INTO "reviews" VALUES('6427d2771abe031ff71c7547',9133,980,'收获颇丰，没学明白的彻底弄懂了，颠覆对语法枯燥无聊的印象。小组pre要认真做，贾老师这方面要求严格h h h ',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('642722371abe031ff71baddd',9134,833,'平时分很低，挂科率极高，考试全英文卷子，不捞人，茅班同学能润就润吧',4,2,2,8,1,0);
