INSERT INTO "reviews" VALUES('64268ad21abe031ff71adb2c',788,1551,'全专业一共100多个人挂了一半，重修班都得开两个😅',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('64266a501abe031ff71aaeaa',9122,9122,'杨帆老师神中神，为了培养同学们自主学习，课件从来不在群里发，就算是有同学在群里要，他也会温柔的说下课自己来拷，当学生想要检查试卷时，他会告诉你应该去找实验中心，为了给同学们一个小小的教训他会挂点全班30%到40%的学生，避免你们在未来的生活里偷懒，里安处理卷子简单高效，计算题只看结果，结果错了直接0分，让同学们更早知道自己的成绩，省的担心，同学们无脑入就行了',5,5,5,15,4,0);
