INSERT INTO "reviews" VALUES('642268e29c3cf57aea081f72',9152,1542,'你的大作业要照模板写，早不说（也没在群里发过模板），非得上了课都交了才说，然后没按模板弄的之后重交……难崩。。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('64224947f11d5e1b0355795a',173,28,'******大一生入学考试最好乱做，0分最好，进了A班就有可能分到她的班，而且大一不能换，进了她的班就等死吧。平时作业全做完，u校园时长挂满，平时分满分六十只有四十多，什么成分不用我说吧，不去参加晨读和竞赛根本不可能上五十。我期末考试接近九十分，最后分数才八十出头，自己品吧。事情贼多，给分贼低，学一堆没用的东西，比高中老师离谱。大二谁选她的班，我笑他两年半。',1,1,1,3,15,0);
