INSERT INTO "reviews" VALUES('641aa5669c3cf57aeafd8321',42,42,'不要信龙文杰给分高，如果你实验挂掉，他该扣都会扣。不要信龙文杰会让你锻炼学习能力和成长能力，就那句话，你要感谢的是克服困难的你，而不是感谢苦难。不要被欺负还要感谢人家。
