INSERT INTO "reviews" VALUES('641a4605f11d5e1b034a7711',626,175,'上课特别无聊，语速很慢，喜欢随机点人回答问题，关键平时分低，听说也不捞人',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('6419b9b29c3cf57aeafc5c87',975,975,'纯伞兵，期末考完其他班都出成绩了他不出， 理由是还有人需要补做实验，行吧所有人实验都做完了开始登成绩。按照要求40分的平时分是实验 课堂表现 作业 期中各十分，他直接把实验那10分删了，把期中改成占20分。那我请问你那么多天不登成绩理由是要等所有人实验做完是什么******操作？期中不往上拉，考了多少就是多少，一个班基本都是6070，当然这没什么，我菜我承认是我的问题。但是你把期中改成占百分之20把基本都给90加的实验删了是什么睿智操作？平时分一下子比其他班少了好几分。出了成绩被学生质问为什么不按照教学大纲执行，他装死不回，发现改不了成绩就把教学大纲改了，把教学大纲里实验那一项删了，离谱。千万别选',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64198e2ef11d5e1b03498b2b',788,788,'懂不懂一百个人挂四分之一的含金量啊🤣',1,4,1,6,7,0);
