INSERT INTO "reviews" VALUES('64192190f11d5e1b0348c993',2598,2598,'上课节奏有点儿快，需要认真听，讲得非常好，老师非常认真负责，作业少，并且qq上问题基本是秒回，人特别好有耐心，想认真学的值得选！',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('6419166e9c3cf57aeafb31e6',1332,81,'太离谱了，感觉和戈培尔一样。光是各种魔怔言论就算了，可以不去理会，还强制要求你必须把他上课讲的记下来.......就算要搞红的内容，能不能表面上水平高一点呢，也不讲什么理论原理，最爱的就是研究领导生平和语录。之前还听说他是博士，以为至少水平不会太离谱，后面一查简历，专业思想政治教育.......这个专业真是恐怖如斯。隔壁某半岛金将军主体思想都已经在指导宇宙运转了，这里还在只想指导全国，格局还是不够大。',1,1,1,3,8,0);
