INSERT INTO "reviews" VALUES('64117831f11d5e1b033d5e55',465,4154,'老师认真负责，期末给分也很宽松，吹爆',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('641152a89c3cf57aeaefae1f',44,249,'如果真的是给分随机就别考试别实验了，分数抽签纯好了。',1,1,5,7,10,0);
INSERT INTO "reviews" VALUES('64113f6b9c3cf57aeaef91c8',433,28,'给分正常水平，平时作业******是同层最多最烦的',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('641117f69c3cf57aeaef54fd',2122,1796,'楼下的那个 形策是零学分的😅😅 光哥说话我觉得没啥不妥的 你要是想卷满绩 没必要 交大不看绩点',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('64110abc9c3cf57aeaef4398',9246,9246,'整体来说，还算可以，但是上王老师的编程课就别想着听课了，直接自学吧。王上课直接照着PPT念，一学期下来没什么讲解内容，上课只会叫学生照着书上代码打字，没有实际的练习作用。但是王老师人挺好，据说会捞人（平时分接近给满的那种）。然而已经上线的学生就不会再捞了。',3,1,4,8,0,0);
INSERT INTO "reviews" VALUES('6410a1c79c3cf57aeaeee159',1158,5,'老师非常好，非常和善，非常负责，平时分直接给满，上课讲的非常好，逻辑清晰易懂',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6410a10d9c3cf57aeaeee088',2122,1796,'不明白为什么老师会在课堂上出口成脏，真的接受不了脏话啊，还有期末考试他完全不看你答的卷纸，统一给分，总分卡在89分不给你满绩，上课还比较喜欢玩烂梗，给人一种高高在上的感觉',1,1,1,3,1,18);
INSERT INTO "reviews" VALUES('64109f7df11d5e1b033c59f1',1753,1753,'老师很好，上课逻辑清晰，然后对数学很严谨，平时分给的挺高的',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('64109ecef11d5e1b033c58fd',242,242,'老师讲的很快，听的怎么样全看你的领悟能力，给分就是大作业如实给，认真上课可以过，但是考试不太划范围',5,3,4,12,0,2);
INSERT INTO "reviews" VALUES('64108f29f11d5e1b033c3c8a',4842,9251,'支持阿托品3号。',5,5,5,15,0,9);
