INSERT INTO "reviews" VALUES('64108df5f11d5e1b033c3ab8',4842,9251,'支持阿托品一号。',5,5,5,15,0,9);
INSERT INTO "reviews" VALUES('64108883f11d5e1b033c31d0',1140,80,'平时看起来很和蔼事情很少，但是平时分给的是真的低，所有的都按时完成了平时分只有82，比别的班少很多很多，不知道怎么给的分…',3,2,1,6,1,0);
INSERT INTO "reviews" VALUES('641065b0f11d5e1b033be6ea',1705,1170,'特别好特别好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64105732f11d5e1b033bcff5',7336,8324,'讲什么都不知道。',2,2,4,8,0,0);
INSERT INTO "reviews" VALUES('64103e80f11d5e1b033bad8e',1705,1170,'老师人很好，对学生很热情很负责，给分很高而且期末还会画重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64102b219c3cf57aeaee1723',36,36,'上课喜欢请人回答问题，偶尔看看视频，主打一个陪伴，往年听说平时分低，今年期末占比百分百让鼠鼠满绩，期末好好复习就能满',2,3,3,8,0,0);
INSERT INTO "reviews" VALUES('640ffcfef11d5e1b033b4a63',1991,188,'爱死了 平时分给满 讲课很客观 不会只讲那些******话',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640ffbcaf11d5e1b033b4875',2172,2172,'这门课是很好的一门课，可以参考mooc上北交的这门课（课程名同名），这老师真的不行。嘴上说一套，手上做一套，最喜欢挂人，讲课水平差（可对比北交），一节课从头到尾就一直傻笑，自以为幽默。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('640febadf11d5e1b033b31a1',9261,9261,'有点无聊，但总体还可以',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('640fe8149c3cf57aeaedb66c',6082,1681,'看得出是位好老师，但婆婆妈妈，过于爱干净讲卫生',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('640fe60a9c3cf57aeaedb378',6082,1681,'专业水平肯定是有的，也确实知识很渊博。
INSERT INTO "reviews" VALUES('640fe1e69c3cf57aeaedad17',1991,188,'平时分给满，考前划重点。上课就是脱口秀，唯一不理解的是为什么每节课都要打倒王一把（晕(=_=)）',4,5,5,14,8,0);
INSERT INTO "reviews" VALUES('640fe15cf11d5e1b033b21c2',9265,9265,'选修课别选这个老师，分数低的要死，真的好无语，选修课唉老师，我又不是你们专业的，你对我的要求跟你们专业一样高是不是有点儿问题？',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640fdfccf11d5e1b033b1f54',9266,1829,'想评价量子力学B的，这是一门小班课，老师人真的超好，后面会让同学分小组做翻转课堂，考前给我们画了重点，还很很捞了一把，真的是好老师啊555555',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640fddaef11d5e1b033b1c3a',199,939,'潘老师真的超好，讲课很生动，也没有口音，有时候会讲一些小故事，能选的真的强烈推荐选他！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640fd2f29c3cf57aeaed93c1',637,694,'我更偏向直接教解题步骤的老师，赵老师讲课是引导式的感觉，对知识讲的通俗易懂深入，适合思维活跃、跟得上老师的同学。ppt全英文对我不太友好，作业适中。老师人挺好，给分还是很高的。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('640fd2cff11d5e1b033b0941',36,36,'事情很多，半期论文拍视频观后感一个不落，上课讲的很水，但是很爱抽人提问，不过答不上来也没啥事。定位签到上学期因为疫情也没有，最后给分90还是可以的',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('640fd127f11d5e1b033b06d1',903,179,'骂老师的多半是自己没学还指望老师捞上来吧。康老师给分高讲课也好，听课前排都爆满。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('640fd023f11d5e1b033b058c',984,850,'老师平时分给好高，上课面带笑容，特别亲切。期中考试还给我们开卷，挺好的老师！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('640fcedff11d5e1b033b03c2',6396,6396,'老师人亲切，是专业大牛，但是课上大部分时间都是讲自己的经历什么的，知识点只讲几分钟，翻转课堂时间太长，要求看mooc（mooc有的课上就不会讲)，经常提问，课上会比较煎熬。最后给分还是可以的。作业没有答案（所有电力系统老师应该都是这样），所以课下要花很多时间。',4,2,3,9,0,0);
INSERT INTO "reviews" VALUES('640fccb59c3cf57aeaed8aca',1130,1130,'老师的上课方式是课下提前看视频，课上再概括重点和讨论。对于自觉的同学能够学得很好。没懂的地方可以反复看视频。视频是老师自己录的，讲得超级详细，可以学到很多！讲课有激情且QQ上答疑秒回！！给分也高！作业要是没达到规定的分会被要求重做，认真负责的好老师！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('640fcb32f11d5e1b033afea6',2119,2119,'课堂特点是抽人回答问题，虽然每次胆战心惊，但是提的问题都是重点。老师反复强调重要知识点，在课堂上掌握的效率就很高！老师讲课也超级好！好老师必选',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640fc7879c3cf57aeaed83d5',785,229,'有点四川口音 但是人超好 回复消息（问题）超级超级快 再简单的也会讲！ 老师亲和力很强也很负责 平时分给的也挺高 阳老师yyds😭😭',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('640fc5edf11d5e1b033af759',1274,36,'第一节课因为没人坐前排骂了我们半节课 交了读书报告（3000字手写稿）和实践报告结果期末考试占比100%😅 但老师不点名上课摸鱼也不管',4,3,3,10,2,0);
INSERT INTO "reviews" VALUES('640fc52f9c3cf57aeaed80e1',315,40,'每节课会点名 课前会抽人读新概念英语 上课一般是讲哲学 但老师人很好平时分巨高😍 讲哲学的时候很有意思hahahah',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('640fbdf3f11d5e1b033aece4',409,192,'******还收手机，拽洋文，感觉自己十分优越😅😅😅',1,1,1,3,11,0);
INSERT INTO "reviews" VALUES('640fb52e9c3cf57aeaed6cc1',36,36,'上课很水，平时破事很多，还喜欢点人回答感想，好在今年平时分没有，期末成绩占百分之百，期末人均高分满绩，就还好，也不知道是不是疫情原因 但我们这一届就还好',2,2,4,8,0,0);
INSERT INTO "reviews" VALUES('640f603e9c3cf57aeaed1fa5',989,989,'******大学三年遇到过最晦气的老师，学弟学妹千万不要选他的电力电子技术，别的两个老师平时分拉满，他是巴不得给你往低了打，我大学三年了没挂过科，他是第一个让我挂的人，晦气晦气晦气！！！',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('640f5cdef11d5e1b033a9217',5120,7510,'神！！！平时分薄纱许建平******',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640f4d65f11d5e1b033a8263',281,9282,'只能说分给的太多辣',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640f4cf69c3cf57aeaed0be5',373,230,'神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640f4ce3f11d5e1b033a81e4',4842,4842,'交运大四上的一门限选，挂不挂科，跟你交的作业内容无关，跟你是谁无关，跟你点名到没到无关。那跟什么有关？
INSERT INTO "reviews" VALUES('640f4ccff11d5e1b033a81d4',43,3227,'要求严格，每个实验亲自验😭，但是最后给分还可以',4,4,2,10,2,0);
INSERT INTO "reviews" VALUES('640f4b639c3cf57aeaed09fc',884,2911,'上课可能很难受，会一直抽问，但下课没事没作业。给分高。
INSERT INTO "reviews" VALUES('640f4b0ff11d5e1b033a7fa1',1452,623,'平时分给的实在太多辣，不过课讲的差点味道，期中期末得靠自己',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640f3d1af11d5e1b033a68f9',4842,6401,'德川淳平，吴梓敬，素质？！祝你的木琴安好。',5,5,5,15,0,9);
INSERT INTO "reviews" VALUES('640f2d58f11d5e1b033a5195',9289,9289,'为啥平时分比别人要少两三分？',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('640f2cadf11d5e1b033a47c9',903,307,'老师是真的好，但是上课不怎么听得懂，需要课下积极思考以及提问。平时分很高，只要你认真做作业，期末考试难度中等，但还是有难题。',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('640f26a7f11d5e1b033a34a7',1452,623,'期末疯狂捞人，想挂科都难',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640f26729c3cf57aeaecbbf7',4842,9241,'没被他挂我可得去烧柱香。这人有病。真有病。快跑。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('640f25e1f11d5e1b033a333f',9289,9289,'很一般，平时啥都做了，也没翘过课，给的分低',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('640f1d849c3cf57aeaecae19',884,884,'如果你让我在上完旅客运输组织的时候就马上给韬姐打分，那我可能会打低分，因为韬姐天天点名回答问题，而且看着有点凶，但是现在旅客运输组织和铁路安全都出分了，我客观评价一下，韬姐就是属于那种平时严格，但绝不会故意卡你成绩的老师，而且给分真的不低！反观铁路安全的张之勇老师，简直不是人！一门大四的一学分的限选课！一个班挂十几个！挂科原因是大作业被他找到出处了，真的一个个找啊，关键大家的作业都是网上缝的，他就随机挂人，如果我们这群被他整的学生没找领导的话就全部延毕，考研保研找工作的全部寄！给他发邮件和消息通通不回！',5,4,4,13,0,3);
INSERT INTO "reviews" VALUES('640f1d3c9c3cf57aeaecada4',9289,9289,'额虽然但是她小组报告都打满了，但平时成绩才九十出头是什么回事',3,3,3,9,3,0);
INSERT INTO "reviews" VALUES('640f1c8ef11d5e1b033a231f',5301,2287,'老师上课内容清晰，知识面广，分析透彻，课堂气氛轻松活跃。教学中注重学生能力的培养，课程内容适当，对基础工程中的难点把握准确并且有独到透彻的理解。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640f1b2ef11d5e1b033a20e0',9297,837,'满分，均均必须满分！除了偶尔语速快会让人有点听不清楚没什么缺点！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640f1a629c3cf57aeaeca824',191,8780,'你好我好大家好同学给的分是三一一，怎么出来就是三四五了呀？😅 ',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('640f16a99c3cf57aeaeca1e4',5301,2287,'魏星老师是一个很好的老师，课都是能给过就给过，除非你真的不想过，完全不想学，点名也很少几乎没有。她是一位女老师，中气肯定没有男老师那么足，一连三堂课，她都是努力讲完的，换作任何一个老师，说讲三堂课不吃力都是骗人的。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('640f114ff11d5e1b033a0efa',736,551,'讲课条理清楚，声音流畅响亮。专业水平高。但会拖堂+点名。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('640f10099c3cf57aeaec952a',855,140,'平时分拉满，有对比才有差距，相比其他几个毛概老师真的神中神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640f0e649c3cf57aeaec9124',9302,551,'一个学期几乎都是别的老师代课，见不到几次，给分也不知道是不是他给的，给分还不错。讲课水平一般，说话有点含糊。但人还可以，比较温和。（原来是公司董事长，怪不得出差频繁。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('640f071a9c3cf57aeaec8466',428,4716,'刘老师上课板书十分详细，人非常好，总体来说跟她学数分真的很幸运！上课时的讲解比较细致，而且每章都有习题课，习题课会给一些其他题目（不来自于课本的），达到他山之石可以攻玉的效果。但是平时作业偏多，曾经在清明节3天假期布置了42道题目🤣。老师偶尔会讲的有点晕，不过绝大多数时间都是逻辑清晰的。还有一个小缺点是考试前不给划重点，当然如果用心揣摩刘老师考前的复习课的话，你会发现“金屋藏娇”哦。',5,4,5,14,4,0);
INSERT INTO "reviews" VALUES('640efd82f11d5e1b0339ec55',8738,737,'注意：上课不要讲课程内容，相比其他老师有系统分析设计，其占比高。 平时分低，划重点******，就是玩儿。期末考试全靠自己努力与平时上课无关。 大三上成绩最低的课程',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('640efc94f11d5e1b0339eb27',3038,228,'……说一些客观事实：
INSERT INTO "reviews" VALUES('640ef99ff11d5e1b0339e6d9',9289,9306,'yyds！老师很负责，一学期只需要做一次10人一组的汇报（可以混）得了100+，期末还会发文档划重点
INSERT INTO "reviews" VALUES('640eeb35f11d5e1b0339d168',95,95,'气死我了，我真的不理解，为什么他不我的实验报告弄丢要让我重新写啊，有病吧，急着要交根本来不及，劝大家选他的课作业备份，不然会想死。',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('640ee13bf11d5e1b0339c1e4',191,8780,'不知道因为什么心情不好，拉着学生不让走，一直追问为什么选课选她，把其他学生问的问题全部怪在某一个人头上😜还要一直问你为什么在意平时分😜沟通不好还会叫你大姐😜拉着学生在楼道吵架😜真的是个很厉害的老师😜',3,4,5,12,1,0);
INSERT INTO "reviews" VALUES('640eddeef11d5e1b0339bd10',198,179,'作业少 除非很多人没来一般不点名 平时分很高 很会捞人 上课回答问题有加分 期中线上考 考两天 讲得也很好 很温柔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640edceaf11d5e1b0339bb72',1596,1596,'老师巨水 平时分99.5 上课一般不管 不点名 讲课一般',4,4,3,11,2,1);
