INSERT INTO "reviews" VALUES('640eaa42f11d5e1b0339691a',1768,92,'我最爱的老师，呜呜呜呜，讲课讲的巨好，也很有亲和力，但是一般情况下平时分跟回答问题的情况挂钩，所以想要平时分高需要多回答几次问题。',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('640ea562f11d5e1b033962e6',888,779,'斯沃特神中神，讲课很好，教学认真负责，除了经常课前抽问坐牢和有小小的口音，其他都很好。平时分直接给满，期末分出来🐭🐭直接看湿了🥵',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('640e9f059c3cf57aeaebe357',2210,1156,'神好吧。除了有点口音，平时分拉满，还会给重点，考前辅导压题基本都中了。回答问题还给你加半期的分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640e89c69c3cf57aeaebc12b',9169,242,'一学期不点名，作业和期中考我怀疑她都不看，但期末给分水就完事了',2,2,4,8,1,0);
INSERT INTO "reviews" VALUES('640e874df11d5e1b03393470',2458,23,'讲课还行，给分很低事情很多,没重点不捞人',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('640e86f2f11d5e1b033933fe',9326,9326,'给分低，ppt差，讲课枯燥乏味，别的班都有重点和原题，他啥也不说，全是重点，考试也不捞人，平时分很低。照本宣科',1,1,1,3,0,0);
