INSERT INTO "reviews" VALUES('640e82e9f11d5e1b03392da2',9329,859,'在群里问问题基本都是秒回 跟老师说谢谢老师还会回不用谢（人尊的超好诶）分也给挺高 推荐',5,5,5,15,0,0);
