INSERT INTO "reviews" VALUES('640e775d9c3cf57aeaeba539',2210,1156,'卿铭老师除了上课有点口音之外 专业水平没得说 问他问题也会及时解答 在期中期末之前都会有考前辅导 会多上一节课 平时分出了半期全部拉满 什么绝世好老师',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('640e71e3f11d5e1b03391413',389,389,'😚平时给分高的嘞，讲的好的嘞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640e71d9f11d5e1b03391409',3038,228,'其实老师人挺好的，上课基本不点名，偶尔抽人回答问题，认真听课可以学到东西，想水的话也很容易，平时分一般般给了我88，就是出成绩稍微有点慢，小问题。',4,4,5,13,1,2);
INSERT INTO "reviews" VALUES('640e7162f11d5e1b03391348',2346,762,'讲课很好人很好，除了半期考试几乎都是满的，而且喜欢海底捞😚',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('640e70339c3cf57aeaeb9b38',246,228,'走吧走吧！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640e7000f11d5e1b03391152',1394,230,'好老师！',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('640e6febf11d5e1b03391121',1291,92,'老师，其实没有大家想象的这么差，我上学期学的他的课当时以为也很差，但是实际只要你认真完成作业去考试分很高的，说话有点口音，平时分40只，扣我2分。那些说不好的，十有八九都是没有做完作业的，不做完作业，他就给分很低。所以说也不是那么坑的人',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('640e6f3a9c3cf57aeaeb99dc',179,179,'有一说一，鹦鹉讲课确实不行。但他作业真的少，而且他的作业对半期期末都极具战略价值（懂不懂他不出卷，期末卷子最后一道大题是他画出来的书本课后题的含金量）。鹦鹉的半期卷子都是祖传万年不变的，还开卷。要是碰上他出期末，直接半期卷子占比80%以上。除了讲课不行（模电确实难懂，建议看看网课吧。我胶模电考的不难）******一学期就点一两次名，每章作业就留两三道题，平时分拉满（38.5/40）。爆赞好吧',5,3,5,13,6,0);
INSERT INTO "reviews" VALUES('640e6b9f9c3cf57aeaeb9441',3038,228,'平时分一般，不爱点名，上课可能会抽人回答问题，出成绩出免单名单特别特别特别慢..第一次见到拖延症这么严重的老师',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('640e68eff11d5e1b03390760',3038,228,'特意注册账号来的呵呵，什么玩意大家赶紧跑吧，平时分低的要死学时这是生怕我过了是吧。拖着拖着到教务要关了最后一天了才出成绩，之前拖着拖着不出免考，考前一天才出还要去口试背书，倒了八辈子血霉😅',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640e6336f11d5e1b0338ff3e',3038,228,'平时分超低，免考都给不了90，不免考的平时分90都不到，小组作业给组员的分还不同，出分还巨慢，真的是我见过最差的思政课老师了，比四大天王还离谱',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640e1577f11d5e1b0338bb5e',250,561,'上课就是******，一节课90%扯皮，10%快速放PPT，不过期末捞了一把很是感激',3,3,2,8,1,2);
INSERT INTO "reviews" VALUES('640e1464f11d5e1b0338ba8b',1169,1169,'我男神！平时分全部拉满！讲的也好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640e09f2f11d5e1b0338aff3',9346,9346,'选到即赚到，不仅捞你还给你高分，讲课还有趣，真的顶',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640e07499c3cf57aeaeb3318',3038,228,'没遇到过这么无语的老师，可能是给的免考最低的老师吧（免考都这么低可以想象平时分有多低），成绩拖到系统快关闭了才出，言而无信，所谓的马原四大天王班上免考都有90，这个老师免考分很低，平时事儿一点都不少',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640e01a49c3cf57aeaeb2d50',703,228,'真的好无语 很自己同学一起上的马克思 平时简答题是互抄 小组作业一起做 结果人家平时成绩90我78 考出来直接拖了平均分2分 真的好无语',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('640df8aef11d5e1b03389a97',9169,242,'想得高分就来，总评全班都九十多，我爱肖老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640def8bf11d5e1b033888a3',42,42,'这些数电实验老师******人才啊，做完都说好30分了，给了老子27分，这就算了，我去私聊问你问题，你说在群里问，好我在群里问，一开始还回复我，后面问问题都不带搭理的是吧。******在我遇到数电实验老师之前我以为老师只有严格与不严格，在我遇到这群老师之后，我才知道什么是混子，真******混啊。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640def38f11d5e1b03388808',9351,5,'神中神，每周有地点答疑，线上问问题回答的很快，问题问的在简单也不会生气',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640dde7ef11d5e1b033869d7',693,693,'想从他课上学到东西就别想了，电力系统分析这门课只有两个老师是教的好的，一个是张雪霞老师，一个是马庆安老师，剩下的老师都一个样。这老师逼事挺多，每周都反转课堂，不过你不点名，随便翘，你只要把你要做的反转课堂做好，平时表现就给满了。我是去隔壁张老师班上旁听了一学期，作业、实验有认真写，所以平时成绩还行，给了96分，算挺高的了，这门课平时成绩都不会特别高。总的来说就是能润就润，不能润也别太慌，去别的班听就完事了',2,1,3,6,1,0);
INSERT INTO "reviews" VALUES('640dde2ef11d5e1b033868f2',2324,81,'给分巨低，课也讲的不好，说话听都听不清，期末也不会给重点，群里问问题也不会回达，直能说快跑。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640dc50df11d5e1b03382d05',703,228,'******50分的平时分给我们组34,37,38，正常写期末挂不了但是纯纯恶心人，邵春波遇到他真的倒了大霉******',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640dbdeff11d5e1b03381ff7',693,693,'喜欢不给过程分是吧
INSERT INTO "reviews" VALUES('640db022f11d5e1b03380aae',4842,6401,'*****张之勇，什么样的**才会在大四的时候挂学生一学分的水课选修！而且直接给教务备注取消考试资格，就明摆着叫学生延毕呗，这个**老师显然很享受玩弄学生前途，希望你自己的小孩也有一个完美顺利的一生！',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('640daadf9c3cf57aeaea8653',1065,1065,'期末36就能过，结果24',1,1,1,3,0,13);
INSERT INTO "reviews" VALUES('640da81f9c3cf57aeaea8282',4842,6401,'很厉害的老师，很擅长把学生玩弄于股掌之间，西南交大党委书记王顺洪同志曾这样评价他：“对于老师，西南交大从不养闲人，除了之勇。”',1,1,1,3,14,0);
