INSERT INTO "reviews" VALUES('640d98b79c3cf57aeaea6c56',250,561,'老师很有能力，教的也很好，大家可以选他，认真负责，也会安排时间答疑，但是他大概率会说一一顿或者嘲讽你一下。口音比较怪，但是可以听懂，按要求完成作业分也会很高的。',5,5,3,13,1,6);
