INSERT INTO "reviews" VALUES('640d6b0df11d5e1b0337a205',4784,2259,'不点名，平时分高。我不是计算机专业的，选了他的课之后没去过，从不点名，平时分基本拉满。不知道教得怎么样，反正我是自学的，半期期末都是满分。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('640d6a019c3cf57aeaea2608',4842,9241,'大四上学期11周交的大作业，第三次选课快结束了登分。然后告诉一批人你们0分还不让补考。这不是报复社会我想不出来其他理由。一下子延毕十几个的掌控感可给他爽死了',1,1,1,3,10,0);
INSERT INTO "reviews" VALUES('640d69e49c3cf57aeaea25c6',4842,9241,'我是真的没想到大四下能挂1分的限选课，而且是直接取消考试资格，直接弄死了。作业拷贝得太明显了',5,5,1,11,7,0);
INSERT INTO "reviews" VALUES('640d42ccf11d5e1b033768d6',9329,859,'平时分蛮高的，只扣一两分。上课也不严格，可以划水。平时作业很少，只有一次开卷半期考试，半期也很水。期末会划重点，强烈推荐！',5,5,5,15,1,0);
