INSERT INTO "reviews" VALUES('640c25d19c3cf57aeae8713c',409,1622,'2023年了还有人上课训狗是吧  喜欢搞效果为什么不去幼儿园上课   大可以把右手的卡地亚换到左手再把左手的破镯子拽了 也省的架着胳膊晃来晃去  整个教室里被一种莫名其妙的恶臭优越感笼罩 被收手机的同学不知道什么心情',3,1,1,5,6,0);
INSERT INTO "reviews" VALUES('640c244ef11d5e1b0335e7b0',9384,9384,'上课水，大部分时间用来吹牛，给分低。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('640c22659c3cf57aeae86bf2',409,1622,'******架子巨大，巨会整事，攻击性一流，上辈子可能是把喷子。给分要求多，按要求做了也凭心情给分。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('640c1fc79c3cf57aeae868b1',932,932,'好老师！ 讲的好而且脾气性格也很好 下课练习题虽然恐怖，但是很帮助理解掌握知识',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640c1f529c3cf57aeae8680c',480,92,'老师很好 很喜欢这种教学风格',5,5,5,15,1,0);
