INSERT INTO "reviews" VALUES('640c08439c3cf57aeae847c2',9390,9390,'讲课一般，事情又多，平时作业题和考试没关系，重点也不划，对比其他老师期末重点就是******，上课全去，作业都交，平时分给70。谁选谁后悔',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('640c07e19c3cf57aeae8473b',373,619,'老实人，大好人，专业水平高，平时分拉满',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640c07acf11d5e1b0335bfd4',13,13,'选修，元宇宙概论，别选，纯**,上课不让做作业，******每次都有课后作业，闭卷考试，平时分巨低，七十多。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('640c070ff11d5e1b0335bed2',409,1622,'老师很会活跃课堂气氛，上课让全班同学一起站起来听课，就为了让同学们不打瞌睡，好好学习。上课中英结合，在中文中时而穿插几句英文，提升同学们的英语听力水平，提高同学们的单词积累，简直好的不得了了呢。😓😓😓😓',1,1,1,3,17,0);
INSERT INTO "reviews" VALUES('640c0533f11d5e1b0335bc8d',2484,92,'超爱女神',5,5,5,15,0,0);
