INSERT INTO "reviews" VALUES('640b35b99c3cf57aeae73ff4',604,5,'教的特别特别特别好，讲题细致，写板书，平时分给的很高，很负责任很有耐心的老师！就是有一点口音喔，听着听着就习惯了！',5,5,5,15,1,3);
