INSERT INTO "reviews" VALUES('640b34f39c3cf57aeae73ed2',3964,80,'这个老师比较水，烟瘾比较大，每节课下课都要抽烟。给分其实中规中矩，半期考试和课设会适当扣点分，但也算情理之中，毕竟看到好多老师只给70多平时分。学渣还是建议选更水一点的老师（平时分基本给满那种），毕竟这课还是有难度',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('640b265cf11d5e1b03349c14',9424,910,'脾气特别好，上课也不咋点名，旷了几节课，平时分也嘎嘎高，上课睡大觉，美滋滋',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640b2603f11d5e1b03349ae6',35,106,'爱点名，但是不为难学生，期末好搞，分数高，可以冲',5,5,5,15,1,0);
