INSERT INTO "reviews" VALUES('640b249af11d5e1b03349872',9351,5,'小老头可可爱爱，讲课清清楚楚，期末给分松松，吸溜吸溜爱死爱死',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640b2407f11d5e1b033497ad',2197,876,'这老师，我爱死，平时分巨高，不点名，纯纯海底捞，无敌和蔼，冲冲冲冲冲，作业也不多，考试前还画重点，寒假还给给学生复习计划，他真的我哭死',5,5,5,15,1,0);
