INSERT INTO "reviews" VALUES('640b175bf11d5e1b03348431',751,1652,'最让人难以忍受的是平时成绩给分过于主观随意，上课声音小照本宣科念ppt，期末答疑化身谜语人，客观评价。另外，这门课的另一个老师平时分是全部拉满的。',2,2,1,5,18,2);
