INSERT INTO "reviews" VALUES('640ae86af11d5e1b03343c98',260,96,'签字签到（但会提前提醒有签到）。随堂测只看态度。平时分态度没问题除了半期直接拉满。会评讲作业会考前复习，考点讲解清晰，上课的规矩要求都传达得很及时清楚，会黑板板书。挺好一老师，至于阴阳怪气，主要是针对一点不学的吧……',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640ae5f19c3cf57aeae6c3f7',4482,157,'非常非常糟糕，给分很低，不捞人，会点名，对学生态度恶劣。会以不明理由攻击辱骂学生，态度极其极其恶劣。',1,1,1,3,5,0);
