INSERT INTO "reviews" VALUES('640990fdf11d5e1b03325d9c',2005,1170,'绝了，遇到赶紧跑，平时分巨低，而且不给好好给分，随便给个低分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('640990eaf11d5e1b03325d89',2005,1170,'******一个班平时分都七十多 什么玩意 平时交作业从不检查 你怎么评的作业分 一个破化学 有什么好压分的 上课提问更6 不会就扣你分 教的什么玩意 期中还自己出试卷 出的死难还排位做 期末一个班就一两个上八十的******看看别的班的 基本都九十多 没几个上八十的66666',1,1,1,3,2,2);
INSERT INTO "reviews" VALUES('640984479c3cf57aeae4d874',785,114,'老师很负责，回答问题很耐心，平时分能给满的都基本给满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6409822c12cdee268e74d26d',616,616,'才上几周可能会觉得他有点水，但是是真的负责，简单的东西会抽人一直给你讲懂，考试放水，有分他是真给，几乎不挂人，做实验也不会折磨你，轻松就验过了，不论是想水还是想好好学的都是非常nice',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6409771612cdee268e74bfb3',4407,4407,'虽然有点口音，跟他沟通也有点困难，但韩森老师真的很好！平时问他问题都很耐心，看我们期中考太差了就把期末改成了开卷，并且期末一半的题都是模拟考原题！就是作业太多了，不过跟他反映后也减少了一点',4,4,5,13,0,0);
