INSERT INTO "reviews" VALUES('640975fa12cdee268e74be07',3755,3888,'上的混凝土******平时事巨多，课程设计直接不及格，课程直接挂掉。。。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('6409736d12cdee268e74ba2e',2646,2960,'平时分拉满全班都满分，教课认真。人也很好很耐心。上课前还会给我们放小猪佩奇，不可多得的好老师。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('64096abad8e01c412d63a703',80,80,'平时上课笑眯眯的，清华博士，一直推崇混凝土这门课太简单了，上课不点名，和同学们打成一片，没想到期末直接笑面虎，考完试直接解散群不给人再找他的机会。平时分巨低！！！平时次次作业按时交上，给我打90，课设也低，半期考试设置一堆题就是让人答不完，然后占比还很大。期末考的分明明能过结果就是因为平时分低。不想上课脑子好的可以选他，其他人劝退！！！！',1,1,4,6,2,0);
INSERT INTO "reviews" VALUES('6409621912cdee268e74a086',89,33,'老师人好，上课可睡觉，会扯其他的。给分可以',5,5,5,15,1,0);
