INSERT INTO "reviews" VALUES('6409520412cdee268e74879c',9122,9122,'真的差得离谱，上课讲得不知所云，完全听不懂也让人根本不想听，水是水了但是给分很低，课外什么都不会讲，也不会捞',1,1,1,3,0,0);
