INSERT INTO "reviews" VALUES('64093a10d8e01c412d635b60',1955,194,'左老师讲课虽然比较快，但是上课并不严厉，平时分甚至直接能给你拉满（我期中没及格，期末硬生生到了80）',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('64093120d8e01c412d634e82',5064,40,'这个老师给分确实不高，但是事也不多',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('64092fd5d8e01c412d634d1d',706,706,'老师上课内容很有趣，讲许多课外的内容，平时总共就做了2次作业，1次期中测试，期中是开卷很水，平时分占比本身也不高。老师期末会根据题来划重点，划的范围不算很大，全记住了考试就没问题，不考的会叫你不用看。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('64092e0912cdee268e744eb5',563,228,'还好，没那么夸张，手写作业偏多，但给分还行，而且感觉老师人还不错',5,5,5,15,1,7);
INSERT INTO "reviews" VALUES('64092e0312cdee268e744eb2',9297,884,'上的均均的运筹学和交通运输统计，老师上课很有趣，经常和你聊课外的东西，上课氛围很轻松。统计一学期就完成一次汇报，平时分拉满，其他没有任何作业。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64092cebd8e01c412d634996',12,4,'专业能力强，是学生的好兄弟，上课运动量不少，幽默风趣，非常适合喜欢足球的同志。上课不水课，有事不想去的话给他说一声就会很容易的通过。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64092bfbd8e01c412d634861',2983,294,'平时作业挺多，要做PPT，录制视频，期末平时分给的不高，但是可以稳过，每节课照点名表点名。',3,3,3,9,0,2);
INSERT INTO "reviews" VALUES('64092b4312cdee268e744b29',535,535,'讲课什么的没有吸引力，但是期末是能捞尽捞，期末平时分给的不错，就算被发现没去，平时分也还可以。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('64092a5012cdee268e744a01',563,228,'上课挺烦的，但是逃课被发现期末平时分也给的挺多，稳过',4,3,3,10,0,1);
INSERT INTO "reviews" VALUES('64092657d8e01c412d634099',3921,2598,'******老师，每节课都去作业都认真完成次次不落，平时分88分，别的班都是95+。******老师一个，别选',2,2,2,6,2,1);
INSERT INTO "reviews" VALUES('64091ad612cdee268e74369d',42,43,'惹啊，龙哥就是龙',1,1,1,3,4,0);
