INSERT INTO "reviews" VALUES('6408c2c212cdee268e73e6ee',442,442,'平时上课几乎全坐在多媒体前，自己对着电脑自言自语，然后讲题就让人看鼠标光标，（我******能这样学懂，我还交444块钱来让你挂我是吧），平时疯狂点名，全勤和缺席平时分还倒着给，（我真的笑），讲课疯狂提“我期末是要挂人的”等等这种挂科洗脑语，讲不清楚作业还多，别说期末捞你了，生怕补考挂不了你！！狠狠重修还要阴阳你“重修的时候加把劲”，这种人我真的不想为他再多码一个字',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('6408ba1912cdee268e73dd80',2424,2178,'赵老师真的不用多说，选到你必赚到',5,5,5,15,1,0);
