INSERT INTO "reviews" VALUES('6407fb7ad8e01c412d61a741',452,452,'讲课方式比较像国外的那些老教授，个人还是很喜欢她这种能够讲清楚原理和启发研究的教学方式的。作业比较多，给分不算特别高，平时分90左右吧。',5,4,4,13,3,0);
INSERT INTO "reviews" VALUES('6407fa2812cdee268e72a232',334,175,'平时分给得挺低，但是老师非常认真负责。',3,2,3,8,1,1);
INSERT INTO "reviews" VALUES('6407fa2512cdee268e72a231',604,96,'老师人好，教学认真，作业能补交，平时分除了期中考试全部拉满，考前还会发复习题，认真做了期末完全不用担心，而且老师还很可爱',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6407f86912cdee268e729fa3',1169,1169,'崔帅，平时分直接拉满，救我狗命',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6407f400d8e01c412d6198ed',4784,641,'课讲的不咋地，但给分巨高',4,4,5,13,0,1);
INSERT INTO "reviews" VALUES('6407f06bd8e01c412d61937e',7,7,'胡军老师yyds，很难的内容也能给你讲得很清楚 来，认真听他的课基本都能学会，平时分还给的很高，期末一个班也只有一两个人挂科，简直是我男神！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6407ec6b12cdee268e728c46',9122,9122,'0分 直接重修 ',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6407ec54d8e01c412d618bbc',247,27,'不是，上个英语老惦记着你那b听写和海报干什么玩意？上课真全程念ppt，点人回答一些莫名其妙的问题，有些言论真的太逆天了让我感觉不像演的。
