INSERT INTO "reviews" VALUES('6407eb5712cdee268e728a92',2116,185,'老师上课不允许玩手机，讲的很好不论是专业知识还是人生经历，平时会有每章的小测验，基本上是ppt原题，跟着老师拿高分绝对没问题',5,5,5,15,3,0);
