INSERT INTO "reviews" VALUES('6407eadbd8e01c412d618976',4626,1087,'一般我只点评特别好和特别烂的老师，这个老师无可挑剔，人还特别帅，讲得好还很负责，平时分还是满分',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('6407eabed8e01c412d61895f',467,22,'老师人挺好的，也有耐心',5,5,5,15,0,0);
