INSERT INTO "reviews" VALUES('6407e475d8e01c412d618007',8138,8138,'话都讲不明白，如果没有听过川普，根本听不懂讲的什么给分巨低，平时分55只给40',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6407e2ee12cdee268e727de5',5064,40,'只能说看活水前和上完课之后不是同一个人:(   如果有下次不会再选',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('6407e14712cdee268e727b95',9122,9122,'''纯**，上课讲个表面，啥也不管，纯纯的牛魔水课，考试跟讲的天差地别，全看个人能力，而且考试大题不看过程只看结果，没有步骤分，错了直接零分。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6407e0d612cdee268e727b01',1537,1651,'期末机考是三个老师里面最难的..好像这学期只有她有半期考试..可能是我自己菜吧我的平时成绩一般（没有传说那么高）',5,5,3,13,4,0);
INSERT INTO "reviews" VALUES('6407e0d212cdee268e727afe',6363,80,'******避雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6407df29d8e01c412d6178fa',1537,1651,'工程制图与画法几何，总分90+。老师人真的很好，专业水平很高，治学严谨，就是有点话唠，不过感觉很亲和。平时只要跟着老师的节奏走，作业认真做，平时成绩和期末都不会差的。而且每周会固定时间地点给同学们答疑解惑，非常负责。老师也很喜欢上课氛围活跃的班级。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('6407d44412cdee268e72697c',989,989,'不捞人，平时分巨低，期末考前发了两套“复习题”结果******完美避开考点😅别的老师要么发考纲要么提醒考点，就他******，真的难蚌',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('6407bf2012cdee268e725113',560,3214,'教的好，给分多',5,5,5,15,0,0);
