INSERT INTO "reviews" VALUES('640762add8e01c412d60fa46',85,597,'飞盘贼好玩，老师嘎嘎好，给分也高
INSERT INTO "reviews" VALUES('64076160d8e01c412d60f831',9122,9122,'工程力学d，上课很水，但是要把作业和系统的实验报告做好，平时分就基本上满分了，老师确实不是很负责任，但是混还是很好混的',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('64076099d8e01c412d60f5fb',1,1351,'讲课挺负责的 但是讲得不怎么样 作业很多很复杂 作业要求高 给分也很低',2,2,4,8,0,0);
INSERT INTO "reviews" VALUES('6406936112cdee268e7090b8',8566,114,'田老师一直是我的心头好，非常适合做笔记的同学，而且课上例题非常丰富，实话讲虽然她认真得看起来有些严格，但不妨碍你能在他的课程中获得高分，作为副教授能把高数的板书写满满几块黑板，擦了又擦，真的很卖力气在传授知识，永远感谢她...',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('6406934912cdee268e709095',767,694,'和黄代绘老师一样好，完美',5,5,5,15,0,0);
