INSERT INTO "reviews" VALUES('64068f24d8e01c412d5f9b11',351,351,'平时分都拉满了你还想咋样？',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('64068ea5d8e01c412d5f9a40',452,2671,'什么******老师，给分水平不行，阴阳怪气倒是有一手😅',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64068da212cdee268e708822',9122,9122,'上课没几节，讲的没有重点，不会捞人，平时分不高的话就等着挂科吧！',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('64068af912cdee268e7083d5',499,194,'神中神，我大一的美好回忆',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6406844c12cdee268e70796f',9122,9122,'你来劝你润，我润你别劝。除了课上讲课。在课下不会回答你的包括请假，作业系统故障，考试题型等各种问题。',4,1,1,6,0,0);
INSERT INTO "reviews" VALUES('6406206112cdee268e701bde',188,188,'虽然老师开学的时候说回答问题会有加分，但是没回答过平时分也几乎给满了，老师也很和蔼，冲冲冲',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('6406205812cdee268e701bd8',1441,228,'郑老师上课很棒，很有思想性，为人处世通透豁达，很多她的教导至今被我奉为箴言，狠狠推荐选课!至于免考也比较容易，郑老师免考的同学一直很多!建议选上的同学好好听郑老师的课，会有很多收获，对未来做事很有帮助!',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('640619fa12cdee268e701533',9569,9569,'老师人很好 教的认真 也很体谅学生 给分也好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640617bc12cdee268e70129d',246,228,'老师上课喜欢东扯西扯，很少讲与考试有关的东西，还很喜欢抽人回答问题，不单是如此，他先会问你他问的问题是什么，然后让你回答，平时上课是不会让你写其他科的实验报告的，至于期中考试，那可是老师自己搞的没有答案的题，平时分能拿到总评的40分你大概可能就是祖上三代都是红军吧，老师还特别喜欢讽刺人，就很喜欢用自己的专业知识来和别人比较，尤其是布置课后作业的时候真的是千奇百怪，交个作业还要按规矩放在安排的地方，放错地方（就是不是指定学号的那个位置）就直接没有分了，至于平时成绩的细分他不会让你知道你各项的成绩的，期末考试老师也不会捞你的，这老师就是不会让你轻松过这一门课程 。',1,2,1,4,4,0);
INSERT INTO "reviews" VALUES('6406169612cdee268e701153',2211,1241,'快跑',1,4,4,9,0,0);
INSERT INTO "reviews" VALUES('640613fed8e01c412d5f1e5b',803,1135,'上课很温柔 问问题会及时回复 如果不明白还会开腾讯会议给你讲题 不可多得的好老师 平时成绩除了实验和慕课都是很好拉满的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64061357d8e01c412d5f1da2',1350,5405,'我女神',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6406127312cdee268e700cc9',246,228,'好评好评，希望大家看到都选他的课，这样大家认认真真一学期平时分都可以只得三十几分，比别的班平均分低十几分哟，还可以上课一直被揪着回答问题哟，期中考试也是看不懂的他自己出的题哦，因为我淋了雨所以我要撕烂大家的伞🥹，想挂的同学快冲他的课😊',5,5,5,15,3,12);
INSERT INTO "reviews" VALUES('6405cd6812cdee268e6f95ec',9450,1702,'我是钢结构来的，老师非常和蔼',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6405c229d8e01c412d5e93f3',18,18,'冲就完了。平时有试卷评讲，期末前还有复习课。上课幽默风趣，通俗易懂，很难不爱。',5,5,5,15,0,0);
