INSERT INTO "reviews" VALUES('6405b17412cdee268e6f6f02',175,175,'平时分拉满，作业就交过三四次，还不画大图，不学cad，不过其他得靠自学了，毕竟这门课老师作用不太大',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('6405ae2c12cdee268e6f69bb',334,242,'老师平时分基本没有，给的很低，上课自己讲自己的不跟同学互动，群里问消息也不太理你 ，自己优选两个班加起来的人数和别的老师一个班的人数一样多，都跑完了，大家自己体会吧',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6405ae1212cdee268e6f697d',36,36,'😅😅😅上了两节课，上课疯狂点人问你怎么看你怎么看，自己讲课也是照着ppt念，感觉讲不出什么花来，自己讲不下去就抽人讲，第二次选课必润',1,1,2,4,4,0);
INSERT INTO "reviews" VALUES('6405aba1d8e01c412d5e74d5',9583,131,'硬是把专业课上成了水课，案例很土，不怎么教，学不到东西，上课经常跑出去聊天',1,1,3,5,0,0);
