INSERT INTO "reviews" VALUES('6405a45b12cdee268e6f598c',3065,140,'我的评价是继刘丽娜之后的又一位，有一说一，这老师从来不点名，除了该自己课程报告那一周之外都可以不来，反正最后平时分都是80多分随便给，来不来都一样。不点名是真的，平时分低也是真的。不想考试周还得背毛概就快run！快跑！快逃！',1,1,1,3,4,0);
