INSERT INTO "reviews" VALUES('64057fe712cdee268e6f2304',351,351,'神中神',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('64057eced8e01c412d5e33f3',1441,228,'思维敏锐，讲课思路清晰，但是语速很快（估计也有课时不够的原因），不怎么容易跟上。有一次作业，因为涉及到期末考试可能出的材料题。有一个半期考试，一节课两个材料题写在纸上交上去。很少点名，会回答同学的问题，好像坐第一排被她注意到比较容易免考（据我观察）。给分应该也挺不错的，给的任务完成了，平时不回答问题估计就有40了（没对比其他班的不知道算不算高）。',5,4,4,13,2,0);
