INSERT INTO "reviews" VALUES('6405613312cdee268e6ef6d4',334,562,'老师挺好的真的，就是平时有点冷漠，作业不多，甚至会不改，群里问问题有时候也不理，平时考试不会通知，期末考试要求不会通知，但是平时分倒不低，在教室里问问题会很耐心地回答你。',4,3,2,9,0,0);
