INSERT INTO "reviews" VALUES('6405495ed8e01c412d5de076',716,716,'李松老师真的巨好，平时分除了一个平时作业其它都拉满了，CAD考试也很简单，上课也很水，和蔼可亲（PS感觉他的皮肤真的巨好哈哈哈哈）好喜欢他。',5,5,5,15,0,0);
