INSERT INTO "reviews" VALUES('6404d031d8e01c412d5d6377',9621,9621,'不知道是不是这个老师 现在的市场调研有这门课 反正就是平常会有周作业 拿出十几分钟认真做 头期末会有一次大作业 都是比较简单的  90+不成问题',3,2,3,8,0,0);
