INSERT INTO "reviews" VALUES('6404b32b12cdee268e6e2c2f',18,18,'上大学以来自我感觉赵老师是上课思路最清晰的，只要跟着老师节奏都能听得懂，而且老师还很幽默，给同学答疑也很认真。总之，老师专业能力和表达能力都很好，选到就是福气！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6404b14b12cdee268e6e29a8',18,18,'平时作业全是期末考试题，没见过这么好的老师！！！！而且给你答疑，直接给你发Qq语音给你答疑，平时分给的又高，上课讲课清晰明白😭😭😭😭没见过这么好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6404a4efd8e01c412d5d244d',373,619,'老师上课不会管你干什么，平时分基本拉满，平时会要求在智慧树上做选择题，但是会发答案自己对，期末直接按照里面的选择题复习，非常方便，强烈推荐！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6404a34dd8e01c412d5d2213',3448,9626,'认真负责，但分数不高',4,3,2,9,0,0);
