INSERT INTO "reviews" VALUES('640499d912cdee268e6df367',2005,1170,'懂得都懂，遇到最好的化学老师，期末绝对不挂科',5,5,5,15,1,8);
INSERT INTO "reviews" VALUES('6404992dd8e01c412d5d010c',788,788,'给分巨低',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('640461c112cdee268e6da179',751,573,'典型刀子嘴豆腐心😭师老师是真好人😭平时分满的，虽然开学说什么不让带ipad但是他看到了也没说啥😭他真的我哭死，从不点名，期中就是唯一的签到，期末最后一节课还能把期中分拉满😭',5,5,5,15,1,9);
INSERT INTO "reviews" VALUES('640460c412cdee268e6da033',984,850,'王老师好人，讲课挺好的，该讲的都讲了，坐前排一学期，她居然过一个暑假还认得我😭就是期末没有重点得蹭蹭其他班同学的，作业记得拍答案，期中考是开卷，作业贼多，就是把课后的作业全写了，不过每次分学号奇偶评分（都得交），就是可以隔一次认真写（不是）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64045fa9d8e01c412d5cae1d',9632,2001,'上的高电压，讲课很水，准点下课，一学期点名三次，考试的时候会捞捞（咳咳）作业真挺多的，这个是课程问题，普遍多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64045f1c12cdee268e6d9e15',1074,1074,'问刘老师题的时候她很耐心，也能听得懂，讲课也挺好的，ppt汇报有加分，狠狠学',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64044f2112cdee268e6d8812',7,7,'胡军老师真的很好，事情不多，ppt简练，能拉满的分都会给拉满的，放心冲就好。',5,5,5,15,0,0);
