INSERT INTO "reviews" VALUES('6404121ed8e01c412d5c377b',1033,736,'非常具有教育意义的课程，老师讲课风趣幽默，作业量小且与考试内容十分契合，期末范围非常具体，抢到就是赚到！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640411d4d8e01c412d5c372c',372,5,'我好爱余老师，呜呜呜 ，课上的超级好，作业也少，板书很棒 ，回答问题很耐心，平时分直接给满，期末扣分也少，呜呜呜，最后期末98美美结课，快乐！',5,5,5,15,2,0);
