INSERT INTO "reviews" VALUES('6403653812cdee268e6c5e18',2197,876,'挺好一老师。和善，为学生考虑，亲切。会评讲作业，讲课也比较仔细。给分除了半期全拉满，半期非常松，学习通上做。课前学习通签到，讲课的时候爱放一些有意思的科学实验视频帮助理解，没有口音，音色还有点好听。很可爱的一件事是：在群里哭诉尝试自动导入平时成绩结果出错了，自己一个一个手动去改。',5,5,5,15,0,1);
