INSERT INTO "reviews" VALUES('6403431012cdee268e6c109c',1853,670,'快逃。刚刚考完试来评价。老师上课事情贼多，前半学期一直拖着，搞小组作业分享。快要结课了才赶进度。占比不大的前三章内容讲半个多学期，最重要的编程芯片中断部分几节课略过。教学抓不住重点分不清主次。期末考试隔壁班重点画到飞起，她缄口不言，群里问她也不回。。。毫无教师责任感和对学生的关心。真的快逃吧。。申请补考了。',1,1,1,3,7,0);
