INSERT INTO "reviews" VALUES('6401fe2c12cdee268e6a7140',975,975,'布置作业非要作业系统，系统无法识别导致作者扣分，期中考试一节课，作业做不完，服了，群里面消息也不回，避雷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6401fb1d12cdee268e6a5b92',9696,1904,'节节课口头点名，几乎无互动，上课听不懂，作业一大堆，平时分不高，也不捞人，甚至让我觉得他期末改错分了。。。。。。不说了，Bu考去了。。。。。。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('6401ee0ed8e01c412d59644d',975,975,'快跑，纯牛马。上课蚊子大小的声音和肾虚了一样，这我都不说，这属于个人没法改变的身体情况。可对于教学是个什么态度呢？上课用的copy的PPT，一个接触不良问题或者网络不良能连着三四节课打水漂；作业用的学生系统，bug一堆，动不动就卡死报废，这就算了，问题是找他是永远找不到人的，发消息不回，有事发邮箱--也不回，你手写拍照发过去，恭喜你期末那部分他一样忘掉给你算分；期末别的班出完五天他开始登成绩。当他的助教也是煎熬，有事你去找老师我不晓得，老师也不知道在哪--那你自己想办法咯。真的倒了八辈子血霉我直接五星好评。',1,1,1,3,1,0);
