INSERT INTO "reviews" VALUES('6401dd0b12cdee268e6a2ba5',903,179,'康老师真的很好，讲课细致，答疑耐心，那个说老师nt的，估计自己也挺nt的，没有好好复习，ta已经在群里面被骂了哦，而且ta还不敢在群里面实名吐槽，懂得都懂',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6401db34d8e01c412d594542',903,179,'选就完事了，这老师真好，课后答疑，作业，讲课都好，还海底捞！',5,5,5,15,1,0);
