INSERT INTO "reviews" VALUES('6401b2bc12cdee268e69ed91',6323,23,'挺和蔼可亲，仁慈的老头。写作业遇到问题问他，他都及时回复。给分仁慈，期末直接给过，也不为难你。能捞则捞，一次通过。都快选陈老师的课！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6401a615d8e01c412d58f666',1191,1191,'没重点，平时分不高，期末背不完，压分',4,2,2,8,0,2);
INSERT INTO "reviews" VALUES('6401a5aad8e01c412d58f5c0',869,3704,'卢耀辉真的******，上课天天让他的博士生讲，******压分严重，作业抄都抄不完，事多，屁话多，平时分很低，上课呆板，枯燥无味，节节课点名，赶紧跑，以后千万读研究生别选他，快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('64019fd3d8e01c412d58ed2b',6323,9062,'老师人和蔼，问问题会耐心解答，但是上课上得很烂，只会读PPT，并且上课每句话钱都要加上“额  ”，作为一个四川人我都听着难受，每节课都要用雨课堂扫描二维码，平时分给的很死板，期末不会划重点也不会捞人，期中考试的时候全班96人及格25人，我们班25人及格4人，刚刚成绩出了，好歹过了，但是不过率依旧很高，想学知识的建议从一开始就自学',1,2,5,8,0,0);
INSERT INTO "reviews" VALUES('64019d00d8e01c412d58e73d',869,3704,'说不上多******，只不过能过',2,2,4,8,0,0);
INSERT INTO "reviews" VALUES('640194cad8e01c412d58daa1',4306,517,'洪老师太好了！强烈推荐',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('64019481d8e01c412d58da46',903,179,'上的是把电分和模电压缩到一个学期三学分的速成课。老师很有亲和力，专业水平不用怀疑，期末前专门给大家划了重点，也会捞人（平时成绩有适当打高）。但语速很快，对上课容易犯困的我非常折磨，每节课都在试图跟上她的思路（失败）。跟楼下说的一样，上课讲的很细致，知识拆解得很懂，但是！！！上这门课她基本不按ppt讲，按自己的来，经常重复的话就是“我们不看ppt上面这个”然后开始用自己的方式写，要复盘她讲的内容非常痛苦（拍了无数张图片和疯狂记笔记）。嗯，确实适合上课不犯困学习能力超强的同学来选。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('640190c5d8e01c412d58cfd1',6319,194,'板书工整，讲的也超棒。',5,5,5,15,1,0);
