INSERT INTO "reviews" VALUES('64018bc9d8e01c412d58c85b',2447,23,'只要是好好做平时实验基本上都是快满分，李老师真的教得很好给分也很高，我的超人！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64018a6e12cdee268e69aba2',2447,23,'我的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('640182ef12cdee268e69a16c',210,28,'老师很亲和（让我想起我的高中老师）上课氛围很轻松，回答问题也不会难为同学，只是网络作业有点多，而且平时分略低（好像大部分英语老师都这样）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6401824712cdee268e69a071',877,2798,'真的很好！讲得蛮清楚的，大家坐前排认真听的话应该都能听懂，节奏有点快要很专心，课后也会回答我们的问题（还会手写解题过程）她真的，我哭死',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6401666012cdee268e697723',1865,708,'上的电力系统分析A。这课吧，除了张雪霞讲的都烂，PPT也稀烂，作业都没答案，屁事也多。童老师能给贼高的平时分我已经很感谢他了',3,3,5,11,4,0);
INSERT INTO "reviews" VALUES('640161d9d8e01c412d588bb2',6510,2015,'不多说，神中神，纯纯姐yyds🥰🥰🥰',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('64015ec3d8e01c412d58872a',2211,1241,'就一句话，90多的期末，70多分的平时分',1,1,5,7,2,0);
INSERT INTO "reviews" VALUES('64015e6d12cdee268e696c22',2211,1241,'老师很好，就算你分是够的，也会给你拉到60捏，肯定会捞你的捏😍😍😍
INSERT INTO "reviews" VALUES('64015da4d8e01c412d588581',2211,1241,'刚开始看资料，本科华科，硕博耶鲁，还以为捡到宝了，结果上课就是照着ppt念，没有一次板书基本上，一门理工科的老师没有板书，ppt不仅是照着念而且点都点不迎，基本上全靠自学，作业量还极其的多，提交时间也是******，逼着你写作业，助教更是******，平时作业的开放性题目跟答案只有不一样就给你判0，说要答疑结果就是进腾讯会议统计题目，统计完以后，答疑后面也是不了了之。总而言之，就是别选，快跑🤗🤗🤗',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64015ce012cdee268e696a01',121,611,'平时分很高，大家无脑冲就好了，而且很和蔼可亲',5,5,5,15,3,2);
