INSERT INTO "reviews" VALUES('6400bc07d8e01c412d57d0e0',1865,708,'我来点评下他的发电厂课设，平时每次都要去，很严，而且事情也很多，每个人设计数据不一样，别的班都是几人一组一起做，而且都是期末才答辩.他次次都要去，要求还很严，给分很低，我的建议是大四考研找工作的别选，保研的无所谓…',2,4,5,11,5,0);
