INSERT INTO "reviews" VALUES('6400ba17d8e01c412d57cd9d',8138,716,'这老师大概脑子不太对，cad机考说好的10分，最后变成25分，刻薄冷酷，59分都不捞一下，平时分打70多分，想挂科的就选',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('64009a02d8e01c412d5787a1',8541,28,'非常优秀的老师！对学生非常好从来都是鼓励大家人也超级和蔼，平时分给的嘎嘎高，班上大家平时分都有五十多，学习压力很小，自身文化素养也很高，只是遗憾马上就要退休了，后面的学弟学妹们上不到他的课太可惜了，祝廖老师退休生活健康快乐！好好享受生活！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('64007af0d8e01c412d575315',430,194,'永远爱虎虎，平时分除了期中考试自己考的，其他的直接拉满，认真学，期末分也不会低，虎虎讲课也讲得很好，永远爱虎虎',5,5,5,15,1,0);
