INSERT INTO "reviews" VALUES('640036c4d8e01c412d56e2e0',452,965,'其实我觉得老师还不错，有的时候确实会有点阴阳怪气，但我似乎感觉没那么伤人，她对化学不好的我也能耐心指导鼓励，平时分给的也挺高',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('640030a3d8e01c412d56dafc',11,11,'虽然老师很温柔和蔼，上课也非常轻松非常水，但是作业实在太多了，a班平时事也很多，比b班作业和杂事不知道多了多少，而且给分非常刻板，平时分完全按照作业的完成情况给，完全没有捞的余地，导致分数会非常低，需要花很多时间才能拿个差不多的平时分。英语如果想拿高分还是开学考摆烂进b班吧',3,3,2,8,10,7);
