INSERT INTO "reviews" VALUES('640010ba12cdee268e6793e3',1910,1910,'他的房屋建筑学烂中烂，上课极其枯燥乏味，考试前什么也不说，不说重点不说题型不说考试范围，学生们问他他还觉得你在挑衅他，考试前还要阴阳你是真的纯纯的逆天，别人的导论课贼好过，他的房屋建筑学你背几天到考试的时候发现屁用没有（闭卷），如果你想保研或者争奖学金来了就是寄😅',1,1,1,3,0,0);
