INSERT INTO "reviews" VALUES('63fff339d8e01c412d568087',545,433,'表面上很严厉实际还是略微宽松的老师，平时成绩做多少给多少，作业有补交的机会，课堂上的语法单词讲的很少，输出观点态度比较多，人品杠杠硬，总体还是很不错的。',5,5,5,15,2,0);
