INSERT INTO "reviews" VALUES('63feee42d8e01c412d551dd4',2484,92,'何老师真的永远的神，相当有气质，平时分奇高无比，非常好说话，错过了作业ddl去私聊老师她还会给你改截止时间，没见过那么好的老师',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('63feedc0d8e01c412d551d24',268,7955,'******期末试卷直接网上找题，问问题从来不回，自己没玩明白这门课能不能别来祸害学生，******属于是没得选，活水是没有******的评价，感兴趣的可以去交大的GitHub资料库看看导师评价里的赵海全，你就明白什么叫做科研败类了',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('63feec8612cdee268e65feb4',3446,4594,'期末五个计算五个简答，各50分，平时分是会比较高，但这门课难度摆在这里了，期末很难顶，不亚于一门三学分的课程，只能说祝你好运',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('63feebdcd8e01c412d551a17',767,694,'好老师，电子的都知道，有问必答，文字讲不明白直接电话教你，平时分再三确定，基本给所有人拉满',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63fee99cd8e01c412d55168e',2567,9789,'老师讲的无敌好，上课不用ppt，纯板书，是所有老师中我最喜欢的老师，上他的电分课完全不用自学。上课还会讲故事，他是40多年前的老学叔，有时会讲以前的交大趣事，很有意思。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63fee6b8d8e01c412d551225',2642,2642,'有史以来最低的平时分，承认我是我自己学的不够精，但布置作业我都认认真真的完成了，真不至于给这么低呀！！！',1,1,1,3,1,3);
