INSERT INTO "reviews" VALUES('63feba0b12cdee268e65b167',1065,1065,'没修蔡老师的毛概修了习概，开局一刀45分期末30就能及格😍😍😍😍回答问题加分机制也能有效防卷安抚社恐，什么美人善心的神仙老师啊，上课也是干什么都行不发出声音打扰老师就行了，三连讲提前一二十分钟下课',5,5,5,15,2,0);
