INSERT INTO "reviews" VALUES('63feb382d8e01c412d54c3b5',1128,40,'说实话老师上课确实是念PPT学不到啥，前几节课都是点名，后面就是按学号安排座位，没来的人就算缺课。上课提问很多，没有人主动回答就点人回答。
INSERT INTO "reviews" VALUES('63feb11512cdee268e65a31e',2303,2303,'PPT真的太难看了，拼贴画一样，出了复习大纲考试还不沾边',5,2,3,10,0,1);
INSERT INTO "reviews" VALUES('63feacdf12cdee268e659be1',9807,1495,'老师人很好，教学方式也很活泼，非常认真负责，有问必答有求必应，期中考试后给我们每节课加上了随堂小测（兼具点名作用）还自愿给基础不牢靠的同学补课，上课你干啥不会管你。缺点是过于认真，按照规定给分，从来不捞人，平时分如果你不是啥都做得很好肯定不会很高。我朋友考了56分都给他挂了（哭笑），对面宿舍一个朋友考了42分被光学另一个老师王楠捞起来了。总之你想学好这门课想取得高分可以考虑严老师，但是你想混过这门课的话，我的建议是速润',4,4,3,11,0,0);
