INSERT INTO "reviews" VALUES('63fc633712cdee268e623109',3718,1796,'老师很好，报了一次他的大学生职业生涯规划选修课，并有幸做了一次组长，平时只要学校不硬性检查，他不会记学生旷课，几次都不会，有一次我把组员的假条给他，他都不要，是没事，给分很高，得到了98分，上课就是玩玩，期末做一个ppt就行了',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('63fc6187d8e01c412d5175cb',1821,1821,'非常好，老师生怕你过不了，考前会有复习，一定要好好听，会有惊喜的，基本是考试原题换了数据，基本必过，就是看你个人能力考好分低分了，老师人真的没话说，值得选择',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('63fc5a94d8e01c412d516cc6',449,3822,'一分耕耘，一分收获。付出的多，分就愈多。老师的作业主要围绕小组工作展开，没有好队友的话，作业会做的非常累。想水课的话，这个老师不推荐。',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('63fc5946d8e01c412d516adf',776,24,'用心一点，老师平时分会给满。由于理论力学这门课整体难度较高，老师的课后作业会比较多，再者，老师是以让同学不挂科为目的进行授课的，所以前期讲简单的讲的很细，后期讲难得讲的很粗略，所以对想拿高分的同学来说不推荐。',3,3,3,9,0,0);
