INSERT INTO "reviews" VALUES('63fb2e0ed8e01c412d4fdcae',2346,2346,'老师人很好，虽然平常不咋布置作业，但是挺负责的，问问题也会耐心解答，关键是老师没有因为我的卷面给我扣分，平时期末都给了我100，只能说娟姐yyds',5,5,4,14,2,0);
