INSERT INTO "reviews" VALUES('63f9a82812cdee268e5e9c4f',9122,9122,'说他不把学生当人的证据很多，一个是学生系统的成绩问题。一个学生提前一周提交了线上作业，并获得了83的分数，看完了评讲内容然后开心的关上了系统。但由于网络波动问题这个成绩没有记录上，还好学生留存了所有的作业完成证据。学生在发现了作业成绩没有记录上时，学生条理清晰，逻辑分明地向老师展示可以证明自己做完了作业成绩。从作业截图，最后完成（修改）时间，存根文件，评讲分数截图，其证据的真实性和完整性天地可鉴，按理来说，一个具有善良之心和良好师德的老师应该是认真检查学生的证据无误后认真给分。但他不是，他估计看都没有看学生的证据，直接说了一句“以学生系统为准”（甚至第一遍打错字了）便置之不理敷衍了事？',3,3,1,7,14,0);
INSERT INTO "reviews" VALUES('63f98f7312cdee268e5e783d',867,28,'只能说：平时分不高',3,3,4,10,0,0);
