INSERT INTO "reviews" VALUES('63f8f08712cdee268e5dccae',767,694,'李老师很温柔，人也巨好，课间喜欢和同学互动，我期末考试的时候，最后一道大题考校正，我相角裕度的公式记反了，然后选错校正方式了，李老师监考时看到我的卷子然后直接在我的相角裕度上用手指轻轻敲了三下，我这才反应过来，真的我哭死(˃ ⌑ ˂ഃ )',5,5,5,15,7,2);
INSERT INTO "reviews" VALUES('63f8d8d812cdee268e5daae0',2637,40,'平时分60分给了53，神',5,5,5,15,1,0);
