INSERT INTO "reviews" VALUES('63f890d712cdee268e5d3199',8138,8138,'******口音贼重，上课照着PPT念，平时分低竟然能出现在一个人身上******。cad机考，别的班允许自带电脑，徐不让带，为啥？******，机考还考各设置，你画的图对不行，设置有问题狠狠扣分。真是滑稽啊。******程度相当于作文判分，完全不看内容，只看字好不好看。当然这个******也看内容，内容错了更是狠狠扣。真的完全不建议选这个人。',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('63f88432d8e01c412d4c6a10',2017,4609,'能学到东西，分还挺高，谁不选谁后悔一辈子!刘教授绝对是概率论之王!',5,5,5,15,1,1);
