INSERT INTO "reviews" VALUES('63f38dc1d8e01c412d45b006',499,194,'Pull it directly when it is flat. Okay. 平时分直接拉满嘎嘎好，上课讲的非常清晰易懂，嘎嘎好。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63f38cb312cdee268e565b07',2005,1170,'人长得好看，年轻，平时分直接拉满，期末全班90➕，从不点名，从不叫人回答问题',3,3,3,9,1,12);
INSERT INTO "reviews" VALUES('63f38c5e12cdee268e565a9c',499,194,'直接冲就完事了，平时分直接拉满，不管你交不交作业或者作业完成度怎么样都是拉满，只需要应付好半期考试，还有期末考试就行，论文写了基本上都是一样的分。冲冲冲！',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('63f38aa912cdee268e565813',433,28,'天天u校园fif事情多的要死，半期考试考得比b班高不少，最后平时分比他们远低 分是真低
INSERT INTO "reviews" VALUES('63f37a7dd8e01c412d4588bc',733,335,'秒回消息，讲课可以，但是考试前什么也不发，别的老师重点发出来，在群里啥也不发，mooc也不提醒做，到期直接发一个成绩，题型也不会说。总结一下：教的靠mooc，mooc不如b站，作业不考，题型不讲，考的试卷不发，学习跟地道战一样防着学生，那学习这门课有什么必要呢？',1,2,1,4,2,0);
