INSERT INTO "reviews" VALUES('63f24e99d7800c003bc9c8a9',788,1551,'🤬',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('63f22bf4ce0cc30ce47dd005',811,762,'上课内容讲得确实不太行，ppt战神，题外话贼多，点了两三次名字吧，课上不如自习，但是在平时分这点最重要的确实不错，分给得高，总体还行',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('63f22267ce0cc30ce47db0a6',542,1170,'考试前哪怕时间不够，也要给大家复习，非常负责',4,4,4,12,0,0);
