INSERT INTO "reviews" VALUES('63f048cdce0cc30ce47b5431',359,228,'全班平均分85******我室友的班全班平均分96，而且平时也没啥事，佛了。',2,2,2,6,13,0);
INSERT INTO "reviews" VALUES('63eef543ce0cc30ce4799822',741,911,'交运概论什么地位啊？茅班六门限修之一。限选还挂人挂的贼狠。期末就给我几分打电话问说是态度问题。我自己写的题她跟我说我抄袭？我抄******啊。茅班的同学自己注意下，课是水课，但是老师有毒。求稳建议选另外几门。',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('63edf23fce0cc30ce4784e00',2028,2028,'本来想分出来了再来评他的，他纯纯搞人心态过来赶紧骂他，提前收作业就算了，生病手术这种理由都不让延迟，我jdhwyhsgt还没做完啊 可恶！专业水平不错 避免以上这些事情就提前做作业吧（）',1,1,4,6,2,0);
INSERT INTO "reviews" VALUES('63edda4cd7800c003bc3e834',198,179,'冲冲冲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63ec88dfe305c074924c4d9c',586,24,'快毕业了给后面来的学弟学妹安利一下，李鹏老师是四年大学我最喜欢的一个老师，想好好学这门课的同学一定不容错过，当然想划水的不建议选',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('63ec82244bc9cb4b13758768',1318,301,'赵老师人很有趣人很好，就是上课难受死了听不懂也听不到重点，现在正在复习物化准备期末考试真的要死了，生医的同学跑也跑不掉毕竟只有这位老师教，大家自求多福吧',3,2,2,7,2,0);
INSERT INTO "reviews" VALUES('63ec667e4bc9cb4b13755de2',819,228,'老师水平不错，讲课认真，但是比较需要回应。期中考试或者作业占比较大。这学期免考名额5人',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('63ec32544bc9cb4b137516d8',2654,1225,'老师很好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63ec2b5be305c074924bcb5e',2654,1225,'事少分高，认真完成每一项作业，平时分能刷到57(满分60)哦，哈哈哈',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('63ea4c03a9aedb7567691741',178,946,'上课幽默风趣，平时分直接拉满，期末基本好好听课没问题。作业也少的可怜，上课基本你不太张扬随便玩的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63e93a3bc00f1f296246646e',1186,40,'平时分给得不错，态度到位、按时完成老师的任务就可，推荐！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63e50dd5c00f1f29624066a6',27,27,'最喜欢的老师，声音好听，为学生着想，给分也很高',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('63e50d83c00f1f296240664b',9122,9122,'真的冷酷无情，回复学生的问题就是机械性答案，上课也是按着PPT念，唯一好一点的是平时分还算高',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('63e4dd8aa9aedb7567614de0',452,2671,'别的不说，好老师给划重点，救我狗命，扳回一局。',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('63e385d7a9aedb75675f7bc5',1748,1007,'******工地英语硬要全英文教学，笑里藏刀，她课程的平均分永远比别人教的低',4,2,1,7,3,0);
INSERT INTO "reviews" VALUES('63e3305ac00f1f29623db5e4',1169,2499,'众所周知，点集拓扑是基础数学方向学生十分关键的一门课，在几何、分析、代数中随处可见它的身影，感谢崔老师的课程为我打好了扎实的基础',3,3,3,9,1,2);
INSERT INTO "reviews" VALUES('63e25504a9aedb75675dd301',5471,9932,'典型的大学佛系混退休老师，自学能力强的同学可以选，锻炼自己的自学能力',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('63e111b8c00f1f29623adf46',3098,3136,'有点抽象，给分还行',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63c6dea03aad7a05547d7a34',1341,114,'******下课问问题他就敷衍得要死，然后动不动阴阳怪气，总感觉她自己高高在上的样子。还特别喜欢公开挖苦你，不让在教室吃早饭😅😅😅小测还******算分无语=_=',1,1,1,3,5,1);
INSERT INTO "reviews" VALUES('63c6dd9ac00f1f296219843e',873,228,'挺好的，上课你干啥他都不管，一次小组展示，一次课堂测验，都特别水，免考比较容易',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63c4d1ecc00f1f296216c951',459,68,'蒋婧姐姐人美心善给分高 专业水平max 难得一遇的好老师 值得冲！',5,5,5,15,4,9);
INSERT INTO "reviews" VALUES('63c4c94f3aad7a05547aadca',2377,230,'别去，快跑。自己都搞不清要干嘛，智慧树到底做不做自己心里都没数就跟学生说要做期末考试，哈 哈。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('63be9c0547929677165d45d8',1600,96,'希望早点成为教授',5,5,5,15,3,0);
