INSERT INTO "reviews" VALUES('63bd6d42b6bbed131bd229d2',4119,9941,'分低，别来',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('63bd6cfbb6bbed131bd22971',2961,761,'不水分高，摸鱼分低，能学到东西',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63bcfa9547929677165afeb1',1265,1265,'呵呵🤭别选这个老师 平时也不教什么 就下达个作业任务 根本不会点评我们的作业 也不教怎么写论文 就这分还打得巨低',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('63b9c1eb479296771656b484',2654,40,'我觉得老师挺好的，基本上完成作业就不会有其他什么事，有问题也可以直接请教。
INSERT INTO "reviews" VALUES('63b96d2fb6bbed131bccacc6',344,1135,'老师人巨好，很抢手!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63b969bd4792967716562ab9',2654,40,'通用学术英语选到就是赚到，事少分高，老师人巨好，分数特别高，平时会和你交流论文写作啥的，总之推荐选课!',5,5,5,15,0,6);
INSERT INTO "reviews" VALUES('63b95715b6bbed131bcc8a01',2654,40,'作业不多（跟我室友的老师相比）有座位表需要按照固定的位置就坐（四舍五入约等于点名） 平时成绩也还行',5,5,4,14,0,1);
INSERT INTO "reviews" VALUES('63b9529cb6bbed131bcc8332',2654,40,'上课无聊死，照本宣科，平时分给的很平均，不算高',3,2,3,8,1,3);
INSERT INTO "reviews" VALUES('63b92318b6bbed131bcc3ee9',545,433,'莫老就是很愿意输出自己观点的男老师，虽然上课可能听不见坐的很后面，但是你想干什么干什么，可能会按名单点名，然后他的空间真的贼有趣，很接地气，其实相处下来一年，发现老师真的挺宽容的，在小测zuobi被抓都一点事没有，给分也不错，这么好的老师，珍惜！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('63b7fc5560195e6845029477',788,9950,'老师的业务能力没得说，但要求确实比较严格，并且很有原则，但是打分很公平。很喜欢老师，如果是真的想去提升自己，那么李娟老师是首选',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('63b7f53860195e6845028a2f',8566,114,'个人感觉教得很好，很细，讲解知识比较系统化，有发PPT的。讲课过程板书和PPT结合，有大量例题展示，作业以学校教材为主，考试是以A4纸作答，给分公正合理，很好的老师',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('63b7e79660195e68450276b7',344,1135,'雷子我的神',5,5,5,15,0,0);
