INSERT INTO "reviews" VALUES('63b7a9f51d356621640f7793',1320,3017,'老师人美心善，作业不多给分很高，讲课也很有趣
INSERT INTO "reviews" VALUES('63b787871d356621640f4211',2015,2015,'给分很高，而且不折磨人',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63b6e96660195e68450136ba',96,96,'平时分满了不多哔哔',5,5,3,13,1,3);
INSERT INTO "reviews" VALUES('63b6e8ef1d356621640e98f1',142,75,'完美老师！',5,5,5,15,0,4);
INSERT INTO "reviews" VALUES('63b6e23e1d356621640e8dc4',2584,7446,'人美心善，救我狗命，大爱吴姐！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63b6cc2a1d356621640e59ec',6319,194,'女神，救星。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63b6c8e61d356621640e53e8',867,27,'通用学术英语给分较低，讲的挺好，作业少事少。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('63b67f8e1d356621640de07a',1186,40,'老师人挺好的，这点不容置疑，但是平时分并不高',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('63b67f0e1d356621640ddf8f',788,9950,'别选给分巨低坑死了',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('63b67e5460195e6845007add',788,449,'分数给的巨低',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('63b64b681d356621640d9227',1506,1506,'从不点名。上课就是看短片+听音乐+听老师分享个人经历。有一次介绍自己和推荐电影的作业。期末是对一部影视作品做音乐赏析加最喜欢上课放的哪一个视频。老师的讲课方向就是低难度的普及知识的课程，非常轻松，唯一比较麻烦的是要组队，每节课课前每一组要推荐一部电影，讲得不是很好的分也给到90以上的，给分很大方。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('63b6497d60195e68450029bd',1186,40,'事情不少。每周除了论文作业还有一些小组作业和个人的阅读文章勾画的作业（而且都是自己上课拍屏幕从来不会在群里提醒，作业每节课会抽查），上课会抽问，一般没人举手就点座位号，超爱一行一行地问（抽问跟分数挂不挂勾不清楚），上课还比较温柔细致，给分感觉有点严格，用心做的话能得个中等偏上分数。',4,3,4,11,2,0);
INSERT INTO "reviews" VALUES('63b581f51d356621640c8a62',3616,3350,'老师保姆式教学，对方案修改很细致也很耐心，随时都可以提问，有问必答，手把手修改。就是表达有些拖拉，有时讲不到要点，在一个同学身上耽误太长时间，导致别的同学缺少交流机会，总的来说还是很不错',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('63b5743360195e6845ff0d34',918,918,'老师专业水平挺高的，但是不会表达，课上可能更不上课下要自己学，但是作业好好写，给分很高。半期考试大部分是近期做过的作业原题。（作业少）',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('63b561841d356621640c51a1',5064,28,'基本每节课都会检查作业，经常上课小组讨论，点人分享讨论结果。按照名单点人起来回答问题，论文看得也很严格，要求挺多的',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('63b54a5960195e6845feccaa',2399,230,'老师讲课很有趣，一学期全程听下来，平时作业有一个小组演讲，期末会画重点，考试范围也都是重点里的，分数九十多分。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63b4fd8060195e6845fe52a3',5064,40,'事情多而且上课不水，课本和论文都有布置任务（作业比其他班会多一些，有些班级没有课本要求），关键是有一些作业毫无意义，做了也不讲，讲了也没啥收获。作业口头布置，会突袭检查，动不动就说扣平时分。上课不水，没法摸鱼，一直逛，喜欢抽人回答问题、小组讨论，逮到人就扣平时分，上课的话整体比较活跃不死板。最后分很低，我是在除课堂表现方面的其他部分尽力拿分，但是最后结果分都不算正常水平。总之，推荐喜欢英语表达、上课活跃、愿意花时间认真做英语作业的同学选，英语想水一点点又能拿正常的平时分（比如我）的避雷。',2,3,3,8,1,0);
INSERT INTO "reviews" VALUES('63b4380f60195e6845fd6bf3',2250,9973,'很严但是给分很高，可以选',5,5,1,11,1,0);
INSERT INTO "reviews" VALUES('63b3f48a60195e6845fcf8b8',8080,8080,'朋友们冲啊！选就完了 基本上每节课是学习通签到 没签上和课代表说一声就完事，课挺有趣的。不听在前排写作业都没人管你。原本是有期中作业的，结果老师拖拉拖着拖着没作业了。期末有几道开放性题目，认真回答自圆其说就行，给分很高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63b3c3341d356621640a02da',2028,9975,'李阳老师对我们专业要求是有的（eg拍的照片需要找他确认）但是他人很好，非常好说话，也会替我们考虑，最后的分数认真做了就是90+',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('63b3b5f61d3566216409ee22',416,1281,'张老师赞赞赞赞，十分可爱的小老头！！！上课非常认真，讲得超级好！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63b3b5261d3566216409ecfa',452,965,'讲的还行，但确实阴阳，系统也真的是******，系统每个星期有课要听，还要上课，每次上课前小测还按小测成绩记到平时分，两学分的课真的可以说上成4学分了。但是抢不到别的老师的课的话就好好学吧，好好学分其实挺不错的，跟着她认真学能学懂物化，期中，期末很多她小测里的题目，认真学90+完全不是问题',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('63b3af401d3566216409e218',2829,9978,'老师人很好，就是讲课方式以自己探索为主，她只会针对性地做点评，不会教你通用的知识',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('63b2e7ac60195e6845fb9580',5190,5190,'期末课程作业超级多，不是真的想学习、练习编程的话还是换老师吧。曹老师人还是挺好的，就是会默认学生都不是编程困难户，学起来费事',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('63b158291d3566216406d95b',2878,27,'几年过去了黄老师依然是我见到最温柔的老师，对于刚入学的新生来说如同天使。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63b0030160195e6845f7c877',491,23,'刘老师和蔼可亲，会经常督促我们的学习，课也讲得很清楚透彻，特别特别好！问她问题总是及时耐心回复，非常认真负责，大爱！',5,5,5,15,8,0);
INSERT INTO "reviews" VALUES('63aef70760195e6845f68da5',1853,670,'超级无语 谁选谁后悔',1,1,1,3,0,0);
