INSERT INTO "reviews" VALUES('63ae862a60195e6845f5d079',9984,9984,'这是对赵老师行车组织的评价，系统没有设置他有这门课，所以评在线路基础下面了。
INSERT INTO "reviews" VALUES('63ae373a60195e6845f56088',6510,2015,'啥都好，就是课听得让我想睡觉（我自己的锅）。另外就是平时分给的比较严格，没啥水分。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63ae36a91d3566216402d12e',21,40,'比较严格认真，甚至有时候有点较真了，尤其是考试和点名。上课前段会说很多比较多的废话，水平应该是有，备课也认真，废话少点多讲课就更好了。',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('63ae35a960195e6845f55ed7',8453,114,'水平有，上课不太爱用课本，注重构建知识体系。在数学建模这一块应该比较牛B，但是最大的缺陷是讲课时候声音小口齿不清，建议学生抢第一排坐。平时不管学生。虽然他说过有问题可以QQ留言，但他一般不会回复。课程考试给翻书，很水。',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('63ad939560195e6845f4aa65',3920,761,'为什么平时分这么低，作业这么多我都做了，无语',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('63ad251d60195e6845f3f449',9807,1495,'严老师我的爹！讲课清晰、专业，人也幽默有趣还负责，就是老师的低音炮在下午第二节这个时间段很容易睡着，点名基本没有，作业是一章一次，小题原创、大题课本原题，但是都很简单，好好学真的能学到很多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63ac21ec60195e6845f2abe3',23,23,'刘老师讲课特别特别好，幽默风趣，和蔼可亲，耐心认真，完美！',5,5,5,15,28,0);
INSERT INTO "reviews" VALUES('63ac15831d35662164000452',5064,28,'虽然老师平时作业每周都布置，但是其实也不用花太多时间，而且还是很好说话的，平时喜欢点同学回答问题和小组讨论',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63abd9c560195e6845f23bf9',887,23,'我爱刘老师！讲的巨好，巨有耐心',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63aab7f21d35662164fe442e',2878,28,'朝华老师绝对是一个超棒的老师，给分巨高，而且很照顾同学，会主动加分的那种，上了大二才知道老师的好，难过，我真的会爱她，以后可能都遇不到比她给分更高的老师了( p′︵‵。)',5,5,5,15,0,0);
