INSERT INTO "reviews" VALUES('63a6ae5760195e6845ebb6f9',68,40,'上完她的课我觉得我抗压能力得到极大提升。单人路坐牢被对面轮流越塔什么的都太逊了好嘛，这和上她的课相比有什么值得破防的？',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('63a6abf260195e6845ebb3cd',4669,1170,'教的简直……搞得我现在还在补，概念什么的上课完全不说，例题上课直接放完，PPT读一遍结课，很多章节都说跳过去了自己看，一个大的理论十分钟解决，我服了，期末考试前会发大纲吧，别的老师都会说，她提都没提那个群跟死了一样',1,1,1,3,1,0);
