INSERT INTO "reviews" VALUES('63a668f51d35662164f8cb9b',51,1346,'非常好的选修课老师，情况与楼上说的大致相同。全程玩手机，没回答过问题，签到也没漏，最后总评96过了。曾老师的课无脑入就行了。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63a5223f60195e6845e9a302',560,3214,'看起来很严厉 表现得很严厉 实际上人很宽容，但是不会喜欢学生无缘无故旷课请假 喜欢努力 学生 贼偏爱我hahha 喜欢舞蹈的而且会努力学的推荐选刘老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63a520881d35662164f70d86',903,179,'康萍姐姐人巨温柔而且作业少 很友善 对每个同学都关心重视 快冲冲 真的好老师 上课也有意思',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63a51ff260195e6845e99be8',281,1156,'咱就说好老师 虽然会抽人爬黑板做题目 很刺激 但是确实好老师讲的好 平时分给的也高 不点名 （2个人爬黑板抽到了就算点名吧）课会枯燥 但是我觉得这是复变函数课程的问题 老师没问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63a51f5e1d35662164f7097e',831,762,'这个老师有毒 上课没有章法和逻辑体系到处乱开Ppt  我只能被迫求助宋浩',3,1,1,5,5,0);
INSERT INTO "reviews" VALUES('63a50c9760195e6845e9751d',3623,6644,'给分就完了昂，用不着听',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63a4861a1d35662164f66615',627,114,'呃，崔老师他真的是。。。（他平时嘲讽拉满，但是有时候还是会说他不再骂我们了）。。。但是想学东西可以选',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('63a3b8c160195e6845e7b469',1748,1007,'郑老师是英语讲一遍，中文翻译一遍。讲的挺慢的，除了最后几节课来不及会比较快，平时会布置作业，给的时间会比较长，认真听讲还是可以拿90分的，期末考试闭卷而且是全英文，但答题可以用中文。建议想出国留学的同学选。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('63a33ad31d35662164f4b269',6396,6396,'避雷，狠狠避雷，其实专业能力是有的，但是感觉你上她的课屁都学不到，上课都在吹自己的各种经历，课程内容几分钟讲完，一学期全靠自学，不讲例题让你写作业，疯狂翻转课堂，上课疯狂点名提问，明明自己什么都没学会还是要硬着头皮回答，整个人都给你一种死亡压迫感，快逃吧',3,2,1,6,7,0);
INSERT INTO "reviews" VALUES('63a3396960195e6845e73ff0',2983,294,'老师人挺好的就是作业多 而且爱点人 虽然回答不上来也没事',4,3,4,11,0,0);
