INSERT INTO "reviews" VALUES('63a2b70e60195e6845e67ab3',725,40,'老师人很好！课也上的很好。对完成书上练习没有要求，课上偶尔会开火车提问，但是答不出也没有关系。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('63a2a69860195e6845e65de1',703,228,'快跑 跑就完了 讲的什么东西',1,1,1,3,0,0);
