INSERT INTO "reviews" VALUES('6387f2ca60195e6845c173eb',4687,4687,'就给我们上了一节课还能展现满满的优越感，我真的要吐了，上课没讲什么光放视频不说（说是要讲案例，结果放宣传片😅），还踩我们班，说你们班怎么样怎么样，他带的班就怎么好怎么好，唉，其实是有点表达能力的，只是表达能力加优越感变成了满满的油腻。',1,1,1,3,0,0);
