INSERT INTO "reviews" VALUES('6386c2841d35662164cd3da5',6131,3563,'早上七点四十要到教室；有次第二天早八，前一天晚上才布置作业，而且要课前提交；没见过这么奇葩的老师，讲课也一般，大部分自学，建议赶紧润',3,1,1,5,5,0);
INSERT INTO "reviews" VALUES('638618e81d35662164cc7e26',1158,26,'小娟老师我的女神!!!!人美心善好说话，温柔负责有能力!高数选小娟就对了!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6385e12760195e6845bea4cb',3407,762,'亮子常说以人为本，以学生为本，所以平时分给的巨高，期末也会捞一捞那些没有及格的同学，平时上课也很很幽默，讲的也不错，遇到就是赚到。',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('6385df8160195e6845bea2a4',315,40,'一个执着于哲学和英音的老师，每节课必点名，缺一次扣一分，且每节课必布置一篇文章要求下节课用英音朗读，如果读的不标准或者不熟也扣分，读的好可以加分，但是每节课基本都是扣分的同学多，加分的一个学期也不够两三个。但是期末老师会根据扣分情况把一部分平时分较低的同学给捞一下。平时很喜欢讲哲学，对于我这种理工男来说感觉很扯，喜欢哲学的同学可以选。',3,3,4,10,6,0);
INSERT INTO "reviews" VALUES('6385de021d35662164cc1020',6994,10120,'广俊的专业性是毋庸置疑的，上课表达能力很强，但是老师给分很低，给的分没有丝毫水分，该是多少就是多少。平时作业给分也比其他老师严格，这就导致每个学期班里面同学的平时分都比其他班的低，期末挂的也很多。总的来说，谨慎选择，喜欢挑战自己的同学可以选。',5,5,2,12,0,0);
INSERT INTO "reviews" VALUES('6385d2ad1d35662164cbff0f',40,40,'给分是真的抠，事情蛮多的，一个问题可以让全班来回答一遍',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('6385d2801d35662164cbfeb0',2500,228,'因为五连讲就没去上过课，给老师点过几次名都不在，交第一次作业回复邮件中给我说了，挺好的，布置的东西认真弄的话分还是很高的。老师很认真很开朗，爆赞。',5,5,5,15,1,0);
