INSERT INTO "reviews" VALUES('636233ae9ab7fe3cc5131eb3',3764,3691,'被一个学生顶撞了，于是期末出了闻所未闻见所未见的考题报复学生，全年级都在及格线，随机挑几个5859，补考直接换题型，题都网上找，毫无学术能力，上课念网上下的PPT',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('6361d1619ab7fe3cc5126126',6726,3691,'大学三年第一次遇到这种集所有缺点于一身的老师 用着十几年前做的老旧ppt 同学提问从来没有回答清楚过 讲了这么多年这门课难道自己还没学透彻嘛？ 就不能看看同学提问的时候自己那个窘迫的样子反思一下嘛？ 天天课堂翻转 作业神多 实验报告这周五刚布置下周就要交 无语😓 希望你给分的时候能先看看自己的教学水平',1,1,1,3,1,0);
