INSERT INTO "reviews" VALUES('632bae95bb98bd0175568450',7,7,'胡军老师真的强！从来没有接触过能把物理讲得这么清楚的老师，重点知识和非重点区分很明白，PPT真正服务于课堂！！大赞！',5,5,5,15,4,0);
