INSERT INTO "reviews" VALUES('632ad09b7f9fa0563863fb51',246,228,'我觉得可能康老师的性格和他名字的三个字毫无关系，甚至背道而驰。毫不否认老师希望和同学们互动，但是每次上课抽人咄咄逼人，刨根问底，反复折磨，被他抽问的同学不得不面对，你再总结一下，提炼一下，这个是什么嘛，没有引导，只是让你像无头苍蝇一样尴尬。上课口音明显，听不清楚，思维不连贯，自己说话磕磕巴巴，极大程度地浇灭了学习兴趣。至于专业水平，不予置评',3,1,1,5,10,1);
INSERT INTO "reviews" VALUES('632ad010f0a4f4680b6756d1',246,228,'真的千万别选这个老师，胶带最恶心老师没有之一，咄咄逼人不说，批事又多，逮着学生不放，发消息不回，自己感觉自己高高在上，脑袋里装的是******，给分也低，******他，真的有病，给他一分都嫌多，拿点钱去治病吧******',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('632a88f6f0a4f4680b66e339',3407,762,'选到了你就是赚到了',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('632a888bf0a4f4680b66e2cd',24,24,'我真的很服气，平时分直接倒扣，一个人带二百多人吧，挂了一百二三十个，上课坐在后排根本听不到在说啥，普通话不标准，但是吧，这人上课讲的还挺好的，就是挂科率太高了，我认认真真学了一学期，就刚刚过线，改试卷也是不留情面，改之前没有说不算结果不给分，最后答题就没有算结果，直接没有给分，我哭死。上课还不允许玩手机。',4,1,1,6,1,26);
INSERT INTO "reviews" VALUES('6329dd097f9fa0563862b9b0',452,2671,'最喜欢阴阳怪气人，而且不是私下阴阳怪气你',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('6329c25f7f9fa05638627e58',250,250,'老师是天才我是sb',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('632960997f9fa0563861d6eb',2211,1241,'我曾经以为自己遇到了一个大佬，华中科技大学的本科，耶鲁的硕博，后来我发现老师的教学能力和我的理解能力完全不匹配。一个理科老师教公式，计算，从来不在黑板上推，直接在ppt念，听力考试现在开始。作业非常多，并且全部要求雨课堂上传，非常麻烦，每次作业20多道题，周二布置周六中午要求交。我终于理解您说的培养自学能力，打不了自学。（材料的同学可以开始就找找其他的书，教材非常老旧）',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('632941d5f0a4f4680b6501c2',1108,188,'第二周开学，第三周选课进来，第四周就让展示小组作业，真踏🐴是一个伞兵，自己也不反思一下为什么自己名声这么差',1,1,1,3,4,0);
