INSERT INTO "reviews" VALUES('631b6c011f226a25e260b9dc',10301,335,'对学生要求很高，但人挺不错。我室友课设都打算摆了重修了，被她亲切的五一节电话问候和宽宏大量的一周延期检查强行捞了起来。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('631b6b4cf21faf4ab5da8b21',2340,2340,'搞科研的年轻老师教书大多不行。就算你很努力，还是不太能从他的讲述里学明白这门课。更何况他讲课大多数时候都听不见或者听不清。',3,1,2,6,1,0);
