INSERT INTO "reviews" VALUES('631b6948f21faf4ab5da88b7',2500,228,'究极好老师，懂年轻人，非常努力想要搞好教学也非常想和同学们搞好关系。到现在还经常约我同学打球、请他们到家里吃饭。有思想，有灵魂，有赤子之心的好老师，也不会对你要求太多。',5,5,5,15,4,0);
