INSERT INTO "reviews" VALUES('631aa9ba6f28591b6603a728',604,5,'老师能控制的平时分都会拉满，老师不经常点名，不要缺课，老师人很好的。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('631aa93f6f28591b6603a64d',961,762,'有人觉得讲的好有人觉得讲的不好，我觉得一般，怎么说，我从来不缺课，让交的课堂练习我也交了，但是平时分还是扣了一些，可能是课堂练习写的太烂，我概率论确实学的不好。那个扣掉的分数我也不知道扣的哪里，老师也没明说。',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('631a9e3eb2de81489999cfc5',961,762,'平时分给得很低，全考勤，平时作业全交的情况下也只给了70分，而且平时作业除了练习册之外还会额外安排章节作业。',2,2,2,6,3,1);
INSERT INTO "reviews" VALUES('631a994c6f28591b66038d41',2878,28,'黄老师真yyds ！作业会尽力帮你缩减，我们和其他班少了很多作业！还会认真记住所有人的名字，十分有亲和力。平时分巨高！作业还很少！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63195192722da6529db67a3e',4257,8943,'专业课上成水课...',3,2,4,9,0,0);
INSERT INTO "reviews" VALUES('631946f6722da6529db668d8',2582,790,'物流笑面虎，作业多点到多给分低。期末一定要提前很久开始背，我承认由于个人水平的差距好好背的会考的特别好，但为了这样一门课总归不值得，我考六级都没考这一门课这么努力过，最后分还很低',1,1,2,4,2,0);
INSERT INTO "reviews" VALUES('6318e51e6095b06986310a14',604,229,'平时分拉满，讲课有重点！冲！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('6318d88f722da6529db5f72c',293,375,'反正上课巨水，期末开卷考，分数基本95+',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('6318d80e722da6529db5f6df',756,22,'真的人超级好，还会分享一些人生方面的看法，只要你认真学，90+稳稳的，而且平时分直接拉满，QQ上问问题也回答的超级快！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6318c1346095b0698630e74f',2323,92,'帅帅的大男孩 完美的身材 要多帅有多帅 皮肤也很白',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63188bf8722da6529db57d1c',5213,5213,'讲话确实不太清楚 但可以感觉到老师很负责很有耐心 上课讲题讲得巨细 给分是真的高啊',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63188a87722da6529db57afb',10328,10328,'徐老师真的超好，平时上课摸鱼听不懂也不用太担心 半期开卷，期末一比一划重点，只要期末肯下功夫背知识点都能取得很高的分数，不过前提是必须要到教室听课，因为老师有时候会随机抽人起来提问，偶尔会点名',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63187741722da6529db559fb',42,42,'期末和平时基本上都拉满了，给分高的不行。明明其他几个老师的打分比龙哥阴间多了，龙哥却一个人独自背负了所有骂名。龙哥被学生错怪被世人谩骂，却依然幽默风趣地面对课堂和人生，他真的😭😭😭我哭死😭😭😭',5,5,5,15,65,30);
INSERT INTO "reviews" VALUES('6318768f722da6529db558cb',351,351,'我女神',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('63186b696095b06986304c27',2323,92,'谢老师平时分超级高，作业只要交了不管怎样都是满分，期末还可以不交，属实很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63186a82722da6529db5467a',1453,114,'重修班老师，yyds，不是王老师就寄了退学了😭，平时没有签到没交作业平时分也给满，我哭死😭😭😭',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('631867646095b06986304771',1855,24,'笑死，好说歹说，上厕所就给你使脸色，上的不自在，平时分给的可以呢',5,4,1,10,0,0);
INSERT INTO "reviews" VALUES('6318556e722da6529db52820',1768,22,'我女神！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('63184ee2747f46052d329176',499,194,'老师思路非常清晰，上课认真，期末复习非常负责，会带着大家从第一个知识点复习到最后一个',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63184cbf722da6529db51a7e',23,23,'绝好的好老师，人超级超级好',5,5,5,15,32,0);
INSERT INTO "reviews" VALUES('63184839722da6529db5142a',228,228,'还好从隔壁跑了',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('63181150722da6529db4bd43',100,478,'人美心善，讲课非常清晰，问问题也会非常耐心负责的回答，期末把要考的知识点讲解了对应的题目，',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6318071f747f46052d322042',4668,6972,'茅院大一上必上******茅院里那么多专业，莫名其妙安排个必选课，而且完全是形式主义毫无实际作用。喜欢致敬茅老是吧？作业还多的离谱，还是早八。只能说茅院的领导真的出生。一个月一篇论文，期末还要三千字以上，格式和引用格式还要求的很严，最恶心人的是给分还不高。课么听名字就知道全是水，论文也只能水，让大一新生一入学就领悟本科论文之精髓，一瞬间就对未来几年的学习生活充满希望了呢',2,2,2,6,3,0);
INSERT INTO "reviews" VALUES('631806c7747f46052d321fd5',264,230,'平时分全班给100的老师！上课也非常幽默有意思，超棒',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('631802fb747f46052d321978',5066,653,'熊大超级可爱，除了喜欢笑着拆模型，人真的超级好，不是那种你一定得听我的的那种老师',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('631777bb747f46052d315e9c',293,375,'课件很老，讲课内容也很陈旧，感觉老师并没有关注很多新的东西，观念陈旧，只有第一节课挺好玩。老师还有点大男子主义。注意有时候上课要签到答题，有三次随堂练习。想水课可以去。',2,4,4,10,6,0);
INSERT INTO "reviews" VALUES('63177685747f46052d315d50',1743,10343,'构成基础，做立体构成。上课是读ppt，然后自己动手画草稿图，做模型。感觉中规中矩吧，感觉老师也是真轻松啊。讲一节课，做两三节课。给分一般。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('631775b2722da6529db3e574',10344,9767,'超哥人很好！专业过硬，认真，人很亲和，基本上有问必答，微信找提问软件也会回，不会下课就消失。为学生着想吧。比如大一教构成基础的时候做了一本纹样的作品集，思路什么的教的很清晰！给分也很高。超哥真的好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63176c55722da6529db3d61c',876,92,'老郑yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6316fb5e722da6529db2e7bc',209,209,'总之就是非常******',1,1,1,3,8,1);
INSERT INTO "reviews" VALUES('6316c739722da6529db299aa',3040,2889,'易倩老师就是交大外院之光！好美好温柔！上她的课好轻松！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6316c448747f46052d30104d',141,141,'给分太低，不把每个东西搞完整，分都不会高',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('6316c405747f46052d300fef',3040,2889,'老师真的特别清和温柔',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('631691ca722da6529db24622',3407,762,'上了两学期亮哥的课，😍 亮哥真的超级好，平时分给满，讲课思路清晰易懂，板书很多，每一道例题都要亲自演算。问问题也很耐心的解答。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('631690ef747f46052d2fbdbe',1883,24,'老师专业水平过硬，上课幽默风趣，虽然讲的有点快，但是思路清晰，听他的课很轻松愉悦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6316903a722da6529db243fe',2819,28,'老师超级耐心负责，有问必答，给分高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63168fcf747f46052d2fbc51',18,18,'春明老师亦师亦友，会提供往年试卷及答案，给分高，讲得好，上课有趣😍',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('63168f40722da6529db242bc',756,22,'老师很好，问问题都会解答，讲的好，得分高，想90+的冲冲冲',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6315c34c722da6529db1106f',1756,52,'平时很严，但是期末捞人平时分拉满，磕一个',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('63155b4d722da6529db06127',23,4181,'真的，霓姐太好了，分也给得很高',5,5,5,15,32,0);
INSERT INTO "reviews" VALUES('631557bb722da6529db05b39',560,3214,'为什么粒姐没有评价捏，双语教学（四川话&普通话），很有意思的家人们，冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('63155548747f46052d2dcb3a',7190,1910,'平时作业不多，老师挺和善的，讲课也不错，不过不是水课会要求上课听讲，而且平时分压分，在其他方向专业课平时分普遍只扣两三、三四分的情况下，这个课平时分最高也不过92、93，平均85。
INSERT INTO "reviews" VALUES('63155463747f46052d2dc9bb',5213,5213,'讲话十分含糊不清，平时作业要做一百年，比别的班要多，然而这是所有专业课老师里平时分给分最高的，如果要保研，建议忍一下。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('6315426a722da6529db03e13',349,194,'神中神 讲的好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6314d16e722da6529dafcd80',100,833,'老师很漂亮，讲话巨温柔，课上的也很好，平易近人，和学生关系也很好，平时分给的也还可以。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6314d0ad722da6529dafcc72',9362,10293,'老师和蔼可亲，人非常好，讲课也能听懂，算是这门课所有老师中中上水平',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6314cfef747f46052d2d45d9',2119,2119,'这门课很难且重要，所以老师可能为了督促学生课下复习，所以上课前十分钟就抽人回答问题。期间简直度日如年，心惊胆战，如芒刺背，如鲠在喉，战战兢，惶恐不安，栗栗危惧，惊恐万状，哆哆嗦嗦。但是老师讲课在这门课所有老师中算好的，也挺负责的，重点画的很准，期中卷出了一些重点，考试最后一节课抽的问题就是简答题本题！！',4,4,3,11,4,0);
INSERT INTO "reviews" VALUES('6314cd5c747f46052d2d4263',803,177,'老师讲的非常好，很清晰明了，是个人都能听懂的那种，作业量中等偏上。目标90+的冲！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6314cbc0722da6529dafc155',14,1978,'老师真的很好，给分很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6314964e722da6529daf5966',14,1978,'不选简直对不起自己，轻松愉快拿到选修学分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('630f3dba722da6529da7d511',1855,24,'虽然课不行，但是不点名，平时分拉满yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('630ee539747f46052d24ac34',2078,23,'一个班一百个人挂了二十来个
INSERT INTO "reviews" VALUES('630de605747f46052d23318d',452,965,'能跑就跑吧，这个老师不好还用什么******系统',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('6309858a747f46052d1cdef9',6994,10120,'老师讲课很认真，语言通俗易懂，幽默风趣。很宽容，尬黑的别叫了。老师很好。给分高。',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('6305c2f4722da6529d9a31e8',16,68,'老师很仁慈，就是会有线上作业，老师不会提醒作业的结束时间，纯靠自觉去做，如果足够自律，老师是一个很好的选择',3,3,5,11,1,0);
INSERT INTO "reviews" VALUES('62fe51c0aec4ae28b5733f6f',2200,2387,'王老师神中神',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('62fe518caec4ae28b5733f29',68,40,'这学期选了她的课，看完评价，好害怕。',3,3,3,9,8,0);
INSERT INTO "reviews" VALUES('62fde7acaec4ae28b5728f61',1480,127,'啥也不说，余志恒yyds!',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62fc806ededc972c208ae064',5471,156,'说话听不明白不清楚，照本宣科，bilibili上比这会讲课的老师多了去了，唉，服了',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('62fb538cdedc972c208946f1',5,114,'老师喜欢自说自话，和学生互动很少，不过给分真的高，作业也不怎么收，适合想水的同学，我就是一学期没听课，最后总成绩60给我捞起来了。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62f78328dedc972c2083ff31',2211,1241,'作业量：作业量极多，粗略估计在其他班的6~8倍，而且大多是考研的题目，作用难度极大而且没啥用。
INSERT INTO "reviews" VALUES('62f1d09eaec4ae28b560f693',10378,38,'大一上刚进来选新生研讨课时选的何晓琼教授的课电气科学家及创新创业漫谈。何教授的课氛围很轻松，就一桌人围在一起聊天那种感觉，还带我们去九里校区参观了国家重点牵引动力实验室，模拟驾驶了动车，参观研究生学长学姐工作，我还玩了一盒液氮，遗憾的是高温超导磁悬浮列车那时在检修，没坐成，建议大家都来选何教授的新生课嗷，可以长见识',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62f1cfa9aec4ae28b560f52a',10379,3167,'老师不愧是东京大学博士毕业，对日本文化相当了解，课堂上会和我们谈很多在日本的经历和风土人情，人也很和蔼可亲，真的学到了很多关于日本的文化知识，就是记得要写作业嗷',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62f1ce9adedc972c207b1832',674,307,'******平时分给我80还好👴🏻考试之前熬了个通宵复习了一遍，但有一说一期末考试真的不难，感谢蜂考嗷',4,4,4,12,1,1);
INSERT INTO "reviews" VALUES('62f1cdf1dedc972c207b1735',281,281,'普通话说好再来教书OK？听课跟猜谜一样，但平时分是真的不错😤',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('62f1cd6eaec4ae28b560f19c',2541,92,'教的可以，就是要自己下去多复习和参悟课本，平时分也说的过去',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62f1cd22aec4ae28b560f145',5,114,'教的******，我同学都比他教得好',1,1,1,3,1,2);
INSERT INTO "reviews" VALUES('62f1cc83dedc972c207b1479',228,228,'感谢马老师的平时分嗷，期末👴🏻考了50都过了，幸好没去隔壁捏',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62f1cc2ededc972c207b140c',18,18,'老师教的挺好的，人也很幽默',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62f1cbe5aec4ae28b560ef66',1162,26,'神中神，平时分给的很高，教的也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62f1cb86dedc972c207b1327',23,23,'西南交大最认真负责的老师，没有之一，我最喜欢的老师',5,5,5,15,34,0);
INSERT INTO "reviews" VALUES('62f1cb38aec4ae28b560ee66',540,540,'老师真的很好，讲课讲的好，对人有耐心，就跟我妈一样。记得有次下课我和同学去问她是不是北京人，还跟我们聊了好久，是我大学第二喜欢的老师',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('62f1caa0aec4ae28b560ed53',4793,4793,'神中神，每次星期五上这门课的时候就到了我最开心的时候，感谢老师期末的复习资料，直接起飞嗷',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62f1ca30dedc972c207b10b8',867,28,'好老师捏，上课经常对我笑',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62f1c9f4dedc972c207b1042',42,43,'逆大天，不过期末平时分给我满分还彳亍，准备背负好一条年轻的生命吧😔✊🔪',1,1,1,3,9,3);
INSERT INTO "reviews" VALUES('62f1c945aec4ae28b560ead2',179,179,'睡就完事了嗷，👴🏻自学的，这门课挺简单的说实话',4,4,4,12,1,3);
INSERT INTO "reviews" VALUES('62f1c8dfdedc972c207b0e83',2119,2119,'老师挺负责的，专业能力很强，讲课很有激情，就是有点严厉说实话',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62ec0da25ba9a90d4c18e4a8',2005,1697,'生命的学生表示，老师有机讲的还可以，考试考原题分挺高，不容易挂科',4,4,5,13,0,1);
INSERT INTO "reviews" VALUES('62e36b1a590c0f6b5b7b92ff',846,27,'李老师真的很好，高级英语事有点多，不过平时分给得很高，上课风格也挺温柔，好想通用学术英语也能遇到这么好的老师，期末前平时分基本拉满。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62e36009590c0f6b5b7b7de2',9120,92,'平时分给的高 需要自学 基本不点名',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('62e21cc1590c0f6b5b799a61',2211,1241,'😭😭😭😭😭😭😭老师授课内容没有逻辑，教得一塌糊涂，上课没几个人听课，全******靠自学，作业巨多时间又紧，但是！！！平时分贼低啊😭班级平均平时成绩都比人家班低二十多🥺壁垒壁垒壁垒，快逃快逃快逃！！！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('62e217d2590c0f6b5b799281',2211,1241,'讲课水平太一般了，几乎没听过他的课，一学期下来就是在找网课。而且作业特别多，特别多，特别多，平时分却贼低，贼低，人家班上九十多，我们班上只有六七十。',3,1,3,7,3,0);
INSERT INTO "reviews" VALUES('62e0ee9e590c0f6b5b77f410',246,228,'给一分都算多的！！！真的恶心人啊',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62dc0d8d590c0f6b5b70fe65',7860,7860,'这老师虽然很水，但是上课回不回答一次问题差别很大，没回答过问题的人平时分只有70几，回答过的人，一次和十几次没有区别，绝对不会关注一下你回答次数多，平时分就高一点，说实话平时分真的不行，上课声音很小，听不清。尤其是，一个免考都不给！人家老师都会给几个免考，就这老师不给，而且给分还低，吐了',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('62d7b1a61b9d1d618f715773',18,18,'6就完了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62d428d25ee85713b0cc29e8',1743,5183,'老师特别好，好的我都不知道怎么夸了😊😊😊',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('62d1596feee31a173e02d114',604,96,'讲课板书，不用PPT，节奏容易跟得上，考前会讲往年真题，并且平时分拉满，凯皇YYDS！',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('62d134f8eee31a173e02901c',803,2387,'超级好 很负责',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62d01932eee31a173e00f22d',1743,5183,'一幅干什么都藏着掖着的样子，生怕学生了解的更多就不能多“锻炼能力”了，16号要交的报告14号才说格式要求；软件怎么用一律不讲，连问都不让问；设计要求模糊不清，标准也不明朗，完全让学生去猜该怎么做😅，这老师完全是有跟没有一样，早知道考完试第二天就回家了。',2,1,3,6,6,0);
INSERT INTO "reviews" VALUES('62cfdc655ee85713b0c5b5d6',1743,5183,'首先，实习群里开禁言，搞的生怕学生会在群里骂她一样；其次，一些关于实习日志和做课设的要求不早点说非要等到最后几天才说，这不是******在搞学生心态吗，我觉得这是她作为一个实习老师的失职；第三，在群里说话的语气感觉就是一副很清高的样子，弄得好像自己很高高在上一样。第四，有同学去问她问题，她还拒绝回答，居然还大言不惭的说要培养学生自己解决问题的能力😅，那你******既然作为一个指导老师却以这样的态度面对学生，那学生要你何用？',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('62cfc1a3eee31a173e005698',3437,3509,'还可以',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62cfbdf75ee85713b0c5836d',954,52,'好的，出了分来二评，四六开的大物1，除了半期，其他平时分都拉满，当然平时作业都是认真做得的基本是A和点名每次都到。看班群里捞得挺多的，应该也是比较仁慈的。讲课水平不太好，表达不够清楚，还经常把自己绕进去，容易跑题说其他的。性格很好，和蔼可亲，补交作业很容易，很少点名，作业就一般的作业，打印下来交给助教评级。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('62cfbb185ee85713b0c57dbc',2535,5043,'你实习摊上他你就完蛋了，想到啥就是啥，不把学生当人，三十多度让我们等了1个小时没来',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('62cfb9daeee31a173e004892',78,78,'******，直接挂三十多个',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('62ce8aae5ee85713b0c3bf51',2078,23,'******给分低就算了，还不符实际，该给的分都不会给******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62cd288c5ee85713b0c1b21a',23,23,'霓姐yyds！讲课超有激情，教学水平高，通俗易懂，很容易接受，学起来轻松，答疑有问必答，处处替学生着想，大爱霓姐！',5,5,5,15,32,0);
INSERT INTO "reviews" VALUES('62cd1df0eee31a173efc6c76',141,765,'老师很负责，课上的很好，也很温柔。给分有理有据。这次平时分拉满，但是想水课的平时分可能不会高。',4,5,4,13,2,5);
INSERT INTO "reviews" VALUES('62ccf79d5ee85713b0c16961',626,306,'郭老师yyds!!!都给我选好吧!!!讲课清晰 认真负责 从不点名 作业也少 几乎不叫人上去回答问题 作业给分高 我四五次大图99 98 下课问问题很耐心的讲解 在QQ上也会及时回复 最重要的是郭老师特别和蔼可亲，课也可以不去上 反正平时分都是作业 选就对了!!!',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('62cc18505ee85713b0bfef57',2437,1954,'老师专业水平还是够的，亲和力比较高，上课爱和同学们说一些学习之外的事.讲课的话我觉得一般吧，有些地方听不懂，但给分还是很高的.老师也特别好，半期说是闭卷，其实你开卷他看见了也只是对你一笑，老师是好老师，可选',5,3,5,13,3,0);
INSERT INTO "reviews" VALUES('62cc17885ee85713b0bfeb51',10416,2280,'老师还算可以，给分比较高，就是这门课从开卷变成闭卷，没有重点可画，期末背的东西比较多，比较爱点名，作业适中，可选',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('62cc16d9eee31a173efac06e',7473,181,'老师还不错，给分也还算高，只是这门课比较水，自己看书也就能看明白，平时只需雨课堂签到，去不去都无所谓',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62cb9eefeee31a173ef9f434',74,74,'到大二为止，最让我无语的一个老师',2,1,1,4,5,0);
INSERT INTO "reviews" VALUES('62cb9dc85ee85713b0bf1b9b',3258,910,'非常非常好！老师很有气质，很温柔，放的电影都挺好看的，强烈推荐！每节课要签到，允许一次不去。平时作业要交3篇600字心理作文，期末写平时看的电影名和电影对你的心理影响这些，可以用手机，轻轻松松96！这么好的课不选是撒子hhhhh',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62cae91c5ee85713b0be3ed0',818,10420,'法学本科有意愿保研的同学注意：今年这门课相比于铁道组，给分严重偏低，建议避开选铁道概论，不然和铁道的同学一拉可能拉个五分十分就很亏了。',3,2,3,8,1,0);
INSERT INTO "reviews" VALUES('62cacde2eee31a173ef8d15f',5357,5357,'磁浮方向的卡密，下午考完晚上出分，肝拜吓疯，给分巨高，作业只有一次大作业，虽然是作业设计论文三合一，一开始被这个吓到过，但是比较水，我同学等级不高但平时分也很高，作业的电路元器件据说还是自费买的，他真的，我哭死，选他，选他',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62cacb77eee31a173ef8cd98',3446,2119,'上他的课像在坐牢，强制坐前排节节课都会点名，缺人就会用他宝贵的三分钟来diss到了的同学，讲课又水的一批，纯纯的ppt教学，最搞笑的是能在网上找到一模一样的你敢信？提高课堂质量的方式是不停地叫人回答问题，只能说老师问的和学生想的毫不相关，然后又会diss一遍，平时分给得算中规中矩吧，布置作业基本就是想一出是一出，可以电子版的他非要手写，然后要求你把手写的拍照上传电子版（论文手写你敢信？），不管你是选修还是必修，遇到王涛劝你最好赶紧跑',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62cac67deee31a173ef8c5c4',7801,7801,'这老师纯的，自以为是，把任务甩给学生然后就啥也不管了，学生问他他还阴阳怪气学生',1,1,1,3,0,0);
