INSERT INTO "reviews" VALUES('62c92036eee31a173ef63b64',3964,80,'瑞哥yyds
INSERT INTO "reviews" VALUES('62c91cd9eee31a173ef63574',1743,5183,'上的机械原理，老师挺亲和，但就是话有点多，天天和我们“考研考研”苦口婆心吧也是为我们好。讲课给三分，有时候会把自己讲晕。上课节奏挺好的基本都能跟上。上课就别拍ppt了，老师很在意把他拍进去哈哈哈，下课他会发的。最后还是捞了，感谢老师。',3,4,5,12,0,9);
INSERT INTO "reviews" VALUES('62c842df5ee85713b0ba4d6a',1606,1606,'老师很好，人格魅力很高。作业会带着我们做，平时分给了95。但是当对于其他班的期末卷面分好像该多少就多少，不会太宽松，会捞及格边缘的人。老师真的人很好，很负责，很认真。没有认真学让人感觉愧对老师。',5,3,5,13,0,3);
INSERT INTO "reviews" VALUES('62c80b935ee85713b0b9ddde',10436,10436,'很好的老师，上课干货很多，几乎不点名，对学生比较放养，给分很高，基本只要提交了期末作业平时分就是满分。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c80ae1eee31a173ef4a113',4668,6972,'很烂很烂很烂的课，每次都点名，事情非常多，且给分非常低！还不停想出新花样，想一出是一出的老师。开学说不考试，写期末论文，结果到了期末又要写论文又要pre还要考试！书本价格非常昂贵，还买不到二手书，期末考试开卷又必须要用，且只用一次！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62c7f1755ee85713b0b99420',5257,2793,'想水可以来，想要高分就算了，别的班课设成绩90+、95+，这个班基本都是85上下，就不懂为什么要控分，离谱',2,2,3,7,0,1);
INSERT INTO "reviews" VALUES('62c79cbeeee31a173ef3aabf',7062,779,'讲课是真不行，平时分给了八九十还算高',2,1,2,5,0,0);
INSERT INTO "reviews" VALUES('62c79c495ee85713b0b8e3a1',45,6778,'快逃！这门课程停开和没人选不是没有道理的，老师心狠手辣，论文绝不能敷衍，上课像******坐牢一样',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62c76501eee31a173ef352dc',10441,10441,'没找到公共政策导论这门课程，就在这里抒发我对严敏老师的喜爱吧。严老师讲课的水平很高，还会给我们介绍当今前沿的公共政策学的研究模型与方法。挺不错的好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c70cbe5ee85713b0b8401b',1909,10442,'****** 只会恶心学生 正事不干 只会搞宫斗 问什么都不回答 只会刁难学生 给1分我都嫌恶心',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62c703b95ee85713b0b8326b',1372,23,'老师授课一般，老师回答学生问题时会阴阳怪气 避重就轻',1,1,1,3,2,0);
