INSERT INTO "reviews" VALUES('62c6b8bc5ee85713b0b7b4ca',7970,1848,'呵呵',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62c6b500eee31a173ef271aa',3577,2642,'游为老师是个认真负责的好老师，希望学生能真的学到东西，但给分不松，而且希望游老师出卷正常点，少考一点很偏的知识点',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62c6b34d5ee85713b0b7aa06',10447,1606,'熊老师yyds，虽然平时分给的一般，但期末真能捞，写了就给分，i了i了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c6b1a55ee85713b0b7a6c6',1606,1606,'事多要求多，给分还巨低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62c6a284eee31a173ef24863',5022,10449,'我上的房屋钢结构。怎么说呢，这个给分还不错。考试挺难的，虽然开卷，但是最后一题来不急。老师给分挺高，比杨老六好多了。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62c6a20b5ee85713b0b780ea',5213,5213,'竟然没人给我林老师评分。这门课开卷。都能找到。给分也还不错。比杨老六好多了。有点名，我两次没到，后补的请假条。希望大家不要缺席。作业很多，每次都是小课设',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('62c6a1295ee85713b0b77eca',1087,10432,'给分低，还不能认识自己的错误。我本来想说的是，希望老师对于平时分能分的更精准一点。上七次课，写七次作业。其他都是A就一个B。每次都去上课，最后平时分88。他跟我扯什么有人A+，问A+是怎么评的。他说看写字，看排版。只能说，快跑。谁来上这个课不是为了保研啥的。分给这么低，拉低了我的绩点。最搞笑是什么，这门课上半学期4、6分，我跟老师说，希望以后给别人分的时候，好好考虑一下。因为我已经出成绩了。我不希望我之后上这个老师课的同学也这样。没想到那老师厚颜无耻的说，会好好考虑，打算把这门课3、7开。当时以为玩笑，没想到下半学期就3、7开。听说试卷也很难。怎么说呢，明明一个学分的课，硬要搞得大家都不高兴',3,1,2,6,3,2);
INSERT INTO "reviews" VALUES('62c69f495ee85713b0b77a5e',7190,1910,'怎么说呢，最后一个大题，没答案就等于整道题扣完。本来开卷，基本都能找到。最后一题直接每分，就等于八十往下。上这个课一定要先写大题。老师给的平时分也不高，全班85😂',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62c6930d5ee85713b0b746a3',2299,760,'读了两年以来遇到的最恶心的老师，平时分给的极低，很是死板，上课水平也差，讲课念PPT，讲例题还会卡顿。基本上每节课点名，为了打考勤，最后一节课上早八让学生自习，教室待了两节课然后点了名才让走。考试周开始考试后还布置作业让学生做并且需要提交，并且布置的作业量还很大，真的不知道这个老师怎么想的，奉劝各位能选其他老师的千万别选这个老师，之前选课时活水上没有这个老师，不知道人怎么样******',1,1,1,3,2,13);
INSERT INTO "reviews" VALUES('62c69305eee31a173ef20954',1017,1017,'你在搜罗琳❓还是琳醬❓还是罗老师❓还是罗皇❓你只需要知道他是流体力学的主宰者👆全能ACE👏可奶可盐的带队老师🤛是老师团队的绝对核心✅出卷的小达人❗一骑绝尘/:平时分给满的存在🙌💝唯一天选💞温柔老师罗琳💘​',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('62c692b15ee85713b0b744e1',1017,1017,'建议自学，建议好好学高数特别是高数下😇😅',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62c6876ceee31a173ef1f012',785,229,'虽然讲话有点连续的，但是人教的很好，也认真负责，答疑问问题都很耐心回答，平时分给满',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('62c686fd5ee85713b0b72cbe',23,23,'很幸运选上她的课，目前遇到过最好的老师，没有之一',5,5,5,15,34,0);
INSERT INTO "reviews" VALUES('62c67e585ee85713b0b71b1b',877,877,'饭饭老师太好了 好可爱 最后成绩拉满',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62c6615a5ee85713b0b6e3f8',873,228,'平时分给的比较合理，如果交额外作业平时分直接拉满，不过额外作业也有篇数/字数/内容质量的要求。
INSERT INTO "reviews" VALUES('62c660515ee85713b0b6e21d',1332,1065,'标哥上课很激情，据说是武大博士。考试复习看书之前，觉得标哥讲课也就那样，没什么兴趣，但是也没那么抵触；看了书之后，标哥上课真挺好的。但是标哥上课其实主要是以学生的回答为主，会有一些互动（但是不回答问题/很少有人回答问题标哥都会不开心，不开心就会说拉低我们平时分）。如果专业清一色的闷葫芦的话，建议换个老师。另外，我这学期毛概平时分100，谢谢标哥，会爱💓💓',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c65298eee31a173ef1897d',828,828,'讲课抽象，全靠自学。
