INSERT INTO "reviews" VALUES('62c5c56c5ee85713b0b61e68',2345,10464,'呃。。上课讲得完全听不懂。。也不建群。。。找她要ppt也不会给。。。。没有什么作业但小测占分非常高。。而且时间随机 点名也是 想起了点一次 而且也不是固定在上课的某个时间点名 请假交假条还要阴阳你 反正总而言之超级无敌不负责任。。。平时分扣得也蛮多。。我不知道那些说给分高的是怎么回事 反正宏观经济学b 能避开就避开吧',1,1,1,3,1,0);
