INSERT INTO "reviews" VALUES('62c560ceeee31a173ef03e41',1175,761,'不点名。班上回答问题有点小卷的，给分不咋高。三次平时作业，包括做PPT（或视频），回答题目，期末考试就是小组上台展示来打分。最后总评90飘过，想学信息检索或者拿高分冲绩点的话可以选其他的老师',5,3,3,11,0,0);
