INSERT INTO "reviews" VALUES('62c54dd7eee31a173ef009b8',5312,5312,'强烈推荐大郭老师的课！平时分拉满，期中考试非常水（其实老师不愿意考试，被迫的hhh），老师上课也很认真，课件PPT也会发给大家，ppt上内容都是精华，没有一个废字。不过这门课确实背的很多，期末复习需要花时间去记忆。老师平常没有任何作业，没有课设，上课不会抽问，为人随和，只有个简单的期中小测验。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62c51e08eee31a173eefa76a',1909,10442,'除了吹牛逼别的不会干了，从来没有站在学生这一面考虑过。',1,1,1,3,0,0);
