INSERT INTO "reviews" VALUES('62c4ebd65ee85713b0b47c19',23,23,'很幸运选到刘老师教学班，不仅在C++这门课上学到了很多东西，也在为人处事方面学到了很多。刘老师教学充满激情，讲解易懂，课后答疑极为耐心，轻松高分通过！美丽、温柔、贴心的老师，太喜欢刘老师了！',5,5,5,15,34,0);
INSERT INTO "reviews" VALUES('62c46a2aeee31a173eeebbb8',74,74,'只能说很不幸分配到这个工测实习老师了，实习任务多且繁琐，所做工作大多都是机械且无脑的，和别班比起来，这个实习真是太让人ex了。',1,1,1,3,11,0);
