INSERT INTO "reviews" VALUES('62c3a393eee31a173eed409e',5824,4047,'老师水平很高，上课十分有激情，看的出来每节课都是精心准备，对待学生认真负责，分给的高，绝对能学到东西。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c3a2e95ee85713b0b26ca9',2251,4577,'赶紧跑，这老师是我大学四年见到的最**的老师',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62c3a1cc5ee85713b0b26972',7274,23,'雨课堂签到，有时候会用教务系统点名。上课比较水，讲的不是很清楚，要学好尽量自学，多做课后练习。平时分基本会给满，作业量也较少。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c3a0b2eee31a173eed38e7',222,222,'无脑冲，张波老师我的神！上课传阅签到表签到，半期考试只考了二三十最后平时分也给满。讲课水平稍微逊色一点，但是人真的巨好。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('62c30f485ee85713b0b1c116',4119,4119,'每节课课前签到，签完到就可以溜了，上课不会抽问，平时没有任何作业，没有期中作业，只有在期末提前给你发几道题，叫你回去做了下周来交，非常水的一门课，分也不错，都是90分，强烈推荐。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62c30ecaeee31a173eec94bf',8080,8080,'老师上课非常有意思，保证让你听的津津有味。每节课都会签到，但是平时没有作业，但是上课经常随机抽问，期末就考一道论述题，总分90+，强烈推荐。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62c30e1b5ee85713b0b1bc00',8645,8645,'老师上课很有意思，很有激情，也给我们经常扩展许多课外知识，治学严谨，上课不准玩手机，开卷考试也很容易。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c30da75ee85713b0b1bb65',5376,4961,'老师经常出差不在，上课从不动粉笔，讲课都是照着PPT和书读，虽然这门课确实没什么需要讲解的，给分还不错，平时分90+。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62c30ce35ee85713b0b1ba50',648,889,'老师平时分高，期末考试的题目重点全部给出，并且考的就是给的52页PPT中的内容，虽然上课讲的很快，听的很懵，但是课设辅导的很仔细，考试也很容易，作业量虽然每节课都有，但都是书上的内容。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('62c2e8625ee85713b0b172cf',10497,10497,'家人们选她，上课有趣，作业也不多，老师本人都很水，但是教得好，期末出题会听学生意见，给分及其宽松，不过好像这个计算方法就这一个老师教，不过这老师就是特别特别特别的好，哈哈哈哈哈哈。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c2d4a15ee85713b0b150fb',6323,23,'老师我爱你',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62c2b92eeee31a173eebf608',2461,2461,'人好心善的老师，特别温柔，很少点名，没有平时作业，给分高，速冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c2b7115ee85713b0b122d8',78,10500,'樊老师不愧为交大复兴之栋梁，严于律人，宽以待己，交大复兴有望了，明年就本升专。',1,1,1,3,13,0);
INSERT INTO "reviews" VALUES('62c2b6c65ee85713b0b12274',78,10500,'****** 说好的二八开 结果慕课期末时间忘了 没做 直接算0分 说好的慕课期末只占慕课成绩的40% 啥也不管直接挂科 一个班挂******三十多个人 真的****** 群也没有 也没有通知考试  没有一点人情味 格局小了',1,1,1,3,4,2);
INSERT INTO "reviews" VALUES('62c2b29ceee31a173eebec3b',2197,876,'我爱他！！！！平时分该给全给了，海底捞',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62c29b22eee31a173eebb9d9',2447,23,'李茜老师我的超人，人美心善的老师。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('62c2767d5ee85713b0b0aa79',2136,313,'这学期的近现代史老师。典型的刀子嘴，豆腐心，上课的时候还说大家不认真，平时分不会高到哪里去，结果一看平时分直接给满。',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('62c263605ee85713b0b0848a',23,23,'刘霓老师讲的超级好，还关心同学，真的是难得一遇的好老师，讲得好人也好。',5,5,5,15,34,0);
INSERT INTO "reviews" VALUES('62c25b54eee31a173eeb474d',1372,23,'态度很差，多个同学找他咨询回复都阴阳怪气，快跑',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62c257b1eee31a173eeb41e9',836,23,'平时分除了实验扣了0.5，全部给满了，直接把期末分拉起来。上课温柔有激情，讲的好，速选！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c24405eee31a173eeb1fbb',78,6991,'逆天老师慕课最后的测试没参加直接打0分，QQ群都不建，就硬水。',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('62c233825ee85713b0b03523',24,24,'小武哥无脑冲！平时分直接拉满，上课讲的非常好，在qq问问题秒回！就是有时候会补课，当然这也是负责的表现！课堂上讲的非常清晰！但玩手机会管你哈，想好好学的无脑冲！ 上课认真听讲下课自己完成作业，期末90+',5,5,5,15,12,0);
INSERT INTO "reviews" VALUES('62c1b4a3eee31a173eea7708',2210,114,'平时分基本拉满，老师讲得更偏向理论，如果没有自学打算别来，如果自学能力不错选他没问题',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('62c1ac4f5ee85713b0af9735',232,24,'一开始我觉得老师的嘴好毒，但是后来发现老师原来人很温柔！！！没见过这么温柔的老师！！！给分也高！！！什么时间都能问问题！！！太负责了！
INSERT INTO "reviews" VALUES('62c1a788eee31a173eea61ca',278,228,'******，多少沾点******，给的平时分是真的低，理由批多分批少',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62c17367eee31a173ee9fd7c',2258,837,'很水，每节课都要签到，上课就是照着ppt念，ppt都是书上的内容，没有额外的，推荐自学。期末没有步骤分，但是平时分很高。',3,3,3,9,3,0);
INSERT INTO "reviews" VALUES('62c171f9eee31a173ee9fac1',8273,4961,'这门课石红国老师37开，其他老师46开，课设分都一样(可能没有看）都是85分，平时分不算高，就80多，但是期末给分很高，没有选择判断，全是选择简答，随便写都是70多，不可能挂科的，上课从不点名，不管你做什么，作业就最后布置一两道，可以冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c1710feee31a173ee9f949',648,889,'老师人特别好，课设90+，期末会划重点，就是上课速度比较快，一看就是备过课的，比其他老师好多了。人也比较平和，微助教随机时间签到，每周都会布置一定量的作业，期中考试会出现一两道期末选择题，冲就完事了！',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('62c16c95eee31a173ee9f132',2984,361,'每节课都点名，课上可以做自己的事。有半期论文和设计地铁文化墙作业，如果文化墙作业排大概前十就可以免考期末。每节课都去，最后免考，给分挺高，90+。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('62c14c8b5ee85713b0aee944',3202,551,'上他的课你不知道在学什么😅',3,1,3,7,2,0);
INSERT INTO "reviews" VALUES('62c07bcd5ee85713b0add517',42,43,'老师今年改观很大啊，并不像他们说的那么恐怖，认真听课，按老师要求做都会给满分的，挺负责的好老师',5,5,5,15,15,30);
INSERT INTO "reviews" VALUES('62c07b285ee85713b0add491',42,43,'老师很温柔 ，会很细致地和你讲实验，比其他不教东西不负责任的老师好多了，讲的很容易理解，给分特别高！',5,5,5,15,4,4);
INSERT INTO "reviews" VALUES('62c07a7e5ee85713b0add3f8',42,43,'平时分好高！！！老师人好好，很热心解答问题，随和',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('62c05712eee31a173ee87663',278,228,'怎么说呢，要求挺多，但完成后分也不低，平时分分值明晰。但这是马原课，比大多数专业课还严，能不选还是不选',2,1,1,4,3,1);
INSERT INTO "reviews" VALUES('62c049225ee85713b0ad7c3e',1017,1017,'1.本课课程难度较高，罗老师上课会用国外教材。他讲的时候也许可能会听懂，但是课下作业难度更高，考试也就是平时作业难度的题目。
INSERT INTO "reviews" VALUES('62c030cb5ee85713b0ad5710',7190,1910,'天天上课吹牛 几乎不布置作业 考完试一两个月不登成绩 然后突然登 平时分巨低 专业课没见过这么低平时分 快跑',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('62c021435ee85713b0ad3fb0',861,6194,'******平时分实验分都给满了，期中出的卷子又简单，平时讲的还有意思，作业也不多，助教姐姐很漂亮。',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('62c0208e5ee85713b0ad3e3c',1105,380,'严老师我的神，温文儒雅，上课讲课又有意思又会说话，处处为学生着想，平时分给满，还会给你讲那恶心的实验（那个实验是真der，******刀哥管的数电是真******不把我们当人），严老师会为了让你过复查卷子，真的我的神，大家冲爆他',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c01f16eee31a173ee81110',1017,1017,'这个课只能选他的，教材100块钱厚厚的一本，外文翻译，连，上课讲课如同念经，个人和******扎克伯格一样，机器人，喜欢玩弄学生，作业又多又难，考试前要个答案解析还不给，说你上课没认真听，ppt也不给说是机密文件，考试出的题简直不是人会的，考试题做错了还要倒扣分，60出头飘过，遭了一学期罪了，终于******上完了，为了想挂人而挂人，你还只能选他',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62c011bceee31a173ee7ee94',4982,4982,'守护人超好的昊哥！讲课很认真！平时分很高！心地善良的好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62c0038e5ee85713b0ad05d5',546,40,'只能说正常偏下给分吧（如果你认真准备她的这些活动的话其实分也不会太难看，平时分能上五十）但是事情确实蛮多，但比起其他三类限选，翻译没有慕课真是太爽了。',4,4,4,12,2,6);
INSERT INTO "reviews" VALUES('62bff914eee31a173ee7c3c3',10529,242,'选他，CAD也给我选他，闭眼选，王枢--我的超人！
INSERT INTO "reviews" VALUES('62bfea915ee85713b0acdd17',604,96,'水的一批，我跟的他概率论，不点名，后半学期我基本没去过，期末给资料，多看看期末考随随便便七十多',5,3,5,13,1,3);
INSERT INTO "reviews" VALUES('62bfc08aeee31a173ee76c05',546,40,'屁事多，给分低，笑里藏刀，快跑！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('62bfb1ee5ee85713b0ac7c7e',9297,884,'(旅客运输组织没上过，想评他的运筹学但没有)陈钉均永远的神，作业少给分高，除了川普没有缺点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bfa7e6eee31a173ee73d35',10533,10533,'神中神，人好水平高',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62bf28feeee31a173ee6a74e',604,229,'讲课有口音，但是就冲着他可以拉满平时分，我怎么的也要给他拉满分数啊…',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62bf28065ee85713b0abd428',7860,7860,'我就第一个评价这个老师的人，那我就全面的说一下我的个人看法，很感谢她能体谅我们理工科的痛，首先近代史是水课，你我老师都知道，因此她没有上课时难为你，但每学期必须要回答一个课堂问题(主动且要计入平时成绩的)，算是比较友好的，上课只要不出格你想干嘛干嘛，每学期都有近代史智慧树视频，必须要看！！占0.3呢，其次期末会给你大题的范围，背了就起码能得30分的大题分数，还是可以的啦，晓得我们上课基本不听但又想要高分的心态，最后她人还是可以的，按时完成一个小组任务，考完视屏，回答一个问题，就可以不挂，想要高分，那么你要下功夫了……就这样吧。最后说一句，她基本不点名……',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('62bf24df5ee85713b0abcfbf',452,965,'我基本对这个老师是一肚子的怨气，首先对于那个nt系统，表面上是严格，其实就是花时间在无意义的改正格式错误，而且她基本都是网课，还要做笔记，上课也是回顾网课的重点，就问你上课90分钟也没干个啥，但她还抽个人回答问题，答不出来各种恶心你，最后十五分钟左右做卷子，还要给分，计入平时成绩，因此平时成绩基本惨不忍睹，我这学期物化基本是废了。遇到这个老师就赶紧换吧，实在是听咱一句劝吧……',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('62bf23005ee85713b0abcc97',6319,194,'老师很好，就看读者愿不愿意学习高数了，老师板书很工整，这在现在的大学中已经很少见到了……让我肃然起敬，老师讲课生动，细致，注意要点。无口音。最重要的是对于平时分只要你认真对待作业上课不缺点名，基本不会给你恶意拉分，甚至期末拉你一把都有可能。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62bf21d65ee85713b0abca92',2646,10298,'选这门课意味着你开始可能会很难接受这位老师的讲课风格，但是只要你愿意去学，还是可以学到东西的，更主要的是作业很少，就是看你愿不愿意多看书而已……平时分基本拉满，这基本已经超过了绝大多数的老师，这不比郝静之类强？',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('62bf1c04eee31a173ee695b1',4081,2598,'平时分会给的比较高，老师长得挺好看的，神中神，平时上课用雨课堂签到。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('62bf04fe5ee85713b0ab91a7',373,230,'平时分拉满就很棒。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('62bf03de5ee85713b0ab8f3e',2202,28,'认真负责，亲切和蔼。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bf02f25ee85713b0ab8c4c',4112,114,'开始听说是四大名捕之一感觉没啥好感，但是架不住他给的平时分实在是太高了，也不点名，作业不交也没事。认真听课的话会发现除了口音重教得也挺不错的。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62bef1eb5ee85713b0ab6399',903,179,'康老师人很好很友善，关键是她是真的会把你捞起来呀。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62beedaeeee31a173ee62e0b',10544,9626,'宁老师人很好，平时作业可以在网上直接找答案，只要作业交了，签到去了，平时分基本上接近满分。老师讲课认真，也讲得清楚。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bee3c8eee31a173ee61b72',309,309,'老师人超级好超级温柔！！除了教课本知识外还讲很多拓展的对我们有用的知识，平时分基本都是90+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bebc83eee31a173ee5dcf8',7459,5368,'愤青，喜欢谈天说地。但课程较水，几乎不点名。期末一篇论文。给分90+。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62bebbf25ee85713b0ab0aff',10547,10547,'每两讲课不同的老师，每个老师的风格和履历都不一样。收获很大。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62beba405ee85713b0ab088f',1949,230,'课程死板，给分低',2,3,4,9,1,0);
INSERT INTO "reviews" VALUES('62beb8015ee85713b0ab046c',10533,10549,'王进老师的专业知识水平很高，认真听她上课可以学到很多。有机化学是一门相对抽象的学科，王老师却总有办法用生动形象的例子将它具体化，从而使学生更好理解。给分方面的话，非常客观，没有夸张到把每一项都拉满，但这些分数绝对和平时的付出程度一一对映。此外，老师看起来比较严格，但私底下会帮助学生解决问题，挺热心的老师，留一个5.0分。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62beb702eee31a173ee5d371',1017,1017,'期末考试考完就报名补考了😅',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62beb647eee31a173ee5d26e',8447,10551,'翁老师是我们这学期综合化学的任课老师，老师人非常不错，唯一一点不足就是讲课讲到关键地方的时候可能会卡顿，需要我们自己去理解，除此之外都还不错，课水，给分大方，作业很少，从不点名。留一个好评捏。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62beaf675ee85713b0aaf51a',10552,10552,'老师人格魅力很大，但是助教是不是有点子毛病。还有为什么不一开始就说是二级制给分🌝壁垒她的助教！！！',5,5,4,14,0,0);
