INSERT INTO "reviews" VALUES('62bd25265ee85713b0a87ca3',3370,228,'上的是形势与政策。每节课雨课堂必签到。上课倒是随便你干什么，别太出格就是。论文给分比较低，很严格。。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('62bd20225ee85713b0a87289',3719,230,'上课随便做什么，老师不会管。给分中等。除了课程本身规定的论文，智慧树网课，没有其他事。还算不错。只点过一次名。',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('62bd1b47eee31a173ee33a31',9627,9627,'点名缺两次，也没被抽过回答问题，课堂表现直接25，分录进去后直接消失联系不到，作业一次3000字，一次1200字，均为手写，作业平均还只给80左右，算下来总分70，无语',2,3,2,7,1,0);
