INSERT INTO "reviews" VALUES('62bc6ee75ee85713b0a794d0',649,36,'老师给分很高，讲课生动有趣，对学生也很好，入股不亏，唯一一点小小不足是不画重点，但不妨碍给分极高，韩老师yyds!',5,5,5,15,0,5);
