INSERT INTO "reviews" VALUES('62bc5b425ee85713b0a771ff',92,92,'平时分给的很高，只要你认真完成作业，按时签到（老师用学习通签到，无定位，平时可以逃课），通常只会被扣几分。老师人很温柔，很棒。',5,5,5,15,0,0);
