INSERT INTO "reviews" VALUES('62bc32ed5ee85713b0a726f4',1066,1066,'专业能力很强，但是不适合讲课，去了跟没去一样，还不如自学，给分还低，******纯纯无语',5,1,1,7,0,0);
INSERT INTO "reviews" VALUES('62bc2be35ee85713b0a71c94',10624,101,'刘老师讲课能力确实不太行，可能更适合研究吧。但是刘老师是那种嘴硬心软的老师，他发现我们过不了的时候，还会私底下找我们一对一解决问题，期末答疑的时候还特意给我们开了腾讯会议就为了讲解得更清楚。总之，刘老师是个很真诚很负责的老师。',5,3,5,13,0,1);
INSERT INTO "reviews" VALUES('62bc29fbeee31a173ee1e895',10624,101,'表达确实不太行，但是！！期末真的会捞，可劲的捞，那天半夜我问问题，还给我开腾讯会议讲。后期接触了他真的超级好！！他和樊明书老师我最喜欢！！',5,4,5,14,1,1);
INSERT INTO "reviews" VALUES('62bc25a05ee85713b0a71242',211,211,'电机学无脑选，王老师电机学就是我爹!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bc23b8eee31a173ee1de7c',3370,228,'老师给分好低啊，平时分，大作业离谱',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('62bc1c3f5ee85713b0a6fd99',542,1170,'上的老师的茶文化选修，只要认真完成作业，高分没问题，我最后综合成绩给了98',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('62bc18495ee85713b0a6f6a1',260,96,'我去！Jesus！谁要学概率论都去给我选他！！！李成刚老师对学术持以十分严谨的态度，同时对学生持以十分宽容的态度！旷课三次以内不算旷课，讲课时会非常清楚地告诉你什么要考，只要每次按时上课按时交作业（作业量还好），不搞小把戏，考试作业都看态度，态度就代表着平时分拉满，50％谁敢信。老师效率也极高，还会结合你的专业知识来授课。给我冲！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bc16965ee85713b0a6f404',260,96,'平时上课的时候可能阴阳怪气，但是给分真的很高！！！作业和点到也是，只要不超过3次都打满，平时测验也是不看成绩！！！只看态度！！！冲冲冲！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bc14565ee85713b0a6f013',2007,24,'除非你是自己会很自觉地学的人，否则就快跑吧…',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('62bc11f9eee31a173ee1bcc8',260,96,'只要不缺席超过两次，平时分给满，期末考试也会捞人，我愿称之为神中神',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62bc11dfeee31a173ee1bcb0',674,307,'老师讲的好，人也很好，但是给分真的低，出题就按照自己班上的标准来，在我看来是属于为难其他班',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62bc0cd25ee85713b0a6e16e',264,230,'闫磊老师知识渊博，待人亲和，尊重学生自己的选择，这才是我理想中大学老师正真的风格。考试前画的重点，出乎意料的全是考点，考试途中我才后悔没有早点发现，以至于最后才刚过及格线，幸好老师没有相煎，最后平时分基本没减。总之闫磊老师是一位上课好，格局大，给分高的好老师！！！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('62bc0be2eee31a173ee1b022',264,230,'上课节奏偏慢吧，会分享一些自己的经历给同学，课堂氛围比较轻松
