INSERT INTO "reviews" VALUES('62bbb2c9eee31a173ee0eb7f',5803,230,'感觉老师还不错啊，除了常点名之外，上课也水，不用答问题，期末会给大题的范围，背了就是原题，难道是最近换教学方式了？没有底下评论说的那么差啊，平时分95，期末也90＋',4,4,5,13,0,2);
INSERT INTO "reviews" VALUES('62bbaf635ee85713b0a6183c',6106,68,'退退退！上个职场英语快把命送了，比专业课还忙，每周都有作业，一学期四五个小组作业，好几个presentation，给分也就一般般，天天上课就是讲自己的事迹',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('62bb97825ee85713b0a5ee7c',3895,1520,'哈哈哈大舌头保江哥，人很随和，好说话，除了实验其余分数都基本能拉满。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62bb24015ee85713b0a57974',264,230,'真的是宝藏老师，人好，讲课好，给分高，给我冲！老师很温柔，很体谅我们，想听课的话坐前面听他讲得超好，知识渊博，想做自己的事情他也不会说你，真的超好！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bb23ae5ee85713b0a5792a',499,194,'讲课很好，作业少，平时分拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62bb115ceee31a173ee02c1e',5803,230,'不行，完全不行。刚开学跟我们吹自己多牛多牛，一上课好家伙原形毕露了属于是。不如改名叫电影鉴赏课算了您。平时******贼多，最后一排不能坐人，堂堂课都要点名，你讲的认真也行啊，放个视频自己都快睡着了。被请回来的是吧，不愿意讲是吧，那走啊你，别搁这儿混了行不行。最后期末更是重量级，你要不要看看你在做什么，画的重点就考了一点，全班近三百人平均分五十八不及格合理吗，嗯？',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('62bb10d85ee85713b0a55fb7',5803,230,'除了放视频就是吹牛皮
INSERT INTO "reviews" VALUES('62bb10175ee85713b0a55e6f',451,36,'老师挺不错的，平时讲课也很认真，但是有点口音。最重要的是不点名，分给的也可以。',4,3,5,12,1,2);
INSERT INTO "reviews" VALUES('62baf4c0eee31a173edfec48',2267,177,'全校最******的老师没有之一，自己把一大堆人的实验报告弄丢了还不承认，考试周要人重写实验报告，离大谱',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('62baefe6eee31a173edfe3ab',1377,26,'非常客观的来说，彭小春老师平常没什么要求，作业偏多，点名手机上面签到，大一上学期很摆烂，但是期末复习了一下，老师还是捞人的，他一个学期有两次小测，非常难受，但即使你考得很低，老师期末在小测上面还是会给你一个可观的分数，这次临近期末还一直给我们录视频答疑，直接泪目，太负责了。如果你没有一个最佳选择的老师，就选小春，再见了高数😘',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62bae3675ee85713b0a506b5',311,1514,'老师人很好，给分高，养身课很好玩，特别是那个祈祷🙏🏻哈哈哈哈',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62bae1745ee85713b0a50441',2205,6022,'给分抠门，事情多',2,2,2,6,0,0);
