INSERT INTO "reviews" VALUES('62badce5eee31a173edfc4a9',696,698,'后辈们，相信我，大三你会回来骂他的',1,2,1,4,2,0);
INSERT INTO "reviews" VALUES('62badce0eee31a173edfc4a2',1265,1265,'客观评价一下，我每次作业认真完成，全勤，每周一次作业（别的班一共就四个大作业），前几次作业均分85以上，最后作业总分只有82，（算起来最后大作业不到80分，我的水平突然就下跌这么多？）并且，有一次她展示优秀作业评分9.5，结果大家一看发现是抄的网上的😅，然而我认认真真自己做只有8.5。上课没人发言，一半时间在点名回答，然后大家课堂分都低👍。最后说成绩压了三次了还给高了🤭，找她理论，她说是合理的，并且不给你看成绩小分******。',1,1,1,3,10,1);
INSERT INTO "reviews" VALUES('62badc66eee31a173edfc3ff',2205,6022,'事儿太多太杂，课设给分确实很迷',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62badc3eeee31a173edfc3aa',696,723,'不开玩笑，小平是真的好。这么久了，就没见过哪个老师考了期中都给你把平时分拉满。大一我也觉得小平在******乱讲，作业也多。等你大二你才知道，小平有多好！！！！如果学弟学妹们选数据分析与计算这课，请能选小平选小平吧，你如果选wy，你这学期可能需要一生去治愈🙏 年少不知小平好，错把wy当成宝！',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('62badb61eee31a173edfc1f2',696,698,'年少不知小平香！！！！平时分直接拉满还不满足吗？？？？期末考二十就过了！！！年少啊孩子们学到后面才懂，只要不挂科就是胜利！！！微助教题都给你了！！！跟武昱比起来！！！小平就是天使！！！别骂了孩子们！！！小平真的比起其他专业课老师已经好太多了！！！！！',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('62badaff5ee85713b0a4fa29',696,723,'年少不知小平好，上了wy的课，才知道qxp有多好，qxp平时分给满，有qxp就别选wy！！！！！',5,5,5,15,1,0);
