INSERT INTO "reviews" VALUES('62bab5c6eee31a173edf7fee',5803,230,'教的什么东西，电影鉴赏课吗（没有说那些影片不好的意思），第一堂课先吹自己教学水平有多好多好。接下来的课程节节放电影，水的一批，啥都不讲，讲的也稀里糊涂扯东扯西。平时分压的贼低，期末考乱改，班级五百个人一两个上八十，其他都特别低，认真背也没分😅。划的重点没考几个牛死了。',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62baa55beee31a173edf5e4a',1738,2349,'崔老师讲课很棒，脾气好。能参观校史馆，一整门课只用做一次ppt汇报和几百字的期末论文，不缺勤给分还是挺高的。',5,5,5,15,1,1);
