INSERT INTO "reviews" VALUES('62ba89fd5ee85713b0a46977',1600,96,'骁哥yyds！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62ba892f5ee85713b0a4682d',1,1351,'大一入学的工图老师，真的特别特别特别好，楼下说作业多可能是空间想象力不太行，其实课后题真的不多，就是比较难，没办法，工程制图就是这样一门学科，在我看来比高数线代概论加起来都难，不过不要紧，陈老师确实很耐心，真的不容错过，我不能忍受如此优秀的老师却默默无闻，大一有陈老师在我真的在这门课上省了很多心，对比其他工图老师实在是体贴到不行，兄弟们别犹豫了！',5,5,5,15,3,2);
