INSERT INTO "reviews" VALUES('62b988f05ee85713b0a2f9b7',3202,551,'老师人挺好，可惜讲的不好。期末会捞人的。',4,3,5,12,1,1);
INSERT INTO "reviews" VALUES('62b9889e5ee85713b0a2f942',535,535,'老师人很好 讲课只要认真听就可以跟得上 平时问问题也很耐心的解答 不管多简单的问题都会解答',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('62b98814eee31a173eddbcfa',2012,1753,'我真的好爱符爷！！！我滴神！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b988135ee85713b0a2f844',2172,2172,'我服了，期末考试说的给公式，结果一发卷子，人傻了😅😅不给公式可以提前通知，而不是考前说要给，结果又不给当阴阳人😅😅差不多得了',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('62b985e05ee85713b0a2f4fc',278,228,'事儿多分少，大家赶紧跑，******老师，谁不跑谁脑瘫！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('62b985785ee85713b0a2f44a',545,433,'平时分给的巨低，不努力拿不到高分，严谨但是迂腐。',1,1,1,3,12,0);
INSERT INTO "reviews" VALUES('62b9759f5ee85713b0a2d8bb',1168,228,'老师巨好，平时分拉满，一定选！期中考参加考试直接给满分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b974685ee85713b0a2d697',1093,1638,'春梅教高数，期末直接海底捞！给差评的不知道是在干嘛，成绩今天才出的',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('62b973915ee85713b0a2d4e2',1377,26,'客观点说吧，彭老师还是挺认真负责的，考前一天还给我们录视频答疑（有点小感动的），但上课确实不咋样，有些甚至不如自学。高数一二上完，给分只能说是铁面无私小包公（几乎不捞人），平时分不像其他老师那么，几乎给不满（甚至还没你卷面分高，如果你想冲满绩，还是趁早润走）。小测难度是有的，是周末找个时间在教室里隔开位置考，用不了手机看不了书，助教管的还挺******（有次让我们一半人都能抄错题目），有些题目是作业册上的（但改了数据，算的更烦），简单来说就是小测一次折磨一次。',4,3,3,10,1,1);
INSERT INTO "reviews" VALUES('62b9737ceee31a173edd9a38',7295,309,'给分很高，上课方式能让你很好地掌握，能认识每个人的脸，。期末考出卷人，懂得都懂～真的是非常好的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b972c25ee85713b0a2d3ac',188,188,'给分巨低 除非没得选不然别上',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('62b972b45ee85713b0a2d387',2202,28,'神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b97055eee31a173edd94b9',96,96,'这个老师的120人优选班只有一个人选，可以一对一授课，真是太好了捏',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('62b96d94eee31a173edd8fe0',2167,2270,'这老师笑嘻嘻的******希望大家多多来加入这个老师的课程一起坐牢。',1,1,1,3,0,2);
INSERT INTO "reviews" VALUES('62b95a89eee31a173edd688a',2012,1753,'直接吹爆！上课讲的超好，而且期末一个一个地捞人，平时分能给的直接拉满，期中考试也向上取整，符伟yyds!',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b959dceee31a173edd6714',9882,22,'老师讲的挺好的，人也挺幽默，就是作业不是交了就有分而是真的按得多少分算多少分的，上课喜欢让人上去写题加平时分',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('62b958b25ee85713b0a29f36',9443,909,'上课好玩，给分很高，选就完事了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b958455ee85713b0a29eae',563,228,'快跑',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62b957ebeee31a173edd6110',4925,4925,'老师主业单口相声副业教书，上课真的很有意思，基本上是我大学生活里听的最认真的几节课之一了，节节课教室人爆多，需要早去一点占位置，期末交论文，给分会比其他选修课低一内内（不过也应该是我期末论文没认真写），想上90还是要下一点功夫的，强推！能抢上直接抢！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b956c55ee85713b0a29c72',40,40,'老师人确实很好，但是英语确实事情很多，给分低，上课不怎么管可以想干啥干啥',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62b9487feee31a173edd0b75',499,194,'大一上的李老师的课，平时讲课很清晰，也会讲习题例题课后题，平时分拉满，期末还有个附加题。这是我到现在为止唯一一个很喜欢的老师，课讲的好，还给分高！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b947335ee85713b0a24621',3065,140,'不好，平时分很低很低，70多',1,2,1,4,2,0);
INSERT INTO "reviews" VALUES('62b93dbf5ee85713b0a23913',373,619,'一学期大概点了2次名，期末会发题库，平时有题库作业。没回答问题，做了作业，平时分一百',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62b93a825ee85713b0a234ba',10378,10715,'别选事多，平时分还很低',1,3,5,9,1,0);
INSERT INTO "reviews" VALUES('62b92fd0eee31a173edce67a',788,9950,'有一说一只要你不是特别摆，每个英语老师其实差不太多（除了避雷那几个），这个老师给分55+，平时上课也还可以吧，早八有时候打瞌睡去了…就回答几次问题，作业稍微上那么一点点心，但是有一点严格，有一次作业过截止时间交的要给扣分呜呜呜求情也没用…',5,5,4,14,1,1);
INSERT INTO "reviews" VALUES('62b92bceeee31a173edce0d8',867,27,'老师人很好看炒鸡温柔耐心～只要作业认真做上课稍微回答几次问题50++稳了！总之冲就完了～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b9283d5ee85713b0a2183f',1441,228,'很好很通情达理的老师
INSERT INTO "reviews" VALUES('62b924f4eee31a173edcd12a',1612,619,'平时分直接拉满，但是上课是真的水。一节课看半节课视频我也是醉了，抽到人回答问题答不上来还要调戏一番，der。期末没重点，平时看视频，复习考试全在天意。
INSERT INTO "reviews" VALUES('62b918e25ee85713b0a1f890',4306,517,'平时分高，老师好，就是游泳馆经常不开。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b916e75ee85713b0a1f5f2',228,228,'随便回答几次问题平时分就能拉满，免考也很简单，几乎不点名，作业检查也很水',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b90f4beee31a173edcaae2',5388,23,'给分很高，可选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b8f8ee5ee85713b0a1c065',867,28,'挺好的，平时正常做，稍微回答点问题分数就上去了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b8bd235ee85713b0a18848',24,24,'认真负责，给分极其客观且高。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('62b8bab6eee31a173edc4800',442,442,'******，给分低，上课水，作业多，喜欢嘲讽别人自己又没有那个实力，给分真的******，这个老师是我大学遇到的******的老师，所有老师只有这个老师给我这种哈皮感受。',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('62b89d9eeee31a173edc33a3',2961,761,'老师人挺好的，认真学能学到很多东西，就是不适合太水，偶尔会点名，小组一共要做了6个ppt（只要小组不水就还好），最后拿了100分',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62b891195ee85713b0a16329',2139,2140,'这个老师极端易怒，极端自私，极度冷血，重男轻女，对女
INSERT INTO "reviews" VALUES('62b890f85ee85713b0a16302',278,228,'很好的老师，平时一次课不去，作业一次不交，期末考试不去最终成绩90+ 很宝藏的老师，那些乱踩的都是怕你们选课和他抢，一定不要相信，冲就完了',5,5,5,15,29,162);
INSERT INTO "reviews" VALUES('62b88e645ee85713b0a15fed',2139,2140,'别选，选了就是不幸，给分极低，还暴躁易怒，学生问什么都会阴阳怪气回去，真的别选，上她的课及其影响心情，有时候还会故意在课堂上点你阴阳你，有人问问题就会暴怒。总而言之别选就对了',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62b8861c5ee85713b0a153ad',1622,1622,'林妈妈yyds！林妈妈喜欢海底捞！（两个层面上都有⊙∀⊙）',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62b83fe95ee85713b0a0becf',1017,1017,'可怕的不是你要上他的课，而是只有他上这门课',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62b83f1deee31a173edb8218',8080,8080,'课堂很有趣，想水课也很容易',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b83e4f5ee85713b0a0bc93',603,603,'真是绝绝子，全班平时分都五六十也是没谁了，比隔壁班作业多一倍，还要求写规范读后感。给分巨低，卡人59分不给及格，大雷快跑。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62b83d89eee31a173edb8001',9196,335,'这肯定是满分捏，张老师说话又好听，讲课又有着重点，四学分的课也只用去一半，慕课又很简单，还会指导一些竞赛，当然不是强制的，机械专业课本来就难一个班机械设计只挂两个',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b83b99eee31a173edb7c46',3407,762,'亮哥闭眼冲就对了！讲的好问问题及时回，平时分按要求就会拉满',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62b83445eee31a173edb719e',10195,223,'给分超高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b832625ee85713b0a0ab25',10671,68,'每次作业都给模板对着抄',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('62b830eceee31a173edb6cd8',1265,1265,'我稍微从我的角度，自认为中肯的说一下我评价的理由：
INSERT INTO "reviews" VALUES('62b830e9eee31a173edb6cd6',2139,2140,'这个老师极端易怒，极端自私，极度冷血，重男轻女，对女生态度极差，虽然对男生也没好到哪里去。你问任何问题都会她都会直接破防直接开骂，你加她QQ问问题她会直接把你删除拉黑。她会在QQ群把你禁言还疯狂@你让你回答她的问题。
INSERT INTO "reviews" VALUES('62b8304c5ee85713b0a0a833',6087,9073,'楼上关于通讯原理的说的很对，平时的课后作业写出来需要复变函数与微积分的知识，虽然开卷考试但是看期中考试那种应该会有计算题，然后考前着重看了（没学复变函数看着我真的有点痛苦），结果期末计算题就考书上一道例题，真的是气死了，这课只有这一个老师跑也跑不掉，只能是把我们的情况陈述出来作为大家平时学习复习的参考了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62b82dd85ee85713b0a0a44d',3267,3267,'唐老师对大四学生还是很仁慈的，不像隔壁某老师对考研的学生百般挖苦，唐老师非常支持考研的学生，整门课程作业只用写一篇文献综述，翻译一篇外文文献，并且打分也很美丽。期末考试是闭卷，但是唐老师给的考试范围都考了，只要认真背了就能高分过。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b82bc85ee85713b0a0a16b',10742,10742,'上的课是电影学概论。作为一个数学专业选到人文专业课的学生，李老师让我惊为天人，从来没有见过这么水这么好过的课，当初为什么选这个b数学专业……总之就是上课从不点名，考试简单到逆天',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b81e2beee31a173edb50e8',16,68,'是真的水啊啊啊，我直接上了一学期电竞课。但是要会水分，平时有任务放聪明点，课堂表现随便念一念平时分不就来了么。最后一节上机考试还给我们发糖，实属不错。对了，会固定座位，也就意味着别逃课了，不过无伤大雅，建议前两节课去早点抢个后排之后就永久固定了（后排一学期电竞课啊什么概念）',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('62b81cebeee31a173edb4f01',1332,188,'标哥就是这么个激情澎湃的人啊，不懂为什么有人谴责他。老师课前每一次洪亮的“上课！”都让人瞬间清醒，这学期的课堂形式完全是反转课堂，回答的太草率可能会被说，经典“我不是针对某个同学”，哈哈哈其实我觉得挺好的，他又宰不了你何必和他计较呢。从每一次同学们回答后老师的评价中能看出老师无论是水平上还是课前工作上都很有内容和思想。后期可能是看到好多同学没有发过言就说纸质的也算了，三次即满分。一学期会不定时点三四次名，但通过本人实践发现只要不是从没来过教室基本都会不计较。最后我只想说标哥yyds',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('62b81ab05ee85713b0a08653',10745,793,'跟他上了两个学期的课，第一学期电工不点名，讲得不错但是不会给ppt，最终的平时分还ok，听说会捞人。但是第二学期电子开始签到点名（可能是迫于学校要求）这学期给了ppt但是最终平时分一般，可能是由于某黄姓实验老师太恶心。作业一般都是书上课后题，有些很难，而且答案也是错误百出，所以说作业还是要费点时间的。另外第二学期老师是先出平时分紧接着解散群再出成绩，应该是没有捞。所以有点阴晴不定，不能完全指望老师，一般别太过分及格都没啥问题。',5,3,3,11,2,0);
INSERT INTO "reviews" VALUES('62b818e8eee31a173edb47e5',68,8881,'1分都不想给，非常喜欢阴阳怪气人！过场多，事不少，但给分还算可以',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('62b81211eee31a173edb3cf2',211,211,'电机学无脑冲好吗，教的好平时分给的也高，平时上课氛围也好，冲浪达人属于是，也很有耐心回答你的问题，期末前答疑次数也多，是个非常认真负责的老师，爱了爱了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b81201eee31a173edb3c7d',211,211,'没有电机学这个选项就在电子市场调研这里评价吧。老师电机讲的很好，平时分拉满，除了慕课不能改平时分其余的平时分全部满分，一分都不扣。老师上课气氛很活跃，几乎不点名，不管你是想划水还是想认真学选它就对了。老师的笑容有点贱贱的，经常坐在课桌上讲课哈哈',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62b811a15ee85713b0a0784b',211,211,'点名少，教的也很好，平时成绩拉满，本人属于比较懒的，平时成绩就扣了0.8分（按100分算的），期末海底捞。谢谢老师！！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b80fb85ee85713b0a07546',211,211,'王老师的电机教得很好，期末给分也高，除了一次慕课的一次作业我忘记做了，其他的平时分都满了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b7f5d3eee31a173edb0d98',876,92,'挺有趣一小老头，平时分一般会给满，但是上课不认真听，真听不懂',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b7f5145ee85713b0a04890',344,1135,'不可多得的好老师，上课不让睡觉玩手机，但是课堂上确实能学到东西，期末还会帮同学准备复习，相当负责任，对学生友善，有耐心。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b7ea8f5ee85713b0a039fa',4081,2598,'中国好老师！！！老师人很温柔讲的还好，平时分全拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b7e88deee31a173edafb7f',9627,10754,'（相对其他选修课）明清小说，个人觉得给分很一般，点名多，作业要写的字多。我全勤参与，作业认真写，最后总成绩才81？？这不纯纯牛马课吗，还有人选明清小说？不会真以为能修炼文学吧？赶紧跑吧，别怪我没劝你',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('62b7da37eee31a173edae53c',9984,2815,'赵老师教超级好，也很好讲话',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b7d5055ee85713b0a018d9',10745,793,'平时分不高，期末不会发复习资料，期末成绩登完就解散群聊。建议选隔壁何圣仲，平时分高，期末总结知识点，还发题。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b7d3de5ee85713b0a015fb',5,114,'真的水，上课讲的什么东西',1,1,1,3,1,2);
INSERT INTO "reviews" VALUES('62b7cf515ee85713b0a00c13',8955,8955,'快逃！！！大学第一个上课上得度秒如年的课，大作业一堆需要编程的上课根本不讲具体编程，实验课助教不用话筒根本听不见在说什么，上理论课说话含糊不清语速还很快，不坐最前面根本听不懂。感觉老师自己有水平吧，但是不会教书还硬教真的很让人难受。哦对，课程群里说的一些话还有上课时候一些评价实在是带着一些偏见以及情商不太高。期末考范围不说重点，大题安排90分却不说具体的类型。真是绝绝子。',4,1,1,6,6,0);
INSERT INTO "reviews" VALUES('62b7cf43eee31a173edad06b',976,5,'吴冲老师还是相当负责任的一位老师，但是线代确实挺难的，老师上课进度会比较快，一定要认真别走神！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b7c76c5ee85713b09ffe45',250,561,'众人皆醉他独醒，喜欢指点江山，还搞点地域歧视
