INSERT INTO "reviews" VALUES('62b66e165ee85713b09e12d2',7344,1073,'石琳老师是个好老师!上了她的高数1高数2。讲课清晰流畅，作业量也适中，在练习册勾一部分题来做。人也比较亲切，专门也设置了每周答疑时间。因为自己课堂上状态不太好经常打瞌睡，经常是下来还得自己看PPT。石老师PPT也做得简练易懂，题型典型，由易到难，所以掌握得也还不错。上学期石老师甚至没有随堂测验，只要每次课堂小作业交了就有分。这学期有随堂，虽然考得很差，但老师还是适当加分，给分还是相当不错的。',5,5,5,15,1,0);
