INSERT INTO "reviews" VALUES('62b4988deee31a173ed62871',8290,8290,'赵川老师真的是大善人，平时作业任选一个写就行400+，期末六选四（300+*4），课也能水，基本不管在做什么，鼓励做pre，给分较高。老师对学术诚信要求很高，禁止抄袭。点名的话，如果下节课要点名，这节课会说。',5,4,5,14,0,0);
