INSERT INTO "reviews" VALUES('62b3ff5d854b19631f023a6e',10671,68,'确实是牛马老师，给分巨低，上课喜欢恶心人，你需要回答问题才可以得到平时分，一般来说，他的平时分比别的老师低5-6分左右。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('62b3e57f854b19631f021353',209,209,'谢老师，打分打的巨高，只要你实验报告写的比较多（实验原理多写点），然后期末考试也不是很难，他会给你很长时间去做，分巨高，平时的实验报告97分的都有好几次，就是平时检查数据时比较凶。',5,5,5,15,4,62);
INSERT INTO "reviews" VALUES('62b3d8cb854b19631f01d6e5',294,294,'贼严格，逃课必被抓，事最多，什么都要求格式，上课不能玩手机，讲课非常尬还没什么用，上了跟没上没区别，还动不动就说自己在国外教的怎么这么样，教的那么好回国干嘛。最关键的是平时分给的还不高，简直天坑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62b3c3fc854b19631f017ca4',10671,68,'我遇到过最******的老师，真不想说什么，之前上课说好utalk是十分，后来看我们全班utalk分都太高了，然后要到期末了，把utalk改成5分，这波操作，我觉得这老师人品不行。上课也总喜欢吹牛B******，别人班课堂表现都会给个基础分，这老师要求一次背很长一段对话，才能得一分，没背就没分，真的无语。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62b3b77a854b19631f016354',449,3822,'啥啊这老师平常和和气气的，给分就这么点？事情还不少，小组作业一堆，请的助教跟大爷似的去查分他还烦了？你在烦什么？无语',1,1,5,7,5,1);
INSERT INTO "reviews" VALUES('62b38d0e2868ff10f63b3ef1',1265,1265,'项目分69作业分84怎么说给我平时分上七十五不过分吧，课堂表现直接给我一手65强行拉到70，谢谢你yxl，让我******英语要期末考满分才能上八十，谁选谁倒霉，看人下菜碟的******老师',1,1,1,3,5,1);
INSERT INTO "reviews" VALUES('62b2de9c854b19631f004756',2424,2178,'如果你愿意像一个学妹一样追着老师问问题，赵老师会像一个学长一样帮你解决。
INSERT INTO "reviews" VALUES('62b2dd10854b19631f00452b',2167,2270,'1、老师挺好的，真的蛮好的，就是说话气人（声音深沉）
INSERT INTO "reviews" VALUES('62b2db93854b19631f00428f',1332,1065,'疯狂（褒义）
INSERT INTO "reviews" VALUES('62b2db1f2868ff10f63a5981',2173,2173,'特别好，童叟无欺',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b2db012868ff10f63a5949',2598,2598,'优点：上课比较系统，由浅入深，上课富有挑战性和趣味性，老师很有耐心，感觉比较有亲和力。
INSERT INTO "reviews" VALUES('62b2d9102868ff10f63a565e',101,114,'小书书超可爱！讲课很有趣！交大宋浩yyds',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b2afd4854b19631ffff6e7',7435,10848,'这个老师我选她真的是倒霉啊……总之这个老师的课不是水课，平时分和期末占比严重不符，平时事多，有十个赏析，都要写，加上期中才占0.3真的是烦，期末就一篇文章，如果你自认为文采可以就上吧，不可以还是算了，我认认真真写的文章才只有83.5分，给分一点也不考虑同学的感受(也就是不能水的！！！)基本在这个班也就85左右的均分，yue了',3,1,3,7,1,1);
INSERT INTO "reviews" VALUES('62b2acb02868ff10f63a0acb',1265,1265,'作业什么的都尽可能好好写了，但到期末给分还是好低，啧～',1,1,1,3,7,1);
INSERT INTO "reviews" VALUES('62b2a113854b19631fffe164',826,26,'平时分给的很多，作业只要不是做的太差就没问题，老师亲和力也很强，就是这个川普有点听不懂……',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('62b29c4f854b19631fffda08',7295,309,'大家嘎嘎选他，给分贼高人贼好，就是上课会有点紧张，其他完全OK！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b29adf854b19631fffd816',228,228,'作业不算多，只要好好完成就能拿到分。平时分高。',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('62b291cf2868ff10f639e001',541,27,'优选班选到苗妙班上的话，恭喜你选到了一个好老师',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b2862c854b19631fffb2fc',3286,3286,'第一次英语平时分这么低，平时事情特多，作业一大堆甚至有时候还临时加作业，哎 避雷啊xdm',2,2,3,7,1,0);
INSERT INTO "reviews" VALUES('62b2794c2868ff10f639b42b',449,3822,'老师人确实很好，但是为什么平时分这么低???',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62b271412868ff10f639a93f',1994,241,'把水课提到早八，说是为了严格要求自己和我们。节节课报数点名，不让你睡觉不让你做作业，不让你坐最后一排，不让你玩手机。把水课上的比正科还严的第一人，一个词形容：crazy！',3,3,1,7,9,0);
INSERT INTO "reviews" VALUES('62b2686c2868ff10f6399ce7',2139,2140,'这个老师极度自我，望小心',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('62b25b44854b19631fff7074',756,22,'好老师 认真负责上课有趣 qq上会积极地回应你 无脑选',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62b25aee2868ff10f639883b',541,28,'好老师 上课水 从不点名  事情不多 除了课程组的就没有额外作业 很负责加分什么的会反复加分 还给我早到加分过 ，口语考试给我分数很高，上课回答过问题就会有很好的印象 想拿高平时分的直接冲就好了 我也不知道会不会捞人 但是勤勤恳恳想拿高分的同学在她班上分数不会差的',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('62b252d8854b19631fff65f1',2861,394,'点名多，偶尔抽人回答问题。期末重点划的很多。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('62b1f426854b19631fff156b',4986,28,'平时分没期末分高太真实了 上了四个学期英语之后回头看 真是恨死何大吉了 给分低的一匹',3,3,3,9,3,0);
INSERT INTO "reviews" VALUES('62b1ef502868ff10f639218e',5357,5357,'划了重点，给了题库，给分还高，董老师，我滴超人！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b15a462868ff10f6381711',68,40,'我就是那种英语能力好受她待见的学生，平时分基本拉满。但我还是想说，这个老师是真的不行，有条件赶紧跑。业务水平也许还行，但表达起来让人基本听不进去，语气让人非常不适。而且她是真会对学生人身攻击，师德堪忧。大学的英语课本来就别想指望学到真东西，而且这门课尤其无聊，如果再摊一个糟心老师实在难受，有条件就速润，哪怕换一个一般般的老师也比踩雷强。',3,2,1,6,5,1);
INSERT INTO "reviews" VALUES('62b156572868ff10f6381166',9133,980,'贾老师专业性很强，能学到很多有用的知识。但是他很喜欢让学生替他干活',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b154492868ff10f6380de6',1481,1481,'很好的老师！！不光专业能力强，还会给我们分享很多她的人生经验。真希望可以一直上她的课。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b14fec2868ff10f638072f',1481,1481,'很好，活学活用的典范，风趣幽默，非常喜欢她的上课方式，可以学到知识以外的东西，比如学习方法。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b14e92854b19631ffdf11f',449,3822,'认真的吗？任慧老师人还是不错，但是这个给分认真的吗。所有的作业都认真完成了，而且分还不低。结果最后平时分比我室友报的别的老师的低5、6分？',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62b14d3b2868ff10f6380373',449,3822,'******给分很低，助教不通人情',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62b13f00854b19631ffdd55b',1535,230,'老师还是不错的，认真写一下平时的大作业基本平时分都会给的比较高，有时候会点名，建议还是去一下，毕竟五分谁不想要呢',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b13dba854b19631ffdd32f',1390,433,'还不错，可选择！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('62b13c63854b19631ffdcf6e',23,23,'超有爱的老师！讲课有激情，很容易听懂，有问必答，霓姐yyds！',5,5,5,15,39,0);
INSERT INTO "reviews" VALUES('62b13a2b2868ff10f637dd30',9650,10872,'贾老师真的是上大学之后遇到的最好最温柔的老师了！！真的会鼓励你去做你想做的设计，这学期才意识到原来做设计没有那么痛苦，真的很喜欢贾老师呜呜呜，希望以后还可以跟着她做设计。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b136122868ff10f637d7d2',546,40,'课程安排极其不合理，她每节课上课之前要喊做练习。5分钟的时间通常要翻译15个句子，就是英专生都做不到吧😅 这个还是要计分的。作业还麻烦得要死。总而言之快跑，我们这几个班都被她坑惨了。',1,1,1,3,12,1);
INSERT INTO "reviews" VALUES('62b135ca2868ff10f637d774',499,194,'特别好，逻辑清晰，语言表达流畅标准，声音洪亮，态度之类的也很好。总之是很推荐。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b13399854b19631ffdc1f2',10671,68,'不点名，常常上课在慕课发布选择题当点名，非常看重慕课和口语作业完成情况并公开处刑。分数中有一项5分是背对话（平均一人一千词左右），一次一分，五次拿满，最好找个搭档，不然就和老师面对面背书。
INSERT INTO "reviews" VALUES('62b132942868ff10f637d294',4016,10876,'老师上课点两次名，而且提前会说。上课很水，比较少叫人起来回答。老师人很好，不会为难你。期末考也是写自己的感受，都是主观题，超级喜欢她，家人们快冲！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b128fb854b19631ffdaeaf',118,126,'肖老师数分功底扎实，课程紧凑。小测和考试给分很严格，想做数学的同学能得到严格的数学训练，不过不喜欢数学的话可能有点痛苦',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('62b1276f2868ff10f637bdd3',10878,10878,'能感觉到老师专业水平很高，人也挺好，但是作业很多，每周一篇4000字的论文外加教材习题，给分主要看助教但是也不怎么高',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62b127502868ff10f637bda1',278,228,'这么多人评价，好评率为0，你要相信不是偶然的。能别选她就别选吧。',1,1,1,3,26,1);
INSERT INTO "reviews" VALUES('62b125a2854b19631ffda959',546,40,'别选！面善心狠，给分很低，做的再好的大作业都给你挑出来一堆毛病，说你不符合要求然后给一个巨低的分，汇报当场问问题刁难你，做个作业比答辩还刺激。班上的平时分都很低，登完平时分还把群禁言，是怕学生不服气吗？？？平时会经常提问，每节课点名，作业也多，总之别来！',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('62b1239e854b19631ffda532',2654,40,'班里整体情况不知道，六十的总分，我们组都四十八以下，我同学其他班五十都嫌低了……',3,4,4,11,1,0);
INSERT INTO "reviews" VALUES('62b10d28854b19631ffd7c41',807,862,'好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b0a9a72868ff10f637339a',2713,2713,'🤤 王老师真的很好捏讲课超棒人也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b01d3d854b19631ffc25ac',8096,23,'老师很好，平时分较高，回答问题很耐心，不点名',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b01cf8854b19631ffc255e',326,419,'good',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62b01ca3854b19631ffc24ee',913,913,'英语白名单第一名，人超好，课堂宽松',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b0177a2868ff10f6362fd9',68,40,'这老师确实鬼畜，我只能说第一节上课就给我雷到了，“我们的发言按次数计分，发一次言大概0.05分，上学期有同学发言了23次我才给的满分”我人傻了，总共10+周的课发言23次是学生讲课还是你讲课。火速润了。
INSERT INTO "reviews" VALUES('62b0153f2868ff10f6362b8e',1441,228,'免考资格都比其他班多是什么含金量啊',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b0150d854b19631ffc1630',3895,1520,'超级无敌好！！！！上课从来不点名，他说“你们来上课是给我面子”，hhhh，讲课也很好，会告诉我们哪里需要掌握，作业布置的也不多',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62b00656854b19631ffc00c2',467,92,'老师人确实挺好的，分给得很高，除了期中期末靠自己外其他全部拉满。另外老师也很好说话，ppt资料都是有求必应，也会认真解答同学们的疑惑，甚至工作到两点。但是讲得挺让人昏昏欲睡的，这只能靠自己学一学了。',2,2,5,9,3,0);
INSERT INTO "reviews" VALUES('62b0017d2868ff10f6360e69',2012,1753,'符爷yyds',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62b001282868ff10f6360dbb',1633,10892,'很难',5,5,1,11,1,0);
INSERT INTO "reviews" VALUES('62aff7c42868ff10f6360015',803,1111,'考试真勾巴费劲。还不捞人',3,3,3,9,1,13);
INSERT INTO "reviews" VALUES('62aff1b1854b19631ffbded6',10,10,'老师人特别负责，对于我来说她讲的内容也特别容易理解，上课也很有活力。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62aff132854b19631ffbde32',1158,26,'娟娟yyds！！！像妈咪一样亲切的老师🥹🥹就算问的是傻瓜问题也会特别耐心的给你讲！我爱娟娟🥹🥹🥹',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62afe59b2868ff10f635def3',68,40,'呵呵，我就是被人身攻击的同学。我真的很想站起来和她怼，被怼到自闭，还好碰到好的组员，一直安慰我，我一直忍了一个学期，她是我学习生涯中遇到最差劲的老师，没有之一，我需要改进的地方你说问题就好了，我努力改，如果我的英语很好，那还需要老师吗？至于把我说的啥都不是？对老师本身来说有什么好处，英语不太好的别选，真心话。对英语很自信的可以试试',1,1,1,3,7,1);
INSERT INTO "reviews" VALUES('62af584e2868ff10f6353a07',1175,27,'压分',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('62af56292868ff10f6353805',315,40,'我不知道为什么讲哲学 平时分还给这么低 受不了了',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('62af52db854b19631ffb2005',1513,1513,'老师的课还不错，期中期末都是论文，然后上课有的课题会应景带猫猫狗狗来教室，就是点名看概率了，她是直接点了没在缺勤的当场上教务网，教务网的学业预警可以查到记录，很多人就缺了一次就中招了，她是不挑时间随机点名的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62af5203854b19631ffb1e55',51,1346,'老师真的很棒，可挺水的，我的意思是给分高，她给题目两人一组做ppt上去演讲，是先是有很久准备的，也可以不脱稿，老师平均都打90+，然后想要考研或者出国的要高分的可以考虑上这个课，然后期中就是这个ppt，期末就是随便给一张试卷，走个过场，不需要多少字因为老师根本不会看最后直接给打上九十多的高分，唯一缺点就是从头到尾的课都点名，每个人都点到，不能缺勤，缺勤会扣分。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('62af4b6d854b19631ffb15b1',627,627,'崔宁伟老师对讽刺学生有一种病态的快感，以言语折磨虐待学生为乐趣，以嘲讽学生为己任******',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('62aeb94b2868ff10f634314f',1390,27,'老师很亲切，会及时提醒你任务，平时分也给的挺高的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62aeb886854b19631ffa1ef8',887,23,'老师讲课调理挺清楚，认真负责，你不会的在qq上问她也会很快就给你解答，事情也不算多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62aeb7b6854b19631ffa1dfc',433,27,'事情有点多，喜欢分小组做任务，上课水也不怎么管你，每节课都点名',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62aeb711854b19631ffa1d23',2202,28,'真的超级好的老师',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62aeb633854b19631ffa1bc6',499,194,'李老师我的神！讲课好，给分高，必选！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62aeb3a62868ff10f63429a1',372,5,'老师人巨好 小测错了好几道都是九十多分 而且回答问题特别及时 你不会她就一直解释给你听',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62aeb2b7854b19631ffa1730',1168,228,'讲得很好，认真听真的能学到东西，当然不听也不会管你，事少的同时又很负责',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62aeb268854b19631ffa16cf',16,68,'事少，任务布置干净利落，不懂的直接问。上课水，该讲的讲完就行，不像别的老师那么多事，还给课堂时间做作业，上课可以回答问题拿点平时分，不回答也没关系。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62aeaeee854b19631ffa1241',44,249,'快跑，有多远跑多远，分低的离谱',1,1,1,3,2,0);
