INSERT INTO "reviews" VALUES('62ad03ce854b19631ff75bc1',4986,28,'爱死大吉老师了，很温柔的一个人，上课很爱笑，虽然作业不是很少，但也不多，说实话，她的作业你都能够水过去，平时测验都是以前做过的题，只要背一背答案啥的，测验很容易高分。，上50分轻松的，说实话，我英语不是一个很好的人，但是我英语平时分有56分，比我寝室许多英语比我好的人还要高。而且他巨能捞人，上学期有几个差八九分没及格的，都让他及格了。我觉得真是人美心善，',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('62ace731854b19631ff72e3f',1705,1241,'讲课很有趣的，点名比较少，上课睡觉也不管，作业也少，但讲知识深入浅出，想好好学的话是个不错的选择，如果你想水，期末也会尽可能捞捞你。',5,5,5,15,0,0);
