INSERT INTO "reviews" VALUES('62abd084854b19631ff56d66',826,26,'流利的川普我真的爱！虽然一开始听着有点困难，但坚持一段时间就发现芬芬真的太可爱了！讲课认真细致，复习面面俱到，是真心希望学生学好考好！每次板书满满当当，写得满手粉笔灰，芬芬yyds！真心想听课想学高数的同学选她！',5,5,5,15,0,0);
