INSERT INTO "reviews" VALUES('62ab16d8854b19631ff4782f',315,40,'马老师虽然课挺水的，讲课也奇奇怪怪，英语课讲成哲学课(她也承认给我们上了一年的哲学课了)上课如果愿意接受她的观点，会上的比较开心，重点还是平时分给的高，期末登记还会给每个人适当加分。总结，想了解哲学可以去她的课，顺便学学英语。',5,5,5,15,5,2);
INSERT INTO "reviews" VALUES('62ab1262854b19631ff4712e',1017,1017,'******上课用的外文翻译的书。不是很好理解。上课用的ppt也全是对着书上抄一遍，所有作业的答案不会发给你复习，你问他他就说让你上课好好听（会讲作业题），他反问你为什么课后不问他题。结果课后问他根本不理人。没有任何复习题，即使有也没有答案。自己做完一遍根本不知道对不对。ppt也不发电子版，让你自己去打印。赶紧溜每节课点名。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62ab11a92868ff10f62e7321',264,230,'知识渊博，眼界开阔，他的课堂轻松活泼，老师本人非常幽默有趣，在群里聊天也和我们学生一个样，没有代沟；虽然上课用PPT，但从不照着念，肚子里很有货，一旦开讲便滔滔不绝，是个非常有料的好老师，可惜只上他一个学期的课',5,5,5,15,22,0);
INSERT INTO "reviews" VALUES('62aaf0e1854b19631ff43809',23,4181,'虽然还没有考试 但是真的想表白刘老师！！太贴心了！',5,5,5,15,36,0);
INSERT INTO "reviews" VALUES('62aaf0df2868ff10f62e3c0d',8384,230,'这位老师很有意思的一个地方，课程上完考试也考了，他就在群里说“那我待会就把群解散了”，然后有的同学就在群里“啊谢谢老师，感谢老师老师辛苦啦”，老师说“这些话就不用说了，我马上就把群解散”虽然课是水课，但是听听文院老师上课还是挺有意思',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62aaedf6854b19631ff4314c',10962,2,'祝兵老师真的很棒一个老师（博士生研究生导师），上课有趣，点名不清楚，一般都是助教在APP上面弄的签到，他能教你很多课上学不到的东西，传道受业解惑。只可惜考试安排很多交给年轻老师，他的本意是，书上找得到的东西，都不用背其实，但是安排考试的老师要求闭卷考😢😢',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62aadcc0854b19631ff40f71',3275,3275,'各种实践 又要跳舞又要弹钢琴后面还每节课考勤 想水别来',2,2,2,6,0,0);
