INSERT INTO "reviews" VALUES('62aad28a2868ff10f62dfa21',1826,48,'大三上的他的体育健康课，人很好，慕课只要做完了分都很高，课程前四周是逛校园，后面有很多神奇的小比赛，不过不管名次如何得分都不低',5,5,5,15,1,1);
