INSERT INTO "reviews" VALUES('62a97df70534fd5ba0cd8ecc',7295,309,'任何人不选他我都会伤心的！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62a97d97e3c0de5dcad21345',1441,228,'真的很棒，老师讲的也很好就是语速有点快，总共留了一次作业一次小组汇报，作业是感想，偶尔会点名，想水也可以，想卷一下免考也可以。而且回答问题不管回答对不对都会算积极回答问题给你加分😂 
INSERT INTO "reviews" VALUES('62a97c80e3c0de5dcad2120a',2074,3017,'只能说一般般，不理解为什么要把mooc线下做，小组作业也是互评，大家都分普遍不高，感觉老师生怕我们拿到分一样。有时候还会叫我们起来回答问题，有时候签到要一个人一个人走到她跟前去签到。不喜欢，还老是让我们拍视频，不理解拍视频和学英语有什么关系',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62a97bc20534fd5ba0cd8bbc',8453,26,'喜欢的是真喜欢，讨厌的是真讨厌，反正我喜欢这个老师，非常的牛皮，上课不用ppt,各种推论和式子全在脑子里然后直接写在黑板上',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62a8b6f40534fd5ba0cc8354',247,27,'铃响后几秒内进的教室也算迟到，直接扣平时分
INSERT INTO "reviews" VALUES('62a88a19e3c0de5dcad0bbc4',8955,8955,'2分给的是老师实力，老师水平肯定是够的，无可挑剔，但是上课的感受对于那些对计算机相关不感兴趣的同学来说实在有点痛苦了，就是压力压力，Python的实际操作不会有过多指导，主要靠自学，一个作业认真做会做很久',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('62a8897c0534fd5ba0cc33a0',2074,3017,'老师人挺好的，平常考的东西怎么说，不用死记硬背，比起其他班老师考的就是课本里的，更灵活，上课也比较和蔼。比如口语和MOOC的更多的就是上课讲到的或者不是靠偷抄能抄的，比较公平。
INSERT INTO "reviews" VALUES('62a8781de3c0de5dcad0a21d',14,1978,'超级温柔，从来不点名。最后作业有一个分享，分数也超高，随随便便90+。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('62a8780fe3c0de5dcad0a211',14,1978,'特别特别特别温柔的老师，非常注重学生的感受，我们当时不强制点名的时候一节课都没有点过而且期末给分特别高',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62a877af0534fd5ba0cc19c4',1021,228,'平时分超高，三分之一及以上的都满分。虽然平时事情很多，讲课也很枯燥。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('62a8776de3c0de5dcad0a14a',1021,228,'上课比较严，作业也不少，但是最后给分真的很高啊 直接一个黑转粉的大动作',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('62a8773fe3c0de5dcad0a109',1320,40,'好温柔的老师，对于社恐来说太舒服了，也真的学到了东西。平时分也给的不低。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62a876dfe3c0de5dcad0a0b5',1320,40,'真的太喜欢了，美女老师讲话温柔，平时布置作业也很为学生着想，业务水平也很高，纯纯自来水',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('62a86dbbe3c0de5dcad09044',2074,3017,'老师人还行，就是给分很低，粗略估计这学期星期二的3个班总平时分没有一个人上55的（54可能也没有）。平时作业很多，慕课、4个口语录音作业、1个PPT展示作业、2个视频拍摄作业、期末口语考试。相较于其他视听说班，作业多的离谱。刚开学没说慕课怎么算分，直到导出成绩了后才说视频时长也算分，所有人都大无语，没一个人慕课是满分的。想高分的，水的快跑！！！！！！！',2,3,2,7,0,1);
INSERT INTO "reviews" VALUES('62a8542f0534fd5ba0cbe232',542,1170,'这分给的是真低 水课中的水课还能给这么低的分 建议不选呢',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('62a81e7be3c0de5dcad014d9',2298,2792,'天天觉得自己水平可高批评这个批评那个，也不看看讲个课讲成什么样子了，******前几个周的作业你到教室了突然说收就收？我******吗？听见这个******的声音我就想吐，有用的就讲10分钟然后尬******两节课，下周就考试了你把全班喊过来听你介绍******研究生，你是怕没人选你当导师你要当绝户头了吗？你不是******？还说自己觉得活水没用，批评大学生光想选水课，你有那个能力教好知识吗，赶紧注册个号跟我对线',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('62a7f5e90534fd5ba0cb3e06',199,199,'守护世界上最好的潘潘！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('62a7f5380534fd5ba0cb3ced',6087,9073,'上了她的通信原理，讲课声音小，念PPT，下课之前会突然让你做几道题交上去，这些也就算了，最让人无语的是半期考试，考课后习题不说，班上一大堆同学都抄习题全解那本小册子，，她也说了禁止抄袭，嗯，是的，我就相信了，希望她能做到最基本的公平公正，于是咱就没看答案，不会的题也是没做，最后整了50多分，我周围那些抄答案的都是80+或者90+，行吧我忍了，结果她上课的时候居然说“看答案也不是不行，但是要自己思考”，我******？？？这不是欺负老实人吗？？？再加上期末开卷考，直接对老实人降维打击，送你俩字，别来！',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('62a77b32e3c0de5dcacf3dba',278,228,'******才选她的课，我是******。一学期下来所有的课程要求都完成了，平时成绩给******30分。不让骂人的话我无话可说。最后强调一遍，这老师是重修启动器',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('62a7634d0534fd5ba0ca9b71',2231,256,'人确实不错，期末还会划重点，他自己说考试还会捞人',5,5,5,15,3,0);
