INSERT INTO "reviews" VALUES('62a6c61be3c0de5dcace14d6',504,5,'杨老师上学期教我高数一，平时分除了半期以外全部给满。点名采用手机签到形式，一学期没点多少次。每周额外线上习题课。讲课ppt结合板书。认真负责的好老师，快选！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62a6b754e3c0de5dcace0025',360,360,'对黄老师不做什么评价，就喷一下学院写的算法实验的教材，实在是垃圾！排版垃圾！代码可读性极差，代码的水平我看也很烂，我都怀疑是故意的！里面的错误很多，有没有人审核过？',3,3,3,9,7,0);
