INSERT INTO "reviews" VALUES('629b8cca0534fd5ba0b9d466',3814,3814,'专业能力较好。能教会你书本以外的很多东西，但他的关于学习之外的理论，乍听之下极为正确，没有自己主见的同学很容易被带跑，他会有意拔高自己，刻意打压学生。他会经常用他的那套标准去吐槽学生不够踏实。他看人很片面，揪住一丝错误会重复提，所以在他的课上你会听到他不厌其烦提及以前学生的错误。选课的同学，请一定要保持自己的判断，不要被其所左右。',4,2,1,7,1,0);
