INSERT INTO "reviews" VALUES('629a1cfee3c0de5dcabc5c23',1243,1243,'常老师课下人挺好的，但是上她的课简直是折磨，没有一节课想听。作业布置多，课又讲不懂，作业跟课的难度天差地别，考试画的重点不考，平时分还低，还喜欢阴阳怪气学生。连着上了三学期常老师的课，痛苦了三学期。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('629a1bd3e3c0de5dcabc5aa6',1955,194,'高中老师，感觉被折磨了一学期，没见过还要找学委要其他课成绩的，布置作业催作业跟上小学一样，高中老师都没你事多',1,1,1,3,0,17);
INSERT INTO "reviews" VALUES('6299c8000534fd5ba0b7460f',542,1170,'照本宣科，开的课一半像僵尸样读ppt，一半放不知所云的视频（甚至只是湾湾综艺节目似的视频，但凡看过点资料都能听出是有吹nb成分的那种），一个搞化学的跑去讲茶文化，因为没听过一种茶查都不查，******看标题是个不认识茶种直接砍掉我一半平时分，占70%的平时分！给我整笑了的是别人直接抄的《茶经》都给了九十分！
INSERT INTO "reviews" VALUES('6299af7ce3c0de5dcabba991',2,11031,'上学期选的岩土工程课设，登录成绩前一天才通知哪些学生缺了一点图纸，上午说好让寒假回去好好改改，下午就登成绩0分，找他一点都不理。听说毕设中期的时候也挂了人，大四学期忙的话慎重选他的课，如果想在岩土方向有所建设，请随意。',1,1,1,3,0,0);
