INSERT INTO "reviews" VALUES('629823360534fd5ba0b4d927',8541,28,'廖老师人真的很好，平时给分巨高，测试的时候只要你别太过分（明目张胆用手机）偷偷用，他不会管你，上课很幽默，想着法给发言的同学加分',4,5,5,14,1,0);
