INSERT INTO "reviews" VALUES('62963189e3c0de5dcab67779',7995,11039,'老师看着有点严厉，但是严谨负责，解答也很有耐心。讲课一级棒，真的是从理论的源头的开始讲，逻辑和条理清楚，知识点融汇贯通，功力深厚。就是平时作业有点多，学起来要下功夫才对得起他讲的课。小荣哥yyds！',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('6296302e0534fd5ba0b1f3ef',270,4406,'老师挺温和的，有时候也会开玩笑，要求不严格，零基础也合适。上课以外交流不多，要求大多通过班长传达。期末无考试，有一论文要交。课程当做运动锻炼挺好，也有拉伸和简单舞蹈内容。瑜伽垫和练功服一学期费用大概一百吧。',5,4,4,13,0,10);
INSERT INTO "reviews" VALUES('62962e180534fd5ba0b1f093',836,23,'老师太棒了，讲的超清楚，完全跟着节奏走不费力，课后多练练题就行。人也温和耐心有趣，基本不会生气。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62962cc90534fd5ba0b1ee8b',2399,230,'讲的超棒，专业知识一流，人也很有趣，不补作业听三连讲也不会困，跟在b站刷历史段子一样。
INSERT INTO "reviews" VALUES('62960f0be3c0de5dcab63201',733,335,'他的机械设计课程设计事情多，要求高，给分还巨低，和其他老师相比真就费力不讨好，快跑',5,3,1,9,3,0);
