INSERT INTO "reviews" VALUES('62958a68e3c0de5dcab54cbc',6398,1196,'第一年开MCU原理及现代电子系统，老师画了重点且开卷，可能是怕我们玩完。不知道以后会不会画以及会不会开卷。老师表达能力欠佳，但是人不错。有较好单片机基础的同学，上课可以划水，没有的可能比较痛苦。',5,3,4,12,0,0);
