INSERT INTO "reviews" VALUES('629585cbe3c0de5dcab5455d',1105,185,'老师水平很高，表达能力强，听得懂。下课好好复习作业都会做，但是课是真的难，好好复习高数，尤其是各种微分算子。懂不懂十年最难电磁场挂科50%的含金量？',5,5,5,15,1,0);
