INSERT INTO "reviews" VALUES('62935ee30534fd5ba0ad9c9a',1265,1265,'峨眉校区来的老师，之前活水上没有她的名字，当时没多考虑就选了，谁知道作业比其他老师教学班的多很多，要求屁事也比其他班多很多，上课回答问题从不等人主动举手而是问完就抽人点名，有些时候都不知所云，有些时候布置作业要求也讲不太清楚，总之体验非常的差',1,1,1,3,8,1);
INSERT INTO "reviews" VALUES('62902654e3c0de5dcaac59e1',1600,96,'真的是很好很负责的老师，马骁老师的概率论是我大学所有课程里学得最轻松最舒适体验感最佳的一门课程。终于有人在意我是不是听得懂跟得上，在意同学们的作业多不多，在意全班同学有没有真正掌握知识。平时上课跟上作业都做了期末就能九十加。他风趣幽默，和蔼可亲，平易近人，真的很不错！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6290249a0534fd5ba0a7d609',485,40,'人美课水给分低，安排不好时间总喜欢课前发任务，说不清楚事情，总之有点不靠谱但还差不多。',4,1,5,10,0,0);
