INSERT INTO "reviews" VALUES('628470edd2d0536a27eef2dd',1732,7616,'上的她的离散数学，呃，一般般吧，这课本来就是照本宣科的……讲得还比较细致。会评讲习题，答题套路还是讲解得比较细致。作业也还好不是特别多。不严厉',3,4,3,10,0,1);
