INSERT INTO "reviews" VALUES('62653c2096549b175e2a1439',4702,4702,'我是实际上上的课程名称是有限元分析，课本用的是铁道机车车辆结构分析。听了半节课就听不下去了，本身课程内容就抽象，而且老师讲课还过于跳跃，也没有好好做引导，逻辑不清晰（至少我们听上去是这样的），导致跟上老师的讲解难如登天，能够一直保持盯着黑板就已经很厉害了。
INSERT INTO "reviews" VALUES('626516f094a0b36151272b3e',7970,1942,'从日本留学归国的精英老师，大忙人一个，设计课九点半以后就见不到人了。关键词：阴晴不定、pua、“我在日本的时候”。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('62651181cfa11057e8c6be08',3502,7517,'我只想说，如果他都能教这门课，那我怕是这门课的专家了😅😅😅，这样的水平都能进西南交大教书，地理信息专业前途无量啊👏👏👏。最后，真诚感谢同学、教科书和浏览器对我这门课学习和答疑的大力支持，也感谢我自己，居然有这么大的自学潜力😅😅😅',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('626508a294a0b36151271baf',3502,2559,'只能说:快跑。老师上课自己都没学明白GIS，一个学分的课讲了0.2个学分，留了四个学分的作业。0.2个学分告诉你今天按着哪节的教程做，提问完你问题之后说觉得你不是自己做的是抄的。老师学的不明不白，有问题就喊你百度，或者自己百度找个没什么用的链接给你，不然就是喊同学给你看一下。给的数据用不了问他怎么解决他回一句找用得了的。总的来说用半学期早八啥都没学到还做了四个学分的作业真是血赚呢',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('626503cecfa11057e8c6af3f',3502,2559,'没上过这门，上过冯老师的地理方法应用blabala，也是讲GIS。老师教学能力有目共睹，主要靠ppt、百度、谷歌、同学互助学习课程。老师很讲究细节，比如作业格式，例如：首行缩进；很有怀疑精神，怕你作业不是自己做的；老师很重视他交的课，毕竟每节课都要长长的实习报告要做。
INSERT INTO "reviews" VALUES('6264ec94cfa11057e8c693b2',7801,10432,'好，自学起来十分的轻松，佛学大师，上课自己开始摆烂，休闲必选，自己评价是深入浅出，帮人解答问题自己不会，牛的，上课必点名',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('6264cc0096549b175e299b7b',1087,10432,'上课不如蔡老师，课件不如蔡老师，但是还算可以把。
INSERT INTO "reviews" VALUES('6264125196549b175e288828',1542,1796,'快跑上课要抽人',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('6263e643cfa11057e8c51f87',294,294,'快跑！快跑！快跑！这个老师上课只干三件事：念QQ群消息（我不知道这是哪个神奇动物发明的），读课文，让同学讲ppt然后强迫全班挑刺（最常见的是大小写）。如果你真的想学习，我建议不要选她的课，因为什么都不讲。如果你是来水分的，那更不要选，她毛都不给你。',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('6262530696549b175e2647f9',2637,40,'老师人很好',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6260091594a0b36151207d1b',334,562,'让好多人挂了',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('625cd4ea96549b175e1ebd9b',2124,2124,'******第二次交个作业，平时要拍照，而且那药材做到后面拿也拿不到，又有2k字论文期末还有考试，一选修课事搞得这么多真让人无语，关键拿不到药材下了课留下问老师能不能拍个五分钟，人不让，叫你下次再来拿，真让人无语，要不是选课系统周三关早就把这课退了',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('625cd41ccfa11057e8bbc078',120,120,'以上三项都很好，但是我对这老师要求很不满，期中考试读两本书简单评价二者的不同，其中一本就是她编的，要我们去买来读，凭什么？还说啥你们都是负担得起这30块钱的，为啥偏偏要买你编的书？难道你没有读者吗？我对此很不满，一个选修课交了钱还有附加投入，这没有任何意义，整节课雨课堂微助教换着平台叫你回答问题，能烦死人，但是整体上老师的课堂还是很有意思的，老师人也很好比较好说话，但是以上两点设定极其不合理！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('625c347094a0b361511b4cf9',2603,11132,'冯老师的法规课就是永远滴神！是本科阶段最喜欢的专业课！冯老师讲课富有逻辑，体系完善，非常清晰明了。而且深入浅出，举的例子很生动形象，能很好地辅助理解记忆。冯老师人也超好，温柔和善，很细心地回答大家的疑惑。虽然每节课点名还有随堂小测验，但是很轻松就能过。冯老师的课值得！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('625b76a596549b175e1cf7ac',8383,1904,'每节课拖堂我是真的无语，刚开学说什么选了清华大学的教材，结果讲了一大堆课本好多都没有，最最讨厌的就是拖堂！点名倒还好，每节课拿表格大家传着签到',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('625aa84794a0b36151193c7d',1649,1649,'其实吧，专业能力，表达能力，亲和力都很好，但就是不想给好评；因为我觉得关于课设这方面老师还不了解学生实际水平以及学生对于小组任务的厌恶，会布置做一个实际东西出来，而且每周小组交进度报告，还有半期进度汇报展示，一堆东西，感觉她出发点是好的，但是缺乏对学生真正的了解，有点自我感动的意思；事情比较多，还开设每周答疑时间，其实就是固定半小时做传感器作业（这个时间点新布置的，必须立刻完成），比较偏主观话，类似于“你对XXXX有什么感受”，反正我这样一个工科生实在不喜欢写这种东西。',3,3,3,9,8,0);
INSERT INTO "reviews" VALUES('625981ab94a0b3615117ce12',10671,68,'职场英语作业都还蛮麻烦的，代老师这个人还挺好的，能学到很多很受用的知识的，男版郝静太过分了，代老师比郝静友好太多太多太多了',5,5,5,15,3,0);
