INSERT INTO "reviews" VALUES('62597eea94a0b3615117cae6',10497,10497,'快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选快选',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('625922e396549b175e19e970',8955,8955,'底下那些好评是靠当初其他老师的平时分打的满分拉起来的吧，新一届这懂得都懂，大部分人平时分据其而言只有六七十，绝绝绝绝绝，上课度分如年，讲话含糊不清做稍微后面一点点根本听不懂，Python不会带做，大部分人安装和导入文件都有问题然而并不管，疯狂提问，如果你有疑问还会被反问，不会就是说以后每节课都提问你，专业水平我就不质疑了，但是就是不会教，真的不适合教，搞科研去吧救命，不是每个学生都那么聪明的，实在是让人感觉莫名其妙，我宁愿选邱小平，一下子心目中变得和蔼起来了，起码你站起来不会也没关系，作业平常也不教，明明机房能投影，让我们看一下怎么操作学一下不更好吗，一个个教又嫌',4,1,1,6,7,0);
INSERT INTO "reviews" VALUES('6258d19bcfa11057e8b690fb',294,294,'屁事很多，动不动就要打回重改，并且老师教育方法有问题，表扬较少，批评很多，很打击人信心和积极性，做pre的无论是好是坏都等着做完在台上被人挑刺然后批评十分钟，最后给出一个不认真的结论吧',3,2,2,7,2,0);
INSERT INTO "reviews" VALUES('6256d91a96549b175e1747dc',4543,3369,'张宇老师人很温柔很耐心，强调对经典案例的分析，并且会带我们学习案例，在网上问他问题的时候也会很快答复。并且很有才华，会拉琴。总而言之，张宇老师是一个认真负责的好老师，为什么会有人说他是伞兵呢？每一个老师都有不一样的风格，相信学弟学妹们能在张宇老师的指导下学习到新的东西。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('62564c7bcfa11057e8b383da',954,2724,'老师人挺好的……只是讲大学物理的这个教学水平……太一言难尽了，约等自学。',2,2,4,8,2,0);
INSERT INTO "reviews" VALUES('62557200cfa11057e8b25cdc',31,3243,'大三考研中回来评价！秦老师yyds！真是大学最重要的数学学科的启蒙老师！太牛逼了秦老师！现在复习高数过程中完全没有压力，听一听课理解的很快很快！只能说做过秦老师的学生是荣幸之至，对我的影响太大了，我太喜欢秦老师拉！！',5,5,5,15,4,0);
