INSERT INTO "reviews" VALUES('6253cde4cfa11057e8b04c51',384,51,'课很水……讲课内容一言难尽，交论文，会点三四次名。',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('6252ecb094a0b361510fe89d',11148,6371,'老师很会说话，很耐心的讲课🤤好高我好爱嘻嘻嘻',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6252ebbb94a0b361510fe776',294,294,'英语都夹着东北腔，上课虽然水，但是要求严厉得一批，作业也多，动不动重写重改，对于认真的同学倒是积极表扬，虽然表扬并不能带来加分就是了。',3,3,5,11,0,1);
INSERT INTO "reviews" VALUES('62527a3acfa11057e8aebf91',3425,1052,'纯纯******，次次全体点名，节节课抽问题，课上不准用电子产品，还敢没收呢！给四天时间完成2000字大作业，什么牛马😅。',1,2,2,5,2,0);
