INSERT INTO "reviews" VALUES('6247fc7c94a0b3615102891c',10,10,'吴老师真的很好，讲课的时候非常仔细，你有任何问题都可以她都可以解答地非常清楚，对平时作业也认真负责，而且课后问她问题也总是可以及时回答。是我在大学里遇到的最好的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6247a7b596549b175e04291e',24,24,'老师yyds，超级温柔还很负责',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6246b6b9cfa11057e89fc46d',250,561,'真的又**又无聊，一节课从视图讲到无人驾驶在中国行不通，真的**，作业多，大图过不过看他心情，一节课不是批判大学生就是瞎聊天，真的没意思，批判各种事情，上他的课，打完几局游戏他还在那里瞎聊天，还看不上这个看不上那个，',1,1,1,3,16,0);
INSERT INTO "reviews" VALUES('62466ecc96549b175e02bc88',309,309,'崔老师真的太好啦，平时作业也不多，都是很基础的作业量，上课超有意思，再也不会感觉三连讲难熬了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('624646ff94a0b36151006c0e',10671,68,'选谁都别选他……******一个，天天上课阴阳怪气的，简直就男版郝静，说话还难听，反正我在他那什么都学不到就学了一肚子气。如果你觉得自己生活太好了缺一个人来打击你，那欢迎选他的课😃',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('62454d18cfa11057e89df4e3',1,1,'作业巨多，很夸张的那种，给分低，该跑就跑',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('62454c9796549b175e013edd',2005,1170,'给分低的******离谱，别人最起码80+，连个75都给不到，半期说全是原题，就一两道原题阴阳怪气，早早跑路(ﾟДﾟ)ﾉ',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('62450e2796549b175e00f480',23,23,'超级有爱心的老师，上课讲解透彻，有激情，有求必应，超级温柔有耐心，只要跟着老师的节奏学，轻松高分通过，还能收获很多课本外的知识，刘老师yyds!',5,5,5,15,38,0);
INSERT INTO "reviews" VALUES('62442a7696549b175efff6ac',2012,1753,'四个字评价：高数大爹。',5,5,5,15,1,0);
