INSERT INTO "reviews" VALUES('6243d3438fdcb24c6182af21',11163,11163,'讲课扯淡，正事不干。玩游戏加分什么睿智',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6243c9641755cc65dbcd91de',1158,26,'人美心善，数学老恐惧人都很爱上娟娟的课，小测验都是在云班课进行，可以翻书什么的很水，数学小菜鸡赶紧冲，上学期平时分能给都给了，有答疑课，问白痴问题也不会嫌烦，认认真真解答，超级温柔，ps（有次看到她丈夫跟儿子在教室外面等她，感觉好温馨，对恐婚人士友好哈哈）',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('62428073dc9e160981debb72',11165,11165,'20年4学分的课花444块钱学分费上了个寂寞 上课就是半小时讲课剩下几个小时全部看bilibili教程 还得交作业 做着毕设用着spss就想喊lls退钱 人还没有耐心 一整个排雷的大动作直接给到',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6241bd68ecdcd03b74afa655',8591,8591,'郑老师还是很好的，上课水平高、半期不考、作业不布置，期末最后一节课还给画重点。郑老师说，就差把题目给你读出来了，同学心里窃喜，想着按着重点复习，一定没问题！等到考场上，看清试卷，瞪大眼睛仔细找，没有一个字是重点里的。全是没见过的题，还以为自己瞎了呢。最后六十分险险飘过，只怪自己没好好复习，谁让你只看重点呢？一个没考，哈哈^^',5,5,1,11,1,0);
INSERT INTO "reviews" VALUES('62415d0fd513f03b16acce81',10441,10441,'上的是严敏老师的公共政策导论 是必修课 真的觉得这个老师讲的很好很亲和',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('62405ccba799374ce1e116ab',42,42,'好老师我好爱，老师人特别好，好负责，长的帅讲的也好捏，大家快来选！！！',5,5,5,15,6,39);
INSERT INTO "reviews" VALUES('623f346bd513f03b16aa6149',268,7955,'这个专业课本来就比较难，但是老师讲课比较跳跃，不会细致推导公式or讲解PPT中的推导过程，甚至三连讲只讲两节课（本来有机会讲满三节课来把知识点讲得更深入和细致的）',3,3,3,9,1,0);
