INSERT INTO "reviews" VALUES('623dffbda799374ce1de7611',9443,1170,'童童真的好可爱！！！！每次必须出境的农夫山泉哈哈哈哈哈！内容也教得不错，很有趣！推荐！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('623dfd73d513f03b16a91189',8265,114,'吹爆海良！！老师很认真负责，讲课也比较有趣，很喜欢！是俺少有喜欢得数学课了',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('623dd91ba799374ce1de2bd8',9120,92,'这老师思维崎岖独特到骇人，说话的方式怪里怪气的，在群里经常捉摸不出他的意思（捂脸），好像他的思维就是高一等的我们不配；线上作业布置到周四凌晨2点，张口说不要我们拖沓真的恶心人，为什么有老师保留着和学生作对的劣弊天性；上课也是播着PPT一顿随意乱讲，从不在原理，公式等等细节的地方讲解，这么说吧没看到几个人在认真听课。',1,1,1,3,5,1);
INSERT INTO "reviews" VALUES('623dd798d513f03b16a8c90a',499,194,'确实讲得好，上课认真听考试没问题',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('623dd2aca799374ce1de251a',9120,92,'谢老师收作业时间突然提前到周四凌晨还不通知同学。同学们跟他提意见，谢老师舌战群儒俩小时就是不肯延长。上课更是勾巴一个字都听不懂，想学辩论的来，学大物的能跑赶紧跑吧。',1,1,1,3,5,1);
INSERT INTO "reviews" VALUES('623dd204d513f03b16a8c2b8',9120,92,'我向来是不惮以最坏的恶意来推测中国人的，******上课讲公式不给你讲原理，作业瞎******设置，提交时间晚上凌晨几点，我也真******服了。本来说是不来平台上面搞他，可今天同学们都对他提出作业提交时间的建议，结果他反手就把我们禁言了。无语。能跑的搞快跑吧，别犹豫了',3,1,1,5,10,2);
INSERT INTO "reviews" VALUES('623dd1d9a799374ce1de2406',9120,92,'专业能力不知道，毕竟是个老师，给他三星吧。但是这人是真不行，遇到的兄弟们快溜快溜',3,1,1,5,5,1);
