INSERT INTO "reviews" VALUES('623d16c9d513f03b16a7cf1e',8080,8080,'不禁想感叹，学法的人真是深刻！老师讲授的东西涵盖了法治、公平，乃至自由、人生，感觉就是少书版的罗翔了！（嗯...杨老师平常似乎没少刷dy...）
