INSERT INTO "reviews" VALUES('623ac4eb65f7bc435e4c1e2e',3437,3509,'上课不怎么讲，嘎嘎让看网课，还没讲就抽人提问，想治疗社恐的同学欢迎选这门课。作业同学互批降低自己工作量，想挑战自己运气的同学也欢迎选这门课',1,1,1,3,0,0);
