INSERT INTO "reviews" VALUES('6239679e969ce676eb5d281f',6705,1753,'很好很好，认真负责，小测会认真改，但期末其实会给你平时分拉满，问问题也很细致的讲，超级好的老师，但是为了考试可以再看看讲习题的网课会更好',5,5,5,15,1,0);
