INSERT INTO "reviews" VALUES('6231c87a25bef044fcba35a0',348,348,'我认为老师讲课很细节，可以尝试，如果不行再第三次换课。上计算机实验还会让同学点歌。不要过于相信原来评价。',4,4,5,13,5,21);
