INSERT INTO "reviews" VALUES('62302c13c537fb5ec88cff04',2340,2340,'很枯燥，爱点名',5,3,5,13,1,0);
INSERT INTO "reviews" VALUES('622fdc195b86756d9b14eaab',42,42,'3个实验没验收，期末基本写错，还是给过了，but,实验经常玩失踪。有个实验，我请教隔壁的老师，人家仔仔细细地给我讲了一遍，我照着做的也达到了验收标准，到了龙这边，来一句“我给过你很多次机会了”，直接在补验上画叉。他从来都是提示，“我提示过你很多次了”，绝对不会多讲一点，以前知乎上有个高赞评论，几乎完美刻画了龙，可惜现在被删掉了，恶毒的话就不说了，毕竟龙没让我重修',3,1,1,5,18,0);
