INSERT INTO "reviews" VALUES('622dbda5c537fb5ec889ab1b',4250,2713,'破防了破防了，只上过这个老师的数据库原理与设计，其他的课不了解也不评价。就我目前这门课来说，我真的从来没有这么难受过，老师的ppt非常凌乱，讲课东扯西扯逻辑不强，学生很难跟上思路，我一度怀疑自己可能是专注力不够。更离谱的是老师还抽人回答问题，在一头雾水的情况下再心理刺激，简直是如坐针毡。下课自学面对凌乱的ppt研究了一个多小时的我直接抓耳挠腮面临崩溃，难受从内心萌发，酝酿，翻滚，是一座沸腾流动喷涌而出的难受火山，如芒刺背，如鲠在喉都不为过，是真的真的很难受',1,1,1,3,1,3);
