INSERT INTO "reviews" VALUES('6224e9c8f04bc232df0f973b',262,5485,'咋说，第一节课给我的印象就是当娱乐性质上课可以听听，但是当严肃历史文化课上可能不太行，有一些历史的专用名词，事件等确实有含糊的地方，很多历史事件感觉有点开玩笑带过了，而且开女生刻板印象玩笑这个实在受不了，一会女生靠男朋友做事一会又觉得女生不懂军事政治是圣母。但是好在课比较水，老师也确实比较和蔼，就当做没听见也行，看了看不是一个老师一直上就还勉强接受吧。等上完这学期再用另一个号来补充吧。',4,4,5,13,2,0);
INSERT INTO "reviews" VALUES('6224be0d3b3f4f50775ecd48',278,228,'挺没意思的，退一步讲，就算上课不让玩手机，不让睡觉，平时分给高一点就算了，可是一个班的最高分不如别人的平均分真的合理吗？平时事情也一堆，要回答三个问题出勤分才能拿满，理解老师希望大家活跃一点，但是真正讲得好的老师是可以靠自己的内容、激情带动学生的，而非强制。',1,1,1,3,9,0);
