INSERT INTO "reviews" VALUES('622457f03b3f4f50775e62bb',9133,980,'知识很渊博的老师，在他的语法课上可以学到很多，跟他一起学习是一种享受，可以不选课，别的专业去听一两节收获都会特别丰富！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6224451e3b3f4f50775e4eaa',489,573,'平时成绩占比不说清楚，提问就是找助教。讲作业都是学生做的拿出来讲，期末考个及格都给你挂。没有老师自己讲的，都是慕课和雨课堂，大学四年没见过这样的老师绝绝子！',2,2,1,5,2,1);
INSERT INTO "reviews" VALUES('622436025b86756d9b05ae84',6705,1753,'不多说了，让我能够继续完成学业的不至于大一就退学的高数老师。人很好，课堂轻松愉悦，作业量平均水平，很有同理心。',5,5,5,15,1,0);
