INSERT INTO "reviews" VALUES('62243470f04bc232df0e8040',282,282,'有生之年遇到最好的老师，任何问题都会给你耐心解答。甚至课后都可以QQ问答，从来不会生气。上课时也讲的很清楚，不讲废话，不耍脾气。德才兼备，不选血亏',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('622433e45b86756d9b05ac1b',56,6139,'以前上体育课，一个动作******演示三遍就要我们自己练******脾气暴大，经常体罚。以前的老头体育老师，七十岁，上课一直在重复动作，和蔼可亲。不知道她有什么脸在那里装',1,1,1,3,5,4);
INSERT INTO "reviews" VALUES('62239a6d5b86756d9b052ef5',604,96,'讲课讲得好，平时分给的高，凯皇yyds！',5,5,5,15,1,2);
