INSERT INTO "reviews" VALUES('6223510e5b86756d9b048c71',179,764,'平时分都拉满，期中测验看你自己，开卷考试，要是走狗运创上他出题，期末考试填空题就和中期一样，背答案就能过。上课就别指望他了，自学吧。偶尔点名，每次都有作业',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('622345bb5b86756d9b047ff9',4112,114,'老师很和蔼，不点名，上课川普,但有时会有课堂训练，会提前告知。分给的很低，不建议选。除非想经常逃课。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('622344433b3f4f50775d153d',7435,10848,'事情挺多的，不是水课。上课经常尬笑，吐词有点不清楚。作业量不少。',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('622343b1f04bc232df0d541b',11279,2027,'这个老师不是很专业的样子呢。经常文学评论的时候找不到词汇，卡壳。对社会的见解不够深入，对文学的理解也很局限。如果同学的理解不符合主流的权威解读，就会认为是错误的。抽人回答问题不会很严格，上课挺随意的。对于文学好像没有自己的解读，阅读也不是很广泛，比如中国哲学，她只知道大概，具体什么她一点都说不出来。专业水平比较差，观点过于片面。但是混学分的话还是可以选择的，要求并不严格。',2,2,5,9,2,0);
INSERT INTO "reviews" VALUES('6222d5fb5b86756d9b04098a',3212,5,'作业多，上课严肃，分少',4,1,1,6,0,0);
