INSERT INTO "reviews" VALUES('6220f4913b3f4f50775aa2e9',11285,26,'任何人觉得孟老师不好，我都会伤心的，孟华老师是在交大这几年里遇到的最好的老师，讲课通俗易懂，很难的推导和内容都很好理解了。孟老师还超级负责任，带了我们三门专业课。太爱了，遇到了一定一定要选',5,5,5,15,1,0);
