INSERT INTO "reviews" VALUES('6220e9ee5b86756d9b01fd9c',720,6419,'老师挺好的，很温柔，上课从来不点名。课上可以听到很多关于建筑，房屋，运维检修等知识或者一些反面案例，也会教建模。虽然要求要bim建模，但是实际上不做bim她也不会说什么 期末只用交一篇自己真情实感的论文就好，给了90分',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('6220e5423b3f4f50775a47cc',3065,140,'老师上课很水，最后结果也很水，平时分远低于其他班，慎重考虑',3,3,3,9,3,0);
