INSERT INTO "reviews" VALUES('621e371b2d830647ce71a664',2,11031,'我的舍友们报了他大四上的岩土工程课程设计，说好寒假前给两周时间修改课设，当天晚上就登成绩给了零分，其中一个舍友做的非常精细，几乎是毕设的水准，就因为只少了一张CAD图，结果被挂了。反观我报的铁道课程设计和城轨课程设计，做完交了都给了80+。导致他们大四下还要重修他的课程设计。怎么说呢，慎重吧。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('621dea2147ea564cbed7d2e1',11307,11307,'讲课语速超快，但是讲的很好，考试也不难，是个能捞人的老师。',5,5,5,15,0,0);
