INSERT INTO "reviews" VALUES('6217a89e47ea564cbed07bf5',535,535,'平时成绩中的半期考试成绩是根据期末考试成绩打的，真不错，选就完事。
INSERT INTO "reviews" VALUES('621105f2ff452429a8c97c82',1372,348,'讲的很差，只会念PPT，而且问问题很不耐烦，几句就搪塞了，很打消学生学习积极性，希望大家选课擦亮眼睛，期末五十几挂了😅',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('6203554954971e406ae8c5d4',573,573,'一个班号挂41个人？',3,3,3,9,7,0);
INSERT INTO "reviews" VALUES('61f4979f54971e406ad90fb4',9122,9122,'不明白那么多人好评到炸，可能我运气差吧，平时分确实给满了，那是因为作业分全是助教给的，实验分是实验室老师和自己在那个软件上做的分数决定的.我来说差评的理由，这个老师除了学习课程有关的问题不会理你学生任何的求助或者提问.就上课给你按着ppt念就完事，对了，课间他不会下课.',4,4,1,9,4,2);
