INSERT INTO "reviews" VALUES('61e8f2a52d14a11501d9c035',693,693,'我后半期有事没来上课，平时分除了半期测验基本都拉满了，期末最后还拉了我一把，可能因为我是重修吧。',4,4,5,13,0,1);
