INSERT INTO "reviews" VALUES('61e4f717fa8548519912e2df',3719,230,'专业课讲的还没有高中老师好，非常非常不负责任，如果遇到什么关于网课进不去的问题是绝对不会给你解决的（网课关系到30分），平时要点名，但是你答了也不一定给你记到，也就是说你就算全勤他也可能只给你打60分，给分全凭心情，一点都不捞人，如果是因为平时分打的太低而挂就挂了，是他的问题也不会捞，很不负责。',2,2,1,5,3,1);
