INSERT INTO "reviews" VALUES('61e3b808fa85485199114e83',674,179,'好好听课，是个人都能过，老师讲课顶呱呱，最爱吃海底捞😀',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61e3a8e7c309d82e0a7c0022',5399,5399,'基本不可能捞人，课讲的也就那样，属于是一整个沉默了。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('61e399dcc6c65335c8fd51df',6396,6396,'她一直反复要求我们线下看mooc，首先mooc不算分，其次，mooc上有的他就不讲，但是mooc上的有些会考，然后就是有次全班没看就发脾气，拿党员班干开刀。经常点名，她作为电力系统组长，作业都是从她那发出来的，所以是最多的，给分的话一般，上课经常抽同学回答问题，好在是助教特别特别特别好，实验报告，作业的批改甚至包括最后期末改卷都是助教改一部分，所以中评是助教拉回来的',4,2,2,8,4,0);
INSERT INTO "reviews" VALUES('61e38e9fc6c65335c8fd43ea',674,179,'平时分不高，半期考很严',3,3,3,9,3,3);
INSERT INTO "reviews" VALUES('61e382bcfa85485199110efb',6826,6826,'真的很无语，一个音乐类选修课要求极其多，连期末考试的用纸都必须规定个交大信纸。又要小组作业，期中又要写论文，期末又要考试。只缺勤过一次，其他都是认真完成的，竟然总分卡到84分，我服了，我选这个算是我倒霉了！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61e3809cc309d82e0a7bd036',1855,6277,'老师讲的很好就是我听不太明白 从不点名 平时分几乎拉满 期末很好过 作业有一点点多',5,5,5,15,0,0);
