INSERT INTO "reviews" VALUES('61e237dec6c65335c8fb8213',11006,694,'上朱老师的课会不由自主地跟着她走，因为会时不时掉落课堂作业嘻嘻，但是只要去了平时分就给满，治学严谨，该多少是多少，应该是不会捞人，不过她讲得真的很好，讲到重点还会提醒你不要玩手机，反正听老师话的都过了',5,4,4,13,1,1);
INSERT INTO "reviews" VALUES('61e2366dc6c65335c8fb8096',8805,304,'虽然每节课都发单子签到，但从不点名，看到人少也是看破不说破，实验甚至不需要验收（但是每周三小时的实验真的有亿点痛苦），去了就有分，平时分拉满，没有平时作业，考前划重点，除了语速太快没有雷点',5,3,5,13,0,0);
