INSERT INTO "reviews" VALUES('61e13073c6c65335c8fa01a9',637,11377,'这平时分也太不合理了',5,5,1,11,3,2);
INSERT INTO "reviews" VALUES('61e11b4dc309d82e0a788b95',5803,230,'平时分巨低，没什么其他好说的了',3,3,1,7,2,1);
INSERT INTO "reviews" VALUES('61e0f275c309d82e0a785652',489,573,'每节课都去，作业也都交了，最后平时分只有四五十？特么期末考六十多都过不了？期末监考也不到，算我倒霉遇到这老师',1,1,1,3,5,3);
INSERT INTO "reviews" VALUES('61e0ec05c6c65335c8f9aa02',489,573,'平时按照老师说的去做，平时分不会低的，前面两个人肯定连课都不上才低分，现在来骂老师有点缺德吧。老师讲课也讲的很好，人美心善。',5,5,5,15,4,27);
INSERT INTO "reviews" VALUES('61e0cf4ac6c65335c8f98977',7449,7449,'PPT十分详细，老师读的一字不差十分认真。期末划重点十分详细，划得都是重点',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('61e0c2b4fa854851990d5a3e',359,228,'米老师人超级好！！选到就是赚到！平时分杠杠的！',5,5,5,15,3,7);
INSERT INTO "reviews" VALUES('61e0bbf1c6c65335c8f974fc',909,11227,'可能专业知识比较强，但讲课是真的不咋地，一句很简单的话说个半天也说不明白。给分低。',4,1,2,7,1,0);
INSERT INTO "reviews" VALUES('61e05295fa854851990d0a99',909,11227,'这学期修读了王艳老师的生物分离工程课程，王老师的实务经验很强，上课会经常提到自己实际操作中对具体厂家和工艺的理解和使用经验，给学生以不少启发，平时很和蔼，给分也比较高。总而言之没有之前的评价说的那么离谱，总体还是好评满满！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61e04effc6c65335c8f92772',489,573,'就******老师 乱给平时分，期末考65都挂了，真的******老师',1,1,1,3,3,3);
INSERT INTO "reviews" VALUES('61e03deac6c65335c8f8df29',489,573,'******，平时分给只给4、50分是吧，什么出生啊，你要求的都做了，除了少交一次作业外，本来屁事就是年级里最多的，上课玩失踪，也不来监考，导致晚发卷子，座位也乱排，疯狂装死，真的出生，谁选谁倒霉。',1,1,1,3,6,3);
INSERT INTO "reviews" VALUES('61e01d6bfa854851990c7fd3',2646,1170,'卤蛋',1,1,1,3,2,2);
INSERT INTO "reviews" VALUES('61e010b0c6c65335c8f89942',2821,40,'杨璐老师属于典型的认真学就给分贼高，不认真学就给分贼低的老师。平时作业是有些小多，但是也很少检查，课本上的作业每次布置了基本就没检查过，想水还是能水过去的。论文的指导也很详细具体，认真听还是干货满满的，你问她问题，她也会耐心的教你。而且人还挺好说话的，之前网课的时候睡过头了，迟到了快半个小时，下课后和她说明原因她也没扣分，平时迟到也不管。最后平时成绩56.7/60 个人觉得要是认真学的话给分还是很乐观的。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('61dff1e9c6c65335c8f87279',5073,313,'期末给分低！快跑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('61dfed3cc6c65335c8f86c76',1596,1596,'首先明确，占涛哥问题确实是有的，讲课过于详细，过于注重数学推导，而且喜欢拖课确实不适合执着于听课的好孩子和求捞的各位老哥
INSERT INTO "reviews" VALUES('61dfe84cc309d82e0a770276',385,28,'作业真的就是不近人情的多  多到怀疑人生，而且压分压的特别低....你不上早自习啥的想85+  做梦去吧',5,5,1,11,3,0);
INSERT INTO "reviews" VALUES('61dfd9f7c6c65335c8f85573',563,228,'座位被安排好，上课搞翻转课堂，每次课前点名 说话声音莫名其妙地降下去，有莫名其妙地升上来，老子是坐在教室看鬼片迈？最后两三节课给我们说，不要以为你们只学你们讲的那一节课哟，都要考的哦。******有什么用，说实话，是个大学生，把公众号发的题做了，把书背了，要你个******在交大教马原有个屁用。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61dfd6d6fa854851990c27b4',19,2812,'隔壁杨骏班的期中考试还能水水，这厮出个卷跟期末考试似的，一个班八九十号人一个上九十的都没有，还说要是期中考差了给我们调期中占分比例，我还真信了，狗东西，说一套做一套。点名还多，三次不去平时分就没了，🌝',2,1,2,5,1,4);
INSERT INTO "reviews" VALUES('61dfd56ac6c65335c8f84fa9',759,759,'一学期下来教个什么东西？照着PPT念一遍，说什么人太多上实验课2周去1次，期末考试自己出题考一堆名次解释。重点没勾过，全部一嘴带过，课程设计要求不讲清楚，也不给评分标准，给分还低，搁这儿恶心人真服了',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61dfd430c309d82e0a76ea6a',759,759,'平时分给分极低，不画重点，上课无趣，期末考默写******',2,1,3,6,4,0);
INSERT INTO "reviews" VALUES('61dfd3e6c6c65335c8f84dea',141,765,'平时分结构设计得离谱，看视频还要算分！还不给我们说一声！哎真的平时分还得看杜华荣，直接拉满',3,3,2,8,1,0);
