INSERT INTO "reviews" VALUES('61df9a8ec309d82e0a76952a',975,975,'******别的班平时分接近满分，******给70分？******中期考试大晚上上了一天课，还拿一张纸对着黑板写，你缺印刷钱？选的人趁早跑路，给分低，讲的不行，******还用******作业系统做作业，******',1,1,1,3,3,2);
INSERT INTO "reviews" VALUES('61df7187c6c65335c8f7c82e',2983,294,'江楠老师如同天神下凡，救了一宿舍狗命，通用学术英语给分巨高，不过就是每节课必点名',3,3,3,9,0,2);
