INSERT INTO "reviews" VALUES('61df2e1dc6c65335c8f79e7e',716,716,'表达能力比较一般而且喜欢各种策谈,有些东西也不会讲很细,但是人还是很好的,课后会留下来很耐心解答问题,个人觉得可以靠自学取得还可以的成绩...给分不严不松吧...笑起来确实有点渗人(',5,3,4,12,0,0);
