INSERT INTO "reviews" VALUES('61ded613c309d82e0a75ea9d',626,306,'大一上是他，我大一学的最认真的就是高数和这个制图了，结果制图给的平时分就65分（百分制）真的离谱啊，讲的东西很生硬，抽象，难懂，上他的课很容易打瞌睡，大一下的老师是叫安什么和，最后88，比他好多了',1,1,1,3,2,0);
