INSERT INTO "reviews" VALUES('61decad7c309d82e0a75dc7f',5581,5581,'每节课都有答题，三次大作业，每个都写了三四千字，只有六十多分😅，能遇到这样的选修课老师是我上辈子造了什么孽啊😅，😅选美育的千万别选这个课',1,1,1,3,9,2);
INSERT INTO "reviews" VALUES('61dec9bfc309d82e0a75daff',11418,11418,'杨珊老师的课绝对要给好评！（ps：这门课的名字现在叫做劳动与社会保障法学，不过不影响就是了）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61dec8cbc309d82e0a75d9dc',3628,3628,'本学期修读了罗红霞老师和李萍老师共同开设的普通生物学课程，总体感觉这门课程还不错，能够学到很多关于植物生理和人体生理的知识，翻转课堂是关于细胞生物学内容的，这三大部分构成本学期学习的主要内容。给分适中不是特别高但也不是特别低，平时分尚可，考试的客观题很多。
INSERT INTO "reviews" VALUES('61dec1f7fa854851990b1473',703,228,'快跑，快跑，免考名额可能不会给表现最好的，dddd，比如关系户啥的',1,1,1,3,1,0);
