INSERT INTO "reviews" VALUES('61de5a9b933e3c158632ce01',6826,6826,'一个选修课事多 还不定期点名 我全勤 要求做的都做了只给80＋
INSERT INTO "reviews" VALUES('61de5288933e3c158632c44f',23,23,'赞赞赞',5,5,5,15,42,0);
INSERT INTO "reviews" VALUES('61de521ea0d6f51419dd5b60',1391,24,'老师上课充满激情充满力量 真的很无语 理力每两周才留一次作业 一次作业才五道大题 上课还会讲类似的例题 属于是很有效的课后练习啦 而且周三交也行周五也行只要周内完成就可以 有些老师每次上课都会留作业 鲁丽老师真的很有办事效率 ppt都是书上的内容 老师会留课上时间给大家做题 好好记笔记 不懂为什么有人连笔记都不会做只靠老师 
