INSERT INTO "reviews" VALUES('61dcffe43d39f2117f311a83',515,118,'我的超人 上课体验极佳 不点名 想做什么做什么 小测 很水 会花很大功夫讲不考但他觉得有意义的东西 如果听一听会发现确实讲的不错 加深了很多理解（虽然他不考） 考前给的重点非常精准 期末真的会捞人 赚到了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61dcf295bbe8e0402097f8fb',703,228,'大家马原一定避坑邵春波，我们一整个教学班大多数卡分60，邵春波的班几乎只有免考（5个），60和挂科的区别，赶紧逃，真******ex，平时分给******那么低显示水平呢？******',1,1,1,3,7,0);
