INSERT INTO "reviews" VALUES('61dc5c663d39f2117f309a1f',4695,7679,'妈呀快跑快跑快跑，选了他的别怪我没提醒你，水得不行，大作业淦到凌晨，平时分给的却还低，建议选其他的老师，比如叶建',3,4,4,11,2,1);
INSERT INTO "reviews" VALUES('61dc59c83d39f2117f3097a9',2582,790,'直接无语，期末考试别问，问就是全是重点，ppt做的没一点技术含量，大概叙述一下重点，说的基本全没考，真的6，平时看着还行，一到期末就背刺一刀，给分也是个迷',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61dc56b74e12fc24115777fc',4695,7679,'建议选另一个老师，平时分更高，教的更好，数据库平时分给的真不太行',2,2,2,6,3,0);
INSERT INTO "reviews" VALUES('61dc50f64e12fc2411577328',8265,10596,'第一节课印象不太好因为听不懂口音，后面也觉得老师有些奇奇怪怪，最后期末也是差一点点及格',5,2,2,9,1,1);
