INSERT INTO "reviews" VALUES('61dc191f3d39f2117f301213',699,2,'老师专业水平很高，但是期末试卷让助教改，给分也是助教，给分是真的很低',5,1,1,7,1,0);
INSERT INTO "reviews" VALUES('61dc189e3d39f2117f30117f',759,759,'挺水的，上课和不听课没有区别。实验课精确到鼠标的每一个点击，有手就会，大作业也是，可比其他老师简单多了，平时无作业，就期末有个大作业。期末他出的题不怎么费脑子，就是得背。考的东西全在ppt上，背了就行，不是很多。就是给分不高',1,1,5,7,1,0);
INSERT INTO "reviews" VALUES('61dc16b64e12fc2411572ef7',2231,256,'还行',3,3,3,9,0,0);
