INSERT INTO "reviews" VALUES('61dc1316bbe8e0402096f151',351,351,'平时分给满的老师，教得不咋地。不认真学习的同学可以选，人还行，就是不要去问一些白痴问题，她会炸的。',3,3,3,9,0,3);
INSERT INTO "reviews" VALUES('61dc109b3d39f2117f30087d',703,228,'真的无语，授课水平就不做评价了，平时啥事儿没犯，平时分给得巨低，快点逃吧',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61dc0b584e12fc2411572084',585,325,'李老师的课上非常有意思，我们的课是早八，非常容易困，走神，在我们注意力不集中的时候，老师会给我们讲一些小故事来帮我们集中注意力，而且李老师对待课程很认真，助教老师解答问题也非常耐心，课上讲的知识点都很仔细',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61dc07a04e12fc2411571c23',975,975,'能跑就跑，布置作业非要用电脑作业系统，一个小时能手写完的作业，用电脑要写两三个小时，作业系统评分还莫名其妙，跟答案一模一样只得六七十分，最后他还就按照那个作业系统给分给平时分，别的班平时分都九十几，他就给七十几',1,1,1,3,4,2);
INSERT INTO "reviews" VALUES('61dbf866766aa132875ec1f9',9693,32,'老师讲的很好，但是平时给分是个迷，是和在一起给，各项小分都看不见，不知道是哪里扣的，也不是太高。期末考试有些也不是他强调的重点，不要一味看他ppt复习。',5,4,2,11,0,1);
INSERT INTO "reviews" VALUES('61dbeef2ceb05208ef91444f',31,1169,'对于以前说秦老师给分低的评价我深深道歉，秦老师我错怪您了，您很好，真的很好，讲课好，判卷送，划的范围靠谱，我以前不懂得您的好是因为没有碰到真正不好的老师😡',5,5,5,15,9,0);
INSERT INTO "reviews" VALUES('61dbdcce3adfef7fd0e73998',703,228,'1星是因为0星不好给',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('61dbca86ceb05208ef911448',9443,909,'老师的川普很有意思，上课写作业经常忍不住去听他讲课，老师也是很有趣的人，喜欢和我们开玩笑，也不会管你上课做什么，老师很温柔的，点名时间也是固定的，在每次的第二节上课前点到，就期中期末3000字论文，论文也可以随便在网上搜，老师不会管你的。写作业的那周还不用去教室上课，其他没有任何事情，必选必选必选童童！！！',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('61dbc938766aa132875e8552',370,370,'大师级别人物，慕课作业分数掌握在其他同学手中。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('61dbc8d73adfef7fd0e71eba',2285,11475,'上课不能去厕所，出去一趟还要和他汇报。上课不能小声说话，讲课也毫无吸引力。占总评70%的论文要求非常高，给分真的很低！想躺平的应该会给你捞过，但是想刷分的千万不要选！',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('61dbacff3adfef7fd0e6fc8e',278,228,'我真的一颗星都不想给，这老师天天自以为是，压榨学生平时分，期末考试根本不给划重点，大家以后能避多远避多远，当然，你要是不想拿分除外，这个老师就这尿性，谁选她的课谁后悔，每次上课屁事情特别多，给分还很低，还天天炫耀去加拿大那点破事儿，牛逼的不要不要的了，想拿高分一定别选她的课！',1,1,1,3,20,0);
INSERT INTO "reviews" VALUES('61dba46e3adfef7fd0e6f29e',18,18,'老师真的好 ，教的好还幽默，认真负责还吃海底捞',5,5,5,15,0,0);
