INSERT INTO "reviews" VALUES('61d910013adfef7fd0e3dd5b',442,573,'哈哈哈哈我怎么感觉喻老师还好哇。助教给作业分很严格，整体作业分被压下去了，同学反映之后就把最低的一次作业分去掉重新算了。因为疫情没有小测，喻老师把全勤的一次签到当成小测分了真的太好了，老师上课就是讲得会很平淡有点枯燥不容易听进去，但是还是很乐意解答的。',4,4,4,12,1,3);
INSERT INTO "reviews" VALUES('61d90cb1766aa132875b4453',1768,22,'钟老师！大物上下都是她在教我，真的超级棒！老师上课特别有条理，逻辑清醒，而且讲的也很清楚。作业就是正常作业量。钟老师的课只要认真听课听进去了，平时作业也认真作业，拿90+是没有问题的（自己复习再多复习透一点95+也轻轻松松！）！老师私下人超好，特别愿意为同学们解答问题！会希望每个同学都在课上发言然后大把大把地给你加分，平时分除了半期都是满的。啊啊啊啊我是钟老师自来水！大家都去选她选她！！',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('61d90644ceb05208ef8dc367',948,22,'很佛系的老师，因为挂你她都嫌麻烦，捞人会捞到61或者62，免得别人一看60就是捞的😂 ，从不点名，作业交了就满分，还可以补交，平时分只扣半期考试。真的爱死何老师了。前面评论有说她脾气不好，至于这点，我表示“脾气不好”跟何老师简直没有半毛钱关系。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('61d903fbceb05208ef8dc0ff',1243,1246,'喜欢搞新花样变着法折腾人，然后还压平时分的老师是真的流批嗷😅画的重点都不考，离了个多谱',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('61d8efba3adfef7fd0e3b8be',5558,790,'笑面虎 ******。他的所有课都很水且给分很低 听课学不到任何东西 还吹嘘自己有多牛逼。你讲课水还不让下面玩手机？还批评作业写的水的同学？',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('61d8ed0fceb05208ef8da6aa',741,741,'给分低 事情多 要求严 统计一定选骆泳吉',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61d8e0f9ceb05208ef8d9a03',3577,631,'游老师平差的给分虽然不像其他老师那么高，但是上课逻辑十分清晰，适合喜欢跟着老师走的学生选。并且虽然给分很死，基本是拿了多少就给多少，很符合本人严谨的气质，但是人是很好的，会耐心解答学生的疑问，并且期末考完还会给那些不及格的同学额外开课讲题，真的很负责任了！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d8df38766aa132875b1332',563,228,'为什么不能给零星！来交大以后遇到过最烂的老师没有之一，整一个学期下来自己基本没讲过几节课。人家搞翻转课堂都是就几节，就这牛马搞一整个学期，如果学生都能自己学进去枯燥的马克思原理的话还要老师做什么?讲话的时候还要突然变得很大声搞的很有道理似的，真不知道为什么这种老师还能待在交大 。如果被分到他的班只能说赶快逃吧',1,1,1,3,16,0);
INSERT INTO "reviews" VALUES('61d889f3766aa132875ad9e6',2654,40,'水，但是平时分一般',4,4,5,13,2,0);
INSERT INTO "reviews" VALUES('61d878563adfef7fd0e3630d',953,953,'我的评价是****** 给分超级低',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('61d877ec766aa132875acf6b',751,573,'除了有点点口音之外挑不出任何毛病',5,4,5,14,2,7);
INSERT INTO "reviews" VALUES('61d86a09766aa132875ac4b8',22,22,'黄老师人真的很好，很有耐心，讲的简单易懂，特别幽默，回复问题都是几分钟之内。大学里第一个卷面100分就是黄老师给的哈哈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d85dea766aa132875a83ba',573,573,'服了，我是伞兵，我考前眼睁睁的看着别人的工程力学平时分38，39，40。我******认认真真做了一个学期作业，就因为他的******回答问题制度，平时分32，******非得学生给你回答是吧，我生性腼腆，社交恐惧咋办。******好不容易回答一个问题，就因为老子忘了找你打勾，第二节课来不认了。非得划分等级制度，旱的旱死涝的涝死。考试完平时分一传，哎，******，一个班能挂一半，狗都不选。',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('61d855903adfef7fd0e308f8',1168,228,'平时分直接拉满，我感觉是人均满分的水平哈哈哈，人也超好，和蔼可亲，非常体谅学生，从来不为难我们，所有事情也都是为了我们好，期末划重点很有用（虽然我没记住呜呜呜感谢平时分）。东哥冲就完事儿了。东哥我爱你！！！😘',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('61d84901766aa132875a6c66',2646,1170,'很无语，离谱',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('61d8368dceb05208ef8cdcd3',2541,22,'张老师太好了，海底捞😭😭',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d80ba8ceb05208ef8cabcb',849,619,'期末交了笔记，平时分就给满了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d8009f766aa132875a1733',452,965,'能跑则跑吧，跑不掉只能努力了。。。。。就是那种一边说着着急讲不完，一边贬低学生自己说废话一堆的矛盾复合体。。。。。。超级无语，生命的学生一定要润。。。。。',4,4,1,9,1,0);
INSERT INTO "reviews" VALUES('61d7fed53adfef7fd0e2a4db',1052,1052,'毛概平时给85是吧，不划重点，一次大作业，三次点名*',2,4,4,10,0,0);
INSERT INTO "reviews" VALUES('61d7f6d4ceb05208ef8c955d',373,426,'老师人很好~看起来很严厉 实际上并不算严 给分还不错 期末总评95+ 但点名比较频繁 想逃课的可以run',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('61d7f4f5ceb05208ef8c92fc',7,7,'巨能捞，人也不错',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('61d7f2b63adfef7fd0e296b3',5558,737,'我只能说，选择比努力更重要，不要选他!你平时再努力，期末也认真复习，也不会有高分的!',2,1,1,4,4,0);
INSERT INTO "reviews" VALUES('61d7c91cceb05208ef8c6146',392,392,'除了上课会抽人回答问题外没有缺点，讲课真的很好',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('61d7c00aceb05208ef8c578b',278,228,'不好说了，不好说了。天天上课互动，上课认真听讲的同学，平时分还没隔壁杨东老师随便给的平时分高。一般上课的平时分40都不好说。',1,1,1,3,15,1);
INSERT INTO "reviews" VALUES('61d7bd74766aa1328759caad',1168,228,'东哥，我滴超人！！！押题还得看我东哥！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d7af453adfef7fd0e24c6a',1600,96,'上课很有激情也很有意思，老师坚持全程板书，不用PPT，这一点在大学老师里面已经实属难得，可以很好的跟上老师的思路，而不是照着读PPT，老师给分也很高，大爱马老师，概率论认准他！！！！！！！而且老师作业也布置的很少！每周作业不会超过6道！呜呜呜~想水的也可以选，因为马老师从来不点到！你别坐最后一排就行了，他抽问题只会从最后一排开始抽！这还等什么！马上选吧',5,5,5,15,12,0);
INSERT INTO "reviews" VALUES('61d7ad6fceb05208ef8c44c4',1168,228,'懂不懂考20分就能过马原的含金量呀？',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('61d70a583adfef7fd0e196bf',1105,380,'严宝，我滴超人！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d70609ceb05208ef8b8e72',373,230,'老教师，讲课非常有水平，有激情，看似比较严厉，实际上非常宽松的老师！近代史，毛概1都给了我满分平时分（大作业都是百度复制粘贴的论文），近代史还划了重点，一考一个准，毛概二还要选她！看来她要成为我大学时代唯一教过我三学期的老师了，真的超爱！虽然都是水课，但是不妨偶尔听一听她的课，真的非常有收获！',5,5,5,15,10,0);
INSERT INTO "reviews" VALUES('61d70143766aa132875900aa',1441,228,'好人',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('61d6ff47766aa1328758fe61',2298,394,'李老师上课比较水，几乎都在摆龙门阵，但是成绩占比4：6，其他班很多是7：3，懂得都懂，光平时分就落后其他班一大截。期末重点靠念，语速很快，没听清楚去问还会被他批评，并且不会再重复，考的跟他上课讲的几乎都没有关系，听了也不会做，只能靠背，慎选！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('61d6fdbc3adfef7fd0e18a33',278,228,'老师上课要求严格，不准玩手机，不准做作业，不准说话，不准睡觉，平时分也给的很低，不回答问题课会扣平时分，在她班上的最高分都没有其他班的平均分高。十分坚守原则，跟她发信息只会被她批。',2,2,1,5,6,0);
INSERT INTO "reviews" VALUES('61d6fa19ceb05208ef8b8063',720,6419,'想学两次混凝土的欢迎选龙姐姐的课呢',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61d6f946ceb05208ef8b7f7c',953,953,'给分不高，真的不高',4,3,1,8,1,1);
INSERT INTO "reviews" VALUES('61d6f8b7ceb05208ef8b7eda',373,619,'首先说大家最喜欢的分，近代史给了我94，毛一给了100；
INSERT INTO "reviews" VALUES('61d6f154766aa1328758ed21',720,6419,'赶紧跑，混凝土平时成绩给70多分，搞心态。讲的不咋地，还经常有错误。',2,2,3,7,4,0);
INSERT INTO "reviews" VALUES('61d6d9a43adfef7fd0e155b4',23,23,'yyds！ 刘老师是同学们的最爱，讲解深入浅出，学起来轻松愉快，一学期除了收获C++，还学到很多人生哲理，总之，爱爱爱！',5,5,5,15,45,0);
INSERT INTO "reviews" VALUES('61d6d5c2ceb05208ef8b52b5',802,706,'讲课声音小不说，讲课的时候一直咳咳，甚至监考的时候都那样，给分非常低，期末占比很高，但老师是那种严格按照标准答案给分',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61d6caa23adfef7fd0e1417d',741,741,'这个老师平时分给的很低，别的班都是90多分，总评直接低4分，讲课虽然讲的好但是分低啊',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('61d6b97c3adfef7fd0e12d9c',278,228,'手机不能看，作业不能写，听她讲课又听不清楚，别的班平时分四十五往上，这老师上四十的都不多。快润。',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('61d6b038ceb05208ef8b2643',759,759,'期末不给划重点',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('61d6a849766aa13287587e34',11070,526,'声音温柔 讲课很好 平时分也很高 最重要的是温柔啊 选她没错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d6a4f23adfef7fd0e11657',728,11573,'平心而论，客观来说，该老师授课及专业程度都比较不错，上课质量是在的，但是期末考不得不提一嘴了，全书几十甚至上百个公式，隔壁班要不然就是试卷提供公式要不然就是直接考前发一个复习题，里面几乎全是考试原题，而这陶莹一不圈重点二不给公式，百来个公式里考试随机挑几个让你自己写，对自己记忆力有自信的英雄能人大可一试，其余凡人建议避雷。总之一句话，平时和蔼可亲，期末大开杀戒',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('61d695d23adfef7fd0e10681',433,27,'除了上课点名，作业以及各种任务贼多，抽人回答问题，考试比较难，分给得比较低之外没什么不好的了。总之抛开事实不谈，这老师挺好的',2,1,1,4,2,0);
INSERT INTO "reviews" VALUES('61d693b0ceb05208ef8b082c',499,194,'这个老师贼好，教得比较清楚，除了上课节奏稍微快了一点，其他方面都很不错',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d67600ceb05208ef8ae9ad',1600,96,'马骁老师，我的超人！！！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('61d6676a766aa132875838f3',74,74,'选了他的课我真是上辈子毁灭了地球，一辈子见过的最让人无语的老师，快跑！',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('61d5b6a2ceb05208ef8a0da8',11578,11578,'我只能说，他自己英语还是很不错的，课课讲不清楚，作业作业布置不清楚，当然啦，出了错，当然是我们自己承担啦，人家可是带研究生的“老教授”了，祝他退休快乐，也祝学弟学妹们，逃离快乐！',5,1,1,7,2,0);
INSERT INTO "reviews" VALUES('61d5a4d73adfef7fd0dff840',3727,1904,'没有签到没有作业，同时乱给平时分，花两个小时开卷期中考，但是没有算进平时分，纯粹被六年前的评价误导选了这个老师',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('61d5889eceb05208ef89d52d',5558,790,'上课就喜欢吹牛逼，也没见他说了啥。自己怎么喜欢怎么来，随意打分，平时分低的要死。划重点乱划，划的基本不考，赶紧跑。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('61d57f003adfef7fd0dfc8ce',1320,40,'人美心不善，事多分不高，上课不能水，点名小测多，想学收获多，想混赶紧跑！',1,1,1,3,2,2);
INSERT INTO "reviews" VALUES('61d576133adfef7fd0dfbf41',674,307,'我今天刚认的干妈，这次的模电考试生怕我们过不了，电气馆一个通宵就把模电稳过了捏，文霞姐，我的超人',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('61d546773adfef7fd0df5415',631,631,'个人感受是:只要认真完成作业和课程设计，上课认真听讲!分数真的很高，老师人也很好，很乐意为同学们解答问题。',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('61d50d1533313d2e403d9bc6',179,764,'期末出题人，模电过关有手就行',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('61d500355e21f07cb8e0234a',74,74,'上课什么都不讲  手机不能玩只能听他吹自己的牛皮  快跑',1,1,1,3,8,1);
INSERT INTO "reviews" VALUES('61d4f4865e21f07cb8e0141f',1320,40,'给分确实低，真心低，低的让我羡慕别人老师。讲得好嘛？没听出来，反正就是东扯西扯。口头禅我们“话不多说”。必点名，想逃课别来了。作业是真的少，这点确实好。是优解但不是最优解。',2,1,3,6,3,1);
INSERT INTO "reviews" VALUES('61d4ef59ef6f3d6cecce9468',11587,6778,'这一门会挂人的选修课',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61d4d490ef6f3d6cecce7b06',3727,1904,'无作业，无签到，但给分牛马',3,3,3,9,4,0);
INSERT INTO "reviews" VALUES('61d46532ef6f3d6ceccdee05',370,370,'妙的很，考试考啥最后都说，强推',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d4504cef6f3d6ceccdd4d7',11590,573,'沈老师超好！教的超好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d44f4733313d2e403cb53c',31,31,'老秦yyds！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('61d42a52ef6f3d6ceccda1f4',803,1111,'郭老师yyds',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d4205233313d2e403c72e6',209,209,'谢美俊老师真的很负责，虽然平时板着个脸，但你夸他帅气他就会很开心，就算你实验没做出来也很会直接给过😁',5,5,5,15,3,63);
INSERT INTO "reviews" VALUES('61d41f9def6f3d6ceccd92bd',1132,631,'yyds，给分超高，除了考试成绩基本都给满，而且没有助教，不管什么都是自己批而且尺度很松，答案对了这一题就是满分。真的是永远的神！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d412c8ef6f3d6ceccd808f',5558,4552,'长这么大，第一次见故意说错考试重点的老师',5,1,3,9,4,0);
INSERT INTO "reviews" VALUES('61d3f01533313d2e403c2f02',3821,4204,'这就不明白为什么什么都可以是，（）表达不清楚就是（）的错',1,2,1,4,1,2);
INSERT INTO "reviews" VALUES('61d3e5deef6f3d6ceccd41df',2012,1753,'半期40多，期末50多，最后还能被捞及格，我只能说好老师了',5,5,5,15,11,3);
INSERT INTO "reviews" VALUES('61d3dd5433313d2e403c12dc',9122,9122,'平时分居然是按照实验得分的，直接拉满了，杨帆这人能处',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d3d8dd33313d2e403c0d34',785,229,'虽然他讲话有点听不清楚但是期末的时候特别用心答疑也给我们准备了复习资料
INSERT INTO "reviews" VALUES('61d3d8ac5e21f07cb8dea54b',9381,11600,'我真的从来没有见过这么糟糕的老师，讲课水平一般，自己都不懂自己在讲什么，从来不发PPT，因为她PPT是用的网上的，怕发给我们我们告她侵犯版权。布置作业评分特别低，和答案一样就半对，做错就没分，讲题的时候还说你们自己去看答案，那到底要不要和答案一样？？？布置的作业和期末毫无关系，而且作业都布置不清楚，大家都不知道要交什么。期末大家问她问题她嫌烦了直接退出课程群了，真的恶心人，从没见过这么******的******，从来没有见过全班同学一起骂的老师。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('61d3d065ef6f3d6ceccd23eb',1320,40,'给分一般，但是事情和作业真的少（划重点），上课很有意思，总的来说强力推荐',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('61d3cc5cef6f3d6ceccd1ed9',1225,40,'真的给分低 都说他好 选了他的课 结果平时分给分巨低',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('61d3952f33313d2e403bbbce',11603,1542,'熊老师的形势与政策课我的爱，建议选！给分非常非常非常高，当然也得考勤都到和正常完成作业～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d394bc33313d2e403bbb52',223,1796,'慎选她的形势与政策课！',3,5,2,10,2,0);
INSERT INTO "reviews" VALUES('61d39446ef6f3d6cecccdd0c',2157,2158,'疫情期间选修了姚老师的生命科学导论课程，感觉是一门很好的课程，很推荐大家去选。姚老师人很好，很热情也很和蔼，如果有不懂的问题可以随时问得到解答，关于课程有不懂的问题可以随时在qq或者教务邮箱问，有课程组织方面的问题也会和同学们讨论商议后再决定。课程本身的内容比较丰富，涵盖了生命科学主要领域的内容，我在姚老师的鼓励下还自行做了两个在家就可完成的小实验，感觉很不错！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d392af5e21f07cb8de521c',2157,4548,'首先纠正一下，这门课的名字叫做“葡萄酒基础知识与品鉴”。其次姚宁老师的选修课我感觉可以放心选：上课可水可不水，可以快乐摸鱼，也能够学到东西，给分很高，还有一些快乐的小活动。本学期活动共两次，一次是老师带了四瓶红葡萄酒分给我们品鉴，还有一次是我们自己分享交流，回答问题最多的一组获得了老师的一瓶红葡萄酒，所以我经常想这门课老师开了会不会亏本x总而言之是可以放心选的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d37ba95e21f07cb8de3f9e',9643,9643,'很好的老师，赞',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('61d353a333313d2e403b928e',5292,1954,'给分可以，平时来了，作业写了直接拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d352ceef6f3d6cecccb4f9',344,1135,'给分高 也能学到东西',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d351caef6f3d6cecccb489',209,209,'必须5星分期',1,1,1,3,18,1);
INSERT INTO "reviews" VALUES('61d32fa65e21f07cb8de17e9',10091,1196,'很不错，上了两学期老师的课。大三上学期的微机和大三下学期的电气测量。平时分给得不错。期末也会捞人。我微机就是捞起来的。当时大三下看到有她的课立马就选了。有时上课完了还会提前放',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d32e6233313d2e403b7a01',175,175,'这老师还不错吧。只是这课太难了，谁来讲都不太讲的懂。期末卷面只有37的我都过了',4,3,5,12,2,0);
INSERT INTO "reviews" VALUES('61d32dc033313d2e403b79af',198,307,'讲的不错，平时分也高。可能事情略微多了点，但总体不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d32d275e21f07cb8de1629',903,179,'算是海底捞的典范了，期中开根乘十。当时120个人的班只挂了8个。学了的都应该能过',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d32c5533313d2e403b78e1',246,228,'给分不高，慎选，除了马原61，其他的思修、近现代史和毛概都在75以上的路过',2,2,1,5,7,0);
INSERT INTO "reviews" VALUES('61d32b4533313d2e403b77bc',42,42,'龙哥，懂得都懂',2,2,1,5,5,0);
INSERT INTO "reviews" VALUES('61d32ae25e21f07cb8de141b',408,2119,'想水的就别选了。各种提问还有小测验，平时给分基本就是取决于四次小测。当然学霸当我没说',2,2,1,5,4,0);
INSERT INTO "reviews" VALUES('61d329eeef6f3d6ceccc9d88',2280,2280,'建议别选，期末给分很迷惑。开卷基本都抄了才给卷面50几。期末低于50直接挂',2,2,1,5,3,3);
INSERT INTO "reviews" VALUES('61d32944ef6f3d6ceccc9d24',67,67,'居然没人，绝对好老师啊。我上他的电分，给分挺高的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61d3287b5e21f07cb8de129b',442,573,'扣分贼凶，当时节节课用金课坊点到，课间有时就没签上，没来一次平时分5分，上课抽问一次没回答上的0.5分。运气好的就平时特别高（抽问抽不到加上都签到），运气差的就二十几分（平时40分）。上课也要求严，不准玩手机',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('61d31fe55e21f07cb8de0c05',42,5127,'感谢龙文杰老铁送来的60平时分',5,5,1,11,11,5);
INSERT INTO "reviews" VALUES('61d300cbef6f3d6ceccc392c',175,175,'老师可能上课讲的不是特别清楚。需要同学下去自习一下。但是老师给的平时分挺高。期末会捞你。（值得注意的是，老师期望与同学们有着较好的互动。也就是说他上课特别希望课堂气氛非常活跃。虽然有时候会尬场。）
INSERT INTO "reviews" VALUES('61d2ff9333313d2e403b10ec',1162,114,'不用多说，直接吹爆。平时分直接拉满。期末捞你。
INSERT INTO "reviews" VALUES('61d2fe705e21f07cb8ddb291',1058,5,'陈新红老师yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d2fd3d5e21f07cb8ddb10c',1162,114,'感谢潘小东老师捞我 平时分全部拉满 太感谢了 课堂讲课也比较认真仔细 就是我容易睡觉 呜呜呜呜',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d2c07533313d2e403abcd2',18,18,'我男神，没什么好说的，yyds',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d2c01333313d2e403abc6c',281,9282,'分高，人好，想把我们教好，有什么好说的，直接拉满',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d284965e21f07cb8dd1494',836,23,'老师上课非常认真负责，很有激情，讲解非常详细，每周的实验题都会手把手带着做，基本上所有代码都敲出来了，任务量也不多，老师很和蔼，爆赞爆赞~',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61d2733333313d2e403a5b97',23,5237,'刘老师yyds，不接受反驳，跟着学就完事了',5,5,5,15,44,0);
INSERT INTO "reviews" VALUES('61d253ae33313d2e403a3551',7890,7890,'快跑快跑，平时分太低，不能加她微信，只能在群里问她，还经常不理你******，别选她，你会哭的',1,1,1,3,5,1);
INSERT INTO "reviews" VALUES('61d1c75533313d2e40399880',909,6957,'生物技术制药，讲了基因工程制药，讲了抗体制药，讲了动物细胞工程制药。最后考的大半是分离工程。',3,3,5,11,2,1);
INSERT INTO "reviews" VALUES('61d1c59f33313d2e403996ff',9169,242,'楼上自己学不好不要怪老师
INSERT INTO "reviews" VALUES('61d1b45e33313d2e40398496',831,762,'我不明白为什么qq群有些人会对老师意见这么大，我们专业的人对这位老师的印象还是很好的，老师专业水平很高，嫌作业分低了也有补交的机会，最后一节课跟我们说的话都是掏心掏肺的话，是真的想让我们好好学习，在大学能遇到这种对学生真诚的老师真的很难得了，如果非要说不足的话，就是老师的ppt排版有待改善吧',5,5,4,14,2,8);
INSERT INTO "reviews" VALUES('61d1aca433313d2e40397bb4',751,1652,'师老师人特别好，虽然严厉但是讲课特别细致，有时候还会说自己当时求学的事情和对学生的忠告，真的是那种为学生着想为学生负责的好老师！这门课不好学但是老师想办法让学生搞懂，考试通过，而且考试前还会有答疑，真的是特别好的老师。选到就是赚到！',5,5,5,15,1,11);
INSERT INTO "reviews" VALUES('61d195005e21f07cb8dbfb39',9122,9122,'平时分基本拉满，最多就是实验扣了1-2分，从来不点到，作业量也比较合适，上课也水，不会管你做啥事',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('61d192a8ef6f3d6cecca89ea',9122,9122,'我们学的是工程力学D，老师是一个可可爱爱的老头（也没有很老），上课挺认真，关键是，平时分，给得巨高！超级高啊朋友们！我差两分满分，我知道的还有人直接拉满（分一出我马上来给老师打好评了嘿嘿嘿:)就这样吧复习去了！',5,5,5,15,4,3);
INSERT INTO "reviews" VALUES('61d1083a5e21f07cb8db5ad4',7890,7890,'太苛刻，平时分低',3,3,1,7,2,0);
INSERT INTO "reviews" VALUES('61d06bbe33313d2e40380f6f',4003,4003,'捞了我两次，感谢老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61d043b35e21f07cb8da7463',3253,2792,'讲课水平差劲，毫无逻辑，专业能力更是扯淡，念个ppt都念不明白。论上讲台的资格更是连助教都不如，布置作业的时候像个脑子不好使的瞎子，出题的时候更是像没有脑子的僵尸，随便说两句话群里就有一群狗腿子开舔，不知道怎么能来开课的？',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61cffe395e21f07cb8da26a8',3461,2678,'老师人特别好，不过这门课适合有对象的人听，听了能够更好地处理与恋人的关系，所以指望这门课能帮你找到对象是不可能的哦。最后考试是写一篇1200字的爱情故事，很水很容易过，想凑学分也可以选',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('61cfbe8a5e21f07cb8d9db32',9851,6356,'什么玩意，问啥都不告诉你，ppt啥的什么都不发******真的不明白******，ppt是你的什么学术机密吗。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('61cfbdaf33313d2e4037456a',467,92,'我上周老师课一年了，讲课比较好，PPT的内容一定要掌握，老师很负责，对我也很有耐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61cf453a5e21f07cb8d973ef',2582,2793,'讲课笑面虎，一到考试就捅刀子🔪',2,2,2,6,5,0);
INSERT INTO "reviews" VALUES('61cf2faa5e21f07cb8d9610e',53,53,'作业多，截止时间短，英文ppt，英文作业，课我也听不明白，无奈心累',3,1,1,5,3,0);
INSERT INTO "reviews" VALUES('61cf2ac7ef6f3d6cecc7fb81',515,118,'老师超级好，试卷判得特别松，给分特别高，小测都是送分的，小测扣分了，但最后还是给满了。作业也比较少，没考勤不点名，专业技能特别强。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61cf26a15e21f07cb8d91bc1',491,1529,'刘倩，我的女神，超级喜欢的，真的什么都好',5,5,5,15,12,5);
INSERT INTO "reviews" VALUES('61cf18265e21f07cb8d90b6d',961,762,'杨老师尽力了，没满分是我的问题😭 😭 😭',5,5,5,15,0,5);
INSERT INTO "reviews" VALUES('61cef72c5e21f07cb8d8de47',18,18,'交大概帮帮主的气势！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61cef6b65e21f07cb8d8ddcd',18,18,'老师讲课很容易懂，作业合情合理，特别幽默风趣，交大最好的老师！',5,5,5,15,1,0);
