INSERT INTO "reviews" VALUES('61cef1c05e21f07cb8d8d872',18,18,'老师拿奖实至名归！我爱赵老师！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61cef049ef6f3d6cecc7771e',674,307,'叶老师的课是真的好，PPT做的整洁美观，习题与知识点共重，上课一听就懂，课后把老师精心布置的题目认真做了就会。模电和数电都是叶老师教的，从老师课上学到很多，给分也很不错老师人特别和蔼，经常老师的笑容，问她问题她都不厌其烦地回复，讲到懂为止。总之这么好的老师选就完事！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61ceee9def6f3d6cecc77540',803,1111,'老师人很好，上课讲的很容易懂，作业合情合理。可惜老师要求很高，治学严谨，根本不会捞人，不管卷子难度如何，卷面分低她的要求肯定是过不了的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61ceec2def6f3d6cecc77279',246,228,'老师人很好，上课管的不严，平时任务也很少，给分高，监考的时候还看了我卷子让我大题多写一点，推荐！',5,5,5,15,0,25);
INSERT INTO "reviews" VALUES('61ced6f9ef6f3d6cecc75a83',1021,228,'这个老师真的很好，按照老师的步骤来，可以免考
INSERT INTO "reviews" VALUES('61cecfceef6f3d6cecc751d3',11587,6778,'也不知道什么仇，平时全去，期末试卷全写，平时分满不了，最后不到80，不点名，前半学期讲课 ，后半学期小组展示，也不知道怎么给分',3,3,1,7,2,0);
INSERT INTO "reviews" VALUES('61cebb955e21f07cb8d89436',246,228,'老师人不错，平时分挺高，这次期末考的解答题基本也都讲过，就是平时上课提问比较多',4,4,4,12,0,16);
INSERT INTO "reviews" VALUES('61cea5ffef6f3d6cecc71ba5',1705,1241,'李羿真的是个好老师！
INSERT INTO "reviews" VALUES('61ce9d0eef6f3d6cecc711ec',873,228,'文老师上课有激情，给分很不错👍',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('61ce990f33313d2e4035e4a7',1186,40,'平时分给得是真不错，平时任务不是特别多，讲课也认真，狠狠推荐了',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('61ce981633313d2e4035e3a9',4119,4119,'这门课我每节课都去，每次都有签到，期末也是认真完成了的，最后期末总分只有80几分。给分低不说，每次签到都是纸质签到，助教七点半准时走，也就是你迟到一分钟都签不上，真的不知道为什么一个选修课给分又低事情还多，期末作业不仅要做题，还有一个观后感，还有一个小论文，真的服了，赶紧逃！！',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('61ce89385e21f07cb8d8586e',467,92,'老师很好，讲的很清晰，一些细节的过程也会讲，对理解很有帮助。qq问问题必回，这学期我至少问了几十次，老师没有一次不耐烦，发资料也很及时。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('61ce848633313d2e4035cc2b',2579,2579,'其他都好说，给分巨******低。没缺过一节课，不知道一个选修课打这么低是什么意思。想卷的同学选这门课你就输在起跑线上了。',3,2,1,6,2,0);
INSERT INTO "reviews" VALUES('61ce83c65e21f07cb8d85228',546,40,'平时分巨******低，事情一堆，qq问问题还不回，在群里面阴阳怪气。上她的课听着就只想笑。不信的可以选哈',1,2,1,4,5,0);
INSERT INTO "reviews" VALUES('61ce7fc433313d2e4035c67f',5946,3167,'基础的语音语调都读错
INSERT INTO "reviews" VALUES('61ce7f7aef6f3d6cecc6efc7',1158,26,'高数1,2和线代都跟着娟娟，三门成绩都90+，她真的人太好了，讲的清楚，给分又高，人又很和善，上大学以来遇见过的最好的老师，以后没她的数学课了很舍不得她。不多说了，我爱娟娟。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61ce7e315e21f07cb8d84c1b',11668,11668,'相当一般。空话多，喜欢摆架子',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('61ce70f9ef6f3d6cecc6dcb0',4119,9941,'给分就八十几？不知道为什么我每节课没缺勤期末考也认真完成作业了，比起其他选修算低的吧ヘ(_ _ヘ)',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('61ce6f055e21f07cb8d836c6',3821,4204,'专业能力能打五分的真的不知道怎么想的，这老师上课就纯聊天好吧，一个话题上节课说下节课想起来还能接着说。她纯纯就是两个小时的废话你还得听，不然你不知道下节课要干啥作业要交啥。',1,1,1,3,2,3);
