INSERT INTO "reviews" VALUES('61ce665133313d2e4035a6ee',10379,5946,'老师真的很好，期末我介绍A-SOUL嗯当引流小👻的时候还对我笑了好一会儿😂😂🤗🤗🥵🥵🥰🥰',5,5,5,15,6,0);
