INSERT INTO "reviews" VALUES('61cda8cdef6f3d6cecc5fb95',11684,11684,'这种人能当老师就是个笑话。上课语速快的起飞，口音离谱，我怀疑说的不是汉语。考试范围也不给，ppt也不发，真给我人整麻了',1,1,1,3,0,0);
