INSERT INTO "reviews" VALUES('61cd466a5e21f07cb8d6d0f9',278,228,'课堂小测20道选择题，占20平时分，错了10道平时分就特别低，而且也特别不讲情面，平时自己都做二排认真听课记笔记的，结果最后还没其他班不去上课的同学高，心里有点难受。还是慎重考虑其他老师吧，课堂测是大题形式，不至于给你特别低的分。',1,1,1,3,10,0);
INSERT INTO "reviews" VALUES('61cd053d5e21f07cb8d68c8a',2582,2793,'重点真的背不完，多到不行，PPT一点逻辑没有。
