INSERT INTO "reviews" VALUES('61cc928733313d2e4033cc7d',1991,188,'风趣的课堂，敢讲真话；几乎没作业，一个报告交了就满分；一学期六次点名但有规律可循，翘课很容易，但老师太有水平以致不忍翘课；平时分拉满，期末二十分就能及格',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('61cc8ff833313d2e4033caa2',4306,517,'洪老师真的比易述鲜好太多了，游泳易述鲜就是歌姬吧！',5,5,5,15,9,2);
INSERT INTO "reviews" VALUES('61cc8e5233313d2e4033c940',1381,517,'我真的服了，上大学以来第一次体育这么低，乱给分，也不说为啥，就嗯扣分，慕课视频和题全做完了，分也莫名其妙的乱扣，上课拖堂45＋分钟，还强度那么高，每次上完课都腰酸背痛好几天，想期末破防选她就完事了，真是老太太钻被窝给爷整笑了，群里问起来也不回******',1,2,1,4,8,1);
INSERT INTO "reviews" VALUES('61cc7a885e21f07cb8d5fa50',2582,2793,'应该是这个物流工程专业******，上课阴阳怪气，期末全是重点，还觉得自己给人的压力很小。',1,1,1,3,2,0);
