INSERT INTO "reviews" VALUES('61cbc14e26ed24158b26adca',162,36,'上课不准玩手机，还特别喜欢针对最后一排的同学，抽你起来回答问题，纯纯的******老师，赶紧跑路吧，千万别选，给分也低******。而且喜欢课间拿来点名，还是三连讲中的第二节下课后点名，想水的千万别选',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('61cbbfe7a7c42629e414998e',832,40,'每节课都有reading circle，事情多的不得了，上课一直搞小组讨论，喜欢抽人回答问题，想水的千万别选，给分也低，上课一直到处转，反正事情多得******',1,1,1,3,2,15);
