INSERT INTO "reviews" VALUES('61cb9b0c316b076c47dd8cd9',7435,10848,'想水的人千万别选 平时要赏析10次诗词 每次200字 期中期末又是赏析每次800字，有责任的助教会所有给你拿去查重的，别想着可以抄网上的******上课还时不时走下来抽问，老师喜欢嘲讽理科生天天做理科作业，******文科一样平时没什么作业啊？******动不动就@全体成员，还叫大家要有礼貌，老师群里发消息都要回收到，******真不知道成绩怎么想的，平时成绩和期末成绩37开******平时成绩这么麻烦才总共30分，期末和期中一样的写赏析，凭什么占70%？分是真的低******',1,1,1,3,6,1);
