INSERT INTO "reviews" VALUES('61cb3220a7c42629e413fee6',485,40,'平时分给了55分，就是从来不发PPT，作业什么的从来都是课上说了就没了，下课要做什么都一头雾水，作业要求还是期末复习的一些资料啥都没有',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('61cb30d7316b076c47dd105d',485,3822,'平时事巨多和其他英语老师比起来，要求也多，关键平时分巨低，平时分总分60，最后只给了40，上了一学期是后悔惨了，别选',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('61cb2780316b076c47dd065a',1225,40,'平时分给分巨低，一言难尽，水是水，平时是事少，但是，铁面无私，也不捞人，给分也无情',3,3,3,9,2,2);
