INSERT INTO "reviews" VALUES('61cb22d4a7c42629e413eed7',8138,716,'徐老师人确实很好，很温柔，但是确实有口音，建议上徐老师的课坐前两排，认真听其实能听懂，也能学会',5,3,5,13,1,19);
