INSERT INTO "reviews" VALUES('61cb1604316b076c47dcf2b6',278,228,'修正，不应该是1分而是0分。我******次次课都不缺，小测考得也不差，就因为没回答问题你******倒扣我3分，想扣学生分想疯了吧？平时讲课讲也讲不清，整天扯你去加拿大的事情，你以为谁都想听啊？平时那张臭脸摆给谁看呐？兢兢业业去上课，认认真真考试，结果平时分就扣了我十几分******。',1,1,1,3,32,0);
INSERT INTO "reviews" VALUES('61cb1412316b076c47dcf051',3202,1771,'上的他的数据结构，很不建议选',2,1,3,6,2,0);
INSERT INTO "reviews" VALUES('61cafe68316b076c47dcd6cc',42,5127,'大家品品，有没有道理',1,1,1,3,19,0);
INSERT INTO "reviews" VALUES('61cafd82a7c42629e413c2e3',1381,517,'老师好是好，就是这学期游泳馆就进了一次，评分还算体测，一般同学就70多分，体育牛逼的同学可能高点。现在疫情肆虐，游泳馆很难进，不建议选游泳，一学期下来连蛙泳都没学会，开合跳倒是学会了。我真是牛马选游泳。',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('61cafac6a7c42629e413bfc0',5558,4552,'******啥玩意，课上吹牛逼，调研作业多，分低******',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('61cadf17316b076c47dcb482',8138,716,'******上课话说不清楚，作业布置******一大堆，作业也从来不评讲，课也讲不明白，上课还必须听他上课，不然就要被点起来罚站，真******只会照着PPT读，只会点PPT放视频',1,1,1,3,6,1);
INSERT INTO "reviews" VALUES('61caddf326ed24158b25b104',278,228,'上课不准玩手机，很少带着勾画笔记，有时完全不知道讲到哪里了，PPT也不发，期末也不划重点，给分也不高，',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61caca9326ed24158b25909e',11739,73,'虽然课很水，但是老师挺认真负责的，喜欢😊
INSERT INTO "reviews" VALUES('61caba2b66423c5ce87aad23',11739,73,'不错的老师，耐心水平高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61cab7144808622f59c3d062',11739,73,'老师为人比较亲切，对学生很负责也很上心，每次都很耐心解答问题',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('61cab69c2a948b0f8d041785',11739,73,'叶老师课程讲的挺有耐心的，很负责任，会及时在课上带同学回顾上讲课的内容，讲的很不错，期末也很照顾学生',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61cab503951f4d6f528de0d6',11739,73,'我觉得叶老师蛮负责的，对学生也很好，日常也会抽点名回答学习情况，对于作业和教程也把握的很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61cab3831d1b250426d3bb13',11739,73,'老师挺负责的，毕竟是一门专业课，所以也不是很水，正常水平吧。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61cab2391d1b250426d3b8fc',11739,73,'老师上课挺有趣的，印象最深的是讲极限状态的时候用阿拉伯之春打比方。之前上课从来都没有预习的习惯，但是因为任课老师课前会点名抽查，所以每次上课前都会预习和复习之前的内容，这也对期末复习起到了很积极的作用。PPT课件与教材是配套的，只是提取了一些重点，一些非重点的老师也会课上提及，按老师的要求和PPT复习的话，考分应该都不会低，班上上90分的都有好几个。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61cab01f1d1b250426d3b539',11739,73,'老师教的不错，对于课程的教授很有自己的见解，教授课程时，比较细心，详略得当，很轻松的知道课程的重难点。
INSERT INTO "reviews" VALUES('61ca9e2e951f4d6f528dc651',626,306,'笑了，平时分给的还没我期中考的高，还好自己学了点，有很大挂科风险的！一次交了五六页作业，发下来中间两页没批，没当回事，第二节课过去说我没交作业？我拿上去给我算的补交分。牛，真牛。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61ca1069b13f15777656d9ee',11748,2159,'人挺幽默，也很专业，因为是限选课所以超级水（水到甚至不想出考试题）',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('61ca0f8434646c767bbd9bc0',3370,228,'人挺温和，就是给分太低了，小测拉胯一个平时分就完了',5,5,3,13,0,1);
INSERT INTO "reviews" VALUES('61ca0eab34646c767bbd9b73',10497,10497,'讲课很认真（是真的想让我们学会但是真的学不会）考前给部分重点，给分还不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61ca0e0834646c767bbd9b27',10328,2158,'徐老师！一学期救了我两门课！给分也高考试还给重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61ca0d7cf20b593e748320ea',11752,11752,'上课基本听不清在说什么，考试不划重点让同学们自生自灭，得靠别的老师救济，平时给得没期末高。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('61ca0cc734646c767bbd9aa6',485,3822,'人挺温和的，给分还算不错，几乎全是小组作业',4,4,5,13,0,0);
