INSERT INTO "reviews" VALUES('61c83f52e0fa941b5372dc9d',359,228,'米老师真的太好啦，好好交作业好好开展活动，没有发言最后平时分也能到96。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('61c837dd0e1e3f54f4c5e5b8',278,228,'这种睿智老师真的就离谱，为了不画重点就不去看期末卷子，平时分能打超级低，别的马原班都几乎满分平时分，******你就扣十几分，你可真行',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('61c83734664d4e2ab8c9d7a3',842,6644,'一门水课每次布置******一堆作业，别的班平时基本就行没有作业，平时分也打得最低，选她是******，发个考场座位表都不会发也是没谁了',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61c82078664d4e2ab8c9bc04',278,228,'真的无语了😅 上课事情贼多，很刻板。。。给分也很离谱，全勤还认真做大作业和课堂分享最后得分还不如翘课没去的人高，我只能说赶紧跑😅😅😅',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('61c816ab664d4e2ab8c9b143',598,28,'上课正常，平时分只要你U校园什么的刷满不会低，也不会特意给你给满，作业不是特多，上课氛围很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c7f4cd664d4e2ab8c98719',685,685,'一定要来给老师个好评！虽然没上过他的其他课，但是老师大物实验给了我99分呜呜呜太感动了！！！讲实验内容ppt的时候也是超级细致，很温柔！一定是个好老师～爱了爱了',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('61c7da95e0fa941b53726487',40,40,'每次都不说清作业是啥，作业都是悄悄的发布，悄悄的截止，一个论文初稿全班最高分才85，给分低，总之，老师人好但是办事差',2,2,3,7,3,0);
INSERT INTO "reviews" VALUES('61c74211664d4e2ab8c8e993',40,40,'老师人很好，很有亲和力，但是给分实在是太抠了',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('61c7217ee0fa941b53719a90',23,23,'刘老师上课激情四射，幽默风趣，讲课通俗易懂，QQ随时答疑，超负责，满满正能量，谁上谁爱，yyds！',5,5,5,15,46,2);
INSERT INTO "reviews" VALUES('61c71331664d4e2ab8c88c9f',2598,2598,'这么好的老师怎么能允许没有好评！上课讲的很仔细很认真讲的很明白，然后课后qq问问题老师也会秒回耐心解答，我问个问题直接给我发了四段一分钟的语音过来，太感动了！师弟师妹们快给我选他',5,5,5,15,1,5);
INSERT INTO "reviews" VALUES('61c6d335664d4e2ab8c83ab6',788,9950,'老师人真的很好，属于是想学的能学到东西，想水的也不会为难你的那类老师。超级有耐心，作业也比较少，不像有些老师破事贼多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c6ce39e0fa941b53712e57',1108,188,'前面有些说的太偏激了，客观的说下，上课有人代签所以才点名，难道不是逃课和代签学生的问题吗？为什么抱怨老师点名20分钟。上课无聊确实无聊，但都还是玩手机啊，又不管你玩手机。只好笔记和认真做实践了老师给的分都还是可以的，自己得低分不应该想想自己的问题吗，那么点笔记自己什么态度就拿什么分数，只能说活该。',3,4,5,12,4,68);
INSERT INTO "reviews" VALUES('61c6cc6a664d4e2ab8c8330b',359,228,'老师人很好，上课多发言认真做作业就能免考',5,5,5,15,3,6);
INSERT INTO "reviews" VALUES('61c6a72be0fa941b5371028d',11785,11785,'很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c6a706e0fa941b5371027b',11070,526,'yyds',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c68432664d4e2ab8c7dbd8',2500,228,'虽然老师上课不点名但是也希望选到他的课同学可以认真去听几次，不是那种照本宣科念PPT的，不全讲课本里的内容，但是这样子的话期末建议自己好好准备，不能指望老师一定要给你们划重点。认真完成任务的话可以去卷免考，老师人很nice，还会一个个问对于课程的建议',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61c67c7e0e1e3f54f4c3d563',2200,803,'讲得很清楚，很负责，给分还不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c5ebc4e0fa941b53701f62',803,1111,'讲课很有调理没有口音，例题多板书多，老师很负责，要是给平时分能再多一点就更好了',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('61c5d77a664d4e2ab8c713c4',491,23,'woc，大学第一年就遇到这么好的老师，课堂有互动，生动有趣，实验会给提示和实验资料，做完了她还会亲自给你看一下纠错，尽可能保证你实验满分，平时还会督促你学习，给一些学习资料，有问必答。
INSERT INTO "reviews" VALUES('61c5c6150e1e3f54f4c30c6f',359,228,'免考生路过，老师讲的很认真很好，有实践活动有课堂展示，都是为了送分的，只要积极参与课堂互动就能获得免考名额',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('61c5c20c0e1e3f54f4c307e9',11792,1702,'gtn，fvv老师',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('61c581867e08401d9efd8ae5',969,23,'老师真的很负责任，从一开学就强调实验的重要性。每节课不厌其烦的讲一遍又一遍，还会主动给我们补由于放假而耽误的课，人也很幽默，讲话语速非常快。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61c57ec87e08401d9efd881c',2525,5,'梁老师很不错，上课如果没跟上那应该是你自己的问题，虽然老师很严格，但那是老师负责，而且一般我在QQ上问问题，基本都是一分钟内回答，只能说是很好的老师。那些打差评的估计应该是没学好。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('61c5725a7e08401d9efd7ab5',616,4776,'春哥虽然上课不按书上来，都按自己PPT的讲，但讲的确实也仔细，他也知道很多人上课没听，每次讲到重点都叫最后几排的同学们听一下，上课很好的，都笑嘻嘻的，实验课也没那么严，他知道有些同学没做出来拿别的同学电脑验收，也不会难为你，而且eda有一个手写代码50分，就是平时做的那四个实验中的一个，期中考前两个选一，期末考后两个选一，期末考试你多问一下春哥他基本也会告诉你考哪一个，背下来就完事了，其他问答题基本都是PPT的题，很多和期中考一样的题，',4,5,5,14,0,1);
INSERT INTO "reviews" VALUES('61c5708272ea8d5fe742428e',6726,3691,'千万别选，只会照本宣科，天天点名，还要一个一个去他面前签到，很浪费时间，6.15下课的课每次给你上到7点，还一直说上课多不是他的问题，是我们自己的问题，属实沾点',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61c55d877e08401d9efd63bb',42,43,'龙哥，我素未谋面，但是久仰大名，给个一分是迎合民意',1,1,1,3,132,4);
INSERT INTO "reviews" VALUES('61c55c3fad94a32d64d41655',228,228,'我******，装啥啊，屁都不讲，作业多的要死
INSERT INTO "reviews" VALUES('61c5539372ea8d5fe7422309',1157,52,'这老师整理资料真的很给力 会分享自己的笔记 课讲得不错 讲重点 有时候课前会有小测试 但会给了答案再交 不算分 都是考试重点题型 脾气很好',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61c54bad7e08401d9efd50c4',6319,194,'张雁女士，我的太阳，我会叫你选她的课吗？不会，因为我怕你和我抢',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('61c53ee572ea8d5fe7420b9e',11070,526,'见过最好的老师了，可惜要退休了，祝柳老师生活快快乐乐',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61c53dc072ea8d5fe7420a6a',3407,762,'高数平时分拉满，朱星老师是我爹',5,5,5,15,6,1);
INSERT INTO "reviews" VALUES('61c531a6ad94a32d64d3e62d',210,28,'老师给分很高了，课很水',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c52f83ad94a32d64d3e429',1590,1590,'老师特别好，基本17周的课程都只能见到三两次，上课从来不点名，都是麻烦助教提前十分钟五分钟开始点名自己乘坐里昂到国内的飞机姗姗来迟，上课氛围轻松活泼，非常喜欢打断同学说话，并持续输出，课后作业量非常合适，量特别大，会体谅同学们的交图周考试周然后尽量与之重合，布置下来的任务都会让温柔的学姐给我们安排妥当，自己再阴晴不定的修改，并对学生和研究生给到一个骂。总而言之，特别推荐我们学院的同学都来体验一下coco姐的课程，在课上能学到非常多没用的知识，课程非常热门听说准备扩容，我会给每个没有上过coco姐课程的人强力推荐，不选修可持续环境设计的人不配获得某交的毕业证。',1,1,1,3,31,2);
INSERT INTO "reviews" VALUES('61c528fead94a32d64d3dadd',3407,5,'爱了呀这位老师，平时成绩拉满，讲课也超级好',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('61c5275fad94a32d64d3d7b4',1600,96,'马老师！',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('61c4a3ae72ea8d5fe7419455',18,18,'站在你面前的是交大第一大帮帮主，活水霸榜人，概帮公众号创立者，概率论正宗传人，犀浦校区数学小霸王--赵春明',5,5,5,15,100,0);
INSERT INTO "reviews" VALUES('61c4a2427e08401d9efccc46',2012,1753,'懂不懂符伟老师海底捞的含金量啊(战术后仰)',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61c48e92ad94a32d64d33296',3407,762,'课堂风趣幽默 平时分也给的很高！ 总之选他没错！！！！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('61c47ef87e08401d9efc70c3',239,239,'恒哥带过我们暑期实习，教我们做MIMO仿真。不夸张的说，恒哥是交大大学四年唯一能激发我学习热情的老师。人贼好，带我们毕设经常请我们吃大餐。毕业后还经常联系，互开玩笑，跟朋友般相处。不愧连续几年被评为信院最受毕业生欢迎老师。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('61c47e1bad94a32d64d3216f',246,228,'没旷课非要说旷课，上课提的问也奇奇怪怪，不是正常人能回答的问题',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('61c47d5dad94a32d64d32083',2484,92,'平时分拉满，感谢何老师捞我，呜呜呜她真的好温柔',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('61c4724772ea8d5fe7412688',811,762,'挺好的一老师，一学期就点了两次名。然后讲课速度太快了。尤其是这学期提前一周结课后，那速度直接起飞，低头写笔记时还在7.1，抬头已经是8.3章了。平时讲课偶尔吹点小牛，讲点儿实事趣闻，发表下他自己的见解，还挺有趣的。平时分也给得很不错，基本上都在90+甚至是100拉满。
INSERT INTO "reviews" VALUES('61c46ecfad94a32d64d30e07',373,230,'咋说呢。这老师讲课是真的不太行。平时上课偶尔点名，态度很凶，讲课声音尖锐刺耳，内容也比较尴尬无聊，不如自己看书看材料。然后课后作业巨多巨多！上百道题上百道题的布置，让人脑壳大。但是另一方面吧，她给的平时分确实很高，也不知道是不是平时作业用科技法而全对才达到的。本来真想打差评的，看在比较可观的平时分上，给个中评。',3,3,3,9,0,11);
INSERT INTO "reviews" VALUES('61c4670d72ea8d5fe741120e',1320,3017,'讲的还可以 给分真的低 想水课的别选',3,3,3,9,3,1);
INSERT INTO "reviews" VALUES('61c4638c72ea8d5fe7410bad',1801,543,'态度极差 慕课截止时间离谱 漏交也不能补 扣去全部作业分数 就******离谱 慕课大师级人物 润物细无声 疫情上网课的时候都不给我们上课 一切都是自学看慕课 选了她的工程流体力学课等于迈进了自学的大门。而且她班上的挂科率很高 还会在课上经常宣扬她班的挂科率 助教作业给分也贼低 讲课速度要不跟蜗牛怕似的 要不直接起飞 根本不考虑学生的理解程度 她还总是每天笑呵呵的 赶快避雷',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('61c452d072ea8d5fe740f651',309,309,'崔老师超级好，授课水平高，课上尽可能让你理解记忆，作业也少，对重点把握很准，总之很好就是了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c452c5ad94a32d64d2e355',1600,96,'我爱马老师，马老师yyds',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61c44af472ea8d5fe740ea87',373,230,'老师人挺好的，平时去上课按时交作业就会平时分给满，期末会画重点，背了之后成绩会不错',5,5,5,15,1,0);
