INSERT INTO "reviews" VALUES('61c3fcd072ea8d5fe74090eb',756,22,'建议选谢宁，室友选谢宁一学期没去过一次，别的去过的说整个大教室只有十来个人都不点名。这个老师从开学点名点到最后一节课，期间还会讲乱七八糟的内容，而且我以为至少最后一节课不会点了……',3,3,1,7,2,44);
INSERT INTO "reviews" VALUES('61c3f88272ea8d5fe7408bd7',5219,280,'老师很优雅，好沟通，有点严厉。教的舞不难。男生觉得跳舞不行还可以跑步加分。',4,5,4,13,1,0);
