INSERT INTO "reviews" VALUES('61c2e3adad94a32d64d13d92',1381,517,'u1s1选易老师就对了，虽然上课挺严，但是真的能学到很多东西。老师就是刀子嘴豆腐心，和同学们相处非常融洽，给分也高。易老师yyds～',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('61c2d92372ea8d5fe73f52df',1590,1590,'我真的没见过这么离谱的老师，阴阳怪气，前后矛盾大师。离谱的我不知道是不是我们全部都有问题，有些时候我都自我怀疑了。还自我感觉很多人抢她的课，拜托跑都跑不赢，坐火箭都跑不赢。作为一个老师，怎么怎么随便？我不理解她是怎么避开了所有优点集尖酸刻薄，前后矛盾，随心所欲，划水自大与一身。抛开事实只靠自我想象，专门来为难人的是吧，大家都是来历劫的。',1,1,1,3,9,2);
