INSERT INTO "reviews" VALUES('61c294e9ad94a32d64d0e4d2',1193,28,'分到这个老师真是到了八辈子血霉了，真就一分都舍不得给，60多的平时分******全班平均30分，******，作业贼多给分还低，上课也不知道在讲什么就天天对着个ppt念，还不准拿手机出来，自己安排固定座位是真的nb，英语挂科的一半都是她教出来的，教******高中去吧，就这还来当大学老师。',1,1,1,3,4,0);
