INSERT INTO "reviews" VALUES('61c1ce687e08401d9ef95c32',505,561,'霞姐人真的挺好，后来去答疑的时候说都是为了确保公平实在是有的大图分不能往上打了，唯一需要注意的是作业是要好好写的哈，好好学不会差',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61c1cdb77e08401d9ef95b6a',891,114,'老师人真的很好，墙裂推荐给自学哥，一般老师看你考试不成问题多少平时分给你使点绊子但是陈老师不会，但是俺期中还是改错了道选择总评拿了99',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61c1c85bad94a32d64cffedf',978,5,'真的很可爱，人很和蔼比较好说话，作业还是有点点多，好好学不要翘课翘作业太过分，平时分就会给得比较高。也很负责，半期不及格会单独布置作业',5,4,5,14,0,4);
