INSERT INTO "reviews" VALUES('61c1a010ad94a32d64cfc54e',8541,27,'给爷冲，什么叫捞，对于我这样求不挂科，并且英语基础极差的孩子，这就是个神仙老师啊，哪怕我线上作业落了很多，四级预测考睡过头了没去考，人家也能给我捞回来，他自己都说，教务网那边的老师都说他的班平均分高的离谱（拼命捞人呢），也会一直鼓舞你，QQ常常能找到人，真是一个很可爱的老师呢！小盆友你觉得呢？',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61c191d272ea8d5fe73dda3e',11887,11887,'茶文化水课，平时就放视频，然后签到是给张表传着签，建议宿舍一起选方便签到，个人期末92，真的挺水。作业和考试就是期中和期末两篇论文，很简单的那种',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('61c18e187e08401d9ef8f9cb',1622,1622,'家人们，林妈妈yyds，选她选她选她就对了！真的很好的一个老师，而且真的巨能捞，我为林妈妈打call！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61c1860f72ea8d5fe73db5c4',957,271,'如果说老师上课像一首歌，那么连朝老师的课就像是一首纯音乐，很平很缓，语调几乎一致。一句话来说呢，就是听了想睡觉。但是人很亲切和蔼，有问必答。适合勤劳、主动学习的同学。半期给分很高。',4,3,5,12,3,0);
