INSERT INTO "reviews" VALUES('61c170d472ea8d5fe73d8667',11891,22,'挺好的，上课不怎么管你做什么，讲课有点枯燥，但是总喜欢随堂小考，虽然不批也不算平时分，只当做点名，但也是有点烦，给分也可以，总体上挺好的，你要是选不上特别好的老师，可以选罗林老师，但听课你就不要指望了，上课不玩手机不睡着就万岁了',4,2,4,10,1,0);
