INSERT INTO "reviews" VALUES('61bf56afad94a32d64cc07f5',5581,5581,'老师人真的很好，上课巨有活力，备课非常的详细，你想听可以学到很多小提琴知识。课前都会给大家拉一段小提琴，人也特别幽默风趣。犹记他那个歇后语，厕所里扔炸弹，激起了民愤。作业的话就是写三次论文。反正只要认真对待，给分都是九十几。',5,5,5,15,8,7);
