INSERT INTO "reviews" VALUES('61be765f72ea8d5fe73923bc',489,573,'千万不要选她的课，事情贼多，一个学期要每个小组两次上台展示，讲课完全听不懂，还要你线下做模拟实验，看网课。学生选实验完全不负责，全部推给实验老师做。每次课要消失十多分钟，给分特别低，期中考试用雨课堂，雨课堂的填空题懂得都懂吧，而且是机器阅卷。完全不回答学生在教学群里的提问。有问题老师让找助教，助教让找老师，从来没遇见集众多缺点于一体的老师。每节课要雨课堂签到。一个词，离谱。除了长得看的过去，其余都不行。',1,1,1,3,2,2);
