INSERT INTO "reviews" VALUES('61bcbff2ad94a32d64c902e8',1108,188,'老师对学生对教学非常负责，各个环节把控得非常细致，因为有同学对作业的评分有异议就收上去自己改，这么多同学这么多工作量，真的很负责，把公平公正诠释得淋漓尽致。讲课很细很认真，会就一张ppt讲很多，认真听的话收获的不止于毛概这门课本身，适合想好好学毛概、提升思想意识的同学。希望大家相信并珍惜大学里这年头为数不多坚持着严谨治学的老师。',5,5,5,15,3,52);
