INSERT INTO "reviews" VALUES('61bc0aae72ea8d5fe7362373',1430,1430,'基础的都教了，讲解清晰不吹比。管信的课程设计不合理，离散数学和算法都没有学，c++上学期教到指针就结课了，然后直接来数据结构，更离谱的是和数据库一起上。早知道我就run了。想真的学好还得靠自学，离散数学可以暂时不管，但至少得提前把c++后半部分的自学完。快期末的时候有个小组作业。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('61bc08e97e08401d9ef16a84',10436,10436,'分老师给满了，学习还得靠你自己',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('61bc086672ea8d5fe7362125',1401,1401,'现在变成4000字手写了，我不能理解。她说为了防止抄袭让我们手写，增加copy成本，我理解，但既然老师想让我们写自己的感悟，为什么又要求这么多字？我有心原创，奈何不给路子，上学期写了个3200字的作文，用电脑打字修修改改都花了我半天多的时间，更遑论手写还要改稿，我在期末是没有这么多时间花费在这上面的。',3,4,4,11,1,2);
INSERT INTO "reviews" VALUES('61bc07137e08401d9ef16895',990,1471,'市场营销课，上课水，从不点名，有一次小组作业，期末有复习（懂得都懂）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61bc04937e08401d9ef165ab',86,2797,'曹勇老师治学严谨，博学多闻，上课侃侃而谈，对学生要求严格，专业能力值得肯定。还会带我们去展览馆参观。
