INSERT INTO "reviews" VALUES('61ba9d8ead94a32d64c64f2c',452,965,'生命的听我一句劝，如果不想每节课莫名其妙被羞辱，不想被慕课系统折磨到想紫砂，就千万别选郝静的课，她不是一般的无赖，别的学院我不知道，反正生命都是被她打压➕贷款辱骂过来的，讲课倒也没有多好，还不如我去中国大学慕课自学，但是她一边讲一边羞辱真的让人很伤自尊😅',2,1,1,4,5,0);
