INSERT INTO "reviews" VALUES('61b96825ad94a32d64c4d165',1108,1065,'讲的慢，喜欢让学生在名单中签到后最后一节课再一个一个点名。还让做笔记，我问了其他朋友的毛概老师都没有这个要求，最后交笔记还要一个一个点名上去交，课都没教完，我的评价是：吃饱了没事干。反正这个老师一点都不水，讲课也一般，给分也低。选她的课你就赢麻了，这样的好老师哪里去找。选吧，最后直接起飞。',1,1,1,3,27,0);
