INSERT INTO "reviews" VALUES('61b6b77bad94a32d64c197f7',2078,23,'课堂死气沉沉，会点人回答问题，讲的全是书上的内容，特别爱拖堂',1,1,1,3,1,2);
INSERT INTO "reviews" VALUES('61b6af82ad94a32d64c18ed4',1108,188,'太坑了，每节课点2次名，期末还要检查笔记，检查的时候才说范围，真是无语，这课谁来谁知道。大无语',1,1,1,3,11,0);
INSERT INTO "reviews" VALUES('61b6ade472ea8d5fe72fbd84',1108,188,'差评。别来，平时上课要点两次名，贼严，最后还要检查笔记，别的班的老师什么事没有，真破事一堆，真的别来。',1,1,2,4,10,2);
INSERT INTO "reviews" VALUES('61b61e49ad94a32d64c1199e',736,551,'我爱周老师！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61b60be172ea8d5fe72efe5b',1608,1608,'老师布置的作业很多，课设很难，但是真能学到东西的。备课PPT准备的很用心，讲课也注重细节。唯一的问题就是希望老师能在群里多一点互动。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('61b6021e72ea8d5fe72ef22b',2500,228,'袁老师yyds!上课不死板不是照着课本念的，有自己的思想，感兴趣的同学听课可以学到很多！有机会选就对了！作业认真完成有真正的去想，上课积极讨论免考没问题！👍 一百二十分的老师！很认真的给你的作业回复，也给你提建议',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('61b5ee1d72ea8d5fe72ed96c',751,573,'师老师人很好，我之前因为生病而缺席了期中考试，补考的时候师老师专门从九里到犀浦帮我改了期中成绩，让我过了',5,5,5,15,5,8);
INSERT INTO "reviews" VALUES('61b5bf06ad94a32d64c06fb6',4352,4352,'瑜伽课很水，真的水，水的一批，上课水，考试更水，轻松每学期。但这老师给分真不行，贼低而且不接受任何请求，别人班均分90+，这老师就喜欢卡80，问他体测的事一直逮着我慕课叨叨叨个不停，从来没有这么反感过一个老师。',2,2,2,6,5,0);
INSERT INTO "reviews" VALUES('61b5b02c7e08401d9ee9ce06',4820,241,'上课纪律稍严，喜欢点名，上课喜欢放视频，自己不怎么讲。感觉水平不行',2,2,1,5,1,1);
