INSERT INTO "reviews" VALUES('61b5883c7e08401d9ee99e04',12052,2586,'经常迟到，但给分还好比李攀低一点但比张晶高，我最后90+，期末会划重点，平时就一个汇报',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('61b5878e72ea8d5fe72e615e',1212,1471,'中规中矩吧，经常抽人回答问题。但没有考试，期末有个4000字报告（其实挺好写的），给分一般90+吧',3,3,3,9,0,0);
