INSERT INTO "reviews" VALUES('61b4e2adad94a32d64bf9ee7',202,82,'私以为张同刚老师是本校工程测量授课教师里比较nb的一位老师，不得不否认的是他的普通话说的非常不标准，但是仔细听渐渐是可以听懂的，而且会觉得他讲的特别全面，基本期末考试的题都是他上课讲过的',5,3,5,13,2,3);
