INSERT INTO "reviews" VALUES('61921de2f277b028fa81aa6d',278,228,'不知道刘老师是不是平时生活特别不顺，感觉对学生恶意很深，很多很平常很普通的小事，她给人的态度就让人感觉很厌恶。动不动就当缺课，扣平时分，自己倒是先保证自己的课程能吸引学生啊，马原课抽问学生抽到回答不出来不是很正常吗。为什么还要引申出同学生活态度方面去呢？我为我的同学感到生气，还在期中，不敢说她平时分最后给的怎么样，但是她每节课上课的态度，说话的语气，真的挺让人受不了的。劝退劝退劝退！！！',1,1,1,3,40,0);
