INSERT INTO "reviews" VALUES('6142ad81b0fc702a29dc10e5',24,24,'小武yyds，除了每节课小测不太水之外，真的很认真负责给分很高，缺课还会另找时间给你辅导，泪目了家人们',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('6142a5a6b0fc702a29dc0600',2267,177,'讲课废话很多，语速慢，还能提早讲完，你细品。平时分给的很严格，我平时比较认真，也只有八十多分。擅长自学的同学可以找他，对了，还提问。',2,2,4,8,3,0);
INSERT INTO "reviews" VALUES('61429d60fb77015d809ad933',885,885,'不知道前一届为啥对何必胜恶评这么多，何必挂都出来了，我大学四年三门课是他上的，一门都没挂过。我上完他的课感觉是个蛮不错的老师，期中开卷，作业当堂交写了东西就作数，课设也是三连讲拆最后一讲出来检查不影响吃饭。要说有什么缺点就是期末重点勾了个寂寞，歪到姥姥家去了，不过那次期末考的也比较偏，怪也怪不到必胜头上。最后我期末考了个75，他平时分给了我98，课设也给了我九十几分。当然这些是从我个人的角度评价问题了，从微控来看何必胜的挂科率和高分率都很低，考虑到这一点的话我的意见是只想求过的学生他非常值得选，但如果你想保研冲高分，还是躲着他走吧。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('6142941efb77015d809acdfb',23,4181,'我在大一遇到过最认真负责的老师',5,5,5,15,57,0);
INSERT INTO "reviews" VALUES('614225d85e26b06dbb2008b6',24,24,'小武yyds 理力就选他',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6141dda8fb77015d809a3e48',442,573,'老师真的会捞 狠狠泪目了',5,4,5,14,1,3);
INSERT INTO "reviews" VALUES('614192f4b1aa8a041712e8c2',7120,1267,'老师很和蔼可亲，上课气氛非常好。平时有一次期中小组汇报，期末写一个课程报告，如果好好听的话还是能学到很多东西的。总的来说推荐',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('61417aaab1aa8a041712cb83',12229,6532,'如果要我对当初选这门课的自己说一句话，那一定是：快逃',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('61414fb7b1aa8a04171290a0',196,2167,'老师和蔼可亲，答疑解惑很专业',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('61414f54b1aa8a0417129040',888,779,'选上高老师的课程就不要考虑其他人了',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('61406f535e85cb71ed211426',6323,23,'上课******，只会念ppt，基础的东西也不讲，直接念书，本人期末59分美美挂科',1,1,2,4,1,0);
INSERT INTO "reviews" VALUES('6140568cd6508519cb5a9471',491,1529,'老师 yyds 老师真的很好 很负责 老师贼好 选就对了',5,5,5,15,9,0);
INSERT INTO "reviews" VALUES('614050bcd6508519cb5a8e15',1052,1052,'感觉老师上课前是不是摔了一跤，火气这么大，期末只给60分',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6140034db1aa8a04171135f5',12235,12235,'只要有机会选上就不要考虑其他的课程了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('613f5cf4b1aa8a041710abfc',7062,779,'讲的不行，事还多',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('613f16bfb1aa8a041710508e',344,793,'太好了',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('613eb1815e85cb71ed1f120c',2259,1129,'计图一般周一早八，加上老师一路平坦的嗓音和讲课节奏，赋予了这门课极强的催眠效果。上课看来到的人数多少随机点名，理论课作业不多，实验课往届的拿来改改就能用，给分还可以。最后，半期开卷，没买书的记得去整一本',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('613eafe2b1aa8a04170fc135',12239,496,'如果开列一个我院最仁慈的老师名单，谭老师必然榜上有名。干练的背头、浓眉如墨，一看就是个慈眉善目的小老头。老师讲课带点口音，吐字也有点不清楚，讲课节奏也有点慢，上课不太能听得进去。（不过计网这门课不全是自学的吗😁）作业是老师自己批改的，晚点交也没问题，半期考试相当于开卷，课程设计交了就基本能及格，也没用特别严格的时间限制，别耽误期末等成绩就行了。每节课都会点名但不会仔细看是谁，所以（嘿嘿嘿）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6130cc90c4ccb57a9d9069dd',11958,12240,'老师比较专业，外教，爱说English，不点名，课上会提问，参与度高主动发言的加分，会分组（找好队友很重要）做PPT，期末演讲，还有可行性报告，文献检索报告，作业涉及医疗知识水平较深，要求高分低，上课感觉不错，期末结果出来冒火',4,3,2,9,1,0);
INSERT INTO "reviews" VALUES('612e1cf55bc1f84d2c22654f',23,23,'刘老师yyds，能听懂，会操作，考试分高，上课也很好玩',5,5,5,15,61,0);
INSERT INTO "reviews" VALUES('6124e744d1f2052035af6456',948,92,'可能挂人了，绝对的冷酷无情，教完就完，上课讲的也贼快，也不管你听没听懂',3,3,1,7,2,3);
INSERT INTO "reviews" VALUES('611b196af8503b7c879fa1b0',489,573,'给个6分，这颗星是多出来的',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('6108ba5c1de21d3e073744ca',803,1111,'老师上课古板',3,3,5,11,0,3);
INSERT INTO "reviews" VALUES('6103a95c0d8ec52cd8293db7',36,36,'太把自己和这门课当回事，觉得自己严格要求像是个好老师？全******严格在分上了，笑面虎一个，平时分也不上传，放假后直接上传总分，一水的不到75，75啊！！！******一个，上课跟访谈节目似的，一节课提问七八个人，拿着老掉牙的邻里纠纷家庭琐事类的鸡毛蒜皮节节课的：“这位同学你怎么看”，我看******，我******想锤你。总结：明明水课一门，非想上出花来，可惜他功力不够，整个一大型尬死社死现场。事还贼多，中期1000字论文，半期考试后接着要小组视频展示，最后给的分数气吐血，直接拉垮均分、排名、绩点。******',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('610206591de21d3e072b4680',505,561,'老师平时分给的很高，人非常温柔，课除了讲的有些快之外挑不出任何毛病',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('610205f81de21d3e072b45c1',1058,5,'老师很负责，很随和，问的问题都会解答，但是表达能力不行，上课经常讲着讲着自己都不知道自己在说什么，搞得人一头雾水',3,3,4,10,2,0);
INSERT INTO "reviews" VALUES('60ffe38f0d8ec52cd8235bb8',760,142,'培培上课讲的细致 作业完全按照作业系统给分 没有期中考试和小测 作业系统可以反复刷到满分 而且作业系统题目本身也不是很难刷 选培培就对了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('60ffcf841de21d3e0727d66a',2390,186,'老师上课幽默，认真，能力强，喜欢和学生互动，选她就对了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60f91aff0d8ec52cd816dfc9',760,142,'讲课非常细致，会板书重点。
INSERT INTO "reviews" VALUES('60f7eac90d8ec52cd8143b1b',82,82,'讲课不说，实习真的******，要求不一次性说完，之前说的东西一直在变，是真******，如果实习请换个老师！',1,1,1,3,1,8);
INSERT INTO "reviews" VALUES('60f450578da04f4456bbc114',293,375,'作为学生 在乎的无非就是一个分 即使所有人都说这门课水 给分高 我还是没有缺席一次课 每次上课都签到了 且我的慕课已经刷满 几乎每节课都会回答问题 （回答问题会有加分）我不太清楚为什么我的平时分依然很低 比那些翘课不来 不回答问题之类的学生低了近20分 这真的很恶心人 对于这门课 大家可以报 它还是一门水课 对于大多数人 老师给的平时分还是挺高 只是希望你运气好点不要成为像我这样的少数人（老师会有指标 一个班的成绩不会都高 看你运气好不好了）期末也看他的心情给分',1,1,1,3,18,7);
INSERT INTO "reviews" VALUES('60f44f698da04f4456bbb925',42,43,'******
INSERT INTO "reviews" VALUES('60f3fdf92c88c922c2e005b6',7062,1606,'一星都不想给 什么鬼******要求还真******',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('60f21fa58da04f4456b730cd',563,228,'上课固定座位，谁没到直接看出来，声音极小而且高高在上的样子，从来不讲重点，每次作业相当于抄书（每章都抄知识点），平时成绩给三十多分（总五十），重点：期末结束后就是不出成绩，就是给你拖，还第一个退出教学群，老师第一个退群呢，你见过吗？太二真人，属实牛了',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('60f1c2c08da04f4456b6bfc5',248,48,'老师人很好 有很多可以加分的东西 认真练习分数不低！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60ef107153922a4cf70129c7',8384,230,'上课有意思，但是平时分给八十多是不是有点过分了，没签到和签到的一个分',5,1,1,7,0,1);
