INSERT INTO "reviews" VALUES('60ee657d53922a4cf7ff96bd',1175,761,'老师人很好，本来是奔着水课给分高去的，结果没找对队友，就挺忙的，找对队友很关键！一学期会做大概5个ppt，最后有期末作业，讲台上展示。老师给分很高，平时分拉满，期末作业也给了90+，总评96，应该不算低，也学到了不少关于信息检索的知识。推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60ee646253922a4cf7ff92fd',1048,6654,'老师人很好，而且上课不点名。我跟着他学的是线性代数B，总评95+，会拓展知识，但就是觉得讲课逻辑性比较差点吧( •̥́ ˍ •̀ू )，还有小测不提前通知，但考的比较简单。要是想总评拿满分，不建议选，因为小测不提前通知，比较容易扣点分。总体来说，还不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60ee5ae91df7645d57b5d42d',2961,761,'每次作业按时交 每节课都去 平时分58 就这啊？',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('60eda78753922a4cf7fe448c',489,573,'这叫什么，这叫雨课堂说啥就是啥，这叫预习题大家都会，我不需要讲。这叫网课真的就是神，大家听网课就全部都会了！！！
INSERT INTO "reviews" VALUES('60ed85711df7645d57b4396c',6761,2792,'老师人挺好，给分很低，作业就两次，还有一次期中，我课堂上她提问一个没回答出来直接扣我2分，50分的平均分只有40分，更何况我期末考了95分，赶紧跑吧',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('60ed48bf1df7645d57b39cf2',23,23,'我永远的神！难忘的一学期，买一赠一，C++90+，外加收获很多人生哲理。话说刘老师的课太难选，拼到第三次选课才幸运进入，太值了！nice！',5,5,5,15,46,0);
INSERT INTO "reviews" VALUES('60ed3e8353922a4cf7fd3d8b',3286,12266,'老师挺好的其实  水货别选  小组作业认真做好就有高分  给分很公平  但是迟到早退缺勤肯定会扣分  可以合理请假啥的  作业多但是期末没有口语考试  没好好做就别说老师给分低了👨',5,5,5,15,1,2);
