INSERT INTO "reviews" VALUES('60ed0f9c1df7645d57b30b02',31,31,'说秦老师是交大最好的数学老师都不过分。出的小测难度略大，但判卷很松，尽量把能给的分都给到。讲得特别好，人也很好，强烈推荐！！！',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('60ed0efa1df7645d57b309aa',23,23,'无需多言，选就完了。不仅能获得高分数，也能学到不少人生哲理。',5,5,5,15,44,0);
INSERT INTO "reviews" VALUES('60ece0d71df7645d57b28cde',10328,12271,'关于实验课程，徐柳老师真的非常好欸～非常关心学生，照顾每一位同学的实验，对于基础不够充分的同学也很关照，强烈建议大家选徐柳老师的课！',5,5,5,15,0,0);
