INSERT INTO "reviews" VALUES('60ec58f91df7645d57b1a85c',1756,52,'老师人美声甜给分高 平时分拉满 讲的很细很好 真的太感动了',5,5,5,15,1,12);
INSERT INTO "reviews" VALUES('60ec4fbf53922a4cf7fb53ce',5198,376,'太喜欢赵老师了，课上的非常精彩，会讲很多有关的工程实例，课堂有趣轻松，根本没时间走神。有问题也会细心解答，并且平时分给的高，台棒了！',5,5,5,15,0,7);
INSERT INTO "reviews" VALUES('60ec2ba21df7645d57b13bc3',11958,12240,'如果你想研讨课可能会挂，而且学不到任何东西，上个选修还要做一堆其余课不需要的东西的话，那就选他吧',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('60ec259653922a4cf7faf58a',736,551,'四十来分给我捞上来了',5,5,5,15,0,0);
