INSERT INTO "reviews" VALUES('60ea7b4453922a4cf7f744b3',11950,2598,'老师讲的很好 知识点讲的很全 唯一的缺点就是助教给分太低了 错一点点等级就是A 错个两三个细节就A- 按十分制每降一级扣一分 作业占比很重 稍微不注意一些就会在作业扣很多分 相比较其他老师基本打满平时分还算比较低的',5,5,5,15,3,0);
