INSERT INTO "reviews" VALUES('60ea610e1df7645d57ad4c2c',8955,8955,'55555武老师yyds，看我们太菜了还把大作业和期中取消了，平时讲的也很细，期末用的max（加权，期末）就算你期末考的差也可以靠平时拉起来，作业不会放水，但是期末会',5,5,5,15,0,2);
