INSERT INTO "reviews" VALUES('60e9835a53922a4cf7f56b68',3370,228,'老师原来在新东方讲考研，教学水平很高，但是因为是新老师打分很严格。平时小测很多，大约五六个，都是考研题，很花时间。平时要写一篇小论文，总的来说平时分给分不高。期末有部分原题',5,5,2,12,0,0);
INSERT INTO "reviews" VALUES('60e982fe53922a4cf7f56afc',1694,12297,'杨老师教学很耐心负责，虽然由于本身不是专门研究逻辑学的而在专业水平上有所欠缺，但是教学的质量还是得到了保证，授课的方法体系合理。最重要的是给分也很高，很推荐大家选课！',5,5,5,15,0,0);
