INSERT INTO "reviews" VALUES('60e6c33f1df7645d57a5fe44',819,228,'我说实话老师讲课水平确实高，结合实事，用到有趣的视频材料，引发大家思考，如果真想学东西的话建议选。奈何我只是想把这门课当水课，可惜这老师真不让水。每节课都抽人回答问题，实践任务也不好水。我上课全去自习去了，没主动回答过问题，任务每次都完成了，得分也都在85以上，最后平时分86.6，同学们平时分平均分80多，追求免考的90+，这么看还算可以。然而隔壁某老师水过去的平时都给90+，期末还告诉你具体考啥，要背啥了。。。这么看又有点不平衡',5,5,3,13,2,0);
