INSERT INTO "reviews" VALUES('60e5d3711df7645d57a41c83',9882,22,'真的麻了，他平时分算错了我们去找他改过来，说我们计较这一分两分，最后找他的人期末都挂了，都差一两分，我朋友学的特别好，期末45分你敢信？避雷，这是我遇到的最离谱的老师，绝对不会捞人，平时分7,8分，作业成绩按每次作业的平均分算，死板至极。你过了看你不顺眼你也不过！绝对不会捞人！避雷！别选！快跑！',2,2,1,5,4,0);
INSERT INTO "reviews" VALUES('60e5bd3f53922a4cf7eda515',23,23,'能作为非优选班选上刘老师的课真的是我来到交大最幸运的事之一。刘老师真的是用自己的教学水平和人格魅力吸引了每一个同学。多的不说，刘老师yyds!',5,5,5,15,44,0);
INSERT INTO "reviews" VALUES('60e5b41e53922a4cf7ed8f4e',491,23,'遇见刘老师简直是我的荣幸，老师很负责，考试没考好会询问学习情况，上课很轻松，每节课都有复习，整理的复习资料也很全面，超级超级棒',5,5,5,15,10,0);
