INSERT INTO "reviews" VALUES('60e580531df7645d57a34dd1',247,27,'每节课都要点名，作业多的不行，在原有的作业外还经常给你布置演讲或者做PPT汇报诸如此类无意义且麻烦的事情。每次上课特别特别啰嗦不知道在讲啥，本来可以一句话表达的东西，要给你扯一大堆，真是罗里吧嗦的，怀疑老师可能逻辑不太好。而且专业知识根本不讲，一般就是给你放一大推听力，听完后到处抽人起来回答问题和答案，或者就是整一大堆听写。毫无收获可言，而且巨喜欢点人回答问题（但是回答问题多且正确平时分会高一点）。总而言之，从未如此讨厌英语过😅',2,2,3,7,1,0);
