INSERT INTO "reviews" VALUES('60dedf9b53922a4cf7df2d2d',348,348,'******还带有口音，吐词不清，专业水平也很一般，而且对学生考试注意事项这一块不怎么负责，反正不是个啥好老师 ，要不是只能给1分，我就给0分了，还有，他的学历可以自己查查🌚',1,1,1,3,16,2);
