INSERT INTO "reviews" VALUES('60de7d1c1df7645d57946e03',2500,228,'好老师，平时分最高的五个人不用参加考试，作业都可以补交，上课基本上不管你，平时分高，人很和善，点到没来也没关系，不算分',5,5,5,15,2,2);
