INSERT INTO "reviews" VALUES('60db5294a7e6a033144cad2e',4084,8140,'易大师，选线扛把子，上课完全不知所云，东拉西扯，自从网上与线下课程结合之后，一个月上一次课，自己还不一定去，MOOC和线下作业多的要死。课程设计讲了和没讲没有区别。4学分的选线估计要没了，TMD后悔。',5,1,1,7,2,0);
