INSERT INTO "reviews" VALUES('60db4d45ed7bbe47477eb7a3',6705,1753,'老师讲课比较清楚，上课节奏不快，重点会讲的比较细致甚至很详细地推导一遍。平时测验和半期考试的难度就是平时课上或课后作业题的难度。
INSERT INTO "reviews" VALUES('60db4d26ed7bbe47477eb791',336,2,'看楼上那位同学绝对和我一个班的（仅针对轨道工程A），无比赞同他的评论。每节课都会布置一些莫名其妙的作业，突然让画几个轨道结构的CAD就离谱，CAD还超级复杂，还动不动就去机车园，之后还点人上黑板画图，连续几个没画出来就扣全班的平时分，上课简直是煎熬。',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('60db4b55ed7bbe47477eb4f7',7785,32,'因为职务原因偶尔会不能上课，上课讲的会有偏题，讲课不是很好。但是！！！平时分拉满，我以土木倒数50名以内的名义发誓！我期末30多分愣是给我过了，凭这一点崔凯yyds！',5,4,5,14,0,0);
