INSERT INTO "reviews" VALUES('60dadc34174cbb36fe6011eb',2885,3822,'上了刘老师一年的课了，从英语到演讲，老师很和善，很漂亮，你就算睡觉老师也不会管你，平时作业会有在QQ群提交，超时未交了就比较麻烦，好在内容都是课上完成了的，所以不太耗时',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60dadb49ed7bbe47477dce1a',674,307,'老师很和善，讲课的时候都是笑着的，很少点名。最大的优点是你QQ找她问题都会尽快给你解答，就算是冗长的代码她也会给你纠错，不过平时分给的一点也不马虎，设项很多，平时作业改的该错就错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60dad0eafee95b52f5c893fd',12552,3645,'老师挺有趣，负责中医部分讲解，巧了的事每节课必点我（看到这张脸就走过来拍桌子说这位同学你来回答一下），当然了，我对副院长印象很好，相信真心想学到东西的同学不会失望。',5,5,5,15,1,0);
