INSERT INTO "reviews" VALUES('60d9e28c591ae10031dd4649',6087,9073,'上课声音很小，问她一些问题也说学生应该自己把握，结果到最后期末考试，虽然是开卷，本来做完觉得还行吧，结果非得给我扣那么多，上课回答问题平时课堂表现分还没有其他同学高，原来问你名字是要给你扣分的，******再也不会选了',1,1,1,3,4,1);
