INSERT INTO "reviews" VALUES('60d896da591ae10031da918c',2173,2173,'老师人很好，但是不建议物流工程外的同学选，哈哈哈哈。老师讲课很清晰，人也很好。我觉得还不错了，期末也有重点',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('60d88d428f119d3e25b287c0',7812,12576,'老师很负责，但是屁事是特别特别多。快跑，如果想要学习到东西也是可以试试的，但是事情是贼多，怕了怕了。期末不考试但是有汇报，而且印象中经常拖堂。它不是正课呀😭😭，老师们心里都没点数吗',4,4,4,12,0,0);
