INSERT INTO "reviews" VALUES('60d6eaf0591ae10031d76f79',258,43,'陈老师是真的好…最难的几个实验，我们班同学都是合作完成的，验收的时候陈老师看出来大家的代码差不多了，但是她完全不在意这些，直接说了一句:“只要你们懂了就好”，那一瞬间真的觉得这才是老师的样子。',5,5,5,15,7,3);
INSERT INTO "reviews" VALUES('60d52bf1591ae10031d3df28',2413,71,'彭老师性格挺好的，专业知识至少就课程来讲没问题，学生有问题去问会很认真地回答，平时上课宽松也很关心同学。个人觉得课程本身确实阴间，但向其他班了解了解就会发现都是这么上的（PPT暴讲，但有板书视频和讲解），不错是真的不错。',5,5,5,15,0,0);
