INSERT INTO "reviews" VALUES('60cc13b58f119d3e2599dfa7',11950,2598,'讲得确实很好，大部分时间都在讲例题，结力理论本来是挺不好懂的，但是他例题讲得多，就很容易听懂，很有优点的一位老师，可惜好像我们是最后一届他教吧哈哈哈哈，后来者没机会了吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60cc1042591ae10031c19264',1320,3017,'张老师是一个非常有亲和力的老师，英语真的是我最厌恶的大学科目了，当得上阴间二字，往往屁事情多而且学不到东西，英语课我是真的不爱上，但是张老师真的给我展示了什么是大学老师该有的样子，上她的课首先听得进去，两节课甚至眨眼间就过去了，之前三个学期的英语课对我来说都是折磨，其次是虽然英语屁事情多，但是张老师真的是把屁事情压缩到挺小的水平了，期末考口语要准备十个题，她让我们选其中最拿手的四个题，给分低不低无所谓，而且也不算低了，起码让英语这个阴间科目变得阳间了，她就是一个优秀的大学老师',5,5,5,15,5,1);
INSERT INTO "reviews" VALUES('60cc0e86591ae10031c18f4d',1320,3017,'可能是最好的英语老师了，直接让英语课的阴间程度下降到了最低。认真负责，为学生减轻负担，上课也很有趣，从没想过这学期唯一听的一门课竟然是英语。👍🏻',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('60ca9f9cf5b5c278f0809308',489,573,'老师讲得很差劲，平时分给的还很低，真的很讨厌，作业很多考研真题，特别离谱',1,1,1,3,1,0);
