INSERT INTO "reviews" VALUES('606d1a55172f751cee86f71f',3764,3691,'这个老师教的信号与系统，通信原理，数字信号处理建议大家都别选！上课大舌头听不清讲啥，全程念ppt，作业做完交了也不批阅不给答案，信号与系统考试不说范围重点，期末考就是找别的学校都期末试题给你做，你复习一点方向和侧重点都没有，上课比学生还水，给分也不高，慎选！',1,1,1,3,2,2);
