INSERT INTO "reviews" VALUES('6059d9624bcfb013cb38f068',280,280,'不要问她任何问题，她不会回答的，甚至还会莫名其妙怼你一顿说你自己不去找别的地方，即使是教务通知问题，她也会刻薄地乱骂一通然后直接走掉。体育舞蹈要自己组队编舞，给分很低，给了八十几就以为自己了不起是活菩萨了，天天吹嘘自己。但是客观的说她的分是正常的，不会给低分反正，上课是稳的。',4,2,1,7,5,0);
