INSERT INTO "reviews" VALUES('60589d82eec6e5629f93f018',2713,2713,'老师是天津人，上课时偶尔夹杂的天津口音让人忍俊不禁，听惯了老师们的四川口音，听王老师讲课也是一大乐趣。上课条理清晰，重点突出，干货满满，和蔼可亲，很能被老师带入课堂的氛围中',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('60589b174bcfb013cb367db9',8764,8764,'和蔼可亲，笑口常开，学识渊博，授业解惑细致入微，一位非常可爱的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('605899bb4bcfb013cb367abc',1853,670,'一句话，能跑就跑。平时分给的挺高，能给满的都给满了，但上课风格见仁见智，我是不太喜欢，老师总是命令你画这个写那个，一度让我梦回小学三年级。教学进度的安排不合理，中间拿出近一个月的时间让全班分组讲解书上的汇编程序，半期考试硬生生推到13/14周，进度远远落后于其他老师的教学班，以至于后面整整两章的内容一节课直接带过，让我们放心，说期末考试不会出这两章的题，结果期末还出了这两章的大题，还说别的班都学了，不考的话说不过去???考完试还没完，让我们补交一个课程设计，说是教务的安排推不掉。可能是因为老师比较年轻，教学经验不太足，我也相信老师的教学水平会越来越高，不过在此之前，我不想学弟学妹们成为“炮灰“',4,2,2,8,5,0);
INSERT INTO "reviews" VALUES('6055782d4bcfb013cb301d7c',23,23,'绝对好评，大爱霓姐的课',5,5,5,15,45,0);
INSERT INTO "reviews" VALUES('6054901aeec6e5629f8bb709',476,476,'好迷的一个老师 每次评判都按照自己的立场去做 实验不明确他要求的是什么 同学问他以后改进的方式以及他具体实验的要求他都不去说 还说我有我的评分原则 你******评分原则和要求是什么都不说 直接说不满意可以调班，不让我们找他理论 真的迷之操作 实验前什么都不发直接说来实验 别的老师都事先发一些实验要求和表格啥的 实验的时候说话的声音也小的要死 都听不清楚具体操作 实验的时候就一团懵 还有平时上课声音也很小都听不到 直接让人听了想睡觉 直接差评 上他的课感觉一点没有意思 班级群就一点用都没有，发课件和作业都是给教务发邮件 很多同学也基本不看教务，QQ群发不就完了嘛 还省事 真的很迷******',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('60522c8e8479e425fa0f1d75',4981,4981,'没上过这个课，但是这个老师教过专业课。老师本人知识渊博，非常有内涵，能提出很多很好的意见，待人也十分亲和。真的非常非常有知识内涵，很厉害，让人崇拜的一个老师',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('60506fe28479e425fa0ac3b7',12648,12648,'大学期间见到为数不多的非常有趣的老师，蒋老师水平很高，上蒋老师的路基工程从来不会感到无聊，有江浙口音，非常幽默，会给你讲他去日本留学的经历，用工程界各大案例给你讲关于路基工程的知识。对于考研的同学，蒋老师第一节课就说上我的课从来不点名，平时分会给你高分，强烈推荐！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('604ffb6eb725a143ea7d112e',6323,23,'上课只会“呃”“呃”“呃”全程读PPT伴有听不懂的讲解',2,1,3,6,2,0);
