INSERT INTO "reviews" VALUES('604eea93b725a143ea7ab86a',637,694,'上课通俗易懂，给分也比较宽松，人也很好，ppt也做得不错，推荐',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('604ee9e88479e425fa06ebf5',5145,12652,'讲课很枯燥，只要课后把作业都弄懂，ppt过一遍，不听都可以。但老师人挺好的，给分比较松。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('604ee92cb725a143ea7ab306',6398,1196,'讲的还可以吧，前期跟上有点困难，后期就稍微轻松一点。反正就是好好听课吧，老师改卷很宽松，人很好。',3,4,4,11,0,0);
INSERT INTO "reviews" VALUES('604ee4f1b725a143ea7aab01',844,850,'只要上课认真听了，作业好好做了，期末80没问题。如果再加上认真复习了，90没问题。老师上课很健谈不觉得枯燥，拓展很多课外的东西，只要好好听了受益匪浅。唯一的问题可能就是课程后期进度拉得有点快，有些内容没有讲透，但所有考点都讲到了，如果是肯定会考的还会强调重复几遍。总而言之，这门课只要上课好好听，没有学不好的。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('604ec7d7b725a143ea7a64c7',11442,2387,'不说了，谭永霞yyds！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('604eaa33b725a143ea7a1848',751,573,'应该是来自山西的老师，身上透着一股子三晋人的霸气。很严但是讲课很清楚，找他答疑特别耐心。不过这门课期末是统考，题目不简单，考不好怪不得任课老师。',5,5,4,14,0,5);
INSERT INTO "reviews" VALUES('604d75308479e425fa02c55a',18,18,'大学遇到过最好的老师! 平时喜欢在群里和大家唠嗑，经常深夜还在答疑。上课风趣幽默，经常穿插一些段子，平时分大部分人直接给满!赵老师，yyds!',5,5,5,15,2,0);
