INSERT INTO "reviews" VALUES('60482de3b725a143ea6916d2',10624,1753,'想学东西别选他，但是他期末分其实会给满，想学东西千万别选他，根本听不懂，上课一半时间吹牛逼，纯自学可以考虑他，而且一学期还经常会有小测试，签到一般第二节课下课才开始签，无奈选到他就听网课吧，反正讲课没法听，他也允许你不听课',1,1,3,5,2,0);
INSERT INTO "reviews" VALUES('6047818fb725a143ea67874f',8265,114,'老师平时上课很严格，对学生要求高，上个经常会叫人回答问题。课后作业也是比较多的，几乎每节课的作业都给批改，真的是很认真负责。不过这个老师看起来严格，到期末的时候都会捞你的。跟这个老师真的能学到很多知识，不只是高数！强烈建议选他的课！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60473623f8ac3a24def87f60',250,561,'只能说yyds  课堂上知识没讲多少 全在那胡扯了******',3,1,1,5,5,0);
