INSERT INTO "reviews" VALUES('604591534a28a709aab2724a',4084,889,'让提前一天看慕课，上课就不讲课，全程吹牛皮，一周四讲课都在扯别的你敢信，后面还有分组讨论，美名搞课程改革。强制土木选她的课，tu了。',2,2,1,5,4,0);
