INSERT INTO "reviews" VALUES('60457f384a28a709aab2435e',8183,2018,'老师感觉是这门课里唯一一个想把学生教好学懂的，平时作业超级多，差不多每周都要写1-2页纸的作业，每节课都有点到。印象深刻的是老师会单独抽时间或是提前一小时上课来为我们补上耽误的课程。并且其他班都没有期中考试，冷老师单独整了一个闭卷的期中考试。所以想水课的朋友们就别选了，但是想好好学习拿高分的同学还是建议选这个老师的课的。因为到了学期末的时间其他班的同学都不知道考试重点是哪，该复习什么地方，平时上课因为放假耽误了许多也没怎么去，所以期末成绩也不是很理想。还有一点就是老师期末卷面成绩是按总体打分的，一般来说分数偏高，我期末的卷面分数就九十多。不怕辛苦的同学可以考虑这个老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60450e384a28a709aab17a1c',751,573,'老师说话超级小声，事还倍多
INSERT INTO "reviews" VALUES('60450d064a28a709aab1771c',4352,4352,'给分还不错，疫情期间几乎都90+',5,5,5,15,1,1);
