INSERT INTO "reviews" VALUES('6040470b4a28a709aaa39b87',2346,762,'太好了，给分拉满，人幽默课有趣，虽然我没去过几次…',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('603f76854a28a709aaa1ec47',9443,909,'我太爱他了，他可爱的我都想亲他一口',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('603dfab74a28a709aa9e1e6e',250,250,'真的是何德何能，如果你被分配到这个老师的班，就只能自认倒霉了，上课说话含糊不清，有一半时间都在侃大山，真正的讲课比上课水。无论是解答问题还是对待学生的态度都是敷衍了事。如果自己不努力的学的话，就算学的再好也会挂科。千万不要指望他能教会你什么，有上他课的时间还不如自学。',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('603df14c3e6c9c38ab454b5d',8805,1196,'平时分拉满，yyds',3,3,5,11,1,1);
INSERT INTO "reviews" VALUES('603d06483f4855680d842952',8774,8774,'绝对是好老师啊！
INSERT INTO "reviews" VALUES('603c6ad44bab7c7292151b0b',7110,7110,'老师人炒鸡无敌好！给分高，温柔细心，下课问问题耐心负责～强烈推荐！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('603c69beab871542616de37c',11418,12391,'杨珊老师人太好了，给分炒鸡无敌高，平时上课人超温柔，还非常关心学生～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('602ce73b69a105789ce3ee6a',1768,22,'平时分除了考试都给满了，挺不错的老师讲的还可以',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('601157341c08365d33fb7836',1663,693,'老师很有责任心也很随和，上课会随时问大家听没听明白，如果有没听明白的会反复讲。有时会提问但是回答不上也没关系，一学期下来大概能叫出每个人的名字。作业跟别的班比不算多，就是平时分一点都不水，该多少就是多少不会捞。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('601156343b730a5a68856c71',10091,1196,'老师很温柔课讲得也很好作业不多不点名期末给分也不错值得选',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6010035177fcd4410f1f0359',12187,73,'没见过这样的老师 摆明了要挂别的班的人',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('6010031777fcd4410f1f02cd',84,73,'龙若迅出题的话 陈远久的课及重点 完全不顶用',2,2,2,6,1,2);
INSERT INTO "reviews" VALUES('600fdaeb0ac9aa761f38586b',2125,80,'******* 这是我大学四年以来见过的最不管学生死活的老师',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('600fc0463a9b5f27cd876f8c',12718,1346,'这老师事真多，每节课签到，不来就扣分，好在我只有一节课没去，乖乖完成任务了，不然gg',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('600fbfec77fcd4410f1e4065',716,716,'虽然老师平时老爱说让你们挂科，但是助教人很好，给分很高，必须选李松，选隔壁徐某你就完球了',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('600fbf3a3a9b5f27cd876d55',819,228,'这个老师真是说话声音嗲嗲的，人还凶，平时布置那么多作业，平时分还一副高高在上的样子，还有什么期中考试，大无语******',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('600fbed80ac9aa761f380a6f',1441,228,'给分还行，老师人一般',4,4,4,12,0,9);
INSERT INTO "reviews" VALUES('600fbe990ac9aa761f3809a3',715,394,'这个老师人太好了，虽然期末分低，但是平时分拉满，我爱老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('600fbe253a9b5f27cd876aa1',788,790,'从未见过给分如此低的老师，一个水课平时分只给70几，人家管理学老师都给一百，这个老师给分太抠了，坏女人',2,1,1,4,7,0);
INSERT INTO "reviews" VALUES('600e90183a9b5f27cd855073',281,281,'老师的专业水平还是不错的，就是有些人听不懂他说的话，因为有口音，给分的话平时都给满了，这门课其实自己稍微学一学90+还是没问题的，选这个老师其实也还行',5,4,3,12,4,1);
INSERT INTO "reviews" VALUES('600e8f8c3a9b5f27cd854dec',932,762,'老师除了讲课有点口音，其他都挺好的，作业，课堂练习都是交了都满分，其实上久了就能从老师说话的言语中发现袁老师是个特别有趣的老师，还挺不错！',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('600cc59277fcd4410f1855ee',716,716,'助教明明把平时分都给的很到位，但是李老师登成绩的时候偏偏要扣你几分，讲课没得说，但是给分很严格，混子误入。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('600c4f133a9b5f27cd80f01f',383,678,'老师讲得很好，人也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('600c4e820ac9aa761f319f01',6403,535,'不如自学',2,1,4,7,2,0);
INSERT INTO "reviews" VALUES('600c4da63a9b5f27cd80ee97',613,613,'期末给分也太低了',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('600c4d490ac9aa761f319de6',612,1386,'太难学了，还好老师会捞一捞',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('600c4c923a9b5f27cd80ed67',6377,6377,'一学期都没听懂老师说的普通话',4,1,4,9,0,0);
INSERT INTO "reviews" VALUES('600c4c123a9b5f27cd80ecf6',7824,11373,'打分高',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('600bd27277fcd4410f16abff',1058,5,'陈老师讲课十分认真负责  讲课很清晰 待同学极为亲切 感觉有什么问题都可以同她讲  没有距离感  很善于为学生着想  平时分给得也很高  选就对啦',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('600a8cc477fcd4410f143edb',11590,573,'老师太棒了！本来以为会挂，感谢老师！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('600a6d360ac9aa761f2db958',23,23,'绝对好老师，上课幽默风趣有激情，只要认真跟着学，高分到手~   不过抢课太难，要看运气，哈哈，我的运气超好，高分飘过',5,5,5,15,49,0);
INSERT INTO "reviews" VALUES('600a6c6d0ac9aa761f2db782',175,175,'慎选，逃离！',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('60098bc73a9b5f27cd7b8fcb',9351,5,'老师很负责任，讲课很热情，也有点幽默哈哈哈。平时分给分也高。从不点名。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60091a253a9b5f27cd7a6b7d',716,716,'这老师我爱了啊！给分很nice！平时分好好写作业基本可以拉满，好好学，90分不是梦！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6008fd413a9b5f27cd7a28b4',716,716,'临近期末了，助教平时分就给我扣了0.4分不到，到他那我直接扣2.5分，莫名其妙',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('6007b5dd77fcd4410f0eaeab',234,256,'孙老师yyds，上课讲解清晰，做实验的时候也会给不清楚的同学细心讲解。我期末考了98，她看到我平时成绩只有37.4，就把我的平时成绩改到了39，最后总分99，我真的太爱这个老师了哈哈哈哈',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6007a0560ac9aa761f28522f',1949,230,'对他的印象只有给分很低，上课还行，大作业让我们拍视频，结果分数只有80。',1,3,3,7,0,1);
INSERT INTO "reviews" VALUES('60079fe277fcd4410f0e7860',3926,2035,'千万不要选他的课，因为你的分数可能比别人差挺多的。这个老师上课喜欢搞突击测验，教了三个班，每个班的小测难度一个班比一个班难。而且还让我们做期中论文，也不知道是什么评分标准，给分低的要死。上课么有时还朝我们发脾气。记得有一个学长和我讲过，他们班有个同学他的作业迟交了一会儿，他就死活不肯收，也是醉了，做学生也不容易啊 ，能不能为学生考虑一下？上课么还给我们排座位，谁知道坐最后一排的同学是什么感受？就呵呵了，大家下次别踩坑哈，记得去窦班哦！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('600797fb77fcd4410f0e685f',3926,2035,'这个老师 ，两个字，无语。每节课都要点名，排座位，测验多，还有应用统计论文，给分贼低，你期末考一百，总分只有九十，因为他可以扣你10分平时分。还有那个助教，老是弄丢同学作业，最后还扣你分，一次两分。真是太糟糕了。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('60078db777fcd4410f0e4554',175,175,'不具备一丝亲和力，上课完全不知道这门课哪些是考点哪些是重点，最后只能靠自学，尤其最后考试周极为痛苦。很严厉的一个人，若向他问任何考试相关的问题，他只会说一句''''保重''''。或许老师高要求的出发点是好的，但是emmmmmmm，能换老师还是建议换老师。',3,1,1,5,1,1);
INSERT INTO "reviews" VALUES('6006f26e77fcd4410f0d8349',467,22,'哈哈哈哈哈哈老师人好好，特别好说话。但是上课不是很有趣，基本上按照PPT，讲得不是很容易懂，但是认真听还是可以，不过三连讲怎么可能保持注意力一直集中呢！所以都是靠自己啊，期末来冲刺！所以，想水的可以选她，给分很好，基本上除了期中和期末，就没有扣分的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('6006f16177fcd4410f0d8188',18,18,'yyds,上课很有趣，能学到很多东西，比那种照着PPT念的，上得飞快的老师好很多，而且给分我太爱了。我不是他优选班的，所以上过其他老师的课，感觉那个老师上一节课，相当于赵老师两节课hhhh',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('6006f0d10ac9aa761f275532',2173,2173,'我觉得老师很好啊。。。。楼下是不是那个不让考试的同学啊，这个老师就是要点名，基本上能认全她班上的学生，但是比较有亲和力，讲课还行，算不上很好。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('6006f0680ac9aa761f275484',8805,1196,'很有趣的一个老头，上课喜欢给你讲如何创业哈哈哈哈哈，挺和蔼的，就是语速稍快了点，可能会听不清',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('6006b3e40ac9aa761f26c766',95,104,'上个实验课，完全不知所云，实验啥也不用你做，然后送你低分。班里同学报告自己整丢了，毫不讲理地直接给0分。亏他这门还是保研课？他也配上？',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('600694013a9b5f27cd759f16',2173,2173,'人挺好的 挺温柔的 平时分按知到的分数给  我上课老睡着就不评价教学水平了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('60068e713a9b5f27cd758d8a',24,24,'小武哥哥，yyds，不说了，平时分直接拉满，上课认真，要求严格，真的是个平时严格，给分宽松，对人负责的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60068dc477fcd4410f0c6ee1',12187,73,'不说了，真的，不是我喷他，全******考他PPT上的东西，有的公式书上都找不到，真的吐了，这就是教考分离吗，爱了爱了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('60068d290ac9aa761f263d82',18,18,'yyds 不说了，不仅期末捞我，最主要上课讲的好！！！',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('600685a83a9b5f27cd756680',18,18,'老师很负责任，很晚了都还在群里面答疑。上课风趣幽默，PPT制作整洁美观，适合预习和复习。自制了公众号“交大概帮”帮助同学们更好地学习',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('600684a177fcd4410f0c4a51',18,18,'赵老师yyds   不愧我交大概帮帮主
INSERT INTO "reviews" VALUES('600675f33a9b5f27cd754175',11887,12577,'避雷！！！所有人都82，还不如选其他选修！2020年开始改革了，不是水课了！',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('60066b990ac9aa761f25dea8',12757,395,'廖老师很好！备课很用心！真的是在认真上课。把知识讲得很透。作业确实很多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('60065f2c3a9b5f27cd75133a',2017,4609,'老师人美心善，很负责任，讲的非常好。不会捞人的，因为平时成绩直接打满没有办法捞了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6006319d77fcd4410f0b69f8',12138,370,'好老师',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('6005a51f77fcd4410f0ac394',2961,761,'老师挺好，就是给分不高😂',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('600597920ac9aa761f247f07',803,1135,'上课一听就懂，只要上课认真听，下课的作业认真完成，平时基本上不用花费多少时间在这一科上，期末稍微复习一下就能取得非常不错的成绩',5,5,5,15,7,0);
INSERT INTO "reviews" VALUES('600596e977fcd4410f0aa8e5',558,198,'向老师永远滴神，在众多模电老师中我觉得算是讲的特别不错的一个老师了，上课还幽默风趣，只要按时上课，基本上平时分打满，上课还会讲期末考试的重点，基本上讲的重点期末都考，而且老师人特别好，选上他的课，认真学90+都没大问题，强推',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('60058bac77fcd4410f0a9305',10,10,'老师人相当和蔼，平时分高，作业交了上课去了就给满，讲的也不错。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('600550113a9b5f27cd733027',607,1519,'老师赢麻了',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('60054b9b3a9b5f27cd732453',2612,859,'非常非常非常非常好的老师，事儿少，给分高，讲的也不错',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('6005198d3a9b5f27cd729f21',11887,11887,'这学期开始大刀阔斧改革了?一刀切，所有人都是82分',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('60050a843a9b5f27cd728101',141,765,'想要平时分不及格拉低期末考试成绩么，选她！',3,3,2,8,5,1);
INSERT INTO "reviews" VALUES('6005045e3a9b5f27cd7272fd',759,759,'平时成绩给60多也是没谁了 一生黑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('600463c80ac9aa761f223224',896,896,'上课听不懂，作业也不会，老师上课会一直嘲讽让人怀疑智商。
INSERT INTO "reviews" VALUES('60044d0b0ac9aa761f21fdeb',480,92,'平时分给满(期中成绩除外)，上课幽默，平时作业按学号尾数单双号交，只用交很少几次，就是满分，上课不去都行，不点名，这学期应教务安排点名，但是每次只点一两个人。
INSERT INTO "reviews" VALUES('60044bac3a9b5f27cd715ecf',2173,2173,'……别选',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('6003e3e977fcd4410f070e28',1565,1565,'没0分真是太可惜了，简直是杀人的课，问题是这个老师自己都讲不明白很多东西，好像她自己都不懂。想学不会东西还得个60分的课的人就选她吧',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('6003df453a9b5f27cd7031b4',246,228,'上课不知所云，搞人心态绝对有一手',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('6003dead3a9b5f27cd702fd7',7995,9692,'老师人很好，讲课专业水准强，考试海底捞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6002e2f83a9b5f27cd6e8422',2484,92,'何老师超级棒，上课讲的好，每天也都是元气满满的样子，脸上从来都是带着笑容，一上课看到她心情都变得好了。然后问题也从来都是秒回同学，解答也很详细，即使问的是上课讲过的内容。平时分扣的也就是期中考的分数，其他基本不会扣，总之就是很好了。',5,5,5,15,5,1);
INSERT INTO "reviews" VALUES('6002c8330ac9aa761f1edcb5',819,9857,'专业，讲的很好，平时分给的高，实践课很多',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('6002c2de3a9b5f27cd6e26ea',141,141,'年少不知谢宁好，错把高思敏当成宝，给分太抠搜惹，坏女人',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('6002c09477fcd4410f04edac',141,765,'想挑战自己么？想认真做作业还要被扣分么？想没什么机会主动回答问题没有课堂表现分么？想期末考的高拉低成绩么？选她就对了！',3,3,3,9,5,0);
INSERT INTO "reviews" VALUES('6002bbc00ac9aa761f1ebae0',68,40,'千万不要选这个老师，平时分给的贼低，别的老师基本拉满了，这个老师太斤斤计较了，一板一眼的，说话阴阳怪气',2,1,1,4,5,1);
INSERT INTO "reviews" VALUES('6002baf70ac9aa761f1eb945',141,765,'这个老师千万不要选，给分太死板了，别的老师都给很高平时分就他只给一半，我平时分只有60几太绝了，期末考80几总分也才70多',3,3,1,7,2,0);
INSERT INTO "reviews" VALUES('6002b16577fcd4410f04c437',141,141,'讲课可以的，但我从未见过如此斤斤计较的老师。别的老师除了期中部分都直接拉满，好家伙她平时分直接扣一半，算个平时分愣是算到了小数点后三位，大无语',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('6002acb00ac9aa761f1e928d',141,141,'讲课还行，但是强烈建议大家不要选  扣分扣的死死地   期末83总评给我打70   平时成绩二十分就给一半  绝了  再来一次我绝对不选她',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('6001bf2f3a9b5f27cd6c1d1d',691,228,'老师人还挺不错的  只要签到点名在一般分都不会太低  作业也少 人也不凶',4,5,5,14,0,1);
INSERT INTO "reviews" VALUES('6001a7903a9b5f27cd6bf4e7',756,22,'老师人很好，讲课仔细认真清晰，很容易跟上，只要下来自己完成作业考试完全没问题，最主要老师平时分也不拉跨！签到跟作业齐了就拉满！学弟学妹们冲就完了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('60019fcb3a9b5f27cd6be162',756,22,'永远的神杨老师！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('6001970877fcd4410f029c48',12424,12424,'选的是分布式数据库，小楼上课很水，人也很好。期末要交报告，报告难度较低。期末考开卷，试卷一半送分一半高难，过肯定过，但除非平时认真学否则后面计算很难拿全分。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('600195f93a9b5f27cd6bc71d',4250,2713,'上的是朱老师的数据仓库，全英文ppt，老师也基本是全英文授课，比较能练习专业英语能力。缺点是朱老师讲课相对来说逻辑性较弱，而且经常揪着一个点提问，有的偏僻的点提问好几个同学答不出就能问上十来分钟，会降低听课体验。考试也是全英文试卷+作答，有的题上课讲过ppt上没有，说是半开卷但那张纸很少用到，但最终给分还是会捞人的。总体来说这门课适合自律大佬，学渣不建议。',5,3,4,12,1,2);
INSERT INTO "reviews" VALUES('600194320ac9aa761f1c5c18',3036,3036,'晓航李永远滴神，上课蛮好懂且不点名，算是水而负责。总共三个实验第一个必做后两个选做，而且都比较简单。期末考会给复习讲义和大题例题，卷子简单给分也高。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('60018dc40ac9aa761f1c4922',359,228,'米老师人超级好，上课特别温柔，然后她会给每个同学都有回答问题的机会（这是有分的），然后每节课都有很多问题准备好给同学们回答，问题都不难，然后回答都能加分，作业也不多，期中考试就两道题，好好做基本上拿满分，还有一个全年级的实践作业，认真做满分不是问题，虽然免考名额不多，但是就算没拿到免考名额，平时分50分基本上也能那到48以上，50分的也不在少数。',5,5,5,15,4,8);
INSERT INTO "reviews" VALUES('600131d63a9b5f27cd6ab34e',2821,40,'杨老师人炒鸡好，虽然点名多，但是你可以随便迟到，不会批评你。上课回答问题都是用手机的，比较水，课堂表现很容音拿满分。平时作业有一点小多，但是都不难，你去请教问题她会很温柔的解答。最重要的是，老师长得是真好看！',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('6001145b0ac9aa761f1b0461',8138,716,'讲的一般，，口音很重，听不懂在讲啥，今年给分还可以，作业交了给了我90多平时分，期末考的也简单',3,3,3,9,0,5);
INSERT INTO "reviews" VALUES('6000ede70ac9aa761f1ab1f0',246,228,'康老师今年的改变很大啊，平时分给的比别的班都高，作业也只有一个中期1000字论文。只是表达水平确实一般。',5,4,3,12,3,16);
INSERT INTO "reviews" VALUES('60005d66f42a8e5b8efa1373',691,228,'上课讲得不怎么样，经常让自己看书然后回答问题，经常点名，最重要是平时分给个不及格，真有你的哦！',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('600017663a9b5f27cd68d958',1058,5,'老师讲得我听不大懂，基本上都是下来自己学的。课程安排比较奇怪，你永远也不清楚下一讲讲什么。如果能提前上教务网知道教学大纲提前预习或许会对听课更有帮助。
INSERT INTO "reviews" VALUES('5fffdf1a6d3d514574131d6d',844,850,'上课爱吹牛，思维太跳跃。考试很严格！期末不捞人，给我59，把我挂了！',2,1,1,4,2,0);
INSERT INTO "reviews" VALUES('5fff94b56d3d5145741284d1',885,883,'期末给分未免太吝啬了，真不至于那么少吧',4,3,2,9,0,1);
INSERT INTO "reviews" VALUES('5fff2c3efcd04147f58bb9b3',788,1551,'垄断寡头就是牛逼，反正就我教，不适应就慢慢适应，一个学期不行就在来一个学期，总有你适应的那一天，瞧，还有14级的漂亮哥哥哦，我的魅力真大哈哈哈。讲课就随随便便啦，讲义参考资料想要，来求我呀，把我哄开心了，我就赏。什么年代了，还流行上世纪唯我独尊的老师姿态，呸',3,1,2,6,28,0);
INSERT INTO "reviews" VALUES('5fff2a076d3d514574121267',788,790,'从来没有这么无语过，反正别选，被折磨过来的',1,1,1,3,11,1);
INSERT INTO "reviews" VALUES('5fff0df6fcd04147f58b937c',885,883,'快跑 快跑',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5fff08f1fcd04147f58b8d19',3930,3930,'作业多的******离谱，考试周快完了还要交作业，真有你的',2,1,2,5,2,0);
INSERT INTO "reviews" VALUES('5ffefadcfcd04147f58b52dd',1441,228,'瑶姐上课像演讲，非常好玩，平时分人均90+
INSERT INTO "reviews" VALUES('5ffef90ded6e521cddefc61a',8460,8460,'老师上课很有亲和力，这课是通识课，能了解的只有皮毛，开拓眼界可以学一学，但是给分并不高！每节课都要签到，期中有个小测试，期末也有测试。老师课上的意思是看看学的情况怎么样，搞了个测试，本以为写一写分数应该都还可以，但是很失望，此次测试就是期中考？有种笑里藏刀的感觉，期末最后给分真的很低',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5ffecdcced6e521cddef58a4',737,394,'自己口语也不怎么样，半学期的课，一周两次，第一堂课巴拉巴拉赶着讲，第二堂就搞考试 ppt上全有，还不如其他上一学期的老师学到的东西多，又搞个英语演讲一直在教训大家的口语和随机应变能力，我上的是英语课？如果选上了跑就完事******。',1,1,1,3,1,2);
INSERT INTO "reviews" VALUES('5ffecbdfed6e521cddef534d',11226,11225,'黄老师很棒真的很棒，大一教完之后没想到大三还能上他的课，真的香，平时没有任何作业哈哈',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ffeab7953c0154da4ccad81',5558,4552,'太水了。每节课用二十分钟抽人回答问题，讲课语速极慢几句话也没一句有用的，怀疑在故意拖延课堂时间，我看也没啥可讲的吧。专业水平何在？念ppt是个人都能。给分很低，期末卷判的很严，平时分提前出估计也不捞人。',1,1,3,5,4,0);
INSERT INTO "reviews" VALUES('5ffea90553c0154da4cca7dc',5558,790,'着实是捞，上课没讲啥，然后给分也不高',3,1,1,5,3,0);
INSERT INTO "reviews" VALUES('5ffe9daa53c0154da4cc8b28',11950,2598,'吹得过了。讲得很好。其他的很一般。不要抱太大期望，希望越大，失望越大。',3,3,2,8,4,2);
INSERT INTO "reviews" VALUES('5ffdac82930d45477545cbb9',74,12555,'王化光，人送外号王挂光******。
INSERT INTO "reviews" VALUES('5ffda7eb54595f432d4a8d78',74,12555,'王化光，江湖人称“王挂光”！(评星实际想不给的，奈何软件最低一颗星)这位老师讲课随心情,PPT从来不给，老师不给重点！老师专考他不讲的，******实验严格要求到变态******，作业题不给！期中考试考他不讲的！一句话，选他的课，如果不自学等于迈进了挂科的大门！所以千万别选，除非你想挂科！',1,1,1,3,21,0);
INSERT INTO "reviews" VALUES('5ffd754654595f432d4a4b1f',849,619,'他怕是对加分有什么误解
INSERT INTO "reviews" VALUES('5ffd73352695bc0ed5696fa2',849,619,'平时分给的低，说好笔记加分，事实上没有笔记就是扣分，而且加分没有一个衡量标准，加几分全凭自己开心，平时分85分起步，真的服',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('5ffd6ae4930d454775457231',408,2119,'hhhhh，葛老师讲课就基本上念ppt吧，爱搞什么二分课堂，其实全靠学生自学，上课还爱唠嗑，同学们上课花了时间还学不懂，只能自学。还超级爱小测，给分',4,4,3,11,0,2);
INSERT INTO "reviews" VALUES('5ffd6a305d6b370989553db4',1105,1105,'挺好的一个老师，讲课比较清晰，也挺好说话的一个老师，给分也不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ffd69aa5d6b370989553c74',2119,2119,'邱老师永远的神，比较为学生考虑的一个老师，而且超好说话',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffd3db554595f432d49f71d',585,325,'李老师的课程从来不缺少精彩，满满的都是干活。知识点讲的都十分细，像教小朋友一样耐心，不懂得地方都能给你讲的明明白白的，会结合最新的科研成果融入教学之中，而且也很体谅学生，课间还会给我们放歌听，是师亦是友，日常中也在关心同学们的生活。看见他的课，就快选吧，绝对是交大最赞的老师啦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ffd312754595f432d49e691',188,188,'老师平时分给分真的低，每节课都到，就是没回答问题，平时只有78分，下次不会再选了',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('5ffc522a2695bc0ed56844f0',11752,11752,'平时分乱给，交了作业的平时分比没交作业的还低，期末考的分数居然比平时高，哎还是徐柳老师好！',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('5ffc4043930d45477544421b',199,428,'讲的好，且给分高。不可多得的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ffc1fe32695bc0ed567fad3',6726,3691,'老师虽然水平有限，但是成绩方面都是按照规矩来的，不坑。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('5ffc1cde930d454775440e72',867,28,'也只能说是一般吧 平时分给的属实不太行',4,5,5,14,2,1);
INSERT INTO "reviews" VALUES('5ffbe9a354595f432d487b45',10624,1753,'司马东西，脑子有坑，不配做老师',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5ffbe1d403400e3ed90676b3',18,18,'良师益友。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffbdeb703400e3ed9067345',2005,1697,'******改卷改得严期考也不捞人，学弟学妹们避雷吧',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5ffbd91903400e3ed9066b75',18,18,'赵老师的讲课真的超级有趣，人也很热情，平时在群里面问得问题，就算是半夜，也会及时回答，他的课上的平时分特别容易挣，擦黑板，回答问题，找PPT的错误，基本上能给的分都给了，而且最重要的一点是，赵老师特别喜欢和同学互动，赵老师是我在交大第一个想给满分的老师，不管是专业水平，表达能力和亲和力，都是一流水平，爱了爱了，这样的老师不选，枉学概率论！！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffbd6eacea97d1b62a0f55c',18,18,'听了学姐的推荐选了赵老师的概率论，赵老师真的是我大学遇到过的最好的老师，上课逻辑清晰，知识点说的很清楚，ppt也做的十分简洁，而且真的是为了同学们的发展与学习考虑，上课也很幽默风趣，平时分虽然有要求，但是做了就是满分，最后即使没能在课上回答问题或者擦黑板，也会给你加上去，也经常在群里回答同学们的问题，跟同学们互动，这还不选等着干啥',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffbcf73cea97d1b62a0ed12',10142,415,'说最温柔的话 给最低的分',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('5ffbc599cea97d1b62a0decf',18,18,'这学期最喜欢上的就是赵老师的课，老师幽默风趣、认真负责，PPT做的非常棒，只要上课认真听，考试绝对没问题。就希望概帮越来越壮大！！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffb038ccea97d1b62a037e8',788,1551,'真的晦气，考试前一周答疑课告诉我们课设怎么做，然后要求在考试周结束之前完成。这个课设的工作量大概就是除了吃饭睡觉光做需要三四天时间。关于上课的水平，逻辑稀烂，基本就是照着ppt讲概念和计算，没有一个知识点串联的过程，而且******，除了求知若渴的同学基本所有人都听不进去',1,1,1,3,16,1);
INSERT INTO "reviews" VALUES('5ffafcfc54595f432d47a2d9',5300,5300,'感觉是我大三上学期唯一一门阳间的课。老师教学水平真的很高，课堂氛围也很好，只要跟着老师的思路走学得很轻松。作业也布置得很有代表性和针对性。考试也非常基础，没有阴间的题目。给分也很高，这要是都学不好就真的是自己的问题了。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ffafaa47ee37d3cfd755a6d',13,13,'老师自身专业水平不低，但是作业和考试太阴间了，作业评分标准谜一样，20万字的复习资料（也总比没有强，对吧😊 ）。上课就来四五十个人也不点名。也没几个人愿意听，反正来跟不来一个样。害，咋办嘛软件专业的孩子没又得选。祝学弟学妹们好运吧。',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('5ffab8e3cea97d1b629fbf23',237,237,'这个老师，就离谱，真的就',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5ffab69b7ee37d3cfd74e9f0',1991,188,'老师人特别好，期末画重点，可以说是犀浦校区最抢手的毛概老师了，可惜我毛概Ⅱ没抢到，希望选课能扩容。不是每节课都点名，但每周的最后一节课还是要去(大家都懂)，还有就是上课可以悄悄地玩手机，但被他逮到会问你问题',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffa9cd41c3f9d25e5cb4d13',2821,3822,'人是真的好，给分是真的低',1,1,4,6,2,0);
INSERT INTO "reviews" VALUES('5ffa8f895d6b37098951c25e',222,222,'老师好得一匹，分也给得高，选他就完事儿了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5ffa81627ee37d3cfd7457a1',5300,5300,'陶老师讲课讲的很好，人很好，给分也很不错！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ffa7a7c5d6b37098951a3c9',12836,441,'每节课必点名
INSERT INTO "reviews" VALUES('5ffa6ed3cea97d1b629f12e7',222,852,'老师是真的好，问问题会很耐心地回答，也很负责认真。
INSERT INTO "reviews" VALUES('5ffa6c361c3f9d25e5cafdb9',1287,40,'有一说一，平时分给的确实低',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('5ffa5fb2cea97d1b629efab0',1293,1007,'老师是非常有趣的一个人，平时上课非常有意思，她说她教书的唯一目的就是让我们对经济学能够有真正的兴趣，最好她的教学能帮助我们在不学经济学的时候还能对它有兴趣。期末考试是平时书上的内容，知识点涉及比较广泛，都需要看，但是题都很简单，只要你对那个知识点有印象基本就会做，偶尔会布置两道作业题，考试计算题就差不多是平时作业里的，真的很喜欢韩老师，又潇洒又热烈的人。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ffa5ead54595f432d466094',12840,12840,'老师上课很有意思，喜欢讲一些生活中的例子，平时考勤会有，小组讨论也有，期末开卷都是论述题，和实事相关用教学知识分析，不会很难。',3,5,5,13,0,0);
INSERT INTO "reviews" VALUES('5ffa4de254595f432d464d39',909,909,'别选，水，给分低',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('5ff9ca727ee37d3cfd73bccf',42,43,'实验期末是分几天考的，我是最后一天，他出了个贼******有误导性的题，结果我思路整个错了，期末给了60多.......',1,1,1,3,2,0);
