INSERT INTO "reviews" VALUES('5ff8446d7ee37d3cfd70df94',737,394,'你名下有房产吗?你有父母给你做担保吗?没有的话你有百米冲刺的经验吗?冲出去，千万别选!',2,2,2,6,2,1);
INSERT INTO "reviews" VALUES('5ff83cbe54595f432d430e21',2169,394,'吐了，虽然老师人很和善，案例讨论给分也是同学们随便打，但是上课讲的大部分都考不到，还整个元旦上午考试，我跨年夜背了一晚上就这，最后一周了大家都要复习让你看个电影写个20分的作业，我真傻逼选了管理学，理工科同学最好别选，不然背死你。',3,3,1,7,4,0);
INSERT INTO "reviews" VALUES('5ff83b7954595f432d430a3d',2169,394,'这门课就挺水的，上课听了没什么用，但是这个老师期末给的重点非常好用，但是平时分给的很低，一个期中测试就给六七十？到期末了还给你插个占比20%的大作业，没谁了！',1,2,3,6,2,0);
INSERT INTO "reviews" VALUES('5ff839fe1c3f9d25e5c78994',12872,12872,'老师专业能力没得说，讲课也很认真，作业很少，甚至可以不交，平时分拉满，唯一的缺点可能就是讲课有点谜语人，听不清在说什么',4,2,5,11,0,0);
