INSERT INTO "reviews" VALUES('5ff81ca37ee37d3cfd709155',737,394,'******，搞毫无意义的全英文课程，简单的东西一用他那蹩脚的英文讲，就啥也听不懂了，讲的贼少，一个学期下来基本学不到知识，搞了一堆浪费时间毫无意义的quiz，平时分给分无敌玄学，改卷子无敌严格（第一次听说复查卷子的时候，给快不及格的同学倒扣（而且人家没写错，是他题目没说明白）好几分的老师！！！）平时不刷脸（简单的说就是舔，听说上几届还让同学看他或者陪他打网球来加平时分？！）就拿不到好分数。最烦的是我之后还要上他的课！爷吐了！',1,1,1,3,13,0);
INSERT INTO "reviews" VALUES('5ff81c197ee37d3cfd709022',1480,194,'余老师超级好，讲课认真负责，他的ppt做得好详细，给分也高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5ff7f31654595f432d428ae9',852,760,'楼下说声音小的，可能忘了他这学期每节课都用的话筒。个人感觉说话很懒散，讲课毫无生气的感觉。写完作业平时分拉满，上课迟到从来不说。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff7e351829787517cc463ef',2346,762,'娟姐人超好，期末还可以补交前面所有的作业，讲课也很耐心，概率论这门课真的太难了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff7e28954595f432d4275c1',3712,92,'老师人很好，分数都仁至义尽了，就是讲课听不太懂',4,4,5,13,0,0);
