INSERT INTO "reviews" VALUES('5ff705ce7ee37d3cfd6f7b85',1394,230,'这是我上过所有马院的课里最好的老师了，我觉得讲课水平已经相当高了。期末出分以后还在教学邮箱里群发了一封信，就是类似于学期总结吧。',5,5,5,15,4,0);
