INSERT INTO "reviews" VALUES('5ff6bca17ee37d3cfd6f12de',751,1652,'老师教研水平高，但讲课不太行。平时分给的高，就是上课听不懂而且拉的很快。',4,2,3,9,2,6);
INSERT INTO "reviews" VALUES('5ff6a269829787517cc3187a',345,96,'好老师！平时分给得挺好的！',5,5,5,15,1,11);
INSERT INTO "reviews" VALUES('5ff69f65cea97d1b6299c591',12683,3868,'窦老师是经管学院为数不多自己学术研究水平和对待本科生教学的认真程度都靠得住的老师了，知识丰富，给分高，美中不足的就是口音重了点',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ff69e88cea97d1b6299c46e',920,12890,'绝了，上他的管理信息系统课，一大半时间在吹嘘自己的社会兼职，关于课程本身的内容少得可怜，那少得可怜的课程本身内容，还居然全都是在读英文原版教材配套的英文ppt，最后给分只能说勉强还过得去，我拿了总评85，在这个教学班里算是个不高不低的成绩',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5ff69e0954595f432d41282a',704,704,'老师给分巨高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff69ab2cea97d1b6299bf9c',1419,48,'我真的不想希望这样的老师再出来害人了。把体育的分打的这么低真的是害学生。平时看哪个学生顺眼就照顾哪个学生。不顺眼的能怼你一学期。她真的不知道把分给的这么低会断送一个学生前途吗',3,2,1,6,8,1);
INSERT INTO "reviews" VALUES('5ff698ec7ee37d3cfd6ee29c',3461,2678,'这门课在知识层面绝不是水课，说水的同学都是不听讲的。老师温柔随和，知识渊博，下课后也会跟问问题的同学耐心交流。没有作业，考试简单，课堂讨论都是自愿的，轻松愉快。！！！（重点来了）课上可以学到相当深入和丰富的心理学知识，只要你肯好好听，这门课可以让你在处理爱情，亲情和友情时都更为合理，减少不必要的情感伤害，真的值得来上。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ff6979a7ee37d3cfd6ee117',819,9857,'真正大学老师的样子，广博的知识，清晰的逻辑，全球视野，收获太多了。这门课有难度，但老师很有耐心，鼓励试教学，且关注学生的发展，期末分数高。',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5ff696d67ee37d3cfd6ee019',246,228,'老师的表达能力有待提高，课堂收获很少，做事想当然，没有计划性。如果你不惹到他就没什么，和和气气的，惹到他就麻烦了',1,1,3,5,4,0);
INSERT INTO "reviews" VALUES('5ff68a03cea97d1b6299a938',129,129,'和蔼 还不戳吧 感觉老师和当代大学生的懒惰特点相辅相成',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5ff6899a5d6b3709894c1dc4',12897,12897,'蓉蓉好看(｡･ω･｡)ﾉ♡头上的大花也好看 反正就是好看牛逼好看',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff6883c5d6b3709894c1c5f',715,394,'特别水。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff687cb54595f432d410c4d',756,22,'杨老师我好爱你好爱你好爱你！！看大家困了会讲笑话讲哲学，还有下课很准时！讲的也很好！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff5f5a754595f432d408dc7',1158,26,'小娟yyds，小娟人美声甜。上课贼认真，经常与学生交流沟通。各种担心我们学不懂啥的。平时分贼高贼高！对学生贼好。对同学们很耐心，问问题都会得到很耐心的解答。很久没有这样好的老师了。如果能在大学入学就遇到这样的好老师，真的也太幸运了！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5ff5ed8e54595f432d40895c',22,22,'黄老师真的非常认真而且让学生愿意主动去学 认真完成每次作业考试轻轻松松！总之选到黄老师的课都是上辈子积的福',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff5788d54595f432d3ff955',13,13,'ya',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff57391829787517cc1d8f1',262,262,'老师脾气很好，风格比较幽默，上课做不影响课堂的事（比如耍手机）也不会说什么，点名较多。就课程本身来说也很有意思，老师比较客观的讲了欧盟的历史，机构，国际关系等。既可以认真听课，学到一些知识，也能当做水课做别事。只有期末考试，而且提前把题目告诉你们，开卷',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff572117ee37d3cfd6db566',344,1135,'超级棒的老师，非常和蔼可亲，对待学习一视同仁，不放弃，特别敬业，职业。给分也高。老师讲的非常好，基本不好说是听不懂，真的强推！学不会来找我，19电气昊鑫',5,5,5,15,8,1);
INSERT INTO "reviews" VALUES('5ff571a97ee37d3cfd6db4bb',22,22,'老师讲的真的好！最好的物理老师了吧。强推！如果你学不会来找我，19电气昊鑫',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5ff56aab829787517cc1ccbb',24,24,'这个老师基本不捞人 因为平时分都拉满了 捞不了',5,5,5,15,9,0);
INSERT INTO "reviews" VALUES('5ff5673254595f432d3fdf77',1158,5,'棒棒棒',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff5597c5d6b3709894ad50b',852,852,'声音有点小，但人很好。每次助教点名。每大章有个小测，不过不难，可以翻书，都是书上题目。作业系统只要平均分过90，作业平时分就给满。有问题群里随便问，一点都不凶',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5ff554015d6b3709894acc65',74,74,'老师专业知识雄厚，但是******，从来不给PPT，只能自己复习，也不知道复习哪里，对作业和考试要求严格。',5,2,2,9,5,7);
INSERT INTO "reviews" VALUES('5ff54f01cea97d1b629857f5',9169,242,'各种理由不上课，上课也是读ppt，专业能力极差，考试前也不答疑，见过的最不负责任的老师',1,1,1,3,3,2);
INSERT INTO "reviews" VALUES('5ff54a2d54595f432d3fbb9d',737,394,'全英文授课，但老师英语******，还自我感觉超好******学不到东西，老师一直在水课 ，得分******，不说了，能不选就别选这个人，',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('5ff53e097ee37d3cfd6d731d',22,22,'老师太好了!!!只要你不是那种态度很不端正的 平时分基本都是满分',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5ff537b47ee37d3cfd6d6ba9',1108,188,'老师人很好说话，小组合作的时候还特地给非优选的同学建了小组，本自闭er落泪。上课不太管下面在干嘛有时候会说一两句别玩手机了之类的但没什么效果。哦老师特别注重考勤每周都会签到。平时分挺高的基本都是47,8这样',5,5,5,15,1,7);
INSERT INTO "reviews" VALUES('5ff4fc89cea97d1b6297fa95',35,35,'强推！老师真的很好！没有平时作业，每节课点到，到了平时成绩就是满分。唯一的考核是期末小组唱歌，给分很高。',5,5,5,15,1,0);
