INSERT INTO "reviews" VALUES('5ff497e15d6b3709894a2a7c',2500,228,'人很和善，知识渊博，有一节课纯板书讲了一节课，平时分高，回答三个问题课堂表现就满分。想水可以水，想学可以学，很好的老师。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5ff4972bcea97d1b6297bff7',2500,228,'想水可以水，想学也可以学到东西，平时分高，这才是理想中的大学老师～',5,5,5,15,2,0);
