INSERT INTO "reviews" VALUES('5ff478f2cea97d1b6297a268',751,573,'老师嘴硬心软好说话，上课经常扯点闲话，不过这门课无聊，老师口音也重，有时候听不清',5,3,5,13,0,5);
INSERT INTO "reviews" VALUES('5ff4639454595f432d3ee493',3370,228,'专业水平非常高，讲课讲的不错，不过平时测验挺多的，比其他老师严太多。如果只是想嫖平时分的话慎选。',5,4,3,12,5,1);
INSERT INTO "reviews" VALUES('5ff45ff95d6b37098949e81d',2984,361,'只要作业做完，给分直接给满。选修里面少有的上100的课。只是注意每节课必点名。上课禁止带电脑。选了一定要准备好书，期末考试开卷，用他写的书，但是我感觉 他的书好像都没在卖了。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5ff45c9fcea97d1b62977ad6',2346,762,'上课幽默风趣，讲解也很清楚',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff45ad154595f432d3ed5d9',1318,301,'人很好，但是上课水平真的不敢恭维，作业多，上课也老是在讲无关的话题，快跑',1,1,5,7,2,0);
INSERT INTO "reviews" VALUES('5ff457137ee37d3cfd6ca0ea',359,228,'米老师人非常温柔随和，讲课有条有理，认真听能学到不少东西，而且常常给我们放与课程相关的视频，布置的作业也比较多样化而且不多，不死板不教条，讲课时也鼓励我们发表自己的想法。只要认真听，配合老师，作业认真做了就算不免考平时分也一定会很高。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('5ff42d19cea97d1b629737bd',246,228,'老师真的不错，到期末还能给补交期中考和大作业的机会，只要认真，平时分也给的很足，最后还划重点，划的都是考点！',5,5,5,15,0,17);
INSERT INTO "reviews" VALUES('5ff42c4454595f432d3e90b8',246,228,'上课讲的东西很多，也会提醒大家这是考点，平时成绩给分很高，而且我们这届期末居然划重点了！马原比想象的好太多了。',5,5,5,15,2,12);
INSERT INTO "reviews" VALUES('5ff3e2c654595f432d3e2a4e',737,394,'****** 不讲课就算了还乱扣分 我真服了 因为他我想换班，千万别选他的课',1,1,1,3,5,1);
INSERT INTO "reviews" VALUES('5ff3306d829787517cbf9041',12930,12930,'老师是百家讲坛的讲师，这门课程也在百家讲坛上有，上课讲得很有意思，老师学识渊博，但是这学期期末考试是闭卷，分A、B卷，挨着的两列试卷不同，需要复习。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff32f887ee37d3cfd6b6fd1',12931,1983,'老师讲课很有意思，聊一些很有趣的事情，也是很典型的事，考试考书上的内容，作业不多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff32dac5d6b37098948a614',175,175,'ppt全是照抄书本的，上课读ppt，那我要你这个老师何用？机器学习一学期啥也没学到，期末考试还煞有介事，机械院凭什么认为一半基础都没有的大二学生可以开始上这种高难度的课了？还整了这么个魔鬼来教，我佛了',1,1,1,3,1,1);
