INSERT INTO "reviews" VALUES('5ff3227454595f432d3d90e0',737,394,'如果你觉得学业太轻松没有挑战性 欢迎来选SWJTU蒋朝哲的课.',1,1,1,3,6,1);
INSERT INTO "reviews" VALUES('5ff32120db1be338d406ee6e',737,394,'他是***，他的课是我的优选课我必须选，所以我也是傻逼，楼下那些骂他的人都是帅逼，夸他的都是傻逼，你们下几届要是还敢选，就真的也是傻逼中的傻逼，选到了就快跑，跑',1,1,1,3,7,0);
