INSERT INTO "reviews" VALUES('5ff31b5154595f432d3d882a',737,394,'认真写了课程的问题分数只有60几，就纯属不看瞎打分。还全英文授课，全英文演讲，全英文考试。就问问为什么这课没关闭？挺奇怪的。遇到了千万别选，一个血的教训。',1,1,1,3,6,0);
