INSERT INTO "reviews" VALUES('5ff277a27ee37d3cfd6a7c26',6826,12954,'作业一堆，期末还考试，PPT演讲，论文加上手写报告一篇，还不如选隔壁音乐与人生麻了',3,2,1,6,0,0);
