INSERT INTO "reviews" VALUES('5ff1ee8854595f432d3c4f28',2701,2701,'期末没有论文没有考试，学期内有小组表演，只要上台就是100，给分高，很水。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff1ee25db1be338d405a7f0',428,4716,'老师的板书真的无人能敌，讲的很细，认真负责，会给专门的例题，人也很温柔。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5ff1ed9e829787517cbe4057',2381,985,'老师真的很认真很负责，特别细心，讲的很好，人也很可爱。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff1aafb7ee37d3cfd69c28a',873,228,'讲的还行，但是开课时候说好的交额外作业有免考，结果期末了别的班都有就他不给，我整了两篇两三千字的论文却没有免考，直接裂开。',4,4,1,9,2,0);
INSERT INTO "reviews" VALUES('5ff13bbc54595f432d3b1942',1108,1065,'很和蔼的老师，布置任务很清楚，平时分合理，态度别太敷衍平时分都是45+。就是上课慢得让人想笑😂😂😂😂花四个星期讲完绪论也没谁了😂😂😂😂',5,5,5,15,2,8);
INSERT INTO "reviews" VALUES('5ff1282b5d6b37098945f428',1193,28,'什么老师嘛，别人家老师平时分都快给到50分了，她就给35分不到，玄学，玄学，还不能换英语课，也不知道怎么了，建议大家千万不要选她的课，你绝对会后悔的，U校园给分也玄学，起初说满10小时就给满分，后面又说看正确率，最后2个都看，老师上课比较水，就给你放放音频，然后让你跟着读，其实并没有真正学到什么东西，很难看出她的水平在哪儿，小考试比较多，喜欢抠各种平时分，建议英语基础不好的同学千万不要选她的课，否则就等着重修吧，因为英语补考也是要算平时分的，你平时分不高，补考也大概率过不了，只能重修。慎重选择！！',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5ff0a70bdb1be338d403fa6a',1938,12962,'每节课都有作业，期末作业也挺多，但是很有趣很有收获，郭老师很有个人魅力，推荐课不多的学期来感受下',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5ff07468829787517cbc6255',12963,138,'上的唐老师的微机原理,老师专业性没的说,对学生也很负责,很亲和,不过唐老师今年已经退休了,以后应该选不了她的课了.',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ff03cb67ee37d3cfd67d029',257,26,'陈老师上课有点水，几乎是照书念的，偶尔还会讲错几道题目。不过专业知识绝对说得过去，人也非常好，思想开明，不严厉，作业量也不是很大。总之，给个好评。',5,4,5,14,3,0);
