INSERT INTO "reviews" VALUES('5feec433db1be338d400e568',1753,1753,'丁老师讲课幽默而风趣，但总感觉有些地方讲的不是很透彻，没有那种一针见血的感觉，而且总觉得本应该详细展开讲得地方他没有讲出来，不必讲得却时时浪费时间。。。。',3,3,4,10,0,5);
