INSERT INTO "reviews" VALUES('5feeaced7ee37d3cfd6522b6',1685,1685,'老师相对严格（但还是讲理的，因为上节课教学楼远迟到，不会扣分。不像某些老师课前上个厕所迟到半分钟都要记名），得高分要求较高，七八十分不难，但只要每节课都跟着上下来，一般总分80-85还是没问题的。每节课都点名。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('5feeaafa54595f432d37576c',867,28,'老师人很好，课挺水的。我感觉平时分不低吧（但也没有特别高），一星期下来基本没有作业，平时作业都是期末大论文的一部分。',5,3,5,13,2,2);
INSERT INTO "reviews" VALUES('5feea9be5d6b370989424f34',2525,229,'老师讲的不错，人也不错。但是给分该是多少是多少，不像别的班级老师给分偏高，相比较之后如果自己能力平平就给分较低。（应用统计课）',5,5,3,13,0,0);
