INSERT INTO "reviews" VALUES('5fee946b54595f432d372a41',175,175,'上他的机器学习痛不欲生，老师杜绝抄袭的心很好，但问题是这个课真的学不懂，然后同答案不同的分，真敢给分，反正班上一堆同学心态已经崩了，还在群里阴阳怪气，让人敢怒而不敢言。',2,1,1,4,6,1);
