INSERT INTO "reviews" VALUES('5fed98b2829787517cb7fc0e',7197,80,'迅哥我爱你😘！介波我大意了啊，没有想到介个老师介么用心、上课认真，引人入胜，从公式的来路到运用讲解得灰常明白、我介个学灰都能感觉到很多收获，知道做题的思路，有疑问老师也从来都是很快地帮忙解答了。从批改作业上每次上午提交，下午甚至中午就把结果发了粗来，错的有批注，改了还能得优，优秀滴也有优。课设给了很多的方案、思路，很是用心，hxdm都能自己完成。如果选rc，就推荐这位老师了！！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5fed96ba54595f432d35fca5',12946,23,'坑的很、神仙平时分，神仙助教，离谱，选了这个课我后悔一生',3,3,2,8,0,0);
