INSERT INTO "reviews" VALUES('5fec6178db1be338d4fdfcfe',4081,2598,'老师人很好，讲得很细',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5fec5fe05d6b3709893fab2e',2646,1170,'每节课查人数，根本水不了。给分特别低，期中班里均分不及格，往届的学生也是。但平时作业留的很少。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5fec5281db1be338d4fde931',1495,1495,'如果你想学到很多知识，你可以不选，但如果你只想水一水，那这一定是最好的选择，你考试可以不相信自己，但一定要相信王老师。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5fec3eaddb1be338d4fdc89d',10344,501,'老师人蛮好 就是有的时候软件使用讲的有点快 总体来说专业能力还是不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fec20c4c4cabd67eaa8e348',8541,28,'很亲切的一位老师，平时分也给很多机会，基本能得满，期末挂科不容易',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5fec18f7c4cabd67eaa8d8f8',8541,28,'是我遇到过最可爱的一位老师，没有之一！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fec0a8ec4cabd67eaa8c5f0',13021,1111,'讲得真的很清楚！很节省复习的时间！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5febfcae9134d1505a3a44fe',141,141,'老师上课认真，给分带点水，很高，热心声音好听。',5,5,5,15,2,4);
INSERT INTO "reviews" VALUES('5febfc0e5fabea2f76f2b580',141,141,'人美心善声音甜 老师超级认真呢！非常喜欢！',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('5febed0e5fabea2f76f2a307',1859,11199,'打了一学期， 不会的还是不会。学球全靠悟性。考试不给机会。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5febe9b45fabea2f76f29fb6',1333,27,'平时分不是很高…',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5febe6ee01213e5afeaae2ed',10547,13026,'一门非常优质的课，不明白为什么不火。课是隔一周一上，每节课都是不同的老师，各个老师擅长的领域不同，对全球化见解很独到。听老师讲课真的可以很大程度拓展知识面，亲和力扣一分，因为其中有一个老师对理工科学生有歧视，在课上反复强调理工科学生什么都不懂。',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('5febe3f9e827d35c642dcf7b',684,684,'关心每一个学生，上课认真，但是！内容太多了讲不完，周末疯狂加课，小组作业思维导图和文献翻译，个人感觉毫无意义浪费时间，建议更习惯自学的朋友不要选，没有时间做自己的计划。',4,2,1,7,1,0);
INSERT INTO "reviews" VALUES('5febe2595fabea2f76f29820',452,965,'本来是线上平台看课（平台经常崩，聊课题目一卡卡个半小时都是常有的事）半期之后线上看课线下还要上总结课，题目布置很少但是整理笔记和思维导图之类毫无意义的作业很多，很浪费时间。',4,2,1,7,1,0);
INSERT INTO "reviews" VALUES('5febe14be827d35c642dcce1',2323,92,'正常上课正常布置作业，不为难学生。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5febe09901213e5afeaadc5a',627,271,'会考的题会重点讲，除了练习册没有别的作业，上课听他吹牛也挺有意思。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5febdf6201213e5afeaadb0d',3477,1697,'作业布置频率合理，形式正常，考前会印试卷给同学复习（不要求做但会给答案，题量很大），甚至会自己总结知识点给同学看，还上过她的工程化学，平时分90+',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5febde4fe827d35c642dc884',1333,28,'英语口音是在交大目前为止听得最舒服的老师！人美心善很好说话，课程设计挺有意思，给分也高',5,5,5,15,6,1);
INSERT INTO "reviews" VALUES('5febdda6c4cabd67eaa892c4',11070,526,'嘴狠心软，上课经常将同学作业批得一无是处但是平时分一般都挺高',4,4,5,13,4,0);
INSERT INTO "reviews" VALUES('5febdd51c4cabd67eaa8926d',1855,24,'网课从不上课不布置作业，但是助教会上习题课，自己看mooc自己做题挺好的，平时分人均95',4,4,5,13,1,0);
