INSERT INTO "reviews" VALUES('5febd168e827d35c642dba63',4986,28,'老师脾气还算可以，比较温和。但是基本学不到东西，上课很枯燥。经常在总结作业以及一些没用的事情浪费一节课以上的时间。对出勤要求比较严格，平时分给的还可以，无功无过',2,2,4,8,0,1);
INSERT INTO "reviews" VALUES('5febcee5e827d35c642db794',867,28,'虽然上课很水，到期末给分很低，平时表现没回答问题五分直接扣没，回答一次问题记一分，上课一共让人回答问题的次数不超过五次。。。差评',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5febcb2f5fabea2f76f27e9f',696,723,'教的一般，作业贼多，事儿逼，千万别选',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5feb59f6e827d35c642d768a',459,40,'不好意思，下边那个longlong的账号是我的账号。蒋老师是很好的，我不小心评价错了！！！蒋老师作业很少，平时分大家都给的很高，人也很亲和，是一个值得推荐的老师',5,5,5,15,7,5);
