INSERT INTO "reviews" VALUES('5fea939201213e5afea98273',236,12571,'上课问题多，只要答不出来问题，那么，同学，你的人生毁了；作业量正常，但会埋坑，考试搞幺蛾子，总而言之，胡节，yyds!',3,1,1,5,2,0);
INSERT INTO "reviews" VALUES('5fea9325e827d35c642c792c',489,573,'分给的低 课又无聊 教的不好🤗',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5fea92399134d1505a38d9aa',1753,1753,'讲课很好，上课也不签到，作业不多，人很有趣，期末的时候好会捞人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fea8b7701213e5afea97619',489,24,'90人的课日常只有三四十人到场，但老师也能微笑面对，很有亲和力！',1,1,2,4,2,1);
INSERT INTO "reviews" VALUES('5fea7d205fabea2f76f12b2c',489,573,'开始不信邪选了她，果然没让我失望，除了教的不好，平时分低，其他方面也没什么，反正一学期见不了几次面。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5fea7bad01213e5afea96006',867,27,'平时分巨低，课堂表现居然回答一个问题给一分，不回答没有，就离谱，平时作业给分也低，避雷',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('5fea77a901213e5afea95ae5',585,325,'李甜心真的是好。上课风趣幽默，专业性也非常强。他能把最难的数学物理方法讲的通俗易懂，常常会结合最新的科研成果给我们举例，拓展我们的视野。备课也十分认真，准备充足，经常十一二点了还在备课。关心学生，经常找同学聊天。我只想说遇到这样的老师，是真的幸运，看见了就快抢吧！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5fe9b53e01213e5afea8b6e7',13051,4761,'详情见知乎，别去，就是个不可回收垃圾',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5fe9af0301213e5afea8aee7',179,764,'选到他的课建议重修',3,1,4,8,0,0);
INSERT INTO "reviews" VALUES('5fe9a7ea9134d1505a3801dd',969,23,'专业知识太弱了，#include能说成是链接指令
INSERT INTO "reviews" VALUES('5fe9a7665fabea2f76f07152',13054,537,'虽然素未谋面，但杜老师是我永远的神',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fe9a6c5c4cabd67eaa65d7c',1495,1495,'考试押题很准，画的重点全是考试要考的。上课喜欢吹逼。从来没有作业。也没见点过名',5,5,5,15,0,0);
