INSERT INTO "reviews" VALUES('5fe99b4501213e5afea89214',12138,370,'麦老师人很好很负责，讲课很仔细，每章节完成后留作业，会认真批改并批注。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fe96a27e827d35c642b354d',11285,9171,'这个老师可以说是非常奈斯了！不禁课讲的很清楚 让人听得很明白 而且还会讲故事 讲各种历史政治数学史之类的 感觉他什么都会 真的很棒！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fe969e0e827d35c642b3505',22,92,'这个老师真的很棒 讲课很清楚！！物理渣渣的我也能学得不错！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5fe96957e827d35c642b346b',5289,307,'老师超级温柔！而且人很好 讲课也比较清晰 对学生有耐心！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5fe969299134d1505a37a3ac',6941,6941,'讲课太难 听不懂 作业多考试难',5,3,1,9,2,0);
INSERT INTO "reviews" VALUES('5fe958d5c4cabd67eaa5eceb',489,24,'这个就是个大雷！巨雷！上个水得很，平时分给得又低，次次都要签到。上课老是迟到，每节课中途还要去上厕所，每次十分钟。讲得而不好',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5fe9518b5fabea2f76eff47b',5581,5581,'葛老师人真的特别特别好，温文尔雅待人和蔼，期末给分也特别高，只要你认真写作业拿满分也是非常容易的。上课葛老师也很认真，讲的很好，还会给你拉小提琴，但是课程内容也不会特别难，想认真听的同学绝对会获得心灵上的愉悦和休闲，想划水的同学也可以划水，感觉真的是一门称得上选修课名字的课，选就完了！',5,5,5,15,4,5);
INSERT INTO "reviews" VALUES('5fe946f9c4cabd67eaa5d291',141,141,'喜欢这个老师！！讲的特别清晰！人也特别和蔼！',5,5,5,15,2,4);
INSERT INTO "reviews" VALUES('5fe944ece827d35c642b0445',5581,5581,'别问，问就是老师人巨好！！！！分也给的高，我爱了！',5,5,5,15,6,4);
INSERT INTO "reviews" VALUES('5fe7fa55e827d35c642955fb',6434,73,'张老师人挺随和的，也比较负责。只是经常喜欢吹牛皮说上他的课就能满分，钢结构公式很多，他不会怎么讲而是直接给结果，内容很跳跃，往往找不到公式在哪里，听来费劲。得课后多看PPT揣摩。',5,3,5,13,1,1);
INSERT INTO "reviews" VALUES('5fe7f985e827d35c642954c2',4003,11034,'这波 这波是大意了，看评论本以为蔡老师讲的很好，实际上讲课完全听不懂(=_=)，说话方式让人提不起劲来，不仅是我周围同学皆是如此，害，不过老师给分挺香的，课后答疑也很负责。建议选上了就课上看慕课吧，三连讲的时间也能学到不少了。',4,2,5,11,1,1);
INSERT INTO "reviews" VALUES('5fe7f808e827d35c64295197',7197,80,'为老师打call！第一节课的时候讲混凝土挂科多，自己平时分会给的很严，当时心里还挺害怕的，但上他的课你会发现他讲的真的很好，知识储备很丰富，会每节课前发PPT，作业交了当天改完群里给结果，课设也是分批改，相比别的班直接期末交给了我们更多的参与感和方向。我真的，巨推荐这个老师。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5fe7f6b301213e5afea66299',9693,32,'老师讲课真的好好啊😭！人很亲和，讲课特别清楚，在众多专业课里是唯一能让我在课上就能掌握90%的知识的老师。而且会抽时间给我们上习题课，值得！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5fe70bb09134d1505a34c75e',18,18,'赵老师yyds!',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fe6e79f01213e5afea52488',13074,496,'网络工程与设计,这课把我上麻了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5fe6bce9e827d35c6427be07',9643,9643,'可以看出老师人很好很为学生着想，但是，老教师，脾气比较大，会把上课走神视为对他的强烈不尊重；但是课下向他请教会很热心很友善。如果上课录音回放复习，可以理清脉络；但是语言表达往往磕磕绊绊，不是很清楚。每节课的信息量不大，想过还是很容易的。',5,3,3,11,1,0);
INSERT INTO "reviews" VALUES('5fe6bbc55fabea2f76ec954a',8447,10551,'翁老师脾气蛮好，就是有一个特点，感觉她所讲的每一个字都会烫到她的嘴。',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('5fe6bb5901213e5afea4c625',13077,13077,'口口声声喊着“我很严！”“落到我手里你们完了！”实际上？哈哈哈哈哈该划重点就划重点 该给答案就给答案 但是又不水，能学到东西 很好的老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fe636b7c4cabd67eaa20043',1320,40,'这个老师，老是说和我们学生一条船上的，要给我们高分，实际上她算的上是给分比较低的老师了，而且别的老师平时作业还可以反复刷分，反正我不推荐，她的课很水，平时分真的不高',3,3,3,9,4,1);
INSERT INTO "reviews" VALUES('5fe1601ff8b4225913c19418',23,23,'交大遇到的最好老师，没有之一~负责、幽默、热情、可爱~同学都喜欢~',5,5,5,15,46,0);
INSERT INTO "reviews" VALUES('5fe020ff0ecbba0374596433',13080,910,'yysy，水课，但是好拿分，推荐',4,4,5,13,1,0);
