INSERT INTO "reviews" VALUES('5fd4b3a70011f22565fe8e70',18,18,'赵老师辣是针滴牛批，要大学老师都是这种我敢说我要考清华',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5fcedf780c1b7765292f763b',2821,40,'****** 作业堆成山。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5fce318abf8910227a0c3acc',613,43,'要求一变再变，有一次本来助教都给了A后来硬生生让改成C，全班最高就给了B。讲解时间特别长而且废话多，留给做实验的时间少得很。上课都是屁话不讲或者一堆废话然后让你开始实验，感觉不咋地。',3,1,3,7,0,0);
INSERT INTO "reviews" VALUES('5fcdabc6bf8910227a0b6c72',2012,1753,'我爱死符伟老师了，yyds',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5fcd00cb7e67e265f61dd650',202,82,'讲课吐字不清晰，有时候坐第一排都听不太清，讲课讲的很快，实习要求也挺严格的',3,1,2,6,5,0);
INSERT INTO "reviews" VALUES('5fcc9e147e67e265f61d3e3b',614,6634,'这门课后半学期是邸老师教的。但是邸老师吐字稍微有点不清晰，配上劣质话筒再加上这门课后半段比较难，简直要裂开了。但是老师人很亲切，如果认真学的同学问问题一定会认真解答。老师实力很强，也是信息学院公认的，很多研究生学生都很厉害。听说他当班导师都很负责。',5,4,5,14,3,2);
INSERT INTO "reviews" VALUES('5fcc9c9ec4244f49f1a06c1d',674,6634,'这门课19级新开的，理论加实验有6个学分…算是内容相当多的一门课了。前半学期是叶老师上，不得不说叶老师还是讲得相当具体和详细的，和后半段比起来简直过于鲜明。',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('5fcb05d8c4244f49f19dcd50',109,109,'再负责也无法掩盖他教学模式的严重不合理性。作业考试，题设离谱（考“为什么单片机开发人员往往不是计算机专业人员？”这种论述题，编程题手写代码），评判死板粗暴（漏一点直接扣完一半分；编程题思路跟答案不同就算错，哪怕能够实现同样的功能），半期考试超纲（考试涉及的论述题来自最后几章，完全没讲过）。想学单片机不如去选电气信息的课，难度一样，好歹人家合理。',4,1,2,7,2,0);
INSERT INTO "reviews" VALUES('5fc71b130c1b776529253ca8',246,228,'这老师，嗯******。
INSERT INTO "reviews" VALUES('5fc4e9b41ed8fc4de19eb077',270,270,'唐老师人很优雅，不愧是空姐导师，但是每节都要让学生上台实操表演，看来她是把我们当空姐培养了。个人建议如果不是想进人民大会堂，最好不要选，主要是不好逃课。',3,1,3,7,10,0);
