INSERT INTO "reviews" VALUES('5fc0bb997bf36739119005d7',489,573,'因为疫情的影响，学校采取了部分课程线上线下相结合的方式授课。好死不死，这门工程力学C就被刘老师报成了线上线下课。没两周火三周会安排在中国大学慕课上搜西南交通大学的工程力学，沈火明教授的，讲得可以。但刘老师的线下课着实没听明白她讲了些啥🥰 半期考试也是在课堂上用雨课堂开卷考 平时作业也是在雨课堂做 题目拍得一点都不清楚🤯无纸化教学真滴是棒棒的呢🤜🏻课堂上还有小组讨论和小组汇报 搞了半天原来我上的是马原😊😊',2,1,2,5,7,1);
