INSERT INTO "reviews" VALUES('5fbcfed122d46e1910f941a2',2005,1697,'这个老师是真的nt，别的班期中考试卷子发给同学回去自己做，就我们班不光考试还闭卷，不光闭卷还让助教死扣分，自己说的90%书上原题，结果原题不到3道，考试全班最高分80多什么概念懂得都懂好吧。还特别做作，明明自己给助教说狠扣分，结果下来还假模假样地问我们考的怎么样，阴阳怪气真的很行，考完试还说分数不到70分的当成作业再做一遍，真就小学生抄卷子的惩罚呗。真的lj，平常上课还下来走，动不动就点名回答问题，平常作业还特别多。',1,1,1,3,11,2);
