INSERT INTO "reviews" VALUES('5fb5c28ab3b86509d32f80f7',13105,1743,'老师好，讲课好。但是他是无敌挂科王。出的卷子常年一个班挂一半。期中考试及格都难。平时分没用。出的题根本无原题。刷题库，刷往年考卷，可能还是做不了新题。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5fb5c0db4c43345923270e05',11684,11684,'不知道哪个地方的口音，疯狂咬舌头，十句话听不懂五句，还抽问。问了问题，问题听不懂，答不上来他的解释的答案也听不懂。还要记你一次。我真的服了。不如自学，老师就不去通过个普通话考试吗？不管有没表达能力，学术能力有些就能讲课吗？',1,1,1,3,0,0);
