INSERT INTO "reviews" VALUES('5f9b4adc0c7d944154685d5c',42,43,'emmm龙哥，大名鼎鼎最严老师，不过我对他确实还挺有好印象的，实验焊板子，结果没弄出来，让他帮我看了好多次，虽然他有点不耐烦，奈何我脸皮厚，每次都笑嘻嘻找他，他也会好好看帮我找问题，帮我换板子，帮我换零件。有一次总结报告的时候，因为我太菜，板子也没有成功弄出来，上台总结也不知道说啥，就稀里糊涂搞搞笑笑瞎说一通，然后我就看着他在下面笑了！！（maybe嘲笑我）不过我脸皮厚啊，还觉得挺搞笑，越说越得劲。最后嘛，期末成绩还挺高的。。',5,5,5,15,3,56);
