INSERT INTO "reviews" VALUES('5f997c69759e7410ee86d9d8',1727,1183,'不怎么教排球技巧，日常看网课。经常到世界各地当裁判，课不算水，考试要求对没有基础的同学来说是挺高的。体育课玩就完事了。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('5f996be70c7d94415465c131',613,43,'上他的数电实验就倒霉了，每次实验前必讲解1个多小时，留给你做的时间只有一节课，别的老师基本都是1节课半还多点，虽然讲解很多但有点浪费时间。实验报告要求很严格，别的班基本全是A，他的班A的就几个，好多B和C',4,3,1,8,0,0);
