INSERT INTO "reviews" VALUES('5f89228b4bf0dc236cfa341c',3212,5,'老师应该还是有些水平，奈何讲的实在是不太行。。。半期考我59分，发觉不能再听她讲下去了。。直接去看网课，最后期末还考了90+。然而总评还是没得90。。。隔壁符伟老师的高数，期末80多，总评都能90多呢。。',3,2,2,7,2,0);
INSERT INTO "reviews" VALUES('5f8834a263136c2d40a0f463',1513,1513,'老师蛮好的，线上上课就看了很多动物被残害的视频，如果害怕的建议闭眼，其他就讲述老师自己对动物保护的事。给分还行了，挺高的。期中看电影写观后感，期末写了文章，重要的是水',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f869132afdb3f347d763ef7',3477,1697,'老师上课负责，知识点详细，如果你能上课耐得住寂寞，那学习就不是问题',5,4,2,11,1,0);
