INSERT INTO "reviews" VALUES('5f81344ba0dfbd5120144514',247,27,'服了，真的服了。同学们，我就问一下，英语补考的人本来就不多，一间考场67个补考的同学，24个都是她班上的学生。邓老师不会提前告诉你成绩占比，比如这一次疫情期间上课，平时成绩占比变成了60%，她没说，我本来靠期末成绩拉分的，平时考一个六七十分，七八十分就可以过了。这下好了，要考接近90分才能过',5,5,5,15,2,1);
