INSERT INTO "reviews" VALUES('5f7458f344c4a3409089371d',1381,517,'完美，上课要求严格，训练量大，技术过硬，真的可以学到东西。虽然嘴上很严厉，但其实对大家都很好，给分90+',5,5,5,15,0,1);
