INSERT INTO "reviews" VALUES('5f71ad8f6cec66034539792f',1381,517,'好课，不过我在家里上的，她还说开学有空可以去蹭课。点名多，要求严，上她的课挺累的，但是给分也还行，在学校游泳馆上的话应该可以学会游泳。',4,4,4,12,0,2);
INSERT INTO "reviews" VALUES('5f71acdfa0dfbd5120f70425',8080,8080,'老师人很好，一楼川普，我上的网课上他的课一点不用客气，有啥问题或者想发言直接说就行，平时有一些时事热点的讨论，期末也是，开放式的言之有理自圆其说就行，分也就90左右。',4,4,5,13,2,0);
INSERT INTO "reviews" VALUES('5f71ac23a0dfbd5120f702e0',2429,2178,'比好评稍差一点吧，上的网课，就讲的PPT上的内容，也会说一些他自己的经历，讲的很快，这个课本身内容很多也没啥趣味。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5f71ab72a0dfbd5120f701ad',9882,92,'中评，上他的是网课，反正我是没听太懂，还会把上一节录下来放，很会省事。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5f71aae9b6b7a048301d9fb8',8265,114,'给个中评吧，老师是数学系的主任，能力肯定是有的，但是他想讲明白各种数学定理的原理，那玩意很深奥，讲的反正我是没听懂太多。给分也还可以吧，正常交作业，正常上课，肯定是能过的，想拿高分推荐看一下蜂考的不挂科视频，做题很好用。',3,3,3,9,0,0);
