INSERT INTO "reviews" VALUES('5f708c796cec660345372158',2525,5,'老师专业水平很高，思维清晰，是真的懂，讲的很详细，如果听课的时候脑子跟得上的话收货蛮多，但是上课速度贼快（全班都感觉在听天书，一开始作业都不会写，不过线代考试题目蛮固定，分数都不错的～），还觉得自己讲慢了😂 人很好，问问题会耐心解答～❤️',5,4,4,13,2,0);
