INSERT INTO "reviews" VALUES('5f6cb08d6cec6603452f345a',23,23,'刘霓老师上课超有激情，还很幽默，学长们都说C++一定要选刘霓老师，果然，跟刘老师学C++轻松愉快，学到很多东西，难忘的一学期，给刘老师点赞！',5,5,5,15,49,0);
INSERT INTO "reviews" VALUES('5f6c5567a0dfbd5120ec28f1',1291,22,'老师专业水平很硬，认真负责，讲得还行，平时分给的也还可以，没有想象中那么差',5,5,4,14,2,6);
