INSERT INTO "reviews" VALUES('5f6aaff044c4a34090753bc3',913,913,'18级快班教师 完美美音 给分奇高 快班期末考试好像同专四难度 但是比例赋分 最后给了100 上课比较注重表达 基本全英文授课 会有要求presentation 基本不点名 都是好同学没人旷课
INSERT INTO "reviews" VALUES('5f69b980a0dfbd5120e72588',1318,10551,'赵老师人特别好，但是他的课适合喜欢自学，容易走神的同学。经常走了十分钟神，你会发现PPT还是那页PPT，赵老师也依旧在扯皮。',5,2,5,12,1,0);
INSERT INTO "reviews" VALUES('5f69b4c644c4a3409073d06b',416,34,'不说了，选到这个老师就是赚了，究极激情，如果没有学好c++，那一定是我们自己的问题。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5f69b2006cec66034529762c',491,23,'选选选，负责程度真的一流，我甚至觉得刘老师是整个交大最负责的，真的，这老师是我目前最喜欢的老师，没有之一。上课讲的我觉得理解挺轻松的，反正方方面面都太好了！',5,5,5,15,16,4);
INSERT INTO "reviews" VALUES('5f69abe21df40b547096c271',876,92,'本来怀着对天文兴趣来上的课，失望而归，分还给的低',1,1,1,3,3,3);
INSERT INTO "reviews" VALUES('5f69a7ecf67afc50fdf5014e',2202,28,'Iris的课还用多说？真心希望老师能教我四年的英语，可惜不行。总之选她就对了！！！',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5f699e2ed3d9ad6df6f1fdfb',236,13182,'这老师真不是人，只要你上课稍微一走神被她发现，她就疯狂扣分，其他老师的实验报告还可以补交，就她不行',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5f697f03d1dae25e9e1bcba3',257,4318,'人挺好的，但就是讲不明白，说话听得到，但就是听不懂。可能他的水平比较高吧。',4,1,3,8,8,0);
INSERT INTO "reviews" VALUES('5f697579d1dae25e9e1bb667',1537,526,'选就对了 香香真的香',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f6848d69bd8096e6360382e',1495,13185,'真的******讲课语速快声音小也讲不清楚，每节课把自己挂在黑板上。板书也完全看不见。真的没见过这么******',1,1,2,4,0,7);
INSERT INTO "reviews" VALUES('5f6809be0e52a07fb08c2c77',141,141,'这个老师真的是一板一眼，做事很认真，对你的期末成绩都是严格根据公式算出来的，多0.1都不会给你加，严格根据每部分成绩的占比给分，如果不认真学习，想着能让这个老师捞一捞，那是妄想。',4,3,3,10,3,1);
INSERT INTO "reviews" VALUES('5f64883a0e52a07fb085091b',5567,1247,'很有意思的老师。像个爱唠家常的大婶，亲和力还不错，就是上的专业课有点让人摸不着头脑。不是难，而是眉毛胡子一把抓，没重点。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5f64874d0e52a07fb085073c',13188,1904,'讲课一团**，不知所云. 给分黑箱操作，毫无公信力.跟杨苹老师搭班材基，简直是对杨老师的侮辱.',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5f64843c151274500e5775ca',12419,910,'分不算高作业还特别多，踩雷了',4,3,1,8,3,1);
