INSERT INTO "reviews" VALUES('5f6425bcd3d9ad6df6e669a3',31,31,'太棒了呜呜呜秦老师是最好的老师，专业知识过硬，上课有趣，作业正常，还会海底捞。是神仙老师了呜呜呜快选他！！！！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5f6425189bd8096e6357785c',68,40,'太无语了，第一节课就一堆事儿，有口音，很催眠，而且不太负责，连教学群都不加也不让同学去加她，有问题只能上课问',3,2,1,6,2,0);
INSERT INTO "reviews" VALUES('5f64065d0e52a07fb083a8d1',21,40,'唐老师其实挺认真的，很多知识点都会讲到，就是给分不高，真的不高，害',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('5f6405bd9bd8096e63571f1c',476,476,'老师上课挺认真负责的，虽然讲课是有点枯燥，但还是很为学生们着想，主要是平时分直接打满 😂',4,4,5,13,0,2);
INSERT INTO "reviews" VALUES('5f61ed273fe62a437872d7e1',9120,92,'谢宁老师上课一节课点名方式层出不穷，问一些不相关的问题，还爱唠嗑，水的不能再水。作业有设置补交，但多次作业补交只算一次，老师在qq群里很活跃，但是到了期末，如果考的不好，平时分就是给你拉到总评60（刚好能过），有两次团队作业，说啥学号没交（他也没说要交学号，最后还统计了学号姓名），硬是给你扣两分。',1,1,3,5,4,1);
INSERT INTO "reviews" VALUES('5f61aebe83950f29e1750c2a',6106,1358,'老师讲课很好，给分也高，就是感觉作业有点多，最让我印象深刻的就是他那一句”嗯哼”，具体参考《银河护卫队2》小树苗放炸弹那段。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f60c049e318d01923332c8d',1174,114,'老师很好，选他不亏。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5f60bfffe318d01923332bc6',452,2671,'郝静老师是一个优秀的老师，她平时很严格教的非常好，她很懂学生不明白的知识点。而且！期末的时候，她会划重点让学生过。
INSERT INTO "reviews" VALUES('5f60be3089921f5fd512e59a',1158,26,'很荣幸能上赵小娟老师的课，她讲的可以，而且很亲切，对学生很耐心。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5f60b65d89921f5fd512d176',2012,1753,'稍微认真一点都可以过，我网课学不进去，考试没及格，多亏符老师捞，老师除了头发有个性，其他样样好',5,5,5,15,2,0);
