INSERT INTO "reviews" VALUES('5f601426ac9b9f59d152d63c',1105,1105,'上学期一直上网课来着，但隔着屏幕也能感受到老师春风拂面般的温柔，作业留的也不多，平时分也蛮高，只是电磁场真的太太太难了跟谁讲没啥关系。',4,4,5,13,0,0);
