INSERT INTO "reviews" VALUES('5f5cea5789921f5fd509cc8a',2399,230,'超级好！！！！平时分高！！！！',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5f5cbd6d89921f5fd50969e7',5318,5318,'平时分标准极其迷惑，作业和上课毫无关系，想到哪讲到嘛，十分可爱🙃',3,1,2,6,1,0);
INSERT INTO "reviews" VALUES('5f5c9113eb571614abc5375c',885,885,'何老师上课特别认真，水分不太大会提问。但提问的基本都是学生应该掌握的重点内容的问题。一般很努力的话，何老师是会海底捞的。但是期末考试的复习重点一般何老师给的会很宽泛，但是覆盖到的考试内容会比较少，老师给的可参考的复习重点一般只有一半。老师人是真的很温柔。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5f5c86ff5a99476ca3fdb1e7',13210,759,'老教授，水平很高，经验也很丰富，像自己的奶奶的感觉，上课认真负责，影响了我的专业选择的一位好老师',5,5,5,15,0,0);
