INSERT INTO "reviews" VALUES('5f214374da423e0006a17a81',2885,3822,'刘老师口语很好，人很温柔，只要是刘老师打分，老师给分还是很高的，普遍反应助教给分比较低。最后平时成绩还挺高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f2141ecda423e0006a176d8',92,22,'娟娟姐水平还是很高的，为人和蔼，给分除了半期考试都给满了，个人觉得还是推荐的。平时不咋点名，喜欢课上做题然后写上名字交上去算考勤。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f201e69d1509d00085ffdcf',23,23,'选就对啦！老师上课生动
INSERT INTO "reviews" VALUES('5f201db5da423e00069f3c81',31,31,'我认为老秦是我大学讲课最好的老师了
INSERT INTO "reviews" VALUES('5f1b9af52f580d0008020a8e',8540,8540,'不建议选，建议避雷',1,4,4,9,1,1);
INSERT INTO "reviews" VALUES('5f194cd85214bd0009febe40',8682,64,'唉  老邓 刀子嘴豆腐心   人不错   就是年纪大了   可能不懂小年轻的奇奇怪怪可可爱爱所以讲话略显刻薄     但他高等数学数学建模给分都很高     网课快乐：“哼 你们居然在会议室聊天”“同学你歌哼的不错啊要不要上来表演啊”“你们在鬼混！”    至于讲课   网课都看视频我又经常使用空气挂课    体会不太深  但人好 值得一冲（一百多小年轻看可爱老年人气的跳脚',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5f194b6914fdb8000819b37c',3941,3253,'额  感觉自己没什么东西  平时的课堂组织作业布置也不管进度不同就跟着另一个班走   就 有点无语  人应该还行的',2,3,4,9,1,0);
INSERT INTO "reviews" VALUES('5f194ae6e80bfc00093ed614',8541,27,'能选上老廖就烧高香吧',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5f194ac25214bd0009feb816',13230,13230,'上的网课   就看电影回答课后一些小问题  但是平时成绩只占10%   期末要写一篇论文  比重很大   虽然我期末还好但是看群里有些同学说写的很认真但分数不高   所以这个期末论文评分应该不是很宽松的那种',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f194a045214bd0009feb5fc',2484,92,'就很好  人也很温柔  讲课也认真',5,5,5,15,0,0);
