INSERT INTO "reviews" VALUES('5f19495e5214bd0009feb49e',5449,5449,'这 老师 也太好了吧 就听的话能学很多 不学的话水也没事 冲hxdm',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f17eb8b14fdb8000816e45a',45,169,'思维偏，和正常老师不太一样，非常有个人的主见，经常怼这怼那，导致必须把论文和报告向她的思路靠近，否则后果自负，给分可以，分差不太大，88-95，就是上课压力有点大',4,3,2,9,3,0);
INSERT INTO "reviews" VALUES('5f17e2c35214bd0009fbd6d3',913,611,'人美脾气好教学质量高，互动多，加分项多。非常好的一位老师。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5f17c7528c2d2a000629549d',844,850,'知识讲解清晰，偶尔穿插吹牛调节气氛，很少点名，作业不收，大作业有点难度，期末给划重点。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f179bc28c2d2a000628e70b',1394,230,'听他讲课，其实也感觉是一种享受',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5f16706c5214bd0009f8e767',8541,28,'英语一和二都是这个老师，一个线下一个线上，老师真的很好，第一学期回答问题少所以按道理平时成绩成绩应该低，但是最后口语考试，因为他觉得我讲的好，所以平时成绩中口语考试和回答问题那一部分他直接给了我满分，比心，其他作业没有，学校规定的那几个u校园和批改网什么的还是要刷的，算在平时成绩里，第二学期线上，这个回答问题简单，也是平时成绩除了学校要刷的那部分之外都是满分，口音我觉得十分标准，人也特别特别亲和，十分绅士，表白就完事儿了',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('5f16704ce80bfc00093908ea',385,27,'上课比较严格，但是事实上并没有学到什么，还有关于平时分的东西，自己要注意！老师不会怎么提醒。还有老师布置的作业完成度和平时分不成正比，要自己看平时分究竟是完成了哪些作业才得得到！！！总之，超烦！形式主义！',3,3,3,9,5,1);
INSERT INTO "reviews" VALUES('5f166e61e80bfc0009390502',1394,230,'老师虽然平时上课看起来有点严厉，但是很好！事也不多，给分还高！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5f166b4e14fdb8000813d8d9',5430,5430,'稍微用点心期末分数就是90+',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5f166a95e80bfc000938fd59',9390,13242,'很棒，挺水，但是要想学知识也学的到',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5f0c2171c880ab0008aee50c',13243,13243,'每次签到都在，每次作业都写了，不强制要求做的作业也写了，最后就给一个85分，吐了，最好别选，虽然都是助教上课，但是每次都要看你来没来上课',1,1,5,7,1,0);
INSERT INTO "reviews" VALUES('5f0afc9bc880ab0008aca6b4',2688,2688,'水 给分高 爱了爱了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f088ea8cd38740008d874d5',270,270,'想说脏话，但还是不说好了',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('5f0579e6c4d9660006b494f8',42,5127,'什么也不教就让你做，拿命给你做。无语了',1,1,1,3,10,1);
INSERT INTO "reviews" VALUES('5f04b9bb49690d00084bd0cf',270,11230,'怀疑让我们写论文是给自己用的，希望有人去扒一下',1,1,1,3,15,0);
INSERT INTO "reviews" VALUES('5f0497aec4d9660006b2e242',13248,13248,'这老师只教了一学期却使我印象十分深刻。他！口！吐！芬！芳！老！是！骂！人！亲身经历同班同学被骂哭，脾气不好，特别暴躁。前期一般讲课，到了后期就要求学生轮流上台介绍史上著名设计师等等等，不合格会暴跳如雷，但不可否认的是他的专业水平确实很高，给分也还行，不会太低，在平均分的样子。也可能是因为后期被举报到学校了收敛了一点',5,2,1,8,1,0);
INSERT INTO "reviews" VALUES('5f04947b49690d00084b9f0b',8,1010,'这破老师给分贼较真，平时事儿还多。点名很频繁，老是点名回答问题，没答出来还罚站。布置作业，天天上课还检查作业，没做真扣平时分。他的挂科率贼高。当然，要是你对自个儿英语很自信你就选呗。给他一星都是因为最低只有一星',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5f047ff749690d00084b7fc0',3186,1529,'这个老师，平时上课挺认真的，但是，期末给分超低，平时成绩给分很低很低，朋友考了59都没给过，服气的老师',1,1,1,3,2,2);
INSERT INTO "reviews" VALUES('5f041accae14a300063438ec',10195,223,'给分很高，老师人很好说话，平时有作业，不难做，期末不考试，交一份报告就可以，超级nice',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f0407c6b1ef0200063593e5',8682,64,'基本每周都有建模作业 因为毕竟是建模 作业量大是无法避免的 但是老师人很好说话 有合理原因会帮忙延迟作业ddl 给分也高 竞赛也有加分  老师说话口音确实有点重 因为我一直划水所以没办法评价讲课水平 可以选',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5f040667b1ef020006359185',8541,27,'老师分给的高 人也很和蔼 会给学生写姓名藏头诗 幽默风趣 课也讲得很好 平时没什么作业 dd！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5f03f583ae14a3000633f05d',13254,114,'很幽默健谈，上课也不会无聊，能学到很多东西',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f03f4a8c4d9660006b18b3e',826,26,'作业堆成山……写到我哭泣',3,3,4,10,1,0);
INSERT INTO "reviews" VALUES('5f03f2d1b1ef020006356d7f',270,270,'什么都做了，就给了八十多分',1,1,2,4,7,0);
INSERT INTO "reviews" VALUES('5f03e6f3b1ef020006355196',2688,2688,'反正我觉得是最好的通识课之一了，老师幽默风趣，平时没作业，不点名，最后给分贼高，基本95+',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f03e5b7ae14a3000633c977',293,375,'老师很好，而且讲课也有意思，给分高事情少课程水，极赞。',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5f03de9d49690d00084a18ad',6726,3691,'******最基础的知识都能讲错 指出来居然告诉你和信号与系统算法不一样所以结果也不一样 后来ppt矛盾了才说自己错了  ******',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5f03538cc4d9660006b04cb1',5894,5894,'只能说还行吧，上课晚上，就是照着念(催眠来的，期中开卷，期末的题目基本都是平时的作业题和往几年考试的题目。ppt是重点，只要ppt和书上的重点都背了就能得分高',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5f035269b1ef020006342bba',6726,3691,'我真的是吐了，同学群里反应的问题也不听，照着ppt念都能念错来，无语',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('5f03448649690d0008490688',887,23,'这个老师真的超级棒，上课思路清晰，还有比较多的复习，高分过。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f03391fae14a30006328d9a',9381,11965,'选就是了',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5f03387849690d000848f57b',12533,394,'老师上课不用ppt，拿着教材帮学生理思路，讲课非常细，但是也确实很无聊很枯燥，容易让人不自觉走神。成绩卡得非常死，平时分只有十分，只要上课期间的那次随机点到在的话这十分就拿满了。剩下九十分全是期末考试，考试内容全是书上的内容（不要信考前划重点，就是把教材梳理了一遍），很多都是需要背诵的，最后的计算大题一般就是考决策树，emmm比书上例题难。但是只要你的分数不是太夸张，老师一般会把你捞上及格线的。千万不要开学时拿着书翻了几页觉得自己看懂了就认为这是门水课啊。',5,3,2,10,0,0);
INSERT INTO "reviews" VALUES('5f03208fc4d9660006affabe',2688,2688,'老师给了我们全班95+的分数，很好的老师，幽默风趣',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5f02f68dc4d9660006af9e57',270,270,'******给分超低。吐了吐了******',1,1,1,3,10,0);
INSERT INTO "reviews" VALUES('5f02e971b1ef020006336446',309,309,'我也好喜欢这个老师，首先知识渊博，讲课清楚明了，而且温柔亲切，特别变通包容，这学期上网课，会签到，有时没签上她都会说没关系，群里说一下，有被暖到。私下问题老师也很认真负责。笔芯！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5f02dea4c4d9660006af649f',9120,92,'上网课强行连麦，回答奇特问题，水的不能再水的大物课，讲的略快，有时候听不懂，每节课点名不知道多少次，太多了，输不起。',2,2,5,9,1,4);
INSERT INTO "reviews" VALUES('5f02dde2b1ef0200063346e4',1390,27,'老师很优秀，人特别好，作业忘交可以补，平时分也高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5f028810ae14a30006310c4f',9120,92,'大物本来就挺难的 还碰到一个让人无语的老师 就很绝 本来是很重要的课程 老师每节课水过去 一个字 绝',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('5f004d6449690d000842a7f5',270,270,'这学期唯一恶心到我的课，建议不论出于什么打算都不要选这门课。
INSERT INTO "reviews" VALUES('5eff1c8eb1ef0200062b38e1',270,270,'事极其多，给分低',1,1,1,3,11,0);
INSERT INTO "reviews" VALUES('5ef6168ee3cb8d0009463371',1193,28,'大学期间遇到的最差劲的一个老师 没有之一
INSERT INTO "reviews" VALUES('5ef32b2a78662d00089c45e4',696,723,'极其事多，一生致力于恶心学生',1,1,1,3,9,0);
INSERT INTO "reviews" VALUES('5ef036628dfe6f0006b7fd59',11758,3017,'老师还是经历十分丰富的，上课总讲一些她在国外的见闻，不过讲着讲着就忘记时间了，两连上成三连是常有的事。交际英语本来事就多，这个老师已经算可以的了。一学期四次小组作业，其中两次要做ppt。三次语音作业(录好了交就可以)。四次慕课测试(这个别的班没有)。期末口语也可以照稿念而且不用跟老师视频，在app上提交音频就好。因为这学期是网上授课，只要在群里打字参与就算额外加分，班上基本都拿到了。认真跟完整个学期平时成绩能拿55左右吧，如果参与竞赛或者当个班长组长的还能高个1分差不多。',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('5eee4d5050e3e40008fb561e',9169,242,'老师很不负责任，找各种借口不来上课，答疑也不耐心，我在地院见过的最不负责的老师就是这位！',1,2,2,5,4,0);
INSERT INTO "reviews" VALUES('5eead4cc50e3e40008f4971f',4784,641,'老师讲的很好，人也很和善。感谢他，大一c语言基础很扎实',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ee6f17c9cba770009d7aa07',13051,13278,'详见知乎 提醒避雷',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5ee6e29d9cba770009d7887e',1291,92,'这个老师是真不行，一讲到关键就加快语速，有问题也不给解决，各种甩锅给领导，别的老师都是10次作业，他是12次都要做少一次扣一分，想方设法的扣平时分',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5ee62faba8db6d00065b86ef',684,2158,'李老师这种极度负责的性格上专业课决定是我的首选。只可惜，通识课选她的话，哎.......我也不好说啥',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5ee184ec0f5ac30009b3d7de',8447,1241,'这个老师......有种一开口就能催眠的能力
INSERT INTO "reviews" VALUES('5ee182659cba770009cdcbd4',573,573,'感觉力学学院的老师都比较严，哪怕是那些高好评的像师明星老师，也不会水（给我们代过课）。成老师相比之下要可爱一些哈哈哈 上课提问，举手回答可以加分。但是有时候问题过于简单🌚 简单到不好意思举手...作业一周3-4题吧，不算多，但若认真做对考试好处很大（没额外刷题期末三位数飘过，低调）。',5,4,5,14,3,6);
INSERT INTO "reviews" VALUES('5ee17f4fa8db6d000652d66c',1418,537,'喜欢网球或者想学好网球的，强力推荐王锐老师，想水的建议换。',5,5,4,14,2,1);
INSERT INTO "reviews" VALUES('5ed9fb529cf15200063a0da1',510,653,'对学生的设计想法很多，个人觉得对不同学生设计和看法的先入为主的主观性强，和蔼可亲',5,2,3,10,0,0);
INSERT INTO "reviews" VALUES('5ed9acfaba7dda00094bf500',2119,2119,'老师专业性是绝对可以的，讲得也非常好，但是就是，上课特别爱点名回答问题，超级超级超级爱点名，一节课恨不得点几十个人的名，问问题突突突突一个接一个，虽然知道老师是为了让同学掌握好，但是还是不太适应，喜欢被老师点名督促学习的，强烈建议你选邱老师，但是喜欢默默学习的，建议慎重考虑，其他几位老师讲的也不错的',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('5ed61025e8d053000818deb1',8591,8591,'这个老师也太可爱了！！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ecfb50716b7490008703c35',1274,36,'我真的服了
INSERT INTO "reviews" VALUES('5ec740fd38bef700082a696d',4066,24,'照着念ppt，作业超多，而且作业中经常出现超前的题目搞你。助教恶心，超级抢戏，要求苛刻，给分很低。很多模型和理论都不讲，作业中遇到靠自己学。',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5ebbe518c9dd6e0008dc102c',383,138,'何蓉老师超有耐心，以后的导师希望能遇到何老师这样的，比某些自以为教的很好的老师强多了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ebbe460c9dd6e0008dc0ee0',13290,13290,'ljlsgbdbsbyzzjdd',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5eb35daf154ee10009e917b6',198,179,'老师给分挺高的，期中考试开卷，期末还会捞你。就是……讲课我实在听不懂，可能也是两次课都是早课的原因吧，脑子还没完全清楚。还有就是作业很少很少，一章留一次，一学期也就交了四五次作业左右，但这就导致了期末不会做题……',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5eb35cfb94016d0008ee444d',199,939,'上学期180多人一个班，因为上一讲有课，每次去都只能坐后面。完全、什么、都跟不上，只能靠自学，平时分给的还行吧。老师人挺好的，期中之前还给了往年的卷子当复习资料',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5eb35c10af55ca0006b74ac6',913,913,'一个上了大二还在想念的老师……再也遇不到像菲菲这样人美心善的了，哭',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5eb35b1694016d0008ee3f39',408,2119,'如果自认为不是保研的人才，不建议选。基本全靠自学，上课堂堂测验，然后随机点名分享屏幕。一学期四次小测(别的班都没有)，限时网上交卷，晚一分钟都不行，时间及其紧张。课上点名回答问题，平均一次课五个人左右。学校补考期间建议停课，他就像不知道一样。',3,4,3,10,2,0);
INSERT INTO "reviews" VALUES('5eaceba6e0a51f00071cf483',4637,229,'上课在提问与跟教材中度过，重要知识点强调不足。从来没有遇到过如此爱抽人的老师，平均每节课提问10人左右，当你回答不上或者没回答时，平时分直接低到离谱。上网课时，同学接麦接慢了，就会被阴阳怪气一波。有同学有事在外面坚持上网课（有车声）直接遭强烈批评。戾气太重了。不建议选择。（大部分同学是自学）',1,2,1,4,1,0);
INSERT INTO "reviews" VALUES('5e95bae35c38580008242ffc',887,23,'选就完了',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('5e93077e5c385800081f8e45',8540,8540,'擅长打鸡血，上课不讲重点内容，课堂催眠，目前体验极差，基本上全靠自学',2,1,1,4,3,0);
INSERT INTO "reviews" VALUES('5e8bca4a21460d006a0f954b',6994,10120,'我感觉学不到什么东西，总是强调这样重要，那样重要，从来没细讲过，感觉都是你自学',2,2,2,6,3,0);
INSERT INTO "reviews" VALUES('5e8168d921b47e006f04bc09',876,92,'感觉对学生不够耐心，有问题也不帮助学生解决，打击学生学习热情',3,1,1,5,3,6);
INSERT INTO "reviews" VALUES('5e8167732a6bfd0077a7f405',4066,24,'要求极严，助教抢戏',3,3,1,7,4,0);
INSERT INTO "reviews" VALUES('5e81594321460d006ab5b5ce',344,1135,'年度感动中国西南交大赛区，电路分析课-组长',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5e75d25791db2800777209f9',876,365,'...',3,2,1,6,0,0);
INSERT INTO "reviews" VALUES('5e7490c87796d9007654c35c',2819,28,'老师真的很好了 碰到她就好好珍惜吧',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e6f55f6546eaad5ca3f7386',913,611,'超级专业，人美还比别的老师讲的东西多，没什么特别奇怪的作业',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e6ef7f97796d9006a95f837',3295,3295,'用英文课本，英文授课。很重视课堂展示和提问，平时成绩很大比重都是按这个算的，所以有平时成绩很低的现象。期末考试还可以',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('5e6ef67721460d006a0ce1d5',2602,13306,'人如其姓，上课不知所云，本身专业技能也不过硬，提建议也难以听懂，希望各位尽量避雷',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5e698d6f21460d006ad17650',13142,52,'交大著名司马老师!每节课都去算我缺勤，她连考勤表都没有!找她询问拒绝回复!作业给分极低!真不知道这个老师是家庭不幸福到什么程度才来这里祸害学生!',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5e698c1491db2800771ba84a',8682,64,'水课一门，就去过2节课，期末90，从不点名，哈哈哈',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e64ec0f91db28007676b0c8',8682,64,'作业加考试就是建模，有人挂科，期末建模成绩相当于期末考试，占分百分之五十，班级平均分不上80。讲课就是照书上读书。',2,2,1,5,2,2);
INSERT INTO "reviews" VALUES('5e6327f65620714cccd39299',510,653,'赵老师在同级的几位专业课老师中，特别是万江老师中算是水的，但是设计能力很强，人也很和蔼，给分。。。算高的？？？',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e62784643c25700767e7a71',408,2119,'不画重点，讲课的时间很短。需要很高的学生参与度。为人亲和，但治学很严谨。不是特别推荐，当时我们上课采用的教材就和别的班教材不一样。期末考试有个知识，老师上课时都没有讲到。',4,4,5,13,0,2);
INSERT INTO "reviews" VALUES('5e62073591db2800765492be',101,101,'顶！顶！顶！只看你能不能选得到',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e610cef546eaa007597b0e4',1381,517,'易老师很“魔鬼”，典型刀子嘴豆腐心，私下里人很可爱，期末给分没下过九十，是能让你真正学到东西的好老师',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('5e610ac9546eaa0075978218',1938,2375,'郭老师很和蔼，给分高，可以给到95分左右，上他的课很快乐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e61097b8a84ab0076703da8',1537,526,'赵老师人超好，讲课超级棒，给分超级高，选到她是这辈子的福分嘻嘻',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5e6107d2fc36ed006aafbb66',510,653,'认真、负责，出人意料的有耐心，超级好，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e60bf7043c2570076685655',11887,11887,'签到都签 期中期末论文按时按要求交 给了100分',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5e60895f43c257007664c2a2',13318,1825,'水的不行，作业布置的也是很有趣的那种实践啊啥的。经常提前下课，最后期末给了我90+，选他没错。期末也没有考试',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e5f9dd40a8a840067162f1e',535,535,'老师很有亲和力，人称简单哥，毕竟清华的大佬，什么题目到了他那里都说很简单。上课也不是读读ppt那种，都是讲的干货，打分也挺合理，只要跟上他的节奏考七八十应该没啥问题。主要是这门课比较恶心，感觉简单哥已经讲的很好了。',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('5e5f26f25620714ccca375ce',13320,2499,'老师幽默风趣，讲课也很生动，很有人格魅力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e5f052091db2800762ec05b',13321,13321,'老师很可爱，温柔大方，给分还高，唱歌还好听',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5e5deb858a84ab007649572a',13254,229,'上课通俗易懂，跟着他走，找到方法就可以学好。另外，老师很可爱，还会打太极',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e5dbc5791db280076201ae0',8096,23,'哭了 听不懂',3,2,5,10,0,0);
