INSERT INTO "reviews" VALUES('5e57b30356207100779ace8c',10624,1001,'好兄弟，老师******，上课说的最多话就是“不好意思，同学们，这道题我想简单了，我们下节课再讲”，******一个，如果选了他的课，建议退课，宁愿晚一年修。
