INSERT INTO "reviews" VALUES('5e56948a7796d9006a2097d2',2484,92,'何钰老师给分还算不错，但是上课催眠系数太高了。不过期中考试期末考试前会发自己的复习资料，上面的题目也很有针对性，非常适合分奴选手。',4,3,4,11,0,1);
INSERT INTO "reviews" VALUES('5e5217fb2a6bfd4d103d2495',7927,1252,'除了上课一直吹牛，给分贼高，高到其他班学生去联名举报他之外啥也不是',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e4e917f1358aa006af3b4db',4352,4352,'这个老师是男的，上课对女学生就十分上心，认真矫正动作。而且给分是真的。。。低',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('5e4e90c1fc36ed006ae5c841',8460,8460,'作为通识课，不累，学到东西，开拓思维。成绩方面，只要努力认真学，会取得让自己满意的成绩的。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e4e903f8a84ab006a577144',1174,5,'上课内容详细，丰富。陈老师自己也十分负责，认真。选到即赚到，选到即赚到。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e4e8fd943c257006a2159de',13340,542,'不知道是不是快退休了。有着老年人特有的缓慢感。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5e4e8fa1fc36ed006ae5bb37',13341,13341,'很有意思的一个老师。讲课生动活泼，但作业也是算多的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e4e8f5c7796d9006ad8cbac',2399,230,'遇到曾老师之前从来不知道原来历史课可以这么有趣。强烈推荐。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e4e8ecf7796d9006ad8c525',3189,186,'十分喜欢这个老师。不仅教学内容丰富多彩，更重要的是其展现的家国情怀让我很欣赏。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e4e8e7a2a6bfd4d101fd943',913,913,'钟老师真的超级好，给分高到离谱。你见过大学上英语课最终成绩100的吗。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5e4e8df856207100774948ab',649,36,'上课呢就是照着PPT念，经常让学生尊重他，但是就我自己而言，感受不到其对于学生的尊重。',2,2,1,5,3,1);
INSERT INTO "reviews" VALUES('5e4e8d581358aa006af37d20',1855,24,'上课经常聊天聊着聊着就收不住了。上课感觉比较随意。选了唐怀平的课，就靠你自己了。',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('5e4e8ce721b47e006b2679b0',2458,23,'吴老师讲东西讲的都很明白，而且会尽最大努力让每个人都能弄懂。而且注重实践能力。值得推荐。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('5e4e8c2f8a84ab006a573bf7',565,762,'杨老师平时分给分很高。但不知是不是因为我当时选他课的时候，是他第一次教概率论。上课所讲授的东西都是含糊不清的。但杨老师在期末的时候说他下次一定会改正，因为自己第一次教这门课什么的。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('5e4e8b36fc36ed006ae5852a',78,195,'上课不知所云，就跟混日子一样。课堂所讲的与平时作业，期末考试没半毛钱关系。还觉得自己有多厉害，给分低的离谱。',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('5e4e8a4e43c257006a21153d',852,852,'上课讲的很详细。给分十分宽松。选到即是赚到。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e4e89da1358aa006af35204',85,407,'陈锴老师上课很有意思，内容也是我们在生活中所能用到的。作为一个通识课，强烈推荐。',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('5e4e894643c257006a210955',2323,22,'如果有幸能够选到谢东，那么再也不用担心大学物理这门课',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5e4a532e21460d0077a50637',13142,1596,'莫名其妙的给分，老子节节课都去，给我记缺勤!让她给出考勤表，没有!讲的好不好另说，能考虑一下学生的感受吗?辛辛苦苦学了一学期你给老子把平时分都扣了!我绝不是不爱学习，是这老师太坑!上了这么多课，遇到这么多老师，这是我见过最无情，最冷酷，丝毫不考虑学生感受，平时分随心所欲给分，最不负责任老师!!!',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5e43bbf143c257006ac3ccfa',2878,28,'超棒的老师，讲课也很清楚，超级亲切可爱啊！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e2333ca7d5774006a11042e',198,179,'讲课讲得不错，而且讲课很有重点，也就是不考的不多讲，半期考试也很水，给分高，期末还划重点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e2332fa21460d006ad4157d',199,939,'额总体来说还不错的一个老师，讲课水平不错，但是就是上课喜欢扯其他的闲话，课上能获得的知识其实不多，也就是例题讲得比较基础，还有就是划重点的可信度不大，说了不考的东西结果考了，说了必考的题没考',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e2331eadd3c13006a0928ea',1768,22,'老师讲课讲得很好，但是节奏稍微偏快，平时分也给得高，很不错的一个老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e1bead57d5774006ad7ee65',18,18,'年轻的老师就是不一样，非常感谢老师！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e1be6e721b47e00703745b6',18,18,'是本学期遇到教的最好的老师，上课不枯燥，耐心，认真负责，期末考试前觉得一遍答疑不够就再开一遍，平时分完成对应的任务就是满分，真好老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e1be57afc36ed006a1d8ee1',18,18,'赵春明老师讲的真的很不错 平时分也给的很高 超棒的老师嗷！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e1be37b5620710077cc44fd',18,18,'赵老师上课活泼，幽默风趣，讲解清晰，还想着法子给大家加平时分，期末能给过的绝对抬过，这种老师不选还干啥啊😱',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e1bda85dd3c13006acf630b',18,18,'果真老师之间没有对比就没有伤害，感谢自己明智地选择了赵春明老师的课 。老师讲课非常有水平，非常吸引人 。一般课前五至十分钟会复习上节课所学知识， 帮助我们更好理解之后所学。课堂氛围轻松愉悦， 课堂讲义资料会完整上传，作业内容有助教会认真批改评讲 。临考试前老师非常认真负责（其他时候也是啦～），会在班群里认真回答同学们的问题，与同学们沟通顺畅。总而言之，选择概帮，让你无怨无悔。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e1bda1c43c257006ff7c6d8',18,18,'虽然赵老师口口声声说“概率论是一门很简单的课”，但说实在的还是有一些难度。老师上课幽默风趣，注意同学们的反馈，课间还会和同学交流些有的没的。有自己个人风格的课件，并会推陈出新，也自己组织了习题册的解答给同学们参考，会额外助教上习题课讲一讲题，偶尔还会亲自上阵。一学期点了两次名，要求习题册写完，有一点并不多的课程作业。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5e198ffafc36ed006a0aa4c3',855,619,'平时事少，有见地，期末给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e181fe45620710077acd572',762,565,'给分不公',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e16c2e6fc36ed006af22c86',10624,101,'来给刘裕老师道个歉，本来以为他是一个啥都不行还疯狂坑学生的老师，今天期末成绩出了，发现老师平时分还是几乎给满了。可以看出来老师还是很想我们好的。只是不太会讲课。。。',4,2,2,8,4,1);
INSERT INTO "reviews" VALUES('5e15c7bd43c257006fc53c3a',819,228,'不水，马猿期末好难，哭了',3,3,3,9,0,0);
