INSERT INTO "reviews" VALUES('5e1420437d5774006a95feba',2324,419,'期末成绩给了70分🙃第一次遇见行政拉低平均分的老师 很fine 上课不点名 疯狂点人起来回答问题 手机都完不成  好好水一水不行吗 
INSERT INTO "reviews" VALUES('5e12f2e5562071007780eb1c',13142,1596,'作业给分很低',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5e12f1bc21b47e0070ebc0d2',652,198,'平时分给分贼低 上课声音小 动不动课堂测试 必点名 对同学提问很冷漠',3,1,1,5,2,0);
INSERT INTO "reviews" VALUES('5e12f132dd3c13006a845f24',1287,68,'平时分给的太低了',3,3,3,9,2,1);
INSERT INTO "reviews" VALUES('5e12956b21b47e0070e7fe3d',1537,526,'老师认真负责，在老师的课上真的能静下心来听课，讲的非常好，平时分也给的很高，建议选择',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5e1295097d5774006a88898d',756,22,'老师真的是很负责的老师 会给你认真回答问题。平时分也给的很高，就是经常点名，但是点名也为了大家好好学 选了他的课你就必须得好好学呀',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e12945d21b47e0070e7f3d9',11891,92,'上课很枯燥，平时分也给的很低，扣了八九分，总之不建议选',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5e1134c443c257006f9d0b8c',703,228,'这老师是的不行，有问题也联系不上，专业水平堪忧，平时分给的低的不行，选了她就等于学了挂科',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e1049d7fc36ed006abb6972',703,228,'讲课一般，半期考试闭卷，（其他班有的开卷，有的问答几个问题就行了），平时分给的不能再低了……',2,3,3,8,0,0);
INSERT INTO "reviews" VALUES('5e0ff224dd3c13006a698324',12218,762,'很好的一个老师 选就完事儿了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e0f2d2a43c257006f8c754b',2381,985,'罗荣老师讲课思路非常清晰，解题思路更是，讲课基本上不需要任何参考资料，足以看出对知识的熟练程度和准备程度。个人认为上罗荣老师的高代是一件非常幸运的事。',5,4,5,14,2,1);
INSERT INTO "reviews" VALUES('5e0f2aad21b47e0070cb7364',2017,4609,'老师人非常好，鼓励我们用知识解决实际问题，平时分只要按照她的要求，除了考试自己考的，其他都是满分。',4,4,5,13,1,1);
INSERT INTO "reviews" VALUES('5e0dcd5c43c257006f80ecaf',433,27,'平时分跟其他老师比真的第一些 上课不允许用手机 其他方面都一般般。 平时分真的好气，而且保研英语要算三次，保研差0.0几分都可以排好远。这个平时分你需不需要，就看你自己了。',3,2,3,8,2,0);
INSERT INTO "reviews" VALUES('5e0dc78b21460d006a2361a5',2298,394,'上课骂骂咧咧，没讲什么和专业相关的知识。作业贼多要求也不说明白，大家做完了才说要求。做的ppt太差会被骂。给分不高事儿贼多，上课就很气。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5e0dc6dbdd3c13006a585eac',8453,13383,'上课说话声音小，什么也听不见，板书字小看不清。只和第一排同学交流。作业很多，要求很高，平时成绩期末成绩都很低。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('5e0dbf0321460d006a230dae',11758,3017,'凶巴巴的，给分也不水，平时成绩难顶',3,2,1,6,1,0);
INSERT INTO "reviews" VALUES('5e0dbddddd3c13006a58086c',8453,13383,'声音贼小，作业贼多，讲课声音贼小，分数给的极其残忍，当事人现在表示十分后悔☹️',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5e0dbd2e5620710077545f09',8453,13383,'数学建模B，上课我就想睡觉，讲课的声音就第一排能听到，字写的也不好认，平时作业多，虽然可交可不交，但是不交就没分，期末平时贼低，别的同学同样限选课的数学实验95+，气死我了气死我了气死我了气死我了气死我了气死我了气死我了气死我了
INSERT INTO "reviews" VALUES('5e0dbd0edd3c13006a5800f1',489,24,'******讲的什么东西。天天出差******专门想让学生挂？？******一点点分亏心吗？',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5e0dbc9f21b47e0070bf793b',8453,13383,'上课几乎没用 分还给的贼低 这老师我真的服了',3,1,1,5,3,1);
INSERT INTO "reviews" VALUES('5e0d7f7821460d006a207e76',10624,101,'清华本科加名古屋的研究生，学历太高可能导致学生没办法跟上他的思维方式，现在上课能跟上的人，一个班没几个，上课不点名，但是会讨厌你去上课带耳机，耍手机。如果跟他学线代，自学是比较好的方式。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5e0d7e7a7796d9006aa66cbc',6510,175,'老师讲得挺细的 知识点也讲的很清楚 上课不会点名 还会主动给学生找复习资料 作业量适当 人也很温柔 唯一的缺点可能就是上课经常会拖下堂',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e0d6a4b7d5774006a5cad85',867,27,'美女老师，上她的职场英语课的同学最后平时分基本都上了50，课堂活跃一点55+不是问题。非常推荐！！！',5,5,5,15,5,2);
INSERT INTO "reviews" VALUES('5e0d56c57d5774006a5bcfd6',4195,36,'老师很有亲和力。但是每节课我感觉她都没有在认真讲课。到了期末她只说了思修的题是从西南交大的题库里调出来的以及题型是什么。然而一提及划重点的事她就“闪烁其辞”。害，反正我感觉整个学期被划分成了三部分1.介绍姓名2.准备社会实践3.社会实践报告。总而言之特别无聊。而且课堂发言还要算平时成绩。建议学弟学妹们emm课堂发够十次言 然后上课有空把书看一遍 ps第六章法律那部分和令人心动的offer 更配哦哈哈哈哈哈',3,3,5,11,2,1);
INSERT INTO "reviews" VALUES('5e0caee47796d9006aa154f4',1318,10551,'屁话特别多，每次下课发现内容没讲完就硬拖，有时候能拖你十分钟，而且还是上午的三连讲，期末最后一次作业都考试了还让你交，而且每次给你布置一大堆作业，课上重点基本都是两下讲完，完全靠你自己学。',2,1,1,4,3,0);
INSERT INTO "reviews" VALUES('5e0c5a1cfc36ed006a9a63e3',1048,6654,'课上不点名，考勤分直接满，送了两次随堂测试15分，平时成绩基本能给满。但期中考试判的有点严，和其他老师有将近十分的差距。没有方言，课讲的还可以，就是我不听',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5e0c3f01562071007747b3f2',1007,1007,'专业水平不知道，但是亲和力是真的不太行。上课呢，提不起兴趣，期末不划重点，给分严',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('5e0b4d1721b47e0070ab7084',1318,10551,'上的物理化学 我相信赵老师的专业水平绝对够硬，但是，三连讲用2.8讲讲一些不用听就能懂的东西，剩下0.2讲瞬间过掉一切重难点，然后考试考后者 嗯，看在是我大一班主任的份上不评太低分',5,1,3,9,1,0);
INSERT INTO "reviews" VALUES('5e0b2437fc36ed006a8f6882',9603,3685,'桥梁工程a是铁道和道路方向的专业课，不算难，记的内容较多，算的很少。
INSERT INTO "reviews" VALUES('5e0b20ab7d5774006a495fa3',11452,370,'水力学算是土木五大力学里面比较简单了的吧，考试也比较简单，原题很多。
INSERT INTO "reviews" VALUES('5e0b1e4521b47e0070a8c80d',13399,12648,'这门课算是铁道专业课里面比较简单的，内容不太多，计算类型也不多。
INSERT INTO "reviews" VALUES('5e0b1c3edd3c13006a412619',13400,336,'轨道工程a是铁道方向的专业课，对轨道的体系以及各组成部分比如轨道板、道岔、钢轨、连接件等做一个介绍，难度适中，有理论有计算。
INSERT INTO "reviews" VALUES('5e0ad04b43c257006f661bf3',246,228,'平时分比别的班的室友低了十分，他还是不听课的',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('5e0a1f797796d9006a8ab658',8182,573,'老师真的很好 平时分直接给满了  偶尔点名 作业也不算多 虽然有一点点口音 但真的是个神仙老师！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e0a14cc21b47e0070a0e39d',442,573,'喻老师讲的挺好的，就是给分太低了。',3,3,3,9,2,2);
INSERT INTO "reviews" VALUES('5e0a1455dd3c13006a394138',8182,573,'老师平时分给满了！太好了！！上课有一点口音，但是我感觉适应两节课就好了。讲课比较能把复杂的东西简化，期末复习的时候非常有用。偶尔随机点名，每节课都有作业，但是题不多，作业好好做期末没什么问题',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e09e4de43c257006f5f37d4',23,23,'强推C++刘霓老师，活泼可爱，幽默风趣，极具爱心，激情教学，跟着刘老师学很轻松，选课首选刘霓老师，保你大大收获',5,5,5,15,49,0);
INSERT INTO "reviews" VALUES('5e09c96b21b47e00709d5ae0',1053,126,'老师上课吹逼，高傲自大，改分乱改',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('5e09a5807796d9006a852fee',1053,127,'不要选******，为了来这骂他两句还专门注册了个号
INSERT INTO "reviews" VALUES('5e0973fbdd3c13006a31fed7',42,5127,'不配做老师',1,1,1,3,8,0);
INSERT INTO "reviews" VALUES('5e09705f21460d006afcddb4',42,43,'我觉得他不是严，他完全是不负责任。每次打分给分低就算了，就是不给原因，有一次问他原因他说给你高点分好了吧？好你*呢？问他问题就让你回座位上。打分完全看心情。最扯的是考试签到自己没组织好还怪学生，我真的是口吐芬芳了。',1,1,1,3,15,3);
INSERT INTO "reviews" VALUES('5e096a8f56207100772e090f',535,535,'很好的老师，讲课有点快但是很专业，口头禅是很简单.',5,5,4,14,3,2);
INSERT INTO "reviews" VALUES('5e096a3621b47e007099347a',281,281,'上课干念PPT ，有口音，期末没有复习资料或者重点，考试合计总分59.6给我挂了，斟酌着选吧',2,1,1,4,1,3);
INSERT INTO "reviews" VALUES('5e0892d77d5774006a339427',876,92,'老师讲课很好，认真负责，平时作业给分需要自己争取（给分不会低于半期成绩，但前提是交了的），很喜欢他能够对作业有一个及时评讲。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5e086dcdfc36ed006a77d246',756,22,'杨金科老师讲得真的好，上课特别有活力，唯一认真上的课',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e07fb09dd3c13006a24e388',887,23,'计算机五星级老师，强推！强推！强推！选到刘老师的课真的是一份幸运。讲课风趣生动，详细易懂，各项满分。会把课件发在群里，十分方便学习。作业也不算多。上了一学期课，下学期没有了，真的很不舍。能上到刘老师课的请好好珍惜，没有被安排的请抓紧机会拼手速拼网速，你绝对会觉得赚到了！',5,5,5,15,3,3);
INSERT INTO "reviews" VALUES('5e0792917d5774006a2b8677',252,114,'nice哈，是我大一的时候的数学老师，授课很清楚，认真听了都能懂，平时分挺好😊',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5e07901e21b47e00708b1266',2541,22,'讲课不行，到后面基本上没有几个人来上课，很凄凉的，给分还不知道，但是人还可以，比较佛的那种。',3,3,3,9,0,2);
INSERT INTO "reviews" VALUES('5e078f0721460d006aee5b03',485,3822,'很难受的就是，平时分会压，我自认为英语还是不错的，平时分给了79，占百分之六十，很拉成绩。再也不会选胡霞老师的英语课了，和我不对付。但是老师人还不错，希望以后能够更加公平地给分，而不是一味地控制班平均，感谢！
INSERT INTO "reviews" VALUES('5e078d17fc36ed006a712f21',247,27,'我铁的邓娟娟推哈，挺好一老师，感觉给分是比较正规那种，不会死压你的分，考的好的就好，不好就是不好，挺公平的，当然要是你英语不好，就选其他的全班给分都一样的劳斯吧。',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('5e078bd321460d006aee4ac5',9085,13419,'韩老师真的是好老师好老师好老师！超级耐心，而且很可爱哈哈哈哈哈！工程制图选他选他选他～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e078bc821460d006aee4a8e',9085,13419,'韩老师虽然上课挺啰嗦的哈哈哈，因为我们这个学得也不是很深，但是平时分给的很大方，讲课其实也挺好的，听听课也能学到很多画图的方法，老师也很可爱～～推荐～～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e078b0b7796d9006a744e74',23,4181,'超级喜欢刘霓老师，上课贼有激情，课间还放歌给大家听哈哈哈哈，只要认真跟着走，没问题der～期末给了九十加还是蛮开心的～',5,5,5,15,49,0);
INSERT INTO "reviews" VALUES('5e0789f27796d9006a74465d',24,24,'超级超级超级喜欢郑小武老师，人真的非常非常非常之好，授课真的很不错，有什么问题去问，真的都很耐心。平时分给满，如果要学理论力学，选他选他选他！！！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e0789957796d9006a74442e',24,24,'郑小武老师真的贼好，上课讲的很透彻，俺期末分不高都是因为没有平时好好练习。跟着郑老师好好学，上课好好听，过是肯定没问题的【给力】',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5e07709743c257006f4ab4a7',234,234,'孙美玲老师是一个很负责且和蔼的老师，特别是课外实习的时候会超有耐心的给我们讲解',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e07703ddd3c13006a225386',234,234,'孙美玲老师很温柔，上课讲得很仔细，如果课上仔细听，考试认真复习分数不会低的',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e0758b67796d9006a722e2f',141,141,'超级负责的老师，讲课比较有激情，因为ppt是教研组统一制作因此没办法修改，但是老师也会尽力给我们修正，总之选她不亏。',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('5e06e8c0dd3c13006a1b9f34',237,5,'真的是******，没想到在交大会碰到这样的老师。天天上课就知道吹牛，不专心讲课。讲课只会念PPT，PPT还是别人的。找不到PPT就叫你自习，感觉是个人就可以替代他。他还经常开一些低级玩笑，很恶心。老师上课自己都会走神，将一句话还会停半句。感觉他就是来混退休的。千万不能选他，能换尽量换，不然你会感觉到绝望。',1,1,1,3,4,1);
INSERT INTO "reviews" VALUES('5e06ce457796d9006a6b6f82',334,562,'默默无闻的挂掉了很多人',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5e06cdeadd3c13006a1a69ee',162,36,'上课管的很多 不让玩手机 不让写作业',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5e06cda3562071007716d7ec',247,28,'老师除了布置作业 貌似不会干什么了呢',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e061a04fc36ed006a635f17',141,141,'对学生非常认真负责，讲课非常细致。点名作业啥的也会很认真。于我而言，唯一的一点点不适应，就是除了ppt之外不怎么写板书，喜欢用嘴说，如果前面不扎实会反应不过来。不过是小问题啦，老师超级棒的！',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('5e0615dbdd3c13006a155530',3251,3332,'上课喜欢扯东扯西，考试与教学脱节，对学生极其不负责任。为人风趣幽默，扯皮听一两次挺有意思，但是想学到东西的朋友还是别选了',3,3,3,9,9,0);
INSERT INTO "reviews" VALUES('5e06097f7796d9006a65b2a7',3251,3332,'拓扑排序警告，关键路径警告',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5e05cd8c7d5774006a19e203',442,573,'对喻勇无******说，一直抽人回答问题，点名，口头禅：你们这样，这门课是过不了的啊。期末给分低到你过不了。懂？',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5e05c04e56207100770d829e',13435,13435,'你不要笑哦，真的是这个样子滴哦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e05a96321460d006adb0dd9',8566,114,'视力不好的同学千万不要选，老师上课写板书所以坐的比较会反光，就看不清。想混的也不要选，考试比较多，给分也不高',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('5e05a79421b47e007077ad5d',2861,394,'没有作业，但是有期中考试，而且点名较多。老师很好，讲的比较仔细，期中考试只要认真复习就可以，平时分就是点名，人少会点。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e05a6f343c257006f3852c3',823,1897,'老师首先很幽默，需要大家在课堂上认真听讲，只要听了一定可以明白，好评，课堂很短暂一样，还会提前下课',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e05a3d98a84ab006afe4d81',442,573,'千万不要选这个老师!!!别选
INSERT INTO "reviews" VALUES('5e0552d621b47e0070744346',5,271,'水+难',1,1,1,3,1,2);
INSERT INTO "reviews" VALUES('5e05472121b47e007073c569',2819,28,'老师很负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e05455543c257006f346e8d',5,114,'太水了',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e047ec67796d9006ae55bda',8147,114,'徐老师人很好，讲课也很好。上课只要认真听都能够学会。上课一定要认真听，老师会抽人回答问题。如果被抽到回答不上来问题就有可能一直被点名。老教授有点口音很正常，多上几节课就适应了。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5e047cccdd3c13006a0683be',1341,114,'老师手书，我个人比较喜欢的风格，上课不用PPT，相对来说课堂进度没有用PPT的老师快，而且手书的思路比较清晰。课后作业虽然有点儿小多，一周也只有两天有课，理清思路之后上手还是比较容易。还有（狂敲黑板）冯老师是魔法少女（划重点），冬天的时候，每次上她星期四的课都会出太阳，要知道在四川，成都冬日的暖阳还是很让人惬意的。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e047b1f21460d006ad15b64',4435,13445,'老师太有意思了，上课既有趣又能学到知识，冷笑话会来的措不及防哈哈哈哈哈哈，人特别好',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e047a4021b47e00706dfc9c',887,23,'刘老师人年轻，有气质（划重点，狂敲黑板），其次，她会建一个学习群，把之前的资料和后面上课用的PPT提前发给我们，方便预习和复习。其实作业真的不多，一个星期就一个上机实验，敲5、6道题就完事，做不完也可以拿回寝室做。真的不算多，而且C艹就是要多上手。选了刘老师就千万别换了，信我没错。',5,5,5,15,13,1);
INSERT INTO "reviews" VALUES('5e0479111358aa006a05b7ea',1390,28,'这个老师水平正常，上课基本全英语，解释作业等时用中文。但是超级超级热情和蔼，作业都会布置然后发群公告，有考试就会提醒，很好。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5e04780443c257006f2e8e35',247,28,'作业很无聊，都是通过平台上布置对水平提高没有一点帮助的作业,上课内容跟考试没有一点关系。建议上课睡觉，养精蓄锐，课后自己多刷点题目。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e0476d221b47e00706dc6c9',887,23,'五星好评！！！不解释。有这样的好老师是我们的幸运！！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5e04756e1358aa006a05824a',246,228,'挺喜欢针对人吧，讲话也比较刻薄，学不到什么东西。',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('5e044f837796d9006ae33b6d',505,561,'老师不错，平时给分也可以，就是在课上有时候会被催眠。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5e0437011358aa006a02f2ab',1105,1105,'特别特别亲和，人超级好，一直怕我们听不懂
INSERT INTO "reviews" VALUES('5e0436798a84ab006af1e65a',18,18,'特别棒，讲课很有趣，老师人也很好，平时分会很容易
INSERT INTO "reviews" VALUES('5e0342a1dd3c13006afbc5b1',13454,195,'课上得无聊枯燥也就算了，作业每一次交齐了，平时分还乱给，脑子不好建议多找几个帮手，幸好以后没这门课了，算是斩妖除魔，建议这老师的课都别选呢。',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e030698dd3c13006af9049f',614,4948,'知乎大v、集成电路优秀回答者forever snow。到目的前为止最有亲和力的老师之一，完全不凶，问他问题贼耐心。上课跳的很快，但是考前给的考纲考点明确。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5e02f4df21b47e00705fce06',913,611,'选就完事了，老师人太好了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5e02e8d11358aa006af713c7',6510,175,'讲课讲的挺不错的，看得出来老师真的想要每个人都听懂。因为19级课时缩减所以有时候会拖堂，但是讲的真的很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5e02de217796d9006ad5cd2e',3920,761,'好的 别错过他！',5,5,5,15,0,0);
