INSERT INTO "reviews" VALUES('5e01e4832a6bfd00745563de',2124,2124,'还可以，经常点名，还要拍照 期末很水 平时分组 没有作业',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5e00e66743c257006c082b9c',1192,27,'老师人真的很好，上课幽默，而且对同学也很好，可以记住每个人的名字，上课也很希望同学们积极回答问题，对待课程严谨认真。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5e00d17521b47e0075a927fa',23,4181,'上课风趣幽默，极其富有激情，语速较快，收获良多，而且给分也比较高，讲得很透彻，只要配合好这门课学起来就很轻松。',5,5,5,15,48,0);
INSERT INTO "reviews" VALUES('5e00ce898a84ab006ee76adf',703,228,'讲了个******讲，谁上谁倒霉',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e00cdf2dd3c130072c28d7c',1776,653,'万老师超好！',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('5e00cc59dd3c130072c279bb',703,228,'快跑！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5e009dd78a84ab006ee4ff0c',13188,13467,'课程其实脉络理清楚过后还是不枯燥的，但是这位老师讲的真的不知所云，念书念ppt，也不告诉你ppt和书上哪里对着（因为ppt的顺序和课本不一样） 上课讲着讲着感觉她自己也不知道讲哪儿去了，不解释原因，希望老师还多加修炼',2,1,3,6,0,0);
INSERT INTO "reviews" VALUES('5e0088802a6bfd007448f302',844,850,'课堂管得严格，较为尖酸刻薄，但是没有作业比较好，慎选',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('5e0055cdd4b56c0074ddf7f1',23,23,'美丽温柔、极具亲和力！刘老师的课堂气氛很好，跟着刘老师学习轻松得高分，宿舍同学在其他班，差别太大。C++首选刘霓老师！',5,5,5,15,51,0);
INSERT INTO "reviews" VALUES('5dff6dd91358aa006e15d02d',932,13470,'袁老师人超好阿，偷偷告诉数院的同学们，想修水一点点的课就千万别错过代林的限选课，三门限选修代林的两门，稍微认真学学保证90+，而且袁老师人也很好，授课能力也很不错，虽然是一口川普，但对于知识点的讲解都是很到位的！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5dff344843c257006cf88e58',2885,3822,'平时分还可以吧，我经常回答问题，平时成绩51/60，考口语的成绩中规中矩',4,4,5,13,1,1);
INSERT INTO "reviews" VALUES('5dff30fc8a84ab006ed8b607',703,228,'快跑，别选
INSERT INTO "reviews" VALUES('5dfeebec43c257006cf53d28',827,827,'讲课逻辑挺清晰的，看得出老师专业过硬，当然自己课下也得对这门课上心',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5dfe55f68a84ab006ed220c9',2458,23,'超级超级棒的一个老师!!!超爱她，讲解细致，非常赞；听她的课然后认真完成作业，就完全OK的了，我们班C++半期的平均分是同学院中最高的了，还高了好几分，超级喜欢她，选她，听我的，没错，她超棒',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5dfe5238d4b56c0074cdf4b1',247,27,'作业超级超级超级多...上课很水，自己基本不讲，都让学生自己弄PPT然后上台讲（所以思考一下你的作业量）根本不考虑学生能否做完....而且期末政策说变就变...说好的下周截止开始算平时分，结果这周没有任何通知突然截止了',2,4,1,7,1,0);
INSERT INTO "reviews" VALUES('5dfe4d4edd3c130072ad1185',237,5,'我也是每节课第一排，老师超级能水。。。基本不讲课，千万别选，或者不行没能换，那就往后排坐，自学吧，平时分给的也低；包括吹牛都只知道追忆大学...多半现在科研也没什么成果...反正除非你就是打算逃课，不然千万千万不要选他。。',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('5dfe206e7796d900687ecf0f',3669,3669,'啥都得搞，搞完啥也不会，花了时间也不会有什么收获，两周一尬讲，外加光立方，期末各种报告，心得，爽。',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5dfe20577796d900687ece58',1007,1007,'真的烂
INSERT INTO "reviews" VALUES('5dfdfb4edd3c130072a961c8',13479,13479,'把丑陋当作个性，把乱画当作独特，误导建筑学生的美术发展形式，与网上那些整日写丑书的所谓书法大师是一类人',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5dfdf81fd4b56c0074ca09b1',13479,3493,'教学水平差劲，打分严重不公平，教授内容也是完全与主流美术审美相距甚远',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5dfdf79b43c257006cedd414',13479,3493,'上课也不指导同学们怎么画，也不说他想要什么样的画，没有任何指导和教学。最后说"你们就随便画，我就看感觉给分。"全班同学兢兢业业认认真真，画了一个学期把所有画交上去。最后他看也不看，直接期末考的那张画随便给了一个分数，还喜欢给跟他熟的同学高分******',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5dfdf6e68a84ab006ece113d',13479,7794,'没有美术鉴赏能力，给学生评分全看主观，根本不管学生的专业水平与绘画水准',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5dfdf41343c257006cedaeea',85,597,'简直太好了，老师人也非常好，飞盘也好玩，期末分也高，太极也是全班过，稳！',5,5,5,15,1,0);
