INSERT INTO "reviews" VALUES('5dfd7c082a6bfd00742d609e',23,23,'刘老师的上课充满激情，风趣幽默，同学都超赞！课下对学生耐心答疑、充满爱心，一学期除了C++收获了高分，还学到很多做人的道理，最喜欢的大学老师！重推刘霓老师！',5,5,5,15,50,0);
INSERT INTO "reviews" VALUES('5dfcf98b2a6bfd00742b2c59',9882,22,'张老师是世界上最好的大物老师o(^o^)o，超级可爱，害，标签只能选三个',5,5,5,15,3,2);
