INSERT INTO "reviews" VALUES('5dfc5e5043c257006cdf783f',10624,101,'老师讲话吐字不清，一句话说到最后就没声了是可以不想让我们听到还是考验我们听力，而且作业还多，随堂测验自己出题，批地很严，水吧倒不能算水课，前提是你能听懂，不过一个班里一百多人大概不超过十个人能跟上，到最后他的课上前排空出好几个座位，后面反而坐满了，唉，这辈子都不想见到他了。',3,1,2,6,4,0);
