INSERT INTO "reviews" VALUES('5dfc5af61358aa006ef9dbbd',2323,92,'我东哥是正教授，上课治学严谨，课后和同学更能融入到一起，私聊问他问题总能给你一本正经的回答，不点名，给分高，作业都是学年统一安排的无其它作业西南交大最好的大物老师',5,5,5,15,1,0);
