INSERT INTO "reviews" VALUES('5dfc30357796d900686c8b91',2323,22,'东东长得帅，人又温柔，对同学们超好。听课的同学必须要保持全神贯注，紧跟节奏，因为稍不留神就听不懂了(我太菜 😭 )',5,5,5,15,1,0);
