INSERT INTO "reviews" VALUES('5dfb4d9843c257006cd70b7c',13510,13510,'老师确实挺和蔼的，但讲课怎么说呢。。。不知道是我太菜还是他讲的不行，反正听得不太懂，而且有几次还是别的老师来上课。关于点名，一次都没点过。。。再说测量实习，水的一批，不去都可以',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5dfb4cee2a6bfd00741c3c75',309,309,'和我刚发的材力评价一样，两个老师都差不多，但都是好老师，上课条理清晰，专业能力很强，认真听绝对能过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5dfb4c598a84ab006eb73287',75,75,'真的是一个很好的老师，也很有亲和力，平时成绩都是电脑上的作业。有时你作业忘做过期了老师还会帮你改一下',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5dfb4965d4b56c0074b30fdd',704,704,'老师非常高，讲课很风趣清晰，平时分给的很高，难得遇到的好老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dfb3b6e21b47e00757827ac',2012,1753,'可爱！',4,5,5,14,2,0);
INSERT INTO "reviews" VALUES('5dfb395f2a6bfd00741b68ce',485,40,'基础分吧，给分不错，但绝不能迟到；上课PPT不会给，最后论文要自己写那种。上课没有活力，单纯念PPT，在下面玩手机也不会为难你，只要该讨论的讨论，该参与的参与就行。小考试也挺水的，期末大考嘛，统一的别想了。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5dfb346443c257006cd5f909',1175,27,'真的超好 选她没错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5dfb31e6d4b56c0074b2063e',5808,2205,'选就对了！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5dfb2f2bdd3c130072910a8a',903,179,'康老师真的可以 建议大家抢他的课',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dfb2ed521b47e0075779281',2210,281,'老师表达不太行 人还是可以 就是有些时候讲课听不太懂 讲的表达不太好',2,1,5,8,0,1);
INSERT INTO "reviews" VALUES('5dfb2e53d4b56c0074b1da0d',3212,5,'平时分是会修改 可是讲课水平不高 讲的真的很******我劝大家还是不要选',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5dfb2abad4b56c0074b1aea7',257,4318,'除了可爱应该没剩什么了
INSERT INTO "reviews" VALUES('5dfb25648a84ab006eb57533',3212,5,'这老师真的不要选，我们当时高数BⅡ讲了3周高中知识，关键是考试不考，全是废话，讲的有些东西自己都讲不明白，磨损学习热情，这是唯一一个我学期课程评价1分的老师，还写了一大段话吐槽，最近竟然看到她被评为优秀党员工作者，我真的服了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5dfb22f343c257006cd5289e',4695,2812,'老师很有意思',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5dfb18da21b47e0075768bc0',11758,3017,'怎么说呢。这门课是口语课，如果你上课积极回答，跟老师混个脸熟平时分会很高，普遍在55左右(满分60)。但如果你默默无闻，不跟老师互动的话平时分会低。老师还是挺好说话的。不过平时作业，很麻烦....占分也很高',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('5dfb0c9e2a6bfd0074197244',823,1897,'李老师真的超级好啊！！课堂幽默有趣，经常讲段子而且特别有激情，三连讲真的不会睡着！上课知识点讲的特别清楚，而且还会每次课后在群里发本节课重点，认真负责，只要有问题不管多简单她也会特别耐心地讲。
INSERT INTO "reviews" VALUES('5dfae77c21b47e0075748ed4',13526,27,'为学生着想，上课幽默。认人很准，虽然不点名但是谁没来一眼就能看出来',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5dfacb2d7796d90068606515',12239,496,'老师人挺好的，专业能力我相信还是很好的，就是讲话不太清晰，光是要弄懂他在说什么都费劲，更别说听课了。而且讲什么都喜欢扯上铁路，emmmm，经常点到',5,3,5,13,1,0);
INSERT INTO "reviews" VALUES('5dfac63a43c257006cd14d3b',5449,5556,'身处课堂，不管听与不听，都有不一样的收获。认真倾听，从商周到秦土堆高楼，到唐宋木构，再到稀少的元庙，明清宫廷，在她富有艺术气息的诉说中感受古代建筑的奇绝与魅力，榫卯，藻井，阑额，歇山，庑殿，一年过后还能谈个大概；不听不来，没有签到，半期调研作业（成都古建筑），期末开卷考试，不听过九十，听了近满分。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dfab9ba1358aa006eeb64ad',2458,23,'挺好的一个老师，很温柔，讲解比较细致',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5dfa54c77796d900685e926c',9882,13530,'这老师。。专业能力是有的，教的也还可。不过，有点坑。上课喜欢吹自己，然后平时作业都打分，期末作业的成绩按打分来给。。。然后也没个群反馈啥的，给我漏登了两次平时作业，发邮件问他，他还不理我了。呜呜呜，尽量别选吧。',4,3,2,9,1,0);
INSERT INTO "reviews" VALUES('5dfa4b7e1358aa006ee9d1e1',819,228,'罗敏老师上课挺有感染力的，语气铿锵，讲课内容高于课本，很好的开拓了视野。平时会推给我们一些好的文章(可以看出她对马原的学习研究之多)。点名很少，比较爱抽问题，一般大家都很积极(坐在一群大佬中间)，每次都很多人举手回答，听回答问题也很开拓思维的，会发现，诶，这个事原来还可以这么看。总之还不错啦，多回答问题还可能免考的。',4,4,5,13,3,1);
INSERT INTO "reviews" VALUES('5dfa434a21b47e007570e7e0',3212,5,'真的是毁掉对这门学科的热爱',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5dfa37d08a84ab006eaeb6bb',2202,28,'最爱的英语老师',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5dfa3608dd3c13007289c5ab',3286,3286,'我客观的讲，这位老师在我见过诸多的英语老师里水平真的很差，而且每节课留2个作业，期末还要占额外时间考试，网上X事还很多，这门课我们小组大部分时间都到了而且花了很多时间完成作业，期末给我们组每人60出头的分。',1,2,2,5,4,0);
INSERT INTO "reviews" VALUES('5dfa2f3e1358aa006ee88e4d',3212,5,'真的倒霉 贼难上这个老师的课',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5dfa2e591358aa006ee8832e',2012,1753,'太好了，这个老师太可爱了',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5dfa2d067796d900685cee6b',24,24,'作为全校挂科率数一数二的课程，理论力学令许多人头疼不已。许多学长学姐毕业工作后也会选择回来参加返校考只为取得毕业证。
INSERT INTO "reviews" VALUES('5dfa2c8e43c257006ccdf6ef',756,22,'我要给杨老师打call！！！讲课特别清楚，知道怎么点拨学生，听了真的有拨开云雾见月明的感觉。平时QQ上问问题也很认真的回复。开始的时候是不点名的，后来因为早课翘课的人太多了开始每节课点名😂 (老师也很无奈啊哈哈哈)。给分怎样还不知道，不过老师人很好的，可以学到很多东西。选他！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5dfa269d7796d900685c991a',228,228,'上课死板，自我为尊，讲的还没高中政治老师讲的好。给分迷惑，两极分化严重，大部分人六七十，只有少部分免考的95+。',1,1,1,3,7,3);
INSERT INTO "reviews" VALUES('5dfa24cc8a84ab006eadc27a',3707,741,'这门课一定要选左大杰老师的，尤其是考研的同学，只要你凭借考研的报名材料就可以不去上课，但是其他老师就不行，甚至还要点名，所以一定要选左大杰',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dfa24677796d900685c79e4',5808,2205,'骆老师人超级好，事情少给分高，很照顾学生的感受，凡事骆老师的课一定要选骆老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5dfa23cb21b47e00756f5e84',8738,13542,'事情多，考试难，不建议选，陶思宇的更可怕还要闭卷考试，但是限选课就那些也很难抉择',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('5dfa1f9d21b47e00756f26be',202,82,'声音实在太小了',3,1,2,6,3,0);
INSERT INTO "reviews" VALUES('5dfa0e908a84ab006eac9429',11891,92,'每每上课，云里雾里，一到下课，面面相窥。内心:我太南了。罗林老师给分高是真的，念PPT也是专业的。',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('5dfa0c508a84ab006eac7a06',7459,36,'徐义文老师最大的槽点就是他的普通话了趴，上了那么多节课，还真没几次听懂他在讲啥，都是熟悉的汉字咋念出来就这么不对劲呢？🤔 
INSERT INTO "reviews" VALUES('5dfa0b858a84ab006eac70b9',775,24,'呵呵，是个新老师，选到陈浩的我只能呵呵了，上课声音极小，每节课都留很多纸质作业，作业分是多少就给你打多少，期末不捞人，59分就59分。',1,1,1,3,4,2);
