INSERT INTO "reviews" VALUES('5dea25be21460d0068ad1a63',13558,143,'简直是个烟王，感觉他好像讲的也挺认真的，拖堂也毫不含糊，二十分钟轻轻松松，但是就是让人不想听他讲课。感觉的确是个巨坑。',3,3,1,7,1,0);
