INSERT INTO "reviews" VALUES('5dce63fe844bb400750ccab0',819,228,'从人文的角度看老师讲的的确很丰富
INSERT INTO "reviews" VALUES('5dcb8b8b43c257006a7c307e',1168,228,'虽然讲课时讲了很多我听不懂的哲学思想，但对学生真心好，换着法子让你学东西。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5dcb8a6543c257006a7c24e1',442,4101,'每次上他的课既犯困又不得不心惊胆战，懂的人都知道我在说啥',3,1,1,5,3,0);
