INSERT INTO "reviews" VALUES('5dc7e049fc36ed0071051a44',18,18,'挺幽默的一位老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dc7d2367d577441a57a24d0',1291,22,'别惹他，别翘课，啥都好说',3,3,3,9,3,2);
INSERT INTO "reviews" VALUES('5dc7d10ed4b56c00747c1201',18,18,'真的很好的一个老师，课上得好，有激情',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5dc7bbc1d4b56c00747b1dd2',42,43,'这么说吧，我第一次被他验收结果的时候，我差点儿被气死，真的，什么都不说，还想让你什么都按照他的意思做，每一次去上他的课，都心惊胆战，真的别报！如果你想活的久点儿，就走远点儿。还有说他只是严格的，对不起我觉得严格和******好像是两回事。',2,1,1,4,10,0);
INSERT INTO "reviews" VALUES('5dc7a981d4b56c00747a481f',9807,13185,'老师真的超级nice，期末考试完我打电话问题还会给我从头到尾捋一遍卷子上的每一道题。希望老师早日康复眼睛快点好起来！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5dc7a5e743c257006a58eb51',18,18,'老师人特别好！！上课很好玩',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dc7a5d3844bb40075d271b4',18,18,'讲课无尿点，干货满满，听课体验极佳',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5dc78729fc36ed007101005c',18,18,'阿明的课超有意思，老师也超级好，还会在微信群里面答疑，还和我们调侃，哈哈哈哈哈，讲课也超级棒 选阿明准没错😁 😁 😁',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5dc77cacfc36ed007100779a',18,18,'老师好可爱的，说话又好听，我超喜欢这里的',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5dc7703b7d577441a5758e52',18,18,'赵春明老师真的是我在交大见过最认真最有耐心最幽默最暖心的老师，非常推荐选赵老师的概率论课程',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5dc763b17d577441a57500af',18,18,'我来交大以来遇到的最聊得来的老师，课堂上讲课就像和朋友聊天一样，把重要的步骤、重点提炼出来，如果你是大佬，可以在课上或者课下解答问题加平时分，如果你对自己不自信，还可以擦黑板加平时分，老师还会经常在微信群给我们做解答，还有习题课，最重要的是课上还有好多漂亮的小姐姐，选上就可以快乐幸福的上课，听我的，选赵老师的课没错，因为老师课上的漂亮妹子真的多',5,5,5,15,45,0);
INSERT INTO "reviews" VALUES('5dc6e0aa7d57740075782dd3',614,4948,'很能熬夜的老师，比我们睡得都晚Onz
INSERT INTO "reviews" VALUES('5dc6e08b21b47e00692459dd',18,18,'老师讲课比较风趣，而且跟同学们很处得来',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5dc6dc392a6bfd00725705fa',480,92,'老师人非常好，平时不点名，作业交够次数平时分就给满。很多人不来上课，但其实认真听讲会发现讲的很好。非常优秀的老师',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5dc535f32a6bfd0072460065',2078,23,'这是我目前以来挂的唯一一科，老师很是不通情达理，讨厌她，要学设计基础的千万要选别的老师啊！！！(○｀ε´○)给分一点也不宽松，是我见过最死板的老师！',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('5dc0cb80f884af0073587138',13582,78,'讲得确实不错，不过点名巨多，作业少：考研党作一般考虑。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('5da049bbc05a800073d702f3',13583,13583,'千万不要选，课设自己做的最后比抄的低十几分，研究生乱改，去找承认改错就是不给加分',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5d9f4a610237d70074e1aad4',3437,6251,'作业多，给分一般，出题特别难，能不能活下来，看运气',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5d91abcf17b54d006ce037c7',5558,4552,'每节课必抽问 讲话一卡一卡的 念ppt方法也不讲清楚 就让大家做题 ppt上的东西书上也都没有',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('5d9176cbc8959c00686171e3',2287,2287,'水过去的课。老师和蔼，作业不多，点名少，课设比较宽松，给分算是高的，不过期末不给重点，好在基础工程考题不会太难，还算靠谱，做一般性推荐，考研党可选。',4,3,4,11,3,0);
INSERT INTO "reviews" VALUES('5d91707243e78c0067fa712f',13400,336,'我打的是好评，因为老师除了不顾及考研人的想法以外，真的几乎没有什么雷点。不过就像我所说，我并不想给他好评，考研党我都不想说慎选了，直接别来选他：他是那种知道你要考研，知道你来不及了还要要求你同样严格的人（节节课签到，大小课设两个，随堂限时测验，严格按照评分组成的比例评分，作业互评，不划重点，后面肯定会变着花样搞创新。。。），所以说。。。表面上的和蔼，实际上的冷酷，差一点点就能够比上易大师了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d916a14eaa375006c9da739',4084,4577,'易大师，不用再多说。分组，每周ppt上去汇报，绝对不水，绝对折腾，挨个检查，不合格的设计不准交。喜欢选线设计的，来吧，易大师只会更严，不会更宽松。我好心提醒一下决定考研或者是想找个好工作的学弟学妹们，易思蓉、杨荣山、赵坪瑞，这三者的课千千万万不要选，选了你就二战准备吧。',5,1,1,7,2,0);
INSERT INTO "reviews" VALUES('5d90237217b54d006875865c',13589,641,'韩奶奶超温柔又有耐心，平时分除了半期考试是固定的，其他给满。而且从不点名，作业随便抄，水得不能再水',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5d88701f30863b0069ab5fca',13590,40,'给分低，低的不能再低。上课就想睡觉。抠鼻',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5d886fb042cda6006853507b',13590,3822,'******给分奇低，作业奇多，一颗星都嫌多',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5d7f4a19c8959c00685300e5',257,4318,'独秀，感觉他有知识就讲不出来，讲给自己听的，完全不管学生听得懂不',3,1,2,6,8,0);
INSERT INTO "reviews" VALUES('5d75d05ba673f50070668b75',24,24,'很认真负责的老师，我期末试卷成绩算错了还专门发消息告诉我，QQ问问题也很快就能得到解答。
INSERT INTO "reviews" VALUES('5d735c0512215f0072d7cb66',3577,2642,'好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d6fbe5012215f0072bfb592',1291,22,'******一说重点声音瞬间缩小到除前三排之外听不见，屁话贼多贼大声',1,1,1,3,3,0);
INSERT INTO "reviews" VALUES('5d6f098f30863b0068eedece',1158,5,'老师很负责，讲的特别认真，一节课能来回擦好多次黑板，期末给分也特别高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d6e51e712215f007327854b',416,34,'老师超级幽默，刚一开始就很强调编程思想，讲得很生动。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d6e50f00237d70068258e75',1596,52,'讲课管你听不听得懂，老师会继续下去。
INSERT INTO "reviews" VALUES('5d6e4f5a0237d70068258092',1158,5,'绝对是好老师，平时分给得特高，讲课非常有条理',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d6e4e9beaa37500682de238',6705,1753,'老师很幽默，与同学关系很好，期末会通过平时成绩捞人，很不错的老师',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('5d6e162e0237d70068238f76',948,92,'老师讲的很耐心仔细啊，重点难点会强调几遍，作业是可以缓交的，只要是自己做的，交齐了就不会扣分，很喜欢何老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d6dbb6043e78c0068e891dc',22,92,'期末靠自己，期中靠自己，讲的好，平时分给满',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5d6c8db1a3180b0068fdb295',1773,1773,'上建筑结构的感觉像回家一样，在课堂里面的感觉，比家里面感觉好多了，在家里面一个人很无聊，都没有朋友，韩君伟老师长得又帅，说话又好听，讲课又负责，超喜欢他的课的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d6bcefb0237d70068146a94',237,5,'我每节课都坐第一排，但老师平时分还是给很低
INSERT INTO "reviews" VALUES('5d6888c60237d70068f71109',237,237,'选了他就可以自学了，只要写完作业，自己学懂，期末就能满分',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5d68884ac05a800073211b44',480,92,'如前所述',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5d65ffed0237d70068e21612',876,92,'挺好的虽然相比其他老师平时分可能低点，按规定给，但是人很可爱。点名方面看你平时作业情况了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d65cdba43e78c0068a7f05f',867,28,'5分好评，老师很温柔，平时成绩给分也很高😁',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('5d65387bba39c8006763b438',13609,619,'讲课比较无聊，给分高，没有老刘那么多过场，但是一般听课的就么得什么激情，不想交流，点名较少，给分不错，十分推荐。',5,3,4,12,1,0);
INSERT INTO "reviews" VALUES('5d65380e12215f0073dee666',3399,3399,'上这个课应该都是坐满的，计科软件其他专业的都有，上课讲很多国外啊，行业前沿啊，还是非常有意思的。每一个设计都是正儿八经能让大家使用起语言这门工具的，学到很多东西。期末考试难度也不是很大，多看看PPT，90以上没有问题。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5d65374eba39c8006763a434',7728,13611,'老赵吹逼蛮厉害的，软件专业就这么课比较贴近时代前沿SSH框架至少有所涉及。每次点名签到可以代签。三个设计，还是有难度，没有花时间做不出来，但是做出来了还是有所理解。期末基本原题，寝室的期末成绩都是98,100。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d653686eaa3750068e56e63',2259,1129,'太军哥图形学的实验课还是很轻松的，程序每年都会变一点，但是基本都能用，最后期末的做不完也无所谓，每年的题都差不多，画画自己的名字学号啊，一个球按计时器弹跳啊。我们推测以报告的页数给分……给分还是挺高的。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5d6535e10237d70068dccef5',12424,12424,'还是老楼的课。期末有一个设计，要自己做测试，其实都是瞎编的，不会真正去做。期末的题只能说还好，但是有很多题他不知道他哪儿找的，打印店没有资料，所以复习东西会很多。划重点=没划，期中考试没几个及格，期末也如实给分，不会给同情分。',4,2,2,8,0,0);
INSERT INTO "reviews" VALUES('5d65355043e78c0068a4e823',12424,1129,'这门课巨坑！如果能选太军的，一定不要选老楼。讲课内容倒是很丰富。期中考试，一个班9个人及格？？？最后如实登记？？？最后划重点就是照着书念一遍？？？最后考到了20%左右？？？期末考试题完全不知所云？？？型值点？样条？鼠标的概念？取景造型的元素？？？考的概念偏的一批，也不给原题，打印店的东西完全没用，大题也有好多不知所云。体验极差。',4,2,2,8,0,0);
INSERT INTO "reviews" VALUES('5d65344d0237d70068dcbc7e',2259,4946,'太军哥讲课很平淡，所以上课的时候可能有点无聊，点名每次扣分公式，第n次被点没到，扣n*2^(n-1)分，自己看着办，一学期4，5次名，作业也差不多这么多。实验课就很麻烦了，需要写很多文档，如果做的认真的话，界面也要写很多，但是感觉最后不是很重要……应该是按页数给分。人机交互考试全部都是PPT上的内容！书等于废纸！半开卷！虽然最后大题全都写错了，但是太军哥看你写的态度给分，所以人还是很不错的。',4,4,4,12,3,0);
INSERT INTO "reviews" VALUES('5d653324a3180b0068c1f949',6935,496,'老师人不错，也不点名，平常上课就交一下作业就算到了，期中不考试，期末的时候发一张上一年的卷子，自己回去做，就算是期末考试成绩了，会给题库，但是不考，最后试题就是去打印店买就是了，99%相似度，背一背就能得高分',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5d639b2312215f0073d07d6d',2210,3723,'普通fa很标准',5,2,3,10,2,0);
