INSERT INTO "reviews" VALUES('5d2aa357c8959c0068bc65e6',1612,619,'好老师，知识渊博。平时都要去上课，很轻松，不讲课本直接放视频然后再讲课，会点名，期末好好背，他不画重点，你可以找其他同学要。我毛概Ⅱ90分，我天，惊喜。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d2aa1dba91c9300691c96ae',1291,92,'我是补修的大物A1，往届学生。曾老师直接说往届学生可以不来上课，太好了，作业必须按时交。曾老师讲课我听不懂是真的，口音重，感觉曾老师一直沉浸在自己的世界里，板书不容易看清。平时作业好好做按时交了分也不低，半期和期末考多少分给多少分，给分正常，给分正常，给分正常（重要的事情说三遍）。
INSERT INTO "reviews" VALUES('5d2aa0497b968a00734ff3b5',2200,177,'老师讲的真的好，平时一定要去听课，她是出题老师，平时贯穿很多期末考点，给分很严格，高分同学考多少给多少，其他不晓得。',5,5,5,15,1,1);
