INSERT INTO "reviews" VALUES('5d1f8c0a43e78c1fd036fd79',2323,92,'谢东老师对待同学们真的挺好的，期末给分也良心。但是！！！上课真的很难听得懂啊…而且作业和上课进度没有做到衔接紧密，直接导致学了后面的忘了前面的这种情况出现。',5,2,4,11,6,1);
