INSERT INTO "reviews" VALUES('5d1f7575c05a800073bde29f',6994,10120,'真的能学到东西吧，给分的话，要看助教了。我倒是觉得平时助教给分比较高了，导致没啥差距',5,3,4,12,0,3);
INSERT INTO "reviews" VALUES('5d1f6c26d5de2b007220f260',6994,1651,'盛传是土木四大名挂之一，同学对他的口碑不好主要是他对工图的要求很高，犯了基础错误就会被扣分扣的很惨。但其实老师上课还是很认真负责的，语速偏快，重点也会强调，上课内容很充实，不喜欢他的人大概是觉得他不好水（毕竟真有些老师上课水给分高我无话可说）我还是挺喜欢广俊哥哥的，真的能学到很多东西，用心学好好画还是有收获的。',5,3,1,9,10,0);
