INSERT INTO "reviews" VALUES('5d1d6d0e30863b007016c362',23,23,'绝对好老师，上课超有激情，认真负责，真的是教书育人，蹭课一学期收获很大，是公认的最好C++老师，值得拥有！',5,5,5,15,50,0);
