INSERT INTO "reviews" VALUES('5d1b834630863b007004a45a',2012,1753,'讲课超级爱举例子，形象生动，节奏较慢，注重基础。唯一不足老师太好了，作业很少（我觉得），点名这学期就一次。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d1b6eefa673f5006992f4f2',2012,1753,'只点过一次名，老师平时分给超高，人也超级好，其实个人觉得作业也不多，只要自己课后稍微认真一点，考试就能考好的。其实符伟老师也是人间天使呀👼👼👼！大家一定要好好学高数！！！',5,5,5,15,1,1);
