INSERT INTO "reviews" VALUES('5d183a4da673f500696d5bcb',1753,2735,'太爱他了，讲完会提前下课，注重思维引导，但不喜欢迟到，会叫你小朋友哦---BEST.DING',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5d182e53a673f500696ca8f0',785,114,'真的很棒了，教的好，负责任。考得烂还安慰你。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d18200e30863b0070dc9f4f',31,31,'非常喜欢他，讲课讲的非常好，引人入胜',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d18149cc8959c007031a327',491,1529,'超级负责的一个老师，讲课和复习ppt都发的很及时也很详细，上课也比较也热情',5,4,5,14,7,0);
INSERT INTO "reviews" VALUES('5d180561d5de2b0072ce9805',4112,114,'老师虽然有口音，但是专业能力很强，平时几乎从不点名，期末平时分能给的都是满分，',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5d18048312215f4e7fe4ed4f',876,685,'每次上课都要点名，缺勤多了期末平时分考勤直接0分，期末给分也很低，只能靠自己有没有兴趣了，期末还有8个小论文（手写）',4,3,2,9,1,0);
INSERT INTO "reviews" VALUES('5d17a09ec05a80007369592f',2241,2241,'自行要求不开卷 不通融',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('5d16c60043e78c007593c846',9120,22,'水群挺厉害的，会经常让你测试他的新插件，喜欢足球，点名方式不同寻常',3,3,3,9,0,4);
INSERT INTO "reviews" VALUES('5d16bf07c05a8000735bfbc8',12963,138,'大学以来见过最和蔼可亲的老师 唐老师非常关心呵护学生 课上严师 课下益友 犹如春风化雨般感化学生的内心 讲课一丝不苟 有什么不懂她也会不厌其烦的一遍又一遍的给你讲解 是不可多得的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d16b61f30863b0070cb8ef1',24,24,'真的是特别好的老师，就是课太难。在群里只要问他绝对耐心回答，讲课贼负责细心，如果学不会应该就是自己的问题了。每节课有小测验，但是事实上期末平时分都给很高',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5d16b47da673f500695a97a7',3286,12266,'老师是位认真负责的好老师 而且给分也不低 想要水的同学就别来了 作业量多 喜欢学术化的东西',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('5d16a5e643e78c0075925429',1453,26,'给分挺水的，上课幽默但表达能力一般不太听得懂，讲的超级快，基本上课自学',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('5d1677b3a91c9300749d8d0e',13700,185,'很喜欢老师，上课很亲和，对学生特别好，喜欢开玩笑，可以把一个知识点重复很多遍，解释很多遍，直到听明白。上朱老师的课，感觉和老师没有距离感。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d167627d5de2b0072bd605e',2701,2701,'期末交一篇课程心得，中间需要上台表演一次，很简单，一个小组的同学表演给的节目，大多数是合唱之类的。助教点名，经常点。上课都在做自己的事，大多数时间老师都在放不同的音乐。上课特别水。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5d1661af30863b0070c9e2c7',9390,13242,'老师很负责，手把手教学，课堂状态非常放松。能学到很多审美方面的东西。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d165e57d5de2b0072bd0f79',8080,8080,'老师上课很有意思，会拉群讨论时事之类的，平时上课不点名，😂但是老师会拍照，期末考试就一个论述题，强推',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d165b8fa673f5006958dc0c',10805,10805,'珍爱生命，远离太极。如果想要上课扎马步，劈叉，压腿，太极你值得拥有→_→。老师期末给分飘移，但优点是太极可速成●━●',5,3,2,10,0,0);
INSERT INTO "reviews" VALUES('5d165536d5de2b0072bcde20',13705,5924,'老师知道得很多，有什么问题私下去找他乐意为你解答。很有原则。平时上课可以不去，但讨论课不去的话抽五个人点名，运气不好就没分了。平常可以成立小组交流，老师报销饭钱或者奶茶费。期末的读后感三千字抄袭一句话零分，直接挂掉。还是挺轻松的。但是他说千万别选他，他不想上了哈哈哈',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5d165253d5de2b0072bcce6e',6106,2230,'文哥超棒一老师！特别努力地给我们加分，期末提成绩还给刷分机会，课堂也很轻松，老师超级随和，就是作业有点多',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d165144c8959c00701f12aa',214,36,'非常好的老师。上课没有按照教材照本宣科，而是请同学自愿来谈自己对教材中观点的感受，然后老师做适当的点评和指引。上何老师的课纠正了我一直以来的悲观情绪，开始理性的审视自己的人生',5,5,5,15,2,5);
INSERT INTO "reviews" VALUES('5d164f46c05a80007359813b',12658,34,'水平还是有一些的，但是讲的跟水，虽然都是自己的理解，但是讲的东西太少，课上学的少，而且经常态度非常恶劣，另外，每节课必点名',4,2,1,7,1,0);
INSERT INTO "reviews" VALUES('5d164c37c05a800073596dc5',13709,36,'有点严肃，不允许玩手机，给分一般，不是很高',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('5d164aae43e78c007590c393',2012,1753,'不点名，不用PPT，讲解细致耐心，平时分给分高，强推',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d164a5dc05a800073596145',2424,2178,'赵志明老师非常地和善，不仅给我们讲述知识，还给我们拓展了一些关于地质的但是又在课本之外的内容。老师人特别亲和，是一位很好的老师!',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5d164a0f30863b0070c95ce7',10552,13712,'如果真心想从现代设计史里学习点东西，推荐选陈宇虹老师的课。上这门课要做好与高分执手相看泪眼，与及格分你侬我侬的心理准备。你学习的内容不会是王受之《现代设计史》里一堆陈谷子烂芝麻的玩意儿，而是问题的思考方式，并以此套用在各个问题上进行知识与知识的连接打通。这门课程一般两周一次小论文，如果将来有意向读研，小论文可以为你的研究生生涯打下一定基础。课堂上的点名由一堆稀奇古怪的问题代替，例如为什么牛奶是纸盒装而可乐是塑料瓶装，西方人为什么那么喜欢制造椅子。这门课上老师并不想跟学生玩平等的游戏，准备好本子跟笔，老老实实听课记下来就行，老师不想回答你问题的原因只有一个，你的问题太傻逼了',5,5,3,13,2,0);
INSERT INTO "reviews" VALUES('5d1648e843e78c007590b626',416,34,'非常优秀的老师，遇到这么一位C++老师非常幸运',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d16471843e78c007590a6d0',11887,11887,'希望把通识课水过去的一定要选这门课！水中之水！诚意推荐！给分贼高！你的不二选择！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d16464ea91c9300749ca392',491,23,'刘老师真的超级好  非优选班过去的 记住了班里很多同学的名字 会发现你最近学习的状态怎么样 时常敲打着  作业可能会比别的课多了章节的课后练习  复习资料总结的超好 课间可以点歌 总在群里回答我们问题 关心大家 讲的也超好 课前还会帮你回顾上节课知识点 总之超级好 选就完事了',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5d16464ca91c9300749ca387',788,790,'很好，老师讲课很生动，专业性很强，作业量正常，很可爱。。。。给分也不低哦',5,5,5,15,2,32);
INSERT INTO "reviews" VALUES('5d164603c8959c00701ec1b3',416,34,'一上来就强调思维的老师那必须好啊，能把c++将成这样的老师应该不多见吧，光是听课都能感受到老师水平不低。非常喜欢这位老师的课，作业也不多，讲的都能懂，不懂还能问，老师很有耐心的',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5d1645bed5de2b0072bc75c0',7890,7890,'分给的很低，教学太严谨了一点',5,5,1,11,1,1);
INSERT INTO "reviews" VALUES('5d1645aca91c9300749c9dd5',7890,7890,'分是真的低 特别低 以至于别的班平时分能比我们高十分',5,2,2,9,3,0);
