INSERT INTO "reviews" VALUES('5d16434830863b0070c923bd',12946,1529,'这就是个****** 别去 真的',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5d16433ca673f500695837db',2541,92,'这个老师，只会念ppt，板书也不咋做，说话表述不清楚，真的不明白他在讲啥。优点就是还比较有亲和力，期中考之前也不布置作业，挺有人情味的哈。就是基础不好的同学和他学习，可能会学不好哈',1,1,4,6,0,2);
