INSERT INTO "reviews" VALUES('5d16382d43e78c00758fff84',1685,1685,'我也是男同学，感觉老师很漂亮，讲解的也很到位，老师带着我们做动作，对了，都是女老师，老师是大四的哟，非常好，老师很和蔼可亲哟，经过一学期下来，肌肉增长了很多，这是实话，燃脂非常好的选择，可以减肥。',3,3,3,9,1,0);
