INSERT INTO "reviews" VALUES('5d1611cdd5de2b0072b97c09',2323,92,'讲课非常清晰，举例也很多。教学节奏掌握的非常到位。而且平时分基本给满。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5d1610f712215f4e7fcfa42d',1048,2735,'讲的很清楚，前因后果都能列出来。并且相比于其他老师，平时分基本给满。而且也很幽默。欢迎大家选他。而且从不点名。',5,5,5,15,0,0);
