INSERT INTO "reviews" VALUES('5d160d04c05a80007355ea93',887,23,'很负责任的老师，讲的也很好，很清晰，不会有听不明白的地方，老师看着挺严肃的其实特别温柔，问题什么的也会耐心解答，总之选她没错啦',5,5,5,15,5,1);
