INSERT INTO "reviews" VALUES('5d11a57a7b968a00759858f2',2012,1753,'老师非常认真负责，讲课细致，讲的很清楚很好懂，不用PPT，上课全部都是手写板书。作业适中，一学期就点过一次名。我平时每节课都去，平时成绩给满了！老师人特别特别好！推荐大家都去选符伟老师的课！！',5,5,5,15,14,1);
