INSERT INTO "reviews" VALUES('5d078dd112215f0071839f5b',1453,5,'转专业，跟着他的重修班上过课。上课极度喜欢吹牛唠嗑，讲题讲到一半开吹，吹到一半回去讲题。上课非常轻松友好，平时分给的很水，但是适合有一定基础的听课，基础薄弱的不推荐上他的课，因为表达能力一般。',3,3,5,11,3,0);
