INSERT INTO "reviews" VALUES('5ce4b7507b968a0073161b86',8138,716,'上课水的一批，作业要求还特别高，所有内容只是把课本的复述一次，有的只是放个视频就没了？视频是他的好哥们，经常帮他讲课，长对正高平齐。',3,2,1,6,1,0);
