INSERT INTO "reviews" VALUES('5c7bc937ac502e0066899f42',411,411,'讲真这个老师说的话我没有几句能听懂 _§:з)))」∠)_ 他还让我们打印那个课件 一百多页! ! 经常要用手机签到 期中期末都要考试（开卷、可用手机）完了期末还要交一个三千字的论文!!这都没完，最后成绩出来我才七十几分!!（期中期末考试都是在课件上找到的原话，这个成绩真的没想到） 心塞ಥ_ಥ',3,1,1,5,1,1);
INSERT INTO "reviews" VALUES('5c7bc6cf12215f007256084f',13795,13795,'每个老师上课都很认真 也很愿意和学生互动 不过要是你想水的话 这门课也可以很水 隔几周才上一次课 网上作业很容易得满分 没有期中考试没有期末考试 期末交一个八百字的论文就完事了 分数90+',5,5,5,15,0,0);
