INSERT INTO "reviews" VALUES('5c4483a3808ca407287b135e',344,601,'认识课上每一个人，逃课是不可能逃课的。喜欢吓我们，结果考试极其简单，人人90+。',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5c44834044d904006a8e8d66',5937,24,'正常水平吧，理力上课都是这样。作业不多，做不做跟平时成绩没有关系，或者说根本没有平时分，全靠期末一锤定音，但好像理力班都是这样。',5,3,3,11,2,1);
INSERT INTO "reviews" VALUES('5c4482a2303f39558b16f26b',8383,441,'上课方式挺奇怪，作业如果真去认真做，比材料专业还难，每节课都要挨个回答问题点到，给分挺高。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('5c446ade9f545400707a0e03',442,442,'千万别选他的课！根本不像来上课的，讲也讲不清楚，听都听不懂。还问我们有什么问题，同学问个问题讲半个小时，还没解决。自学都不行，贼喜欢点名！千万不能玩手机，也不能抄作业，有同学平时成绩低的可怕。这个老师不讲人情的。找他没用的。',1,1,1,3,3,0);
