INSERT INTO "reviews" VALUES('5c3bdfc80b6160007064494a',10294,228,'给个好评平一下反。。。真的很有意思，虽然不像下面那个刷完马原的学霸那样，但最起码打开了我对社会科学的认知，很有意思。近来挂科率已经不算高了，跟着走，节节课听讲做笔记（随堂测验都是自己上课讲过的题）平时分基本不会低。。。其实专业课我觉得反而不是最重要的东西，你到大学真正学到了什么，是你自己决定的。',5,5,4,14,1,1);
INSERT INTO "reviews" VALUES('5c3bddea44d904005d696f2e',12946,1529,'听不进去当年。。。感觉像催眠，擦边球过，其实已经不像以前那么严了，总的来说只要别经常逃课平时分就还好',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('5c3bdc6a0b616000706414c4',11452,370,'不好做评价。。。上过的无数个水过去的主干课中的一个，讲得还不错吧，前几节课还算是听进去了，就是会把茅班的ppt和作业给我们？不知是出于什么考量，用英语ppt讲课。作业量较多，有一般量的考勤，仅作普通推荐，如果能遇见更好的老师尽量就别选这儿了。',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('5c39742844d904005d42b8eb',1773,1773,'无话可说',1,1,1,3,0,4);
INSERT INTO "reviews" VALUES('5c39681e9f5454007008385e',8453,5,'专业能力nb至极，会相当注重公式推导以及各种概念，不是很讲例题，不点名，作业在期末前全部交齐就可以得到相应分数可以说是相当松了。想水可以上他的课，但是考试本身挺难的，建议各位好好听丫，当年我考的时候好多同学都挂了。。。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('5c39645c44d904005d417cc5',852,760,'专业性不质疑，点名较少，给分还好，但是他讲课我10分钟就能睡着，声音太小没有起伏好催眠，最后基本是跟着幕课走的，没怎么听过他讲课。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('5c39638d44d904005d416b4e',755,75,'全幕课配置，等于没有点名，只要按时上网上系统看视频交作业，平时分是多少就是多少，还不用去上课简直美滋滋，其次是人贼好，网上问问题基本很快就能回复。幕课质量大家有目共睹，这个无需细说你看一遍就知道。期末跟着过一遍一般来说80＋没问题',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c39623afb4ffe005f2af305',9693,32,'会加课，亲和力满分，讲得不错，简明扼要。查考勤也比较水，可能就两三次，给分比较松，作业交满就可以得到还不错的平时成绩，给的复习提纲也相当明确，很适合于临时抱佛脚hhhh（虽然我并没有），做一般性推荐',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('5c3960be0b616000703bd094',10973,4003,'名师不解释了，b2还不考结构动力学，听他讲课不用翻书很容易懂，跟着他走加上平时自己做作业，考试80+没有问题，有一定次数的签到但不严重',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c395fc144d904005d411b2c',7369,73,'你要是真的很想学好钢结构找他没跑了，讲得深而且还在课堂上勾重点，喜欢扯一切和结构有关的东西，是真的对结构怀有极大热忱的人。就是无法水课，比较严，作业是单独布置自己的题，每堂课都会签到，而且一定会加课，所以想水课的童鞋尽量避开。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5c36936944d904005d13680d',13845,1753,'老师真的上课讲得十分👎
INSERT INTO "reviews" VALUES('5c366f7244d904005d120bc6',442,573,'从来没有对一个老师评价这么差过！！
INSERT INTO "reviews" VALUES('5c361b9644d904005d0f4d02',760,142,'讲课比较慢很基础，听不下去，最后靠靠龚主播的慕课学的，不过给分什么都挺好的',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('5c3619b80b6160007009b637',326,36,'老师挺好的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c36192c8d6d8100670dd94a',1058,5,'讲的有点快，但是老师比较和蔼，会态度很好的为同学解答问题',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5c36190644d904005d0f15dc',9443,1170,'什么神仙老师！吹爆，上课从不担心挂科，期中我们班平均分80+！！人特别好，上课只要接受他的上课方式，工化85+没有任何问题。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5c3617fa0b61600070099851',3025,2259,'作业太多，讲课太快，但是考试占平时分不算高，不准请假',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('5c36154644d904005d0ed290',8480,8480,'作业三到四次也不算多，关键是必须0抄袭，只要你有一句话是网上抄的就让你挂科，对于喜欢写作的同学来说还行吧，水我倒是没发现水，反正几千字的作业我抄了一两百字，挂了。',4,4,2,10,2,0);
INSERT INTO "reviews" VALUES('5c3606249f54540070d40d69',232,24,'老师人真的超级超级超级好！！！认真负责，和蔼，平时分也给得高！！！',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('5c358ac2fb4ffe005fecdc25',913,611,'温柔，安逸，分高',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5c355a0c44d904005dff7232',573,573,'通过降低学生平时分的方式来显示自己的严格，我也是醉了，加上平时分倒扣分，对这种报复社会的老师无语。',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('5c347f390b61600070ed9ff9',2699,13856,'对初学者来说有点难，建议真正想学的同学选，不然你会很痛苦的。',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('5c33082944d904005d379297',42,43,'司马老师，不多解释。',1,1,1,3,7,1);
INSERT INTO "reviews" VALUES('5c3308149f5454007215fee4',12218,762,'只要是跟着老师一起学肯定没问题。上课的例题都是往年半期或者期末题，点名会提前通知，测验也是讲例题，最后抽人上交，反正老师真的挺好！不过写板书真的快，毕竟人家不用ppt',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c3307e5fb4ffe1186ba91a0',141,765,'超级负责的老师，讲的很清楚，和大物有关的事情都会通知同学们',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('5c3306970b61600067b12168',5894,5894,'这老师纯属XX，讲了半学期没作业，期末作业一大堆，自己晚发了作业，还说不如不交了，同学们期末多考几分。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('5c30a69d44d904005d0b6f08',250,561,'人家都说没有挂科的大学是不完整的，应该是大学挂的第一科了，感谢陈老师给我一个圆满的大学！',5,5,5,15,11,6);
INSERT INTO "reviews" VALUES('5c2ef417fb4ffe005fbb3cdf',8182,573,'讲课有口音，脾气大，没有变通，挂科率高',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5c2ef23967f3560063057747',6403,535,'王小川还是8⃣️要教书了吧',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5c2cdf797f6fd3005dbf7703',12946,1529,'年轻时很帅（见过照片）  大概还是六扇门里的四大名捕 （比较严）    年纪大了   管的比以前少   同学大多数不怎么听课（老师有点像严肃  照本宣科）   想听的话尽量坐前排    PPT教务网上都有    戴老师年纪大了   也变得比较和蔼了 总的来说别逃课  好好学习  认真复习    没有太大的问题（助教的实验课认真做）',3,3,2,8,1,0);
INSERT INTO "reviews" VALUES('5c2b6c7cfb4ffe005fc69212',4925,3645,'超喜欢这个老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c29ddf7fb4ffe005fb33b05',344,601,'老师讲课超级好，只要上课不玩手机不聊天都没问题，就是课太火了，可能抢不到电子技术的课了',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5c29dd751579a3005f67f829',5937,24,'前半个学期讲课还行，后半个学期讲得很快，而且黑板上的板书非常乱，稍微走点神就不知道在讲哪里了，后半学期没有自学想完全学懂不太可能。作业布置得倒还合适。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5c299b4e4773f71736d48d6a',3407,762,'专业知识过硬的，我感觉朱老师每次上课都有备课，讲课没有什么卡顿，一气呵成，我还去上过他讲的高数也感觉不错。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5c278b041579a3005f4db8ea',1175,27,'想尽一切办法让你及格。超好。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5c271c80fb4ffe005f923a57',1274,36,'讲课幽默，普通话好。虽然没几个人会听思修与法基。很少点名，基本上没有作业，推荐。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c271c0f4773f71736b76ecc',4986,28,'何老师对出勤要求比较严格，平时考试，小测验，单词听写（单词听写可能比较烦）什么的都比较水。本来上了大学英语就是考四六级的，课本上的内容学了也没什么用，就是期末考试应付一下，老师人很好，常带笑容，和蔼可亲。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c271aaa67f356005f54a919',257,5,'除了第一章矩阵，其他的他根本讲不明白，讲着讲着就把自己绕里面那种，计算经常出错。后三章就自学就对了，刚来就学线性代数，也不能换课谁。分到他算谁倒霉。就自学吧。老师人倒是挺好，就是根本讲不明白 。基本上不点名，一学期一次两次吧考试前会有通知。考试签到。标签选不上，我想选的是耐心（虽然讲不明白），博学（你和他根本不是一个层次的），深邃（他给你讲的也不是你问的）。',1,1,2,4,8,0);
INSERT INTO "reviews" VALUES('5c2716967f6fd3005d79c08b',252,114,'用了活水这么久了，自己也来给学弟学妹做点贡献啥的。蒲伟老师人超级好，讲课清晰明白，认真负责。及时答疑。虽然有些四川口音，导数和倒数分不清之外，其他都没得挑。能选上蒲伟老师的课真的是太好啦。据说给分也高，虽然我半期只得了64分（那是我刚开始没认真学习），我相信期末还是阔以的（正在期末努力ing）不点名，一学期手机签到两次，作业可以补交。',5,5,5,15,4,5);
INSERT INTO "reviews" VALUES('5c26f9339f54540070e2d494',823,1897,'老师讲的非常好，上课超级有趣，知识点讲的很好，做题方法也会总结，而且老师人很有激情，很和蔼，而且很懂我们的想法，很好，非常好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c26f8ad1579a3005f44fe8a',12218,762,'老师很有趣，讲的不错，就是有点点快，可能下来要自己吸收一下，不过老师人很好，平时成绩满分，选吧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c26f83d4773f71736b576fc',10552,13876,'老师水平非常高   略有点不近人情（个人感受）   但是不能否认能力真的非常强  平时认真听课  有什么疑问尽量找同学解决就行',5,3,2,10,3,0);
INSERT INTO "reviews" VALUES('5c26f82a67f356005f518151',22,92,'老师超级负责，给分超级高，平时几乎是满分，上课很有趣，讲知识很透彻，老师人超级好，非常好，十分好，认真学，期末毫不会担心挂科',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c26f689fb4ffe005f9029ba',8138,716,'强强真的讲的超级差，给分超级低，上课有口音也听不懂，只能靠自学，而且人很冷酷，不要选啊，谁选谁后悔',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5c26d3e3fb4ffe005f8e3eda',1694,501,'老师专业水平的确强，但是第二节课就开始讲高阶操作，后来更加是先做完自己的再说，完全不理会台下已经在知识的海洋中溺死的同学们了，这谁吃得消啊。。。',5,2,4,11,0,2);
INSERT INTO "reviews" VALUES('5c265fcf67f356005f46cb57',24,24,'没有任何黑点
INSERT INTO "reviews" VALUES('5c265e0e7f6fd3005d730292',3670,13881,'听课坐在前两排才能听清楚，至于内容，基本都是PPT的内容，不过专业水平可以，很可爱，适合爱自由的朋友选',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('5c265dd1fb4ffe005f8b3a1e',1753,1753,'丁老师也是个超级优秀的老师啊，不点名，讲的好，很推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c264ed29f54540070dd3b66',4121,4121,'老师人不错。不点名，抽问抽到了没来也没事，给分高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c264cae1579a3005f3f49e4',2298,394,'给分低，作业要求多，自己布置的作业自己都描述不好，最后悔的一门课，没有之一',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5c262d1e1579a3005f3d6d54',9693,2,'毛坚强老师的课堂氛围很不错，只要你想听你就能得到东西，各个地方都讲的很细致，有他亲自讲解的习题课，还会抽课或者加课来进行答疑，总之你想认真的学就选他的没毛病，分数吗，作业都按时交了，认真学了，会有回报的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c261e0bfb4ffe005f87b8fa',9031,28,'很有亲和力的老师，总是在笑，除了学习之外也会关心我们的生活，授课基本用英语，口音不错，但是讲课比较水，不适合想在课上提高自己英语能力的同学，而且上课会提问，基本每节课都会点到翘课的人（也不知道该夸她认人厉害还是巧合）',4,5,5,14,0,3);
INSERT INTO "reviews" VALUES('5c23a38c1579a3005f1f589a',6377,6377,'姜炒根老师还是厉害啊',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5c2343757f6fd3005d4c9091',2346,762,'人很好 上课氛围轻松 作业正常  没点过名 偶尔课堂作业',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('5c1ccae5808ca400733a95d3',13889,476,'首先从老师的角度来说，岑老师绝对是一名老学究派的老师（无贬义），他不按照考试来讲课，而是按照工程实际来讲，讲的很深入，但可能和考试无关，所以他的课对考试真的不太友好。他不会点名，但是每节课都会布置作业，而且有期中考试，考试形式很正规，但实际上很水，都是助教监考的。
INSERT INTO "reviews" VALUES('5c1bd08c9f5454007068e324',23,1529,'瞧一瞧看一看，选一送三了啊，选一门大计基附赠大学生心理发展指导（永久售后）、流行音乐鉴赏、公益广告鉴赏，走过路过不要错过啊。
INSERT INTO "reviews" VALUES('5c1bac519f5454007067931a',395,1007,'虽然教得很烂，但是脾气很好，而且经常早一点下课，基本不点名',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c1b57c81579a3005fc50a22',8264,96,'老师上课完全不看表，不打铃就不会下课，三连讲经常到六点二十才下课',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('5c1b16581579a3005fc1d152',13341,13341,'老师讲的很有趣，但作业有点多，会有视频作业，看个人吧',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('5c1b1264808ca40073270262',2205,80,'啥都不说  阿力天下第一',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c19d29a1579a3005f682420',1332,188,'标哥是武大的博士，感觉他上课不是在上课，而是在奉献自己的激情，自己对于党和国家的一份激情，有点偏激的说，他对于党和国家热爱是狂热的，我也已经成功被他洗脑，我觉得这是正确的。
INSERT INTO "reviews" VALUES('5c19ccca808ca40072c47d99',3286,3286,'老师认真负责，讲课活泼有趣，课程设置细心合理，能学到很多东西，非常棒的老师。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('5c19cca267f356006606f091',1537,1651,'老师非常好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c19c7919f5454006654bc01',3439,2298,'专业过硬 课堂丰富 作业少 偶尔点名 期末没考试 期中一次调研 期末一次论文',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c19bda99f54540066543c47',9807,13185,'真的是好老师，认真负责，讲课也生动，有条理，作业不多但很精细，上课会有一些拓展，不是只讲理论，会联系实际应用做一些创新思考之类的，上课会带一些实验仪器什么的给大家演示，很有意思～',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c19b49344d904005fbb8037',1175,761,'老师特别和蔼，几乎不点名，在图书馆上课时会有小组作业，不过当堂就能做完，找对组员很重要。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c19b43867f356006605a663',141,141,'老师特别特别特别特别棒，特别特别特别特别喜欢，认真负责，讲课很细致很耐心，特别好，真是相见恨晚。',5,5,5,15,2,4);
INSERT INTO "reviews" VALUES('5c199ae444d904005fba38c9',12946,1529,'没上过，跟风',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5c1996ca1579a3005f6525bb',13341,13341,'上课都可以不听！！但每节课下来都有作业！！抄绘论文视频作业一个都少不了！！唯一的好处就是期末考试不复习做问卷了哈哈',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5c19906f808ca40072c18f94',257,5,'不按照教材顺序讲 讲课混乱无比 学生听不懂 基本概念也照本宣科',3,1,1,5,5,0);
INSERT INTO "reviews" VALUES('5c1929cc808ca40072bf9b61',785,114,'小阳上课比较生动，板书和ppt都有。
INSERT INTO "reviews" VALUES('5c19278744d904005fb7d875',24,24,'老师是真的特别特别好的老师，就是课太难了🌚',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5c1927191579a3005f62ec80',1341,114,'下课提问真的敷衍',4,2,1,7,4,1);
INSERT INTO "reviews" VALUES('5c1922e944d904005fb7b6e2',309,309,'老师特别友好，上课清楚易懂',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c190b1b808ca40072be7f65',6726,3581,'上课僵硬，给分很低，平时分平均在60到70，交大有史以来最最最最让人绝望的司马老师',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5c19035a9f5454047494fc6c',13910,619,'邓小林老师的讲课风格是让人不自觉被他吸引过去，就不会感觉三连讲那么难熬了。另外也不会让人很担心分数，作业很轻松（对比其他毛概课的小组作业和展示，只要求一篇读书笔记），上课的时候经常提醒同学翻到哪一页做做笔记，期末的时候还特别关照理科生讲讲答题技巧（向来为文科类考试头疼的我仿佛突然被一束佛光照耀）。很宽松也很亲切滴老师，三连讲总是提前下课嘻嘻',5,5,5,15,7,1);
INSERT INTO "reviews" VALUES('5c18fb869f545400664e3e4a',459,68,'不点名，老师专业知识过硬，懂的超多，平时会留一些作业，但是从来不检查，除了作文   平时很水，但是考试要靠自己',5,5,5,15,3,5);
INSERT INTO "reviews" VALUES('5c18f3e1fb4ffe0069d9b134',12235,12235,'老师是真.学霸，课程以讲为辅，主要锻炼表达，思辨能力，平时要做实习报告，小组汇报，期末论文＋答辩，还要准备辩论，课堂氛围极好。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c18eddd808ca40072bcfaf0',13913,48,'老师心很好，有点啰嗦，平时主要看你态度，有时候态度认真，考不好也可能让你过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c18d590808ca40072bb9abd',23,4181,'超级好！',5,5,5,15,53,0);
INSERT INTO "reviews" VALUES('5c18d1bd1579a3005f5ec388',13913,48,'老师有丶毒舌，不过对同学挺关心的，是个好人',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c18b96c1579a3005f5d5e18',2200,2387,'老师上课认真细致，半期占总成绩不高，平时分都给的很高。相对于其它电分老师来说上课进度偏慢，但也保证了大家只要听课就能听懂。总之还是很推荐的',4,5,5,14,0,1);
INSERT INTO "reviews" VALUES('5c18b3b944d904005fb1dea5',9120,92,'讲课是真的不好，但是平时分给的还是过得去',5,1,3,9,0,5);
INSERT INTO "reviews" VALUES('5c18b2aefb4ffe0069d5f641',826,114,'讲课有头有尾，比较友好，平时考试也比较放水',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5c18b11d9f54540474905fd0',11684,13919,'上课水，看视频居多，作业以口头报告做PPT为主，没期末考试，一学期就两次作业，很爽。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5c187afd9f545400664738be',31,31,'大学最爱的老师，没有之一，太好啦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c1874cb9f545404748d4f32',13341,13341,'每节课都布置作业有时候真的受不了，专业课有时候还没这么忙。期末会让你去拍园林视频，慎重',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('5c186e51303f39005f0cd6b6',13795,521,'基本上在MOOC上看视频，只有几节课需要去教室，只不过去教室的时候不允许请假。有时候会有提问，不过随便答就行。每节课最后都会有一个问题，随便答一两行就可以了，主要是通过这个来看你来了没有。MOOC上的视频不用看，刷了就行，测试百度就可以。期末有论文，800字就行，就是需要自己写，查重相似度不能超过30%。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c186905fb4ffe0069d245f6',13923,114,'老师真的特别好 讲的很好 人也很好 平时也没有太多小测 平时分基本给满分',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c1867ec1579a3005f4eb5ac',1341,114,'老师讲课很负责，点到不多，一周交一次作业，课下还有视频资料给你看，帮你学习，',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c186361808ca40072b5acf1',4352,4352,'从没有见过这么讨厌的老师，上课挖苦学生，没有给分标准地随意扣分，凭借自己的心情给学生评级，上课懒散，毫无重点，从不听学生反映问题，时常把人骂哭。是我在交大见过的最没有素质的老师，希望他能和同教研部门的刘旭老师学习如何教书育人以及做人修养。国家教育部门针对这种毫无人品和教育素养可言的“教师”应该做出一些改变才对。',1,1,1,3,14,1);
INSERT INTO "reviews" VALUES('5c186285303f39005f0c4fe2',13926,2158,'上课比较枯燥吧 坐在后排也听不到啥 给分还好',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5c185941fb4ffe0069d186e0',986,13927,'老师人很好，挺好的',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5c1858cb67f3560066f7a677',4306,517,'老师人很好，也很耐心，课前会收一卡通，有事去不了可以找她另外的课补课',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c18580f808ca40072b51c44',505,175,'老师人很可爱，会提前讲解需要做的作业，上课条理清晰，给分也还可以',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c185722808ca40072b510f0',1122,2015,'老师会在画图前仔细讲解，人很可爱，给分也还可以',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c18561c1579a3005f4d18c7',449,3822,'老师上课很温柔，人很好。就是分，有努力才有收获。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c185543808ca40072b4fa8d',480,92,'课上除了大声说话都可以，也可以不来。作业按单双号交，一学期交够规定次数就可以了，敢保证考试分够高好像还可以不交作业。讲解很清楚，有专门的自己的网站给学生PPT和作业答案。很不错！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5c1854271579a3005f4d0084',13933,965,'一学期就开学第一节课点了名，期末考试还会帮你过🌝，就是上课节奏不好跟',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('5c1852f31579a3005f4cf3ef',250,250,'别选…真的夺命，期中还是陈老师出的题，别的班平均六七十，他带的三个班三四十',3,2,1,6,7,0);
INSERT INTO "reviews" VALUES('5c184f97808ca40072b4ba3a',3212,5,'巨抽象。还有作业会在下一节课讲，都交上去自学完了还要你讲干什么。。。',2,1,4,7,1,0);
INSERT INTO "reviews" VALUES('5c184ef71579a3005f4cccf6',1732,3689,'会就会，不会的永远也别想会，不知道最好的程序是什么样子。
INSERT INTO "reviews" VALUES('5c17ce6dfb4ffe0069ce3d3d',175,175,'待人友好，讲课细致，就爱是在画大图上挑毛病',5,5,5,15,1,5);
INSERT INTO "reviews" VALUES('5c17cbd167f3560066f44f14',31,31,'主修世界史，辅修数学',5,5,5,15,11,0);
INSERT INTO "reviews" VALUES('5c17bfa167f3560066f3d132',31,31,'超级超级棒，讲课细致，通俗易懂，夹带历史课哈哈哈哈',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5c17b68167f3560066f36c26',13435,13435,'讲课强的一批，课堂紧张刺激严肃活泼，真的是这个样子的哦，你不要不信哦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c17b62f303f39005f0794b9',4986,28,'爱笑的老师教课不会太差',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c17b5d667f3560066f36437',13942,5,'灯灯灯，给我讲的云里雾里。',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('5c17b0281579a3005f48af57',2961,761,'老师很好，教学上课也很认真。作业不是论文什么的，我们组七个人，一学期下来一共必做五个PPT，选做3个，工程量不大，都是图加少量文字的形式。通过这个课，我了解到交大图书馆里有许多免费的为在校大学生提供的资源库，学习了检索方法。个人感觉只要用心学，还是有很大作用的。期末还是做一个PPT，还会帮你指出不足，修改后再打分。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5c179b971579a3005f47864e',7459,36,'一般般，改改方言即可',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('5c1798fb1579a3005f475fc8',2202,28,'老师真的很优秀，会有很多视频和歌曲也会有很多分享，喜欢。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c1798da303f39005f05f336',8096,1529,'就是课前用微信章节测试有点烦，幸好是开卷',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('5c17976044d904005fa77950',1290,28,'咋不点名，咋安排座位，上课一目了然{捂脸}',4,2,4,10,1,0);
INSERT INTO "reviews" VALUES('5c1787b29f545400663ecfdf',2582,790,'综合运输概论，老师讲课幽默，专业知识丰富，作业比较多。先是学生分小组上去讲课，然后再提问，补充知识。考试要背的内容很多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5c178142fb4ffe0069ca33f4',13942,5,'讲的太跳跃太抽象不利于理解',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5c177f86808ca40072adba1d',1542,1796,'太差',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5c176604303f39005f005fa3',13845,1753,'人又凶，讲的又差。还难为我们助教。特别swjadikdke',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5c0dd0dbfb4ffe006954cfb7',13526,28,'老刘非常好，口语有点川味，但可以理解，教学方式很为学生着想（可能会有人觉得老刘在考试过级方面导向性太强？）但是只要跟着她走，期末得分不会低。虽然重视四六级考试，但也很注重培养各方面综合能力，不忽视口语能力培养（比如说课前给了我将近30mins做完我题为“21世纪我国意识形态教育的重要性”的课前presentation，和我熟的同学基本能猜出来我是谁了）
INSERT INTO "reviews" VALUES('5c00e9c5fb4ffe0069bb639b',13341,13341,'老师非常幽默，内容很有趣味，虽然是双语课但是中文是很多滴，每节课后都有小作业，量不算大建议尝试一下蛤',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5bf663e9303f39005ea26b88',13589,641,'讲的挺好的，老师给分挺松的。想学好也容易，老师给PPT(๑°3°๑)。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5be14dd9ee920a006621c614',1341,114,'老师讲课不用ppt，全部板书，喜欢跟我们讨论教学方式，认真负责，超好哦',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5be0f046ee920a00661c9ad0',9443,13956,'讲课幽默认真，十分吸引人',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5bd875400b616000661f0279',334,562,'挂了一排人',3,2,1,6,4,0);
INSERT INTO "reviews" VALUES('5bd87060ee920a006832371c',887,23,'老师很严格，不水，能学到东西，平时上课很少点名。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5bd7db31ac502e0061052536',85,85,'超级温柔的老师，很尊重学生。课程不水，很好玩，考试打分很高。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5bbbf56f9f54540070effe81',281,1156,'讲课还好，但是口音让人难以接受，有的时候还会自己前后矛盾，不过大体还是听得下去',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5ba6628e570c350066ca9c3d',13318,1825,'感觉老师是严肃中带皮的那种。我是理科生，2年多没接触文科，当听到这是哲学时我内心是崩溃的。但课堂很早有趣，没有我中学时文科生不如死的感觉。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5ba480577f6fd3005d396781',4784,641,'oh my god，上课不迟到是不可能的，不照本宣科是不可能的，不无聊是不可能的，讲得贼差，要求贼高。这位神一般的老师终于在坑害了一代又一代学生后，不再授课了。而我们是他最后坑害的一代，而由此造成多届计算机学生C语言基础极差，副教授忍无可忍决定亲自授课。 愿后来的学弟学妹们学好C语言，走好人生路。',1,1,3,5,2,1);
INSERT INTO "reviews" VALUES('5ba0c011fb4ffe005ce6e2f3',8138,716,'讲的太烂，听不懂，还光提问，大坑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5b9a0e6b1b69e6005b945be8',11887,11887,'交大第一水课！！不点名，没平时作业，老师基本不在，助教放了视频就走，签完到走一半人，无考试，期中期末各一篇论文，给分超级高！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5b9a0cc09f54540039aa07aa',88,88,'我上的是李老师的篮球课，和隔壁张问宇老师的篮球课形成鲜明的对比！！非常的非常的轻松！！基本跑几圈就开始自由活动，老师脾气非常好，性格开朗，风趣幽默！女生要想谁说篮球一定要选这个班！',5,5,5,15,0,5);
INSERT INTO "reviews" VALUES('5b99dfe21579a3003a3f2f19',7553,7553,'老师之前据说是一直在日本当留学生日语老师的，日语能力没的说，很厉害。
INSERT INTO "reviews" VALUES('5b99de951579a3003a3f2095',214,36,'老师超级有意思的好吗，平时分给的很高，上课幽默风趣，超有意思的。',5,5,5,15,2,4);
INSERT INTO "reviews" VALUES('5b978d2f9f5454003990f38f',2688,2688,'不点名，最水的通识课没有之一。 但就是不知道为什么没人选。  节节课放视频，最后一节课放了的士速递1，期末交篇论文就行。     想水的同学们可以选，强烈推荐。  喜欢汽车的同学也可以选，能了解很多汽车的历史。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5b9765511579a3003a262075',8814,8814,'好老师，作业最少，点名最多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b95db65808ca43cd2e79bd6',13736,114,'很好的老师，讲课非常风趣幽默，上课气氛很轻松，平时分给的也很高，可能有的同学说听不清老师讲话，其实习惯了就好，我一开始也这样，到后来过了两三周基本都能听清了。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5b955005808ca43cd2e3beca',13971,1106,'老师挺好的，虽然不太管学生，不听就是门水课，听了满满都是干货。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5b954f401b69e6005b635754',36,36,'面容和善，鹤立鸡群，在一群8-90分+中，他给分70几，是真的天秀🐷',3,2,4,9,0,0);
INSERT INTO "reviews" VALUES('5b8f7660d50eee00394cc4e4',767,5151,'PPT很及时，内容非常好，期末复习条理清晰，表达能力挺好的，上课会有一些些无聊，但是重点较多，上课时会圈重点，期末复习也很用心，作业不多，课设咨询非常详细，期中考试没考好可以交论文补平时分，非常nice的老师。（助教也很好）',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('5b8dfb95a22b9d0037145afc',13974,13974,'极差',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5b8dfa93fb4ffe003117d7e9',13975,13975,'上课多位老师轮流，讲课内容很无趣，给分不高，经常点名，选通识课选这门会十分痛苦。',1,3,3,7,0,0);
INSERT INTO "reviews" VALUES('5b8deb4e0b61600063480773',13976,13976,'讲话很清晰 语速合适 讲课干净利落 期末答疑很尽职尽责 好老师๛ก(ｰ̀ωｰ́ก)',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b6b94dffe88c2005aff549e',13977,397,'老师超好的，为人很亲和，老师的专业素养很棒，讲课有条理，曾经是一位让人敬佩的女强人，现在变为一名人民教师，老师真的很棒，给分也挺高的。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b697a549f54540035ed8a60',696,698,'老师上课不知道在干些啥，而且听不懂！',5,1,1,7,3,0);
INSERT INTO "reviews" VALUES('5b56c9de808ca4006fa2721e',449,3822,'老师人很好啊，一学期下来能记住每个人的名字。只要认真上课的话，最后给的分都挺高的，有几个人最后平时成绩都给满了。平常录音讨论还挺多的，但是努力还是有回报。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5b56c8f9808ca4006fa267aa',3098,3136,'水平高，愤青，固执。平常给分还行，也比较负责，双语教学很坑。其实最好是你用中文学，最后背一些单词就行了。上课经常扯一些有的没的，社会，足球啥的。本人应该是妻子儿女不在身边，端午节都从上午8点讲到了11点半。给分还行，期末英语考试略坑。',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('5b56c7f49f5454003cffeff1',360,360,'老黄人挺好的，给分很高，因为期末考试很难23333上课讲的也很有条理，但是嘛，这个讲题这种事情本来就很无聊，所以也不能怪老师。作业很少，期末很难。',5,5,5,15,1,9);
INSERT INTO "reviews" VALUES('5b56c770128fe1002f6b444b',3025,5119,'先打差评，教授强是强，但是固执也是真的。思维过于跳跃，讲一个东西的时候就经常跳到其他的地方去了，一学期下来没懂啥是实体类，啥是边界类。上课讲的很实用，以后工作可能用得到，但是又不给模板，学生自己又不知道写啥。请了两次假，不准假，一次不到就扣一分平时分。期末考试很坑爹，什么都没说，还觉得自己什么都说清楚了，给分很低。一学期写很多文档，给分很低。',5,1,1,7,2,1);
INSERT INTO "reviews" VALUES('5b56c4c09f54540035da0440',13983,13983,'良心老师。每节课都会有一些题，最后的填空题或者概念题就从这里面出，老师人很好，学术人才，沉迷学术无法自拔，导致自我形象都……不点名，只要你交了上课的题就行。上课讲题也很慢，保证你能听懂。课程设计也很水，copy的也给高分。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b56c342808ca4006fa22c97',8883,8883,'老师人挺好，上课也不怎么管，也不怎么点名，给分还算不错，就是课程本身还是有难度，期中考试很难，选择题很肯定，期末的时候给范围所以不用担心。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b540af39f5454003ceb556c',7728,3332,'大学最喜欢的老师，课讲的很好，能学到东西，人又有趣，教学非常负责，赵老师满身大汗还面带笑容的讲课，时不时还要讲故事逗逗大家，氛围轻松愉快。期末给分也很高，超级棒。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5b51f35b0b61600031eb0292',5021,2586,'张晶老师怎么那么棒！博学多才，幽默风趣见识广，魅力无穷！希望能成为像张晶老师一样的人吧哈哈哈哈，强烈推荐给每一位同学！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5b51f0e19f54540035b80b32',1991,1065,'超喜欢的一个老师，讲政治一点都不枯燥，讲历史故事信手拈来，有自己的看法，也尊重同学们的想法，喜欢！！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b5187d89f5454003cd9fd0d',13988,5,'薛老师是一位很棒的老师,讲课耐心细致,会很负责地为同学们讲解习题,亲和力爆表。虽然已并不年轻但精力充沛,不带一点口音的普通话让所有同学都能清楚地理解,班上还有许多其它院的同学来听课。强势推荐',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5b518184808ca4006f7c49c7',13926,2158,'讲课认真',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('5b517c5b0b61600031e6afc9',13942,5,'不知道是我太笨还是老师太专业,感觉上课听的不是很懂。',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('5b5173ae808ca4003c245c27',13991,2254,'老师认真负责,对学生友好',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5b516c2e128fe1002f44538c',11065,11065,'老师认真负责,很与学生合得来',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5b5163f9ee920a003c47e4e2',13971,13993,'老师一个人在上面讲,下面学生自己做自己的事,老师不会管。但认真听一会儿觉得讲得不错。',5,2,3,10,0,0);
INSERT INTO "reviews" VALUES('5b515c3c0b61600031e58887',13994,13994,'节节课点名,还要学生上去讲,类似反转课堂,还写了3篇300字以上的essay',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5b5155ac808ca4006f78dab8',1230,13995,'老师热情,富有激情,课上活动较多,有较好的学习氛围。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b514def808ca4003c22eb0a',330,448,'孙燕云虽为理科老师,却极富文采,并且所讲东西更是将物理结合进我们没有想到的其他领域,冲击我们的大脑。',5,5,5,15,1,8);
INSERT INTO "reviews" VALUES('5b51448e9f54540035b1c1a0',2323,448,'上课认真,老师负责,授课能力强,学识渊博,可以学得较多的知识。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b513c5a128fe1002f4283db',10328,2158,'上课十分认真,讲课内容十分丰富,让我们学到了很多。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('5b51345c808ca4006f77a7ea',491,1529,'非常优秀,专业水平挺高的,就是很厉害！',4,4,4,12,4,0);
