INSERT INTO "reviews" VALUES('5b5128a3ee920a003c45c635',2701,2701,'只要对音乐感兴趣,可以在课堂上得到很多,讲的东西比较通俗易懂,是一门值得选修的学科。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5b4e92510b6160003116b504',819,9857,'老师很好,如果认真听课可以学到很多知识,但是倘若不认真听,也无多大关系吧。',5,5,4,14,1,0);
