INSERT INTO "reviews" VALUES('5b4be20fd50eee00318d005a',1290,28,'讲课专业知识很棒,但是老师口音奇特,开始的时候听不懂。',5,3,4,12,0,2);
INSERT INTO "reviews" VALUES('5b48a8d79f54540031df6a8b',11950,2598,'交大上学过遇到的第二个觉得值得的老师，讲课极好，最后得到的分数也算很高，认真听他讲课真的很爽，学到了很多东西，全好评不解释',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b48a2152f301e003b84ea30',12658,34,'老师其实很有水平的，他讲的都是他自己的理解，也会留些东西让我们自己思考。虽然他作业比较难，但确实可以学到东西。而且认真听，考试真的很简单的，推荐!',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5b46acaf9f54540031cff38e',5,114,'学科充满挑战性。做题充满乐趣,老师风趣幽默,讲课有趣。',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('5b46a70f0b61600031df3eb5',51,1346,'这位老师的这门课学生展示时间比较多,老师讲得比较少。老师讲得时候语速太快了,口齿略有不清,让人听讲兴趣不大。',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('5b46a16eee920a003cf0a87d',5,114,'上课氛围比较轻松,讲解也比较轻松,但应该对习题的进行一些讲解并归纳总结。',5,4,5,14,1,1);
INSERT INTO "reviews" VALUES('5b469b919f54540031cf6e26',5,114,'上课认真负责,课堂氛围也很轻松。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('5b462b1f9f5454003146fdbb',1537,526,'特别好',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5b462b03fe88c200350b9d62',7560,526,'别选，有点严',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('5b462ace0b6160003c429787',913,611,'挺好的，但是天下英语老师上课都一般水，，，还是找个人好看心又善的水....',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b462a6d2f301e003451e769',101,10194,'我为樊老师打爆call',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b462a0b0b6160003c4291df',11891,22,'老师人很好，但是上课不管你听不听得懂，自己对着PPT念，平时分好多人都给了满分，怕挂选他你懂的....想高分只能靠自己',2,2,5,9,0,0);
INSERT INTO "reviews" VALUES('5b45798efe88c200350505d0',5,114,'老师上课气氛好,为人和蔼,热情,轻松,幽默,思路宽然而准确,效率有待提高,作业量可再减少,考试难度继续保持',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b4576f967f356003a835133',13988,114,'上课认真,但上课速度很快,对同学很好。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5b4571949f54540031401d8d',7459,36,'讲解相当生动有趣,讲解认真,引人入胜。',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('5b456f3bfe88c2003504a1b3',12235,12235,'老师认真负责,课堂收获很大,知识面很广。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b45699b2f301e00344ab81c',2202,28,'本来我不太喜欢英语的,现在我的兴趣正在逐步提升。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5b4564362f301e00344a851a',14030,114,'老师上课十分认真,讲解十分仔细,治学严谨,博学,是个难得的老师。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5b4560ad2f301e00344a673e',27,28,'上课内容丰富让人觉得充实,讲课幽默,为人和蔼。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5b455b48fe88c2003503e9c6',257,5,'说话听不清,有时讲得自己都晕。',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('5b45547b67f356003a82155d',4784,641,'很尽职的老师,我要好好学习啦！',5,5,4,14,0,1);
INSERT INTO "reviews" VALUES('5b454fcb2f301e003449e00e',384,1267,'课比较水,想听就听,不想听拉倒,期末几节来点个到,交个论文就行。',3,3,5,11,1,0);
INSERT INTO "reviews" VALUES('5b454cfa9f545400313edb72',14035,1267,'很水,很水,很水。期末考试只有一份20字论文。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b454a2a9f5454003b1d3680',7045,28,'上课很亲切。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b449740ee920a003b1300a8',785,26,'男神，真的非常好。爱他（虽然我是男的）',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b4430689f545400313758a5',3258,910,'老师放的电影都超好看啊,老师的电影赏析也很专业,对我来讲收获很大。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5b442ac70b6160003c32af6e',9246,5,'讲课不太清楚。',2,3,4,9,0,0);
INSERT INTO "reviews" VALUES('5b442432fe88c20035fb70fb',9443,1170,'老师讲话带一些川普,2周后应该就习惯了。专业知识很强,讲课时经常“18xx年”,“19xx年”顺手拈来。口头禅：“哦豁”。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5b4420e9fe88c20035fb4bc4',9246,5,'老师很棒,讲得挺好,对待学生很有耐心,从来没甩过脸子。讲得很细致,如果你预习了,跟课不是问题。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5b441e19fe88c20035fb2d12',252,114,'老师非常敬业,尤其课后答疑非常及时,建立专门的高数学习群,同学们课后学习热情极高。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b4417c4d50eee003ae9e28f',13243,13243,'老师一学期亲自上课不超过5次,都是助教的学姐在上课,氛围轻松。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5b44134f2f301e003441351c',836,1529,'老师上课富有激情且能够联系实际授课,课程富有趣味但难度较大,即便认真听课也未必能理解其内容,是一门水分适中的课程。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5b440c83fe88c20035fa8b6e',649,36,'老师讲得很不错啊,学到很多法律小知识,增长了知识。',5,5,4,14,0,4);
INSERT INTO "reviews" VALUES('5b44075a0b6160003c31594a',4112,114,'杨老师人挺好,讲课方式比较传统',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('5b44026dee920a003b2b3a37',4112,114,'上课很有特色,川普说得不错,经常乐呵呵的。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5b43fd09d50eee003ae905de',826,5,'每说一句话就笑一次,每次都感染我。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b43f9489f5454003b13c8b3',4112,5,'上课说话听不太懂“噻,撒”使用过多,迷之笑点！！！你看他笑自己都替他尴尬。',4,3,3,10,0,1);
INSERT INTO "reviews" VALUES('5b4061ea9f545400311dc796',7435,7435,'段老师温文尔雅，有大家学者风范，讲授宋词娓娓道来，引人渐入佳境，让人回味无穷，不留宝山空回之憾！所以她的宋词之美通识课，每学期选课都会呈现人数爆满的盛况，为段老点赞100+++，',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b405f0067f356003a608734',13321,2027,'付老学识渊博，讲课亲和力超强，课堂气氛生动活泼，教学相长，不耻下问，点赞100+++',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b403fbf9f545400311c90b4',558,792,'老师是真的好   平时分给了接近满分   上课全靠自觉  期末全靠自己',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5b40363267f356003a5f0380',887,23,'老师很负责，不点名，会及时上传课件，对学生真的特别特别负责，讲课也很清楚，超级棒',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b402c19d50eee003acf4b66',101,114,'讲得很清楚,很详细,老师很负责。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b4029c1fe88c20035e01eb3',1938,2375,'每两个星期换一次老师,节节课有作业（思维导图,当天晚12点前交）,12-16周设计作品,最后有个至少2500的论文QAQ肿么感觉一点都不水。',4,4,3,11,0,1);
INSERT INTO "reviews" VALUES('5b40239667f356003a5e54be',4936,14056,'一名只喜欢男生的奇怪老师。板书字迹潦草到看不懂也不爱用ppt。班级女生占绝大多数，曾因为指出老师板书解题的错误被莫名其妙一顿痛骂。但是考试会划重点和题目。',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('5b40236c9f5454003b50363d',826,5,'老师讲课口音太重,说话声音忽高忽低,十分催眠,解题思路不清晰,常常解题解到一半发现不能使用该方法,又换一种解法。',4,3,4,11,5,0);
INSERT INTO "reviews" VALUES('5b40224bee920a003b10f4fc',5021,2586,'张晶老师女神！干练的职场女强人，讲课生动，案例丰富，深入浅出非常好懂又引人入胜。足以激发非法学学生对法学的向往啊',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b401dccee920a003bc8d595',785,229,'和蔼 温柔 男神',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5b401d2d2f301e0034261f72',3251,1131,'老师真挺好的，讲课幽默风趣，爱听他吹水+1，据说能记住所有人的脸，哈哈，到期末都能叫出大部分的名字了。虽然我离散还是很悬，不过绝对不是老师的问题就对了。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b4018a2d50eee003ace9559',826,5,'口音什么的都是醉了,每天上课就只是对着PPT念。然后有的时候还照看念错了。以为学生什么都会了。其实都要靠课后自学。',3,1,4,8,1,0);
INSERT INTO "reviews" VALUES('5b4013b5d50eee003ace6bd3',826,5,'线代课是线代老师一个人的狂欢。但是。。。虽然她上课很投入。但是。。。口音重,只讲PPT上的,因为写板书会突然进入误区,一个人想明白了好高兴。“就出来了哟”—_— 对自己的答案和思路不确定。',3,2,5,10,2,0);
INSERT INTO "reviews" VALUES('5b400fe9ee920a003b1057a5',92,92,'作业只要交了就好，不会打等级。一学期会有不超过五次课堂练习的考勤，就交张纸就好了。老师普通话说的蛮好但是讲的没几个人听得明白，每节课都是照着PPT念，水平很一般。人还不错，要是自学可以选她，如果自学大物可以不挂的话。',3,1,4,8,5,1);
INSERT INTO "reviews" VALUES('5b3fb83c0b6160003c151be0',348,10913,'口音严重，逻辑不清，不知所云',3,1,2,6,11,0);
INSERT INTO "reviews" VALUES('5b3fb7939f5454003b4e5973',175,175,'看到好多评论说听不懂，个人感觉讲的其实也不算太差，可能擅长这方面的同学听听课就懂了。大图画的差不多分就不会低。但是分低的也不少。可以重画倒是蛮不错的。',5,3,5,13,1,5);
INSERT INTO "reviews" VALUES('5b3fb6269f5454003bf7c2d9',12558,1007,'还蛮有趣的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3fb5660b6160003c151377',14067,14067,'老师年纪大了很和蔼，讲得蛮有趣，非常可爱，还爱飙几句英语呢，也很轻松',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3fb4e12f301e0034247711',13341,1849,'大爱翔哥！可惜选修课没什么人好好听，都在玩手机写作业，这个课不是特别水，但是任务很有趣，做了就给分，爱翔哥(⑉°з°)-♡',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b3fb3c50b6160003c150ecb',803,1111,'郭老师对学生特别特别好，真的，讲课也非常好，上课听得很舒服，课下基本不用自学了',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b3fb2c10b6160003c150b99',2485,26,'非常喜欢韩老师，遇到其它讲的一塌糊涂的老师才知道韩老师厉害',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b3fab6b9f5454003bf7a3c5',2878,28,'非常好的老师，负责任，关心学生，给分高，讲课也蛮好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3fa3df0b6160003c14d5d9',480,92,'老师人真的很好 平时不会点名 所以一大半人都不会去听课 但是去听课还是比翘课效果好的多 考试重点会懂一些 平时把作业和课件搞懂分数就不错了 要高分还得多做些题练练',5,3,5,13,2,0);
INSERT INTO "reviews" VALUES('5b3f9e5cee920a003b0ec417',887,23,'非常棒的一位老师，在复习时候还准备了很详细的复习提纲，问问题的时候特别有耐心，就算是很简单的问题也会很仔细认真回答。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b3f927aee920a003bc154d2',13709,36,'思修老师讲很颠覆我的三观,而且作业超级超级超级多。',5,2,1,8,0,0);
INSERT INTO "reviews" VALUES('5b3f8c61fe88c20035dd41e6',1536,14075,'课程内容可谓玄之又玄,精神难懂,极度催眠。教授授课认真,但常常GET不到其笑点。每节课前或后要签到。作业不少,考试难搞,给分小气,吾义固不上其课也。',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('5b3f85d167f356003a5b830b',13709,36,'真的想用“名堂多”来形容她——读书心得、研讨报告、论文…上课笔记搞个没玩,每项都必须在200字以上。然后上课举的例子都是好多年前的。上课经常点名！！！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5b3f806bee920a003bc03006',236,1529,'老师很好,完美',5,5,5,15,0,4);
INSERT INTO "reviews" VALUES('5b3ef5582f301e00341e3bcb',9062,23,'气氛活泼轻松，老师很好，但是有点缺条理，听课收获不大，还是靠自己',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('5b3ef4d1ee920a003bb5f9e2',948,92,'很利落，制度很合理，作业可以晚交但必须自己做，根据自己的时间，去跟着她别的班的课也可以
INSERT INTO "reviews" VALUES('5b3ef3e80b6160003c0eca87',13845,1753,'感谢肖老师激发了我强大的自学能力。首先必须说肖老师人特别好，特别热情，很想关心学生，很想负责，奈何讲得极度不清楚，破了我们班逃课人数的记录，平时成绩还极低。另外，感谢糊涂老师带出来的糊涂助教，考试开始了还没把我们的座位安排好，助教人多还办不来事，整个班作业和平时成一锅粥，和老师讲的一样烂七八糟',3,1,5,9,3,0);
INSERT INTO "reviews" VALUES('5b3ef1cefe88c20035d7a5cb',5,5,'天马行空，毫无逻辑，自我非常投入，但是emmmm学生不懂啊。。。。。全班同学有意见',5,1,5,11,4,1);
INSERT INTO "reviews" VALUES('5b3eed25fe88c20035d7771c',755,3756,'上慕课不用去教室，讲得非常好。不选后悔死。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5b3eeba7ee920a003b0887d5',1307,1307,'客观评价，老师教的还可以。可是期末复习时告诉我们的重点完全没考，非重点考了近1/3，太坑了。想拿高分去选英语班吧。',4,3,4,11,2,0);
INSERT INTO "reviews" VALUES('5b3e62759f5454003b44a39c',14084,28,'上课非常有激情,几句口头禅使用非常流利,除了个别事件表达过于激动.讲课内容还好,老师挺负责任的,总体水平我给打3分.',3,5,3,11,0,0);
INSERT INTO "reviews" VALUES('5b3e601cee920a003b05757e',14085,114,'老师性格温和,平易近人。教导学生很耐心,同时知识渊博,表达能力强,思维清晰,具有丰富的授课经验。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3e5cd4ee920a003b056c0e',2005,3390,'受不了她的声音,而且上课喜欢走下来,容易抽人回答问题,最后PPT喜爱挑刺,',4,4,1,9,6,1);
INSERT INTO "reviews" VALUES('5b3e594f9f5454003b4487f8',14085,114,'老师资历颇深,见过的题型多且全面能全面覆盖考试要点,表达能力尚好,为人十分和蔼可亲,与学生关系相处的十分融洽。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('5b3e558f9f545400310fd5da',2701,2701,'每节课都有不同的主题,围绕其展开,打开进入音乐新世界的大门。可是点名,每节课都要,并且我不去的时候必点名。尴尬无语。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3e51569f5454003b44655c',1453,114,'老师很可爱,讲课有口音,有时候表达得不清楚,但绝对是认真负责的好老师。因为期中考得不好还被叫去办公室单独辅导,有种重回高中的感觉。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('5b3e4b3d2f301e00341a6f4c',13589,14090,'真的就是一门水课哦……从来不点名,最后一节课只有几个人去上了……也没有作业,只要期末交一份十六题的作业即可……那些题网上也能找到,总之很水。',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('5b3e486d9f545400310f96db',2377,322,'不来上课就惨了,每一次上课考一次试,上课特严格特正经特无聊。考试内容就是她上课的PPT再抄一遍。手写的都快断了。',4,4,2,10,1,1);
INSERT INTO "reviews" VALUES('5b3e459cee920a003bab9b0c',5739,5739,'钟永祥老师的课非常有趣',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5b3e00c267f356003a4ffb6a',785,114,'阳老师可以说是交大的良心之一【这话丝毫不过吧
INSERT INTO "reviews" VALUES('5b3c9bab9f5454003a94cf9d',5739,5739,'有趣的灵魂',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3b39fafe88c200350a7b72',913,611,'女神一样的老师，美式发音炒鸡舒服，上课简直就是享受，而且基本都90+',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('5b3ae4f59f5454003b69237f',246,228,'一个真实的******了。你交了课堂测验他还是会说你没交，节节课都到还会扣你考勤分，讲道理也讲不通他觉得他自己就是道理👌🏻',1,1,1,3,12,1);
INSERT INTO "reviews" VALUES('5b39cf5c9f5454003b615e79',8566,114,'老师人很好 但是上课有点照本宣科 讲解的不是特别透彻需要靠自己课下去理解 但考试难度不高 给分也比较高
INSERT INTO "reviews" VALUES('5b3992e067f3560038145f75',8371,3098,'建议选到这个课的同学上课听网课自学。
INSERT INTO "reviews" VALUES('5b38ae8c2f301e0035a21454',13942,5,'只用板书 上的很慢 但下一节课的时候发现那一章他居然算讲完了 基本靠自学 可能老师是很渊博的  只是授课方式我不认同  对于初学者来说是很痛苦的 但是老师人还是很和蔼的',4,2,4,10,0,0);
INSERT INTO "reviews" VALUES('5b38adf32f301e0035a20f74',234,256,'讲课非常细致 会提醒我们不要玩手机好好听课 她会把每个知识点都讲清楚  真的很喜欢她 每一个上过她的课的人 都会感激她对学生的责任心',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5b38ad5d9f54540035898a6f',785,114,'我大一的高数老师 真的很好 很负责任 讲的也很清楚 平时分只要交了作业都是给满分的 真的很感激他',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b3592b2ee920a003a0c3fea',785,229,'真的真的非常负责认真，甚至牺牲自己的时间给同学们免费补课，可以说大一遇到这样的老师是幸福啊',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b34773e9f5454003a9bf03e',4784,641,'从来不讲课，上课提了要求就是让我们做实验，实验要求还经常在中途改，
INSERT INTO "reviews" VALUES('5b346fc19f5454003cd95018',416,34,'大爱张跃老师',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5b34571b756571003cd1b32d',14084,27,'人很好，期末给全班加分，不过该扣都会扣。有点婆婆妈妈（自嘲），会为学生着想，不过在她课上挂了就别想再去了，她也能记住所有人，所以想逃课的就散了吧。
INSERT INTO "reviews" VALUES('5b3447e1756571003cd12a71',4003,10449,'蔡老师很好，讲课很清楚。关键还很漂亮。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5b343f6a9f5454003a9a10fa',27,28,'挺亲切的一个老师，听课比较轻松，作业不多，而且老师经常交流作业完成情况',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5b343ef12f301e006006f442',334,562,'听不懂讲的啥，一来就开讲，自己讲自己的，完全不与学生交流，作业要求还非常高，有挂科风险。',4,2,2,8,9,0);
INSERT INTO "reviews" VALUES('5b343b51ee920a003c598da4',1394,230,'认真听讲会有收获很多干货，民族归属感与自豪感油然而生，很好的一位老师',5,4,4,13,4,0);
INSERT INTO "reviews" VALUES('5b3427f82f301e0060063e2b',18,18,'讲课认真，平时分给得高，他还提供很多次机会让你课堂表现分直接满分，估计一个班八九成同学课堂表现是满分的，作业给分也高。忌讳的就是:翘课，没交作业，迟到，坐后排。坐后排的可能会被提问，迟到的进教室比较麻烦，作业交了话不管写的好不好都给分很高，但没交就给分很低。',5,5,5,15,20,1);
INSERT INTO "reviews" VALUES('5b33b37d9f5454003a97eb4b',10955,3509,'她在说什么你永远听不懂，p事还多的要命。',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5b33b337ee920a003c578de7',903,179,'康姐姐从来不考虑听不懂的人，哒哒哒打机关枪一样的语速',4,1,5,10,0,4);
INSERT INTO "reviews" VALUES('5b33aba1ee920a003c576209',416,34,'张跃老师真的太赞了！每节课都特别有意思0.0感觉大学里有这样的老师真的太不容易了！',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5b33a57a9f5454006bb2a5d0',913,611,'女神超好看超温柔的！口音也超棒！就算全英文上课也没有太大的障碍。不过她真的很不擅长做绕来绕去的题目呢，讲题目也比较枯燥哈哈，所以她很少讲题目哒。不过我上的是高级英语A，不是英语三。',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('5b3393342f301e006003e689',811,762,'老师认真负责是真的，并没有一些人说的那么不堪。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5b3392569f5454003cd49ca9',13254,229,'老师认真负责，是真的好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b3391749f5454003a96fe3e',11887,12577,'从不点名，作业选做，真性情。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b334deafe88c20060ac4dd0',385,28,'比较严格，平时分数就是考试+听写之类累积起来。不背课文分数就会很低。上课有时候就是翻译课文，感觉学不到什么。趣味性低。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5b326c2fac502e0031e0243b',9984,2815,'孤儿老师…不想多说…不要选…忠告',3,3,1,7,3,4);
INSERT INTO "reviews" VALUES('5b326bb12f301e00356495ff',737,394,'水…上课啥也讲不出来型…要编程…不过给分确实高',1,2,2,5,2,0);
INSERT INTO "reviews" VALUES('5b3225b82f301e00356221c0',2119,3019,'电机课上得最好的老师，没有只有！
INSERT INTO "reviews" VALUES('5b30a9619f545400352a1e32',3025,5119,'文档太多，上课讲知识时穿插的重复的话太多',1,1,5,7,2,1);
INSERT INTO "reviews" VALUES('5b2f9e6367f356003453dc51',416,34,'老师真的太太太太赞了，怎么没人评价？可以说是交大第一好的老师，讲课生动幽默，可惜只教大一啊，我好想大二也报他的课，哭死',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5b2c853fa22b9d003a7c55e0',246,228,'我这次评价只想尽量的公正，康老师上课的确很认真，这是无可非议的，但是讲课水平以及思想深度实在不敢恭维，作为马克思主义学院的老师，对其理解竟然也仅仅是在照本宣科，讲课也完全没有逻辑，感觉全是把一些官话，套话讲给我们。如果你是想真正学习马克思主义原理的建议不要选他的课，如果是想得高分的，想水的建议也别选他的课。他对学生的态度很不好，每节课都要抽大量同学来回答问题，答错扣分，平时测试也很多，感觉他的心胸比较狭隘，之前在上课的时候误解了一个学生，自己又不想承认，上课的时候就专门针对这个学生，抽他起来回答问题，故意刁难他。总之不管怎么样，都建议别选康厚德。',1,1,1,3,18,0);
INSERT INTO "reviews" VALUES('5b27ad4b44d9040030b5484e',478,2570,'没见过这么坑逼的老师，就这个老师屁事多，同样一节概论水课，别的老师要求期末交个感想。她呢？又是搭房子，平时又是每周一大篇论文，******还让你双休日跑到地铁站火车站去拍照片写论文，怕不是******吧。选她的课，你就别想学到什么东西了，想水？更是别想了，就折腾吧，到你怀疑人生为止。',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('5b22141fac502e003174e853',13254,114,'我超级喜欢何老师，手机里面太多他的表情包了，特别负责，可以专门找时间给你答疑或者帮你补补课，不过马上小何就要退休了，特别不舍，很感谢何老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5b02380567f356b38bdff127',8371,3098,'上课抓不住重点，表达能力差，照本宣科，双语授课直接当成中文授课，全英文考试。点名狂魔。没有激情。',1,1,3,5,4,0);
INSERT INTO "reviews" VALUES('5afe1c03ac502e3c23d99ec7',68,40,'神马玩意儿，我去！差评差评差评！！！！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5af437932f301e4370b971fb',2072,22,'超级超级好老师 很好说话 为人亲切 长得很帅（划重点） 从不点名 上课只要不扰乱课堂都不会管 考试只要掌握课件上的就好 结合课本再认真完成作业考试绝对高分 期末考试给分很给力 费尽心机给及格 爆灯推荐',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5af435c52f301e4370b96032',2992,6194,'课件和教材都讲解的很详细 老师带点口音说话不太听的清楚  作业不多 经常会讲和专业相关的知识 考试划重点超级详细 很幽默',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5af43494fb4ffed7759aa16f',10878,10878,'上课进度贼快 基本就是过ppt 表达不清不楚有很枯燥 要求很多 作业会留很多论文 基本每节课都点名 调研会有',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('5af433527f6fd30038a1b64a',706,706,'老师学识渊博 上课会发散 很有趣 点名很少  期末考试特别坑 什么重点都不划 看书没用得看课件',5,4,4,13,0,1);
INSERT INTO "reviews" VALUES('5ae477fd0b616000758997a8',12627,2793,'老师专业素养很好，但是总是留一些乱七八糟的作业，找也找不到，查也查不到，而且非常教条死板，绝对是一个事逼，千万不能选他的课！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5ae30d96ee920a0043065ce0',51,1346,'水，啊，想水的就来，有一次课堂展示，50percents.考试，50percents，没有最水，只有更水，想水的同学，你值得拥有！',1,1,5,7,8,0);
