INSERT INTO "reviews" VALUES('5aaf25f79f5454003762c6a4',8040,185,'迷之板书，仿佛一坨翔糊在黑板上，令人不忍直视。推到能力极差，朗诵ppt，自己都不知所云。吹牛倒挺厉害的，渣渣！',1,1,1,3,0,2);
