INSERT INTO "reviews" VALUES('5aa537dd44d90400440e71c1',14148,40,'之前上她课 让我们讲ppt 特别喜欢打断 我的ppt是由双十一导入网购 不过讲到双十一她就打断了 说要大标题引人注目 第二页讲到大标题 她又打断 说这样好 大概就记得这老师超级爱在别人讲ppt的时候打断别人 给分也不高',3,3,1,7,0,0);
