INSERT INTO "reviews" VALUES('5a6e9e6d0b616000443f681f',2298,394,'优点：1 讲课认真；2 给分细则明确；3 对待发言多的同学加分不少。
INSERT INTO "reviews" VALUES('5a6e9c4fac502e005cd39338',703,228,'优点：1 上课按大纲来，不水，认真听的话确实对提高姿势水平有好处；2 勤查邮箱，需要联系老师的时候可以直接使用教务邮箱联系；
INSERT INTO "reviews" VALUES('5a6de4fa0b616000443c1024',293,375,'老师讲课很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a65d35cd50eee1ad920c1b3',449,3822,'声音甜美，讲话温柔，给分大方，作业略多(可能这个课都这样)没有录音就有讨论或者辩论 不过随便水一水就能过 上课爱抽人回答问题，如果积极的话还可以加很多分',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('5a65d067d50eee00455a1f05',12218,762,'书本内容讲得不是特别详细，大多通过例题解释公式，课上会讲很多例题。就是声音有点小，在没有麦克风的教室第五排都吃力，板书书写太凌乱，板书的书写速度太慢，讲课风趣幽默，平时分挺高的，不爱点名都是抽点很少一部分。作业超级多',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('5a61fb329f5454008f655693',198,179,'好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a604b521b69e60066dc91eb',12218,762,'曾老师是我上过的最好的概率论老师了（本人修过两次概率，略做对比），曾老师上课从来不用ppt，都是手写的板书，而且例题很多，更容易对知识点理解，里面还有很多考研题曾老师也会耐心讲解，总之曾老师讲的真的是非常的好，推荐大家上曾老师的课，很值，最后的分数也不错，选曾老师平时分完全不用担心！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5a5d6b637565710044fb6f4e',6,619,'平时成绩大片七十多分，与之对比的其他班却是很多直接给95,100，或者是给加分机会，这位老师基本没有
