INSERT INTO "reviews" VALUES('5a585ea10b61600043e53d4c',9297,884,'陈老师人挺不错的，但就是有一个问题说话真的是太不清晰了，感觉超过前三排就什么也听不到了，这算是唯一的不足吧',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('5a585e2bee920a00581a5a3a',2612,859,'叶老师真的是超超超超超级好，上课讲的很清晰，也很好理解，平时也会留作业但真的不多而且挺简单的，期末还会划重点，给分也是很可观的，总之是一个超级好的老师，规划原理一定要选叶老师的',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5a54d7aed50eee066815cb41',826,26,'我不知道为啥有些同学不喜欢老师的川普，我就特别喜欢😍 ，可能我是四川人吧。老师讲数学思维活跃，我觉得这就是数学课应该有的氛围，为啥总是要按照书本上的例题一步一步照着念。上大学最喜欢的老师哈哈，最后老师分给的也挺高的，95，虽然不及某些大佬那么牛逼，但是我很喜欢夏老师，我要为夏老师正名！',5,5,5,15,1,0);
