INSERT INTO "reviews" VALUES('5a405f6f0b616050142ddad6',101,114,'樊老师上课真的超有趣，课也讲的很好，而且非常的负责，真的好庆幸我们的优学课老师是樊老师哈哈哈哈，总得来说就一句话，要想学好高数，跟着樊老师走一定没错',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5a3df159d50eee44b17e1d1d',2579,2579,'老师很好 学校唯二的俄语老师(另一个是叶老师的丈夫 哈哈)  老师在俄罗斯留过学，想了解俄罗斯文化风情的强烈建议选这门课',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('5a3d433275657100437a247b',8147,114,'有口音,但是讲课清晰,上课会结合例题,偶尔抽人回答问题（反正我没被抽中过）有过一两次全体点名。',5,4,5,14,1,0);
