INSERT INTO "reviews" VALUES('5a3d11f71579a300413981e0',2323,448,'老师十分博学,表达能力很强,亲和力十足,对待学生很热情。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5a3cc32f570c350032fb7cd5',1608,641,'总的来说还算不错,专业水平有目共睹,就是上课太严谨了,教学氛围比较压抑,很僵硬,其他的还行。',4,3,4,11,0,0);
