INSERT INTO "reviews" VALUES('5a3a5b9867f35600610fa4d0',2202,28,'老师亲和力很强,英语教得很好,上课生动有趣。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5a3a55851579a3004129683b',8081,14232,'留给学弟学妹一个忠告，千万别选这节课。一学期点名11次，4个平时作业，1个期末总结，还要2000字。我真是无fuck说。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('5a3a52af44d904003783f69c',13496,28,'慈祥和蔼,上课认真负责,生动有趣',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5a3a491217d0090037c9ce4a',13736,114,'刘秀峰老师讲高数特别详细与仔细,为人特别亲和,虽然讲课速度很慢……虽然他说的话我们几乎一句也听不懂……但确实是个好老师',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('5a3a4190570c350032ed2276',13736,114,'这老师讲课讲不明白,口齿不清,拖拖拉拉嗓音忽高忽低,字丑看不懂,从不用PPT',1,1,1,3,0,2);
INSERT INTO "reviews" VALUES('5a392ac1128fe1004492e318',2984,361,'对地铁感兴趣的同学，或者真正想从选修课里学到些什么的同学，强推这门课(现在这种真正有意义的课已经很少了)；如果只是想换个地方写作业或者是为了凑通识限选课，建议不要选。
INSERT INTO "reviews" VALUES('5a3903f017d0090037c38e28',1332,188,'标哥真是用生命的激情在上课，成都九月酷夏，因为噪音太大听不清讲课内容关掉风扇，下课路过讲台才发现标哥衬衣全湿。上课还会读他大学和研究生的日记，故事很多，讲着讲着就拉不回来了（扶额）总之对上课很有激情，对思政很有理想，感觉标哥找到了人生真爱（逃）',3,5,5,13,8,7);
INSERT INTO "reviews" VALUES('5a38d46afe88c20063a9097e',9351,5,'秦老师很好，人很瘦，但是精神矍铄，对学生很负责任，就是作业巨多，不过也是为了大家的成绩。',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5a38c8d817d0090037c15ace',13736,114,'这位高数老师知识渊博,水平极高,有丰富的知识底蕴,具有各种解题方法,思维敏锐,对学生态度温和,负责,就是表达能力有限,听力不过外语四级很难听懂QAQ',5,1,5,11,2,0);
INSERT INTO "reviews" VALUES('5a38b4ebfe88c20063a7f45b',3477,1170,'非常好的老师,大学高中无缝对接',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a38a2a275657100435ed8b0',13736,114,'耐心,幽默',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a37fccb75657100435ad062',3477,1170,'宋老师上课层次清晰,容易理解,积极回答学生问题,待人亲和。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a37bb66fe88c20063a1d238',14243,5828,'每节课必点名,还有周计划,年计划表格,每堂课还要小组人员上去发言,超级认真。',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('5a377dfdfe88c200639f8b6c',311,1346,'唐老师上课很热情,并且整堂课都面带微笑,讲得也很好,人也很温柔。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5a3777a517d0090037b7c811',1106,1106,'这个老师偏心特别严重',3,1,2,6,1,0);
INSERT INTO "reviews" VALUES('5a376e58d50eee44b157d74c',433,27,'很水，教得还行，感觉不是很认真负责，节节课点名，但是来了以后你干啥她都不管，口语........不太接受得了，上课讲英语也讲的比较少，总体来说比较无聊ヽ(ー_ー)ノ大家的平时分都差不多，给分不高',1,3,4,8,1,0);
INSERT INTO "reviews" VALUES('5a376d770b61604a10e899d1',13643,5924,'老师很亲和，上课气氛很轻松，很舒服，课水不水取决于自己，认真的话要看的书很多的，但是还是很有意思',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a376cbf7565710043565c1d',9351,5,'老师太棒了，讲课讲得真的好，又耐心又负责，超级棒！我都觉得自己学不好活该，给秦老师打call！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5a376c1d17d0090037b7494d',1377,26,'我觉得老师挺好的啊，虽然有点迷迷糊糊的，人还是很好的，解答问题也很耐心，不怎么严，偶尔会有意想不到的点名，作业也不多',4,3,5,12,2,0);
INSERT INTO "reviews" VALUES('5a376be6d50eee00788d6129',13923,114,'我们的线代老师，有一次代我们高数课，竟然比我们高数老师讲得好多了。很幽默，呆萌。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a3766b80b6160006ae3fb8a',1332,188,'讲的很好但。。。有点不切考。。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5a3754b1d50eee00788c6f0b',626,175,'比较好的老师，温柔不发脾气。  课比较好过',4,4,5,13,0,4);
INSERT INTO "reviews" VALUES('5a375408e696c9003748b610',311,1346,'非常亲切的一位老师。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5a373f3ee696c9003747f6e9',480,92,'老师人真的真的超级好，管得不严，很随意，反正我很喜欢',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5a373eb77565710043548a5d',1048,114,'老师很友好，至于课嘛，反正我没认真听，不知道讲得咋样',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5a37023b0b6160006ae06df0',13795,13795,'表示是在MOOC上了解到的这门课，老师们讲得还不错，特别是讲解了许多我看过的书，虽然MOOC上的考试也有一点难(；一_一)',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a368a9217d0090037b1bcd4',8295,2461,'这个老师专业能力还不错，但个人行为很古怪，总留一些乱七八糟不着边际的作业，而且现在教了茅班的詹班以后天天想着比比茅班和詹班那个厉害，然后出卷子也特别难，给分也特别低，别的班期中开卷他闭卷，别的班没课设，他有课设，而且课设内容他还不讲，绝对是一个神坑！！！',3,1,1,5,2,0);
INSERT INTO "reviews" VALUES('5a3685d1e696c90037440a4c',2646,2960,'一开始觉得他水，但是认真听了之后，真的受益匪浅，平时学的也很轻松。很和蔼可亲',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5a3684c0128fe10044802cac',1536,14075,'以社交现实的视角讲授中国哲学的见解立场,宣扬一种中立而包容的中国哲学价值观。',4,5,5,14,2,1);
INSERT INTO "reviews" VALUES('5a365ec7d50eee44b1510332',14260,641,'上课照本宣科,课程枯燥无味',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('5a3657b80b6160006add23f0',14261,114,'上课就是快速翻ppt也不管听没听懂 自学吧',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5a365687fe88c2006397df12',247,27,'为什么要有这么对大多数人无实用的听写？',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('5a36196f0b61604a10df9ca1',6060,6060,'只有第一节课或第二节课点名，作业少，很有趣，大一上唯一喜欢的专业老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a3618d31579a300410d8992',14264,394,'我们班选课大部分都想换了这个老师，所以，你懂的，人格魅力欠缺，不过作业少，经常点名',3,2,4,9,2,0);
INSERT INTO "reviews" VALUES('5a36118a128fe100447c923e',2984,361,'真的不怎么样，大家说这门课水，结果我就呵呵了，别选这个课',3,3,1,7,4,3);
INSERT INTO "reviews" VALUES('5a3608cf1579a300410cec1c',27,28,'别的不说了真的不错',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5a36043575657100434c73f4',535,535,'听不清讲什么。。。一直说很简单很简单     呵呵',3,3,3,9,3,0);
INSERT INTO "reviews" VALUES('5a360328fe88c20063951409',2047,27,'老师挺好的，',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a35f2eed50eee007882c819',1377,26,'自己迟到，还让我们周末补课！讲课一般，基本自学，就是念ppt',4,3,3,10,5,1);
INSERT INTO "reviews" VALUES('5a354c6fd50eee00787edbd7',378,14270,'辣鸡，不要选，每次让人看十多个小时毫无营养的课程。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5a3540c10b616000441dcffb',1353,1353,'这是这学期收货最大的课，真心不错，老师很认真，会教给你真正受用的东西，会提示自己的思想高度。最适合情商过低的人选，会学到真正好的知识，',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5a353cb6e696c900373adce7',8566,114,'超级喜欢田老师，人超好，感觉要不是他自己会很堕落，讲课只要认真做笔记就好了Y(^o^)Y强推',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a353581e696c900373aaecd',1168,228,'超级好的老师！平时分给的很高而且很好商量，上课会放一些视频，觉得比讲课好玩……推荐推荐，还会给期末复习大纲！',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('5a353512128fe1004476b02a',2654,1225,'口语是所有英语老师里数一数二的了！上课也是按教学大纲就这么下来的，很认真。听着声音就很舒服好吗！给分目前还不清楚，英语基础好的强烈推荐',5,5,5,15,1,7);
INSERT INTO "reviews" VALUES('5a3531260b616000441d6b4b',2202,27,'老师人非常亲切和蔼,教学方法很棒',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a352dba75657100434707db',9120,92,'谢宁老师真的属于那种懂得很多但不知道如何正确教授给学生的那种。举个栗子，他上课的时候经常会举一些实例来解释一些理论，但常常是八竿子都打不到的比喻。而且刚上他的课的话，可能会跟不上他的思维，但只要适应了，就会发现能学到很多。而且点名也很水，会提前通知的。作业的话会布置一些网上作业。所以，是一个值得推荐的老师（如果你能适应的话）。',4,3,4,11,4,6);
INSERT INTO "reviews" VALUES('5a3528ac0b6160006ad4d206',247,28,'听写，推挤成山的听写，不想说了，难受',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5a34fcaf756571004345345c',2579,2579,'选修课，非常轻松，平时没有作业，但每节课要签到，期中期末都是开卷考论述题。第一讲讲俄罗斯相关知识，第二讲看电影。',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5a34cd431579a3004103e0ef',11065,11065,'范老师是一个非常好的老师，上课很轻松，想学的话是可以学到东西的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5a34c11a0b61600044196854',696,698,'（通识课）基本没讲专业知识，讲的都是如何做PPT，外加论文的文件',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('59fa6b24fe88c2006de804ba',13736,114,'上了他一年课点了一次名。听他讲课很想睡觉，给分很高，平时给满，不听课的同学很适合选，比如我。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('59c8556efe88c2003c0adf8b',380,601,'其他都还凑合，就是口音有点迷。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('59c854ea67f35600427ac617',1596,1596,'上课极其无聊，没有一次不拖堂，打铃下课对他而言是不存在的，下课了还要同学边走边做题，十五分钟之内在一个公众号上提交，全靠念ppt讲课，太一般了。',3,3,3,9,4,0);
INSERT INTO "reviews" VALUES('59ba447bfe88c2005741f6cd',4247,1007,'非常阔耐的一个老师，说话讲课很有个性，强调自觉，不过多要求学生，待学生好。经常把萨老师，曼老师挂在嘴边',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59b9f1e0ac502e0060f553c0',14285,14285,'一个会说希腊语的老师。要求严格，特别是论文，要求十分严格。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5976ac941b69e6006c409631',2740,2735,'老头儿讲课从不用ppt，一节课满满两黑板的手写板书。虽然有老教授的遗风，但英国留学读博回来的老头跟年轻人交流毫无压力。
INSERT INTO "reviews" VALUES('59762c2e128fe155ce7e9e64',887,23,'老师认真负责，每节上机课都在解答疑问，平时很严格，给分高(＊／ω＼＊)',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('59762b7861ff4b006c7c99bd',9443,10930,'炒鸡爱童童啊o(*////▽////*)q',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('596b16a08d6d8100576a1b2d',9062,23,'期末98平时分97 老师讲课非常有趣 例子很多很容易听懂 人风趣幽默 强烈推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5965e81f61ff4b005792c30e',489,24,'一句话：能选别人就别选她。理由？当然是为了自己好。
INSERT INTO "reviews" VALUES('5961fabe0ce4630058100767',14291,7794,'课堂教学质量较差,比较水。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('5961e220ac502e00581bad56',2377,322,'上课老是让拍PPT,每节课都要写一大堆字',3,1,1,5,0,1);
INSERT INTO "reviews" VALUES('5961cdbb128fe10054b5a458',2202,27,'老师生平经历很丰富,视野很广阔,我们学习到的不只有课本上的内容还有很多其他有意思的东西。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59619142ac502e00581740ec',2602,653,'点评犀利,会把你的方案批的一文不值,心情阴阳不定,不过上课还是会讲一些对专业有用的知识。',4,3,1,8,4,1);
INSERT INTO "reviews" VALUES('596141db2f301e0064ad1a92',891,114,'陈老师上课很棒啊,怪只怪自己学不会啊。很喜欢这个这个老师呐,下学期也要跟着学哦,希望这学期高数能过,阿门',5,4,5,14,0,1);
INSERT INTO "reviews" VALUES('59611e3a1b69e64c8d0db2b5',891,114,'老师讲得不错,速度适中,也很有耐心,尽职尽责,总之是一个特别可爱的老师。但是！！不知道为什么我的高数就是及不了格？？！！OAO',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59610b005c497d00638b6634',12757,8460,'通识课，不水是重点。平时分占70%，包括课堂测试，两次网上作业，期中网上作业，还有出勤。期末30%做一套卷子。老师讲课很接地气，专业能力强，只要你平时上课认真听一听，收获是很大的，作业和考试也不难，拿90+并不困难。但如果想混过去，一定会挂科的。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('59610a890ce4630058066da7',3670,13665,'不怎么讲课,一味让学生讲,作业说不清楚,但又要收。',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('596108f5ac502e0058134aad',2646,2960,'老师很好，专业能力很强。讲课比较高深，经常听不懂，但针对考试足够了。老师师生情很浓，挂科的人很少。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('5960ca8c2f301e0064a847ea',8265,114,'老师讲课非常非常快,不会管你懂没懂,上课前请预习≥20页。',5,4,4,13,2,1);
INSERT INTO "reviews" VALUES('5960994f570c350058bc4b8b',68,68,'人是真的凶，一点别的英语老师的亲和力都没有，而且给分超级超级低',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('595fa550ac502e006bbf709c',4784,641,'因为上课完全不讲，所以全部一星。不评讲，不指点。
INSERT INTO "reviews" VALUES('595ef2b0a22b9d006b64f103',14303,14303,'谢老师是位资深教授，理论力学知识十分深厚，上课极少用ppt，主要课程内容都是板书，谢老师上课主要以讲解各种例题的形式来阐述方法、概念等，他讲课主要是讲题，这一点就要求学生自己上课前一定要预习，要事先把教材概念搞懂。谢老师一节课讲的题很多，而且讲的很快，思维跳跃性有点大，讲的都是经典题目，有一定深度，预习了概念都不一定能全部听懂，更别提没预习的了，那将会是一头雾水，不知所云。作业是自己去网上下载打印，然后做完后定时交给助教，作业题目老师是不评讲的，有问题自己去问。总之，老师很有耐心，脾气很好，从不发火，如果你认真学，那么你会学到很多。如果你不认真听讲，得过且过，那么你什么都学不到。',5,3,3,11,2,0);
INSERT INTO "reviews" VALUES('595d37dc570c35005895e5cb',1453,114,'诙谐幽默,可爱呆萌',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('595cf6efac502e7589e3e52f',14305,14305,'大牛啊！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('595cd2468d6d8100570f6bd6',13988,26,'薛老师是我大学遇见的第一个超级好的老师。很幸运选课时押了大权重选到了薛老师的课。上第一节课就觉得这老师我选对了。薛老师讲课重点非常突出内容精炼明了，重点和易错点会再三强调，板书工整都是主干内容，例题非常贴合知识点且非常具有代表性和覆盖性，很特色的老师每节课上课之前都会提问默写上节课重点内容带领回顾（看到了我高中班主任的影子），考试前都会带着复习，很细心负责任还会根据考纲给我们出一套模拟卷子，没有口音声音很洪亮很有底气听她的声音很舒服。薛老师非常非常亲切和蔼，很慈祥的老奶奶。选她的课只要上课听讲例题会做课后作业都认真做完九十分肯定有的。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('595ccf161b69e676a1d37e50',2202,27,'老师可好了,上课很有趣,超亲和的。喜欢?',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('595ca5205c497d00589a0202',1453,114,'普通话极其不标准,作为非四川人真心听不懂,上课太爱扯皮,但是挺有意思的。',4,3,5,12,1,1);
INSERT INTO "reviews" VALUES('595c73a5128fe10058678158',1768,92,'来客观评价一下钟老师吧。在选课时就听说钟老师可以称得上是交大第二好的大物老师了，讲课确实很棒，专业技能非常深厚，很有条理重点突出，她的总结非常棒，但就是讲的太快啊。。另外，私下接触钟老师的冷漠实在让人心寒。早先听闻钟老师给分不错，可结果却让人大跌眼镜，就连四大名挂的曾勇平时分都几乎给满了，我平时兢兢业业才给我六十。。。exm？？！？',5,4,2,11,2,1);
INSERT INTO "reviews" VALUES('595c2e22ac502e006b971cca',785,114,'男神老师非常好。教学生动，能带领同学复习。进大学以来最喜欢的老师没有之一。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5959bd76ac502e006b7a0c48',831,14311,'这个老师大家小心哦，经典案例有个同学最后考试迟到十五分钟，这老师死活不让进还说，没事这次出的难，反正在里面的人也不见得能及格。
INSERT INTO "reviews" VALUES('5956288dac502e006bd38fd8',18,18,'很有活力，与同学关系好，认真负责',4,5,5,14,4,0);
INSERT INTO "reviews" VALUES('59545fba570c357d06d73c1a',13496,28,'这课上的真的是没谁了,上课前二十分钟一句话不吭,底下人基本玩手机讲课啰嗦且教师本人心机太深,千万不要选她的课！世界上没有后悔药。',3,3,1,7,2,0);
INSERT INTO "reviews" VALUES('5953f504128fe10065555114',459,68,'老师萌萌哒！一股台湾腔！特别爱笑总跟我们开玩笑(˶‾᷄ ⁻̫ ‾᷅˵)给分也超级高',5,5,5,15,1,7);
INSERT INTO "reviews" VALUES('595082daac502e006c855da6',416,1281,'不多说，程序员之路的引路恩师。如果大一没有他的第一堂c语言课，也许我压根不会对编程产生兴趣。感谢张跃老师，一个可爱的小老头。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('594df7995c497d005cbadc5e',13736,114,'老师真的教的很好。你们好好学。我高数大一上98',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('594b74e5b123db005db79291',9443,4500,'上课风趣幽默,知识面广,气氛轻松,与同学交流很多,平易近人,很萌的老师,当然,一切都建立在能听懂那奇特的口音之上（手动滑稽）,总结,好老师。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('594b5f180ce46300574469b0',9443,4500,'老师上课用生动活泼的川普带领我们走进无机化学的世界,喜欢童老师。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('594ab3f3a0bb9f006b1519db',9443,4500,'被他记住就倒霉了,因为他会一直点你回答问题,而且问题很坑爹',3,5,5,13,2,0);
INSERT INTO "reviews" VALUES('594a7faeac502e006bc49f43',1453,114,'普通话不标准,上课时经常跑题,喜欢讽刺社会现象,很有想法,还很毒舌。',4,2,3,9,0,0);
INSERT INTO "reviews" VALUES('594a5a2dac502e006bc2d07d',1230,1267,'几乎每节课都是做个心理测试就结束了,但是老师会让参加的小组上交名单,只有参加了的才算到了,不公开点名。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('594a3e0cac502e006bc1847f',13795,521,'几个老师合着讲的,其中一个翻译的老师讲得很好,另外期末作业给的时间很短。',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('594a23caac502e006bc059db',4119,4119,'好 好 好 （重要的事情说三遍）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5949fbb5ac502e5490f75379',14324,394,'讲课轻松,爱吹牛,评分较高',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5949d184ac502e5490f5865f',8328,230,'上课认真,讲解仔细,考试较难,作业打分高。',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('5948eb2fa0bb9f006bf42b7d',14326,3628,'课程专业性强,知识量大,有点枯燥,不想背专业名词的英文,我英语不好,不要为难我,我们真的承受不起！TAT',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5948d03aac502e006bb4cc5c',3628,3628,'非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5948b905ac502e006bb3b643',2172,10614,'课堂内容很有趣,拓展很多,PS 老师的川普很标准。水到疯,大家快去抢吧！',5,4,5,14,3,4);
INSERT INTO "reviews" VALUES('594882a461ff4b006c02133a',2047,28,'老师很和蔼,挺有亲和力的,就是觉得作业有点儿多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5947a10da0bb9f006bdc2a9f',2484,92,'老师真的人超好啊
INSERT INTO "reviews" VALUES('5944400561ff4b006cdcd014',909,14331,'上课容易说错,表达能力不是很强,听课效率差。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('59442857fe88c2006a6b4306',14332,241,'孙老师上课以读PPT为主要形式,无其余内容,作业量巨大,并且对作业评判仅依靠个人心情。同时,孙老师向班上同学售卖自己编写的书籍,购书少的班级须多次重写作业。',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('59441596da2f6000676a825c',11226,14333,'老师创造很好的讨论氛围,提高了我们的表达能力,和制作PPT的技巧',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5943e7dcda2f60006768c10e',3628,3628,'罗老师为人和蔼可亲,耐心为同学讲解问题,是难得一见的良师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5943aeab128fe1006a2bf3d4',326,36,'老师讲课比较有意思就是听得人较少。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('5943717e8d6d810058d12466',13845,114,'认真负责,有时讲错。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('59433901ac502e006b80eaca',915,250,'老师很和善,讲课也很清楚,作业也是划题有重点地做。最最重要的是平时测验和大图给分很高,手画大图最低60,唯一缺点是课件不给拷',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('59429fe1ac502e006b7c4539',14324,394,'上课水,作业不多,喜欢创新、吹牛',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('59428812fe88c2006a5a80b3',2885,3822,'******别选她的课，作业多，期末考口语给分好低。还不好说话',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('59427e20ac502e006b7a5a7b',8328,230,'要买书,期末考题从她的书中选 上课照本宣科枯燥无味时而点名回答问题',4,2,4,10,1,0);
INSERT INTO "reviews" VALUES('59423883ac502e006b76b8ca',13988,26,'非常可爱的数学老师,资源很丰富,没选她的课的人也可以去长虹雪苑逛逛。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59421ef5ac502e006c598c39',9443,1170,'上课时,幽默风趣,课堂氛围好,一句话,嗨到爆炸,课堂上也学习到了应用的知识。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5941e984ac502e006b72c422',250,250,'老师,我真的看不见你PPT的内容,你可以改变一下字体颜色或者背景颜色吗？',4,3,2,9,4,1);
INSERT INTO "reviews" VALUES('5941084461ff4b006cba6c52',8453,114,'工作认真尽职尽业,讲课条理清晰,生动,通俗易懂。',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('5940e11f8d6d810058b500b8',210,28,'绝不是一门水课,课堂内容很多。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5940a9915c497d006bb0d378',210,28,'备课很认真,亲切和蔼,但是作业有点小多。总的来说很不错。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5940a2258d6d810058b1f6a6',246,228,'选了就知道 cannot hold',2,1,1,4,9,0);
INSERT INTO "reviews" VALUES('593fae89128fe1006a0025a8',250,250,'用90年代的PPT来教育我们新世纪的大学生,并且从来只是对着PPT随便一讲就以为我们都懂…………',5,3,4,12,9,0);
INSERT INTO "reviews" VALUES('593f9484da2f6000673a3bb7',14349,14349,'真的能学到很多东西。能够结合很多案例来进行讲解。经常还会放一些心理访谈类似的片子。很多异常心理我们也能发现身边的人具有。因为到的人不多，经常让写名字下课前交上去就行。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('593f93498d6d810058a67684',1938,2375,'上面哥们说的我就不说了，我觉得要想来学工业设计的恐怕要失望了，很多东西都上升到哲学上面了，所以对理科生启发不是太大？课堂形式多样，经常有很多其他的老师来上课，还去看了岩石标本感觉还比较好玩。',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('593f9236128fe1006afeacea',4925,4925,'每节课需要提前抢位置。很好玩，经常放柯南啊，包青天啊，大宋提刑官啊。六一还发礼物。点名只点上次到了的。期末一篇论文就行。要学还是能学很多医学知识的。当然了，法医。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('593f915d8d6d810058a65ced',14352,2158,'老师有时候有些字念错了哈哈。这门课内容就是人教版生物必修部分。作业的话，一次讨论课，一次调查课，一次翻转课堂，一次观察报告，总的来说不少。平常上课听的人不多，有时候放纪录片也很好玩。老师人也不错，认真学的人都有单独加分。一学期签到三次。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('593f9060128fe1006afe96ca',1596,1596,'没有人评？不科学啊。上课没有几个人听，下课拖堂。QQ群里面匿名之后下课前很活跃。现在在尝试雨课堂，上课用手机答题。不知道算不算点名。除此之外无点名。作业物理老师都一样。期中考试全是原题。',5,4,3,12,3,1);
INSERT INTO "reviews" VALUES('593f8d7d8d6d810058a62be4',1732,1264,'上机可到可不到，不点名。实验做完就行。回去也可以做。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('593f8ca8da2f60006739ce77',1732,7616,'人挺好的。上课中规中矩。倒数第二节课点名，坐在边上和最后上课可能被抽问。作业不多。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('593f8aa5a0bb9f006b670b2b',14356,1131,'崩了崩了，点评的没提交得重新写。老师很强，可百度。那个上课很严，不许玩手机，不许睡觉，不许上厕所。作业一开始巨多，后面就几分钟就能做完。期中考试五道大题，还是六道。',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('593f874afe88c2006a388e3b',4784,641,'上课的时候不会讲太多，念下PPT，看下例程，其他的让百度。助教说老师教本科生很随意，但是本人很厉害，在软件谷有公司。至于课嘛，固定位置，有时候迟到要登记。期中期末分别提交一次报告，以及一次考试。没有书面考试，实践考试。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('593f7f6cda2f600067393167',716,729,'总的来说,非常不错,我很喜欢',4,3,4,11,1,0);
INSERT INTO "reviews" VALUES('593f3d5261ff4b006ca578c0',867,28,'授课能力强,知识点表达清晰,乐于听学生的问题并用以提出建议。',5,4,5,14,2,2);
INSERT INTO "reviews" VALUES('593f063d5c497d006b9f11ca',13991,2254,'人好,很可爱,上课轻松,无期末考,交论文即可。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('593ee9e05c497d006b9e90b9',2202,27,'人很温柔,个人专业素养很高,平时讲课的方式很特别,生动而有吸引力。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('593ebe46128fe1006af765bc',3925,5,'教学很认真负责,乐于为同学讲解疑难并会额外抽时间为我们基础较差的同学补习。',5,4,5,14,0,1);
INSERT INTO "reviews" VALUES('593e87e4ac502e006b4f2654',14363,542,'老师很和蔼',3,1,5,9,0,0);
INSERT INTO "reviews" VALUES('593e63cb5c497d006b987e08',716,729,'不明觉厉,在后面睡觉玩手机很好,容易被吵醒',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('593e498a61ff4b006c9c31ad',1738,230,'老师讲课认真负责,历史积淀深厚,每次讲课都引人深思,让我们对历史认识又更深见解,作为一个历史爱好者,这位老师的讲解虽不能满足我对历史的渴求,但绝不会让我失去对历史的兴趣,很喜欢她的课。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('593e0af4ac502e006c0615c8',716,729,'讲课枯燥,但是很恐怖,动不动就要让我们挂科。笑起来有种渗人的难受。',4,3,2,9,7,1);
INSERT INTO "reviews" VALUES('593df20dda2f600067289dc9',716,729,'总体来说,挺好的了。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('593d6c77da2f600067259ae2',14368,14368,'不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('593abeaaa0bb9f006b377c4e',1341,114,'挂了科的会很惨……',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5938dbce8d6d81005847c9c8',452,2671,'事儿超多的老师……近几年在搞教学改革，用两种教学方式代课，我们是改革派的班……第一节课抽签分组。每次上课前在教务网上发视频，要求看视频然后提一个问题给她。要课代表打印下节课的PPT发给同学然后学生课前预习要把PPT补充完整。留的作业每小组抽一个同学收，这个同学的分就是小组所有人的分。但实施起来有各种问题，视频有问题啊，发视频晚啊，问题提的不好啊，反正没有什么用还浪费时间。后来又改革，用微信软件点名答题什么的，结果一整节课都在搞微信，特别讨厌。总说课要讲不完了，浪费时间的东西不都是她搞出来的(ノ｀⊿´)ノ
INSERT INTO "reviews" VALUES('5937b367570c35005b7874f7',2202,27,'非常棒的老师！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('593619c8fe88c20061dbd7cc',1941,653,'水密韬的课堂氛围很轻松,讲课也很幽默。经常在评图评模型的时候讲段子,从来不批评同学（很委婉）,会给我们很多启示。给学生的自主发挥空间较大',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('593558c7570c35005b5e5301',3517,3517,'老师水平很高,但表达能力不太行,上课经常听不清他讲了什么,抓不到重点,考试打分挺高哒！（熊老师是专门教地质工程专业同学的,好像）',5,3,5,13,1,0);
INSERT INTO "reviews" VALUES('5935204a0ce4630057283c5c',14261,114,'上课只能听懂半小时,后面就被催眠。',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('593511b02f301e00586242c7',14375,990,'容易跑偏，考试简单',3,1,5,9,0,0);
INSERT INTO "reviews" VALUES('5930f7f32f301e006bd77eb9',5739,5739,'上课幽默风趣,讲的认真详细',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59250cae0ce4630069772cff',14085,114,'高数课知识涵量大,难度很高,需要花很多时间,希望老师能够把速度放慢些。',5,3,4,12,1,0);
INSERT INTO "reviews" VALUES('5924f4c58d6d810058fee4e8',14085,114,'老师讲课有些呆板,一个人在黑板上演算,大部分时候感觉他自己在给自己讲。但是老师特别耐心,讲解也很认真,虽然我几乎听不懂他在讲什么,尴尬！！',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('5924b9000ce4630069743e35',14085,114,'提高了我们的自主学习能力。',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('592493f7128fe1005c43cb06',2320,1346,'很好的老师,课程有趣,视频因吹斯挺',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5924658da0bb9f005f78dcf8',716,729,'老师很幽默,幽默,幽默。老师语录：与其让你出去祸害社会还不如让你现在就毕不了业。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('59243328a0bb9f005f763a8c',3925,5,'老师知识水平较高,工作认真负责,抽时间免费给学生上答疑课,课堂互动多。但讲授新知识讲得太快,不提前预习思维跟不上。',5,3,5,13,1,1);
INSERT INTO "reviews" VALUES('5923f8522f301e006b2bc35e',3925,5,'老师上课讲得很清楚,平时也会给大家答疑,非常负责。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5923e4a02f301e006b2a9ed5',4247,1007,'小辫很萌,讲课很认真,很仔细,很专业',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5923c3cf570c350069c856b8',14085,114,'和蔼,易亲近,作业太多,同学问的问题总是很认真的解答。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('591902530ce4630069f57c21',4247,1007,'课教的有性格,人也有性格,长得也有性格。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('591886e82f301e006bada74f',3442,14387,'上课贼无聊，每节课都困，听不懂也不想听，真的心力交瘁',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('59159e4fa0bb9f005fd6755d',598,28,'专业知识丰富,课间可以放英语电影,氛围比较好',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('59155d250ce4630069d615f7',2646,1170,'讲课生动有趣,不感觉枯燥,能清晰解释难点,课后十分有亲和力,耐心回答我的问题,很棒棒的老师。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5913c7a2a0bb9f005fc4bb3d',846,28,'老师漂亮,授课认真',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('59138589a0bb9f0058bf89e9',4112,5,'他的课我听不懂,：）一口川普,到现在还没适应基本每节课都要自学。',3,1,5,9,0,0);
INSERT INTO "reviews" VALUES('5913638b1b69e600686ffc93',8453,114,'老师讲课很好,讲得很清楚,专业能力很高,水平很高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59133216a0bb9f0058bb9913',8453,114,'上课认真,内容丰富,有亲和力,语言流畅,工作负责。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5913144f44d90400610c3584',1487,1487,'专业水平未知,表达讲课十分随和,课程要求轻松,他讲的东西在尽量靠近实际,如工作。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('59130151ac502e45028f5d8e',4112,5,'讲课速度适合,普通话太差,说话时而很难听懂,但笑口常开,很有亲和力。',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('5912ee9061ff4b00626b72d1',4112,5,'上课有幽默感,为人亲和,长得也很好,课堂节奏把握得很好,上一个问题没有搞懂的话可以利用一些零碎的时间搞懂,但是,四川话！有些听不懂！所以尽量往前坐,这样才可以解决口音听不懂的问题!',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('5912a8b12f301e006c3b6555',4195,36,'是此学科在西交的带头人,专业水平高,讲课也比较温柔,善解人意,相比于其他老师作业也少。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59126d642f301e0057ef0a08',14398,14398,'围绕大学的建筑讲解人文方向上的内容与拓展,应为是通识课,多的是兴趣的培养,看到很多外院的学生兴致勃勃地来听课。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('59118946a0bb9f0058ab958e',1372,4181,'内容比较枯燥,讲解也无聊,如果不考试也不会想去接触这些知识。',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('59114b9c2f301e0057e6b29d',2202,27,'讲课和为人都超nice。英语水平很高,知识面也很广,在英语课上攒出了很多想看的电影和剧,对学生的影响以及价值观的影响应该是深远的且伴随一生的。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('591128eb44d904007bf73cfc',12552,516,'真正对中医药感兴趣的同学会想要参与这节课,针灸部分内容令人印象深刻。',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('5910c151ac502e45027e91a9',3493,14402,'其实相当于建筑专业的休息课,练习一下素描静物,几何体,人物头像,老师比较专业,也会和学生闲聊,氛围轻松。',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('59108f272f301e0057e2b68b',7435,7435,'300字好难啊,因为我没怎么听过……只听过两节课吧……讲得挺好,有时候会自己把自己逗乐……专业知识还是很足的,适合真正喜欢宋词的同学选择。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('591063c944d904007bf286f5',1826,87,'很负责人且技艺高超',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('591041ccac502e00654f9ffb',14175,250,'虽然老师看起来很高冷,但人确实很厉害。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('59100fa3a0bb9f0058a06852',13254,114,'为人亲和,授课耐心,能够调动学生学习的热情,讲课富有激情。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('590c3a1dda2f60005342b830',13923,1169,'老师授课认真细致,能充分利用时间。讲课重点突出,授课清晰条理,认真负责,内容丰富,涉及内容十分广泛,课堂气氛活跃。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('590bf8ef1b69e6006837f2a6',373,230,'老师的专业知识无法用清晰明了通俗易懂的语言来表达以致课堂氛围压抑,收获很小。',1,2,1,4,1,16);
INSERT INTO "reviews" VALUES('590bbecdda2f6000533e5a09',14409,114,'教学认真,课堂效率很高,授课内容详细,大部分学生能跟着老师的思路,气氛活跃整节课下来收获巨大同学们都对此课产生浓厚的兴趣。',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('590ba6a861ff4b00699132b3',5066,653,'身高可爱,动作略萌,拆模型挺狠,也很话唠,专业水平没得说,每次上课为了拉他都要费好大的劲。',4,4,3,11,1,0);
INSERT INTO "reviews" VALUES('590b66e744d9040069243533',9443,4500,'很可爱的老师,虽然上课带口音,平时考试给分很高,童锦鲤,生命一宝,你值得拥有。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('590b2fd144d904006922c02e',11748,14412,'系主任温柔儒雅学识渊博,只是课程形式单一,几乎所有人都沉浸在自己的世界里,发言内容基本由百度照搬,一个学期我除了掌握了“熟练使用百度”这一技能外无任何收获。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('590b0435da2f60005329c911',9443,4500,'好！炒鸡nice的一个老师,上课认真负责,不时还会讲一些笑话来活跃课堂气氛。炒鸡喜欢他！特别特别负责！希望他能教我四年！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('590ad2faac502e005827dc09',915,250,'老师在授课时重点突出合理使用各种教学形式易于让学生接受老师严于律己从不迟到早退为学生起到模范表率的作用',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('590a9e3b5c497d005852fb29',14409,114,'老师课程内容很熟悉,上课很认真',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('590a892244d90400691c88b7',1333,28,'老师流利的口语,幽默的上课方式使英语成为一门富有趣味的课目。丰富的课外作业使英语从书面到口语都得到很大的提升。老师对每一节都很负责。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5909f52e1b69e60058f8612f',915,250,'讲课清晰耐心,认真负责,使学生易于理解接受',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5909b969570c3500583b51d2',826,5,'老师亲切可爱,专业水平高,但是普通话不够标准,讲课条理性不够,所以有些同学难以接受。',4,1,5,10,0,0);
INSERT INTO "reviews" VALUES('59099af044d9040069427e83',785,229,'方言话比较重,上课重点不是很明确,表达有待提高',5,3,4,12,3,5);
INSERT INTO "reviews" VALUES('59097a5a570c350058391545',101,114,'讲课很仔细,知识点梳理得很有条理,非常热情,不至于让人昏昏欲睡。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('590945d9570c350058377017',101,114,'亲切,关心学习,有耐心,博学多识',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5908075aa0bb9f00650e4d08',101,114,'讲得很好,很有责任感！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5907f2f5570c3500582cd7eb',1162,114,'翻转课堂实在接受不了,发布的视频多为念书无总结。',5,1,5,11,1,0);
INSERT INTO "reviews" VALUES('5907dfbcac502e0063f81c93',1175,28,'老师专业能力很强,上课前做了充分 准备,并注重培养学生的团队意识和实践能力。课后经常给学生传授重要知识,关心学生。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('59034a4db123db3ee4703678',1175,28,'老师长得好看,人超级好,教得也很好。很有耐心,很细致,和同学关系很好。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('590333c0a0bb9f0065efcb1f',247,28,'老师说话敲温柔,虽然进度略慢,但涉及面很丰富,好评！',5,4,5,14,0,1);
INSERT INTO "reviews" VALUES('59031a33570c3500580ea26d',832,2230,'老师很好,英语标准,还懂法语德语,很负责,每节课每位同学都会被要求回答问题,锻炼口语,还懂历史和名著。好！',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5902f21e61ff4b00669457d6',6323,5237,'老师人很好,但上课以读PPT为主,伴有一定讲解。',4,4,4,12,3,0);
INSERT INTO "reviews" VALUES('5901ff235c497d005825671d',2320,1346,'老师非常有亲和力,爱笑,给我们授课时耐心,细心。主要是基本不点名',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('59017f9f8d6d810058b75bcc',9443,4500,'老师操着一口流利的川普,尽管老师经验丰富,讲课十分好。但作为一个两年没学过化学的人来说,实在不会,泪奔啊……',5,2,3,10,0,0);
INSERT INTO "reviews" VALUES('590161258d6d810058b667ed',9443,4500,'一口流利的川普,和对专业知识的高度把握,perfect！',5,2,2,9,0,1);
INSERT INTO "reviews" VALUES('58ff918d0ce463006143e9dc',762,762,'陈老师讲课速度、声音都不够掌握适当,讲段子太冷,挂的人太多,给分不够合理,水平很高但我没有觉得展现了出来,还喜欢说英文。  挥手/.',2,1,5,8,2,0);
INSERT INTO "reviews" VALUES('58ff5f63570c350058f46a48',4435,516,'老师上课受说爱提问,讲起课来带着笑话,气氛轻松,而且中医一直是我所喜欢的方向,与药膳结合让人更感兴趣。老师声音很好听。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('58ff3ad2a22b9d0065b49abc',4072,3845,'遇到张老师是我们的幸运,虽然数分真的很难,但还好有张老师在。另外,希望张老师严抓期中、期末考试作弊的行为',4,4,5,13,0,2);
INSERT INTO "reviews" VALUES('58fec258a0bb9f0065cf1a4b',3100,99,'希望他可以用502把话筒粘在手上，不要讲10分钟就没声了。',3,1,2,6,2,0);
INSERT INTO "reviews" VALUES('58ec371661ff4b00691b6237',762,762,'这个老师把大学课堂整成了高中模式。大学每学期的课都不简单,要是每位老师像他那样严格给分超低,还怎么学得下去。给人印象就是毫无亲和力和人情味的古板学究（明明年级也不大……）',4,2,1,7,1,0);
INSERT INTO "reviews" VALUES('58e66d6cda2f60005fef908c',272,10064,'课前认真做ＰＰＴ，图文并茂，此类ＰＰＴ比较不枯燥，课上与同学互动，讲课不乏味，每节课都有小节。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('58e641d3570c350057c06c8c',6024,6024,'师资力量雄厚，每次上课带着一堆博士生学生来上课。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('58e5ff41ac502e006c264d6d',637,694,'老师人长得超帅，绰号电气男神，讲得深入浅出，与学生互动性特别强，令人豁然开朗，而且老师并不是填鸭式教学，而是引导式的，好评。:)',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('58e5c3b8da2f60005fea7ae9',1174,3872,'上学比较枯燥，但学习数学似乎都是这样，老师博学多识，这个我没话说。就是一口河南腔，那夸张的表情，想严肃都严肃不起来。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('58e5acfb8d6d8100616ba0b5',14441,12484,'非常生动有趣，会将自己在国外的事情讲给我们，提高课堂趣味性，课下与同学们互动较多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58df228aa22b9d0058638f51',14442,12872,'上课比较枯燥',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('58dee46c2f301e006205b4a8',674,2155,'老师上课认真负责，对学生也很好。',4,4,5,13,0,3);
INSERT INTO "reviews" VALUES('58dea127a22b9d00586195e0',4003,2598,'老师讲课很清晰有条理，课堂上经常拓展，善于创新，开发思维，课堂气氛较好，表达力好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58de719244d904006d07da8f',13254,26,'上课很搞笑，很负责，第二讲的课都第一讲坐在旁边的教室给答疑，给分高。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58de302da22b9d00585ebc4b',142,5359,'老师做题简直牛到爆炸；智商高情商低。',5,5,4,14,0,1);
INSERT INTO "reviews" VALUES('58de07288d6d81006140b911',10467,14447,'较好。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('58dd718a2f301e0062fd8f5b',14148,68,'课堂较生动，但老师比较高冷。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('58dd5e510ce463005818e341',12010,7428,'没办法，老师就是有这种能力，让人很喜欢很喜欢很喜欢听他讲课，呃，可能是太萌了吧。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58dd38d0ac502e006cf50c34',1225,40,'老师很有责任，布置作业量与练习都十分充分。',4,3,3,10,2,0);
INSERT INTO "reviews" VALUES('58dd0bcfa0bb9f0069d69151',1168,228,'讲课很好，给分可以~',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('58dce4a961ff4b0061567b67',3253,3586,'上课不够精彩，PPT好无聊啊！一大本课本好难背啊！！物流，集装箱，储存…………这是些什么啊。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('58dca65044d904006dfc9955',11148,14453,'很好，讲课通俗易懂，认真负责。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58d971bbb123db199f49c9a1',10533,10533,'讲解生动，富有亲和力，习题讲解可增加。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('58d948f244d9040069469007',14455,14455,'上课以开放同学思维为主，不拘泥于课本。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58d92f291b69e6006bc06b3c',11148,14456,'上课认真备课；不厌其烦讲重点，只要听课就能听懂，关心学生学习，身体。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58d9087cac502e0058db5171',6377,6377,'讲道理，在他手下没学到什么，真的感觉没学到什么，基本都是自己去看。而且上课的时候也听不清他表达什么。',4,3,2,9,1,0);
INSERT INTO "reviews" VALUES('58d8e247570c350058e2eb28',13290,14458,'很负责，认真的一个老师，要求严格。',5,5,5,15,0,1);
