INSERT INTO "reviews" VALUES('58d3f76c61ff4b006cb9f26e',1320,3017,'专业水平高，有亲和力，教给我们很多有用的知识，不论是学习上还是生活上。但是太爱表达自己的观点，有些主观，',4,5,5,14,3,2);
INSERT INTO "reviews" VALUES('58d3b91344d90400685e3631',1291,3128,'过于封建，建议老师以后领带不要系在脖子上，时尚体现在内涵上。',4,3,1,8,1,0);
