INSERT INTO "reviews" VALUES('58bcc79561ff4b006cf5d798',8974,12495,'老师理论与实例相结合，与学生互动较好，较于其他专业课更有趣且易接受。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('58b8f9bb8ac2470d784eb7f9',459,68,'希望能与其它英语课比较一下，确定打分标准以及批卷标准，避免造成分数差异大的情况。',3,3,4,10,4,1);
INSERT INTO "reviews" VALUES('58b8e20e8d6d8100652eeb62',14484,1225,'特别喜欢的老师，上课也很有收获，专心上课的，受益匪浅',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58b8ca9944d904006ad02dd5',7459,36,'口音重，听多了就习惯了～',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('58b8c6a1128fe1007e41d7fe',14486,40,'教学工作安排的好，但是课程考核太过松懈，考试成绩要求不严格',4,4,3,11,1,0);
INSERT INTO "reviews" VALUES('58b85ed1570c35005991b277',12930,12930,'老师学识渊博，富有涵养 讲课常常引经据典，以实例为例讲解 生动有趣 十分推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58b85de961ff4b006cdafa64',7459,36,'老师人很好，亲切和蔼 口音听上去很俏皮啊 最喜欢翻转课堂的讨论课 老师也很敢于创新 学识渊博 给分也高啊 就是一个赞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58b7d43aa22b9d005ed00894',2992,2815,'逗，讲了许多关于专业前景的问题',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('58b79838128fe100642a3550',903,307,'老师人很好，能够及时解决我们的问题，',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('58b776b38fd9c594cff55380',535,535,'真的听不清他在说些什么，吐字不清，讲课没有重点，没有亲和力，没有经验，不近人情。',5,1,1,7,2,0);
INSERT INTO "reviews" VALUES('58b69d56a22b9d005ec816d4',14455,2190,'很不错的一位老师，考试前不说考试范围，我们就只能整本书都看了！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('58b65c682f301e006c47898a',13771,13771,'正课不讲，全在和学生聊天，强行将自我价值观传输给学生，本身为教授，连最基本的教学责任都未尽到。',1,1,5,7,0,0);
INSERT INTO "reviews" VALUES('58b6483f1b69e6006bfd2e48',5618,14494,'很亲切并专业的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58b6249eac502e006bb4c930',5145,2119,'课程比较难，比较繁琐，讲课课件单元比较混乱，不知道在讲书上哪里。',4,4,3,11,1,0);
INSERT INTO "reviews" VALUES('58b598d9b123db0057371824',10447,1606,'负责，认真严谨。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58b57de3b123db00573656da',8040,185,'讲课口音很重，但讲的确实挺好的，上课风格也很幽默。',5,3,5,13,0,1);
INSERT INTO "reviews" VALUES('58b55af6570c35006b0e763f',13926,14498,'可以退休了',5,4,2,11,0,0);
INSERT INTO "reviews" VALUES('58b52765570c350058abc19b',10142,415,'老师上课没有多大问题，只是这门课偏难，考试内容几乎平时作业，没有什么收获，感觉就是考验记忆力。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('58b3c677570c350069319464',903,2276,'讲课很清楚',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('58b3b24e570c350069310569',13142,1596,'王老师专业知识非常丰富，讲课讲的很好，就是严。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('58b396ce8fd9c50063dfb2d7',2205,80,'李力老师教的很不错。平时成绩也高。按时交作业就不被点名。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('58b394892f301e006c110d7b',823,380,'心灵鸡汤丰富，很有感触，你值得拥有。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('58b2d0f4ac502e006ca46ea8',12757,1007,'大一上的第一门专业基础课。指定两本教材：平狄克和柯兰德的微观经济学，前者为主。两本教材从不同角度阐述各种理论，真想学经济学两本一起比对着看是很有用的。
INSERT INTO "reviews" VALUES('58a5cbe2128fe100646abbe1',14505,241,'真的蛮无聊的，其实是一个类似于军人团队讲课，有的老师谈吐幽默，但多数时候，同学被讲得睡着或者做自己的事情',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('58a5ca77570c35006b5e6176',1940,653,'有耐心，亲切，我喜欢他',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58a5c787b123db005eae3bc6',4482,157,'运动员出身的老师，身材魁梧，专业水平毋庸置疑。希望同学们玩得开心，但也要求掌握基本技巧。上课较为负责，不会过早下课，对同学们比较和蔼，但对不认真练习导致考试不及格的同学会严肃起来。',5,5,4,14,0,15);
INSERT INTO "reviews" VALUES('58a3c31461ff4b006c86d861',3920,761,'限选课中给分比较高的。分理论课和上机课，有时点名，记忆中会分小组，交小组作业，希望没记错 - -
INSERT INTO "reviews" VALUES('58a2ac440ce46300564b6b26',9443,909,'老师有点能掰，科普一些菜系渊源，哪些地方人好哪口之类，然后放放美食视频，期末交一篇论文。好过。',4,4,4,12,4,1);
INSERT INTO "reviews" VALUES('58a2ab338d6d81006ca65f5d',1513,1513,'课上老师会放动物被残害的视频，讲些流浪动物的坎坷经历，教我们怎样以动物的立场保护他们。
INSERT INTO "reviews" VALUES('588b3fbe1b69e600594b85dd',14511,1106,'每节课的前十分钟是近期热点讨论时间，积极参与的话会很有意思。每学期好像还有几次学生主题演讲的加分展示机会？年代久远有点忘了。公共产品理论和公共选择理论是课程重点，可以跟很多实际情况结合，是学起来最带感的章节。
INSERT INTO "reviews" VALUES('588353d6b123db4a39d98778',14512,14512,'陈老师的服务营销和人力资源管理实务是最热门的限选课之一。
INSERT INTO "reviews" VALUES('587eef552f301e0057a9637b',2654,14513,'王老师讲课清晰，能扣住关键点，而且考试紧紧围绕平时做过的练习。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('587eeea861ff4b00651578b8',239,239,'恒哥长得帅，车技好，而且讲课很清晰易懂，考试帮助复习要点，很有收获的课程~',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('586e6d238d6d8100586fde73',5732,9127,'老师很有亲和力啊，还很年轻呢…虽然我是有一次想去蹭课，结果弄错时间，弄错教室，却刚好碰上韩老师的课，听了一节感觉非常棒！！！大赞',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('586de773b123db005d0bb730',11950,2598,'慧宣是我大学三年来遇到过的最优秀的老师，没的说',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('586cc41ca22b9d0056906d6d',5732,9127,'最最认真负责的老师！希望学生可以学到真正的知识，很晚都还在帮学生答疑，回答问题。专业知识也绝对过硬，热爱数学，而不仅仅是当作一份工作。韩冬春老师最棒了！希望以后可以上更多韩老师的课。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('586b9ac7ac502e12d62d866f',903,179,'论亲和力交大无人能敌！人超级好讲课超级细致，而且专业能力一顶一，问她考试不考的很偏的地方都会给你详细讲。能给的分都给的不低。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('586b99aeac502e12d62d7afd',1633,949,'老师很认真负责，很用心，上课能学到很多。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('58676d0d61ff4b006bb0f5b8',827,827,'陈老师数值分析讲的的好 重点突出 留的作业量适中 很有针对性',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5866c2951b69e6006b37a738',10294,228,'有内容有思想，提升思考维度',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('586688b0ac502e006d640802',558,623,'老师挺好的',4,5,4,13,1,0);
INSERT INTO "reviews" VALUES('586658f6ac502e00612c9ee9',14035,1267,'老师超级好！！会给学生看许多影片实例，并从中引出心理学相关话题。话题也非常适合大学生，从恋爱到记忆力相关到情绪，认真听也会有不少收获，总的来说，想水也能水过去，想学习也有许多收获',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('58664f4361ff4b006baaec4d',4305,4305,'认真负责，讲得耐心，联系实际，深入浅出，是好老师。',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('58661161da2f6000559f86b8',7728,3332,'老师讲课的思路很清晰，对待教学很负责',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5865cf47da2f6000559dc3e5',7878,7878,'老师上课碎碎念过多，回答学生问题不耐心，',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('5864d2a51b69e6006cf62e39',8081,8917,'一般是张锦教授团队授课，平时作业很多，而且这门课对物管很不友好闭卷+高难度考试。物管如果必须要选请慎重。物工是开卷不用太担心（但是课程名字和代码不一样）。',3,2,3,8,0,0);
