INSERT INTO "reviews" VALUES('5864d1061b69e6006cf61fea',2170,12441,'正常吧',3,4,3,10,0,4);
INSERT INTO "reviews" VALUES('5864d0df128fe1006d117d0a',14537,12484,'很牛逼但是有种茶壶里倒饺子的感觉。要求比较严格，他是负责物流设计大赛方向的老师。有竞赛需求的可以留意。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('5864d0aa61ff4b006cfdd0b5',3439,14538,'出国的同学可以留意一下，你懂的',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('5864d088ac502e005ff5e9bd',2078,721,'评论两极分化。个人感觉老师不太喜欢物流管理的学生，物工推荐可以选择',4,4,4,12,0,0);
