INSERT INTO "reviews" VALUES('5864cfea61ff4b00631c20ee',1007,2035,'平时事情有点多，而且比较反感学生挑战其权威。不给划重点，期末考试真的只有各显神通，慎选。',3,3,3,9,1,0);
