INSERT INTO "reviews" VALUES('5864cf7361ff4b0068baf76a',8096,23,'正常水平',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5864cee2da2f600065af5f5f',14544,14544,'外教课，英语水平较低慎入。最后是做presentation，非考试',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5864cea31b69e675fce39789',3821,3821,'比较严格，',4,4,4,12,1,1);
INSERT INTO "reviews" VALUES('5864ce7e128fe10069f79502',5732,9127,'老师专业知识绝对过关！无论什么样的数学题一看就会！几个特点：1.超好说话，会在微信群里同大家斗图，可能是因为年轻好打交道；2.在讲与知识无关的问题时通常前后矛盾，e.g:这种类型很难...其实这种题很简单，我一看就会。你们不要灰心，不及格没关系，学到知识就好（其实他在安慰我们）',5,4,5,14,5,0);
INSERT INTO "reviews" VALUES('5864ce7361ff4b005838d6c8',2525,2525,'十分负责而且给分一般在80+左右，她的授课方法也很好，有问题也可以问，但是不接受挂科后的打电话之类的',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5864ce28570c3500695cf70c',715,14548,'只要平时好好去了期末一般不会太低。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5864cd9061ff4b006cfdba59',5077,2815,'日常需要好好听课',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5864cd65570c3500695cf158',5732,9127,'上课认真，讲题细致，为人友好',5,4,5,14,3,0);
INSERT INTO "reviews" VALUES('5864c90d61ff4b0068bac23d',3920,761,'说实话上课内容还是很实用的，如果不是上这个课我也不会去了解我们学校图书馆的网站里有那么多资源😳每个星期的小组作业都是考验队友的时候，也会有很有意思的主题，邓老师人很好，嘴上说着“旷课就挂”，实际上也没点名呀。上课氛围有点沉闷，主要是听课的人不多啦。成绩看平时，期末不考试还是挺轻松的。',4,3,4,11,2,0);
INSERT INTO "reviews" VALUES('5863e847ac502e0067498479',4925,4925,'讲课很有意思，心态年轻没有年龄差的感觉，逗逼。分享案例也还算不错。是写论文的选修课啦',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('5863cdc61b69e6006cf1548c',344,793,'老师上课认真，负责',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('5863b0011b69e675fcdde286',751,1652,'老师有点照着讲，但拓展很宽，多用力学问题做解决。',5,4,4,13,0,6);
INSERT INTO "reviews" VALUES('58639757ac502e005fef6efd',6377,6377,'讲课混乱无章，好多时候后面和前面都接不上，讲课时常让人不明白。',2,1,1,4,0,0);
