INSERT INTO "reviews" VALUES('586295401b69e675fcd866f7',11950,2598,'很有风格的一位老师，讲课很生动，很富有激情。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58626fc561ff4b006cf177e0',8805,1196,'考试上课很有激情  丰富的肢体语言 是一个老头',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('586259b71b69e675fcd69315',8383,441,'讲解很认真，但同学能够理解的层次不多。',5,1,5,11,0,0);
INSERT INTO "reviews" VALUES('5862178fac502e00673ec0ec',2433,142,'为人友善，与人交好，说话幽默，专业知识排名前列。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5861fbe6da2f6000659fd67e',14561,68,'作业种类齐全，无一不烦，平时分给分标准在正常水平十分一下，给分又严又死，不懂变通==',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5861d448128fe10069e7017f',1320,3822,'老师上课可能和每一个同学的互动不够多，上课老师可以再给予时间给学生发言表达自己',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('5861d2e6128fe1006bbc5d63',7459,36,'#给那些不是为了分来上课的同学的推荐#
INSERT INTO "reviews" VALUES('5861d144b123db0065c211a2',10294,228,'其实想推荐一些老师给部分不是为了分数上课学习的同学
INSERT INTO "reviews" VALUES('58612fb561ff4b0068a83964',14565,14565,'大一第一学期选的通识课，五分好评。
INSERT INTO "reviews" VALUES('586113ef8d6d810065f49fbb',527,14566,'老师比较温柔，很博学，我上这节课收获颇丰，很喜欢这门课和这个老师',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('58611352b123db0065befd6b',763,763,'胖胖哒一个老师 讲课的时候可以一直讲一直讲 社会学本身也是比较有意思的课程  最重要的是 老师虽然不按时下课 但是下课非常早 基本会提前个20-25分钟 大家早早吃饭去吧~ 基本没有作业 但是点名蛮重要的 一次6分啊 不算比例 6分就是6分 直接加入期末成绩 所以尽量别逃课吧 去坐坐挣6分也好啊~',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('5861131b61ff4b006cea148c',14085,114,'认真听会发现其实讲的不错，但真的让人很想睡。。。',5,3,4,12,1,0);
INSERT INTO "reviews" VALUES('5861131a1b69e6006ce25b80',11684,13919,'来的人很少，所以老师动不动就点名。最烦的是老师特别喜欢关灯，那就除了看讲台啥也干不了。不过课程水是真的。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('58610f5d61ff4b0068a73735',533,2566,'身为数学非常 非常 非常不好的文科生 还要学数学真的是…太惨了…但是 徐老师 非常 非常 非常棒 教的内容在老师看来 可能简单的不能再简单了 可是 老师很关爱我们 几乎每道题 老师都会亲自带着我们算 即使是最开始行列式里简单的十以内加减法…徐老师很酷 一头干净利落的短发 给数学很厉害的徐老师比心！',5,5,4,14,2,2);
INSERT INTO "reviews" VALUES('58610ee3128fe1006bb91c41',9443,1170,'绝不会打瞌睡的课——老师带一点川普（听两节课后完全可以习惯），上课喜欢点前排同学回答问题，口头禅是“哦豁”。专业知识很厉害，化学历史上的年份可以随口而出！顺便回复楼下：老师讲课是挺直接的，需要一定的课前预习。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('58610436128fe10069e362b2',14137,14572,'大学一年半来接触最多，觉得最棒的老师。专业水平爆好，风趣，上她的课爆开心。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58610321b123db0065be7820',14573,14573,'老师有耐心也很亲切，课堂丰富，令人满意。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5860aaeb8d6d810065f168f0',819,9857,'真的很好
INSERT INTO "reviews" VALUES('585bcfb661ff4b006cca9d81',13,13,'也许赵老师在行业领域确实比较屌，但我还是不喜欢这种总是强调自己有多厉害的人。这课确实没学到什么东西。现在正在准备明天的考试，感觉很蛋疼',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('585bcf021b69e6005607f1bf',7728,13611,'赵老师的一大特点就是喜欢聊天，有时候会扯很远。赵老师在信息学院应该算是比较有名气的吧。不过这课确实有点和实际脱节，讲的东西太老了，没用，所以不想学。考试开卷，基本都在ppt上',5,4,5,14,3,0);
INSERT INTO "reviews" VALUES('585bcdafac502e00671a3de7',3036,3036,'老师水平不错，嗯学了这课感觉离成为黑客又近了一点。考前提示的重点一定要仔细复习',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('585bcd0261ff4b0063e8d7d1',14578,14578,'英文课件，不过基本都是参考的冈萨雷斯的那本《数字图像处理》讲的比较清楚。老师对学生态度非常好。典型工科面瘫脸有一种意外的萌感🙈',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('585ba39f61ff4b00688668ae',818,10420,'差别对待',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('585b7ad6da2f60006579a7d7',2559,2559,'慎利是一位很值得研究的老师，有很多需要沟通解决的问题。',2,1,1,4,0,0);
INSERT INTO "reviews" VALUES('585b65811b69e6006cbfbd92',7736,370,'上课热情大，但是水平不怎么行。',3,2,4,9,1,1);
INSERT INTO "reviews" VALUES('585b31008d6d810065d088a5',199,939,'人特别好，特别温和，考试还会划重点。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('585ab4351b69e6006cbce1ca',12963,14583,'上课有热情，但是表达能力不强，描述不清楚',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('585a979c61ff4b0063e22083',2559,2559,'上课要求始终抬头',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('585a536761ff4b00687eb2d9',4003,2598,'结构力学太难，根本学不会',5,3,3,11,0,1);
INSERT INTO "reviews" VALUES('585a1db9128fe1006dd365d0',1590,1687,'对工作和对学生不够负责，没有传授足够有用的知识，喜欢冷暴力。给学生打分过于主观，不够尊重客观事实，不在意学生的创造力，一味追求传统和规范。',1,1,5,7,3,2);
INSERT INTO "reviews" VALUES('5857bd11b123db006583bb79',925,925,'听不懂啊听不懂',4,2,3,9,0,1);
INSERT INTO "reviews" VALUES('58579b508e450a006c74da16',802,706,'老师学识渊博，授课内容丰富多彩，涉及课内外，不过听不到！（声音小，吐字不清楚）',4,1,3,8,1,2);
INSERT INTO "reviews" VALUES('58550ba5570c350069f4da7c',1381,517,'专业素养绝对没得说，而且要求严格，让我学到了真正的游泳技巧。刚开始的“恐吓”再后来的接触里就变成了刀子嘴豆腐心。动作不标准的去找她都能够得到详细的指点，不知不觉的就达到了以前梦想的水平。一句话——易老师，想学真本事的唯一选择🌝',5,5,5,15,12,1);
INSERT INTO "reviews" VALUES('58540c20570c350069f004bc',5924,5924,'非常好的一门课，大家互相交流，讨论',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5853bd9a61ff4b006c8e99df',760,760,'老师课讲得很好，生动风趣，但老师本身说话有点啰嗦……',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('58538c14128fe1006986ebc7',674,307,'老师真的很认真负责，而且特别温柔，路上碰到会和你微笑，问很多问题也不会不耐心，讲课水平也很高。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('58538b7d61ff4b006c8d2e59',9882,22,'在讲课的过程中穿插很多幽默段子',3,3,3,9,0,1);
INSERT INTO "reviews" VALUES('5853864861ff4b0063ab73cd',449,3822,'……老师人特好，温柔善良',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5853514f1b69e6006c842174',2821,40,'给分太低，老师人还不错。',3,3,2,8,0,0);
INSERT INTO "reviews" VALUES('58531e231b69e6006c833e5c',2354,792,'老师专业水平非常高，对学生十分负责，讲课讲得很详细。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5852f0321b69e60056c808b8',13021,14597,'多些科学的思想，注重对学生逻辑感情培养。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('5852d08c8d6d81006594d90b',14598,671,'老师不爱与学生交流，上课对知识内容讲解不深刻。大部分都让我们自己看一大段PPT！！！同学跟老师反映太多人作弊考试不公平的情况，他不予理睬。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('5852ad9f8e450a006c5073fb',1087,2,'老师虽然讲得不够清楚，但是特别认真负责，而且很可爱。',4,3,5,12,1,0);
INSERT INTO "reviews" VALUES('5852770261ff4b006c87c86c',1770,441,'蒋老师是一个认真负责的好老师，他是真心希望我们能够学到知识',5,4,4,13,3,0);
INSERT INTO "reviews" VALUES('585240a1b123db00655b03ab',14601,1891,'讲得不错，能让你听懂，考试，给分一点也不水。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5851ff3c128fe100697e5318',12317,12317,'老师上课风趣，有亲和力，对于同学们提的问题，都能耐心地讲解',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58519cb11b69e6006c7bb4f6',4982,14603,'讲题准备精细，思路清晰，表达能力欠佳。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('585179c48d6d8100658d9cef',3202,5424,'最后实验做的有点紧。',3,3,3,9,0,1);
INSERT INTO "reviews" VALUES('58513463570c350069dffb3b',7473,181,'老师讲课认真，形象生动，使学生易于理解。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58511ffeac502e0067d02c20',14606,14606,'专业水平一般，没有重点。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('5850ed99128fe1006d928ac9',14607,7866,'老师讲课认真，待人亲切，知识全面。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5850b5d0128fe10069775547',10469,10469,'上课生动形象，考试严格',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('585086e68d6d8100658748b4',785,114,'上面吐字清晰的我们真的是同一个老师吗，不知道是哪的方言，个人听的有点费劲，上课主要为ppt，但是ppt内容很丰富，例题较多，能否快速理解看个人，老师积极性还是很高的，对学生负责，会提醒不要玩手机',5,2,4,11,6,0);
INSERT INTO "reviews" VALUES('585005878e450a006ad564af',14610,14610,'钱老师用自己一生的规划经验为学生讲授课程，把本枯燥的理论课变得生动，这是真正的言传身教。课上优势会受到感动，一学期下来收获颇丰，真心崇拜这位老师。',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('585004ec61ff4b0058f29694',459,68,'额大概是我把这节课选到了下午的第一讲，所以基本都是听一节课睡一节课，总体来说还不错，中规中矩那种，作业是有点多。',4,3,5,12,2,5);
INSERT INTO "reviews" VALUES('5850047a2f301e00573db0ea',14612,14612,'老师讲的很好，但是基本上课有很多案例，个人觉得可能要自己下来多花功夫回归课本。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('584ffd108e450a006ad52150',1386,1386,'老师非常认真负责，讲课细致耐心，可是通信电路实在是一门神课。。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584fec7c128fe1006c99f604',2298,2792,'老师讲的很有意思，对于物流的认也提升了很多',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('584fe07e128fe1006c9993a3',4925,4925,'老师讲课很幽默啊。课堂间穿插着自己做学生时候的学习过程和好多有趣的案例。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584fc8d08e450a006ad38402',11950,4003,'萱哥绝对的老师中的楷模，业界良心，专业水平没得说，超认真负责，讲得内容也很细致，每次选课都爆满。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584fb566b123db0066294abc',5449,5556,'老师很细致，知识也很渊博
INSERT INTO "reviews" VALUES('584fa0432f301e00573aab44',262,5485,'采用流动式教学，即不是由一个老师完成一学期的课，每个老师观点都丰富多彩很有跳跃性，上课形式丰富精彩。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584f91368e450a006c6fab89',12301,12301,'老师很有激情，讲了很多现实的问题，学生要回答问题，可以加分',5,3,4,12,0,0);
INSERT INTO "reviews" VALUES('584f908bac502e006c7bd4b7',2701,2701,'助教点名很认真，其他还挺好的，能学到有趣的东西，课上可以做自己的事。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584f9019ac502e006c7bd1cd',887,4181,'教的不错。老师有点严肃。',5,5,3,13,4,0);
INSERT INTO "reviews" VALUES('584f8f9e128fe10058b8653c',230,230,'老师讲的很好，而且不点名。就是平时作业有点多。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('584f8f2dac502e0069387cf5',14203,14203,'饶妈妈太好了！！就是期末不划重点，课堂上经常点名回答问题。但是课上的真的很好！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584f5aa9128fe10058b6f429',14441,12484,'上课三语教学，讲道理，日语能看懂一点，英语完全无理了好伐。三讲课两讲课回忆他日本生活中的趣事，确实很有意思，最后一讲课唰唰翻完一百页PPT，也很有意思……',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584edd958e450a006acf1670',674,179,'叶文霞是我在所有工科课里最喜欢的老师，没有之一，上课非常认真，人也好',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('584ec840b123db00662501d2',1536,14075,'老师对中国哲学有自己独到的见解，能分别从儒、道、法等不同学派分别详细解析，令学生受益良多',5,4,4,13,1,1);
INSERT INTO "reviews" VALUES('584eb534b123db0066247e3e',459,68,'老师讲课挺好的 基本不点名 作业是要交的 要不然没分。',5,4,5,14,1,8);
INSERT INTO "reviews" VALUES('584eb3280ce463005c661421',42,5127,'你不会永远是对的',3,2,1,6,10,0);
INSERT INTO "reviews" VALUES('584e9ec3ac502e0069342676',4003,2598,'蔡老师很高冷啊！平时一副冷漠脸，但上课实力确实没得说，只能用“极好的”三个字来形容。只愿以后的学弟学妹去问问题时老师能更热情一些。',5,5,3,13,3,0);
INSERT INTO "reviews" VALUES('584e81eeac502e0069333f27',383,679,'老师特别有责任心，问问题她会耐心地回答，发邮件也会回的很及时，很得我们尊重。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584e7dc6128fe10058b2f6c4',14631,14631,'雷老师身体不好，还一直教课。是一个有故事的人，我记得他头疼还会批改作业，心疼',5,3,4,12,1,0);
INSERT INTO "reviews" VALUES('584e7c40128fe10058b2ea78',763,763,'唯一服气的老师，虽然上课全是照着课本念，但是课本上都能看懂，用心点，都能学好。他不会给ppt，但是给分会比较高。让人最怀念的就是考前一天一夜熬夜背完一本书。老师不会找你麻烦，但也不会给你捷径',5,3,3,11,1,0);
INSERT INTO "reviews" VALUES('584e6dd02f301e00573458c7',891,114,'老师超级认真，但是上课都是照着课本念，没内容，高数全靠自学，自学能力强的可以来。',2,3,5,10,1,1);
INSERT INTO "reviews" VALUES('584e44fca22b9d0058e4e888',10142,415,'上课念PPT，考试考原题。公式一大把，根本记不住。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('584e28142f301e0057324450',9246,5,'挺不错的一个老师
INSERT INTO "reviews" VALUES('584e276e61ff4b006cd18889',8328,230,'一个很不错的老师
INSERT INTO "reviews" VALUES('584e243561ff4b0058e6f414',785,114,'超棒 老师真的很好',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584e18690ce463005c617d8a',2961,761,'不是我想象中的水课。点到，考试，作业。不适合想水的同学，并且我觉得学不到实用的东西。',3,3,2,8,1,1);
INSERT INTO "reviews" VALUES('584e0b2ca22b9d0058e3669f',891,114,'讲课很细致，但进度慢。老师脾气很好，很负责。但讲课偏向照本宣科，有点枯燥。',3,3,5,11,0,0);
INSERT INTO "reviews" VALUES('584d8ce08d6d810054522db2',13709,36,'老师特别有意思',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d6bf561ff4b006cce9bea',2202,27,'老师为人特别好！！课堂内容很丰富，专业知识渊博，真正和学生打成一片的老师！！欢迎来到Iris的英语世界！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d6b4c61ff4b006cce967b',13988,26,'老师上课风趣幽默，专业知识信手拈来，授课很好！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('584d5fdb75c4cd7cbe6e061c',14260,641,'上她的课不自觉的走神。。。一点上课的激情都没有。有点照本宣科。但还是很有耐心的一个老师。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('584d5e71ac502e006c70754e',14035,1267,'老师人很和蔼。隔三差五签到。上课经常放一些电影，还会讲一些自己心理咨询的案例，而且老师自己购买BBC正版碟纪录片给同学们看。期末不考试。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d5d998e450a006c64458d',1058,5,'老师人很好啊。这学期开始就怀孕了还是认真的上课。考试考的不好老师很着急。很负责，耐心。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d5cc22f301e00572ed57c',14260,641,'上课语气平缓，听多了就睡着了。不过讲的都是考试要考的。作业，编程题打印上交，写在书上的不检查。很少点名。人很好，很负责。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d5bc7128fe100692285c4',13589,14090,'上课不点名，16周交作业，每章做两道题，网上有一模一样的答案拷贝就行。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d38c1ac502e00692beba4',12218,762,'一般吧。',3,3,3,9,1,1);
INSERT INTO "reviews" VALUES('584d36fc61ff4b0058e24e77',1537,1651,'老师hin牛，非常nice的一个人。因为工图画得好，被男同学天天约上自习，最后这位男同学成为了她丈夫😂很喜欢赵老师，因为她，我才开始觉得画图很有意思。',5,5,5,15,11,1);
INSERT INTO "reviews" VALUES('584d36ed128fe1006c8a739a',166,619,'老师讲课真的很不错，很喜欢的一位老师，多才多艺',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('584d36beac502e006c6f24e1',2202,28,'老师极具亲和力和责任心 真正把教育当成自己的职业和乐趣 对同学超好 授课的思维独特、有趣而且有效 极大地拓展了同学们的视野 她的学生也一定是一群有趣的人哈哈',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('584d31b7ac502e00692bb169',1536,14075,'老师学识渊博，讲课风趣，时不时来个搞笑的段子，举个食堂大妈打饭的例子',5,5,4,14,0,1);
INSERT INTO "reviews" VALUES('584d2fd38e450a006c62b864',2202,27,'老师非常有魅力，讲解科学，英语非常纯正，是我最喜欢的那种老师，可以和学生成为朋友。常常分享许多有意思的东西，开阔眼界。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584d07208e450a006ac3c9f5',13496,27,'心机很重，定了座位以后虽然不点名，但是每次都会看谁没到，偷偷的记下来，期末扣你的分，心机',1,1,1,3,4,0);
INSERT INTO "reviews" VALUES('584d0521ac502e006c6daab0',2202,28,'这真的是我上大学遇到最好的老师了! 无比幸运!! 上课内容很丰富也很有趣 而且老师口语也很棒',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584d0389b123db006619f02e',8328,230,'我觉得讲的不错 课堂上有很多延展',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('584d01668e450a006c6156c7',14175,14657,'老师讲的不错，，就是有点严格',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('584cfb8b8e450a006c61297b',2202,28,'超级负责和用心的老师，了解的东西也很多，很庆幸大学能碰到她',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584ca27a128fe100691d4a8a',13988,114,'非常棒的一个老师，负责认真，知识点都能解释得很清楚，为学生着想！点赞！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584ca14ca22b9d0058db5cb7',2202,27,'自己真的很幸运，能遇到这么好的老师，真的是最好，没有之一.课堂上不是死板的教学，通过很多有趣的方式让我们获得知识，给学生足够的平台来展现自己.比心～',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584c31f3ac502e006926b415',13589,14090,'一门水的不能再水的选修',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('584c26c88e450a006c5d8899',449,3822,'很良心的老师，期末口试给了我满分，别的老师是按1分扣得，而她却是0.1分扣得',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('584ba7f22f301e00572466d9',1938,376,'上课平时作业少，就画思维导图。不教设计技巧而是思想，理论的。期末比较容易，一个作品展示（照片都行），一份3000字报告。从不点名，就每节课思维导图传到群里当签到。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('584b8dd561ff4b006cc315fe',2202,28,'一个非常professional和kind的老师，从那么多人爱她就可以看出她有多么得优秀~非常乐观，真心得喜欢英语，希望同学能从英语学习中得到快乐。很幸运能来到Iris的班上^O^',5,5,5,15,8,0);
INSERT INTO "reviews" VALUES('584b8af4a22b9d0058d58fd0',13988,565,'非常非常棒的老师！讲得特别细致，和善风趣，真心希望同学们能拿高分^O^选薛老师的课准没错！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('584b714e2f301e005722fb76',9246,5,'挺和蔼负责的老师，课前稍微预习一下的话会发现他讲得已经相当清楚了...同学听不懂的时候会重新讲，考试分析也足够到位。这样的老师我觉得已经相当好了呢。作业嘛...两周收一次，如果太浪的话可能会发现一天要写十几页.........哦对了，顺便说一句，在教务系统上填的信息量超过他的老师我很少能见到，认真没得说。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('584b6f26b123db006610e19e',8328,230,'本身来说...这种课....可能也不太可能上得多好吧...尤其是老师讲得很激情台下同学又没什么兴趣的情况下...从开学起就是抱着【你们慢慢就会不好好听】这样感觉在上课的老师。对于某些顶撞型提问和反驳会比较生气和严肃...不多说Orz，毕竟这课听起来跟校史有点雷同的无奈感。点名在人少的时候会抽名字，上课可能会冷不丁叫同学回答（选择的时候大体不是选过的就是逃过课的...）',4,2,2,8,1,0);
INSERT INTO "reviews" VALUES('584b6de2128fe1006916c4d0',1175,761,'不算很喜欢的通识课...感觉过于...普通了，甚至有点陈旧感，虽然内容基本都蛮新的但是基本停留在ppt录屏水平了。还是有一定帮助，不过上课感觉一般般...',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('584b6ca70ce463005c528e6a',2202,27,'很庆幸能让我在大一的时候就遇上这么好的老师，上课有看不完的视频听不完的歌，不限于教材，总能教导我们一些生活的甚至是有关人生的思考。而且人很好啊，笑起来的时候真的让人觉得很暖~恩恩反正就是很喜欢Iris',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('584b6c9b2f301e005722dd08',236,1529,'中规中矩的老师，碰到缺勤多之类不会爆发撒脾气，基本上还是和气地以经验劝说利用好课上时间之类。上机课比较少出现，基本交给助教。有一段时间每节上机课点名，后期又松下来。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('584b6b278e450a006c58450e',13340,542,'虽然不是很清楚学长为什么给差评...但是我蛮喜欢老太太讲课的啊？大三的学长给的评价是“把工化上成水课”的老师，怎么说呢个人觉得老太太很有学问，有种老教授特有的感觉，挺和蔼可亲的，曾经说“来的人少点也好，上课的效果更好”，没点名就继续上课了。上课还能带到土木学科相关的一点知识。外国的材料不少，不少国外教材和大学网站的材料。历史性的讲解国内外都可以有延伸。上课经常讲到还剩20分钟就讲完了...【友情提示下课早意味着讲得快，主要是激发兴趣，课后要自己花时间，但是这个模式习惯了其实很舒服】作业是每章课后挑几道题，量还行。考试不难注意格式。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('584b4167128fe10058a02a3f',2202,27,'lris超级好，超级负责任，课堂上给我们补充很多有趣的有用的视频，了解了很多东西，而且感觉老师的知识超级渊博，对我们像朋友一样，丝毫不拘束。总之，三生有幸遇见她！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('584ad3cf0ce463005c508045',8541,28,'有爱',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584ad2a92f301e005720d308',1162,114,'翻转课堂要把人翻死了，需要自己耗费大量的精力看各种视频和数字教材，上课也是分小组上去讲题，可能更适合学霸们',4,3,4,11,5,0);
INSERT INTO "reviews" VALUES('584acf6b8e450a006c562580',2202,27,'上课会补充很多课本之外的东西，棒棒哒！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584ac9f7128fe1006c7d93c0',716,526,'很好的老师，虽然有时莫名的怼人。。。。。。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('584ac77961ff4b006cbfd8bb',1748,12558,'超级可爱的老师，但是很容易自嗨。上的双语课，有英语基础的同学可以不选这种，完全自学比较好。因为上课最多就是给你翻译，而且翻译的让你感到很无奈。。。
INSERT INTO "reviews" VALUES('584ac6a361ff4b006cbfd2c9',14324,394,'这个老师给分很高，很容易水过去课程，但是人超级自恋。超级，超级，超级自恋。（忍不了的那种）然后。。。尽量坐在第一排，会给你高分的。',3,3,5,11,1,0);
INSERT INTO "reviews" VALUES('584ac63dac502e00691edcff',5,5,'还没体验过答疑，但是课堂值得享受一番。有时候讲太快了学生会懵逼',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('584ac59361ff4b006cbfcaab',1048,26,'间歇性懵逼 很可爱23333',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('584ac37e128fe100691447cc',13243,13243,'平时课蛮水，大都是她学生讲，但是内容扩展了知识面。日常点名较严，而且结课的3000字论文很不好写。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('584ab617ac502e006c619344',819,9857,'我到现在为止都没有逃过可见这课多有意思（笑），除了这是土木狗一周唯一的文化调剂之外，老师讲课的角度和方式都很好，不算难懂。会需要在课后自己看一些视频或者原著的材料。有讨论环节计分（虽然其实略水）。想了解一下西方哲学的我很推荐。引用一句老师的话概述就是，希望开拓我们的视野，看一看马哲之外的西方哲学，也会看一看中国哲学。真的想上有意思的通识课的话，这个强力推荐！（啊，作业在通识课里算多的，助教也很BT，但是我觉得没问题）',5,4,5,14,5,0);
INSERT INTO "reviews" VALUES('584ab44dac502e006c618711',13736,114,'很明显了...就是表达能力比较捉急啊比较捉急......大概三节课以后才能大致听懂他在说什么，不过还是会有很多细碎到只有第一排才能听到的话还有无厘头的脑洞举例....但是是个很和蔼的老师就是啦...不拖堂，点名只有学院点名老师不会点，不过进度跟不上可能会把两讲课变成三连讲啦......',5,1,4,10,2,0);
INSERT INTO "reviews" VALUES('584ab371ac502e006c618038',12,4,'很好的一个老师。幽默。能力强。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('584ab356ac502e00691e4343',2202,27,'Iris是我见过最好的英语老师之一，唯一的缺憾就是口语不算完全标准？但是表达足够地道风趣，而且上课的时候会有很多互动。视频库感觉简直无穷无尽啊XDDD~快班小伙伴们都很赞的老师，值得选！（珍惜',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('584ab0ff61ff4b0058d49782',11070,1651,'老师其实人还是很好的，技术水准没话说，不过上课偶尔会生气吧...(主要是同学浪啊浪...）然后就是...工图日常了，课前要自己预习课后作业多，不过所有老师都这样吧XDD。有同学觉得批改严格，可是我觉得还好，自己大体上都是80+...只要认真啥问题没有',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('584aa740128fe100589db2bd',6377,7761,'这门课后来就全在浪费时间，没有实际做东西出来。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('584a75528e450a006c5378bc',637,694,'任课教师讲课十分细致，人很幽默',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('584a53cdac502e006c5eb960',11006,694,'老师讲课讲得好，就是自己学习不认真。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584981aa61ff4b0058ce9d8f',13105,14690,'只要交了就让过（前提是自己做的）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584963310ce463005c48917e',14691,14691,'讲得很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58494b838d6d8100543a6b19',14692,14692,'不挂人一切都好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584929c2b123db0066051983',11209,4305,'上课无聊乏味',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('5849047c8d6d810054385a0a',14694,850,'老师长得好看',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('584817d8128fe10058bf826f',733,335,'超级好，挑不出毛病。',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('5847ee5b128fe1006c60dcae',8295,2461,'上课无活力，绝大部分听不懂。',5,2,1,8,1,0);
INSERT INTO "reviews" VALUES('5847d059ac502e006ce66dba',11785,11785,'老师专业，亲切，与同学是朋友关系。专业知识，人生哲理样样都说，收获很大。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5847ae21128fe1006c5f1fe5',14698,14698,'很有大师风范，讲课好，课上气氛有张有弛，学到内容很多，收获大',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5846b9d8a22b9d007aa889ff',13080,14699,'幽默诙谐，亲和力强，专业水平高，讲的很多我们都听不懂，然而也知道我们听不懂，关键是压根没指望我们能听懂！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5846a4bfac502e006ce0afd7',13975,13975,'老师很温柔而且讲课内容很丰富，互动很足但不会觉得很尴尬，重点是老师很有气质看得出来年轻时候一定很漂亮，当然现在也很漂亮，而且年轻。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584677be128fe10058b632c9',732,156,'认真，负责，健康向上',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('584644e161ff4b006ba6254e',14702,2,'上课很有活力，一反传统授课方式，很有大牌教授风范。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5846293861ff4b006c3c169f',14703,14703,'上课认真负责，从中收获颇丰。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('583fe770128fe1005763231b',175,175,'首先，讲课真的无聊！！！完全照ppt讲，我们有问题的话也不过是再念多几遍ppt，只能自学。其次，特别抠细节，第一节课的时候提了不下10条要求，诸如名字和班级哪个在前等，错了直接扣到不及格，舍友最近的大图得分是80-30，就是因为花多一条可有可无的中轴线[手动再见]
INSERT INTO "reviews" VALUES('583eaba861ff4b006b66ba86',5145,12652,'很少挂人，不错',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('583e6baa0ce463006bb3554c',2168,2779,'教课方式很好，比较容易接受，也能学到很多东西',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('583e3c150ce463006bb22cf0',14707,14707,'课堂生动有趣',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('583e27ecac502e006c2de8c2',14708,14708,'知识渊博，讲课生动有趣，令人受益匪浅，对待学生认真，负责，简直业界良心！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('583d900561ff4b007edc63a4',13243,13243,'如果是她学生上的话会很水基本也不点名，不过如果赶上她上课的时候比较严经常点名，无故旷两次课没有学分',4,3,3,10,1,0);
INSERT INTO "reviews" VALUES('58370c8b570c35005e4b55f8',7952,496,'超爱点名。但是讲课真心很好。我敲过一些课，第三讲去都给我算到了。😂最后还给了我很高的分。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5836c4a0c59e0d0057794cf7',13510,13510,'上课有激情，幽默有趣，学术大牛。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('58369bd7c59e0d005777afea',14712,14712,'牛逼的老师，渣渣学生。但是所经历的最负责的最会授课的老师，没有之一。',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('58368496128fe178553dac03',14606,14606,'没有重点，全书都是考点。跪求老师手下留情，明天考试加油，Fighting！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5835dea6570c35005e43aa30',696,698,'老师让我们自己学习的内容过多。',3,2,2,7,3,0);
INSERT INTO "reviews" VALUES('5835a26961ff4b0061f4b8b9',2205,14715,'老师挺好，给分可以',5,4,4,13,0,0);
