INSERT INTO "reviews" VALUES('5829cce3da2f600056e85bf4',696,723,'真心不配当老师！作为老师，讲课都是助教讲的。不知道工资是给谁的！',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5829a05a0ce46300560cd64d',327,327,'亲和力给1分已经说明了一切',4,3,1,8,1,0);
