INSERT INTO "reviews" VALUES('582690ab5bbb50004f0bf9e1',14442,14738,'本门课程偏理论理解，计算不难。所以老师多数时候照书念，公式计算过得快，但在文学理解记忆型知识上会穿插课外知识，此时氛围一般轻松活跃。老师高谈幽默，和蔼可亲，我个人很喜欢这个老师。',3,4,5,12,0,0);
INSERT INTO "reviews" VALUES('58248de15bbb5000590ed035',14607,14739,'郭老师仅管头发斑白，环绕在头上，但一直认为自己是个青年，上课积极活泼，为人和蔼可亲，生活上也是一个帅气的小老头儿。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('58246464a22b9d006706d55d',14740,313,'李老师人很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('582443932e958a1299285c26',14607,14739,'老师讲课很认真，同学的疑问也会认真解答，很好的老师。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('58242646128fe1005a2b2aa7',14607,7866,'这门课比较生涩难懂，对数学、物理水平要求高，公式推导复杂，学起来比较困难。老师教学热情，讲解十分尽心，努力让我们理解，但我们还是听不太懂，学霸除外！！！',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('582410f167f3560058c37f6f',5160,10064,'善于结合自己所做的工程来讲述课程内容，负责任，有幽默感',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('5822e9d50ce4630058a88fc5',14606,14606,'讲课认真负责，经常会讲一些课外的前沿知识分享给我们。不仅教授书本知识，还会讲一些生活道理给我们。不过有一点得差评，期末竟然不给我们划重点。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5822c453bf22ec0068eb356e',14745,14745,'老师非常负责认真，而且讲课生动有感染力',4,5,5,14,0,0);
