INSERT INTO "reviews" VALUES('58045491d203090068403c69',7785,8134,'人还是可以的，就是比较忙，对学生关注感觉有点少。（本科的学生）。上课略缺乏吸引力，平时对学生还是可以的。',4,4,4,12,0,0);
