INSERT INTO "reviews" VALUES('57eb999bc4c971005f8bf714',3031,3031,'互动十足，内容丰富',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('57ea4f7ca3413100625110f7',32,14780,'老师非常好，讲课认真，有耐心，就是平时点名有点多！',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('57ea35efda2f600060e6272f',637,694,'讲得好，学不懂，课程太难',4,4,5,13,1,1);
INSERT INTO "reviews" VALUES('57e90d3eda2f600060de2039',2390,186,'好人，东北妞，哈工大毕业，女博士！上课聊韩剧。很热情，给分高，偶尔点名，期末考试的考题会在最后一节课上讲，背会就行了😂，平时成绩都给满。',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('57e90b1b0e3dd900582d2a3c',2688,2688,'从不点名，讲的内容汽车迷不容错过',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57e8c7fba22b9d00615b846a',14784,14784,'老师讲课很生动，学识渊博',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57e8a0d667f3560057a13006',1608,1608,'课程设计太多，又不进行讲解，效果很差',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('57e87d710bd1d0005b092bd6',2251,2251,'课程设计讲得太碎，但认真',1,3,1,5,2,0);
INSERT INTO "reviews" VALUES('57e77fb5da2f600060d17aac',811,14787,'一个傻子，上课笑着骂自己傻。他可是个妈咪宝贝呦。同学们，跟着这种老师没自我的人是不会学到什么东西的。',3,3,3,9,0,2);
INSERT INTO "reviews" VALUES('57e6649667f35600579295a3',811,762,'老师只知道得得得的说，还嘴欠。那个嘴碎的呀比女的都能哆机。上课不讲重点，重点一笔带过，不重要的讲个没完！',1,1,1,3,2,2);
INSERT INTO "reviews" VALUES('57e616098ac247005bc61e65',2210,1156,'上课氛围轻松，但是有点催眠，老师讲课都是带着笑容的，上课听的人很少，还好线代简单，期末前复习撸过了。',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('57e615600e3dd90058177acc',7824,307,'老师很耐心，很友善，可是表达略繁复，有时听不懂。上课有时会拿出芯片里的电路图(全班懵逼)，平时成绩有适当提分。上课声音有点小，略催眠，给分松，全班只挂了1个。',4,2,5,11,1,0);
INSERT INTO "reviews" VALUES('57e61429128fe100570159fd',198,179,'外表和内心都是标准的教师的feel，作业很少，讲课细致，有针对性，上课喜欢在PPT上用鼠标画图(PS好希望学校给胡老师配一个画板)，上课会引用生活中的例子。私下也很nice，很幽默，很温柔。另外，她的课非常难抢，大家应该懂原因了吧。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57e612c1c4c971005f64c999',13021,803,'很有范儿的老师，上课氛围轻松，讲解详细有耐心，和蔼可亲。(PS 老师很有魅力，在过道上走很多人朝她问好)虽然作业不少但是还是挡不住人格魅力。另外，平时成绩给的很高',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57e611a4a341310062434e07',2259,641,'讲课没有激情，非常催眠，上课也面无表情，给分一般，上课人太少会点名',3,3,2,8,0,1);
INSERT INTO "reviews" VALUES('57e610d4128fe10057013a25',68,68,'上课活跃的话会很被他喜欢，感觉有点势力的老师，说的最多的话就是快上来讲有加分，英语基础不好的根本不怎么鸟你，但是专业水平还是不错的。(顺序有点乱不管了)',5,4,1,10,0,0);
INSERT INTO "reviews" VALUES('57e60f880bd1d0005bfa3140',1320,3017,'张老师的教学有点偏向疯狂英语，口语嘚啵嘚啵讲的飞快，中文也是。上课经常抽点名，自诩能记住全班名字，然而经常刚点完名说好大家都来了，过几分钟就有迟到的进来了(尴尬)。好像迟到会被扣分，不过如果你坐后排也很普通她没记住你名字就还好说。上课会就书本上的内容挖掘很多，也经常扯得太远，经常结合生活讲一些笑话',5,4,4,13,1,1);
INSERT INTO "reviews" VALUES('57e50388da2f600060bff021',7728,3332,'赵老师水平高，讲话也比较有意思，上课气氛也不错，讲课棒，复习给重点。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57e4df6f0e3dd900580ce96b',1975,619,'远超越课程的收获',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('57e4bc0aa22b9d00613bd8aa',14777,14777,'幽默的工程老手，实践经验丰富，深藏不漏。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57e49d1ac4c971005f56ffa0',9895,9895,'讲课很好，认真，考试公平公正',4,2,5,11,0,0);
INSERT INTO "reviews" VALUES('57e3ba8cbf22ec005852c6b8',14800,14800,'每次上课都有很大收获，总能让大家不约而同地为老师鼓掌。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57e39e6b7db2a200639b48e6',7233,14801,'老师态度和蔼可亲，在知识讲解中很详细，仔细。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57e38196d20309006920a248',13644,13644,'是一位非常有才学的老师，不局限于课本，对于史记的研讨从不在课上讲文本，（这过于简单，难度低），只分析司马迁的写作手段与历史人物的分析深入研究。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('57e26ccfa0bb9f0058b8e39c',14803,27,'老师讲课能抓住我们的兴趣',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('57e249a6c4c971006141d322',344,5760,'老师平时要求严格，但是课后却和蔼可亲。上课讲得很好。',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('57e223adbf22ec0058294781',8,8,'存在着教学歧视。',4,4,3,11,1,0);
INSERT INTO "reviews" VALUES('57e10c03128fe10064de7423',8,8,'有严重的教学歧视，极度不认真！！！',3,2,5,10,1,0);
INSERT INTO "reviews" VALUES('57e0e98e5bbb50005e753cfa',586,24,'人很好，讲课仔细。',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('57e0bc150e3dd900697d26bb',1158,26,'娟姐人特别好，不论你问的问题有多简单，她都耐心地为你解答，态度温和，对学生很好。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57e0956867f3560056b70d82',13977,397,'讲的不咋样，让人超级想睡觉；基本只能靠自学；而且考试不划重点。',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('57dffa720e3dd9006979a987',5415,51,'董洁老师的课程引导我们思考许许多多哲学、道德、心理等问题，是拓展我们思维和视野的不可多得的好课程！',4,5,5,14,2,0);
INSERT INTO "reviews" VALUES('57dff35e0bd1d00057fd7bc9',846,27,'老师非常好，对学生关心，对学生很有耐心。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57dfeae4c4c971006133639e',1048,26,'多讲点题，主要是人太帅了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57dfe6338ac24700616eccbe',1738,2349,'课程内容简单明了。一门通识课，不算特别水，但也没有很严。作业轻松，给分不错，老师年轻，挺随和的。',4,5,4,13,0,1);
INSERT INTO "reviews" VALUES('57de6a1f7db2a24eb1b9f47d',986,13927,'老师上课很认真，也交给我们很多听译技巧，帮助我们找一些有趣的方法活跃课堂，口语也很好，对我们也很温柔、幽默=w=',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57de5182c4c971006129acb2',867,27,'完全好评，人特别温柔，基本不点名，迟到也不生气，平时考试直接人不见了放纵我们。讲课也不错，喜欢，长得也好看。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('57de2d2d2e958a005468d1a4',11891,92,'我认为罗林老师专业水平还是相当好的，但上课的方式过于死板，让很多同学都集中不了精力。（虽然大部分原因在自己），应该多加一点习题课，这样更能巩固知识。',4,2,3,9,1,0);
INSERT INTO "reviews" VALUES('57de15805bbb50005e64a16f',118,3845,'肖建波老师上课认真投入，非常有逻辑性。同时，肖建波老师很关心同学们的专业素养，与专业兴趣。',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('57dded6ba0bb9f00589c28b0',741,911,'总体不错',4,4,3,11,1,2);
INSERT INTO "reviews" VALUES('57d96356d203090069c7ba50',1201,1201,'和蔼的老师，敬业，有耐心',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57d93dd567f35600568accbe',8138,8138,'课很水，但作业和考试十分严格。第一次教土木，总是只上一节课，挺逗的。',4,3,3,10,1,1);
INSERT INTO "reviews" VALUES('57d92664d203090069c59d79',14821,14821,'讲解的知识比较通俗易懂，但是上课速度过快',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('57d902ff8ac247006144756f',14822,14822,'老师认真负责，课堂幽默风趣，课堂形式多种多样，在学中玩，在玩中学。真正可以实现跨学科的交流。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('57d8bade2e958a0054456738',762,762,'讲课自顾自不管学生听得懂不懂 给分超级低 乱扣平时成绩 十分腊鸡',2,1,1,4,4,0);
INSERT INTO "reviews" VALUES('57d8b97bc4c971006105348c',4936,14056,'讲不清课 给分低',1,1,3,5,0,0);
