INSERT INTO "reviews" VALUES('57d78fab2e958a005476c01d',4072,3845,'老师非常负责，每周必加一节习题课，假期过后90%会补课，上课爱讲证明，考试计算证明齐飞，学生分数巨低。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('57d774f20bd1d0005856d227',2381,2381,'课程难度大、大、大',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57d75d0967f3560057ecff85',10328,2158,'这个老师讲课很有意思。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57d68815a0bb9f0057e9bf33',9882,22,'和善可亲，教学幽默风趣，课堂氛围轻松，认真负责，耐心解答疑难',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('57d663fcd20309006a04b512',14409,26,'虽然听不进去，但也让人不好意思说坏话。',5,2,5,12,1,0);
INSERT INTO "reviews" VALUES('57d63953d20309006a033e15',4986,27,'何老师工作认真负责，经常和同学们聊天，平时分也挺高的，关心同学，就是感觉听不到东西，讲不出知识来。',4,5,5,14,4,0);
INSERT INTO "reviews" VALUES('57d617925bbb50005bc4124d',510,86,'不水，博学，认真，负责',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57d4dbe6816dfa0054452ea0',31,3243,'很认真很负责任的好老师，教学授课很有亲和感，水平很高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57d4b5ed816dfa0054442ba5',3477,1697,'表面上严肃认真，无私拖堂，周考测试。其实讲课无重点。跳跃太快，教不好就学不好，学不好又不停地考。导致学生拒有厌学心理。',2,3,1,6,0,0);
INSERT INTO "reviews" VALUES('57d265762e958a005454ad8e',1105,13010,'我特别迷恋他',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('57d23dd57db2a200682691bd',14409,26,'很负责，学生有不会的题可以进群问',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57d2189067f3560057ca3982',586,24,'认真，负责，有热心，相处很随和，无压力',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('57d18e3ca0bb9f0057c9bf72',1949,230,'时隔一年在课堂上在遇这个老师，讲实话样子早就模糊了。但是在她开口的时候，怎会忘记。😄这个老师是一个十分有感染力的老师，如果你喜欢历史的话，你会被她带入一种氛围，唤醒对历史上中国革命者一种敬意的情怀。讲课是循循善诱型。表达的永远是自己的观点，不是强加型。算是我大学里面遇见的值得我喜欢尊敬的好老师之一。忽然有一种惆怅呀。大学水课太多。少遇这种会让你真正想学习知识的课呀。珍惜。',5,5,5,15,12,1);
INSERT INTO "reviews" VALUES('57d186cda22b9d006c43f520',5828,5828,'不得不说，锦红老师是对我影响最大的老师，老师认真负责，十分亲切，而且很有心，真正切身处地地为每一位学生着想。老师教会了我许多关于自我管理的方法，让我开始学着改变自己，我开始管理自己的时间，学着做详细的计划与目标，学着让自己的生活变得更加规律。在与老师的交流中，我懂得了很多道理，这些远比高数书上的知识更有用，他会让你改变内在，修正生活方式，而这些对一个人的发展更加重要！在老师的督促下，我会努力让自己变得更加优秀。虽然这是一门通识课，但是请相信：心不唤物，物不至。只要认真对待，一定会有收获！选这门课，是我做过最正确的一件事，如果你也有幸遇到，一定不要忘记我这篇发自内心的极力推荐ヽ(○^㉨^)ﾉ♪',5,5,5,15,18,0);
INSERT INTO "reviews" VALUES('57d1713a67f3560057c6d933',373,230,'教学十分地热情，专业知识很多，我学到很多。',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('57d14d99c4c971006121a088',14841,26,'老师讲课全无艺术性，给我们学习课本造成了很大障碍，增加复习压力',2,2,1,5,0,0);
