INSERT INTO "reviews" VALUES('57cd321d7db2a200789f0f93',8572,27,'老师不仅自身专业背景过硬，而且非常有气质，举手投足都让我们感受到成熟女性的优雅姿态。不仅是良师，更是益友。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57cd28bcdf0eea00613fbdcb',586,24,'喜欢老师的上课风格，教学认真又不失亲和力，能让我从内心喜欢这门课，喜欢这个老师。',4,4,5,13,1,0);
