INSERT INTO "reviews" VALUES('57cd0d762e958a0068e72026',13254,229,'宽而不松，，严而不紧。难得的好老师，平时分高，会提分救人。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57ccfe76c4c97100543d6705',4112,281,'川普，打分的话月考多少分就多少分，基本不点名。有时说一些冷笑话，不过不知道为什么我总能get到他的点',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('57ccf85467f3560057c89c33',2200,2200,'老师真的很负责，讲课讲得很细致，生动',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('57ccf09767f3560057c86229',13814,14867,'老师专业水平极高，课程组织很好，可惜人有些高冷。',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('57cce8da165abd0068f40ce1',6994,8138,'上课语速太快！废话有点多！给分超级低！希望能...体谅一下学生！',5,5,3,13,1,1);
INSERT INTO "reviews" VALUES('57cce069a22b9d006ba3b460',8138,8138,'讲课太枯燥，给分太低，要求太高，对于这门并不那么有用的课',2,1,3,6,1,0);
INSERT INTO "reviews" VALUES('57cbee7b5bbb500074f1bff9',14870,14870,'我觉得这个课很好！能学很多知识',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('57cba34ec4c9710054349bbb',14565,14871,'缺  安排不妥，组织不好，时间没有合理安排     优  让同学们自由讨论，自由选题；提交作业方式新颖 老师工作很积极很投入',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('57cb99edc4c9710054345174',8453,26,'上课风格好，讲课清楚，吸引注意力，感觉很有学问，一道题可能有很好的解决方法和多样路径，注重公式的原理，',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57cb90c8a0bb9f007f47c555',8453,26,'袁俭授课认真负责，每一知识点都讲解的细致，也容易听懂，每一道题都会亲自在黑板上认真计算一遍，细节讲解十分详细',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57cb89fb165abd0068eb10e5',2740,2735,'老师授课全程板书，不用听，而且讲推导过程。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57cb823e165abd0068ead34f',2567,7573,'老师总体来说真心不错，能够积极地调动课堂气氛，专业能力也强',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57ca5d5ddf0eea00613d096b',293,375,'老师风趣幽默，课堂轻松活泼，五星好评！！！',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('57ca58702e958a0068d580e5',727,3225,'感觉老师的专业水平挺不错的，但上课有点无聊',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('57ca4f0f7db2a200788c0e84',785,26,'老师上课富有激情，而且十分负责',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('57ca49e68ac247006446050a',14879,14879,'这个课可以没有，太难了。',5,3,5,13,0,0);
INSERT INTO "reviews" VALUES('57ca44bd5bbb500074e691cc',556,556,'还行吧！虽然理论课有点无聊。',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('57ca3b5d7db2a200788b66cd',14881,14881,'不知道大一英语/翻译专业的人学新概念英语3有什么意义，那是一本简单到我用来训练语感的东西！！老师还像幼师！******',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('57c973ae6be3ff006a7e1054',4925,4925,'讲课生动有趣，案例清晰，老师随和，上课幽默',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57c96d95c4c9710054272cbd',293,375,'生动有趣，有吸引力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57c9686cc4c971005426fefb',4112,26,'讲课认真，重要的是手写，不用多媒体展示，虽说说话带点川普，不过还是讲得超级棒！',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('57c962cb67f3560057b211a4',51,375,'表达清晰，感觉有亲和力，例子生动，给人以正能量',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57c95cee0a2b58006b25d05a',1001,2381,'棒！考试真的爽~hhh',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('57c9538d8ac24700644092fb',3754,156,'与学生的互动不够，按照课件来授课，比较无趣，无法激起学生们的学习兴趣',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('57c94e287db2a200788626ce',762,762,'讲得很清楚，但讲的都是不考的，很容易听糊涂，而且课堂要求严，给分低',5,4,4,13,0,1);
INSERT INTO "reviews" VALUES('57c911ab5bbb500074df283f',1855,24,'上课全是啰里啰嗦的废话，总是找各种理由瞧不起学生。讲课很渣，从不点名，没有期中考试，你问问题他永远答不上来。但是期末考试挂科少，34分就能过',2,2,1,5,2,0);
INSERT INTO "reviews" VALUES('57c8daff0a2b58006b21b919',12301,394,'课程比较无聊，给分还算大方。无聊的课程之中活跃的同学更显得难得，不论对学生还是对老师。难得有这种学生，有了后因难得老师更喜欢。所以，好好把握吧。',2,2,4,8,0,0);
INSERT INTO "reviews" VALUES('57c8d9b38ac24700643ce514',13971,14891,'最爱的老师之一。李老师是以开放的心和严谨的态度来教学的，因此给很多同学造成的印象是：严肃、师太、要挂。这门课属于必选，因此，就讲些实用的吧。1.上课积极点，平时成绩比重很高。跟李老师有互动，但别乱回答，基础的理论别搞错，其他的开放性的东西随便讲；2.想得高分要做Pre；3.别作弊。要拿高分方法很多，作弊是最蠢的一种。最后唠叨一下，到了专业课的时期，试卷都比较开放，平时积累很重要。',5,5,3,13,3,0);
INSERT INTO "reviews" VALUES('57c8d6660a2b58006b219c84',5415,51,'每次上课都会讲很多朋友ABC的例子，亲切有代入感，讲故事的过程中渗入一些道理，属于不计较分数、点名我都风雨无阻地主动上课的那种课。除了，第一节课好像有互动吧，促进相互认识，当时性格寡淡，不感兴趣所以好像走了吧？',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57c8d4b08ac24700643cc633',14800,14800,'1.课程比较开放，无指定教材，会讲很多营销案例，很有趣，让我直到现在都对营销充满兴趣。
INSERT INTO "reviews" VALUES('57c8d1da0bd1d0006b446c47',4936,14056,'周老师的课铁定五分！深入浅出的讲解，简单易懂，保证了课程质量，这是一点。第二，考试划范围，基本就是平时作业题吧，试题简单，给分大方，周围的小伙伴都是90分以上。PS：周老师的形象、风格请参考周立波（^人^）',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('57c83607c4c97100541ffed7',762,762,'讲的内容很奇怪啊——证明题我们都不考——在那边讲好多。',5,4,4,13,0,1);
INSERT INTO "reviews" VALUES('57c82f3ad342d30068d106c9',13341,13341,'老师很好，知识储备丰富，授课内容很生动，而且有涵养 但唯一不满意，即上课没人听。大家都写作业或玩手机',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57c827f56be3ff006a764172',293,375,'上课很有意思',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57c820b0165abd0068d65e06',467,22,'上课过度依赖PPT，对定义解析不透',2,3,4,9,3,4);
INSERT INTO "reviews" VALUES('57c8187ba633bd006c000acb',819,9857,'上课很极积，内容很丰富，情感很饱满',4,3,4,11,3,0);
INSERT INTO "reviews" VALUES('57c7e4078ac247006437b144',13171,965,'老师讲话有点不清晰，三连讲上着上着就饿了。平时听不懂，考前突击很有效，85加。期中半开卷，带一张a4纸大小的小抄。老师负责任，真不错。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('57c7e370df0eea006134f3be',12218,762,'满黑板的公式符号，真的想睡觉啊！关键是，考试题怎么可以比平常作业最难的题还难呢（黑人问号？？？）给分还超严。概率论老师都这么不食人间烟火吗....................',5,3,4,12,0,4);
INSERT INTO "reviews" VALUES('57c7e33b79bc440063e84498',4,4,'人很nice，风趣幽默！长得帅！给分高！不点名！',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('57c7e2dfc4c97100541d5a1b',14201,48,'老师只爱年轻漂亮的小伙子。🙂🙂🙂给女生分数低，而且对女生极其凶！！上课，男生小组打比赛，没女生啥事……',3,2,2,7,2,0);
INSERT INTO "reviews" VALUES('57c7d77d5bbb500074d7b73b',3437,6251,'讲课认真，讲得也不错，但是，为什么我就那么想睡觉呢',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('57c7d6d379bc440063e7d93e',5,2735,'超棒超酷 答疑耐心可爱 超棒 呆萌 太可爱了。讲的可以 好棒好棒 好棒，哈哈~~~',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('57c7d670a341310064db3be5',2525,1169,'必须满分好吧，真正从头到尾给你梳理的好老师！大学还有哪个老师能像梁老师一样用高中老师的教学方法给你上课？上她的课，想睡觉都难',5,5,5,15,10,1);
INSERT INTO "reviews" VALUES('57c7d4e36be3ff006a738904',736,551,'能把这么无聊的数据结构讲出花来我也是服了，分析得真的挺透彻的，当然，没学好又只能怪自己了(；′⌒`)',5,4,3,12,3,0);
INSERT INTO "reviews" VALUES('57c7d3a0a633bd006cfdc32f',2231,256,'老师真的不错，讲得挺生动的，还经常给我们灌鸡汤，就是不生动的部分全都没讲......',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57c7d2f5a341310064db1fe3',7459,426,'不好意思，您那不知道哪里的方言和口音让我完全听不懂您在说什么。我枉为一个中国人，真的对不住您',3,1,3,7,6,1);
INSERT INTO "reviews" VALUES('57c7d2478ac2470064371932',14910,14910,'这个老师讲课真的好，不厌其烦地给我们讲题。听说他要退休了，不知道以后还有没有他的课。易男神，工数没学好是我对不住你/(ㄒoㄒ)/~~',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('57c7d1758ac24700643711e0',8682,31,'怎么说呢，这个老师很好玩。作业少，基本不点名。但是该死的口音毁了一切！真的听不清啊！！！工数本来就比高数难还要我自学，要我老命呐！',4,2,5,11,1,0);
INSERT INTO "reviews" VALUES('57c7cf82165abd0068d3a1c7',1419,48,'很多人不习惯王老师的教学，认为她太严。但我想在国家队队员的眼中，这些可能都是皮毛中的皮毛吧。专业性没的说，课堂管理也很灵活，没事了也不会硬留着上课，还有供学生刷分的机会。想学真本事的话，建议不要错过！',5,5,4,14,8,3);
INSERT INTO "reviews" VALUES('57c7ca456be3ff006a732fca',5267,837,'冯琳老师是新入校的老师，待学生亲和，平易近人，但上课方式单一、平淡，难以吸引学生注意力。',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('57c7b6eba341310064da273a',14822,85,'老师人很好，平时基本都很爱笑，而且不点名的，给分也还可以，不过建议乒乓球选第一年之后不换课因为第二年是在第一年的基础之上的。',3,5,5,13,0,1);
INSERT INTO "reviews" VALUES('57c7b585c4c97100541bc74d',4925,4925,'这门课绝了！能把各种血淋淋的杀人事件讲得如此爆笑的仅此一人。不过警告一些心理承受能力巨弱的妹子请绕道。还有就是有轻生念头的孩子，也请做决定之前来听听这老师的课。血腥中带着搞笑。你值得拥有。😄',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('57c7b33779bc440063e6a4a8',280,280,'分给的很高，老师也很漂亮，跳舞也很好。课程不需要舞蹈基础。不单单是跳舞，还会教一些塑性减脂的锻炼。大一上半学期教了维也纳舞曲，下半学期教了华尔兹。总的来说对我在舞蹈上面的认知提高了不少。上个班女生不是很多，所以舞伴需要主动去争取，男同胞们要加油。虽然选这个课的大多是其它课没选上的同学，但是去了跟着老师主动的好好学好好练，一年来收获会很大。',5,5,4,14,3,2);
INSERT INTO "reviews" VALUES('57c7b2eca341310064da05b3',1267,5618,'高飞老师是我最喜欢的一个老师。她的课基本上我都上过。如果你想水过也没关系，但是这样太可惜了，因为她讲课讲的很好。她的课虽然不是属于开阔眼见型，但是对自己，以及人际相处，甚至思考未来身份的转换等方面都具有启迪的作用。她的课很难选的。属于爆款型哈哈哈。你们加油。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57c7acc5128fe100695972a5',5219,280,'老师腿好漂亮啊，是个辣妈。上课挺严厉的，但真的很适合女生上。形体 协调性 都会有改善，最重要的是可以教你穿高跟鞋。 教的物种也很多，像是华尔兹 恰恰 伦巴都有，虽然学的很浅，但是大家一起恰恰恰真的很开心！ 还有男生可以来哦 很多美女 还能牵手跳舞 是不是很爽。',5,5,4,14,4,0);
INSERT INTO "reviews" VALUES('57c7ac3a165abd0068d27b60',13913,48,'算是我羽毛球启蒙老师吧😂但是明显的男女区别对待，有好有坏吧。虽然待我不错，打分大部分靠的是实力。打淘汰赛。但是也有例外的。好吧应该大学都有这种情况吧。无所谓。还算公正、不过第一轮考试的时候如果没有实力的话，还是挺难过的。我们发球考核全班男女生首轮过总共才十几个左右。总体而言上她的体育也好玩，感谢！',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('57c7a99ea633bd006cfc5338',248,48,'这老师挺好的。男女生一视同仁。除了有点啰嗦。哈哈哈。打分也是公正类型，你有实力的话分更高。😄😄挺喜欢羽毛球打团体赛的。哦对。这老师还有一点不太好。寒假作业😂类似于竞技体育精神，或者战略思想。总之不错。大学生活不能缺少的一门羽毛球课。',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('57c7a8636be3ff006a720e42',13913,48,'上了两年龙老师的羽毛球课，羽毛球水平还是提升很大的。龙老师的教学非常专业，而且平时也相当平易近人，会跟大家一起打球。龙老师的课每年都特别抢手，建议先下手为强啊！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57c7a8550a2b58006b1a577b',12757,8460,'老师很好啊，热情，亲切，平时也没作业。关于上一条评论：期末作业这种东西，经济学的论文，随便抄抄扯扯，字数就够了好麽；另外期末考试啊，老！师！都！发！了！原！题！的！好！嘛！对着手机抄就是了啊，诶，都是选择题的原题。课堂确实能学到很多经济学知识的',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57c7a7205bbb500074d6133e',1685,1685,'首先这个课程非常适合我们的女同学（虽然我是男的，哈哈）。课程的主要内容就是一些健身房常见的的有氧运动，很燃脂的，对女同学们保持身材很有好处吧(*''▽''*)♪，女的多了，男同学是不是就想去呢？嘿嘿，美女多啊，不过学长叮嘱一下：上课要紧哈！关于课程：老师经常点名，不过不要缺勤三分之一就没问题，考试也很简单，经常去，或者即使临时抱佛脚也是可以的，不会挂。个人觉得还是很值的，环境设施都很好，这些在健身房都是要收费的哦',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('57c7a6232e958a0068c4598d',5219,280,'这个老师的专业水平上舞蹈课是绰绰有余的，但是由于是体育课，就学的比较水，没有基础的人也可以很快上手。有很多男女搭手的场景，男生很少。期末要自己组队编舞，老师有点小严厉，两周点次名，其实影响也不大',3,5,4,12,1,0);
INSERT INTO "reviews" VALUES('57c7a2160e3dd9006a28b006',280,280,'老师水平高，然而非常冷酷不近人情，动作细节讲得粗略，下来问她也不是很耐烦。请假必须交假条盖章，不认口头请假的',5,2,1,8,4,0);
INSERT INTO "reviews" VALUES('57c797aa8ac24700643524a9',87,537,'马老师教的是足球，建议喜欢足球的报，绝对值得。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57c7943b79bc440063e5af02',87,6744,'马老师据说以前是中超裁判，所以专业性不用怀疑。要求也比较人性化，但是女生最好不要报这个，强烈建议喜欢足球的报这个老师。最后考试也好过，基本不会挂人',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('57c790ca128fe10069589203',2674,3409,'老师人很素雅，很和气。教地很棒，不能逃课，可以学到很多知识。',5,5,5,15,1,11);
INSERT INTO "reviews" VALUES('57c7812b8ac2470064347332',27,27,'普通话很标准，很和善，从讲课时的流利度来看，她在备课时一定花了很多功父',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('57c6db8b2e958a0069948b4f',8453,26,'旁听过袁俭教授的课，交大建模总教练，上课特牛逼，满满人格魅力！好多妹子都说他是男神一般的存在。年纪虽大，发色却是乌黑的！帅！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('57c6d8a8a633bd005d907c49',969,23,'讨厌的老师！坑！最后的综合实验说我抄袭给了我0分，平时成绩拉低不少！上课无聊，催眠神师',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('57c6d805128fe1005fe79b79',4784,641,'我认为老师其实很亲切，给分可以，平时成绩基本可以得满，前提是作业每次交。最后快期末会让你自愿举手回答问题，回答了就平时成绩给满。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57c6d779165abd00667f7352',9882,13530,'上课思维跳跃，动作丰富',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('57c6c007165abd00667eb7e4',452,965,'上课幽默，对同学们要求严格',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('57c576512e958a00698b2358',13975,13975,'以极快的速度了解我们，在极短的时间内传播有效的信息，以极丰富的经历充实我们',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57c56de0128fe1005fddf7c9',7435,14936,'亲和，细心，热情，与同学打成一片，且专业素养较高，是一位德才兼备的教师。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('57c564f70a2b58006c07e74a',1320,3017,'张老师上课很有热情，表达能力很强，口才也很好，张老师的口语讲的口音正，上课也不怎么点名，平时分给很高的。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('57c55c0ec4c97100619f4a8d',380,793,'个人知识渊博，能力出众，就是口头表述欠缺训练，口音有催眠功能，想听课都止不住想睡。',5,3,4,12,3,0);
INSERT INTO "reviews" VALUES('57c52d18128fe1005fdbd526',13828,14939,'老师不修边幅且随性之至，这么重要的一门课在老师迷一样的口音中彻底毁了，苍天啊，期末都不知道怎么复习。',2,1,4,7,0,0);
INSERT INTO "reviews" VALUES('57c52957165abd0066739037',2895,92,'不会说普通话，还记迟到',2,1,2,5,1,0);
INSERT INTO "reviews" VALUES('57c522c76be3ff00584977e1',762,762,'陈老师的课上老是讲一些听不懂的段子，黑板上写满数学符号，还时不时来几句英文。/再见',3,2,3,8,1,0);
INSERT INTO "reviews" VALUES('57c51e8edf0eea0066892277',13828,13828,'咋整？！咋回事呢。一位无与伦比的老师，完全刷新了我的世界观',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('57c51785c4c97100619ce862',2821,40,'选了她的课真特么后悔。',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('57c512986be3ff005848de6b',13828,14939,'这个老师的口音从山东向西跨越至新疆（醉了-_-），这么重要的专业课全班没有人能听懂他说话（怪我咯^v^)划重点？？他说了哈？EXO Me？？！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('57c50f1379bc440063efecc1',737,737,'上课根本不讲课******',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('57c50b8e8ac2470063535298',1225,40,'他吧，咋说呢？不喜欢他，铁面无私的小包公，虽然长得很清秀，口语水平，专业水平都很高，但是感觉讲课讲不了实质内容，一种痞子的感觉。',4,3,2,9,8,3);
INSERT INTO "reviews" VALUES('57c5053aa341316fa62df1c1',485,3822,'老师人很好，除了上课以后还不经意地给我们传授许多人生经验，老师很漂亮。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57b9ad8e5bbb500063f566e0',2298,3586,'老师相当负责，好吗，这学期对他印象深，三次网上作业忘交，希望老师给我加上（通过邮箱补交了）。本以为是水课却这么多作业！天天天！！！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('57b9aa9d2e958a00693212ae',7927,1252,'跪求90+，亲爱的赵子，宝宝把头像都换成你TAT',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('579eb4f58ac247005fe8ac75',6323,23,'大叔真的是个很好很和气的人，真的像大伯一样。60人的课堂每次到20个左右，却从来不点名；上课的时候睡觉玩手机也不会来讲你；怕下面的人听不清，虽然他声音很大声也一直拿着个话筒；如北京躺般轻松的课堂氛围；In conclusion，藏青色的PPT背景不变的字体慈祥得如安眠曲一样的声音是导致之前现象的根本原因。',5,3,5,13,6,0);
INSERT INTO "reviews" VALUES('5798dd038ac247005f4ee021',3025,3025,'何老师是比较懂学生的老师，上课讲课件上的东西其实相对较少，更多的是扩展开来讲一些学生一般接触不到的实践知识。
INSERT INTO "reviews" VALUES('5798db9b5bbb50006302cd62',12424,1129,'虽然这门课我拿到了几乎是专业的最高分，但我还是要给楼老师差评。楼老师的专业水准我不怀疑，但讲课实在太不走心了点。虽然看的出来楼老师不是故意这样的，但还是多注意一下讲课的质量比较好吧。
INSERT INTO "reviews" VALUES('5798d9822e958a006538791e',3098,3098,'胡晓鹏老师是交大我见过的最良心的老师，不止专业功力深厚，更重要的是为人非常有原则非常nice。',5,5,5,15,3,5);
INSERT INTO "reviews" VALUES('579071adc4c9710054ebb26e',1694,501,'老师，专业性很强。上他的课需要很强大的受挫能力啊。玻璃心的自觉绕道，不仅会碎成渣渣，更有胜者是三观破灭。莫名一股气场来袭。。。。。。。。',5,3,3,11,2,2);
INSERT INTO "reviews" VALUES('57906f66165abd005842ee72',14955,14955,'老师挺好的。好评。很亲切',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('578bbfc70a2b580068450b9d',9362,9362,'白老师和学生相处很好，回答问题十分细致，十分负责，深受学生喜欢。期末时给的参考题目十分有用！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('57845deb165abd0062ad35cc',7062,14957,'我觉得吧，如果遇到这个老师就一定要具备强大的自学能力，不知道老师是不想讲还是啥都不会，反正这门课讲的那叫一个渣…',1,1,1,3,5,0);
INSERT INTO "reviews" VALUES('578356e6a633bd005b260588',2699,14958,'罗宁老师上课幽默，可以学到很多知识',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('578350cda633bd005b25af06',1106,1106,'老师很负责任，讲课生动',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57834c59128fe10056823b5a',5376,4961,'就是喜欢，对味，没别的理由',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('578346b82e958a0054d53b18',722,722,'好啊！！！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('578341538ac2470061fb1167',14962,14962,'老师好，内容也很好，是有干货的课啦',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57833b3a165abd0055732cc0',5066,6885,'认真负责，有亲和力',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('578337020a2b580057728198',3253,3586,'老师讲的不错，能结合当今世界发展对我们进行讲解',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('578331d9a633bd005b2407f9',11945,11945,'老师很好，很负责任',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57832bfc2e958a0054d3ce4b',3253,3586,'给分不高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('578326977db2a2005428dd89',14967,1687,'老师亲和，负责任，不偏不倚，思路清晰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('578320435bbb5000610817db',7435,14936,'亲和力十足，但希望更生动',4,5,5,14,2,1);
INSERT INTO "reviews" VALUES('57831bced342d30057d8f756',10207,14969,'邓老师上课很有激情，专业水平高，能和同学们亲密相处',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5783153d79bc440032bdc042',12010,7428,'上课很有趣，老师本人也很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5783108c1532bc005f55ead0',12010,14971,'老师专业水平高，上课氛围轻松，老师对待同学问题会给出正确及时反馈，再给分上也十分放得开。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57830aaf0a2b580057705590',14972,14972,'讲课思路条理清晰，引人入胜，气氛营造轻松。',5,5,5,15,1,0);
