INSERT INTO "reviews" VALUES('577f7cd50a2b58005753db6d',14976,14976,'完全觉得开课没有任何必要啊，你不在我们对软件应用不熟练的大一或大二开课让我们有时间熟悉。反而在大三，而且觉得许多东西百度了解的更详细。觉得完全浪费时间，而且觉得这些软件课从大一开始都是自学，呵呵哒',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('577f7ab9a633bd005b055dd7',14601,301,'不和学生交流，课堂互动性不好，枯燥乏味，成绩不够理想',3,2,3,8,0,0);
