INSERT INTO "reviews" VALUES('577f5e18165abd0055526aa1',8067,573,'神坑！！！超级无敌大坑！！！宝宝入大学来遇到的最坑的老师！！平时占45%每个人都扣了将近十分，两次期考考的是中科院理论力学学院研究生入学考题！！老子一个电气的学的还是C为什么要去做中科院的题！！还不划重点。整天上课拿着留美经验瞎吹，只知道一味贬低中国，一吹就一小时！！',1,1,1,3,0,1);
INSERT INTO "reviews" VALUES('577f59a379bc4400329f1cdb',8067,573,'大学三年选过最让人无语的老师，上课就爱装B，阶段考试给我们中科院的力学考研题，我们学的是C好嘛！做这个考研题，还不让带计算器，手开三次方根，全班最高分60几，真是呵呵了，平时成绩超低，有的同学光是看平时，期末就已经挂了',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('577f556a8ac2470061d98268',2602,653,'视野窄，手法死板，讲课故弄玄虚，课程安排流于形式效率低下',2,1,2,5,2,0);
