INSERT INTO "reviews" VALUES('577cfef9a3413100619b6041',7110,7110,'个人很喜欢老师，与同学之间的交流很多，上课的内容讲解也比较详细，但是，整体授课方式过于枯燥',4,3,4,11,0,0);
