INSERT INTO "reviews" VALUES('577ce7092e958a00549c87b2',12010,7428,'赵老师专业素养很高，鼓励我们积极思考，且为人幽默风趣，很有亲和力，让我在轻松愉悦的氛围中学好了古代汉语。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('577ce4380a2b5800573aca56',2722,15002,'郭老师给学生的感觉是有点严厉，但是严厉中带着慈祥，对学生认真，尽职尽责，让学生可以在课堂上能够真正学到知识',5,5,5,15,0,0);
