INSERT INTO "reviews" VALUES('5775dba32e958a005574bf92',4003,11034,'所有的坏情绪无非来自考试，长胖，没对象，缺钱。明天结构力学我愿拿我的人品来过，但是只能拿一点点，毕竟还有其他课。都如此夸奖了还不让过不够意思了',5,4,5,14,2,1);
