INSERT INTO "reviews" VALUES('5774be331532bc0060c9685a',909,15041,'王老师专业水平高，而且具有实际工作能力，但普通话不标准，偏四川话，部分让我听不懂',5,3,3,11,2,0);
INSERT INTO "reviews" VALUES('5771475e5bbb50005971d196',762,762,'讲课不怎么样屁事倒挺多，迟到的还让鞠躬说不要浪费时间，也不知道是谁在浪费全班的时间还牛逼哄哄。不负责任，感觉他整个人自以为很牛的样子。实际讲课水平并不高。。。(概率论和建模尽量别选他)',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('576d2a457db2a20054e8e531',762,565,'虽然说是选修，但老师弄得比专业课还严格。期末交论文还要一个个答辩，他说过才能交。简直巨坑啊（︶︿︶）',3,2,1,6,3,0);
INSERT INTO "reviews" VALUES('576a1a87df0eea006211ff29',12931,1983,'袁老师挺幽默，跟同学们也很亲近，挺好的一个老师',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('576a159b1532bc006044d438',14976,14976,'老师可以更好的改进授课模式，比如说电脑授课啥的，坐在后排完全不知道老师在说啥，影响上课效率',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('576a09e22e958a005841cd7c',14962,14962,'老师很好，也讲的特别专业，很喜欢他',5,4,4,13,0,0);
