INSERT INTO "reviews" VALUES('5769fa682e958a00699b1476',14601,301,'亲和力不够，老师上课从头到尾都是一个表情，一个声调',5,4,2,11,0,0);
INSERT INTO "reviews" VALUES('5769f6e32e958a00699af4a9',743,743,'老师很有热情，有耐心',5,4,5,14,0,0);
