INSERT INTO "reviews" VALUES('576887e82e958a0069904de2',480,92,'。讲课浮夸没有重点，多次讲错，不讲作业，平时成绩给分到最低。还觉得自己讲的怎么好。真是服了他了。。学校教育全被他们这种人毁了。',1,1,1,3,3,37);
INSERT INTO "reviews" VALUES('576764e1d342d30058fb7429',15011,15011,'老师专业水平高，亲和力好，表达能力稍差，上课时过分活泼',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57675ec92e958a00698717e9',15000,15000,'陈迎新老师上课时不像某些特别严肃的老师，也不像上课较水的老师，在我看来至少上课感觉稍好，学的东西也较实用，并不会太无聊。',4,4,3,11,1,0);
INSERT INTO "reviews" VALUES('576755682e958a00582ce669',2170,2793,'老师讲得还行，不过互动不多。',3,4,3,10,0,5);
INSERT INTO "reviews" VALUES('57674b8f7f57850054876968',14962,14962,'王俊老师讲课比较有趣，知识面十分丰富，就是讲的有点啰嗦',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57674621128fe10057b03411',15007,15020,'老师专业水平很高，可以解决很多同学的疑问，但希望老师能加大自己的讲授部分，并且在讲授的时候让知识点更有条理',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('57656d74207703006b173efb',433,28,'总得来讲，田田老师非常水，尤其是在大一的第二学期，她的课长期都只有不到一半的人，平时考试基本不巡视，底下基本全是作弊的。第二学期后面有一次上课只有十几个后来田田老师就每节课点名了。口语不怎么样，很偏中式，至于优点就是他的英语很容易听懂。缺过几次课，一年生病了几次，说后面会补课然而只是说说而已。基本没什么作业，上课底下基本全是玩手机的，她也不说什么。',2,3,4,9,2,0);
INSERT INTO "reviews" VALUES('57629919d342d30058d6da89',3253,3586,'挺好的，平时作业有点多',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57628e146be3ff006a105a3a',12317,15059,'黄老师上课很幽默诙谐',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('576283875bbb500063e6ed28',207,207,'好老师，不可多得，尤其是颜值',5,5,5,15,1,5);
INSERT INTO "reviews" VALUES('57627e227f5785005462c548',2169,5249,'老师态度很好，教学水平高，为人和善',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('57616416a341310064b8eea3',2202,28,'老师上课有热情，真的是让你觉得老师自己都在很认真的对待这门课，然后就是人格魅力啦，我也惊叹于她的阅读量和观影量，还有对很多英语歌的了解，最羡慕的是每次看到一个单词，一个短语她如果想起什么有关于这些的联系，她会觉得很开心，少女心满满💕💕💕',5,5,5,15,18,0);
INSERT INTO "reviews" VALUES('57615e28816dfa00543cfe87',8265,114,'幽默可爱，上一秒在讲重积分，下一秒就在讲甄嬛体😊个人感觉他阅读量很大，而且也经常板书，不是一直放PPT那种，上课很幽默，普通话和四川话随意转换，嗯最后还是觉得可爱👏🏻👏🏻👏🏻',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5760531f6be3ff006a005d1a',3186,4181,'挺有趣的一个老师，上理论课不怎么管人你想干啥干啥，但他还是会认真讲课认真开玩笑……理论课不点名，实验课都是助教来上要签到或者抽点名，期末考试是上机考该多少给多少，选择+判断+做Word/Excek/PPT三选二随机，选择判断都是书后面练习原题，每周都有实验作业不过很简单',4,4,5,13,6,0);
INSERT INTO "reviews" VALUES('57605204128fe100577c4e02',397,397,'老师比较可爱，上课氛围轻松，偶尔点名，主要按照书上讲，偶尔叫人回答问题上去写答案啥的，讲的还是比较清晰，期中考试随堂考，期末考试基础填空+选择题+会计分录，会计分录是大头务必学好了……',4,4,5,13,5,0);
INSERT INTO "reviews" VALUES('57605094816dfa0054351241',2377,230,'老师有点事儿，偶尔点名，上课时候会抽人回答问题，还要每个班出小组做PPT回答展示，有偶尔的课堂小作业，回答问题交纸上去这种，期中考试是随堂考，回答书上两个问题，期末考试开卷然而还是会找半天，虽然事儿不过给分挺好，点名好像有一两次没到有点忘记了……？不过平时分基本给满',5,5,4,14,6,0);
INSERT INTO "reviews" VALUES('57604f40207703006bf06534',14565,14565,'好几个不同的外院老师轮流上的课，陈老师就第一节课和考试出现了下。课的内容还是挺充实的，分国家讲。平时不点名，没有平时分数的部分，期末考试开卷啥都可以查，自认为大部分都答对然而只有60几？！我心很痛啊',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('57604d926be3ff006a004f95',1293,14631,'讲课很有趣，上她的课从来不想睡。平时没作业也没期中考试，会点名，每节课都到最后平时分80……QAQ期末考试比较难，选择题+计算题+问答题，问答题是要配图回答的那种，所以你平时啥题不做想过是不可能的，老师有一种奇妙的人格魅力……总之挺喜欢的……但给分还是……',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('57604b5a207703006bf05bdf',1192,27,'能记住所有学生名字，超厉害……语音语调也很棒，英音_(:3」∠)_上课挺有趣，会鼓励同学们发言，最后的口语考试形式任意，笔试也都是课本内容很简单_(:3」∠)_可惜这学期不教我们了QUQ',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('575fd3d11532bc0060faad10',13845,1753,'用ppt上课的高数老师，有时候会把自己讲糊涂，上她的课需要极强的自学能力，全神贯注开始上课五分钟就会想睡……考试基本都是基础题',3,2,3,8,5,0);
INSERT INTO "reviews" VALUES('575fac257f578500544d8519',13243,13243,'妥妥一门水课啊！而且这门课挂的黄梅名字其实是她的研究生在讲，特别宽松，内容也都是业余的。上课的话，只要发短信请假都批准，而且请假不限次数，就算无故旷课也三次之后才会追究。',4,3,5,12,2,0);
INSERT INTO "reviews" VALUES('575faa9b7f578500544d7790',2381,2381,'讲课不喜欢按书上顺序，会把一课最重要的定理先介绍出来，再以此为开头引入新概念定理和证明，其实这个讲课方法如果你上课认真跟着走会收益颇多，而且老师很认真负责，有的重要内容会讲不止一遍。从这个角度我很欣赏这个老师。可是考试不透题我就不懂什么心态了。我还要去别的专业的老师那里搬好小板凳勾题。唉～',5,4,4,13,8,0);
INSERT INTO "reviews" VALUES('575f777b2e958a00694aac1f',9984,9984,'军哥爽的你不要不要的',1,1,1,3,1,3);
INSERT INTO "reviews" VALUES('575f501980dda4005f5e02e6',2298,2792,'点名点到******',1,1,1,3,0,5);
INSERT INTO "reviews" VALUES('575f4c5bdf0eea0062c26306',12658,34,'第一节上课就给我们谈思想谈哲学，上课你爱来不来，但是期末的作业你要交。可是就算你平时来了，期末作业也靠自学，还不一定做的完。慎重，慎重，慎重╭(°A°`)╮',4,4,2,10,4,0);
INSERT INTO "reviews" VALUES('575ebd795bbb50006381715b',6060,6060,'非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('575e6b05207703006f0dbf55',23,4181,'老师很~讲课也清楚',5,5,5,15,50,0);
INSERT INTO "reviews" VALUES('575e66381532bc006097fdf0',2699,14958,'老师既能贴近生活又能立足学科，与学生之间有一种“不即不离”的关系',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('575e5e7c6be3ff006a4d3114',5066,6885,'老师特别好，认真负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('575e52c32e958a0069ed2aae',723,723,'我上过三个老师的数据库管理系统，发现只有吕红霞老师讲得深入浅出，很容易懂，而且老师为人亲和很愿意给同学们解答',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('575e0b295bbb5000637b0162',3251,1131,'上课幽默风趣，最喜欢听他吹课堂之外的东西，他自己说平时经常漏题，还没期末考所以不是很清楚，但确实是个不错的老师，虽然我离散多半还是要挂 …',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('575e094d816dfa0056c57520',250,561,'尼古拉斯·陈·天·星     极其魔性    讲正课很无聊，侃大山很牛逼。对于画图要求很高。有益于培养良好的画图习惯。（你看我在勇敢的微笑，你看我在勇敢的去挥手啊）',5,4,2,11,11,4);
INSERT INTO "reviews" VALUES('575e031b5bbb5000637acaeb',2047,28,'老师挺好的，不过像我这种对英语不感兴趣的学生对她的课提不起兴趣',4,3,5,12,2,1);
INSERT INTO "reviews" VALUES('575dfe45a34131006154c85b',41,34,'老师很认真，但是经验欠缺，确实让人听的难受。这是班里几乎所有人的看法。但老师人还是不错，很认真负责，答疑也很认真，就是上课有点枯燥',5,2,4,11,16,1);
INSERT INTO "reviews" VALUES('575d8180816dfa0056c2fbbc',12658,34,'神坑 讲的理论的确有用 但和他布置的作业没有任何关系 平时也不练习小程序 反正选了还不如自学',3,2,2,7,5,0);
INSERT INTO "reviews" VALUES('575d76c3d342d300579cdf6b',2213,2213,'很渊博的老师，上课很引人入胜，很有风范和自信的学者，对学生帮助很大。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('575d6d8a2e958a0069e77968',2047,28,'凑合着还是可以',4,3,5,12,1,1);
INSERT INTO "reviews" VALUES('575d6cec2e958a0059cc8878',14142,14305,'他说他是好老师',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('575d6384816dfa0056c1cd35',14181,15006,'沈老师的课程很能吸引人，而且讲授的知识很容易让人理解，但又不失深度',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('575d6038a3413100615157db',23,4181,'特别好特别好',5,5,5,15,50,0);
