INSERT INTO "reviews" VALUES('575d596edf0eea006489b910',5376,4961,'讲课很好，脉络清晰，生动有趣，但不太爱布置作业与批改作业',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('575d5766165abd00555449ce',210,27,'老师的确特别好，但是讲的一般，助教给分不高，老师特别好说话',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('575d4ea57db2a200543a13ec',12931,1983,'老师讲课很有吸引力，讲的内容也很丰富，推荐老师能继续上法学二专的行政法学与行政诉讼法学。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('575d45802077030063b94a49',4044,737,'很负责任的老师，热情耐心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('575d3b2fd342d300579ab0b4',722,722,'老师正直，思路清晰，授课能力强',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('575d2f761532bc006090a01e',12931,1983,'老师学识很广，看问题很全面。对待学生很和蔼',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('575d25612e958a0069e4dc5d',2582,790,'老师上课很不错，专业知识丰富，且能联系最新资讯，课堂气氛好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('575d1b4d2e958a0069e46f01',7812,4819,'韩效老师并非一定要将自己的想法施以在我们的设计中，而是指导我们根据自己的想法进行深化。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('57567a0f6be3ff006b00e5cc',2170,2793,'不怎么听得清楚，没兴趣',2,2,3,7,2,9);
INSERT INTO "reviews" VALUES('5756656fdf0eea006468167b',378,378,'老师内容设置充实，但课程进度不太跟得上计划，时间控制不够好，指导欠缺',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('57565c4adf0eea006467cf28',10207,14969,'只关心表现优秀的学生，课程不给出意见与建议',5,3,1,9,1,0);
INSERT INTO "reviews" VALUES('57564911d342d3006b4a698e',4543,3369,'上次设计课没有来，没有给出理由，感觉不是很负责任，有些太自由了，任性！',4,4,1,9,0,0);
INSERT INTO "reviews" VALUES('575527b7df0eea00645ff1dd',4543,3369,'嗯……挺帅的。（Hardly makes it on time）',4,4,3,11,1,0);
INSERT INTO "reviews" VALUES('5750fd19a341310063b5c610',14972,14972,'周老师人挺好的，只是后半期调了个老师不太亲和。',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('5750ef44530fd30068ecb45c',721,721,'上课乱讲，没有主线',3,4,3,10,0,0);
INSERT INTO "reviews" VALUES('575016251532bc0059e5e63a',14972,14972,'专业，耐心，讲课重点分明；考试前画重点，可以利于学生有方向复习。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('574fff2c530fd300696f576e',6403,535,'把我挂了，宝宝不开心',5,1,5,11,3,0);
INSERT INTO "reviews" VALUES('574feb03530fd300696e9267',257,4318,'这个老师是我上大学3年最差的老师，从来没有见过比他还差的老师，如果能让他下岗，我谢谢你了',1,1,1,3,6,0);
INSERT INTO "reviews" VALUES('574fd482e4fd690054c6ef39',257,4318,'呵呵哒的老师，上课讲课自己都不懂，错了这错了那，讲的能不能有点逻辑！还说我们不认真听！全班都只有自己下课借其他参考书看书！天呐！什么啊！差评！最差没之一！讲的水得不行，考的难的不行',2,1,1,4,1,0);
INSERT INTO "reviews" VALUES('574fcc627db2a20055c63a3e',442,573,'千万别选他的课',3,1,1,5,4,0);
INSERT INTO "reviews" VALUES('574ec238816dfa0067f1976a',14976,14976,'专业能力可以，只是讲课毫无逻辑，考试全凭运气，不够实际、客观',5,1,3,9,0,0);
INSERT INTO "reviews" VALUES('574eb770128fe10055fc6dcd',14976,14976,'老师授课内容不够详细丰富，讲课快可以理解，可是讲授软件不将屏幕共享，坐得的远的同学听不见也看不清，对同学们提出的问题也没有进行直接且详尽的解答，问其他同学是解决的一种，可是老师也要进行回答，才不愧为师。',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('574ea833816dfa0067f08d5f',4543,3369,'经常迟到，不来上课，使得方案无法改进深化。对学生极不负责任',3,2,3,8,0,0);
INSERT INTO "reviews" VALUES('574e9a2271cfe4005ec1326c',14976,14976,'不能良好地与实际应用结合，知识点过于零散，建议联机授课！',2,2,3,7,0,0);
INSERT INTO "reviews" VALUES('574e84cd79bc4400626bfa32',3253,3586,'老师在学期开学前，未说明评分标准，说话不算数，平时所说的加分项到期末都没有',4,3,4,11,1,0);
INSERT INTO "reviews" VALUES('57441dbda3413100625ef30a',14180,143,'简直不顾师生情。',5,1,1,7,0,1);
INSERT INTO "reviews" VALUES('574413a82b51e90069718406',8067,573,'日了狗了',5,1,1,7,1,0);
INSERT INTO "reviews" VALUES('57440b37c26a38006b895840',6190,8972,'太有杀伤，上课压抑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5743f78671cfe40068bd6616',2444,13813,'真是日了杨武东了！',1,1,1,3,0,2);
INSERT INTO "reviews" VALUES('573ed1c12e958a00661e2c94',948,92,'老师人很好，讲的也很好。不过有时估计是姨妈期把，会发脾气。各种制度完善，没有钻空子的时候。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('573e71b475c4cd1bd7221e5b',8449,561,'老师讲的很好，但是大图给分标准很高能拿80基本就到头了。人很严厉，课一点也不水，就是有点大舌头，听不清。',5,3,2,10,3,0);
INSERT INTO "reviews" VALUES('573be58b79bc44005c74ad24',15123,376,'发音不清晰，期中考试，每节课至少点一次名，不认假条，每节课都有作业（很多教材上都找不到）。鉴定完毕',1,1,1,3,0,6);
INSERT INTO "reviews" VALUES('5739a1c12e958a0069d7e446',909,15041,'讲课详略得当，待人亲和，课程讲过较明白，不足之处是讲课声音有点小。',4,3,4,11,2,0);
INSERT INTO "reviews" VALUES('5739958f71cfe4006c033f46',2170,2793,'上课只顾着讲PPT上的内容，忽略学生的感受，上课过于无聊',3,3,2,8,0,5);
INSERT INTO "reviews" VALUES('5739812a2e958a0066f348b3',1983,1983,'林老师是我在大学中遇到的最严谨，最认真负责的老师，虽然表面十分严厉，但内心还是很和蔼，也很关心同学，在专业水平上也很高，能帮助同学建立知识体系框架。',5,5,5,15,2,4);
INSERT INTO "reviews" VALUES('57396a6df38c8400672376b4',14962,14962,'非常有亲和力喔～就是说话有点太～～～慢了！有点困-_-|||',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57395c202e958a0069d51b1a',14972,14984,'专业水平高，可爱，幽默，上课形式多样化',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('573952bfc4c971006019f231',14870,15010,'老师知识很强大，对学生要求也很严格，棒棒哒！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('57393c3e71cfe4006cffd3ac',11945,15130,'干练有感觉',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('573930fddf0eea006097a0cb',7729,684,'大学以来给我印象很深的老师，授课能力、水平都很高，至少能带动我的学习兴趣',4,5,5,14,0,1);
INSERT INTO "reviews" VALUES('57392ce079bc44005c5ed9fd',13340,542,'绝对差评，讲课就会读ppt，平时分给的超级低，期末考60平时分给你拉成不及格。改期末卷乱改。1万个差评。',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('573928c82e958a0066f0028c',909,15041,'老师教授的课程十分用心，充分的与学生互动，但是感觉要求严格',4,4,3,11,0,0);
INSERT INTO "reviews" VALUES('5739209379df54006018c7ec',12931,1983,'知识渊博，平易近人，上课方式棒，案例多，容易理解',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('57385851c4c9710060134245',15135,1897,'这上课速度越来越快了……简直无聊死了',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('57349267f38c840067f61062',10544,15136,'老师，期末考试您倒是给点重点撒，400多页的课本……不想说了。',5,1,3,9,0,0);
INSERT INTO "reviews" VALUES('57347fc52e958a0069ade7a8',41,34,'老师讲的有点糟糕，经常讲着讲着就糊涂了，很多自己都搞不清楚，不过平时分给的还不错，不点名',2,3,3,8,2,0);
INSERT INTO "reviews" VALUES('57347eee71cfe4006cd99d77',674,307,'老师讲课很好，逻辑条理，思维清晰，很好的老师。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('57347e7c71cfe4006cd997ca',416,34,'认真负责，耐心，讲的内容很条理，非常好的老师。',4,5,5,14,6,0);
INSERT INTO "reviews" VALUES('57347dd2c4c9710060f2dd84',246,228,'老师讲的还得不错，也认真负责。就是脾气不太好，给分也有些低',4,3,2,9,1,8);
INSERT INTO "reviews" VALUES('57347be6f38c840067f515d4',11518,32,'从不按照教材讲，他教的学生从不给答疑',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('57346a501ea493006414a6df',14610,6419,'全班都烦，没事找事',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('573454fb2e958a0066c8c591',8371,3098,'上课总是“啊啊啊”让人完全听不进去东西，考试还偏难偏怪！而且还全英文考试！全英文作答！',2,1,1,4,3,0);
INSERT INTO "reviews" VALUES('57343e02df0eea00634b339e',8067,573,'蒋老师大名鼎鼎的海归，教同学有一手；常用名言：这是你自己的问题。上课还好******。同学们这个题就这样做。老师究竟怎样做啊。上课不讲工力，讲世界经济，考试很简单，基本考研题，我还是留点字数在成绩系统里评价好了。装逼有一手',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('57342b41df0eea0063490088',3442,3265,'水，批改作业也不认真，连5：2和2.5答案一样的都不知道，还博士呢，讲课也讲不清楚，全靠自己才能考好',2,1,1,4,3,1);
INSERT INTO "reviews" VALUES('573410111ea49300640d5c6a',13994,13994,'各种讲，感觉老师脑动大，反射弧长。聊学校领导外教儿子出国经历。讲课能从一道语法题跳到学好外语是会有好的思维一下跳到罗马还是啥的历史。******这是什么鬼！！！还能让我们好好学英！语！上世纪发音i哈哈。不过老师还是很负责，用心教学生，不过我还小不懂感恩 ～',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('5733340679df540060e4e856',1291,22,'虽然是个好老师，但太严了谁喜欢',4,4,1,9,0,2);
INSERT INTO "reviews" VALUES('5732c7311ea493006402c4f3',14484,40,'超级不负责任，把我们班同学的论文都弄丢了。上课毫无安排，没有规划',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('5732b650f38c840067e1c3d7',15149,15149,'上课认真，但为人古板，上课教条，ppt上全是大段文字，看着就累。讲课方式一般，引导不了学生兴趣。缺乏经验，不成体系。',3,1,2,6,0,0);
INSERT INTO "reviews" VALUES('57329fcf1ea49300640107ff',109,109,'材料学院学生对此课程普遍比较痛恨，不说学什么有没有用，这门课要求低等于没学，要求高又学不懂，所以说这门课没有任何效果',2,1,2,5,1,0);
INSERT INTO "reviews" VALUES('57328fde71cfe40057cc404d',2413,71,'什么玩意，一学期不知道在讲什么，照着ppt从前往后念，期末还挂人！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('57302db771cfe40057b6c9b9',11684,15152,'不讲课，点名次数量较多，观看视频频繁但无用',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('57301eb671cfe40057b64268',13845,1753,'讲得大家都糊涂',5,1,5,11,2,0);
INSERT INTO "reviews" VALUES('5730119579df540060c7e295',13845,1753,'上课自己都不知道在讲什么，一会儿这错一会儿那错，想的和说的不一样，说的和写的不一样，想的和写的也不一样。您是性贿赂当的老师吗？',1,1,5,7,4,1);
INSERT INTO "reviews" VALUES('572ffe201ea49300609fd78d',14692,15155,'讲课太模糊，听不懂在讲啥',1,1,3,5,0,0);
INSERT INTO "reviews" VALUES('572feae8df0eea006321471d',831,762,'这学期概率课很枯燥，老师表达能力不好，只顾自己讲课，不管学生是否接受。上课逻辑性差，课堂组织不好。',4,1,1,6,3,0);
INSERT INTO "reviews" VALUES('572bfa7679df540060a1dadb',2078,2815,'课上的不错，但是为人装逼，较为刻板，不考虑学生感受',5,5,1,11,1,1);
INSERT INTO "reviews" VALUES('572a026b71cfe400577f3b39',11684,13919,'万老师的课专业性比较强，知识确实有些不平易近人。但是对于喜爱汽车的同学来说，确实是一门不可多得的好课。绝对不水。令人印象深刻。其实也希望他讲课能更加亲民一些。作业的话每次课都有，不过感觉也不多吧，半个小时就能做完的，作业当第二次的点名。课在小教室上，30个人，30张椅子，少人一清二楚。期中期末有考试，但是抄他好像不管，给分也较高（真的没看见？）期末有一个设计性的作业。难度略大。真正喜欢的同学值得选。',5,3,4,12,2,2);
INSERT INTO "reviews" VALUES('572a003b79df5400609169c4',1162,114,'怎么说呢，小东老师本身是完全没毛病的。然而他的翻转课堂，真的玩的6的也是没谁了。报他的课吧，需要很强的自主学习能力，因为课程的基础知识全靠看他的视频自习，部分重点包含在视频里，不看不知道。翻转课堂虽然新奇，当时事实上所需的时间也是大幅增加的。适合学霸，有上进心的同学。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5729883ff38c8400678d32bc',15160,186,'老师上课声音洪亮，专业性很强。为人也非常正直，有原则。',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5728587c71cfe4006b84aea6',1162,26,'上高数课开阔眼界啊  而且视频啊讲课啊讲的很清楚  绝对比自己看书效率高 人也很好 课堂题讲完了会灌心灵鸡汤啊 而且没什么口音 不像有些老师讲完课好了',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('5728302849830c005363b578',15162,15162,'张翠芳老师上课氛围很轻松，但教学十分认真负责，作业与课程进度相配套，课堂上随机的练习对学习很有帮助。期末会给很有用的指导材料。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('5727616a5bbb500062a98df2',416,34,'这个好评是真的，我觉得讲课就应该要有激情，而他就是这样的，不戴话筒还能喊这么响，绝对没有几个想睡觉的，而且讲的C++的东西都能对比到生活中的事例，虽然我C++还是很烂。。。不过这个绝对是这门课的问题而不是出在老师身上！最后献上老师“恐吓”我们的名言：下午实验课我来检查你们的情况，再这样做的话，我看你个子矮直接就揍你s(・｀ヘ´・;)ゞ，看你个子高我就温柔的问你学号，然后再后面默默的打把叉（楼主又自high啦 ，写了辣么多）',5,5,5,15,23,1);
INSERT INTO "reviews" VALUES('5721d99d128fe10060141ddd',4112,281,'普通话太差',4,1,4,9,0,0);
INSERT INTO "reviews" VALUES('5721c7545bbb5000626b5f66',246,228,'从我的打分就可以看出',1,1,1,3,7,0);
INSERT INTO "reviews" VALUES('5721ba6f1532bc006243f891',6403,535,'竟无语凝噎。',2,1,1,4,2,0);
INSERT INTO "reviews" VALUES('5721abe72e958a00653432f3',15167,114,'渣到爆，不配做老师。术不行，德更不行',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('571d9c2079bc440064c56166',12658,34,'基本不上课，上课就扯道家，人都不来了也不管，乱给分数',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('571d84b039b0570068131799',2885,40,'首先开设这门课程我没有得到任何在英语方面的提高，其次老师打分莫名其妙，问她还呵呵我！！！差评！',1,1,1,3,1,0);
INSERT INTO "reviews" VALUES('571d704b1ea493006efa92ba',896,896,'神奇的课+神奇的老师=昏睡、癫狂、无助、崩溃（4学时）',4,1,1,6,3,0);
INSERT INTO "reviews" VALUES('57199b7cc4c9710054c96142',741,911,'******上课讲了些啥？？宝宝听不懂啊！！><宝宝有努力听啊！！根本停不下来！！期末一天预习一本背背背，还小班上课逃都逃不了啊 /(ㄒoㄒ)/~~',3,1,1,5,0,1);
INSERT INTO "reviews" VALUES('571987ca128fe100600d620b',11684,15172,'此老师为人迂腐，泥古不化。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('57197daa1ea493006ce1c165',15167,114,'老师讲课不分学生交流，自己讲自己听，讲课声音小，课程进度太快同学跟不上',3,1,1,5,1,0);
INSERT INTO "reviews" VALUES('57184ca871cfe4006dc57f6f',5318,15174,'讲课没劲，稚气脱俗，喜欢卖萌，同济大学霸，但不善于表达。空有满腹才华，不切实际，不会与人相处。我校安全工程系克星。',5,1,1,7,4,0);
INSERT INTO "reviews" VALUES('57183e5cc4c9710054bc202b',7459,36,'方言很重，发音不标准，爱布置小作业，有点黄',3,1,2,6,2,0);
INSERT INTO "reviews" VALUES('5718279fc4c9710054bb4520',9443,4500,'说话很有趣，教学很善良，然而听不懂，听不懂，听不懂，适合教提前预习的好学生，渣渣跟不上节奏',3,1,5,9,0,3);
INSERT INTO "reviews" VALUES('57145ed11ea493006834aa11',175,175,'老师是有原则的人，该挂则挂。',2,1,1,4,1,1);
INSERT INTO "reviews" VALUES('5714488b71cfe4005b3a0311',920,12890,'没人听！听不懂！他不管！考试全死背！毫无知识与思考可言！',5,2,2,9,1,0);
INSERT INTO "reviews" VALUES('571431cedf0eea0064a342a3',13558,143,'老烟鬼，一口气抽三根 根本不费劲',5,2,1,8,1,0);
INSERT INTO "reviews" VALUES('57108dad2e958a0069ec9f8b',257,4318,'老师讲课条理不清晰，有点混乱，有时候自己都讲晕',3,2,2,7,1,0);
INSERT INTO "reviews" VALUES('5710844c71cfe40067567fa7',730,1124,'对知识的讲解不够系统',4,2,3,9,0,1);
INSERT INTO "reviews" VALUES('570f1188df0eea006465785e',2413,6356,'上课没多大意思，没有互动，只对着PPT讲，感觉很呆板',4,2,2,8,0,0);
INSERT INTO "reviews" VALUES('570f08db1ea4930068f4afd8',257,4318,'课程内容本身晦涩难懂，老师上课时讲的也不够详细清楚，没能将问题简化，要求也较高，考试重点不详细，讲课经验不丰富。',2,2,1,5,2,0);
INSERT INTO "reviews" VALUES('570f002e8ac2470064383f50',257,4318,'讲得什么东西呀！上课嘀嘀咕咕都听不清，哼~周三考试不攒人品了！对了，还没有课件，差差差差评！',3,2,1,6,4,0);
INSERT INTO "reviews" VALUES('570eefc571cfe40067487ec6',535,535,'给分少，太严了',2,2,2,6,3,0);
INSERT INTO "reviews" VALUES('570dc6c12e958a005c61fe32',535,535,'平时成绩给的高 考试水 补考更水 虽然挂的人多',5,2,5,12,0,3);
INSERT INTO "reviews" VALUES('570c70fe128fe1006caced5f',6,619,'上课水分比较大，常常提前下课，照本宣科',2,2,3,7,3,0);
INSERT INTO "reviews" VALUES('570c67612e958a005c50569f',2821,40,'课讲得不怎么的，谱摆挺大',4,2,3,9,0,0);
INSERT INTO "reviews" VALUES('57073985d342d30054254bd5',21,40,'讲课缺乏乐趣，没有终点，不与大家良好互动',3,2,3,8,2,0);
INSERT INTO "reviews" VALUES('570729d05bbb500051ef923d',4066,24,'不怎么讲，念PPT还总快进，给分也不怎么高，留一堆作业。',3,2,2,7,4,0);
INSERT INTO "reviews" VALUES('5707147b71cfe4005ddc7087',179,179,'充分体现了当代技术宅的特色，自己有充分的专业知识，但表达不出来！！！！！阿西巴',5,2,2,9,1,0);
INSERT INTO "reviews" VALUES('570706a65bbb500051ee2871',8067,15192,'太高深了，适合讲座，不太适合搞授课',5,2,2,9,0,0);
INSERT INTO "reviews" VALUES('5705b84a128fe100525c7ff2',751,573,'说好上届平时成绩占70%，这届只占了30%，结果考出本年度最低成绩，绩点被拖惨了！不要求高了，平时成绩占40%与另一个老师一样也还说得过去嘛！讲得真的很一般，心塞！',3,2,2,7,7,6);
INSERT INTO "reviews" VALUES('56f9dca58ac24700501df149',913,611,'这老师不错，口音纯正，积极鼓励学生创新，尝试，授课方式不死板',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56f0dc4c731956005d3f5bfd',229,985,'实力超凡，然而并不考虑你是否听懂了，没有从已知常规类比引入新知识的能力；可以问她题，课还靠自学。各种神跳跃、神省略、神速度，适合提高不适合上新课',5,2,4,11,6,2);
INSERT INTO "reviews" VALUES('56f0cba67db2a2005230ff33',2885,40,'此课感受意义不大，老师指导也不到位，收获不多',3,2,1,6,1,2);
INSERT INTO "reviews" VALUES('56f0be85df0eea0054464db9',2210,5,'我知道你是专业的，但表达能力实在是不能接受，逼的我们这些后排钉子户自学，希望在以后你我都有所提高',4,2,3,9,1,1);
INSERT INTO "reviews" VALUES('56f0b4508ac2470054bc839e',9696,1904,'讲的一般，百分之百点名倒是没话说。。。。上课有架子',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('56f0af48da2f60004cb2616d',15167,114,'此老师上课从不用PPT，坚持用他我们无法辨认的狂草板书，从不用扩音器，沙哑有磁性的嗓音讲课，上课时大约每隔半个小时大家会因为不懂他在讲什么而骚动，他会有几次自己也发现自己讲得不对劲而把自己挂黑板上。',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('56efbffe1532bc005065e28b',15200,309,'挺不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56ebc240da2f60004c81307d',11684,15172,'不知道具体课程怎样，老师极其死板、无聊，上课爱提问女同学，作为研讨课爱布置各种奇葩作业，以此来点名，期中有考试，期末有考试，还要设计汽车。课为水课，老师略醇',4,2,1,7,0,1);
INSERT INTO "reviews" VALUES('56eba0bbda2f60004c7fcbb1',826,5,'我就是喜欢那一口流利的川普',5,2,5,12,3,0);
INSERT INTO "reviews" VALUES('56eb81c97db2a20052fbef66',3025,641,'上课过于呆板，讲课缺乏幽默性，总是板着脸，从不给人批假，经常批评同学',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('56eb706f8ac247005488215f',13340,4257,'只会照着PPT读，而且PPT还是很久以前的',4,2,1,7,0,0);
INSERT INTO "reviews" VALUES('56eb59761ea49300553777e8',6323,5237,'没人能阻止老师的激情演讲，只是他从不理会是否有学生在为他鼓掌（就是没人听课还是自嗨！）',4,2,2,8,1,0);
INSERT INTO "reviews" VALUES('56ea690defa6310054523d0b',14784,32,'老师照着PPT念，是好久以前的PPT，跟教材完全不同步，全靠自学。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('56ea5ef8f3609a00544fc0ee',4936,15207,'云里雾里',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('56ea55d3f3609a00544f6409',612,1386,'上课枯燥乏味，不能很好的表达自己的想法。',5,3,2,10,2,1);
INSERT INTO "reviews" VALUES('56ea47c2128fe10051133624',15209,223,'老师上课要求严格，不像大学老师。课水，人不水，千万别选',2,3,1,6,0,0);
INSERT INTO "reviews" VALUES('56ea3d351ea493005530569e',13105,1743,'可以，有点难懂，期末飘过就很好了。',5,3,5,13,1,0);
INSERT INTO "reviews" VALUES('56ea34c4df0eea005409a05f',5318,15174,'给分太低',2,3,1,6,0,0);
INSERT INTO "reviews" VALUES('56ea26efb014600029345cfc',1291,22,'言辞清晰但听不懂，口音略重，有责任心',4,3,2,9,0,2);
INSERT INTO "reviews" VALUES('56ea1cdbc4c97100515efddc',9693,32,'平时成绩太低（每节课认真，作业认真完成，实验亲手完成条件下）期末出题偏难偏怪，不按套路，致使期末成绩整体偏低',5,3,4,12,1,0);
