INSERT INTO "reviews" VALUES('56ea0d9d1532bc0050314075',15215,15215,'给分很严，考试内容较简单',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('56e91a70a341310054864829',5803,619,'老师上课较有趣，经常点名，扣分严厉',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('56e9132befa631005446ea85',3477,1697,'挺好的老师…',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('56e9089e1ea4930055264eca',8182,15218,'教学较为死板。课程讲解内容中规中矩，无半点新颖，是锻炼耐性的好课。脾性较为暴躁，做事要求较为严苛。课程量极大，所以耐性对于此课极其重要。',3,3,1,7,1,0);
INSERT INTO "reviews" VALUES('56e8fcaa1ea493005525fdc6',2078,721,'作业太多，点名太勤',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('56e8f2d1efa6310054460dd0',13845,2735,'感觉老师水平不足，上课讲得十分纠结，时而还把自己给弄糊涂',3,3,3,9,3,0);
INSERT INTO "reviews" VALUES('56e8f11c731956005c0e5f66',15221,6194,'老师讲得很细很细，拓展较多，给分高，好评',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('56e8ea9c1ea4930055257904',179,179,'不知道上课在讲什么，总是感觉国外的比国内的好，有时还会吐槽编写模拟电子技术A书的人，你说他咋不上天呢',3,3,4,10,1,0);
INSERT INTO "reviews" VALUES('56e8dd3fb01460002929c6d9',13977,397,'上课就像评书，时时刻刻询问我们的意见，讲话声音像蜜蜂叫',3,3,1,7,0,1);
INSERT INTO "reviews" VALUES('56e8cf2e5bbb50004c2e571d',535,535,'讲课听不懂，太难，老师说话不清楚',4,3,3,10,0,0);
INSERT INTO "reviews" VALUES('56e8c1d28ac2470054744b49',13631,40,'水课，没有价值',3,3,1,7,1,0);
INSERT INTO "reviews" VALUES('56e8b529c4c9710051534c3b',5937,24,'这个老师只按期末给平时分，不讲道理',5,3,1,9,0,1);
INSERT INTO "reviews" VALUES('56e80e8dda2f60004c65414c',5937,24,'挂科大神！凭什么茅以升学院考试要比专业院难这么多？！影响排名！',3,3,1,7,1,1);
