INSERT INTO "reviews" VALUES('56e7be9bd342d300545a7447',12301,394,'专业能力强，深入浅出，理论重点强调。老师与同学互动一般，由于上课人数太多，太吵，纪律较差，老师性格急躁，表达不清',5,3,4,12,0,0);
