INSERT INTO "reviews" VALUES('56e63b9d731956005dda09eb',542,542,'我的天！我就不想吐槽了，我们最亲爱的工化老师永远沉浸在自己想象的美好世界中，活在自己的青春里，自说自话。（笑死我，不是不想听，而是她都被实验老师吐槽了，所以你说呢？！）by the way ，一本书都是考试重点',1,3,1,5,4,0);
INSERT INTO "reviews" VALUES('56e633a4d342d3005446af4a',13496,28,'上课简直是在浪费时间，前十分钟基本不说话，后面一句话能磨叽半天，简直无语。',3,3,3,9,2,0);
