INSERT INTO "reviews" VALUES('56e28d97efa6310054fb5a65',14598,15257,'老师上课的方式比较活跃，和同学的互动比较频繁，让我们能够感受到课堂上的学习氛围。时常讲讲笑话活跃课堂氛围，提高我们的学习积极性',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('56e28b3f8ac24700542b481a',1636,1636,'说话声音好听，不过课堂氛围不够好，不能吸引学生注意力，课程内容无趣，没什么价值，且课堂规矩不人道呀，不准请假不开心！（说其他老师“坏话”~）',4,4,2,10,0,1);
