INSERT INTO "reviews" VALUES('56e12d4e8ac24700541ae821',3517,3517,'老师亲和力较强，专业知识掌握很多。但讲得不清晰、无条理，主要是吐字不清，让人听了想睡觉。',2,4,3,9,1,2);
INSERT INTO "reviews" VALUES('56e126f97664bf005177a81b',13254,114,'我觉得何老师讲高数课讲得很好，很多关键的地方他都会讲到并且多次强调。并且，何老师教学态度严谨，平时很认真，也很负责',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('56e120a4816dfa0051dd167d',12757,8460,'通识课，平常从来不点名。期末整死你！3000字超级专业的学习报告+闭卷期末考（P.S.别人17周都停课，它考试拖到18周，还分考场分座位，按学号排跟期末考一样，2个监考老师每个考场！！！）出题范围为60页的习题集，最后60分钟100道选择题，还有好多不是原题',5,4,4,13,4,0);
INSERT INTO "reviews" VALUES('56e11c2fc4c9710051f944a2',627,271,'作为解几老师，还得兼讲高代，韩国粉笔的梗 2333 讲课比较简单 是上的专业课里一周内课最少的，上课很轻松',4,4,5,13,2,0);
