INSERT INTO "reviews" VALUES('56dfce2d1532bc00515f5d50',4250,2713,'老师人很好，上课仔细，教学认真，条理清晰，教学方法很好，不像某些老师只知道读课件，无聊死了',4,5,5,14,0,2);
