INSERT INTO "reviews" VALUES('56df89167664bf0052c44db1',1291,15322,'一个大学教师模范，思想很新颖，视野广，在专业方面有很多独特的个人见解，并且乐于分享',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56df81d1731956005c15788f',11950,4003,'黄老师教学经验丰富，有自己的一套教学方法。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('56df7c6c816dfa0052672df5',803,1111,'郭爱老师上课很细心，讲得非常好，很容易听懂',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('56df7960c4c9710051e6976e',13105,1743,'老师很好，自身具有很强的专业素养，课堂上能认真负责且通俗易懂的向我们讲解，理解起来更加容易。为人很和善，很有亲和力。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de9593128fe1005acf9d67',11748,2159,'用生动简单易于理解的语言解释复杂的专业词汇，让学生更易掌握',5,5,5,15,0,0);
