INSERT INTO "reviews" VALUES('56de8d21f3609a00544283c6',11225,11225,'专业知识强，啥都知道，上课跟听讲座似的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de8acda341310055efa698',15329,15329,'老师实战经验比较丰富，上课讲很多亲身经历，让身在象牙塔的我开了开眼界',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('56de87f81ea493005ede6922',9882,22,'上课讲解独到，个人富有魅力',5,5,5,15,1,1);
