INSERT INTO "reviews" VALUES('56de7e965bbb5000523616ca',7785,32,'讲得好，不枯燥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de78411ea493005eddd762',9643,9643,'课非常好，是我在大学遇到的最好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de7354731956005e19eb99',293,293,'老师学期课程安排很有计划性，讲课内容丰富清晰，对学生的作业要求合理',4,5,4,13,2,0);
INSERT INTO "reviews" VALUES('56de6d3b816dfa00590a559a',166,619,'上课风趣，知识丰富',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56de6b97731956005e19b62d',1074,2119,'老师人特别好，特别负责，最后还给我过了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de66aa7664bf00559cec0a',2069,1743,'光帅老师虽然头顶发光，但丝毫不影响他的“帅气”！虽然机原很让人头疼，但光帅老师的幽默还是让课堂有趣不少。顶着“机械名挂”的头号，但还是放了一条生路。我只能说谢帅老师不杀之恩，好人一生平安！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56de62e9efa631005ec17314',2567,7573,'好好好！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de6090816dfa0052e84dd2',22,22,'讲得很好',5,5,3,13,3,0);
INSERT INTO "reviews" VALUES('56de5c587664bf00559c992c',7369,73,'呵呵，万分无敌非常好，如果碰上他有兴致拖堂扯淡的话',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de55c7731956005c45eb99',15342,6356,'老师认真负责，专业水平雄厚，比其他老师教的好，学到的知识很多。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de536edf0eea0055453a96',1105,1105,'讲得好，认真，复习好，考得难。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('56de5205f3609a0054409a12',311,51,'唐老师很善良，希望把自己了解的专业知识都分享给听课的同学。我很喜欢唐老师的课',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56de4ca08ac2470056e6face',8147,26,'幽默风趣，有责任心，耐心细致，授课逻辑性强，是一位真正以德服人以教学为主的老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56de4b381ea493005edc84a0',4306,517,'有趣，好玩，好过',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56de44e3f3609a0054401884',9807,12085,'男神一枚，交大老师都像严哥的话，交大学费也应该2万/年，最负责，教得好，专业性强，易懂，实用，赞美词太多，写不完了！',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('56de3f42128fe1005accbe30',10091,1196,'老师讲课很有趣，内容丰富不枯燥，上课管的也不严，最重要的是不点名，给分还高，今年随便考考就得93分',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56de3b45da2f600055aea3f8',15349,15349,'讲课结合实际案例，可以将书本内容与实际应用结合起来。人具有亲和力，讲课生动，有趣。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56de37fca341310055ed0358',15350,80,'专业知识扎实，严于要求学生，待人较亲切。表达流畅，思维清晰',5,5,4,14,0,1);
INSERT INTO "reviews" VALUES('56dd1b54d342d30054a8a603',2205,80,'讲课内容十分丰富；信息量大',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dd17b77db2a200514d9b6a',393,15352,'长得像陈以桐，半学期不留作业，除了长着明星脸，人也很好',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('56dd168a816dfa005a69f165',6363,80,'老师上课很严谨，同时通过实际工程进行讲解',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('56dd146d7664bf005202a053',7369,73,'老师给人的感觉就是博学多才，具有非常深厚的专业能力和知识，愿意为同学讲更多的东西，而且课堂氛围非常的好。人的性格也很容易和同学相处',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56dd1161f3609a005dad565d',7369,73,'上课认真负责，课堂氛围轻松愉快，最重要是期末给分给得高啊。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dd0ddc7664bf0052025472',166,619,'老师不仅仅单纯地讲课本内容，而且通过许多生活学习中的例子来丰富课堂，通过他的课堂，可以获取许多人生哲理。老师博学和蔼，作业少。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('56dd0bfbf3609a005dad15c0',417,417,'徐老师上课很详细幽默，能引起我的听课兴趣，对学生的问题回答也比较详细认真，能鼓励我们实践动手能力，希望他的课越讲越好。',4,5,4,13,0,3);
INSERT INTO "reviews" VALUES('56dd0876df0eea0055b14c49',22,22,'讲课时能让人愿意去倾听，不枯燥，认真负责。如果课下有问题，也会耐心解答',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56dd052d1ea493005de17bc5',13736,26,'老师讲的好，亲和力很强',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dd02987664bf005201efca',1105,1105,'当之无愧的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dcff50efa6310054db935c',15361,15361,'非常有意思的一门选修，真真的扩大眼界，涨姿势！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dcfc43d342d30054a790ef',13080,2681,'虽然只是一门选修，但还是让我印象深刻，蒋老师幽默的讲课风格令我记忆犹新。听说蒋老师现在病了，我给他个好评当作鼓励，嘿嘿。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56dcf936f3609a005dac7c0e',9807,15363,'课本讨论联系生活实际，从一个小的问题引出到运用所学的解决过程让人印象深刻',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56dcf5b1f3609a005dac651d',9807,15363,'老师讲课很清楚，而且很有耐心，对学生很好，很负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dcf22dd342d30054a74d32',15349,15349,'杨老师上课有激情，选用案例多为自身参与，真实有用，课堂内容与实际结合，能吸引学生注意力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dcef985bbb50004ccecc1a',15366,15366,'王英老师讲课讲得比较好，思路清晰，有条理，能引导学生一步步紧跟她的步伐。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dced03a341310053029952',344,1111,'老师讲课很清楚，思维清晰，而且为人特别认真负责，会照顾成绩差的学生，给分也高，还能帮你复习。',5,5,5,15,3,1);
INSERT INTO "reviews" VALUES('56dceaaa1532bc00509fc033',23,5237,'刘老师讲课细致，条理清晰，重点突出，备课认真，有亲和力，经常传授一些关于做人方面的道理',5,5,5,15,50,0);
INSERT INTO "reviews" VALUES('56dce8521ea493005de0b065',15369,75,'极其有原则性的一名老师',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('56dce509a341310053026c04',2567,7573,'讲课水平相当高，但是4大名挂之一，考试铁面无私，毫无作弊可能。',5,5,4,14,1,1);
INSERT INTO "reviews" VALUES('56dce1c0f3609a005dabe5a5',23,5237,'老师人很好，不仅专业水平高而且还教我们做人的道理，非常好的一个老师。',5,5,5,15,50,0);
INSERT INTO "reviews" VALUES('56dce01bd342d30054a6dee3',2323,22,'讲课生动有趣，认真负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dcdd86816dfa005a560076',24,24,'老师专业知识深厚，上课与学生互动大，语言幽默风趣，学生听课认真有效',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56dcdc1e731956005d9829a0',9807,13185,'讲课有趣，会有小实验',5,5,5,15,0,0);
