INSERT INTO "reviews" VALUES('56dcd5c6a34131005302175d',1048,114,'好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dbc309efa6310054d303d4',684,2158,'老师人好，友善，对于我这种文科生也能耐心讲解，深入浅出，好评',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56dadf5cefa6310054c933b0',23,23,'刘霓老师 对她绝对是好评啊，讲课不枯燥，内容重点突出，超有亲和力，人特好，很热心，问她问题总是挨个耐心解答，而且教出来的基本都是高分啊！',5,5,5,15,53,1);
INSERT INTO "reviews" VALUES('56daddf3731956005d869a69',3577,2642,'呆萌认真负责的蜀叔，教不好学生内心非常愧疚自责。儒雅',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('56dadb22816dfa005a5688a4',803,1111,'老师讲课很有条理',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('56dad9057664bf0052ef2c63',3477,1697,'老师讲课讲得很细，对我们的学习也很关心，是一位很负责任的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dad79b8ac24700548b60fe',5937,24,'教学严谨，认真负责。每次授课中都能举一反三，极大激发了同学们的术学热情，积极与同学沟通交流，教学氛围良好。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('56dad632c4c9710055c28972',2433,75,'语言风格幽默，能调动课堂气氛，知识讲解有条理，透彻易懂。认真负责，又和蔼可亲。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56dad416efa6310054c89cf1',9807,13185,'讲课时很生动形象，经常利用身边随手可见的东西做高大上的光学实验，一支激光笔，一支注射器，就可以像显微镜般让你看到水中的微小生物。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56dad1bd8ac24700548b1a97',1169,199,'崔庆老师上课很有耐心啊！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56dace731ea493005dce0be8',1169,199,'崔老师是我男神，我们都爱他！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56dacb665bbb50004cbbe110',344,1135,'和学生互动很多，幽默风趣',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56dac8591532bc00508ccb19',9134,1135,'李春茂老师给我的第一感觉是严肃，治学严谨，但两个学期的接触使我感受到李老师其实是一位亲切，低调，认真的老师。他的讲课水平很高，听他的课能学到很多有用的知识。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('56da6764efa6310054c4582b',818,10420,'房屋建筑工程概论听得一脸懵逼不懂为啥要修，幸好老师帅！简直是大学老师颜值巅峰',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56da65c2df0eea005599d26e',818,10420,'虽然节节课点名，但我依然爱他~！贼帅！不行，太帅了，我要嫁他。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56da5416816dfa005a513e12',13590,40,'2333，老师非常非常逗，时不时就冒出来一个段子，课堂气氛非常好',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('56da4fa11ea493005dc93c47',1169,199,'从大一到大二，从数分1到数分4，小崔都十分敬业，讲课也讲得十分好，有重点，很全面，而且是以我们听得懂的方式讲。很喜欢他的教学方式，也很喜欢他本人，更喜欢他一个人讲课傻笑的样子^_^',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56da4899816dfa005a3e7e28',13142,1596,'认真负责，上课严谨，解答亲和。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('56da41907db2a20051340502',24,24,'上课表达清晰，下课老师具有亲和力',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('56d95592a341310053e38cd0',16,40,'衣着打扮浮夸张扬，以偏概全，态度冷漠，不太负责任（缺勤两次，上课玩手机）',1,5,3,9,1,6);
INSERT INTO "reviews" VALUES('56d953b2d342d3005487e5cd',14561,40,'陈老师人挺好的，课也上得不错',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d95195731956005d792a08',15398,15398,'幽默，讲课全面',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d94e10efa6310054bb96d5',2567,7573,'上课水平好，表达能力好，幽默风趣，给分较严格，出题较难，但是他的课可以学到很多',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('56d94c6b1532bc0050803ae3',459,40,'老师上课流畅，表达清晰，主干知识明朗。专业功底扎实。',5,5,5,15,1,5);
INSERT INTO "reviews" VALUES('56d94a13816dfa005a48f624',1391,24,'讲课有激情，生动！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d94706731956005d78c322',1768,22,'少有的好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d94471816dfa005a367e79',684,684,'老师太负责了！！！负责得学不好都感觉不好意思了！可是就是学不好！我尽力了，背的太多了！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d94308731956005d789a0c',1320,40,'认真负责，漂亮，和蔼，very good！',5,5,5,15,1,1);
