INSERT INTO "reviews" VALUES('56d93c3b1ea493005dc095a5',7459,5368,'叼',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d939a67664bf0052e1219e',12301,394,'说出了许多社会中的实际问题，不像其他老师一样瞎扯',4,5,4,13,0,0);
INSERT INTO "reviews" VALUES('56d9365d1ea493005dc06c21',14085,114,'大一最最喜欢的老师，好萌，虽然声音带催眠特效……',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d933c88ac24700547d4d44',15409,15409,'知识面广，见识丰富，三观端正而且很有人格魅力，专业水平也高于大部分英语老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d931e8816dfa005a4828ae',6871,309,'很好，和蔼可亲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d92e9f1ea493005dc03513',15366,601,'这课贼难，老师讲课贼牛，又快又讲得清晰，提前了4、5周结课。',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('56d92c46731956005d77ebd5',416,1281,'讲课很好，风趣。对知识讲解很到位，这应该是这一年半中唯一听过的课',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56d929b15bbb50004cae011e',614,198,'老师很合得来，这是我上大学后遇到的亲和力最高的老师，当然，其他老师也不错。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('56d92849731956005d77cd65',23,23,'老师上课非常激情，具有说服力，课后也非常具有亲和力，时时鼓励学生。',5,5,5,15,50,0);
INSERT INTO "reviews" VALUES('56d925f0f3609a005d8b6e10',1535,230,'这课又写调研，又写论文，还要卷考，实在不是一门水课。但他喜欢从不同角度不同时期不同立场的名人评论讲历史，让人理解其方方面面，好评。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d92487f3609a005d8b6440',179,179,'老师上课讲解清晰，课外知识拓展丰富，专业知识过硬',5,5,5,15,1,3);
INSERT INTO "reviews" VALUES('56d922a6d342d30054864b21',13142,1596,'太严格，但是认真',5,5,2,12,0,2);
