INSERT INTO "reviews" VALUES('56d91df45bbb50004cad9ca9',1768,22,'如果你想真的学到东西，真的清楚物理知识的话，钟老师是一个great选择。她讲课条理清晰，习题讲解也认真。选择她，木有错了。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('56d91c8c1532bc00507ea00a',4435,15420,'老师很好！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d91b231532bc00507e903d',330,22,'老师上课幽默风趣，内容充实易懂！',5,5,5,15,1,7);
INSERT INTO "reviews" VALUES('56d919421ea493005dbf73fe',14409,114,'老师为人和蔼，讲课比较认真详细，比较有趣',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d917d98ac24700547c58fe',8566,114,'田老师上课的氛围比较活跃，讲解知识系统化，能够抓住重点，强调考点，突破难点，是一个优秀的老师',5,5,4,14,2,0);
INSERT INTO "reviews" VALUES('56d914548ac24700547c36bf',14203,14203,'老师很负责任，专业水平毋庸置疑，人很和蔼',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d910cf816dfa005a47031d',1175,28,'老师非常好，很漂亮，上课很轻松，没有一次犯困过！',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('56d90d86f3609a005d8a833c',1058,5,'讲解清晰明了，针对性强，亲和力强',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d90b2ddf0eea00558ed141',11065,11065,'范老师是个很活跃的老师，只要你想学，一向可以从他身上学到知识。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d907a8c4c9710055b2fa7e',15428,15428,'闫老师上课，课堂气氛活跃，很自由，开放，对于我们大一新生来说，他把一些专业知识讲得简单生动易懂，很好',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d904231ea493005dbeb858',627,114,'很认真的老师，上课充分准备，有重点，偶尔吹牛挺有意思',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('56d90206d342d300548514e5',2202,28,'还是很开心的一个学期，每次上课都能收获到课本之外的东西，视野也开拓许多',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d8ffeaa341310053e0a27f',2202,28,'讲得好，态度好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d8fe08a341310053e096d4',293,375,'很有趣的老师，上课能学到许多原来没有听闻的心理学知识，同时又能帮助到生活。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d8fafca341310053e08282',15433,15433,'用英文上数学课——欲仙欲死',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d8f7ef128fe1005144f7f4',15433,15433,'李老师用在美国讲学的模式教育我们，虽然英语很难听懂，但开阔了自己的视野。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d8f4a6128fe1005144dfd1',627,114,'幽默机智可爱，很贴心。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56d8f15dc4c9710055b25d54',627,114,'认真负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d8f031731956005d75f2df',23,5237,'挺不错的老师',5,5,5,15,51,0);
INSERT INTO "reviews" VALUES('56d8ece8731956005d75e054',14774,14774,'上课生动形象，亲和力极强，一口川普流利得无法直视。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d8ebbb816dfa005a33b05e',6060,6060,'周静老师是一个特别有热情，能教会我们很多的东西！课堂也十分有趣，好评！希望以后还能选到她的课！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d8e9267664bf0052dea33e',6060,6060,'这个老师6得飞起，不过今年她要出国blabla所以好像16年没有她的课，反正她的课特！别！有！趣！走过路过不要错过~考试是随堂考那种，案例分析：）',5,5,4,14,4,0);
INSERT INTO "reviews" VALUES('56d8e6ce1532bc00507cfc17',8265,5,'赵老师具有很强思维能力，讲解的内容清晰易懂，上课话语幽默打趣，具有很高的人气，很强的课堂感染力，我非常赞赏赵老师！（转眼明日战现代，望我取得胜果归）。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d8e4397db2a20051295b54',229,985,'老师讲得挺好的，就是课程难度大，理解有困难',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d83aa3816dfa005a305b05',13988,114,'上课亲和力极强，会开玩笑',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56d838fe816dfa005a4285c9',14181,1536,'很可爱的老师>w<翩翩沈公子=w=  也很温柔，知识面广（对 我就是来夸他的）',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d8375ad342d300548102e7',334,175,'什么都好，可是师生情哪去了？师生情！师生情！给分特别严！跪求师生情！',5,5,5,15,7,1);
INSERT INTO "reviews" VALUES('56d83500df0eea00558a51b0',8453,114,'老师很和蔼，上课上得很牛逼，完全不用PPT等现代教学方式，教学理念深得人心，而且，上课很幽默（主要是人）。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('56d8331ff3609a005d85e0ab',8453,114,'真正牛X的老师，特别严谨。讲课从不用PPT，都是纯手写，真正优秀的老师。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('56d827bd1532bc005078f05d',9569,15448,'雷厉风行的老师',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('56d824b0d342d30054803d60',15449,114,'首先，是老乡，必须挺，教得很好。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d82293816dfa005a419a91',13988,114,'上课认真，负责，课后习题紧跟，让我们不是片面了解知识，懂得运用，而且耐心。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d8203af3609a005d851cf9',13988,114,'老师上课讲课很细腻，多用手写板书，学生上课能跟得上，讲课很好。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d81d2d7664bf0052da26dc',11285,114,'是一个能给人启发的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d81ad5816dfa005a4150b2',6060,6060,'很好的课，推荐',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d819a88ac247005476574b',785,114,'阳老师的线代和高数课我都有在上~很多自己看书看不懂的地方，被他一说就弄懂了~人也很好~',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d8165e7664bf0052d9ed10',4112,114,'四川话标准，但对于听不太懂的北方人，表示略有不适',5,5,3,13,3,0);
INSERT INTO "reviews" VALUES('56d815317db2a2005124b3c2',210,28,'好.好.好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d8138c7db2a2005124a575',14085,114,'平易近人，讲题仔细，过程详细',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d810bb816dfa005a2eb830',785,114,'教课水平高，对学生负责，上课幽默风趣，很有亲和力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7cd141532bc00507598cf',334,175,'上课很无聊，听着要睡着，不预习不知道讲什么。但是专业水平和表达能力还是不能否认的',5,5,3,13,1,3);
INSERT INTO "reviews" VALUES('56d7caf71ea493005db67e62',14203,14203,'具有亲和力，与同学们打成一片，异常亲近。讲课充满激情，生动有趣。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7c916816dfa005a3e40e3',1390,28,'老师很负责任，和蔼可亲，有耐心。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7c7e9128fe100513ce9c9',491,1529,'为学生提供的复习资料十分全面，上课讲解认真负责，课堂生动活泼，举例真实',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('56d7c680d342d300547cb2d8',229,985,'为人和蔼可亲，考试一定会给我高分的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7c463816dfa005a2bc721',229,985,'老师很耐心，课堂氛围很轻松',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('56d7c0df7664bf0052d6ac25',372,5,'思路清晰，认真负责，十分喜欢',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7bec21ea493005db5fc7e',627,114,'喜欢吹牛，崔牛伟老师，上课讲到一半就胡扯各种大道理，但是讲课讲题非常细致，毫不含糊。幽默风趣，超赞',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d7bd1ddf0eea005585c766',13526,28,'上课比较严谨，比较认真负责，特别为学生着想，很和蔼',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7bbb4128fe100513c7024',12682,15468,'胡老师拥有新闻采访的实战经验，因而上起课来有很多真实、新鲜的事例来充实课堂。还记得她第一讲课便给我们推荐了很多书籍，并且以其亲身经历告诉了我们读书的重要性。课下对同学热心关照，绝对的良师益友！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d7b998d342d300547c3f9b',11285,114,'讲课都听的懂，看大家累了还会扯一些其他有的没的，讲题也很容易明白',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7b7f35bbb50004ca3b892',1162,114,'有思想，有创造力，时代感很强',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7b4e65bbb50004ca3a133',8265,114,'上课比较幽默，原本较难的高数，被他讲的十分生动，加深了对知识点的理解。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7b19d5bbb50004ca3848c',86,653,'非常有才华的老师，口才也是极好的，相当有魅力！',5,5,5,15,1,11);
INSERT INTO "reviews" VALUES('56d7b0715bbb50004ca378a3',14264,394,'“给我一点启发”是最常见的口头禅，上课风格还算幽默，但是在把知识点明确一下就更好了。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7af441532bc005074805f',13254,114,'目前为止我最喜欢的大学老师。会打太极~',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7acebdf0eea00558545da',785,114,'幽默多识，经验丰富',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('56d7ab82816dfa005a2afdc0',14910,229,'课堂气氛轻松有趣，讲授认真仔细，对待同学热情专心',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7a8767664bf0052d5e886',15477,8061,'这老师特别好玩\( >ω< )/，讲得很生动，人也很好，上课很注重对数学思维的培养，还可以提高我们对数学的兴趣。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7a4f1efa6310054af7599',4411,27,'讲课有热情，十分有亲和力，与同学相处融洽，在课堂上也会有很多互动，授课方式也十分灵活，深受学生喜爱。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d7a220128fe100513babeb',627,114,'很喜欢他，但是他扩充得有点多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d79fc7731956005d6cd76f',1058,5,'细心，认真，和同学互动多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d79e235bbb50004ca2fa3b',888,256,'高老师平易近人，授课专业水平高，对同学们的疑问总能耐心解答',5,5,5,15,4,5);
INSERT INTO "reviews" VALUES('56d79b52816dfa005a2a9359',8566,114,'老师认真仔细，严谨负责，板书授课，课堂活跃，是一位非常棒的老师。（例题经典，让你轻松学高数）',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d79a24efa6310054af3a41',11285,114,'知识面广，讲课幽默风趣，亲和力高',4,5,5,14,1,0);
INSERT INTO "reviews" VALUES('56d797905bbb50004ca2d402',1192,27,'陈老师可以在第一次点的时候就把名字和人对应起来，然后后面的点名就呵呵了，谁不在一眼便知≈不可能逃的课',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('56d79573731956005d6c9cd6',8572,28,'还可以，挺不错的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d7931a7664bf0052d56288',8265,114,'赵老师善于调动课堂气氛和学生积极性，讲课注意思维和方法，且亲切、平易近人，是深受学生欢迎的好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d790851ea493005db4b76c',8265,114,'讲课风趣幽默，课件内容丰富。有亲和力',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d6e146d342d30054a55feb',1192,27,'下学期由于某些原因，“私奔”老师将不会教我们英语，老师是一个严谨却又不失幽默的人，有机会上到她的课是一种幸福哦！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56d6ddfea633bd0056605b95',1162,114,'非常好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d6dcd1c507b60055765f2a',14085,114,'老教师，有水平，概念例子很到位，例题讲解清晰，非常棒',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('56d6da786be3ff005c1727d9',13254,114,'何老师讲课重点突出，习题题大，方法新奇简便，是个可爱的小老头。有时候会来几道线代乱入，还会把高数和道家理论、太极联系在一起 -_-',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('56d6d7a6d342d30054a5008a',1394,230,'没有照本宣科，想获得知识的人感到满足，不想认真听课的人也不好意思不给老师以尊重。',5,4,5,14,4,0);
INSERT INTO "reviews" VALUES('56d6d602a633bd0056600719',15493,241,'太多理论的东西，让学生感到很乏味，没有新颖',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('56d6d498816dfa0059482488',14363,542,'化学课好无聊！神愣',2,2,2,6,0,0);
INSERT INTO "reviews" VALUES('56d6d18ad342d30054a4bd68',2202,28,'老师人很好，上课也不会很无聊，有时课间还有歌听，或者小短片可以看。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('56d6cfa9c507b6005575d0db',13988,114,'待人亲切有耐心，认真负责，关心学生。教学宽松但并非水。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d6cd158ac2470053b0e496',8480,15497,'讲课形式新颖，内容发散思维',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d6c9cca341310055d67ee0',1341,114,'觉得高数老师课讲的很好，很亲切',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d6c7afdf0eea0051fecf4f',4112,114,'开始讲课便进入了自嗨模式，你听没听懂不重要，他开口就好。',3,2,4,9,4,0);
INSERT INTO "reviews" VALUES('56d6c4deefa631005587dc40',6060,6060,'老师讲课很主动，富有经验，而且对学生很负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d6c20d816dfa0051ca1bce',1535,230,'教学认真，负责，讲课深动，即使没人听也尽职尽责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d6b6458ac2470053b00eae',15433,15433,'教授采取全英教学，教学内容横跨古今中外科学史，不仅开拓眼界，受益匪浅，而且上课及私下，教授那种对科学的严谨态度让人终身难忘。这也是教授传授的比知识更重要的东西。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('56d6b3b01532bc004c77af9a',15433,15433,'李教授知识渊博，数学大师，只是一口川味英语让学生迷糊，曾于美国任教多年（orz，这口语也可以！）以美式教育给我们上课（全英，讨论，互动）让我们先体验外国教育。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('56d6b02ba633bd00565e9ee1',1341,114,'教学严谨，一丝不苟，并且板书工整，课堂穿插一天的预习与复习，对课程的开展有较大帮助，上课会及时反馈作业与考试的错题，总之，对我个人以及所有同学的学习都起到了很大的作用。',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('56d6ad1e7db2a200557967d6',14375,5739,'上课讲着讲着就跑题了，总是不知道为什么就自嗨了起来。因为上课时大家不认真听课，首次在考试中使用了闭卷',3,1,5,9,0,0);
INSERT INTO "reviews" VALUES('56d6abb5efa6310055870b8d',247,28,'为什么别的班都能看电影？',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d6a8a8df0eea0051fdbfae',2381,985,'老师表达得不是很清楚，讲题也是讲一半就感觉大家都会了不再讲下去。其实对于我这一类低水平还不管用。',4,2,3,9,2,0);
INSERT INTO "reviews" VALUES('56d6a77b1532bc004c77454e',2525,5,'专业水平较高，但上课过于热衷与同学互动，让人不适。过于关注考试，成绩 点名时有拍照！抄作业的时候感觉很多~',5,5,3,13,3,0);
INSERT INTO "reviews" VALUES('56d687a15bbb50004c7c15e0',2525,5,'太严了，完全就是让人挂科',3,3,3,9,1,2);
INSERT INTO "reviews" VALUES('56d68110efa631005585a6db',13923,114,'记得一次脚扭伤依然坚持，认真负责的给我们上课，并且还向我们致歉，太感动了。很好的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d67c9c816dfa0059451f94',2525,1169,'超级喜欢',5,5,5,15,0,0);
