INSERT INTO "reviews" VALUES('56d670e21ea493005c22fcb1',15513,1346,'第一节课就讲有钱不是幸福，老师，我们观点不同，我更爱王思聪',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d66b411ea493005c22cd27',14030,5,'教授水平毋庸置疑，对题目的理解已经无人能及，然..由于翘课过多，实在无法跟在其节奏，人生一大憾也。',5,4,5,14,0,1);
INSERT INTO "reviews" VALUES('56d66834efa631005584c4bd',13923,114,'老师随和，僵化幽默，讲课方法易懂',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d665a0efa631005584b0ae',15477,8061,'天马行空，专业知识太高深',4,4,2,10,0,0);
INSERT INTO "reviews" VALUES('56d661671532bc004c74f483',14085,5,'思维活跃，讲课生动',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d65c026be3ff005c12d056',175,175,'此老师大图给分较高，但此人不具有一丝亲和力，教学方法简单枯燥，课程基本自学，期末给分不高，每节课都有人给他打电话，发短信，若他是您的老师，送你二字：“保重”。',4,3,1,8,2,1);
INSERT INTO "reviews" VALUES('56d65571d342d30054a09c5a',14085,5,'韩老师讲课水平一流，分析问题透彻，使我有质的飞跃，但上课时讲课比较枯燥，容易乏困',5,4,3,12,0,0);
INSERT INTO "reviews" VALUES('56d65444a341310055d2a7f9',13340,542,'有点不通情达理',5,5,1,11,0,0);
INSERT INTO "reviews" VALUES('56d64f1c1ea493005c221380',14085,5,'易催眠',5,2,5,12,0,0);
INSERT INTO "reviews" VALUES('56d64c0fd342d30054a064d0',3669,3669,'上课形式新颖，能带领学生近距离接触本专业的前沿科技，并且鼓励学生发表见解，搜集资料，当堂展示，锻炼了学生的交流能力，也认识了很多专业方向，为就业铺垫，结实了许多老师',5,4,4,13,3,4);
INSERT INTO "reviews" VALUES('56d64542d342d30054a03402',13988,114,'上课富有创新，专业知识丰厚，为人和蔼可亲',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d58b9bc4c971005194f973',6060,6060,'超级喜欢她! (^O^)非常亲切，而且上课好友趣啊！完全不会觉得枯燥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56d585826be3ff005c0e7f74',9351,5,'上课思路清晰，有亲和力，对学生认真负责',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('56d57ef0df0eea0051f6b6e8',4257,4257,'知道很多但讲不出来',5,3,3,11,2,0);
INSERT INTO "reviews" VALUES('56d5785fd342d300549bf941',13526,28,'绝对好老师，给分高，教得好',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d56169c507b600556c4c2c',13254,114,'比较和蔼，差几分几个的同学都算及格',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('56d55f4c1532bc004c6f1864',1570,394,'老师为人幽默，很关心学生，按理说大学课堂上老师是很少抽学生起来回答问题的，但是这样导致学生上课极不集中精力，效率十分低，而李老师会在你注意力不集中的时候抽你起来回答问题，这样不仅提醒了学生，而且也让学生更加专注。我认为这样体现出了他是很有责任心的一个老师，同时也很为学生着想。',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('56d55e1fc507b600556c2a58',120,10214,'魏老师讲课不拘泥于常规，常会用幽默风趣的语言给我们授课，并且经常会给我们讲述我们专业的前景，让我们充满了自信。魏老师还能经常主动亲近同学，了解我们的学习、生活状况。作为我们的专业老师和班级导师，她很够格！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56d55c7b8ac2470053a75519',14085,5,'主要是随意，为人和善，大师风范',5,3,5,13,2,0);
INSERT INTO "reviews" VALUES('56d1aec5816dfa005615aa33',6377,6377,'蒋老师最棒！',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('56d1666defa631005501c5f2',1433,15533,'饶老师特别好！周末还抽空免费帮我辅导！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('56a834f6816dfa005ab2f9f2',15534,241,'要红妆，不要武装',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('56a1c49ac24aa800541405e4',4112,114,'幽默',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('56a1c3c4df0eea0054c0581c',13923,114,'负责任，能力强，很幽默',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56a1bb0d816dfa005917293a',3036,3113,'李老师是本科生涯中向我传授知识最多的老师，可谓恩师。平易近人，乐于和学生交流。上课十分为基础薄弱的同学着想，基础知识阐述得很仔细并经常重复。我每每感慨现在高校的教师评价体系有问题都会想起尊敬的李老师！',5,5,5,15,5,1);
INSERT INTO "reviews" VALUES('56a1b8a5d342d30054ea3109',8764,8883,'优秀的老师，待人非常亲切。曾拜托过私事，马老师十分热心。
INSERT INTO "reviews" VALUES('56a1b64bc24aa800541354e9',819,9857,'在中国的大环境下，敢于辩证的看待各种哲学流派并发表自己见解的人实在太少，尤其是批判马克思主义。至今无法忘记罗老师在课堂上铿锵有力的演讲，感谢您开拓了我的视野。',5,5,4,14,6,0);
INSERT INTO "reviews" VALUES('569f4775c24aa80053ba5125',6403,535,'忍不住发一条骂一骂王小川******一学期点名9次也就算了，每次都是早上8点准时点名，迟到了一分钟也要记也就算了。我迟到了几次考勤给我65也就算了。课堂表现给我57，exuse me？你知道我上课怎么表现的？更过分的是期末给的超级低！！！我加起来错了不到一个大题，小题可能错了几个，怎么可能才60多？？？步骤分1分不给还是怎么地？其他同学的情况是，卷面59最后也会不及格，卷面70多会被平时成绩拉到60多，班长大学霸卷面70******亏我复习那么长时间刷了那么多套题感觉自己都会做了！请大家选课的时候记住这个名字: 王！小！川！',4,3,1,8,10,0);
INSERT INTO "reviews" VALUES('569f06f8df0eea0054674db6',344,1135,'老师特别好，请继续这样。',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('569ef301c24aa80053b71bb4',15428,15428,'教得好，风趣，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569ef25d816dfa00596264f8',13988,114,'老师为人亲和，有时会给大一新生解答选课、生活上的疑难，拉近了学生和老师之前的距离',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('569ef1ab816dfa0059625f9b',1414,2027,'整体还不错',4,4,4,12,0,2);
INSERT INTO "reviews" VALUES('569ef0d39123b80055669f47',13988,114,'讲课很有水平，谈吐显得很博学。高数作为一门必修课，不会让我感到枯燥，上课的氛围很轻松。',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('569ef035816dfa00596254fd',13988,114,'特别和善，上课不点名，有时会在课前放小视频或放歌，高数作业量应该也不是很多',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569eefaf8ac2470054e1318c',13988,114,'在大学之前听说高数很难，但是上了高数老师的课以后觉得并不难，因为老师能用自己的独特的教学方法表达出来，有几次老师有事不能来上课，就让其他老师来教，一下子就不懂了。老师回来以后又能给我们整理出思路，我对这个老师非常满意。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569eeee03bb4d300547d5f8f',976,5,'上课只会照本宣科，毫无新意。一个半小时的课程只有一种音调，让人听了只想睡觉',3,3,2,8,1,1);
INSERT INTO "reviews" VALUES('569ee9b5816dfa005962279c',1058,5,'感觉老师讲的很好，同时也很有耐心，当学生有不会的问题时老师都会耐心的讲解',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569e36a78ac2470054dd8026',15366,601,'人好，没得说，讲的好，全身透着一种光辉。要不是老师下学期去教茅班，我一定追随她！-.-最好不要挂科！！！希望分给的松，本哥哥挂不挂科，就在此一举了！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('569e35a41532bc00540bdac8',344,601,'很有个性~刚开始可能觉得他有些高冷，上课不准玩手机吃东西睡觉，一发现就会挖苦你，（偶尔三观不正，但久了一定会爱上他！人格魅力！）但真的不讨厌，他的课是我唯一能认真听完不碰手机的！讲课很好，人很幽默，给分也高，他带的班平均分秒杀同年级其他所有。考前给我们上了好多次复习课！其他都停课了仍旧上课',5,5,5,15,6,1);
INSERT INTO "reviews" VALUES('569e33e43bb4d30054799600',7995,9692,'老师讲得很好，就是太难',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569e333a79bc440059cf2870',6403,535,'什么老师，乱七八糟的，成天打击学生。自己出的题自己半天都做不出来，上课讲的莫名其妙，前后矛盾。',2,2,1,5,3,0);
INSERT INTO "reviews" VALUES('569e32639123b8005562b8a1',13142,1596,'认真对待教学和工作的老师，正因如此，显得过于严厉',5,5,2,12,1,2);
INSERT INTO "reviews" VALUES('569e31af2e958a0059da6010',13631,40,'上课讲的毫无用处还无聊，不知道工科生为什么非要学。社科类的学术英语，翻译过来我们都看不懂！！！反人类。全班卡了至少5个89分，多给点能死啊！！！',1,1,1,3,0,0);
INSERT INTO "reviews" VALUES('569e30201532bc00540b9dfa',3286,12266,'专业技能强  课堂安排有新意，课堂氛围轻松',5,5,5,15,2,3);
INSERT INTO "reviews" VALUES('569e2f97816dfa00595e55bb',13736,114,'给分很给力',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('569e2effdf0eea0054627a8c',1381,517,'老师讲的很有趣，但很严，还好我学会了游泳',5,5,1,11,5,1);
INSERT INTO "reviews" VALUES('569e2e49c24aa80053b2f3f5',1320,40,'张老师的水平真的是不敢恭维，作为一个英语老师，满黑板的单词拼写错误，无力吐槽，口语更是说着说着就卡壳，然后就：“sorry·······”，就是这么一个老师，一直给自己吹牛逼，然后讲她给学生期末多高多高的分，大家也一直以为她就是这么水，万万没想到，她平时成绩竟然那么低，然后果断把她下学期的课给退了，再见再见！！！平时看着水，给分抠的一逼。',1,3,5,9,14,5);
INSERT INTO "reviews" VALUES('569e2b44128fe10059426ff1',14756,14756,'上课轻松且收获很多',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569e2aad1532bc00540b6670',5937,24,'上课好，考试分不高，讲得容易，做的难',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('569e2853d342d30053b99e76',15562,15562,'老师上课讲授声音有点小，内容太过繁杂，没有get到重点。但总体很专业，也很认真负责',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569e26c73bb4d300547907ff',3577,631,'讲课比较透彻，作业非常多，非常多，非常多，复习的几乎不考，不考，没来得及复习的全是大题，大题，大题。希望作业减少，少，少。出题正常点，正常点，正常点。重要的事说三遍！',5,3,2,10,5,3);
INSERT INTO "reviews" VALUES('569e2543a341310053ede1d5',8774,8774,'老师自己还是比较有知识水平的，就是不知道怎么去将自己的知识有效的传达给学生，讲课根本就没有重点。',5,3,1,9,1,0);
INSERT INTO "reviews" VALUES('569e23c92e958a0059d9c9bf',896,896,'专业知识很强，但是老师很严格，显示出极大对智商的杀伤力',5,5,4,14,1,1);
INSERT INTO "reviews" VALUES('569e22648ac2470054dc9fa8',2433,75,'上课气氛轻松活跃，老师讲课通俗易懂，容易理解',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569e20aa9123b8005561f9dd',13923,15567,'一个老师是否能第一次就吸引学生，我认为在于气质和音色。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569e1e0d7db2a20052136bd2',3437,6251,'讲错了自己不知道，错误的解题方法不改正，不严谨',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('569e00732e958a0059d84b40',627,271,'表达幽默，讲课思路清晰，内容较为有趣',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569dfffd816dfa00595c55ef',13988,114,'老师很有经验，她的特点是说话很亲和，易懂，也很负责。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('569dfebe79bc440059ccf5c2',4112,114,'讲课幽默但是平时要求并不十分严格，上课富有热情。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569df5be3bb4d3005476fdc1',696,723,'其实想给零分的。
INSERT INTO "reviews" VALUES('569df4dfd342d30053b77441',3911,859,'老师专业能力强，幽默风趣，上课鼓励大家思考，不错的好老师！但平时成绩给的有点低',5,5,5,15,0,4);
INSERT INTO "reviews" VALUES('569df41cd342d30053b76b48',6726,3691,'自从看到念错PPT，再无听过完整的一讲课',3,2,3,8,1,0);
INSERT INTO "reviews" VALUES('569df38b2e958a0059d7bf23',5803,619,'平时分低。。。。。。',4,4,4,12,1,2);
INSERT INTO "reviews" VALUES('569df347a341310053ebcb14',11518,32,'好，好可以',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('569df209816dfa00595bb9ca',11950,4003,'讲得好，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569df15ac24aa80053b05fd6',394,5739,'老师上课强调“悟”，然后本人确实非常幽默，教授的不是一般老师传递的知识，我给满分！（毕竟期末他给了超级给力的分数！）',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('569df074df0eea00545fd107',2992,6194,'超级好老师，期末你懂的。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('569df005128fe100593feac3',2484,92,'讲课认真仔细，注重平时成绩',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('569def5e7db2a20052117718',11958,11958,'打的分就是我的全部评价',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('569dee6c9123b800555fd840',12317,12391,'上课风趣，为人亲和，对他讲过的内容印象总是十分深刻。PS：发型超棒！！！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('569dedb0a633bd005b2db6cb',15349,15349,'知道学生喜欢听什么，从什么途径来获取知识，并完成的很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569dece41532bc005408ccab',1612,619,'老师幽默，实事掌握多，上课收获多',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569debe8df0eea00545fa533',360,360,'黄老师人很好，教的每门课都容易过，可是听他讲课的人太少了。',3,2,1,6,0,3);
INSERT INTO "reviews" VALUES('569deb6c7db2a20052115387',14598,15586,'棒极了，萌萌哒',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569de9d11532bc005408b4b3',5803,619,'平时成绩好低！！差评差评！老师你以后再这样我就要报警啦！考个试一把辛酸泪',4,4,4,12,1,2);
INSERT INTO "reviews" VALUES('569de931d342d30053b6fe0f',12138,370,'讲得很好，虽然不常听。实验居然扣分。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569de814128fe100593fa77d',12138,370,'上课并不怎么听。好吧，从来不听，平时成绩给分不高，如果这是统计将来推荐选谁的课，不建议选',5,1,4,10,0,0);
INSERT INTO "reviews" VALUES('569de786816dfa00595b5c28',11950,4003,'讲得很不错，考试时给分也高！挺喜欢这个老师的',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569de6a1128fe100593f9ce3',257,4318,'不发作业不讲题，不划重点不答疑',2,2,2,6,20,0);
INSERT INTO "reviews" VALUES('569de17b75c4cd2b1bd5cfc8',13254,114,'我们高数老师的专业素养很高，但是讲课速度太快，希望能把语速放缓，方便我们大脑接受有用的信息。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('569de08a75c4cd2b1bd5cb1d',1162,114,'我觉得潘小东老师和蔼可亲，平易近人，会注意学生的全面发展，很努力的想要培养学生对高数的兴趣，对于学生提出的疑问也是十分积极热情的解答，但讲课速度略快。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('569ddf9975c4cd2b1bd5c651',11285,114,'老师不仅在数学上有造诣，还对历史人物深入了解，博学多识',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569ddf0375c4cd2b1bd5c2e3',976,5,'虽然你讲得好，但是我听不懂啊！听了不一定懂，懂了不一定会做作业，做了作业不一定能应付考试，应付考试不一定能拿分，拿分也不一定能过。。。〒_〒',3,2,1,6,2,0);
INSERT INTO "reviews" VALUES('569dde4575c4cd2b1bd5bee7',4435,13445,'老师真的是666666翻了，冷笑话讲得不好，段子手，"姿势"多',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569ddd9d75c4cd2b1bd5badb',175,175,'自从上了他的课，整个人都不好了，上课没意思，他讲的不够吸引人，僵化刻板，枯燥无味，照本宣科，导致我不能认真听课，完全自学',3,2,1,6,0,1);
INSERT INTO "reviews" VALUES('569ddcef75c4cd2b1bd5b7b4',785,114,'阳老师是一位治学严谨而且又非常有耐心的老师，同时还非常幽默，我印象最深的一次是有一天点名，结果有几个金融的同学没来上课，于是他来了一句：“最近股市很好吗？怎么金融的同学都炒股去了。”
INSERT INTO "reviews" VALUES('569dac67816dfa0059597ded',11950,4003,'非常负责，讲课相当认真，在大学里很少有比他更敬业的老师了',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569dabd7d342d30053b50e51',676,676,'好',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('569dab3f8ac2470054d85859',10136,496,'全英文的试卷真是醉了，虽然平时讲课用英文，但好歹我还可以参照中文教材，这考试全英文，我有一题中题干主要单词不认识,平时也没有遇见过，你这不是逗我吗？说好的不考编程结果来了个20分的编程socket，祝你新年快乐！',4,4,4,12,3,0);
INSERT INTO "reviews" VALUES('569da9cda633bd005b2b92cb',13983,15602,'考试开始攒人品，老师人特别好！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569da958816dfa0059596774',15603,15603,'和蔼可亲的老教授，就是有点耿直，讲课有点感染力就更好了，能看出水平很高。求不每堂课点名',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('569da865d342d30053b4f5f5',15604,4003,'刘老师是一个非常专业的力学老师，讲得非常的清晰，给分也很高，感觉有真正学懂这门课。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569da7c6c24aa80053ae09d2',1386,1386,'嗯不错',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('569da700816dfa00595955f9',13077,13077,'为人风趣幽默，课堂氛围较好',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('569da67edf0eea00545d77e6',268,7955,'这是很重要的专业课，但老师讲得很一般或者说很差',5,2,5,12,2,0);
INSERT INTO "reviews" VALUES('569da5dc1532bc0054069343',2069,1743,'讲课很好',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569da582a341310053e9471f',15609,32,'这位老师我觉得有其独特的个人魅力，讲课让我感到十分轻松，点名一学期只点了3次，平时作业只要写了，点名不缺到，平时成绩就能满分了，各位土木的小伙伴还不赶快选他的课',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569da4bddf0eea00545d684b',2069,1743,'光头一个，讲笑话挺有意思的',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('569da3bb2e958a0059d52a2c',6398,1196,'一般般',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('569da32ea341310053e93347',11518,32,'老师我知道你牛X，专业领域里6得不行，但是你得让我们听懂啊！照书读教案不靠谱吧。要是给我打上90分，我就改成好评',3,2,3,8,1,0);
INSERT INTO "reviews" VALUES('569da251816dfa0059592caf',4784,641,'老师虽然看起来不苟言笑但是人很好',5,5,5,15,0,0);
