INSERT INTO "reviews" VALUES('569da0fba341310053e92079',12187,80,'根据国际最先进的土木行业混凝土设计规范美国ACI318规范吐槽中国规范水得一逼，为中国规范堪忧',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('569d9fe779bc440059c9c4bb',5318,15616,'全英文PPT，专业术语看不懂，不提前给PPT，期中考试全班最高67还是在看卷松的情况下，上课前后无逻辑',3,3,3,9,2,1);
INSERT INTO "reviews" VALUES('569d9ebedf0eea00545d3597',8147,15617,'见过讲的最好的老师之一',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('569d9d668ac2470054d7e53a',8764,8883,'很好',5,5,5,15,0,0);
