INSERT INTO "reviews" VALUES('569d9bd61532bc0054063f35',12946,1529,'选戴老师的课和进六扇门没什么区别，只能说这么多，其他的自己体会',3,1,1,5,5,0);
INSERT INTO "reviews" VALUES('569ba2ad00b0bca0e8043f50',4986,28,'很好，就喜欢爱笑的老师.....',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('569ba06400b0de391c681882',11065,11065,'超热情，除了期末论文防抄袭之外，一切完美！见过的第一个用Google查重的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b9afe34949965fe9ae68a',1506,1506,'老师讲课很有吸引力，乐意与人交流，专业水平高，口语标准，听她的课仿佛是在听一个美丽的故事，很有个性。',4,5,4,13,2,0);
INSERT INTO "reviews" VALUES('569b990560b2b80a9eb42c9d',2567,7308,'为数不多的好老师，严谨认真',5,5,4,14,2,1);
INSERT INTO "reviews" VALUES('569b988b00b00ef385122790',2078,721,'老师讲课讲的不错，注重开发学生的学习和思考能力。虽然作业有点多，但确实在他的课上学到一些知识。',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('569b97bf60b2a421c945d709',5415,51,'我的女神之一！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569b974360b28d0531b63208',15627,179,'讲课好，人好，给分高。然而今年要退休了~',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b949c00b0b6cb0009a09f',13320,8061,'老师实力雄厚，但是为人低调，见多识广，上课时就像在聊天，富有亲和力',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569b941600b0de391c6790c4',7459,36,'1.讲课内容犀利，不是照本宣科2.结合实例讲课，避免枯燥3.讲了许多教会我们如何做人的知识',3,5,3,11,1,0);
INSERT INTO "reviews" VALUES('569b582f60b219d1017df168',109,109,'老师认真负责，但真学不来这个……',3,3,1,7,0,0);
INSERT INTO "reviews" VALUES('569b57ae60b2f5adae9a535c',15349,15349,'杨老师首先给人印象亲切，且自身知识掌握牢固，对教学内容十分熟悉，十分耐心，是少数几个会把以前的课程复习（不是他课的教学内容，但是专业基础知识）这样学起来轻松了很多，因为教材是他编的，那些例子用一种亲身经历的方式引入，很吸引注意力。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('569b566660b219d1017de25e',15632,15632,'还行！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b55e060b21c0487442b3c',10973,4003,'讲课拓展很好，老师很厉害，为人亲和',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569b555900b0d8c9b76e8e4f',1458,676,'老师讲的很清楚，只要跟着老师思路走就能掌握知识点',5,5,5,15,0,0);
