INSERT INTO "reviews" VALUES('569b535660b26385cca2f9ec',7369,73,'余老师对教学非常有责任心，讲课时非常认真负责，专业水平高，对待同学热情，不仅在课后答疑时间为同学们答疑，还在工作之余在QQ群内为同学们答疑，甚至加课！学霸不二之选。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('569b524460b2b80a9eb15f79',15627,179,'大学以来遇到的最好的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b513d00b0b6cb0006fc98',4608,7819,'跪求不挂，跪求高分',5,5,2,12,1,0);
INSERT INTO "reviews" VALUES('569b50af60b2b80a9eb152b7',2559,2559,'很好',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('569b500800b00ef3850f46c8',15642,370,'老师人很好，上课很认真',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b4ea360b26385cca2cf97',15643,14612,'老师很亲切，讲解清楚细致，对同学的进步给予一定表扬，人超nice，赞！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b4d3800b0b6cb0006d741',3517,2937,'老师期末考试勾的重点方向不对，完全欺骗了同学们的感情，还复习了那些长时间，都没考。',3,3,3,9,1,2);
INSERT INTO "reviews" VALUES('569b4c9000b00ef3850f2576',1291,22,'非常喜欢这位老师，老师教学非常认真，负责也很有耐心，给满分',5,5,5,15,1,6);
INSERT INTO "reviews" VALUES('569b4c1600b0b6cbe3c11975',1063,143,'这位老师，他太多废话了，他太多废话了，他太多废话了，他太多废话了……',3,2,1,6,2,0);
INSERT INTO "reviews" VALUES('569b4b4a34949965fe97bf59',674,307,'叶文霞老师上课十分走心，与同学互动性强，重点把握准确，好老师',5,5,5,15,2,2);
INSERT INTO "reviews" VALUES('569b4af360b2b80a9eb11d70',4413,28,'讲课只会照本宣科，没有创新力，没有针对专门的问题讲解。',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('569b4a9a60b2b80a9eb11a83',198,179,'交大信息学院最好，最温柔最具信服力的老师，没有之一',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b4a7360b2a421c942c9cf',2525,5,'教学有激情，讲课由浅及深。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b499f60b2b80a9eb110d3',13988,114,'虽然是位数学老师，而且一把年纪了，薛老师给人的第一印象却是和蔼可亲。她的课上总是能以浅显的语言传达大师级的知识。举止中也透着深厚的数学功力。另外，她也喜欢周杰伦的歌。她也懂许多我们这个年龄才懂的东西。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('569b47d360b2f5adae99c5a1',7459,36,'足足一个愤青，假大空',3,2,1,6,6,0);
INSERT INTO "reviews" VALUES('569b475d60b219d1017d5bde',8265,114,'上课认真，有时候板书会算错哈哈！信他得永生（什么鬼），很正经，各种鼓掌，有很多名言，喜欢看圣经！',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('569b46a060b21c048743a26d',2303,2303,'表达清晰，但感觉有点照本宣科，讲的不够通俗生动，没讲到重点。',3,4,4,11,0,0);
INSERT INTO "reviews" VALUES('569b464360b28d0531b317cf',7459,36,'老师用研究性教学，课堂注重学生感受。不点名，但见其见解深，我比较愿意听。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('569b455d60b21c048743986f',9122,9122,'老师认真负责，教导严谨，课程的实用性强。略有美中不足的是对考试的方式每年不是很明确。希望提纲和课件可以下载。非常感谢谢老师。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569b42a400b0b6cb00067f7b',68,40,'在他的课上，不论学渣还是学霸，没有一个人听得进去。（对，没有一个）所以英语想要提高千万别选她。（PS：给分还算可以）',4,3,1,8,0,0);
INSERT INTO "reviews" VALUES('569b2e7600b0b6cbe3c02714',751,573,'师老师极负责任，为学生着想，尽自己所能为学生解决学习之外的后顾之忧。良心教师',5,4,5,14,3,9);
INSERT INTO "reviews" VALUES('569b2daa60b26385cca1c167',293,375,'不论是想学到东西，还是只想水水，这门课都很适合。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569b1f5660b2a421c94166d8',3437,6251,'讲课认真，但太无聊，缺乏创新，没有激情。但网上作业还可以，重基础，严要求',4,3,4,11,0,0);
INSERT INTO "reviews" VALUES('569b1f2b00b0d8c9b76cc522',8147,15617,'普通话不标准，节节课点名考试难，上课还不准睡觉玩手机，给六分算人情。',3,1,2,6,0,15);
INSERT INTO "reviews" VALUES('569b1d3a00b00ef3850da245',823,1897,'老师上课幽默风趣，引人入胜，很多知识点让我记忆深刻。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569b1cc400b0de391c6334a5',903,179,'老师上课仔细，作业布置量较少，比较有亲和力。',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('569b1c2900b00ef3850d9990',11891,22,'说话太松散，人不错，但平时成绩的管理太烂',3,3,4,10,1,0);
INSERT INTO "reviews" VALUES('569b1ba800b0bca0e7ff3818',751,573,'老师讲课认真，打分透明。',5,4,3,12,0,6);
INSERT INTO "reviews" VALUES('569b188260b2f5adae983ff7',7369,73,'讲课思路清晰，表达清楚，且讲课不限于教材，注重对公式的推导及基本概念的理解，同时也会给出考试重点，但其讲课的目的绝不在于应试，而是了解更多的知识。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('569b171100b00ef3850d7136',13700,1105,'1.问问题得到解答:你去知网上下我的论文看看就明白；2.期末重点：无论怎么问，只有一句话：一个中心，三个基本点；3.在下课点名',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('569b165e60b2a421c9411f68',2567,7308,'马冰老师是一位现在很少见的上课写板书的老师，个人认为知识水平很高，上课也比较轻松幽默。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('569b15a660b21c0487421170',803,1135,'讲课略有枯燥',4,4,5,13,1,0);
INSERT INTO "reviews" VALUES('569b159e00b0d8c9b76c79a7',762,762,'讲课不咋的，毛病倒是挺多，最脑残的是上课迟到的要到讲台上给全部同学鞠躬，不鞠躬还不上课，真不知道谁在耽误上课时间。',3,3,1,7,7,0);
INSERT INTO "reviews" VALUES('569b156b60b28d0531b18b1a',614,198,'讲课细节不够',4,4,5,13,2,0);
INSERT INTO "reviews" VALUES('569b14ff00b0b6cbe3bf54be',15167,281,'上课声音太小，学生听不清。',2,1,3,6,1,0);
INSERT INTO "reviews" VALUES('569b147960b26385cca0f237',13105,1743,'老师专业素养很高，但是老师考试出的题目也很难，给分相当严苛。总体来说，谢进老师是一位优秀的老师，学到不少东西。',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('569b13b800b0bca0e7fef83e',13558,143,'上课没听过，一两次也听不懂，期末突袭，平时老师讲授到点，希望交大老师给力点，同学们也希望有自觉性最终结果可以接受。',3,2,2,7,1,0);
INSERT INTO "reviews" VALUES('569b13b034949965fe95fc1d',11442,1135,'谢谢老师不挂之恩',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('569b12a900b00ef3850d4eb3',9882,22,'上课最大的特点就是特别有趣，操着一口流利的川普，讲话都搞笑，还经常讲一些笑话，自己以为很好笑，课上大部分时间都在他吹牛逼中度过。',3,4,5,12,0,1);
INSERT INTO "reviews" VALUES('569b128a00b0b6cb0004f5e1',293,375,'懂学生所想，知学生所需',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('569b11d800b0b6cb0004efcb',10294,228,'老师太狠了，同样的课，作业比别人多，还要评价内容，给分超低，考生大呼不公平',1,1,1,3,2,2);
INSERT INTO "reviews" VALUES('569b11ce60b2b80a9eaf4b91',13105,1743,'老师专业水平高，表达能力出众，亲和力好，但老师讲课与考试要求不符，考试要求高，讲课深度不够，创新引导也较少，对学生也严格，59就59！',5,4,5,14,5,0);
INSERT INTO "reviews" VALUES('569b107760b219d1017b9fd6',228,228,'关于考试，说的跟做的不一样，平时分极坑',4,3,1,8,3,1);
INSERT INTO "reviews" VALUES('569b102360b2f5adae97fd0f',3098,3136,'上课话较多，喜欢装逼',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('569b0f9060b26385cca0cb25',360,360,'太过于苛刻，在大学没有必要',4,2,2,8,1,0);
INSERT INTO "reviews" VALUES('569b0f6500b0de391c62c885',15683,762,'李老师讲课十分清楚且有条理。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569b0eaf34949965fe95cd74',14800,15684,'老师知识丰富并且很乐意给学生分享自己的学术见解。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569b0d7c00b0d8c9b76c31be',13983,15602,'讲课化简为难，可以把抽象的问题具体化讲课水平一流。同时，丁老师也喜欢讲一点课外的东西，如做学术时要恪守的原则。总之，对于计算机专业的学子，我推荐选丁老师的课。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569b05df00b0d8c9b76bf187',1192,27,'对学生要求严格，认真负责，风趣幽默，教学引人入胜，能记住所有同学的名字。仁慈好老师推荐！！！！',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('5699d2e600b0b6cbfffc0e59',15687,15687,'上课很认真，对学生尽心尽责，教授了我许多课堂之外的知识',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5699d25200b0de391c5a02bc',7062,1606,'讲课逻辑差，课件做的渣，考试出题风格诡异。',2,2,1,5,4,0);
INSERT INTO "reviews" VALUES('5699cf6e60b28d0531a878b6',7459,36,'无法适应他那南通口音的普通话，印象最深刻的就是他把“狗”念成“gěi”。还有那深刻的讽刺：“人贵在有思想，那些做作业的同学是无法理解的。”还有秒杀一切的犀利眼神。他的期末考试就是一篇论文而已........然而.......平时也有5篇平均字数>3000字的论文。哭瞎！',5,4,1,10,5,2);
INSERT INTO "reviews" VALUES('5699cbc160b2b80a9ea62dce',2701,2701,'既能学到东西，又能提起兴趣学，这门课我很少翘也很满意，教民族乐少一点',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5699cafc00b0d8c9b7633629',14085,5,'韩老师水平很高，注重思想方法，而不是题，达到了教育的同时，我喜欢他的教学。助教太可恶，好多作业。',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('5699c97f60b26385cc97ae49',101,10194,'课讲得好，亲切',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5699c12060b2a421c937876e',1453,5,'王中宝老师上课很有效率，他能够与同学们相互开玩笑，具有很强的亲和力，以及他独特的教学方式，提倡健康积极的人生态度，使课堂氛围很活跃。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5699bf9560b26385cc975723',785,114,'虽说话有点听不懂，板书也有点小丑，但讲起课来丝毫不含糊，专业水平也挺高的，只期待下学期他的语言对于我不再是天方夜谭。',5,4,5,14,8,0);
INSERT INTO "reviews" VALUES('5699bec160b2f5adae8e7206',14409,114,'水平很高，但老讲太难，考试不考的东西',5,2,3,10,1,0);
INSERT INTO "reviews" VALUES('5699be1300b0de391c594c7b',1394,230,'一门很好的涨知识的课，考试很容易过，平时成绩分数高。不用为了考试而读书。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5699bd6134949965fe8c49f7',8540,8540,'分析问题很透彻，讲课很认真',5,5,5,15,0,3);
INSERT INTO "reviews" VALUES('5699bcf360b2f5adae8e6125',1063,143,'不好',1,1,1,3,2,0);
INSERT INTO "reviews" VALUES('5699bca100b0bca0e7f543d7',14610,6419,'不想被挂啊！！！老师，期末题太难了啊！！！',5,4,2,11,0,0);
INSERT INTO "reviews" VALUES('5699bc7f60b2a421c9375e55',785,114,'锐顺老师的亲和力是最受学生们赞赏的，专业水平那更不用说，锐顺老师的课堂生动有氛围，高数课常带给我们心理课般的惊喜和感动。很朴素很实在。他点名少是因为真的很少有学生逃课，不想逃课的学生不是好学生，逃了他课的也不是好学生',5,4,5,14,2,1);
INSERT INTO "reviews" VALUES('5699bbf200b0de391c5938d8',7369,73,'只怪学院不会排课，这门课实在不够老师讲',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5699ba6060b2f5adae8e47d8',13923,114,'高数是一门神奇的学科，应当多介绍课外的，发散性，拓展性开展课本以外的数学。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5699b8d800b00ef38503774d',385,28,'老师负责任，关心学生的学习状况，但是课堂氛围还有提高的地方。',4,4,4,12,0,1);
INSERT INTO "reviews" VALUES('5699b84e60b2f5adae8e3446',1162,114,'非常富有创新力！他上的第一节课就把我震住了！弄得我以为上的是什么信息课！老师也比较能听别人意见，也改了些上课模式，讲的题都十分到位，无一例外，没听他讲都做不出来.....',4,5,5,14,4,0);
INSERT INTO "reviews" VALUES('5699b36900b0de391c58ede7',15643,14612,'有吸引力，有实践性。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5698f0219d22730284e711b2',13845,1753,'感觉还不错，自己在数学方面也有更加深入的认识，最主要是觉得自己学到东西，有所收获。',4,3,5,12,1,1);
INSERT INTO "reviews" VALUES('5698eef960b28d0531a2ae06',13845,1753,'每节课都在卖萌！水水的，但是讲得很细致！',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5698ede060b26385cc91f8eb',13845,1753,'讲课表达不太清楚，讲课能力不够。',1,1,5,7,1,0);
INSERT INTO "reviews" VALUES('5698ed3360b26385cc91f080',21,40,'认真负责，专业性强，平易近人，易于沟通',5,5,4,14,0,2);
INSERT INTO "reviews" VALUES('5698ec3800b0b6cbe3b02b15',4066,24,'只会读ppt，给成绩是按期末成绩给平时成绩。期末成绩考得好，平时成绩就给得高，期末成绩不好，平时成绩就低，想过非常难！！',3,2,2,7,4,0);
INSERT INTO "reviews" VALUES('5698eb7700b0d8c9b75d53aa',803,1111,'郭妈大法好，平时作业少，只要期末考得高，平时成绩不会少。上课讲的清楚，习题知识点共重，还能听故事。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5698e8c000b0de391c53c81b',7995,9692,'老师讲得很好，但由于每次课都在第一节课，有时精神状态不好，而且课程内容太多，导致现在我可能要挂了',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('5698e7079d22730284e6afbb',3577,2642,'老师博学且低调，课程知识专业性强。只要认真学，就可以拿高分！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5698c98200b00ef384fcdf5b',15714,9062,'景红老师讲授的C++课，课堂形式新颖，并且选修该课可以在网上看景红老师亲自制作的程序教学视频，课堂中听漏的，不懂的，都可以在网上再次观看本节课内容。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5698c76500b0de391c526759',2567,7573,'老师上课抄板书，而且教学认真',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5698c6c360b28d0531a10acf',13988,26,'“来的加分，不来的不扣分！”',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5698c53f60b219d1016b23f9',2821,40,'哎呀，反正平时教得想睡觉，学不到啥，考试也没重点，作业超级怪，分数还很低',2,2,1,5,0,0);
INSERT INTO "reviews" VALUES('5698c4ac60b28d0531a0fa26',2821,40,'上课不讲内容！讲得不好！差评！给分严又不讲课！差评差评差评！！！上课都不让我吃包子！！！！！',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('5698c3c860b28d0531a0f2fc',1021,12297,'想要成为卷福的第一步就是拥有严密的逻辑思维和超群的推理能力，逻辑学值得你拥有！',5,5,5,15,2,1);
INSERT INTO "reviews" VALUES('5698c2f200b0bca0e7ee4c18',1225,40,'讲课认真，且有吸引力',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('5698c27200b0b6cbfff44021',7995,9692,'上课很认真负责，特别严谨的一位老师，对我们要求也挺高，表面上特别严厉，但私底下很平易近人。',5,4,4,13,2,0);
INSERT INTO "reviews" VALUES('5698c1b200b00ef384fc9329',442,573,'老师讲课好像只给自己讲或是给回答问题的同学讲，从来不管学生听没听懂！',5,2,4,11,0,0);
INSERT INTO "reviews" VALUES('5698c09c00b0b6cbfff430f3',1168,228,'相当不错！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5698bfbb00b0b6cbfff42a4e',7995,9692,'老师很热情，上课很认真，耐心，很会教人学习的方法，而不是照本宣科。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5698bc2e60b2a421c9303289',15007,15725,'这门学科挺有意思，感觉老师懂蛮多的，但同时课程理解起来略难。 考试是：写论文+ppt+英文原文阅读&读书笔记（论文/文献）',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5698a7d960b2f5adae866be8',14203,14203,'讲很多引人入胜的案例，一点也不枯燥。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5698a72260b2b80a9e9dc251',1320,40,'张国琳老师是一个典型的文艺女青年，上她的英语课时就像在听一场唯美的故事会。她用她的文艺，以及她流利的英语征服了我',5,5,5,15,4,2);
INSERT INTO "reviews" VALUES('5698a5e900b0b6cbfff338d0',10294,228,'蔑视权威，胡作非为',1,1,1,3,2,1);
INSERT INTO "reviews" VALUES('5698a55660b2a421c92f5d3c',1021,228,'本以为一个比较有氛围的课，要求的太过严格，一次未到便会收到课程警告，只能用乏味来形容',3,2,1,6,0,2);
INSERT INTO "reviews" VALUES('5698a4bf60b26385cc8f2e17',13188,1904,'讲课枯燥乏味，完全照着书手机和讲义读，水的很。讲的什么也不是，经常不知道下一句该讲啥，同学们一直懵逼。',2,2,2,6,1,0);
INSERT INTO "reviews" VALUES('5698a41760b21c0487304e3b',14194,22,'老师为人和蔼，讲课较为细致，对待学生较为认真，专业水平，表达能力都很不错，学生有问题也能认真帮忙解决。',4,4,4,12,1,0);
INSERT INTO "reviews" VALUES('5698a34c00b0b6cbfff32440',630,630,'老师是很赞的，有责任心，专业能力也很强。但问题在于老师对于学生的了解太少，课堂上和同学们交互性太弱。',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('5698a2ad9d22730284e420f2',12946,1529,'每次我想专心听课时，都无法如愿以偿',5,1,1,7,2,0);
INSERT INTO "reviews" VALUES('5698a22100b0b6cbe3ad5d39',11442,1135,'谭老师上课非常认真，有深厚的知识储备，讲课时深入浅出，启发同学们思考，对待学生的问题耐心，细致，自己从这门课收获很多',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('5698a15600b0de391c5117af',2654,40,'这老师还行吧',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('5698a0c460b26385cc8f0fc8',760,75,'讲课风趣，好老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56987c1b60b26385cc8e0c27',1377,15737,'老师上课严谨认真，对同学负责',4,4,5,13,1,1);
INSERT INTO "reviews" VALUES('56986b7c60b28d05319e375a',2190,15738,'老师很亲和，讲课知识量十分丰富，善于启发、引领学生。富有发散性思维',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56971bec60b2f5adfd594dd1',7110,7110,'老师课程具有开放性特点，同学各抒己见、讨论激烈。同时，老师理论水平深厚，善于总结。且老师温柔、表达清楚，具有十分亲和力。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56971ac300b0e743b7376f64',234,256,'认真负责，人非常nice，期末这门课一定要过',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56971a0f00b0d9aca1eda23d',1162,114,'潘小东给人和蔼亲切的感觉，上课生动幽默，有问题他会给你耐心解答，有这样的老师让高数变得很简单',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('5697195060b2608e6c44f6cf',31,31,'交大好老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('569718f960b299654424d93b',10328,2158,'讲课生动有趣，以具体事例丰富课堂内容，引人入胜，课堂氛围较好。',5,4,4,13,0,0);
INSERT INTO "reviews" VALUES('569648fe7af26f38f0845536',14631,14631,'老师应该是个有故事的人，感觉比较沧桑，讲课的时候言语之中透露着对社会和国家的担忧。。。很少点名，几乎从不为难学生。就经济学这门课而言（用的曼昆的第五版教材）讲得确实还是清楚易懂的，只要你好好上课了。',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('5696436900b00ef37a963487',15745,15745,'这是一位神奇的老师，这是一门神奇的水课（研讨）。曹中清老师吧，很活跃，自己会让自己非常high，几乎每一个周五的晚上，我都要听他吹自己当年如何厉害，其他人如何一般，自己做过某公司亚洲老总，随便一个项目上千万如何......没事，你只需要玩手机，时不时“哇”“哦”“厉害”就行了，还是很easy的。水课，奇水无比，听他吹牛心有点累',1,3,5,9,15,0);
INSERT INTO "reviews" VALUES('5696417760b2bb638915b892',8566,114,'田老师是一个很敬业的人，上课时讲得非常的仔细，当我们问问题时，也是不厌其烦的给我们讲解，总之，我很喜欢她上课',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('56963ff37af26f38f083f7c2',14631,14631,'雷老师可能年纪真的大了吧......上课讲的时候经常忘记自己讲到哪儿，又没有助教，批改作业虽然很认真，但作业发下来的时间太长了...',3,2,2,7,0,2);
INSERT INTO "reviews" VALUES('56962cb500b0de393d84f46f',27,28,'很有亲和力的一位魅力老师，像知心大姐姐一样，负责热情，使英语的学习变得更加有趣轻松，很萌很棒。',4,4,5,13,4,0);
INSERT INTO "reviews" VALUES('56962b5960b2bb638914daff',24,24,'老师讲课非常详细易懂，不点名，不半期考，认真负责，板书整洁详细，会发课件和作业答案便于复习，人很好。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569629b766d8746b73634e40',751,573,'师老师极其负责任，为学生着想，尽自己所能为学生解决学习之外的后顾之忧。',5,4,5,14,2,6);
INSERT INTO "reviews" VALUES('569628ff66d8746b73634795',214,36,'“老师刚从England回来”“老师下学期要去England”是口头禅。上课不用中文喜欢说英文装B',1,3,3,7,12,5);
INSERT INTO "reviews" VALUES('5696282500b0d8c961fce159',15449,114,'上课有趣，表达流畅，易于理解。',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('5694eb6f60b2b80a9d2069b6',2190,15738,'老师亲和力出众，而且非常博学，绝对的治学严谨，考试那简单、任性的很，经历过期中和期末考试的同学便知。但是确实是很好的老师，不仅教学还育人。',5,5,5,15,5,0);
INSERT INTO "reviews" VALUES('5694e9a366d868b08824b3f9',5415,51,'董洁老师说实话并不像是一个老师，而更像是一个学姐的身份来上课。课程本身十分轻松，想要了解些心理学知识或水过的同学可以选择',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5694e8e860b26385b5b77063',11055,11055,'李老师讲课热情洋溢，对学生爱护有加，授课尽职尽责，重视培养学生思考能力，批判思维能力。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('5694e80e60b285839273498f',15010,15010,'老师很有学问，讲得也很好，稍微有点枯燥，主要是这门课太难了',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5694e7d160b28583927345af',31,1169,'老师每次上课总会回顾上讲内容，对作业题、考试题都及时讲解；并且讲课非常棒',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5694e6de00b0b6cb18f4a885',15349,15349,'非常有趣！经常讲故事，故事讲的好！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('5694e68966d868b0882494e5',11019,15759,'明明是专业课，上成水课。。。难以引人入胜',4,3,2,9,0,0);
INSERT INTO "reviews" VALUES('5694e60860b2bb639d28859c',4112,114,'杨老师经常将一些生活中的例子引入教学中，课堂氛围好',5,3,4,12,2,0);
INSERT INTO "reviews" VALUES('5694e57566d868b088248a47',8566,114,'一直用板书，认真负责，讲课时内容有条理，课下主动与学生交流，很好。',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('5694e46560b2d690e775a9f4',344,1135,'老师讲课很清楚，思维清晰，而且为人特别认真负责，会照顾成绩差的学生，给分也高，还能帮你复习。',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56949faf00b00ef3faea82c5',23,4181,'刘老师讲课细致，条理清晰，重点突出，备课认真，有亲和力。 经常传授一些关于做人方面的道理。',5,5,5,15,51,0);
INSERT INTO "reviews" VALUES('56935ce9a5b43198e5d96334',1169,199,'男神，重复一千遍。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56935c2e00b009a31ab3415d',293,375,'课堂话题都是贴近大学生活的，听的每一节课都很有感触，老师人也很好。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('56935b2a60b26bd85da71987',14085,114,'慈祥',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5692108200b009a31aaae5b4',4784,2259,'说我老是不去上课肯定不好好学？excuse me？我开学就做完了一学期实验，助教说期末验收你说了我特殊可以不去上课，我是刷分的哥，我不是大一的，您能不能不坑我？？毫不负责，当面一套，背后一套！！',4,4,1,9,2,1);
INSERT INTO "reviews" VALUES('56920fc860b2a0990f7cdff2',4784,2259,'继续！一学期给他发过了3次短信从来不回。周五下午该他值班我去办公室找他，办公室老师说他周五下午不会来？？！给他我打过一次电话（小测被他坑的那次），之后又有事打电话给他发现被他拉黑了。4个小时打了8次电话全是正在通话？？期末去交实验报告我被登了3次很低的平时成绩，助教说老师让打的，说我',4,4,1,9,2,1);
INSERT INTO "reviews" VALUES('56920e6260b20f9aeaab8c8f',4784,2259,'评论字数还有限制，一个老师只能评一次？太不人性化！接上文我继续！第二次小测验他没提前通知，当堂突然宣布测验，那个班上的同学也没办法及时通知我赶过去，事后我向老师说明情况，死活不允许我补，说你不来是你的事，谁让你不来上课？（开学答应的可以不来您忘了，补不补考您嫌麻烦就拒我？？）',4,4,1,9,4,3);
INSERT INTO "reviews" VALUES('56920cd860b2ad083a90dae5',4784,2259,'我出国，去找他刷分，说好了我开学就把一学期程序编完，平时不去上课，他答应了，还说这学期会有小测试，点名用的，你刷分，可以不来。结果真的测试的时候他说你出国刷分就能不来？不来没分！我翘了课去参加他的所谓“不来没成绩”的考试，从4：50听他在实验课上讲他理论课的东西，等到7：00就考了一个a+b',4,4,1,9,1,1);
INSERT INTO "reviews" VALUES('56920abe00b009a31aaab7b6',13845,1753,'上课是坑，讲评是渣，高数考试呵呵哒',2,2,3,7,3,0);
INSERT INTO "reviews" VALUES('569209e700b09aa2217957a8',10328,2158,'徐老师的知识底蕴棒棒哒，不只是讲生命导论课，更是讲大学生应该有的能力与素质该怎样炼成',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('569208d300b009a33497a849',14409,114,'666上课到了种境界！',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5692081860b2ad083a90b37c',13583,3625,'教学认真，对学生有耐心，能在轻松氛围中为学生提供课程以外的帮助。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5691e8cc60b27e9ba8d5cbdd',4112,114,'除了普通话和容易挂，我给满分。',5,3,2,10,1,0);
INSERT INTO "reviews" VALUES('5691e7a560b27e9ba8d5c27c',8682,31,'邓老师上课和蔼可亲，亲自为我们解答疑难问题，但有时候方言口音略重。',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('568bb3c600b068a2a981ca9b',6675,6675,'曾经在成飞工作，老师人很好，偶尔开玩笑，不过表达有些绕；知识点很多，尺寸链计算有点难，但是考试很轻松，你懂的~',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('568bb2db00b09aa2fde40d44',15778,15778,'大四专业课讲的最细最清楚的，西安交大来的新老师。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('56889a6600b068a2a96bfa50',14774,14774,'超级超级水，老师都没见过几次。期末交的论文，给分超高。成绩高不高完全是看运气，不过不会挂',3,3,4,10,0,0);
INSERT INTO "reviews" VALUES('568884b000b0bca0764c75e8',14578,14578,'平时上课不点名不签到，有三次实验，Matlab编程制图，复习给重点，就是PPT是英文的，看起来比较头疼，但都是基本概念啦，作为大四的课过应该是很easy的，建议小伙伴复习的时候交换笔记',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('5687530960b2cd25b7dc3e80',2674,10920,'教的很差，喜欢找茬，人品又差，不知道怎么当上体育老师的。千万不要选他的课，体育老师里面挂科率最高，还挂人家两学期体育 两学期！你能想把 害我多刷一年卡',2,2,2,6,2,0);
INSERT INTO "reviews" VALUES('5686aa2c00b068a2a9628b4e',1949,230,'特别喜欢汪老师的历史课，从未缺席，不愿缺席！',5,5,5,15,1,2);
INSERT INTO "reviews" VALUES('5686a9ba60b2fa064c33215c',2390,186,'很喜欢孙老师的地震工程导论课，每节课都有新看点，开怀大笑之后又学到了知识，很难想象地震可以这样学！いい先生ですよ！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('56867e5960b24d71feaf2373',14409,114,'老师的学术水平绝对过硬，但是讲课难懂，不是大神不如自学。平时给分高，人也很和气。',5,4,3,12,1,0);
INSERT INTO "reviews" VALUES('5686662860b2a099cdc9128f',1333,28,'特别温柔的老师',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('5686632e60b2a099cdc8f5c5',10447,1606,'不能辜负熊教授对我们的期望啊',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('5680e7aae4b001e2e736e29b',1453,5,'每个老师的风格适合不同的人，表达能力一般，上课念ppt，上课趣味性一般。他的风格不太适合那种需要从课堂中获取较多知识的同学。总体上说，教学态度还是值得肯定，他也说过每年的学生节日给他发短信的越来越少，亲和力以及上课节奏的控制有关吧。',4,3,4,11,2,0);
INSERT INTO "reviews" VALUES('567ec14660b2c1e224cd96f5',1453,5,'宝宝老师的课含金量非常高，在课堂上，虽然授课进度比较快，但是课堂气氛十分活跃。而且老师对于答疑和作业这两方面也很认真对待，批改作业时，不仅批对错，还会帮学生写出正确的过程和做题思路。在答疑方面，屡次督促同学参加答疑。并督促所有人的出勤状况。总之，是一个非常负责任的幽默的老师。',5,5,5,15,6,1);
INSERT INTO "reviews" VALUES('567e6fbf00b0adf744ef42dd',491,1529,'刘老师，上课很有重点，口齿清晰，上课生动有趣。上机操作对学生疑问也是耐心地回答。理论课时常点名，只有极少数的缺勤。虽然到期末了理论课有点无聊，但这和老师关系不大。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('567e394100b0adf744edbb45',877,877,'老师很可爱…三四十岁的样子还跟个小姑娘一样萌萌哒，而且特别亲和有耐心，但是讲题目却是一副很干练的风格，清楚明白易懂',5,4,5,14,1,0);
INSERT INTO "reviews" VALUES('567e317700b06f9f61880de6',228,228,'上课死板得要死，我高中老师都要讲的比她好，还常常点名。属于没啥才华和亲和力的那类',1,1,1,3,3,1);
INSERT INTO "reviews" VALUES('567d59a300b0e902c086e217',13142,1596,'这老师很坑，点名不到就直接取消考试资格。而且不好说话，特别特别不好说话！！还爱摆架子，一副典型的旧时代教书匠做派。上课很枯燥很死板，照本宣科，作业量不小。给分也不高。总之就是能不选就尽量不选，毕竟教得好的老师多得是。',2,2,1,5,4,1);
INSERT INTO "reviews" VALUES('567d462d00b0e902c0861f34',166,619,'刘老师，就我看来思政类最好老师，教课风趣，为人幽默，有涵养，他永远谦虚，而且为人和善最最重要在于他学富五车，跟他学习你会感受到什么叫做真正的学子，太爱刘老师，他甚至改变了我的人生！',5,5,5,15,5,1);
INSERT INTO "reviews" VALUES('567c0cb060b2c0befd5c0889',5415,51,'大家应该都听说过董洁和她的大心了，亲测确实讲的很有趣，我也听过其他老师的大心，课堂体验不能比。很可爱的老师。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('567c0b1560b2c1e224bdaabe',4687,4687,'兼具专业素养和人文关怀的老师，讲课生动风趣，条理清晰，是能引导人爱上这门学科的人。当然最重要的是给分相当良心～',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('567c0a0a60b2855b7d3fad98',5300,5300,'陶老师上课有时非常幽默，有时非常严格，不过还是非常有教授风度的，不妨自己来听听嘛!大家很崇拜他哦!老师治学严谨，要求严格，能深入了解学生的学习和生活状况，循循善诱，平易近人;注意启发和调动学生的积极性，课堂气氛较为活跃;上课例题丰富，不厌其烦，细心讲解，使学生有所收获;半数认真工整，批改作业认真及时',3,2,3,8,1,0);
INSERT INTO "reviews" VALUES('567c03161e949ec0524be0cb',14260,641,'彭老师上课讲的细致，思路清晰，讲的比较明白，课后作业少，考前带着复习一波…考试妥妥的！！！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('567bf98560b2e1871df5977d',1949,230,'汪姐，博士。讲课生动有重点，讲课字正腔圆，声音洪亮。每次去上近代史都带了作业准备上课做一点，然而每次都失败了，讲课很有吸引力，对学生也很亲和，实力推荐。',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('567960cd00b0023c1cb5e065',891,114,'陈老师，人非常和蔼，从来不对学生发火。讲课细致，所以进度比别的老师稍慢。我很喜欢他她的风格，推荐。',5,4,5,14,1,1);
INSERT INTO "reviews" VALUES('5677d70160b2f42a12894bcb',15800,223,'基本上高中说教水平，套路是：点人起来回答，要你报学号，然后中断讲课对照名单给你记下加分，一堂课上演无数遍（老师你总是停下来计分不觉得夸张吗）。既功利又无聊。下面的学生跟着一唱一和，反正随便扯几句就能加分！填鸭教育都算不上',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('56727a36e4b073ef44ca7d1a',12301,12301,'有种无力吐槽的感觉，老师自以为自己很幽默，其实枯燥乏味。 分给的不错，期末时都会发送题库，把题刷完，妥妥能过。 很喜欢让人回答问题，然后加分。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('567278c3e4b073ef44ca7c36',1768,22,'极好的老师！人满为患！专业水平高，表述能力强，给分也很高。课堂上比较严肃，私底下人却很热情，很关心学生。钟晓春好估计是所有学生都知道的吧？ 综合榜第一！冲冲冲',5,5,4,14,8,0);
INSERT INTO "reviews" VALUES('5670fe7360b2d0be157ccabc',1727,87,'区别对待学生',3,3,1,7,3,1);
INSERT INTO "reviews" VALUES('5670dfa760b262671c811759',15162,15804,'翠芳姐人是相当的好呀，上课让同学们回答问题，答不上来也不会批评，耐心地再给你讲，超赞',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566f867b60b2ed36d963b8bc',10544,15136,'学了就知道这门课怎么样了，老师给了我们很多时间做课上报告，加强我们的表达能力训练！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566f85b560b20de546403543',15806,15806,'傅老师这门课对我的影响很大，上课方式有很新颖。认真的人肯定收获很多！也鼓励大家积极回答问题，多老多得！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566f855a60b2d0be15726e3f',573,573,'成老师讲课很有意思，有点高中时代的味道，鼓励大家回答问题，积极思考。我就上课回答了很多问题，平时分给满，期末也可以！',5,5,5,15,1,4);
INSERT INTO "reviews" VALUES('566f849300b0814d65f9b8f9',15366,1897,'王英老师绝对是个认真负责的好老师，有着很强的专业能力，认真听她的课肯定能学好知识！而且上课不失幽默！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566f841200b0bf37f5f14ecd',9807,15363,'严老师是我见过大学里为数不多的好老师之一，上课认真，讲解有条理。作业不多，为人亲和。鼓励学生各种形式的创新，课堂内容与实际联系紧密。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('566ed7ba00b0d1dbc756b011',13290,13290,'汪老师是难得的好老师，我们私下一直喜欢叫她汪大妈。上课非常严肃认真，课后却非常平易近人，对学生的要求也很严格，会尽力将知识给所有人讲懂。上完这个课程真的学到很多自控知识，在后面的竞赛以及工程中都非常有用！',5,5,5,15,1,1);
INSERT INTO "reviews" VALUES('566ed79100b0bf377b32d58c',1267,5618,'高老师上课形式很新颖，而且讲的真的很棒，难得的好老师，最关键的是，不点名哦，考试不为难我们也～',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566eb57700b0ee7f998552b4',15812,15812,'很有趣的老师',5,5,3,13,1,0);
INSERT INTO "reviews" VALUES('566ea66060b20de5463b6b0c',309,309,'崔老师上课很形象很生动，建筑材料课上的有滋有味。知识点清晰，层次分明。而且人也很和蔼亲切，愿意帮助同学各方面的事情。好评好评。推荐推荐',4,5,5,14,0,0);
INSERT INTO "reviews" VALUES('566e9d9160b202590be9412a',1168,228,'老师说的真心听不懂，感觉进入另外一个世界。
INSERT INTO "reviews" VALUES('566d645560b2d0be1564a7dc',6935,496,'老师不错！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566d63e3ddb2a41931312862',6323,1529,'陈老师不错🙌',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566d490c60b25b04371a0396',1320,40,'张先生，とでも優しい人。课堂氛围活跃，和蔼可亲。交大最负责的老师之一，课余时间义务开课帮助4、6级没过的同学。鉴于张老师大学时间就是学霸hh，对考托考雅也很有经验。（上课大量鸡汤）',5,5,5,15,4,1);
INSERT INTO "reviews" VALUES('566d2b4060b20de5462fc32d',330,448,'绝对是我看到的物理讲的最差的老师了，我物理基础不好，她的课基本是念ppt，讲不明白，而且上课总卖萌，像哄小朋友那种。而且给分很低，反正就是选她的课纯自学。',2,2,2,6,13,1);
INSERT INTO "reviews" VALUES('566d1c9000b0bf37f5e04f09',2202,28,'很好的一个老师。温柔。。。耐心教导每一个同学。。。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566d161e00b0ee7f997823d8',330,22,'最不喜欢的老师之一，讲的差，给分低，上课毛病还多，学长学姐良心推荐，千万别选她的课',2,3,1,6,9,1);
INSERT INTO "reviews" VALUES('566d14de00b0d1dbc73cb29d',8147,15821,'大学最喜欢的老师，没有之一，负责，讲课风格很好，容易勾起学生的兴趣，按照他的思路来学习，期末不复习成绩也很好',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('566d107360b2ed36d95217b0',2202,28,'亲和力强，认真负责，风趣幽默，引人入胜，和蔼可亲，没有距离感。就像是一同学习英语的parter一样。大赞金老师！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566cf88800b0814d65e73d62',15262,15262,'老师很漂亮，讲课也很专业很仔细，可是好严肃啊！不苟言笑。课程不算生动，但也不枯燥，有很多案例分析，作业较多，绝对能学到东西！',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('566cf84f00b0d1dbc73ae51e',15262,15824,'老师很漂亮，讲课也很专业很仔细，可是好严肃啊！不苟言笑。课程不算生动，但也不枯燥，有很多案例分析，作业较多，绝对能学到东西！',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566cf764ddb2a419312c7190',4936,14056,'老师上课可幽默了，周老师的笑声……那绝对是有魔性的，你不开心都会想跟着笑！！！老师讲课很仔细，保证你听得懂，期末会划题，复习很轻松，也能学到东西。',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('566cf72360b202590bdbc5bf',9807,12085,'交大遇见的最认真负责的老师，记得留到很晚帮学生答疑，在他的课上也真的学到了实用的知识，课下特别乐意跟我们交流，永远很耐心，大学里还有这样的老师太难得了。',5,5,5,15,8,0);
INSERT INTO "reviews" VALUES('566cf6a060b215d68bce8c0b',397,397,'第一次见胡老师就觉得亲切，很爱笑，老师看起来很年轻很可爱。可是要说专业水平，我就只能呵呵了，和自学差不太多吧。上课倒是很轻松~~',3,4,5,12,2,0);
INSERT INTO "reviews" VALUES('566cf5c000b0bf377b22f99a',5021,12405,'张晶老师是我最喜欢的老师前三，特别有人格魅力。学法出生，有自己坚定的原则，主见。一点没有沾染上社会的俗气，对很多案例的审判有独特的见解。老师上课很循循善诱，让你没办法走神，总愿意跟着她思考。她的思维方式，独特视角，也给我打开了新的思想大门。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('566cf40900b0bf37f5dea41f',6060,14800,'周老师的市场营销学在大一上的，会有很多营销案例帮助理解。里面讲的一些模型还可以用在很多其他方面的分析。周老师也是周老板哦，女强人一个，边做事业边教学，很厉害，上课也生动。',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566cf2d060b2e416628c2f3a',15830,15830,'段老师非常认真负责，上课细致有条理。段老师过了CPA的哦，专业素养是杠杠的。在现在已经很难在大学里看到这么为学生考虑的老师了。段老师上课很严肃，看起来略凶，但私下里真的是亲切到不行，还会和我们聊私生活。。。绝对的好老师。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566cf2a260b262671c64efd8',15830,15831,'段老师非常认真负责，上课细致有条理。段老师过了CPA的哦，专业素养是杠杠的。在现在已经很难在大学里看到这么为学生考虑的老师了。段老师上课很严肃，看起来略凶，但私下里真的是亲切到不行，还会和我们聊私生活。。。绝对的好老师。',5,5,5,15,0,0);
