INSERT INTO "reviews" VALUES('566cf12d60b20fc91169dd0e',1433,1433,'私下里我们叫她饶姐姐，很专业，讲课也很细致，人也很好。只是上课还是比较枯燥。但是你如果是想学习审计专业知识，那么饶姐姐完全能满足你。',5,5,5,15,0,0);
