INSERT INTO "reviews" VALUES('566ce9a500b0ee7f997663cc',15836,15836,'额，真的是背书式的上课！组织行为学前几周都在讲儿童心理！后面就是读ppt啊！考试整本书都是重点啊！而且是一条一条画出来的！',3,2,5,10,4,0);
