INSERT INTO "reviews" VALUES('566ce12060b20fc91169468a',867,28,'里娜老师是我很喜欢的一位老师 老师很亲切 教学水平也不错 她的英语课很生动 老师也是大美女',4,4,5,13,1,2);
INSERT INTO "reviews" VALUES('566ce0a8ddb2a419312b8a35',15842,676,'老师说话有点方言的腔调 很容易听不懂 喜欢照着ppt念 讲课质量一般',3,2,2,7,0,0);
INSERT INTO "reviews" VALUES('566cd46860b202590bda77ab',684,684,'李老师专业水平很高，自己也很负责。生化这门课对于生工专业的同学来说特别特别重要，所以想好好学生化的同学就应该选李老师的课。不过，她的课一般都会在第一讲，而且她会要求签到，记笔记还要定座位。',5,5,5,15,6,0);
