INSERT INTO "reviews" VALUES('566c12de00b07a18ded4b1ee',823,1897,'思维清晰，善于总结，对学生热情友好。 记得当时给她发短信套题，她也知无不言 言无不尽。点名少 ，会把布置的作业讲解清楚。超有耐心的 经常看到她给别人讲题到中午。',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('566c128e60b294bccfbcc5a5',4510,6000,'课都是一样的，老师有所不同。杨老师很和蔼（甚至好欺负？……），人超nice，很好说话…选她的知识经济创新比较安心',3,4,5,12,0,6);
INSERT INTO "reviews" VALUES('566c123060b202590bd61605',10544,15136,'老师很随和，期末考试比较简单，关键老师还不经常点名。',5,5,5,15,0,1);
INSERT INTO "reviews" VALUES('566c10cd60b215d68bc8d868',1768,22,'大物讲得很好，很有条理，很清晰。而且老师上课很有激情，很负责，给分也是很不错的。',5,5,5,15,3,2);
INSERT INTO "reviews" VALUES('566c0f5b60b20de54627e089',10544,9626,'没有认真听过，只是觉得这个老师不太好，给她邮件 电话都是一副我是老师我说的算的态度，不会去理解学生。哎 长的又丑。大学最讨厌的老师。但好像给分不错',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('566c0e4960b202590bd5eb8c',1287,11674,'美女老师，声音甜美，给分还好吧。她经常逃课 哈哈 而且不会补回来……',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566c0ce000b0ee7f99710490',4411,27,'很亲和啊，可惜我浪费了她的两年课',3,3,3,9,0,1);
