INSERT INTO "reviews" VALUES('566c07d060b20fc911640a34',9032,4528,'很负责，讲解清晰，课程中要自己看文献讲ppt',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('566c072a00b0d1dbc72ea87a',11958,11958,'老师专业能力很强，但是有时不太友好，毕竟外教，上课很小声，两排之后听不见，跟着他就是长见识，专业知识还是靠自己学',5,3,3,11,0,0);
