INSERT INTO "reviews" VALUES('566c055c60b202590bd593df',13077,3814,'课程清晰，个人很有见地，上课会提问，这门课也全靠背',5,5,4,14,0,0);
INSERT INTO "reviews" VALUES('566c03fc60b25b0437105d15',12718,15867,'老师很和蔼，不点名，但感觉没有什么实质性的东西，混学分必备吧',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('566c01ed60b2e41662860b92',12320,15868,'老师很和蔼很温柔，授课详尽，不点名，给分高',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566c015c60b2d0be15598c32',1243,1247,'老师很负责，讲课也很清晰，但会让你在课下查很多东西，认真的话会收获很大',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566c00be60b2d0be1559861f',10533,10533,'条理清晰，授课生动，很有激情，人很好。然而这门课要记得东西好多',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566bffdf60b2d0be15597e54',9696,15871,'万老师博学！上课特热情！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('566bff5e60b20fc91163b43d',1235,1243,'超级亲和有耐心，你帮他拿东西都给加分',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566bfe8c60b215d68bc8203d',948,22,'讲课调理清晰，耐心，整个人都很温柔，从不点名，作业可以晚交',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('566bfd2960b202590bd54093',9643,9643,'资料说参加过863等国家工程项目，专业能力应该是可以的，但就课堂而言，表达不清很严重，教育观点陈旧。虽然也是能看出为学生好，但实在无法交流。必点到。',3,1,1,5,0,0);
INSERT INTO "reviews" VALUES('566bfbb860b2ed36d94a9329',1506,1506,'课程活泼生动，汪老师很有表现力，会讲自己出国的有趣经历，从不点名，就两次课堂作业，期末还会派发自己的碟。正常情况给分八十左右，但课程确实有趣',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('566bdb1a60b202590bd40a11',15149,15149,'是大学里我遇到过最开明的老师，很理解学生。我基本上没有听过他的课，但是跟他讲明后非常理解。分也给的很高 很棒的老师',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566bdb0f00b0d1dbc72bf0d7',9696,1904,'万老师挺有水平的，比较有见识！',4,4,4,12,0,0);
INSERT INTO "reviews" VALUES('566bda2b00b0bf377b1b48b2',10533,10533,'王老师课讲的特别好，有激情，是我大学遇到的最好的老师，没有之一！',5,5,5,15,1,0);
INSERT INTO "reviews" VALUES('566bd99a00b0bf37f5d70c52',1243,1243,'老师很负责，就是有点严格，如果想真正学点东西就可以上她的课',5,4,4,13,1,0);
INSERT INTO "reviews" VALUES('566bd8eb60b262671c5d5bf2',12320,15868,'老师挺好的，和蔼可亲，比较有亲和力，也比较温柔，重要的是不容易挂科哟！',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('566bd8b760b20fc91162582d',12320,15868,'老师跟和蔼，专业能力强，讲课清晰',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('566bd83560b262671c5d569c',13558,143,'表示这门课基本没听过，也不知道他在讲些啥……从来没点过名，还老爱吸烟。不过最后分给得不错就行了。最后两周才买书看…',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('566bd7a560b20de54625d651',15149,15149,'妥妥的好老师！！上课那会东拉西扯很多，不过大多数都是讲以后工作中会遇到的…因为孟老师接实际项目比较多，所以很能够结合实际例子来讲课。老师喜欢点名～考试分超高啊！',5,4,5,14,2,0);
INSERT INTO "reviews" VALUES('566bd78000b0bf377b1b34c2',1235,1243,'老师很好，很负责，对学生很有亲和力',4,3,5,12,0,0);
INSERT INTO "reviews" VALUES('566bd77100b07a18ded28072',15885,15885,'******讲课没特色，一次作业没交上，期末直接挂科，千万别选！',1,1,1,3,1,1);
INSERT INTO "reviews" VALUES('566bd74860b202590bd3edef',6403,535,'王小川是超级坑的老师，至今已经点了10次名，而且有时候会一次课点两回。而且是上午第一讲一上课就点名，迟到了的都记迟到。心好累💔',4,3,3,10,3,0);
INSERT INTO "reviews" VALUES('566bd6e000b0ee7f996f11a5',24,24,'不知道他水平究竟如何，只知道他挂了我两次。每次都有提前打电话 考完也打电话，还是残忍的拒绝了我。 哦 好像他很喜欢抽烟 喜欢抽烟的同学有福气了 可以多跟他交流下',3,3,3,9,2,46);
INSERT INTO "reviews" VALUES('566bd6db00b0bf377b1b2fed',1768,22,'记得当时是自己班的优选老师，第一次上课把自己都吓一跳～绝对的爆满。没想到上个大物还有这么多人。大物上下都是这个老师，钟老师的讲课水平真是没的说！只要你听了，基本就能听懂。而且老师特负责。要求也稍严…至于给分，当然高了。',5,5,4,14,12,0);
INSERT INTO "reviews" VALUES('566bd68960b20de54625cdcf',14324,394,'老师水平一般，讲课时强行将愤世嫉俗观念传播给学生，对人不尊重，差评！',1,2,2,5,4,0);
INSERT INTO "reviews" VALUES('566baba460b2e41662832a0d',2202,28,'大学里遇到最好的老师，不仅教授文化知识，还带领我们认识世界，用正确的世界观去了解世界。老师讲课细致认真，提出的问题也发人深省，在老师的课堂上学到的不仅仅是知识，还有思考问题的方法。老师很有亲和力，最后结课的时候还很热情地和我们合照。',5,5,5,15,10,0);
INSERT INTO "reviews" VALUES('566ba59900b07a18ded0d7e8',23,1529,'公认大学计算机基础最好的老师，没有之一',5,5,5,15,82,0);
INSERT INTO "reviews" VALUES('566b9b6000b0814d65dd58d0',15836,15836,'老师亲和力够，就是上课不够生动。',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('566b9a8b60b20de54623d279',7369,73,'老师认真严谨，讲课严谨。学生很受用。',5,3,3,11,0,0);
INSERT INTO "reviews" VALUES('566b97e500b0bf377b1920e1',762,762,'平时没咋学，期末也没复习。平时成绩给了57 期末成绩70 刚刚过',3,3,3,9,0,1);
INSERT INTO "reviews" VALUES('566b8ef360b202590bd194dd',15895,3736,'水课鉴定：最水的就是他！',3,3,3,9,1,1);
INSERT INTO "reviews" VALUES('566b8eca60b25b04370c70a2',15895,1137,'超水的一门课，轻轻松松拿到学分， 我几乎选了他所有的选修，真的很水',3,3,3,9,2,0);
INSERT INTO "reviews" VALUES('566b8e7760b2d0be1555b4c3',15895,3645,'如果你想不花任何精力修一门选修，非他莫属。最水的就是他',3,3,3,9,1,0);
INSERT INTO "reviews" VALUES('566b89d460b215d68bc43cfb',3727,1904,'非常接地气的老师，上课轻松，极具亲和力，拓展很多，如果选到他的课，恭喜你，可能会颠覆你的价值观哦！',5,5,5,15,2,5);
INSERT INTO "reviews" VALUES('566b862160b294bccfb7fbb3',14035,6211,'马老师经验丰富，和蔼可亲，她的课实例很多，总能引人入胜。上她的课虽然感觉平平淡淡，但是很受用。',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('566b838a00b0bf37f5d4497c',1267,2678,'能选上高老师的课的人是幸福的，这是一门交友把妹、解决困扰的福利课，每次都爆满。高老师颜值高，上课轻松，常有活动，最爱的选修课，没有之一！',5,5,5,15,6,0);
INSERT INTO "reviews" VALUES('566af5cf00b0814d65da96c1',2069,1743,'老师挺好的，讲的也不错，就是听不懂😀',4,4,5,13,0,0);
INSERT INTO "reviews" VALUES('566aea5800b0814d65da3569',2202,28,'首先要说的一点就是：在交大能够遇到这么好的英语老师真是三生有幸。老师不仅人很和气，个性温和，在课程内容上也是一点也不马虎，在学习课本知识的同时也十分注重与学生分享各种奇闻异事，同时善于挖掘学生的潜能，让他尽可能的发挥自己的优势，提升自信，我觉得金老师很值得推荐。',5,5,5,15,15,0);
INSERT INTO "reviews" VALUES('566ae8c000b0d1dbc72090aa',5300,5300,'我很喜欢陶老师的课程。首先从老师的态度上来讲，课程内容充实，备课认真；然后从授课技巧来讲，老师可以将难懂的数据库概念讲解的便于学生理解，我很喜欢；最后从老师的为人处世来看，陶老师是一个平易近人的人，喜欢和学生接触，我就是因为这门课喜欢上这位老师同时请他作为我的毕业设计导师的。',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('566ae0bfddb2a419311f0e3d',13142,1596,'王老师的专业水平非常高，课程讲解到位，但是对学生要求比较高，太严肃，缺勤或者不交作业次数到3次就取消期末考试资格，可怕。',5,4,1,10,2,1);
INSERT INTO "reviews" VALUES('566adebd60b262671c57bb10',1608,641,'他专业知识还可以，但是表述不是很好，上课老是跑题，讲些乱七八糟的吧。选择他的课，我觉得极大程度上锻练了我的自学能力，所以，大家选课注意啊',4,1,1,6,1,0);
INSERT INTO "reviews" VALUES('566adc3100b0814d65d9a47c',4250,15906,'个人觉得朱焱老师是一个非常优秀的老师，德国留学8年，平时对学生要求比较严格，我们每周都要做英语ppt并演讲锻炼了学生的口头表达能力和综合能力，但是老师给分不高，同志们按自己需求选择吧。',5,5,5,15,0,2);
INSERT INTO "reviews" VALUES('566adc1460b294bccfb4e5a8',903,179,'康萍老师是难得在大学里让我想听课的老师。讲课思路非常清楚，模电被她讲的感觉一点都不难。各位想学好、考高分的，请一定要选康萍老师的。不过课很难抢到哦。作业也比较少，人很有亲和力。',4,4,4,12,2,0);
INSERT INTO "reviews" VALUES('566adb5c60b2ed36d9438e8e',13254,114,'表情包。。。。。。名字也不错。。。',5,5,5,15,0,0);
INSERT INTO "reviews" VALUES('566adb3760b202590bce37d1',716,716,'李松老师表达很好，讲的也很有技术含量，不过这门课确实难',5,5,4,14,1,0);
INSERT INTO "reviews" VALUES('566ad70a60b215d68bc0d6e9',3036,3036,'虽然大四了，没有多少人听课，但是晓航哥还是很认真的对待每一节课，每次看到在上面辛苦的讲课，然后大家都不听的时候，对他好愧疚，但是我还是不想听课，老师对不起了，不过，你真的很好，很负责。每次布置完作业，老师都是很认真的点评，课后都是很认真的讲解，做得好的分还高，远远高于平均水平，哈哈~~~~',5,5,5,15,6,1);
INSERT INTO "reviews" VALUES('566ad34360b262671c573a25',15911,223,'郭老师讲课挺好的，上课状态略妩媚，内容通俗易懂，发人深省，福利是他不考试。但是不要轻易跟他对着干，他曾是校辩论队主力，你说不过他；他也是跆拳道黑带，你打不过他！',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('566ad22500b0d1dbc71f0f76',13105,1743,'超级可怕的老师，专业能力很强，课也讲的很好，但是太严格了
INSERT INTO "reviews" VALUES('566acfe760b215d68bc087a7',1768,22,'老师讲课特别好，条理清晰，定期做章程总结，对学生的听课态度要求高。教大物的大牛！想要学好的大物的童鞋一定要选它，权重投100分最好，因为很火爆的！给分也比较高 语速很慢',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('566acefc00b0bf37f5d0b14d',9807,13185,'老师真的超级好，我大学最喜欢的三个老师:王英，严映律，潘志刚。他们都认真负责，讲课条理清晰，听不懂的完全是自己好好学，对了我听的课是工程光学C，因为只看到A,所以就评论到这里～',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('566acef000b0ee7f9968d0ac',15149,15149,'老师特活跃，上课很长知识，从没睡过觉。爱点名，上课前5分钟点，上16周的课点14次名！',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('566acd9800b0bf377b14cef0',15366,1897,'王英老师真的是我见过最好的老师之一！讲课条理清晰，老师虽然年龄大些，但是正因如此亲和力很强～',5,5,5,15,3,0);
INSERT INTO "reviews" VALUES('566ac4dd00b07a18decbbfa8',82,82,'老师上课负责，特别是对于实习操作，很耐心讲解，亲自演示，态度很平和',4,4,5,13,3,0);
INSERT INTO "reviews" VALUES('566abf0060b294bccfb38b44',15200,309,'老师上课认真负责',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('566abe9000b0bf377b14208c',2535,5043,'谢老师人特别好，划重点特别清晰，就是爱点名！',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('566abda960b25b043707b007',15920,15920,'老师自称正直，喜爱教书育人，上课管的特别严，虽说学生比较烦他，不过能一直叮嘱我们让我们学习说明他是一个好老师。',4,5,1,10,2,0);
INSERT INTO "reviews" VALUES('566ab25fddb2a419311cdc23',13582,78,'授课认真负责，不照本宣科，拓展知识多。',5,5,3,13,0,0);
INSERT INTO "reviews" VALUES('566980a660b2298f8e764e4f',15922,4577,'老师很不错的，值得推荐',3,3,3,9,0,0);
INSERT INTO "reviews" VALUES('566816e100b0d1db76dd9b6e',15923,15923,'非常和蔼的日本老师，完美再现日本人的感觉（怎么感觉这话是在找吐槽），而且很能说…坚持和她交流一定能提高听力和口语。态度认真且鼓励学生',5,5,5,15,4,0);
INSERT INTO "reviews" VALUES('56652a4560b204d55d579696',2202,28,'在交大能找到的屈指可数的好英语老师，脱离了填鸭和枯燥无味的教学模式，善于鼓励和启发学生，是可以做朋友的那种老师！P.S：英式英语；善于做媒，良心好评！！',5,5,5,15,30,0);
INSERT INTO "reviews" VALUES('566445d100b0d1dba29867f7',8953,605,'好好好',5,4,5,14,0,0);
INSERT INTO "reviews" VALUES('5662ada000b0d1db00db4dba',13254,229,'非常有趣的小老头，非常亲切，但又对课程要求高，有什么不懂的也耐心解答 非常不错',5,5,5,15,2,0);
INSERT INTO "reviews" VALUES('565d394600b0c0603026ea50',14612,14612,'叶老上课很专业，用的教材是罗斯的《公司理财》，需要做课程小组展示，分析公司财务报表。上课很生动。',5,4,4,13,3,0);
INSERT INTO "reviews" VALUES('565b164c60b2597424f50a64',15428,15428,'闫叫瘦是个好老师！',5,5,2,12,0,0);
